#[allow(clippy::arithmetic_side_effects)]
fn cmd_uptime() {
    // Use TSC-based timekeeping for precise uptime.
    let (up_secs, up_ms) = crate::timekeeping::uptime_ms();
    let seconds = up_secs;
    let minutes = seconds / 60;
    let hours = minutes / 60;

    // Current wall-clock time.
    let now = crate::timekeeping::now();

    // Load averages (1/5/15 minute EWMA).
    let (l1, l5, l15) = crate::loadavg::get();
    let (l1_w, l1_f) = crate::loadavg::format_load(l1);
    let (l5_w, l5_f) = crate::loadavg::format_load(l5);
    let (l15_w, l15_f) = crate::loadavg::format_load(l15);

    // Active (non-idle) task count.
    let stats = crate::sched::sched_stats();
    let active = stats.total_tasks_spawned.saturating_sub(stats.total_tasks_exited);
    let nr_run = crate::loadavg::nr_running();

    shell_println!(
        " {:02}:{:02}:{:02} up {:02}:{:02}:{:02}.{:03}, load: {}.{:02}, {}.{:02}, {}.{:02}, {}/{} tasks",
        now.hour, now.minute, now.second,
        hours,
        minutes % 60,
        seconds % 60,
        up_ms,
        l1_w, l1_f,
        l5_w, l5_f,
        l15_w, l15_f,
        nr_run,
        active,
    );
}

/// `dmesg [-n COUNT]` — display kernel log messages.
///
/// Reads the structured log ring buffer and displays entries in a
/// human-readable format: `[timestamp] level/module: message`.
///
/// Options:
///   `-n COUNT` — limit output to the last COUNT entries
///   `-l LEVEL` — filter by minimum level (trace/debug/info/warn/error)
///   `-m MODULE` — filter by module name (substring match)
fn cmd_dmesg(args: &str) {
    let mut limit: usize = usize::MAX;
    let mut min_level: &str = "";
    let mut module_filter: &str = "";
    let words: Vec<&str> = args.split_whitespace().collect();
    let mut i = 0;
    while i < words.len() {
        match words[i] {
            "-n" => {
                i = i.saturating_add(1);
                if let Some(n) = words.get(i).and_then(|s| s.parse::<usize>().ok()) {
                    limit = n;
                }
            }
            "-l" => {
                i = i.saturating_add(1);
                if let Some(&lvl) = words.get(i) {
                    min_level = lvl;
                }
            }
            "-m" => {
                i = i.saturating_add(1);
                if let Some(&m) = words.get(i) {
                    module_filter = m;
                }
            }
            _ => {}
        }
        i = i.saturating_add(1);
    }

    // Map level string to numeric priority for filtering.
    let min_prio = match min_level {
        "trace" => 0u8,
        "debug" => 1,
        "info" => 2,
        "warn" => 3,
        "error" => 4,
        _ => 0, // No filter (show all).
    };

    // Read all log entries from the ring buffer.
    // The buffer is JSON-lines format; we'll read raw bytes and parse
    // the timestamp, level, module, and message from each line.
    let mut buf = alloc::vec![0u8; 64 * 1024];
    let (written, _last_seq) = crate::klog::read_logs(u64::MAX, &mut buf);
    let text = core::str::from_utf8(buf.get(..written).unwrap_or(&[]))
        .unwrap_or("");

    // Collect lines, apply filters, then take the last `limit` entries.
    let lines: alloc::vec::Vec<&str> = text.lines().filter(|line| {
        // Level filter.
        if min_prio > 0 {
            let level = extract_json_str(line, "\"l\":\"");
            let prio = match level {
                "trace" => 0u8,
                "debug" => 1,
                "info" => 2,
                "warn" => 3,
                "error" => 4,
                _ => 0,
            };
            if prio < min_prio {
                return false;
            }
        }
        // Module filter.
        if !module_filter.is_empty() {
            let module = extract_json_str(line, "\"m\":\"");
            if !module.contains(module_filter) {
                return false;
            }
        }
        true
    }).collect();

    let start = lines.len().saturating_sub(limit);

    for line in lines.get(start..).unwrap_or(&[]) {
        // JSON-lines format: {"t":MS,"l":"level","m":"module","msg":"text"}
        // Simple key extraction (no full JSON parser in kernel).
        let ts = extract_json_u64(line, "\"t\":");
        let level = extract_json_str(line, "\"l\":\"");
        let module = extract_json_str(line, "\"m\":\"");
        let msg = extract_json_str(line, "\"msg\":\"");

        let secs = ts / 1000;
        let ms = ts % 1000;
        shell_println!(
            "[{:5}.{:03}] {}/{}: {}",
            secs, ms, level, module, msg
        );
    }
}

/// Extract a u64 value from a JSON-lines string at the given key prefix.
fn extract_json_u64(line: &str, key: &str) -> u64 {
    if let Some(pos) = line.find(key) {
        let start = pos.saturating_add(key.len());
        let rest = line.get(start..).unwrap_or("");
        let end = rest.find(|c: char| !c.is_ascii_digit()).unwrap_or(rest.len());
        rest.get(..end).and_then(|s| s.parse().ok()).unwrap_or(0)
    } else {
        0
    }
}

/// Extract a string value from a JSON-lines string at the given key prefix.
/// Expects the key prefix to end with `:"`, and reads until the next `"`.
fn extract_json_str<'a>(line: &'a str, key: &str) -> &'a str {
    if let Some(pos) = line.find(key) {
        let start = pos.saturating_add(key.len());
        let rest = line.get(start..).unwrap_or("");
        let end = rest.find('"').unwrap_or(rest.len());
        rest.get(..end).unwrap_or("")
    } else {
        ""
    }
}

fn cmd_echo(args: &str) {
    let mut no_newline = false;
    let mut interpret_escapes = false;
    let mut rest = args;

    // Parse flags: -n (no trailing newline), -e (interpret escapes).
    loop {
        if rest.starts_with("-n ") || rest.starts_with("-n\t") {
            no_newline = true;
            rest = rest.get(3..).unwrap_or("").trim_start();
        } else if rest.starts_with("-e ") || rest.starts_with("-e\t") {
            interpret_escapes = true;
            rest = rest.get(3..).unwrap_or("").trim_start();
        } else if rest.starts_with("-ne ") || rest.starts_with("-en ")
            || rest.starts_with("-ne\t") || rest.starts_with("-en\t") {
            no_newline = true;
            interpret_escapes = true;
            rest = rest.get(4..).unwrap_or("").trim_start();
        } else if rest == "-n" {
            no_newline = true;
            rest = "";
        } else if rest == "-e" {
            interpret_escapes = true;
            rest = "";
        } else {
            break;
        }
    }

    if interpret_escapes {
        let output = interpret_echo_escapes(rest);
        if no_newline {
            shell_print!("{}", output);
        } else {
            shell_println!("{}", output);
        }
    } else if no_newline {
        shell_print!("{}", rest);
    } else {
        shell_println!("{}", rest);
    }
}

/// Interpret C-style escape sequences for `echo -e`.
fn interpret_echo_escapes(s: &str) -> String {
    let mut result = String::with_capacity(s.len());
    let bytes = s.as_bytes();
    let len = bytes.len();
    let mut i = 0;

    while i < len {
        if bytes[i] == b'\\' && i.saturating_add(1) < len {
            let next = bytes[i.saturating_add(1)];
            match next {
                b'n' => { result.push('\n'); i = i.saturating_add(2); }
                b't' => { result.push('\t'); i = i.saturating_add(2); }
                b'r' => { result.push('\r'); i = i.saturating_add(2); }
                b'\\' => { result.push('\\'); i = i.saturating_add(2); }
                b'0' => { result.push('\0'); i = i.saturating_add(2); }
                b'a' => { result.push('\x07'); i = i.saturating_add(2); } // bell
                b'b' => { result.push('\x08'); i = i.saturating_add(2); } // backspace
                _ => { result.push('\\'); i = i.saturating_add(1); }
            }
        } else {
            result.push(bytes[i] as char);
            i = i.saturating_add(1);
        }
    }
    result
}

/// `printf FORMAT [ARG ...]` — formatted output (subset of POSIX printf).
///
/// Supported format specifiers:
///   `%s` — string
///   `%d` / `%i` — signed decimal integer
///   `%u` — unsigned decimal integer
///   `%x` — lowercase hexadecimal
///   `%X` — uppercase hexadecimal
///   `%o` — octal
///   `%c` — first character of argument
///   `%%` — literal percent sign
///   `%0Nd` — zero-padded to N digits (e.g., `%05d`)
///
/// Escape sequences: `\n`, `\t`, `\\`, `\0`.
fn cmd_printf(args: &str) {
    if args.is_empty() {
        crate::console_println!("Usage: printf FORMAT [ARGS...]");
        return;
    }

    // Split format string from arguments.
    // The format string may be quoted.
    let (format, rest) = if args.starts_with('"') {
        // Find closing quote.
        if let Some(end) = args.get(1..).and_then(|s| s.find('"')) {
            let fmt = args.get(1..end.saturating_add(1)).unwrap_or("");
            let rest = args.get(end.saturating_add(2)..).unwrap_or("").trim_start();
            (fmt, rest)
        } else {
            (args.get(1..).unwrap_or(""), "")
        }
    } else if args.starts_with('\'') {
        if let Some(end) = args.get(1..).and_then(|s| s.find('\'')) {
            let fmt = args.get(1..end.saturating_add(1)).unwrap_or("");
            let rest = args.get(end.saturating_add(2)..).unwrap_or("").trim_start();
            (fmt, rest)
        } else {
            (args.get(1..).unwrap_or(""), "")
        }
    } else {
        // Unquoted: first word is the format string.
        let end = args.find(' ').unwrap_or(args.len());
        let fmt = args.get(..end).unwrap_or("");
        let rest = args.get(end..).unwrap_or("").trim_start();
        (fmt, rest)
    };

    // Parse arguments (space-separated, quote-aware).
    let arg_list = split_words(rest);
    let mut arg_iter = arg_list.iter();

    // Process format string.
    let mut chars = format.chars().peekable();
    while let Some(ch) = chars.next() {
        if ch == '\\' {
            // Escape sequence.
            match chars.next() {
                Some('n') => shell_print!("\n"),
                Some('t') => shell_print!("\t"),
                Some('\\') => shell_print!("\\"),
                Some('0') => shell_print!("\0"),
                Some(c) => shell_print!("\\{}", c),
                None => shell_print!("\\"),
            }
        } else if ch == '%' {
            // Format specifier.
            // Check for flags: zero-padding and width.
            let mut zero_pad = false;
            let mut width: usize = 0;

            if chars.peek() == Some(&'0') {
                zero_pad = true;
                chars.next();
            }
            while chars.peek().is_some_and(|c| c.is_ascii_digit()) {
                if let Some(d) = chars.next() {
                    width = width.saturating_mul(10).saturating_add(
                        (d as u8).saturating_sub(b'0') as usize,
                    );
                }
            }

            match chars.next() {
                Some('s') => {
                    let arg = arg_iter.next().map(|s| s.as_str()).unwrap_or("");
                    if width > 0 {
                        shell_print!("{:>width$}", arg, width = width);
                    } else {
                        shell_print!("{}", arg);
                    }
                }
                Some('d') | Some('i') => {
                    let arg = arg_iter.next().map(|s| s.as_str()).unwrap_or("0");
                    let val: i64 = arg.parse().unwrap_or(0);
                    if zero_pad && width > 0 {
                        shell_print!("{:0>width$}", val, width = width);
                    } else if width > 0 {
                        shell_print!("{:>width$}", val, width = width);
                    } else {
                        shell_print!("{}", val);
                    }
                }
                Some('u') => {
                    let arg = arg_iter.next().map(|s| s.as_str()).unwrap_or("0");
                    let val: u64 = arg.parse().unwrap_or(0);
                    if zero_pad && width > 0 {
                        shell_print!("{:0>width$}", val, width = width);
                    } else if width > 0 {
                        shell_print!("{:>width$}", val, width = width);
                    } else {
                        shell_print!("{}", val);
                    }
                }
                Some('x') => {
                    let arg = arg_iter.next().map(|s| s.as_str()).unwrap_or("0");
                    let val: u64 = arg.parse().unwrap_or(0);
                    if zero_pad && width > 0 {
                        shell_print!("{:0>width$x}", val, width = width);
                    } else {
                        shell_print!("{:x}", val);
                    }
                }
                Some('X') => {
                    let arg = arg_iter.next().map(|s| s.as_str()).unwrap_or("0");
                    let val: u64 = arg.parse().unwrap_or(0);
                    if zero_pad && width > 0 {
                        shell_print!("{:0>width$X}", val, width = width);
                    } else {
                        shell_print!("{:X}", val);
                    }
                }
                Some('o') => {
                    let arg = arg_iter.next().map(|s| s.as_str()).unwrap_or("0");
                    let val: u64 = arg.parse().unwrap_or(0);
                    if zero_pad && width > 0 {
                        shell_print!("{:0>width$o}", val, width = width);
                    } else {
                        shell_print!("{:o}", val);
                    }
                }
                Some('c') => {
                    let arg = arg_iter.next().map(|s| s.as_str()).unwrap_or("");
                    if let Some(c) = arg.chars().next() {
                        shell_print!("{}", c);
                    }
                }
                Some('%') => shell_print!("%"),
                Some(c) => shell_print!("%{}", c),
                None => shell_print!("%"),
            }
        } else {
            shell_print!("{}", ch);
        }
    }
}

/// Display the current date/time with optional format string.
///
/// Usage: `date` (default: YYYY-MM-DD HH:MM:SS)
///        `date +FORMAT` (strftime-like: %Y %m %d %H %M %S %a %A %b %B %j %u %Z)
///
/// Supported format specifiers:
/// - `%Y` 4-digit year, `%m` month (01-12), `%d` day (01-31)
/// - `%H` hour (00-23), `%M` minute (00-59), `%S` second (00-59)
/// - `%a` abbreviated weekday (Sun..Sat), `%A` full weekday
/// - `%b`/`%h` abbreviated month (Jan..Dec), `%B` full month name
/// - `%j` day of year (001-366), `%u` ISO weekday (1=Mon..7=Sun)
/// - `%Z` timezone (always "UTC"), `%n` newline, `%t` tab, `%%` literal %
/// - `%F` = `%Y-%m-%d`, `%T` = `%H:%M:%S`, `%D` = `%m/%d/%Y`
/// - `%s` epoch seconds
#[allow(clippy::arithmetic_side_effects, clippy::cast_possible_truncation)]
fn cmd_date(args: &str) {
    // Use timekeeping (TSC-based) instead of slow CMOS I/O reads.
    let dt = crate::timekeeping::now();

    if args.is_empty() {
        // Default output: YYYY-MM-DD HH:MM:SS
        shell_println!("{}", dt);
        return;
    }

    let fmt = if let Some(f) = args.strip_prefix('+') {
        f
    } else {
        crate::console_println!("Usage: date [+FORMAT]");
        set_exit(1);
        return;
    };

    // Day-of-week via Tomohiko Sakamoto's algorithm.
    let dow = {
        let mut y = i32::from(dt.year);
        let m = dt.month as usize;
        let d = i32::from(dt.day);
        const T: [i32; 12] = [0, 3, 2, 5, 0, 3, 5, 1, 4, 6, 2, 4];
        if m < 3 { y -= 1; }
        let idx = if m >= 1 && m <= 12 { T[m - 1] } else { 0 };
        ((y + y / 4 - y / 100 + y / 400 + idx + d) % 7) as u8 // 0=Sun
    };

    // Day of year (1-based).
    let is_leap = {
        let y = u32::from(dt.year);
        (y % 4 == 0 && y % 100 != 0) || y % 400 == 0
    };
    let month_days: [u16; 12] = [
        0, 31, 59, 90, 120, 151, 181, 212, 243, 273, 304, 334,
    ];
    let mi = if dt.month >= 1 && dt.month <= 12 {
        (dt.month - 1) as usize
    } else {
        0
    };
    let mut yday = month_days[mi] + u16::from(dt.day);
    if is_leap && dt.month > 2 {
        yday += 1;
    }

    // Epoch seconds (approximate — good enough for display).
    let epoch_secs = {
        let y = i64::from(dt.year);
        // Days from 1970-01-01 to Jan 1 of this year (approx).
        let mut days: i64 = (y - 1970) * 365 + (y - 1969) / 4 - (y - 1901) / 100 + (y - 1601) / 400;
        days += i64::from(yday) - 1; // yday is 1-based
        days * 86400 + i64::from(dt.hour) * 3600 + i64::from(dt.minute) * 60 + i64::from(dt.second)
    };

    const DAY_ABBR: [&str; 7] = ["Sun", "Mon", "Tue", "Wed", "Thu", "Fri", "Sat"];
    const DAY_FULL: [&str; 7] = [
        "Sunday", "Monday", "Tuesday", "Wednesday", "Thursday", "Friday", "Saturday",
    ];
    const MON_ABBR: [&str; 12] = [
        "Jan", "Feb", "Mar", "Apr", "May", "Jun",
        "Jul", "Aug", "Sep", "Oct", "Nov", "Dec",
    ];
    const MON_FULL: [&str; 12] = [
        "January", "February", "March", "April", "May", "June",
        "July", "August", "September", "October", "November", "December",
    ];

    let mut out = alloc::string::String::with_capacity(fmt.len() + 32);
    let bytes = fmt.as_bytes();
    let mut i = 0;
    while i < bytes.len() {
        if bytes[i] == b'%' && i + 1 < bytes.len() {
            i += 1;
            match bytes[i] {
                b'Y' => out.push_str(&alloc::format!("{:04}", dt.year)),
                b'm' => out.push_str(&alloc::format!("{:02}", dt.month)),
                b'd' => out.push_str(&alloc::format!("{:02}", dt.day)),
                b'H' => out.push_str(&alloc::format!("{:02}", dt.hour)),
                b'M' => out.push_str(&alloc::format!("{:02}", dt.minute)),
                b'S' => out.push_str(&alloc::format!("{:02}", dt.second)),
                b'a' => out.push_str(DAY_ABBR[dow as usize % 7]),
                b'A' => out.push_str(DAY_FULL[dow as usize % 7]),
                b'b' | b'h' => {
                    let idx = if dt.month >= 1 && dt.month <= 12 {
                        (dt.month - 1) as usize
                    } else {
                        0
                    };
                    out.push_str(MON_ABBR[idx]);
                }
                b'B' => {
                    let idx = if dt.month >= 1 && dt.month <= 12 {
                        (dt.month - 1) as usize
                    } else {
                        0
                    };
                    out.push_str(MON_FULL[idx]);
                }
                b'j' => out.push_str(&alloc::format!("{:03}", yday)),
                b'u' => {
                    // ISO weekday: Mon=1..Sun=7.  dow 0=Sun → 7.
                    let iso = if dow == 0 { 7 } else { dow };
                    out.push_str(&alloc::format!("{}", iso));
                }
                b'Z' => out.push_str("UTC"),
                b'n' => out.push('\n'),
                b't' => out.push('\t'),
                b'%' => out.push('%'),
                b'F' => out.push_str(&alloc::format!(
                    "{:04}-{:02}-{:02}", dt.year, dt.month, dt.day
                )),
                b'T' => out.push_str(&alloc::format!(
                    "{:02}:{:02}:{:02}", dt.hour, dt.minute, dt.second
                )),
                b'D' => out.push_str(&alloc::format!(
                    "{:02}/{:02}/{:04}", dt.month, dt.day, dt.year
                )),
                b's' => out.push_str(&alloc::format!("{}", epoch_secs)),
                _ => {
                    out.push('%');
                    out.push(bytes[i] as char);
                }
            }
        } else {
            out.push(bytes[i] as char);
        }
        i += 1;
    }
    shell_println!("{}", out);
}

/// Time the execution of a shell command.
///
/// Usage: `time <command>` — runs the command and prints elapsed wall time.
/// Uses HPET for nanosecond-resolution timing when available, falling back
/// to APIC tick counter (~10ms resolution).
fn cmd_time_cmd(args: &str) {
    if args.is_empty() {
        // No command — just show current time (legacy compat).
        let dt = crate::rtc::read_datetime();
        shell_println!("{}", dt);
        return;
    }

    let start_ns = crate::hpet::elapsed_ns();
    execute_single(args);
    let end_ns = crate::hpet::elapsed_ns();

    let elapsed_ns = end_ns.saturating_sub(start_ns);
    let secs = elapsed_ns / 1_000_000_000;
    let ms = (elapsed_ns % 1_000_000_000) / 1_000_000;
    let us = (elapsed_ns % 1_000_000) / 1_000;

    if secs > 0 {
        crate::console_println!("\nreal\t{}m{}.{:03}s", secs / 60, secs % 60, ms);
    } else if ms > 0 {
        crate::console_println!("\nreal\t0m0.{:03}s", ms);
    } else {
        crate::console_println!("\nreal\t{}us", us);
    }
}

/// Show the number of available CPUs.
fn cmd_nproc() {
    shell_println!("{}", crate::smp::cpu_count());
}

/// Extract printable ASCII strings from a file.
///
/// Usage: `strings [-n MIN] <file>`
///
/// Scans the file for runs of printable ASCII characters (0x20..0x7E plus
/// tab and newline).  Prints each run that meets the minimum length
/// (default 4, matching Unix `strings`).  Useful for inspecting binary
/// files, ELF executables, and firmware images.
#[allow(clippy::arithmetic_side_effects)]
fn cmd_strings(args: &str) {
    let mut min_len: usize = 4;
    let mut path_arg = "";

    let mut words = args.split_whitespace();
    while let Some(w) = words.next() {
        if w == "-n" {
            if let Some(n_str) = words.next() {
                min_len = n_str.parse::<usize>().unwrap_or(4);
            }
        } else if let Some(n_str) = w.strip_prefix("-n") {
            min_len = n_str.parse::<usize>().unwrap_or(4);
        } else {
            path_arg = w;
        }
    }

    if path_arg.is_empty() {
        crate::console_println!("Usage: strings [-n MIN] <file>");
        set_exit(1);
        return;
    }

    let path = resolve_path(path_arg);
    let data = match crate::fs::Vfs::read_file(&path) {
        Ok(d) => d,
        Err(e) => {
            crate::console_println!("strings: {}: {:?}", path, e);
            set_exit(1);
            return;
        }
    };

    let mut current = alloc::string::String::new();
    for &b in &data {
        if (b >= 0x20 && b <= 0x7E) || b == b'\t' {
            current.push(b as char);
        } else {
            if current.len() >= min_len {
                crate::console_println!("{}", current);
            }
            current.clear();
        }
    }
    // Flush trailing run.
    if current.len() >= min_len {
        crate::console_println!("{}", current);
    }
}

/// Format text into aligned columns.
///
/// Usage: `column [-t] [-s SEP]` (reads from file or pipe)
///
/// `-t` — format into a table (auto-detect columns based on whitespace)
/// `-s CHAR` — use CHAR as the delimiter (default: whitespace)
///
/// Without `-t`, merges short lines into side-by-side columns filling
/// the terminal width.
fn cmd_column(args: &str) {
    if args.is_empty() {
        crate::console_println!("Usage: column [-t] [-s SEP] <file>");
        crate::console_println!("   or: ... | column -t");
        set_exit(1);
        return;
    }

    // Parse flags.
    let mut table_mode = false;
    let mut sep: Option<char> = None;
    let mut file_path = "";

    let mut words = args.split_whitespace().peekable();
    while let Some(w) = words.next() {
        if w == "-t" {
            table_mode = true;
        } else if w == "-s" {
            if let Some(s) = words.next() {
                sep = s.chars().next();
            }
        } else {
            file_path = w;
        }
    }

    if file_path.is_empty() {
        crate::console_println!("column: no input file");
        set_exit(1);
        return;
    }

    let path = resolve_path(file_path);
    let data = match crate::fs::Vfs::read_file(&path) {
        Ok(d) => d,
        Err(e) => {
            crate::console_println!("column: {}: {:?}", path, e);
            set_exit(1);
            return;
        }
    };
    let text = alloc::string::String::from_utf8_lossy(&data);
    column_format(&text, table_mode, sep);
}

/// column from piped input.
fn cmd_column_input(args: &str, input: &str) {
    if input.is_empty() && args.is_empty() {
        crate::console_println!("Usage: ... | column [-t] [-s SEP]");
        set_exit(1);
        return;
    }

    let mut table_mode = false;
    let mut sep: Option<char> = None;
    let mut file_path = "";

    let mut words = args.split_whitespace().peekable();
    while let Some(w) = words.next() {
        if w == "-t" {
            table_mode = true;
        } else if w == "-s" {
            if let Some(s) = words.next() {
                sep = s.chars().next();
            }
        } else {
            file_path = w;
        }
    }

    // If a file was specified, read from it; otherwise use piped input.
    if !file_path.is_empty() {
        let path = resolve_path(file_path);
        let data = match crate::fs::Vfs::read_file(&path) {
            Ok(d) => d,
            Err(e) => {
                crate::console_println!("column: {}: {:?}", path, e);
                set_exit(1);
                return;
            }
        };
        let text = alloc::string::String::from_utf8_lossy(&data);
        column_format(&text, table_mode, sep);
    } else {
        column_format(input, table_mode, sep);
    }
}

/// Core column formatting: split lines into columns and align.
#[allow(clippy::arithmetic_side_effects)]
fn column_format(text: &str, table_mode: bool, sep: Option<char>) {
    let lines: alloc::vec::Vec<&str> = text.lines().collect();
    if lines.is_empty() {
        return;
    }

    if table_mode {
        // Split each line into fields, compute max width per column,
        // then print left-aligned with 2-space padding.
        let rows: alloc::vec::Vec<alloc::vec::Vec<&str>> = lines
            .iter()
            .map(|line| {
                if let Some(c) = sep {
                    line.split(c).collect()
                } else {
                    line.split_whitespace().collect()
                }
            })
            .collect();

        // Find max columns and per-column max width.
        let max_cols = rows.iter().map(|r| r.len()).max().unwrap_or(0);
        let mut widths = alloc::vec![0usize; max_cols];
        for row in &rows {
            for (i, field) in row.iter().enumerate() {
                if field.len() > widths[i] {
                    widths[i] = field.len();
                }
            }
        }

        for row in &rows {
            let mut out = alloc::string::String::new();
            for (i, field) in row.iter().enumerate() {
                if i > 0 {
                    out.push_str("  ");
                }
                out.push_str(field);
                // Pad to column width (except for the last column).
                if i + 1 < row.len() {
                    let pad = widths[i].saturating_sub(field.len());
                    for _ in 0..pad {
                        out.push(' ');
                    }
                }
            }
            crate::console_println!("{}", out);
        }
    } else {
        // Simple mode: print lines as-is (no table formatting).
        // A full implementation would fill the terminal width, but
        // without terminal width info we just print each line.
        for line in &lines {
            crate::console_println!("{}", line);
        }
    }
}

/// Display a monthly calendar.
///
/// Usage: `cal` (current month), `cal MONTH YEAR`, or `cal YEAR`.
/// Uses Tomohiko Sakamoto's day-of-week algorithm for the 1st of the
/// month, then prints a standard 7-column grid (Su Mo Tu We Th Fr Sa)
/// with today highlighted by brackets.
///
/// Reference: Unix cal(1).
#[allow(clippy::arithmetic_side_effects, clippy::cast_possible_truncation)]
fn cmd_cal(args: &str) {
    let dt = crate::rtc::read_datetime();
    let trimmed = args.trim();

    let (month, year) = if trimmed.is_empty() {
        // No arguments — show current month.
        (u32::from(dt.month), u32::from(dt.year))
    } else {
        let parts: alloc::vec::Vec<&str> = trimmed.split_whitespace().collect();
        match parts.len() {
            1 => {
                // Single argument: either a year (>12) or month (1-12).
                if let Ok(v) = parts[0].parse::<u32>() {
                    if v >= 1 && v <= 12 {
                        (v, u32::from(dt.year))
                    } else if v >= 1970 && v <= 9999 {
                        // Show just one month — default to current month.
                        (u32::from(dt.month), v)
                    } else {
                        crate::console_println!("Usage: cal [MONTH] [YEAR]");
                        set_exit(1);
                        return;
                    }
                } else {
                    crate::console_println!("Usage: cal [MONTH] [YEAR]");
                    set_exit(1);
                    return;
                }
            }
            2 => {
                let m = parts[0].parse::<u32>().unwrap_or(0);
                let y = parts[1].parse::<u32>().unwrap_or(0);
                if m < 1 || m > 12 || y < 1 || y > 9999 {
                    crate::console_println!("Usage: cal [MONTH (1-12)] [YEAR (1-9999)]");
                    set_exit(1);
                    return;
                }
                (m, y)
            }
            _ => {
                crate::console_println!("Usage: cal [MONTH] [YEAR]");
                set_exit(1);
                return;
            }
        }
    };

    // Month names.
    let month_names = [
        "January", "February", "March", "April", "May", "June",
        "July", "August", "September", "October", "November", "December",
    ];
    let mname = month_names.get((month - 1) as usize).unwrap_or(&"???");

    // Header: centered month and year over the 20-char-wide grid.
    let header = alloc::format!("{} {}", mname, year);
    // The grid is 20 characters wide (Su Mo Tu .. Sa).
    let pad = if header.len() < 20 {
        (20 - header.len()) / 2
    } else {
        0
    };
    shell_println!("{:>width$}{}", "", header, width = pad);
    shell_println!("Su Mo Tu We Th Fr Sa");

    // Days in month.
    let dim = days_in_month(year, month);

    // Day of the week for the 1st of this month.
    // Tomohiko Sakamoto's algorithm: returns 0=Sunday, 1=Monday, ..., 6=Saturday.
    let dow1 = day_of_week(year, month, 1);

    // Is this the current month? (for highlighting today.)
    let is_current = year == u32::from(dt.year) && month == u32::from(dt.month);
    let today = u32::from(dt.day);

    // Build each day cell as a fixed 2-character string, then join
    // with single spaces (3 chars per cell: "DD ").  This avoids
    // alignment issues with highlighted-today markers.
    //
    // Standard cal(1) format: each day is right-justified in a
    // 2-char field, separated by single spaces.

    // Print leading blanks for the first week.
    for _ in 0..dow1 {
        shell_print!("   ");
    }

    let mut col = dow1;
    for day in 1..=dim {
        let highlight = is_current && day == today;
        if highlight {
            // Highlight today with an asterisk suffix.  We replace the
            // trailing space with '*' so alignment is preserved.
            shell_print!("{:2}*", day);
        } else if col < 6 || day < dim {
            shell_print!("{:2} ", day);
        } else {
            // Last column or last day — no trailing space.
            shell_print!("{:2}", day);
        }

        col += 1;
        if col == 7 {
            shell_println!("");
            col = 0;
        }
    }

    // Final newline if we didn't just print one.
    if col != 0 {
        shell_println!("");
    }
}

/// Number of days in a given month (1-12) of a given year.
#[allow(clippy::arithmetic_side_effects)]
fn days_in_month(year: u32, month: u32) -> u32 {
    match month {
        1 | 3 | 5 | 7 | 8 | 10 | 12 => 31,
        4 | 6 | 9 | 11 => 30,
        2 => {
            if (year.is_multiple_of(4) && !year.is_multiple_of(100)) || year.is_multiple_of(400) {
                29
            } else {
                28
            }
        }
        _ => 30, // Shouldn't happen with validated input.
    }
}

/// Day of the week for a given date (0=Sunday, 1=Monday, ..., 6=Saturday).
///
/// Tomohiko Sakamoto's algorithm.  Works for any Gregorian date with
/// year ≥ 1.
#[allow(clippy::arithmetic_side_effects)]
fn day_of_week(year: u32, month: u32, day: u32) -> u32 {
    // Lookup table for month offset.
    let t: [u32; 12] = [0, 3, 2, 5, 0, 3, 5, 1, 4, 6, 2, 4];
    let y = if month < 3 { year - 1 } else { year };
    let m = month as usize;
    (y + y / 4 - y / 100 + y / 400 + t[m - 1] + day) % 7
}

// PCI device class/subclass descriptions and bar formatting use simple
// fixed-width arithmetic on small known values.
#[allow(clippy::arithmetic_side_effects)]
fn cmd_pci() {
    let devices = crate::pci::scan_bus0();
    if devices.is_empty() {
        crate::console_println!("No PCI devices found.");
        return;
    }

    for dev in &devices {
        let desc = crate::pciids::describe(
            dev.vendor_id,
            dev.device_id,
            dev.class,
            dev.subclass,
        );
        crate::console_println!(
            "{:02x}:{:02x}.{} {:04x}:{:04x} {} (IRQ {})",
            dev.address.bus,
            dev.address.device,
            dev.address.function,
            dev.vendor_id,
            dev.device_id,
            desc,
            dev.irq_line,
        );
    }
    crate::console_println!("{} device(s)", devices.len());
}

// Sector formatting uses small arithmetic on known-bounded values.
#[allow(clippy::arithmetic_side_effects)]
fn cmd_disk() {
    let devices = crate::blkdev::list_devices_full();
    if devices.is_empty() {
        crate::console_println!("No block devices registered.");
        return;
    }
    crate::console_println!("Block devices:");
    for dev in &devices {
        let kib = dev.sector_count.saturating_mul(u64::from(dev.sector_size)) / 1024;
        let mib = kib / 1024;
        crate::console_println!(
            "  {} — {} sectors ({} KiB / {} MiB){}",
            dev.name,
            dev.sector_count,
            kib,
            mib,
            if dev.read_only { " [read-only]" } else { "" }
        );
    }
}

// Hex-dump formatting uses offsets bounded by SECTOR_SIZE (512).
#[allow(clippy::arithmetic_side_effects)]
fn cmd_blkread(args: &str) {
    // Parse: "blkread <sector>" or "blkread <device> <sector>"
    let (dev_name, sector) = parse_blkread_args(args);
    let Some(sector) = sector else {
        crate::console_println!("Usage: blkread [device] <sector>");
        crate::console_println!("  e.g., blkread 0  or  blkread vda 0");
        return;
    };

    let result = crate::blkdev::with_device(&dev_name, |dev| {
        let mut buf = [0u8; crate::blkdev::SECTOR_SIZE];
        match dev.read_sector(sector, &mut buf) {
            Ok(()) => {
                crate::console_println!("Sector {} on {}:", sector, dev_name);
                // Print 32 rows of 16 bytes each (512 bytes total).
                for row in 0..32 {
                    let offset = row * 16;
                    crate::console_print!("  {:04x}:", offset);
                    for col in 0..16 {
                        if let Some(&byte) = buf.get(offset + col) {
                            crate::console_print!(" {:02x}", byte);
                        }
                    }
                    // ASCII column.
                    crate::console_print!("  |");
                    for col in 0..16 {
                        if let Some(&byte) = buf.get(offset + col) {
                            let ch = if byte >= 0x20 && byte < 0x7F {
                                byte as char
                            } else {
                                '.'
                            };
                            crate::console_print!("{}", ch);
                        }
                    }
                    crate::console_println!("|");
                }
            }
            Err(e) => {
                crate::console_println!("Error reading sector {}: {:?}", sector, e);
            }
        }
    });
    if result.is_none() {
        crate::console_println!("No block device '{}' found.", dev_name);
    }
}

/// Parse blkread args: either "<sector>" or "<device> <sector>".
/// Returns (device_name, Some(sector)) or (_, None) on parse error.
fn parse_blkread_args(args: &str) -> (alloc::string::String, Option<u64>) {
    let mut parts = args.split_whitespace();
    let first = match parts.next() {
        Some(s) => s,
        None => return (alloc::string::String::from("vda"), None),
    };

    if let Some(second) = parts.next() {
        // Two args: device name + sector
        match second.parse::<u64>() {
            Ok(s) => (alloc::string::String::from(first), Some(s)),
            Err(_) => (alloc::string::String::from("vda"), None),
        }
    } else {
        // One arg: try as sector number (default device "vda")
        match first.parse::<u64>() {
            Ok(s) => (alloc::string::String::from("vda"), Some(s)),
            Err(_) => (alloc::string::String::from("vda"), None),
        }
    }
}

/// Format an octal permission mode as a `rwxrwxrwx` string.
fn format_perms(perms: u16) -> [u8; 9] {
    let mut out = [b'-'; 9];
    if perms & 0o400 != 0 { out[0] = b'r'; }
    if perms & 0o200 != 0 { out[1] = b'w'; }
    if perms & 0o100 != 0 { out[2] = b'x'; }
    if perms & 0o040 != 0 { out[3] = b'r'; }
    if perms & 0o020 != 0 { out[4] = b'w'; }
    if perms & 0o010 != 0 { out[5] = b'x'; }
    if perms & 0o004 != 0 { out[6] = b'r'; }
    if perms & 0o002 != 0 { out[7] = b'w'; }
    if perms & 0o001 != 0 { out[8] = b'x'; }
    out
}

/// Format a byte count as a human-readable string (K/M/G).
fn format_size_human(size: u64) -> String {
    if size >= 1_073_741_824 {
        alloc::format!("{:.1}G", size as f64 / 1_073_741_824.0)
    } else if size >= 1_048_576 {
        alloc::format!("{:.1}M", size as f64 / 1_048_576.0)
    } else if size >= 1024 {
        alloc::format!("{:.1}K", size as f64 / 1024.0)
    } else {
        alloc::format!("{}", size)
    }
}

fn cmd_ls(args: &str) {
    // Parse flags and path.
    let mut long_format = false;
    let mut show_all = false;
    let mut human_sizes = false;
    let mut recursive = false;
    let mut sort_by_size = false;
    let mut sort_by_time = false;
    let mut reverse_sort = false;
    let mut path_arg = "";

    for token in args.split_whitespace() {
        if let Some(flags) = token.strip_prefix('-') {
            for ch in flags.chars() {
                match ch {
                    'l' => long_format = true,
                    'a' => show_all = true,
                    'h' => human_sizes = true,
                    'R' => recursive = true,
                    'S' => sort_by_size = true,
                    't' => sort_by_time = true,
                    'r' => reverse_sort = true,
                    _ => {
                        crate::console_println!("ls: unknown option -{}", ch);
                        set_exit(1);
                        return;
                    }
                }
            }
        } else {
            path_arg = token;
        }
    }

    let path = if path_arg.is_empty() {
        get_cwd()
    } else {
        resolve_path(path_arg)
    };

    ls_list_dir(
        &path, long_format, show_all, human_sizes,
        sort_by_size, sort_by_time, reverse_sort,
        recursive, 0,
    );
}

/// Internal helper for ls: list one directory and optionally recurse.
///
/// `depth` guards against infinite recursion (e.g., symlink loops);
/// maximum depth is 32.
#[allow(clippy::too_many_arguments)]
fn ls_list_dir(
    path: &str,
    long_format: bool,
    show_all: bool,
    human_sizes: bool,
    sort_by_size: bool,
    sort_by_time: bool,
    reverse_sort: bool,
    recursive: bool,
    depth: u32,
) {
    if depth > 32 {
        crate::console_println!("ls: recursion limit reached");
        return;
    }

    // When recursing, print the directory name as a header.
    if recursive && depth > 0 {
        shell_println!("");
        shell_println!("{}:", path);
    }

    let entries = match crate::fs::Vfs::readdir(path) {
        Ok(e) => e,
        Err(e) => {
            crate::console_println!("ls: {}: {:?}", path, e);
            set_exit(1);
            return;
        }
    };

    if entries.is_empty() {
        shell_println!("(empty directory)");
        if !recursive { return; }
    }

    // Filter hidden files unless -a is given.
    let mut filtered: Vec<crate::fs::vfs::DirEntry> = entries
        .into_iter()
        .filter(|e| show_all || !e.name.starts_with('.'))
        .collect();

    // Apply sorting.  Sorting requires metadata lookups.
    if sort_by_size {
        filtered.sort_by_key(|e| core::cmp::Reverse(e.size));
    } else if sort_by_time {
        // Sort by modification time (most recent first).
        // We need to look up metadata for each entry.
        let mut with_mtime: Vec<(crate::fs::vfs::DirEntry, u64)> = filtered
            .into_iter()
            .map(|e| {
                let fp = if path == "/" {
                    alloc::format!("/{}", e.name)
                } else {
                    alloc::format!("{}/{}", path, e.name)
                };
                let mtime = crate::fs::Vfs::metadata(&fp)
                    .map(|m| m.modified_ns)
                    .unwrap_or(0);
                (e, mtime)
            })
            .collect();
        with_mtime.sort_by_key(|e| core::cmp::Reverse(e.1));
        filtered = with_mtime.into_iter().map(|(e, _)| e).collect();
    }

    if reverse_sort {
        filtered.reverse();
    }

    if long_format {
        // Long format: type+perms links uid gid size date name
        // First pass: gather metadata and compute total blocks.
        let mut total_blocks: u64 = 0;
        let mut metas: Vec<Option<crate::fs::vfs::FileMeta>> =
            Vec::with_capacity(filtered.len());

        for entry in &filtered {
            let full_path = if path == "/" {
                alloc::format!("/{}", entry.name)
            } else {
                alloc::format!("{}/{}", path, entry.name)
            };
            if let Ok(meta) = crate::fs::Vfs::metadata(&full_path) {
                total_blocks = total_blocks.saturating_add(meta.blocks);
                metas.push(Some(meta));
            } else {
                metas.push(None);
            }
        }

        shell_println!("total {}", total_blocks);

        for (i, entry) in filtered.iter().enumerate() {
            let type_ch = match entry.entry_type {
                crate::fs::EntryType::Directory => 'd',
                crate::fs::EntryType::File => '-',
                crate::fs::EntryType::Symlink => 'l',
                crate::fs::EntryType::VolumeLabel => 'v',
            };

            if let Some(Some(meta)) = metas.get(i) {
                let perms = format_perms(meta.permissions);
                let perm_str = core::str::from_utf8(&perms).unwrap_or("---------");

                let size_str = if human_sizes {
                    format_size_human(meta.size)
                } else {
                    alloc::format!("{}", meta.size)
                };

                // Format modification time as YYYY-MM-DD HH:MM:SS.
                let time_str = if meta.modified_ns > 0 {
                    format_epoch_ns(meta.modified_ns)
                } else {
                    String::from("-")
                };

                // For symlinks, show " -> target".
                let suffix = if entry.entry_type == crate::fs::EntryType::Symlink {
                    let full_path = if path == "/" {
                        alloc::format!("/{}", entry.name)
                    } else {
                        alloc::format!("{}/{}", path, entry.name)
                    };
                    match crate::fs::Vfs::readlink(&full_path) {
                        Ok(target) => alloc::format!(" -> {}", target),
                        Err(_) => String::new(),
                    }
                } else {
                    String::new()
                };

                shell_println!(
                    "{}{} {:>3} {:>5} {:>5} {:>8} {} {}{}",
                    type_ch, perm_str, meta.nlinks,
                    meta.uid, meta.gid, size_str,
                    time_str, entry.name, suffix,
                );
            } else {
                // Metadata unavailable — basic listing.
                let size_str = if human_sizes {
                    format_size_human(entry.size)
                } else {
                    alloc::format!("{}", entry.size)
                };
                shell_println!(
                    "{}--------- {:>3} {:>5} {:>5} {:>8}            {}",
                    type_ch, 1, 0, 0, size_str, entry.name,
                );
            }
        }
    } else {
        // Default format (original behavior).
        for entry in &filtered {
            let type_indicator = match entry.entry_type {
                crate::fs::EntryType::Directory => "<DIR>    ",
                crate::fs::EntryType::File => "         ",
                crate::fs::EntryType::Symlink => "<LINK>   ",
                crate::fs::EntryType::VolumeLabel => "<VOL>    ",
            };
            let size_str = if human_sizes {
                alloc::format!("{:>8}", format_size_human(entry.size))
            } else {
                alloc::format!("{:>8}", entry.size)
            };
            shell_println!(
                "  {} {}  {}",
                type_indicator, size_str, entry.name
            );
        }
    }
    shell_println!("{} entry(ies)", filtered.len());

    // Recurse into subdirectories for -R.
    if recursive {
        for entry in &filtered {
            if entry.entry_type == crate::fs::EntryType::Directory
                && entry.name != "." && entry.name != ".."
            {
                let child_path = if path == "/" {
                    alloc::format!("/{}", entry.name)
                } else {
                    alloc::format!("{}/{}", path, entry.name)
                };
                ls_list_dir(
                    &child_path, long_format, show_all, human_sizes,
                    sort_by_size, sort_by_time, reverse_sort,
                    recursive, depth + 1,
                );
            }
        }
    }
}

fn cmd_cat(args: &str) {
    if args.is_empty() {
        crate::console_println!("Usage: cat <filename>");
        return;
    }

    let path = resolve_path(args);

    match crate::fs::Vfs::read_file(&path) {
        Ok(data) => {
            // Try to display as UTF-8 text.
            match core::str::from_utf8(&data) {
                Ok(text) => {
                    shell_print!("{}", text);
                    // Ensure there's a newline at the end.
                    if !text.ends_with('\n') {
                        shell_println!();
                    }
                }
                Err(_) => {
                    shell_println!(
                        "(binary file, {} bytes — use blkread for hex dump)",
                        data.len()
                    );
                }
            }
        }
        Err(e) => {
            crate::console_println!("cat: {}: {:?}", path, e);
            set_exit(1);
        }
    }
}

fn cmd_write(args: &str) {
    // Parse: "write FILENAME text to write..."
    let mut parts = args.splitn(2, ' ');
    let filename = match parts.next() {
        Some(f) if !f.is_empty() => f,
        _ => {
            crate::console_println!("Usage: write <filename> <text>");
            return;
        }
    };
    let text = parts.next().unwrap_or("");
    let path = resolve_path(filename);

    // Append a newline if the text doesn't have one.
    let mut data = alloc::vec::Vec::from(text.as_bytes());
    if !text.ends_with('\n') {
        data.push(b'\n');
    }

    match crate::fs::Vfs::write_file(&path, &data) {
        Ok(()) => {
            crate::console_println!("Wrote {} bytes to {}", data.len(), path);
        }
        Err(e) => {
            crate::console_println!("write: {}: {:?}", path, e);
            set_exit(1);
        }
    }
}

fn cmd_rm(args: &str) {
    // Support -r/-R flag for recursive removal.
    let (recursive, args) = if args.starts_with("-r ") || args.starts_with("-R ")
        || args.starts_with("-rf ") || args.starts_with("-Rf ")
    {
        let skip = if args.starts_with("-rf") || args.starts_with("-Rf") { 4 } else { 3 };
        (true, &args[skip..])
    } else {
        (false, args)
    };

    if args.is_empty() {
        crate::console_println!("Usage: rm [-r] <filename>");
        return;
    }

    let path = resolve_path(args);

    if recursive {
        match crate::fs::Vfs::remove_recursive(&path) {
            Ok(count) => {
                crate::console_println!("Removed {} ({} items)", path, count);
            }
            Err(e) => {
                crate::console_println!("rm: {}: {:?}", path, e);
                set_exit(1);
            }
        }
    } else {
        match crate::fs::Vfs::remove(&path) {
            Ok(()) => {
                crate::console_println!("Deleted {}", path);
            }
            Err(e) => {
                crate::console_println!("rm: {}: {:?}", path, e);
                set_exit(1);
            }
        }
    }
}

fn cmd_mkdir(args: &str) {
    if args.is_empty() {
        crate::console_println!("Usage: mkdir [-p] <dirname>");
        return;
    }

    // Parse -p flag for recursive creation.
    let (recursive, dir_arg) = if args.starts_with("-p ") {
        (true, args.get(3..).unwrap_or("").trim())
    } else if args == "-p" {
        crate::console_println!("Usage: mkdir [-p] <dirname>");
        return;
    } else {
        (false, args)
    };

    let path = resolve_path(dir_arg);

    let result = if recursive {
        crate::fs::Vfs::mkdir_all(&path)
    } else {
        crate::fs::Vfs::mkdir(&path)
    };

    match result {
        Ok(()) => {
            crate::console_println!("Created directory {}", path);
        }
        Err(e) => {
            crate::console_println!("mkdir: {}: {:?}", path, e);
            set_exit(1);
        }
    }
}

fn cmd_rmdir(args: &str) {
    if args.is_empty() {
        crate::console_println!("Usage: rmdir <dirname>");
        return;
    }

    let path = resolve_path(args);

    match crate::fs::Vfs::rmdir(&path) {
        Ok(()) => {
            crate::console_println!("Removed directory {}", path);
        }
        Err(e) => {
            crate::console_println!("rmdir: {}: {:?}", path, e);
            set_exit(1);
        }
    }
}

/// Show detailed file/directory metadata.
#[allow(clippy::cast_possible_truncation)]
fn cmd_stat(args: &str) {
    if args.is_empty() {
        crate::console_println!("Usage: stat <path>");
        return;
    }

    let path = resolve_path(args);

    match crate::fs::Vfs::metadata(&path) {
        Ok(meta) => {
            let type_str = match meta.entry_type {
                crate::fs::EntryType::File => "regular file",
                crate::fs::EntryType::Directory => "directory",
                crate::fs::EntryType::Symlink => "symbolic link",
                crate::fs::EntryType::VolumeLabel => "volume label",
            };
            crate::console_println!("  File: {}", path);
            crate::console_println!("  Size: {}  Blocks: {}  Type: {}", meta.size, meta.blocks, type_str);
            crate::console_println!("  Links: {}", meta.nlinks);
            if meta.permissions != 0 {
                let perms = format_perms(meta.permissions);
                let perm_str = core::str::from_utf8(&perms).unwrap_or("---------");
                crate::console_println!("  Perms: {:04o} ({})  Uid: {}  Gid: {}",
                    meta.permissions, perm_str, meta.uid, meta.gid);
            }
            if meta.attributes != crate::fs::FileAttr::NONE {
                let a = meta.attributes;
                let mut flags = alloc::string::String::new();
                if a.contains(crate::fs::FileAttr::IMMUTABLE) { flags.push_str("immutable "); }
                if a.contains(crate::fs::FileAttr::APPEND_ONLY) { flags.push_str("append-only "); }
                if a.contains(crate::fs::FileAttr::HIDDEN) { flags.push_str("hidden "); }
                if a.contains(crate::fs::FileAttr::SYSTEM) { flags.push_str("system "); }
                crate::console_println!("  Attrs: {}", flags.trim_end());
            }

            // Show filesystem type via VFS mount table.
            if let Ok(info) = crate::fs::Vfs::statvfs(&path) {
                if info.volume_label.is_empty() {
                    crate::console_println!("  FS:   {} (block size: {})", info.fs_type, info.block_size);
                } else {
                    crate::console_println!(
                        "  FS:   {} \"{}\" (block size: {})",
                        info.fs_type, info.volume_label, info.block_size,
                    );
                }
            }

            let ns_to_display = |ns: u64| -> alloc::string::String {
                if ns == 0 {
                    alloc::string::String::from("-")
                } else {
                    format_epoch_ns(ns)
                }
            };
            crate::console_println!("  Created:  {}", ns_to_display(meta.created_ns));
            crate::console_println!("  Modified: {}", ns_to_display(meta.modified_ns));
            crate::console_println!("  Accessed: {}", ns_to_display(meta.accessed_ns));
            crate::console_println!("  Changed:  {}", ns_to_display(meta.changed_ns));

            // Show extended attributes if any.
            if !meta.xattrs.is_empty() {
                crate::console_println!("  Xattrs:");
                for (key, value) in &meta.xattrs {
                    if value.len() <= 64 {
                        // Short value — display inline.
                        let display = if value.iter().all(|&b| b >= 0x20 && b < 0x7F) {
                            alloc::format!("\"{}\"",
                                core::str::from_utf8(value).unwrap_or("?"))
                        } else {
                            alloc::format!("({} bytes, binary)", value.len())
                        };
                        crate::console_println!("    {} = {}", key, display);
                    } else {
                        crate::console_println!("    {} ({} bytes)", key, value.len());
                    }
                }
            }
        }
        Err(e) => {
            crate::console_println!("stat: {}: {:?}", path, e);
            set_exit(1);
        }
    }
}

/// Create a hard link.
fn cmd_ln(args: &str) {
    let parts: alloc::vec::Vec<&str> = args.splitn(2, ' ').collect();
    if parts.len() < 2 || parts[1].is_empty() {
        crate::console_println!("Usage: ln <source> <link-name>");
        return;
    }

    let src = parts[0];
    let dst = parts[1];

    let src_path = resolve_path(src);
    let dst_path = resolve_path(dst);

    match crate::fs::Vfs::link(&src_path, &dst_path) {
        Ok(()) => {
            crate::console_println!("{} -> {}", dst_path, src_path);
        }
        Err(e) => {
            crate::console_println!("ln: {:?}", e);
            set_exit(1);
        }
    }
}

/// Show filesystem disk usage (like Unix `df`).
#[allow(clippy::arithmetic_side_effects)]
fn cmd_df(args: &str) {
    let mut verbose = false;
    let mut path_arg = args;
    if args.starts_with("-v") {
        verbose = true;
        path_arg = args.get(2..).unwrap_or("").trim();
    }

    if path_arg.is_empty() {
        // Show all mounts.
        match crate::fs::Vfs::mount_info() {
            Ok(mounts) => {
                crate::console_println!(
                    "{:<12} {:>10} {:>10} {:>10} {:>5}  {:<16} {}",
                    "Filesystem", "Size", "Used", "Avail", "Use%", "Mounted on", "Label"
                );
                for (mount_path, info) in &mounts {
                    let total = info.total_bytes();
                    let free = info.free_bytes();
                    let used = info.used_bytes();
                    let pct = info.usage_percent();
                    crate::console_println!(
                        "{:<12} {:>10} {:>10} {:>10} {:>4}%  {:<16} {}",
                        info.fs_type,
                        format_bytes(total),
                        format_bytes(used),
                        format_bytes(free),
                        pct,
                        mount_path,
                        info.volume_label,
                    );
                    if verbose {
                        if let Ok(stats) = crate::fs::Vfs::debug_stats(mount_path) {
                            if !stats.is_empty() {
                                for line in stats.lines() {
                                    shell_println!("  {}", line);
                                }
                            }
                        }
                    }
                }
            }
            Err(e) => {
                crate::console_println!("df: {:?}", e);
            }
        }
    } else {
        // Show info for specific path.
        let path = resolve_path(args);
        match crate::fs::Vfs::statvfs(&path) {
            Ok(info) => {
                crate::console_println!(
                    "{:<12} {:>10} {:>10} {:>10} {:>5}  {:<16} {}",
                    "Filesystem", "Size", "Used", "Avail", "Use%", "Path", "Label"
                );
                let total = info.total_bytes();
                let free = info.free_bytes();
                let used = info.used_bytes();
                let pct = info.usage_percent();
                crate::console_println!(
                    "{:<12} {:>10} {:>10} {:>10} {:>4}%  {:<16} {}",
                    info.fs_type,
                    format_bytes(total),
                    format_bytes(used),
                    format_bytes(free),
                    pct,
                    path,
                    info.volume_label,
                );
            }
            Err(e) => {
                crate::console_println!("df: {:?}", e);
            }
        }
    }
}

/// Format a byte count as human-readable (K/M/G).
#[allow(clippy::arithmetic_side_effects)]
fn format_bytes(bytes: u64) -> alloc::string::String {
    if bytes < 1024 {
        alloc::format!("{}B", bytes)
    } else if bytes < 1024 * 1024 {
        alloc::format!("{}K", bytes / 1024)
    } else if bytes < 1024 * 1024 * 1024 {
        alloc::format!("{}M", bytes / (1024 * 1024))
    } else {
        alloc::format!("{}G", bytes / (1024 * 1024 * 1024))
    }
}

/// Format a Unix epoch timestamp (nanoseconds) as YYYY-MM-DD HH:MM:SS.
///
/// Uses the civil-from-days algorithm to convert days since epoch to
/// year/month/day.  Based on Howard Hinnant's `civil_from_days()`.
#[allow(clippy::arithmetic_side_effects)]
fn format_epoch_ns(ns: u64) -> alloc::string::String {
    let total_secs = ns / 1_000_000_000;
    let days_since_epoch = (total_secs / 86400) as i64;
    let time_of_day = total_secs % 86400;
    let hour = time_of_day / 3600;
    let minute = (time_of_day % 3600) / 60;
    let second = time_of_day % 60;

    // Howard Hinnant's civil_from_days algorithm.
    // Converts days since 1970-01-01 to (year, month, day).
    let z = days_since_epoch + 719468; // shift epoch to 0000-03-01
    let era = if z >= 0 { z } else { z - 146096 } / 146097;
    let doe = (z - era * 146097) as u32; // day of era [0, 146096]
    let yoe = (doe - doe / 1460 + doe / 36524 - doe / 146096) / 365;
    let y = yoe as i64 + era * 400;
    let doy = doe - (365 * yoe + yoe / 4 - yoe / 100); // day of year [0, 365]
    let mp = (5 * doy + 2) / 153; // [0, 11]
    let d = doy - (153 * mp + 2) / 5 + 1; // day [1, 31]
    let m = if mp < 10 { mp + 3 } else { mp - 9 }; // month [1, 12]
    let year = if m <= 2 { y + 1 } else { y };

    alloc::format!(
        "{:04}-{:02}-{:02} {:02}:{:02}:{:02}",
        year, m, d, hour, minute, second
    )
}

/// Copy a file.
fn cmd_cp(args: &str) {
    // Support -r flag for recursive copy.
    let (recursive, args) = if args.starts_with("-r ") || args.starts_with("-R ") {
        (true, &args[3..])
    } else {
        (false, args)
    };

    let parts: alloc::vec::Vec<&str> = args.splitn(2, ' ').collect();
    if parts.len() < 2 || parts[1].is_empty() {
        crate::console_println!("Usage: cp [-r] <source> <dest>");
        return;
    }

    let src = parts[0];
    let dst = parts[1];

    let src_path = resolve_path(src);
    let dst_path = resolve_path(dst);

    if recursive {
        match crate::fs::Vfs::copy_recursive(&src_path, &dst_path) {
            Ok(size) => {
                crate::console_println!("'{}' -> '{}' ({} bytes copied)", src_path, dst_path, size);
            }
            Err(e) => {
                crate::console_println!("cp: {:?}", e);
                set_exit(1);
            }
        }
    } else {
        match crate::fs::Vfs::copy(&src_path, &dst_path) {
            Ok(size) => {
                crate::console_println!("'{}' -> '{}' ({} bytes)", src_path, dst_path, size);
            }
            Err(e) => {
                crate::console_println!("cp: {:?}", e);
                set_exit(1);
            }
        }
    }
}

/// Rename/move a file or directory.
fn cmd_mv(args: &str) {
    let parts: alloc::vec::Vec<&str> = args.splitn(2, ' ').collect();
    if parts.len() < 2 || parts[1].is_empty() {
        crate::console_println!("Usage: mv <source> <dest>");
        return;
    }

    let src = parts[0];
    let dst = parts[1];

    let src_path = resolve_path(src);
    let dst_path = resolve_path(dst);

    match crate::fs::Vfs::rename(&src_path, &dst_path) {
        Ok(()) => {
            crate::console_println!("'{}' -> '{}'", src_path, dst_path);
        }
        Err(e) => {
            crate::console_println!("mv: {:?}", e);
            set_exit(1);
        }
    }
}

/// Change file permissions.
fn cmd_chmod(args: &str) {
    let parts: alloc::vec::Vec<&str> = args.splitn(2, ' ').collect();
    if parts.len() < 2 || parts[1].is_empty() {
        crate::console_println!("Usage: chmod <mode> <path>");
        crate::console_println!("  mode: octal (e.g., 755, 644)");
        return;
    }

    let mode_str = parts[0];
    let file = parts[1];

    let mode = match u16::from_str_radix(mode_str, 8) {
        Ok(m) => m,
        Err(_) => {
            crate::console_println!("chmod: invalid mode '{}' (use octal, e.g., 755)", mode_str);
            return;
        }
    };

    let path = resolve_path(file);

    match crate::fs::Vfs::set_permissions(&path, mode) {
        Ok(()) => {
            crate::console_println!("{}: mode set to {:04o}", path, mode);
        }
        Err(e) => {
            crate::console_println!("chmod: {:?}", e);
        }
    }
}

/// Change file ownership.
fn cmd_chown(args: &str) {
    let parts: alloc::vec::Vec<&str> = args.splitn(2, ' ').collect();
    if parts.len() < 2 || parts[1].is_empty() {
        crate::console_println!("Usage: chown <uid:gid> <path>");
        crate::console_println!("  e.g., chown 1000:1000 /home/user");
        return;
    }

    let owner_str = parts[0];
    let file = parts[1];

    // Parse uid:gid.
    let (uid, gid) = if let Some(colon) = owner_str.find(':') {
        let uid_s = &owner_str[..colon];
        let gid_s = &owner_str[colon + 1..];
        let uid = match uid_s.parse::<u32>() {
            Ok(u) => u,
            Err(_) => {
                crate::console_println!("chown: invalid uid '{}'", uid_s);
                return;
            }
        };
        let gid = match gid_s.parse::<u32>() {
            Ok(g) => g,
            Err(_) => {
                crate::console_println!("chown: invalid gid '{}'", gid_s);
                return;
            }
        };
        (uid, gid)
    } else {
        // Just uid, set gid to same.
        match owner_str.parse::<u32>() {
            Ok(u) => (u, u),
            Err(_) => {
                crate::console_println!("chown: invalid owner '{}'", owner_str);
                return;
            }
        }
    };

    let path = resolve_path(file);

    match crate::fs::Vfs::set_owner(&path, uid, gid) {
        Ok(()) => {
            crate::console_println!("{}: owner set to {}:{}", path, uid, gid);
        }
        Err(e) => {
            crate::console_println!("chown: {:?}", e);
        }
    }
}

/// Change file attributes (immutable, hidden, system, append-only).
///
/// Usage:
///   `chattr +i file`  — set immutable
///   `chattr -i file`  — clear immutable
///   `chattr +iha file` — set immutable, hidden, append-only
///   `chattr = file`   — clear all attributes
///
/// Flags: `i` = immutable, `a` = append-only, `h` = hidden, `s` = system.
///
/// On FAT: immutable maps to read-only, hidden/system map directly;
/// append-only is silently ignored.  On ext4: immutable and append-only
/// map to EXT4_IMMUTABLE_FL / EXT4_APPEND_FL.
fn cmd_chattr(args: &str) {
    let parts: alloc::vec::Vec<&str> = args.splitn(2, ' ').collect();
    if parts.len() < 2 || parts[1].is_empty() {
        crate::console_println!("Usage: chattr [+|-]FLAGS FILE");
        crate::console_println!("  +FLAGS  set attributes    -FLAGS  clear attributes");
        crate::console_println!("  =       clear all attributes");
        crate::console_println!("  Flags: i=immutable a=append-only h=hidden s=system");
        set_exit(1);
        return;
    }

    let flag_str = parts[0];
    let file = parts[1].trim();
    let path = resolve_path(file);

    // Parse the operation: +, -, or =
    let (op, flags) = if flag_str == "=" {
        ('=', "")
    } else if let Some(f) = flag_str.strip_prefix('+') {
        ('+', f)
    } else if let Some(f) = flag_str.strip_prefix('-') {
        ('-', f)
    } else {
        crate::console_println!("chattr: expected +FLAGS, -FLAGS, or =");
        set_exit(1);
        return;
    };

    // Parse flag characters into a FileAttr mask.
    let mut mask = crate::fs::FileAttr::NONE;
    for ch in flags.chars() {
        match ch {
            'i' => mask = mask.union(crate::fs::FileAttr::IMMUTABLE),
            'a' => mask = mask.union(crate::fs::FileAttr::APPEND_ONLY),
            'h' => mask = mask.union(crate::fs::FileAttr::HIDDEN),
            's' => mask = mask.union(crate::fs::FileAttr::SYSTEM),
            _ => {
                crate::console_println!("chattr: unknown flag '{}'", ch);
                set_exit(1);
                return;
            }
        }
    }

    // Get current attributes.
    let current_attrs = match crate::fs::Vfs::metadata(&path) {
        Ok(meta) => meta.attributes,
        Err(e) => {
            crate::console_println!("chattr: {}: {:?}", path, e);
            set_exit(1);
            return;
        }
    };

    // Compute new attributes based on the operation.
    let new_attrs = match op {
        '+' => current_attrs.union(mask),
        '-' => crate::fs::FileAttr::from_bits(current_attrs.bits() & !mask.bits()),
        '=' => crate::fs::FileAttr::NONE,
        _ => current_attrs,
    };

    match crate::fs::Vfs::set_attributes(&path, new_attrs) {
        Ok(()) => {
            // Show the resulting attributes.
            let mut desc = alloc::string::String::new();
            if new_attrs.contains(crate::fs::FileAttr::IMMUTABLE) {
                desc.push('i');
            }
            if new_attrs.contains(crate::fs::FileAttr::APPEND_ONLY) {
                desc.push('a');
            }
            if new_attrs.contains(crate::fs::FileAttr::HIDDEN) {
                desc.push('h');
            }
            if new_attrs.contains(crate::fs::FileAttr::SYSTEM) {
                desc.push('s');
            }
            if desc.is_empty() {
                desc.push_str("(none)");
            }
            crate::console_println!("{}: attributes = {}", path, desc);
        }
        Err(e) => {
            crate::console_println!("chattr: {:?}", e);
            set_exit(1);
        }
    }
}

/// Show file attributes (complement to chattr).
///
/// Usage: `lsattr FILE`
fn cmd_lsattr(args: &str) {
    if args.is_empty() {
        crate::console_println!("Usage: lsattr <path>");
        set_exit(1);
        return;
    }

    let path = resolve_path(args.trim());

    match crate::fs::Vfs::metadata(&path) {
        Ok(meta) => {
            let attrs = meta.attributes;
            let mut flags = alloc::string::String::new();
            flags.push(if attrs.contains(crate::fs::FileAttr::IMMUTABLE) { 'i' } else { '-' });
            flags.push(if attrs.contains(crate::fs::FileAttr::APPEND_ONLY) { 'a' } else { '-' });
            flags.push(if attrs.contains(crate::fs::FileAttr::HIDDEN) { 'h' } else { '-' });
            flags.push(if attrs.contains(crate::fs::FileAttr::SYSTEM) { 's' } else { '-' });
            crate::console_println!("{} {}", flags, path);
        }
        Err(e) => {
            crate::console_println!("lsattr: {}: {:?}", path, e);
            set_exit(1);
        }
    }
}

/// Create a file or update timestamps.
/// Create file or update timestamps.
///
/// Usage: `touch <path>` — set timestamps to now
///        `touch -d DATETIME <path>` — set to specific ISO-8601 date
///        `touch -r REFFILE <path>` — copy timestamps from reference file
///
/// DATETIME format: `YYYY-MM-DD`, `YYYY-MM-DD HH:MM:SS`, or epoch seconds.
#[allow(clippy::arithmetic_side_effects)]
fn cmd_touch(args: &str) {
    if args.is_empty() {
        crate::console_println!("Usage: touch [-d DATETIME | -r REFFILE] <path>");
        return;
    }

    let mut date_str: Option<&str> = None;
    let mut ref_file: Option<&str> = None;
    let mut file_path = "";

    let mut words = args.split_whitespace();
    while let Some(w) = words.next() {
        if w == "-d" {
            // Collect the date string — it might have spaces (e.g., "2026-01-15 12:30:00").
            date_str = words.next();
        } else if w == "-r" {
            ref_file = words.next();
        } else {
            file_path = w;
        }
    }

    if file_path.is_empty() {
        crate::console_println!("touch: missing file operand");
        set_exit(1);
        return;
    }

    let path = resolve_path(file_path);

    // Determine the timestamp to use.
    let timestamp = if let Some(ds) = date_str {
        // Parse the date string.
        match parse_datetime_to_ns(ds) {
            Some(ns) => ns,
            None => {
                crate::console_println!(
                    "touch: invalid date '{}' (use YYYY-MM-DD or YYYY-MM-DD HH:MM:SS or epoch secs)",
                    ds
                );
                set_exit(1);
                return;
            }
        }
    } else if let Some(rf) = ref_file {
        // Copy timestamp from reference file.
        let ref_path = resolve_path(rf);
        match crate::fs::Vfs::metadata(&ref_path) {
            Ok(meta) => meta.modified_ns,
            Err(e) => {
                crate::console_println!("touch: {}: {:?}", ref_path, e);
                set_exit(1);
                return;
            }
        }
    } else {
        crate::hpet::elapsed_ns()
    };

    // Check if file exists.
    match crate::fs::Vfs::stat(&path) {
        Ok(_) => {
            // File exists — update timestamps.
            match crate::fs::Vfs::set_times(&path, timestamp, timestamp) {
                Ok(()) => {
                    crate::console_println!("{}: timestamps updated", path);
                }
                Err(e) => {
                    crate::console_println!("touch: {}: {:?}", path, e);
                    set_exit(1);
                }
            }
        }
        Err(_) => {
            // File doesn't exist — create empty file.
            match crate::fs::Vfs::write_file(&path, &[]) {
                Ok(()) => {
                    crate::console_println!("{}: created", path);
                }
                Err(e) => {
                    crate::console_println!("touch: {}: {:?}", path, e);
                    set_exit(1);
                }
            }
        }
    }
}

/// Parse a datetime string to nanoseconds since epoch.
///
/// Accepts:
/// - `YYYY-MM-DD` (midnight UTC)
/// - `YYYY-MM-DD HH:MM:SS` (UTC)
/// - Plain integer (epoch seconds)
#[allow(clippy::arithmetic_side_effects)]
fn parse_datetime_to_ns(s: &str) -> Option<u64> {
    // Try epoch seconds first.
    if let Ok(secs) = s.parse::<u64>() {
        return Some(secs.saturating_mul(1_000_000_000));
    }

    // Try YYYY-MM-DD or YYYY-MM-DD HH:MM:SS.
    let parts: alloc::vec::Vec<&str> = s.splitn(2, ' ').collect();
    let date_part = parts.first()?;
    let time_part = parts.get(1);

    let date_fields: alloc::vec::Vec<&str> = date_part.split('-').collect();
    if date_fields.len() != 3 {
        return None;
    }

    let year = date_fields[0].parse::<i64>().ok()?;
    let month = date_fields[1].parse::<u32>().ok()?;
    let day = date_fields[2].parse::<u32>().ok()?;

    if month < 1 || month > 12 || day < 1 || day > 31 {
        return None;
    }

    let (hour, minute, second) = if let Some(tp) = time_part {
        let time_fields: alloc::vec::Vec<&str> = tp.split(':').collect();
        let h = time_fields.first().and_then(|s| s.parse::<u32>().ok()).unwrap_or(0);
        let m = time_fields.get(1).and_then(|s| s.parse::<u32>().ok()).unwrap_or(0);
        let s = time_fields.get(2).and_then(|s| s.parse::<u32>().ok()).unwrap_or(0);
        (h, m, s)
    } else {
        (0, 0, 0)
    };

    // Convert to days since epoch using standard algorithm.
    let is_leap = (year % 4 == 0 && year % 100 != 0) || year % 400 == 0;
    let month_days: [u32; 12] = [0, 31, 59, 90, 120, 151, 181, 212, 243, 273, 304, 334];
    let mi = if month >= 1 && month <= 12 { (month - 1) as usize } else { 0 };
    let mut yday = month_days[mi] + day;
    if is_leap && month > 2 {
        yday += 1;
    }

    // Days from 1970-01-01 to start of this year (approximate).
    let mut days: i64 = (year - 1970) * 365 + (year - 1969) / 4 - (year - 1901) / 100 + (year - 1601) / 400;
    days += i64::from(yday) - 1;

    let total_secs = days * 86400 + i64::from(hour) * 3600 + i64::from(minute) * 60 + i64::from(second);
    if total_secs < 0 {
        return None;
    }
    Some((total_secs as u64).saturating_mul(1_000_000_000))
}

/// Append text to a file.
fn cmd_append(args: &str) {
    let mut parts = args.splitn(2, ' ');
    let filename = match parts.next() {
        Some(f) if !f.is_empty() => f,
        _ => {
            crate::console_println!("Usage: append <filename> <text>");
            return;
        }
    };
    let text = parts.next().unwrap_or("");
    let path = resolve_path(filename);

    let mut data = alloc::vec::Vec::from(text.as_bytes());
    if !text.ends_with('\n') {
        data.push(b'\n');
    }
    match crate::fs::Vfs::append(&path, &data) {
        Ok(()) => {
            crate::console_println!("Appended {} bytes to {}", data.len(), path);
        }
        Err(e) => {
            crate::console_println!("append: {}: {:?}", path, e);
        }
    }
}

/// Recursive directory tree listing.
fn cmd_tree(args: &str) {
    let path = if args.is_empty() {
        get_cwd()
    } else {
        resolve_path(args)
    };

    crate::console_println!("{}", path);
    let mut dirs: u64 = 0;
    let mut files: u64 = 0;
    tree_recurse(&path, "", &mut dirs, &mut files, 0);
    crate::console_println!("\n{} directories, {} files", dirs, files);
}

/// Internal recursive helper for tree display.
///
/// Limits depth to 8 levels to avoid excessive output.
fn tree_recurse(path: &str, prefix: &str, dirs: &mut u64, files: &mut u64, depth: u32) {
    if depth > 8 {
        return;
    }

    let entries = match crate::fs::Vfs::readdir(path) {
        Ok(e) => e,
        Err(_) => return,
    };

    let count = entries.len();
    for (i, entry) in entries.iter().enumerate() {
        let is_last = i + 1 == count;
        let connector = if is_last { "└── " } else { "├── " };
        let type_marker = match entry.entry_type {
            crate::fs::EntryType::Directory => "/",
            crate::fs::EntryType::Symlink => "@",
            _ => "",
        };

        crate::console_println!("{}{}{}{}", prefix, connector, entry.name, type_marker);

        if entry.entry_type == crate::fs::EntryType::Directory {
            *dirs = dirs.saturating_add(1);
            let child_path = if path == "/" {
                alloc::format!("/{}", entry.name)
            } else {
                alloc::format!("{}/{}", path, entry.name)
            };
            let child_prefix = if is_last {
                alloc::format!("{}    ", prefix)
            } else {
                alloc::format!("{}│   ", prefix)
            };
            tree_recurse(&child_path, &child_prefix, dirs, files, depth + 1);
        } else {
            *files = files.saturating_add(1);
        }
    }
}

/// Show disk usage for a path (like Unix `du`).
#[allow(clippy::arithmetic_side_effects)]
fn cmd_du(args: &str) {
    let mut summary_only = false;
    let mut max_depth: usize = usize::MAX;
    let mut path_arg = "";

    for word in args.split_whitespace() {
        if word == "-s" {
            summary_only = true;
        } else if let Some(rest) = word.strip_prefix("-d") {
            // -d N or -dN
            let num_str = if rest.is_empty() {
                // -d followed by next arg is not handled in this simple parser;
                // use -dN form.
                "0"
            } else {
                rest
            };
            max_depth = num_str.parse::<usize>().unwrap_or(0);
        } else {
            path_arg = word;
        }
    }

    let path = if path_arg.is_empty() {
        get_cwd()
    } else {
        resolve_path(path_arg)
    };

    let total = du_recurse(&path, 0, max_depth, summary_only);
    crate::console_println!("{}\t{}", format_bytes(total), path);
}

/// Recursively calculate total size of a directory tree.
///
/// `depth` is the current recursion depth (0 = root).
/// `max_depth` limits how deep subdirectories are printed.
/// `summary_only` suppresses all subdirectory output.
#[allow(clippy::arithmetic_side_effects)]
fn du_recurse(path: &str, depth: usize, max_depth: usize, summary_only: bool) -> u64 {
    let mut total: u64 = 0;

    let entries = match crate::fs::Vfs::readdir(path) {
        Ok(e) => e,
        Err(_) => return 0,
    };

    for entry in &entries {
        let child_path = if path == "/" {
            alloc::format!("/{}", entry.name)
        } else {
            alloc::format!("{}/{}", path, entry.name)
        };

        total = total.saturating_add(entry.size);

        if entry.entry_type == crate::fs::EntryType::Directory {
            let subdir_total = du_recurse(
                &child_path,
                depth.saturating_add(1),
                max_depth,
                summary_only,
            );
            if !summary_only && depth < max_depth {
                crate::console_println!("{}\t{}", format_bytes(subdir_total), child_path);
            }
            total = total.saturating_add(subdir_total);
        }
    }

    total
}

/// Search for files matching a pattern (basic find).
/// Search for files matching predicates (like Unix `find`).
///
/// Usage: `find [PATH] [PREDICATES...]`
///
/// Predicates:
///   `-name PATTERN`   Match filename against glob pattern
///   `-type f|d|l`     Match by type (f=file, d=directory, l=symlink)
///   `-size +N|-N|N`   Match by size (+ = larger, - = smaller, no prefix = exact)
///                     Suffixes: k (KiB), M (MiB), G (GiB), c (bytes, default)
///   `-maxdepth N`     Limit recursion depth
///   `-empty`          Match empty files (size 0) or empty directories
///
/// Without predicates, acts as a recursive glob (legacy behavior).
///
/// Examples:
///   `find /tmp -name *.txt`
///   `find / -type d -name src`
///   `find . -size +1M`
///   `find /tmp -empty`
#[allow(clippy::arithmetic_side_effects)]
fn cmd_find(args: &str) {
    if args.is_empty() {
        crate::console_println!("Usage: find [PATH] [PREDICATES...]");
        crate::console_println!("  Predicates:");
        crate::console_println!("    -name PATTERN   Glob match on filename");
        crate::console_println!("    -type f|d|l     File type (f=file, d=dir, l=symlink)");
        crate::console_println!("    -size +N|-N|N   Size filter (suffixes: c, k, M, G)");
        crate::console_println!("    -maxdepth N     Limit recursion depth");
        crate::console_println!("    -empty          Empty files or directories");
        crate::console_println!("  Example: find /tmp -name *.txt -type f");
        return;
    }

    // Parse arguments.
    let mut search_path = "";
    let mut name_pattern: Option<&str> = None;
    let mut type_filter: Option<char> = None; // 'f', 'd', or 'l'
    let mut size_filter: Option<(i64, char)> = None; // (threshold, '+'/'-'/'=')
    let mut max_depth: u32 = 16;
    let mut empty_filter = false;

    let mut words = args.split_whitespace().peekable();
    while let Some(w) = words.next() {
        if w == "-name" {
            name_pattern = words.next();
        } else if w == "-type" {
            if let Some(t) = words.next() {
                type_filter = t.chars().next();
            }
        } else if w == "-size" {
            if let Some(s) = words.next() {
                size_filter = Some(parse_size_predicate(s));
            }
        } else if w == "-maxdepth" {
            if let Some(d) = words.next() {
                max_depth = d.parse::<u32>().unwrap_or(16);
            }
        } else if w == "-empty" {
            empty_filter = true;
        } else if !w.starts_with('-') && search_path.is_empty() {
            search_path = w;
        } else if !w.starts_with('-') && name_pattern.is_none() {
            // Legacy: bare pattern without -name.
            name_pattern = Some(w);
        }
    }

    if search_path.is_empty() {
        search_path = ".";
    }

    let root = resolve_path(search_path);

    let filter = FindFilter {
        name_pattern,
        is_glob: name_pattern.is_some_and(|p| {
            p.contains('*') || p.contains('?') || p.contains('[')
        }),
        type_filter,
        size_filter,
        empty_filter,
        max_depth,
    };

    let mut count: u64 = 0;
    find_recurse_filtered(&root, &filter, &mut count, 0);
    shell_println!("\n{} matches found", count);
}

/// Parsed find predicates.
struct FindFilter<'a> {
    name_pattern: Option<&'a str>,
    is_glob: bool,
    type_filter: Option<char>,
    size_filter: Option<(i64, char)>,
    empty_filter: bool,
    max_depth: u32,
}

/// Parse a `-size` argument like `+1M`, `-512k`, `100c`.
fn parse_size_predicate(s: &str) -> (i64, char) {
    let (sign, rest) = if let Some(stripped) = s.strip_prefix('+') {
        ('+', stripped)
    } else if let Some(stripped) = s.strip_prefix('-') {
        ('-', stripped)
    } else {
        ('=', s)
    };

    // Parse suffix.
    let (num_str, multiplier) = if rest.ends_with('G') || rest.ends_with('g') {
        (&rest[..rest.len() - 1], 1024i64 * 1024 * 1024)
    } else if rest.ends_with('M') || rest.ends_with('m') {
        (&rest[..rest.len() - 1], 1024i64 * 1024)
    } else if rest.ends_with('k') || rest.ends_with('K') {
        (&rest[..rest.len() - 1], 1024i64)
    } else if let Some(stripped) = rest.strip_suffix('c') {
        (stripped, 1i64)
    } else {
        (rest, 1i64) // default: bytes
    };

    let value = num_str.parse::<i64>().unwrap_or(0) * multiplier;
    (value, sign)
}

/// `locate` — fast file search using the filesystem index.
///
/// Usage:
///   `locate --update`               Rebuild the full index
///   `locate --stats`                Show index statistics
///   `locate PATTERN`                Search by name (case-insensitive substring)
///   `locate --ext EXT`              Search by file extension
///   `locate --ext EXT PATTERN`      Search by extension + name
///   `locate --size MIN-MAX`         Search by file size range
///   `locate --path PATTERN`         Search in full path, not just filename
///   `updatedb`                      Alias for `locate --update`
#[allow(clippy::too_many_lines)]
fn cmd_locate(args: &str) {
    use crate::fs::index;

    let parts: alloc::vec::Vec<&str> = args.split_whitespace().collect();

    // `updatedb` with no args → rebuild
    if parts.is_empty() {
        crate::console_println!(
            "Usage: locate [--update|--stats|--ext E|--size MIN-MAX|--path] PATTERN"
        );
        return;
    }

    let mut do_update = false;
    let mut do_stats = false;
    let mut ext_filter: Option<&str> = None;
    let mut size_min: Option<u64> = None;
    let mut size_max: Option<u64> = None;
    let mut path_mode = false;
    let mut pattern: Option<&str> = None;
    let mut i = 0;

    while i < parts.len() {
        match parts.get(i).copied().unwrap_or("") {
            "--update" | "-u" => do_update = true,
            "--stats" | "-s" => do_stats = true,
            "--path" | "-p" => path_mode = true,
            "--ext" | "-e" => {
                i = i.saturating_add(1);
                ext_filter = parts.get(i).copied();
            }
            "--size" => {
                i = i.saturating_add(1);
                if let Some(range_str) = parts.get(i).copied() {
                    if let Some(dash) = range_str.find('-') {
                        let min_s = &range_str[..dash];
                        let max_s = &range_str[dash.saturating_add(1)..];
                        size_min = parse_size_value(min_s);
                        size_max = parse_size_value(max_s);
                    }
                }
            }
            s => {
                if !s.starts_with('-') {
                    pattern = Some(s);
                }
            }
        }
        i = i.saturating_add(1);
    }

    // Handle --update.
    if do_update {
        let st = index::stats();
        if !st.initialized {
            index::init(index::default_config());
        }
        crate::console_println!("Rebuilding file index...");
        match index::rebuild() {
            Ok(()) => {
                let st = index::stats();
                crate::console_println!(
                    "Done: {} entries indexed ({} bytes, {} extensions){}",
                    st.total_entries,
                    st.total_size,
                    st.extension_count,
                    if st.truncated { " [truncated]" } else { "" }
                );
            }
            Err(e) => crate::console_println!("Error rebuilding index: {:?}", e),
        }
        return;
    }

    // Handle --stats.
    if do_stats {
        let st = index::stats();
        if !st.initialized {
            crate::console_println!("Index not initialized. Run `locate --update` first.");
            return;
        }
        crate::console_println!("=== File Index Statistics ===");
        crate::console_println!("  Entries:     {}", st.total_entries);
        crate::console_println!("  Total size:  {} bytes", st.total_size);
        crate::console_println!("  Extensions:  {}", st.extension_count);
        crate::console_println!("  Rebuilds:    {}", st.rebuild_count);
        crate::console_println!("  Truncated:   {}", st.truncated);
        crate::console_println!("  Initialized: {}", st.initialized);
        return;
    }

    // Ensure index is built.
    let st = index::stats();
    if !st.initialized || st.total_entries == 0 {
        crate::console_println!("Index empty or not built. Run `locate --update` first.");
        return;
    }

    // Perform search.
    let results = if ext_filter.is_some() || size_min.is_some() || pattern.is_some() {
        if path_mode {
            // --path mode: search in full path.
            if let Some(q) = pattern {
                index::search_path(q)
            } else {
                // Extension/size only.
                index::search(None, ext_filter, size_min, size_max)
            }
        } else {
            index::search(pattern, ext_filter, size_min, size_max)
        }
    } else {
        crate::console_println!("No search pattern given.");
        return;
    };

    if results.is_empty() {
        crate::console_println!("No matches found.");
        return;
    }

    // Print results.
    let max_display = 100;
    for (i, entry) in results.iter().enumerate() {
        if i >= max_display {
            crate::console_println!(
                "... and {} more ({} total)",
                results.len().saturating_sub(max_display),
                results.len()
            );
            break;
        }
        let type_char = match entry.entry_type {
            crate::fs::EntryType::File => ' ',
            crate::fs::EntryType::Directory => 'd',
            crate::fs::EntryType::Symlink => 'l',
            _ => '?',
        };
        crate::console_println!("{} {:>8}  {}", type_char, entry.size, entry.path);
    }

    if results.len() <= max_display {
        crate::console_println!("({} match{})", results.len(), if results.len() == 1 { "" } else { "es" });
    }
}

/// Parse a human-readable size value like "1024", "10k", "2M".
fn parse_size_value(s: &str) -> Option<u64> {
    if s.is_empty() {
        return None;
    }
    let s_trimmed = s.trim();
    let (num_part, multiplier) = if s_trimmed.ends_with('k') || s_trimmed.ends_with('K') {
        (&s_trimmed[..s_trimmed.len().saturating_sub(1)], 1024u64)
    } else if s_trimmed.ends_with('m') || s_trimmed.ends_with('M') {
        (&s_trimmed[..s_trimmed.len().saturating_sub(1)], 1024u64 * 1024)
    } else if s_trimmed.ends_with('g') || s_trimmed.ends_with('G') {
        (&s_trimmed[..s_trimmed.len().saturating_sub(1)], 1024u64 * 1024 * 1024)
    } else {
        (s_trimmed, 1u64)
    };
    num_part.parse::<u64>().ok().map(|n| n.saturating_mul(multiplier))
}

/// `dedup [--dry-run] [--min-size N] [--max-size N] [DIR]` — find duplicate files.
///
/// Walks the directory tree rooted at DIR (default: current directory),
/// groups files by size as a cheap pre-filter, then computes SHA-256 hashes
/// for files with matching sizes to identify true duplicates.
///
/// Options:
/// - `--dry-run` / `-n`: only report duplicates, don't offer deletion
/// - `--min-size N`: skip files smaller than N bytes (default: 1, skips empty)
/// - `--max-size N`: skip files larger than N bytes (default: 64 MiB)
/// - `--delete`: interactively delete duplicates (keeps first file in each group)
/// - `--stats` / `-s`: show summary statistics only
///
/// ## Algorithm
///
/// 1. Walk directory tree, collecting (path, size) for all regular files.
/// 2. Group by size. Discard groups with only one file (unique by size).
/// 3. For remaining files, read contents and compute SHA-256 hash.
/// 4. Group by hash. Discard groups with only one file.
/// 5. Report duplicate groups: hash, count, wasted bytes, file list.
///
/// This is the standard size→hash two-phase dedup strategy used by tools
/// like `fdupes`, `rdfind`, and `jdupes`.  The size pre-filter avoids
/// reading+hashing files that can't possibly be duplicates, which is the
/// vast majority in typical filesystems.
fn cmd_dedup(args: &str) {
    use crate::fs::{Vfs, EntryType};
    use alloc::collections::BTreeMap;

    let parts: Vec<&str> = args.split_whitespace().collect();

    let mut dry_run = true; // Default to dry-run for safety.
    let mut delete_mode = false;
    let mut stats_only = false;
    let mut min_size: u64 = 1; // Skip empty files by default.
    let mut max_size: u64 = 64 * 1024 * 1024; // 64 MiB.
    let mut target_dir: Option<&str> = None;
    let mut i = 0;

    while i < parts.len() {
        match parts.get(i).copied().unwrap_or("") {
            "--dry-run" | "-n" => dry_run = true,
            "--delete" => { delete_mode = true; dry_run = false; }
            "--stats" | "-s" => stats_only = true,
            "--min-size" => {
                i = i.saturating_add(1);
                if let Some(v) = parts.get(i).copied() {
                    min_size = parse_size_value(v).unwrap_or(1);
                }
            }
            "--max-size" => {
                i = i.saturating_add(1);
                if let Some(v) = parts.get(i).copied() {
                    max_size = parse_size_value(v).unwrap_or(64 * 1024 * 1024);
                }
            }
            "--help" | "-h" => {
                shell_println!("Usage: dedup [--dry-run|-n] [--delete] [--stats|-s] [--min-size N] [--max-size N] [DIR]");
                shell_println!("  Find and report duplicate files by content hash (SHA-256).");
                shell_println!("  Default: dry-run mode (report only, no changes).");
                shell_println!("  --delete: remove duplicates, keeping the first file in each group.");
                shell_println!("  --stats:  show summary only (no file listing).");
                return;
            }
            s => {
                if !s.starts_with('-') {
                    target_dir = Some(s);
                }
            }
        }
        i = i.saturating_add(1);
    }

    let root = resolve_path(target_dir.unwrap_or("."));
    shell_println!("Scanning {} for duplicates...", root);

    // Phase 1: Walk the directory tree, collecting (path, size) pairs.
    let mut file_list: Vec<(String, u64)> = Vec::new();
    let mut dirs_to_visit: Vec<String> = Vec::new();
    dirs_to_visit.push(root.clone());

    let mut total_scanned: u64 = 0;
    let mut total_skipped: u64 = 0;
    let max_files: usize = 100_000; // Safety limit to prevent OOM.

    while let Some(dir) = dirs_to_visit.pop() {
        let entries = match Vfs::readdir(&dir) {
            Ok(e) => e,
            Err(_) => continue, // Skip unreadable directories.
        };

        for entry in &entries {
            let path = if dir == "/" {
                alloc::format!("/{}", entry.name)
            } else {
                alloc::format!("{}/{}", dir, entry.name)
            };

            match entry.entry_type {
                EntryType::Directory => {
                    // Skip . and .. (shouldn't appear, but be safe).
                    if entry.name != "." && entry.name != ".." {
                        dirs_to_visit.push(path);
                    }
                }
                EntryType::File => {
                    total_scanned = total_scanned.saturating_add(1);

                    // Size filter.
                    if entry.size < min_size || entry.size > max_size {
                        total_skipped = total_skipped.saturating_add(1);
                        continue;
                    }

                    file_list.push((path, entry.size));

                    if file_list.len() >= max_files {
                        shell_println!("Warning: hit {} file limit, results may be incomplete.", max_files);
                        dirs_to_visit.clear();
                        break;
                    }
                }
                _ => {} // Skip symlinks, etc.
            }
        }
    }

    if file_list.is_empty() {
        shell_println!("No files found matching criteria.");
        shell_println!("  Scanned: {} files, skipped: {}", total_scanned, total_skipped);
        return;
    }

    // Phase 2: Group by size.
    let mut by_size: BTreeMap<u64, Vec<String>> = BTreeMap::new();
    for (path, size) in &file_list {
        by_size.entry(*size)
            .or_default()
            .push(path.clone());
    }

    // Keep only groups with 2+ files (potential duplicates).
    let candidate_groups: Vec<(u64, Vec<String>)> = by_size
        .into_iter()
        .filter(|(_, paths)| paths.len() > 1)
        .collect();

    if candidate_groups.is_empty() {
        shell_println!("No duplicate candidates found (all files have unique sizes).");
        shell_println!("  Scanned: {} files, skipped: {}", total_scanned, total_skipped);
        return;
    }

    let mut candidates_count: usize = 0;
    for (_, paths) in &candidate_groups {
        candidates_count = candidates_count.saturating_add(paths.len());
    }
    shell_println!("Phase 1: {} files have non-unique sizes ({} size groups). Hashing...",
        candidates_count, candidate_groups.len());

    // Phase 3: Hash files in each size group and group by hash.
    let mut dup_groups: Vec<(String, u64, Vec<String>)> = Vec::new(); // (hex_hash, size, paths)
    let mut hash_errors: u64 = 0;
    let mut files_hashed: u64 = 0;

    for (size, paths) in &candidate_groups {
        let mut by_hash: BTreeMap<String, Vec<String>> = BTreeMap::new();

        for path in paths {
            match Vfs::read_file(path) {
                Ok(data) => {
                    let hash = crate::crypto::sha256(&data);
                    let hex = crate::fs::cas::hash_to_hex(&hash);
                    by_hash.entry(hex)
                        .or_default()
                        .push(path.clone());
                    files_hashed = files_hashed.saturating_add(1);
                }
                Err(_) => {
                    hash_errors = hash_errors.saturating_add(1);
                }
            }
        }

        // Collect groups with 2+ files (true duplicates).
        for (hex, dup_paths) in by_hash {
            if dup_paths.len() > 1 {
                dup_groups.push((hex, *size, dup_paths));
            }
        }
    }

    // Phase 4: Report results.
    let total_dup_groups = dup_groups.len();
    let mut total_dup_files: u64 = 0;
    let mut total_wasted: u64 = 0;

    for (_, size, paths) in &dup_groups {
        let extras = (paths.len() as u64).saturating_sub(1);
        total_dup_files = total_dup_files.saturating_add(extras);
        total_wasted = total_wasted.saturating_add(size.saturating_mul(extras));
    }

    if dup_groups.is_empty() {
        shell_println!("No duplicates found.");
        shell_println!("  Scanned: {}, hashed: {}, errors: {}",
            total_scanned, files_hashed, hash_errors);
        return;
    }

    // Summary.
    shell_println!();
    shell_println!("=== Duplicate Report ===");
    shell_println!("  Duplicate groups:   {}", total_dup_groups);
    shell_println!("  Duplicate files:    {} (extra copies)", total_dup_files);
    shell_println!("  Wasted space:       {}", format_size_human(total_wasted));
    shell_println!("  Files scanned:      {}", total_scanned);
    shell_println!("  Files hashed:       {}", files_hashed);
    if hash_errors > 0 {
        shell_println!("  Read errors:        {}", hash_errors);
    }
    shell_println!();

    if !stats_only {
        // Print each duplicate group.
        let max_groups_display = 50;
        for (gi, (hex, size, paths)) in dup_groups.iter().enumerate() {
            if gi >= max_groups_display {
                shell_println!("... and {} more groups (showing first {})",
                    total_dup_groups.saturating_sub(max_groups_display),
                    max_groups_display);
                break;
            }
            let short_hash = if hex.len() >= 12 { &hex[..12] } else { hex.as_str() };
            shell_println!("[{}...] {} x {} (wasted: {})",
                short_hash,
                paths.len(),
                format_size_human(*size),
                format_size_human(size.saturating_mul((paths.len() as u64).saturating_sub(1))));
            for (pi, path) in paths.iter().enumerate() {
                if pi == 0 {
                    shell_println!("  KEEP  {}", path);
                } else {
                    shell_println!("  DUP   {}", path);
                }
            }
        }
    }

    // Delete mode: remove duplicate files (keep the first in each group).
    if delete_mode && !dry_run {
        let mut deleted_count: u64 = 0;
        let mut deleted_bytes: u64 = 0;
        let mut delete_errors: u64 = 0;

        for (_, size, paths) in &dup_groups {
            // Skip the first file (keep it), delete the rest.
            for path in paths.iter().skip(1) {
                match Vfs::remove(path) {
                    Ok(()) => {
                        deleted_count = deleted_count.saturating_add(1);
                        deleted_bytes = deleted_bytes.saturating_add(*size);
                    }
                    Err(e) => {
                        shell_println!("  Error deleting {}: {:?}", path, e);
                        delete_errors = delete_errors.saturating_add(1);
                    }
                }
            }
        }

        shell_println!();
        shell_println!("Deleted {} duplicate files, reclaimed {}.",
            deleted_count, format_size_human(deleted_bytes));
        if delete_errors > 0 {
            shell_println!("  {} files could not be deleted.", delete_errors);
        }
    } else if !delete_mode {
        shell_println!("(dry-run: no files deleted. Use --delete to remove duplicates.)");
    }
}

/// `integrity [baseline|verify|stats|clear] [DIR|FILE]` — file integrity monitoring.
///
/// Manages file integrity baselines and verification:
///
/// - `integrity baseline [DIR]` — Compute SHA-256 hashes for all files
///   under DIR (default: current directory) and store as the baseline.
/// - `integrity verify [DIR]` — Compare current file hashes against the
///   baseline. Reports: MODIFIED, MISSING, NEW files.
/// - `integrity baseline FILE` — Baseline a single file.
/// - `integrity verify FILE` — Verify a single file against its baseline.
/// - `integrity stats` — Show baseline statistics.
/// - `integrity clear` — Clear the baseline.
/// - `integrity list [PREFIX]` — List baselined files (optionally filtered).
fn cmd_integrity(args: &str) {
    use crate::fs::integrity;

    let parts: Vec<&str> = args.split_whitespace().collect();

    if parts.is_empty() {
        shell_println!("Usage: integrity <baseline|verify|stats|clear|list> [DIR|FILE]");
        shell_println!("  baseline [DIR]  — Compute SHA-256 hashes and store as baseline");
        shell_println!("  verify [DIR]    — Compare current hashes against baseline");
        shell_println!("  stats           — Show baseline statistics");
        shell_println!("  clear           — Clear the baseline");
        shell_println!("  list [PREFIX]   — List baselined file paths");
        return;
    }

    let subcommand = parts.first().copied().unwrap_or("");
    let target = parts.get(1).copied();

    match subcommand {
        "baseline" | "bl" => {
            if let Some(path) = target {
                let resolved = resolve_path(path);

                // Check if it's a file or directory.
                match crate::fs::Vfs::stat(&resolved) {
                    Ok(entry) => {
                        if entry.entry_type == crate::fs::EntryType::File {
                            // Single file baseline.
                            match integrity::baseline_file(&resolved) {
                                Ok(hash) => {
                                    let hex = crate::fs::cas::hash_to_hex(&hash);
                                    shell_println!("Baselined: {} ({})", resolved, &hex[..12]);
                                }
                                Err(e) => shell_println!("Error: {:?}", e),
                            }
                        } else if entry.entry_type == crate::fs::EntryType::Directory {
                            // Directory baseline.
                            shell_println!("Baselining {}...", resolved);
                            match integrity::baseline_dir(&resolved) {
                                Ok(count) => {
                                    shell_println!("Baselined {} files. Total entries: {}",
                                        count, integrity::baseline_len());
                                }
                                Err(e) => shell_println!("Error: {:?}", e),
                            }
                        } else {
                            shell_println!("Error: not a file or directory");
                        }
                    }
                    Err(e) => shell_println!("Error: {:?}", e),
                }
            } else {
                // Default: baseline current directory.
                let cwd = get_cwd();
                shell_println!("Baselining {}...", cwd);
                match integrity::baseline_dir(&cwd) {
                    Ok(count) => {
                        shell_println!("Baselined {} files. Total entries: {}",
                            count, integrity::baseline_len());
                    }
                    Err(e) => shell_println!("Error: {:?}", e),
                }
            }
        }

        "verify" | "vf" => {
            if integrity::baseline_len() == 0 {
                shell_println!("No baseline exists. Run `integrity baseline [DIR]` first.");
                return;
            }

            if let Some(path) = target {
                let resolved = resolve_path(path);

                // Check if it's a file or directory.
                match crate::fs::Vfs::stat(&resolved) {
                    Ok(entry) => {
                        if entry.entry_type == crate::fs::EntryType::File {
                            // Single file verify.
                            match integrity::verify_file(&resolved) {
                                Ok(result) => {
                                    print_verify_result(&result);
                                }
                                Err(crate::error::KernelError::NotFound) => {
                                    shell_println!("{}: not in baseline", resolved);
                                }
                                Err(e) => shell_println!("Error: {:?}", e),
                            }
                        } else if entry.entry_type == crate::fs::EntryType::Directory {
                            // Directory verify.
                            shell_println!("Verifying {}...", resolved);
                            run_dir_verify(&resolved);
                        } else {
                            shell_println!("Error: not a file or directory");
                        }
                    }
                    Err(_) => {
                        // Path doesn't exist — might still be in baseline as missing.
                        // Try as directory verify (will detect missing files).
                        shell_println!("Verifying {}...", resolved);
                        run_dir_verify(&resolved);
                    }
                }
            } else {
                // Default: verify current directory.
                let cwd = get_cwd();
                shell_println!("Verifying {}...", cwd);
                run_dir_verify(&cwd);
            }
        }

        "stats" | "st" => {
            let st = integrity::stats();
            shell_println!("=== Integrity Monitoring Statistics ===");
            shell_println!("  Baseline entries:    {}", st.baseline_entries);
            shell_println!("  Max entries:         {}", st.max_entries);
            shell_println!("  Max file size:       {} bytes", st.max_file_size);
            shell_println!("  Baseline operations: {}", st.baseline_count);
            shell_println!("  Verify operations:   {}", st.verify_count);
            if st.baseline_timestamp > 0 {
                let secs = st.baseline_timestamp / 1_000_000_000;
                shell_println!("  Last baseline:       {}s after boot", secs);
            } else {
                shell_println!("  Last baseline:       never");
            }
        }

        "clear" => {
            let old_count = integrity::baseline_len();
            integrity::clear_baseline();
            shell_println!("Baseline cleared ({} entries removed).", old_count);
        }

        "list" | "ls" => {
            let prefix = target.map(resolve_path);
            let max_display = 100;

            let (entries, total) = integrity::list_entries(
                prefix.as_deref(),
                max_display,
            );

            if entries.is_empty() {
                shell_println!("No entries in baseline{}.",
                    if prefix.is_some() { " matching prefix" } else { "" });
            } else {
                for (path, hash, size) in &entries {
                    let hex = crate::fs::cas::hash_to_hex(hash);
                    shell_println!("{}  {:>8}  {}", &hex[..12], size, path);
                }
                if entries.len() >= max_display && total > max_display {
                    shell_println!("... showing first {} of {} entries", max_display, total);
                } else {
                    shell_println!("({} entries)", entries.len());
                }
            }
        }

        _ => {
            shell_println!("Unknown subcommand '{}'. Use: baseline, verify, stats, clear, list", subcommand);
        }
    }
}

/// Print a single verify result with status indicator.
fn print_verify_result(result: &crate::fs::integrity::VerifyResult) {
    use crate::fs::integrity::VerifyStatus;

    let status_str = match result.status {
        VerifyStatus::Ok => "  OK  ",
        VerifyStatus::Modified => "MODIFY",
        VerifyStatus::Missing => " MISS ",
        VerifyStatus::New => " NEW  ",
        VerifyStatus::Error => "ERROR ",
    };

    shell_println!("[{}] {}", status_str, result.path);

    if result.status == VerifyStatus::Modified {
        if let (Some(bl_hash), Some(cur_hash)) = (result.baseline_hash, result.current_hash) {
            let bl_hex = crate::fs::cas::hash_to_hex(&bl_hash);
            let cur_hex = crate::fs::cas::hash_to_hex(&cur_hash);
            shell_println!("    baseline: {}...", &bl_hex[..16]);
            shell_println!("    current:  {}...", &cur_hex[..16]);
        }
        if let (Some(bl_size), Some(cur_size)) = (result.baseline_size, result.current_size) {
            if bl_size != cur_size {
                shell_println!("    size: {} -> {} bytes", bl_size, cur_size);
            }
        }
    }
}

/// Run a directory verify and print the summary.
fn run_dir_verify(dir: &str) {
    use crate::fs::integrity;

    let (results, summary) = integrity::verify_dir(dir);

    // Print changes (non-OK results).
    let max_display = 100;
    for (i, result) in results.iter().enumerate() {
        if i >= max_display {
            shell_println!("... and {} more changes",
                results.len().saturating_sub(max_display));
            break;
        }
        print_verify_result(result);
    }

    shell_println!();
    shell_println!("=== Verification Summary ===");
    shell_println!("  Total checked: {}", summary.total);
    shell_println!("  OK:            {}", summary.ok);
    if summary.modified > 0 {
        shell_println!("  Modified:      {}", summary.modified);
    }
    if summary.missing > 0 {
        shell_println!("  Missing:       {}", summary.missing);
    }
    if summary.new > 0 {
        shell_println!("  New:           {}", summary.new);
    }
    if summary.errors > 0 {
        shell_println!("  Errors:        {}", summary.errors);
    }

    if summary.modified == 0 && summary.missing == 0 && summary.errors == 0 {
        shell_println!("  Status: ALL CLEAR ✓");
    } else {
        shell_println!("  Status: CHANGES DETECTED");
    }
}

/// `fhist [show|restore|clear|stats|enable|disable] [FILE] [VERSION]`
///
/// View and manage file version history.
///
/// - `fhist show FILE` — Show version history for a file.
/// - `fhist restore FILE VERSION` — Restore file to a previous version.
/// - `fhist record FILE` — Manually record current version of a file.
/// - `fhist clear [FILE]` — Clear history (for file or all).
/// - `fhist stats` — Show history system statistics.
/// - `fhist list [PREFIX]` — List all tracked files.
/// - `fhist enable` / `fhist disable` — Toggle tracking.
fn cmd_fhist(args: &str) {
    use crate::fs::history;

    let parts: Vec<&str> = args.split_whitespace().collect();

    if parts.is_empty() {
        shell_println!("Usage: fhist <show|restore|record|clear|stats|list|enable|disable|autoversion> [FILE] [VERSION]");
        return;
    }

    let subcommand = parts.first().copied().unwrap_or("");
    let target = parts.get(1).copied();

    match subcommand {
        "show" | "log" => {
            let path = match target {
                Some(p) => resolve_path(p),
                None => {
                    shell_println!("Usage: fhist show FILE");
                    return;
                }
            };

            let versions = history::get_history(&path);
            if versions.is_empty() {
                shell_println!("No version history for {}", path);
                return;
            }

            shell_println!("Version history for {}:", path);
            shell_println!("{:>4}  {:>12}  {:>10}  {}", "Ver", "Hash", "Size", "Time");
            shell_println!("{}", "-".repeat(50));

            for v in versions.iter().rev() {
                let hex = crate::fs::cas::hash_to_hex(&v.hash);
                let secs = v.timestamp_ns / 1_000_000_000;
                shell_println!("{:>4}  {}  {:>10}  {}s",
                    v.version,
                    &hex[..12],
                    v.size,
                    secs);
            }
            shell_println!("({} versions)", versions.len());
        }

        "restore" => {
            let path = match target {
                Some(p) => resolve_path(p),
                None => {
                    shell_println!("Usage: fhist restore FILE VERSION_NUMBER");
                    return;
                }
            };

            // Get version number.
            let version_num: u64 = match parts.get(2) {
                Some(s) => match s.parse() {
                    Ok(n) => n,
                    Err(_) => {
                        shell_println!("Invalid version number: {}", s);
                        return;
                    }
                },
                None => {
                    // Default to latest version.
                    let versions = history::get_history(&path);
                    if versions.is_empty() {
                        shell_println!("No version history for {}", path);
                        return;
                    }
                    // Latest stored version.
                    versions.last().map(|v| v.version).unwrap_or(0)
                }
            };

            // Find the version with that number.
            let versions = history::get_history(&path);
            let version_entry = versions.iter().find(|v| v.version == version_num);

            match version_entry {
                Some(v) => {
                    let hash = v.hash;
                    match history::restore_version(&path, &hash) {
                        Ok(()) => {
                            let hex = crate::fs::cas::hash_to_hex(&hash);
                            shell_println!("Restored {} to version {} ({}...)",
                                path, version_num, &hex[..12]);
                        }
                        Err(e) => shell_println!("Error restoring: {:?}", e),
                    }
                }
                None => {
                    shell_println!("Version {} not found for {}. Use `fhist show {}` to see available versions.",
                        version_num, path, path);
                }
            }
        }

        "record" => {
            let path = match target {
                Some(p) => resolve_path(p),
                None => {
                    shell_println!("Usage: fhist record FILE");
                    return;
                }
            };

            match history::record_version(&path) {
                Ok(Some(hash)) => {
                    let hex = crate::fs::cas::hash_to_hex(&hash);
                    shell_println!("Recorded version of {} ({}...)", path, &hex[..12]);
                }
                Ok(None) => shell_println!("No version recorded (file not found or tracking disabled)."),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }

        "clear" => {
            if let Some(path) = target {
                let resolved = resolve_path(path);
                history::clear_file(&resolved);
                shell_println!("Cleared history for {}", resolved);
            } else {
                let count = history::tracked_files();
                history::clear_all();
                shell_println!("Cleared all history ({} files)", count);
            }
        }

        "stats" | "st" => {
            let st = history::stats();
            shell_println!("=== File History Statistics ===");
            shell_println!("  Tracked files:   {}", st.tracked_files);
            shell_println!("  Total versions:  {}", st.total_versions);
            shell_println!("  Records:         {}", st.record_count);
            shell_println!("  Restores:        {}", st.restore_count);
            shell_println!("  Evicted:         {}", st.evicted_versions);
            shell_println!("  Enabled:         {}", st.enabled);
            shell_println!("  Auto-version:    {}", st.auto_version);
        }

        "list" | "ls" => {
            let prefix = target.map(resolve_path);
            let tracked = history::list_tracked(prefix.as_deref(), 100);

            if tracked.is_empty() {
                shell_println!("No tracked files{}.",
                    if prefix.is_some() { " matching prefix" } else { "" });
            } else {
                for (path, count) in &tracked {
                    shell_println!("  {:>3} versions  {}", count, path);
                }
                shell_println!("({} tracked files)", tracked.len());
            }
        }

        "enable" => {
            history::set_enabled(true);
            shell_println!("File version tracking enabled.");
        }

        "disable" => {
            history::set_enabled(false);
            shell_println!("File version tracking disabled.");
        }

        "autoversion" | "auto" => {
            match target {
                Some("on") | Some("enable") => {
                    history::set_auto_version(true);
                    shell_println!("VFS auto-versioning enabled (files versioned automatically on write/delete).");
                }
                Some("off") | Some("disable") => {
                    history::set_auto_version(false);
                    shell_println!("VFS auto-versioning disabled (use `fhist record` for manual versioning).");
                }
                _ => {
                    let st = history::stats();
                    shell_println!("Auto-versioning: {}", if st.auto_version { "on" } else { "off" });
                    shell_println!("Usage: fhist autoversion <on|off>");
                }
            }
        }

        _ => {
            shell_println!("Unknown subcommand '{}'. Use: show, restore, record, clear, stats, list, enable, disable, autoversion", subcommand);
        }
    }
}

/// `mime PATH [PATH...]` — show the MIME content type of files.
///
/// Uses magic byte detection first, falling back to extension-based
/// detection.  Also shows the content category (Image, Audio, etc.).
fn cmd_mime(args: &str) {
    if args.is_empty() {
        shell_println!("Usage: mime <path> [path...]");
        set_exit(1);
        return;
    }

    for word in args.split_whitespace() {
        let path = resolve_path(word);
        match crate::fs::mime::detect(&path) {
            Ok(mime) => {
                let cat = crate::fs::mime::category(mime);
                shell_println!("{}: {} ({})", path, mime, cat);
            }
            Err(e) => {
                shell_println!("{}: error: {:?}", path, e);
                set_exit(1);
            }
        }
    }
}

/// `file PATH` — identify a file's type and basic info.
///
/// `assoc` — manage file type associations.
///
/// Subcommands:
///   assoc list             - list all MIME types with associations
///   assoc show MIME        - show apps registered for a MIME type
///   assoc add MIME APP NAME [PRIO] - register an app
///   assoc remove MIME APP  - unregister an app
///   assoc lookup FILE      - show default app for a file
///   assoc stats            - show registry statistics
fn cmd_assoc(args: &str) {
    use crate::fs::associations;

    let parts: Vec<&str> = args.split_whitespace().collect();

    if parts.is_empty() {
        shell_println!("Usage: assoc <list|show|add|remove|lookup|stats> [args...]");
        return;
    }

    match parts.first().copied().unwrap_or("") {
        "list" | "ls" => {
            let types = associations::list_types();
            if types.is_empty() {
                shell_println!("No file type associations registered.");
            } else {
                shell_println!("{:>3}  {}", "Apps", "MIME Type");
                shell_println!("{}", "-".repeat(50));
                for (mime, count) in &types {
                    shell_println!("{:>3}  {}", count, mime);
                }
                shell_println!("({} types)", types.len());
            }
        }

        "show" => {
            let mime = match parts.get(1) {
                Some(m) => *m,
                None => {
                    shell_println!("Usage: assoc show <MIME_TYPE>");
                    return;
                }
            };

            let apps = associations::apps_for(mime);
            if apps.is_empty() {
                shell_println!("No applications registered for '{}'.", mime);
            } else {
                shell_println!("Applications for '{}':", mime);
                for (i, app) in apps.iter().enumerate() {
                    let default_marker = if i == 0 { " [default]" } else { "" };
                    let user_marker = if app.user_set { " (user)" } else { "" };
                    shell_println!("  {:>3}  {} — {}{}{}", app.priority, app.app_path, app.app_name, default_marker, user_marker);
                }
            }
        }

        "add" => {
            if parts.len() < 4 {
                shell_println!("Usage: assoc add <MIME> <APP_PATH> <APP_NAME> [PRIORITY]");
                return;
            }
            let mime = parts[1];
            let app_path = parts[2];
            let app_name = parts[3];
            let priority: u32 = parts.get(4).and_then(|s| s.parse().ok()).unwrap_or(100);

            associations::register(mime, app_path, app_name, priority, true);
            shell_println!("Registered '{}' for {} (priority {})", app_name, mime, priority);
        }

        "remove" | "rm" => {
            if parts.len() < 3 {
                shell_println!("Usage: assoc remove <MIME> <APP_PATH>");
                return;
            }
            let mime = parts[1];
            let app_path = parts[2];

            if associations::unregister(mime, app_path) {
                shell_println!("Removed '{}' from {}", app_path, mime);
            } else {
                shell_println!("No association found for '{}' in {}", app_path, mime);
            }
        }

        "lookup" => {
            let path = match parts.get(1) {
                Some(p) => resolve_path(p),
                None => {
                    shell_println!("Usage: assoc lookup <FILE>");
                    return;
                }
            };

            let mime = crate::fs::mime::detect(&path).unwrap_or("unknown");
            shell_println!("File:     {}", path);
            shell_println!("MIME:     {}", mime);

            match associations::default_app_for_file(&path) {
                Some(app) => {
                    shell_println!("Open with: {} ({})", app.app_name, app.app_path);
                }
                None => {
                    shell_println!("Open with: (no application registered)");
                }
            }
        }

        "stats" | "st" => {
            let st = associations::stats();
            shell_println!("=== File Association Statistics ===");
            shell_println!("  MIME types:     {}", st.mime_types);
            shell_println!("  Total entries:  {}", st.total_entries);
            shell_println!("  User entries:   {}", st.user_entries);
        }

        _ => {
            shell_println!("Unknown subcommand '{}'. Use: list, show, add, remove, lookup, stats", parts[0]);
        }
    }
}

/// `quota` — manage filesystem quotas.
///
/// Subcommands:
///   quota on/off                  - enable/disable enforcement
///   quota set user UID soft hard  - set byte limits for a user
///   quota set group GID soft hard - set byte limits for a group
///   quota setfiles user UID soft hard - set inode limits
///   quota show [user UID | group GID] - show quota info
///   quota list                    - list all quotas
///   quota stats                   - show summary statistics
///   quota remove user UID | group GID - remove a quota
fn cmd_quota(args: &str) {
    use crate::fs::quota;

    let parts: Vec<&str> = args.split_whitespace().collect();

    if parts.is_empty() {
        shell_println!("Usage: quota <on|off|set|setfiles|show|list|stats|remove> [args...]");
        shell_println!("  Quotas are currently {}.", if quota::is_enabled() { "enabled" } else { "disabled" });
        return;
    }

    match parts.first().copied().unwrap_or("") {
        "on" | "enable" => {
            quota::set_enabled(true);
            shell_println!("Quota enforcement enabled.");
        }

        "off" | "disable" => {
            quota::set_enabled(false);
            shell_println!("Quota enforcement disabled.");
        }

        "set" => {
            // quota set user UID SOFT_BYTES HARD_BYTES [GRACE_SECS]
            // quota set group GID SOFT_BYTES HARD_BYTES [GRACE_SECS]
            if parts.len() < 5 {
                shell_println!("Usage: quota set <user|group> <ID> <soft_bytes> <hard_bytes> [grace_secs]");
                return;
            }
            let subject = match parts[1] {
                "user" | "u" => {
                    match parts[2].parse::<u32>() {
                        Ok(uid) => quota::QuotaSubject::User(uid),
                        Err(_) => { shell_println!("Invalid UID: {}", parts[2]); return; }
                    }
                }
                "group" | "g" => {
                    match parts[2].parse::<u32>() {
                        Ok(gid) => quota::QuotaSubject::Group(gid),
                        Err(_) => { shell_println!("Invalid GID: {}", parts[2]); return; }
                    }
                }
                _ => { shell_println!("Expected 'user' or 'group', got '{}'", parts[1]); return; }
            };

            let soft: u64 = match parse_size_suffix(parts[3]) {
                Some(v) => v,
                None => { shell_println!("Invalid size: {}", parts[3]); return; }
            };
            let hard: u64 = match parse_size_suffix(parts[4]) {
                Some(v) => v,
                None => { shell_println!("Invalid size: {}", parts[4]); return; }
            };
            let grace = parts.get(5).and_then(|s| s.parse::<u64>().ok()).unwrap_or(7 * 24 * 3600);

            // Preserve existing inode limits if any.
            let existing = quota::get_info(subject);
            let (si, hi) = existing.map_or((0, 0), |i| (i.limits.soft_inodes, i.limits.hard_inodes));

            quota::set_limits(subject, quota::QuotaLimits {
                soft_bytes: soft,
                hard_bytes: hard,
                soft_inodes: si,
                hard_inodes: hi,
                grace_seconds: grace,
            });
            shell_println!("Set byte quota: soft={}, hard={}, grace={}s",
                quota::format_bytes(soft), quota::format_bytes(hard), grace);
        }

        "setfiles" | "setinodes" => {
            // quota setfiles user UID SOFT_INODES HARD_INODES
            if parts.len() < 5 {
                shell_println!("Usage: quota setfiles <user|group> <ID> <soft_files> <hard_files>");
                return;
            }
            let subject = match parts[1] {
                "user" | "u" => {
                    match parts[2].parse::<u32>() {
                        Ok(uid) => quota::QuotaSubject::User(uid),
                        Err(_) => { shell_println!("Invalid UID: {}", parts[2]); return; }
                    }
                }
                "group" | "g" => {
                    match parts[2].parse::<u32>() {
                        Ok(gid) => quota::QuotaSubject::Group(gid),
                        Err(_) => { shell_println!("Invalid GID: {}", parts[2]); return; }
                    }
                }
                _ => { shell_println!("Expected 'user' or 'group', got '{}'", parts[1]); return; }
            };

            let soft: u64 = match parts[3].parse() {
                Ok(v) => v,
                Err(_) => { shell_println!("Invalid number: {}", parts[3]); return; }
            };
            let hard: u64 = match parts[4].parse() {
                Ok(v) => v,
                Err(_) => { shell_println!("Invalid number: {}", parts[4]); return; }
            };

            // Preserve existing byte limits if any.
            let existing = quota::get_info(subject);
            let (sb, hb, grace) = existing.map_or((0, 0, 7 * 24 * 3600), |i| {
                (i.limits.soft_bytes, i.limits.hard_bytes, i.limits.grace_seconds)
            });

            quota::set_limits(subject, quota::QuotaLimits {
                soft_bytes: sb,
                hard_bytes: hb,
                soft_inodes: soft,
                hard_inodes: hard,
                grace_seconds: grace,
            });
            shell_println!("Set inode quota: soft={}, hard={}", soft, hard);
        }

        "show" => {
            if parts.len() < 3 {
                shell_println!("Usage: quota show <user|group> <ID>");
                return;
            }
            let subject = match parts[1] {
                "user" | "u" => {
                    match parts[2].parse::<u32>() {
                        Ok(uid) => quota::QuotaSubject::User(uid),
                        Err(_) => { shell_println!("Invalid UID: {}", parts[2]); return; }
                    }
                }
                "group" | "g" => {
                    match parts[2].parse::<u32>() {
                        Ok(gid) => quota::QuotaSubject::Group(gid),
                        Err(_) => { shell_println!("Invalid GID: {}", parts[2]); return; }
                    }
                }
                _ => { shell_println!("Expected 'user' or 'group', got '{}'", parts[1]); return; }
            };

            match quota::get_info(subject) {
                Some(info) => {
                    print_quota_info(&info);
                }
                None => {
                    shell_println!("No quota configured for {:?}", subject);
                }
            }
        }

        "list" | "ls" => {
            let all = quota::list_all();
            if all.is_empty() {
                shell_println!("No quotas configured.");
            } else {
                shell_println!("{:<12} {:>12} {:>12} {:>12} {:>12}  Status",
                    "Subject", "Bytes Used", "Soft Limit", "Hard Limit", "Files");
                shell_println!("{}", "-".repeat(78));
                for info in &all {
                    let subj_str = match info.subject {
                        quota::QuotaSubject::User(uid) => alloc::format!("user:{}", uid),
                        quota::QuotaSubject::Group(gid) => alloc::format!("group:{}", gid),
                    };
                    let status = if info.over_hard_bytes || info.over_hard_inodes {
                        "OVER HARD"
                    } else if info.over_soft_bytes || info.over_soft_inodes {
                        "over soft"
                    } else {
                        "ok"
                    };
                    shell_println!("{:<12} {:>12} {:>12} {:>12} {:>12}  {}",
                        subj_str,
                        quota::format_bytes(info.usage.bytes_used),
                        if info.limits.soft_bytes > 0 { quota::format_bytes(info.limits.soft_bytes) } else { "-".to_string() },
                        if info.limits.hard_bytes > 0 { quota::format_bytes(info.limits.hard_bytes) } else { "-".to_string() },
                        info.usage.inodes_used,
                        status,
                    );
                }
                shell_println!("({} quota entries)", all.len());
            }
        }

        "stats" | "st" => {
            let st = quota::stats();
            shell_println!("=== Filesystem Quota Statistics ===");
            shell_println!("  Enforcement: {}", if st.enabled { "enabled" } else { "disabled" });
            shell_println!("  Total entries: {}", st.entries);
            shell_println!("  User quotas:  {}", st.user_quotas);
            shell_println!("  Group quotas: {}", st.group_quotas);
            shell_println!("  Over soft:    {}", st.over_soft);
            shell_println!("  Over hard:    {}", st.over_hard);
        }

        "remove" | "rm" => {
            if parts.len() < 3 {
                shell_println!("Usage: quota remove <user|group> <ID>");
                return;
            }
            let subject = match parts[1] {
                "user" | "u" => {
                    match parts[2].parse::<u32>() {
                        Ok(uid) => quota::QuotaSubject::User(uid),
                        Err(_) => { shell_println!("Invalid UID: {}", parts[2]); return; }
                    }
                }
                "group" | "g" => {
                    match parts[2].parse::<u32>() {
                        Ok(gid) => quota::QuotaSubject::Group(gid),
                        Err(_) => { shell_println!("Invalid GID: {}", parts[2]); return; }
                    }
                }
                _ => { shell_println!("Expected 'user' or 'group', got '{}'", parts[1]); return; }
            };

            if quota::remove(subject) {
                shell_println!("Quota removed for {:?}.", subject);
            } else {
                shell_println!("No quota found for {:?}.", subject);
            }
        }

        _ => {
            shell_println!("Unknown subcommand '{}'. Use: on, off, set, setfiles, show, list, stats, remove", parts[0]);
        }
    }
}

/// Helper to print detailed quota info.
fn print_quota_info(info: &crate::fs::quota::QuotaInfo) {
    use crate::fs::quota;

    let subj_str = match info.subject {
        quota::QuotaSubject::User(uid) => alloc::format!("User {}", uid),
        quota::QuotaSubject::Group(gid) => alloc::format!("Group {}", gid),
    };

    shell_println!("=== Quota: {} ===", subj_str);
    shell_println!("  Bytes:");
    shell_println!("    Used:  {}", quota::format_bytes(info.usage.bytes_used));
    shell_println!("    Soft:  {}", if info.limits.soft_bytes > 0 { quota::format_bytes(info.limits.soft_bytes) } else { "unlimited".to_string() });
    shell_println!("    Hard:  {}", if info.limits.hard_bytes > 0 { quota::format_bytes(info.limits.hard_bytes) } else { "unlimited".to_string() });
    if info.over_hard_bytes {
        shell_println!("    ** OVER HARD LIMIT **");
    } else if info.over_soft_bytes {
        shell_println!("    * over soft limit (grace period active) *");
    }

    shell_println!("  Files:");
    shell_println!("    Used:  {}", info.usage.inodes_used);
    shell_println!("    Soft:  {}", if info.limits.soft_inodes > 0 { alloc::format!("{}", info.limits.soft_inodes) } else { "unlimited".to_string() });
    shell_println!("    Hard:  {}", if info.limits.hard_inodes > 0 { alloc::format!("{}", info.limits.hard_inodes) } else { "unlimited".to_string() });
    if info.over_hard_inodes {
        shell_println!("    ** OVER HARD LIMIT **");
    } else if info.over_soft_inodes {
        shell_println!("    * over soft limit *");
    }

    shell_println!("  Grace period: {}s", info.limits.grace_seconds);
}

/// `intercept` — manage filesystem operation interceptors.
///
/// Subcommands:
///   intercept list           - list all interceptors
///   intercept stats          - show statistics
///   intercept add-ro PATH    - add read-only zone interceptor
///   intercept add-nodelete PATH - add no-delete zone
///   intercept add-audit PATH - add audit logger
///   intercept enable ID      - enable an interceptor
///   intercept disable ID     - disable an interceptor
///   intercept remove ID      - remove an interceptor
fn cmd_intercept(args: &str) {
    use crate::fs::intercept;

    let parts: Vec<&str> = args.split_whitespace().collect();
    if parts.is_empty() {
        shell_println!("Usage: intercept <list|stats|add-ro|add-nodelete|add-audit|enable|disable|remove> [args...]");
        return;
    }

    match parts.first().copied().unwrap_or("") {
        "list" | "ls" => {
            let all = intercept::list();
            if all.is_empty() {
                shell_println!("No interceptors registered.");
            } else {
                shell_println!("{:>4}  {:<6}  {:>6}  {:>6}  {:<16}  Path",
                    "ID", "Active", "Calls", "Deny", "Name");
                shell_println!("{}", "-".repeat(70));
                for i in &all {
                    shell_println!("{:>4}  {:<6}  {:>6}  {:>6}  {:<16}  {}",
                        i.id,
                        if i.active { "yes" } else { "no" },
                        i.invocations,
                        i.denials,
                        i.name,
                        if i.path_prefix.is_empty() { "(all)" } else { &i.path_prefix },
                    );
                }
            }
        }

        "stats" | "st" => {
            let st = intercept::stats();
            shell_println!("=== Filesystem Interceptor Stats ===");
            shell_println!("  Registered: {}", st.interceptors);
            shell_println!("  Active:     {}", st.active);
            shell_println!("  Checks:     {}", st.total_checks);
            shell_println!("  Denials:    {}", st.total_denials);
            shell_println!("  Allows:     {}", st.total_allows);
        }

        "add-ro" => {
            let prefix = match parts.get(1) {
                Some(p) => resolve_path(p),
                None => { shell_println!("Usage: intercept add-ro <path_prefix>"); return; }
            };
            match intercept::register("read-only-zone", &prefix, intercept::FsOpMask::ALL_WRITES, intercept::readonly_handler) {
                Ok(id) => shell_println!("Registered read-only zone interceptor #{} for '{}'", id, prefix),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }

        "add-nodelete" => {
            let prefix = match parts.get(1) {
                Some(p) => resolve_path(p),
                None => { shell_println!("Usage: intercept add-nodelete <path_prefix>"); return; }
            };
            match intercept::register("no-delete-zone", &prefix, intercept::FsOpMask::DELETE, intercept::no_delete_handler) {
                Ok(id) => shell_println!("Registered no-delete zone interceptor #{} for '{}'", id, prefix),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }

        "add-audit" => {
            let prefix = parts.get(1).map(|p| resolve_path(p)).unwrap_or_default();
            match intercept::register("audit-log", &prefix, intercept::FsOpMask::ALL, intercept::audit_handler) {
                Ok(id) => shell_println!("Registered audit logger #{} for '{}'", id, if prefix.is_empty() { "(all paths)" } else { &prefix }),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }

        "enable" => {
            let id = match parts.get(1).and_then(|s| s.parse::<u64>().ok()) {
                Some(id) => id,
                None => { shell_println!("Usage: intercept enable <ID>"); return; }
            };
            match intercept::set_active(id, true) {
                Ok(()) => shell_println!("Interceptor {} enabled.", id),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }

        "disable" => {
            let id = match parts.get(1).and_then(|s| s.parse::<u64>().ok()) {
                Some(id) => id,
                None => { shell_println!("Usage: intercept disable <ID>"); return; }
            };
            match intercept::set_active(id, false) {
                Ok(()) => shell_println!("Interceptor {} disabled.", id),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }

        "remove" | "rm" => {
            let id = match parts.get(1).and_then(|s| s.parse::<u64>().ok()) {
                Some(id) => id,
                None => { shell_println!("Usage: intercept remove <ID>"); return; }
            };
            if intercept::unregister(id) {
                shell_println!("Interceptor {} removed.", id);
            } else {
                shell_println!("No interceptor with ID {}.", id);
            }
        }

        _ => {
            shell_println!("Unknown subcommand '{}'. Use: list, stats, add-ro, add-nodelete, add-audit, enable, disable, remove", parts[0]);
        }
    }
}

/// `ulimit` — display and set resource limits.
///
/// Usage:
///   ulimit            - show all limits
///   ulimit -n         - show max open files
///   ulimit -f         - show max file size
///   ulimit -n VALUE   - set soft limit for open files
///   ulimit -n hard VALUE - set hard limit (requires root)
///   ulimit -S/-H      - show soft/hard limits
fn cmd_ulimit(args: &str) {
    use crate::fs::rlimit;

    let parts: Vec<&str> = args.split_whitespace().collect();
    let uid = 0u32; // kshell runs as root

    if parts.is_empty() {
        // Show all limits.
        let limits = rlimit::get_limits(uid);
        shell_println!("Resource     Soft               Hard");
        shell_println!("{}", "-".repeat(50));
        shell_println!("{:<12} {:>18} {:>18}",
            "nofile", rlimit::Rlimit::format_value(limits.nofile.soft), rlimit::Rlimit::format_value(limits.nofile.hard));
        shell_println!("{:<12} {:>18} {:>18}",
            "fsize", rlimit::Rlimit::format_value(limits.fsize.soft), rlimit::Rlimit::format_value(limits.fsize.hard));
        shell_println!("{:<12} {:>18} {:>18}",
            "locks", rlimit::Rlimit::format_value(limits.locks.soft), rlimit::Rlimit::format_value(limits.locks.hard));
        return;
    }

    match parts[0] {
        "-n" | "nofile" => {
            if parts.len() == 1 {
                let limit = rlimit::get_limit(uid, rlimit::Resource::NoFile);
                shell_println!("open files: soft={}, hard={}",
                    rlimit::Rlimit::format_value(limit.soft),
                    rlimit::Rlimit::format_value(limit.hard));
            } else if parts.get(1) == Some(&"hard") {
                if let Some(val) = parts.get(2).and_then(|s| parse_limit_value(s)) {
                    match rlimit::set_hard(uid, rlimit::Resource::NoFile, val, 0) {
                        Ok(()) => shell_println!("nofile hard limit set to {}", rlimit::Rlimit::format_value(val)),
                        Err(e) => shell_println!("Error: {:?}", e),
                    }
                } else {
                    shell_println!("Usage: ulimit -n hard <value|unlimited>");
                }
            } else if let Some(val) = parse_limit_value(parts[1]) {
                match rlimit::set_soft(uid, rlimit::Resource::NoFile, val, 0) {
                    Ok(()) => shell_println!("nofile soft limit set to {}", rlimit::Rlimit::format_value(val)),
                    Err(e) => shell_println!("Error: {:?}", e),
                }
            } else {
                shell_println!("Invalid value: {}", parts[1]);
            }
        }

        "-f" | "fsize" => {
            if parts.len() == 1 {
                let limit = rlimit::get_limit(uid, rlimit::Resource::FileSize);
                shell_println!("file size: soft={}, hard={}",
                    rlimit::Rlimit::format_value(limit.soft),
                    rlimit::Rlimit::format_value(limit.hard));
            } else if let Some(val) = parse_limit_value(parts[1]) {
                match rlimit::set_soft(uid, rlimit::Resource::FileSize, val, 0) {
                    Ok(()) => shell_println!("fsize soft limit set to {}", rlimit::Rlimit::format_value(val)),
                    Err(e) => shell_println!("Error: {:?}", e),
                }
            } else {
                shell_println!("Invalid value: {}", parts[1]);
            }
        }

        "-l" | "locks" => {
            if parts.len() == 1 {
                let limit = rlimit::get_limit(uid, rlimit::Resource::Locks);
                shell_println!("file locks: soft={}, hard={}",
                    rlimit::Rlimit::format_value(limit.soft),
                    rlimit::Rlimit::format_value(limit.hard));
            } else if let Some(val) = parse_limit_value(parts[1]) {
                match rlimit::set_soft(uid, rlimit::Resource::Locks, val, 0) {
                    Ok(()) => shell_println!("locks soft limit set to {}", rlimit::Rlimit::format_value(val)),
                    Err(e) => shell_println!("Error: {:?}", e),
                }
            } else {
                shell_println!("Invalid value: {}", parts[1]);
            }
        }

        "-a" | "all" => {
            let limits = rlimit::get_limits(uid);
            shell_println!("Resource     Soft               Hard");
            shell_println!("{}", "-".repeat(50));
            shell_println!("{:<12} {:>18} {:>18}",
                "nofile", rlimit::Rlimit::format_value(limits.nofile.soft), rlimit::Rlimit::format_value(limits.nofile.hard));
            shell_println!("{:<12} {:>18} {:>18}",
                "fsize", rlimit::Rlimit::format_value(limits.fsize.soft), rlimit::Rlimit::format_value(limits.fsize.hard));
            shell_println!("{:<12} {:>18} {:>18}",
                "locks", rlimit::Rlimit::format_value(limits.locks.soft), rlimit::Rlimit::format_value(limits.locks.hard));
        }

        _ => {
            shell_println!("Usage: ulimit [-n|-f|-l|-a] [value|unlimited]");
        }
    }
}

/// Parse "unlimited" or a numeric value for limit setting.
fn parse_limit_value(s: &str) -> Option<u64> {
    if s == "unlimited" || s == "infinity" || s == "inf" {
        Some(crate::fs::rlimit::RLIM_INFINITY)
    } else {
        // Support K/M/G suffixes for file size.
        parse_size_suffix(s)
    }
}

/// `overlay` — manage overlay filesystem mounts.
///
/// Usage:
///   overlay list                    - list all overlays
///   overlay create NAME LOWER UPPER - create overlay mount
///   overlay destroy NAME            - destroy overlay mount
///   overlay ls NAME [PATH]          - list merged directory
///   overlay cat NAME PATH           - read file through overlay
///   overlay write NAME PATH DATA    - write file through overlay
///   overlay rm NAME PATH            - remove file through overlay
///   overlay which NAME PATH         - show which layer a path is in
///   overlay whiteouts NAME          - list whiteout entries
///   overlay stats NAME              - show overlay statistics
///   overlay reset NAME              - discard all upper-layer changes
///   overlay commit NAME             - merge upper into lower
fn cmd_overlay(args: &str) {
    use crate::fs::overlay;

    let parts: Vec<&str> = args.split_whitespace().collect();
    if parts.is_empty() {
        shell_println!("Usage: overlay <list|create|destroy|ls|cat|write|rm|which|whiteouts|stats|reset|commit> ...");
        return;
    }

    match parts[0] {
        "list" | "ls-all" => {
            let overlays = overlay::list();
            if overlays.is_empty() {
                shell_println!("No active overlays.");
                return;
            }
            shell_println!("{:<4} {:<16} {:<24} {:<24} {:>4} {:>6} {:>6}",
                "ID", "Name", "Lower", "Upper", "WO", "Reads", "Writes");
            shell_println!("{}", "-".repeat(84));
            for (id, s) in &overlays {
                shell_println!("{:<4} {:<16} {:<24} {:<24} {:>4} {:>6} {:>6}",
                    id, s.name, s.lower_path, s.upper_path,
                    s.whiteout_count, s.reads, s.writes);
            }
        }

        "create" => {
            if parts.len() < 4 {
                shell_println!("Usage: overlay create NAME LOWER_PATH UPPER_PATH");
                return;
            }
            let name = parts[1];
            let lower = parts[2];
            let upper = parts[3];
            match overlay::create(name, lower, upper) {
                Ok(id) => shell_println!("Overlay '{}' created (id={})", name, id),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }

        "destroy" => {
            if parts.len() < 2 {
                shell_println!("Usage: overlay destroy NAME");
                return;
            }
            if let Some(id) = overlay::find_by_name(parts[1]) {
                match overlay::destroy(id) {
                    Ok(()) => shell_println!("Overlay '{}' destroyed.", parts[1]),
                    Err(e) => shell_println!("Error: {:?}", e),
                }
            } else {
                shell_println!("Overlay '{}' not found.", parts[1]);
            }
        }

        "ls" => {
            if parts.len() < 2 {
                shell_println!("Usage: overlay ls NAME [PATH]");
                return;
            }
            if let Some(id) = overlay::find_by_name(parts[1]) {
                let rel = if parts.len() > 2 { parts[2] } else { "" };
                match overlay::readdir(id, rel) {
                    Ok(entries) => {
                        for e in &entries {
                            let type_char = match e.entry_type {
                                crate::fs::EntryType::Directory => "d",
                                crate::fs::EntryType::File => "-",
                                crate::fs::EntryType::Symlink => "l",
                                _ => "?",
                            };
                            // Show which layer.
                            let layer = overlay::which_layer(id, &if rel.is_empty() {
                                e.name.clone()
                            } else {
                                alloc::format!("{}/{}", rel, e.name)
                            }).unwrap_or(overlay::Layer::None);
                            let layer_tag = match layer {
                                overlay::Layer::Upper => "[upper]",
                                overlay::Layer::Lower => "[lower]",
                                overlay::Layer::Both => "[both] ",
                                overlay::Layer::None => "[none] ",
                            };
                            shell_println!("{} {} {:>8} {}", type_char, layer_tag, e.size, e.name);
                        }
                        shell_println!("({} entries)", entries.len());
                    }
                    Err(e) => shell_println!("Error: {:?}", e),
                }
            } else {
                shell_println!("Overlay '{}' not found.", parts[1]);
            }
        }

        "cat" => {
            if parts.len() < 3 {
                shell_println!("Usage: overlay cat NAME PATH");
                return;
            }
            if let Some(id) = overlay::find_by_name(parts[1]) {
                match overlay::read_file(id, parts[2]) {
                    Ok(data) => {
                        if let Ok(text) = core::str::from_utf8(&data) {
                            shell_println!("{}", text);
                        } else {
                            shell_println!("(binary data, {} bytes)", data.len());
                        }
                    }
                    Err(e) => shell_println!("Error: {:?}", e),
                }
            } else {
                shell_println!("Overlay '{}' not found.", parts[1]);
            }
        }

        "write" => {
            if parts.len() < 4 {
                shell_println!("Usage: overlay write NAME PATH DATA...");
                return;
            }
            if let Some(id) = overlay::find_by_name(parts[1]) {
                let data = parts[3..].join(" ");
                match overlay::write_file(id, parts[2], data.as_bytes()) {
                    Ok(()) => shell_println!("Written {} bytes to overlay.", data.len()),
                    Err(e) => shell_println!("Error: {:?}", e),
                }
            } else {
                shell_println!("Overlay '{}' not found.", parts[1]);
            }
        }

        "rm" => {
            if parts.len() < 3 {
                shell_println!("Usage: overlay rm NAME PATH");
                return;
            }
            if let Some(id) = overlay::find_by_name(parts[1]) {
                match overlay::remove(id, parts[2]) {
                    Ok(()) => shell_println!("Removed from overlay view."),
                    Err(e) => shell_println!("Error: {:?}", e),
                }
            } else {
                shell_println!("Overlay '{}' not found.", parts[1]);
            }
        }

        "which" => {
            if parts.len() < 3 {
                shell_println!("Usage: overlay which NAME PATH");
                return;
            }
            if let Some(id) = overlay::find_by_name(parts[1]) {
                match overlay::which_layer(id, parts[2]) {
                    Ok(layer) => {
                        let desc = match layer {
                            overlay::Layer::Upper => "upper (writable layer only)",
                            overlay::Layer::Lower => "lower (read-only base)",
                            overlay::Layer::Both => "both (upper overrides lower)",
                            overlay::Layer::None => "not found (or whited out)",
                        };
                        shell_println!("{}: {}", parts[2], desc);
                    }
                    Err(e) => shell_println!("Error: {:?}", e),
                }
            } else {
                shell_println!("Overlay '{}' not found.", parts[1]);
            }
        }

        "whiteouts" => {
            if parts.len() < 2 {
                shell_println!("Usage: overlay whiteouts NAME");
                return;
            }
            if let Some(id) = overlay::find_by_name(parts[1]) {
                match overlay::list_whiteouts(id) {
                    Ok(wos) => {
                        if wos.is_empty() {
                            shell_println!("No whiteout entries.");
                        } else {
                            for w in &wos {
                                shell_println!("  .wh.{}", w);
                            }
                            shell_println!("({} whiteouts)", wos.len());
                        }
                    }
                    Err(e) => shell_println!("Error: {:?}", e),
                }
            } else {
                shell_println!("Overlay '{}' not found.", parts[1]);
            }
        }

        "stats" => {
            if parts.len() < 2 {
                shell_println!("Usage: overlay stats NAME");
                return;
            }
            if let Some(id) = overlay::find_by_name(parts[1]) {
                match overlay::stats(id) {
                    Ok(s) => {
                        shell_println!("Overlay: {}", s.name);
                        shell_println!("  Lower: {}", s.lower_path);
                        shell_println!("  Upper: {}", s.upper_path);
                        shell_println!("  Whiteouts:    {}", s.whiteout_count);
                        shell_println!("  Opaque dirs:  {}", s.opaque_dir_count);
                        shell_println!("  Reads:        {}", s.reads);
                        shell_println!("  Writes:       {}", s.writes);
                        shell_println!("  Copy-ups:     {}", s.copyups);
                    }
                    Err(e) => shell_println!("Error: {:?}", e),
                }
            } else {
                shell_println!("Overlay '{}' not found.", parts[1]);
            }
        }

        "reset" => {
            if parts.len() < 2 {
                shell_println!("Usage: overlay reset NAME");
                return;
            }
            if let Some(id) = overlay::find_by_name(parts[1]) {
                match overlay::reset(id) {
                    Ok(removed) => shell_println!("Reset overlay '{}': removed {} upper entries.", parts[1], removed),
                    Err(e) => shell_println!("Error: {:?}", e),
                }
            } else {
                shell_println!("Overlay '{}' not found.", parts[1]);
            }
        }

        "commit" => {
            if parts.len() < 2 {
                shell_println!("Usage: overlay commit NAME");
                return;
            }
            if let Some(id) = overlay::find_by_name(parts[1]) {
                match overlay::commit(id) {
                    Ok(applied) => shell_println!("Committed overlay '{}': {} changes applied to lower.", parts[1], applied),
                    Err(e) => shell_println!("Error: {:?}", e),
                }
            } else {
                shell_println!("Overlay '{}' not found.", parts[1]);
            }
        }

        _ => {
            shell_println!("Unknown overlay subcommand: {}", parts[0]);
            shell_println!("Usage: overlay <list|create|destroy|ls|cat|write|rm|which|whiteouts|stats|reset|commit>");
        }
    }
}

/// `mkfifo PATH` — create a named pipe.
///
/// Usage:
///   mkfifo /tmp/mypipe            - create with default 64K buffer
///   mkfifo -s 8192 /tmp/mypipe    - create with 8K buffer
fn cmd_mkfifo(args: &str) {
    use crate::fs::pipe;

    let parts: Vec<&str> = args.split_whitespace().collect();
    if parts.is_empty() {
        shell_println!("Usage: mkfifo [-s SIZE] PATH");
        return;
    }

    let (capacity, path) = if parts[0] == "-s" {
        if parts.len() < 3 {
            shell_println!("Usage: mkfifo -s SIZE PATH");
            return;
        }
        if let Some(cap) = parse_size_suffix(parts[1]) {
            (cap as usize, parts[2])
        } else {
            shell_println!("Invalid size: {}", parts[1]);
            return;
        }
    } else {
        (pipe::DEFAULT_CAPACITY, parts[0])
    };

    let resolved = resolve_path(path);
    match pipe::mkfifo_with_capacity(&resolved, capacity) {
        Ok(id) => shell_println!("Named pipe created: {} (id={}, capacity={})", resolved, id, capacity),
        Err(e) => shell_println!("Error: {:?}", e),
    }
}

/// `lspipe` / `pipes` — list named pipes.
fn cmd_lspipe(_args: &str) {
    use crate::fs::pipe;

    let pipes = pipe::list();
    if pipes.is_empty() {
        shell_println!("No active named pipes.");
        return;
    }

    shell_println!("{:<30} {:>8} {:>8} {:>4} {:>4} {:>12} {:>12}",
        "Path", "Capacity", "Buffered", "R", "W", "BytesIn", "BytesOut");
    shell_println!("{}", "-".repeat(82));
    for p in &pipes {
        shell_println!("{:<30} {:>8} {:>8} {:>4} {:>4} {:>12} {:>12}",
            p.path, p.capacity, p.buffered, p.readers, p.writers,
            p.bytes_written, p.bytes_read);
    }
    shell_println!("({} pipes)", pipes.len());
}

/// `tmpwatch` — manage automatic temporary file cleanup.
///
/// Usage:
///   tmpwatch --run                   - run cleanup now
///   tmpwatch --dry-run               - show what would be removed
///   tmpwatch --status                - show config and stats
///   tmpwatch --max-age SECONDS       - set max file age
///   tmpwatch --add DIR               - add watch directory
///   tmpwatch --remove DIR            - remove watch directory
///   tmpwatch --exclude PREFIX        - add exclude prefix
///   tmpwatch --enable / --disable    - enable/disable
fn cmd_tmpwatch(args: &str) {
    use crate::fs::tmpwatch;

    let parts: Vec<&str> = args.split_whitespace().collect();
    if parts.is_empty() {
        // Default: show status.
        let dirs = tmpwatch::watch_dirs();
        let exc = tmpwatch::excludes();
        let s = tmpwatch::stats();
        shell_println!("Tmpwatch status:");
        shell_println!("  Enabled:     {}", if tmpwatch::is_enabled() { "yes" } else { "no" });
        shell_println!("  Max age:     {} seconds", tmpwatch::max_age());
        shell_println!("  Watch dirs:  {}", if dirs.is_empty() { "(none)".into() } else { dirs.join(", ") });
        shell_println!("  Excludes:    {}", if exc.is_empty() { "(none)".into() } else { exc.join(", ") });
        shell_println!("  Runs:        {}", s.runs);
        shell_println!("  Removed:     {} files ({} bytes)", s.total_files_removed, s.total_bytes_freed);
        return;
    }

    match parts[0] {
        "--run" | "run" | "-r" => {
            // Use current time from RTC if available, or 0.
            let now = crate::timekeeping::clock_realtime() / 1_000_000_000;
            match tmpwatch::run(now) {
                Ok(result) => {
                    shell_println!("Cleanup complete: {} files removed, {} bytes freed, {} skipped, {} errors",
                        result.files_removed, result.bytes_freed, result.files_skipped, result.errors);
                    if !result.removed_paths.is_empty() {
                        for p in &result.removed_paths {
                            shell_println!("  removed: {}", p);
                        }
                    }
                }
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }

        "--dry-run" | "dry-run" | "-n" => {
            let now = crate::timekeeping::clock_realtime() / 1_000_000_000;
            match tmpwatch::dry_run(now) {
                Ok(candidates) => {
                    if candidates.is_empty() {
                        shell_println!("No files would be removed.");
                    } else {
                        shell_println!("Would remove {} files:", candidates.len());
                        let mut total = 0u64;
                        for (path, size) in &candidates {
                            shell_println!("  {} ({} bytes)", path, size);
                            total = total.saturating_add(*size);
                        }
                        shell_println!("Total: {} bytes", total);
                    }
                }
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }

        "--status" | "status" | "-s" => {
            let dirs = tmpwatch::watch_dirs();
            let exc = tmpwatch::excludes();
            let s = tmpwatch::stats();
            shell_println!("Tmpwatch status:");
            shell_println!("  Enabled:     {}", if tmpwatch::is_enabled() { "yes" } else { "no" });
            shell_println!("  Max age:     {} seconds", tmpwatch::max_age());
            shell_println!("  Watch dirs:");
            for d in &dirs { shell_println!("    {}", d); }
            shell_println!("  Excludes:");
            for e in &exc { shell_println!("    {}", e); }
            shell_println!("  Stats:");
            shell_println!("    Runs:            {}", s.runs);
            shell_println!("    Files removed:   {}", s.total_files_removed);
            shell_println!("    Bytes freed:     {}", s.total_bytes_freed);
        }

        "--max-age" | "max-age" => {
            if parts.len() < 2 {
                shell_println!("Current max age: {} seconds", tmpwatch::max_age());
                return;
            }
            if let Ok(secs) = parts[1].parse::<u64>() {
                tmpwatch::set_max_age(secs);
                shell_println!("Max age set to {} seconds.", secs);
            } else {
                shell_println!("Invalid value: {}", parts[1]);
            }
        }

        "--add" | "add" => {
            if parts.len() < 2 {
                shell_println!("Usage: tmpwatch --add DIR");
                return;
            }
            let dir = resolve_path(parts[1]);
            match tmpwatch::add_watch_dir(&dir) {
                Ok(()) => shell_println!("Added watch directory: {}", dir),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }

        "--remove" | "remove" => {
            if parts.len() < 2 {
                shell_println!("Usage: tmpwatch --remove DIR");
                return;
            }
            if tmpwatch::remove_watch_dir(parts[1]) {
                shell_println!("Removed watch directory: {}", parts[1]);
            } else {
                shell_println!("Directory not in watch list: {}", parts[1]);
            }
        }

        "--exclude" | "exclude" => {
            if parts.len() < 2 {
                shell_println!("Usage: tmpwatch --exclude PREFIX");
                return;
            }
            tmpwatch::add_exclude(parts[1]);
            shell_println!("Added exclude: {}", parts[1]);
        }

        "--enable" | "enable" => {
            tmpwatch::set_enabled(true);
            shell_println!("Tmpwatch enabled.");
        }

        "--disable" | "disable" => {
            tmpwatch::set_enabled(false);
            shell_println!("Tmpwatch disabled.");
        }

        "--init" | "init" => {
            tmpwatch::init();
            shell_println!("Tmpwatch initialized with defaults.");
        }

        _ => {
            shell_println!("Usage: tmpwatch [--run|--dry-run|--status|--max-age N|--add DIR|--remove DIR|--exclude PREFIX|--enable|--disable|--init]");
        }
    }
}

/// `audit` — filesystem audit logging.
///
/// Usage:
///   audit                          - show status
///   audit enable / disable         - toggle
///   audit log [-n N]               - show recent entries
///   audit add-rule [PATH_PREFIX] [--writes|--security|--all] [--uid UID] [--failures]
///   audit rm-rule ID               - remove rule
///   audit rules                    - list rules
///   audit search [--op OP] [--path PREFIX] [--uid UID] [--failures]
///   audit clear                    - clear log buffer
///   audit stats                    - show statistics
fn cmd_audit(args: &str) {
    use crate::fs::audit;

    let parts: Vec<&str> = args.split_whitespace().collect();
    if parts.is_empty() {
        // Show status.
        let s = audit::stats();
        shell_println!("Audit: {}", if s.enabled { "enabled" } else { "disabled" });
        shell_println!("  Rules:        {}", s.rules_count);
        shell_println!("  Buffer:       {}/{}", s.buffer_used, s.buffer_size);
        shell_println!("  Total events: {}", s.total_events);
        shell_println!("  Dropped:      {}", s.dropped_events);
        return;
    }

    match parts[0] {
        "enable" => {
            audit::enable();
            shell_println!("Audit logging enabled.");
        }
        "disable" => {
            audit::disable();
            shell_println!("Audit logging disabled.");
        }

        "log" | "show" => {
            let n = if parts.len() > 1 {
                if parts[1] == "-n" && parts.len() > 2 {
                    parts[2].parse::<usize>().unwrap_or(20)
                } else {
                    parts[1].parse::<usize>().unwrap_or(20)
                }
            } else {
                20
            };
            let entries = audit::recent(n);
            if entries.is_empty() {
                shell_println!("No audit entries.");
                return;
            }
            shell_println!("{:<6} {:<10} {:<8} {:>5} {:<5} {}",
                "Seq", "Timestamp", "Op", "UID", "OK?", "Path");
            shell_println!("{}", "-".repeat(70));
            for e in &entries {
                let ok = if e.success { "OK" } else { "FAIL" };
                let path_display = if let Some(p2) = &e.path2 {
                    alloc::format!("{} -> {}", e.path, p2)
                } else {
                    e.path.clone()
                };
                shell_println!("{:<6} {:<10} {:<8} {:>5} {:<5} {}",
                    e.seq, e.timestamp, e.op.name(), e.uid, ok, path_display);
            }
        }

        "add-rule" => {
            let mut prefix = "";
            let mut mask = audit::AuditMask::ALL;
            let mut uid: Option<u32> = None;
            let mut failures = false;

            let mut i = 1;
            while i < parts.len() {
                match parts[i] {
                    "--writes" => mask = audit::AuditMask::WRITES,
                    "--security" => mask = audit::AuditMask::SECURITY,
                    "--all" => mask = audit::AuditMask::ALL,
                    "--failures" => failures = true,
                    "--uid" => {
                        if i + 1 < parts.len() {
                            i += 1;
                            uid = parts[i].parse::<u32>().ok();
                        }
                    }
                    _ => prefix = parts[i],
                }
                i += 1;
            }

            let id = audit::add_rule(prefix, mask, uid, failures);
            shell_println!("Audit rule {} added (prefix='{}', mask=0x{:X}, uid={:?}, failures_only={})",
                id, prefix, mask.0, uid, failures);
        }

        "rm-rule" => {
            if parts.len() < 2 {
                shell_println!("Usage: audit rm-rule ID");
                return;
            }
            if let Ok(id) = parts[1].parse::<u64>() {
                if audit::remove_rule(id) {
                    shell_println!("Rule {} removed.", id);
                } else {
                    shell_println!("Rule {} not found.", id);
                }
            } else {
                shell_println!("Invalid rule ID: {}", parts[1]);
            }
        }

        "rules" => {
            let rules = audit::list_rules();
            if rules.is_empty() {
                shell_println!("No audit rules configured.");
                return;
            }
            shell_println!("{:<4} {:<6} {:<24} {:>10} {:>6} {}",
                "ID", "Active", "Path prefix", "Mask", "UID", "Flags");
            shell_println!("{}", "-".repeat(60));
            for r in &rules {
                let flags = if r.failures_only { "fail-only" } else { "" };
                let uid_str = r.uid.map(|u| alloc::format!("{}", u)).unwrap_or_else(|| String::from("*"));
                shell_println!("{:<4} {:<6} {:<24} 0x{:>08X} {:>6} {}",
                    r.id, if r.enabled { "yes" } else { "no" },
                    if r.path_prefix.is_empty() { "(all)" } else { &r.path_prefix },
                    r.mask.0, uid_str, flags);
            }
        }

        "search" => {
            let mut op_filter: Option<audit::AuditOp> = None;
            let mut path_prefix: Option<&str> = None;
            let mut uid_filter: Option<u32> = None;
            let mut failures = false;

            let mut i = 1;
            while i < parts.len() {
                match parts[i] {
                    "--op" => {
                        if i + 1 < parts.len() {
                            i += 1;
                            op_filter = match parts[i].to_uppercase().as_str() {
                                "READ" => Some(audit::AuditOp::Read),
                                "WRITE" => Some(audit::AuditOp::Write),
                                "DELETE" => Some(audit::AuditOp::Delete),
                                "RENAME" => Some(audit::AuditOp::Rename),
                                "CHMOD" => Some(audit::AuditOp::Chmod),
                                "CHOWN" => Some(audit::AuditOp::Chown),
                                "MKDIR" => Some(audit::AuditOp::Mkdir),
                                "RMDIR" => Some(audit::AuditOp::Rmdir),
                                _ => None,
                            };
                        }
                    }
                    "--path" => {
                        if i + 1 < parts.len() {
                            i += 1;
                            path_prefix = Some(parts[i]);
                        }
                    }
                    "--uid" => {
                        if i + 1 < parts.len() {
                            i += 1;
                            uid_filter = parts[i].parse::<u32>().ok();
                        }
                    }
                    "--failures" => failures = true,
                    _ => {}
                }
                i += 1;
            }

            let results = audit::search(50, op_filter, path_prefix, uid_filter, failures);
            if results.is_empty() {
                shell_println!("No matching entries.");
                return;
            }
            for e in &results {
                let ok = if e.success { "OK" } else { "FAIL" };
                shell_println!("[{}] {} uid={} {} {} {}",
                    e.seq, e.op.name(), e.uid, ok, e.path,
                    e.path2.as_deref().unwrap_or(""));
            }
            shell_println!("({} results)", results.len());
        }

        "clear" => {
            audit::clear();
            shell_println!("Audit log cleared.");
        }

        "stats" => {
            let s = audit::stats();
            shell_println!("Audit statistics:");
            shell_println!("  Enabled:      {}", s.enabled);
            shell_println!("  Rules:        {}", s.rules_count);
            shell_println!("  Buffer:       {}/{} entries", s.buffer_used, s.buffer_size);
            shell_println!("  Total events: {}", s.total_events);
            shell_println!("  Dropped:      {}", s.dropped_events);
        }

        _ => {
            shell_println!("Usage: audit [enable|disable|log|add-rule|rm-rule|rules|search|clear|stats]");
        }
    }
}

/// `namespace` / `ns` — manage mount namespaces.
///
/// Usage:
///   namespace list                      - list all namespaces
///   namespace create NAME [PARENT_ID]   - create child namespace
///   namespace destroy ID                - destroy namespace
///   namespace mounts ID                 - list mounts in namespace
///   namespace mount ID PATH TYPE [ro]   - add mount to namespace
///   namespace unmount ID PATH           - remove mount from namespace
///   namespace info ID                   - show namespace details
///   namespace init                      - initialize namespace subsystem
fn cmd_namespace(args: &str) {
    use crate::fs::mount_ns;

    let parts: Vec<&str> = args.split_whitespace().collect();
    if parts.is_empty() {
        let nss = mount_ns::list();
        if nss.is_empty() {
            shell_println!("No namespaces (run `namespace init` first).");
            return;
        }
        shell_println!("{:<4} {:<16} {:>6} {:>6} {:>4}",
            "ID", "Name", "Parent", "Mounts", "Refs");
        shell_println!("{}", "-".repeat(40));
        for ns in &nss {
            let parent = ns.parent.map(|p| alloc::format!("{}", p)).unwrap_or_else(|| String::from("-"));
            shell_println!("{:<4} {:<16} {:>6} {:>6} {:>4}",
                ns.id, ns.name, parent, ns.mount_count, ns.refcount);
        }
        return;
    }

    match parts[0] {
        "init" => {
            mount_ns::init();
            shell_println!("Mount namespace subsystem initialized.");
        }

        "list" | "ls" => {
            let nss = mount_ns::list();
            if nss.is_empty() {
                shell_println!("No namespaces.");
                return;
            }
            shell_println!("{:<4} {:<16} {:>6} {:>6} {:>4} {}",
                "ID", "Name", "Parent", "Mounts", "Refs", "Nested");
            shell_println!("{}", "-".repeat(55));
            for ns in &nss {
                let parent = ns.parent.map(|p| alloc::format!("{}", p)).unwrap_or_else(|| String::from("-"));
                shell_println!("{:<4} {:<16} {:>6} {:>6} {:>4} {}",
                    ns.id, ns.name, parent, ns.mount_count, ns.refcount,
                    if ns.allow_nested { "yes" } else { "no" });
            }
        }

        "create" => {
            if parts.len() < 2 {
                shell_println!("Usage: namespace create NAME [PARENT_ID]");
                return;
            }
            let name = parts[1];
            let parent = if parts.len() > 2 {
                parts[2].parse::<u64>().unwrap_or(mount_ns::ROOT_NAMESPACE)
            } else {
                mount_ns::ROOT_NAMESPACE
            };
            match mount_ns::create(parent, name) {
                Ok(id) => shell_println!("Namespace '{}' created (id={})", name, id),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }

        "destroy" => {
            if parts.len() < 2 {
                shell_println!("Usage: namespace destroy ID");
                return;
            }
            if let Ok(id) = parts[1].parse::<u64>() {
                match mount_ns::destroy(id) {
                    Ok(()) => shell_println!("Namespace {} destroyed.", id),
                    Err(e) => shell_println!("Error: {:?}", e),
                }
            } else {
                shell_println!("Invalid ID: {}", parts[1]);
            }
        }

        "mounts" => {
            if parts.len() < 2 {
                shell_println!("Usage: namespace mounts ID");
                return;
            }
            if let Ok(id) = parts[1].parse::<u64>() {
                match mount_ns::ns_mounts(id) {
                    Ok(mounts) => {
                        shell_println!("{:<24} {:<12} {}",
                            "Mount point", "Type", "Flags");
                        shell_println!("{}", "-".repeat(42));
                        for m in &mounts {
                            let flags = if m.readonly { "ro" } else { "rw" };
                            shell_println!("{:<24} {:<12} {}", m.mount_path, m.fs_type, flags);
                        }
                        shell_println!("({} mounts)", mounts.len());
                    }
                    Err(e) => shell_println!("Error: {:?}", e),
                }
            } else {
                shell_println!("Invalid ID: {}", parts[1]);
            }
        }

        "mount" => {
            if parts.len() < 4 {
                shell_println!("Usage: namespace mount ID PATH TYPE [ro]");
                return;
            }
            if let Ok(id) = parts[1].parse::<u64>() {
                let ro = parts.get(4) == Some(&"ro");
                match mount_ns::ns_mount(id, parts[2], parts[3], ro) {
                    Ok(()) => shell_println!("Mounted {} ({}) in namespace {}",
                        parts[2], parts[3], id),
                    Err(e) => shell_println!("Error: {:?}", e),
                }
            } else {
                shell_println!("Invalid ID: {}", parts[1]);
            }
        }

        "unmount" => {
            if parts.len() < 3 {
                shell_println!("Usage: namespace unmount ID PATH");
                return;
            }
            if let Ok(id) = parts[1].parse::<u64>() {
                match mount_ns::ns_unmount(id, parts[2]) {
                    Ok(()) => shell_println!("Unmounted {} from namespace {}", parts[2], id),
                    Err(e) => shell_println!("Error: {:?}", e),
                }
            } else {
                shell_println!("Invalid ID: {}", parts[1]);
            }
        }

        "info" => {
            if parts.len() < 2 {
                shell_println!("Usage: namespace info ID");
                return;
            }
            if let Ok(id) = parts[1].parse::<u64>() {
                match mount_ns::info(id) {
                    Ok(i) => {
                        shell_println!("Namespace {}:", i.id);
                        shell_println!("  Name:       {}", i.name);
                        shell_println!("  Parent:     {:?}", i.parent);
                        shell_println!("  Mounts:     {}", i.mount_count);
                        shell_println!("  Refcount:   {}", i.refcount);
                        shell_println!("  Nested OK:  {}", i.allow_nested);
                    }
                    Err(e) => shell_println!("Error: {:?}", e),
                }
            } else {
                shell_println!("Invalid ID: {}", parts[1]);
            }
        }

        _ => {
            shell_println!("Usage: namespace [list|create|destroy|mounts|mount|unmount|info|init]");
        }
    }
}

/// `fssnapshot` / `fssnap` — filesystem snapshot management.
///
/// Subcommands:
///   create PATH NAME [--parent ID]   Create a snapshot of PATH
///   restore ID [TARGET]              Restore snapshot to TARGET (or original path)
///   list                             List all snapshots
///   info ID                          Show snapshot details
///   diff ID1 ID2                     Compare two snapshots
///   delete ID                        Delete a snapshot
///   entries ID                       List all entries in a snapshot
fn cmd_fssnapshot(args: &str) {
    use crate::fs::snapshot;

    let parts: Vec<&str> = args.split_whitespace().collect();
    if parts.is_empty() {
        shell_println!("Usage: fssnapshot <create|restore|list|info|diff|delete|entries> ...");
        shell_println!("");
        shell_println!("  create PATH NAME [--parent ID]  — create snapshot of directory tree");
        shell_println!("  restore ID [TARGET]             — restore snapshot to target path");
        shell_println!("  list                            — list all snapshots");
        shell_println!("  info ID                         — show snapshot details");
        shell_println!("  diff ID1 ID2                    — compare two snapshots");
        shell_println!("  delete ID                       — delete a snapshot");
        shell_println!("  entries ID                      — list entries in snapshot");
        return;
    }

    match parts[0] {
        "create" => {
            if parts.len() < 3 {
                shell_println!("Usage: fssnapshot create PATH NAME [--parent ID]");
                return;
            }
            let path = parts[1];
            let name = parts[2];

            // Parse optional --parent ID.
            let mut parent = None;
            if parts.len() >= 5 && parts[3] == "--parent" {
                if let Ok(id) = parts[4].parse::<u64>() {
                    parent = Some(snapshot::SnapshotId(id));
                } else {
                    shell_println!("Error: invalid parent ID");
                    return;
                }
            }

            let opts = snapshot::SnapshotOptions::default();
            match snapshot::create(path, name, parent, &opts) {
                Ok(id) => {
                    let info = snapshot::info(id).ok();
                    if let Some(i) = info {
                        shell_println!(
                            "Snapshot '{}' created (id={}, {} files, {} bytes)",
                            i.name, i.id.0, i.file_count, i.total_bytes,
                        );
                    } else {
                        shell_println!("Snapshot created: id={}", id.0);
                    }
                }
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "restore" => {
            if parts.len() < 2 {
                shell_println!("Usage: fssnapshot restore ID [TARGET]");
                return;
            }
            let id = match parts[1].parse::<u64>() {
                Ok(v) => snapshot::SnapshotId(v),
                Err(_) => {
                    shell_println!("Error: invalid snapshot ID");
                    return;
                }
            };
            // Target: either specified or use original root_path.
            let target = if parts.len() >= 3 {
                parts[2]
            } else {
                match snapshot::info(id) {
                    Ok(i) => {
                        // We need to use the root_path, but we can't borrow from KernelResult
                        // because the String is temporary. Use a fallback approach.
                        shell_println!("Restoring to original path: {}", i.root_path);
                        // Re-fetch info for the path.
                        let info = snapshot::info(id).expect("just checked");
                        let target = info.root_path.clone();
                        match snapshot::restore(id, &target) {
                            Ok(r) => {
                                shell_println!(
                                    "Restored: {} files, {} dirs, {} symlinks, {} errors",
                                    r.files_restored, r.dirs_created, r.symlinks_created, r.errors,
                                );
                            }
                            Err(e) => shell_println!("Error: {:?}", e),
                        }
                        return;
                    }
                    Err(e) => {
                        shell_println!("Error: {:?}", e);
                        return;
                    }
                }
            };
            match snapshot::restore(id, target) {
                Ok(r) => {
                    shell_println!(
                        "Restored: {} files, {} dirs, {} symlinks, {} errors",
                        r.files_restored, r.dirs_created, r.symlinks_created, r.errors,
                    );
                }
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "list" => {
            let snaps = snapshot::list();
            if snaps.is_empty() {
                shell_println!("No snapshots.");
                return;
            }
            shell_println!("{:>4}  {:20}  {:30}  {:>8}  {:>12}  {}",
                "ID", "NAME", "PATH", "FILES", "BYTES", "PARENT");
            for s in &snaps {
                let parent_str = s.parent
                    .map(|p| alloc::format!("{}", p.0))
                    .unwrap_or_else(|| "-".to_string());
                shell_println!("{:>4}  {:20}  {:30}  {:>8}  {:>12}  {}",
                    s.id.0, s.name, s.root_path, s.file_count, s.total_bytes, parent_str);
            }
        }
        "info" => {
            if parts.len() < 2 {
                shell_println!("Usage: fssnapshot info ID");
                return;
            }
            let id = match parts[1].parse::<u64>() {
                Ok(v) => snapshot::SnapshotId(v),
                Err(_) => {
                    shell_println!("Error: invalid ID");
                    return;
                }
            };
            match snapshot::info(id) {
                Ok(i) => {
                    shell_println!("Snapshot ID: {}", i.id.0);
                    shell_println!("  Name:   {}", i.name);
                    shell_println!("  Path:   {}", i.root_path);
                    shell_println!("  Files:  {}", i.file_count);
                    shell_println!("  Bytes:  {}", i.total_bytes);
                    shell_println!("  Parent: {}", i.parent
                        .map(|p| alloc::format!("{}", p.0))
                        .unwrap_or_else(|| "none".to_string()));
                    let kids = snapshot::children(i.id);
                    if !kids.is_empty() {
                        let ids: Vec<_> = kids.iter()
                            .map(|k| alloc::format!("{}", k.0))
                            .collect();
                        shell_println!("  Children: {}", ids.join(", "));
                    }
                }
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "diff" => {
            if parts.len() < 3 {
                shell_println!("Usage: fssnapshot diff ID1 ID2");
                return;
            }
            let id1 = match parts[1].parse::<u64>() {
                Ok(v) => snapshot::SnapshotId(v),
                Err(_) => {
                    shell_println!("Error: invalid ID1");
                    return;
                }
            };
            let id2 = match parts[2].parse::<u64>() {
                Ok(v) => snapshot::SnapshotId(v),
                Err(_) => {
                    shell_println!("Error: invalid ID2");
                    return;
                }
            };
            match snapshot::diff(id1, id2) {
                Ok((added, removed, modified)) => {
                    if added.is_empty() && removed.is_empty() && modified.is_empty() {
                        shell_println!("Snapshots are identical.");
                    } else {
                        for p in &added {
                            shell_println!("  + {}", p);
                        }
                        for p in &removed {
                            shell_println!("  - {}", p);
                        }
                        for p in &modified {
                            shell_println!("  ~ {}", p);
                        }
                        shell_println!("");
                        shell_println!("{} added, {} removed, {} modified",
                            added.len(), removed.len(), modified.len());
                    }
                }
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "delete" => {
            if parts.len() < 2 {
                shell_println!("Usage: fssnapshot delete ID");
                return;
            }
            let id = match parts[1].parse::<u64>() {
                Ok(v) => snapshot::SnapshotId(v),
                Err(_) => {
                    shell_println!("Error: invalid ID");
                    return;
                }
            };
            match snapshot::delete(id) {
                Ok(()) => shell_println!("Snapshot {} deleted.", id.0),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "entries" => {
            if parts.len() < 2 {
                shell_println!("Usage: fssnapshot entries ID");
                return;
            }
            let id = match parts[1].parse::<u64>() {
                Ok(v) => snapshot::SnapshotId(v),
                Err(_) => {
                    shell_println!("Error: invalid ID");
                    return;
                }
            };
            match snapshot::entries(id) {
                Ok(ents) => {
                    for e in &ents {
                        let t = match e.entry_type {
                            crate::fs::EntryType::File => "F",
                            crate::fs::EntryType::Directory => "D",
                            crate::fs::EntryType::Symlink => "L",
                            _ => "?",
                        };
                        let hash_str = e.content_hash
                            .as_ref()
                            .map(snapshot::hash_to_hex)
                            .map(|s| {
                                // Show first 16 hex chars.
                                let short: String = s.chars().take(16).collect();
                                short
                            })
                            .unwrap_or_else(|| "-".to_string());
                        shell_println!("  {} {:>8}  {}  {}",
                            t, e.size, hash_str, e.path);
                    }
                    shell_println!("{} entries", ents.len());
                }
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        _ => {
            shell_println!("Unknown subcommand: {}", parts[0]);
            shell_println!("Use: create, restore, list, info, diff, delete, entries");
        }
    }
}

/// `reclaim` — disk space reclamation management.
///
/// Subcommands:
///   run          Force a reclamation pass now
///   status       Show reclamation stats and config
///   enable/disable  Toggle auto-reclamation
///   watermark HIGH LOW  Set trigger/stop thresholds
fn cmd_reclaim(args: &str) {
    use crate::fs::reclaim;

    let parts: Vec<&str> = args.split_whitespace().collect();
    match parts.first().copied().unwrap_or("status") {
        "run" | "--run" => {
            shell_println!("Running space reclamation...");
            match reclaim::run() {
                Some(r) => {
                    shell_println!("Reclamation complete:");
                    shell_println!("  Cache flushed:    {} bytes", r.cache_freed);
                    shell_println!("  CAS GC:           {} blobs, {} bytes", r.cas_gc_blobs, r.cas_gc_bytes);
                    shell_println!("  Tmpwatch cleaned: {} files", r.tmpwatch_cleaned);
                    shell_println!("  Trash purged:     {} items", r.trash_purged);
                    shell_println!("  Journal flushed:  {} entries", r.journal_trimmed);
                    shell_println!("  Total freed:      ~{} bytes", r.total_freed);
                    shell_println!("  Disk usage after: {}%", r.usage_after);
                }
                None => shell_println!("Reclamation already running or disabled."),
            }
        }
        "status" | "stats" => {
            let s = reclaim::stats();
            let (hi, lo) = reclaim::watermarks();
            let p = reclaim::phases();
            shell_println!("Space reclamation: {}", if reclaim::is_enabled() { "enabled" } else { "disabled" });
            shell_println!("  Watermarks:    high={}% low={}%", hi, lo);
            shell_println!("  Triggers:      {}", s.trigger_count);
            shell_println!("  Total freed:   {} bytes", s.total_bytes_freed);
            shell_println!("  CAS blobs:     {}", s.total_cas_blobs);
            shell_println!("  Tmpwatch files:{}", s.total_tmpwatch_files);
            shell_println!("  Trash items:   {}", s.total_trash_items);
            shell_println!("  Journal ents:  {}", s.total_journal_entries);
            shell_println!("  Active:        {}", s.active);
            shell_println!("  Phases: cache={} cas={} tmp={} trash={} journal={}",
                p.cache, p.cas_gc, p.tmpwatch, p.trash, p.journal);
        }
        "enable" => {
            reclaim::set_enabled(true);
            shell_println!("Reclamation enabled.");
        }
        "disable" => {
            reclaim::set_enabled(false);
            shell_println!("Reclamation disabled.");
        }
        "watermark" => {
            if parts.len() < 3 {
                shell_println!("Usage: reclaim watermark HIGH LOW  (e.g., 90 80)");
                return;
            }
            let hi = parts[1].parse::<u64>().unwrap_or(90);
            let lo = parts[2].parse::<u64>().unwrap_or(80);
            if lo >= hi {
                shell_println!("Error: LOW must be < HIGH");
                return;
            }
            reclaim::set_high_watermark(hi);
            reclaim::set_low_watermark(lo);
            shell_println!("Watermarks set: high={}% low={}%", hi, lo);
        }
        _ => {
            shell_println!("Usage: reclaim [run|status|enable|disable|watermark HIGH LOW]");
        }
    }
}

/// `fstx` — filesystem atomic transactions.
///
/// Subcommands:
///   fstx begin [LABEL]              - start a new transaction
///   fstx write TXID PATH DATA       - queue a file write
///   fstx remove TXID PATH           - queue a file removal
///   fstx mkdir TXID PATH            - queue a directory creation
///   fstx rename TXID FROM TO        - queue a rename
///   fstx symlink TXID PATH TARGET   - queue a symlink creation
///   fstx commit TXID                - commit (execute) the transaction
///   fstx rollback TXID              - discard the transaction
///   fstx info TXID                  - show transaction details
///   fstx list                       - list all transactions
///   fstx delete TXID                - remove a completed transaction
fn cmd_fstx(args: &str) {
    use crate::fs::transaction;

    let parts: Vec<&str> = args.split_whitespace().collect();
    match parts.first().copied().unwrap_or("list") {
        "begin" | "start" => {
            let label = if parts.len() > 1 {
                parts[1..].join(" ")
            } else {
                alloc::string::String::new()
            };
            match transaction::begin_with_label(&label) {
                Ok(id) => shell_println!("Transaction {} started.", id.0),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "write" => {
            if parts.len() < 4 {
                shell_println!("Usage: fstx write TXID PATH DATA");
                return;
            }
            let id = match parts[1].parse::<u64>() {
                Ok(n) => transaction::TxId(n),
                Err(_) => { shell_println!("Invalid TXID"); return; }
            };
            let path = resolve_path(parts[2]);
            let data = parts[3..].join(" ");
            match transaction::tx_write(id, &path, data.as_bytes()) {
                Ok(()) => shell_println!("Queued write to {} in tx {}", path, id.0),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "remove" | "rm" => {
            if parts.len() < 3 {
                shell_println!("Usage: fstx remove TXID PATH");
                return;
            }
            let id = match parts[1].parse::<u64>() {
                Ok(n) => transaction::TxId(n),
                Err(_) => { shell_println!("Invalid TXID"); return; }
            };
            let path = resolve_path(parts[2]);
            match transaction::tx_remove(id, &path) {
                Ok(()) => shell_println!("Queued removal of {} in tx {}", path, id.0),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "mkdir" => {
            if parts.len() < 3 {
                shell_println!("Usage: fstx mkdir TXID PATH");
                return;
            }
            let id = match parts[1].parse::<u64>() {
                Ok(n) => transaction::TxId(n),
                Err(_) => { shell_println!("Invalid TXID"); return; }
            };
            let path = resolve_path(parts[2]);
            match transaction::tx_mkdir(id, &path) {
                Ok(()) => shell_println!("Queued mkdir {} in tx {}", path, id.0),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "rename" | "mv" => {
            if parts.len() < 4 {
                shell_println!("Usage: fstx rename TXID FROM TO");
                return;
            }
            let id = match parts[1].parse::<u64>() {
                Ok(n) => transaction::TxId(n),
                Err(_) => { shell_println!("Invalid TXID"); return; }
            };
            let from = resolve_path(parts[2]);
            let to = resolve_path(parts[3]);
            match transaction::tx_rename(id, &from, &to) {
                Ok(()) => shell_println!("Queued rename {} -> {} in tx {}", from, to, id.0),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "symlink" | "link" => {
            if parts.len() < 4 {
                shell_println!("Usage: fstx symlink TXID PATH TARGET");
                return;
            }
            let id = match parts[1].parse::<u64>() {
                Ok(n) => transaction::TxId(n),
                Err(_) => { shell_println!("Invalid TXID"); return; }
            };
            let path = resolve_path(parts[2]);
            let target = parts[3];
            match transaction::tx_symlink(id, &path, target) {
                Ok(()) => shell_println!("Queued symlink {} -> {} in tx {}", path, target, id.0),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "commit" => {
            if parts.len() < 2 {
                shell_println!("Usage: fstx commit TXID");
                return;
            }
            let id = match parts[1].parse::<u64>() {
                Ok(n) => transaction::TxId(n),
                Err(_) => { shell_println!("Invalid TXID"); return; }
            };
            match transaction::commit(id) {
                Ok(()) => shell_println!("Transaction {} committed successfully.", id.0),
                Err(e) => shell_println!("Transaction {} failed: {:?}", id.0, e),
            }
        }
        "rollback" | "abort" => {
            if parts.len() < 2 {
                shell_println!("Usage: fstx rollback TXID");
                return;
            }
            let id = match parts[1].parse::<u64>() {
                Ok(n) => transaction::TxId(n),
                Err(_) => { shell_println!("Invalid TXID"); return; }
            };
            match transaction::rollback(id) {
                Ok(()) => shell_println!("Transaction {} rolled back.", id.0),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "info" | "show" => {
            if parts.len() < 2 {
                shell_println!("Usage: fstx info TXID");
                return;
            }
            let id = match parts[1].parse::<u64>() {
                Ok(n) => transaction::TxId(n),
                Err(_) => { shell_println!("Invalid TXID"); return; }
            };
            match transaction::info(id) {
                Ok(i) => {
                    shell_println!("Transaction {}:", i.id.0);
                    shell_println!("  State: {:?}", i.state);
                    shell_println!("  Ops:   {}", i.ops_count);
                    shell_println!("  Label: {}", if i.label.is_empty() { "(none)" } else { &i.label });
                }
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "list" | "ls" => {
            let txns = transaction::list();
            if txns.is_empty() {
                shell_println!("No transactions.");
            } else {
                shell_println!("{:<6} {:<12} {:<6} {}", "ID", "STATE", "OPS", "LABEL");
                for t in &txns {
                    let state = match t.state {
                        transaction::TxState::Active => "active",
                        transaction::TxState::Committed => "committed",
                        transaction::TxState::RolledBack => "rolled-back",
                        transaction::TxState::Dirty => "DIRTY",
                    };
                    shell_println!("{:<6} {:<12} {:<6} {}", t.id.0, state, t.ops_count, t.label);
                }
            }
        }
        "delete" | "del" | "clean" => {
            if parts.len() < 2 {
                shell_println!("Usage: fstx delete TXID");
                return;
            }
            let id = match parts[1].parse::<u64>() {
                Ok(n) => transaction::TxId(n),
                Err(_) => { shell_println!("Invalid TXID"); return; }
            };
            match transaction::remove(id) {
                Ok(()) => shell_println!("Transaction {} removed.", id.0),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        _ => {
            shell_println!("Usage: fstx <begin|write|remove|mkdir|rename|symlink|commit|rollback|info|list|delete> [args...]");
        }
    }
}

/// `changetrack` / `ct` — persistent filesystem change tracking.
///
/// Subcommands:
///   ct register NAME          - register a new change cursor
///   ct unregister NAME        - remove a cursor
///   ct changes NAME [PATH]    - show changes since last check (advances cursor)
///   ct peek NAME [PATH]       - show changes without advancing cursor
///   ct reset NAME             - skip all pending changes
///   ct info NAME              - show cursor details
///   ct list / ct status       - list all cursors
///   ct flush                  - persist cursors to disk
fn cmd_changetrack(args: &str) {
    use crate::fs::changetrack;

    let parts: Vec<&str> = args.split_whitespace().collect();
    match parts.first().copied().unwrap_or("list") {
        "register" | "reg" | "add" => {
            if parts.len() < 2 {
                shell_println!("Usage: ct register NAME");
                return;
            }
            match changetrack::register(parts[1]) {
                Ok(()) => shell_println!("Cursor '{}' registered.", parts[1]),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "unregister" | "unreg" | "rm" | "remove" => {
            if parts.len() < 2 {
                shell_println!("Usage: ct unregister NAME");
                return;
            }
            match changetrack::unregister(parts[1]) {
                Ok(()) => shell_println!("Cursor '{}' removed.", parts[1]),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "changes" | "since" => {
            if parts.len() < 2 {
                shell_println!("Usage: ct changes NAME [PATH_PREFIX]");
                return;
            }
            let mut filter = changetrack::ChangeFilter::default();
            if parts.len() >= 3 {
                filter.path_prefixes = alloc::vec![alloc::string::String::from(resolve_path(parts[2]).as_str())];
            }
            match changetrack::changes(parts[1], &filter) {
                Ok(result) => {
                    if result.gap_detected {
                        shell_println!("WARNING: Some entries may have been lost (journal eviction).");
                    }
                    if result.changes.is_empty() {
                        shell_println!("No changes since last check.");
                    } else {
                        shell_println!("{} change(s):", result.changes.len());
                        for c in &result.changes {
                            let etype = match c.event_type {
                                crate::fs::journal::JournalEventType::Created => "CREATE",
                                crate::fs::journal::JournalEventType::Modified => "MODIFY",
                                crate::fs::journal::JournalEventType::Deleted => "DELETE",
                                crate::fs::journal::JournalEventType::Renamed => "RENAME",
                            };
                            if c.old_path.is_empty() {
                                shell_println!("  [{}] seq={} {}", etype, c.seq, c.path);
                            } else {
                                shell_println!("  [{}] seq={} {} -> {}", etype, c.seq, c.old_path, c.path);
                            }
                        }
                    }
                    shell_println!("Cursor advanced to seq {}.", result.new_seq);
                }
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "peek" | "preview" => {
            if parts.len() < 2 {
                shell_println!("Usage: ct peek NAME [PATH_PREFIX]");
                return;
            }
            let mut filter = changetrack::ChangeFilter::default();
            if parts.len() >= 3 {
                filter.path_prefixes = alloc::vec![alloc::string::String::from(resolve_path(parts[2]).as_str())];
            }
            match changetrack::peek(parts[1], &filter) {
                Ok(result) => {
                    if result.changes.is_empty() {
                        shell_println!("No pending changes.");
                    } else {
                        shell_println!("{} pending change(s) (cursor NOT advanced):", result.changes.len());
                        for c in &result.changes {
                            let etype = match c.event_type {
                                crate::fs::journal::JournalEventType::Created => "CREATE",
                                crate::fs::journal::JournalEventType::Modified => "MODIFY",
                                crate::fs::journal::JournalEventType::Deleted => "DELETE",
                                crate::fs::journal::JournalEventType::Renamed => "RENAME",
                            };
                            if c.old_path.is_empty() {
                                shell_println!("  [{}] seq={} {}", etype, c.seq, c.path);
                            } else {
                                shell_println!("  [{}] seq={} {} -> {}", etype, c.seq, c.old_path, c.path);
                            }
                        }
                    }
                }
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "reset" | "skip" => {
            if parts.len() < 2 {
                shell_println!("Usage: ct reset NAME");
                return;
            }
            match changetrack::reset(parts[1]) {
                Ok(()) => shell_println!("Cursor '{}' reset to current position.", parts[1]),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "info" | "show" => {
            if parts.len() < 2 {
                shell_println!("Usage: ct info NAME");
                return;
            }
            match changetrack::info(parts[1]) {
                Ok(i) => {
                    shell_println!("Cursor '{}':", i.name);
                    shell_println!("  Last seq:     {}", i.last_seq);
                    shell_println!("  Advances:     {}", i.advance_count);
                }
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "list" | "ls" | "status" => {
            let cursors = changetrack::list();
            if cursors.is_empty() {
                shell_println!("No change tracking cursors registered.");
            } else {
                shell_println!("{:<20} {:<10} {:<10}", "NAME", "LAST_SEQ", "ADVANCES");
                for c in &cursors {
                    shell_println!("{:<20} {:<10} {:<10}", c.name, c.last_seq, c.advance_count);
                }
            }
        }
        "flush" | "save" => {
            match changetrack::flush() {
                Ok(()) => shell_println!("Cursors persisted to disk."),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        _ => {
            shell_println!("Usage: ct <register|unregister|changes|peek|reset|info|list|flush> [args...]");
        }
    }
}

/// `fcompress` / `fc` — transparent filesystem compression.
///
/// Subcommands:
///   fc enable / fc disable         - toggle transparent compression
///   fc status                      - show stats and rules
///   fc algo ALGORITHM              - set default algorithm (lz4/gzip/zstd/bzip2/xz)
///   fc minsize BYTES               - set minimum file size for compression
///   fc rule add PREFIX [ALGO] [EXT,..] - add a compression rule
///   fc rule rm PREFIX              - remove rules for a prefix
///   fc rule list                   - list all rules
///   fc info PATH                   - show compression info for a file
///   fc compress PATH [ALGO]        - manually compress a file
///   fc decompress PATH             - manually decompress a file
fn cmd_fcompress(args: &str) {
    use crate::fs::fcompress;

    let parts: Vec<&str> = args.split_whitespace().collect();
    match parts.first().copied().unwrap_or("status") {
        "enable" | "on" => {
            fcompress::set_enabled(true);
            shell_println!("Transparent compression enabled.");
        }
        "disable" | "off" => {
            fcompress::set_enabled(false);
            shell_println!("Transparent compression disabled.");
        }
        "status" | "stats" => {
            let s = fcompress::stats();
            let algo = fcompress::default_algorithm();
            shell_println!("Transparent compression: {}", if fcompress::is_enabled() { "enabled" } else { "disabled" });
            shell_println!("  Default algorithm: {}", algo.name());
            shell_println!("  Min file size:     {} bytes", fcompress::min_size());
            shell_println!("  Files compressed:  {}", s.files_compressed);
            shell_println!("  Files decompressed:{}", s.files_decompressed);
            shell_println!("  Files skipped:     {}", s.files_skipped);
            if s.bytes_original > 0 {
                let ratio = s.bytes_original as f64 / s.bytes_stored.max(1) as f64;
                shell_println!("  Original bytes:    {}", s.bytes_original);
                shell_println!("  Stored bytes:      {}", s.bytes_stored);
                shell_println!("  Ratio:             {:.2}:1", ratio);
            }

            let rules = fcompress::list_rules();
            if rules.is_empty() {
                shell_println!("  Rules:             (none)");
            } else {
                shell_println!("  Rules:");
                for r in &rules {
                    let exts = if r.extensions.is_empty() {
                        alloc::string::String::from("*")
                    } else {
                        r.extensions.join(",")
                    };
                    shell_println!("    {} -> {} (ext: {})", r.path_prefix, r.algorithm.name(), exts);
                }
            }
        }
        "algo" | "algorithm" => {
            if parts.len() < 2 {
                shell_println!("Current: {}", fcompress::default_algorithm().name());
                shell_println!("Usage: fc algo <lz4|gzip|zstd|bzip2|xz>");
                return;
            }
            match fcompress::Algorithm::from_name(parts[1]) {
                Some(a) => {
                    fcompress::set_default_algorithm(a);
                    shell_println!("Default algorithm set to {}.", a.name());
                }
                None => shell_println!("Unknown algorithm: {}", parts[1]),
            }
        }
        "minsize" | "min" => {
            if parts.len() < 2 {
                shell_println!("Current: {} bytes", fcompress::min_size());
                return;
            }
            match parts[1].parse::<u64>() {
                Ok(n) => {
                    fcompress::set_min_size(n);
                    shell_println!("Min size set to {} bytes.", n);
                }
                Err(_) => shell_println!("Invalid number: {}", parts[1]),
            }
        }
        "rule" => {
            match parts.get(1).copied().unwrap_or("list") {
                "add" => {
                    if parts.len() < 3 {
                        shell_println!("Usage: fc rule add PREFIX [ALGO] [EXT1,EXT2,...]");
                        return;
                    }
                    let prefix = alloc::string::String::from(parts[2]);
                    let algo = if parts.len() > 3 {
                        fcompress::Algorithm::from_name(parts[3]).unwrap_or(fcompress::default_algorithm())
                    } else {
                        fcompress::default_algorithm()
                    };
                    let extensions: Vec<alloc::string::String> = if parts.len() > 4 {
                        parts[4].split(',').map(alloc::string::String::from).collect()
                    } else {
                        Vec::new()
                    };

                    match fcompress::add_rule(fcompress::CompressionRule {
                        path_prefix: prefix.clone(),
                        extensions,
                        algorithm: algo,
                    }) {
                        Ok(()) => shell_println!("Rule added: {} -> {}", prefix, algo.name()),
                        Err(e) => shell_println!("Error: {:?}", e),
                    }
                }
                "rm" | "remove" | "del" => {
                    if parts.len() < 3 {
                        shell_println!("Usage: fc rule rm PREFIX");
                        return;
                    }
                    let n = fcompress::remove_rules(parts[2]);
                    shell_println!("Removed {} rule(s).", n);
                }
                "list" | "ls" => {
                    let rules = fcompress::list_rules();
                    if rules.is_empty() {
                        shell_println!("No compression rules.");
                    } else {
                        shell_println!("{:<30} {:<8} {}", "PREFIX", "ALGO", "EXTENSIONS");
                        for r in &rules {
                            let exts = if r.extensions.is_empty() {
                                alloc::string::String::from("*")
                            } else {
                                r.extensions.join(",")
                            };
                            shell_println!("{:<30} {:<8} {}", r.path_prefix, r.algorithm.name(), exts);
                        }
                    }
                }
                "clear" => {
                    fcompress::clear_rules();
                    shell_println!("All rules cleared.");
                }
                _ => shell_println!("Usage: fc rule <add|rm|list|clear>"),
            }
        }
        "info" => {
            if parts.len() < 2 {
                shell_println!("Usage: fc info PATH");
                return;
            }
            let path = resolve_path(parts[1]);
            match crate::fs::Vfs::read_file(&path) {
                Ok(data) => {
                    let info = fcompress::file_info(&data);
                    if info.compressed {
                        shell_println!("File: {} (COMPRESSED)", path);
                        shell_println!("  Algorithm:   {}", info.algorithm.name());
                        shell_println!("  Original:    {} bytes", info.original_size);
                        shell_println!("  Stored:      {} bytes", info.stored_size);
                        shell_println!("  Ratio:       {:.2}:1", info.ratio);
                    } else {
                        shell_println!("File: {} (not compressed)", path);
                        shell_println!("  Size: {} bytes", info.stored_size);
                    }
                }
                Err(e) => shell_println!("Error reading {}: {:?}", path, e),
            }
        }
        "compress" => {
            if parts.len() < 2 {
                shell_println!("Usage: fc compress PATH [ALGO]");
                return;
            }
            let path = resolve_path(parts[1]);
            let algo = if parts.len() > 2 {
                match fcompress::Algorithm::from_name(parts[2]) {
                    Some(a) => a,
                    None => {
                        shell_println!("Unknown algorithm: {}", parts[2]);
                        return;
                    }
                }
            } else {
                fcompress::default_algorithm()
            };

            // Read, compress, write back.
            match crate::fs::Vfs::read_file(&path) {
                Ok(data) => {
                    if fcompress::is_compressed(&data) {
                        shell_println!("File is already compressed.");
                        return;
                    }
                    // Temporarily enable and add a rule to compress.
                    let was_enabled = fcompress::is_enabled();
                    let old_min = fcompress::min_size();
                    fcompress::set_enabled(true);
                    fcompress::set_min_size(0);
                    fcompress::add_rule(fcompress::CompressionRule {
                        path_prefix: path.clone(),
                        extensions: Vec::new(),
                        algorithm: algo,
                    }).expect("add temp rule");

                    match fcompress::compress_for_write(&path, &data) {
                        Some(compressed) => {
                            let saved = data.len().saturating_sub(compressed.len());
                            if let Err(e) = crate::fs::Vfs::write_file(&path, &compressed) {
                                shell_println!("Error writing: {:?}", e);
                            } else {
                                shell_println!(
                                    "Compressed {} ({} -> {} bytes, saved {})",
                                    path, data.len(), compressed.len(), saved
                                );
                            }
                        }
                        None => shell_println!("File could not be compressed (incompressible or too small)."),
                    }

                    fcompress::remove_rules(&path);
                    fcompress::set_min_size(old_min);
                    fcompress::set_enabled(was_enabled);
                }
                Err(e) => shell_println!("Error reading {}: {:?}", path, e),
            }
        }
        "decompress" | "expand" => {
            if parts.len() < 2 {
                shell_println!("Usage: fc decompress PATH");
                return;
            }
            let path = resolve_path(parts[1]);
            match crate::fs::Vfs::read_file(&path) {
                Ok(data) => {
                    if !fcompress::is_compressed(&data) {
                        shell_println!("File is not compressed (no FCMP header).");
                        return;
                    }
                    match fcompress::decompress_for_read(&data) {
                        Some(decompressed) => {
                            if let Err(e) = crate::fs::Vfs::write_file(&path, &decompressed) {
                                shell_println!("Error writing: {:?}", e);
                            } else {
                                shell_println!(
                                    "Decompressed {} ({} -> {} bytes)",
                                    path, data.len(), decompressed.len()
                                );
                            }
                        }
                        None => shell_println!("Decompression failed."),
                    }
                }
                Err(e) => shell_println!("Error reading {}: {:?}", path, e),
            }
        }
        _ => {
            shell_println!("Usage: fc <enable|disable|status|algo|minsize|rule|info|compress|decompress>");
        }
    }
}

/// `encrypt` — file encryption using ChaCha20 + HMAC-SHA256.
///
/// Subcommands:
///   encrypt key add NAME PASSPHRASE   - derive and store a key
///   encrypt key rm NAME               - remove a key
///   encrypt key list                  - list stored keys
///   encrypt file PATH KEY             - encrypt a file in-place
///   encrypt decrypt PATH KEY          - decrypt a file in-place
///   encrypt read PATH KEY             - decrypt and display (no write)
///   encrypt info PATH                 - show encryption status
///   encrypt status                    - show stats
fn cmd_encrypt(args: &str) {
    use crate::fs::encrypt;

    let parts: Vec<&str> = args.split_whitespace().collect();
    match parts.first().copied().unwrap_or("status") {
        "key" | "keys" => {
            match parts.get(1).copied().unwrap_or("list") {
                "add" | "create" => {
                    if parts.len() < 4 {
                        shell_println!("Usage: encrypt key add NAME PASSPHRASE");
                        return;
                    }
                    let name = parts[2];
                    let pass = parts[3..].join(" ");
                    match encrypt::add_key(name, &pass) {
                        Ok(()) => shell_println!("Key '{}' added.", name),
                        Err(e) => shell_println!("Error: {:?}", e),
                    }
                }
                "rm" | "remove" | "del" => {
                    if parts.len() < 3 {
                        shell_println!("Usage: encrypt key rm NAME");
                        return;
                    }
                    match encrypt::remove_key(parts[2]) {
                        Ok(()) => shell_println!("Key '{}' removed.", parts[2]),
                        Err(e) => shell_println!("Error: {:?}", e),
                    }
                }
                "list" | "ls" => {
                    let keys = encrypt::list_keys();
                    if keys.is_empty() {
                        shell_println!("No encryption keys stored.");
                    } else {
                        shell_println!("Stored keys:");
                        for k in &keys {
                            shell_println!("  {}", k.name);
                        }
                    }
                }
                _ => shell_println!("Usage: encrypt key <add|rm|list>"),
            }
        }
        "file" | "enc" => {
            if parts.len() < 3 {
                shell_println!("Usage: encrypt file PATH KEY_NAME");
                return;
            }
            let path = resolve_path(parts[1]);
            let key_name = parts[2];

            match crate::fs::Vfs::read_file(&path) {
                Ok(data) => {
                    if encrypt::is_encrypted(&data) {
                        shell_println!("File is already encrypted.");
                        return;
                    }
                    match encrypt::encrypt(&data, key_name) {
                        Ok(encrypted) => {
                            match crate::fs::Vfs::write_file(&path, &encrypted) {
                                Ok(()) => shell_println!(
                                    "Encrypted {} ({} -> {} bytes)",
                                    path, data.len(), encrypted.len()
                                ),
                                Err(e) => shell_println!("Error writing: {:?}", e),
                            }
                        }
                        Err(e) => shell_println!("Encryption failed: {:?}", e),
                    }
                }
                Err(e) => shell_println!("Error reading {}: {:?}", path, e),
            }
        }
        "decrypt" | "dec" => {
            if parts.len() < 3 {
                shell_println!("Usage: encrypt decrypt PATH KEY_NAME");
                return;
            }
            let path = resolve_path(parts[1]);
            let key_name = parts[2];

            match crate::fs::Vfs::read_file(&path) {
                Ok(data) => {
                    if !encrypt::is_encrypted(&data) {
                        shell_println!("File is not encrypted (no FENC header).");
                        return;
                    }
                    match encrypt::decrypt(&data, key_name) {
                        Ok(plaintext) => {
                            match crate::fs::Vfs::write_file(&path, &plaintext) {
                                Ok(()) => shell_println!(
                                    "Decrypted {} ({} -> {} bytes)",
                                    path, data.len(), plaintext.len()
                                ),
                                Err(e) => shell_println!("Error writing: {:?}", e),
                            }
                        }
                        Err(crate::error::KernelError::PermissionDenied) => {
                            shell_println!("Authentication failed — wrong key or file tampered.");
                        }
                        Err(e) => shell_println!("Decryption failed: {:?}", e),
                    }
                }
                Err(e) => shell_println!("Error reading {}: {:?}", path, e),
            }
        }
        "read" | "cat" => {
            if parts.len() < 3 {
                shell_println!("Usage: encrypt read PATH KEY_NAME");
                return;
            }
            let path = resolve_path(parts[1]);
            let key_name = parts[2];

            match crate::fs::Vfs::read_file(&path) {
                Ok(data) => {
                    if !encrypt::is_encrypted(&data) {
                        shell_println!("File is not encrypted.");
                        return;
                    }
                    match encrypt::decrypt(&data, key_name) {
                        Ok(plaintext) => {
                            if let Ok(text) = core::str::from_utf8(&plaintext) {
                                shell_println!("{}", text);
                            } else {
                                shell_println!("(binary data, {} bytes)", plaintext.len());
                            }
                        }
                        Err(crate::error::KernelError::PermissionDenied) => {
                            shell_println!("Authentication failed — wrong key or tampered.");
                        }
                        Err(e) => shell_println!("Decryption failed: {:?}", e),
                    }
                }
                Err(e) => shell_println!("Error reading {}: {:?}", path, e),
            }
        }
        "info" => {
            if parts.len() < 2 {
                shell_println!("Usage: encrypt info PATH");
                return;
            }
            let path = resolve_path(parts[1]);
            match crate::fs::Vfs::read_file(&path) {
                Ok(data) => {
                    let info = encrypt::file_info(&data);
                    if info.encrypted {
                        shell_println!("File: {} (ENCRYPTED)", path);
                        shell_println!("  Cipher:   {}", info.cipher);
                        shell_println!("  Original: {} bytes", info.original_size);
                        shell_println!("  Stored:   {} bytes", info.stored_size);
                    } else {
                        shell_println!("File: {} (not encrypted)", path);
                    }
                }
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "status" | "stats" => {
            let (enc, dec, keys) = encrypt::stats();
            shell_println!("Encryption stats:");
            shell_println!("  Keys stored:      {}", keys);
            shell_println!("  Files encrypted:  {}", enc);
            shell_println!("  Files decrypted:  {}", dec);
        }
        _ => {
            shell_println!("Usage: encrypt <key|file|decrypt|read|info|status> [args...]");
        }
    }
}

/// `fsearch` — advanced file search with compound queries.
///
/// Subcommands:
///   fsearch name <pattern> [path]   — search by name substring
///   fsearch glob <pattern> [path]   — search by glob pattern
///   fsearch ext <ext> [path]        — search by file extension
///   fsearch size <min> [max] [path] — search by size range
///   fsearch type <file|dir> [path]  — search by entry type
///   fsearch query [path]            — interactive compound query
///   fsearch stats                   — show search statistics
fn cmd_fsearch(args: &str) {
    use crate::fs::search;

    let parts: Vec<&str> = args.splitn(2, ' ').collect();
    let sub = parts.first().copied().unwrap_or("");
    let rest = if parts.len() > 1 { parts[1].trim() } else { "" };

    match sub {
        "name" => {
            // fsearch name <pattern> [path]
            let tok: Vec<&str> = rest.splitn(2, ' ').collect();
            let pattern = tok.first().copied().unwrap_or("");
            let root = if tok.len() > 1 { tok[1].trim() } else { "/" };

            if pattern.is_empty() {
                shell_println!("Usage: fsearch name <pattern> [path]");
                return;
            }

            match search::Query::new()
                .name_contains(pattern)
                .limit(50)
                .execute(root)
            {
                Ok(results) => {
                    shell_println!("Found {} result(s):", results.len());
                    for r in &results {
                        let typ = match r.entry_type {
                            crate::fs::EntryType::File => "F",
                            crate::fs::EntryType::Directory => "D",
                            _ => "?",
                        };
                        shell_println!("  [{}] {:>8} {}", typ, r.size, r.path);
                    }
                }
                Err(e) => shell_println!("Search error: {:?}", e),
            }
        }
        "glob" => {
            let tok: Vec<&str> = rest.splitn(2, ' ').collect();
            let pattern = tok.first().copied().unwrap_or("");
            let root = if tok.len() > 1 { tok[1].trim() } else { "/" };

            if pattern.is_empty() {
                shell_println!("Usage: fsearch glob <pattern> [path]");
                return;
            }

            match search::Query::new()
                .name_glob(pattern)
                .limit(50)
                .execute(root)
            {
                Ok(results) => {
                    shell_println!("Found {} result(s):", results.len());
                    for r in &results {
                        let typ = match r.entry_type {
                            crate::fs::EntryType::File => "F",
                            crate::fs::EntryType::Directory => "D",
                            _ => "?",
                        };
                        shell_println!("  [{}] {:>8} {}", typ, r.size, r.path);
                    }
                }
                Err(e) => shell_println!("Search error: {:?}", e),
            }
        }
        "ext" => {
            let tok: Vec<&str> = rest.splitn(2, ' ').collect();
            let ext = tok.first().copied().unwrap_or("");
            let root = if tok.len() > 1 { tok[1].trim() } else { "/" };

            if ext.is_empty() {
                shell_println!("Usage: fsearch ext <extension> [path]");
                return;
            }

            match search::Query::new()
                .extension(ext)
                .limit(50)
                .execute(root)
            {
                Ok(results) => {
                    shell_println!("Found {} .{} file(s):", results.len(), ext);
                    for r in &results {
                        shell_println!("  {:>8} {}", r.size, r.path);
                    }
                }
                Err(e) => shell_println!("Search error: {:?}", e),
            }
        }
        "size" => {
            // fsearch size <min> [max] [path]
            let tok: Vec<&str> = rest.split_whitespace().collect();
            if tok.is_empty() {
                shell_println!("Usage: fsearch size <min> [max] [path]");
                return;
            }

            let min: u64 = match tok[0].parse() {
                Ok(v) => v,
                Err(_) => {
                    shell_println!("Invalid min size: {}", tok[0]);
                    return;
                }
            };

            let mut max: Option<u64> = None;
            let mut root = "/";

            if tok.len() >= 2 {
                if let Ok(v) = tok[1].parse::<u64>() {
                    max = Some(v);
                    if tok.len() >= 3 {
                        root = tok[2];
                    }
                } else {
                    root = tok[1];
                }
            }

            let mut q = search::Query::new()
                .size_min(min)
                .files_only()
                .limit(50);
            if let Some(mx) = max {
                q = q.size_max(mx);
            }

            match q.execute(root) {
                Ok(results) => {
                    shell_println!("Found {} file(s) >= {} bytes:", results.len(), min);
                    for r in &results {
                        shell_println!("  {:>8} {}", r.size, r.path);
                    }
                }
                Err(e) => shell_println!("Search error: {:?}", e),
            }
        }
        "type" => {
            let tok: Vec<&str> = rest.splitn(2, ' ').collect();
            let typ = tok.first().copied().unwrap_or("");
            let root = if tok.len() > 1 { tok[1].trim() } else { "/" };

            let q = match typ {
                "file" | "f" => search::Query::new().files_only().limit(50),
                "dir" | "d" => search::Query::new().dirs_only().limit(50),
                _ => {
                    shell_println!("Usage: fsearch type <file|dir> [path]");
                    return;
                }
            };

            match q.execute(root) {
                Ok(results) => {
                    shell_println!("Found {} result(s):", results.len());
                    for r in &results {
                        let t = match r.entry_type {
                            crate::fs::EntryType::File => "F",
                            crate::fs::EntryType::Directory => "D",
                            _ => "?",
                        };
                        shell_println!("  [{}] {:>8} {}", t, r.size, r.path);
                    }
                }
                Err(e) => shell_println!("Search error: {:?}", e),
            }
        }
        "stats" => {
            let (searches, results) = search::stats();
            shell_println!("File Search Statistics:");
            shell_println!("  total searches: {}", searches);
            shell_println!("  total results:  {}", results);
            if searches > 0 {
                shell_println!("  avg results:    {}", results / searches);
            }
        }
        _ => {
            shell_println!("Usage: fsearch <name|glob|ext|size|type|stats> [args...]");
            shell_println!();
            shell_println!("Subcommands:");
            shell_println!("  name <pattern> [path]   Search by name substring");
            shell_println!("  glob <pattern> [path]   Search by glob pattern");
            shell_println!("  ext <extension> [path]  Search by file extension");
            shell_println!("  size <min> [max] [path] Search by size range");
            shell_println!("  type <file|dir> [path]  Search by entry type");
            shell_println!("  stats                   Show search statistics");
        }
    }
}

/// `tag` — file tagging system for BFS-style metadata queries.
///
/// Subcommands:
///   tag add <path> <tag>           — add a tag to a file
///   tag rm <path> <tag>            — remove a tag from a file
///   tag get <path>                 — list tags on a file
///   tag set <path> <tag1,tag2,...> — set all tags on a file
///   tag clear <path>               — remove all tags from a file
///   tag search <tag> [path]        — find files with a tag
///   tag find <tag1,tag2> [path]    — find files with ALL tags
///   tag list                       — list all known tags
///   tag index [path]               — build/rebuild tag index
///   tag stats                      — show tag statistics
fn cmd_tag(args: &str) {
    use crate::fs::tags;

    let parts: Vec<&str> = args.splitn(2, ' ').collect();
    let sub = parts.first().copied().unwrap_or("");
    let rest = if parts.len() > 1 { parts[1].trim() } else { "" };

    match sub {
        "add" => {
            let tok: Vec<&str> = rest.splitn(2, ' ').collect();
            let path = tok.first().copied().unwrap_or("");
            let tag = if tok.len() > 1 { tok[1].trim() } else { "" };

            if path.is_empty() || tag.is_empty() {
                shell_println!("Usage: tag add <path> <tag>");
                return;
            }

            match tags::add(path, tag) {
                Ok(()) => shell_println!("Tagged '{}' with '{}'", path, tag),
                Err(e) => shell_println!("tag add: {:?}", e),
            }
        }
        "rm" | "remove" => {
            let tok: Vec<&str> = rest.splitn(2, ' ').collect();
            let path = tok.first().copied().unwrap_or("");
            let tag = if tok.len() > 1 { tok[1].trim() } else { "" };

            if path.is_empty() || tag.is_empty() {
                shell_println!("Usage: tag rm <path> <tag>");
                return;
            }

            match tags::remove(path, tag) {
                Ok(()) => shell_println!("Removed tag '{}' from '{}'", tag, path),
                Err(e) => shell_println!("tag rm: {:?}", e),
            }
        }
        "get" | "show" => {
            if rest.is_empty() {
                shell_println!("Usage: tag get <path>");
                return;
            }

            match tags::get(rest) {
                Ok(t) => {
                    if t.is_empty() {
                        shell_println!("(no tags)");
                    } else {
                        shell_println!("{}", t.join(", "));
                    }
                }
                Err(e) => shell_println!("tag get: {:?}", e),
            }
        }
        "set" => {
            let tok: Vec<&str> = rest.splitn(2, ' ').collect();
            let path = tok.first().copied().unwrap_or("");
            let tag_str = if tok.len() > 1 { tok[1].trim() } else { "" };

            if path.is_empty() || tag_str.is_empty() {
                shell_println!("Usage: tag set <path> <tag1,tag2,...>");
                return;
            }

            let tag_list: Vec<&str> = tag_str.split(',').map(|s| s.trim()).collect();
            match tags::set(path, &tag_list) {
                Ok(()) => shell_println!("Set {} tag(s) on '{}'", tag_list.len(), path),
                Err(e) => shell_println!("tag set: {:?}", e),
            }
        }
        "clear" => {
            if rest.is_empty() {
                shell_println!("Usage: tag clear <path>");
                return;
            }

            match tags::clear(rest) {
                Ok(()) => shell_println!("Cleared all tags from '{}'", rest),
                Err(e) => shell_println!("tag clear: {:?}", e),
            }
        }
        "search" | "find" => {
            let tok: Vec<&str> = rest.splitn(2, ' ').collect();
            let tag_str = tok.first().copied().unwrap_or("");
            let root = if tok.len() > 1 { tok[1].trim() } else { "/" };

            if tag_str.is_empty() {
                shell_println!("Usage: tag search <tag> [path]");
                shell_println!("       tag find <tag1,tag2,...> [path]");
                return;
            }

            let tag_list: Vec<&str> = tag_str.split(',').collect();
            let results = if tag_list.len() == 1 {
                tags::search(tag_list[0], root)
            } else {
                tags::search_multi(&tag_list, root)
            };

            match results {
                Ok(files) => {
                    if files.is_empty() {
                        shell_println!("No files found.");
                    } else {
                        shell_println!("Found {} file(s):", files.len());
                        for f in &files {
                            shell_println!("  {} [{}]", f.path, f.tags.join(", "));
                        }
                    }
                }
                Err(e) => shell_println!("tag search: {:?}", e),
            }
        }
        "list" => {
            let all_tags = tags::list_tags();
            if all_tags.is_empty() {
                shell_println!("No tags in index. Run 'tag index' to build.");
            } else {
                shell_println!("{} unique tag(s):", all_tags.len());
                for (tag, count) in &all_tags {
                    shell_println!("  {:20} {} file(s)", tag, count);
                }
            }
        }
        "index" | "rebuild" => {
            let root = if rest.is_empty() { "/" } else { rest };
            shell_println!("Building tag index from '{}'...", root);
            match tags::build_index(root) {
                Ok(count) => shell_println!("Indexed {} tagged file(s)", count),
                Err(e) => shell_println!("tag index: {:?}", e),
            }
        }
        "stats" | "status" => {
            let s = tags::stats();
            shell_println!("File Tagging: {}", if tags::is_enabled() { "enabled" } else { "disabled" });
            shell_println!("  unique tags:   {}", s.unique_tags);
            shell_println!("  tagged files:  {}", s.tagged_files);
            shell_println!("  associations:  {}", s.total_associations);
            shell_println!("  adds:          {}", s.adds);
            shell_println!("  removes:       {}", s.removes);
            shell_println!("  searches:      {}", s.searches);
            shell_println!("  index built:   {}", s.index_built);
        }
        _ => {
            shell_println!("Usage: tag <add|rm|get|set|clear|search|find|list|index|stats>");
            shell_println!();
            shell_println!("Subcommands:");
            shell_println!("  add <path> <tag>           Add a tag to a file");
            shell_println!("  rm <path> <tag>            Remove a tag from a file");
            shell_println!("  get <path>                 List tags on a file");
            shell_println!("  set <path> <t1,t2,...>     Set all tags on a file");
            shell_println!("  clear <path>               Remove all tags");
            shell_println!("  search <tag> [path]        Find files with a tag");
            shell_println!("  find <t1,t2,...> [path]    Find files with ALL tags");
            shell_println!("  list                       List all known tags");
            shell_println!("  index [path]               Build tag index");
            shell_println!("  stats                      Show statistics");
        }
    }
}

/// `diskuse [path]` — detailed disk usage analysis.
///
/// Runs a comprehensive disk usage analysis showing top dirs,
/// top files, extension breakdown, age distribution, and wasted space.
fn cmd_diskuse(args: &str) {
    use crate::fs::usage;

    let root = if args.is_empty() { "/" } else { args.trim() };

    shell_println!("Analyzing disk usage from '{}'...", root);

    match usage::analyze_path(root) {
        Ok(report) => {
            shell_println!();
            shell_println!("=== Disk Usage Report: {} ===", report.root);
            shell_println!();
            shell_println!("  Total size:      {}", usage::format_size(report.total_size));
            shell_println!("  Files:           {}", report.file_count);
            shell_println!("  Directories:     {}", report.dir_count);
            shell_println!("  Symlinks:        {}", report.symlink_count);
            shell_println!("  Avg file size:   {}", usage::format_size(report.avg_file_size));
            shell_println!("  Median file size:{}", usage::format_size(report.median_file_size));

            if !report.top_dirs.is_empty() {
                shell_println!();
                shell_println!("--- Top Directories ---");
                for d in report.top_dirs.iter().take(10) {
                    let pct = if report.total_size > 0 {
                        d.size * 100 / report.total_size
                    } else {
                        0
                    };
                    shell_println!("  {:>10} {:>3}%  {}", usage::format_size(d.size), pct, d.path);
                }
            }

            if !report.top_files.is_empty() {
                shell_println!();
                shell_println!("--- Top Files ---");
                for f in report.top_files.iter().take(10) {
                    shell_println!("  {:>10}  {}", usage::format_size(f.size), f.path);
                }
            }

            if !report.by_extension.is_empty() {
                shell_println!();
                shell_println!("--- By Extension ---");
                for e in report.by_extension.iter().take(10) {
                    let pct = if report.total_size > 0 {
                        e.total_size * 100 / report.total_size
                    } else {
                        0
                    };
                    shell_println!(
                        "  .{:8} {:>10} {:>3}%  ({} files)",
                        e.extension,
                        usage::format_size(e.total_size),
                        pct,
                        e.count
                    );
                }
            }

            shell_println!();
            shell_println!("--- Age Distribution ---");
            shell_println!(
                "  < 1 day:    {:>6} files  {}",
                report.by_age.last_day.count,
                usage::format_size(report.by_age.last_day.size)
            );
            shell_println!(
                "  < 1 week:   {:>6} files  {}",
                report.by_age.last_week.count,
                usage::format_size(report.by_age.last_week.size)
            );
            shell_println!(
                "  < 1 month:  {:>6} files  {}",
                report.by_age.last_month.count,
                usage::format_size(report.by_age.last_month.size)
            );
            shell_println!(
                "  < 1 year:   {:>6} files  {}",
                report.by_age.last_year.count,
                usage::format_size(report.by_age.last_year.size)
            );
            shell_println!(
                "  > 1 year:   {:>6} files  {}",
                report.by_age.older.count,
                usage::format_size(report.by_age.older.size)
            );

            shell_println!();
            shell_println!("--- Wasted Space ---");
            shell_println!("  Empty files (0 B):   {}", report.wasted.empty_files);
            shell_println!(
                "  Tiny files (<64 B):  {} ({})",
                report.wasted.tiny_files,
                usage::format_size(report.wasted.tiny_size)
            );
            shell_println!("  Duplicate names:     {}", report.wasted.duplicate_names);
        }
        Err(e) => shell_println!("diskuse: {:?}", e),
    }
}

/// `fshealth` — filesystem health check.
///
/// Runs all health checks and reports status with recommendations.
fn cmd_fshealth(_args: &str) {
    use crate::fs::health;

    shell_println!("Running filesystem health check...");
    shell_println!();

    match health::check() {
        Ok(report) => {
            let status_str = match report.status {
                health::HealthStatus::Healthy => "HEALTHY",
                health::HealthStatus::Warning => "WARNING",
                health::HealthStatus::Critical => "CRITICAL",
            };
            shell_println!("=== Filesystem Health: {} ===", status_str);
            shell_println!("  {} check(s): {} healthy, {} warning(s), {} critical",
                report.total_checks, report.healthy, report.warnings, report.critical);
            shell_println!();

            for c in &report.checks {
                let icon = match c.status {
                    health::HealthStatus::Healthy => "[+]",
                    health::HealthStatus::Warning => "[!]",
                    health::HealthStatus::Critical => "[X]",
                };
                shell_println!("{} {:14} {}", icon, c.name, c.message);
                if let Some(ref rec) = c.recommendation {
                    shell_println!("    -> {}", rec);
                }
            }
        }
        Err(e) => shell_println!("fshealth: {:?}", e),
    }
}

/// `fswatch` — create and read filesystem watches.
///
/// Subcommands:
///   fswatch <path>                 — create watch and drain events
///   fswatch create <path> [mask]   — create a watch (returns ID)
///   fswatch read <id> [count]      — read events from a watch
///   fswatch close <id>             — close a watch
///   fswatch pending <id>           — show pending event count
fn cmd_fswatch(args: &str) {
    use crate::fs::notify;

    let parts: Vec<&str> = args.splitn(2, ' ').collect();
    let sub = parts.first().copied().unwrap_or("");
    let rest = if parts.len() > 1 { parts[1].trim() } else { "" };

    match sub {
        "create" => {
            let tok: Vec<&str> = rest.splitn(2, ' ').collect();
            let path = tok.first().copied().unwrap_or("");
            if path.is_empty() {
                shell_println!("Usage: fswatch create <path> [mask]");
                shell_println!("  Masks: create,delete,modify,rename,metadata,all (default: all)");
                return;
            }

            let mask_str = if tok.len() > 1 { tok[1].trim() } else { "all" };
            let mask = parse_event_mask(mask_str);
            let recursive = true;

            match notify::create_watch(path, mask, recursive) {
                Ok(id) => shell_println!("Watch created: id={} path={}", id, path),
                Err(e) => shell_println!("fswatch create: {:?}", e),
            }
        }
        "read" => {
            let tok: Vec<&str> = rest.splitn(2, ' ').collect();
            let id_str = tok.first().copied().unwrap_or("");
            let count_str = if tok.len() > 1 { tok[1].trim() } else { "20" };

            if id_str.is_empty() {
                shell_println!("Usage: fswatch read <id> [count]");
                return;
            }

            let id: u64 = match id_str.parse() {
                Ok(v) => v,
                Err(_) => { shell_println!("Invalid watch ID: {}", id_str); return; }
            };
            let count: usize = count_str.parse().unwrap_or(20);

            match notify::read_events(id, count) {
                Ok(events) => {
                    if events.is_empty() {
                        shell_println!("(no pending events)");
                    } else {
                        for ev in &events {
                            let kind = match ev.event_type {
                                notify::FsEventType::Created => "CREATE",
                                notify::FsEventType::Deleted => "DELETE",
                                notify::FsEventType::Modified => "MODIFY",
                                notify::FsEventType::Renamed => "RENAME",
                                notify::FsEventType::MetadataChanged => "META",
                                notify::FsEventType::Accessed => "ACCESS",
                                notify::FsEventType::Opened => "OPEN",
                                notify::FsEventType::ClosedWrite => "CLOSE_W",
                                notify::FsEventType::ClosedNoWrite => "CLOSE_NW",
                                notify::FsEventType::Overflow => "OVERFLOW",
                            };
                            let dirtag = if ev.is_dir { " [dir]" } else { "" };
                            if let Some(ref new) = ev.new_path {
                                shell_println!("  {:8} {} -> {}{}", kind, ev.path, new, dirtag);
                            } else {
                                shell_println!("  {:8} {}{}", kind, ev.path, dirtag);
                            }
                        }
                    }
                }
                Err(e) => shell_println!("fswatch read: {:?}", e),
            }
        }
        "close" => {
            if rest.is_empty() {
                shell_println!("Usage: fswatch close <id>");
                return;
            }
            let id: u64 = match rest.parse() {
                Ok(v) => v,
                Err(_) => { shell_println!("Invalid watch ID: {}", rest); return; }
            };
            match notify::close_watch(id) {
                Ok(()) => shell_println!("Watch {} closed", id),
                Err(e) => shell_println!("fswatch close: {:?}", e),
            }
        }
        "pending" => {
            if rest.is_empty() {
                shell_println!("Usage: fswatch pending <id>");
                return;
            }
            let id: u64 = match rest.parse() {
                Ok(v) => v,
                Err(_) => { shell_println!("Invalid watch ID: {}", rest); return; }
            };
            match notify::pending_count(id) {
                Ok(n) => shell_println!("{} event(s) pending", n),
                Err(e) => shell_println!("fswatch pending: {:?}", e),
            }
        }
        _ => {
            // Default: if arg looks like a path, create watch + drain events.
            if !sub.is_empty() && (sub.starts_with('/') || sub == ".") {
                let mask = notify::FsEventMask::ALL_CHANGES;
                match notify::create_watch(sub, mask, true) {
                    Ok(id) => {
                        shell_println!("Watch {} on '{}' (use 'fswatch read {}' to check events)", id, sub, id);
                    }
                    Err(e) => shell_println!("fswatch: {:?}", e),
                }
            } else {
                shell_println!("Usage: fswatch <path|create|read|close|pending>");
                shell_println!();
                shell_println!("Quick:   fswatch /path        Create a watch on path");
                shell_println!();
                shell_println!("Subcommands:");
                shell_println!("  create <path> [mask]   Create a watch (returns ID)");
                shell_println!("  read <id> [count]      Read events from a watch");
                shell_println!("  close <id>             Close a watch");
                shell_println!("  pending <id>           Show pending event count");
                shell_println!();
                shell_println!("Masks: create,delete,modify,rename,metadata,all");
            }
        }
    }
}

/// `dirsync` — directory comparison and sync.
fn cmd_dirsync(args: &str) {
    use crate::fs::dirsync;

    let parts: Vec<&str> = args.split_whitespace().collect();
    let sub = parts.first().copied().unwrap_or("");

    match sub {
        "compare" | "cmp" | "diff" => {
            if parts.len() < 3 {
                shell_println!("Usage: dirsync compare <src> <dst>");
                return;
            }
            let src = parts[1];
            let dst = parts[2];
            match dirsync::compare(src, dst) {
                Ok(diff) => {
                    shell_println!("Directory Comparison: {} vs {}", src, dst);
                    shell_println!("  Source files:   {} ({} bytes)", diff.src_file_count, diff.src_total_size);
                    shell_println!("  Dest files:     {} ({} bytes)", diff.dst_file_count, diff.dst_total_size);
                    shell_println!("  New files:      {}", diff.new_files.len());
                    shell_println!("  Modified files: {}", diff.modified_files.len());
                    shell_println!("  Deleted files:  {}", diff.deleted_files.len());
                    shell_println!("  Unchanged:      {}", diff.unchanged_files.len());
                    shell_println!("  New dirs:       {}", diff.new_dirs.len());
                    shell_println!("  Deleted dirs:   {}", diff.deleted_dirs.len());
                    if !diff.new_files.is_empty() {
                        shell_println!();
                        shell_println!("  New:");
                        for f in &diff.new_files {
                            shell_println!("    + {}", f);
                        }
                    }
                    if !diff.modified_files.is_empty() {
                        shell_println!();
                        shell_println!("  Modified:");
                        for f in &diff.modified_files {
                            shell_println!("    ~ {}", f);
                        }
                    }
                    if !diff.deleted_files.is_empty() {
                        shell_println!();
                        shell_println!("  Deleted:");
                        for f in &diff.deleted_files {
                            shell_println!("    - {}", f);
                        }
                    }
                }
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "sync" => {
            if parts.len() < 3 {
                shell_println!("Usage: dirsync sync <src> <dst> [--delete] [--verify] [--dry-run]");
                return;
            }
            let src = parts[1];
            let dst = parts[2];
            let flags = &parts[3..];
            let opts = dirsync::SyncOptions {
                delete_extra: flags.iter().any(|f| *f == "--delete" || *f == "-d"),
                verify_content: flags.iter().any(|f| *f == "--verify" || *f == "-v"),
                dry_run: flags.iter().any(|f| *f == "--dry-run" || *f == "-n"),
                ..dirsync::SyncOptions::default()
            };
            if opts.dry_run {
                shell_println!("(dry run — no changes will be made)");
            }
            match dirsync::sync(src, dst, &opts) {
                Ok(result) => {
                    shell_println!("Sync complete: {} -> {}", src, dst);
                    shell_println!("  Files copied:    {}", result.copied);
                    shell_println!("  Files deleted:   {}", result.deleted);
                    shell_println!("  Dirs created:    {}", result.dirs_created);
                    shell_println!("  Dirs deleted:    {}", result.dirs_deleted);
                    shell_println!("  Bytes copied:    {}", result.bytes_copied);
                    if !result.errors.is_empty() {
                        shell_println!("  Errors:");
                        for e in &result.errors {
                            shell_println!("    ! {}", e);
                        }
                    }
                }
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "stats" => {
            let (comps, syncs) = dirsync::stats();
            shell_println!("Comparisons: {}", comps);
            shell_println!("Syncs:       {}", syncs);
        }
        _ => {
            shell_println!("Usage: dirsync <command> [args]");
            shell_println!();
            shell_println!("Commands:");
            shell_println!("  compare <src> <dst>                Compare two directory trees");
            shell_println!("  sync <src> <dst> [flags]           Sync source to destination");
            shell_println!("  stats                              Show comparison/sync counts");
            shell_println!();
            shell_println!("Sync flags:");
            shell_println!("  --delete, -d    Delete extra files in destination");
            shell_println!("  --verify, -v    Verify content hash before skipping");
            shell_println!("  --dry-run, -n   Show what would be done without doing it");
        }
    }
}

/// `backup` — incremental backup engine.
fn cmd_backup(args: &str) {
    use crate::fs::backup;

    let parts: Vec<&str> = args.split_whitespace().collect();
    let sub = parts.first().copied().unwrap_or("");

    match sub {
        "create" | "full" => {
            if parts.len() < 3 {
                shell_println!("Usage: backup create <src> <dst> [--incremental] [--no-verify] [--dry-run] [--exclude <prefix>]");
                return;
            }
            let src = parts[1];
            let dst = parts[2];
            let flags = &parts[3..];
            let mut exclude = Vec::new();
            let mut i = 0;
            while i < flags.len() {
                if flags[i] == "--exclude" || flags[i] == "-x" {
                    if i + 1 < flags.len() {
                        exclude.push(String::from(flags[i + 1]));
                        i += 1;
                    }
                }
                i += 1;
            }
            let opts = backup::BackupOptions {
                mode: if flags.iter().any(|f| *f == "--incremental" || *f == "-i") {
                    backup::BackupMode::Incremental
                } else {
                    backup::BackupMode::Full
                },
                verify: !flags.contains(&"--no-verify"),
                dry_run: flags.iter().any(|f| *f == "--dry-run" || *f == "-n"),
                exclude,
                ..backup::BackupOptions::default()
            };
            if opts.dry_run {
                shell_println!("(dry run — no changes will be made)");
            }
            shell_println!("Backing up {} -> {} ({:?})...", src, dst, opts.mode);
            match backup::create(src, dst, &opts) {
                Ok(result) => {
                    shell_println!("Backup complete: {}", result.manifest_id);
                    shell_println!("  Files copied:  {}", result.files_copied);
                    shell_println!("  Files skipped: {}", result.files_skipped);
                    shell_println!("  Dirs created:  {}", result.dirs_created);
                    shell_println!("  Bytes copied:  {}", result.bytes_copied);
                    if !result.errors.is_empty() {
                        shell_println!("  Errors ({}):", result.errors.len());
                        for e in &result.errors {
                            shell_println!("    ! {}", e);
                        }
                    }
                }
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "incr" | "incremental" => {
            if parts.len() < 3 {
                shell_println!("Usage: backup incr <src> <dst> [--no-verify] [--dry-run]");
                return;
            }
            let src = parts[1];
            let dst = parts[2];
            let flags = &parts[3..];
            let opts = backup::BackupOptions {
                mode: backup::BackupMode::Incremental,
                verify: !flags.contains(&"--no-verify"),
                dry_run: flags.iter().any(|f| *f == "--dry-run" || *f == "-n"),
                ..backup::BackupOptions::default()
            };
            if opts.dry_run {
                shell_println!("(dry run — no changes will be made)");
            }
            shell_println!("Incremental backup {} -> {}...", src, dst);
            match backup::create(src, dst, &opts) {
                Ok(result) => {
                    shell_println!("Backup complete: {}", result.manifest_id);
                    shell_println!("  Files copied:  {}", result.files_copied);
                    shell_println!("  Files skipped: {}", result.files_skipped);
                    shell_println!("  Bytes copied:  {}", result.bytes_copied);
                    if !result.errors.is_empty() {
                        shell_println!("  Errors: {}", result.errors.len());
                    }
                }
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "restore" => {
            if parts.len() < 3 {
                shell_println!("Usage: backup restore <backup_root> <dst> [manifest_id] [--no-verify] [--dry-run]");
                return;
            }
            let backup_root = parts[1];
            let dst = parts[2];
            let manifest_id = parts.get(3).and_then(|s| {
                if s.starts_with('-') { None } else { Some(*s) }
            });
            let flags = &parts[3..];
            let opts = backup::RestoreOptions {
                verify: !flags.contains(&"--no-verify"),
                dry_run: flags.iter().any(|f| *f == "--dry-run" || *f == "-n"),
                ..backup::RestoreOptions::default()
            };
            if opts.dry_run {
                shell_println!("(dry run)");
            }
            match backup::restore(backup_root, dst, manifest_id, &opts) {
                Ok(result) => {
                    shell_println!("Restore complete:");
                    shell_println!("  Files restored: {}", result.files_restored);
                    shell_println!("  Dirs created:   {}", result.dirs_created);
                    shell_println!("  Bytes restored: {}", result.bytes_restored);
                    if result.verify_failures > 0 {
                        shell_println!("  VERIFY FAILURES: {}", result.verify_failures);
                    }
                    if !result.errors.is_empty() {
                        shell_println!("  Errors ({}):", result.errors.len());
                        for e in &result.errors {
                            shell_println!("    ! {}", e);
                        }
                    }
                }
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "list" | "ls" => {
            if parts.len() < 2 {
                shell_println!("Usage: backup list <backup_root>");
                return;
            }
            match backup::list(parts[1]) {
                Ok(backups) => {
                    if backups.is_empty() {
                        shell_println!("No backups found in {}", parts[1]);
                    } else {
                        shell_println!("Backups in {}:", parts[1]);
                        for b in &backups {
                            let mode = match b.mode {
                                backup::BackupMode::Full => "full",
                                backup::BackupMode::Incremental => "incr",
                            };
                            shell_println!(
                                "  {} [{}] {} files, {} bytes, from {}",
                                b.id, mode, b.file_count, b.total_bytes, b.source,
                            );
                        }
                    }
                }
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "verify" => {
            if parts.len() < 2 {
                shell_println!("Usage: backup verify <backup_root> [manifest_id]");
                return;
            }
            let manifest_id = parts.get(2).copied();
            match backup::verify(parts[1], manifest_id) {
                Ok((ok, fail, failures)) => {
                    shell_println!("Verification: {} ok, {} failed", ok, fail);
                    for f in &failures {
                        shell_println!("  FAIL: {}", f);
                    }
                }
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "stats" => {
            let (backups, restores, bytes) = backup::stats();
            shell_println!("Backups created: {}", backups);
            shell_println!("Restores done:   {}", restores);
            shell_println!("Bytes backed up: {}", bytes);
        }
        _ => {
            shell_println!("Usage: backup <command> [args]");
            shell_println!();
            shell_println!("Commands:");
            shell_println!("  create <src> <dst> [flags]         Create a full backup");
            shell_println!("  incr <src> <dst> [flags]           Create an incremental backup");
            shell_println!("  restore <root> <dst> [id] [flags]  Restore from backup");
            shell_println!("  list <backup_root>                 List available backups");
            shell_println!("  verify <backup_root> [id]          Verify backup integrity");
            shell_println!("  stats                              Show backup statistics");
            shell_println!();
            shell_println!("Create flags:");
            shell_println!("  --incremental, -i    Incremental mode");
            shell_println!("  --no-verify          Skip hash verification");
            shell_println!("  --dry-run, -n        Show what would be done");
            shell_println!("  --exclude, -x <pfx>  Exclude paths with prefix");
        }
    }
}

/// `undelete` — advanced file recovery.
fn cmd_undelete(args: &str) {
    use crate::fs::undelete;

    let parts: Vec<&str> = args.split_whitespace().collect();
    let sub = parts.first().copied().unwrap_or("");

    match sub {
        "scan" | "list" | "ls" => {
            let mut filter = undelete::ScanFilter::new();
            let mut i = 1;
            while i < parts.len() {
                match parts[i] {
                    "--prefix" | "-p" => {
                        if i + 1 < parts.len() {
                            filter = filter.with_prefix(parts[i + 1]);
                            i += 1;
                        }
                    }
                    "--name" | "-n" => {
                        if i + 1 < parts.len() {
                            filter = filter.with_name(parts[i + 1]);
                            i += 1;
                        }
                    }
                    "--limit" | "-l" => {
                        if i + 1 < parts.len() {
                            if let Ok(n) = parts[i + 1].parse::<usize>() {
                                filter = filter.with_limit(n);
                            }
                            i += 1;
                        }
                    }
                    other => {
                        // First positional arg is a path prefix shortcut.
                        if !other.starts_with('-') {
                            filter = filter.with_prefix(other);
                        }
                    }
                }
                i += 1;
            }
            match undelete::scan(&filter) {
                Ok(results) => {
                    if results.is_empty() {
                        shell_println!("No recoverable files found.");
                    } else {
                        shell_println!("Recoverable files ({}):", results.len());
                        for r in &results {
                            let size_str = r.size.map_or_else(
                                || String::from("?"),
                                |s| alloc::format!("{}", s),
                            );
                            let sources: Vec<&str> = r.sources.iter().map(|s| s.label()).collect();
                            shell_println!(
                                "  {} ({} bytes) [{}]",
                                r.path, size_str, sources.join(", "),
                            );
                        }
                    }
                }
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "recover" | "restore" => {
            if parts.len() < 2 {
                shell_println!("Usage: undelete recover <path> [dest]");
                return;
            }
            let path = parts[1];
            let dest = parts.get(2).copied();
            match undelete::recover(path, dest) {
                Ok(result) => {
                    shell_println!("Recovered: {} -> {}", path, result.recovered_path);
                    shell_println!("  Source: {}", result.source.label());
                    shell_println!("  Bytes:  {}", result.bytes);
                    if let Some(verified) = result.verified {
                        shell_println!("  Verified: {}", if verified { "OK" } else { "FAILED" });
                    }
                }
                Err(crate::error::KernelError::NotFound) => {
                    shell_println!("No recoverable data found for: {}", path);
                    shell_println!("Tip: use `undelete scan` to see what's available.");
                }
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "stats" => {
            let (scans, recoveries, bytes) = undelete::stats();
            shell_println!("Scans performed: {}", scans);
            shell_println!("Recoveries:      {}", recoveries);
            shell_println!("Bytes recovered: {}", bytes);
        }
        _ => {
            shell_println!("Usage: undelete <command> [args]");
            shell_println!();
            shell_println!("Commands:");
            shell_println!("  scan [opts]             Scan for recoverable files");
            shell_println!("  recover <path> [dest]   Recover a deleted file");
            shell_println!("  stats                   Show recovery statistics");
            shell_println!();
            shell_println!("Scan options:");
            shell_println!("  --prefix, -p <path>    Only files under this path");
            shell_println!("  --name, -n <substr>    Only files with name containing substr");
            shell_println!("  --limit, -l <N>        Maximum results (default 1000)");
            shell_println!();
            shell_println!("Sources (searched in priority order):");
            shell_println!("  1. Trash (full content)");
            shell_println!("  2. File history/CAS (versioned content)");
            shell_println!("  3. Integrity baseline (hash only)");
            shell_println!("  4. Journal (deletion record only)");
        }
    }
}

/// `archive` — unified archive management.
fn cmd_archive(args: &str) {
    use crate::fs::archive;

    let parts: Vec<&str> = args.split_whitespace().collect();
    let sub = parts.first().copied().unwrap_or("");

    match sub {
        "list" | "ls" | "t" => {
            if parts.len() < 2 {
                shell_println!("Usage: archive list <file>");
                return;
            }
            let path = resolve_path(parts[1]);
            match crate::fs::Vfs::read_file(&path) {
                Ok(data) => {
                    let fmt = archive::detect(&data);
                    let fmt_label = fmt.map_or("unknown", |f| f.label());
                    shell_println!("Archive: {} ({})", path, fmt_label);
                    match archive::list(&data) {
                        Ok(entries) => {
                            for e in &entries {
                                let kind_ch = match e.kind {
                                    archive::EntryKind::File => ' ',
                                    archive::EntryKind::Directory => 'd',
                                    archive::EntryKind::Symlink => 'l',
                                    archive::EntryKind::Other => '?',
                                };
                                shell_println!("{} {:>10}  {}", kind_ch, e.size, e.name);
                            }
                            shell_println!("({} entries)", entries.len());
                        }
                        Err(e) => shell_println!("Error listing: {:?}", e),
                    }
                }
                Err(e) => shell_println!("Error reading {}: {:?}", path, e),
            }
        }
        "extract" | "x" => {
            if parts.len() < 2 {
                shell_println!("Usage: archive extract <file> [dest]");
                return;
            }
            let path = resolve_path(parts[1]);
            let dest = if parts.len() >= 3 {
                resolve_path(parts[2])
            } else {
                String::from(".")
            };
            match crate::fs::Vfs::read_file(&path) {
                Ok(data) => {
                    match archive::extract_all(&data, &dest) {
                        Ok(result) => {
                            shell_println!("Extracted to {}:", dest);
                            shell_println!("  Files:   {}", result.files_extracted);
                            shell_println!("  Dirs:    {}", result.dirs_created);
                            shell_println!("  Bytes:   {}", result.bytes_written);
                            if !result.errors.is_empty() {
                                shell_println!("  Errors ({}):", result.errors.len());
                                for e in &result.errors {
                                    shell_println!("    ! {}", e);
                                }
                            }
                        }
                        Err(e) => shell_println!("Error extracting: {:?}", e),
                    }
                }
                Err(e) => shell_println!("Error reading {}: {:?}", path, e),
            }
        }
        "get" => {
            if parts.len() < 3 {
                shell_println!("Usage: archive get <archive> <entry_name>");
                return;
            }
            let path = resolve_path(parts[1]);
            let entry_name = parts[2];
            match crate::fs::Vfs::read_file(&path) {
                Ok(data) => {
                    match archive::extract_one(&data, entry_name) {
                        Ok(content) => {
                            if let Ok(text) = core::str::from_utf8(&content) {
                                shell_println!("{}", text);
                            } else {
                                shell_println!("(binary data, {} bytes)", content.len());
                            }
                        }
                        Err(e) => shell_println!("Error: {:?}", e),
                    }
                }
                Err(e) => shell_println!("Error reading {}: {:?}", path, e),
            }
        }
        "detect" | "info" => {
            if parts.len() < 2 {
                shell_println!("Usage: archive detect <file>");
                return;
            }
            let path = resolve_path(parts[1]);
            match crate::fs::Vfs::read_file(&path) {
                Ok(data) => {
                    match archive::detect(&data) {
                        Some(fmt) => {
                            shell_println!("Format: {} ({})", fmt.label(), path);
                            shell_println!("Extensions: {:?}", fmt.extensions());
                            shell_println!("Create support: {}", fmt.supports_create());
                        }
                        None => {
                            // Try extension-based detection.
                            match archive::detect_from_extension(&path) {
                                Some(fmt) => shell_println!("Format (by extension): {}", fmt.label()),
                                None => shell_println!("Unknown archive format"),
                            }
                        }
                    }
                }
                Err(e) => shell_println!("Error reading {}: {:?}", path, e),
            }
        }
        "create" => {
            if parts.len() < 4 {
                shell_println!("Usage: archive create <format> <output> <file1> [file2] ...");
                shell_println!("Formats: zip, tar, cpio, ar");
                return;
            }
            let fmt = match parts[1] {
                "zip" => archive::ArchiveFormat::Zip,
                "tar" => archive::ArchiveFormat::Tar,
                "cpio" => archive::ArchiveFormat::Cpio,
                "ar" => archive::ArchiveFormat::Ar,
                other => {
                    shell_println!("Unknown format: {}. Use: zip, tar, cpio, ar", other);
                    return;
                }
            };
            let output = resolve_path(parts[2]);
            let mut entries = Vec::new();
            for name in &parts[3..] {
                let path = resolve_path(name);
                match crate::fs::Vfs::read_file(&path) {
                    Ok(data) => {
                        let entry_name = path.rsplit('/').next().unwrap_or(&path);
                        entries.push(archive::CreateEntry {
                            name: String::from(entry_name),
                            data,
                            kind: archive::EntryKind::File,
                        });
                    }
                    Err(e) => shell_println!("Warning: skipping {}: {:?}", path, e),
                }
            }
            if entries.is_empty() {
                shell_println!("No files to archive.");
                return;
            }
            match archive::create(fmt, &entries) {
                Ok(data) => {
                    match crate::fs::Vfs::write_file(&output, &data) {
                        Ok(()) => shell_println!("Created {} ({} bytes, {} entries)", output, data.len(), entries.len()),
                        Err(e) => shell_println!("Error writing {}: {:?}", output, e),
                    }
                }
                Err(e) => shell_println!("Error creating archive: {:?}", e),
            }
        }
        "stats" => {
            let (lists, extracts, creates) = archive::stats();
            shell_println!("Archive operations:");
            shell_println!("  Listings:    {}", lists);
            shell_println!("  Extractions: {}", extracts);
            shell_println!("  Creations:   {}", creates);
        }
        _ => {
            shell_println!("Usage: archive <command> [args]");
            shell_println!();
            shell_println!("Commands:");
            shell_println!("  list <file>                        List archive contents");
            shell_println!("  extract <file> [dest]              Extract all to directory");
            shell_println!("  get <archive> <entry>              Extract single entry to stdout");
            shell_println!("  detect <file>                      Detect archive format");
            shell_println!("  create <fmt> <output> <files...>   Create archive");
            shell_println!("  stats                              Show operation counts");
            shell_println!();
            shell_println!("Supported formats: ZIP, TAR, CPIO, AR, RAR5, 7z");
            shell_println!("Create supports: zip, tar, cpio, ar");
        }
    }
}

/// `batch` — bulk file operations with pattern matching.
fn cmd_batch(args: &str) {
    use crate::fs::batch;
    let parts: Vec<&str> = args.split_whitespace().collect();
    let sub = parts.first().copied().unwrap_or("");
    let dry_run = parts.iter().any(|f| *f == "--dry-run" || *f == "-n");
    let conflict = if parts.contains(&"--overwrite") {
        batch::ConflictStrategy::Overwrite
    } else if parts.contains(&"--rename") {
        batch::ConflictStrategy::Rename
    } else {
        batch::ConflictStrategy::Skip
    };
    let opts = batch::BatchOptions { on_conflict: conflict, dry_run };
    match sub {
        "rename" | "ren" => {
            if parts.len() < 4 {
                shell_println!("Usage: batch rename <dir> <pattern> <replacement>");
                return;
            }
            let dir = resolve_path(parts[1]);
            if dry_run { shell_println!("(dry run)"); }
            match batch::rename(&dir, parts[2], parts[3], &opts) {
                Ok(r) => {
                    shell_println!("{} renamed, {} failed:", r.succeeded, r.failed);
                    for item in &r.items {
                        if item.ok {
                            shell_println!("  {} -> {}", item.src, item.dst);
                        } else {
                            shell_println!("  ! {}: {}", item.src, item.error);
                        }
                    }
                }
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "copy" | "cp" => {
            if parts.len() < 3 {
                shell_println!("Usage: batch copy <dest> <file1> [file2...]");
                return;
            }
            let dest = resolve_path(parts[1]);
            let resolved: Vec<String> = parts[2..].iter()
                .filter(|f| !f.starts_with('-')).map(|f| resolve_path(f)).collect();
            let paths: Vec<&str> = resolved.iter().map(|s| s.as_str()).collect();
            if dry_run { shell_println!("(dry run)"); }
            match batch::copy(&paths, &dest, &opts) {
                Ok(r) => shell_println!("{} copied, {} failed, {} bytes", r.succeeded, r.failed, r.bytes),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "move" | "mv" => {
            if parts.len() < 3 {
                shell_println!("Usage: batch move <dest> <file1> [file2...]");
                return;
            }
            let dest = resolve_path(parts[1]);
            let resolved: Vec<String> = parts[2..].iter()
                .filter(|f| !f.starts_with('-')).map(|f| resolve_path(f)).collect();
            let paths: Vec<&str> = resolved.iter().map(|s| s.as_str()).collect();
            if dry_run { shell_println!("(dry run)"); }
            match batch::move_files(&paths, &dest, &opts) {
                Ok(r) => shell_println!("{} moved, {} failed", r.succeeded, r.failed),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "delete" | "del" | "rm" => {
            if parts.len() < 2 {
                shell_println!("Usage: batch delete <file1> [file2...]");
                return;
            }
            let resolved: Vec<String> = parts[1..].iter()
                .filter(|f| !f.starts_with('-')).map(|f| resolve_path(f)).collect();
            let paths: Vec<&str> = resolved.iter().map(|s| s.as_str()).collect();
            if dry_run { shell_println!("(dry run)"); }
            match batch::delete(&paths, &opts) {
                Ok(r) => shell_println!("{} deleted, {} failed", r.succeeded, r.failed),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "glob" => {
            if parts.len() < 3 {
                shell_println!("Usage: batch glob <dir> <pattern>");
                return;
            }
            let dir = resolve_path(parts[1]);
            match batch::glob_files(&dir, parts[2]) {
                Ok(files) => {
                    for f in &files {
                        shell_println!("  {}", f);
                    }
                    shell_println!("({} matches)", files.len());
                }
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "stats" => {
            let (ren, cp, mv, del) = batch::stats();
            shell_println!("Renames: {} | Copies: {} | Moves: {} | Deletes: {}", ren, cp, mv, del);
        }
        _ => {
            shell_println!("Usage: batch <command> [args]");
            shell_println!("  rename <dir> <pat> <repl>  Bulk rename by pattern");
            shell_println!("  copy <dest> <files...>     Bulk copy");
            shell_println!("  move <dest> <files...>     Bulk move");
            shell_println!("  delete <files...>          Bulk delete");
            shell_println!("  glob <dir> <pattern>       List matching files");
            shell_println!("  stats                      Counts");
            shell_println!("Flags: --dry-run/-n  --overwrite  --rename");
        }
    }
}

/// `linkcheck` — find broken symlinks and hardlink analysis.
fn cmd_linkcheck(args: &str) {
    use crate::fs::linkcheck;
    let parts: Vec<&str> = args.split_whitespace().collect();
    let sub = parts.first().copied().unwrap_or("");
    match sub {
        "check" | "scan" => {
            let dir = if parts.len() >= 2 { resolve_path(parts[1]) } else { String::from("/") };
            let opts = linkcheck::CheckOptions::default();
            match linkcheck::check(&dir, &opts) {
                Ok(report) => {
                    shell_println!("Link check: {}", dir);
                    shell_println!("  Files scanned:    {}", report.files_scanned);
                    shell_println!("  Dirs scanned:     {}", report.dirs_scanned);
                    shell_println!("  Symlinks:         {} ({} valid, {} broken)",
                        report.symlinks_scanned, report.valid_symlinks, report.broken_symlinks.len());
                    shell_println!("  Hardlink groups:  {}", report.hardlink_groups.len());
                    if !report.broken_symlinks.is_empty() {
                        shell_println!();
                        shell_println!("  Broken symlinks:");
                        for b in &report.broken_symlinks {
                            shell_println!("    {} -> {}", b.link_path, b.target);
                        }
                    }
                    if !report.hardlink_groups.is_empty() {
                        shell_println!();
                        shell_println!("  Hardlink groups:");
                        for g in &report.hardlink_groups {
                            shell_println!("    [{} bytes, {} links]:", g.size, g.nlinks);
                            for p in &g.paths {
                                shell_println!("      {}", p);
                            }
                        }
                    }
                }
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "broken" => {
            let dir = if parts.len() >= 2 { resolve_path(parts[1]) } else { String::from("/") };
            match linkcheck::find_broken(&dir) {
                Ok(broken) => {
                    if broken.is_empty() {
                        shell_println!("No broken symlinks in {}", dir);
                    } else {
                        shell_println!("{} broken symlinks:", broken.len());
                        for b in &broken {
                            shell_println!("  {} -> {}", b.link_path, b.target);
                        }
                    }
                }
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "fix" => {
            let dir = if parts.len() >= 2 { resolve_path(parts[1]) } else { String::from("/") };
            let dry_run = parts.iter().any(|f| *f == "--dry-run" || *f == "-n");
            if dry_run { shell_println!("(dry run)"); }
            match linkcheck::fix_broken(&dir, dry_run) {
                Ok((removed, errors)) => {
                    shell_println!("Removed {} broken symlinks", removed);
                    for e in &errors {
                        shell_println!("  ! {}", e);
                    }
                }
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "stats" => {
            let (checks, broken) = linkcheck::stats();
            shell_println!("Checks: {} | Broken found: {}", checks, broken);
        }
        _ => {
            shell_println!("Usage: linkcheck <command> [dir]");
            shell_println!("  check [dir]    Full link analysis (default: /)");
            shell_println!("  broken [dir]   Find broken symlinks only");
            shell_println!("  fix [dir]      Remove broken symlinks [--dry-run]");
            shell_println!("  stats          Show counters");
        }
    }
}

/// Filesystem I/O profiling — enable/disable, view reports, manage counters.
fn cmd_fsprofile(args: &str) {
    use crate::fs::profile;
    let parts: Vec<&str> = args.split_whitespace().collect();
    let sub = parts.first().copied().unwrap_or("");
    match sub {
        "on" | "enable" => {
            profile::enable();
            shell_println!("Filesystem I/O profiling enabled.");
        }
        "off" | "disable" => {
            profile::disable();
            shell_println!("Filesystem I/O profiling disabled.");
        }
        "reset" | "clear" => {
            profile::reset();
            shell_println!("Profiling counters reset.");
        }
        "report" | "show" | "" => {
            let (total_ops, total_bytes, enabled) = profile::stats();
            shell_println!("Filesystem I/O Profile");
            shell_println!("  Status:  {}", if enabled { "ENABLED" } else { "disabled" });
            shell_println!("  Total ops:   {}", total_ops);
            shell_println!("  Total bytes: {}", total_bytes);

            if total_ops == 0 {
                if !enabled {
                    shell_println!();
                    shell_println!("  (enable with: fsprofile on)");
                }
                return;
            }

            let rpt = profile::report();
            shell_println!("  Duration:    {} ms", rpt.duration_ns / 1_000_000);
            shell_println!();
            shell_println!("  {:10} {:>8} {:>12} {:>10} {:>10} {:>10}",
                "OPERATION", "COUNT", "BYTES", "AVG(ns)", "MIN(ns)", "MAX(ns)");
            shell_println!("  {}", "-".repeat(64));
            for (kind, stats) in &rpt.ops {
                shell_println!("  {:10} {:>8} {:>12} {:>10} {:>10} {:>10}",
                    kind.label(), stats.count, stats.bytes,
                    stats.avg_ns(), stats.min_ns, stats.max_ns);
            }

            // Show throughput for ops that transferred data.
            let read_tput = rpt.ops.iter()
                .find(|(k, _)| *k == profile::OpKind::Read)
                .map(|(_, s)| s.throughput_bps());
            let write_tput = rpt.ops.iter()
                .find(|(k, _)| *k == profile::OpKind::Write)
                .map(|(_, s)| s.throughput_bps());
            if read_tput.is_some() || write_tput.is_some() {
                shell_println!();
                shell_println!("  Throughput:");
                if let Some(bps) = read_tput {
                    if bps > 1_000_000 {
                        shell_println!("    Read:  {} MB/s", bps / 1_000_000);
                    } else {
                        shell_println!("    Read:  {} KB/s", bps / 1_000);
                    }
                }
                if let Some(bps) = write_tput {
                    if bps > 1_000_000 {
                        shell_println!("    Write: {} MB/s", bps / 1_000_000);
                    } else {
                        shell_println!("    Write: {} KB/s", bps / 1_000);
                    }
                }
            }

            if !rpt.hot_paths.is_empty() {
                shell_println!();
                shell_println!("  Hot paths (most accessed):");
                for (path, count) in &rpt.hot_paths {
                    shell_println!("    {:6} {}", count, path);
                }
            }
        }
        "stats" => {
            let (total_ops, total_bytes, enabled) = profile::stats();
            shell_println!("Ops: {} | Bytes: {} | {}", total_ops, total_bytes,
                if enabled { "ENABLED" } else { "disabled" });
        }
        _ => {
            shell_println!("Usage: fsprofile <command>");
            shell_println!("  on|enable      Start profiling filesystem I/O");
            shell_println!("  off|disable    Stop profiling");
            shell_println!("  report|show    Show detailed report (default)");
            shell_println!("  reset|clear    Reset all counters");
            shell_println!("  stats          Quick summary");
        }
    }
}

/// Filesystem policy engine — centralized tuning and workload profiles.
fn cmd_fspolicy(args: &str) {
    use crate::fs::policy;
    let parts: Vec<&str> = args.split_whitespace().collect();
    let sub = parts.first().copied().unwrap_or("");
    match sub {
        "apply" => {
            let name = if parts.len() >= 2 { parts[1] } else {
                shell_println!("Usage: fspolicy apply <desktop|server|dev|gaming>");
                return;
            };
            match policy::FsProfile::from_name(name) {
                Some(p) => {
                    policy::apply_profile(p);
                    shell_println!("Applied filesystem profile: {}", p.label());
                }
                None => {
                    shell_println!("Unknown profile: {}", name);
                    shell_println!("Available: desktop, server, dev, gaming");
                }
            }
        }
        "show" | "list" | "" => {
            let profile = policy::current_profile();
            shell_println!("Filesystem Policy");
            shell_println!("  Active profile: {}",
                match profile {
                    Some(p) => p.label(),
                    None => "custom (manually tuned)",
                });
            shell_println!();
            shell_println!("  {:28} {:>10} {}", "SETTING", "VALUE", "DESCRIPTION");
            shell_println!("  {}", "-".repeat(70));
            let settings = policy::list_settings();
            for s in &settings {
                shell_println!("  {:28} {:>10} {}", s.key, s.value, s.description);
            }
        }
        "get" => {
            let key = if parts.len() >= 2 { parts[1] } else {
                shell_println!("Usage: fspolicy get <key>");
                return;
            };
            match policy::get_setting(key) {
                Some(val) => shell_println!("{} = {}", key, val),
                None => shell_println!("Unknown setting: {}", key),
            }
        }
        "set" => {
            if parts.len() < 3 {
                shell_println!("Usage: fspolicy set <key> <value>");
                return;
            }
            let key = parts[1];
            let value = parts[2];
            match policy::set_setting(key, value) {
                Ok(()) => shell_println!("Set {} = {}", key, value),
                Err(e) => shell_println!("Error: {}", e),
            }
        }
        "presets" | "compare" => {
            shell_println!("  {:28} {:>8} {:>8} {:>8} {:>8}",
                "SETTING", "Desktop", "Server", "Dev", "Gaming");
            shell_println!("  {}", "-".repeat(64));
            let settings = policy::list_settings();
            for s in &settings {
                shell_println!("  {:28} {:>8} {:>8} {:>8} {:>8}",
                    s.key, s.presets[0], s.presets[1], s.presets[2], s.presets[3]);
            }
        }
        "detect" => {
            match policy::detect_profile() {
                Some(p) => shell_println!("Current settings match profile: {}", p.label()),
                None => shell_println!("Current settings do not match any preset profile."),
            }
        }
        "export" => {
            let text = policy::export_settings();
            shell_println!("{}", text);
        }
        "stats" => {
            let st = policy::stats();
            shell_println!("Profiles applied: {} | Settings changed: {} | Queries: {}",
                st.profiles_applied, st.settings_changed, st.settings_queried);
        }
        _ => {
            shell_println!("Usage: fspolicy <command>");
            shell_println!("  show|list           Show current settings (default)");
            shell_println!("  apply <profile>     Apply preset (desktop/server/dev/gaming)");
            shell_println!("  get <key>           Get a single setting value");
            shell_println!("  set <key> <value>   Set a single setting (marks profile custom)");
            shell_println!("  presets             Compare all profile presets side-by-side");
            shell_println!("  detect              Detect which profile matches current settings");
            shell_println!("  export              Export current config as text");
            shell_println!("  stats               Show policy engine counters");
        }
    }
}

/// Filesystem microbenchmark suite — measure I/O performance against targets.
fn cmd_fsbench(args: &str) {
    use crate::fs::bench;
    let parts: Vec<&str> = args.split_whitespace().collect();
    let sub = parts.first().copied().unwrap_or("");
    match sub {
        "all" | "" => {
            let dir = if parts.len() >= 2 { resolve_path(parts[1]) } else { String::from("/tmp") };
            shell_println!("Running filesystem benchmark suite in {}...", dir);
            match bench::run_all(&dir) {
                Ok(report) => {
                    shell_println!();
                    shell_println!("  {:18} {:>8} {:>10} {:>10} {:>10} {:>8}",
                        "BENCHMARK", "ITERS", "TOTAL(ms)", "AVG(ns)", "OPS/s", "TARGET");
                    shell_println!("  {}", "-".repeat(72));
                    for r in &report.results {
                        let target_str = match r.meets_target() {
                            Some(true) => "  PASS",
                            Some(false) => "  FAIL",
                            None => "     -",
                        };
                        shell_println!("  {:18} {:>8} {:>10} {:>10} {:>10} {}",
                            r.name, r.iterations,
                            r.total_ns / 1_000_000,
                            r.avg_ns(),
                            r.ops_per_sec(),
                            target_str);
                        if r.bytes > 0 {
                            let mbps = r.throughput_bps() / 1_000_000;
                            if mbps > 0 {
                                shell_println!("  {:18} {:>8} throughput: {} MB/s", "", "", mbps);
                            }
                        }
                    }
                    shell_println!();
                    shell_println!("  Suite total: {} ms | Targets: {}/{} passed",
                        report.total_ns / 1_000_000,
                        report.targets_met.0, report.targets_met.1);
                }
                Err(e) => shell_println!("Benchmark failed: {:?}", e),
            }
        }
        "read" => {
            let path = if parts.len() >= 2 { resolve_path(parts[1]) } else { String::from("/tmp/_bench_read") };
            let iters: u64 = parts.get(2).and_then(|s| s.parse().ok()).unwrap_or(500);
            match bench::bench_sequential_read(&path, iters) {
                Ok(r) => {
                    shell_println!("Sequential read: {} iterations", r.iterations);
                    shell_println!("  Avg: {}ns | {} ops/s | {} MB/s",
                        r.avg_ns(), r.ops_per_sec(), r.throughput_bps() / 1_000_000);
                }
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "write" => {
            let dir = if parts.len() >= 2 { resolve_path(parts[1]) } else { String::from("/tmp") };
            let size: usize = parts.get(2).and_then(|s| s.parse().ok()).unwrap_or(4096);
            let iters: u64 = parts.get(3).and_then(|s| s.parse().ok()).unwrap_or(200);
            match bench::bench_sequential_write(&dir, size, iters) {
                Ok(r) => {
                    shell_println!("Sequential write ({}B): {} iterations", size, r.iterations);
                    shell_println!("  Avg: {}ns | {} ops/s | {} MB/s",
                        r.avg_ns(), r.ops_per_sec(), r.throughput_bps() / 1_000_000);
                }
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "meta" => {
            let dir = if parts.len() >= 2 { resolve_path(parts[1]) } else { String::from("/tmp") };
            let iters: u64 = parts.get(2).and_then(|s| s.parse().ok()).unwrap_or(200);
            match bench::bench_metadata(&dir, iters) {
                Ok(r) => {
                    shell_println!("Metadata cycle (create+stat+delete): {} iterations", r.iterations);
                    shell_println!("  Avg: {}ns | {} ops/s | target: {}ns {}",
                        r.avg_ns(), r.ops_per_sec(), r.target_ns,
                        if r.meets_target() == Some(true) { "PASS" } else { "FAIL" });
                }
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "lookup" => {
            let path = if parts.len() >= 2 { resolve_path(parts[1]) } else { String::from("/tmp") };
            let iters: u64 = parts.get(2).and_then(|s| s.parse().ok()).unwrap_or(1000);
            match bench::bench_path_lookup(&path, iters) {
                Ok(r) => {
                    shell_println!("Path lookup ({}): {} iterations", path, r.iterations);
                    shell_println!("  Avg: {}ns | {} ops/s | target: {}ns {}",
                        r.avg_ns(), r.ops_per_sec(), r.target_ns,
                        if r.meets_target() == Some(true) { "PASS" } else { "FAIL" });
                }
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "stats" => {
            let (runs, last_ns) = bench::stats();
            shell_println!("Benchmarks run: {} | Last suite: {} ms", runs, last_ns / 1_000_000);
        }
        _ => {
            shell_println!("Usage: fsbench <command> [options]");
            shell_println!("  all [dir]              Run full suite (default: /tmp)");
            shell_println!("  read [path] [iters]    Sequential read benchmark");
            shell_println!("  write [dir] [sz] [n]   Sequential write benchmark");
            shell_println!("  meta [dir] [iters]     Metadata cycle (create+stat+delete)");
            shell_println!("  lookup [path] [iters]  VFS path resolution latency");
            shell_println!("  stats                  Show run history");
        }
    }
}

/// I/O priority management — view and set per-task I/O scheduling class.
fn cmd_ionice(args: &str) {
    use crate::fs::ioprio::{self, IoClass, IoPriority};
    let parts: Vec<&str> = args.split_whitespace().collect();
    let sub = parts.first().copied().unwrap_or("");
    match sub {
        "show" | "" => {
            let all = ioprio::list_all();
            let current = ioprio::current_ioprio();
            shell_println!("Current task I/O priority: {}", current.display());
            shell_println!();
            if all.is_empty() {
                shell_println!("No explicit I/O priorities set.");
                shell_println!("All tasks use default: best-effort:4");
            } else {
                shell_println!("{:>6} {:>12} {:>6}", "TASK", "CLASS", "LEVEL");
                shell_println!("{}", "-".repeat(28));
                for (tid, prio) in &all {
                    shell_println!("{:>6} {:>12} {:>6}", tid, prio.class.label(), prio.level);
                }
            }
        }
        "set" => {
            if parts.len() < 3 {
                shell_println!("Usage: ionice set <task_id> <class> [level]");
                shell_println!("  Classes: realtime|rt, best-effort|be, idle|bg");
                shell_println!("  Level: 0-7 (only for best-effort, default 4)");
                return;
            }
            let task_id: u64 = match parts[1].parse() {
                Ok(v) => v,
                Err(_) => { shell_println!("Invalid task ID: {}", parts[1]); return; }
            };
            let class = match IoClass::from_name(parts[2]) {
                Some(c) => c,
                None => { shell_println!("Unknown class: {} (use: rt, be, idle)", parts[2]); return; }
            };
            let level: u8 = parts.get(3).and_then(|s| s.parse().ok()).unwrap_or(4);
            let prio = IoPriority::new(class, level);
            match ioprio::set_ioprio(task_id, prio) {
                Ok(()) => shell_println!("Set task {} I/O priority: {}", task_id, prio.display()),
                Err(e) => shell_println!("Error: {}", e),
            }
        }
        "clear" => {
            if parts.len() < 2 {
                shell_println!("Usage: ionice clear <task_id>");
                return;
            }
            let task_id: u64 = match parts[1].parse() {
                Ok(v) => v,
                Err(_) => { shell_println!("Invalid task ID: {}", parts[1]); return; }
            };
            ioprio::clear_ioprio(task_id);
            shell_println!("Cleared I/O priority for task {} (reset to default)", task_id);
        }
        "get" => {
            if parts.len() < 2 {
                shell_println!("Usage: ionice get <task_id>");
                return;
            }
            let task_id: u64 = match parts[1].parse() {
                Ok(v) => v,
                Err(_) => { shell_println!("Invalid task ID: {}", parts[1]); return; }
            };
            let prio = ioprio::get_ioprio(task_id);
            shell_println!("Task {} I/O priority: {}", task_id, prio.display());
        }
        "stats" => {
            let (sets, gets, active) = ioprio::stats();
            shell_println!("Active entries: {}/256 | Set calls: {} | Get calls: {}", active, sets, gets);
        }
        _ => {
            shell_println!("Usage: ionice <command>");
            shell_println!("  show               List all I/O priorities (default)");
            shell_println!("  set <tid> <class> [level]  Set task I/O priority");
            shell_println!("  get <tid>          Get task I/O priority");
            shell_println!("  clear <tid>        Reset task to default priority");
            shell_println!("  stats              Show counters");
            shell_println!();
            shell_println!("Classes: realtime (rt), best-effort (be), idle (bg)");
            shell_println!("Levels: 0-7 (0=highest, only for best-effort)");
        }
    }
}

/// Access time (atime) policy management.
fn cmd_atime(args: &str) {
    use crate::fs::atime::{self, AtimePolicy};
    let parts: Vec<&str> = args.split_whitespace().collect();
    let sub = parts.first().copied().unwrap_or("");
    match sub {
        "show" | "" => {
            let policy = atime::global_policy();
            let st = atime::stats();
            shell_println!("Atime Policy: {}", policy.label());
            shell_println!("  Checks: {} | Updates: {} | Skipped: {}",
                st.checks, st.updates, st.skipped);
            if st.checks > 0 {
                shell_println!("  Skip rate: {}%", (st.skipped * 100) / st.checks);
            }
            let overrides = atime::list_overrides();
            if !overrides.is_empty() {
                shell_println!();
                shell_println!("  Per-mount overrides:");
                for ovr in &overrides {
                    shell_println!("    {:20} → {}", ovr.mount_path, ovr.policy.label());
                }
            }
        }
        "set" => {
            let name = if parts.len() >= 2 { parts[1] } else {
                shell_println!("Usage: atime set <always|relatime|noatime|lazyday>");
                return;
            };
            match AtimePolicy::from_name(name) {
                Some(p) => {
                    atime::set_global_policy(p);
                    shell_println!("Global atime policy set to: {}", p.label());
                }
                None => {
                    shell_println!("Unknown policy: {}", name);
                    shell_println!("Available: always, relatime, noatime, lazyday");
                }
            }
        }
        "mount" => {
            if parts.len() < 3 {
                shell_println!("Usage: atime mount <path> <policy>");
                return;
            }
            let path = parts[1];
            match AtimePolicy::from_name(parts[2]) {
                Some(p) => {
                    atime::add_override(path, p);
                    shell_println!("Override: {} → {}", path, p.label());
                }
                None => shell_println!("Unknown policy: {}", parts[2]),
            }
        }
        "unmount" | "remove" => {
            if parts.len() < 2 {
                shell_println!("Usage: atime remove <mount_path>");
                return;
            }
            if atime::remove_override(parts[1]) {
                shell_println!("Removed override for {}", parts[1]);
            } else {
                shell_println!("No override found for {}", parts[1]);
            }
        }
        "reset" => {
            atime::reset_stats();
            shell_println!("Atime statistics reset.");
        }
        "stats" => {
            let st = atime::stats();
            shell_println!("Checks: {} | Updates: {} | Skipped: {}",
                st.checks, st.updates, st.skipped);
        }
        _ => {
            shell_println!("Usage: atime <command>");
            shell_println!("  show                  Show policy and stats (default)");
            shell_println!("  set <policy>          Set global policy");
            shell_println!("  mount <path> <policy> Add per-mount override");
            shell_println!("  remove <path>         Remove per-mount override");
            shell_println!("  reset                 Reset statistics");
            shell_println!("  stats                 Show counters only");
            shell_println!();
            shell_println!("Policies: always, relatime (default), noatime, lazyday");
        }
    }
}

/// File access pattern hinting and prefetch control.
fn cmd_prefetch(args: &str) {
    use crate::fs::prefetch::{self, AccessAdvice};
    let parts: Vec<&str> = args.split_whitespace().collect();
    let sub = parts.first().copied().unwrap_or("");
    match sub {
        "advise" | "hint" => {
            if parts.len() < 3 {
                shell_println!("Usage: prefetch advise <path> <normal|seq|rand|willneed|dontneed>");
                return;
            }
            let path = resolve_path(parts[1]);
            match AccessAdvice::from_name(parts[2]) {
                Some(advice) => {
                    prefetch::advise(&path, advice);
                    shell_println!("Advised {}: {}", path, advice.label());
                }
                None => shell_println!("Unknown advice: {} (use: normal, seq, rand, willneed, dontneed)", parts[2]),
            }
        }
        "load" | "fetch" => {
            if parts.len() < 2 {
                shell_println!("Usage: prefetch load <path> [offset] [length]");
                return;
            }
            let path = resolve_path(parts[1]);
            let offset: u64 = parts.get(2).and_then(|s| s.parse().ok()).unwrap_or(0);
            let len: u64 = parts.get(3).and_then(|s| s.parse().ok()).unwrap_or(0);
            match prefetch::prefetch(&path, offset, len) {
                Ok(r) => shell_println!("Prefetched {} bytes from {}", r.bytes_prefetched, path),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "list" | "show" | "" => {
            let entries = prefetch::list_active();
            let (advises, prefetches, bytes, active) = prefetch::stats();
            shell_println!("Prefetch / Access Advisory");
            shell_println!("  Active entries: {}/256", active);
            shell_println!("  Advise calls:   {} | Prefetch calls: {} | Bytes: {}",
                advises, prefetches, bytes);
            if entries.is_empty() {
                shell_println!();
                shell_println!("  No active advice entries.");
            } else {
                shell_println!();
                shell_println!("  {:40} {}", "PATH", "ADVICE");
                shell_println!("  {}", "-".repeat(52));
                for (path, advice) in &entries {
                    shell_println!("  {:40} {}", path, advice.label());
                }
            }
        }
        "clear" => {
            if parts.len() >= 2 {
                let path = resolve_path(parts[1]);
                if prefetch::clear_advice(&path) {
                    shell_println!("Cleared advice for {}", path);
                } else {
                    shell_println!("No advice found for {}", path);
                }
            } else {
                prefetch::clear_all();
                shell_println!("Cleared all advice entries.");
            }
        }
        "stats" => {
            let (advises, prefetches, bytes, active) = prefetch::stats();
            shell_println!("Active: {} | Advises: {} | Prefetches: {} | Bytes: {}",
                active, advises, prefetches, bytes);
        }
        _ => {
            shell_println!("Usage: prefetch <command>");
            shell_println!("  advise <path> <hint>   Set access advice for a file");
            shell_println!("  load <path> [off] [n]  Prefetch file data into cache");
            shell_println!("  list|show              Show active advice entries (default)");
            shell_println!("  clear [path]           Clear advice (one or all)");
            shell_println!("  stats                  Show counters");
            shell_println!();
            shell_println!("Hints: normal, seq(uential), rand(om), willneed, dontneed");
        }
    }
}

fn cmd_splice(args: &str) {
    use crate::fs::splice;
    let parts: Vec<&str> = args.split_whitespace().collect();
    let sub = parts.first().copied().unwrap_or("");
    match sub {
        "copy" | "cp" => {
            if parts.len() < 3 {
                shell_println!("Usage: splice copy <src> <dst> [src_offset] [dst_offset] [len]");
                return;
            }
            let src = resolve_path(parts[1]);
            let dst = resolve_path(parts[2]);
            let src_off: u64 = parts.get(3).and_then(|s| s.parse().ok()).unwrap_or(0);
            let dst_off: u64 = parts.get(4).and_then(|s| s.parse().ok()).unwrap_or(0);
            let len: usize = parts.get(5).and_then(|s| s.parse().ok()).unwrap_or(1024 * 1024);
            match splice::copy_file_range(&src, src_off, &dst, dst_off, len) {
                Ok(r) => shell_println!("Copied {} bytes ({} chunks): {} -> {}",
                    r.bytes_transferred, r.chunks, src, dst),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "send" | "sendfile" => {
            if parts.len() < 3 {
                shell_println!("Usage: splice send <src> <dst> [offset] [len]");
                return;
            }
            let src = resolve_path(parts[1]);
            let dst = resolve_path(parts[2]);
            let offset: u64 = parts.get(3).and_then(|s| s.parse().ok()).unwrap_or(0);
            let len: usize = parts.get(4).and_then(|s| s.parse().ok()).unwrap_or(1024 * 1024);
            match splice::sendfile(&src, &dst, offset, len) {
                Ok(r) => shell_println!("Sent {} bytes ({} chunks): {} -> {}",
                    r.bytes_transferred, r.chunks, src, dst),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "pipe" | "splice" => {
            if parts.len() < 3 {
                shell_println!("Usage: splice pipe <src> <dst> [src_offset] [len]");
                return;
            }
            let src = resolve_path(parts[1]);
            let dst = resolve_path(parts[2]);
            let src_off: u64 = parts.get(3).and_then(|s| s.parse().ok()).unwrap_or(0);
            let len: usize = parts.get(4).and_then(|s| s.parse().ok()).unwrap_or(1024 * 1024);
            match splice::splice(&src, src_off, &dst, len) {
                Ok(r) => shell_println!("Spliced {} bytes ({} chunks): {} -> {}",
                    r.bytes_transferred, r.chunks, src, dst),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "tee" => {
            if parts.len() < 3 {
                shell_println!("Usage: splice tee <src> <dst> [offset] [len]");
                return;
            }
            let src = resolve_path(parts[1]);
            let dst = resolve_path(parts[2]);
            let offset: u64 = parts.get(3).and_then(|s| s.parse().ok()).unwrap_or(0);
            let len: usize = parts.get(4).and_then(|s| s.parse().ok()).unwrap_or(1024 * 1024);
            match splice::tee(&src, offset, &dst, len) {
                Ok(r) => shell_println!("Tee'd {} bytes: {} -> {}",
                    r.bytes_transferred, src, dst),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "stats" | "show" | "" => {
            shell_println!("{}", splice::summary());
        }
        "reset" => {
            splice::reset_stats();
            shell_println!("Splice statistics reset.");
        }
        _ => {
            shell_println!("Usage: splice <command>");
            shell_println!("  copy <src> <dst> [soff] [doff] [len]  Copy file range (server-side)");
            shell_println!("  send <src> <dst> [off] [len]          Sendfile (file to dest)");
            shell_println!("  pipe <src> <dst> [soff] [len]         Splice (pipe-style transfer)");
            shell_println!("  tee <src> <dst> [off] [len]           Tee (dup without consuming)");
            shell_println!("  stats|show                            Show statistics (default)");
            shell_println!("  reset                                 Reset counters");
        }
    }
}

fn cmd_directio(args: &str) {
    use crate::fs::directio;
    let parts: Vec<&str> = args.split_whitespace().collect();
    let sub = parts.first().copied().unwrap_or("");
    match sub {
        "read" => {
            if parts.len() < 2 {
                shell_println!("Usage: directio read <path> [offset] [len]");
                return;
            }
            let path = resolve_path(parts[1]);
            let offset: u64 = parts.get(2).and_then(|s| s.parse().ok()).unwrap_or(0);
            let len: usize = parts.get(3).and_then(|s| s.parse().ok()).unwrap_or(4096);
            match directio::dio_read(&path, offset, len) {
                Ok((data, r)) => {
                    shell_println!("DIO read {} bytes (aligned={}, cache_inv={})",
                        r.bytes, r.aligned, r.cache_invalidated);
                    if data.len() <= 64 {
                        shell_println!("  data: {:?}", &data);
                    } else {
                        shell_println!("  data: [{} bytes, first 16: {:?}...]",
                            data.len(), &data[..16]);
                    }
                }
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "write" => {
            if parts.len() < 3 {
                shell_println!("Usage: directio write <path> <data|hex:AABB..> [offset]");
                return;
            }
            let path = resolve_path(parts[1]);
            let offset: u64 = parts.get(3).and_then(|s| s.parse().ok()).unwrap_or(0);
            let data: Vec<u8> = if let Some(hex) = parts[2].strip_prefix("hex:") {
                // Parse hex bytes.
                hex.as_bytes().chunks(2).filter_map(|pair| {
                    if pair.len() == 2 {
                        let s = core::str::from_utf8(pair).ok()?;
                        u8::from_str_radix(s, 16).ok()
                    } else {
                        None
                    }
                }).collect()
            } else {
                parts[2].as_bytes().to_vec()
            };
            match directio::dio_write(&path, offset, &data) {
                Ok(r) => shell_println!("DIO wrote {} bytes (aligned={}, cache_inv={})",
                    r.bytes, r.aligned, r.cache_invalidated),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "register" | "reg" => {
            if parts.len() < 2 {
                shell_println!("Usage: directio register <path>");
                return;
            }
            let path = resolve_path(parts[1]);
            if directio::register_path(&path) {
                shell_println!("Registered {} for direct I/O", path);
            } else {
                shell_println!("Already registered: {}", path);
            }
        }
        "unregister" | "unreg" => {
            if parts.len() < 2 {
                shell_println!("Usage: directio unregister <path>");
                return;
            }
            let path = resolve_path(parts[1]);
            if directio::unregister_path(&path) {
                shell_println!("Unregistered: {}", path);
            } else {
                shell_println!("Not registered: {}", path);
            }
        }
        "list" | "paths" => {
            let paths = directio::list_paths();
            if paths.is_empty() {
                shell_println!("No registered direct-I/O paths.");
            } else {
                shell_println!("Registered DIO paths ({}):", paths.len());
                for p in &paths {
                    shell_println!("  {}", p);
                }
            }
        }
        "stats" | "show" | "" => {
            let (reads, writes, rbytes, wbytes, unaligned, inv, npaths) = directio::stats();
            shell_println!("Direct I/O Statistics");
            shell_println!("  Reads:       {} ({} bytes)", reads, rbytes);
            shell_println!("  Writes:      {} ({} bytes)", writes, wbytes);
            shell_println!("  Unaligned:   {}", unaligned);
            shell_println!("  Cache inv.:  {}", inv);
            shell_println!("  Reg. paths:  {}/128", npaths);
        }
        "reset" => {
            directio::reset_stats();
            shell_println!("Direct I/O statistics reset.");
        }
        "clear" => {
            directio::clear_paths();
            shell_println!("All DIO path registrations cleared.");
        }
        _ => {
            shell_println!("Usage: directio <command>");
            shell_println!("  read <path> [off] [len]       Read with cache bypass");
            shell_println!("  write <path> <data> [off]     Write with cache bypass");
            shell_println!("  register <path>               Register path for auto-DIO");
            shell_println!("  unregister <path>             Remove path registration");
            shell_println!("  list|paths                    Show registered DIO paths");
            shell_println!("  stats|show                    Show statistics (default)");
            shell_println!("  reset                         Reset counters");
            shell_println!("  clear                         Clear all path registrations");
        }
    }
}

fn cmd_fstrim(args: &str) {
    use crate::fs::fstrim;
    let parts: Vec<&str> = args.split_whitespace().collect();
    let sub = parts.first().copied().unwrap_or("");
    match sub {
        "run" | "flush" | "" => {
            let device = parts.get(1).copied().unwrap_or("");
            let result = fstrim::flush(device);
            if result.ranges_trimmed == 0 {
                shell_println!("No pending discard ranges to trim.");
            } else {
                shell_println!("Trimmed {} ranges ({} bytes, {} coalesced)",
                    result.ranges_trimmed, result.bytes_trimmed, result.ranges_coalesced);
            }
        }
        "mode" => {
            if let Some(mode_str) = parts.get(1) {
                match fstrim::TrimMode::from_name(mode_str) {
                    Some(mode) => {
                        fstrim::set_mode(mode);
                        shell_println!("TRIM mode set to: {}", mode.label());
                    }
                    None => shell_println!("Unknown mode: {} (manual, periodic, continuous)", mode_str),
                }
            } else {
                shell_println!("Current mode: {}", fstrim::get_mode().label());
                shell_println!("  Available: manual, periodic, continuous");
            }
        }
        "pending" => {
            let summary = fstrim::pending_summary();
            if summary.is_empty() {
                shell_println!("No pending discard ranges.");
            } else {
                shell_println!("{:20} {:>8} {:>12}", "DEVICE", "RANGES", "BYTES");
                shell_println!("{}", "-".repeat(44));
                for (dev, count, bytes) in &summary {
                    shell_println!("{:20} {:>8} {:>12}", dev, count, bytes);
                }
                shell_println!("\nTotal: {} ranges", fstrim::pending_count());
            }
        }
        "drop" => {
            let count = fstrim::drop_pending();
            shell_println!("Dropped {} pending discard ranges.", count);
        }
        "notify" => {
            if parts.len() < 4 {
                shell_println!("Usage: fstrim notify <device> <offset> <length>");
                return;
            }
            let device = parts[1];
            let offset: u64 = match parts[2].parse() {
                Ok(v) => v,
                Err(_) => { shell_println!("Invalid offset"); return; }
            };
            let length: u64 = match parts[3].parse() {
                Ok(v) => v,
                Err(_) => { shell_println!("Invalid length"); return; }
            };
            fstrim::notify_free(device, offset, length);
            shell_println!("Queued discard: {} offset={} len={}", device, offset, length);
        }
        "stats" => {
            let (trims, bytes, queued, coalesced, overflows, pending, last_flush) = fstrim::stats();
            shell_println!("TRIM Statistics");
            shell_println!("  Mode:          {}", fstrim::get_mode().label());
            shell_println!("  Pending:       {}", pending);
            shell_println!("  Total TRIMs:   {}", trims);
            shell_println!("  Bytes trimmed: {}", bytes);
            shell_println!("  Queued:        {}", queued);
            shell_println!("  Coalesced:     {}", coalesced);
            shell_println!("  Overflows:     {}", overflows);
            shell_println!("  Last flush:    {} ns", last_flush);
        }
        "reset" => {
            fstrim::reset_stats();
            shell_println!("TRIM statistics reset.");
        }
        _ => {
            shell_println!("Usage: fstrim [command]");
            shell_println!("  run|flush [device]         Flush pending TRIMs (default)");
            shell_println!("  mode [manual|periodic|continuous]  Get/set TRIM mode");
            shell_println!("  pending                    Show pending discard ranges");
            shell_println!("  notify <dev> <off> <len>   Queue a discard notification");
            shell_println!("  drop                       Drop all pending (no TRIM)");
            shell_println!("  stats                      Show TRIM statistics");
            shell_println!("  reset                      Reset counters");
        }
    }
}

fn cmd_sparse(args: &str) {
    use crate::fs::sparse;
    let parts: Vec<&str> = args.split_whitespace().collect();
    let sub = parts.first().copied().unwrap_or("");
    match sub {
        "punch" | "hole" => {
            if parts.len() < 4 {
                shell_println!("Usage: sparse punch <path> <offset> <length>");
                return;
            }
            let path = resolve_path(parts[1]);
            let offset: u64 = match parts[2].parse() {
                Ok(v) => v,
                Err(_) => { shell_println!("Invalid offset"); return; }
            };
            let length: u64 = match parts[3].parse() {
                Ok(v) => v,
                Err(_) => { shell_println!("Invalid length"); return; }
            };
            match sparse::punch_hole(&path, offset, length) {
                Ok(r) => shell_println!("Punched {} bytes at offset {} (hole={})",
                    r.bytes_affected, offset, r.created_hole),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "zero" => {
            if parts.len() < 4 {
                shell_println!("Usage: sparse zero <path> <offset> <length>");
                return;
            }
            let path = resolve_path(parts[1]);
            let offset: u64 = match parts[2].parse() {
                Ok(v) => v,
                Err(_) => { shell_println!("Invalid offset"); return; }
            };
            let length: u64 = match parts[3].parse() {
                Ok(v) => v,
                Err(_) => { shell_println!("Invalid length"); return; }
            };
            match sparse::zero_range(&path, offset, length) {
                Ok(r) => shell_println!("Zeroed {} bytes at offset {}", r.bytes_affected, offset),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "collapse" => {
            if parts.len() < 4 {
                shell_println!("Usage: sparse collapse <path> <offset> <length>");
                return;
            }
            let path = resolve_path(parts[1]);
            let offset: u64 = match parts[2].parse() {
                Ok(v) => v,
                Err(_) => { shell_println!("Invalid offset"); return; }
            };
            let length: u64 = match parts[3].parse() {
                Ok(v) => v,
                Err(_) => { shell_println!("Invalid length"); return; }
            };
            match sparse::collapse_range(&path, offset, length) {
                Ok(r) => shell_println!("Collapsed {} bytes at offset {}", r.bytes_affected, offset),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "insert" => {
            if parts.len() < 4 {
                shell_println!("Usage: sparse insert <path> <offset> <length>");
                return;
            }
            let path = resolve_path(parts[1]);
            let offset: u64 = match parts[2].parse() {
                Ok(v) => v,
                Err(_) => { shell_println!("Invalid offset"); return; }
            };
            let length: u64 = match parts[3].parse() {
                Ok(v) => v,
                Err(_) => { shell_println!("Invalid length"); return; }
            };
            match sparse::insert_range(&path, offset, length) {
                Ok(r) => shell_println!("Inserted {} zero bytes at offset {}", r.bytes_affected, offset),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "map" => {
            if parts.len() < 2 {
                shell_println!("Usage: sparse map <path>");
                return;
            }
            let path = resolve_path(parts[1]);
            match sparse::map_regions(&path) {
                Ok(map) => {
                    shell_println!("Sparse map: {} ({} bytes)", path, map.file_size);
                    shell_println!("  Data: {} bytes | Holes: {} bytes", map.data_bytes, map.hole_bytes);
                    if map.file_size > 0 {
                        let ratio = (map.hole_bytes as f64 / map.file_size as f64) * 100.0;
                        shell_println!("  Sparseness: {:.1}%", ratio);
                    }
                    shell_println!();
                    shell_println!("  {:>12} {:>12} {:>6}", "OFFSET", "LENGTH", "TYPE");
                    shell_println!("  {}", "-".repeat(34));
                    for region in &map.regions {
                        shell_println!("  {:>12} {:>12} {:>6}",
                            region.offset, region.length, region.kind.label());
                    }
                }
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "list" | "tracked" => {
            let files = sparse::list_tracked();
            if files.is_empty() {
                shell_println!("No tracked sparse files.");
            } else {
                shell_println!("{:40} {:>6}", "PATH", "HOLES");
                shell_println!("{}", "-".repeat(48));
                for (path, holes) in &files {
                    shell_println!("{:40} {:>6}", path, holes);
                }
            }
        }
        "stats" | "show" | "" => {
            let (punches, punch_bytes, zeros, collapses, inserts, maps, tracked) = sparse::stats();
            shell_println!("Sparse File Statistics");
            shell_println!("  Tracked files:   {}/256", tracked);
            shell_println!("  Punch holes:     {} ({} bytes)", punches, punch_bytes);
            shell_println!("  Zero ranges:     {}", zeros);
            shell_println!("  Collapse ranges: {}", collapses);
            shell_println!("  Insert ranges:   {}", inserts);
            shell_println!("  Map queries:     {}", maps);
        }
        "clear" => {
            sparse::clear_tracking();
            shell_println!("Sparse tracking data cleared.");
        }
        "reset" => {
            sparse::reset_stats();
            shell_println!("Sparse statistics reset.");
        }
        _ => {
            shell_println!("Usage: sparse <command>");
            shell_println!("  punch <path> <off> <len>    Punch a hole (deallocate range)");
            shell_println!("  zero <path> <off> <len>     Zero a range (keep allocated)");
            shell_println!("  collapse <path> <off> <len> Remove range, shift data down");
            shell_println!("  insert <path> <off> <len>   Insert zeros, shift data up");
            shell_println!("  map <path>                  Show sparse region map");
            shell_println!("  list|tracked                List tracked sparse files");
            shell_println!("  stats|show                  Show statistics (default)");
            shell_println!("  clear                       Clear tracking data");
            shell_println!("  reset                       Reset counters");
        }
    }
}

fn cmd_lsplus(args: &str) {
    use crate::fs::readdir_plus::{self, ListOptions, SortOrder, TypeFilter};
    let parts: Vec<&str> = args.split_whitespace().collect();

    let mut dir_path = String::new();
    let mut sort = SortOrder::Name;
    let mut type_filter = TypeFilter::All;
    let mut pattern = String::new();
    let mut show_hidden = true;
    let mut show_stats = false;

    let mut i = 0;
    while i < parts.len() {
        match parts[i] {
            "-s" | "--sort" => {
                if let Some(&val) = parts.get(i + 1) {
                    sort = SortOrder::from_name(val).unwrap_or(SortOrder::Name);
                    i += 1;
                }
            }
            "-t" | "--type" => {
                if let Some(&val) = parts.get(i + 1) {
                    type_filter = match val {
                        "file" | "f" => TypeFilter::FilesOnly,
                        "dir" | "d" => TypeFilter::DirsOnly,
                        "link" | "l" => TypeFilter::SymlinksOnly,
                        _ => TypeFilter::All,
                    };
                    i += 1;
                }
            }
            "-p" | "--pattern" => {
                if let Some(&val) = parts.get(i + 1) {
                    pattern = String::from(val);
                    i += 1;
                }
            }
            "-A" => show_hidden = false,
            "--stats" => show_stats = true,
            other => {
                if dir_path.is_empty() {
                    dir_path = resolve_path(other);
                }
            }
        }
        i += 1;
    }

    if show_stats {
        let (calls, entries, fetched, errors) = readdir_plus::stats();
        shell_println!("readdir+ stats: {} calls, {} entries, {} metadata fetched, {} errors",
            calls, entries, fetched, errors);
        return;
    }

    if dir_path.is_empty() {
        dir_path = get_cwd();
    }

    let opts = ListOptions {
        sort,
        type_filter,
        pattern,
        show_hidden,
        limit: 0,
        offset: 0,
    };

    match readdir_plus::readdir_plus(&dir_path, &opts) {
        Ok(result) => {
            shell_println!("{} entries ({} total bytes):", result.total_count, result.total_size);
            shell_println!();
            shell_println!("  {:4} {:>10} {:40}", "TYPE", "SIZE", "NAME");
            shell_println!("  {}", "-".repeat(58));
            for entry in &result.entries {
                let type_str = match entry.entry_type {
                    crate::fs::EntryType::File => "FILE",
                    crate::fs::EntryType::Directory => "DIR ",
                    crate::fs::EntryType::Symlink => "LINK",
                    crate::fs::EntryType::VolumeLabel => "VOL ",
                };
                let size = entry.meta.as_ref().map_or(0, |m| m.size);
                shell_println!("  {:4} {:>10} {}", type_str, size, entry.name);
            }
            if result.has_more {
                shell_println!("  ... ({} more)", result.total_count - result.entries.len());
            }
        }
        Err(e) => shell_println!("Error: {:?}", e),
    }
}

fn cmd_fsfreeze(args: &str) {
    use crate::fs::freeze;
    let parts: Vec<&str> = args.split_whitespace().collect();
    let sub = parts.first().copied().unwrap_or("");
    match sub {
        "freeze" | "f" => {
            if parts.len() < 2 {
                shell_println!("Usage: fsfreeze freeze <mountpoint> [reason]");
                return;
            }
            let mp = resolve_path(parts[1]);
            let reason = if parts.len() > 2 {
                parts[2..].join(" ")
            } else {
                alloc::string::String::from("manual")
            };
            match freeze::freeze(&mp, &reason) {
                Ok(r) => {
                    if r.was_initial {
                        shell_println!("Frozen: {} (level {})", mp, r.freeze_level);
                    } else {
                        shell_println!("Freeze level increased: {} (level {})", mp, r.freeze_level);
                    }
                }
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "thaw" | "t" => {
            if parts.len() < 2 {
                shell_println!("Usage: fsfreeze thaw <mountpoint>");
                return;
            }
            let mp = resolve_path(parts[1]);
            match freeze::thaw(&mp) {
                Ok(r) => {
                    if r.fully_thawed {
                        shell_println!("Thawed: {} ({} writes were blocked)", mp, r.blocked_writes);
                    } else {
                        shell_println!("Freeze level decreased: {} (level {})", mp, r.freeze_level);
                    }
                }
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "force" => {
            if parts.len() < 2 {
                shell_println!("Usage: fsfreeze force <mountpoint>");
                return;
            }
            let mp = resolve_path(parts[1]);
            match freeze::force_thaw(&mp) {
                Ok(r) => shell_println!("Force-thawed: {} ({} writes blocked)", mp, r.blocked_writes),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "list" | "show" | "" => {
            let list = freeze::list_frozen();
            if list.is_empty() {
                shell_println!("No frozen filesystems.");
            } else {
                shell_println!("{:20} {:>5} {:>8} {:>8} {:>8} {}",
                    "MOUNTPOINT", "LEVEL", "DUR(s)", "TTL(s)", "BLOCKED", "REASON");
                shell_println!("{}", "-".repeat(70));
                for entry in &list {
                    let dur_s = entry.frozen_duration_ns / 1_000_000_000;
                    let ttl_s = entry.time_until_thaw_ns / 1_000_000_000;
                    shell_println!("{:20} {:>5} {:>8} {:>8} {:>8} {}",
                        entry.mountpoint, entry.freeze_level,
                        dur_s, ttl_s, entry.blocked_writes, entry.reason);
                }
            }
        }
        "stats" => {
            let (freezes, thaws, auto_thaws, blocked, frozen) = freeze::stats();
            shell_println!("Freeze Statistics");
            shell_println!("  Frozen now:     {}/16", frozen);
            shell_println!("  Freeze ops:     {}", freezes);
            shell_println!("  Thaw ops:       {}", thaws);
            shell_println!("  Auto-thaws:     {}", auto_thaws);
            shell_println!("  Blocked writes: {}", blocked);
        }
        "reset" => {
            freeze::reset_stats();
            shell_println!("Freeze statistics reset.");
        }
        _ => {
            shell_println!("Usage: fsfreeze <command>");
            shell_println!("  freeze <mount> [reason]  Freeze filesystem");
            shell_println!("  thaw <mount>             Thaw (decrement level)");
            shell_println!("  force <mount>            Force-thaw (ignore level)");
            shell_println!("  list|show                List frozen filesystems (default)");
            shell_println!("  stats                    Show statistics");
            shell_println!("  reset                    Reset counters");
        }
    }
}

fn cmd_seal(args: &str) {
    use crate::fs::sealing::{self, SealFlags};
    let parts: Vec<&str> = args.split_whitespace().collect();
    let sub = parts.first().copied().unwrap_or("");
    match sub {
        "add" | "set" => {
            if parts.len() < 3 {
                shell_println!("Usage: seal add <path> <seals>");
                shell_println!("  Seals: shrink, grow, write, seal, exec, all");
                shell_println!("  Combine with + or ,: shrink+grow+write");
                return;
            }
            let path = resolve_path(parts[1]);
            let flags = SealFlags::from_str(parts[2]);
            if flags.is_empty() {
                shell_println!("No valid seals specified.");
                return;
            }
            match sealing::add_seals(&path, flags) {
                Ok(total) => shell_println!("Sealed {}: {}", path, total.label()),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "get" | "query" => {
            if parts.len() < 2 {
                shell_println!("Usage: seal get <path>");
                return;
            }
            let path = resolve_path(parts[1]);
            let seals = sealing::get_seals(&path);
            shell_println!("{}: {}", path, seals.label());
        }
        "check" => {
            if parts.len() < 3 {
                shell_println!("Usage: seal check <path> <write|shrink|grow|addseal|exec>");
                return;
            }
            let path = resolve_path(parts[1]);
            let op = match parts[2] {
                "write" | "w" => sealing::SealOp::Write,
                "shrink" | "s" => sealing::SealOp::Shrink,
                "grow" | "g" => sealing::SealOp::Grow,
                "addseal" | "seal" => sealing::SealOp::AddSeal,
                "exec" | "x" => sealing::SealOp::ChangeExec,
                _ => { shell_println!("Unknown op: {}", parts[2]); return; }
            };
            match sealing::check_seals(&path, op) {
                Ok(()) => shell_println!("ALLOWED: {} on {}", parts[2], path),
                Err(_) => shell_println!("DENIED: {} on {} (sealed)", parts[2], path),
            }
        }
        "list" | "show" | "" => {
            let files = sealing::list_sealed();
            if files.is_empty() {
                shell_println!("No sealed files.");
            } else {
                shell_println!("{:40} {}", "PATH", "SEALS");
                shell_println!("{}", "-".repeat(60));
                for (path, flags) in &files {
                    shell_println!("{:40} {}", path, flags.label());
                }
            }
        }
        "stats" => {
            let (seal_ops, check_ops, denied, count) = sealing::stats();
            shell_println!("Sealing Statistics");
            shell_println!("  Sealed files: {}/512", count);
            shell_println!("  Seal ops:     {}", seal_ops);
            shell_println!("  Check ops:    {}", check_ops);
            shell_println!("  Denied ops:   {}", denied);
        }
        "reset" => {
            sealing::reset_stats();
            shell_println!("Sealing statistics reset.");
        }
        _ => {
            shell_println!("Usage: seal <command>");
            shell_println!("  add <path> <seals>         Add seals (shrink+grow+write+seal+exec)");
            shell_println!("  get <path>                 Query current seals");
            shell_println!("  check <path> <op>          Check if operation is permitted");
            shell_println!("  list|show                  List sealed files (default)");
            shell_println!("  stats                      Show statistics");
            shell_println!("  reset                      Reset counters");
        }
    }
}

fn cmd_recent(args: &str) {
    use crate::fs::recent::{self, AccessType, RecentFilter};
    let parts: Vec<&str> = args.split_whitespace().collect();
    let sub = parts.first().copied().unwrap_or("");
    match sub {
        "list" | "show" | "" => {
            // recent [list] [-n N] [-t type]
            let mut limit: usize = 20;
            let mut type_filter: Option<AccessType> = None;
            let mut i = if sub == "list" || sub == "show" { 1 } else { 0 };
            while i < parts.len() {
                match parts[i] {
                    "-n" | "--limit" => {
                        if let Some(n_str) = parts.get(i + 1) {
                            if let Ok(n) = n_str.parse::<usize>() {
                                limit = n;
                            }
                        }
                        i += 2;
                    }
                    "-t" | "--type" => {
                        if let Some(t_str) = parts.get(i + 1) {
                            type_filter = AccessType::from_name(t_str);
                        }
                        i += 2;
                    }
                    _ => { i += 1; }
                }
            }
            let filter = RecentFilter {
                access_type: type_filter,
                limit,
                ..Default::default()
            };
            let entries = recent::query(&filter);
            if entries.is_empty() {
                shell_println!("No recent files.");
            } else {
                shell_println!("{:40} {:8} {:>5} {}", "PATH", "TYPE", "COUNT", "SOURCE");
                shell_println!("{}", "-".repeat(70));
                for e in &entries {
                    shell_println!("{:40} {:8} {:>5} {}", e.path, e.access_type.label(), e.access_count, e.source);
                }
                shell_println!("\n{} entries shown.", entries.len());
            }
        }
        "record" | "add" => {
            if parts.len() < 3 {
                shell_println!("Usage: recent record <path> <type> [source]");
                shell_println!("  Types: open, modify, create, exec");
                return;
            }
            let path = resolve_path(parts[1]);
            let access_type = match AccessType::from_name(parts[2]) {
                Some(t) => t,
                None => { shell_println!("Unknown type: {}. Use: open, modify, create, exec", parts[2]); return; }
            };
            let source = if parts.len() > 3 { parts[3] } else { "kshell" };
            recent::record(&path, access_type, source);
            shell_println!("Recorded: {} ({})", path, access_type.label());
        }
        "clear" => {
            recent::clear();
            shell_println!("Recent files list cleared.");
        }
        "remove" | "rm" => {
            if parts.len() < 2 {
                shell_println!("Usage: recent remove <path>");
                return;
            }
            let path = resolve_path(parts[1]);
            if recent::remove(&path) {
                shell_println!("Removed: {}", path);
            } else {
                shell_println!("Not found: {}", path);
            }
        }
        "exclude" => {
            let action = parts.get(1).copied().unwrap_or("list");
            match action {
                "add" => {
                    if parts.len() < 3 {
                        shell_println!("Usage: recent exclude add <prefix>");
                        return;
                    }
                    recent::add_exclude(parts[2]);
                    shell_println!("Excluded prefix: {}", parts[2]);
                }
                "rm" | "remove" => {
                    if parts.len() < 3 {
                        shell_println!("Usage: recent exclude remove <prefix>");
                        return;
                    }
                    if recent::remove_exclude(parts[2]) {
                        shell_println!("Removed exclude: {}", parts[2]);
                    } else {
                        shell_println!("Not found: {}", parts[2]);
                    }
                }
                "list" | "" => {
                    let excludes = recent::list_excludes();
                    shell_println!("Default excludes: /tmp, /proc, /sys, /dev");
                    if excludes.is_empty() {
                        shell_println!("Custom excludes:  (none)");
                    } else {
                        shell_println!("Custom excludes:");
                        for e in &excludes {
                            shell_println!("  {}", e);
                        }
                    }
                }
                _ => shell_println!("Usage: recent exclude <add|remove|list> [prefix]"),
            }
        }
        "enable" => {
            recent::set_enabled(true);
            shell_println!("Recent files tracking enabled.");
        }
        "disable" => {
            recent::set_enabled(false);
            shell_println!("Recent files tracking disabled.");
        }
        "expire" => {
            let expired = recent::expire();
            shell_println!("Expired {} entries beyond retention period.", expired);
        }
        "stats" => {
            let (recorded, queried, evicted, excluded, count, enabled) = recent::stats();
            shell_println!("Recent Files Statistics");
            shell_println!("  Status:     {}", if enabled { "enabled" } else { "disabled" });
            shell_println!("  Tracked:    {}/1024", count);
            shell_println!("  Recorded:   {}", recorded);
            shell_println!("  Queried:    {}", queried);
            shell_println!("  Evicted:    {}", evicted);
            shell_println!("  Excluded:   {}", excluded);
            let ret_ns = recent::get_retention_ns();
            let ret_days = ret_ns / (24 * 60 * 60 * 1_000_000_000);
            shell_println!("  Retention:  {} days", ret_days);
        }
        "reset" => {
            recent::reset_stats();
            shell_println!("Recent files statistics reset.");
        }
        _ => {
            shell_println!("Usage: recent <command>");
            shell_println!("  list|show [-n N] [-t type]  List recent files (default)");
            shell_println!("  record <path> <type> [src]  Record a file access");
            shell_println!("  remove <path>              Remove from recent list");
            shell_println!("  clear                      Clear all entries");
            shell_println!("  exclude <add|rm|list> [p]  Manage exclusion prefixes");
            shell_println!("  enable|disable             Toggle tracking");
            shell_println!("  expire                     Remove expired entries");
            shell_println!("  stats                      Show statistics");
            shell_println!("  reset                      Reset counters");
        }
    }
}

fn cmd_fileinfo(args: &str) {
    use crate::fs::fileinfo;
    let parts: Vec<&str> = args.split_whitespace().collect();
    let sub = parts.first().copied().unwrap_or("");
    match sub {
        "stats" => {
            let (extractions, fields, errors) = fileinfo::stats();
            shell_println!("File Info Statistics");
            shell_println!("  Extractions: {}", extractions);
            shell_println!("  Fields:      {}", fields);
            shell_println!("  Errors:      {}", errors);
        }
        "reset" => {
            fileinfo::reset_stats();
            shell_println!("File info statistics reset.");
        }
        "fields" => {
            // Show known fields for a MIME type.
            if parts.len() < 2 {
                shell_println!("Usage: fileinfo fields <mime-type>");
                shell_println!("  Example: fileinfo fields audio/mpeg");
                return;
            }
            let fields = fileinfo::fields_for_mime(parts[1]);
            if fields.is_empty() {
                shell_println!("No known fields for: {}", parts[1]);
            } else {
                shell_println!("Fields for {}:", parts[1]);
                for (name, label) in &fields {
                    shell_println!("  {:30} {}", name, label);
                }
            }
        }
        "" => {
            shell_println!("Usage: fileinfo <path> | fileinfo <command>");
            shell_println!("  <path>                       Extract metadata from file");
            shell_println!("  fields <mime-type>           List known fields for MIME type");
            shell_println!("  stats                        Show statistics");
            shell_println!("  reset                        Reset counters");
        }
        _ => {
            // Treat as file path.
            let path = resolve_path(sub);
            match fileinfo::extract(&path) {
                Ok(info) => {
                    shell_println!("File:   {}", info.path);
                    shell_println!("MIME:   {}", info.mime);
                    shell_println!("Format: {}", info.format_desc);
                    if info.fields.is_empty() {
                        shell_println!("\nNo metadata fields extracted.");
                    } else {
                        shell_println!("\n{:30} {}", "FIELD", "VALUE");
                        shell_println!("{}", "-".repeat(60));
                        for field in &info.fields {
                            shell_println!("{:30} {}", field.label, field.value.display());
                        }
                    }
                }
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
    }
}

fn cmd_fswalk(args: &str) {
    use crate::fs::fswalk::{self, WalkOptions, WalkFilter, WalkOrder};
    let parts: Vec<&str> = args.split_whitespace().collect();
    let sub = parts.first().copied().unwrap_or("");
    match sub {
        "stats" => {
            let (walks, entries, errors) = fswalk::stats();
            shell_println!("Walk Statistics");
            shell_println!("  Walks:   {}", walks);
            shell_println!("  Entries: {}", entries);
            shell_println!("  Errors:  {}", errors);
        }
        "reset" => {
            fswalk::reset_stats();
            shell_println!("Walk statistics reset.");
        }
        "count" => {
            let path = if parts.len() > 1 { resolve_path(parts[1]) } else { get_cwd() };
            let depth = parts.get(2).and_then(|s| s.parse::<usize>().ok()).unwrap_or(64);
            match fswalk::count(&path, depth) {
                Ok((files, dirs)) => {
                    shell_println!("{}: {} files, {} dirs", path, files, dirs);
                }
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "size" => {
            let path = if parts.len() > 1 { resolve_path(parts[1]) } else { get_cwd() };
            let depth = parts.get(2).and_then(|s| s.parse::<usize>().ok()).unwrap_or(64);
            match fswalk::total_size(&path, depth) {
                Ok(size) => {
                    shell_println!("{}: {} bytes", path, size);
                }
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "find" => {
            if parts.len() < 2 {
                shell_println!("Usage: fswalk find <pattern> [path] [max-depth]");
                return;
            }
            let pattern = parts[1];
            let path = if parts.len() > 2 { resolve_path(parts[2]) } else { get_cwd() };
            let depth = parts.get(3).and_then(|s| s.parse::<usize>().ok()).unwrap_or(64);
            match fswalk::find(&path, pattern, depth) {
                Ok(files) => {
                    if files.is_empty() {
                        shell_println!("No files found matching '{}'.", pattern);
                    } else {
                        for f in &files {
                            shell_println!("{}", f);
                        }
                        shell_println!("\n{} matches.", files.len());
                    }
                }
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "" => {
            // Default: walk current directory with default options.
            let path = get_cwd();
            let opts = WalkOptions {
                max_depth: 3,
                limit: 50,
                ..Default::default()
            };
            match fswalk::walk(&path, &opts) {
                Ok(result) => {
                    for entry in &result.entries {
                        let prefix = "  ".repeat(entry.depth);
                        let type_char = match entry.entry_type {
                            crate::fs::EntryType::Directory => "d",
                            crate::fs::EntryType::File => "f",
                            crate::fs::EntryType::Symlink => "l",
                            _ => "?",
                        };
                        let name = entry.path.rsplit('/').next().unwrap_or(&entry.path);
                        if entry.size > 0 {
                            shell_println!("{}[{}] {} ({} B)", prefix, type_char, name, entry.size);
                        } else {
                            shell_println!("{}[{}] {}", prefix, type_char, name);
                        }
                    }
                    shell_println!("\n{} files, {} dirs, {} total bytes",
                        result.stats.files, result.stats.dirs, result.stats.total_size);
                    if result.truncated {
                        shell_println!("(truncated)");
                    }
                }
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        _ => {
            // Treat as path.
            let path = resolve_path(sub);
            let mut opts = WalkOptions {
                max_depth: 3,
                limit: 100,
                ..Default::default()
            };
            // Parse extra options.
            let mut i = 1;
            while i < parts.len() {
                match parts[i] {
                    "-d" | "--depth" => {
                        if let Some(d) = parts.get(i + 1).and_then(|s| s.parse::<usize>().ok()) {
                            opts.max_depth = d;
                        }
                        i += 2;
                    }
                    "-n" | "--limit" => {
                        if let Some(n) = parts.get(i + 1).and_then(|s| s.parse::<usize>().ok()) {
                            opts.limit = n;
                        }
                        i += 2;
                    }
                    "-f" | "--files" => { opts.filter = WalkFilter::FilesOnly; i += 1; }
                    "-D" | "--dirs" => { opts.filter = WalkFilter::DirsOnly; i += 1; }
                    "-a" | "--all" => { opts.show_hidden = true; i += 1; }
                    "-b" | "--bfs" => { opts.order = WalkOrder::BreadthFirst; i += 1; }
                    "-p" | "--pattern" => {
                        if let Some(p) = parts.get(i + 1) {
                            opts.pattern = alloc::string::String::from(*p);
                        }
                        i += 2;
                    }
                    _ => { i += 1; }
                }
            }
            match fswalk::walk(&path, &opts) {
                Ok(result) => {
                    for entry in &result.entries {
                        let prefix = "  ".repeat(entry.depth);
                        let type_char = match entry.entry_type {
                            crate::fs::EntryType::Directory => "d",
                            crate::fs::EntryType::File => "f",
                            crate::fs::EntryType::Symlink => "l",
                            _ => "?",
                        };
                        let name = entry.path.rsplit('/').next().unwrap_or(&entry.path);
                        if entry.size > 0 {
                            shell_println!("{}[{}] {} ({} B)", prefix, type_char, name, entry.size);
                        } else {
                            shell_println!("{}[{}] {}", prefix, type_char, name);
                        }
                    }
                    shell_println!("\n{} files, {} dirs, {} total bytes",
                        result.stats.files, result.stats.dirs, result.stats.total_size);
                    if result.truncated {
                        shell_println!("(truncated)");
                    }
                }
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
    }
}

fn cmd_findex(args: &str) {
    use crate::fs::findex;
    let parts: Vec<&str> = args.split_whitespace().collect();
    let sub = parts.first().copied().unwrap_or("");
    match sub {
        "build" => {
            let path = if parts.len() > 1 { resolve_path(parts[1]) } else { get_cwd() };
            let depth = parts.get(2).and_then(|s| s.parse::<usize>().ok()).unwrap_or(3);
            shell_println!("Indexing {}  (depth {})...", path, depth);
            match findex::build(&path, depth) {
                Ok(count) => shell_println!("Indexed {} files.", count),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "add" | "index" => {
            if parts.len() < 2 {
                shell_println!("Usage: findex add <path>");
                return;
            }
            let path = resolve_path(parts[1]);
            match findex::index_file(&path) {
                Ok(fields) => shell_println!("Indexed {}: {} fields", path, fields),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "remove" | "rm" => {
            if parts.len() < 2 {
                shell_println!("Usage: findex remove <path>");
                return;
            }
            let path = resolve_path(parts[1]);
            if findex::remove_file(&path) {
                shell_println!("Removed: {}", path);
            } else {
                shell_println!("Not indexed: {}", path);
            }
        }
        "query" | "q" => {
            if parts.len() < 2 {
                shell_println!("Usage: findex query <field op value [AND ...]>");
                shell_println!("  Ops: = != < > <= >= ~ (contains) ^ (starts) $ (ends)");
                shell_println!("  Example: findex query audio.artist=Radiohead");
                shell_println!("  Example: findex query image.width>=1920 AND image.height>=1080");
                return;
            }
            let query_str = parts[1..].join(" ");
            let predicates = findex::parse_query(&query_str);
            if predicates.is_empty() {
                shell_println!("No valid predicates in query.");
                return;
            }
            let results = findex::query(&predicates);
            if results.is_empty() {
                shell_println!("No matching files.");
            } else {
                for path in &results {
                    shell_println!("{}", path);
                }
                shell_println!("\n{} matches.", results.len());
            }
        }
        "get" | "show" => {
            if parts.len() < 2 {
                shell_println!("Usage: findex get <path>");
                return;
            }
            let path = resolve_path(parts[1]);
            let fields = findex::get_fields(&path);
            if fields.is_empty() {
                shell_println!("No indexed fields for: {}", path);
            } else {
                shell_println!("{:30} {}", "FIELD", "VALUE");
                shell_println!("{}", "-".repeat(60));
                for (name, value) in &fields {
                    shell_println!("{:30} {}", name, value);
                }
            }
        }
        "columns" | "cols" => {
            let path = if parts.len() > 1 { resolve_path(parts[1]) } else { get_cwd() };
            let columns = findex::columns_for_dir(&path);
            if columns.is_empty() {
                shell_println!("No indexed files in: {}", path);
            } else {
                shell_println!("Recommended columns for {}:", path);
                shell_println!("{:30} {:20} {:>5}", "FIELD", "LABEL", "FILES");
                shell_println!("{}", "-".repeat(60));
                for col in &columns {
                    shell_println!("{:30} {:20} {:>5}", col.name, col.label, col.count);
                }
            }
        }
        "fields" => {
            let fields = findex::known_fields();
            if fields.is_empty() {
                shell_println!("No fields indexed yet.");
            } else {
                shell_println!("{:30} {}", "FIELD NAME", "LABEL");
                shell_println!("{}", "-".repeat(50));
                for (name, label) in &fields {
                    shell_println!("{:30} {}", name, label);
                }
            }
        }
        "clear" => {
            findex::clear();
            shell_println!("Index cleared.");
        }
        "stats" => {
            let (builds, ops, queries, indexed, fields) = findex::stats();
            shell_println!("File Index Statistics");
            shell_println!("  Indexed files: {}/16384", indexed);
            shell_println!("  Known fields:  {}/256", fields);
            shell_println!("  Builds:        {}", builds);
            shell_println!("  Index ops:     {}", ops);
            shell_println!("  Queries:       {}", queries);
        }
        "reset" => {
            findex::reset_stats();
            shell_println!("Index statistics reset.");
        }
        _ => {
            shell_println!("Usage: findex <command>");
            shell_println!("  build [path] [depth]         Build index for directory");
            shell_println!("  add <path>                   Index a single file");
            shell_println!("  remove <path>                Remove from index");
            shell_println!("  query <predicates>           Search by attributes");
            shell_println!("  get <path>                   Show fields for a file");
            shell_println!("  columns [dir]                Discover columns for dir");
            shell_println!("  fields                       List all known field names");
            shell_println!("  clear                        Clear entire index");
            shell_println!("  stats                        Show statistics");
            shell_println!("  reset                        Reset counters");
        }
    }
}

fn cmd_thumbcache(args: &str) {
    use crate::fs::thumbcache;
    let parts: Vec<&str> = args.split_whitespace().collect();
    let sub = parts.first().copied().unwrap_or("");
    match sub {
        "list" | "show" | "" => {
            let entries = thumbcache::list();
            if entries.is_empty() {
                shell_println!("Thumbnail cache is empty.");
            } else {
                shell_println!("{:40} {:8} {:>5}x{:<5} {:>8}", "PATH", "SIZE", "W", "H", "BYTES");
                shell_println!("{}", "-".repeat(75));
                for (path, size, w, h, bytes) in &entries {
                    shell_println!("{:40} {:8} {:>5}x{:<5} {:>8}", path, size.label(), w, h, bytes);
                }
                shell_println!("\n{} entries, {} bytes used.", entries.len(), thumbcache::memory_used());
            }
        }
        "invalidate" | "inv" => {
            if parts.len() < 2 {
                shell_println!("Usage: thumbcache invalidate <path>");
                return;
            }
            let path = resolve_path(parts[1]);
            let removed = thumbcache::invalidate(&path);
            shell_println!("Invalidated {} entries for: {}", removed, path);
        }
        "clear" => {
            thumbcache::clear();
            shell_println!("Thumbnail cache cleared.");
        }
        "stats" => {
            let (hits, misses, stores, evicts, count, mem) = thumbcache::stats();
            let hit_rate = if hits + misses > 0 { (hits * 100) / (hits + misses) } else { 0 };
            shell_println!("Thumbnail Cache Statistics");
            shell_println!("  Cached:    {}/2048", count);
            shell_println!("  Memory:    {} / {} bytes", mem, 16 * 1024 * 1024);
            shell_println!("  Hit rate:  {}% ({} hits, {} misses)", hit_rate, hits, misses);
            shell_println!("  Stores:    {}", stores);
            shell_println!("  Evictions: {}", evicts);
        }
        "reset" => {
            thumbcache::reset_stats();
            shell_println!("Thumbnail cache statistics reset.");
        }
        _ => {
            shell_println!("Usage: thumbcache <command>");
            shell_println!("  list|show                    List cached thumbnails (default)");
            shell_println!("  invalidate <path>            Invalidate cache for file");
            shell_println!("  clear                        Clear entire cache");
            shell_println!("  stats                        Show statistics");
            shell_println!("  reset                        Reset counters");
        }
    }
}

fn cmd_bookmark(args: &str) {
    use crate::fs::bookmarks::{self, Category};
    let parts: Vec<&str> = args.split_whitespace().collect();
    let sub = parts.first().copied().unwrap_or("");
    match sub {
        "list" | "show" | "" => {
            let bm_list = bookmarks::list_visible();
            if bm_list.is_empty() {
                shell_println!("No bookmarks.");
            } else {
                let mut current_cat = "";
                for bm in &bm_list {
                    let cat = bm.category.label();
                    if cat != current_cat {
                        if !current_cat.is_empty() { shell_println!(""); }
                        shell_println!("{}:", cat);
                        current_cat = cat;
                    }
                    let vis = if bm.system { "(sys)" } else { "" };
                    shell_println!("  {:12} {:30} {} {}", bm.name, bm.path, bm.label, vis);
                }
            }
        }
        "add" => {
            if parts.len() < 3 {
                shell_println!("Usage: bookmark add <name> <path> [label] [category]");
                shell_println!("  Categories: places, favorites (default), devices, network");
                return;
            }
            let name = parts[1];
            let path = resolve_path(parts[2]);
            let label = if parts.len() > 3 { parts[3] } else { "" };
            let category = parts.get(4)
                .and_then(|s| Category::from_name(s))
                .unwrap_or(Category::Favorites);
            match bookmarks::add(name, &path, label, category) {
                Ok(()) => shell_println!("Bookmark '{}' added: {}", name, path),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "rm" | "remove" => {
            if parts.len() < 2 {
                shell_println!("Usage: bookmark remove <name>");
                return;
            }
            match bookmarks::remove(parts[1]) {
                Ok(()) => shell_println!("Bookmark '{}' removed.", parts[1]),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "go" | "cd" => {
            if parts.len() < 2 {
                shell_println!("Usage: bookmark go <name>");
                return;
            }
            if let Some(path) = bookmarks::resolve(parts[1]) {
                bookmarks::record_access(parts[1]);
                // Update CWD like cmd_cd does.
                {
                    let mut cwd = CWD.lock();
                    cwd.clear();
                    cwd.push_str(&path);
                }
                shell_println!("{}", path);
            } else {
                shell_println!("Unknown bookmark: {}", parts[1]);
            }
        }
        "rename" => {
            if parts.len() < 3 {
                shell_println!("Usage: bookmark rename <old-name> <new-name>");
                return;
            }
            match bookmarks::rename(parts[1], parts[2]) {
                Ok(()) => shell_println!("Renamed '{}' → '{}'", parts[1], parts[2]),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "validate" => {
            let results = bookmarks::validate();
            for (name, path, exists) in &results {
                let status = if *exists { "OK" } else { "MISSING" };
                shell_println!("{:12} {:30} {}", name, path, status);
            }
        }
        "stats" => {
            let (resolves, adds, count) = bookmarks::stats();
            shell_println!("Bookmark Statistics");
            shell_println!("  Bookmarks: {}/128", count);
            shell_println!("  Resolves:  {}", resolves);
            shell_println!("  Adds:      {}", adds);
        }
        "reset" => {
            bookmarks::reset_stats();
            shell_println!("Bookmark statistics reset.");
        }
        _ => {
            shell_println!("Usage: bookmark <command>");
            shell_println!("  list|show                    List bookmarks (default)");
            shell_println!("  add <name> <path> [lbl] [cat] Add bookmark");
            shell_println!("  remove <name>                Remove bookmark");
            shell_println!("  go <name>                    Navigate to bookmark");
            shell_println!("  rename <old> <new>           Rename bookmark");
            shell_println!("  validate                     Check paths exist");
            shell_println!("  stats                        Show statistics");
            shell_println!("  reset                        Reset counters");
        }
    }
}

/// `clipboard` — system clipboard operations.
fn cmd_clipboard(args: &str) {
    use crate::fs::clipboard;
    let parts: Vec<&str> = args.split_whitespace().collect();
    let sub = parts.first().copied().unwrap_or("");
    match sub {
        "copy" | "text" => {
            let text = args.trim_start_matches("copy").trim_start_matches("text").trim();
            if text.is_empty() {
                shell_println!("Usage: clipboard copy <text>");
                return;
            }
            match clipboard::set_text(text, "kshell") {
                Ok(()) => shell_println!("Copied to clipboard."),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "paste" | "get" => {
            match clipboard::get_text() {
                Some(text) => shell_println!("{}", text),
                None => shell_println!("Clipboard is empty or not text."),
            }
        }
        "files" => {
            match clipboard::get_files() {
                Some((paths, op)) => {
                    let op_label = match op {
                        clipboard::FileOp::Copy => "copy",
                        clipboard::FileOp::Cut => "cut",
                    };
                    shell_println!("File operation: {}", op_label);
                    for p in &paths {
                        shell_println!("  {}", p);
                    }
                }
                None => shell_println!("No files on clipboard."),
            }
        }
        "formats" => {
            let fmts = clipboard::available_formats();
            if fmts.is_empty() {
                shell_println!("Clipboard is empty.");
            } else {
                shell_println!("Available formats:");
                for f in &fmts {
                    shell_println!("  {}", f.mime());
                }
            }
        }
        "history" | "hist" => {
            let hist = clipboard::history();
            if hist.is_empty() {
                shell_println!("No clipboard history.");
            } else {
                shell_println!("{:4} {:10} {:20} {}", "IDX", "SEQ", "SOURCE", "FORMATS");
                for (i, entry) in hist.iter().enumerate() {
                    let fmts: Vec<&str> = entry.formats.iter()
                        .map(|f| f.format.mime())
                        .collect();
                    shell_println!("{:4} {:10} {:20} {}", i, entry.sequence, entry.source,
                        fmts.join(", "));
                }
            }
        }
        "restore" => {
            if let Some(idx_str) = parts.get(1) {
                if let Ok(idx) = idx_str.parse::<usize>() {
                    match clipboard::restore_from_history(idx) {
                        Ok(()) => shell_println!("Restored entry {}.", idx),
                        Err(e) => shell_println!("Error: {:?}", e),
                    }
                } else {
                    shell_println!("Invalid index.");
                }
            } else {
                shell_println!("Usage: clipboard restore <index>");
            }
        }
        "watch" => {
            let label = parts.get(1).copied().unwrap_or("kshell");
            match clipboard::watch(label) {
                Ok(id) => shell_println!("Watching clipboard (id={}).", id),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "unwatch" => {
            if let Some(id_str) = parts.get(1) {
                if let Ok(id) = id_str.parse::<u64>() {
                    if clipboard::unwatch(id) {
                        shell_println!("Unwatched id {}.", id);
                    } else {
                        shell_println!("No watcher with id {}.", id);
                    }
                } else {
                    shell_println!("Invalid watcher id.");
                }
            } else {
                shell_println!("Usage: clipboard unwatch <id>");
            }
        }
        "watchers" => {
            let ws = clipboard::list_watchers();
            if ws.is_empty() {
                shell_println!("No watchers.");
            } else {
                shell_println!("{:6} {}", "ID", "LABEL");
                for (id, label) in &ws {
                    shell_println!("{:6} {}", id, label);
                }
            }
        }
        "clear" => {
            clipboard::clear();
            shell_println!("Clipboard cleared.");
        }
        "clearall" => {
            clipboard::clear_all();
            shell_println!("Clipboard and history cleared.");
        }
        "stats" | "" => {
            let (copies, pastes, total_bytes, seq, hist_count, watchers) = clipboard::stats();
            shell_println!("Clipboard statistics:");
            shell_println!("  Sequence:     {}", seq);
            shell_println!("  Copies:       {}", copies);
            shell_println!("  Pastes:       {}", pastes);
            shell_println!("  Total bytes:  {}", total_bytes);
            shell_println!("  History:      {}/{}", hist_count, 32);
            shell_println!("  Watchers:     {}/{}", watchers, 16);
            let fmts = clipboard::available_formats();
            if !fmts.is_empty() {
                shell_println!("  Formats:      {}", fmts.len());
            }
        }
        "reset" => {
            clipboard::reset_stats();
            shell_println!("Clipboard statistics reset.");
        }
        _ => {
            shell_println!("Usage: clipboard <command>");
            shell_println!("  copy <text>      Copy text to clipboard");
            shell_println!("  paste|get        Paste text from clipboard");
            shell_println!("  files            Show file operations on clipboard");
            shell_println!("  formats          Show available formats");
            shell_println!("  history|hist     Show clipboard history");
            shell_println!("  restore <idx>    Restore entry from history");
            shell_println!("  watch [label]    Register change watcher");
            shell_println!("  unwatch <id>     Remove watcher");
            shell_println!("  watchers         List watchers");
            shell_println!("  clear            Clear current clipboard");
            shell_println!("  clearall         Clear clipboard and history");
            shell_println!("  stats            Show statistics (default)");
            shell_println!("  reset            Reset counters");
        }
    }
}

/// `contextmenu` / `ctxmenu` — context menu system.
fn cmd_contextmenu(args: &str) {
    let parts: Vec<&str> = args.split_whitespace().collect();
    let sub = parts.first().copied().unwrap_or("");
    match sub {
        "build" => {
            // contextmenu build <target> [path]
            let target_str = parts.get(1).copied().unwrap_or("file");
            let path = parts.get(2).map(|p| resolve_path(p)).unwrap_or_else(get_cwd);
            let target = match target_str {
                "file" => crate::fs::contextmenu::ContextTarget::File,
                "dir" | "directory" => crate::fs::contextmenu::ContextTarget::Directory,
                "multi" => crate::fs::contextmenu::ContextTarget::MultiSelection,
                "desktop" => crate::fs::contextmenu::ContextTarget::DesktopBackground,
                "explorer" => crate::fs::contextmenu::ContextTarget::ExplorerBackground,
                "taskbar" => crate::fs::contextmenu::ContextTarget::Taskbar,
                _ => {
                    shell_println!("Unknown target: {}. Use: file, dir, multi, desktop, explorer, taskbar", target_str);
                    return;
                }
            };
            let menu = crate::fs::contextmenu::build(target, &path);
            shell_println!("Context menu for {:?} on '{}':", menu.target, menu.target_path);
            for item in &menu.items {
                if item.separator {
                    shell_println!("  ─────────────────────");
                } else if !item.submenu.is_empty() {
                    shell_println!("  {} ►  ({})", item.label, item.submenu.len());
                    for sub_item in &item.submenu {
                        if sub_item.separator {
                            shell_println!("    ───────────");
                        } else {
                            shell_println!("    {}", sub_item.label);
                        }
                    }
                } else {
                    let shortcut = if item.shortcut.is_empty() {
                        String::new()
                    } else {
                        alloc::format!("  ({})", item.shortcut)
                    };
                    let enabled = if item.enabled { "" } else { " [disabled]" };
                    shell_println!("  {}{}{}", item.label, shortcut, enabled);
                }
            }
        }
        "extensions" | "ext" => {
            let exts = crate::fs::contextmenu::list_extensions();
            if exts.is_empty() {
                shell_println!("(no registered extensions)");
            } else {
                shell_println!("{:<6} {:<20} {:<8} {}", "ID", "Application", "Status", "Items");
                shell_println!("{}", "-".repeat(50));
                for (id, name, enabled, items) in &exts {
                    shell_println!("#{:<5} {:<20} {:<8} {}",
                                   id, name,
                                   if *enabled { "on" } else { "off" },
                                   items);
                }
            }
        }
        "enable" => {
            if let Some(id) = parts.get(1).and_then(|s| s.parse::<u64>().ok()) {
                match crate::fs::contextmenu::set_extension_enabled(id, true) {
                    Ok(()) => shell_println!("Extension #{} enabled", id),
                    Err(e) => shell_println!("Error: {:?}", e),
                }
            } else {
                shell_println!("Usage: contextmenu enable <ext-id>");
            }
        }
        "disable" => {
            if let Some(id) = parts.get(1).and_then(|s| s.parse::<u64>().ok()) {
                match crate::fs::contextmenu::set_extension_enabled(id, false) {
                    Ok(()) => shell_println!("Extension #{} disabled", id),
                    Err(e) => shell_println!("Error: {:?}", e),
                }
            } else {
                shell_println!("Usage: contextmenu disable <ext-id>");
            }
        }
        "remove" => {
            if let Some(id) = parts.get(1).and_then(|s| s.parse::<u64>().ok()) {
                match crate::fs::contextmenu::unregister_extension(id) {
                    Ok(()) => shell_println!("Extension #{} removed", id),
                    Err(e) => shell_println!("Error: {:?}", e),
                }
            } else {
                shell_println!("Usage: contextmenu remove <ext-id>");
            }
        }
        "stats" => {
            let (builds, executes, ext_count) = crate::fs::contextmenu::stats();
            shell_println!("Builds:     {}", builds);
            shell_println!("Executions: {}", executes);
            shell_println!("Extensions: {}", ext_count);
        }
        "reset" => {
            crate::fs::contextmenu::reset_stats();
            shell_println!("Context menu stats reset");
        }
        _ => {
            shell_println!("Usage: contextmenu <subcommand>");
            shell_println!("  build <target> [path]  Build context menu");
            shell_println!("    targets: file, dir, multi, desktop, explorer, taskbar");
            shell_println!("  extensions             List registered extensions");
            shell_println!("  enable <id>            Enable an extension");
            shell_println!("  disable <id>           Disable an extension");
            shell_println!("  remove <id>            Remove an extension");
            shell_println!("  stats                  Show statistics");
            shell_println!("  reset                  Reset statistics");
        }
    }
}

/// `deskicons` — desktop icon layout management.
fn cmd_deskicons(args: &str) {
    let parts: Vec<&str> = args.split_whitespace().collect();
    let sub = parts.first().copied().unwrap_or("");
    match sub {
        "load" => {
            let dir = parts.get(1).map(|p| resolve_path(p)).unwrap_or_else(|| String::from("/home/user/Desktop"));
            let w: u32 = parts.get(2).and_then(|s| s.parse().ok()).unwrap_or(1920);
            let h: u32 = parts.get(3).and_then(|s| s.parse().ok()).unwrap_or(1080);
            match crate::fs::deskicons::load(&dir, w, h) {
                Ok(()) => {
                    let count = crate::fs::deskicons::icon_count();
                    shell_println!("Loaded {} desktop icons from {}", count, dir);
                }
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "list" => {
            if let Some(layout) = crate::fs::deskicons::get_layout() {
                shell_println!("Desktop: {} ({}x{}) [{:?}]",
                               layout.desktop_path, layout.screen_w, layout.screen_h, layout.mode);
                shell_println!("{:<20} {:<8} {:<8} {}", "Name", "X", "Y", "Type");
                shell_println!("{}", "-".repeat(50));
                for icon in &layout.icons {
                    let kind = if icon.special.is_some() {
                        "special"
                    } else if icon.is_dir {
                        "dir"
                    } else {
                        "file"
                    };
                    let sel = if icon.selected { " *" } else { "" };
                    shell_println!("{:<20} {:<8} {:<8} {}{}", icon.name, icon.x, icon.y, kind, sel);
                }
            } else {
                shell_println!("(no desktop layout loaded - use 'deskicons load' first)");
            }
        }
        "arrange" => {
            let sort_str = parts.get(1).copied().unwrap_or("name");
            let sort = match sort_str {
                "name" => crate::fs::deskicons::SortBy::Name,
                "size" => crate::fs::deskicons::SortBy::Size,
                "type" => crate::fs::deskicons::SortBy::Type,
                "date" => crate::fs::deskicons::SortBy::DateModified,
                _ => {
                    shell_println!("Sort options: name, size, type, date");
                    return;
                }
            };
            match crate::fs::deskicons::auto_arrange(sort) {
                Ok(()) => shell_println!("Icons arranged by {:?}", sort),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "mode" => {
            let mode_str = parts.get(1).copied().unwrap_or("");
            let mode = match mode_str {
                "grid" | "snap" => crate::fs::deskicons::LayoutMode::SnapToGrid,
                "free" => crate::fs::deskicons::LayoutMode::FreePlacement,
                _ => {
                    shell_println!("Usage: deskicons mode <grid|free>");
                    return;
                }
            };
            match crate::fs::deskicons::set_mode(mode) {
                Ok(()) => shell_println!("Layout mode: {:?}", mode),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "select" => {
            if let Some(name) = parts.get(1) {
                let exclusive = !parts.contains(&"--add");
                match crate::fs::deskicons::select(name, exclusive) {
                    Ok(()) => shell_println!("Selected: {}", name),
                    Err(e) => shell_println!("Error: {:?}", e),
                }
            } else {
                shell_println!("Usage: deskicons select <name> [--add]");
            }
        }
        "deselect" => {
            match crate::fs::deskicons::deselect_all() {
                Ok(()) => shell_println!("All icons deselected"),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "refresh" => {
            match crate::fs::deskicons::refresh() {
                Ok(()) => shell_println!("Desktop refreshed ({} icons)", crate::fs::deskicons::icon_count()),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "hit" => {
            if let (Some(x), Some(y)) = (
                parts.get(1).and_then(|s| s.parse::<u32>().ok()),
                parts.get(2).and_then(|s| s.parse::<u32>().ok()),
            ) {
                match crate::fs::deskicons::icon_at(x, y) {
                    Some(name) => shell_println!("Hit: {}", name),
                    None => shell_println!("(no icon at {}, {})", x, y),
                }
            } else {
                shell_println!("Usage: deskicons hit <x> <y>");
            }
        }
        "stats" => {
            let (loads, arranges, count) = crate::fs::deskicons::stats();
            shell_println!("Icons:    {}", count);
            shell_println!("Loads:    {}", loads);
            shell_println!("Arranges: {}", arranges);
        }
        "reset" => {
            crate::fs::deskicons::reset_stats();
            shell_println!("Desktop icon stats reset");
        }
        _ => {
            shell_println!("Usage: deskicons <subcommand>");
            shell_println!("  load [dir] [w] [h]  Load desktop icons");
            shell_println!("  list                List all icons");
            shell_println!("  arrange <sort>      Auto-arrange (name/size/type/date)");
            shell_println!("  mode <grid|free>    Set layout mode");
            shell_println!("  select <name>       Select an icon");
            shell_println!("  deselect            Deselect all");
            shell_println!("  refresh             Refresh from filesystem");
            shell_println!("  hit <x> <y>         Hit test at coordinates");
            shell_println!("  stats               Show statistics");
            shell_println!("  reset               Reset statistics");
        }
    }
}

/// `dragdrop` — drag-and-drop subsystem management.
fn cmd_dragdrop(args: &str) {
    use crate::fs::dragdrop;
    let parts: Vec<&str> = args.split_whitespace().collect();
    let sub = parts.first().copied().unwrap_or("");
    match sub {
        "status" | "" => {
            let (drags, drops, cancels, total_bytes, zone_count) = dragdrop::stats();
            shell_println!("Drag-and-drop status:");
            shell_println!("  Total drags:    {}", drags);
            shell_println!("  Total drops:    {}", drops);
            shell_println!("  Total cancels:  {}", cancels);
            shell_println!("  Total bytes:    {}", total_bytes);
            shell_println!("  Drop zones:     {}/{}", zone_count, 256);
            shell_println!("  Active drag:    {}", if dragdrop::is_dragging() { "yes" } else { "no" });
            if let Some(session) = dragdrop::current_session() {
                shell_println!("  Source:         {}", session.source);
                shell_println!("  Formats:        {}", session.offered_formats.len());
                shell_println!("  Cursor:         ({}, {})", session.cursor.0, session.cursor.1);
            }
        }
        "zones" => {
            let zones = dragdrop::list_zones();
            if zones.is_empty() {
                shell_println!("No drop zones registered.");
            } else {
                shell_println!("{:6} {:8} {:12} {:20} {:20} {}", "ID", "ACTIVE", "KIND", "OWNER", "LABEL", "BOUNDS");
                for z in &zones {
                    let kind = match z.kind {
                        dragdrop::DropZoneKind::FileListEmpty => "file-list",
                        dragdrop::DropZoneKind::FolderEntry => "folder",
                        dragdrop::DropZoneKind::FileEntry => "file",
                        dragdrop::DropZoneKind::TextInput => "text",
                        dragdrop::DropZoneKind::ImageArea => "image",
                        dragdrop::DropZoneKind::Custom => "custom",
                    };
                    let (x, y, w, h) = z.bounds;
                    shell_println!("{:6} {:8} {:12} {:20} {:20} {}x{}+{}+{}",
                        z.id, if z.active { "yes" } else { "no" }, kind,
                        z.owner, z.label, w, h, x, y);
                }
            }
        }
        "test" => {
            // Quick text drag test for shell.
            match dragdrop::begin_text_drag("kshell", "test drag data") {
                Ok(id) => {
                    shell_println!("Started test drag session {}.", id);
                    match dragdrop::accept(dragdrop::DragFormat::PlainText) {
                        Ok(data) => {
                            let text = core::str::from_utf8(&data).unwrap_or("<binary>");
                            shell_println!("Accepted: {}", text);
                        }
                        Err(e) => shell_println!("Accept error: {:?}", e),
                    }
                    dragdrop::finish();
                    shell_println!("Test drag completed.");
                }
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "cancel" => {
            if dragdrop::cancel() {
                dragdrop::finish();
                shell_println!("Active drag cancelled.");
            } else {
                shell_println!("No active drag to cancel.");
            }
        }
        "stats" => {
            let (drags, drops, cancels, total_bytes, zone_count) = dragdrop::stats();
            shell_println!("Drag-and-drop statistics:");
            shell_println!("  Drags:       {}", drags);
            shell_println!("  Drops:       {}", drops);
            shell_println!("  Cancels:     {}", cancels);
            shell_println!("  Bytes:       {}", total_bytes);
            shell_println!("  Zones:       {}", zone_count);
        }
        "reset" => {
            dragdrop::reset_stats();
            shell_println!("Drag-and-drop statistics reset.");
        }
        _ => {
            shell_println!("Usage: dragdrop <command>");
            shell_println!("  status       Show current state (default)");
            shell_println!("  zones        List registered drop zones");
            shell_println!("  test         Run a test drag-and-drop");
            shell_println!("  cancel       Cancel active drag session");
            shell_println!("  stats        Show statistics");
            shell_println!("  reset        Reset counters");
        }
    }
}

/// `fileops` — bulk file operations engine.
fn cmd_fileops(args: &str) {
    use crate::fs::fileops;
    let parts: Vec<&str> = args.split_whitespace().collect();
    let sub = parts.first().copied().unwrap_or("");
    match sub {
        "copy" | "cp" => {
            // fileops copy <src> [<src2> ...] <dest> [--overwrite|--skip|--rename]
            if parts.len() < 3 {
                shell_println!("Usage: fileops copy <source...> <dest> [--overwrite|--skip|--rename]");
                return;
            }
            let mut sources = Vec::new();
            let mut policy = fileops::ConflictPolicy::AutoRename;

            // Parse: everything except last non-flag arg is a source, last non-flag is dest.
            let mut non_flags: Vec<&str> = Vec::new();
            for &p in parts.iter().skip(1) {
                match p {
                    "--overwrite" | "-o" => policy = fileops::ConflictPolicy::Overwrite,
                    "--skip" | "-s" => policy = fileops::ConflictPolicy::Skip,
                    "--rename" | "-r" => policy = fileops::ConflictPolicy::AutoRename,
                    "--merge" | "-m" => policy = fileops::ConflictPolicy::MergeDir,
                    _ => non_flags.push(p),
                }
            }

            if non_flags.len() < 2 {
                shell_println!("Need at least one source and one destination.");
                return;
            }

            let dest = non_flags.last().copied().unwrap_or("");
            for &nf in non_flags.iter().take(non_flags.len().saturating_sub(1)) {
                sources.push(resolve_path(nf));
            }

            let dest_resolved = resolve_path(dest);
            let src_refs: Vec<&str> = sources.iter().map(|s| s.as_str()).collect();

            match fileops::create(fileops::OpKind::Copy, &src_refs, &dest_resolved, policy) {
                Ok(op_id) => {
                    shell_println!("Created copy operation {}.", op_id);
                    match fileops::execute(op_id) {
                        Ok(prog) => {
                            shell_println!("Completed: {}/{} items, {} bytes, {} skipped, {} failed.",
                                prog.processed_items, prog.total_items,
                                prog.transferred_bytes, prog.skipped, prog.failed);
                        }
                        Err(e) => shell_println!("Execution error: {:?}", e),
                    }
                }
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "move" | "mv" => {
            if parts.len() < 3 {
                shell_println!("Usage: fileops move <source...> <dest> [--overwrite|--skip|--rename]");
                return;
            }
            let mut policy = fileops::ConflictPolicy::AutoRename;
            let mut non_flags: Vec<&str> = Vec::new();

            for &p in parts.iter().skip(1) {
                match p {
                    "--overwrite" | "-o" => policy = fileops::ConflictPolicy::Overwrite,
                    "--skip" | "-s" => policy = fileops::ConflictPolicy::Skip,
                    "--rename" | "-r" => policy = fileops::ConflictPolicy::AutoRename,
                    _ => non_flags.push(p),
                }
            }

            if non_flags.len() < 2 {
                shell_println!("Need at least one source and one destination.");
                return;
            }

            let dest_str = non_flags.last().copied().unwrap_or("");
            let mut sources = Vec::new();
            for &nf in non_flags.iter().take(non_flags.len().saturating_sub(1)) {
                sources.push(resolve_path(nf));
            }

            let dest_resolved = resolve_path(dest_str);
            let src_refs: Vec<&str> = sources.iter().map(|s| s.as_str()).collect();

            match fileops::create(fileops::OpKind::Move, &src_refs, &dest_resolved, policy) {
                Ok(op_id) => {
                    shell_println!("Created move operation {}.", op_id);
                    match fileops::execute(op_id) {
                        Ok(prog) => {
                            shell_println!("Completed: {}/{} items, {} bytes, {} skipped, {} failed.",
                                prog.processed_items, prog.total_items,
                                prog.transferred_bytes, prog.skipped, prog.failed);
                        }
                        Err(e) => shell_println!("Execution error: {:?}", e),
                    }
                }
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "delete" | "del" => {
            if parts.len() < 2 {
                shell_println!("Usage: fileops delete <path...>");
                return;
            }
            let mut sources = Vec::new();
            for &p in parts.iter().skip(1) {
                sources.push(resolve_path(p));
            }
            let src_refs: Vec<&str> = sources.iter().map(|s| s.as_str()).collect();

            match fileops::create(fileops::OpKind::Delete, &src_refs, "", fileops::ConflictPolicy::Skip) {
                Ok(op_id) => {
                    shell_println!("Created delete operation {}.", op_id);
                    match fileops::execute(op_id) {
                        Ok(prog) => {
                            shell_println!("Completed: {}/{} items, {} skipped, {} failed.",
                                prog.processed_items, prog.total_items,
                                prog.skipped, prog.failed);
                        }
                        Err(e) => shell_println!("Execution error: {:?}", e),
                    }
                }
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "list" | "ls" => {
            let ops = fileops::list_ops();
            if ops.is_empty() {
                shell_println!("No file operations.");
            } else {
                shell_println!("{:6} {:6} {:10} {}", "ID", "KIND", "STATE", "LABEL");
                for (id, kind, state, label) in &ops {
                    let state_str = match state {
                        fileops::OpState::Queued => "queued",
                        fileops::OpState::Running => "running",
                        fileops::OpState::Paused => "paused",
                        fileops::OpState::Completed => "done",
                        fileops::OpState::Cancelled => "cancelled",
                        fileops::OpState::Undoing => "undoing",
                    };
                    shell_println!("{:6} {:6} {:10} {}", id, kind.label(), state_str, label);
                }
            }
        }
        "cancel" => {
            if let Some(id_str) = parts.get(1) {
                if let Ok(id) = id_str.parse::<u64>() {
                    match fileops::cancel(id) {
                        Ok(()) => shell_println!("Operation {} cancelled.", id),
                        Err(e) => shell_println!("Error: {:?}", e),
                    }
                } else {
                    shell_println!("Invalid operation ID.");
                }
            } else {
                shell_println!("Usage: fileops cancel <op_id>");
            }
        }
        "undo" => {
            if let Some(id_str) = parts.get(1) {
                if let Ok(id) = id_str.parse::<u64>() {
                    match fileops::undo(id) {
                        Ok((undone, failed)) => {
                            shell_println!("Undo: {} undone, {} could not be undone.", undone, failed);
                        }
                        Err(e) => shell_println!("Error: {:?}", e),
                    }
                } else {
                    shell_println!("Invalid operation ID.");
                }
            } else {
                shell_println!("Usage: fileops undo <op_id>");
            }
        }
        "cleanup" => {
            let removed = fileops::cleanup();
            shell_println!("Removed {} completed/cancelled operations.", removed);
        }
        "stats" | "" => {
            let (total, completed, cancelled, bytes_moved) = fileops::stats();
            shell_println!("File operations statistics:");
            shell_println!("  Total ops:   {}", total);
            shell_println!("  Completed:   {}", completed);
            shell_println!("  Cancelled:   {}", cancelled);
            shell_println!("  Bytes moved: {}", bytes_moved);
        }
        "reset" => {
            fileops::reset_stats();
            fileops::clear();
            shell_println!("File operations reset.");
        }
        _ => {
            shell_println!("Usage: fileops <command>");
            shell_println!("  copy <src...> <dest> [flags]  Copy files");
            shell_println!("  move <src...> <dest> [flags]  Move files");
            shell_println!("  delete <path...>              Delete files");
            shell_println!("  list|ls                       List operations");
            shell_println!("  cancel <id>                   Cancel operation");
            shell_println!("  undo <id>                     Undo operation");
            shell_println!("  cleanup                       Remove finished ops");
            shell_println!("  stats                         Show statistics (default)");
            shell_println!("  reset                         Reset all");
            shell_println!("");
            shell_println!("Flags: --overwrite|-o  --skip|-s  --rename|-r  --merge|-m");
        }
    }
}

/// `fileselect` / `fsel` — file selection management.
fn cmd_fileselect(args: &str) {
    let parts: Vec<&str> = args.split_whitespace().collect();
    let sub = parts.first().copied().unwrap_or("");
    match sub {
        "create" => {
            let dir = if parts.len() > 1 {
                resolve_path(parts[1])
            } else {
                get_cwd()
            };
            match crate::fs::fileselect::create(&dir) {
                Ok(id) => shell_println!("Created selection set #{} for {}", id, dir),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "destroy" => {
            if let Some(id) = parts.get(1).and_then(|s| s.parse::<u64>().ok()) {
                match crate::fs::fileselect::destroy(id) {
                    Ok(()) => shell_println!("Destroyed selection set #{}", id),
                    Err(e) => shell_println!("Error: {:?}", e),
                }
            } else {
                shell_println!("Usage: fileselect destroy <set-id>");
            }
        }
        "select" => {
            // fileselect select <set-id> <path>
            if let (Some(id), Some(path)) = (
                parts.get(1).and_then(|s| s.parse::<u64>().ok()),
                parts.get(2),
            ) {
                let resolved = resolve_path(path);
                match crate::fs::fileselect::select_single(id, &resolved, 0) {
                    Ok(()) => shell_println!("Selected: {}", resolved),
                    Err(e) => shell_println!("Error: {:?}", e),
                }
            } else {
                shell_println!("Usage: fileselect select <set-id> <path>");
            }
        }
        "toggle" => {
            if let (Some(id), Some(path)) = (
                parts.get(1).and_then(|s| s.parse::<u64>().ok()),
                parts.get(2),
            ) {
                let resolved = resolve_path(path);
                match crate::fs::fileselect::select_toggle(id, &resolved, 0) {
                    Ok(()) => {
                        let sel = crate::fs::fileselect::is_selected(id, &resolved).unwrap_or(false);
                        shell_println!("{}: {}", resolved, if sel { "selected" } else { "deselected" });
                    }
                    Err(e) => shell_println!("Error: {:?}", e),
                }
            } else {
                shell_println!("Usage: fileselect toggle <set-id> <path>");
            }
        }
        "clear" => {
            if let Some(id) = parts.get(1).and_then(|s| s.parse::<u64>().ok()) {
                match crate::fs::fileselect::clear(id) {
                    Ok(()) => shell_println!("Selection cleared"),
                    Err(e) => shell_println!("Error: {:?}", e),
                }
            } else {
                shell_println!("Usage: fileselect clear <set-id>");
            }
        }
        "list" => {
            if let Some(id) = parts.get(1).and_then(|s| s.parse::<u64>().ok()) {
                match crate::fs::fileselect::selected_paths(id) {
                    Ok(paths) => {
                        if paths.is_empty() {
                            shell_println!("(no items selected)");
                        } else {
                            for p in &paths {
                                shell_println!("  {}", p);
                            }
                        }
                    }
                    Err(e) => shell_println!("Error: {:?}", e),
                }
            } else {
                // List all sets.
                let sets = crate::fs::fileselect::list_sets();
                if sets.is_empty() {
                    shell_println!("(no active selection sets)");
                } else {
                    shell_println!("{:<6} {:<30} {}", "ID", "Directory", "Items");
                    shell_println!("{}", "-".repeat(50));
                    for (id, dir, count) in &sets {
                        shell_println!("#{:<5} {:<30} {}", id, dir, count);
                    }
                }
            }
        }
        "summary" => {
            if let Some(id) = parts.get(1).and_then(|s| s.parse::<u64>().ok()) {
                match crate::fs::fileselect::summary(id) {
                    Ok(s) => {
                        shell_println!("Selection #{}: {} items", id, s.count);
                        shell_println!("  Files: {}, Dirs: {}", s.files, s.dirs);
                        shell_println!("  Total size: {}", s.size_display);
                    }
                    Err(e) => shell_println!("Error: {:?}", e),
                }
            } else {
                shell_println!("Usage: fileselect summary <set-id>");
            }
        }
        "pattern" => {
            // fileselect pattern <set-id> <glob>
            if let (Some(id), Some(pat)) = (
                parts.get(1).and_then(|s| s.parse::<u64>().ok()),
                parts.get(2).copied(),
            ) {
                // Get listing from the set's directory.
                let sets = crate::fs::fileselect::list_sets();
                let dir = sets.iter()
                    .find(|(sid, _, _)| *sid == id)
                    .map(|(_, d, _)| d.clone());
                if let Some(dir) = dir {
                    if let Ok(entries) = crate::fs::vfs::Vfs::readdir(&dir) {
                        let paths: Vec<String> = entries.iter().map(|e| {
                            if dir == "/" {
                                alloc::format!("/{}", e.name)
                            } else {
                                alloc::format!("{}/{}", dir, e.name)
                            }
                        }).collect();
                        let refs: Vec<&str> = paths.iter().map(|s| s.as_str()).collect();
                        match crate::fs::fileselect::select_pattern(id, &refs, pat) {
                            Ok(()) => {
                                let count = crate::fs::fileselect::count(id).unwrap_or(0);
                                shell_println!("Pattern '{}' applied; {} items selected", pat, count);
                            }
                            Err(e) => shell_println!("Error: {:?}", e),
                        }
                    } else {
                        shell_println!("Cannot read directory for set #{}", id);
                    }
                } else {
                    shell_println!("Set #{} not found", id);
                }
            } else {
                shell_println!("Usage: fileselect pattern <set-id> <glob-pattern>");
            }
        }
        "tree" => {
            // Build checkbox tree for a directory.
            let dir = if parts.len() > 1 {
                resolve_path(parts[1])
            } else {
                get_cwd()
            };
            match crate::fs::fileselect::build_check_tree(&dir) {
                Ok(tree) => {
                    shell_println!("[{}] {} ({})", check_char(tree.state), tree.name,
                                   if tree.is_dir { "dir" } else { "file" });
                    for child in &tree.children {
                        shell_println!("  [{}] {} ({})", check_char(child.state), child.name,
                                       if child.is_dir { "dir" } else { "file" });
                    }
                }
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "stats" => {
            let (selects, deselects, active) = crate::fs::fileselect::stats();
            shell_println!("Active sets:  {}", active);
            shell_println!("Select ops:   {}", selects);
            shell_println!("Deselect ops: {}", deselects);
        }
        "reset" => {
            crate::fs::fileselect::reset_stats();
            shell_println!("Selection stats reset");
        }
        _ => {
            shell_println!("Usage: fileselect <subcommand>");
            shell_println!("  create [dir]        Create selection set");
            shell_println!("  destroy <id>        Destroy selection set");
            shell_println!("  select <id> <path>  Select single item");
            shell_println!("  toggle <id> <path>  Toggle item selection");
            shell_println!("  clear <id>          Clear all selections");
            shell_println!("  list [id]           List sets or items");
            shell_println!("  summary <id>        Selection summary");
            shell_println!("  pattern <id> <glob> Select by pattern");
            shell_println!("  tree [dir]          Show checkbox tree");
            shell_println!("  stats               Show statistics");
            shell_println!("  reset               Reset statistics");
        }
    }
}

/// Helper for checkbox tree display.
fn check_char(state: crate::fs::fileselect::CheckState) -> char {
    match state {
        crate::fs::fileselect::CheckState::Checked => 'X',
        crate::fs::fileselect::CheckState::Unchecked => ' ',
        crate::fs::fileselect::CheckState::Partial => '-',
    }
}

/// `filetype` / `ftype` — file type and icon registry.
fn cmd_filetype(args: &str) {
    let parts: Vec<&str> = args.split_whitespace().collect();
    let sub = parts.first().copied().unwrap_or("");
    match sub {
        "init" => {
            crate::fs::filetype::init();
            let (_, _, types, _) = crate::fs::filetype::stats();
            shell_println!("File type registry initialized ({} types)", types);
        }
        "list" => {
            let types = crate::fs::filetype::list_types();
            if types.is_empty() {
                shell_println!("(no file types registered — run 'filetype init')");
            } else {
                shell_println!("{:<25} {:<20} {:<15} {}", "MIME", "Description", "Icon", "Exts");
                shell_println!("{}", "-".repeat(70));
                for (mime, desc, icon, ext_count) in &types {
                    shell_println!("{:<25} {:<20} {:<15} {}", mime, desc, icon, ext_count);
                }
            }
        }
        "icon" => {
            // filetype icon <path>
            if let Some(path) = parts.get(1) {
                let resolved = resolve_path(path);
                let icon = crate::fs::filetype::icon_for_file(&resolved);
                shell_println!("File: {}", resolved);
                shell_println!("  MIME:        {}", icon.mime);
                shell_println!("  Description: {}", icon.description);
                shell_println!("  Icon:        {}", icon.icon);
                shell_println!("  Category:    {:?}", icon.category);
                shell_println!("  Source:      {:?}", icon.source);
            } else {
                shell_println!("Usage: filetype icon <path>");
            }
        }
        "register" => {
            // filetype register <mime> <description> <icon> [ext1 ext2...]
            if parts.len() < 4 {
                shell_println!("Usage: filetype register <mime> <desc> <icon> [ext...]");
                return;
            }
            let mime = parts[1];
            let desc = parts[2];
            let icon = parts[3];
            let exts: Vec<&str> = parts[4..].to_vec();
            match crate::fs::filetype::register_type(mime, desc, icon, &exts) {
                Ok(()) => shell_println!("Registered: {} ({})", mime, desc),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "ext" => {
            // filetype ext <extension>
            if let Some(ext) = parts.get(1) {
                match crate::fs::filetype::mime_for_extension(ext) {
                    Some(mime) => shell_println!(".{} → {}", ext, mime),
                    None => shell_println!("No type registered for .{}", ext),
                }
            } else {
                shell_println!("Usage: filetype ext <extension>");
            }
        }
        "stats" => {
            let (lookups, registers, types, app_icons) = crate::fs::filetype::stats();
            shell_println!("Types:       {}", types);
            shell_println!("App icons:   {}", app_icons);
            shell_println!("Lookups:     {}", lookups);
            shell_println!("Registers:   {}", registers);
        }
        "reset" => {
            crate::fs::filetype::reset_stats();
            shell_println!("File type stats reset");
        }
        _ => {
            shell_println!("Usage: filetype <subcommand>");
            shell_println!("  init                Initialize defaults");
            shell_println!("  list                List registered types");
            shell_println!("  icon <path>         Resolve icon for file");
            shell_println!("  register <m> <d> <i> [ext...]  Register type");
            shell_println!("  ext <extension>     Lookup MIME by extension");
            shell_println!("  stats               Show statistics");
            shell_println!("  reset               Reset statistics");
        }
    }
}

/// `openw` — Open With dialog infrastructure.
fn cmd_openwith(args: &str) {
    let parts: Vec<&str> = args.split_whitespace().collect();
    let sub = parts.first().copied().unwrap_or("");
    match sub {
        "choices" => {
            // openw choices <file>
            if let Some(path) = parts.get(1) {
                let resolved = resolve_path(path);
                match crate::fs::openwith::build_choices(&resolved) {
                    Ok(choices) => {
                        if choices.is_empty() {
                            shell_println!("No applications found for {}", resolved);
                        } else {
                            shell_println!("Open With choices for {}:", resolved);
                            shell_println!("{:<25} {:<15} {:<8} {}", "Application", "Reason", "Default", "Uses");
                            shell_println!("{}", "-".repeat(60));
                            for c in &choices {
                                let reason = match c.reason {
                                    crate::fs::openwith::ChoiceReason::RegisteredHandler => "registered",
                                    crate::fs::openwith::ChoiceReason::RecentlyUsed => "recent",
                                    crate::fs::openwith::ChoiceReason::InstalledApp => "installed",
                                };
                                let def = if c.is_default { "*" } else { "" };
                                shell_println!("{:<25} {:<15} {:<8} {}", c.app_name, reason, def, c.use_count);
                            }
                        }
                    }
                    Err(e) => shell_println!("Error: {:?}", e),
                }
            } else {
                shell_println!("Usage: openw choices <file>");
            }
        }
        "open" => {
            // openw open <file> <app-path> [--default]
            if parts.len() < 3 {
                shell_println!("Usage: openw open <file> <app-path> [--default]");
                return;
            }
            let file = resolve_path(parts[1]);
            let app_path = parts[2];
            let set_default = parts.contains(&"--default");
            let app_name = app_path.rsplit('/').next().unwrap_or(app_path);
            match crate::fs::openwith::open_with(&file, app_path, app_name, set_default) {
                Ok(result) => {
                    shell_println!("Opened {} with {}", result.file_path, result.app_path);
                    if result.default_changed {
                        shell_println!("  (set as default for this type)");
                    }
                }
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "default" => {
            // openw default <file>
            if let Some(path) = parts.get(1) {
                let resolved = resolve_path(path);
                match crate::fs::openwith::current_default(&resolved) {
                    Some(name) => shell_println!("Default app for {}: {}", resolved, name),
                    None => shell_println!("No default app for {}", resolved),
                }
            } else {
                shell_println!("Usage: openw default <file>");
            }
        }
        "recent" => {
            // openw recent <mime-type>
            if let Some(mime) = parts.get(1) {
                let entries = crate::fs::openwith::recent_for_type(mime);
                if entries.is_empty() {
                    shell_println!("No recent choices for {}", mime);
                } else {
                    shell_println!("Recent apps for {}:", mime);
                    for (path, name, count) in &entries {
                        shell_println!("  {} ({}) — {} uses", name, path, count);
                    }
                }
            } else {
                shell_println!("Usage: openw recent <mime-type>");
            }
        }
        "apps" => {
            let apps = crate::fs::openwith::list_apps();
            if apps.is_empty() {
                shell_println!("(no registered applications)");
            } else {
                shell_println!("{:<30} {}", "Path", "Name");
                shell_println!("{}", "-".repeat(50));
                for (path, name) in &apps {
                    shell_println!("{:<30} {}", path, name);
                }
            }
        }
        "register" => {
            // openw register <app-path> <app-name>
            if parts.len() < 3 {
                shell_println!("Usage: openw register <app-path> <app-name>");
                return;
            }
            let app_path = parts[1];
            let app_name = parts[2..].join(" ");
            match crate::fs::openwith::register_app(app_path, &app_name) {
                Ok(()) => shell_println!("Registered: {} ({})", app_name, app_path),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "clear" => {
            if let Some(mime) = parts.get(1) {
                crate::fs::openwith::clear_recent_for_type(mime);
                shell_println!("Cleared recent choices for {}", mime);
            } else {
                crate::fs::openwith::clear_recent();
                shell_println!("Cleared all recent choices");
            }
        }
        "stats" => {
            let (opens, defaults, recent, apps) = crate::fs::openwith::stats();
            shell_println!("Opens:           {}", opens);
            shell_println!("Default changes: {}", defaults);
            shell_println!("Recent entries:  {}", recent);
            shell_println!("Known apps:      {}", apps);
        }
        "reset" => {
            crate::fs::openwith::reset_stats();
            shell_println!("Open With stats reset");
        }
        _ => {
            shell_println!("Usage: openw <subcommand>");
            shell_println!("  choices <file>       Show app choices for file");
            shell_println!("  open <file> <app>    Open file with app [--default]");
            shell_println!("  default <file>       Show default app for file");
            shell_println!("  recent <mime>        Show recent choices for type");
            shell_println!("  apps                 List known applications");
            shell_println!("  register <path> <name>  Register an application");
            shell_println!("  clear [mime]         Clear recent choices");
            shell_println!("  stats                Show statistics");
            shell_println!("  reset                Reset statistics");
        }
    }
}

/// `sidebar` — file explorer navigation sidebar.
fn cmd_sidebar(args: &str) {
    let parts: Vec<&str> = args.split_whitespace().collect();
    let sub = parts.first().copied().unwrap_or("");
    match sub {
        "show" | "" => {
            let sidebar = crate::fs::sidebar::build();
            for section in &sidebar.sections {
                let marker = if section.expanded { "v" } else { ">" };
                shell_println!("[{}] {} ({} items)", marker, section.label, section.items.len());
                if section.expanded {
                    for item in &section.items {
                        let info = if item.usage_info.is_empty() {
                            String::new()
                        } else {
                            alloc::format!("  ({})", item.usage_info)
                        };
                        shell_println!("    {} → {}{}", item.label, item.path, info);
                    }
                }
            }
        }
        "toggle" => {
            if let Some(section) = parts.get(1) {
                let kind = match *section {
                    "quickaccess" | "qa" => Some(crate::fs::sidebar::SectionKind::QuickAccess),
                    "thispc" | "pc" => Some(crate::fs::sidebar::SectionKind::ThisPC),
                    "network" | "net" => Some(crate::fs::sidebar::SectionKind::Network),
                    "recent" => Some(crate::fs::sidebar::SectionKind::Recent),
                    "tags" => Some(crate::fs::sidebar::SectionKind::Tags),
                    _ => None,
                };
                if let Some(kind) = kind {
                    let expanded = crate::fs::sidebar::toggle_expanded(kind);
                    shell_println!("{}: {}", section, if expanded { "expanded" } else { "collapsed" });
                } else {
                    shell_println!("Unknown section: {}. Use: quickaccess, thispc, network, recent, tags", section);
                }
            } else {
                shell_println!("Usage: sidebar toggle <section>");
            }
        }
        "hide" => {
            if let Some(section) = parts.get(1) {
                let kind = parse_section_kind(section);
                if let Some(kind) = kind {
                    crate::fs::sidebar::hide_section(kind);
                    shell_println!("{} hidden", section);
                } else {
                    shell_println!("Unknown section: {}", section);
                }
            } else {
                shell_println!("Usage: sidebar hide <section>");
            }
        }
        "unhide" => {
            if let Some(section) = parts.get(1) {
                let kind = parse_section_kind(section);
                if let Some(kind) = kind {
                    crate::fs::sidebar::show_section(kind);
                    shell_println!("{} shown", section);
                } else {
                    shell_println!("Unknown section: {}", section);
                }
            } else {
                shell_println!("Usage: sidebar unhide <section>");
            }
        }
        "pin" => {
            // sidebar pin <path> [label]
            if let Some(path) = parts.get(1) {
                let resolved = resolve_path(path);
                let label = if parts.len() > 2 {
                    parts[2..].join(" ")
                } else {
                    String::from(resolved.rsplit('/').next().unwrap_or(&resolved))
                };
                match crate::fs::sidebar::pin_to_quick_access(&resolved, &label) {
                    Ok(()) => shell_println!("Pinned: {} ({})", label, resolved),
                    Err(e) => shell_println!("Error: {:?}", e),
                }
            } else {
                shell_println!("Usage: sidebar pin <path> [label]");
            }
        }
        "unpin" => {
            if let Some(path) = parts.get(1) {
                let resolved = resolve_path(path);
                match crate::fs::sidebar::unpin_from_quick_access(&resolved) {
                    Ok(()) => shell_println!("Unpinned: {}", resolved),
                    Err(e) => shell_println!("Error: {:?}", e),
                }
            } else {
                shell_println!("Usage: sidebar unpin <path>");
            }
        }
        "stats" => {
            let (builds, sections, hidden) = crate::fs::sidebar::stats();
            shell_println!("Builds:   {}", builds);
            shell_println!("Sections: {}", sections);
            shell_println!("Hidden:   {}", hidden);
        }
        "reset" => {
            crate::fs::sidebar::reset_stats();
            shell_println!("Sidebar stats reset");
        }
        _ => {
            shell_println!("Usage: sidebar <subcommand>");
            shell_println!("  show                 Show sidebar tree");
            shell_println!("  toggle <section>     Toggle expand/collapse");
            shell_println!("  hide <section>       Hide a section");
            shell_println!("  unhide <section>     Show a section");
            shell_println!("  pin <path> [label]   Pin to Quick Access");
            shell_println!("  unpin <path>         Unpin from Quick Access");
            shell_println!("  stats                Show statistics");
            shell_println!("  reset                Reset statistics");
            shell_println!("Sections: quickaccess, thispc, network, recent, tags");
        }
    }
}

fn parse_section_kind(name: &str) -> Option<crate::fs::sidebar::SectionKind> {
    match name {
        "quickaccess" | "qa" => Some(crate::fs::sidebar::SectionKind::QuickAccess),
        "thispc" | "pc" => Some(crate::fs::sidebar::SectionKind::ThisPC),
        "network" | "net" => Some(crate::fs::sidebar::SectionKind::Network),
        "recent" => Some(crate::fs::sidebar::SectionKind::Recent),
        "tags" => Some(crate::fs::sidebar::SectionKind::Tags),
        _ => None,
    }
}

/// `statusbar` — file explorer status bar content.
fn cmd_statusbar(args: &str) {
    let parts: Vec<&str> = args.split_whitespace().collect();
    let sub = parts.first().copied().unwrap_or("");
    match sub {
        "show" | "" => {
            let dir = parts.get(1).map(|p| resolve_path(p)).unwrap_or_else(get_cwd);
            let status = crate::fs::statusbar::generate_for_dir(&dir, 0, 0);
            shell_println!("Left:   {}", status.left);
            if !status.center.is_empty() {
                shell_println!("Center: {}", status.center);
            }
            if !status.right.is_empty() {
                shell_println!("Right:  {}", status.right);
            }
        }
        "disk" => {
            let dir = parts.get(1).map(|p| resolve_path(p)).unwrap_or_else(get_cwd);
            match crate::fs::statusbar::disk_info(&dir) {
                Some(info) => {
                    shell_println!("Filesystem: {}", info.fs_type);
                    shell_println!("Free:  {} bytes", info.free_bytes);
                    shell_println!("Total: {} bytes", info.total_bytes);
                }
                None => shell_println!("No disk info available for {}", dir),
            }
        }
        "stats" => {
            let gen_count = crate::fs::statusbar::stats();
            shell_println!("Generates: {}", gen_count);
        }
        "reset" => {
            crate::fs::statusbar::reset_stats();
            shell_println!("Status bar stats reset");
        }
        _ => {
            shell_println!("Usage: statusbar <subcommand>");
            shell_println!("  show [dir]    Show status bar content");
            shell_println!("  disk [dir]    Show disk info");
            shell_println!("  stats         Show statistics");
            shell_println!("  reset         Reset statistics");
        }
    }
}

/// `toolbar` — file explorer toolbar / command bar.
fn cmd_toolbar(args: &str) {
    use crate::fs::toolbar;
    let parts: Vec<&str> = args.split_whitespace().collect();
    let sub = parts.first().copied().unwrap_or("");
    match sub {
        "show" | "" => {
            // Build toolbar with optional flags.
            let mut ctx = toolbar::ToolbarContext::default();
            for &flag in parts.iter().skip(1) {
                match flag {
                    "--selected" | "-s" => { ctx.has_selection = true; ctx.selection_count = 1; }
                    "--multi" | "-m" => { ctx.has_selection = true; ctx.selection_count = 3; }
                    "--trash" | "-t" => ctx.is_trash = true,
                    "--readonly" | "-r" => ctx.read_only = true,
                    "--paste" | "-p" => ctx.can_paste = true,
                    "--back" => ctx.can_go_back = true,
                    "--forward" => ctx.can_go_forward = true,
                    "--search" => ctx.is_searching = true,
                    "--hidden" => ctx.show_hidden = true,
                    _ => {}
                }
            }
            let layout = toolbar::build(&ctx);
            shell_println!("Toolbar ({} buttons):", layout.buttons.len());
            shell_println!("{:16} {:12} {:8} {:8} {}", "ACTION", "SECTION", "ENABLED", "TOGGLE", "LABEL");
            for btn in &layout.buttons {
                let sec = match btn.section {
                    toolbar::ToolbarSection::Navigation => "Navigation",
                    toolbar::ToolbarSection::Actions => "Actions",
                    toolbar::ToolbarSection::View => "View",
                    toolbar::ToolbarSection::New => "New",
                    toolbar::ToolbarSection::Search => "Search",
                };
                let en = if btn.enabled { "yes" } else { "no" };
                let tg = if btn.toggled { "ON" } else { "-" };
                shell_println!("{:16} {:12} {:8} {:8} {}", btn.action, sec, en, tg, btn.label);
                if btn.has_dropdown {
                    for item in &btn.dropdown {
                        let chk = if item.checked { "*" } else { " " };
                        shell_println!("  {} [{}] {}", chk, item.action, item.label);
                    }
                }
            }
        }
        "section" => {
            let sec_name = parts.get(1).copied().unwrap_or("");
            let section = match sec_name {
                "nav" | "navigation" => Some(toolbar::ToolbarSection::Navigation),
                "actions" | "act" => Some(toolbar::ToolbarSection::Actions),
                "view" => Some(toolbar::ToolbarSection::View),
                "new" => Some(toolbar::ToolbarSection::New),
                "search" => Some(toolbar::ToolbarSection::Search),
                _ => None,
            };
            match section {
                Some(sec) => {
                    let ctx = toolbar::ToolbarContext::default();
                    let layout = toolbar::build(&ctx);
                    let btns = toolbar::section_buttons(&layout, sec);
                    shell_println!("{} buttons in {:?} section:", btns.len(), sec);
                    for btn in &btns {
                        let en = if btn.enabled { "enabled" } else { "disabled" };
                        shell_println!("  {} ({}){}", btn.action, en,
                            if btn.label.is_empty() { String::new() } else { alloc::format!(" - {}", btn.label) });
                    }
                }
                None => {
                    shell_println!("Usage: toolbar section <nav|actions|view|new|search>");
                }
            }
        }
        "check" => {
            let action = parts.get(1).copied().unwrap_or("");
            if action.is_empty() {
                shell_println!("Usage: toolbar check <action>");
                return;
            }
            let ctx = toolbar::ToolbarContext {
                has_selection: true,
                selection_count: 1,
                can_paste: true,
                can_go_back: true,
                can_go_forward: true,
                ..Default::default()
            };
            let layout = toolbar::build(&ctx);
            let enabled = toolbar::is_action_enabled(&layout, action);
            shell_println!("Action '{}': {}", action, if enabled { "enabled" } else { "disabled" });
        }
        "trash" => {
            let ctx = toolbar::ToolbarContext {
                has_selection: true,
                selection_count: 1,
                is_trash: true,
                ..Default::default()
            };
            let layout = toolbar::build(&ctx);
            shell_println!("Trash toolbar ({} buttons):", layout.buttons.len());
            for btn in &layout.buttons {
                if btn.section == toolbar::ToolbarSection::Actions {
                    let en = if btn.enabled { "enabled" } else { "disabled" };
                    shell_println!("  {} - {} ({})", btn.action, btn.label, en);
                }
            }
        }
        "test" => {
            match toolbar::self_test() {
                Ok(()) => shell_println!("All toolbar self-tests passed"),
                Err(e) => shell_println!("Toolbar self-test failed: {:?}", e),
            }
        }
        "stats" => {
            let (builds, actions) = toolbar::stats();
            shell_println!("Builds:  {}", builds);
            shell_println!("Actions: {}", actions);
        }
        "reset" => {
            toolbar::reset_stats();
            shell_println!("Toolbar stats reset");
        }
        _ => {
            shell_println!("Usage: toolbar <subcommand>");
            shell_println!("  show [flags]        Show toolbar layout");
            shell_println!("    -s/--selected     Simulate item selected");
            shell_println!("    -m/--multi        Simulate multi-selection");
            shell_println!("    -t/--trash        Simulate trash directory");
            shell_println!("    -r/--readonly     Simulate read-only dir");
            shell_println!("    -p/--paste        Simulate clipboard content");
            shell_println!("    --back/--forward  Enable nav buttons");
            shell_println!("    --search          Simulate search active");
            shell_println!("    --hidden          Simulate hidden shown");
            shell_println!("  section <name>      Show section buttons");
            shell_println!("  check <action>      Check if action enabled");
            shell_println!("  trash               Show trash-mode toolbar");
            shell_println!("  test                Run self-tests");
            shell_println!("  stats               Show statistics");
            shell_println!("  reset               Reset statistics");
        }
    }
}

/// `queryable` / `qattr` — queryable file metadata (BFS-inspired).
fn cmd_queryable(args: &str) {
    use crate::fs::queryable;
    let parts: Vec<&str> = args.split_whitespace().collect();
    let sub = parts.first().copied().unwrap_or("");
    match sub {
        "set" => {
            // qattr set <path> <name> <type> <value>
            let path_arg = parts.get(1).copied().unwrap_or("");
            let attr_name = parts.get(2).copied().unwrap_or("");
            let type_name = parts.get(3).copied().unwrap_or("text");
            let val_str = parts.get(4).copied().unwrap_or("");
            if path_arg.is_empty() || attr_name.is_empty() || val_str.is_empty() {
                shell_println!("Usage: qattr set <path> <name> <text|int|bool> <value>");
                return;
            }
            let path = resolve_path(path_arg);
            let value = match type_name {
                "int" | "i" => {
                    match val_str.parse::<i64>() {
                        Ok(n) => queryable::AttrValue::Int(n),
                        Err(_) => { shell_println!("Invalid integer: {}", val_str); return; }
                    }
                }
                "bool" | "b" => {
                    match val_str {
                        "true" | "1" | "yes" => queryable::AttrValue::Bool(true),
                        "false" | "0" | "no" => queryable::AttrValue::Bool(false),
                        _ => { shell_println!("Invalid bool: {}", val_str); return; }
                    }
                }
                _ => queryable::AttrValue::Text(String::from(val_str)),
            };
            match queryable::set_attr(&path, attr_name, value) {
                Ok(()) => shell_println!("Set {}={} on {}", attr_name, val_str, path),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "get" => {
            let path_arg = parts.get(1).copied().unwrap_or("");
            let attr_name = parts.get(2).copied().unwrap_or("");
            if path_arg.is_empty() || attr_name.is_empty() {
                shell_println!("Usage: qattr get <path> <name>");
                return;
            }
            let path = resolve_path(path_arg);
            match queryable::get_attr(&path, attr_name) {
                Ok(val) => {
                    let display = match &val {
                        queryable::AttrValue::Text(s) => alloc::format!("\"{}\"", s),
                        queryable::AttrValue::Int(n) => alloc::format!("{}", n),
                        queryable::AttrValue::Bool(b) => alloc::format!("{}", b),
                        queryable::AttrValue::Bytes(b) => alloc::format!("[{} bytes]", b.len()),
                    };
                    shell_println!("{}={} ({})", attr_name, display, val.type_name());
                }
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "rm" | "remove" => {
            let path_arg = parts.get(1).copied().unwrap_or("");
            let attr_name = parts.get(2).copied().unwrap_or("");
            if path_arg.is_empty() || attr_name.is_empty() {
                shell_println!("Usage: qattr rm <path> <name>");
                return;
            }
            let path = resolve_path(path_arg);
            match queryable::remove_attr(&path, attr_name) {
                Ok(()) => shell_println!("Removed {} from {}", attr_name, path),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "list" | "ls" => {
            let path_arg = parts.get(1).copied().unwrap_or("");
            if path_arg.is_empty() {
                shell_println!("Usage: qattr list <path>");
                return;
            }
            let path = resolve_path(path_arg);
            match queryable::list_attrs(&path) {
                Ok(attrs) => {
                    if attrs.is_empty() {
                        shell_println!("No attributes on {}", path);
                    } else {
                        shell_println!("{} attributes on {}:", attrs.len(), path);
                        for (name, val) in &attrs {
                            let display = match val {
                                queryable::AttrValue::Text(s) => alloc::format!("\"{}\"", s),
                                queryable::AttrValue::Int(n) => alloc::format!("{}", n),
                                queryable::AttrValue::Bool(b) => alloc::format!("{}", b),
                                queryable::AttrValue::Bytes(b) => alloc::format!("[{} bytes]", b.len()),
                            };
                            shell_println!("  {} = {} ({})", name, display, val.type_name());
                        }
                    }
                }
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "clear" => {
            let path_arg = parts.get(1).copied().unwrap_or("");
            if path_arg.is_empty() {
                shell_println!("Usage: qattr clear <path>");
                return;
            }
            let path = resolve_path(path_arg);
            match queryable::clear_attrs(&path) {
                Ok(n) => shell_println!("Cleared {} attributes from {}", n, path),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "query" | "q" => {
            // qattr query <attr> <op> <value> [root]
            let attr_name = parts.get(1).copied().unwrap_or("");
            let op_str = parts.get(2).copied().unwrap_or("=");
            let val_str = parts.get(3).copied().unwrap_or("");
            let root = parts.get(4).map(|p| resolve_path(p));
            if attr_name.is_empty() || val_str.is_empty() {
                shell_println!("Usage: qattr query <attr> <op> <value> [root]");
                shell_println!("  ops: = != < <= > >= contains starts-with ends-with");
                return;
            }
            let op = match op_str {
                "=" | "==" | "eq" => queryable::CompareOp::Equal,
                "!=" | "ne" => queryable::CompareOp::NotEqual,
                "<" | "lt" => queryable::CompareOp::LessThan,
                "<=" | "le" => queryable::CompareOp::LessEqual,
                ">" | "gt" => queryable::CompareOp::GreaterThan,
                ">=" | "ge" => queryable::CompareOp::GreaterEqual,
                "contains" | "~" => queryable::CompareOp::Contains,
                "starts-with" | "^" => queryable::CompareOp::StartsWith,
                "ends-with" | "$" => queryable::CompareOp::EndsWith,
                _ => { shell_println!("Unknown operator: {}", op_str); return; }
            };
            // Auto-detect type: try int first, then text.
            let value = if let Ok(n) = val_str.parse::<i64>() {
                queryable::AttrValue::Int(n)
            } else {
                queryable::AttrValue::Text(String::from(val_str))
            };
            let pred = queryable::Predicate {
                attr_name: String::from(attr_name),
                op,
                value,
            };
            let results = queryable::query(
                &[pred],
                queryable::QueryMode::All,
                root.as_deref(),
            );
            if results.is_empty() {
                shell_println!("No matches");
            } else {
                shell_println!("{} results:", results.len());
                for r in &results {
                    let vals: Vec<String> = r.matched_attrs.iter().map(|(k, v)| {
                        let d = match v {
                            queryable::AttrValue::Text(s) => alloc::format!("\"{}\"", s),
                            queryable::AttrValue::Int(n) => alloc::format!("{}", n),
                            queryable::AttrValue::Bool(b) => alloc::format!("{}", b),
                            queryable::AttrValue::Bytes(b) => alloc::format!("[{} bytes]", b.len()),
                        };
                        alloc::format!("{}={}", k, d)
                    }).collect();
                    shell_println!("  {} ({})", r.path, vals.join(", "));
                }
            }
        }
        "index" => {
            let idx_sub = parts.get(1).copied().unwrap_or("");
            match idx_sub {
                "create" => {
                    let attr_name = parts.get(2).copied().unwrap_or("");
                    if attr_name.is_empty() {
                        shell_println!("Usage: qattr index create <attr_name>");
                        return;
                    }
                    match queryable::create_index(attr_name) {
                        Ok(()) => shell_println!("Index created for {}", attr_name),
                        Err(e) => shell_println!("Error: {:?}", e),
                    }
                }
                "drop" => {
                    let attr_name = parts.get(2).copied().unwrap_or("");
                    if attr_name.is_empty() {
                        shell_println!("Usage: qattr index drop <attr_name>");
                        return;
                    }
                    match queryable::drop_index(attr_name) {
                        Ok(()) => shell_println!("Index dropped for {}", attr_name),
                        Err(e) => shell_println!("Error: {:?}", e),
                    }
                }
                "list" | "" => {
                    let indexes = queryable::list_indexes();
                    if indexes.is_empty() {
                        shell_println!("No indexed attributes");
                    } else {
                        shell_println!("{} indexed attributes:", indexes.len());
                        for name in &indexes {
                            let count = queryable::count_with_attr(name);
                            shell_println!("  {} ({} files)", name, count);
                        }
                    }
                }
                _ => shell_println!("Usage: qattr index <create|drop|list> [attr_name]"),
            }
        }
        "schema" => {
            let schema_sub = parts.get(1).copied().unwrap_or("");
            match schema_sub {
                "init" => {
                    match queryable::register_builtins() {
                        Ok(()) => shell_println!("Built-in schemas registered"),
                        Err(e) => shell_println!("Error: {:?}", e),
                    }
                }
                "list" | "" => {
                    let schemas = queryable::list_schemas();
                    if schemas.is_empty() {
                        shell_println!("No schemas registered (use 'qattr schema init')");
                    } else {
                        shell_println!("{} schemas:", schemas.len());
                        shell_println!("{:30} {:8} {:8} {}", "NAME", "TYPE", "INDEXED", "DESCRIPTION");
                        for s in &schemas {
                            let idx = if s.indexed { "yes" } else { "no" };
                            shell_println!("{:30} {:8} {:8} {}", s.name, s.value_type, idx, s.description);
                        }
                    }
                }
                _ => shell_println!("Usage: qattr schema <init|list>"),
            }
        }
        "test" => {
            match queryable::self_test() {
                Ok(()) => shell_println!("All queryable self-tests passed"),
                Err(e) => shell_println!("Queryable self-test failed: {:?}", e),
            }
        }
        "stats" => {
            let (files, total_attrs, sets, gets, queries, indexes) = queryable::stats();
            shell_println!("Files:      {}", files);
            shell_println!("Attributes: {}", total_attrs);
            shell_println!("Indexes:    {}", indexes);
            shell_println!("Set ops:    {}", sets);
            shell_println!("Get ops:    {}", gets);
            shell_println!("Queries:    {}", queries);
        }
        "reset" => {
            queryable::clear_all();
            queryable::reset_stats();
            shell_println!("Queryable store cleared and stats reset");
        }
        _ => {
            shell_println!("Usage: qattr <subcommand>");
            shell_println!("  set <path> <name> [text|int|bool] <value>");
            shell_println!("  get <path> <name>");
            shell_println!("  rm <path> <name>");
            shell_println!("  list <path>             List file attributes");
            shell_println!("  clear <path>            Remove all attributes");
            shell_println!("  query <attr> <op> <val> [root]");
            shell_println!("    ops: = != < <= > >= contains starts-with ends-with");
            shell_println!("  index create|drop|list  Manage attribute indexes");
            shell_println!("  schema init|list        Manage attribute schemas");
            shell_println!("  test                    Run self-tests");
            shell_println!("  stats                   Show statistics");
            shell_println!("  reset                   Clear all data and stats");
        }
    }
}

/// `fcomment` — file comments and annotations.
fn cmd_fcomment(args: &str) {
    use crate::fs::fcomment;
    let parts: Vec<&str> = args.split_whitespace().collect();
    let sub = parts.first().copied().unwrap_or("");
    match sub {
        "set" => {
            // fcomment set <path> <comment text...>
            let path_arg = parts.get(1).copied().unwrap_or("");
            if path_arg.is_empty() || parts.len() < 3 {
                shell_println!("Usage: fcomment set <path> <comment text...>");
                return;
            }
            let path = resolve_path(path_arg);
            // Join remaining parts as comment text.
            let comment: String = parts[2..].iter()
                .enumerate()
                .fold(String::new(), |mut acc, (i, s)| {
                    if i > 0 { acc.push(' '); }
                    acc.push_str(s);
                    acc
                });
            match fcomment::set(&path, &comment) {
                Ok(()) => shell_println!("Comment set on {} ({} bytes)", path, comment.len()),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "get" | "show" => {
            let path_arg = parts.get(1).copied().unwrap_or("");
            if path_arg.is_empty() {
                shell_println!("Usage: fcomment get <path>");
                return;
            }
            let path = resolve_path(path_arg);
            match fcomment::get(&path) {
                Some(comment) => shell_println!("{}", comment),
                None => shell_println!("No comment on {}", path),
            }
        }
        "append" => {
            let path_arg = parts.get(1).copied().unwrap_or("");
            if path_arg.is_empty() || parts.len() < 3 {
                shell_println!("Usage: fcomment append <path> <text...>");
                return;
            }
            let path = resolve_path(path_arg);
            let text: String = parts[2..].iter()
                .enumerate()
                .fold(String::new(), |mut acc, (i, s)| {
                    if i > 0 { acc.push(' '); }
                    acc.push_str(s);
                    acc
                });
            match fcomment::append(&path, &text) {
                Ok(()) => shell_println!("Appended to comment on {}", path),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "rm" | "remove" => {
            let path_arg = parts.get(1).copied().unwrap_or("");
            if path_arg.is_empty() {
                shell_println!("Usage: fcomment rm <path>");
                return;
            }
            let path = resolve_path(path_arg);
            match fcomment::remove(&path) {
                Ok(()) => shell_println!("Comment removed from {}", path),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "search" => {
            let needle = parts.get(1).copied().unwrap_or("");
            let root = parts.get(2).map(|p| resolve_path(p));
            if needle.is_empty() {
                shell_println!("Usage: fcomment search <text> [root]");
                return;
            }
            let results = fcomment::search(needle, root.as_deref());
            if results.is_empty() {
                shell_println!("No matches");
            } else {
                shell_println!("{} results:", results.len());
                for (path, comment) in &results {
                    let preview: String = comment.chars().take(60).collect();
                    let preview = preview.replace('\n', " ");
                    shell_println!("  {} — {}", path, preview);
                }
            }
        }
        "list" | "" => {
            let root = parts.get(1).map(|p| resolve_path(p));
            let all = fcomment::list(root.as_deref());
            if all.is_empty() {
                shell_println!("No commented files");
            } else {
                shell_println!("{} commented files:", all.len());
                for (path, comment) in &all {
                    let preview: String = comment.chars().take(50).collect();
                    let preview = preview.replace('\n', " ");
                    shell_println!("  {:40} {}", path, preview);
                }
            }
        }
        "test" => {
            match fcomment::self_test() {
                Ok(()) => shell_println!("All fcomment self-tests passed"),
                Err(e) => shell_println!("File comment self-test failed: {:?}", e),
            }
        }
        "stats" => {
            let (count, sets, gets, searches) = fcomment::stats();
            shell_println!("Comments:    {}", count);
            shell_println!("Set ops:     {}", sets);
            shell_println!("Get ops:     {}", gets);
            shell_println!("Search ops:  {}", searches);
        }
        "reset" => {
            fcomment::clear_all();
            fcomment::reset_stats();
            shell_println!("File comments cleared and stats reset");
        }
        _ => {
            shell_println!("Usage: fcomment <subcommand>");
            shell_println!("  set <path> <text...>   Set comment on file");
            shell_println!("  get <path>             Show comment");
            shell_println!("  append <path> <text>   Append to comment");
            shell_println!("  rm <path>              Remove comment");
            shell_println!("  search <text> [root]   Search comments");
            shell_println!("  list [root]            List commented files");
            shell_println!("  test                   Run self-tests");
            shell_println!("  stats                  Show statistics");
            shell_println!("  reset                  Clear all data and stats");
        }
    }
}

/// `rundialog` / `rund` — run dialog backend.
fn cmd_rundialog(args: &str) {
    use crate::fs::rundialog;
    let parts: Vec<&str> = args.split_whitespace().collect();
    let sub = parts.first().copied().unwrap_or("");
    match sub {
        "run" => {
            let cmd_text = if parts.len() > 1 {
                parts[1..].join(" ")
            } else {
                shell_println!("Usage: rundialog run <command>");
                return;
            };
            match rundialog::resolve(&cmd_text) {
                Ok(result) => {
                    let src = match result.source {
                        rundialog::CompletionSource::Recent => "recent",
                        rundialog::CompletionSource::Path => "PATH",
                        rundialog::CompletionSource::Alias => "alias",
                        rundialog::CompletionSource::Bookmark => "bookmark",
                    };
                    shell_println!("Resolved: {} (via {})", result.path, src);
                    if !result.args.is_empty() {
                        shell_println!("Args: {:?}", result.args);
                    }
                    rundialog::record(&cmd_text, &result.path);
                    shell_println!("Recorded in history");
                }
                Err(e) => shell_println!("Could not resolve '{}': {:?}", cmd_text, e),
            }
        }
        "complete" | "comp" => {
            let prefix = parts.get(1).copied().unwrap_or("");
            let comps = rundialog::completions(prefix);
            if comps.is_empty() {
                shell_println!("No completions for '{}'", prefix);
            } else {
                shell_println!("{} completions:", comps.len());
                for c in &comps {
                    let src = match c.source {
                        rundialog::CompletionSource::Recent => "recent",
                        rundialog::CompletionSource::Path => "PATH",
                        rundialog::CompletionSource::Alias => "alias",
                        rundialog::CompletionSource::Bookmark => "bookmark",
                    };
                    shell_println!("  {:20} [{:8}] {}", c.text, src, c.description);
                }
            }
        }
        "recent" => {
            let limit = parts.get(1).and_then(|s| s.parse::<usize>().ok()).unwrap_or(20);
            let recent = rundialog::recent(limit);
            if recent.is_empty() {
                shell_println!("No recent commands");
            } else {
                shell_println!("{} recent commands:", recent.len());
                for cmd in &recent {
                    shell_println!("  {:30} x{:<4} {}", cmd.command, cmd.run_count, cmd.resolved_path);
                }
            }
        }
        "alias" => {
            let alias_sub = parts.get(1).copied().unwrap_or("list");
            match alias_sub {
                "add" => {
                    let name = parts.get(2).copied().unwrap_or("");
                    let path = parts.get(3).copied().unwrap_or("");
                    if name.is_empty() || path.is_empty() {
                        shell_println!("Usage: rundialog alias add <name> <path>");
                        return;
                    }
                    match rundialog::register_alias(name, path) {
                        Ok(()) => shell_println!("Alias '{}' → '{}'", name, path),
                        Err(e) => shell_println!("Error: {:?}", e),
                    }
                }
                "rm" => {
                    let name = parts.get(2).copied().unwrap_or("");
                    if name.is_empty() {
                        shell_println!("Usage: rundialog alias rm <name>");
                        return;
                    }
                    match rundialog::remove_alias(name) {
                        Ok(()) => shell_println!("Alias '{}' removed", name),
                        Err(e) => shell_println!("Error: {:?}", e),
                    }
                }
                "list" | "" => {
                    let aliases = rundialog::list_aliases();
                    if aliases.is_empty() {
                        shell_println!("No aliases");
                    } else {
                        shell_println!("{} aliases:", aliases.len());
                        for (name, target) in &aliases {
                            shell_println!("  {:20} → {}", name, target);
                        }
                    }
                }
                _ => shell_println!("Usage: rundialog alias <add|rm|list>"),
            }
        }
        "bookmark" | "bm" => {
            let bm_sub = parts.get(1).copied().unwrap_or("list");
            match bm_sub {
                "add" => {
                    let cmd_text = if parts.len() > 2 {
                        parts[2..].join(" ")
                    } else {
                        shell_println!("Usage: rundialog bookmark add <command>");
                        return;
                    };
                    match rundialog::add_bookmark(&cmd_text) {
                        Ok(()) => shell_println!("Bookmarked: {}", cmd_text),
                        Err(e) => shell_println!("Error: {:?}", e),
                    }
                }
                "rm" => {
                    let cmd_text = if parts.len() > 2 {
                        parts[2..].join(" ")
                    } else {
                        shell_println!("Usage: rundialog bookmark rm <command>");
                        return;
                    };
                    match rundialog::remove_bookmark(&cmd_text) {
                        Ok(()) => shell_println!("Bookmark removed"),
                        Err(e) => shell_println!("Error: {:?}", e),
                    }
                }
                "list" | "" => {
                    let bm = rundialog::list_bookmarks();
                    if bm.is_empty() {
                        shell_println!("No bookmarks");
                    } else {
                        shell_println!("{} bookmarks:", bm.len());
                        for cmd in &bm {
                            shell_println!("  {}", cmd);
                        }
                    }
                }
                _ => shell_println!("Usage: rundialog bookmark <add|rm|list>"),
            }
        }
        "path" => {
            let path_sub = parts.get(1).copied().unwrap_or("show");
            match path_sub {
                "show" | "" => {
                    let dirs = rundialog::get_path();
                    if dirs.is_empty() {
                        shell_println!("No PATH directories set");
                    } else {
                        shell_println!("PATH ({} dirs):", dirs.len());
                        for d in &dirs {
                            shell_println!("  {}", d);
                        }
                    }
                }
                "refresh" => {
                    match rundialog::refresh_path_cache() {
                        Ok(n) => shell_println!("Found {} executables in PATH", n),
                        Err(e) => shell_println!("Error: {:?}", e),
                    }
                }
                "clear" => {
                    rundialog::clear_path_cache();
                    shell_println!("PATH cache cleared");
                }
                _ => shell_println!("Usage: rundialog path <show|refresh|clear>"),
            }
        }
        "init" => {
            match rundialog::init_defaults() {
                Ok(()) => shell_println!("Run dialog defaults initialized"),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "test" => {
            match rundialog::self_test() {
                Ok(()) => shell_println!("All run dialog self-tests passed"),
                Err(e) => shell_println!("Run dialog self-test failed: {:?}", e),
            }
        }
        "stats" => {
            let (recent, aliases, cache, bookmarks, runs, completions) = rundialog::stats();
            shell_println!("Recent:      {}", recent);
            shell_println!("Aliases:     {}", aliases);
            shell_println!("PATH cache:  {}", cache);
            shell_println!("Bookmarks:   {}", bookmarks);
            shell_println!("Run ops:     {}", runs);
            shell_println!("Completions: {}", completions);
        }
        "reset" => {
            rundialog::clear_all();
            rundialog::reset_stats();
            shell_println!("Run dialog cleared and stats reset");
        }
        _ => {
            shell_println!("Usage: rundialog <subcommand>");
            shell_println!("  run <command>          Resolve and record command");
            shell_println!("  complete [prefix]      Get completions");
            shell_println!("  recent [limit]         Show recent commands");
            shell_println!("  alias add|rm|list      Manage aliases");
            shell_println!("  bookmark add|rm|list   Manage bookmarks");
            shell_println!("  path show|refresh|clear  Manage PATH");
            shell_println!("  init                   Initialize defaults");
            shell_println!("  test                   Run self-tests");
            shell_println!("  stats                  Show statistics");
            shell_println!("  reset                  Clear all data and stats");
        }
    }
}

/// `notifcenter` / `notif` — desktop notification center.
fn cmd_notifcenter(args: &str) {
    use crate::fs::notifcenter;
    let parts: Vec<&str> = args.split_whitespace().collect();
    let sub = parts.first().copied().unwrap_or("");
    match sub {
        "send" => {
            let app = parts.get(1).copied().unwrap_or("");
            let title = parts.get(2).copied().unwrap_or("");
            if app.is_empty() || title.is_empty() {
                shell_println!("Usage: notif send <app> <title> [body] [category] [priority]");
                shell_println!("  categories: info, warning, error, success, progress");
                shell_println!("  priorities: low, normal, high, critical");
                return;
            }
            let body = parts.get(3).copied().unwrap_or("");
            let cat = match parts.get(4).copied().unwrap_or("info") {
                "warning" | "warn" => notifcenter::Category::Warning,
                "error" | "err" => notifcenter::Category::Error,
                "success" | "ok" => notifcenter::Category::Success,
                "progress" | "prog" => notifcenter::Category::Progress,
                _ => notifcenter::Category::Info,
            };
            let pri = match parts.get(5).copied().unwrap_or("normal") {
                "low" => notifcenter::Priority::Low,
                "high" => notifcenter::Priority::High,
                "critical" | "crit" => notifcenter::Priority::Critical,
                _ => notifcenter::Priority::Normal,
            };
            let (id, show) = notifcenter::send(app, title, body, cat, pri);
            shell_println!("Notification #{}: {} (toast: {})", id,
                if show { "shown" } else { "muted" },
                if show { "yes" } else { "no" });
        }
        "list" | "" => {
            let limit = parts.get(1).and_then(|s| s.parse::<usize>().ok()).unwrap_or(20);
            let notifs = notifcenter::history(limit);
            if notifs.is_empty() {
                shell_println!("No notifications");
            } else {
                shell_println!("{} notifications:", notifs.len());
                for n in &notifs {
                    let read_mark = if n.read { " " } else { "*" };
                    shell_println!("  {} #{:<4} [{}] [{}] {}: {} — {}",
                        read_mark, n.id, n.category.label(), n.priority.label(),
                        n.app, n.title, n.body);
                }
            }
        }
        "unread" => {
            let notifs = notifcenter::unread();
            if notifs.is_empty() {
                shell_println!("No unread notifications");
            } else {
                shell_println!("{} unread:", notifs.len());
                for n in &notifs {
                    shell_println!("  #{:<4} [{}] {}: {}", n.id, n.category.label(), n.app, n.title);
                }
            }
        }
        "dismiss" => {
            let target = parts.get(1).copied().unwrap_or("");
            match target {
                "all" => {
                    let count = notifcenter::dismiss_all();
                    shell_println!("Dismissed {} notifications", count);
                }
                "" => shell_println!("Usage: notif dismiss <id|all|app-name>"),
                _ => {
                    if let Ok(id) = target.parse::<u64>() {
                        match notifcenter::dismiss(id) {
                            Ok(()) => shell_println!("Dismissed #{}", id),
                            Err(e) => shell_println!("Error: {:?}", e),
                        }
                    } else {
                        let count = notifcenter::dismiss_app(target);
                        shell_println!("Dismissed {} notifications from {}", count, target);
                    }
                }
            }
        }
        "rm" | "remove" => {
            let id_str = parts.get(1).copied().unwrap_or("");
            match id_str.parse::<u64>() {
                Ok(id) => match notifcenter::remove(id) {
                    Ok(()) => shell_println!("Removed #{}", id),
                    Err(e) => shell_println!("Error: {:?}", e),
                },
                Err(_) => shell_println!("Usage: notif rm <id>"),
            }
        }
        "mute" => {
            let app = parts.get(1).copied().unwrap_or("");
            if app.is_empty() {
                shell_println!("Usage: notif mute <app-name>");
                return;
            }
            match notifcenter::mute_app(app) {
                Ok(()) => shell_println!("Muted {}", app),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "unmute" => {
            let app = parts.get(1).copied().unwrap_or("");
            if app.is_empty() {
                shell_println!("Usage: notif unmute <app-name>");
                return;
            }
            match notifcenter::unmute_app(app) {
                Ok(()) => shell_println!("Unmuted {}", app),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "muted" => {
            let muted = notifcenter::muted_apps();
            if muted.is_empty() {
                shell_println!("No muted apps");
            } else {
                shell_println!("{} muted apps:", muted.len());
                for app in &muted {
                    shell_println!("  {}", app);
                }
            }
        }
        "apps" => {
            let summaries = notifcenter::app_summaries();
            if summaries.is_empty() {
                shell_println!("No notifications from any app");
            } else {
                shell_println!("{:20} {:6} {:6} {:6}", "APP", "TOTAL", "UNREAD", "MUTED");
                for s in &summaries {
                    let m = if s.muted { "yes" } else { "no" };
                    shell_println!("{:20} {:6} {:6} {:6}", s.app, s.total, s.unread, m);
                }
            }
        }
        "expire" => {
            let expired = notifcenter::expire();
            shell_println!("Expired {} notifications", expired);
        }
        "test" => {
            match notifcenter::self_test() {
                Ok(()) => shell_println!("All notification center self-tests passed"),
                Err(e) => shell_println!("Notification center self-test failed: {:?}", e),
            }
        }
        "stats" => {
            let (total, unread_n, muted, sends, dismisses) = notifcenter::stats();
            shell_println!("Total:       {}", total);
            shell_println!("Unread:      {}", unread_n);
            shell_println!("Muted apps:  {}", muted);
            shell_println!("Send ops:    {}", sends);
            shell_println!("Dismiss ops: {}", dismisses);
        }
        "reset" => {
            notifcenter::clear_all();
            notifcenter::reset_stats();
            shell_println!("Notification center cleared and stats reset");
        }
        _ => {
            shell_println!("Usage: notif <subcommand>");
            shell_println!("  send <app> <title> [body] [cat] [pri]");
            shell_println!("  list [limit]            Show notification history");
            shell_println!("  unread                  Show unread notifications");
            shell_println!("  dismiss <id|all|app>    Mark as read");
            shell_println!("  rm <id>                 Remove notification");
            shell_println!("  mute <app>              Mute app's notifications");
            shell_println!("  unmute <app>            Unmute app");
            shell_println!("  muted                   List muted apps");
            shell_println!("  apps                    Per-app summary");
            shell_println!("  expire                  Remove expired notifications");
            shell_println!("  test                    Run self-tests");
            shell_println!("  stats                   Show statistics");
            shell_println!("  reset                   Clear all data and stats");
        }
    }
}

/// `appregistry` / `appreg` — application registry for start menu, file associations, search.
fn cmd_appregistry(args: &str) {
    use crate::fs::appregistry;
    let parts: Vec<&str> = args.split_whitespace().collect();
    let sub = parts.first().copied().unwrap_or("");
    match sub {
        "register" | "reg" => {
            // appreg register <id> <name> <exec_path> [category]
            let id = parts.get(1).copied().unwrap_or("");
            let name = parts.get(2).copied().unwrap_or("");
            let exec_path = parts.get(3).copied().unwrap_or("");
            if id.is_empty() || name.is_empty() || exec_path.is_empty() {
                shell_println!("Usage: appreg register <id> <name> <exec_path> [category]");
                shell_println!("  Categories: system, office, graphics, multimedia, internet,");
                shell_println!("              games, development, education, science, accessories,");
                shell_println!("              terminal, filemanager, settings, other");
                return;
            }
            let cat = parts.get(4).and_then(|s| appregistry::AppCategory::from_str(s));
            let categories = match cat {
                Some(c) => alloc::vec![c],
                None => alloc::vec![appregistry::AppCategory::Other],
            };
            let now = crate::timekeeping::clock_monotonic();
            match appregistry::register(appregistry::AppInfo {
                id: String::from(id),
                name: String::from(name),
                description: String::new(),
                exec_path: String::from(exec_path),
                icon: String::new(),
                categories,
                mime_types: Vec::new(),
                keywords: Vec::new(),
                show_in_menu: true,
                tray_icon: false,
                start_hidden: false,
                version: String::from("1.0"),
                installed_ns: now,
            }) {
                Ok(()) => shell_println!("Registered: {} ({})", name, id),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "unregister" | "unreg" => {
            let id = parts.get(1).copied().unwrap_or("");
            if id.is_empty() {
                shell_println!("Usage: appreg unregister <app-id>");
                return;
            }
            match appregistry::unregister(id) {
                Ok(()) => shell_println!("Unregistered: {}", id),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "get" | "info" => {
            let id = parts.get(1).copied().unwrap_or("");
            if id.is_empty() {
                shell_println!("Usage: appreg get <app-id>");
                return;
            }
            match appregistry::get(id) {
                Some(app) => {
                    shell_println!("ID:          {}", app.id);
                    shell_println!("Name:        {}", app.name);
                    shell_println!("Description: {}", app.description);
                    shell_println!("Exec:        {}", app.exec_path);
                    shell_println!("Icon:        {}", app.icon);
                    shell_println!("Version:     {}", app.version);
                    shell_println!("Menu:        {}", if app.show_in_menu { "yes" } else { "no" });
                    shell_println!("Tray:        {}", if app.tray_icon { "yes" } else { "no" });
                    if !app.categories.is_empty() {
                        let cats: Vec<&str> = app.categories.iter().map(|c| c.label()).collect();
                        shell_println!("Categories:  {}", cats.join(", "));
                    }
                    if !app.mime_types.is_empty() {
                        shell_println!("MIME types:  {}", app.mime_types.join(", "));
                    }
                    if !app.keywords.is_empty() {
                        shell_println!("Keywords:    {}", app.keywords.join(", "));
                    }
                }
                None => shell_println!("App not found: {}", id),
            }
        }
        "list" | "" => {
            let apps = appregistry::list_all();
            if apps.is_empty() {
                shell_println!("No registered applications");
            } else {
                shell_println!("{} applications:", apps.len());
                shell_println!("{:32} {:20} {}", "ID", "NAME", "EXEC");
                for app in &apps {
                    shell_println!("{:32} {:20} {}", app.id, app.name, app.exec_path);
                }
            }
        }
        "category" | "cat" => {
            let cat_name = parts.get(1).copied().unwrap_or("");
            if cat_name.is_empty() {
                // List all categories with counts.
                for &cat in appregistry::AppCategory::all() {
                    let apps = appregistry::by_category(cat);
                    if !apps.is_empty() {
                        shell_println!("  {:16} {} apps", cat.label(), apps.len());
                    }
                }
                return;
            }
            match appregistry::AppCategory::from_str(cat_name) {
                Some(cat) => {
                    let apps = appregistry::by_category(cat);
                    if apps.is_empty() {
                        shell_println!("No apps in category: {}", cat.label());
                    } else {
                        shell_println!("{} — {} apps:", cat.label(), apps.len());
                        for app in &apps {
                            shell_println!("  {} — {}", app.name, app.exec_path);
                        }
                    }
                }
                None => shell_println!("Unknown category: {}", cat_name),
            }
        }
        "mime" => {
            let mime = parts.get(1).copied().unwrap_or("");
            if mime.is_empty() {
                shell_println!("Usage: appreg mime <mime-type>");
                return;
            }
            let handlers = appregistry::handlers_for_mime(mime);
            if handlers.is_empty() {
                shell_println!("No handlers for: {}", mime);
            } else {
                shell_println!("{} handlers for {}:", handlers.len(), mime);
                for app in &handlers {
                    shell_println!("  {} ({}) — {}", app.name, app.id, app.exec_path);
                }
            }
        }
        "menu" => {
            let tree = appregistry::menu_tree();
            if tree.is_empty() {
                shell_println!("No menu entries");
            } else {
                for (cat, entries) in &tree {
                    shell_println!("[{}]", cat.label());
                    for entry in entries {
                        shell_println!("  {} — {}", entry.name, entry.exec_path);
                    }
                }
            }
        }
        "search" => {
            let query = parts.get(1).copied().unwrap_or("");
            if query.is_empty() {
                shell_println!("Usage: appreg search <query>");
                return;
            }
            let results = appregistry::search(query);
            if results.is_empty() {
                shell_println!("No matches for: {}", query);
            } else {
                shell_println!("{} matches:", results.len());
                for app in &results {
                    shell_println!("  {} ({}) — {}", app.name, app.id, app.description);
                }
            }
        }
        "tray" => {
            let apps = appregistry::tray_apps();
            if apps.is_empty() {
                shell_println!("No tray applications");
            } else {
                shell_println!("{} tray apps:", apps.len());
                for app in &apps {
                    let hidden = if app.start_hidden { " (start hidden)" } else { "" };
                    shell_println!("  {} — {}{}", app.name, app.exec_path, hidden);
                }
            }
        }
        "init" => {
            match appregistry::register_builtins() {
                Ok(()) => shell_println!("Registered built-in applications ({} total)", appregistry::app_count()),
                Err(e) => shell_println!("Error registering builtins: {:?}", e),
            }
        }
        "test" => {
            match appregistry::self_test() {
                Ok(()) => shell_println!("All app registry self-tests passed"),
                Err(e) => shell_println!("App registry self-test failed: {:?}", e),
            }
        }
        "stats" => {
            let (apps, mimes, reg_ops, lookup_ops) = appregistry::stats();
            shell_println!("Apps:         {}", apps);
            shell_println!("MIME types:   {}", mimes);
            shell_println!("Register ops: {}", reg_ops);
            shell_println!("Lookup ops:   {}", lookup_ops);
        }
        "reset" => {
            appregistry::clear_all();
            appregistry::reset_stats();
            shell_println!("App registry cleared and stats reset");
        }
        _ => {
            shell_println!("Usage: appreg <subcommand>");
            shell_println!("  register <id> <name> <path> [cat]  Register an application");
            shell_println!("  unregister <id>                    Remove an application");
            shell_println!("  get <id>                           Show app details");
            shell_println!("  list                               List all apps");
            shell_println!("  category [cat]                     List by category");
            shell_println!("  mime <mime-type>                   Find handlers for type");
            shell_println!("  menu                               Show start menu tree");
            shell_println!("  search <query>                     Search apps");
            shell_println!("  tray                               List tray apps");
            shell_println!("  init                               Register built-in apps");
            shell_println!("  test                               Run self-tests");
            shell_println!("  stats                              Show statistics");
            shell_println!("  reset                              Clear all data and stats");
        }
    }
}

/// `theme` — desktop color scheme and visual style management.
fn cmd_theme(args: &str) {
    use crate::fs::theme;
    let parts: Vec<&str> = args.split_whitespace().collect();
    let sub = parts.first().copied().unwrap_or("");
    match sub {
        "mode" => {
            let mode_str = parts.get(1).copied().unwrap_or("");
            if mode_str.is_empty() {
                shell_println!("Current mode: {}", theme::mode().label());
                return;
            }
            match theme::ThemeMode::from_str(mode_str) {
                Some(m) => {
                    theme::set_mode(m);
                    shell_println!("Mode set: {}", m.label());
                }
                None => shell_println!("Unknown mode: {} (use: light, dark, highcontrast)", mode_str),
            }
        }
        "accent" => {
            let hex = parts.get(1).copied().unwrap_or("");
            if hex.is_empty() {
                shell_println!("Accent: {}", theme::accent().to_hex());
                return;
            }
            if hex == "clear" || hex == "reset" {
                theme::clear_accent();
                shell_println!("Accent reset to default");
                return;
            }
            match theme::Color::from_hex(hex) {
                Some(c) => {
                    theme::set_accent(c);
                    shell_println!("Accent set: {}", c.to_hex());
                }
                None => shell_println!("Invalid hex color: {}", hex),
            }
        }
        "color" | "get" => {
            let role_str = parts.get(1).copied().unwrap_or("");
            if role_str.is_empty() {
                // List all colors.
                for &role in theme::ColorRole::all() {
                    let c = theme::color(role);
                    shell_println!("  {:20} {}", role.label(), c.to_hex());
                }
                return;
            }
            match theme::ColorRole::from_str(role_str) {
                Some(role) => {
                    let c = theme::color(role);
                    shell_println!("{}: {}", role.label(), c.to_hex());
                }
                None => shell_println!("Unknown role: {}", role_str),
            }
        }
        "set" => {
            let role_str = parts.get(1).copied().unwrap_or("");
            let hex = parts.get(2).copied().unwrap_or("");
            if role_str.is_empty() || hex.is_empty() {
                shell_println!("Usage: theme set <role> <#hex>");
                return;
            }
            let role = match theme::ColorRole::from_str(role_str) {
                Some(r) => r,
                None => { shell_println!("Unknown role: {}", role_str); return; }
            };
            let color = match theme::Color::from_hex(hex) {
                Some(c) => c,
                None => { shell_println!("Invalid hex color: {}", hex); return; }
            };
            theme::set_override(role, color);
            shell_println!("Override: {} → {}", role.label(), color.to_hex());
        }
        "clear" => {
            let role_str = parts.get(1).copied().unwrap_or("");
            if role_str.is_empty() || role_str == "all" {
                theme::clear_all_overrides();
                shell_println!("All overrides cleared");
                return;
            }
            match theme::ColorRole::from_str(role_str) {
                Some(role) => {
                    theme::clear_override(role);
                    shell_println!("Override cleared: {}", role.label());
                }
                None => shell_println!("Unknown role: {}", role_str),
            }
        }
        "overrides" => {
            let overrides = theme::list_overrides();
            if overrides.is_empty() {
                shell_println!("No active overrides");
            } else {
                shell_println!("{} overrides:", overrides.len());
                for (role, color) in &overrides {
                    shell_println!("  {:20} {}", role.label(), color.to_hex());
                }
            }
        }
        "save" => {
            let name = parts.get(1).copied().unwrap_or("");
            if name.is_empty() {
                shell_println!("Usage: theme save <name>");
                return;
            }
            // Save current overrides as a custom theme.
            let overrides = theme::list_overrides();
            let mut map = alloc::collections::BTreeMap::new();
            for (role, color) in overrides {
                map.insert(role, color);
            }
            let mode = theme::mode();
            match theme::save_custom(name, mode, map) {
                Ok(()) => shell_println!("Saved custom theme: {}", name),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "load" | "apply" => {
            let name = parts.get(1).copied().unwrap_or("");
            if name.is_empty() {
                shell_println!("Usage: theme load <name>");
                return;
            }
            match theme::apply_custom(name) {
                Ok(()) => shell_println!("Applied theme: {}", name),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "delete" | "rm" => {
            let name = parts.get(1).copied().unwrap_or("");
            if name.is_empty() {
                shell_println!("Usage: theme delete <name>");
                return;
            }
            match theme::delete_custom(name) {
                Ok(()) => shell_println!("Deleted theme: {}", name),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "list" | "" => {
            shell_println!("Mode: {}", theme::mode().label());
            shell_println!("Accent: {}", theme::accent().to_hex());
            let overrides = theme::list_overrides();
            if !overrides.is_empty() {
                shell_println!("Overrides: {}", overrides.len());
            }
            let custom = theme::list_custom();
            if !custom.is_empty() {
                shell_println!("Custom themes:");
                for name in &custom {
                    shell_println!("  {}", name);
                }
            }
        }
        "test" => {
            match theme::self_test() {
                Ok(()) => shell_println!("All theme self-tests passed"),
                Err(e) => shell_println!("Theme self-test failed: {:?}", e),
            }
        }
        "stats" => {
            let (mode, customs, overrides, queries, changes) = theme::stats();
            shell_println!("Mode:      {}", mode.label());
            shell_println!("Customs:   {}", customs);
            shell_println!("Overrides: {}", overrides);
            shell_println!("Queries:   {}", queries);
            shell_println!("Changes:   {}", changes);
        }
        "reset" => {
            theme::clear_all();
            theme::reset_stats();
            shell_println!("Theme reset to defaults");
        }
        _ => {
            shell_println!("Usage: theme <subcommand>");
            shell_println!("  mode [light|dark|hc]       Get/set theme mode");
            shell_println!("  accent [#hex|clear]        Get/set accent color");
            shell_println!("  color [role]               Show color(s)");
            shell_println!("  set <role> <#hex>          Override a color");
            shell_println!("  clear [role|all]           Clear override(s)");
            shell_println!("  overrides                  List active overrides");
            shell_println!("  save <name>                Save custom theme");
            shell_println!("  load <name>                Apply custom theme");
            shell_println!("  delete <name>              Delete custom theme");
            shell_println!("  list                       Show theme status");
            shell_println!("  test                       Run self-tests");
            shell_println!("  stats                      Show statistics");
            shell_println!("  reset                      Reset to defaults");
        }
    }
}

/// `hotkey` — global keyboard shortcut management.
fn cmd_hotkey(args: &str) {
    use crate::fs::hotkeys;
    let parts: Vec<&str> = args.split_whitespace().collect();
    let sub = parts.first().copied().unwrap_or("");
    match sub {
        "bind" => {
            let combo_str = parts.get(1).copied().unwrap_or("");
            let action_str = parts.get(2).copied().unwrap_or("");
            if combo_str.is_empty() || action_str.is_empty() {
                shell_println!("Usage: hotkey bind <combo> <action> [description]");
                shell_println!("  combo: Ctrl+S, Alt+F4, Super+L, etc.");
                shell_println!("  actions: close, switch, minimize-all, run, start,");
                shell_println!("    screenshot, lock, logout, copy, cut, paste, undo,");
                shell_println!("    redo, select-all, launch:<app>, cmd:<command>");
                return;
            }
            let combo = match hotkeys::KeyCombo::parse(combo_str) {
                Some(c) => c,
                None => { shell_println!("Invalid combo: {}", combo_str); return; }
            };
            let action = match hotkeys::HotkeyAction::from_str(action_str) {
                Some(a) => a,
                None => { shell_println!("Unknown action: {}", action_str); return; }
            };
            let desc = if parts.len() > 3 {
                parts[3..].join(" ")
            } else {
                action.label()
            };
            match hotkeys::bind(combo, action, &desc, false) {
                Ok(()) => shell_println!("Bound: {} → {}", combo_str, desc),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "unbind" => {
            let combo_str = parts.get(1).copied().unwrap_or("");
            if combo_str.is_empty() {
                shell_println!("Usage: hotkey unbind <combo>");
                return;
            }
            let combo = match hotkeys::KeyCombo::parse(combo_str) {
                Some(c) => c,
                None => { shell_println!("Invalid combo: {}", combo_str); return; }
            };
            match hotkeys::unbind(&combo) {
                Ok(()) => shell_println!("Unbound: {}", combo_str),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "enable" | "disable" => {
            let combo_str = parts.get(1).copied().unwrap_or("");
            if combo_str.is_empty() {
                shell_println!("Usage: hotkey {} <combo>", sub);
                return;
            }
            let combo = match hotkeys::KeyCombo::parse(combo_str) {
                Some(c) => c,
                None => { shell_println!("Invalid combo: {}", combo_str); return; }
            };
            let enabled = sub == "enable";
            match hotkeys::set_enabled(&combo, enabled) {
                Ok(()) => shell_println!("{}: {}", if enabled { "Enabled" } else { "Disabled" }, combo_str),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "dispatch" | "trigger" => {
            let combo_str = parts.get(1).copied().unwrap_or("");
            if combo_str.is_empty() {
                shell_println!("Usage: hotkey dispatch <combo>");
                return;
            }
            let combo = match hotkeys::KeyCombo::parse(combo_str) {
                Some(c) => c,
                None => { shell_println!("Invalid combo: {}", combo_str); return; }
            };
            let actions = hotkeys::dispatch(&combo);
            if actions.is_empty() {
                shell_println!("No binding for: {}", combo_str);
            } else {
                for a in &actions {
                    shell_println!("Action: {}", a.label());
                }
            }
        }
        "find" => {
            let action_str = parts.get(1).copied().unwrap_or("");
            if action_str.is_empty() {
                shell_println!("Usage: hotkey find <action>");
                return;
            }
            match hotkeys::HotkeyAction::from_str(action_str) {
                Some(action) => {
                    match hotkeys::find_binding(&action) {
                        Some(combo) => shell_println!("{} → {}", combo.display(), action.label()),
                        None => shell_println!("No binding for: {}", action_str),
                    }
                }
                None => shell_println!("Unknown action: {}", action_str),
            }
        }
        "search" => {
            let query = parts.get(1).copied().unwrap_or("");
            if query.is_empty() {
                shell_println!("Usage: hotkey search <query>");
                return;
            }
            let results = hotkeys::search(query);
            if results.is_empty() {
                shell_println!("No matches for: {}", query);
            } else {
                for h in &results {
                    let actions: Vec<String> = h.actions.iter().map(|a| a.label()).collect();
                    let en = if h.enabled { "" } else { " (disabled)" };
                    shell_println!("  {:20} → {}{}", h.combo.display(), actions.join(", "), en);
                }
            }
        }
        "list" | "" => {
            let all = hotkeys::list_all();
            if all.is_empty() {
                shell_println!("No hotkeys configured");
            } else {
                shell_println!("{} hotkeys:", all.len());
                for h in &all {
                    let actions: Vec<String> = h.actions.iter().map(|a| a.label()).collect();
                    let en = if h.enabled { "" } else { " [off]" };
                    let def = if h.is_default { " [default]" } else { "" };
                    shell_println!("  {:20} → {}{}{}", h.combo.display(), actions.join(", "), en, def);
                }
            }
        }
        "init" | "defaults" => {
            match hotkeys::register_defaults() {
                Ok(()) => {
                    let (total, _, _, _) = hotkeys::stats();
                    shell_println!("Registered default hotkeys ({} total)", total);
                }
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "test" => {
            match hotkeys::self_test() {
                Ok(()) => shell_println!("All hotkey self-tests passed"),
                Err(e) => shell_println!("Hotkey self-test failed: {:?}", e),
            }
        }
        "stats" => {
            let (total, enabled, dispatches, hits) = hotkeys::stats();
            shell_println!("Bindings:   {}", total);
            shell_println!("Enabled:    {}", enabled);
            shell_println!("Dispatches: {}", dispatches);
            shell_println!("Hits:       {}", hits);
        }
        "reset" => {
            hotkeys::clear_all();
            hotkeys::reset_stats();
            shell_println!("Hotkeys cleared and stats reset");
        }
        _ => {
            shell_println!("Usage: hotkey <subcommand>");
            shell_println!("  bind <combo> <action> [desc]  Register hotkey");
            shell_println!("  unbind <combo>                Remove hotkey");
            shell_println!("  enable <combo>                Enable hotkey");
            shell_println!("  disable <combo>               Disable hotkey");
            shell_println!("  dispatch <combo>              Simulate keypress");
            shell_println!("  find <action>                 Find combo for action");
            shell_println!("  search <query>                Search bindings");
            shell_println!("  list                          List all hotkeys");
            shell_println!("  init                          Register defaults");
            shell_println!("  test                          Run self-tests");
            shell_println!("  stats                         Show statistics");
            shell_println!("  reset                         Clear all");
        }
    }
}

/// `widgets` / `widget` — desktop widget management.
fn cmd_widgets(args: &str) {
    use crate::fs::widgets;
    let parts: Vec<&str> = args.split_whitespace().collect();
    let sub = parts.first().copied().unwrap_or("");
    match sub {
        "add" => {
            // widgets add <kind> [x y]
            let kind_str = parts.get(1).copied().unwrap_or("");
            if let Some(kind) = widgets::WidgetKind::from_str(kind_str) {
                let x: i32 = parts.get(2).and_then(|s| s.parse().ok()).unwrap_or(100);
                let y: i32 = parts.get(3).and_then(|s| s.parse().ok()).unwrap_or(100);
                match widgets::add(kind, x, y) {
                    Ok(id) => shell_println!("Widget added: id={} kind={}", id, kind.label()),
                    Err(e) => shell_println!("Error: {:?}", e),
                }
            } else if !kind_str.is_empty() {
                // Try as custom type
                let x: i32 = parts.get(2).and_then(|s| s.parse().ok()).unwrap_or(100);
                let y: i32 = parts.get(3).and_then(|s| s.parse().ok()).unwrap_or(100);
                match widgets::add_custom(kind_str, x, y) {
                    Ok(id) => shell_println!("Custom widget added: id={}", id),
                    Err(e) => shell_println!("Error: {:?}", e),
                }
            } else {
                shell_println!("Usage: widgets add <kind> [x y]");
                shell_println!("Kinds: clock sysmon notes calendar disk recent weather network");
            }
        }
        "remove" | "rm" => {
            if let Some(id) = parts.get(1).and_then(|s| s.parse::<u64>().ok()) {
                match widgets::remove(id) {
                    Ok(()) => shell_println!("Widget {} removed", id),
                    Err(e) => shell_println!("Error: {:?}", e),
                }
            } else {
                shell_println!("Usage: widgets remove <id>");
            }
        }
        "get" | "info" => {
            if let Some(id) = parts.get(1).and_then(|s| s.parse::<u64>().ok()) {
                if let Some(w) = widgets::get(id) {
                    shell_println!("Widget #{}", w.id);
                    shell_println!("  Kind:     {}", w.kind.label());
                    shell_println!("  Type:     {}", w.type_name);
                    shell_println!("  Title:    {}", w.title);
                    shell_println!("  Position: ({}, {})", w.x, w.y);
                    shell_println!("  Size:     {}x{}", w.width, w.height);
                    shell_println!("  Visible:  {}", w.visible);
                    shell_println!("  Opacity:  {}%", w.opacity);
                    shell_println!("  Refresh:  {}ms", w.refresh_ms);
                    if !w.data.is_empty() {
                        let trunc = if w.data.len() > 80 {
                            &w.data[..80]
                        } else {
                            &w.data
                        };
                        shell_println!("  Data:     {}", trunc);
                    }
                } else {
                    shell_println!("Widget not found");
                }
            } else {
                shell_println!("Usage: widgets get <id>");
            }
        }
        "list" | "ls" => {
            let all = widgets::active_widgets();
            if all.is_empty() {
                shell_println!("No widgets");
            } else {
                shell_println!("{:6} {:16} {:20} {:10} {:10} {:4} {}",
                    "ID", "KIND", "TITLE", "POS", "SIZE", "VIS", "OPACITY");
                for w in &all {
                    let pos = alloc::format!("{},{}", w.x, w.y);
                    let sz = alloc::format!("{}x{}", w.width, w.height);
                    let vis = if w.visible { "yes" } else { "no" };
                    shell_println!("{:<6} {:16} {:20} {:10} {:10} {:4} {}%",
                        w.id, w.kind.label(), w.title, pos, sz, vis, w.opacity);
                }
            }
        }
        "move" | "mv" => {
            // widgets move <id> <x> <y>
            let id = parts.get(1).and_then(|s| s.parse::<u64>().ok());
            let x = parts.get(2).and_then(|s| s.parse::<i32>().ok());
            let y = parts.get(3).and_then(|s| s.parse::<i32>().ok());
            if let (Some(id), Some(x), Some(y)) = (id, x, y) {
                match widgets::move_widget(id, x, y) {
                    Ok(()) => shell_println!("Widget {} moved to ({}, {})", id, x, y),
                    Err(e) => shell_println!("Error: {:?}", e),
                }
            } else {
                shell_println!("Usage: widgets move <id> <x> <y>");
            }
        }
        "resize" => {
            // widgets resize <id> <w> <h>
            let id = parts.get(1).and_then(|s| s.parse::<u64>().ok());
            let w = parts.get(2).and_then(|s| s.parse::<u32>().ok());
            let h = parts.get(3).and_then(|s| s.parse::<u32>().ok());
            if let (Some(id), Some(w), Some(h)) = (id, w, h) {
                match widgets::resize(id, w, h) {
                    Ok(()) => shell_println!("Widget {} resized to {}x{}", id, w, h),
                    Err(e) => shell_println!("Error: {:?}", e),
                }
            } else {
                shell_println!("Usage: widgets resize <id> <width> <height>");
            }
        }
        "show" => {
            if let Some(id) = parts.get(1).and_then(|s| s.parse::<u64>().ok()) {
                match widgets::set_visible(id, true) {
                    Ok(()) => shell_println!("Widget {} shown", id),
                    Err(e) => shell_println!("Error: {:?}", e),
                }
            } else {
                shell_println!("Usage: widgets show <id>");
            }
        }
        "hide" => {
            if let Some(id) = parts.get(1).and_then(|s| s.parse::<u64>().ok()) {
                match widgets::set_visible(id, false) {
                    Ok(()) => shell_println!("Widget {} hidden", id),
                    Err(e) => shell_println!("Error: {:?}", e),
                }
            } else {
                shell_println!("Usage: widgets hide <id>");
            }
        }
        "opacity" => {
            let id = parts.get(1).and_then(|s| s.parse::<u64>().ok());
            let val = parts.get(2).and_then(|s| s.parse::<u8>().ok());
            if let (Some(id), Some(val)) = (id, val) {
                match widgets::set_opacity(id, val) {
                    Ok(()) => shell_println!("Widget {} opacity set to {}%", id, val.min(100)),
                    Err(e) => shell_println!("Error: {:?}", e),
                }
            } else {
                shell_println!("Usage: widgets opacity <id> <0-100>");
            }
        }
        "data" => {
            // widgets data <id> <text...>
            if let Some(id) = parts.get(1).and_then(|s| s.parse::<u64>().ok()) {
                let text = if parts.len() > 2 {
                    parts[2..].join(" ")
                } else {
                    alloc::string::String::new()
                };
                match widgets::set_data(id, &text) {
                    Ok(()) => shell_println!("Widget {} data set ({} bytes)", id, text.len()),
                    Err(e) => shell_println!("Error: {:?}", e),
                }
            } else {
                shell_println!("Usage: widgets data <id> [text...]");
            }
        }
        "title" => {
            if let Some(id) = parts.get(1).and_then(|s| s.parse::<u64>().ok()) {
                let title = if parts.len() > 2 {
                    parts[2..].join(" ")
                } else {
                    alloc::string::String::new()
                };
                match widgets::set_title(id, &title) {
                    Ok(()) => shell_println!("Widget {} title set to '{}'", id, title),
                    Err(e) => shell_println!("Error: {:?}", e),
                }
            } else {
                shell_println!("Usage: widgets title <id> <title...>");
            }
        }
        "refresh" => {
            let stale = widgets::needs_refresh();
            if stale.is_empty() {
                shell_println!("All widgets up to date");
            } else {
                shell_println!("{} widget(s) need refresh: {:?}", stale.len(), stale);
                for id in &stale {
                    let _ = widgets::mark_refreshed(*id);
                }
                shell_println!("Marked all as refreshed");
            }
        }
        "regtype" => {
            // widgets regtype <type_id> <name> [w h app]
            let type_id = parts.get(1).copied().unwrap_or("");
            let name = parts.get(2).copied().unwrap_or("");
            if type_id.is_empty() || name.is_empty() {
                shell_println!("Usage: widgets regtype <type_id> <name> [width height app]");
            } else {
                let w = parts.get(3).and_then(|s| s.parse::<u32>().ok()).unwrap_or(200);
                let h = parts.get(4).and_then(|s| s.parse::<u32>().ok()).unwrap_or(200);
                let app = parts.get(5).copied().unwrap_or("custom");
                match widgets::register_type(type_id, name, w, h, app) {
                    Ok(()) => shell_println!("Custom type '{}' registered", type_id),
                    Err(e) => shell_println!("Error: {:?}", e),
                }
            }
        }
        "unregtype" => {
            let type_id = parts.get(1).copied().unwrap_or("");
            if type_id.is_empty() {
                shell_println!("Usage: widgets unregtype <type_id>");
            } else {
                match widgets::unregister_type(type_id) {
                    Ok(()) => shell_println!("Custom type '{}' unregistered", type_id),
                    Err(e) => shell_println!("Error: {:?}", e),
                }
            }
        }
        "types" => {
            let types = widgets::list_types();
            if types.is_empty() {
                shell_println!("No custom widget types registered");
            } else {
                shell_println!("{:20} {:24} {:8} {:8} {}",
                    "TYPE_ID", "NAME", "WIDTH", "HEIGHT", "APP");
                for t in &types {
                    shell_println!("{:20} {:24} {:8} {:8} {}",
                        t.type_id, t.display_name, t.default_width, t.default_height, t.provider_app);
                }
            }
        }
        "test" => {
            shell_println!("Running widget self-tests...");
            match widgets::self_test() {
                Ok(()) => shell_println!("All widget tests passed"),
                Err(e) => shell_println!("Test failed: {:?}", e),
            }
        }
        "stats" => {
            let (wcount, tcount, adds, refreshes) = widgets::stats();
            shell_println!("Widgets: {}/64", wcount);
            shell_println!("Types:   {}/128", tcount);
            shell_println!("Adds:    {}", adds);
            shell_println!("Refresh: {}", refreshes);
        }
        "reset" => {
            widgets::clear_all();
            widgets::reset_stats();
            shell_println!("Widget state reset");
        }
        _ => {
            shell_println!("Usage: widgets <subcommand>");
            shell_println!("  add <kind> [x y]             Add a built-in widget");
            shell_println!("  remove <id>                  Remove a widget");
            shell_println!("  get <id>                     Show widget details");
            shell_println!("  list                         List active widgets");
            shell_println!("  move <id> <x> <y>            Reposition a widget");
            shell_println!("  resize <id> <w> <h>          Resize a widget");
            shell_println!("  show <id>                    Make widget visible");
            shell_println!("  hide <id>                    Hide a widget");
            shell_println!("  opacity <id> <0-100>         Set opacity");
            shell_println!("  data <id> [text...]          Set widget data");
            shell_println!("  title <id> <title...>        Set widget title");
            shell_println!("  refresh                      Check/update stale widgets");
            shell_println!("  regtype <id> <name> [w h app]  Register custom type");
            shell_println!("  unregtype <id>               Unregister custom type");
            shell_println!("  types                        List custom types");
            shell_println!("  test                         Run self-tests");
            shell_println!("  stats                        Show statistics");
            shell_println!("  reset                        Clear all");
            shell_println!("");
            shell_println!("Kinds: clock sysmon notes calendar disk recent weather network");
        }
    }
}

/// `soundmixer` / `smixer` — per-app volume control.
fn cmd_soundmixer(args: &str) {
    use crate::fs::soundmixer;
    let parts: Vec<&str> = args.split_whitespace().collect();
    let sub = parts.first().copied().unwrap_or("");
    match sub {
        "vol" | "volume" => {
            // soundmixer vol [value]
            if let Some(v) = parts.get(1).and_then(|s| s.parse::<u8>().ok()) {
                soundmixer::set_master_volume(v);
                shell_println!("Master volume: {}%", v.min(100));
            } else {
                shell_println!("Master volume: {}%{}", soundmixer::master_volume(),
                    if soundmixer::master_muted() { " (MUTED)" } else { "" });
            }
        }
        "mute" => {
            let new = soundmixer::toggle_master_mute();
            shell_println!("Master {}", if new { "muted" } else { "unmuted" });
        }
        "adddev" => {
            // soundmixer adddev <id> <name...>
            let id = parts.get(1).copied().unwrap_or("");
            if id.is_empty() || parts.len() < 3 {
                shell_println!("Usage: soundmixer adddev <id> <name...>");
            } else {
                let name = parts[2..].join(" ");
                match soundmixer::add_device(id, &name) {
                    Ok(()) => shell_println!("Device '{}' added", id),
                    Err(e) => shell_println!("Error: {:?}", e),
                }
            }
        }
        "rmdev" => {
            let id = parts.get(1).copied().unwrap_or("");
            if id.is_empty() {
                shell_println!("Usage: soundmixer rmdev <id>");
            } else {
                match soundmixer::remove_device(id) {
                    Ok(()) => shell_println!("Device '{}' removed", id),
                    Err(e) => shell_println!("Error: {:?}", e),
                }
            }
        }
        "default" => {
            let id = parts.get(1).copied().unwrap_or("");
            if id.is_empty() {
                shell_println!("Usage: soundmixer default <device_id>");
            } else {
                match soundmixer::set_default_device(id) {
                    Ok(()) => shell_println!("Default device: {}", id),
                    Err(e) => shell_println!("Error: {:?}", e),
                }
            }
        }
        "devvol" => {
            let id = parts.get(1).copied().unwrap_or("");
            let vol = parts.get(2).and_then(|s| s.parse::<u8>().ok());
            if id.is_empty() || vol.is_none() {
                shell_println!("Usage: soundmixer devvol <device_id> <0-100>");
            } else if let Some(v) = vol {
                match soundmixer::set_device_volume(id, v) {
                    Ok(()) => shell_println!("Device '{}' volume: {}%", id, v.min(100)),
                    Err(e) => shell_println!("Error: {:?}", e),
                }
            }
        }
        "devices" => {
            let devs = soundmixer::list_devices();
            if devs.is_empty() {
                shell_println!("No audio devices");
            } else {
                shell_println!("{:16} {:24} {:6} {:6} {}",
                    "ID", "NAME", "VOL", "MUTED", "DEFAULT");
                for d in &devs {
                    shell_println!("{:16} {:24} {:6} {:6} {}",
                        d.id, d.name,
                        alloc::format!("{}%", d.volume),
                        if d.muted { "yes" } else { "no" },
                        if d.is_default { "*" } else { "" });
                }
            }
        }
        "appvol" => {
            // soundmixer appvol <app_id> <vol>
            let app = parts.get(1).copied().unwrap_or("");
            let vol = parts.get(2).and_then(|s| s.parse::<u8>().ok());
            if app.is_empty() || vol.is_none() {
                shell_println!("Usage: soundmixer appvol <app_id> <0-100>");
            } else if let Some(v) = vol {
                match soundmixer::set_app_volume(app, v) {
                    Ok(()) => shell_println!("App '{}' volume: {}%", app, v.min(100)),
                    Err(e) => shell_println!("Error: {:?}", e),
                }
            }
        }
        "appmute" => {
            let app = parts.get(1).copied().unwrap_or("");
            let val = parts.get(2).copied().unwrap_or("true");
            if app.is_empty() {
                shell_println!("Usage: soundmixer appmute <app_id> [true|false]");
            } else {
                let muted = val != "false" && val != "0";
                match soundmixer::set_app_muted(app, muted) {
                    Ok(()) => shell_println!("App '{}' {}", app, if muted { "muted" } else { "unmuted" }),
                    Err(e) => shell_println!("Error: {:?}", e),
                }
            }
        }
        "approute" => {
            let app = parts.get(1).copied().unwrap_or("");
            let dev = parts.get(2).copied();
            if app.is_empty() {
                shell_println!("Usage: soundmixer approute <app_id> [device_id]");
            } else {
                match soundmixer::set_app_output(app, dev) {
                    Ok(()) => {
                        let target = dev.unwrap_or("default");
                        shell_println!("App '{}' routed to '{}'", app, target);
                    }
                    Err(e) => shell_println!("Error: {:?}", e),
                }
            }
        }
        "apps" => {
            let entries = soundmixer::app_entries();
            if entries.is_empty() {
                shell_println!("No audio apps");
            } else {
                shell_println!("{:20} {:20} {:6} {:6} {:8} {:7} {}",
                    "APP_ID", "NAME", "VOL", "MUTED", "STREAMS", "PLAYING", "EFF.VOL");
                for a in &entries {
                    let eff = soundmixer::effective_volume(&a.app_id);
                    shell_println!("{:20} {:20} {:6} {:6} {:8} {:7} {}%",
                        a.app_id, a.app_name,
                        alloc::format!("{}%", a.volume),
                        if a.muted { "yes" } else { "no" },
                        a.stream_count,
                        if a.playing { "YES" } else { "-" },
                        eff);
                }
            }
        }
        "stream" => {
            // soundmixer stream <app_id> <name> <label> [category]
            let app_id = parts.get(1).copied().unwrap_or("");
            let name = parts.get(2).copied().unwrap_or("");
            let label = parts.get(3).copied().unwrap_or("");
            let cat = parts.get(4).copied()
                .and_then(soundmixer::StreamCategory::from_str)
                .unwrap_or(soundmixer::StreamCategory::Application);
            if app_id.is_empty() || name.is_empty() {
                shell_println!("Usage: soundmixer stream <app_id> <name> <label> [category]");
                shell_println!("Categories: system comm media game app");
            } else {
                match soundmixer::register_stream(app_id, name, label, cat) {
                    Ok(id) => shell_println!("Stream registered: id={} app={}", id, app_id),
                    Err(e) => shell_println!("Error: {:?}", e),
                }
            }
        }
        "unstream" => {
            if let Some(id) = parts.get(1).and_then(|s| s.parse::<u64>().ok()) {
                match soundmixer::unregister_stream(id) {
                    Ok(()) => shell_println!("Stream {} unregistered", id),
                    Err(e) => shell_println!("Error: {:?}", e),
                }
            } else {
                shell_println!("Usage: soundmixer unstream <stream_id>");
            }
        }
        "play" => {
            if let Some(id) = parts.get(1).and_then(|s| s.parse::<u64>().ok()) {
                match soundmixer::report_activity(id) {
                    Ok(()) => shell_println!("Stream {} now playing", id),
                    Err(e) => shell_println!("Error: {:?}", e),
                }
            } else {
                shell_println!("Usage: soundmixer play <stream_id>");
            }
        }
        "stop" => {
            if let Some(id) = parts.get(1).and_then(|s| s.parse::<u64>().ok()) {
                match soundmixer::report_inactive(id) {
                    Ok(()) => shell_println!("Stream {} stopped", id),
                    Err(e) => shell_println!("Error: {:?}", e),
                }
            } else {
                shell_println!("Usage: soundmixer stop <stream_id>");
            }
        }
        "streams" => {
            let streams = soundmixer::list_streams();
            if streams.is_empty() {
                shell_println!("No streams");
            } else {
                shell_println!("{:6} {:16} {:16} {:6} {:12} {}",
                    "ID", "APP", "LABEL", "VOL", "CATEGORY", "ACTIVE");
                for s in &streams {
                    shell_println!("{:<6} {:16} {:16} {:6} {:12} {}",
                        s.id, s.app_id, s.label,
                        alloc::format!("{}%", s.volume),
                        s.category.label(),
                        if s.active { "YES" } else { "-" });
                }
            }
        }
        "history" => {
            let hist = soundmixer::sound_history();
            if hist.is_empty() {
                shell_println!("No sound history");
            } else {
                shell_println!("{:20} {:20} {:30} {}",
                    "APP_ID", "NAME", "DESCRIPTION", "TIME_NS");
                for h in hist.iter().take(30) {
                    shell_println!("{:20} {:20} {:30} {}",
                        h.app_id, h.app_name, h.description, h.timestamp_ns);
                }
            }
        }
        "duck" => {
            // soundmixer duck [policy]
            if let Some(p) = parts.get(1).and_then(|s| soundmixer::DuckingPolicy::from_str(s)) {
                soundmixer::set_ducking_policy(p);
                shell_println!("Ducking policy: {}", p.label());
            } else {
                let current = soundmixer::ducking_policy();
                shell_println!("Ducking: {} (none/comm/bg)", current.label());
            }
        }
        "init" => {
            soundmixer::init_defaults();
            shell_println!("Default audio device initialized");
        }
        "test" => {
            shell_println!("Running sound mixer self-tests...");
            match soundmixer::self_test() {
                Ok(()) => shell_println!("All sound mixer tests passed"),
                Err(e) => shell_println!("Test failed: {:?}", e),
            }
        }
        "stats" => {
            let (streams, apps, devs, vol_ch, total) = soundmixer::stats();
            let master = soundmixer::master_volume();
            let muted = soundmixer::master_muted();
            shell_println!("Master:  {}%{}", master, if muted { " (MUTED)" } else { "" });
            shell_println!("Devices: {}/32", devs);
            shell_println!("Apps:    {}/128", apps);
            shell_println!("Streams: {}/256", streams);
            shell_println!("Vol chg: {}", vol_ch);
            shell_println!("Created: {}", total);
        }
        "reset" => {
            soundmixer::clear_all();
            soundmixer::reset_stats();
            shell_println!("Sound mixer reset");
        }
        _ => {
            shell_println!("Usage: soundmixer <subcommand>");
            shell_println!("  vol [0-100]                   Get/set master volume");
            shell_println!("  mute                          Toggle master mute");
            shell_println!("  adddev <id> <name...>         Add audio device");
            shell_println!("  rmdev <id>                    Remove audio device");
            shell_println!("  default <id>                  Set default device");
            shell_println!("  devvol <id> <0-100>           Set device volume");
            shell_println!("  devices                       List audio devices");
            shell_println!("  appvol <app> <0-100>          Set per-app volume");
            shell_println!("  appmute <app> [true|false]    Mute/unmute app");
            shell_println!("  approute <app> [device]       Route app to device");
            shell_println!("  apps                          List app audio entries");
            shell_println!("  stream <app> <name> <label> [cat]  Register stream");
            shell_println!("  unstream <id>                 Unregister stream");
            shell_println!("  play <id>                     Mark stream active");
            shell_println!("  stop <id>                     Mark stream inactive");
            shell_println!("  streams                       List all streams");
            shell_println!("  history                       Sound event history");
            shell_println!("  duck [none|comm|bg]           Get/set ducking policy");
            shell_println!("  init                          Add default device");
            shell_println!("  test                          Run self-tests");
            shell_println!("  stats                         Show statistics");
            shell_println!("  reset                         Clear all");
        }
    }
}

/// `wallpaper` / `wp` — desktop background management.
fn cmd_wallpaper(args: &str) {
    use crate::fs::wallpaper;
    let parts: Vec<&str> = args.split_whitespace().collect();
    let sub = parts.first().copied().unwrap_or("");
    match sub {
        "set" => {
            // wallpaper set <path>
            let path = if parts.len() > 1 { parts[1..].join(" ") } else { alloc::string::String::new() };
            if path.is_empty() {
                shell_println!("Usage: wallpaper set <path>");
            } else {
                match wallpaper::set_image(&path) {
                    Ok(()) => shell_println!("Wallpaper set: {}", path),
                    Err(e) => shell_println!("Error: {:?}", e),
                }
            }
        }
        "color" => {
            let color = parts.get(1).copied().unwrap_or("");
            if color.is_empty() {
                let cfg = wallpaper::current();
                shell_println!("Background color: {}", cfg.background_color);
            } else {
                wallpaper::set_solid_color(color).unwrap_or_else(|e| {
                    shell_println!("Error: {:?}", e);
                });
                shell_println!("Solid color set: {}", color);
            }
        }
        "fit" => {
            if let Some(mode) = parts.get(1).and_then(|s| wallpaper::FitMode::from_str(s)) {
                wallpaper::set_fit_mode(mode);
                shell_println!("Fit mode: {}", mode.label());
            } else {
                let cfg = wallpaper::current();
                shell_println!("Fit mode: {} (fill/fit/stretch/center/tile/span)", cfg.fit_mode.label());
            }
        }
        "bgcolor" => {
            let color = parts.get(1).copied().unwrap_or("");
            if color.is_empty() {
                shell_println!("Usage: wallpaper bgcolor <#hex>");
            } else {
                wallpaper::set_background_color(color);
                shell_println!("Background color: {}", color);
            }
        }
        "offset" => {
            let x = parts.get(1).and_then(|s| s.parse::<f32>().ok());
            let y = parts.get(2).and_then(|s| s.parse::<f32>().ok());
            if let (Some(x), Some(y)) = (x, y) {
                wallpaper::set_offset(x, y);
                shell_println!("Offset: ({:.2}, {:.2})", x.clamp(0.0, 1.0), y.clamp(0.0, 1.0));
            } else {
                let cfg = wallpaper::current();
                shell_println!("Offset: ({:.2}, {:.2})", cfg.offset_x, cfg.offset_y);
                shell_println!("Usage: wallpaper offset <x 0.0-1.0> <y 0.0-1.0>");
            }
        }
        "slideshow" => {
            // wallpaper slideshow <path1> <path2> ... [--interval N]
            let mut paths: Vec<&str> = Vec::new();
            let mut interval = 300u64;
            let mut i = 1;
            while i < parts.len() {
                if parts.get(i).copied() == Some("--interval") {
                    if let Some(v) = parts.get(i + 1).and_then(|s| s.parse::<u64>().ok()) {
                        interval = v;
                    }
                    i += 2;
                } else if let Some(p) = parts.get(i) {
                    paths.push(p);
                    i += 1;
                } else {
                    i += 1;
                }
            }
            if paths.is_empty() {
                shell_println!("Usage: wallpaper slideshow <path1> [path2 ...] [--interval N]");
            } else {
                match wallpaper::set_slideshow(&paths, interval) {
                    Ok(()) => shell_println!("Slideshow: {} images, {}s interval", paths.len(), interval),
                    Err(e) => shell_println!("Error: {:?}", e),
                }
            }
        }
        "next" => {
            match wallpaper::slideshow_next() {
                Ok(path) => shell_println!("Next: {}", path),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "prev" => {
            match wallpaper::slideshow_prev() {
                Ok(path) => shell_println!("Previous: {}", path),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "pause" => {
            wallpaper::set_slideshow_running(false);
            shell_println!("Slideshow paused");
        }
        "resume" => {
            wallpaper::set_slideshow_running(true);
            shell_println!("Slideshow resumed");
        }
        "interval" => {
            if let Some(secs) = parts.get(1).and_then(|s| s.parse::<u64>().ok()) {
                wallpaper::set_slideshow_interval(secs);
                shell_println!("Slideshow interval: {}s", secs);
            } else {
                let cfg = wallpaper::current();
                shell_println!("Interval: {}s", cfg.slideshow_interval_secs);
            }
        }
        "animated" => {
            let source = if parts.len() > 1 { parts[1..].join(" ") } else { alloc::string::String::new() };
            if source.is_empty() {
                shell_println!("Usage: wallpaper animated <source>");
            } else {
                match wallpaper::set_animated(&source) {
                    Ok(()) => shell_println!("Animated wallpaper: {}", source),
                    Err(e) => shell_println!("Error: {:?}", e),
                }
            }
        }
        "dynamic" => {
            let source = if parts.len() > 1 { parts[1..].join(" ") } else { alloc::string::String::new() };
            if source.is_empty() {
                shell_println!("Usage: wallpaper dynamic <source>");
            } else {
                match wallpaper::set_dynamic(&source) {
                    Ok(()) => shell_println!("Dynamic wallpaper: {}", source),
                    Err(e) => shell_println!("Error: {:?}", e),
                }
            }
        }
        "login" => {
            let val = parts.get(1).copied().unwrap_or("");
            if val == "on" || val == "true" || val == "yes" {
                wallpaper::set_use_for_login(true);
                shell_println!("Login screen uses desktop wallpaper");
            } else if val == "off" || val == "false" || val == "no" {
                wallpaper::set_use_for_login(false);
                shell_println!("Login screen uses separate wallpaper");
            } else {
                shell_println!("Login wallpaper: {}", if wallpaper::use_for_login() { "same" } else { "separate" });
            }
        }
        "monitor" => {
            // wallpaper monitor <id> <path>
            let mon = parts.get(1).copied().unwrap_or("");
            let path = if parts.len() > 2 { parts[2..].join(" ") } else { alloc::string::String::new() };
            if mon.is_empty() {
                shell_println!("Usage: wallpaper monitor <id> <path>");
            } else if path.is_empty() {
                let wp = wallpaper::wallpaper_for_monitor(mon);
                shell_println!("Monitor '{}': {}", mon, if wp.is_empty() { "(none)" } else { &wp });
            } else {
                match wallpaper::set_per_monitor(mon, &path) {
                    Ok(()) => shell_println!("Monitor '{}' wallpaper: {}", mon, path),
                    Err(e) => shell_println!("Error: {:?}", e),
                }
            }
        }
        "random" => {
            let val = parts.get(1).copied().unwrap_or("");
            if val == "boot" {
                let cur = wallpaper::current().random_on_boot;
                wallpaper::set_random_on_boot(!cur);
                shell_println!("Random on boot: {}", !cur);
            } else if val == "daily" {
                let cur = wallpaper::current().change_daily;
                wallpaper::set_change_daily(!cur);
                shell_println!("Change daily: {}", !cur);
            } else {
                let cfg = wallpaper::current();
                shell_println!("Random on boot: {}, daily: {}", cfg.random_on_boot, cfg.change_daily);
            }
        }
        "exclude" => {
            let pattern = if parts.len() > 1 { parts[1..].join(" ") } else { alloc::string::String::new() };
            if pattern.is_empty() {
                let cfg = wallpaper::current();
                if cfg.exclusions.is_empty() {
                    shell_println!("No exclusions");
                } else {
                    for (i, e) in cfg.exclusions.iter().enumerate() {
                        shell_println!("  [{}] {}", i, e);
                    }
                }
            } else {
                match wallpaper::add_exclusion(&pattern) {
                    Ok(()) => shell_println!("Exclusion added: {}", pattern),
                    Err(e) => shell_println!("Error: {:?}", e),
                }
            }
        }
        "unexclude" => {
            if let Some(idx) = parts.get(1).and_then(|s| s.parse::<usize>().ok()) {
                match wallpaper::remove_exclusion(idx) {
                    Ok(()) => shell_println!("Exclusion {} removed", idx),
                    Err(e) => shell_println!("Error: {:?}", e),
                }
            } else {
                shell_println!("Usage: wallpaper unexclude <index>");
            }
        }
        "history" => {
            let hist = wallpaper::history();
            if hist.is_empty() {
                shell_println!("No wallpaper history");
            } else {
                shell_println!("{:40} {:12} {}", "PATH", "SOURCE", "TIME_NS");
                for h in hist.iter().take(20) {
                    shell_println!("{:40} {:12} {}", h.path, h.source, h.set_at_ns);
                }
            }
        }
        "show" | "info" => {
            let cfg = wallpaper::current();
            shell_println!("Kind:       {}", cfg.kind.label());
            shell_println!("Image:      {}", if cfg.image_path.is_empty() { "(none)" } else { &cfg.image_path });
            shell_println!("Fit:        {}", cfg.fit_mode.label());
            shell_println!("BG Color:   {}", cfg.background_color);
            shell_println!("Offset:     ({:.2}, {:.2})", cfg.offset_x, cfg.offset_y);
            shell_println!("Login:      {}", if cfg.use_for_login { "same as desktop" } else { "separate" });
            shell_println!("Slideshow:  {} images, {}s, {}",
                cfg.slideshow_paths.len(), cfg.slideshow_interval_secs,
                if cfg.slideshow_running { "running" } else { "paused" });
            shell_println!("Random:     boot={} daily={}", cfg.random_on_boot, cfg.change_daily);
            if !cfg.per_monitor.is_empty() {
                shell_println!("Per-monitor:");
                for (mon, path) in &cfg.per_monitor {
                    shell_println!("  {} → {}", mon, path);
                }
            }
        }
        "test" => {
            shell_println!("Running wallpaper self-tests...");
            match wallpaper::self_test() {
                Ok(()) => shell_println!("All wallpaper tests passed"),
                Err(e) => shell_println!("Test failed: {:?}", e),
            }
        }
        "stats" => {
            let (slides, hist, sets, advances) = wallpaper::stats();
            shell_println!("Slideshow:  {} images", slides);
            shell_println!("History:    {}/64", hist);
            shell_println!("Sets:       {}", sets);
            shell_println!("Advances:   {}", advances);
        }
        "reset" => {
            wallpaper::clear_all();
            wallpaper::reset_stats();
            shell_println!("Wallpaper state reset");
        }
        _ => {
            shell_println!("Usage: wallpaper <subcommand>");
            shell_println!("  set <path>                    Set static wallpaper");
            shell_println!("  color <#hex>                  Set solid color");
            shell_println!("  fit [fill|fit|stretch|center|tile|span]  Get/set fit mode");
            shell_println!("  bgcolor <#hex>                Set letterbox color");
            shell_println!("  offset <x> <y>                Set crop offset (0.0-1.0)");
            shell_println!("  slideshow <p1> [p2...] [--interval N]  Set slideshow");
            shell_println!("  next / prev                   Navigate slideshow");
            shell_println!("  pause / resume                Control slideshow");
            shell_println!("  interval <secs>               Set slideshow interval");
            shell_println!("  animated <source>             Set animated wallpaper");
            shell_println!("  dynamic <source>              Set dynamic wallpaper");
            shell_println!("  login [on|off]                Login screen wallpaper");
            shell_println!("  monitor <id> [path]           Per-monitor wallpaper");
            shell_println!("  random [boot|daily]           Toggle random options");
            shell_println!("  exclude [pattern]             Add/list exclusions");
            shell_println!("  unexclude <index>             Remove exclusion");
            shell_println!("  history                       Wallpaper history");
            shell_println!("  show                          Show current config");
            shell_println!("  test                          Run self-tests");
            shell_println!("  stats                         Show statistics");
            shell_println!("  reset                         Clear all");
        }
    }
}

/// `credentials` / `cred` — OS credential store.
fn cmd_credentials(args: &str) {
    use crate::fs::credentials;
    let parts: Vec<&str> = args.split_whitespace().collect();
    let sub = parts.first().copied().unwrap_or("");
    match sub {
        "unlock" => {
            credentials::unlock();
            shell_println!("Credential store unlocked");
        }
        "lock" => {
            credentials::lock();
            shell_println!("Credential store locked");
        }
        "status" => {
            shell_println!("Store: {}", if credentials::is_unlocked() { "UNLOCKED" } else { "LOCKED" });
        }
        "store" => {
            // cred store <app> <service> <user> <secret> [kind]
            let app = parts.get(1).copied().unwrap_or("");
            let svc = parts.get(2).copied().unwrap_or("");
            let user = parts.get(3).copied().unwrap_or("");
            let secret = parts.get(4).copied().unwrap_or("");
            let kind = parts.get(5).and_then(|s| credentials::CredentialKind::from_str(s))
                .unwrap_or(credentials::CredentialKind::Password);
            if app.is_empty() || svc.is_empty() || secret.is_empty() {
                shell_println!("Usage: cred store <app> <service> <user> <secret> [kind]");
                shell_println!("Kinds: password apikey token ssh cert generic");
            } else {
                match credentials::store(app, svc, user, secret, kind) {
                    Ok(()) => shell_println!("Credential stored: {}@{}", app, svc),
                    Err(e) => shell_println!("Error: {:?}", e),
                }
            }
        }
        "get" | "retrieve" => {
            let app = parts.get(1).copied().unwrap_or("");
            let svc = parts.get(2).copied().unwrap_or("");
            if app.is_empty() || svc.is_empty() {
                shell_println!("Usage: cred get <app> <service>");
            } else {
                match credentials::retrieve(app, svc) {
                    Ok(c) => {
                        shell_println!("App:      {}", c.app_id);
                        shell_println!("Service:  {}", c.service);
                        shell_println!("User:     {}", c.username);
                        shell_println!("Kind:     {}", c.kind.label());
                        shell_println!("Secret:   {}****", &c.secret[..c.secret.len().min(2)]);
                        if !c.label.is_empty() {
                            shell_println!("Label:    {}", c.label);
                        }
                    }
                    Err(e) => shell_println!("Error: {:?}", e),
                }
            }
        }
        "delete" | "rm" => {
            let app = parts.get(1).copied().unwrap_or("");
            let svc = parts.get(2).copied().unwrap_or("");
            if app.is_empty() || svc.is_empty() {
                shell_println!("Usage: cred delete <app> <service>");
            } else {
                match credentials::delete(app, svc) {
                    Ok(()) => shell_println!("Deleted: {}@{}", app, svc),
                    Err(e) => shell_println!("Error: {:?}", e),
                }
            }
        }
        "deleteapp" => {
            let app = parts.get(1).copied().unwrap_or("");
            if app.is_empty() {
                shell_println!("Usage: cred deleteapp <app_id>");
            } else {
                let n = credentials::delete_app(app);
                shell_println!("Deleted {} credential(s) for '{}'", n, app);
            }
        }
        "list" => {
            let app = parts.get(1).copied().unwrap_or("");
            let creds = if app.is_empty() {
                credentials::list_all()
            } else {
                credentials::list_for_app(app)
            };
            if creds.is_empty() {
                shell_println!("No credentials{}", if app.is_empty() { "" } else { " for this app" });
            } else {
                shell_println!("{:16} {:24} {:20} {:10} {}",
                    "APP", "SERVICE", "USER", "KIND", "EXPIRED");
                for c in &creds {
                    shell_println!("{:16} {:24} {:20} {:10} {}",
                        c.app_id, c.service, c.username, c.kind.label(),
                        if c.expired { "YES" } else { "-" });
                }
            }
        }
        "search" => {
            let query = if parts.len() > 1 { parts[1..].join(" ") } else { alloc::string::String::new() };
            if query.is_empty() {
                shell_println!("Usage: cred search <query>");
            } else {
                let results = credentials::search(&query);
                if results.is_empty() {
                    shell_println!("No matches");
                } else {
                    shell_println!("{:16} {:24} {:20} {}",
                        "APP", "SERVICE", "USER", "KIND");
                    for c in &results {
                        shell_println!("{:16} {:24} {:20} {}",
                            c.app_id, c.service, c.username, c.kind.label());
                    }
                }
            }
        }
        "autofill" => {
            // cred autofill <app> <field> <service> [auto]
            let app = parts.get(1).copied().unwrap_or("");
            let field = parts.get(2).copied().unwrap_or("");
            let svc = parts.get(3).copied().unwrap_or("");
            if app.is_empty() {
                // List all autofill rules.
                let all = credentials::list_all();
                shell_println!("Use: cred autofill <app> to list rules for an app");
                shell_println!("     cred autofill <app> <field> <service> [auto]  to add a rule");
                let _ = all;
            } else if field.is_empty() {
                let rules = credentials::list_autofill(app);
                if rules.is_empty() {
                    shell_println!("No autofill rules for '{}'", app);
                } else {
                    shell_println!("{:16} {:16} {:24} {}",
                        "APP", "FIELD", "SERVICE", "AUTO");
                    for r in &rules {
                        shell_println!("{:16} {:16} {:24} {}",
                            r.app_id, r.field_type, r.service,
                            if r.auto { "yes" } else { "prompt" });
                    }
                }
            } else if svc.is_empty() {
                shell_println!("Usage: cred autofill <app> <field> <service> [auto]");
            } else {
                let auto = parts.get(4).copied().unwrap_or("true") != "false";
                match credentials::add_autofill(app, field, svc, auto) {
                    Ok(()) => shell_println!("Autofill rule added: {}:{} → {}", app, field, svc),
                    Err(e) => shell_println!("Error: {:?}", e),
                }
            }
        }
        "rmautofill" => {
            let app = parts.get(1).copied().unwrap_or("");
            let field = parts.get(2).copied().unwrap_or("");
            if app.is_empty() || field.is_empty() {
                shell_println!("Usage: cred rmautofill <app> <field>");
            } else {
                match credentials::remove_autofill(app, field) {
                    Ok(()) => shell_println!("Autofill rule removed"),
                    Err(e) => shell_println!("Error: {:?}", e),
                }
            }
        }
        "verify" => {
            let user = parts.get(1).copied().unwrap_or("default");
            if credentials::check_debounce(user) {
                shell_println!("Identity verified (debounce active)");
            } else {
                shell_println!("Re-verification needed");
                credentials::confirm_identity(user);
                shell_println!("Identity confirmed for '{}'", user);
            }
        }
        "label" => {
            let app = parts.get(1).copied().unwrap_or("");
            let svc = parts.get(2).copied().unwrap_or("");
            let label = if parts.len() > 3 { parts[3..].join(" ") } else { alloc::string::String::new() };
            if app.is_empty() || svc.is_empty() {
                shell_println!("Usage: cred label <app> <service> <label...>");
            } else {
                match credentials::set_label(app, svc, &label) {
                    Ok(()) => shell_println!("Label set"),
                    Err(e) => shell_println!("Error: {:?}", e),
                }
            }
        }
        "test" => {
            shell_println!("Running credential store self-tests...");
            match credentials::self_test() {
                Ok(()) => shell_println!("All credential tests passed"),
                Err(e) => shell_println!("Test failed: {:?}", e),
            }
        }
        "stats" => {
            let (creds, af, stores, retrieves) = credentials::stats();
            shell_println!("Status:    {}", if credentials::is_unlocked() { "UNLOCKED" } else { "LOCKED" });
            shell_println!("Stored:    {}/4096", creds);
            shell_println!("Autofill:  {}/1024", af);
            shell_println!("Stores:    {}", stores);
            shell_println!("Retrieves: {}", retrieves);
        }
        "reset" => {
            credentials::clear_all();
            credentials::reset_stats();
            shell_println!("Credential store reset");
        }
        _ => {
            shell_println!("Usage: credentials <subcommand>");
            shell_println!("  unlock                        Unlock store");
            shell_println!("  lock                          Lock store");
            shell_println!("  status                        Show lock status");
            shell_println!("  store <app> <svc> <user> <secret> [kind]  Store credential");
            shell_println!("  get <app> <service>           Retrieve credential");
            shell_println!("  delete <app> <service>        Delete credential");
            shell_println!("  deleteapp <app>               Delete all for app");
            shell_println!("  list [app]                    List credentials");
            shell_println!("  search <query>                Search credentials");
            shell_println!("  autofill <app> [field svc]    Add/list autofill rules");
            shell_println!("  rmautofill <app> <field>      Remove autofill rule");
            shell_println!("  verify [user]                 Check/confirm identity");
            shell_println!("  label <app> <svc> <label>     Set label");
            shell_println!("  test                          Run self-tests");
            shell_println!("  stats                         Show statistics");
            shell_println!("  reset                         Clear all");
        }
    }
}

/// `power` — power management settings.
fn cmd_power(args: &str) {
    use crate::fs::power;
    let parts: Vec<&str> = args.split_whitespace().collect();
    let sub = parts.first().copied().unwrap_or("");
    match sub {
        "profile" => { if let Some(p) = parts.get(1).and_then(|s| power::PowerProfile::from_str(s)) { power::set_profile(p); shell_println!("Profile: {}", p.label()); } else { shell_println!("Profile: {}", power::current_profile().label()); } }
        "button" => { if let Some(a) = parts.get(1).and_then(|s| power::PowerAction::from_str(s)) { power::set_power_button_action(a.clone()); shell_println!("Power button: {}", a.label()); } else { shell_println!("Power button: {}", power::config().power_button_action.label()); } }
        "lid" => { if let Some(a) = parts.get(1).and_then(|s| power::PowerAction::from_str(s)) { power::set_lid_close_action(a.clone()); shell_println!("Lid: {}", a.label()); } else { shell_println!("Lid: {}", power::config().lid_close_action.label()); } }
        "screenoff" => { if let Some(m) = parts.get(1).and_then(|s| s.parse::<u32>().ok()) { power::set_screen_off_minutes(m); shell_println!("Screen off: {}min", m); } else { shell_println!("Screen off: {}min", power::config().screen_off_minutes); } }
        "sleepafter" => { if let Some(m) = parts.get(1).and_then(|s| s.parse::<u32>().ok()) { power::set_sleep_minutes(m); shell_println!("Sleep: {}min", m); } else { shell_println!("Sleep: {}min", power::config().sleep_minutes); } }
        "battery" => { let b = power::battery_status(); if b.present { shell_println!("Battery: {}%{} health={}% {}", b.percent, if b.charging {" charging"} else {""}, b.health, b.source.label()); } else { shell_println!("No battery"); } }
        "lowbat" => { if let (Some(p), Some(a)) = (parts.get(1).and_then(|s| s.parse::<u8>().ok()), parts.get(2).and_then(|s| power::PowerAction::from_str(s))) { power::set_low_battery(p, a.clone()); shell_println!("Low: {}% -> {}", p, a.label()); } else { let c = power::config(); shell_println!("Low: {}% -> {}", c.low_battery_percent, c.low_battery_action.label()); } }
        "critical" => { if let (Some(m), Some(a)) = (parts.get(1).and_then(|s| s.parse::<u32>().ok()), parts.get(2).and_then(|s| power::PowerAction::from_str(s))) { power::set_critical_battery(m, a.clone()); shell_println!("Critical: {}min -> {}", m, a.label()); } else { let c = power::config(); shell_println!("Critical: {}min -> {}", c.critical_battery_minutes, c.critical_battery_action.label()); } }
        "idle" => { let s = parts.get(1).and_then(|s| s.parse::<u64>().ok()).unwrap_or(0); shell_println!("Idle {}s -> {}", s, power::check_idle(s).label()); }
        "autosaver" => { match parts.get(1).copied().unwrap_or("") { "on"|"true" => { power::set_auto_power_saver(true); shell_println!("Auto saver: on"); } "off"|"false" => { power::set_auto_power_saver(false); shell_println!("Auto saver: off"); } _ => { shell_println!("Auto saver: {}", power::config().auto_power_saver); } } }
        "brightness" => { if let Some(v) = parts.get(1).and_then(|s| s.parse::<u8>().ok()) { power::set_battery_brightness(v); shell_println!("Brightness: {}%", v.min(100)); } else { shell_println!("Brightness: {}%", power::config().battery_brightness); } }
        "cpulimit" => { if let Some(v) = parts.get(1).and_then(|s| s.parse::<u8>().ok()) { power::set_cpu_battery_limit(v); shell_println!("CPU limit: {}%", v.min(100)); } else { shell_println!("CPU limit: {}%", power::config().cpu_battery_limit); } }
        "simbat" => { let pct = parts.get(1).and_then(|s| s.parse::<u8>().ok()).unwrap_or(50); let min = parts.get(2).and_then(|s| s.parse::<i32>().ok()).unwrap_or(-1); let ch = parts.get(3).copied() == Some("charging"); power::handle_battery_update(pct, min, ch); shell_println!("Battery: {}% {}min{}", pct, min, if ch {" charging"} else {""}); }
        "show" | "info" => { let c = power::config(); let b = power::battery_status(); shell_println!("Profile: {}  Button: {}  Lid: {}", c.profile.label(), c.power_button_action.label(), c.lid_close_action.label()); shell_println!("Screen: {}min  Sleep: {}min  AutoSaver: {}", c.screen_off_minutes, c.sleep_minutes, c.auto_power_saver); if b.present { shell_println!("Battery: {}%{}", b.percent, if b.charging {" charging"} else {""}); } }
        "test" => { match power::self_test() { Ok(()) => shell_println!("All power tests passed"), Err(e) => shell_println!("Test failed: {:?}", e), } }
        "stats" => { let (ev, id, so, bp) = power::stats(); shell_println!("Events:{} Idles:{} Screen:{} Bat:{}", ev, id, if so {"OFF"} else {"ON"}, if bp {"yes"} else {"no"}); }
        "reset" => { power::clear_all(); power::reset_stats(); shell_println!("Power reset"); }
        _ => { shell_println!("power: profile/button/lid/screenoff/sleepafter/battery/lowbat/critical/idle/autosaver/brightness/cpulimit/simbat/show/test/stats/reset"); }
    }
}

/// `display` — display/monitor settings (resolution, DPI, scaling, layout).
fn cmd_display(args: &str) {
    use crate::fs::display;
    let parts: Vec<&str> = args.split_whitespace().collect();
    let sub = parts.first().copied().unwrap_or("");
    match sub {
        "add" => { let id = parts.get(1).copied().unwrap_or(""); let name = parts.get(2).copied().unwrap_or("Monitor"); let pw = parts.get(3).and_then(|s| s.parse::<u32>().ok()).unwrap_or(0); let ph = parts.get(4).and_then(|s| s.parse::<u32>().ok()).unwrap_or(0); if id.is_empty() { shell_println!("Usage: display add <id> [name] [phys_w_mm] [phys_h_mm]"); } else { match display::add_monitor(id, name, pw, ph) { Ok(()) => shell_println!("Added monitor '{}'", id), Err(e) => shell_println!("Error: {:?}", e), } } }
        "remove" | "rm" => { let id = parts.get(1).copied().unwrap_or(""); if id.is_empty() { shell_println!("Usage: display remove <id>"); } else { match display::remove_monitor(id) { Ok(()) => shell_println!("Removed '{}'", id), Err(e) => shell_println!("Error: {:?}", e), } } }
        "addmode" => { let id = parts.get(1).copied().unwrap_or(""); let w = parts.get(2).and_then(|s| s.parse::<u32>().ok()); let h = parts.get(3).and_then(|s| s.parse::<u32>().ok()); let hz = parts.get(4).and_then(|s| s.parse::<u32>().ok()); let pref = parts.get(5).copied() == Some("preferred"); if let (Some(w), Some(h), Some(hz)) = (w, h, hz) { match display::add_mode(id, w, h, hz, pref) { Ok(()) => shell_println!("Added {}x{}@{}Hz{}", w, h, hz, if pref {" (preferred)"} else {""}), Err(e) => shell_println!("Error: {:?}", e), } } else { shell_println!("Usage: display addmode <id> <w> <h> <hz> [preferred]"); } }
        "get" => { let id = parts.get(1).copied().unwrap_or(""); if let Some(m) = display::get_monitor(id) { shell_println!("Monitor '{}': {} {}x{}  scale={}% orient={:?} pos=({},{}) {}{}", m.id, m.name, if let Some(mode) = m.modes.get(m.active_mode) { alloc::format!("{}x{}@{}Hz", mode.width, mode.height, mode.refresh_hz) } else { String::from("(no mode)") }, m.modes.len(), m.scale_percent, m.orientation, m.pos_x, m.pos_y, if m.primary {"primary "} else {""}, if m.enabled {"ON"} else {"OFF"}); for (i, mode) in m.modes.iter().enumerate() { shell_println!("  [{}] {}x{}@{}Hz{}{}", i, mode.width, mode.height, mode.refresh_hz, if mode.preferred {" *"} else {""}, if i == m.active_mode {" (active)"} else {""}); } } else { shell_println!("Monitor '{}' not found", id); } }
        "list" | "ls" => { let monitors = display::list_monitors(); if monitors.is_empty() { shell_println!("No monitors"); } else { for m in &monitors { let active = if let Some(mode) = m.modes.get(m.active_mode) { alloc::format!("{}x{}@{}Hz", mode.width, mode.height, mode.refresh_hz) } else { String::from("(none)") }; shell_println!("{}{}: {} {} scale={}% pos=({},{}) {}", if m.primary {"*"} else {" "}, m.id, m.name, active, m.scale_percent, m.pos_x, m.pos_y, if m.enabled {"ON"} else {"OFF"}); } } }
        "mode" | "setmode" => { let id = parts.get(1).copied().unwrap_or(""); let idx = parts.get(2).and_then(|s| s.parse::<usize>().ok()); if let Some(idx) = idx { match display::set_mode(id, idx) { Ok(()) => shell_println!("Mode set to [{}] — confirm within timeout", idx), Err(e) => shell_println!("Error: {:?}", e), } } else { shell_println!("Usage: display mode <id> <mode_index>"); } }
        "res" | "resolution" => { let id = parts.get(1).copied().unwrap_or(""); let w = parts.get(2).and_then(|s| s.parse::<u32>().ok()); let h = parts.get(3).and_then(|s| s.parse::<u32>().ok()); let hz = parts.get(4).and_then(|s| s.parse::<u32>().ok()).unwrap_or(60); if let (Some(w), Some(h)) = (w, h) { match display::set_resolution(id, w, h, hz) { Ok(()) => shell_println!("Resolution: {}x{}@{}Hz — confirm within timeout", w, h, hz), Err(e) => shell_println!("Error: {:?}", e), } } else { shell_println!("Usage: display res <id> <w> <h> [hz]"); } }
        "confirm" => { match display::confirm_change() { Ok(()) => shell_println!("Change confirmed"), Err(e) => shell_println!("Error: {:?}", e), } }
        "revert" => { match display::revert_change() { Ok(()) => shell_println!("Change reverted"), Err(e) => shell_println!("Error: {:?}", e), } }
        "pending" => { if let Some(p) = display::pending_change() { shell_println!("Pending: monitor={} timeout={}s prev_mode={}", p.monitor_id, p.timeout_secs, p.previous_mode); } else { shell_println!("No pending change"); } }
        "scale" => { let id = parts.get(1).copied().unwrap_or(""); let pct = parts.get(2).and_then(|s| s.parse::<u32>().ok()); if let Some(pct) = pct { match display::set_scale(id, pct) { Ok(()) => shell_println!("Scale: {}%", pct.clamp(50, 400)), Err(e) => shell_println!("Error: {:?}", e), } } else { if let Some(m) = display::get_monitor(id) { shell_println!("Scale: {}%", m.scale_percent); } else { shell_println!("Usage: display scale <id> [percent]"); } } }
        "autoscale" => { let id = parts.get(1).copied().unwrap_or(""); match display::auto_scale(id) { Ok(pct) => shell_println!("Auto scale: {}%", pct), Err(e) => shell_println!("Error: {:?}", e), } }
        "pos" | "position" => { let id = parts.get(1).copied().unwrap_or(""); let x = parts.get(2).and_then(|s| s.parse::<i32>().ok()); let y = parts.get(3).and_then(|s| s.parse::<i32>().ok()); if let (Some(x), Some(y)) = (x, y) { match display::set_position(id, x, y) { Ok(()) => shell_println!("Position: ({},{})", x, y), Err(e) => shell_println!("Error: {:?}", e), } } else { shell_println!("Usage: display pos <id> <x> <y>"); } }
        "orient" | "orientation" => { let id = parts.get(1).copied().unwrap_or(""); let o = match parts.get(2).copied().unwrap_or("") { "landscape" | "l" => Some(display::Orientation::Landscape), "portrait" | "p" => Some(display::Orientation::Portrait), "landscape-flip" | "lf" => Some(display::Orientation::LandscapeFlipped), "portrait-flip" | "pf" => Some(display::Orientation::PortraitFlipped), _ => None, }; if let Some(o) = o { match display::set_orientation(id, o) { Ok(()) => shell_println!("Orientation set"), Err(e) => shell_println!("Error: {:?}", e), } } else { shell_println!("Usage: display orient <id> <landscape|portrait|landscape-flip|portrait-flip>"); } }
        "primary" => { let id = parts.get(1).copied().unwrap_or(""); if id.is_empty() { shell_println!("Usage: display primary <id>"); } else { match display::set_primary(id) { Ok(()) => shell_println!("Primary: {}", id), Err(e) => shell_println!("Error: {:?}", e), } } }
        "enable" => { let id = parts.get(1).copied().unwrap_or(""); match display::set_enabled(id, true) { Ok(()) => shell_println!("Enabled '{}'", id), Err(e) => shell_println!("Error: {:?}", e), } }
        "disable" => { let id = parts.get(1).copied().unwrap_or(""); match display::set_enabled(id, false) { Ok(()) => shell_println!("Disabled '{}'", id), Err(e) => shell_println!("Error: {:?}", e), } }
        "test" => { match display::self_test() { Ok(()) => shell_println!("All display tests passed"), Err(e) => shell_println!("Test failed: {:?}", e), } }
        "stats" => { let (mc, changes) = display::stats(); shell_println!("Monitors:{} ModeChanges:{}", mc, changes); }
        "reset" => { display::clear_all(); display::reset_stats(); shell_println!("Display reset"); }
        _ => { shell_println!("display: add/remove/addmode/get/list/mode/res/confirm/revert/pending/scale/autoscale/pos/orient/primary/enable/disable/test/stats/reset"); }
    }
}

/// `vdesktop` / `vd` — virtual desktops (workspaces).
fn cmd_vdesktop(args: &str) {
    use crate::fs::vdesktop;
    let parts: Vec<&str> = args.split_whitespace().collect();
    let sub = parts.first().copied().unwrap_or("");
    match sub {
        "create" | "new" => { let name = if parts.len() > 1 { parts[1..].join(" ") } else { String::from("Desktop") }; match vdesktop::create(&name) { Ok(id) => shell_println!("Created desktop #{}: {}", id, name), Err(e) => shell_println!("Error: {:?}", e), } }
        "remove" | "rm" => { let id = parts.get(1).and_then(|s| s.parse::<u32>().ok()).unwrap_or(0); if id == 0 { shell_println!("Usage: vd remove <id>"); } else { match vdesktop::remove(id) { Ok(()) => shell_println!("Removed desktop #{}", id), Err(e) => shell_println!("Error: {:?}", e), } } }
        "rename" => { let id = parts.get(1).and_then(|s| s.parse::<u32>().ok()).unwrap_or(0); let name = if parts.len() > 2 { parts[2..].join(" ") } else { String::new() }; if id == 0 || name.is_empty() { shell_println!("Usage: vd rename <id> <name>"); } else { match vdesktop::rename(id, &name) { Ok(()) => shell_println!("Renamed #{} → {}", id, name), Err(e) => shell_println!("Error: {:?}", e), } } }
        "get" => { let id = parts.get(1).and_then(|s| s.parse::<u32>().ok()).unwrap_or(0); if let Some(d) = vdesktop::get(id) { shell_println!("Desktop #{}: {} ({} windows){}{}", d.id, d.name, d.windows.len(), if d.active {" [active]"} else {""}, if d.wallpaper.is_empty() {String::new()} else {alloc::format!(" wp={}", d.wallpaper)}); for w in &d.windows { shell_println!("  window {}", w); } } else { shell_println!("Desktop #{} not found", id); } }
        "list" | "ls" => { let desktops = vdesktop::list(); if desktops.is_empty() { shell_println!("No desktops"); } else { for d in &desktops { shell_println!("{}{}: {} ({} windows){}", if d.active {"*"} else {" "}, d.id, d.name, d.windows.len(), if d.wallpaper.is_empty() {String::new()} else {alloc::format!(" wp={}", d.wallpaper)}); } } }
        "switch" | "sw" => { let id = parts.get(1).and_then(|s| s.parse::<u32>().ok()).unwrap_or(0); if id == 0 { shell_println!("Usage: vd switch <id>"); } else { match vdesktop::switch(id) { Ok(()) => shell_println!("Switched to #{}", id), Err(e) => shell_println!("Error: {:?}", e), } } }
        "next" => { match vdesktop::next() { Ok(()) => shell_println!("Now on #{}", vdesktop::current()), Err(e) => shell_println!("Error: {:?}", e), } }
        "prev" => { match vdesktop::previous() { Ok(()) => shell_println!("Now on #{}", vdesktop::current()), Err(e) => shell_println!("Error: {:?}", e), } }
        "current" => { shell_println!("Current: #{}", vdesktop::current()); }
        "addwin" => { let did = parts.get(1).and_then(|s| s.parse::<u32>().ok()).unwrap_or(0); let wid = parts.get(2).and_then(|s| s.parse::<u64>().ok()).unwrap_or(0); if did == 0 || wid == 0 { shell_println!("Usage: vd addwin <desktop_id> <window_id>"); } else { match vdesktop::add_window(did, wid) { Ok(()) => shell_println!("Added window {} to desktop #{}", wid, did), Err(e) => shell_println!("Error: {:?}", e), } } }
        "rmwin" => { let did = parts.get(1).and_then(|s| s.parse::<u32>().ok()).unwrap_or(0); let wid = parts.get(2).and_then(|s| s.parse::<u64>().ok()).unwrap_or(0); if did == 0 || wid == 0 { shell_println!("Usage: vd rmwin <desktop_id> <window_id>"); } else { match vdesktop::remove_window(did, wid) { Ok(()) => shell_println!("Removed window {} from desktop #{}", wid, did), Err(e) => shell_println!("Error: {:?}", e), } } }
        "movewin" => { let wid = parts.get(1).and_then(|s| s.parse::<u64>().ok()).unwrap_or(0); let from = parts.get(2).and_then(|s| s.parse::<u32>().ok()).unwrap_or(0); let to = parts.get(3).and_then(|s| s.parse::<u32>().ok()).unwrap_or(0); if wid == 0 || from == 0 || to == 0 { shell_println!("Usage: vd movewin <window_id> <from_desktop> <to_desktop>"); } else { match vdesktop::move_window(wid, from, to) { Ok(()) => shell_println!("Moved window {} from #{} to #{}", wid, from, to), Err(e) => shell_println!("Error: {:?}", e), } } }
        "where" => { let wid = parts.get(1).and_then(|s| s.parse::<u64>().ok()).unwrap_or(0); if wid == 0 { shell_println!("Usage: vd where <window_id>"); } else { match vdesktop::desktop_of(wid) { Some(did) => shell_println!("Window {} on desktop #{}", wid, did), None => shell_println!("Window {} not found", wid), } } }
        "visible" => { let did = parts.get(1).and_then(|s| s.parse::<u32>().ok()).unwrap_or(vdesktop::current()); let wins = vdesktop::visible_windows(did); shell_println!("Desktop #{}: {} visible windows", did, wins.len()); for w in &wins { shell_println!("  {}{}", w, if vdesktop::is_pinned(*w) {" (pinned)"} else {""}); } }
        "pin" => { let wid = parts.get(1).and_then(|s| s.parse::<u64>().ok()).unwrap_or(0); if wid == 0 { shell_println!("Usage: vd pin <window_id>"); } else { match vdesktop::pin(wid) { Ok(()) => shell_println!("Pinned window {}", wid), Err(e) => shell_println!("Error: {:?}", e), } } }
        "unpin" => { let wid = parts.get(1).and_then(|s| s.parse::<u64>().ok()).unwrap_or(0); vdesktop::unpin(wid); shell_println!("Unpinned window {}", wid); }
        "pinned" => { let pins = vdesktop::pinned_windows(); if pins.is_empty() { shell_println!("No pinned windows"); } else { for w in &pins { shell_println!("  window {}", w); } } }
        "wallpaper" | "wp" => { let id = parts.get(1).and_then(|s| s.parse::<u32>().ok()).unwrap_or(0); let path = parts.get(2).copied().unwrap_or(""); if id == 0 { shell_println!("Usage: vd wp <id> [path|clear]"); } else if path == "clear" { match vdesktop::clear_wallpaper(id) { Ok(()) => shell_println!("Cleared wallpaper for #{}", id), Err(e) => shell_println!("Error: {:?}", e), } } else if !path.is_empty() { match vdesktop::set_wallpaper(id, path) { Ok(()) => shell_println!("Set wallpaper for #{}: {}", id, path), Err(e) => shell_println!("Error: {:?}", e), } } else { if let Some(d) = vdesktop::get(id) { shell_println!("Wallpaper: {}", if d.wallpaper.is_empty() {"(global)"} else {&d.wallpaper}); } } }
        "anim" | "animation" => { if let Some(a) = parts.get(1).and_then(|s| vdesktop::SwitchAnimation::from_str(s)) { vdesktop::set_animation(a); shell_println!("Animation: {}", a.label()); } else { shell_println!("Animation: {} (none/slide/fade/overview)", vdesktop::animation().label()); } }
        "wrap" => { match parts.get(1).copied().unwrap_or("") { "on"|"true" => { vdesktop::set_wrap(true); shell_println!("Wrap: on"); } "off"|"false" => { vdesktop::set_wrap(false); shell_println!("Wrap: off"); } _ => { shell_println!("Wrap: {}", vdesktop::wrap_around()); } } }
        "init" => { match vdesktop::init_defaults() { Ok(()) => shell_println!("Initialized default desktops"), Err(e) => shell_println!("Error: {:?}", e), } }
        "reorder" => { let id = parts.get(1).and_then(|s| s.parse::<u32>().ok()).unwrap_or(0); let pos = parts.get(2).and_then(|s| s.parse::<usize>().ok()).unwrap_or(0); if id == 0 { shell_println!("Usage: vd reorder <id> <position>"); } else { match vdesktop::reorder(id, pos) { Ok(()) => shell_println!("Reordered #{} to position {}", id, pos), Err(e) => shell_println!("Error: {:?}", e), } } }
        "test" => { match vdesktop::self_test() { Ok(()) => shell_println!("All vdesktop tests passed"), Err(e) => shell_println!("Test failed: {:?}", e), } }
        "stats" => { let (dc, wc, pc, sw, mv) = vdesktop::stats(); shell_println!("Desktops:{} Windows:{} Pinned:{} Switches:{} Moves:{}", dc, wc, pc, sw, mv); }
        "reset" => { vdesktop::clear_all(); vdesktop::reset_stats(); shell_println!("Virtual desktops reset"); }
        _ => { shell_println!("vdesktop: create/remove/rename/get/list/switch/next/prev/current/addwin/rmwin/movewin/where/visible/pin/unpin/pinned/wp/anim/wrap/init/reorder/test/stats/reset"); }
    }
}

/// `keylayout` / `kbl` — keyboard layout manager.
fn cmd_keylayout(args: &str) {
    use crate::fs::keylayout;
    let parts: Vec<&str> = args.split_whitespace().collect();
    let sub = parts.first().copied().unwrap_or("");
    match sub {
        "create" | "new" => { let name = parts.get(1).copied().unwrap_or(""); let desc = if parts.len() > 2 { parts[2..].join(" ") } else { String::new() }; if name.is_empty() { shell_println!("Usage: kbl create <name> [description]"); } else { match keylayout::create_layout(name, &desc) { Ok(()) => shell_println!("Created layout '{}'", name), Err(e) => shell_println!("Error: {:?}", e), } } }
        "remove" | "rm" => { let name = parts.get(1).copied().unwrap_or(""); if name.is_empty() { shell_println!("Usage: kbl remove <name>"); } else { match keylayout::remove_layout(name) { Ok(()) => shell_println!("Removed '{}'", name), Err(e) => shell_println!("Error: {:?}", e), } } }
        "list" | "ls" => { let layouts = keylayout::list_layouts(); if layouts.is_empty() { shell_println!("No layouts"); } else { let active = keylayout::active(); for (name, desc, builtin) in &layouts { shell_println!("{}{}: {}{}", if *name == active {"*"} else {" "}, name, desc, if *builtin {" [built-in]"} else {""}); } } }
        "get" | "show" => { let name = parts.get(1).copied().unwrap_or(""); if let Some(l) = keylayout::get_layout(name) { shell_println!("Layout '{}': {} ({} remaps, {} disabled){}", l.name, l.description, l.remaps.len(), l.disabled.len(), if l.builtin {" [built-in]"} else {""}); for (&from, &to) in &l.remaps { shell_println!("  {} (0x{:02X}) → {} (0x{:02X})", keylayout::key_name(from), from, keylayout::key_name(to), to); } for &k in &l.disabled { shell_println!("  {} (0x{:02X}) [disabled]", keylayout::key_name(k), k); } } else { shell_println!("Layout '{}' not found", name); } }
        "use" | "activate" => { let name = parts.get(1).copied().unwrap_or(""); match keylayout::set_active(name) { Ok(()) => shell_println!("Active: {}", if name.is_empty() {"(none)"} else {name}), Err(e) => shell_println!("Error: {:?}", e), } }
        "active" => { let a = keylayout::active(); shell_println!("Active: {}", if a.is_empty() {"(none)"} else {&a}); }
        "remap" => { let layout = parts.get(1).copied().unwrap_or(""); let from = parts.get(2).and_then(|s| keylayout::parse_key(s)); let to = parts.get(3).and_then(|s| keylayout::parse_key(s)); if let (Some(f), Some(t)) = (from, to) { match keylayout::remap(layout, f, t) { Ok(()) => shell_println!("Mapped {} → {} in '{}'", keylayout::key_name(f), keylayout::key_name(t), layout), Err(e) => shell_println!("Error: {:?}", e), } } else { shell_println!("Usage: kbl remap <layout> <from_key> <to_key>"); } }
        "unmap" => { let layout = parts.get(1).copied().unwrap_or(""); let from = parts.get(2).and_then(|s| keylayout::parse_key(s)); if let Some(f) = from { match keylayout::unmap(layout, f) { Ok(()) => shell_println!("Unmapped {} in '{}'", keylayout::key_name(f), layout), Err(e) => shell_println!("Error: {:?}", e), } } else { shell_println!("Usage: kbl unmap <layout> <key>"); } }
        "disable" => { let layout = parts.get(1).copied().unwrap_or(""); let key = parts.get(2).and_then(|s| keylayout::parse_key(s)); if let Some(k) = key { match keylayout::disable_key(layout, k) { Ok(()) => shell_println!("Disabled {} in '{}'", keylayout::key_name(k), layout), Err(e) => shell_println!("Error: {:?}", e), } } else { shell_println!("Usage: kbl disable <layout> <key>"); } }
        "enable" => { let layout = parts.get(1).copied().unwrap_or(""); let key = parts.get(2).and_then(|s| keylayout::parse_key(s)); if let Some(k) = key { match keylayout::enable_key(layout, k) { Ok(()) => shell_println!("Enabled {} in '{}'", keylayout::key_name(k), layout), Err(e) => shell_println!("Error: {:?}", e), } } else { shell_println!("Usage: kbl enable <layout> <key>"); } }
        "translate" | "xlat" => { let key = parts.get(1).and_then(|s| keylayout::parse_key(s)); if let Some(k) = key { match keylayout::translate(k) { Some(mapped) => shell_println!("{} → {}", keylayout::key_name(k), keylayout::key_name(mapped)), None => shell_println!("{} → (disabled)", keylayout::key_name(k)), } } else { shell_println!("Usage: kbl translate <key>"); } }
        "init" => { match keylayout::init_defaults() { Ok(()) => shell_println!("Initialized default layouts"), Err(e) => shell_println!("Error: {:?}", e), } }
        "test" => { match keylayout::self_test() { Ok(()) => shell_println!("All keylayout tests passed"), Err(e) => shell_println!("Test failed: {:?}", e), } }
        "stats" => { let (lc, rc, tc, sc) = keylayout::stats(); shell_println!("Layouts:{} Remaps:{} Translates:{} Switches:{}", lc, rc, tc, sc); }
        "reset" => { keylayout::clear_all(); keylayout::reset_stats(); shell_println!("Keyboard layouts reset"); }
        _ => { shell_println!("keylayout: create/remove/list/get/use/active/remap/unmap/disable/enable/translate/init/test/stats/reset"); }
    }
}

/// `screenshot` / `scap` — screen capture.
fn cmd_screenshot(args: &str) {
    use crate::fs::screenshot;
    let parts: Vec<&str> = args.split_whitespace().collect();
    let sub = parts.first().copied().unwrap_or("");
    match sub {
        "full" | "screen" => { let w = parts.get(1).and_then(|s| s.parse::<u32>().ok()).unwrap_or(1920); let h = parts.get(2).and_then(|s| s.parse::<u32>().ok()).unwrap_or(1080); match screenshot::capture_full(w, h) { Ok(id) => shell_println!("Captured full screen #{} ({}x{})", id, w, h), Err(e) => shell_println!("Error: {:?}", e), } }
        "window" | "win" => { let wid = parts.get(1).and_then(|s| s.parse::<u64>().ok()).unwrap_or(0); let w = parts.get(2).and_then(|s| s.parse::<u32>().ok()).unwrap_or(800); let h = parts.get(3).and_then(|s| s.parse::<u32>().ok()).unwrap_or(600); if wid == 0 { shell_println!("Usage: scap window <window_id> [w] [h]"); } else { match screenshot::capture_window(wid, w, h) { Ok(id) => shell_println!("Captured window #{} ({}x{})", id, w, h), Err(e) => shell_println!("Error: {:?}", e), } } }
        "region" | "rect" => { let x = parts.get(1).and_then(|s| s.parse::<u32>().ok()); let y = parts.get(2).and_then(|s| s.parse::<u32>().ok()); let w = parts.get(3).and_then(|s| s.parse::<u32>().ok()); let h = parts.get(4).and_then(|s| s.parse::<u32>().ok()); if let (Some(x), Some(y), Some(w), Some(h)) = (x, y, w, h) { match screenshot::capture_region(x, y, w, h) { Ok(id) => shell_println!("Captured region #{} ({}x{} at {},{})", id, w, h, x, y), Err(e) => shell_println!("Error: {:?}", e), } } else { shell_println!("Usage: scap region <x> <y> <w> <h>"); } }
        "monitor" | "mon" => { let mid = parts.get(1).copied().unwrap_or(""); let w = parts.get(2).and_then(|s| s.parse::<u32>().ok()).unwrap_or(1920); let h = parts.get(3).and_then(|s| s.parse::<u32>().ok()).unwrap_or(1080); if mid.is_empty() { shell_println!("Usage: scap monitor <id> [w] [h]"); } else { match screenshot::capture_monitor(mid, w, h) { Ok(id) => shell_println!("Captured monitor '{}' #{}", mid, id), Err(e) => shell_println!("Error: {:?}", e), } } }
        "get" => { let id = parts.get(1).and_then(|s| s.parse::<u64>().ok()).unwrap_or(0); if let Some(s) = screenshot::get(id) { shell_println!("#{}: {} {}x{} {} {}", s.id, s.kind.label(), s.width, s.height, s.format.label(), s.path); } else { shell_println!("Screenshot #{} not found", id); } }
        "history" | "list" | "ls" => { let shots = screenshot::history(); if shots.is_empty() { shell_println!("No screenshots"); } else { for s in &shots { shell_println!("#{}: {} {}x{} {}", s.id, s.kind.label(), s.width, s.height, s.path); } } }
        "recent" => { let n = parts.get(1).and_then(|s| s.parse::<usize>().ok()).unwrap_or(5); let shots = screenshot::recent(n); for s in &shots { shell_println!("#{}: {} {}x{} {}", s.id, s.kind.label(), s.width, s.height, s.path); } }
        "delete" | "rm" => { let id = parts.get(1).and_then(|s| s.parse::<u64>().ok()).unwrap_or(0); match screenshot::delete(id) { Ok(()) => shell_println!("Deleted #{}", id), Err(e) => shell_println!("Error: {:?}", e), } }
        "clear" => { screenshot::clear_history(); shell_println!("History cleared"); }
        "dir" | "savedir" => { let dir = parts.get(1).copied().unwrap_or(""); if dir.is_empty() { shell_println!("Save dir: {}", screenshot::config().save_dir); } else { match screenshot::set_save_dir(dir) { Ok(()) => shell_println!("Save dir: {}", dir), Err(e) => shell_println!("Error: {:?}", e), } } }
        "format" | "fmt" => { if let Some(f) = parts.get(1).and_then(|s| screenshot::ImageFormat::from_str(s)) { screenshot::set_format(f); shell_println!("Format: {}", f.label()); } else { shell_println!("Format: {} (png/jpeg/bmp/webp)", screenshot::config().format.label()); } }
        "quality" => { if let Some(q) = parts.get(1).and_then(|s| s.parse::<u8>().ok()) { screenshot::set_jpeg_quality(q); shell_println!("JPEG quality: {}", q.clamp(1, 100)); } else { shell_println!("JPEG quality: {}", screenshot::config().jpeg_quality); } }
        "cursor" => { match parts.get(1).copied().unwrap_or("") { "on"|"true" => { screenshot::set_include_cursor(true); shell_println!("Cursor: on"); } "off"|"false" => { screenshot::set_include_cursor(false); shell_println!("Cursor: off"); } _ => { shell_println!("Cursor: {}", screenshot::config().include_cursor); } } }
        "sound" => { match parts.get(1).copied().unwrap_or("") { "on"|"true" => { screenshot::set_play_sound(true); shell_println!("Sound: on"); } "off"|"false" => { screenshot::set_play_sound(false); shell_println!("Sound: off"); } _ => { shell_println!("Sound: {}", screenshot::config().play_sound); } } }
        "delay" => { if let Some(d) = parts.get(1).and_then(|s| s.parse::<u32>().ok()) { screenshot::set_delay(d); shell_println!("Delay: {}s", d); } else { shell_println!("Delay: {}s", screenshot::config().delay_seconds); } }
        "clipboard" => { match parts.get(1).copied().unwrap_or("") { "on"|"true" => { screenshot::set_copy_to_clipboard(true); shell_println!("Clipboard: on"); } "off"|"false" => { screenshot::set_copy_to_clipboard(false); shell_println!("Clipboard: off"); } _ => { shell_println!("Clipboard: {}", screenshot::config().copy_to_clipboard); } } }
        "init" => { screenshot::init_defaults(); shell_println!("Screenshot defaults initialized"); }
        "test" => { match screenshot::self_test() { Ok(()) => shell_println!("All screenshot tests passed"), Err(e) => shell_println!("Test failed: {:?}", e), } }
        "stats" => { let (hc, cc) = screenshot::stats(); shell_println!("History:{} Captures:{}", hc, cc); }
        "reset" => { screenshot::clear_all(); screenshot::reset_stats(); shell_println!("Screenshot reset"); }
        _ => { shell_println!("screenshot: full/window/region/monitor/get/history/recent/delete/clear/dir/format/quality/cursor/sound/delay/clipboard/init/test/stats/reset"); }
    }
}

/// `a11y` / `accessibility` — accessibility subsystem.
fn cmd_a11y(args: &str) {
    use crate::fs::a11y;
    let parts: Vec<&str> = args.split_whitespace().collect();
    let sub = parts.first().copied().unwrap_or("");
    match sub {
        "regtool" => { let kind_s = parts.get(1).copied().unwrap_or(""); let name = if parts.len() > 2 { parts[2..].join(" ") } else { String::from("Tool") }; if let Some(kind) = a11y::ToolKind::from_str(kind_s) { match a11y::register_tool(kind, &name, true, true) { Ok(id) => shell_println!("Registered tool #{}: {} [{}]", id, name, kind.label()), Err(e) => shell_println!("Error: {:?}", e), } } else { shell_println!("Usage: a11y regtool <kind> [name] (kinds: reader/mag/osk/voice/switch/eye/auto/custom)"); } }
        "unregtool" => { let id = parts.get(1).and_then(|s| s.parse::<u64>().ok()).unwrap_or(0); match a11y::unregister_tool(id) { Ok(()) => shell_println!("Unregistered tool #{}", id), Err(e) => shell_println!("Error: {:?}", e), } }
        "tools" => { let tools = a11y::list_tools(); if tools.is_empty() { shell_println!("No tools registered"); } else { for t in &tools { shell_println!("#{}: {} [{}]{}", t.id, t.name, t.kind.label(), if t.active {""} else {" (inactive)"}); } } }
        "regelem" => { let wid = parts.get(1).and_then(|s| s.parse::<u64>().ok()).unwrap_or(0); let role_s = parts.get(2).copied().unwrap_or("generic"); let name = if parts.len() > 3 { parts[3..].join(" ") } else { String::from("Element") }; let role = match role_s { "button" | "btn" => a11y::ElementRole::Button, "text" | "input" => a11y::ElementRole::TextInput, "label" => a11y::ElementRole::Label, "menu" => a11y::ElementRole::Menu, "checkbox" | "check" => a11y::ElementRole::Checkbox, "slider" => a11y::ElementRole::Slider, "list" => a11y::ElementRole::List, "link" => a11y::ElementRole::Link, _ => a11y::ElementRole::Generic, }; match a11y::register_element(wid, role, &name, (0, 0, 100, 30)) { Ok(id) => shell_println!("Registered element #{}: {} [{}] in window {}", id, name, role.label(), wid), Err(e) => shell_println!("Error: {:?}", e), } }
        "rmelem" => { let id = parts.get(1).and_then(|s| s.parse::<u64>().ok()).unwrap_or(0); match a11y::remove_element(id) { Ok(()) => shell_println!("Removed element #{}", id), Err(e) => shell_println!("Error: {:?}", e), } }
        "focus" => { let id = parts.get(1).and_then(|s| s.parse::<u64>().ok()).unwrap_or(0); match a11y::set_focus(id) { Ok(()) => shell_println!("Focused element #{}", id), Err(e) => shell_println!("Error: {:?}", e), } }
        "focused" => { match a11y::focused_element() { Some(e) => shell_println!("Focused: #{} [{}] '{}'", e.id, e.role.label(), e.name), None => shell_println!("No focused element"), } }
        "elems" => { let wid = parts.get(1).and_then(|s| s.parse::<u64>().ok()).unwrap_or(0); let elems = a11y::elements_in_window(wid); if elems.is_empty() { shell_println!("No elements in window {}", wid); } else { for e in &elems { shell_println!("  #{}: [{}] '{}'{}", e.id, e.role.label(), e.name, if e.focused {" *"} else {""}); } } }
        "hit" => { let x = parts.get(1).and_then(|s| s.parse::<i32>().ok()).unwrap_or(0); let y = parts.get(2).and_then(|s| s.parse::<i32>().ok()).unwrap_or(0); match a11y::element_at(x, y) { Some(e) => shell_println!("Hit: #{} [{}] '{}'", e.id, e.role.label(), e.name), None => shell_println!("No element at ({},{})", x, y), } }
        "inject" => { let what = parts.get(1).copied().unwrap_or(""); match what { "key" => { let code = parts.get(2).and_then(|s| s.parse::<u16>().ok()).unwrap_or(0); let _ = a11y::inject_key(code, true); let _ = a11y::inject_key(code, false); shell_println!("Injected key 0x{:02X}", code); } "click" => { let x = parts.get(2).and_then(|s| s.parse::<i32>().ok()).unwrap_or(0); let y = parts.get(3).and_then(|s| s.parse::<i32>().ok()).unwrap_or(0); let _ = a11y::inject_click(x, y, 1); shell_println!("Injected click at ({},{})", x, y); } "text" => { let text = if parts.len() > 2 { parts[2..].join(" ") } else { String::new() }; let _ = a11y::inject_text(&text); shell_println!("Injected text: {}", text); } _ => { shell_println!("Usage: a11y inject key|click|text ..."); } } }
        "announce" => { let prio_s = parts.get(1).copied().unwrap_or("normal"); let text = if parts.len() > 2 { parts[2..].join(" ") } else { String::new() }; let prio = a11y::AnnouncePriority::from_str(prio_s).unwrap_or(a11y::AnnouncePriority::Normal); match a11y::announce(&text, prio) { Ok(id) => shell_println!("Announcement #{}: [{}] {}", id, prio.label(), text), Err(e) => shell_println!("Error: {:?}", e), } }
        "pending" => { let msgs = a11y::pending_announcements(); if msgs.is_empty() { shell_println!("No pending announcements"); } else { for m in &msgs { shell_println!("#{}: [{}] {}", m.id, m.priority.label(), m.text); } } }
        "contrast" => { match parts.get(1).copied().unwrap_or("") { "on"|"true" => { a11y::set_high_contrast(true); shell_println!("High contrast: on"); } "off"|"false" => { a11y::set_high_contrast(false); shell_println!("High contrast: off"); } _ => { shell_println!("High contrast: {}", a11y::config().high_contrast); } } }
        "motion" => { match parts.get(1).copied().unwrap_or("") { "on"|"true" => { a11y::set_reduce_motion(true); shell_println!("Reduce motion: on"); } "off"|"false" => { a11y::set_reduce_motion(false); shell_println!("Reduce motion: off"); } _ => { shell_println!("Reduce motion: {}", a11y::config().reduce_motion); } } }
        "reader" => { match parts.get(1).copied().unwrap_or("") { "on"|"true" => { a11y::set_screen_reader(true); shell_println!("Screen reader: on"); } "off"|"false" => { a11y::set_screen_reader(false); shell_println!("Screen reader: off"); } _ => { shell_println!("Screen reader: {}", a11y::config().screen_reader_active); } } }
        "fontscale" => { if let Some(v) = parts.get(1).and_then(|s| s.parse::<u32>().ok()) { a11y::set_font_scale(v); shell_println!("Font scale: {}%", v.clamp(50, 500)); } else { shell_println!("Font scale: {}%", a11y::config().font_scale); } }
        "sticky" => { match parts.get(1).copied().unwrap_or("") { "on"|"true" => { a11y::set_sticky_keys(true); shell_println!("Sticky keys: on"); } "off"|"false" => { a11y::set_sticky_keys(false); shell_println!("Sticky keys: off"); } _ => { shell_println!("Sticky keys: {}", a11y::config().sticky_keys); } } }
        "mousekeys" => { match parts.get(1).copied().unwrap_or("") { "on"|"true" => { a11y::set_mouse_keys(true); shell_println!("Mouse keys: on"); } "off"|"false" => { a11y::set_mouse_keys(false); shell_println!("Mouse keys: off"); } _ => { shell_println!("Mouse keys: {}", a11y::config().mouse_keys); } } }
        "cursor" => { if let Some(v) = parts.get(1).and_then(|s| s.parse::<u32>().ok()) { a11y::set_cursor_scale(v); shell_println!("Cursor scale: {}%", v.clamp(50, 500)); } else { shell_println!("Cursor scale: {}%", a11y::config().cursor_scale); } }
        "captions" => { match parts.get(1).copied().unwrap_or("") { "on"|"true" => { a11y::set_captions(true); shell_println!("Captions: on"); } "off"|"false" => { a11y::set_captions(false); shell_println!("Captions: off"); } _ => { shell_println!("Captions: {}", a11y::config().captions); } } }
        "show" | "config" => { let cfg = a11y::config(); shell_println!("Contrast:{} Motion:{} Reader:{} Font:{}% Sticky:{} Mouse:{} Cursor:{}% Captions:{}", cfg.high_contrast, cfg.reduce_motion, cfg.screen_reader_active, cfg.font_scale, cfg.sticky_keys, cfg.mouse_keys, cfg.cursor_scale, cfg.captions); }
        "test" => { match a11y::self_test() { Ok(()) => shell_println!("All a11y tests passed"), Err(e) => shell_println!("Test failed: {:?}", e), } }
        "stats" => { let (tc, ec, ic, ac) = a11y::stats(); shell_println!("Tools:{} Elements:{} Injections:{} Announcements:{}", tc, ec, ic, ac); }
        "reset" => { a11y::clear_all(); a11y::reset_stats(); shell_println!("Accessibility reset"); }
        _ => { shell_println!("a11y: regtool/unregtool/tools/regelem/rmelem/focus/focused/elems/hit/inject/announce/pending/contrast/motion/reader/fontscale/sticky/mousekeys/cursor/captions/show/test/stats/reset"); }
    }
}

/// `ime` — input method editor (multilingual text input, emoji).
fn cmd_ime(args: &str) {
    use crate::fs::ime;
    let parts: Vec<&str> = args.split_whitespace().collect();
    let sub = parts.first().copied().unwrap_or("");
    match sub {
        "register" | "reg" => { let id = parts.get(1).copied().unwrap_or(""); let name = parts.get(2).copied().unwrap_or("Method"); let lang = parts.get(3).copied().unwrap_or("en"); let ind = parts.get(4).copied().unwrap_or("?"); let compose = parts.get(5).copied() != Some("false"); if id.is_empty() { shell_println!("Usage: ime reg <id> [name] [lang] [indicator] [compose]"); } else { match ime::register_method(id, name, lang, ind, compose) { Ok(()) => shell_println!("Registered '{}' ({} [{}])", id, name, lang), Err(e) => shell_println!("Error: {:?}", e), } } }
        "unregister" | "unreg" => { let id = parts.get(1).copied().unwrap_or(""); match ime::unregister_method(id) { Ok(()) => shell_println!("Unregistered '{}'", id), Err(e) => shell_println!("Error: {:?}", e), } }
        "list" | "ls" => { let methods = ime::list_methods(); if methods.is_empty() { shell_println!("No input methods"); } else { let active = ime::active(); for m in &methods { shell_println!("{}{}: {} ({}) [{}]{}", if m.id == active {"*"} else {" "}, m.id, m.name, m.language, m.indicator, if m.builtin {" built-in"} else {""}); } } }
        "use" | "activate" => { let id = parts.get(1).copied().unwrap_or(""); match ime::set_active(id) { Ok(()) => shell_println!("Active: {} [{}]", if id.is_empty() {"(none)"} else {id}, ime::active_indicator()), Err(e) => shell_println!("Error: {:?}", e), } }
        "active" => { shell_println!("Active: {} [{}]", { let a = ime::active(); if a.is_empty() { String::from("(none)") } else { a } }, ime::active_indicator()); }
        "cycle" => { let next = ime::cycle_next(); shell_println!("Switched to: {} [{}]", if next.is_empty() {"(none)"} else {&next}, ime::active_indicator()); }
        "type" | "key" => { for ch in parts.get(1).copied().unwrap_or("").chars() { match ime::process_key(ch) { ime::ImeResult::Consumed => shell_println!("  '{}' → consumed", ch), ime::ImeResult::Commit(t) => shell_println!("  '{}' → commit '{}'", ch, t), ime::ImeResult::PassThrough => shell_println!("  '{}' → passthrough", ch), ime::ImeResult::Cancelled => shell_println!("  '{}' → cancelled", ch), } } }
        "commit" => { let idx = parts.get(1).and_then(|s| s.parse::<usize>().ok()).unwrap_or(0); match ime::commit_candidate(idx) { Ok(t) => shell_println!("Committed: {}", t), Err(e) => shell_println!("Error: {:?}", e), } }
        "cancel" => { ime::cancel_composition(); shell_println!("Composition cancelled"); }
        "comp" | "composition" => { let c = ime::composition(); if c.active { shell_println!("Buffer: '{}' ({} candidates, selected={})", c.buffer, c.candidates.len(), c.selected); for (i, cand) in c.candidates.iter().enumerate() { shell_println!("  [{}]{} {}", i, if i == c.selected {" *"} else {""}, cand); } } else { shell_println!("No active composition"); } }
        "emoji" => { let query = if parts.len() > 1 { parts[1..].join(" ") } else { String::new() }; if query.is_empty() { let recent = ime::recent_emoji(); if recent.is_empty() { shell_println!("No recent emoji"); } else { shell_println!("Recent: {}", recent.join(" ")); } } else { let results = ime::search_emoji(&query); if results.is_empty() { shell_println!("No emoji found for '{}'", query); } else { for e in &results { shell_println!("  {} {} ({})", e.emoji, e.name, e.category); } } } }
        "pick" => { let emoji = parts.get(1).copied().unwrap_or(""); if emoji.is_empty() { shell_println!("Usage: ime pick <emoji>"); } else { ime::select_emoji(emoji); shell_println!("Selected: {}", emoji); } }
        "picker" => { match parts.get(1).copied().unwrap_or("") { "open" => { ime::set_emoji_picker(true); shell_println!("Emoji picker: open"); } "close" => { ime::set_emoji_picker(false); shell_println!("Emoji picker: closed"); } _ => { shell_println!("Emoji picker: {}", if ime::emoji_picker_open() {"open"} else {"closed"}); } } }
        "init" => { match ime::init_defaults() { Ok(()) => shell_println!("IME defaults initialized"), Err(e) => shell_println!("Error: {:?}", e), } }
        "test" => { match ime::self_test() { Ok(()) => shell_println!("All IME tests passed"), Err(e) => shell_println!("Test failed: {:?}", e), } }
        "stats" => { let (mc, ec, cc, kc) = ime::stats(); shell_println!("Methods:{} Emoji:{} Commits:{} Keys:{}", mc, ec, cc, kc); }
        "reset" => { ime::clear_all(); ime::reset_stats(); shell_println!("IME reset"); }
        _ => { shell_println!("ime: register/unregister/list/use/active/cycle/type/commit/cancel/comp/emoji/pick/picker/init/test/stats/reset"); }
    }
}

/// `netindicator` / `netind` — network status indicator.
fn cmd_netindicator(args: &str) {
    use crate::fs::netindicator;
    let parts: Vec<&str> = args.split_whitespace().collect();
    let sub = parts.first().copied().unwrap_or("");
    match sub {
        "addif" => { let name = parts.get(1).copied().unwrap_or(""); let t = parts.get(2).and_then(|s| netindicator::InterfaceType::from_str(s)).unwrap_or(netindicator::InterfaceType::Ethernet); let mac = parts.get(3).copied().unwrap_or("00:00:00:00:00:00"); if name.is_empty() { shell_println!("Usage: netind addif <name> [type] [mac]"); } else { match netindicator::update_interface(name, t, mac) { Ok(()) => shell_println!("Added {} ({})", name, t.label()), Err(e) => shell_println!("Error: {:?}", e), } } }
        "rmif" => { let name = parts.get(1).copied().unwrap_or(""); match netindicator::remove_interface(name) { Ok(()) => shell_println!("Removed {}", name), Err(e) => shell_println!("Error: {:?}", e), } }
        "state" => { let name = parts.get(1).copied().unwrap_or(""); let s = parts.get(2).and_then(|s| netindicator::ConnectionState::from_str(s)); if let Some(s) = s { match netindicator::set_state(name, s) { Ok(()) => shell_println!("{}: {}", name, s.label()), Err(e) => shell_println!("Error: {:?}", e), } } else { shell_println!("Usage: netind state <name> <connected|disconnected|...>"); } }
        "ip" => { let name = parts.get(1).copied().unwrap_or(""); let ip = parts.get(2).copied().unwrap_or(""); let gw = parts.get(3).copied().unwrap_or(""); match netindicator::set_ip(name, ip, gw) { Ok(()) => shell_println!("{}: ip={} gw={}", name, ip, gw), Err(e) => shell_println!("Error: {:?}", e), } }
        "speed" => { let name = parts.get(1).copied().unwrap_or(""); let mbps = parts.get(2).and_then(|s| s.parse::<u32>().ok()).unwrap_or(0); match netindicator::set_speed(name, mbps) { Ok(()) => shell_println!("{}: {}Mbps", name, mbps), Err(e) => shell_println!("Error: {:?}", e), } }
        "list" | "ls" => { let ifaces = netindicator::list_interfaces(); if ifaces.is_empty() { shell_println!("No interfaces"); } else { for i in &ifaces { shell_println!("{}: {} [{}]{}{}", i.name, i.iface_type.label(), i.state.label(), if i.ipv4.is_empty() {String::new()} else {alloc::format!(" ip={}", i.ipv4)}, if !i.ssid.is_empty() {alloc::format!(" ssid={} {}%", i.ssid, i.signal)} else {String::new()}); } } }
        "status" => { let (cs, desc) = netindicator::connection_summary(); shell_println!("{}: {}", cs.label(), desc); }
        "scan" => { netindicator::scan_wifi(); shell_println!("WiFi scan started"); }
        "wifi" => { let nets = netindicator::wifi_networks(); if nets.is_empty() { shell_println!("No WiFi networks"); } else { for n in &nets { shell_println!("  {} {}% [{}] ch{}{}", n.ssid, n.signal, n.security.label(), n.channel, if n.saved {" (saved)"} else {""}); } } }
        "report" => { let ssid = parts.get(1).copied().unwrap_or(""); let sig = parts.get(2).and_then(|s| s.parse::<u8>().ok()).unwrap_or(50); let sec = match parts.get(3).copied().unwrap_or("wpa2") { "open" => netindicator::WifiSecurity::Open, "wep" => netindicator::WifiSecurity::Wep, "wpa" => netindicator::WifiSecurity::Wpa, "wpa3" => netindicator::WifiSecurity::WPA3, _ => netindicator::WifiSecurity::WPA2, }; let ch = parts.get(4).and_then(|s| s.parse::<u32>().ok()).unwrap_or(6); if ssid.is_empty() { shell_println!("Usage: netind report <ssid> [signal] [security] [channel]"); } else { netindicator::report_wifi(ssid, sig, sec, ch, 2437); shell_println!("Reported {} {}% {}", ssid, sig, sec.label()); } }
        "connect" => { let ssid = parts.get(1).copied().unwrap_or(""); let pw = parts.get(2).copied().unwrap_or(""); if ssid.is_empty() { shell_println!("Usage: netind connect <ssid> [password]"); } else { match netindicator::connect_wifi(ssid, pw) { Ok(()) => shell_println!("Connected to {}", ssid), Err(e) => shell_println!("Error: {:?}", e), } } }
        "disconnect" => { match netindicator::disconnect_wifi() { Ok(()) => shell_println!("Disconnected"), Err(e) => shell_println!("Error: {:?}", e), } }
        "save" => { let ssid = parts.get(1).copied().unwrap_or(""); if ssid.is_empty() { shell_println!("Usage: netind save <ssid>"); } else { let _ = netindicator::save_profile(ssid, netindicator::WifiSecurity::WPA2, true); shell_println!("Saved profile for {}", ssid); } }
        "forget" => { let ssid = parts.get(1).copied().unwrap_or(""); match netindicator::forget_profile(ssid) { Ok(()) => shell_println!("Forgot {}", ssid), Err(e) => shell_println!("Error: {:?}", e), } }
        "profiles" => { let profs = netindicator::list_profiles(); if profs.is_empty() { shell_println!("No saved profiles"); } else { for p in &profs { shell_println!("  {} [{}]{}{}", p.ssid, p.security.label(), if p.auto_connect {" auto"} else {""}, if p.metered {" metered"} else {""}); } } }
        "airplane" => { match parts.get(1).copied().unwrap_or("") { "on"|"true" => { netindicator::set_airplane_mode(true); shell_println!("Airplane mode: on"); } "off"|"false" => { netindicator::set_airplane_mode(false); shell_println!("Airplane mode: off"); } _ => { shell_println!("Airplane mode: {}", netindicator::airplane_mode()); } } }
        "dns" => { match parts.get(1).copied().unwrap_or("") { "auto" => { netindicator::set_dns_auto(); shell_println!("DNS: auto"); } "manual" => { let servers: Vec<&str> = parts[2..].to_vec(); if servers.is_empty() { shell_println!("Usage: netind dns manual <server1> [server2]"); } else { let _ = netindicator::set_dns_manual(&servers); shell_println!("DNS: manual {:?}", servers); } } _ => { let (mode, servers) = netindicator::dns_config(); shell_println!("DNS: {:?} {:?}", mode, servers); } } }
        "test" => { match netindicator::self_test() { Ok(()) => shell_println!("All netindicator tests passed"), Err(e) => shell_println!("Test failed: {:?}", e), } }
        "stats" => { let (ic, wc, pc, sc, cc) = netindicator::stats(); shell_println!("Interfaces:{} WiFi:{} Profiles:{} Scans:{} Connects:{}", ic, wc, pc, sc, cc); }
        "reset" => { netindicator::clear_all(); netindicator::reset_stats(); shell_println!("Network indicator reset"); }
        _ => { shell_println!("netindicator: addif/rmif/state/ip/speed/list/status/scan/wifi/report/connect/disconnect/save/forget/profiles/airplane/dns/test/stats/reset"); }
    }
}

/// `winsnap` / `wsnap` — window snapping and tiling.
fn cmd_winsnap(args: &str) {
    use crate::fs::winsnap;
    let parts: Vec<&str> = args.split_whitespace().collect();
    let sub = parts.first().copied().unwrap_or("");
    match sub {
        "snap" => { let wid = parts.get(1).and_then(|s| s.parse::<u64>().ok()).unwrap_or(0); let pos_s = parts.get(2).copied().unwrap_or(""); if let Some(pos) = winsnap::SnapPosition::from_str(pos_s) { let (x, y, w, h) = winsnap::snap(wid, pos, 0, 0, 800, 600); shell_println!("Window {} → {} at ({},{} {}x{})", wid, pos.label(), x, y, w, h); } else { shell_println!("Usage: wsnap snap <wid> <left|right|top|bottom|tl|tr|bl|br|max|l3|c3|r3|restore>"); } }
        "unsnap" => { let wid = parts.get(1).and_then(|s| s.parse::<u64>().ok()).unwrap_or(0); if let Some((x, y, w, h)) = winsnap::unsnap(wid) { shell_println!("Restored {} to ({},{} {}x{})", wid, x, y, w, h); } else { shell_println!("Window {} not snapped", wid); } }
        "state" => { let wid = parts.get(1).and_then(|s| s.parse::<u64>().ok()).unwrap_or(0); match winsnap::window_snap_state(wid) { Some(p) => shell_println!("Window {}: {}", wid, p.label()), None => shell_println!("Window {} not snapped", wid), } }
        "detect" => { let cx = parts.get(1).and_then(|s| s.parse::<i32>().ok()).unwrap_or(0); let cy = parts.get(2).and_then(|s| s.parse::<i32>().ok()).unwrap_or(0); match winsnap::detect_zone(cx, cy) { Some(p) => shell_println!("Zone at ({},{}): {}", cx, cy, p.label()), None => shell_println!("No snap zone at ({},{})", cx, cy), } }
        "remove" => { let wid = parts.get(1).and_then(|s| s.parse::<u64>().ok()).unwrap_or(0); winsnap::remove_window(wid); shell_println!("Removed tracking for window {}", wid); }
        "layouts" | "ls" => { let layouts = winsnap::list_layouts(); if layouts.is_empty() { shell_println!("No layouts"); } else { for l in &layouts { shell_println!("{}: {} ({} zones)", l.name, l.description, l.zones.len()); for z in &l.zones { shell_println!("  {} ({},{} {}x{})", z.name, z.x_pct, z.y_pct, z.w_pct, z.h_pct); } } } }
        "addlayout" => { let name = parts.get(1).copied().unwrap_or(""); let desc = parts[2..].join(" "); if name.is_empty() { shell_println!("Usage: wsnap addlayout <name> <desc>"); } else { match winsnap::add_layout(name, &desc) { Ok(()) => shell_println!("Layout '{}' created", name), Err(e) => shell_println!("Error: {:?}", e), } } }
        "rmlayout" => { let name = parts.get(1).copied().unwrap_or(""); match winsnap::remove_layout(name) { Ok(()) => shell_println!("Removed layout '{}'", name), Err(e) => shell_println!("Error: {:?}", e), } }
        "addzone" => { let lay = parts.get(1).copied().unwrap_or(""); let zname = parts.get(2).copied().unwrap_or(""); let xp = parts.get(3).and_then(|s| s.parse::<u32>().ok()).unwrap_or(0); let yp = parts.get(4).and_then(|s| s.parse::<u32>().ok()).unwrap_or(0); let wp = parts.get(5).and_then(|s| s.parse::<u32>().ok()).unwrap_or(0); let hp = parts.get(6).and_then(|s| s.parse::<u32>().ok()).unwrap_or(0); if lay.is_empty() || zname.is_empty() { shell_println!("Usage: wsnap addzone <layout> <name> <x> <y> <w> <h> (0-1000)"); } else { match winsnap::add_zone(lay, zname, xp, yp, wp, hp) { Ok(()) => shell_println!("Zone '{}' added to '{}'", zname, lay), Err(e) => shell_println!("Error: {:?}", e), } } }
        "enabled" => { match parts.get(1).copied().unwrap_or("") { "on"|"true" => { winsnap::set_enabled(true); shell_println!("Snapping enabled"); } "off"|"false" => { winsnap::set_enabled(false); shell_println!("Snapping disabled"); } _ => { shell_println!("Snapping: {}", winsnap::config().enabled); } } }
        "edge" => { if let Some(px) = parts.get(1).and_then(|s| s.parse::<u32>().ok()) { winsnap::set_edge_distance(px); shell_println!("Edge distance: {}px", px); } else { shell_println!("Edge distance: {}px", winsnap::config().edge_distance); } }
        "preview" => { match parts.get(1).copied().unwrap_or("") { "on"|"true" => { winsnap::set_show_preview(true); shell_println!("Preview: on"); } "off"|"false" => { winsnap::set_show_preview(false); shell_println!("Preview: off"); } _ => { shell_println!("Preview: {}", winsnap::config().show_preview); } } }
        "animation" => { if let Some(ms) = parts.get(1).and_then(|s| s.parse::<u32>().ok()) { winsnap::set_animation_ms(ms); shell_println!("Animation: {}ms", ms); } else { shell_println!("Animation: {}ms", winsnap::config().animation_ms); } }
        "corner" => { match parts.get(1).copied().unwrap_or("") { "on"|"true" => { winsnap::set_corner_snap(true); shell_println!("Corner snap: on"); } "off"|"false" => { winsnap::set_corner_snap(false); shell_println!("Corner snap: off"); } _ => { shell_println!("Corner snap: {}", winsnap::config().corner_snap); } } }
        "thirds" => { match parts.get(1).copied().unwrap_or("") { "on"|"true" => { winsnap::set_thirds(true); shell_println!("Thirds: on"); } "off"|"false" => { winsnap::set_thirds(false); shell_println!("Thirds: off"); } _ => { shell_println!("Thirds: {}", winsnap::config().thirds); } } }
        "screen" => { let w = parts.get(1).and_then(|s| s.parse::<u32>().ok()).unwrap_or(0); let h = parts.get(2).and_then(|s| s.parse::<u32>().ok()).unwrap_or(0); if w > 0 && h > 0 { winsnap::set_screen(w, h); shell_println!("Screen: {}x{}", w, h); } else { shell_println!("Usage: wsnap screen <width> <height>"); } }
        "config" => { let cfg = winsnap::config(); shell_println!("Enabled: {}  Edge: {}px  Preview: {}  Anim: {}ms  Corner: {}  Thirds: {}", cfg.enabled, cfg.edge_distance, cfg.show_preview, cfg.animation_ms, cfg.corner_snap, cfg.thirds); }
        "init" => { winsnap::init_defaults(); shell_println!("Default layouts initialized"); }
        "test" => { match winsnap::self_test() { Ok(()) => shell_println!("All winsnap tests passed"), Err(e) => shell_println!("Test failed: {:?}", e), } }
        "stats" => { let (sc, lc, ops) = winsnap::stats(); shell_println!("Snapped:{} Layouts:{} Ops:{}", sc, lc, ops); }
        "reset" => { winsnap::clear_all(); winsnap::reset_stats(); shell_println!("Window snap reset"); }
        _ => { shell_println!("winsnap: snap/unsnap/state/detect/remove/layouts/addlayout/rmlayout/addzone/enabled/edge/preview/animation/corner/thirds/screen/config/init/test/stats/reset"); }
    }
}

/// `colorpicker` / `cpick` — system color picker.
fn cmd_colorpicker(args: &str) {
    use crate::fs::colorpicker;
    let parts: Vec<&str> = args.split_whitespace().collect();
    let sub = parts.first().copied().unwrap_or("");
    match sub {
        "open" => { let hex = parts.get(1).copied().unwrap_or("#000000"); let c = colorpicker::Color::from_hex(hex).unwrap_or(colorpicker::Color::rgb(0, 0, 0)); let alpha = parts.get(2).copied() == Some("alpha"); match colorpicker::open_picker(c, alpha) { Ok(id) => shell_println!("Picker #{} opened ({})", id, c.to_hex()), Err(e) => shell_println!("Error: {:?}", e), } }
        "rgb" => { let pid = parts.get(1).and_then(|s| s.parse::<u64>().ok()).unwrap_or(0); let r = parts.get(2).and_then(|s| s.parse::<u8>().ok()).unwrap_or(0); let g = parts.get(3).and_then(|s| s.parse::<u8>().ok()).unwrap_or(0); let b = parts.get(4).and_then(|s| s.parse::<u8>().ok()).unwrap_or(0); match colorpicker::set_rgb(pid, r, g, b) { Ok(()) => shell_println!("#{}: rgb({},{},{})", pid, r, g, b), Err(e) => shell_println!("Error: {:?}", e), } }
        "hsv" => { let pid = parts.get(1).and_then(|s| s.parse::<u64>().ok()).unwrap_or(0); let h = parts.get(2).and_then(|s| s.parse::<u16>().ok()).unwrap_or(0); let s_val = parts.get(3).and_then(|s| s.parse::<u8>().ok()).unwrap_or(0); let v = parts.get(4).and_then(|s| s.parse::<u8>().ok()).unwrap_or(0); match colorpicker::set_hsv(pid, h, s_val, v) { Ok(()) => shell_println!("#{}: hsv({},{},{})", pid, h, s_val, v), Err(e) => shell_println!("Error: {:?}", e), } }
        "hsl" => { let pid = parts.get(1).and_then(|s| s.parse::<u64>().ok()).unwrap_or(0); let h = parts.get(2).and_then(|s| s.parse::<u16>().ok()).unwrap_or(0); let s_val = parts.get(3).and_then(|s| s.parse::<u8>().ok()).unwrap_or(0); let l = parts.get(4).and_then(|s| s.parse::<u8>().ok()).unwrap_or(0); match colorpicker::set_hsl(pid, h, s_val, l) { Ok(()) => shell_println!("#{}: hsl({},{},{})", pid, h, s_val, l), Err(e) => shell_println!("Error: {:?}", e), } }
        "hex" => { let pid = parts.get(1).and_then(|s| s.parse::<u64>().ok()).unwrap_or(0); let hex = parts.get(2).copied().unwrap_or(""); match colorpicker::set_hex(pid, hex) { Ok(()) => shell_println!("#{}: {}", pid, hex), Err(e) => shell_println!("Error: {:?}", e), } }
        "alpha" => { let pid = parts.get(1).and_then(|s| s.parse::<u64>().ok()).unwrap_or(0); let a = parts.get(2).and_then(|s| s.parse::<u8>().ok()).unwrap_or(255); match colorpicker::set_alpha(pid, a) { Ok(()) => shell_println!("#{}: alpha={}", pid, a), Err(e) => shell_println!("Error: {:?}", e), } }
        "model" => { let pid = parts.get(1).and_then(|s| s.parse::<u64>().ok()).unwrap_or(0); let m = parts.get(2).and_then(|s| colorpicker::ColorModel::from_str(s)); if let Some(m) = m { match colorpicker::set_model(pid, m) { Ok(()) => shell_println!("#{}: model={}", pid, m.label()), Err(e) => shell_println!("Error: {:?}", e), } } else { shell_println!("Models: rgb, hsv, hsl, hex, cmyk"); } }
        "get" => { let pid = parts.get(1).and_then(|s| s.parse::<u64>().ok()).unwrap_or(0); match colorpicker::get_picker(pid) { Ok(p) => { let (h, s, v) = p.color.to_hsv(); let (hl, sl, l) = p.color.to_hsl(); shell_println!("#{}: {} rgb({},{},{}) a={} hsv({},{},{}) hsl({},{},{}) model={}", p.id, p.color.to_hex(), p.color.r, p.color.g, p.color.b, p.color.a, h, s, v, hl, sl, l, p.model.label()); } Err(e) => shell_println!("Error: {:?}", e), } }
        "revert" => { let pid = parts.get(1).and_then(|s| s.parse::<u64>().ok()).unwrap_or(0); match colorpicker::revert(pid) { Ok(c) => shell_println!("#{}: reverted to {}", pid, c.to_hex()), Err(e) => shell_println!("Error: {:?}", e), } }
        "confirm" | "ok" => { let pid = parts.get(1).and_then(|s| s.parse::<u64>().ok()).unwrap_or(0); match colorpicker::confirm(pid) { Ok(c) => shell_println!("Selected: {}", c.to_hex()), Err(e) => shell_println!("Error: {:?}", e), } }
        "cancel" => { let pid = parts.get(1).and_then(|s| s.parse::<u64>().ok()).unwrap_or(0); match colorpicker::cancel(pid) { Ok(()) => shell_println!("Picker #{} cancelled", pid), Err(e) => shell_println!("Error: {:?}", e), } }
        "sample" => { let x = parts.get(1).and_then(|s| s.parse::<u32>().ok()).unwrap_or(0); let y = parts.get(2).and_then(|s| s.parse::<u32>().ok()).unwrap_or(0); let c = colorpicker::sample_screen(x, y); shell_println!("Sampled ({},{}): {}", x, y, c.to_hex()); }
        "recent" => { let colors = colorpicker::recent_colors(); if colors.is_empty() { shell_println!("No recent colors"); } else { for c in &colors { shell_println!("  {}", c.to_hex()); } } }
        "mkpal" => { let name = parts.get(1).copied().unwrap_or(""); if name.is_empty() { shell_println!("Usage: cpick mkpal <name>"); } else { match colorpicker::create_palette(name) { Ok(()) => shell_println!("Palette '{}' created", name), Err(e) => shell_println!("Error: {:?}", e), } } }
        "rmpal" => { let name = parts.get(1).copied().unwrap_or(""); match colorpicker::remove_palette(name) { Ok(()) => shell_println!("Palette '{}' removed", name), Err(e) => shell_println!("Error: {:?}", e), } }
        "paladd" => { let name = parts.get(1).copied().unwrap_or(""); let hex = parts.get(2).copied().unwrap_or(""); if let Some(c) = colorpicker::Color::from_hex(hex) { match colorpicker::palette_add(name, c) { Ok(()) => shell_println!("Added {} to '{}'", hex, name), Err(e) => shell_println!("Error: {:?}", e), } } else { shell_println!("Usage: cpick paladd <palette> <#rrggbb>"); } }
        "palrm" => { let name = parts.get(1).copied().unwrap_or(""); let idx = parts.get(2).and_then(|s| s.parse::<usize>().ok()).unwrap_or(0); match colorpicker::palette_remove(name, idx) { Ok(()) => shell_println!("Removed color #{} from '{}'", idx, name), Err(e) => shell_println!("Error: {:?}", e), } }
        "palettes" | "pals" => { let pals = colorpicker::list_palettes(); if pals.is_empty() { shell_println!("No palettes"); } else { for p in &pals { shell_println!("{}: {} colors", p.name, p.colors.len()); for (i, c) in p.colors.iter().enumerate() { shell_println!("  [{}] {}", i, c.to_hex()); } } } }
        "convert" => { let hex = parts.get(1).copied().unwrap_or(""); if let Some(c) = colorpicker::Color::from_hex(hex) { let (h, s, v) = c.to_hsv(); let (hl, sl, l) = c.to_hsl(); let (cm, mg, ye, k) = c.to_cmyk(); shell_println!("{} → rgb({},{},{}) hsv({},{},{}) hsl({},{},{}) cmyk({},{},{},{})", c.to_hex(), c.r, c.g, c.b, h, s, v, hl, sl, l, cm, mg, ye, k); } else { shell_println!("Usage: cpick convert <#rrggbb>"); } }
        "init" => { colorpicker::init_defaults(); shell_println!("Default palettes initialized"); }
        "test" => { match colorpicker::self_test() { Ok(()) => shell_println!("All colorpicker tests passed"), Err(e) => shell_println!("Test failed: {:?}", e), } }
        "stats" => { let (ap, pc, rc, picks, samples) = colorpicker::stats(); shell_println!("Pickers:{} Palettes:{} Recent:{} Picks:{} Samples:{}", ap, pc, rc, picks, samples); }
        "reset" => { colorpicker::clear_all(); colorpicker::reset_stats(); shell_println!("Color picker reset"); }
        _ => { shell_println!("colorpicker: open/rgb/hsv/hsl/hex/alpha/model/get/revert/confirm/cancel/sample/recent/mkpal/rmpal/paladd/palrm/palettes/convert/init/test/stats/reset"); }
    }
}

/// `cursorsettings` / `cursor` — mouse pointer and cursor settings.
fn cmd_cursorsettings(args: &str) {
    use crate::fs::cursorsettings;
    let parts: Vec<&str> = args.split_whitespace().collect();
    let sub = parts.first().copied().unwrap_or("");
    match sub {
        "speed" => { if let Some(v) = parts.get(1).and_then(|s| s.parse::<i8>().ok()) { cursorsettings::set_speed(v); shell_println!("Pointer speed: {}", v); } else { shell_println!("Pointer speed: {}", cursorsettings::config().speed); } }
        "accel" => { if let Some(p) = parts.get(1).and_then(|s| cursorsettings::AccelProfile::from_str(s)) { cursorsettings::set_accel_profile(p); shell_println!("Acceleration: {}", p.label()); } else { shell_println!("Acceleration: {} (flat/adaptive/custom)", cursorsettings::config().accel_profile.label()); } }
        "accelfactor" => { if let Some(v) = parts.get(1).and_then(|s| s.parse::<u8>().ok()) { cursorsettings::set_accel_factor(v); shell_println!("Accel factor: {}", v); } else { shell_println!("Accel factor: {}", cursorsettings::config().accel_factor); } }
        "buttons" => { match parts.get(1).copied().unwrap_or("") { "left"|"lefthanded" => { cursorsettings::set_button_layout(cursorsettings::ButtonLayout::LeftHanded); shell_println!("Buttons: left-handed"); } "right"|"righthanded" => { cursorsettings::set_button_layout(cursorsettings::ButtonLayout::RightHanded); shell_println!("Buttons: right-handed"); } _ => { shell_println!("Buttons: {} (left/right)", cursorsettings::config().button_layout.label()); } } }
        "dblclick" => { if let Some(ms) = parts.get(1).and_then(|s| s.parse::<u32>().ok()) { cursorsettings::set_double_click_ms(ms); shell_println!("Double-click: {}ms", ms); } else { shell_println!("Double-click: {}ms", cursorsettings::config().double_click_ms); } }
        "scroll" => { if let Some(v) = parts.get(1).and_then(|s| s.parse::<u8>().ok()) { cursorsettings::set_scroll_speed(v); shell_println!("Scroll speed: {}", v); } else { shell_println!("Scroll speed: {}", cursorsettings::config().scroll_speed); } }
        "natural" => { match parts.get(1).copied().unwrap_or("") { "on"|"true" => { cursorsettings::set_natural_scroll(true); shell_println!("Natural scroll: on"); } "off"|"false" => { cursorsettings::set_natural_scroll(false); shell_println!("Natural scroll: off"); } _ => { shell_println!("Natural scroll: {}", cursorsettings::config().natural_scroll); } } }
        "size" => { if let Some(sz) = parts.get(1).and_then(|s| s.parse::<u32>().ok()) { cursorsettings::set_cursor_size(sz); shell_println!("Cursor size: {}px", sz); } else { shell_println!("Cursor size: {}px (avail: {:?})", cursorsettings::config().cursor_size, cursorsettings::available_sizes()); } }
        "trail" => { match parts.get(1).copied().unwrap_or("") { "on"|"true" => { cursorsettings::set_show_trail(true); shell_println!("Trail: on"); } "off"|"false" => { cursorsettings::set_show_trail(false); shell_println!("Trail: off"); } _ => { if let Some(l) = parts.get(1).and_then(|s| s.parse::<u8>().ok()) { cursorsettings::set_trail_length(l); shell_println!("Trail length: {}", l); } else { let cfg = cursorsettings::config(); shell_println!("Trail: {} (len={})", cfg.show_trail, cfg.trail_length); } } } }
        "locate" => { match parts.get(1).copied().unwrap_or("") { "on"|"true" => { cursorsettings::set_locate_on_ctrl(true); shell_println!("Locate on Ctrl: on"); } "off"|"false" => { cursorsettings::set_locate_on_ctrl(false); shell_println!("Locate on Ctrl: off"); } _ => { shell_println!("Locate on Ctrl: {}", cursorsettings::config().locate_on_ctrl); } } }
        "hidetyping" => { match parts.get(1).copied().unwrap_or("") { "on"|"true" => { cursorsettings::set_hide_while_typing(true); shell_println!("Hide while typing: on"); } "off"|"false" => { cursorsettings::set_hide_while_typing(false); shell_println!("Hide while typing: off"); } _ => { shell_println!("Hide while typing: {}", cursorsettings::config().hide_while_typing); } } }
        "theme" => { let name = parts.get(1).copied().unwrap_or(""); if name.is_empty() { match cursorsettings::active_theme() { Ok(t) => shell_println!("Active: {} ({})", t.name, t.description), Err(e) => shell_println!("Error: {:?}", e), } } else { match cursorsettings::set_active_theme(name) { Ok(()) => shell_println!("Theme: {}", name), Err(e) => shell_println!("Error: {:?}", e), } } }
        "themes" | "ls" => { let themes = cursorsettings::list_themes(); if themes.is_empty() { shell_println!("No themes"); } else { for t in &themes { shell_println!("{}: {} ({}px, {} cursors{})", t.name, t.description, t.base_size, t.cursors.len(), if t.builtin { ", builtin" } else { "" }); } } }
        "addtheme" => { let name = parts.get(1).copied().unwrap_or(""); let desc = parts[2..].join(" "); let sz = 24u32; if name.is_empty() { shell_println!("Usage: cursor addtheme <name> <description>"); } else { match cursorsettings::register_theme(name, &desc, sz, false) { Ok(()) => shell_println!("Theme '{}' created", name), Err(e) => shell_println!("Error: {:?}", e), } } }
        "rmtheme" => { let name = parts.get(1).copied().unwrap_or(""); match cursorsettings::unregister_theme(name) { Ok(()) => shell_println!("Removed '{}'", name), Err(e) => shell_println!("Error: {:?}", e), } }
        "addcursor" => { let theme = parts.get(1).copied().unwrap_or(""); let shape_s = parts.get(2).copied().unwrap_or(""); if let Some(shape) = cursorsettings::CursorShape::from_str(shape_s) { let hx = parts.get(3).and_then(|s| s.parse::<u32>().ok()).unwrap_or(0); let hy = parts.get(4).and_then(|s| s.parse::<u32>().ok()).unwrap_or(0); match cursorsettings::add_cursor(theme, shape, hx, hy, 1, 0) { Ok(()) => shell_println!("Added {} to '{}'", shape.label(), theme), Err(e) => shell_println!("Error: {:?}", e), } } else { shell_println!("Usage: cursor addcursor <theme> <shape> [hotx] [hoty]"); } }
        "lookup" => { let shape_s = parts.get(1).copied().unwrap_or("default"); if let Some(shape) = cursorsettings::CursorShape::from_str(shape_s) { match cursorsettings::cursor_for(shape) { Some(c) => shell_println!("{}: hotspot=({},{}) frames={}", shape.label(), c.hotspot_x, c.hotspot_y, c.frames), None => shell_println!("No cursor for {} in active theme", shape.label()), } } else { shell_println!("Unknown shape: {}", shape_s); } }
        "shapes" => { for s in cursorsettings::CursorShape::ALL { shell_println!("  {}", s.label()); } }
        "show" | "config" => { let cfg = cursorsettings::config(); shell_println!("Theme: {}  Size: {}px  Speed: {}  Accel: {}  Buttons: {}  Dblclick: {}ms  Scroll: {}  Natural: {}  Trail: {}  Locate: {}  HideTyping: {}", cfg.active_theme, cfg.cursor_size, cfg.speed, cfg.accel_profile.label(), cfg.button_layout.label(), cfg.double_click_ms, cfg.scroll_speed, cfg.natural_scroll, cfg.show_trail, cfg.locate_on_ctrl, cfg.hide_while_typing); }
        "init" => { cursorsettings::init_defaults(); shell_println!("Default cursor settings initialized"); }
        "test" => { match cursorsettings::self_test() { Ok(()) => shell_println!("All cursorsettings tests passed"), Err(e) => shell_println!("Test failed: {:?}", e), } }
        "stats" => { let (tc, changes) = cursorsettings::stats(); shell_println!("Themes:{} Changes:{}", tc, changes); }
        "reset" => { cursorsettings::clear_all(); cursorsettings::reset_stats(); shell_println!("Cursor settings reset"); }
        _ => { shell_println!("cursor: speed/accel/accelfactor/buttons/dblclick/scroll/natural/size/trail/locate/hidetyping/theme/themes/addtheme/rmtheme/addcursor/lookup/shapes/show/init/test/stats/reset"); }
    }
}

/// `kbsettings` / `kbs` — keyboard settings.
fn cmd_kbsettings(args: &str) {
    use crate::fs::kbsettings;
    let parts: Vec<&str> = args.split_whitespace().collect();
    let sub = parts.first().copied().unwrap_or("");
    match sub {
        "preset" => { if let Some(p) = parts.get(1).and_then(|s| kbsettings::RepeatPreset::from_str(s)) { kbsettings::set_preset(p); let cfg = kbsettings::config(); shell_println!("Preset: {} (delay={}ms rate={}ms)", p.label(), cfg.repeat_delay_ms, cfg.repeat_rate_ms); } else { shell_println!("Preset: {} (slow/normal/fast/veryfast)", kbsettings::config().preset.label()); } }
        "delay" => { if let Some(ms) = parts.get(1).and_then(|s| s.parse::<u32>().ok()) { kbsettings::set_repeat_delay(ms); shell_println!("Repeat delay: {}ms", ms); } else { shell_println!("Repeat delay: {}ms", kbsettings::config().repeat_delay_ms); } }
        "rate" => { if let Some(ms) = parts.get(1).and_then(|s| s.parse::<u32>().ok()) { kbsettings::set_repeat_rate(ms); shell_println!("Repeat rate: {}ms", ms); } else { shell_println!("Repeat rate: {}ms", kbsettings::config().repeat_rate_ms); } }
        "numlock" => { if let Some(v) = parts.get(1).and_then(|s| kbsettings::NumLockBoot::from_str(s)) { kbsettings::set_numlock_boot(v); shell_println!("NumLock boot: {}", v.label()); } else { shell_println!("NumLock boot: {} (on/off/unchanged)", kbsettings::config().numlock_boot.label()); } }
        "capslock" => { match parts.get(1).copied().unwrap_or("") { "toggle" => { kbsettings::set_caps_lock_toggle(true); shell_println!("CapsLock: toggle"); } "momentary" => { kbsettings::set_caps_lock_toggle(false); shell_println!("CapsLock: momentary"); } _ => { shell_println!("CapsLock: {} (toggle/momentary)", if kbsettings::config().caps_lock_toggle { "toggle" } else { "momentary" }); } } }
        "sticky" => { match parts.get(1).copied().unwrap_or("") { "on"|"true" => { kbsettings::set_sticky_keys(true); shell_println!("Sticky Keys: on"); } "off"|"false" => { kbsettings::set_sticky_keys(false); shell_println!("Sticky Keys: off"); } "lock" => { match parts.get(2).copied().unwrap_or("") { "on"|"true" => { kbsettings::set_sticky_lock_on_double(true); shell_println!("Sticky lock on double: on"); } "off"|"false" => { kbsettings::set_sticky_lock_on_double(false); shell_println!("Sticky lock on double: off"); } _ => { shell_println!("Sticky lock: {}", kbsettings::config().sticky_lock_on_double); } } } _ => { let cfg = kbsettings::config(); shell_println!("Sticky Keys: {} (lock on double: {})", cfg.sticky_keys, cfg.sticky_lock_on_double); } } }
        "filter" => { match parts.get(1).copied().unwrap_or("") { "on"|"true" => { kbsettings::set_filter_keys(true); shell_println!("Filter Keys: on"); } "off"|"false" => { kbsettings::set_filter_keys(false); shell_println!("Filter Keys: off"); } "hold" => { if let Some(ms) = parts.get(2).and_then(|s| s.parse::<u32>().ok()) { kbsettings::set_filter_min_hold(ms); shell_println!("Filter min hold: {}ms", ms); } } "debounce" => { if let Some(ms) = parts.get(2).and_then(|s| s.parse::<u32>().ok()) { kbsettings::set_filter_debounce(ms); shell_println!("Filter debounce: {}ms", ms); } } _ => { let cfg = kbsettings::config(); shell_println!("Filter Keys: {} (hold={}ms debounce={}ms)", cfg.filter_keys, cfg.filter_min_hold_ms, cfg.filter_debounce_ms); } } }
        "toggle" => { match parts.get(1).copied().unwrap_or("") { "on"|"true" => { kbsettings::set_toggle_keys_sound(true); shell_println!("Toggle sounds: on"); } "off"|"false" => { kbsettings::set_toggle_keys_sound(false); shell_println!("Toggle sounds: off"); } _ => { shell_println!("Toggle sounds: {}", kbsettings::config().toggle_keys_sound); } } }
        "bounce" => { match parts.get(1).copied().unwrap_or("") { "on"|"true" => { kbsettings::set_bounce_keys(true); shell_println!("Bounce Keys: on"); } "off"|"false" => { kbsettings::set_bounce_keys(false); shell_println!("Bounce Keys: off"); } _ => { if let Some(ms) = parts.get(1).and_then(|s| s.parse::<u32>().ok()) { kbsettings::set_bounce_ms(ms); shell_println!("Bounce: {}ms", ms); } else { let cfg = kbsettings::config(); shell_println!("Bounce Keys: {} ({}ms)", cfg.bounce_keys, cfg.bounce_ms); } } } }
        "compose" => { match parts.get(1).copied().unwrap_or("") { "on"|"true" => { kbsettings::set_compose_key(true); shell_println!("Compose key: on"); } "off"|"false" => { kbsettings::set_compose_key(false); shell_println!("Compose key: off"); } _ => { shell_println!("Compose key: {}", kbsettings::config().compose_key); } } }
        "altgr" => { match parts.get(1).copied().unwrap_or("") { "on"|"true" => { kbsettings::set_ctrl_alt_as_altgr(true); shell_println!("Ctrl+Alt=AltGr: on"); } "off"|"false" => { kbsettings::set_ctrl_alt_as_altgr(false); shell_println!("Ctrl+Alt=AltGr: off"); } _ => { shell_println!("Ctrl+Alt=AltGr: {}", kbsettings::config().ctrl_alt_as_altgr); } } }
        "override" => { let kc = parts.get(1).and_then(|s| s.parse::<u16>().ok()).unwrap_or(0); let delay = parts.get(2).and_then(|s| s.parse::<u32>().ok()).unwrap_or(0); let rate = parts.get(3).and_then(|s| s.parse::<u32>().ok()).unwrap_or(0); let no_rep = parts.get(4).copied() == Some("norepeat"); match kbsettings::add_override(kc, delay, rate, no_rep) { Ok(()) => shell_println!("Override for key 0x{:02x}: delay={}ms rate={}ms{}", kc, delay, rate, if no_rep { " norepeat" } else { "" }), Err(e) => shell_println!("Error: {:?}", e), } }
        "rmoverride" => { let kc = parts.get(1).and_then(|s| s.parse::<u16>().ok()).unwrap_or(0); match kbsettings::remove_override(kc) { Ok(()) => shell_println!("Removed override for 0x{:02x}", kc), Err(e) => shell_println!("Error: {:?}", e), } }
        "overrides" => { let ovrs = kbsettings::list_overrides(); if ovrs.is_empty() { shell_println!("No overrides"); } else { for o in &ovrs { shell_println!("  0x{:02x}: delay={}ms rate={}ms{}", o.keycode, o.delay_ms, o.rate_ms, if o.no_repeat { " norepeat" } else { "" }); } } }
        "mkprofile" => { let name = parts.get(1).copied().unwrap_or(""); if name.is_empty() { shell_println!("Usage: kbs mkprofile <name>"); } else { match kbsettings::create_profile(name) { Ok(()) => shell_println!("Profile '{}' created", name), Err(e) => shell_println!("Error: {:?}", e), } } }
        "rmprofile" => { let name = parts.get(1).copied().unwrap_or(""); match kbsettings::remove_profile(name) { Ok(()) => shell_println!("Profile '{}' removed", name), Err(e) => shell_println!("Error: {:?}", e), } }
        "useprofile" => { let name = parts.get(1).copied().unwrap_or(""); match kbsettings::activate_profile(name) { Ok(()) => { let cfg = kbsettings::config(); shell_println!("Profile '{}' active (delay={}ms rate={}ms)", name, cfg.repeat_delay_ms, cfg.repeat_rate_ms); } Err(e) => shell_println!("Error: {:?}", e), } }
        "profiles" => { let profs = kbsettings::list_profiles(); if profs.is_empty() { shell_println!("No profiles"); } else { for p in &profs { shell_println!("{}: {} delay={}ms rate={}ms{}", p.name, p.preset.label(), p.repeat_delay_ms, p.repeat_rate_ms, if p.active { " [active]" } else { "" }); } } }
        "show" | "config" => { let cfg = kbsettings::config(); shell_println!("Preset:{} Delay:{}ms Rate:{}ms NumLock:{} CapsLock:{} Sticky:{} Filter:{} Toggle:{} Bounce:{} Compose:{} AltGr:{}", cfg.preset.label(), cfg.repeat_delay_ms, cfg.repeat_rate_ms, cfg.numlock_boot.label(), if cfg.caps_lock_toggle {"toggle"} else {"momentary"}, cfg.sticky_keys, cfg.filter_keys, cfg.toggle_keys_sound, cfg.bounce_keys, cfg.compose_key, cfg.ctrl_alt_as_altgr); }
        "init" => { kbsettings::init_defaults(); shell_println!("Default keyboard settings initialized"); }
        "test" => { match kbsettings::self_test() { Ok(()) => shell_println!("All kbsettings tests passed"), Err(e) => shell_println!("Test failed: {:?}", e), } }
        "stats" => { let (pc, oc, changes) = kbsettings::stats(); shell_println!("Profiles:{} Overrides:{} Changes:{}", pc, oc, changes); }
        "reset" => { kbsettings::clear_all(); kbsettings::reset_stats(); shell_println!("Keyboard settings reset"); }
        _ => { shell_println!("kbsettings: preset/delay/rate/numlock/capslock/sticky/filter/toggle/bounce/compose/altgr/override/rmoverride/overrides/mkprofile/rmprofile/useprofile/profiles/show/init/test/stats/reset"); }
    }
}

/// `detailcols` / `dcols` — file explorer detail columns.
fn cmd_detailcols(args: &str) {
    use crate::fs::detailcols;
    let parts: Vec<&str> = args.split_whitespace().collect();
    let sub = parts.first().copied().unwrap_or("");
    match sub {
        "list" | "ls" => { let cat = parts.get(1).and_then(|s| detailcols::ColumnCategory::from_str(s)); let cols = detailcols::list_columns(cat); if cols.is_empty() { shell_println!("No columns"); } else { for c in &cols { shell_println!("  {} [{}] {} ({}{})", c.id, c.category.label(), c.display_name, c.col_type.label(), if c.source_app.is_empty() { String::new() } else { alloc::format!(", app={}", c.source_app) }); } shell_println!("{} columns", cols.len()); } }
        "get" => { let id = parts.get(1).copied().unwrap_or(""); match detailcols::get_column(id) { Ok(c) => shell_println!("{}: {} [{}] {} w={} sort={}", c.id, c.display_name, c.category.label(), c.col_type.label(), c.default_width, c.sortable), Err(e) => shell_println!("Error: {:?}", e), } }
        "register" => { let id = parts.get(1).copied().unwrap_or(""); let name = parts.get(2).copied().unwrap_or(""); let ct = parts.get(3).and_then(|s| detailcols::ColumnType::from_str(s)).unwrap_or(detailcols::ColumnType::Text); let cat = parts.get(4).and_then(|s| detailcols::ColumnCategory::from_str(s)).unwrap_or(detailcols::ColumnCategory::AppDefined); if id.is_empty() || name.is_empty() { shell_println!("Usage: dcols register <id> <name> [type] [category]"); } else { match detailcols::register_column(id, name, ct, cat, 15, true, "shell") { Ok(()) => shell_println!("Registered column '{}'", id), Err(e) => shell_println!("Error: {:?}", e), } } }
        "unregister" => { let id = parts.get(1).copied().unwrap_or(""); match detailcols::unregister_column(id) { Ok(()) => shell_println!("Unregistered '{}'", id), Err(e) => shell_println!("Error: {:?}", e), } }
        "bind" => { let mime = parts.get(1).copied().unwrap_or(""); let col_ids: Vec<&str> = parts[2..].to_vec(); if mime.is_empty() || col_ids.is_empty() { shell_println!("Usage: dcols bind <mime> <col_id> [col_id...]"); } else { match detailcols::bind_columns(mime, &col_ids) { Ok(()) => shell_println!("Bound {} columns to {}", col_ids.len(), mime), Err(e) => shell_println!("Error: {:?}", e), } } }
        "unbind" => { let mime = parts.get(1).copied().unwrap_or(""); match detailcols::unbind(mime) { Ok(()) => shell_println!("Unbound {}", mime), Err(e) => shell_println!("Error: {:?}", e), } }
        "bindings" => { let bindings = detailcols::list_bindings(); if bindings.is_empty() { shell_println!("No bindings"); } else { for b in &bindings { shell_println!("  {} → {}", b.mime_pattern, b.column_ids.join(", ")); } } }
        "query" => { let types: Vec<&str> = parts[1..].to_vec(); if types.is_empty() { shell_println!("Usage: dcols query <mime> [mime...]"); } else { let cols = detailcols::columns_for_types(&types); shell_println!("Columns for {:?}:", types); for c in &cols { shell_println!("  {} ({})", c.display_name, c.id); } } }
        "userset" => { let mime = parts.get(1).copied().unwrap_or(""); let col_ids: Vec<&str> = parts[2..].to_vec(); if mime.is_empty() { shell_println!("Usage: dcols userset <mime> <col_id> [col_id...]"); } else { match detailcols::set_user_columns(mime, &col_ids) { Ok(()) => shell_println!("User columns set for {}", mime), Err(e) => shell_println!("Error: {:?}", e), } } }
        "userclear" => { let mime = parts.get(1).copied().unwrap_or(""); match detailcols::clear_user_columns(mime) { Ok(()) => shell_println!("Cleared user selection for {}", mime), Err(e) => shell_println!("Error: {:?}", e), } }
        "userlist" => { let sels = detailcols::list_user_selections(); if sels.is_empty() { shell_println!("No user selections"); } else { for s in &sels { shell_println!("  {} → {}", s.mime_pattern, s.visible_columns.join(", ")); } } }
        "init" => { detailcols::init_defaults(); shell_println!("Default columns initialized"); }
        "test" => { match detailcols::self_test() { Ok(()) => shell_println!("All detailcols tests passed"), Err(e) => shell_println!("Test failed: {:?}", e), } }
        "stats" => { let (cc, bc, uc, qc) = detailcols::stats(); shell_println!("Columns:{} Bindings:{} UserPrefs:{} Queries:{}", cc, bc, uc, qc); }
        "reset" => { detailcols::clear_all(); detailcols::reset_stats(); shell_println!("Detail columns reset"); }
        _ => { shell_println!("detailcols: list/get/register/unregister/bind/unbind/bindings/query/userset/userclear/userlist/init/test/stats/reset"); }
    }
}

/// `partmgr` / `pmgr` — partition manager.
fn cmd_partmgr(args: &str) {
    use crate::fs::partmgr;
    let parts: Vec<&str> = args.split_whitespace().collect();
    let sub = parts.first().copied().unwrap_or("");
    match sub {
        "disks" | "ls" => { let disks = partmgr::list_disks(); if disks.is_empty() { shell_println!("No disks"); } else { for d in &disks { let gb = d.size_bytes / (1024*1024*1024); shell_println!("#{}: {} {} {}GB [{}]{}", d.id, d.name, d.model, gb, d.table_type.label(), if d.removable { " (removable)" } else { "" }); } } }
        "adddisk" => { let name = parts.get(1).copied().unwrap_or(""); let model = parts.get(2).copied().unwrap_or(""); let gb = parts.get(3).and_then(|s| s.parse::<u64>().ok()).unwrap_or(0); if name.is_empty() || gb == 0 { shell_println!("Usage: pmgr adddisk <name> <model> <size_gb>"); } else { match partmgr::register_disk(name, model, "", gb * 1024 * 1024 * 1024, 512, partmgr::TableType::Gpt, false) { Ok(id) => shell_println!("Disk #{}: {} {}GB", id, name, gb), Err(e) => shell_println!("Error: {:?}", e), } } }
        "rmdisk" => { let did = parts.get(1).and_then(|s| s.parse::<u64>().ok()).unwrap_or(0); match partmgr::unregister_disk(did) { Ok(()) => shell_println!("Disk #{} removed", did), Err(e) => shell_println!("Error: {:?}", e), } }
        "table" => { let did = parts.get(1).and_then(|s| s.parse::<u64>().ok()).unwrap_or(0); let tt = parts.get(2).and_then(|s| partmgr::TableType::from_str(s)); if let Some(tt) = tt { match partmgr::set_table_type(did, tt) { Ok(()) => shell_println!("Disk #{}: {}", did, tt.label()), Err(e) => shell_println!("Error: {:?}", e), } } else { shell_println!("Usage: pmgr table <disk_id> <gpt|mbr|none>"); } }
        "parts" => { let did = parts.get(1).and_then(|s| s.parse::<u64>().ok()).unwrap_or(0); let plist = partmgr::list_partitions(did); if plist.is_empty() { shell_println!("No partitions on disk #{}", did); } else { for p in &plist { let mb = p.size_bytes / (1024*1024); shell_println!("  #{} (id={}) {} {}MB {} [{}]{}", p.number, p.id, p.label, mb, p.fs_type.label(), p.flags.iter().map(|f| f.label()).collect::<Vec<_>>().join(","), if p.mount_point.is_empty() { String::new() } else { alloc::format!(" → {}", p.mount_point) }); } } }
        "create" => { let did = parts.get(1).and_then(|s| s.parse::<u64>().ok()).unwrap_or(0); let start_mb = parts.get(2).and_then(|s| s.parse::<u64>().ok()).unwrap_or(0); let size_mb = parts.get(3).and_then(|s| s.parse::<u64>().ok()).unwrap_or(0); let fs = parts.get(4).and_then(|s| partmgr::FsType::from_str(s)).unwrap_or(partmgr::FsType::Unformatted); let label = parts.get(5).copied().unwrap_or(""); if did == 0 || size_mb == 0 { shell_println!("Usage: pmgr create <disk_id> <start_mb> <size_mb> [fstype] [label]"); } else { match partmgr::create_partition(did, start_mb * 1024 * 1024, size_mb * 1024 * 1024, fs, label) { Ok(id) => shell_println!("Partition #{} created ({}MB {})", id, size_mb, fs.label()), Err(e) => shell_println!("Error: {:?}", e), } } }
        "delete" => { let did = parts.get(1).and_then(|s| s.parse::<u64>().ok()).unwrap_or(0); let pid = parts.get(2).and_then(|s| s.parse::<u64>().ok()).unwrap_or(0); match partmgr::delete_partition(did, pid) { Ok(()) => shell_println!("Partition deleted"), Err(e) => shell_println!("Error: {:?}", e), } }
        "resize" => { let did = parts.get(1).and_then(|s| s.parse::<u64>().ok()).unwrap_or(0); let pid = parts.get(2).and_then(|s| s.parse::<u64>().ok()).unwrap_or(0); let new_mb = parts.get(3).and_then(|s| s.parse::<u64>().ok()).unwrap_or(0); if new_mb == 0 { shell_println!("Usage: pmgr resize <disk_id> <part_id> <new_size_mb>"); } else { match partmgr::resize_partition(did, pid, new_mb * 1024 * 1024) { Ok(()) => shell_println!("Resized to {}MB", new_mb), Err(e) => shell_println!("Error: {:?}", e), } } }
        "format" => { let did = parts.get(1).and_then(|s| s.parse::<u64>().ok()).unwrap_or(0); let pid = parts.get(2).and_then(|s| s.parse::<u64>().ok()).unwrap_or(0); let fs = parts.get(3).and_then(|s| partmgr::FsType::from_str(s)); if let Some(fs) = fs { match partmgr::format_partition(did, pid, fs) { Ok(()) => shell_println!("Formatted as {}", fs.label()), Err(e) => shell_println!("Error: {:?}", e), } } else { shell_println!("Usage: pmgr format <disk_id> <part_id> <ext4|fat32|ntfs|btrfs|swap|efi>"); } }
        "label" => { let did = parts.get(1).and_then(|s| s.parse::<u64>().ok()).unwrap_or(0); let pid = parts.get(2).and_then(|s| s.parse::<u64>().ok()).unwrap_or(0); let lbl = parts.get(3).copied().unwrap_or(""); match partmgr::set_label(did, pid, lbl) { Ok(()) => shell_println!("Label: {}", lbl), Err(e) => shell_println!("Error: {:?}", e), } }
        "flag" => { let did = parts.get(1).and_then(|s| s.parse::<u64>().ok()).unwrap_or(0); let pid = parts.get(2).and_then(|s| s.parse::<u64>().ok()).unwrap_or(0); let f = parts.get(3).and_then(|s| partmgr::PartFlag::from_str(s)); let v = parts.get(4).copied() != Some("off"); if let Some(f) = f { match partmgr::set_flag(did, pid, f, v) { Ok(()) => shell_println!("Flag {} = {}", f.label(), v), Err(e) => shell_println!("Error: {:?}", e), } } else { shell_println!("Usage: pmgr flag <disk> <part> <boot|esp|hidden|readonly|system> [off]"); } }
        "mount" => { let did = parts.get(1).and_then(|s| s.parse::<u64>().ok()).unwrap_or(0); let pid = parts.get(2).and_then(|s| s.parse::<u64>().ok()).unwrap_or(0); let mp = parts.get(3).copied().unwrap_or(""); match partmgr::set_mount_point(did, pid, mp) { Ok(()) => shell_println!("Mount: {}", mp), Err(e) => shell_println!("Error: {:?}", e), } }
        "free" => { let did = parts.get(1).and_then(|s| s.parse::<u64>().ok()).unwrap_or(0); match partmgr::free_space(did) { Ok(bytes) => { let mb = bytes / (1024*1024); shell_println!("Free: {}MB ({}B)", mb, bytes); } Err(e) => shell_println!("Error: {:?}", e), } }
        "test" => { match partmgr::self_test() { Ok(()) => shell_println!("All partmgr tests passed"), Err(e) => shell_println!("Test failed: {:?}", e), } }
        "stats" => { let (dc, pc, ops) = partmgr::stats(); shell_println!("Disks:{} Partitions:{} Ops:{}", dc, pc, ops); }
        "reset" => { partmgr::clear_all(); partmgr::reset_stats(); shell_println!("Partition manager reset"); }
        _ => { shell_println!("partmgr: disks/adddisk/rmdisk/table/parts/create/delete/resize/format/label/flag/mount/free/test/stats/reset"); }
    }
}

/// `locale` / `lcl` — locale and regional settings.
fn cmd_locale(args: &str) {
    use crate::fs::locale;
    let parts: Vec<&str> = args.split_whitespace().collect();
    let sub = parts.first().copied().unwrap_or("");
    match sub {
        "lang" => { let tag = parts.get(1).copied().unwrap_or(""); if tag.is_empty() { shell_println!("Language: {}", locale::language()); } else { match locale::set_language(tag) { Ok(()) => shell_println!("Language: {}", tag), Err(e) => shell_println!("Error: {:?}", e), } } }
        "fallback" => { let tag = parts.get(1).copied().unwrap_or(""); if tag.is_empty() { shell_println!("Fallback: {}", locale::config().fallback_language); } else { locale::set_fallback_language(tag); shell_println!("Fallback: {}", tag); } }
        "region" => { let tag = parts.get(1).copied().unwrap_or(""); if tag.is_empty() { shell_println!("Region: {}", locale::config().region_format); } else { locale::set_region_format(tag); shell_println!("Region: {}", tag); } }
        "number" => { if let Some(fmt) = parts.get(1).and_then(|s| locale::NumberSeparator::from_str(s)) { locale::set_number_format(fmt); shell_println!("Numbers: {}", fmt.label()); } else { shell_println!("Numbers: {} (commadot/dotcomma/spacecomma/apostrophedot)", locale::config().number_format.label()); } }
        "currency" => { let sym = parts.get(1).copied().unwrap_or(""); let pos = parts.get(2).copied().unwrap_or("before"); if sym.is_empty() { let cfg = locale::config(); shell_println!("Currency: {} ({})", cfg.currency_symbol, if cfg.currency_before {"before"} else {"after"}); } else { locale::set_currency(sym, pos != "after"); shell_println!("Currency: {} ({})", sym, pos); } }
        "date" => { if let Some(ord) = parts.get(1).and_then(|s| locale::DateOrder::from_str(s)) { locale::set_date_order(ord); shell_println!("Date: {}", ord.label()); } else { shell_println!("Date: {} (mdy/dmy/ymd)", locale::config().date_order.label()); } }
        "datesep" => { if let Some(sep) = parts.get(1).and_then(|s| locale::DateSeparator::from_str(s)) { locale::set_date_separator(sep); shell_println!("Date separator: {}", sep.label()); } else { shell_println!("Date separator: {} (slash/dash/dot)", locale::config().date_separator.label()); } }
        "time" => { if let Some(fmt) = parts.get(1).and_then(|s| locale::TimeFormat::from_str(s)) { locale::set_time_format(fmt); shell_println!("Time: {}", fmt.label()); } else { shell_println!("Time: {} (12/24)", locale::config().time_format.label()); } }
        "firstday" => { if let Some(d) = parts.get(1).and_then(|s| locale::FirstDay::from_str(s)) { locale::set_first_day(d); shell_println!("First day: {}", d.label()); } else { shell_println!("First day: {} (sun/mon/sat)", locale::config().first_day.label()); } }
        "measure" => { if let Some(m) = parts.get(1).and_then(|s| locale::MeasurementSystem::from_str(s)) { locale::set_measurement(m); shell_println!("Measurement: {}", m.label()); } else { shell_println!("Measurement: {} (metric/imperial)", locale::config().measurement.label()); } }
        "tz" | "timezone" => { let id = parts.get(1).copied().unwrap_or(""); if id.is_empty() { let cfg = locale::config(); shell_println!("Timezone: {} (UTC{:+})", cfg.timezone, locale::timezone_offset_minutes() as f32 / 60.0); } else { match locale::set_timezone(id) { Ok(()) => shell_println!("Timezone: {} (UTC{:+})", id, locale::timezone_offset_minutes() as f32 / 60.0), Err(e) => shell_println!("Error: {:?}", e), } } }
        "paper" => { match parts.get(1).copied().unwrap_or("") { "a4" | "A4" => { locale::set_paper_a4(true); shell_println!("Paper: A4"); } "letter" | "Letter" => { locale::set_paper_a4(false); shell_println!("Paper: Letter"); } _ => { shell_println!("Paper: {} (a4/letter)", if locale::config().paper_a4 {"A4"} else {"Letter"}); } } }
        "langs" | "languages" => { let langs = locale::list_languages(); if langs.is_empty() { shell_println!("No languages"); } else { for l in &langs { shell_println!("  {} — {} ({})", l.tag, l.native_name, l.english_name); } } }
        "tzlist" | "timezones" => { let tzs = locale::list_timezones(); if tzs.is_empty() { shell_println!("No timezones"); } else { for t in &tzs { shell_println!("  {} — {} UTC{:+}{}", t.id, t.display_name, t.utc_offset_min as f32 / 60.0, if t.observes_dst {" (DST)"} else {""}); } } }
        "show" | "config" => { let cfg = locale::config(); shell_println!("Lang:{} Region:{} Num:{} Date:{}{} Time:{} Day1:{} Measure:{} TZ:{} Paper:{} Currency:{}", cfg.language, cfg.region_format, cfg.number_format.label(), cfg.date_order.label(), cfg.date_separator.label(), cfg.time_format.label(), cfg.first_day.label(), cfg.measurement.label(), cfg.timezone, if cfg.paper_a4 {"A4"} else {"Letter"}, cfg.currency_symbol); }
        "init" => { locale::init_defaults(); shell_println!("Default locale settings initialized"); }
        "test" => { match locale::self_test() { Ok(()) => shell_println!("All locale tests passed"), Err(e) => shell_println!("Test failed: {:?}", e), } }
        "stats" => { let (lc, tc, changes) = locale::stats(); shell_println!("Languages:{} Timezones:{} Changes:{}", lc, tc, changes); }
        "reset" => { locale::clear_all(); locale::reset_stats(); shell_println!("Locale settings reset"); }
        _ => { shell_println!("locale: lang/fallback/region/number/currency/date/datesep/time/firstday/measure/tz/paper/langs/tzlist/show/init/test/stats/reset"); }
    }
}

/// `useracct` / `uacct` — user accounts, groups, sessions.
fn cmd_useracct(args: &str) {
    use crate::fs::useracct;
    let parts: Vec<&str> = args.split_whitespace().collect();
    let sub = parts.first().copied().unwrap_or("");
    match sub {
        "list" | "ls" => { let users = useracct::list_users(); if users.is_empty() { shell_println!("No users"); } else { for u in &users { let t = match u.account_type { useracct::AccountType::Administrator => "admin", useracct::AccountType::Standard => "standard", useracct::AccountType::Guest => "guest", useracct::AccountType::System => "system" }; let s = if u.locked { "locked" } else if !u.enabled { "disabled" } else { "active" }; shell_println!("  uid={} {} ({}) [{}] home={}", u.uid, u.username, t, s, u.home_dir); } } }
        "add" | "create" => { if parts.len() < 3 { shell_println!("Usage: useracct add <username> <password> [admin|standard|guest]"); } else { let name = parts[1]; let pass = parts[2]; let acct_type = match parts.get(3).copied().unwrap_or("standard") { "admin" | "administrator" => useracct::AccountType::Administrator, "guest" => useracct::AccountType::Guest, _ => useracct::AccountType::Standard }; match useracct::create_user(name, name, pass, acct_type) { Ok(uid) => shell_println!("Created user '{}' (uid={})", name, uid), Err(e) => shell_println!("Error: {:?}", e) } } }
        "remove" | "rm" | "del" => { if parts.len() < 2 { shell_println!("Usage: useracct remove <uid>"); } else { match parts[1].parse::<u64>() { Ok(uid) => match useracct::remove_user(uid) { Ok(()) => shell_println!("Removed user uid={}", uid), Err(e) => shell_println!("Error: {:?}", e) }, Err(_) => shell_println!("Invalid uid") } } }
        "info" | "show" => { if parts.len() < 2 { shell_println!("Usage: useracct info <uid|username>"); } else { let result = if let Ok(uid) = parts[1].parse::<u64>() { useracct::get_user(uid) } else { useracct::get_user_by_name(parts[1]) }; match result { Ok(u) => { let t = match u.account_type { useracct::AccountType::Administrator => "Administrator", useracct::AccountType::Standard => "Standard", useracct::AccountType::Guest => "Guest", useracct::AccountType::System => "System" }; let m = match u.login_method { useracct::LoginMethod::Password => "password", useracct::LoginMethod::Pin => "pin", useracct::LoginMethod::Fingerprint => "fingerprint", useracct::LoginMethod::NoPassword => "none" }; shell_println!("User: {} (uid={})", u.username, u.uid); shell_println!("  Display name: {}", u.display_name); shell_println!("  Type:         {}", t); shell_println!("  Login method: {}", m); shell_println!("  Home:         {}", u.home_dir); shell_println!("  Shell:        {}", u.shell); shell_println!("  Avatar:       {}", if u.avatar.is_empty() { "(default)" } else { &u.avatar }); shell_println!("  Auto-login:   {}", u.auto_login); shell_println!("  Enabled:      {}", u.enabled); shell_println!("  Locked:       {}", u.locked); shell_println!("  Groups:       {:?}", u.groups); }, Err(e) => shell_println!("Error: {:?}", e) } } }
        "whoami" => { match useracct::current_user() { Some(u) => shell_println!("{} (uid={})", u.username, u.uid), None => shell_println!("No active session") } }
        "login" => { if parts.len() < 3 { shell_println!("Usage: useracct login <username> <password>"); } else { match useracct::authenticate(parts[1], parts[2]) { Ok(sid) => shell_println!("Logged in as '{}' (session={})", parts[1], sid), Err(e) => shell_println!("Auth failed: {:?}", e) } } }
        "logout" => { if parts.len() < 2 { shell_println!("Usage: useracct logout <session_id>"); } else { match parts[1].parse::<u64>() { Ok(sid) => match useracct::logout(sid) { Ok(()) => shell_println!("Logged out session {}", sid), Err(e) => shell_println!("Error: {:?}", e) }, Err(_) => shell_println!("Invalid session id") } } }
        "sessions" | "sess" => { let sessions = useracct::list_sessions(); if sessions.is_empty() { shell_println!("No active sessions"); } else { for s in &sessions { shell_println!("  session={} uid={} user={} active={}", s.session_id, s.uid, s.username, s.active); } } }
        "passwd" | "password" => { if parts.len() < 3 { shell_println!("Usage: useracct passwd <uid> <new_password>"); } else { match parts[1].parse::<u64>() { Ok(uid) => match useracct::change_password(uid, parts[2]) { Ok(()) => shell_println!("Password changed for uid={}", uid), Err(e) => shell_println!("Error: {:?}", e) }, Err(_) => shell_println!("Invalid uid") } } }
        "enable" => { if parts.len() < 2 { shell_println!("Usage: useracct enable <uid>"); } else { match parts[1].parse::<u64>() { Ok(uid) => match useracct::set_enabled(uid, true) { Ok(()) => shell_println!("Enabled uid={}", uid), Err(e) => shell_println!("Error: {:?}", e) }, Err(_) => shell_println!("Invalid uid") } } }
        "disable" => { if parts.len() < 2 { shell_println!("Usage: useracct disable <uid>"); } else { match parts[1].parse::<u64>() { Ok(uid) => match useracct::set_enabled(uid, false) { Ok(()) => shell_println!("Disabled uid={}", uid), Err(e) => shell_println!("Error: {:?}", e) }, Err(_) => shell_println!("Invalid uid") } } }
        "unlock" => { if parts.len() < 2 { shell_println!("Usage: useracct unlock <uid>"); } else { match parts[1].parse::<u64>() { Ok(uid) => match useracct::unlock(uid) { Ok(()) => shell_println!("Unlocked uid={}", uid), Err(e) => shell_println!("Error: {:?}", e) }, Err(_) => shell_println!("Invalid uid") } } }
        "type" => { if parts.len() < 3 { shell_println!("Usage: useracct type <uid> <admin|standard|guest>"); } else { match parts[1].parse::<u64>() { Ok(uid) => { let acct_type = match parts[2] { "admin" | "administrator" => useracct::AccountType::Administrator, "guest" => useracct::AccountType::Guest, "system" => useracct::AccountType::System, _ => useracct::AccountType::Standard }; match useracct::set_account_type(uid, acct_type) { Ok(()) => shell_println!("Set type for uid={}", uid), Err(e) => shell_println!("Error: {:?}", e) } }, Err(_) => shell_println!("Invalid uid") } } }
        "display" | "dname" => { if parts.len() < 3 { shell_println!("Usage: useracct display <uid> <name...>"); } else { match parts[1].parse::<u64>() { Ok(uid) => { let name = parts[2..].join(" "); match useracct::set_display_name(uid, &name) { Ok(()) => shell_println!("Set display name for uid={}", uid), Err(e) => shell_println!("Error: {:?}", e) } }, Err(_) => shell_println!("Invalid uid") } } }
        "avatar" => { if parts.len() < 3 { shell_println!("Usage: useracct avatar <uid> <path>"); } else { match parts[1].parse::<u64>() { Ok(uid) => match useracct::set_avatar(uid, parts[2]) { Ok(()) => shell_println!("Set avatar for uid={}", uid), Err(e) => shell_println!("Error: {:?}", e) }, Err(_) => shell_println!("Invalid uid") } } }
        "autologin" => { if parts.len() < 3 { shell_println!("Usage: useracct autologin <uid> <on|off>"); } else { match parts[1].parse::<u64>() { Ok(uid) => { let on = matches!(parts[2], "on" | "true" | "yes" | "1"); match useracct::set_auto_login(uid, on) { Ok(()) => shell_println!("Auto-login {} for uid={}", if on { "enabled" } else { "disabled" }, uid), Err(e) => shell_println!("Error: {:?}", e) } }, Err(_) => shell_println!("Invalid uid") } } }
        "groups" | "grp" => { let groups = useracct::list_groups(); if groups.is_empty() { shell_println!("No groups"); } else { for g in &groups { let kind = if g.system_group { "system" } else { "user" }; shell_println!("  gid={} {} ({}) — {}", g.gid, g.name, kind, g.description); } } }
        "addgroup" | "gadd" => { if parts.len() < 2 { shell_println!("Usage: useracct addgroup <name> [description] [--system]"); } else { let sys = parts.contains(&"--system"); let desc = parts.get(2).copied().unwrap_or(""); match useracct::create_group(parts[1], desc, sys) { Ok(gid) => shell_println!("Created group '{}' (gid={})", parts[1], gid), Err(e) => shell_println!("Error: {:?}", e) } } }
        "rmgroup" | "gdel" => { if parts.len() < 2 { shell_println!("Usage: useracct rmgroup <gid>"); } else { match parts[1].parse::<u64>() { Ok(gid) => match useracct::remove_group(gid) { Ok(()) => shell_println!("Removed group gid={}", gid), Err(e) => shell_println!("Error: {:?}", e) }, Err(_) => shell_println!("Invalid gid") } } }
        "join" => { if parts.len() < 3 { shell_println!("Usage: useracct join <uid> <gid>"); } else { match (parts[1].parse::<u64>(), parts[2].parse::<u64>()) { (Ok(uid), Ok(gid)) => match useracct::add_to_group(uid, gid) { Ok(()) => shell_println!("Added uid={} to gid={}", uid, gid), Err(e) => shell_println!("Error: {:?}", e) }, _ => shell_println!("Invalid uid/gid") } } }
        "leave" => { if parts.len() < 3 { shell_println!("Usage: useracct leave <uid> <gid>"); } else { match (parts[1].parse::<u64>(), parts[2].parse::<u64>()) { (Ok(uid), Ok(gid)) => match useracct::remove_from_group(uid, gid) { Ok(()) => shell_println!("Removed uid={} from gid={}", uid, gid), Err(e) => shell_println!("Error: {:?}", e) }, _ => shell_println!("Invalid uid/gid") } } }
        "stats" => { let (uc, gc, sc, lc) = useracct::stats(); shell_println!("Users: {}  Groups: {}  Sessions: {}  Total logins: {}", uc, gc, sc, lc); }
        "init" => { useracct::init_defaults(); shell_println!("User accounts initialized with defaults"); }
        "test" => { match useracct::self_test() { Ok(()) => shell_println!("useracct: all tests passed"), Err(e) => shell_println!("useracct: test FAILED: {:?}", e) } }
        _ => {
            shell_println!("useracct — user accounts, groups, sessions");
            shell_println!("  list|ls          List users");
            shell_println!("  add <user> <pw> [type]  Create user");
            shell_println!("  remove <uid>     Remove user");
            shell_println!("  info <uid|name>  Show user details");
            shell_println!("  whoami           Current user");
            shell_println!("  login <u> <pw>   Authenticate");
            shell_println!("  logout <sid>     End session");
            shell_println!("  sessions         List sessions");
            shell_println!("  passwd <uid> <pw> Change password");
            shell_println!("  enable <uid>     Enable account");
            shell_println!("  disable <uid>    Disable account");
            shell_println!("  unlock <uid>     Unlock account");
            shell_println!("  type <uid> <t>   Set account type");
            shell_println!("  display <uid> <n> Set display name");
            shell_println!("  avatar <uid> <p> Set avatar path");
            shell_println!("  autologin <uid> <on|off>  Toggle auto-login");
            shell_println!("  groups           List groups");
            shell_println!("  addgroup <name>  Create group");
            shell_println!("  rmgroup <gid>    Remove group");
            shell_println!("  join <uid> <gid> Add user to group");
            shell_println!("  leave <uid> <gid> Remove from group");
            shell_println!("  stats            Show statistics");
            shell_println!("  init             Load defaults");
            shell_println!("  test             Run self-tests");
        }
    }
}

/// `progmgr` / `prog` — program management settings.
fn cmd_progmgr(args: &str) {
    use crate::fs::progmgr;
    let parts: Vec<&str> = args.split_whitespace().collect();
    let sub = parts.first().copied().unwrap_or("");
    match sub {
        "list" | "ls" => { let progs = progmgr::list_programs(); if progs.is_empty() { shell_println!("No programs registered"); } else { for p in &progs { let prio = match p.priority { progmgr::PriorityLevel::Idle => "idle", progmgr::PriorityLevel::BelowNormal => "below", progmgr::PriorityLevel::Normal => "normal", progmgr::PriorityLevel::AboveNormal => "above", progmgr::PriorityLevel::High => "high", progmgr::PriorityLevel::Realtime => "rt" }; let status = if p.installed { "installed" } else { "removed" }; shell_println!("  {} v{} [{}] prio={} caps={}", p.app_id, p.version, status, prio, p.capabilities.len()); } } }
        "installed" => { let progs = progmgr::list_installed(); if progs.is_empty() { shell_println!("No installed programs"); } else { for p in &progs { shell_println!("  {} — {} v{}", p.app_id, p.name, p.version); } } }
        "info" | "show" => { if parts.len() < 2 { shell_println!("Usage: progmgr info <app_id>"); } else { match progmgr::get_program(parts[1]) { Ok(p) => { let prio = match p.priority { progmgr::PriorityLevel::Idle => "Idle", progmgr::PriorityLevel::BelowNormal => "Below Normal", progmgr::PriorityLevel::Normal => "Normal", progmgr::PriorityLevel::AboveNormal => "Above Normal", progmgr::PriorityLevel::High => "High", progmgr::PriorityLevel::Realtime => "Realtime" }; shell_println!("Program: {} ({})", p.name, p.app_id); shell_println!("  Version:    {}", p.version); shell_println!("  Install:    {}", p.install_dir); shell_println!("  Settings:   {}", p.settings_dir); shell_println!("  Data:       {}", p.data_dir); shell_println!("  Priority:   {}", prio); shell_println!("  Caps:       {}", p.capabilities.len()); shell_println!("  Notifs:     {}", p.notifications.len()); shell_println!("  Size:       {} bytes", p.size_bytes); shell_println!("  Installed:  {}", p.installed); shell_println!("  Compilable: {}", p.compilable); shell_println!("  Snapshots:  {}", p.snapshots.len()); }, Err(e) => shell_println!("Error: {:?}", e) } } }
        "register" | "reg" => { if parts.len() < 4 { shell_println!("Usage: progmgr register <app_id> <name> <install_dir> [size]"); } else { let size = parts.get(4).and_then(|s| s.parse::<u64>().ok()).unwrap_or(0); match progmgr::register(parts[1], parts[2], "1.0.0", parts[3], size) { Ok(()) => shell_println!("Registered '{}'", parts[1]), Err(e) => shell_println!("Error: {:?}", e) } } }
        "uninstall" | "uninst" => { if parts.len() < 2 { shell_println!("Usage: progmgr uninstall <app_id> [full|keepfiles|keepsettings|keepall]"); } else { let opt = match parts.get(2).copied().unwrap_or("full") { "keepfiles" | "keep-files" => progmgr::UninstallOption::KeepFiles, "keepsettings" | "keep-settings" => progmgr::UninstallOption::KeepSettings, "keepall" | "keep-all" => progmgr::UninstallOption::KeepAll, _ => progmgr::UninstallOption::Full }; match progmgr::uninstall(parts[1], opt) { Ok(()) => shell_println!("Uninstalled '{}'", parts[1]), Err(e) => shell_println!("Error: {:?}", e) } } }
        "priority" | "prio" => { if parts.len() < 3 { shell_println!("Usage: progmgr priority <app_id> <idle|below|normal|above|high|rt>"); } else { let prio = match parts[2] { "idle" => progmgr::PriorityLevel::Idle, "below" => progmgr::PriorityLevel::BelowNormal, "above" => progmgr::PriorityLevel::AboveNormal, "high" => progmgr::PriorityLevel::High, "rt" | "realtime" => progmgr::PriorityLevel::Realtime, _ => progmgr::PriorityLevel::Normal }; match progmgr::set_priority(parts[1], prio) { Ok(()) => shell_println!("Priority set for '{}'", parts[1]), Err(e) => shell_println!("Error: {:?}", e) } } }
        "grant" => { if parts.len() < 3 { shell_println!("Usage: progmgr grant <app_id> <cap>"); shell_println!("  Caps: network, filesystem, removable, audio, camera, location,"); shell_println!("  notifications, autostart, system, crossapp, background,"); shell_println!("  hardware, install, usermgmt, clipboard"); } else { let cap = match parts[2] { "network" | "net" => Some(progmgr::ProgCapability::Network), "filesystem" | "fs" => Some(progmgr::ProgCapability::FilesystemFull), "removable" => Some(progmgr::ProgCapability::RemovableMedia), "audio" => Some(progmgr::ProgCapability::Audio), "camera" => Some(progmgr::ProgCapability::Camera), "location" => Some(progmgr::ProgCapability::Location), "notifications" | "notif" => Some(progmgr::ProgCapability::Notifications), "autostart" => Some(progmgr::ProgCapability::Autostart), "system" => Some(progmgr::ProgCapability::SystemSettings), "crossapp" => Some(progmgr::ProgCapability::CrossAppData), "background" | "bg" => Some(progmgr::ProgCapability::Background), "hardware" | "hw" => Some(progmgr::ProgCapability::Hardware), "install" => Some(progmgr::ProgCapability::InstallSoftware), "usermgmt" => Some(progmgr::ProgCapability::UserManagement), "clipboard" | "clip" => Some(progmgr::ProgCapability::Clipboard), _ => None }; match cap { Some(c) => match progmgr::grant_capability(parts[1], c) { Ok(()) => shell_println!("Granted '{}' to '{}'", parts[2], parts[1]), Err(e) => shell_println!("Error: {:?}", e) }, None => shell_println!("Unknown capability: {}", parts[2]) } } }
        "revoke" => { if parts.len() < 3 { shell_println!("Usage: progmgr revoke <app_id> <cap>"); } else { let cap = match parts[2] { "network" | "net" => Some(progmgr::ProgCapability::Network), "filesystem" | "fs" => Some(progmgr::ProgCapability::FilesystemFull), "removable" => Some(progmgr::ProgCapability::RemovableMedia), "audio" => Some(progmgr::ProgCapability::Audio), "camera" => Some(progmgr::ProgCapability::Camera), "location" => Some(progmgr::ProgCapability::Location), "notifications" | "notif" => Some(progmgr::ProgCapability::Notifications), "autostart" => Some(progmgr::ProgCapability::Autostart), "system" => Some(progmgr::ProgCapability::SystemSettings), "crossapp" => Some(progmgr::ProgCapability::CrossAppData), "background" | "bg" => Some(progmgr::ProgCapability::Background), "hardware" | "hw" => Some(progmgr::ProgCapability::Hardware), "install" => Some(progmgr::ProgCapability::InstallSoftware), "usermgmt" => Some(progmgr::ProgCapability::UserManagement), "clipboard" | "clip" => Some(progmgr::ProgCapability::Clipboard), _ => None }; match cap { Some(c) => match progmgr::revoke_capability(parts[1], c) { Ok(()) => shell_println!("Revoked '{}' from '{}'", parts[2], parts[1]), Err(e) => shell_println!("Error: {:?}", e) }, None => shell_println!("Unknown capability: {}", parts[2]) } } }
        "addnotif" => { if parts.len() < 3 { shell_println!("Usage: progmgr addnotif <app_id> <name>"); } else { match progmgr::add_notification(parts[1], parts[2]) { Ok(()) => shell_println!("Added notification '{}' to '{}'", parts[2], parts[1]), Err(e) => shell_println!("Error: {:?}", e) } } }
        "rmnotif" => { if parts.len() < 3 { shell_println!("Usage: progmgr rmnotif <app_id> <name>"); } else { match progmgr::remove_notification(parts[1], parts[2]) { Ok(()) => shell_println!("Removed notification '{}' from '{}'", parts[2], parts[1]), Err(e) => shell_println!("Error: {:?}", e) } } }
        "notifcfg" => { if parts.len() < 4 { shell_println!("Usage: progmgr notifcfg <app_id> <name> <show|sound|banner|lock> <value>"); } else { let val = parts.get(4).copied().unwrap_or(""); match parts[3] { "show" => { let v = matches!(val, "on" | "true" | "yes" | "1"); match progmgr::set_notification_config(parts[1], parts[2], Some(v), None, None, None) { Ok(()) => shell_println!("Set show={} for {}/{}", v, parts[1], parts[2]), Err(e) => shell_println!("Error: {:?}", e) } }, "sound" => { match progmgr::set_notification_config(parts[1], parts[2], None, Some(val), None, None) { Ok(()) => shell_println!("Set sound='{}' for {}/{}", val, parts[1], parts[2]), Err(e) => shell_println!("Error: {:?}", e) } }, "banner" => { let v = matches!(val, "on" | "true" | "yes" | "1"); match progmgr::set_notification_config(parts[1], parts[2], None, None, Some(v), None) { Ok(()) => shell_println!("Set banner={} for {}/{}", v, parts[1], parts[2]), Err(e) => shell_println!("Error: {:?}", e) } }, "lock" => { let v = matches!(val, "on" | "true" | "yes" | "1"); match progmgr::set_notification_config(parts[1], parts[2], None, None, None, Some(v)) { Ok(()) => shell_println!("Set lock_screen={} for {}/{}", v, parts[1], parts[2]), Err(e) => shell_println!("Error: {:?}", e) } }, _ => shell_println!("Unknown field: {}", parts[3]) } } }
        "snap" => { if parts.len() < 3 { shell_println!("Usage: progmgr snap <app_id> <name> [full|settings|data] [parent_id]"); } else { let scope = match parts.get(3).copied().unwrap_or("full") { "settings" => progmgr::SnapshotScope::SettingsOnly, "data" => progmgr::SnapshotScope::DataOnly, _ => progmgr::SnapshotScope::Full }; let parent = parts.get(4).and_then(|s| s.parse::<u64>().ok()).unwrap_or(0); match progmgr::create_snapshot(parts[1], parts[2], scope, parent) { Ok(id) => shell_println!("Created snapshot {} for '{}'", id, parts[1]), Err(e) => shell_println!("Error: {:?}", e) } } }
        "rmsnap" => { if parts.len() < 3 { shell_println!("Usage: progmgr rmsnap <app_id> <snap_id>"); } else { match parts[2].parse::<u64>() { Ok(id) => match progmgr::delete_snapshot(parts[1], id) { Ok(()) => shell_println!("Deleted snapshot {}", id), Err(e) => shell_println!("Error: {:?}", e) }, Err(_) => shell_println!("Invalid snapshot id") } } }
        "snaps" => { if parts.len() < 2 { shell_println!("Usage: progmgr snaps <app_id>"); } else { match progmgr::list_snapshots(parts[1]) { Ok(snaps) => { if snaps.is_empty() { shell_println!("No snapshots"); } else { for s in &snaps { let scope = match s.scope { progmgr::SnapshotScope::Full => "full", progmgr::SnapshotScope::SettingsOnly => "settings", progmgr::SnapshotScope::DataOnly => "data" }; shell_println!("  id={} '{}' parent={} scope={} size={}", s.id, s.name, s.parent_id, scope, s.size_bytes); } } }, Err(e) => shell_println!("Error: {:?}", e) } } }
        "rollback" => { if parts.len() < 3 { shell_println!("Usage: progmgr rollback <app_id> <snap_id>"); } else { match parts[2].parse::<u64>() { Ok(id) => match progmgr::rollback(parts[1], id) { Ok(snap) => shell_println!("Rollback to '{}' (scope={:?})", snap.name, snap.scope), Err(e) => shell_println!("Error: {:?}", e) }, Err(_) => shell_println!("Invalid snapshot id") } } }
        "compile" => { if parts.len() < 3 { shell_println!("Usage: progmgr compile <app_id> <source_dir> [params]"); } else { let params = if parts.len() > 3 { parts[3..].join(" ") } else { String::new() }; match progmgr::set_compilable(parts[1], parts[2], &params) { Ok(()) => shell_println!("Marked '{}' as compilable from {}", parts[1], parts[2]), Err(e) => shell_println!("Error: {:?}", e) } } }
        "buildparams" => { if parts.len() < 3 { shell_println!("Usage: progmgr buildparams <app_id> <params...>"); } else { let params = parts[2..].join(" "); match progmgr::set_build_params(parts[1], &params) { Ok(()) => shell_println!("Build params updated for '{}'", parts[1]), Err(e) => shell_println!("Error: {:?}", e) } } }
        "wipedata" => { if parts.len() < 2 { shell_println!("Usage: progmgr wipedata <app_id>"); } else { match progmgr::wipe_data(parts[1]) { Ok(dir) => shell_println!("Wiped data directory: {}", dir), Err(e) => shell_println!("Error: {:?}", e) } } }
        "wipesettings" => { if parts.len() < 2 { shell_println!("Usage: progmgr wipesettings <app_id>"); } else { match progmgr::wipe_settings(parts[1]) { Ok(dir) => shell_println!("Wiped settings directory: {}", dir), Err(e) => shell_println!("Error: {:?}", e) } } }
        "version" => { if parts.len() < 3 { shell_println!("Usage: progmgr version <app_id> <version>"); } else { match progmgr::set_version(parts[1], parts[2]) { Ok(()) => shell_println!("Version set for '{}'", parts[1]), Err(e) => shell_println!("Error: {:?}", e) } } }
        "stats" => { let (total, installed, snaps, ops) = progmgr::stats(); shell_println!("Programs: {} ({} installed)  Snapshots: {}  Operations: {}", total, installed, snaps, ops); }
        "init" => { progmgr::init_defaults(); shell_println!("Program manager initialized with defaults"); }
        "test" => { match progmgr::self_test() { Ok(()) => shell_println!("progmgr: all tests passed"), Err(e) => shell_println!("progmgr: test FAILED: {:?}", e) } }
        _ => {
            shell_println!("progmgr — program management settings");
            shell_println!("  list|ls          List all programs");
            shell_println!("  installed        List installed only");
            shell_println!("  info <id>        Show program details");
            shell_println!("  register <id> <name> <dir>  Register");
            shell_println!("  uninstall <id> [opt]  Uninstall");
            shell_println!("  priority <id> <lvl>   Set priority");
            shell_println!("  grant <id> <cap>      Grant capability");
            shell_println!("  revoke <id> <cap>     Revoke capability");
            shell_println!("  addnotif <id> <name>  Add notification type");
            shell_println!("  rmnotif <id> <name>   Remove notification");
            shell_println!("  notifcfg <id> <n> <k> <v>  Configure");
            shell_println!("  snap <id> <name>      Create snapshot");
            shell_println!("  rmsnap <id> <sid>     Delete snapshot");
            shell_println!("  snaps <id>            List snapshots");
            shell_println!("  rollback <id> <sid>   Rollback to snapshot");
            shell_println!("  compile <id> <src>    Mark compilable");
            shell_println!("  buildparams <id> <p>  Set build params");
            shell_println!("  wipedata <id>         Wipe program data");
            shell_println!("  wipesettings <id>     Wipe settings");
            shell_println!("  version <id> <ver>    Set version");
            shell_println!("  stats                 Show statistics");
            shell_println!("  init                  Load defaults");
            shell_println!("  test                  Run self-tests");
        }
    }
}

/// `scriptlang` / `slang` — scripting language engine registry.
fn cmd_scriptlang(args: &str) {
    use crate::fs::scriptlang;
    let parts: Vec<&str> = args.split_whitespace().collect();
    let sub = parts.first().copied().unwrap_or("");
    match sub {
        "list" | "ls" => { let engines = scriptlang::list_engines(); if engines.is_empty() { shell_println!("No engines registered"); } else { for e in &engines { let etype = match e.engine_type { scriptlang::EngineType::Interpreted => "interp", scriptlang::EngineType::Jit => "jit", scriptlang::EngineType::Wasm => "wasm", scriptlang::EngineType::Shell => "shell", scriptlang::EngineType::Dsl => "dsl", scriptlang::EngineType::Compiled => "compiled" }; let status = if e.enabled { "on" } else { "off" }; shell_println!("  id={} {} v{} [{}] type={} exts={:?}", e.id, e.name, e.version, status, etype, e.extensions); } } }
        "info" | "show" => { if parts.len() < 2 { shell_println!("Usage: scriptlang info <engine_id>"); } else { match parts[1].parse::<u64>() { Ok(id) => match scriptlang::get_engine(id) { Ok(e) => { let etype = match e.engine_type { scriptlang::EngineType::Interpreted => "Interpreted", scriptlang::EngineType::Jit => "JIT", scriptlang::EngineType::Wasm => "WebAssembly", scriptlang::EngineType::Shell => "Shell", scriptlang::EngineType::Dsl => "DSL", scriptlang::EngineType::Compiled => "Compiled" }; let sbox = match e.sandbox { scriptlang::SandboxLevel::None => "None", scriptlang::SandboxLevel::Basic => "Basic", scriptlang::SandboxLevel::Strict => "Strict", scriptlang::SandboxLevel::Capability => "Capability" }; shell_println!("Engine: {} v{} (id={})", e.name, e.version, e.id); shell_println!("  Type:        {}", etype); shell_println!("  Sandbox:     {}", sbox); shell_println!("  Path:        {}", e.engine_path); shell_println!("  Extensions:  {:?}", e.extensions); shell_println!("  MIME types:  {:?}", e.mime_types); shell_println!("  Max memory:  {} bytes", e.max_memory); shell_println!("  Max time:    {} ms", e.max_time_ms); shell_println!("  Builtin:     {}", e.builtin); shell_println!("  Enabled:     {}", e.enabled); shell_println!("  {}", e.description); }, Err(e) => shell_println!("Error: {:?}", e) }, Err(_) => shell_println!("Invalid engine id") } } }
        "register" | "reg" => { if parts.len() < 4 { shell_println!("Usage: scriptlang register <name> <version> <path> [type] [sandbox]"); } else { let etype = match parts.get(4).copied().unwrap_or("interp") { "jit" => scriptlang::EngineType::Jit, "wasm" => scriptlang::EngineType::Wasm, "shell" => scriptlang::EngineType::Shell, "dsl" => scriptlang::EngineType::Dsl, "compiled" => scriptlang::EngineType::Compiled, _ => scriptlang::EngineType::Interpreted }; let sbox = match parts.get(5).copied().unwrap_or("basic") { "none" => scriptlang::SandboxLevel::None, "strict" => scriptlang::SandboxLevel::Strict, "caps" | "capability" => scriptlang::SandboxLevel::Capability, _ => scriptlang::SandboxLevel::Basic }; match scriptlang::register_engine(parts[1], parts[2], etype, sbox, parts[3], "", false) { Ok(id) => shell_println!("Registered '{}' v{} (id={})", parts[1], parts[2], id), Err(e) => shell_println!("Error: {:?}", e) } } }
        "unregister" | "unreg" => { if parts.len() < 2 { shell_println!("Usage: scriptlang unregister <engine_id>"); } else { match parts[1].parse::<u64>() { Ok(id) => match scriptlang::unregister_engine(id) { Ok(()) => shell_println!("Unregistered engine {}", id), Err(e) => shell_println!("Error: {:?}", e) }, Err(_) => shell_println!("Invalid engine id") } } }
        "enable" => { if parts.len() < 2 { shell_println!("Usage: scriptlang enable <engine_id>"); } else { match parts[1].parse::<u64>() { Ok(id) => match scriptlang::set_enabled(id, true) { Ok(()) => shell_println!("Enabled engine {}", id), Err(e) => shell_println!("Error: {:?}", e) }, Err(_) => shell_println!("Invalid engine id") } } }
        "disable" => { if parts.len() < 2 { shell_println!("Usage: scriptlang disable <engine_id>"); } else { match parts[1].parse::<u64>() { Ok(id) => match scriptlang::set_enabled(id, false) { Ok(()) => shell_println!("Disabled engine {}", id), Err(e) => shell_println!("Error: {:?}", e) }, Err(_) => shell_println!("Invalid engine id") } } }
        "addext" => { if parts.len() < 3 { shell_println!("Usage: scriptlang addext <engine_id> <extension>"); } else { match parts[1].parse::<u64>() { Ok(id) => match scriptlang::add_extension(id, parts[2]) { Ok(()) => shell_println!("Added extension '{}' to engine {}", parts[2], id), Err(e) => shell_println!("Error: {:?}", e) }, Err(_) => shell_println!("Invalid engine id") } } }
        "addmime" => { if parts.len() < 3 { shell_println!("Usage: scriptlang addmime <engine_id> <mime_type>"); } else { match parts[1].parse::<u64>() { Ok(id) => match scriptlang::add_mime_type(id, parts[2]) { Ok(()) => shell_println!("Added MIME '{}' to engine {}", parts[2], id), Err(e) => shell_println!("Error: {:?}", e) }, Err(_) => shell_println!("Invalid engine id") } } }
        "limits" => { if parts.len() < 4 { shell_println!("Usage: scriptlang limits <engine_id> <max_memory_mb> <max_time_ms>"); } else { match (parts[1].parse::<u64>(), parts[2].parse::<u64>(), parts[3].parse::<u64>()) { (Ok(id), Ok(mem_mb), Ok(time)) => match scriptlang::set_limits(id, mem_mb * 1024 * 1024, time) { Ok(()) => shell_println!("Set limits for engine {}: {}MB, {}ms", id, mem_mb, time), Err(e) => shell_println!("Error: {:?}", e) }, _ => shell_println!("Invalid arguments") } } }
        "lookup" => { if parts.len() < 2 { shell_println!("Usage: scriptlang lookup <extension>"); } else { match scriptlang::engine_for_extension(parts[1]) { Some(e) => shell_println!("Extension '{}' → {} v{} (id={})", parts[1], e.name, e.version, e.id), None => shell_println!("No engine for extension '{}'", parts[1]) } } }
        "ctx" | "create" => { if parts.len() < 3 { shell_println!("Usage: scriptlang ctx <engine_id> <app_id>"); } else { match parts[1].parse::<u64>() { Ok(id) => match scriptlang::create_context(id, parts[2]) { Ok(h) => shell_println!("Created context {} on engine {} for '{}'", h, id, parts[2]), Err(e) => shell_println!("Error: {:?}", e) }, Err(_) => shell_println!("Invalid engine id") } } }
        "destroy" => { if parts.len() < 2 { shell_println!("Usage: scriptlang destroy <handle>"); } else { match parts[1].parse::<u64>() { Ok(h) => match scriptlang::destroy_context(h) { Ok(()) => shell_println!("Destroyed context {}", h), Err(e) => shell_println!("Error: {:?}", e) }, Err(_) => shell_println!("Invalid handle") } } }
        "contexts" | "ctxs" => { let ctxs = scriptlang::list_contexts(); if ctxs.is_empty() { shell_println!("No active contexts"); } else { for c in &ctxs { shell_println!("  handle={} engine={} app={} evals={} bindings={}", c.handle, c.engine_id, c.app_id, c.eval_count, c.bindings.len()); } } }
        "bind" => { if parts.len() < 4 { shell_println!("Usage: scriptlang bind <handle> <name> <type> [rw]"); } else { match parts[1].parse::<u64>() { Ok(h) => { let writable = parts.get(4).copied() == Some("rw"); match scriptlang::add_binding(h, parts[2], parts[3], writable) { Ok(()) => shell_println!("Bound '{}' in context {}", parts[2], h), Err(e) => shell_println!("Error: {:?}", e) } }, Err(_) => shell_println!("Invalid handle") } } }
        "unbind" => { if parts.len() < 3 { shell_println!("Usage: scriptlang unbind <handle> <name>"); } else { match parts[1].parse::<u64>() { Ok(h) => match scriptlang::remove_binding(h, parts[2]) { Ok(()) => shell_println!("Unbound '{}' from context {}", parts[2], h), Err(e) => shell_println!("Error: {:?}", e) }, Err(_) => shell_println!("Invalid handle") } } }
        "eval" => { if parts.len() < 3 { shell_println!("Usage: scriptlang eval <handle> <code...>"); } else { match parts[1].parse::<u64>() { Ok(h) => { let code = parts[2..].join(" "); match scriptlang::eval(h, &code) { Ok(r) => { if r.success { shell_println!("OK: {} ({}us)", r.output, r.duration_us); } else { shell_println!("ERR: {}", r.error); } }, Err(e) => shell_println!("Error: {:?}", e) } }, Err(_) => shell_println!("Invalid handle") } } }
        "stats" => { let (ec, cc, ev, ch) = scriptlang::stats(); shell_println!("Engines: {}  Contexts: {}  Evals: {}  Changes: {}", ec, cc, ev, ch); }
        "init" => { scriptlang::init_defaults(); shell_println!("Scripting language engines initialized with defaults"); }
        "test" => { match scriptlang::self_test() { Ok(()) => shell_println!("scriptlang: all tests passed"), Err(e) => shell_println!("scriptlang: test FAILED: {:?}", e) } }
        _ => {
            shell_println!("scriptlang — scripting language engine registry");
            shell_println!("  list|ls          List engines");
            shell_println!("  info <id>        Show engine details");
            shell_println!("  register <n> <v> <path>  Register engine");
            shell_println!("  unregister <id>  Remove engine");
            shell_println!("  enable <id>      Enable engine");
            shell_println!("  disable <id>     Disable engine");
            shell_println!("  addext <id> <ext> Add file extension");
            shell_println!("  addmime <id> <m> Add MIME type");
            shell_println!("  limits <id> <mb> <ms>  Set limits");
            shell_println!("  lookup <ext>     Find engine by extension");
            shell_println!("  ctx <id> <app>   Create context");
            shell_println!("  destroy <h>      Destroy context");
            shell_println!("  contexts         List contexts");
            shell_println!("  bind <h> <n> <t> Add binding");
            shell_println!("  unbind <h> <n>   Remove binding");
            shell_println!("  eval <h> <code>  Evaluate code");
            shell_println!("  stats            Show statistics");
            shell_println!("  init             Load defaults");
            shell_println!("  test             Run self-tests");
        }
    }
}

/// `osreset` / `reset` — OS reset, repair, and rollback.
fn cmd_osreset(args: &str) {
    use crate::fs::osreset;
    let parts: Vec<&str> = args.split_whitespace().collect();
    let sub = parts.first().copied().unwrap_or("");
    match sub {
        "status" => { let s = match osreset::status() { osreset::ResetStatus::Idle => "Idle", osreset::ResetStatus::Scanning => "Scanning", osreset::ResetStatus::Checkpointing => "Checkpointing", osreset::ResetStatus::Planning => "Planning", osreset::ResetStatus::Executing => "Executing", osreset::ResetStatus::Repairing => "Repairing" }; shell_println!("Reset status: {}", s); }
        "checkpoint" | "cp" => { if parts.len() < 2 { shell_println!("Usage: osreset checkpoint <name> [full|keepfiles|keepapps|repair]"); } else { let scope = match parts.get(2).copied().unwrap_or("keepfiles") { "full" => osreset::ResetScope::Full, "keepapps" => osreset::ResetScope::KeepFilesAndApps, "repair" => osreset::ResetScope::RepairOnly, _ => osreset::ResetScope::KeepFiles }; match osreset::create_checkpoint(parts[1], scope) { Ok(id) => shell_println!("Created checkpoint {} '{}'", id, parts[1]), Err(e) => shell_println!("Error: {:?}", e) } } }
        "checkpoints" | "cps" => { let cps = osreset::list_checkpoints(); if cps.is_empty() { shell_println!("No checkpoints"); } else { for c in &cps { let scope = match c.scope { osreset::ResetScope::Full => "full", osreset::ResetScope::KeepFiles => "keep-files", osreset::ResetScope::KeepFilesAndApps => "keep-files+apps", osreset::ResetScope::RepairOnly => "repair" }; let valid = if c.valid { "valid" } else { "invalid" }; shell_println!("  id={} '{}' scope={} [{}]", c.id, c.name, scope, valid); } } }
        "rmcp" => { if parts.len() < 2 { shell_println!("Usage: osreset rmcp <checkpoint_id>"); } else { match parts[1].parse::<u64>() { Ok(id) => match osreset::delete_checkpoint(id) { Ok(()) => shell_println!("Deleted checkpoint {}", id), Err(e) => shell_println!("Error: {:?}", e) }, Err(_) => shell_println!("Invalid id") } } }
        "plan" => { if parts.len() < 2 { shell_println!("Usage: osreset plan <full|keepfiles|keepapps|repair>"); } else { let scope = match parts[1] { "full" => osreset::ResetScope::Full, "keepapps" => osreset::ResetScope::KeepFilesAndApps, "repair" => osreset::ResetScope::RepairOnly, _ => osreset::ResetScope::KeepFiles }; match osreset::plan_reset(scope) { Ok(id) => { shell_println!("Created plan {}", id); if let Ok(p) = osreset::get_plan(id) { shell_println!("  Apps to import: {}", p.apps.iter().filter(|a| a.include).count()); shell_println!("  Settings cats:  {}", p.settings.iter().filter(|s| s.include).count()); shell_println!("  Preserve:       {} bytes", p.preserve_bytes); shell_println!("  Delete:         {} bytes", p.delete_bytes); } }, Err(e) => shell_println!("Error: {:?}", e) } } }
        "plans" => { let plans = osreset::list_plans(); if plans.is_empty() { shell_println!("No plans"); } else { for p in &plans { let scope = match p.scope { osreset::ResetScope::Full => "full", osreset::ResetScope::KeepFiles => "keep-files", osreset::ResetScope::KeepFilesAndApps => "keep-files+apps", osreset::ResetScope::RepairOnly => "repair" }; let ex = if p.executed { "executed" } else { "pending" }; shell_println!("  id={} scope={} [{}] apps={} settings={}", p.id, scope, ex, p.apps.len(), p.settings.len()); } } }
        "showplan" => { if parts.len() < 2 { shell_println!("Usage: osreset showplan <plan_id>"); } else { match parts[1].parse::<u64>() { Ok(id) => match osreset::get_plan(id) { Ok(p) => { shell_println!("Plan {} ({:?}):", p.id, p.scope); if !p.apps.is_empty() { shell_println!("  Apps:"); for a in &p.apps { let risk = match a.risk { osreset::AppRiskLevel::Safe => "safe", osreset::AppRiskLevel::Moderate => "moderate", osreset::AppRiskLevel::Dangerous => "DANGEROUS", osreset::AppRiskLevel::Unknown => "unknown" }; let inc = if a.include { "YES" } else { "no" }; shell_println!("    {} [{}] risk={} settings={} data={}", a.name, inc, risk, a.import_settings, a.import_data); } }
                            if !p.settings.is_empty() { shell_println!("  Settings:"); for s in &p.settings { let inc = if s.include { "YES" } else { "no" }; shell_println!("    {:?} [{}] — {}", s.category, inc, s.description); } } }, Err(e) => shell_println!("Error: {:?}", e) }, Err(_) => shell_println!("Invalid id") } } }
        "appinc" => { if parts.len() < 4 { shell_println!("Usage: osreset appinc <plan_id> <app_id> <on|off>"); } else { match parts[1].parse::<u64>() { Ok(pid) => { let inc = matches!(parts[3], "on" | "yes" | "true" | "1"); match osreset::set_app_include(pid, parts[2], inc) { Ok(()) => shell_println!("Set app '{}' include={} in plan {}", parts[2], inc, pid), Err(e) => shell_println!("Error: {:?}", e) } }, Err(_) => shell_println!("Invalid plan id") } } }
        "execute" | "exec" => { if parts.len() < 2 { shell_println!("Usage: osreset execute <plan_id>"); } else { match parts[1].parse::<u64>() { Ok(id) => match osreset::execute_reset(id) { Ok(()) => shell_println!("Reset plan {} executed", id), Err(e) => shell_println!("Error: {:?}", e) }, Err(_) => shell_println!("Invalid id") } } }
        "cancel" => { if parts.len() < 2 { shell_println!("Usage: osreset cancel <plan_id>"); } else { match parts[1].parse::<u64>() { Ok(id) => match osreset::cancel_plan(id) { Ok(()) => shell_println!("Cancelled plan {}", id), Err(e) => shell_println!("Error: {:?}", e) }, Err(_) => shell_println!("Invalid id") } } }
        "rollback" | "rb" => { if parts.len() < 2 { shell_println!("Usage: osreset rollback <checkpoint_id>"); } else { match parts[1].parse::<u64>() { Ok(id) => match osreset::rollback(id) { Ok(cp) => shell_println!("Rolling back to '{}' (checkpoint {})", cp.name, cp.id), Err(e) => shell_println!("Error: {:?}", e) }, Err(_) => shell_println!("Invalid id") } } }
        "scan" => { match osreset::scan_integrity() { Ok(r) => { shell_println!("Integrity scan: {}/{} files OK", r.good_files, r.total_files); if r.corrupted_files > 0 { shell_println!("  Corrupted: {}", r.corrupted_files); }
                if r.missing_files > 0 { shell_println!("  Missing:   {}", r.missing_files); } for path in &r.problem_paths { shell_println!("  ! {}", path); } }, Err(e) => shell_println!("Error: {:?}", e) } }
        "repair" => { match osreset::repair_files() { Ok(n) => { if n > 0 { shell_println!("Repaired {} files", n); } else { shell_println!("No problems to repair (run 'osreset scan' first)"); } }, Err(e) => shell_println!("Error: {:?}", e) } }
        "stats" => { let (cps, plans, problems, ops) = osreset::stats(); shell_println!("Checkpoints: {}  Plans: {}  Problems: {}  Ops: {}", cps, plans, problems, ops); }
        "test" => { match osreset::self_test() { Ok(()) => shell_println!("osreset: all tests passed"), Err(e) => shell_println!("osreset: test FAILED: {:?}", e) } }
        _ => {
            shell_println!("osreset — OS reset, repair, and rollback");
            shell_println!("  status           Current status");
            shell_println!("  checkpoint <n>   Create checkpoint");
            shell_println!("  checkpoints      List checkpoints");
            shell_println!("  rmcp <id>        Delete checkpoint");
            shell_println!("  plan <scope>     Create reset plan");
            shell_println!("  plans            List plans");
            shell_println!("  showplan <id>    Show plan details");
            shell_println!("  appinc <p> <a> <on|off>  Toggle app");
            shell_println!("  execute <id>     Execute plan");
            shell_println!("  cancel <id>      Cancel plan");
            shell_println!("  rollback <id>    Rollback to checkpoint");
            shell_println!("  scan             Integrity scan");
            shell_println!("  repair           Repair corrupted files");
            shell_println!("  stats            Show statistics");
            shell_println!("  test             Run self-tests");
        }
    }
}

/// `bootcfg` / `boot` — bootloader and boot entry management.
fn cmd_bootcfg(args: &str) {
    use crate::fs::bootcfg;
    let parts: Vec<&str> = args.split_whitespace().collect();
    let sub = parts.first().copied().unwrap_or("");
    match sub {
        "show" | "config" => { let cfg = bootcfg::get_config(); let loader = match cfg.loader_type { bootcfg::BootloaderType::Grub2 => "GRUB2", bootcfg::BootloaderType::SystemdBoot => "systemd-boot", bootcfg::BootloaderType::CustomUefi => "Custom UEFI", bootcfg::BootloaderType::DirectUefi => "Direct UEFI" }; let console = match cfg.console_mode { bootcfg::ConsoleMode::Text => "text", bootcfg::ConsoleMode::Graphical => "graphical", bootcfg::ConsoleMode::Verbose => "verbose", bootcfg::ConsoleMode::Silent => "silent" }; shell_println!("Bootloader: {}", loader); shell_println!("Timeout:    {}s", cfg.timeout_secs); shell_println!("Console:    {}", console); shell_println!("Activity:   {}", cfg.show_boot_activity); shell_println!("Secure Boot:{}", cfg.secure_boot); shell_println!("ESP:        {}", cfg.esp_path); shell_println!("GRUB cfg:   {}", cfg.grub_config_path); shell_println!("GFX mode:   {}", cfg.gfx_mode); shell_println!("Dual boot:  {}", cfg.dual_boot); }
        "entries" | "ls" => { let entries = bootcfg::list_entries(); if entries.is_empty() { shell_println!("No boot entries"); } else { for e in &entries { let kind = match e.kind { bootcfg::EntryKind::SlateOs => "os", bootcfg::EntryKind::Linux => "linux", bootcfg::EntryKind::Windows => "windows", bootcfg::EntryKind::MacOs => "macos", bootcfg::EntryKind::Recovery => "recovery", bootcfg::EntryKind::MemTest => "memtest", bootcfg::EntryKind::FirmwareSettings => "firmware", bootcfg::EntryKind::Custom => "custom" }; let def = if e.is_default { " *" } else { "" }; let hid = if e.hidden { " (hidden)" } else { "" }; shell_println!("  #{} id={} {} [{}]{}{}", e.position, e.id, e.name, kind, def, hid); } } }
        "add" => { if parts.len() < 4 { shell_println!("Usage: bootcfg add <name> <kernel_path> <params...> [--type os|linux|windows|recovery]"); } else { let kind = if parts.contains(&"linux") { bootcfg::EntryKind::Linux } else if parts.contains(&"windows") { bootcfg::EntryKind::Windows } else if parts.contains(&"recovery") { bootcfg::EntryKind::Recovery } else { bootcfg::EntryKind::SlateOs }; let params = parts[3..].iter().filter(|p| !["--type", "os", "linux", "windows", "recovery"].contains(p)).copied().collect::<Vec<_>>().join(" "); match bootcfg::add_entry(parts[1], kind, parts[2], "", &params, false) { Ok(id) => shell_println!("Added entry '{}' (id={})", parts[1], id), Err(e) => shell_println!("Error: {:?}", e) } } }
        "remove" | "rm" => { if parts.len() < 2 { shell_println!("Usage: bootcfg remove <entry_id>"); } else { match parts[1].parse::<u64>() { Ok(id) => match bootcfg::remove_entry(id) { Ok(()) => shell_println!("Removed entry {}", id), Err(e) => shell_println!("Error: {:?}", e) }, Err(_) => shell_println!("Invalid id") } } }
        "default" | "def" => { if parts.len() < 2 { shell_println!("Usage: bootcfg default <entry_id>"); } else { match parts[1].parse::<u64>() { Ok(id) => match bootcfg::set_default(id) { Ok(()) => shell_println!("Set default to entry {}", id), Err(e) => shell_println!("Error: {:?}", e) }, Err(_) => shell_println!("Invalid id") } } }
        "params" => { if parts.len() < 3 { shell_println!("Usage: bootcfg params <entry_id> <parameters...>"); } else { match parts[1].parse::<u64>() { Ok(id) => { let params = parts[2..].join(" "); match bootcfg::set_parameters(id, &params) { Ok(()) => shell_println!("Set parameters for entry {}", id), Err(e) => shell_println!("Error: {:?}", e) } }, Err(_) => shell_println!("Invalid id") } } }
        "hide" => { if parts.len() < 2 { shell_println!("Usage: bootcfg hide <entry_id>"); } else { match parts[1].parse::<u64>() { Ok(id) => match bootcfg::set_hidden(id, true) { Ok(()) => shell_println!("Hidden entry {}", id), Err(e) => shell_println!("Error: {:?}", e) }, Err(_) => shell_println!("Invalid id") } } }
        "unhide" => { if parts.len() < 2 { shell_println!("Usage: bootcfg unhide <entry_id>"); } else { match parts[1].parse::<u64>() { Ok(id) => match bootcfg::set_hidden(id, false) { Ok(()) => shell_println!("Unhidden entry {}", id), Err(e) => shell_println!("Error: {:?}", e) }, Err(_) => shell_println!("Invalid id") } } }
        "timeout" => { if parts.len() < 2 { shell_println!("Usage: bootcfg timeout <seconds>"); } else { match parts[1].parse::<u32>() { Ok(s) => match bootcfg::set_timeout(s) { Ok(()) => shell_println!("Timeout set to {}s", s), Err(e) => shell_println!("Error: {:?}", e) }, Err(_) => shell_println!("Invalid seconds") } } }
        "console" => { if parts.len() < 2 { shell_println!("Usage: bootcfg console <text|graphical|verbose|silent>"); } else { let mode = match parts[1] { "text" => bootcfg::ConsoleMode::Text, "verbose" => bootcfg::ConsoleMode::Verbose, "silent" => bootcfg::ConsoleMode::Silent, _ => bootcfg::ConsoleMode::Graphical }; match bootcfg::set_console_mode(mode) { Ok(()) => shell_println!("Console mode set to {}", parts[1]), Err(e) => shell_println!("Error: {:?}", e) } } }
        "activity" => { if parts.len() < 2 { shell_println!("Usage: bootcfg activity <on|off>"); } else { let on = matches!(parts[1], "on" | "true" | "yes" | "1"); match bootcfg::set_boot_activity(on) { Ok(()) => shell_println!("Boot activity listing: {}", if on { "on" } else { "off" }), Err(e) => shell_println!("Error: {:?}", e) } } }
        "gfx" => { if parts.len() < 2 { shell_println!("Usage: bootcfg gfx <resolution>"); } else { match bootcfg::set_gfx_mode(parts[1]) { Ok(()) => shell_println!("GFX mode set to {}", parts[1]), Err(e) => shell_println!("Error: {:?}", e) } } }
        "loader" => { if parts.len() < 2 { shell_println!("Usage: bootcfg loader <grub2|systemd|custom|direct>"); } else { let lt = match parts[1] { "grub2" | "grub" => bootcfg::BootloaderType::Grub2, "systemd" | "sd-boot" => bootcfg::BootloaderType::SystemdBoot, "direct" => bootcfg::BootloaderType::DirectUefi, _ => bootcfg::BootloaderType::CustomUefi }; match bootcfg::set_loader_type(lt) { Ok(()) => shell_println!("Loader type set"), Err(e) => shell_println!("Error: {:?}", e) } } }
        "log" => { let limit = parts.get(1).and_then(|s| s.parse::<usize>().ok()).unwrap_or(10); let log = bootcfg::boot_log(limit); if log.is_empty() { shell_println!("No boot events"); } else { for ev in &log { let ok = if ev.success { "OK" } else { "FAIL" }; shell_println!("  #{} {} [{}] {}ms — {}", ev.id, ev.entry_name, ok, ev.duration_ms, ev.reason); } } }
        "stats" => { let (ec, evc, boots, ch) = bootcfg::stats(); shell_println!("Entries: {}  Events: {}  Total boots: {}  Changes: {}", ec, evc, boots, ch); }
        "init" => { bootcfg::init_defaults(); shell_println!("Boot configuration initialized with defaults"); }
        "test" => { match bootcfg::self_test() { Ok(()) => shell_println!("bootcfg: all tests passed"), Err(e) => shell_println!("bootcfg: test FAILED: {:?}", e) } }
        _ => {
            shell_println!("bootcfg — bootloader and boot entry management");
            shell_println!("  show             Show configuration");
            shell_println!("  entries          List boot entries");
            shell_println!("  add <n> <k> <p>  Add entry");
            shell_println!("  remove <id>      Remove entry");
            shell_println!("  default <id>     Set default entry");
            shell_println!("  params <id> <p>  Set kernel params");
            shell_println!("  hide <id>        Hide entry");
            shell_println!("  unhide <id>      Unhide entry");
            shell_println!("  timeout <sec>    Set menu timeout");
            shell_println!("  console <mode>   Set console mode");
            shell_println!("  activity <on|off> Boot activity listing");
            shell_println!("  gfx <res>        Set GFX resolution");
            shell_println!("  loader <type>    Set bootloader type");
            shell_println!("  log [n]          Show boot log");
            shell_println!("  stats            Show statistics");
            shell_println!("  init             Load defaults");
            shell_println!("  test             Run self-tests");
        }
    }
}

/// `swapcfg` / `swap` — swap space configuration and management.
fn cmd_swapcfg(args: &str) {
    use crate::fs::swapcfg;
    let parts: Vec<&str> = args.split_whitespace().collect();
    let sub = parts.first().copied().unwrap_or("");
    match sub {
        "show" | "config" => { let cfg = swapcfg::get_config(); shell_println!("Swap enabled:  {}", cfg.enabled); shell_println!("Swappiness:    {}", cfg.swappiness); shell_println!("Min free:      {} bytes", cfg.min_free_bytes); shell_println!("zswap:         {} ({}, {}%)", cfg.zswap_enabled, cfg.zswap_algorithm, cfg.zswap_max_pool_pct); shell_println!("Hibernate ID:  {}", cfg.hibernate_swap_id); }
        "list" | "ls" => { let areas = swapcfg::list_swaps(); if areas.is_empty() { shell_println!("No swap areas"); } else { for a in &areas { let stype = match a.swap_type { swapcfg::SwapType::File => "file", swapcfg::SwapType::Partition => "part", swapcfg::SwapType::Compressed => "zram" }; let status = if a.active { "active" } else { "off" }; let mb = a.size_bytes / (1024 * 1024); let used_mb = a.used_bytes / (1024 * 1024); shell_println!("  id={} {} [{}] {} {}MB/{}MB prio={}", a.id, a.path, stype, status, used_mb, mb, a.priority.0); } } }
        "usage" => { let u = swapcfg::usage(); let total_mb = u.total_bytes / (1024 * 1024); let used_mb = u.used_bytes / (1024 * 1024); let free_mb = u.free_bytes / (1024 * 1024); shell_println!("Total: {}MB  Used: {}MB  Free: {}MB  Active areas: {}", total_mb, used_mb, free_mb, u.active_areas); shell_println!("Pages in: {}  Pages out: {}", u.pages_in, u.pages_out); }
        "add" => { if parts.len() < 3 { shell_println!("Usage: swapcfg add <path> <size_mb> [file|partition|zram] [priority]"); } else { match parts[2].parse::<u64>() { Ok(mb) => { let stype = match parts.get(3).copied().unwrap_or("file") { "partition" | "part" => swapcfg::SwapType::Partition, "zram" | "compressed" => swapcfg::SwapType::Compressed, _ => swapcfg::SwapType::File }; let prio = parts.get(4).and_then(|s| s.parse::<i32>().ok()).unwrap_or(0); match swapcfg::add_swap(stype, parts[1], mb * 1024 * 1024, prio, "") { Ok(id) => shell_println!("Added swap '{}' (id={}, {}MB)", parts[1], id, mb), Err(e) => shell_println!("Error: {:?}", e) } }, Err(_) => shell_println!("Invalid size") } } }
        "remove" | "rm" => { if parts.len() < 2 { shell_println!("Usage: swapcfg remove <id>"); } else { match parts[1].parse::<u64>() { Ok(id) => match swapcfg::remove_swap(id) { Ok(()) => shell_println!("Removed swap {}", id), Err(e) => shell_println!("Error: {:?}", e) }, Err(_) => shell_println!("Invalid id") } } }
        "on" | "activate" => { if parts.len() < 2 { shell_println!("Usage: swapcfg on <id>"); } else { match parts[1].parse::<u64>() { Ok(id) => match swapcfg::activate(id) { Ok(()) => shell_println!("Activated swap {}", id), Err(e) => shell_println!("Error: {:?}", e) }, Err(_) => shell_println!("Invalid id") } } }
        "off" | "deactivate" => { if parts.len() < 2 { shell_println!("Usage: swapcfg off <id>"); } else { match parts[1].parse::<u64>() { Ok(id) => match swapcfg::deactivate(id) { Ok(()) => shell_println!("Deactivated swap {}", id), Err(e) => shell_println!("Error: {:?}", e) }, Err(_) => shell_println!("Invalid id") } } }
        "resize" => { if parts.len() < 3 { shell_println!("Usage: swapcfg resize <id> <new_size_mb>"); } else { match (parts[1].parse::<u64>(), parts[2].parse::<u64>()) { (Ok(id), Ok(mb)) => match swapcfg::resize(id, mb * 1024 * 1024) { Ok(()) => shell_println!("Resized swap {} to {}MB", id, mb), Err(e) => shell_println!("Error: {:?}", e) }, _ => shell_println!("Invalid arguments") } } }
        "priority" | "prio" => { if parts.len() < 3 { shell_println!("Usage: swapcfg priority <id> <value>"); } else { match (parts[1].parse::<u64>(), parts[2].parse::<i32>()) { (Ok(id), Ok(p)) => match swapcfg::set_priority(id, p) { Ok(()) => shell_println!("Set priority {} for swap {}", p, id), Err(e) => shell_println!("Error: {:?}", e) }, _ => shell_println!("Invalid arguments") } } }
        "swappiness" => { if parts.len() < 2 { shell_println!("Usage: swapcfg swappiness <0-100>"); } else { match parts[1].parse::<u32>() { Ok(v) => match swapcfg::set_swappiness(v) { Ok(()) => shell_println!("Swappiness set to {}", v), Err(e) => shell_println!("Error: {:?}", e) }, Err(_) => shell_println!("Invalid value") } } }
        "enable" => { match swapcfg::set_enabled(true) { Ok(()) => shell_println!("Swap enabled"), Err(e) => shell_println!("Error: {:?}", e) } }
        "disable" => { match swapcfg::set_enabled(false) { Ok(()) => shell_println!("Swap disabled"), Err(e) => shell_println!("Error: {:?}", e) } }
        "zswap" => { if parts.len() < 3 { shell_println!("Usage: swapcfg zswap <on|off> <algorithm> [max_pool_%]"); } else { let on = matches!(parts[1], "on" | "true" | "yes"); let algo = parts[2]; let pct = parts.get(3).and_then(|s| s.parse::<u32>().ok()).unwrap_or(20); match swapcfg::set_zswap(on, algo, pct) { Ok(()) => shell_println!("zswap: {} algorithm={} pool={}%", if on { "enabled" } else { "disabled" }, algo, pct), Err(e) => shell_println!("Error: {:?}", e) } } }
        "stats" => { let (ac, active, total, ops) = swapcfg::stats(); let total_mb = total / (1024 * 1024); shell_println!("Areas: {} ({} active)  Total: {}MB  Ops: {}", ac, active, total_mb, ops); }
        "init" => { swapcfg::init_defaults(); shell_println!("Swap configuration initialized with defaults"); }
        "test" => { match swapcfg::self_test() { Ok(()) => shell_println!("swapcfg: all tests passed"), Err(e) => shell_println!("swapcfg: test FAILED: {:?}", e) } }
        _ => {
            shell_println!("swapcfg — swap space configuration");
            shell_println!("  show             Show configuration");
            shell_println!("  list             List swap areas");
            shell_println!("  usage            Show usage stats");
            shell_println!("  add <path> <mb>  Add swap area");
            shell_println!("  remove <id>      Remove swap area");
            shell_println!("  on <id>          Activate");
            shell_println!("  off <id>         Deactivate");
            shell_println!("  resize <id> <mb> Resize");
            shell_println!("  priority <id> <v> Set priority");
            shell_println!("  swappiness <n>   Set swappiness");
            shell_println!("  enable/disable   Toggle swap");
            shell_println!("  zswap <on> <alg> Configure zswap");
            shell_println!("  stats            Show statistics");
            shell_println!("  init             Load defaults");
            shell_println!("  test             Run self-tests");
        }
    }
}

/// `fstune` — filesystem tuning profiles and parameters.
fn cmd_fstune(args: &str) {
    use crate::fs::fstune;
    let parts: Vec<&str> = args.split_whitespace().collect();
    let sub = parts.first().copied().unwrap_or("");
    match sub {
        "list" => {
            let profiles = fstune::list_profiles();
            if profiles.is_empty() { shell_println!("No profiles"); return; }
            shell_println!("{:<6} {:<20} {:<8} {:<12} {:<8} {:<10} {}", "ID", "NAME", "FS", "WORKLOAD", "BLOCK", "JOURNAL", "APPLIED");
            for p in &profiles {
                let fs_name = match p.fs_type { fstune::FsType::Ext4 => "ext4", fstune::FsType::Btrfs => "btrfs", fstune::FsType::Xfs => "xfs", fstune::FsType::F2fs => "f2fs", fstune::FsType::Fat32 => "fat32" };
                let wl = match p.workload { fstune::WorkloadType::Desktop => "desktop", fstune::WorkloadType::Database => "database", fstune::WorkloadType::Server => "server", fstune::WorkloadType::Development => "dev", fstune::WorkloadType::Gaming => "gaming" };
                let jm = match p.journal_mode { fstune::JournalMode::Ordered => "ordered", fstune::JournalMode::Journal => "journal", fstune::JournalMode::Writeback => "writeback", fstune::JournalMode::Off => "off" };
                shell_println!("{:<6} {:<20} {:<8} {:<12} {:<8} {:<10} {}", p.id, p.name, fs_name, wl, p.block_size, jm, if p.applied { "yes" } else { "no" });
            }
        }
        "info" => {
            let id: u64 = parts.get(1).and_then(|s| s.parse().ok()).unwrap_or(0);
            match fstune::get_profile(id) {
                Ok(p) => {
                    shell_println!("ID:              {}", p.id);
                    shell_println!("Name:            {}", p.name);
                    shell_println!("Block size:      {}", p.block_size);
                    shell_println!("Journal mode:    {:?}", p.journal_mode);
                    shell_println!("Commit interval: {}s", p.commit_interval_secs);
                    shell_println!("Reserved:        {}%", p.reserved_pct);
                    shell_println!("Inode ratio:     {}", p.inode_ratio);
                    shell_println!("Dir index:       {}", p.dir_index);
                    shell_println!("Alloc strategy:  {:?}", p.alloc_strategy);
                    shell_println!("Lazy init:       {}", p.lazy_init);
                    shell_println!("Discard:         {}", p.discard);
                    shell_println!("Xattr:           {}", p.xattr);
                    shell_println!("Stripe width:    {}", p.stripe_width);
                    shell_println!("Data checksum:   {}", p.data_checksum);
                    shell_println!("Compression:     {}{}", p.compression, if p.compression { alloc::format!(" ({})", p.compression_algo) } else { alloc::string::String::new() });
                    shell_println!("Applied:         {}", p.applied);
                }
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "create" => {
            let name = parts.get(1).copied().unwrap_or("unnamed");
            let fs_type = match parts.get(2).copied().unwrap_or("ext4") {
                "btrfs" => fstune::FsType::Btrfs, "xfs" => fstune::FsType::Xfs, "f2fs" => fstune::FsType::F2fs, "fat32" => fstune::FsType::Fat32, _ => fstune::FsType::Ext4,
            };
            let workload = match parts.get(3).copied().unwrap_or("desktop") {
                "database" | "db" => fstune::WorkloadType::Database, "server" | "srv" => fstune::WorkloadType::Server, "dev" | "development" => fstune::WorkloadType::Development, "gaming" | "game" => fstune::WorkloadType::Gaming, _ => fstune::WorkloadType::Desktop,
            };
            match fstune::create_profile(name, fs_type, workload) { Ok(id) => shell_println!("Created profile {} (ID {})", name, id), Err(e) => shell_println!("Error: {:?}", e) }
        }
        "remove" => {
            let id: u64 = parts.get(1).and_then(|s| s.parse().ok()).unwrap_or(0);
            match fstune::remove_profile(id) { Ok(()) => shell_println!("Removed"), Err(e) => shell_println!("Error: {:?}", e) }
        }
        "workload" => {
            let id: u64 = parts.get(1).and_then(|s| s.parse().ok()).unwrap_or(0);
            let wl = match parts.get(2).copied().unwrap_or("desktop") {
                "database" | "db" => fstune::WorkloadType::Database, "server" | "srv" => fstune::WorkloadType::Server, "dev" | "development" => fstune::WorkloadType::Development, "gaming" | "game" => fstune::WorkloadType::Gaming, _ => fstune::WorkloadType::Desktop,
            };
            match fstune::apply_workload(id, wl) { Ok(()) => shell_println!("Applied workload preset"), Err(e) => shell_println!("Error: {:?}", e) }
        }
        "blocksize" => {
            let id: u64 = parts.get(1).and_then(|s| s.parse().ok()).unwrap_or(0);
            let sz: u32 = parts.get(2).and_then(|s| s.parse().ok()).unwrap_or(0);
            match fstune::set_block_size(id, sz) { Ok(()) => shell_println!("Block size set to {}", sz), Err(e) => shell_println!("Error: {:?}", e) }
        }
        "journal" => {
            let id: u64 = parts.get(1).and_then(|s| s.parse().ok()).unwrap_or(0);
            let mode = match parts.get(2).copied().unwrap_or("ordered") {
                "journal" | "full" => fstune::JournalMode::Journal, "writeback" | "wb" => fstune::JournalMode::Writeback, "off" | "none" => fstune::JournalMode::Off, _ => fstune::JournalMode::Ordered,
            };
            match fstune::set_journal_mode(id, mode) { Ok(()) => shell_println!("Journal mode set"), Err(e) => shell_println!("Error: {:?}", e) }
        }
        "commit" => {
            let id: u64 = parts.get(1).and_then(|s| s.parse().ok()).unwrap_or(0);
            let secs: u32 = parts.get(2).and_then(|s| s.parse().ok()).unwrap_or(0);
            match fstune::set_commit_interval(id, secs) { Ok(()) => shell_println!("Commit interval set to {}s", secs), Err(e) => shell_println!("Error: {:?}", e) }
        }
        "reserved" => {
            let id: u64 = parts.get(1).and_then(|s| s.parse().ok()).unwrap_or(0);
            let pct: u32 = parts.get(2).and_then(|s| s.parse().ok()).unwrap_or(0);
            match fstune::set_reserved_pct(id, pct) { Ok(()) => shell_println!("Reserved {}%", pct), Err(e) => shell_println!("Error: {:?}", e) }
        }
        "inode" => {
            let id: u64 = parts.get(1).and_then(|s| s.parse().ok()).unwrap_or(0);
            let ratio: u32 = parts.get(2).and_then(|s| s.parse().ok()).unwrap_or(0);
            match fstune::set_inode_ratio(id, ratio) { Ok(()) => shell_println!("Inode ratio set to {}", ratio), Err(e) => shell_println!("Error: {:?}", e) }
        }
        "alloc" => {
            let id: u64 = parts.get(1).and_then(|s| s.parse().ok()).unwrap_or(0);
            let strat = match parts.get(2).copied().unwrap_or("spread") {
                "pack" => fstune::AllocStrategy::Pack, "sequential" | "seq" => fstune::AllocStrategy::Sequential, _ => fstune::AllocStrategy::Spread,
            };
            match fstune::set_alloc_strategy(id, strat) { Ok(()) => shell_println!("Alloc strategy set"), Err(e) => shell_println!("Error: {:?}", e) }
        }
        "discard" => {
            let id: u64 = parts.get(1).and_then(|s| s.parse().ok()).unwrap_or(0);
            let on = parts.get(2).copied().unwrap_or("on") != "off";
            match fstune::set_discard(id, on) { Ok(()) => shell_println!("Discard {}", if on { "enabled" } else { "disabled" }), Err(e) => shell_println!("Error: {:?}", e) }
        }
        "checksum" => {
            let id: u64 = parts.get(1).and_then(|s| s.parse().ok()).unwrap_or(0);
            let on = parts.get(2).copied().unwrap_or("on") != "off";
            match fstune::set_data_checksum(id, on) { Ok(()) => shell_println!("Data checksum {}", if on { "enabled" } else { "disabled" }), Err(e) => shell_println!("Error: {:?}", e) }
        }
        "compress" => {
            let id: u64 = parts.get(1).and_then(|s| s.parse().ok()).unwrap_or(0);
            let algo = parts.get(2).copied().unwrap_or("off");
            if algo == "off" { match fstune::set_compression(id, false, "") { Ok(()) => shell_println!("Compression disabled"), Err(e) => shell_println!("Error: {:?}", e) } }
            else { match fstune::set_compression(id, true, algo) { Ok(()) => shell_println!("Compression: {}", algo), Err(e) => shell_println!("Error: {:?}", e) } }
        }
        "apply" => {
            let id: u64 = parts.get(1).and_then(|s| s.parse().ok()).unwrap_or(0);
            match fstune::mark_applied(id) { Ok(()) => shell_println!("Marked as applied"), Err(e) => shell_println!("Error: {:?}", e) }
        }
        "tradeoffs" => {
            let infos = fstune::tradeoffs();
            if infos.is_empty() { shell_println!("No tradeoff info (run init first)"); return; }
            for t in &infos {
                shell_println!("\n{} = {}", t.param_name, t.value_desc);
                for a in &t.advantages { shell_println!("  + {}", a); }
                for d in &t.disadvantages { shell_println!("  - {}", d); }
            }
        }
        "stats" => { let (p, t, a, ops) = fstune::stats(); shell_println!("Profiles: {}  Tradeoffs: {}  Applied: {}  Ops: {}", p, t, a, ops); }
        "init" => { fstune::init_defaults(); shell_println!("Defaults initialised"); }
        "test" => { match fstune::self_test() { Ok(()) => shell_println!("All tests passed"), Err(e) => shell_println!("Test failed: {:?}", e) } }
        _ => shell_println!("Usage: fstune <list|info|create|remove|workload|blocksize|journal|commit|reserved|inode|alloc|discard|checksum|compress|apply|tradeoffs|stats|init|test>"),
    }
}

/// `certmgr` / `cert` — SSL/TLS certificate management.
fn cmd_certmgr(args: &str) {
    use crate::fs::certmgr;
    let parts: Vec<&str> = args.split_whitespace().collect();
    let sub = parts.first().copied().unwrap_or("");
    match sub {
        "list" => {
            let certs = certmgr::list_certs();
            if certs.is_empty() { shell_println!("No certificates"); return; }
            shell_println!("{:<6} {:<28} {:<10} {:<8} {:<10} {}", "ID", "CN", "TYPE", "SRC", "STATUS", "AUTO");
            for c in &certs {
                let ct = match c.cert_type { certmgr::CertType::Root => "root", certmgr::CertType::Intermediate => "inter", certmgr::CertType::Server => "server", certmgr::CertType::Client => "client", certmgr::CertType::CodeSigning => "code", certmgr::CertType::SelfSigned => "self" };
                let src = match c.source { certmgr::CertSource::System => "sys", certmgr::CertSource::UserImported => "user", certmgr::CertSource::LetsEncrypt => "LE", certmgr::CertSource::Acme => "acme", certmgr::CertSource::Generated => "gen" };
                let st = match c.status { certmgr::CertStatus::Valid => "valid", certmgr::CertStatus::Expired => "expired", certmgr::CertStatus::Revoked => "revoked", certmgr::CertStatus::NotYetValid => "future", certmgr::CertStatus::Untrusted => "untrust", certmgr::CertStatus::Disabled => "off" };
                shell_println!("{:<6} {:<28} {:<10} {:<8} {:<10} {}", c.id, c.common_name, ct, src, st, if c.auto_renew { "yes" } else { "no" });
            }
        }
        "info" => {
            let id: u64 = parts.get(1).and_then(|s| s.parse().ok()).unwrap_or(0);
            match certmgr::get_cert(id) {
                Ok(c) => {
                    shell_println!("ID:          {}", c.id);
                    shell_println!("CN:          {}", c.common_name);
                    shell_println!("SANs:        {}", if c.alt_names.is_empty() { alloc::string::String::from("(none)") } else { c.alt_names.join(", ") });
                    shell_println!("Type:        {:?}", c.cert_type);
                    shell_println!("Source:      {:?}", c.source);
                    shell_println!("Status:      {:?}", c.status);
                    shell_println!("Key:         {:?}", c.key_type);
                    shell_println!("Issuer:      {}", c.issuer);
                    shell_println!("Serial:      {}", c.serial);
                    shell_println!("Fingerprint: {}", c.fingerprint);
                    shell_println!("Service:     {}", if c.service.is_empty() { "(system-wide)" } else { &c.service });
                    shell_println!("Auto-renew:  {}", c.auto_renew);
                    shell_println!("Renewals:    {}", c.renewal_count);
                    shell_println!("Cert path:   {}", c.cert_path);
                    shell_println!("Key path:    {}", c.key_path);
                    shell_println!("Pinned:      {}", c.pinned);
                }
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "import" => {
            let cn = parts.get(1).copied().unwrap_or("unknown");
            let ct = match parts.get(2).copied().unwrap_or("server") {
                "root" => certmgr::CertType::Root, "inter" => certmgr::CertType::Intermediate, "client" => certmgr::CertType::Client, "code" => certmgr::CertType::CodeSigning, "self" => certmgr::CertType::SelfSigned, _ => certmgr::CertType::Server,
            };
            let cert_path = parts.get(3).copied().unwrap_or("/etc/ssl/certs/cert.pem");
            let key_path = parts.get(4).copied().unwrap_or("");
            match certmgr::import_cert(cn, ct, certmgr::CertSource::UserImported, certmgr::KeyType::EcdsaP256, "User", cert_path, key_path) {
                Ok(id) => shell_println!("Imported {} (ID {})", cn, id), Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "remove" => {
            let id: u64 = parts.get(1).and_then(|s| s.parse().ok()).unwrap_or(0);
            match certmgr::remove_cert(id) { Ok(()) => shell_println!("Removed"), Err(e) => shell_println!("Error: {:?}", e) }
        }
        "san" => {
            let id: u64 = parts.get(1).and_then(|s| s.parse().ok()).unwrap_or(0);
            let name = parts.get(2).copied().unwrap_or("");
            match certmgr::add_san(id, name) { Ok(()) => shell_println!("SAN added: {}", name), Err(e) => shell_println!("Error: {:?}", e) }
        }
        "service" => {
            let id: u64 = parts.get(1).and_then(|s| s.parse().ok()).unwrap_or(0);
            let svc = parts.get(2).copied().unwrap_or("");
            match certmgr::set_service(id, svc) { Ok(()) => shell_println!("Service set: {}", svc), Err(e) => shell_println!("Error: {:?}", e) }
        }
        "status" => {
            let id: u64 = parts.get(1).and_then(|s| s.parse().ok()).unwrap_or(0);
            let st = match parts.get(2).copied().unwrap_or("valid") {
                "expired" => certmgr::CertStatus::Expired, "revoked" => certmgr::CertStatus::Revoked, "disabled" | "off" => certmgr::CertStatus::Disabled, "untrusted" => certmgr::CertStatus::Untrusted, _ => certmgr::CertStatus::Valid,
            };
            match certmgr::set_status(id, st) { Ok(()) => shell_println!("Status updated"), Err(e) => shell_println!("Error: {:?}", e) }
        }
        "autorenew" => {
            let id: u64 = parts.get(1).and_then(|s| s.parse().ok()).unwrap_or(0);
            let on = parts.get(2).copied().unwrap_or("on") != "off";
            match certmgr::set_auto_renew(id, on) { Ok(()) => shell_println!("Auto-renew {}", if on { "enabled" } else { "disabled" }), Err(e) => shell_println!("Error: {:?}", e) }
        }
        "pin" => {
            let id: u64 = parts.get(1).and_then(|s| s.parse().ok()).unwrap_or(0);
            let on = parts.get(2).copied().unwrap_or("on") != "off";
            match certmgr::set_pinned(id, on) { Ok(()) => shell_println!("{}", if on { "Pinned" } else { "Unpinned" }), Err(e) => shell_println!("Error: {:?}", e) }
        }
        "renew" => {
            let id: u64 = parts.get(1).and_then(|s| s.parse().ok()).unwrap_or(0);
            match certmgr::renew_cert(id) { Ok(()) => shell_println!("Renewed"), Err(e) => shell_println!("Error: {:?}", e) }
        }
        "threshold" => {
            let days: u32 = parts.get(1).and_then(|s| s.parse().ok()).unwrap_or(0);
            if days == 0 { shell_println!("Renewal threshold: {} days", certmgr::renewal_threshold()); }
            else { match certmgr::set_renewal_threshold(days) { Ok(()) => shell_println!("Threshold set to {} days", days), Err(e) => shell_println!("Error: {:?}", e) } }
        }
        "request" => {
            let domain = parts.get(1).copied().unwrap_or("example.com");
            let email = parts.get(2).copied().unwrap_or("admin@example.com");
            match certmgr::request_cert(domain, email, certmgr::KeyType::EcdsaP256, certmgr::ChallengeType::Http01) {
                Ok(id) => shell_println!("ACME request {} for {}", id, domain), Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "complete" => {
            let id: u64 = parts.get(1).and_then(|s| s.parse().ok()).unwrap_or(0);
            match certmgr::complete_request(id) { Ok(cid) => shell_println!("Certificate created (ID {})", cid), Err(e) => shell_println!("Error: {:?}", e) }
        }
        "requests" => {
            let reqs = certmgr::list_requests();
            if reqs.is_empty() { shell_println!("No pending requests"); return; }
            for r in &reqs { shell_println!("ID {} domain={} state={:?}", r.id, r.domain, r.state); }
        }
        "find" => {
            let domain = parts.get(1).copied().unwrap_or("");
            let matches = certmgr::certs_for_domain(domain);
            if matches.is_empty() { shell_println!("No certs for {}", domain); }
            else { for c in &matches { shell_println!("ID {} {} ({:?})", c.id, c.common_name, c.status); } }
        }
        "stats" => { let (t, r, s, req, ops) = certmgr::stats(); shell_println!("Total: {}  Roots: {}  Servers: {}  Requests: {}  Ops: {}", t, r, s, req, ops); }
        "init" => { certmgr::init_defaults(); shell_println!("Defaults initialised"); }
        "test" => { match certmgr::self_test() { Ok(()) => shell_println!("All tests passed"), Err(e) => shell_println!("Test failed: {:?}", e) } }
        _ => shell_println!("Usage: certmgr <list|info|import|remove|san|service|status|autorenew|pin|renew|threshold|request|complete|requests|find|stats|init|test>"),
    }
}

/// `installer` — OS installation wizard management.
fn cmd_installer(args: &str) {
    use crate::fs::installer;
    let parts: Vec<&str> = args.split_whitespace().collect();
    let sub = parts.first().copied().unwrap_or("");
    match sub {
        "list" => {
            let sessions = installer::list_sessions();
            if sessions.is_empty() { shell_println!("No sessions"); return; }
            shell_println!("{:<6} {:<12} {:<14} {:<5} {}", "ID", "MODE", "PHASE", "PCT", "STATUS");
            for s in &sessions {
                let mode = match s.mode { installer::InstallMode::Easy => "easy", installer::InstallMode::Manual => "manual", installer::InstallMode::Unattended => "unattended" };
                let phase = match s.phase { installer::InstallPhase::NotStarted => "not-started", installer::InstallPhase::PreInstall => "pre-install", installer::InstallPhase::Partitioning => "partitioning", installer::InstallPhase::Copying => "copying", installer::InstallPhase::Bootloader => "bootloader", installer::InstallPhase::PendingReboot => "reboot", installer::InstallPhase::FirstBoot => "first-boot", installer::InstallPhase::Complete => "complete", installer::InstallPhase::Failed => "FAILED" };
                shell_println!("{:<6} {:<12} {:<14} {:<5} {}", s.id, mode, phase, s.progress_pct, s.status_message);
            }
        }
        "info" => {
            let id: u64 = parts.get(1).and_then(|s| s.parse().ok()).unwrap_or(0);
            match installer::get_session(id) {
                Ok(s) => {
                    shell_println!("ID:        {}", s.id);
                    shell_println!("Mode:      {:?}", s.mode);
                    shell_println!("Phase:     {:?}", s.phase);
                    shell_println!("Progress:  {}%", s.progress_pct);
                    shell_println!("Keyboard:  {} {}", s.keyboard_layout, s.keyboard_variant);
                    shell_println!("Scale:     {:?} ({}dpi)", s.scale_preset, s.detected_dpi);
                    shell_println!("Workload:  {:?}", s.workload);
                    if let Some(ref plan) = s.partition_plan {
                        shell_println!("Disk:      {} (erase={})", plan.disk, plan.erase_disk);
                        shell_println!("Boot:      {} MiB", plan.boot_mib);
                        shell_println!("Swap:      {}", if let Some(m) = plan.swap_mib { alloc::format!("{} MiB partition", m) } else { alloc::string::String::from("swap file") });
                    }
                    shell_println!("Timezone:  {}", s.timezone);
                    shell_println!("User:      {} (pass={} auto={})", s.username, s.password_set, s.auto_login);
                    shell_println!("Browser:   {:?}", s.browser);
                    shell_println!("Theme:     {}", s.theme_mode);
                    if !s.wifi_ssid.is_empty() { shell_println!("Wifi:      {}", s.wifi_ssid); }
                    if !s.error_message.is_empty() { shell_println!("Error:     {}", s.error_message); }
                }
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "create" => {
            let mode = match parts.get(1).copied().unwrap_or("easy") {
                "manual" => installer::InstallMode::Manual, "unattended" | "auto" => installer::InstallMode::Unattended, _ => installer::InstallMode::Easy,
            };
            match installer::create_session(mode) { Ok(id) => shell_println!("Created session {}", id), Err(e) => shell_println!("Error: {:?}", e) }
        }
        "remove" => {
            let id: u64 = parts.get(1).and_then(|s| s.parse().ok()).unwrap_or(0);
            match installer::remove_session(id) { Ok(()) => shell_println!("Removed"), Err(e) => shell_println!("Error: {:?}", e) }
        }
        "keyboard" => {
            let id: u64 = parts.get(1).and_then(|s| s.parse().ok()).unwrap_or(0);
            let layout = parts.get(2).copied().unwrap_or("us");
            let variant = parts.get(3).copied().unwrap_or("");
            match installer::set_keyboard(id, layout, variant) { Ok(()) => shell_println!("Keyboard: {} {}", layout, variant), Err(e) => shell_println!("Error: {:?}", e) }
        }
        "scaling" => {
            let id: u64 = parts.get(1).and_then(|s| s.parse().ok()).unwrap_or(0);
            let dpi: u32 = parts.get(2).and_then(|s| s.parse().ok()).unwrap_or(96);
            match installer::detect_and_set_scaling(id, dpi) { Ok(p) => shell_println!("DPI {} → {:?}", dpi, p), Err(e) => shell_println!("Error: {:?}", e) }
        }
        "workload" => {
            let id: u64 = parts.get(1).and_then(|s| s.parse().ok()).unwrap_or(0);
            let wl = match parts.get(2).copied().unwrap_or("desktop") {
                "server" | "srv" => installer::WorkloadType::Server, "dev" | "development" => installer::WorkloadType::Development, "gaming" | "game" => installer::WorkloadType::Gaming, _ => installer::WorkloadType::Desktop,
            };
            match installer::set_workload(id, wl) { Ok(()) => shell_println!("Workload set"), Err(e) => shell_println!("Error: {:?}", e) }
        }
        "partition" => {
            let id: u64 = parts.get(1).and_then(|s| s.parse().ok()).unwrap_or(0);
            let disk = parts.get(2).copied().unwrap_or("/dev/sda");
            let boot: u32 = parts.get(3).and_then(|s| s.parse().ok()).unwrap_or(1024);
            let swap_str = parts.get(4).copied().unwrap_or("file");
            let swap = if swap_str == "file" { None } else { swap_str.parse().ok() };
            match installer::set_partition_plan(id, installer::PartitionPlan { disk: alloc::string::String::from(disk), boot_mib: boot, swap_mib: swap, root_label: alloc::string::String::from("MintOS"), erase_disk: true }) {
                Ok(()) => shell_println!("Partition plan set"), Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "check" => {
            let id: u64 = parts.get(1).and_then(|s| s.parse().ok()).unwrap_or(0);
            match installer::sanity_check(id) {
                Ok(r) => {
                    shell_println!("Sanity check: {}", if r.passed { "PASSED" } else { "FAILED" });
                    for w in &r.warnings { shell_println!("  WARN: {}", w); }
                    for e in &r.errors { shell_println!("  ERR:  {}", e); }
                }
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "install" => {
            let id: u64 = parts.get(1).and_then(|s| s.parse().ok()).unwrap_or(0);
            match installer::execute_install(id) { Ok(()) => shell_println!("Installation complete — reboot required"), Err(e) => shell_println!("Error: {:?}", e) }
        }
        "firstboot" => {
            let id: u64 = parts.get(1).and_then(|s| s.parse().ok()).unwrap_or(0);
            match installer::start_first_boot(id) { Ok(()) => shell_println!("First-boot setup started"), Err(e) => shell_println!("Error: {:?}", e) }
        }
        "timezone" => {
            let id: u64 = parts.get(1).and_then(|s| s.parse().ok()).unwrap_or(0);
            let tz = parts.get(2).copied().unwrap_or("UTC");
            match installer::set_timezone(id, tz) { Ok(()) => shell_println!("Timezone: {}", tz), Err(e) => shell_println!("Error: {:?}", e) }
        }
        "user" => {
            let id: u64 = parts.get(1).and_then(|s| s.parse().ok()).unwrap_or(0);
            let name = parts.get(2).copied().unwrap_or("user");
            let pass = parts.get(3).copied().unwrap_or("yes") == "yes";
            let auto = parts.get(4).copied().unwrap_or("no") == "yes";
            match installer::set_user(id, name, pass, auto) { Ok(()) => shell_println!("User: {}", name), Err(e) => shell_println!("Error: {:?}", e) }
        }
        "browser" => {
            let id: u64 = parts.get(1).and_then(|s| s.parse().ok()).unwrap_or(0);
            let br = match parts.get(2).copied().unwrap_or("firefox") {
                "chromium" | "chrome" => installer::BrowserChoice::Chromium, "epiphany" | "gnome" => installer::BrowserChoice::Epiphany, "custom" => installer::BrowserChoice::Custom, _ => installer::BrowserChoice::Firefox,
            };
            match installer::set_browser(id, br) { Ok(()) => shell_println!("Browser set"), Err(e) => shell_println!("Error: {:?}", e) }
        }
        "theme" => {
            let id: u64 = parts.get(1).and_then(|s| s.parse().ok()).unwrap_or(0);
            let mode = parts.get(2).copied().unwrap_or("dark");
            match installer::set_theme(id, mode) { Ok(()) => shell_println!("Theme: {}", mode), Err(e) => shell_println!("Error: {:?}", e) }
        }
        "wifi" => {
            let id: u64 = parts.get(1).and_then(|s| s.parse().ok()).unwrap_or(0);
            let ssid = parts.get(2).copied().unwrap_or("");
            let pass = parts.get(3).copied().unwrap_or("yes") == "yes";
            match installer::set_wifi(id, ssid, pass) { Ok(()) => shell_println!("Wifi: {}", ssid), Err(e) => shell_println!("Error: {:?}", e) }
        }
        "audio" => {
            let id: u64 = parts.get(1).and_then(|s| s.parse().ok()).unwrap_or(0);
            let dev = parts.get(2).copied().unwrap_or("default");
            match installer::set_audio_device(id, dev) { Ok(()) => shell_println!("Audio: {}", dev), Err(e) => shell_println!("Error: {:?}", e) }
        }
        "complete" => {
            let id: u64 = parts.get(1).and_then(|s| s.parse().ok()).unwrap_or(0);
            match installer::complete_first_boot(id) { Ok(()) => shell_println!("First-boot complete"), Err(e) => shell_println!("Error: {:?}", e) }
        }
        "stats" => { let (t, c, f, ops) = installer::stats(); shell_println!("Sessions: {}  Complete: {}  Failed: {}  Ops: {}", t, c, f, ops); }
        "init" => { installer::init_defaults(); shell_println!("Defaults initialised"); }
        "test" => { match installer::self_test() { Ok(()) => shell_println!("All tests passed"), Err(e) => shell_println!("Test failed: {:?}", e) } }
        _ => shell_println!("Usage: installer <list|info|create|remove|keyboard|scaling|workload|partition|check|install|firstboot|timezone|user|browser|theme|wifi|audio|complete|stats|init|test>"),
    }
}

/// `timezone` / `tz` — timezone and system clock settings.
fn cmd_timezone(args: &str) {
    use crate::fs::timezone;
    let parts: Vec<&str> = args.split_whitespace().collect();
    let sub = parts.first().copied().unwrap_or("");
    match sub {
        "show" | "" => {
            let tz = timezone::current_timezone();
            let (tf, df, ws, sec, date) = timezone::format_settings();
            let ntp = timezone::ntp_status();
            shell_println!("Timezone:     {}", tz);
            shell_println!("Time format:  {:?}", tf);
            shell_println!("Date format:  {:?}", df);
            shell_println!("Week start:   {:?}", ws);
            shell_println!("Show seconds: {}", sec);
            shell_println!("Show date:    {}", date);
            shell_println!("NTP status:   {:?}", ntp);
        }
        "set" => {
            let name = parts.get(1).copied().unwrap_or("UTC");
            match timezone::set_timezone(name) { Ok(()) => shell_println!("Timezone: {}", name), Err(e) => shell_println!("Error: {:?}", e) }
        }
        "list" => {
            let region = parts.get(1).copied().unwrap_or("");
            let tzs = timezone::list_timezones(region);
            if tzs.is_empty() { shell_println!("No timezones{}", if region.is_empty() { "" } else { " in region" }); return; }
            shell_println!("{:<28} {:<8} {:<6} {}", "NAME", "OFFSET", "ABBR", "DISPLAY");
            for t in &tzs {
                let sign = if t.std_offset_min >= 0 { "+" } else { "" };
                let h = t.std_offset_min / 60;
                let m = (t.std_offset_min % 60).unsigned_abs();
                shell_println!("{:<28} {}{:02}:{:02}  {:<6} {}", t.name, sign, h, m, t.std_abbrev, t.display_name);
            }
        }
        "regions" => {
            let regions = timezone::list_regions();
            for r in &regions { shell_println!("{}", r); }
        }
        "detect" => {
            let lat: f32 = parts.get(1).and_then(|s| s.parse().ok()).unwrap_or(0.0);
            let lon: f32 = parts.get(2).and_then(|s| s.parse().ok()).unwrap_or(0.0);
            match timezone::detect_from_location(lat, lon) { Ok(tz) => shell_println!("Detected: {}", tz), Err(e) => shell_println!("Error: {:?}", e) }
        }
        "ntp" => {
            let on = parts.get(1).copied().unwrap_or("on") != "off";
            match timezone::set_ntp_enabled(on) { Ok(()) => shell_println!("NTP {}", if on { "enabled" } else { "disabled" }), Err(e) => shell_println!("Error: {:?}", e) }
        }
        "servers" => {
            let servers = timezone::list_ntp_servers();
            if servers.is_empty() { shell_println!("No NTP servers"); return; }
            for s in &servers { shell_println!("{} :{} enabled={} offset={}us", s.hostname, s.port, s.enabled, s.offset_us); }
        }
        "addntp" => {
            let host = parts.get(1).copied().unwrap_or("pool.ntp.org");
            let port: u16 = parts.get(2).and_then(|s| s.parse().ok()).unwrap_or(123);
            match timezone::add_ntp_server(host, port) { Ok(()) => shell_println!("Added {}", host), Err(e) => shell_println!("Error: {:?}", e) }
        }
        "rmntp" => {
            let host = parts.get(1).copied().unwrap_or("");
            match timezone::remove_ntp_server(host) { Ok(()) => shell_println!("Removed"), Err(e) => shell_println!("Error: {:?}", e) }
        }
        "timefmt" => {
            match parts.get(1).copied().unwrap_or("24") { "12" => timezone::set_time_format(timezone::TimeFormat::H12), _ => timezone::set_time_format(timezone::TimeFormat::H24) }
            shell_println!("Time format set");
        }
        "datefmt" => {
            match parts.get(1).copied().unwrap_or("iso") {
                "mdy" | "us" => timezone::set_date_format(timezone::DateFormat::Mdy),
                "dmy" | "eu" => timezone::set_date_format(timezone::DateFormat::Dmy),
                "dot" | "de" => timezone::set_date_format(timezone::DateFormat::DmyDot),
                _ => timezone::set_date_format(timezone::DateFormat::Iso),
            }
            shell_println!("Date format set");
        }
        "weekstart" => {
            match parts.get(1).copied().unwrap_or("mon") {
                "sun" | "sunday" => timezone::set_week_start(timezone::WeekStart::Sunday),
                "sat" | "saturday" => timezone::set_week_start(timezone::WeekStart::Saturday),
                _ => timezone::set_week_start(timezone::WeekStart::Monday),
            }
            shell_println!("Week start set");
        }
        "seconds" => {
            let on = parts.get(1).copied().unwrap_or("on") != "off";
            timezone::set_show_seconds(on);
            shell_println!("Seconds {}", if on { "shown" } else { "hidden" });
        }
        "showdate" => {
            let on = parts.get(1).copied().unwrap_or("on") != "off";
            timezone::set_show_date(on);
            shell_println!("Date {}", if on { "shown" } else { "hidden" });
        }
        "stats" => { let (tzs, ntps, ntp_on, ops) = timezone::stats(); shell_println!("Timezones: {}  NTP servers: {}  NTP on: {}  Ops: {}", tzs, ntps, ntp_on, ops); }
        "init" => { timezone::init_defaults(); shell_println!("Defaults initialised"); }
        "test" => { match timezone::self_test() { Ok(()) => shell_println!("All tests passed"), Err(e) => shell_println!("Test failed: {:?}", e) } }
        _ => shell_println!("Usage: timezone <show|set|list|regions|detect|ntp|servers|addntp|rmntp|timefmt|datefmt|weekstart|seconds|showdate|stats|init|test>"),
    }
}

/// `fontmgr` / `fonts` — font registry and rendering settings.
fn cmd_fontmgr(args: &str) {
    use crate::fs::fontmgr;
    let parts: Vec<&str> = args.split_whitespace().collect();
    let sub = parts.first().copied().unwrap_or("");
    match sub {
        "list" => {
            let cat = match parts.get(1).copied().unwrap_or("all") {
                "sans" => Some(fontmgr::FontCategory::SansSerif), "serif" => Some(fontmgr::FontCategory::Serif), "mono" => Some(fontmgr::FontCategory::Monospace), "display" => Some(fontmgr::FontCategory::Display), "hand" => Some(fontmgr::FontCategory::Handwriting), "symbol" => Some(fontmgr::FontCategory::Symbol), _ => None,
            };
            let fonts = fontmgr::list_fonts(cat);
            if fonts.is_empty() { shell_println!("No fonts"); return; }
            shell_println!("{:<6} {:<20} {:<12} {:<6} {:<8} {}", "ID", "FAMILY", "STYLE", "FMT", "GLYPHS", "SYS");
            for f in &fonts {
                let st = match f.style { fontmgr::FontStyle::Regular => "regular", fontmgr::FontStyle::Bold => "bold", fontmgr::FontStyle::Italic => "italic", fontmgr::FontStyle::BoldItalic => "bold-it", fontmgr::FontStyle::Light => "light", fontmgr::FontStyle::Medium => "medium", fontmgr::FontStyle::SemiBold => "semibold", fontmgr::FontStyle::ExtraBold => "xbold", fontmgr::FontStyle::Thin => "thin" };
                let fmt = match f.format { fontmgr::FontFormat::TrueType => "ttf", fontmgr::FontFormat::OpenType => "otf", fontmgr::FontFormat::Woff => "woff", fontmgr::FontFormat::Woff2 => "woff2", fontmgr::FontFormat::Bitmap => "bmp" };
                shell_println!("{:<6} {:<20} {:<12} {:<6} {:<8} {}", f.id, f.family, st, fmt, f.glyph_count, if f.system { "yes" } else { "no" });
            }
        }
        "families" => {
            let fams = fontmgr::list_families();
            for f in &fams { shell_println!("{}", f); }
        }
        "info" => {
            let id: u64 = parts.get(1).and_then(|s| s.parse().ok()).unwrap_or(0);
            match fontmgr::get_font(id) {
                Ok(f) => {
                    shell_println!("ID:       {}", f.id);
                    shell_println!("Family:   {}", f.family);
                    shell_println!("Style:    {:?}", f.style);
                    shell_println!("Format:   {:?}", f.format);
                    shell_println!("Category: {:?}", f.category);
                    shell_println!("Path:     {}", f.path);
                    shell_println!("Version:  {}", f.version);
                    shell_println!("Glyphs:   {}", f.glyph_count);
                    shell_println!("System:   {}", f.system);
                    shell_println!("Enabled:  {}", f.enabled);
                }
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "install" => {
            let family = parts.get(1).copied().unwrap_or("Unknown");
            let path = parts.get(2).copied().unwrap_or("/fonts/new.ttf");
            match fontmgr::install_font(family, fontmgr::FontStyle::Regular, fontmgr::FontFormat::TrueType, fontmgr::FontCategory::SansSerif, path, "1.0", 0) {
                Ok(id) => shell_println!("Installed {} (ID {})", family, id), Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "uninstall" => {
            let id: u64 = parts.get(1).and_then(|s| s.parse().ok()).unwrap_or(0);
            match fontmgr::uninstall_font(id) { Ok(()) => shell_println!("Uninstalled"), Err(e) => shell_println!("Error: {:?}", e) }
        }
        "enable" => {
            let id: u64 = parts.get(1).and_then(|s| s.parse().ok()).unwrap_or(0);
            match fontmgr::set_enabled(id, true) { Ok(()) => shell_println!("Enabled"), Err(e) => shell_println!("Error: {:?}", e) }
        }
        "disable" => {
            let id: u64 = parts.get(1).and_then(|s| s.parse().ok()).unwrap_or(0);
            match fontmgr::set_enabled(id, false) { Ok(()) => shell_println!("Disabled"), Err(e) => shell_println!("Error: {:?}", e) }
        }
        "default" => {
            let role = match parts.get(1).copied().unwrap_or("ui") {
                "doc" | "document" => fontmgr::FontRole::Document, "mono" | "monospace" => fontmgr::FontRole::Monospace, "title" | "titlebar" => fontmgr::FontRole::Titlebar, "fallback" => fontmgr::FontRole::Fallback, _ => fontmgr::FontRole::Ui,
            };
            let family = parts.get(2).copied().unwrap_or("");
            if family.is_empty() {
                let defs = fontmgr::default_fonts();
                shell_println!("UI:        {}", defs.ui);
                shell_println!("Document:  {}", defs.document);
                shell_println!("Monospace: {}", defs.monospace);
                shell_println!("Titlebar:  {}", defs.titlebar);
                shell_println!("Fallback:  {}", defs.fallback);
            } else {
                match fontmgr::set_default(role, family) { Ok(()) => shell_println!("Default set"), Err(e) => shell_println!("Error: {:?}", e) }
            }
        }
        "size" => {
            let pt: u32 = parts.get(1).and_then(|s| s.parse().ok()).unwrap_or(0);
            if pt == 0 { shell_println!("Size: {} pt", fontmgr::render_settings().global_size_pt); }
            else { match fontmgr::set_global_size(pt) { Ok(()) => shell_println!("Size: {} pt", pt), Err(e) => shell_println!("Error: {:?}", e) } }
        }
        "hint" => {
            match parts.get(1).copied().unwrap_or("slight") {
                "none" => fontmgr::set_hint_mode(fontmgr::HintMode::None), "medium" | "med" => fontmgr::set_hint_mode(fontmgr::HintMode::Medium), "full" => fontmgr::set_hint_mode(fontmgr::HintMode::Full), _ => fontmgr::set_hint_mode(fontmgr::HintMode::Slight),
            }
            shell_println!("Hinting set");
        }
        "antialias" | "aa" => {
            match parts.get(1).copied().unwrap_or("subpixel") {
                "none" | "off" => fontmgr::set_antialias(fontmgr::AntialiasMode::None), "gray" | "grayscale" => fontmgr::set_antialias(fontmgr::AntialiasMode::Grayscale), _ => fontmgr::set_antialias(fontmgr::AntialiasMode::Subpixel),
            }
            shell_println!("Antialiasing set");
        }
        "dpi" => {
            let dpi: u32 = parts.get(1).and_then(|s| s.parse().ok()).unwrap_or(0);
            if dpi == 0 { shell_println!("DPI: {}", fontmgr::render_settings().dpi); }
            else { match fontmgr::set_dpi(dpi) { Ok(()) => shell_println!("DPI: {}", dpi), Err(e) => shell_println!("Error: {:?}", e) } }
        }
        "find" => {
            let family = parts.get(1).copied().unwrap_or("");
            let fonts = fontmgr::find_family(family);
            if fonts.is_empty() { shell_println!("No fonts for '{}'", family); }
            else { for f in &fonts { shell_println!("ID {} {} {:?}", f.id, f.family, f.style); } }
        }
        "stats" => { let (t, f, s, ops) = fontmgr::stats(); shell_println!("Fonts: {}  Families: {}  System: {}  Ops: {}", t, f, s, ops); }
        "init" => { fontmgr::init_defaults(); shell_println!("Defaults initialised"); }
        "test" => { match fontmgr::self_test() { Ok(()) => shell_println!("All tests passed"), Err(e) => shell_println!("Test failed: {:?}", e) } }
        _ => shell_println!("Usage: fontmgr <list|families|info|install|uninstall|enable|disable|default|size|hint|antialias|dpi|find|stats|init|test>"),
    }
}

/// `autostart` / `astart` — manage startup items.
fn cmd_autostart(args: &str) {
    use crate::fs::autostart;
    use alloc::format;

    let parts: Vec<&str> = args.split_whitespace().collect();
    let sub = parts.first().copied().unwrap_or("");

    match sub {
        "init" => {
            autostart::init_defaults();
            shell_println!("Initialised default system startup items.");
        }
        "list" | "ls" => {
            let items = autostart::list_items();
            if items.is_empty() {
                shell_println!("No autostart items configured.");
                return;
            }
            shell_println!("{:<4} {:<20} {:<16} {:<12} {:<8} {:<6} {}",
                "ID", "NAME", "PHASE", "CONDITION", "ON", "ORDER", "COMMAND");
            for it in &items {
                shell_println!("{:<4} {:<20} {:<16} {:<12} {:<8} {:<6} {}",
                    it.id, it.name,
                    format!("{:?}", it.phase),
                    format!("{:?}", it.condition),
                    it.enabled, it.order, it.command);
            }
        }
        "user" => {
            let uid: u64 = match parts.get(1).and_then(|s| s.parse().ok()) {
                Some(v) => v,
                None => { shell_println!("Usage: autostart user <uid>"); return; }
            };
            let items = autostart::items_for_user(uid);
            if items.is_empty() {
                shell_println!("No autostart items for user {}.", uid);
                return;
            }
            shell_println!("{:<4} {:<20} {:<16} {:<6} {:<8} {}",
                "ID", "NAME", "PHASE", "ORDER", "DELAY", "COMMAND");
            for it in &items {
                shell_println!("{:<4} {:<20} {:<16} {:<6} {:<8} {}",
                    it.id, it.name,
                    format!("{:?}", it.phase),
                    it.order, it.delay_ms, it.command);
            }
        }
        "add" => {
            if parts.len() < 4 {
                shell_println!("Usage: autostart add <name> <command> <phase> [uid]");
                shell_println!("Phases: system, desktop, login, deferred");
                return;
            }
            let name = parts[1];
            let cmd = parts[2];
            let phase = match parts[3] {
                "system" => autostart::StartPhase::SystemService,
                "desktop" => autostart::StartPhase::DesktopReady,
                "login" => autostart::StartPhase::UserLogin,
                "deferred" => autostart::StartPhase::Deferred,
                _ => { shell_println!("Unknown phase: {}. Use system/desktop/login/deferred", parts[3]); return; }
            };
            let uid: u64 = parts.get(4).and_then(|s| s.parse().ok()).unwrap_or(0);
            match autostart::add_item(name, cmd, phase, uid) {
                Ok(id) => shell_println!("Added autostart item {} (id={}).", name, id),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "remove" | "rm" => {
            let id: u64 = match parts.get(1).and_then(|s| s.parse().ok()) {
                Some(v) => v,
                None => { shell_println!("Usage: autostart remove <id>"); return; }
            };
            match autostart::remove_item(id) {
                Ok(()) => shell_println!("Removed autostart item {}.", id),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "get" => {
            let id: u64 = match parts.get(1).and_then(|s| s.parse().ok()) {
                Some(v) => v,
                None => { shell_println!("Usage: autostart get <id>"); return; }
            };
            match autostart::get_item(id) {
                Ok(it) => {
                    shell_println!("ID:          {}", it.id);
                    shell_println!("Name:        {}", it.name);
                    shell_println!("Command:     {}", it.command);
                    shell_println!("Arguments:   {}", it.arguments);
                    shell_println!("Phase:       {:?}", it.phase);
                    shell_println!("Condition:   {:?}", it.condition);
                    shell_println!("Delay:       {} ms", it.delay_ms);
                    shell_println!("Order:       {}", it.order);
                    shell_println!("Enabled:     {}", it.enabled);
                    shell_println!("System:      {}", it.system);
                    shell_println!("Impact:      {:?}", it.impact);
                    shell_println!("UID:         {}", it.uid);
                    shell_println!("Description: {}", it.description);
                    shell_println!("Launches:    {}", it.launch_count);
                    shell_println!("Avg launch:  {} ms", it.avg_duration_ms);
                }
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "enable" => {
            let id: u64 = match parts.get(1).and_then(|s| s.parse().ok()) {
                Some(v) => v,
                None => { shell_println!("Usage: autostart enable <id>"); return; }
            };
            match autostart::set_enabled(id, true) {
                Ok(()) => shell_println!("Enabled item {}.", id),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "disable" => {
            let id: u64 = match parts.get(1).and_then(|s| s.parse().ok()) {
                Some(v) => v,
                None => { shell_println!("Usage: autostart disable <id>"); return; }
            };
            match autostart::set_enabled(id, false) {
                Ok(()) => shell_println!("Disabled item {}.", id),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "delay" => {
            if parts.len() < 3 {
                shell_println!("Usage: autostart delay <id> <ms>");
                return;
            }
            let id: u64 = match parts.get(1).and_then(|s| s.parse().ok()) {
                Some(v) => v,
                None => { shell_println!("Invalid id."); return; }
            };
            let ms: u32 = match parts.get(2).and_then(|s| s.parse().ok()) {
                Some(v) => v,
                None => { shell_println!("Invalid delay."); return; }
            };
            match autostart::set_delay(id, ms) {
                Ok(()) => shell_println!("Set delay for item {} to {} ms.", id, ms),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "order" => {
            if parts.len() < 3 {
                shell_println!("Usage: autostart order <id> <order>");
                return;
            }
            let id: u64 = match parts.get(1).and_then(|s| s.parse().ok()) {
                Some(v) => v,
                None => { shell_println!("Invalid id."); return; }
            };
            let ord: u32 = match parts.get(2).and_then(|s| s.parse().ok()) {
                Some(v) => v,
                None => { shell_println!("Invalid order."); return; }
            };
            match autostart::set_order(id, ord) {
                Ok(()) => shell_println!("Set order for item {} to {}.", id, ord),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "phase" => {
            if parts.len() < 3 {
                shell_println!("Usage: autostart phase <id> <system|desktop|login|deferred>");
                return;
            }
            let id: u64 = match parts.get(1).and_then(|s| s.parse().ok()) {
                Some(v) => v,
                None => { shell_println!("Invalid id."); return; }
            };
            let phase = match parts[2] {
                "system" => autostart::StartPhase::SystemService,
                "desktop" => autostart::StartPhase::DesktopReady,
                "login" => autostart::StartPhase::UserLogin,
                "deferred" => autostart::StartPhase::Deferred,
                _ => { shell_println!("Unknown phase. Use system/desktop/login/deferred"); return; }
            };
            match autostart::set_phase(id, phase) {
                Ok(()) => shell_println!("Set phase for item {}.", id),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "condition" | "cond" => {
            if parts.len() < 3 {
                shell_println!("Usage: autostart condition <id> <always|ac|network|firstlogin>");
                return;
            }
            let id: u64 = match parts.get(1).and_then(|s| s.parse().ok()) {
                Some(v) => v,
                None => { shell_println!("Invalid id."); return; }
            };
            let cond = match parts[2] {
                "always" => autostart::StartCondition::Always,
                "ac" => autostart::StartCondition::AcPower,
                "network" => autostart::StartCondition::NetworkAvailable,
                "firstlogin" => autostart::StartCondition::FirstLoginOnly,
                _ => { shell_println!("Unknown condition. Use always/ac/network/firstlogin"); return; }
            };
            match autostart::set_condition(id, cond) {
                Ok(()) => shell_println!("Set condition for item {}.", id),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "args" => {
            if parts.len() < 3 {
                shell_println!("Usage: autostart args <id> <arguments...>");
                return;
            }
            let id: u64 = match parts.get(1).and_then(|s| s.parse().ok()) {
                Some(v) => v,
                None => { shell_println!("Invalid id."); return; }
            };
            let arg_str = parts[2..].join(" ");
            match autostart::set_arguments(id, &arg_str) {
                Ok(()) => shell_println!("Set arguments for item {}.", id),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "desc" => {
            if parts.len() < 3 {
                shell_println!("Usage: autostart desc <id> <description...>");
                return;
            }
            let id: u64 = match parts.get(1).and_then(|s| s.parse().ok()) {
                Some(v) => v,
                None => { shell_println!("Invalid id."); return; }
            };
            let desc_str = parts[2..].join(" ");
            match autostart::set_description(id, &desc_str) {
                Ok(()) => shell_println!("Set description for item {}.", id),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "impact" => {
            if parts.len() < 3 {
                shell_println!("Usage: autostart impact <id> <low|medium|high|unknown>");
                return;
            }
            let id: u64 = match parts.get(1).and_then(|s| s.parse().ok()) {
                Some(v) => v,
                None => { shell_println!("Invalid id."); return; }
            };
            let imp = match parts[2] {
                "low" => autostart::Impact::Low,
                "medium" | "med" => autostart::Impact::Medium,
                "high" => autostart::Impact::High,
                "unknown" => autostart::Impact::Unknown,
                _ => { shell_println!("Unknown impact. Use low/medium/high/unknown"); return; }
            };
            match autostart::set_impact(id, imp) {
                Ok(()) => shell_println!("Set impact for item {}.", id),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "launch" => {
            if parts.len() < 3 {
                shell_println!("Usage: autostart launch <id> <duration_ms>");
                return;
            }
            let id: u64 = match parts.get(1).and_then(|s| s.parse().ok()) {
                Some(v) => v,
                None => { shell_println!("Invalid id."); return; }
            };
            let dur: u32 = match parts.get(2).and_then(|s| s.parse().ok()) {
                Some(v) => v,
                None => { shell_println!("Invalid duration."); return; }
            };
            match autostart::record_launch(id, dur) {
                Ok(()) => shell_println!("Recorded launch for item {} ({} ms).", id, dur),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "stats" => {
            let (total, enabled, system, ops) = autostart::stats();
            shell_println!("Total items:   {}", total);
            shell_println!("Enabled:       {}", enabled);
            shell_println!("System:        {}", system);
            shell_println!("Operations:    {}", ops);
        }
        "clear" => {
            autostart::clear_all();
            shell_println!("Cleared all autostart items.");
        }
        "test" => {
            match autostart::self_test() {
                Ok(()) => shell_println!("autostart: all tests passed."),
                Err(e) => shell_println!("autostart: test failed: {:?}", e),
            }
        }
        _ => {
            shell_println!("autostart — manage startup items");
            shell_println!();
            shell_println!("Subcommands:");
            shell_println!("  init                          Initialise default system items");
            shell_println!("  list / ls                     List all items");
            shell_println!("  user <uid>                    Items for specific user (sorted)");
            shell_println!("  add <name> <cmd> <phase> [uid]  Add item");
            shell_println!("  remove / rm <id>              Remove item (non-system)");
            shell_println!("  get <id>                      Show item details");
            shell_println!("  enable <id>                   Enable item");
            shell_println!("  disable <id>                  Disable item");
            shell_println!("  delay <id> <ms>               Set startup delay");
            shell_println!("  order <id> <order>            Set order (lower=earlier)");
            shell_println!("  phase <id> <phase>            Set phase");
            shell_println!("  condition <id> <cond>         Set start condition");
            shell_println!("  args <id> <args...>           Set arguments");
            shell_println!("  desc <id> <text...>           Set description");
            shell_println!("  impact <id> <level>           Set impact level");
            shell_println!("  launch <id> <dur_ms>          Record a launch event");
            shell_println!("  stats                         Show statistics");
            shell_println!("  clear                         Clear all items");
            shell_println!("  test                          Run self-tests");
            shell_println!();
            shell_println!("Phases: system, desktop, login, deferred");
            shell_println!("Conditions: always, ac, network, firstlogin");
            shell_println!("Impact: low, medium, high, unknown");
            shell_println!("Alias: astart");
        }
    }
}

/// `schedtune` / `stune` — scheduler tuning settings.
fn cmd_schedtune(args: &str) {
    use crate::fs::schedtune;
    use alloc::format;

    let parts: Vec<&str> = args.split_whitespace().collect();
    let sub = parts.first().copied().unwrap_or("");

    match sub {
        "init" => {
            schedtune::init_defaults();
            shell_println!("Initialised default scheduler profiles.");
        }
        "list" | "ls" => {
            let profiles = schedtune::list_profiles();
            if profiles.is_empty() {
                shell_println!("No scheduler profiles configured.");
                return;
            }
            shell_println!("{:<4} {:<25} {:<12} {:<18} {:<8} {}",
                "ID", "NAME", "WORKLOAD", "MODEL", "ACTIVE", "PREEMPT");
            for p in &profiles {
                shell_println!("{:<4} {:<25} {:<12} {:<18} {:<8} {:?}",
                    p.id, p.name,
                    format!("{:?}", p.workload),
                    format!("{:?}", p.model),
                    p.active,
                    p.preempt);
            }
        }
        "active" | "show" => {
            match schedtune::active_profile() {
                Ok(a) => {
                    shell_println!("Active: {} (id={})", a.name, a.id);
                    shell_println!("  Workload:       {:?}", a.workload);
                    shell_println!("  Model:          {:?}", a.model);
                    shell_println!("  Preempt:        {:?}", a.preempt);
                    shell_println!("  Timeslice:      {} us", a.timeslice_us);
                    shell_println!("  Min granularity:{} us", a.min_granularity_us);
                    shell_println!("  Target latency: {} us", a.target_latency_us);
                    shell_println!("  Priority levels:{}", a.priority_levels);
                    shell_println!("  Interactive:    {}", a.interactive_boost);
                    shell_println!("  Affinity:       {}", a.affinity_strictness);
                    shell_println!("  Balance:        {:?} ({}ms)", a.balance_strategy, a.balance_interval_ms);
                    shell_println!("  Per-CPU queues: {}", a.per_cpu_queues);
                    shell_println!("  NUMA-aware:     {}", a.numa_aware);
                    shell_println!("  Prio inherit:   {}", a.priority_inheritance);
                    shell_println!("  Idle powersave: {}", a.idle_powersave);
                    if a.requires_recompile {
                        shell_println!("  ⚠ Requires recompile to apply");
                    }
                    if a.requires_reboot {
                        shell_println!("  ⚠ Requires reboot to apply");
                    }
                }
                Err(_) => shell_println!("No active profile."),
            }
        }
        "get" => {
            let id: u64 = match parts.get(1).and_then(|s| s.parse().ok()) {
                Some(v) => v,
                None => { shell_println!("Usage: schedtune get <id>"); return; }
            };
            match schedtune::get_profile(id) {
                Ok(p) => {
                    shell_println!("ID:            {}", p.id);
                    shell_println!("Name:          {}", p.name);
                    shell_println!("Workload:      {:?}", p.workload);
                    shell_println!("Model:         {:?}", p.model);
                    shell_println!("Preempt:       {:?}", p.preempt);
                    shell_println!("Timeslice:     {} us", p.timeslice_us);
                    shell_println!("Min gran:      {} us", p.min_granularity_us);
                    shell_println!("Target lat:    {} us", p.target_latency_us);
                    shell_println!("Priorities:    {}", p.priority_levels);
                    shell_println!("Interactive:   {}", p.interactive_boost);
                    shell_println!("Affinity:      {}", p.affinity_strictness);
                    shell_println!("Balance:       {:?} ({}ms)", p.balance_strategy, p.balance_interval_ms);
                    shell_println!("Per-CPU:       {}", p.per_cpu_queues);
                    shell_println!("NUMA:          {}", p.numa_aware);
                    shell_println!("Migration:     {} us", p.migration_cost_us);
                    shell_println!("Prio inherit:  {}", p.priority_inheritance);
                    shell_println!("Idle save:     {}", p.idle_powersave);
                    shell_println!("Built-in:      {}", p.builtin);
                    shell_println!("Active:        {}", p.active);
                    shell_println!("Recompile:     {}", p.requires_recompile);
                    shell_println!("Reboot:        {}", p.requires_reboot);
                }
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "create" => {
            if parts.len() < 4 {
                shell_println!("Usage: schedtune create <name> <workload> <model>");
                shell_println!("Workloads: desktop, server, gaming, dev, realtime, lowpower");
                shell_println!("Models: prr, cfs, eevdf, bfs, rtfifo");
                return;
            }
            let name = parts[1];
            let workload = match parts[2] {
                "desktop" => schedtune::WorkloadType::Desktop,
                "server" => schedtune::WorkloadType::Server,
                "gaming" => schedtune::WorkloadType::Gaming,
                "dev" | "development" => schedtune::WorkloadType::Development,
                "realtime" | "rt" => schedtune::WorkloadType::Realtime,
                "lowpower" | "lp" => schedtune::WorkloadType::LowPower,
                _ => { shell_println!("Unknown workload type."); return; }
            };
            let model = match parts[3] {
                "prr" => schedtune::SchedModel::PriorityRoundRobin,
                "cfs" => schedtune::SchedModel::Cfs,
                "eevdf" => schedtune::SchedModel::Eevdf,
                "bfs" => schedtune::SchedModel::Bfs,
                "rtfifo" | "rt" => schedtune::SchedModel::RtFifo,
                _ => { shell_println!("Unknown model."); return; }
            };
            match schedtune::create_profile(name, workload, model) {
                Ok(id) => shell_println!("Created profile {} (id={}).", name, id),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "remove" | "rm" => {
            let id: u64 = match parts.get(1).and_then(|s| s.parse().ok()) {
                Some(v) => v,
                None => { shell_println!("Usage: schedtune remove <id>"); return; }
            };
            match schedtune::remove_profile(id) {
                Ok(()) => shell_println!("Removed profile {}.", id),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "apply" => {
            let id: u64 = match parts.get(1).and_then(|s| s.parse().ok()) {
                Some(v) => v,
                None => { shell_println!("Usage: schedtune apply <id>"); return; }
            };
            match schedtune::apply_profile(id) {
                Ok(()) => shell_println!("Applied profile {}.", id),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "timeslice" | "ts" => {
            if parts.len() < 3 {
                shell_println!("Usage: schedtune timeslice <id> <us>");
                return;
            }
            let id: u64 = match parts.get(1).and_then(|s| s.parse().ok()) {
                Some(v) => v,
                None => { shell_println!("Invalid id."); return; }
            };
            let us: u32 = match parts.get(2).and_then(|s| s.parse().ok()) {
                Some(v) => v,
                None => { shell_println!("Invalid microseconds."); return; }
            };
            match schedtune::set_timeslice(id, us) {
                Ok(()) => shell_println!("Set timeslice to {} us.", us),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "preempt" => {
            if parts.len() < 3 {
                shell_println!("Usage: schedtune preempt <id> <none|voluntary|full|realtime>");
                return;
            }
            let id: u64 = match parts.get(1).and_then(|s| s.parse().ok()) {
                Some(v) => v,
                None => { shell_println!("Invalid id."); return; }
            };
            let pm = match parts[2] {
                "none" => schedtune::PreemptModel::None,
                "voluntary" | "vol" => schedtune::PreemptModel::Voluntary,
                "full" => schedtune::PreemptModel::Full,
                "realtime" | "rt" => schedtune::PreemptModel::RealTime,
                _ => { shell_println!("Unknown model."); return; }
            };
            match schedtune::set_preempt(id, pm) {
                Ok(()) => shell_println!("Set preemption model."),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "latency" | "lat" => {
            if parts.len() < 3 {
                shell_println!("Usage: schedtune latency <id> <us>");
                return;
            }
            let id: u64 = match parts.get(1).and_then(|s| s.parse().ok()) {
                Some(v) => v,
                None => { shell_println!("Invalid id."); return; }
            };
            let us: u32 = match parts.get(2).and_then(|s| s.parse().ok()) {
                Some(v) => v,
                None => { shell_println!("Invalid microseconds."); return; }
            };
            match schedtune::set_target_latency(id, us) {
                Ok(()) => shell_println!("Set target latency to {} us.", us),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "interactive" => {
            if parts.len() < 3 {
                shell_println!("Usage: schedtune interactive <id> <on|off>");
                return;
            }
            let id: u64 = match parts.get(1).and_then(|s| s.parse().ok()) {
                Some(v) => v,
                None => { shell_println!("Invalid id."); return; }
            };
            let on = parts[2] == "on" || parts[2] == "true";
            match schedtune::set_interactive_boost(id, on) {
                Ok(()) => shell_println!("Set interactive boost {}.", if on { "on" } else { "off" }),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "affinity" => {
            if parts.len() < 3 {
                shell_println!("Usage: schedtune affinity <id> <0-100>");
                return;
            }
            let id: u64 = match parts.get(1).and_then(|s| s.parse().ok()) {
                Some(v) => v,
                None => { shell_println!("Invalid id."); return; }
            };
            let v: u8 = match parts.get(2).and_then(|s| s.parse().ok()) {
                Some(v) => v,
                None => { shell_println!("Invalid value."); return; }
            };
            match schedtune::set_affinity(id, v) {
                Ok(()) => shell_println!("Set affinity strictness to {}.", v),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "balance" => {
            if parts.len() < 3 {
                shell_println!("Usage: schedtune balance <id> <steal|push|hybrid|pinned>");
                return;
            }
            let id: u64 = match parts.get(1).and_then(|s| s.parse().ok()) {
                Some(v) => v,
                None => { shell_println!("Invalid id."); return; }
            };
            let bs = match parts[2] {
                "steal" | "workstealing" => schedtune::BalanceStrategy::WorkStealing,
                "push" => schedtune::BalanceStrategy::PushMigration,
                "hybrid" => schedtune::BalanceStrategy::Hybrid,
                "pinned" | "none" => schedtune::BalanceStrategy::Pinned,
                _ => { shell_println!("Unknown strategy."); return; }
            };
            match schedtune::set_balance_strategy(id, bs) {
                Ok(()) => shell_println!("Set balance strategy."),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "numa" => {
            if parts.len() < 3 {
                shell_println!("Usage: schedtune numa <id> <on|off>");
                return;
            }
            let id: u64 = match parts.get(1).and_then(|s| s.parse().ok()) {
                Some(v) => v,
                None => { shell_println!("Invalid id."); return; }
            };
            let on = parts[2] == "on" || parts[2] == "true";
            match schedtune::set_numa_aware(id, on) {
                Ok(()) => shell_println!("Set NUMA-aware {}.", if on { "on" } else { "off" }),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "tradeoffs" | "pros" => {
            let id: u64 = match parts.get(1).and_then(|s| s.parse().ok()) {
                Some(v) => v,
                None => { shell_println!("Usage: schedtune tradeoffs <id>"); return; }
            };
            match schedtune::tradeoffs(id) {
                Ok(info) => {
                    shell_println!("{}", info.label);
                    shell_println!();
                    shell_println!("Advantages:");
                    for a in &info.advantages {
                        shell_println!("  + {}", a);
                    }
                    shell_println!();
                    shell_println!("Disadvantages:");
                    for d in &info.disadvantages {
                        shell_println!("  - {}", d);
                    }
                }
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "stats" => {
            let (total, active, tradeoffs, ops) = schedtune::stats();
            shell_println!("Profiles:    {}", total);
            shell_println!("Active:      {}", active);
            shell_println!("Tradeoffs:   {}", tradeoffs);
            shell_println!("Operations:  {}", ops);
        }
        "clear" => {
            schedtune::clear_all();
            shell_println!("Cleared all scheduler profiles.");
        }
        "test" => {
            match schedtune::self_test() {
                Ok(()) => shell_println!("schedtune: all tests passed."),
                Err(e) => shell_println!("schedtune: test failed: {:?}", e),
            }
        }
        _ => {
            shell_println!("schedtune — scheduler tuning parameters");
            shell_println!();
            shell_println!("Subcommands:");
            shell_println!("  init                          Load default profiles");
            shell_println!("  list / ls                     List all profiles");
            shell_println!("  active / show                 Show active profile details");
            shell_println!("  get <id>                      Show profile details");
            shell_println!("  create <name> <wl> <model>    Create custom profile");
            shell_println!("  remove / rm <id>              Remove custom profile");
            shell_println!("  apply <id>                    Activate a profile");
            shell_println!("  timeslice <id> <us>           Set time slice");
            shell_println!("  preempt <id> <model>          Set preemption model");
            shell_println!("  latency <id> <us>             Set target latency");
            shell_println!("  interactive <id> <on|off>     Toggle interactive boost");
            shell_println!("  affinity <id> <0-100>         Set CPU affinity strictness");
            shell_println!("  balance <id> <strategy>       Set load balance strategy");
            shell_println!("  numa <id> <on|off>            Toggle NUMA-aware scheduling");
            shell_println!("  tradeoffs <id>                Show pros/cons");
            shell_println!("  stats                         Show statistics");
            shell_println!("  clear                         Clear all profiles");
            shell_println!("  test                          Run self-tests");
            shell_println!();
            shell_println!("Workloads: desktop, server, gaming, dev, realtime, lowpower");
            shell_println!("Models: prr, cfs, eevdf, bfs, rtfifo");
            shell_println!("Preempt: none, voluntary, full, realtime");
            shell_println!("Balance: steal, push, hybrid, pinned");
            shell_println!("Alias: stune");
        }
    }
}

/// `mmtune` / `mtune` — memory management tuning settings.
fn cmd_mmtune(args: &str) {
    use crate::fs::mmtune;
    use alloc::format;

    let parts: Vec<&str> = args.split_whitespace().collect();
    let sub = parts.first().copied().unwrap_or("");

    match sub {
        "init" => {
            mmtune::init_defaults();
            shell_println!("Initialised default memory profiles.");
        }
        "list" | "ls" => {
            let profiles = mmtune::list_profiles();
            if profiles.is_empty() {
                shell_println!("No memory profiles configured.");
                return;
            }
            shell_println!("{:<4} {:<25} {:<12} {:<12} {:<12} {}",
                "ID", "NAME", "WORKLOAD", "ALLOCATOR", "RECLAIM", "ACTIVE");
            for p in &profiles {
                shell_println!("{:<4} {:<25} {:<12} {:<12} {:<12} {}",
                    p.id, p.name,
                    format!("{:?}", p.workload),
                    format!("{:?}", p.alloc_model),
                    format!("{:?}", p.reclaim),
                    p.active);
            }
        }
        "active" | "show" => {
            match mmtune::active_profile() {
                Ok(a) => {
                    shell_println!("Active: {} (id={})", a.name, a.id);
                    shell_println!("  Workload:       {:?}", a.workload);
                    shell_println!("  Allocator:      {:?}", a.alloc_model);
                    shell_println!("  Reclaim:        {:?}", a.reclaim);
                    shell_println!("  Overcommit:     {:?} ({}%)", a.overcommit, a.overcommit_ratio);
                    shell_println!("  Huge pages:     {:?}", a.huge_pages);
                    shell_println!("  Huge reserve:   {}", a.huge_page_reserve);
                    shell_println!("  Compaction:     {:?}", a.compact_level);
                    shell_println!("  Swappiness:     {}", a.swappiness);
                    shell_println!("  Dirty ratio:    {}/{}", a.dirty_ratio, a.dirty_bg_ratio);
                    shell_println!("  Dirty expire:   {} cs", a.dirty_expire_cs);
                    shell_println!("  Cache pressure: {}", a.vfs_cache_pressure);
                    shell_println!("  Min free:       {} KiB", a.min_free_kib);
                    shell_println!("  ZRAM:           {} ({}%)", a.zram_enabled, a.zram_max_pct);
                    shell_println!("  Zero on free:   {}", a.zero_on_free);
                    shell_println!("  Per-CPU pages:  {}", a.per_cpu_pages);
                    shell_println!("  NUMA interleave:{}", a.numa_interleave);
                    shell_println!("  Stack pages:    {}", a.kernel_stack_pages);
                    if a.requires_recompile {
                        shell_println!("  ⚠ Requires recompile");
                    }
                    if a.requires_reboot {
                        shell_println!("  ⚠ Requires reboot");
                    }
                }
                Err(_) => shell_println!("No active profile."),
            }
        }
        "get" => {
            let id: u64 = match parts.get(1).and_then(|s| s.parse().ok()) {
                Some(v) => v,
                None => { shell_println!("Usage: mmtune get <id>"); return; }
            };
            match mmtune::get_profile(id) {
                Ok(p) => {
                    shell_println!("ID:            {}", p.id);
                    shell_println!("Name:          {}", p.name);
                    shell_println!("Workload:      {:?}", p.workload);
                    shell_println!("Allocator:     {:?}", p.alloc_model);
                    shell_println!("Reclaim:       {:?}", p.reclaim);
                    shell_println!("Overcommit:    {:?} ({}%)", p.overcommit, p.overcommit_ratio);
                    shell_println!("Huge pages:    {:?}", p.huge_pages);
                    shell_println!("Compaction:    {:?}", p.compact_level);
                    shell_println!("Swappiness:    {}", p.swappiness);
                    shell_println!("Dirty:         {}/{}", p.dirty_ratio, p.dirty_bg_ratio);
                    shell_println!("Cache press:   {}", p.vfs_cache_pressure);
                    shell_println!("Min free:      {} KiB", p.min_free_kib);
                    shell_println!("ZRAM:          {} ({}%)", p.zram_enabled, p.zram_max_pct);
                    shell_println!("Zero free:     {}", p.zero_on_free);
                    shell_println!("NUMA:          {}", p.numa_interleave);
                    shell_println!("Built-in:      {}", p.builtin);
                    shell_println!("Active:        {}", p.active);
                    shell_println!("Recompile:     {}", p.requires_recompile);
                    shell_println!("Reboot:        {}", p.requires_reboot);
                }
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "create" => {
            if parts.len() < 4 {
                shell_println!("Usage: mmtune create <name> <workload> <allocator>");
                shell_println!("Workloads: desktop, server, gaming, dev, lowmem, vmhost");
                shell_println!("Allocators: buddy, slabbuddy, bitmap, zonebased");
                return;
            }
            let name = parts[1];
            let workload = match parts[2] {
                "desktop" => mmtune::WorkloadType::Desktop,
                "server" => mmtune::WorkloadType::Server,
                "gaming" => mmtune::WorkloadType::Gaming,
                "dev" | "development" => mmtune::WorkloadType::Development,
                "lowmem" | "embedded" => mmtune::WorkloadType::LowMemory,
                "vmhost" | "vm" => mmtune::WorkloadType::VmHost,
                _ => { shell_println!("Unknown workload."); return; }
            };
            let alloc = match parts[3] {
                "buddy" => mmtune::AllocModel::Buddy,
                "slabbuddy" | "slab" => mmtune::AllocModel::SlabBuddy,
                "bitmap" => mmtune::AllocModel::Bitmap,
                "zonebased" | "zone" => mmtune::AllocModel::ZoneBased,
                _ => { shell_println!("Unknown allocator."); return; }
            };
            match mmtune::create_profile(name, workload, alloc) {
                Ok(id) => shell_println!("Created profile {} (id={}).", name, id),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "remove" | "rm" => {
            let id: u64 = match parts.get(1).and_then(|s| s.parse().ok()) {
                Some(v) => v,
                None => { shell_println!("Usage: mmtune remove <id>"); return; }
            };
            match mmtune::remove_profile(id) {
                Ok(()) => shell_println!("Removed profile {}.", id),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "apply" => {
            let id: u64 = match parts.get(1).and_then(|s| s.parse().ok()) {
                Some(v) => v,
                None => { shell_println!("Usage: mmtune apply <id>"); return; }
            };
            match mmtune::apply_profile(id) {
                Ok(()) => shell_println!("Applied profile {}.", id),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "overcommit" | "oc" => {
            if parts.len() < 3 {
                shell_println!("Usage: mmtune overcommit <id> <never|heuristic|always>");
                return;
            }
            let id: u64 = match parts.get(1).and_then(|s| s.parse().ok()) {
                Some(v) => v,
                None => { shell_println!("Invalid id."); return; }
            };
            let mode = match parts[2] {
                "never" => mmtune::OvercommitMode::Never,
                "heuristic" | "heur" => mmtune::OvercommitMode::Heuristic,
                "always" => mmtune::OvercommitMode::Always,
                _ => { shell_println!("Unknown mode."); return; }
            };
            match mmtune::set_overcommit(id, mode) {
                Ok(()) => shell_println!("Set overcommit mode."),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "hugepages" | "hp" => {
            if parts.len() < 3 {
                shell_println!("Usage: mmtune hugepages <id> <off|madvise|transparent|always>");
                return;
            }
            let id: u64 = match parts.get(1).and_then(|s| s.parse().ok()) {
                Some(v) => v,
                None => { shell_println!("Invalid id."); return; }
            };
            let mode = match parts[2] {
                "off" | "disabled" => mmtune::HugePageMode::Disabled,
                "madvise" => mmtune::HugePageMode::MadviseOnly,
                "transparent" | "thp" => mmtune::HugePageMode::Transparent,
                "always" => mmtune::HugePageMode::Always,
                _ => { shell_println!("Unknown mode."); return; }
            };
            match mmtune::set_huge_pages(id, mode) {
                Ok(()) => shell_println!("Set huge page mode."),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "compact" => {
            if parts.len() < 3 {
                shell_println!("Usage: mmtune compact <id> <off|light|background|aggressive>");
                return;
            }
            let id: u64 = match parts.get(1).and_then(|s| s.parse().ok()) {
                Some(v) => v,
                None => { shell_println!("Invalid id."); return; }
            };
            let lvl = match parts[2] {
                "off" => mmtune::CompactLevel::Off,
                "light" => mmtune::CompactLevel::Light,
                "background" | "bg" => mmtune::CompactLevel::Background,
                "aggressive" | "agg" => mmtune::CompactLevel::Aggressive,
                _ => { shell_println!("Unknown level."); return; }
            };
            match mmtune::set_compact_level(id, lvl) {
                Ok(()) => shell_println!("Set compaction level."),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "swappiness" => {
            if parts.len() < 3 {
                shell_println!("Usage: mmtune swappiness <id> <0-200>");
                return;
            }
            let id: u64 = match parts.get(1).and_then(|s| s.parse().ok()) {
                Some(v) => v,
                None => { shell_println!("Invalid id."); return; }
            };
            let val: u16 = match parts.get(2).and_then(|s| s.parse().ok()) {
                Some(v) => v,
                None => { shell_println!("Invalid value."); return; }
            };
            match mmtune::set_swappiness(id, val) {
                Ok(()) => shell_println!("Set swappiness to {}.", val),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "dirty" => {
            if parts.len() < 4 {
                shell_println!("Usage: mmtune dirty <id> <ratio> <bg_ratio>");
                return;
            }
            let id: u64 = match parts.get(1).and_then(|s| s.parse().ok()) {
                Some(v) => v,
                None => { shell_println!("Invalid id."); return; }
            };
            let ratio: u8 = match parts.get(2).and_then(|s| s.parse().ok()) {
                Some(v) => v,
                None => { shell_println!("Invalid ratio."); return; }
            };
            let bg: u8 = match parts.get(3).and_then(|s| s.parse().ok()) {
                Some(v) => v,
                None => { shell_println!("Invalid bg ratio."); return; }
            };
            if let Err(e) = mmtune::set_dirty_ratio(id, ratio) {
                shell_println!("Error: {:?}", e);
                return;
            }
            match mmtune::set_dirty_bg_ratio(id, bg) {
                Ok(()) => shell_println!("Set dirty ratios to {}/{}.", ratio, bg),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "cache" => {
            if parts.len() < 3 {
                shell_println!("Usage: mmtune cache <id> <pressure 0-1000>");
                return;
            }
            let id: u64 = match parts.get(1).and_then(|s| s.parse().ok()) {
                Some(v) => v,
                None => { shell_println!("Invalid id."); return; }
            };
            let val: u16 = match parts.get(2).and_then(|s| s.parse().ok()) {
                Some(v) => v,
                None => { shell_println!("Invalid value."); return; }
            };
            match mmtune::set_cache_pressure(id, val) {
                Ok(()) => shell_println!("Set VFS cache pressure to {}.", val),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "zram" => {
            if parts.len() < 3 {
                shell_println!("Usage: mmtune zram <id> <on|off>");
                return;
            }
            let id: u64 = match parts.get(1).and_then(|s| s.parse().ok()) {
                Some(v) => v,
                None => { shell_println!("Invalid id."); return; }
            };
            let on = parts[2] == "on" || parts[2] == "true";
            match mmtune::set_zram_enabled(id, on) {
                Ok(()) => shell_println!("Set ZRAM {}.", if on { "on" } else { "off" }),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "zerofree" => {
            if parts.len() < 3 {
                shell_println!("Usage: mmtune zerofree <id> <on|off>");
                return;
            }
            let id: u64 = match parts.get(1).and_then(|s| s.parse().ok()) {
                Some(v) => v,
                None => { shell_println!("Invalid id."); return; }
            };
            let on = parts[2] == "on" || parts[2] == "true";
            match mmtune::set_zero_on_free(id, on) {
                Ok(()) => shell_println!("Set zero-on-free {}.", if on { "on" } else { "off" }),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "reclaim" => {
            if parts.len() < 3 {
                shell_println!("Usage: mmtune reclaim <id> <lru|clock|mglru|workingset>");
                return;
            }
            let id: u64 = match parts.get(1).and_then(|s| s.parse().ok()) {
                Some(v) => v,
                None => { shell_println!("Invalid id."); return; }
            };
            let rs = match parts[2] {
                "lru" => mmtune::ReclaimStrategy::Lru,
                "clock" => mmtune::ReclaimStrategy::Clock,
                "mglru" | "multigen" => mmtune::ReclaimStrategy::MultiGenLru,
                "workingset" | "ws" => mmtune::ReclaimStrategy::WorkingSet,
                _ => { shell_println!("Unknown strategy."); return; }
            };
            match mmtune::set_reclaim(id, rs) {
                Ok(()) => shell_println!("Set reclaim strategy."),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "tradeoffs" | "pros" => {
            let id: u64 = match parts.get(1).and_then(|s| s.parse().ok()) {
                Some(v) => v,
                None => { shell_println!("Usage: mmtune tradeoffs <id>"); return; }
            };
            match mmtune::tradeoffs(id) {
                Ok(info) => {
                    shell_println!("{}", info.label);
                    shell_println!();
                    shell_println!("Advantages:");
                    for a in &info.advantages {
                        shell_println!("  + {}", a);
                    }
                    shell_println!();
                    shell_println!("Disadvantages:");
                    for d in &info.disadvantages {
                        shell_println!("  - {}", d);
                    }
                }
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "stats" => {
            let (total, active, tradeoffs, ops) = mmtune::stats();
            shell_println!("Profiles:    {}", total);
            shell_println!("Active:      {}", active);
            shell_println!("Tradeoffs:   {}", tradeoffs);
            shell_println!("Operations:  {}", ops);
        }
        "clear" => {
            mmtune::clear_all();
            shell_println!("Cleared all memory profiles.");
        }
        "test" => {
            match mmtune::self_test() {
                Ok(()) => shell_println!("mmtune: all tests passed."),
                Err(e) => shell_println!("mmtune: test failed: {:?}", e),
            }
        }
        _ => {
            shell_println!("mmtune — memory management tuning parameters");
            shell_println!();
            shell_println!("Subcommands:");
            shell_println!("  init                          Load default profiles");
            shell_println!("  list / ls                     List all profiles");
            shell_println!("  active / show                 Show active profile details");
            shell_println!("  get <id>                      Show profile details");
            shell_println!("  create <name> <wl> <alloc>    Create custom profile");
            shell_println!("  remove / rm <id>              Remove custom profile");
            shell_println!("  apply <id>                    Activate a profile");
            shell_println!("  overcommit <id> <mode>        Set overcommit mode");
            shell_println!("  hugepages <id> <mode>         Set huge page mode");
            shell_println!("  compact <id> <level>          Set compaction level");
            shell_println!("  swappiness <id> <0-200>       Set swappiness");
            shell_println!("  dirty <id> <ratio> <bg>       Set dirty ratios");
            shell_println!("  cache <id> <pressure>         Set VFS cache pressure");
            shell_println!("  zram <id> <on|off>            Toggle ZRAM");
            shell_println!("  zerofree <id> <on|off>        Toggle zero-on-free");
            shell_println!("  reclaim <id> <strategy>       Set reclaim strategy");
            shell_println!("  tradeoffs <id>                Show pros/cons");
            shell_println!("  stats                         Show statistics");
            shell_println!("  clear                         Clear all profiles");
            shell_println!("  test                          Run self-tests");
            shell_println!();
            shell_println!("Workloads: desktop, server, gaming, dev, lowmem, vmhost");
            shell_println!("Allocators: buddy, slabbuddy, bitmap, zonebased");
            shell_println!("Overcommit: never, heuristic, always");
            shell_println!("Huge pages: off, madvise, transparent, always");
            shell_println!("Compaction: off, light, background, aggressive");
            shell_println!("Reclaim: lru, clock, mglru, workingset");
            shell_println!("Alias: mtune");
        }
    }
}

/// `capsettings` / `caps` — capability settings management.
fn cmd_capsettings(args: &str) {
    use crate::fs::capsettings;

    let parts: Vec<&str> = args.split_whitespace().collect();
    let sub = parts.first().copied().unwrap_or("");

    match sub {
        "init" => {
            capsettings::init_defaults();
            shell_println!("Initialised default capability settings.");
        }
        "groups" | "lg" => {
            let groups = capsettings::list_groups();
            if groups.is_empty() {
                shell_println!("No capability groups.");
                return;
            }
            shell_println!("{:<4} {:<20} {:<8} {:<8} {}",
                "ID", "NAME", "CAPS", "BUILTIN", "DESCRIPTION");
            for g in &groups {
                shell_println!("{:<4} {:<20} {:<8} {:<8} {}",
                    g.id, g.name, g.caps.len(), g.builtin, g.description);
            }
        }
        "group" => {
            let id: u64 = match parts.get(1).and_then(|s| s.parse().ok()) {
                Some(v) => v,
                None => { shell_println!("Usage: capsettings group <id>"); return; }
            };
            match capsettings::get_group(id) {
                Ok(g) => {
                    shell_println!("ID:          {}", g.id);
                    shell_println!("Name:        {}", g.name);
                    shell_println!("Description: {}", g.description);
                    shell_println!("Built-in:    {}", g.builtin);
                    shell_println!("Capabilities:");
                    for cap in &g.caps {
                        shell_println!("  {:?}", cap);
                    }
                }
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "mkgroup" => {
            if parts.len() < 3 {
                shell_println!("Usage: capsettings mkgroup <name> <desc>");
                return;
            }
            let name = parts[1];
            let desc = parts[2..].join(" ");
            match capsettings::create_group(name, &desc, &[]) {
                Ok(id) => shell_println!("Created group {} (id={}).", name, id),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "rmgroup" => {
            let id: u64 = match parts.get(1).and_then(|s| s.parse().ok()) {
                Some(v) => v,
                None => { shell_println!("Usage: capsettings rmgroup <id>"); return; }
            };
            match capsettings::remove_group(id) {
                Ok(()) => shell_println!("Removed group {}.", id),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "gadd" => {
            if parts.len() < 3 {
                shell_println!("Usage: capsettings gadd <group_id> <capability>");
                return;
            }
            let gid: u64 = match parts.get(1).and_then(|s| s.parse().ok()) {
                Some(v) => v,
                None => { shell_println!("Invalid group id."); return; }
            };
            let cap = match parse_capability(parts[2]) {
                Some(c) => c,
                None => { shell_println!("Unknown capability: {}", parts[2]); return; }
            };
            match capsettings::group_add_cap(gid, cap) {
                Ok(()) => shell_println!("Added {:?} to group {}.", cap, gid),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "grm" => {
            if parts.len() < 3 {
                shell_println!("Usage: capsettings grm <group_id> <capability>");
                return;
            }
            let gid: u64 = match parts.get(1).and_then(|s| s.parse().ok()) {
                Some(v) => v,
                None => { shell_println!("Invalid group id."); return; }
            };
            let cap = match parse_capability(parts[2]) {
                Some(c) => c,
                None => { shell_println!("Unknown capability: {}", parts[2]); return; }
            };
            match capsettings::group_remove_cap(gid, cap) {
                Ok(()) => shell_println!("Removed {:?} from group {}.", cap, gid),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "users" | "lu" => {
            let users = capsettings::list_user_assignments();
            if users.is_empty() {
                shell_println!("No user capability assignments.");
                return;
            }
            shell_println!("{:<6} {:<15} {:<8} {:<8} {}",
                "UID", "USERNAME", "GROUPS", "EXTRA", "DENIED");
            for u in &users {
                shell_println!("{:<6} {:<15} {:<8} {:<8} {}",
                    u.uid, u.username, u.groups.len(),
                    u.extra_caps.len(), u.denied_caps.len());
            }
        }
        "user" => {
            let uid: u64 = match parts.get(1).and_then(|s| s.parse().ok()) {
                Some(v) => v,
                None => { shell_println!("Usage: capsettings user <uid>"); return; }
            };
            match capsettings::get_user_assignment(uid) {
                Ok(a) => {
                    shell_println!("UID:     {}", a.uid);
                    shell_println!("Name:    {}", a.username);
                    shell_println!("Groups:  {:?}", a.groups);
                    shell_println!("Extra:   {:?}", a.extra_caps);
                    shell_println!("Denied:  {:?}", a.denied_caps);
                    match capsettings::user_effective_caps(uid) {
                        Ok(caps) => {
                            shell_println!("Effective capabilities:");
                            for cap in &caps {
                                shell_println!("  {:?}", cap);
                            }
                        }
                        Err(e) => shell_println!("Error resolving caps: {:?}", e),
                    }
                }
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "adduser" => {
            if parts.len() < 3 {
                shell_println!("Usage: capsettings adduser <uid> <username>");
                return;
            }
            let uid: u64 = match parts.get(1).and_then(|s| s.parse().ok()) {
                Some(v) => v,
                None => { shell_println!("Invalid uid."); return; }
            };
            match capsettings::assign_user(uid, parts[2]) {
                Ok(id) => shell_println!("Created user assignment (id={}).", id),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "ugroup" => {
            if parts.len() < 3 {
                shell_println!("Usage: capsettings ugroup <uid> <group_id>");
                return;
            }
            let uid: u64 = match parts.get(1).and_then(|s| s.parse().ok()) {
                Some(v) => v,
                None => { shell_println!("Invalid uid."); return; }
            };
            let gid: u64 = match parts.get(2).and_then(|s| s.parse().ok()) {
                Some(v) => v,
                None => { shell_println!("Invalid group id."); return; }
            };
            match capsettings::user_add_group(uid, gid) {
                Ok(()) => shell_println!("Added user {} to group {}.", uid, gid),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "ucap" => {
            if parts.len() < 3 {
                shell_println!("Usage: capsettings ucap <uid> <capability>");
                return;
            }
            let uid: u64 = match parts.get(1).and_then(|s| s.parse().ok()) {
                Some(v) => v,
                None => { shell_println!("Invalid uid."); return; }
            };
            let cap = match parse_capability(parts[2]) {
                Some(c) => c,
                None => { shell_println!("Unknown capability."); return; }
            };
            match capsettings::user_add_cap(uid, cap) {
                Ok(()) => shell_println!("Added {:?} to user {}.", cap, uid),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "udeny" => {
            if parts.len() < 3 {
                shell_println!("Usage: capsettings udeny <uid> <capability>");
                return;
            }
            let uid: u64 = match parts.get(1).and_then(|s| s.parse().ok()) {
                Some(v) => v,
                None => { shell_println!("Invalid uid."); return; }
            };
            let cap = match parse_capability(parts[2]) {
                Some(c) => c,
                None => { shell_println!("Unknown capability."); return; }
            };
            match capsettings::user_deny_cap(uid, cap) {
                Ok(()) => shell_println!("Denied {:?} for user {}.", cap, uid),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "check" => {
            if parts.len() < 3 {
                shell_println!("Usage: capsettings check <uid> <path>");
                return;
            }
            let uid: u64 = match parts.get(1).and_then(|s| s.parse().ok()) {
                Some(v) => v,
                None => { shell_println!("Invalid uid."); return; }
            };
            match capsettings::check_access(uid, parts[2]) {
                Ok(true) => shell_println!("Access GRANTED for user {} to {}", uid, parts[2]),
                Ok(false) => shell_println!("Access DENIED for user {} to {}", uid, parts[2]),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "programs" | "lp" => {
            let progs = capsettings::list_programs();
            if progs.is_empty() {
                shell_println!("No program capability assignments.");
                return;
            }
            shell_println!("{:<30} {:<8} {:<8} {}",
                "PROGRAM", "REQ", "MAX", "SANDBOX");
            for p in &progs {
                shell_println!("{:<30} {:<8} {:<8} {}",
                    p.program, p.required_caps.len(), p.max_caps.len(), p.sandboxed);
            }
        }
        "paths" => {
            let reqs = capsettings::list_path_requirements();
            if reqs.is_empty() {
                shell_println!("No path capability requirements.");
                return;
            }
            shell_println!("{:<4} {:<30} {:<8} {}",
                "ID", "PATH", "CAPS", "RECURSIVE");
            for r in &reqs {
                shell_println!("{:<4} {:<30} {:<8} {}",
                    r.id, r.path, r.required_caps.len(), r.recursive);
            }
        }
        "addpath" => {
            if parts.len() < 3 {
                shell_println!("Usage: capsettings addpath <path> <capability> [recursive]");
                return;
            }
            let cap = match parse_capability(parts[2]) {
                Some(c) => c,
                None => { shell_println!("Unknown capability."); return; }
            };
            let recursive = parts.get(3).copied() == Some("recursive") ||
                           parts.get(3).copied() == Some("r");
            match capsettings::set_path_requirement(parts[1], &[cap], recursive) {
                Ok(id) => shell_println!("Created path requirement (id={}).", id),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "rmpath" => {
            let id: u64 = match parts.get(1).and_then(|s| s.parse().ok()) {
                Some(v) => v,
                None => { shell_println!("Usage: capsettings rmpath <id>"); return; }
            };
            match capsettings::remove_path_requirement(id) {
                Ok(()) => shell_println!("Removed path requirement {}.", id),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "caplist" => {
            shell_println!("Available capabilities:");
            shell_println!("  fileread, filewrite, execute, network, bindlowport,");
            shell_println!("  rawsocket, mount, useradmin, packageinstall, systemconfig,");
            shell_println!("  hardwareaccess, debugprocess, chown, dacoverride,");
            shell_println!("  setclock, reboot, moduleload, auditread, auditwrite,");
            shell_println!("  capadmin");
        }
        "stats" => {
            let (groups, users, programs, paths, ops) = capsettings::stats();
            shell_println!("Groups:      {}", groups);
            shell_println!("Users:       {}", users);
            shell_println!("Programs:    {}", programs);
            shell_println!("Path reqs:   {}", paths);
            shell_println!("Operations:  {}", ops);
        }
        "clear" => {
            capsettings::clear_all();
            shell_println!("Cleared all capability settings.");
        }
        "test" => {
            match capsettings::self_test() {
                Ok(()) => shell_println!("capsettings: all tests passed."),
                Err(e) => shell_println!("capsettings: test failed: {:?}", e),
            }
        }
        _ => {
            shell_println!("capsettings — capability groups and assignments");
            shell_println!();
            shell_println!("Groups:");
            shell_println!("  groups / lg                   List all groups");
            shell_println!("  group <id>                    Show group details");
            shell_println!("  mkgroup <name> <desc>         Create group");
            shell_println!("  rmgroup <id>                  Remove group");
            shell_println!("  gadd <gid> <cap>              Add cap to group");
            shell_println!("  grm <gid> <cap>               Remove cap from group");
            shell_println!();
            shell_println!("Users:");
            shell_println!("  users / lu                    List user assignments");
            shell_println!("  user <uid>                    Show user caps");
            shell_println!("  adduser <uid> <name>          Create user assignment");
            shell_println!("  ugroup <uid> <gid>            Add user to group");
            shell_println!("  ucap <uid> <cap>              Add extra cap to user");
            shell_println!("  udeny <uid> <cap>             Deny cap for user");
            shell_println!("  check <uid> <path>            Check access");
            shell_println!();
            shell_println!("Programs & Paths:");
            shell_println!("  programs / lp                 List program caps");
            shell_println!("  paths                         List path requirements");
            shell_println!("  addpath <path> <cap> [r]      Add path requirement");
            shell_println!("  rmpath <id>                   Remove path requirement");
            shell_println!();
            shell_println!("Other:");
            shell_println!("  caplist                       List all capabilities");
            shell_println!("  init                          Load defaults");
            shell_println!("  stats / clear / test");
            shell_println!("Alias: caps");
        }
    }
}

fn parse_capability(s: &str) -> Option<crate::fs::capsettings::Capability> {
    use crate::fs::capsettings::Capability;
    match s {
        "fileread" | "fread" => Some(Capability::FileRead),
        "filewrite" | "fwrite" => Some(Capability::FileWrite),
        "execute" | "exec" => Some(Capability::Execute),
        "network" | "net" => Some(Capability::Network),
        "bindlowport" | "blp" => Some(Capability::BindLowPort),
        "rawsocket" | "raw" => Some(Capability::RawSocket),
        "mount" => Some(Capability::Mount),
        "useradmin" | "uadmin" => Some(Capability::UserAdmin),
        "packageinstall" | "pkg" => Some(Capability::PackageInstall),
        "systemconfig" | "sysconfig" => Some(Capability::SystemConfig),
        "hardwareaccess" | "hw" => Some(Capability::HardwareAccess),
        "debugprocess" | "debug" => Some(Capability::DebugProcess),
        "chown" => Some(Capability::Chown),
        "dacoverride" | "dac" => Some(Capability::DacOverride),
        "setclock" | "clock" => Some(Capability::SetClock),
        "reboot" => Some(Capability::Reboot),
        "moduleload" | "modload" => Some(Capability::ModuleLoad),
        "auditread" | "aread" => Some(Capability::AuditRead),
        "auditwrite" | "awrite" => Some(Capability::AuditWrite),
        "capadmin" | "cadmin" => Some(Capability::CapAdmin),
        _ => None,
    }
}

/// `vpn` — VPN connection management.
fn cmd_vpn(args: &str) {
    use crate::fs::vpn;
    use alloc::format;

    let parts: Vec<&str> = args.split_whitespace().collect();
    let sub = parts.first().copied().unwrap_or("");

    match sub {
        "init" => {
            vpn::init_defaults();
            shell_println!("Initialised default VPN profiles.");
        }
        "list" | "ls" => {
            let profiles = vpn::list_profiles();
            if profiles.is_empty() {
                shell_println!("No VPN profiles configured.");
                return;
            }
            shell_println!("{:<4} {:<20} {:<12} {:<20} {:<6} {:<6} {}",
                "ID", "NAME", "PROTOCOL", "SERVER", "PORT", "AUTO", "KILL");
            for p in &profiles {
                shell_println!("{:<4} {:<20} {:<12} {:<20} {:<6} {:<6} {}",
                    p.id, p.name,
                    format!("{:?}", p.protocol),
                    p.server, p.port, p.auto_connect, p.kill_switch);
            }
        }
        "status" | "show" => {
            let s = vpn::status();
            shell_println!("State:       {:?}", s.state);
            if let Some(pid) = s.active_profile {
                shell_println!("Profile:     {}", pid);
            }
            shell_println!("Server:      {}", if s.connected_server.is_empty() { "-" } else { &s.connected_server });
            shell_println!("VPN IP:      {}", if s.vpn_ip.is_empty() { "-" } else { &s.vpn_ip });
            shell_println!("Uptime:      {} s", s.uptime_s);
            shell_println!("Sent:        {} bytes", s.bytes_sent);
            shell_println!("Received:    {} bytes", s.bytes_received);
            shell_println!("Active:      {}", vpn::is_active());

            let tp = vpn::list_third_party();
            if !tp.is_empty() {
                shell_println!("\nThird-party VPNs:");
                for t in &tp {
                    shell_println!("  {} ({}) — {} [{}]",
                        t.app_name,
                        t.app_path,
                        if t.connected { "connected" } else { "disconnected" },
                        t.interface);
                }
            }
        }
        "get" => {
            let id: u64 = match parts.get(1).and_then(|s| s.parse().ok()) {
                Some(v) => v,
                None => { shell_println!("Usage: vpn get <id>"); return; }
            };
            match vpn::get_profile(id) {
                Ok(p) => {
                    shell_println!("ID:            {}", p.id);
                    shell_println!("Name:          {}", p.name);
                    shell_println!("Protocol:      {:?}", p.protocol);
                    shell_println!("Server:        {}:{}", p.server, p.port);
                    shell_println!("Transport:     {:?}", p.transport);
                    shell_println!("Auth:          {:?}", p.auth);
                    shell_println!("Username:      {}", p.username);
                    shell_println!("Cert:          {}", p.cert_path);
                    shell_println!("Key:           {}", p.key_path);
                    shell_println!("CA:            {}", p.ca_path);
                    shell_println!("DNS:           {:?}", p.dns_servers);
                    shell_println!("Route all:     {}", p.route_all);
                    shell_println!("Kill switch:   {}", p.kill_switch);
                    shell_println!("Auto connect:  {}", p.auto_connect);
                    shell_println!("Auto reconnect:{}", p.auto_reconnect);
                }
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "create" => {
            if parts.len() < 5 {
                shell_println!("Usage: vpn create <name> <protocol> <server> <port>");
                shell_println!("Protocols: openvpn, wireguard, ipsec, l2tp, pptp, ssh");
                return;
            }
            let name = parts[1];
            let proto = match parts[2] {
                "openvpn" | "ovpn" => vpn::VpnProtocol::OpenVpn,
                "wireguard" | "wg" => vpn::VpnProtocol::WireGuard,
                "ipsec" | "ikev2" => vpn::VpnProtocol::IpSec,
                "l2tp" => vpn::VpnProtocol::L2tp,
                "pptp" => vpn::VpnProtocol::Pptp,
                "ssh" => vpn::VpnProtocol::SshTunnel,
                _ => { shell_println!("Unknown protocol."); return; }
            };
            let port: u16 = match parts.get(4).and_then(|s| s.parse().ok()) {
                Some(v) => v,
                None => { shell_println!("Invalid port."); return; }
            };
            match vpn::create_profile(name, proto, parts[3], port) {
                Ok(id) => shell_println!("Created VPN profile {} (id={}).", name, id),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "remove" | "rm" => {
            let id: u64 = match parts.get(1).and_then(|s| s.parse().ok()) {
                Some(v) => v,
                None => { shell_println!("Usage: vpn remove <id>"); return; }
            };
            match vpn::remove_profile(id) {
                Ok(()) => shell_println!("Removed VPN profile {}.", id),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "connect" | "up" => {
            let id: u64 = match parts.get(1).and_then(|s| s.parse().ok()) {
                Some(v) => v,
                None => { shell_println!("Usage: vpn connect <id>"); return; }
            };
            match vpn::connect(id) {
                Ok(()) => shell_println!("Connected to VPN."),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "disconnect" | "down" => {
            match vpn::disconnect() {
                Ok(()) => shell_println!("Disconnected from VPN."),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "auth" => {
            if parts.len() < 3 {
                shell_println!("Usage: vpn auth <id> <userpass|cert|psk|token>");
                return;
            }
            let id: u64 = match parts.get(1).and_then(|s| s.parse().ok()) {
                Some(v) => v,
                None => { shell_println!("Invalid id."); return; }
            };
            let auth = match parts[2] {
                "userpass" | "up" => vpn::AuthMethod::UserPass,
                "cert" | "certificate" => vpn::AuthMethod::Certificate,
                "psk" => vpn::AuthMethod::PreSharedKey,
                "token" | "otp" => vpn::AuthMethod::Token,
                _ => { shell_println!("Unknown auth method."); return; }
            };
            match vpn::set_auth(id, auth) {
                Ok(()) => shell_println!("Set authentication method."),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "transport" => {
            if parts.len() < 3 {
                shell_println!("Usage: vpn transport <id> <udp|tcp>");
                return;
            }
            let id: u64 = match parts.get(1).and_then(|s| s.parse().ok()) {
                Some(v) => v,
                None => { shell_println!("Invalid id."); return; }
            };
            let t = match parts[2] {
                "udp" => vpn::Transport::Udp,
                "tcp" => vpn::Transport::Tcp,
                _ => { shell_println!("Use udp or tcp."); return; }
            };
            match vpn::set_transport(id, t) {
                Ok(()) => shell_println!("Set transport."),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "killswitch" | "ks" => {
            if parts.len() < 3 {
                shell_println!("Usage: vpn killswitch <id> <on|off>");
                return;
            }
            let id: u64 = match parts.get(1).and_then(|s| s.parse().ok()) {
                Some(v) => v,
                None => { shell_println!("Invalid id."); return; }
            };
            let on = parts[2] == "on" || parts[2] == "true";
            match vpn::set_kill_switch(id, on) {
                Ok(()) => shell_println!("Kill switch {}.", if on { "enabled" } else { "disabled" }),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "routeall" => {
            if parts.len() < 3 {
                shell_println!("Usage: vpn routeall <id> <on|off>");
                return;
            }
            let id: u64 = match parts.get(1).and_then(|s| s.parse().ok()) {
                Some(v) => v,
                None => { shell_println!("Invalid id."); return; }
            };
            let on = parts[2] == "on" || parts[2] == "true";
            match vpn::set_route_all(id, on) {
                Ok(()) => shell_println!("Route all traffic {}.", if on { "enabled" } else { "disabled" }),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "autoconnect" | "ac" => {
            if parts.len() < 3 {
                shell_println!("Usage: vpn autoconnect <id> <on|off>");
                return;
            }
            let id: u64 = match parts.get(1).and_then(|s| s.parse().ok()) {
                Some(v) => v,
                None => { shell_println!("Invalid id."); return; }
            };
            let on = parts[2] == "on" || parts[2] == "true";
            match vpn::set_auto_connect(id, on) {
                Ok(()) => shell_println!("Auto-connect {}.", if on { "enabled" } else { "disabled" }),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "dns" => {
            if parts.len() < 3 {
                shell_println!("Usage: vpn dns <id> <server>");
                return;
            }
            let id: u64 = match parts.get(1).and_then(|s| s.parse().ok()) {
                Some(v) => v,
                None => { shell_println!("Invalid id."); return; }
            };
            match vpn::add_dns(id, parts[2]) {
                Ok(()) => shell_println!("Added DNS server {}.", parts[2]),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "stats" => {
            let (total, connected, tp, ops) = vpn::conn_stats();
            shell_println!("Profiles:    {}", total);
            shell_println!("Connected:   {}", connected);
            shell_println!("Third-party: {}", tp);
            shell_println!("Operations:  {}", ops);
        }
        "clear" => {
            vpn::clear_all();
            shell_println!("Cleared all VPN configuration.");
        }
        "test" => {
            match vpn::self_test() {
                Ok(()) => shell_println!("vpn: all tests passed."),
                Err(e) => shell_println!("vpn: test failed: {:?}", e),
            }
        }
        _ => {
            shell_println!("vpn — VPN connection management");
            shell_println!();
            shell_println!("Subcommands:");
            shell_println!("  init                          Load default profiles");
            shell_println!("  list / ls                     List all profiles");
            shell_println!("  status / show                 Show current status");
            shell_println!("  get <id>                      Show profile details");
            shell_println!("  create <name> <proto> <srv> <port>  Create profile");
            shell_println!("  remove / rm <id>              Remove profile");
            shell_println!("  connect / up <id>             Connect to VPN");
            shell_println!("  disconnect / down             Disconnect");
            shell_println!("  auth <id> <method>            Set auth method");
            shell_println!("  transport <id> <udp|tcp>      Set transport");
            shell_println!("  killswitch <id> <on|off>      Toggle kill switch");
            shell_println!("  routeall <id> <on|off>        Route all traffic");
            shell_println!("  autoconnect <id> <on|off>     Auto-connect on startup");
            shell_println!("  dns <id> <server>             Add DNS server");
            shell_println!("  stats / clear / test");
            shell_println!();
            shell_println!("Protocols: openvpn, wireguard, ipsec, l2tp, pptp, ssh");
            shell_println!("Auth: userpass, cert, psk, token");
        }
    }
}

/// `dyndns` / `ddns` — dynamic DNS and port forwarding.
fn cmd_dyndns(args: &str) {
    use crate::fs::dyndns;
    use alloc::format;

    let parts: Vec<&str> = args.split_whitespace().collect();
    let sub = parts.first().copied().unwrap_or("");

    match sub {
        "init" => {
            dyndns::init_defaults();
            shell_println!("Initialised default dynamic DNS config.");
        }
        "list" | "ls" => {
            let entries = dyndns::list_entries();
            if entries.is_empty() {
                shell_println!("No DDNS entries configured.");
                return;
            }
            shell_println!("{:<4} {:<15} {:<10} {:<25} {:<10} {}",
                "ID", "NAME", "PROVIDER", "HOSTNAME", "STATUS", "IP");
            for e in &entries {
                shell_println!("{:<4} {:<15} {:<10} {:<25} {:<10} {}",
                    e.id, e.name,
                    format!("{:?}", e.provider),
                    e.hostname,
                    format!("{:?}", e.status),
                    e.last_ip);
            }
        }
        "get" => {
            let id: u64 = match parts.get(1).and_then(|s| s.parse().ok()) {
                Some(v) => v,
                None => { shell_println!("Usage: dyndns get <id>"); return; }
            };
            match dyndns::get_entry(id) {
                Ok(e) => {
                    shell_println!("ID:          {}", e.id);
                    shell_println!("Name:        {}", e.name);
                    shell_println!("Provider:    {:?}", e.provider);
                    shell_println!("Hostname:    {}", e.hostname);
                    shell_println!("Username:    {}", e.username);
                    shell_println!("URL:         {}", e.update_url);
                    shell_println!("Interval:    {} s", e.interval_s);
                    shell_println!("Enabled:     {}", e.enabled);
                    shell_println!("Status:      {:?}", e.status);
                    shell_println!("Last IP:     {}", e.last_ip);
                    shell_println!("Updates:     {}", e.update_count);
                    shell_println!("Failures:    {}", e.fail_count);
                }
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "add" => {
            if parts.len() < 5 {
                shell_println!("Usage: dyndns add <name> <provider> <hostname> <user>");
                shell_println!("Providers: dynu, noip, duckdns, cloudflare, freedns, custom");
                return;
            }
            let provider = match parts[2] {
                "dynu" => dyndns::DynDnsProvider::Dynu,
                "noip" => dyndns::DynDnsProvider::NoIp,
                "duckdns" | "duck" => dyndns::DynDnsProvider::DuckDns,
                "cloudflare" | "cf" => dyndns::DynDnsProvider::Cloudflare,
                "freedns" => dyndns::DynDnsProvider::FreeDns,
                "custom" => dyndns::DynDnsProvider::Custom,
                _ => { shell_println!("Unknown provider."); return; }
            };
            match dyndns::add_entry(parts[1], provider, parts[3], parts[4]) {
                Ok(id) => shell_println!("Added DDNS entry {} (id={}).", parts[1], id),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "remove" | "rm" => {
            let id: u64 = match parts.get(1).and_then(|s| s.parse().ok()) {
                Some(v) => v,
                None => { shell_println!("Usage: dyndns remove <id>"); return; }
            };
            match dyndns::remove_entry(id) {
                Ok(()) => shell_println!("Removed DDNS entry {}.", id),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "enable" => {
            let id: u64 = match parts.get(1).and_then(|s| s.parse().ok()) {
                Some(v) => v,
                None => { shell_println!("Usage: dyndns enable <id>"); return; }
            };
            match dyndns::set_enabled(id, true) {
                Ok(()) => shell_println!("Enabled entry {}.", id),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "disable" => {
            let id: u64 = match parts.get(1).and_then(|s| s.parse().ok()) {
                Some(v) => v,
                None => { shell_println!("Usage: dyndns disable <id>"); return; }
            };
            match dyndns::set_enabled(id, false) {
                Ok(()) => shell_println!("Disabled entry {}.", id),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "interval" => {
            if parts.len() < 3 {
                shell_println!("Usage: dyndns interval <id> <seconds>");
                return;
            }
            let id: u64 = match parts.get(1).and_then(|s| s.parse().ok()) {
                Some(v) => v,
                None => { shell_println!("Invalid id."); return; }
            };
            let secs: u32 = match parts.get(2).and_then(|s| s.parse().ok()) {
                Some(v) => v,
                None => { shell_println!("Invalid seconds."); return; }
            };
            match dyndns::set_interval(id, secs) {
                Ok(()) => shell_println!("Set interval to {} s.", secs),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "update" => {
            if parts.len() < 3 {
                shell_println!("Usage: dyndns update <id> <ip>");
                return;
            }
            let id: u64 = match parts.get(1).and_then(|s| s.parse().ok()) {
                Some(v) => v,
                None => { shell_println!("Invalid id."); return; }
            };
            match dyndns::update_now(id, parts[2]) {
                Ok(()) => shell_println!("Updated DDNS entry with IP {}.", parts[2]),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "forwards" | "fwd" => {
            let fwds = dyndns::list_forwards();
            if fwds.is_empty() {
                shell_println!("No port forwards configured.");
                return;
            }
            shell_println!("{:<4} {:<20} {:<6} {:<6} {:<6} {:<16} {:<6} {}",
                "ID", "DESCRIPTION", "EXT", "INT", "PROTO", "INTERNAL_IP", "ACT", "METHOD");
            for f in &fwds {
                shell_println!("{:<4} {:<20} {:<6} {:<6} {:<6} {:<16} {:<6} {:?}",
                    f.id, f.description,
                    f.external_port, f.internal_port,
                    format!("{:?}", f.protocol),
                    f.internal_ip, f.active, f.method);
            }
        }
        "addfwd" => {
            if parts.len() < 6 {
                shell_println!("Usage: dyndns addfwd <desc> <ext_port> <int_port> <proto> <ip>");
                shell_println!("Proto: tcp, udp, both");
                return;
            }
            let ext: u16 = match parts.get(2).and_then(|s| s.parse().ok()) {
                Some(v) => v,
                None => { shell_println!("Invalid external port."); return; }
            };
            let int: u16 = match parts.get(3).and_then(|s| s.parse().ok()) {
                Some(v) => v,
                None => { shell_println!("Invalid internal port."); return; }
            };
            let proto = match parts[4] {
                "tcp" => dyndns::ForwardProtocol::Tcp,
                "udp" => dyndns::ForwardProtocol::Udp,
                "both" => dyndns::ForwardProtocol::Both,
                _ => { shell_println!("Unknown protocol."); return; }
            };
            match dyndns::add_forward(parts[1], ext, int, proto, parts[5], dyndns::NatMethod::Upnp) {
                Ok(id) => shell_println!("Added port forward (id={}).", id),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "rmfwd" => {
            let id: u64 = match parts.get(1).and_then(|s| s.parse().ok()) {
                Some(v) => v,
                None => { shell_println!("Usage: dyndns rmfwd <id>"); return; }
            };
            match dyndns::remove_forward(id) {
                Ok(()) => shell_println!("Removed port forward {}.", id),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "router" => {
            match dyndns::router_info() {
                Some(ri) => {
                    shell_println!("Router IP:    {}", ri.ip);
                    shell_println!("External IP:  {}", ri.external_ip);
                    shell_println!("Model:        {}", ri.model);
                    shell_println!("UPnP:         {}", ri.upnp_available);
                    shell_println!("NAT-PMP:      {}", ri.natpmp_available);
                }
                None => shell_println!("No router detected."),
            }
        }
        "stats" => {
            let (entries, fwds, router, ops) = dyndns::stats();
            shell_println!("DDNS entries:  {}", entries);
            shell_println!("Forwards:      {}", fwds);
            shell_println!("Router:        {}", if router { "detected" } else { "none" });
            shell_println!("Operations:    {}", ops);
        }
        "clear" => {
            dyndns::clear_all();
            shell_println!("Cleared all dynamic DNS configuration.");
        }
        "test" => {
            match dyndns::self_test() {
                Ok(()) => shell_println!("dyndns: all tests passed."),
                Err(e) => shell_println!("dyndns: test failed: {:?}", e),
            }
        }
        _ => {
            shell_println!("dyndns — dynamic DNS and port forwarding");
            shell_println!();
            shell_println!("DDNS:");
            shell_println!("  list / ls                     List DDNS entries");
            shell_println!("  get <id>                      Show entry details");
            shell_println!("  add <name> <prov> <host> <user>  Add entry");
            shell_println!("  remove / rm <id>              Remove entry");
            shell_println!("  enable <id>                   Enable entry");
            shell_println!("  disable <id>                  Disable entry");
            shell_println!("  interval <id> <seconds>       Set update interval");
            shell_println!("  update <id> <ip>              Force update");
            shell_println!();
            shell_println!("Port Forwarding:");
            shell_println!("  forwards / fwd                List forwards");
            shell_println!("  addfwd <desc> <ext> <int> <proto> <ip>  Add forward");
            shell_println!("  rmfwd <id>                    Remove forward");
            shell_println!();
            shell_println!("Other:");
            shell_println!("  router                        Show router info");
            shell_println!("  init / stats / clear / test");
            shell_println!();
            shell_println!("Providers: dynu, noip, duckdns, cloudflare, freedns, custom");
            shell_println!("Alias: ddns");
        }
    }
}

/// `loginscreen` / `logscr` — login screen configuration.
fn cmd_loginscreen(args: &str) {
    use crate::fs::loginscreen;

    let parts: Vec<&str> = args.split_whitespace().collect();
    let sub = parts.first().copied().unwrap_or("");

    match sub {
        "init" => {
            loginscreen::init_defaults();
            shell_println!("Initialised login screen defaults.");
        }
        "show" => {
            let cfg = loginscreen::config();
            shell_println!("Background:    {:?}", cfg.background_mode);
            shell_println!("Image:         {}", if cfg.background_path.is_empty() { "-" } else { &cfg.background_path });
            shell_println!("Color:         #{}", cfg.background_color);
            shell_println!("Synced:        {}", cfg.synced_with_desktop);
            shell_println!("Fit:           {:?}", cfg.fit_mode);
            shell_println!("Blur:          {}", cfg.blur_amount);
            shell_println!("Clock:         {:?}", cfg.clock_position);
            shell_println!("Show date:     {}", cfg.show_date);
            shell_println!("Show weather:  {}", cfg.show_weather);
            shell_println!("User list:     {:?}", cfg.user_list);
            shell_println!("Last login:    {}", cfg.show_last_login);
            shell_println!("Virt keyboard: {}", cfg.virtual_keyboard);
            shell_println!("A11y button:   {}", cfg.show_a11y);
            shell_println!("Power button:  {}", cfg.show_power);
            shell_println!("Lock timeout:  {} s", cfg.lock_timeout_s);
            shell_println!("Message:       {}", if cfg.message.is_empty() { "-" } else { &cfg.message });
            shell_println!("Logo:          {}", if cfg.logo_path.is_empty() { "-" } else { &cfg.logo_path });
        }
        "bg" => {
            let mode = match parts.get(1).copied() {
                Some("image") => loginscreen::BackgroundMode::Image,
                Some("color") | Some("solid") => loginscreen::BackgroundMode::SolidColor,
                Some("gradient") => loginscreen::BackgroundMode::Gradient,
                Some("slideshow") => loginscreen::BackgroundMode::Slideshow,
                Some("blur") => loginscreen::BackgroundMode::BlurDesktop,
                _ => { shell_println!("Usage: loginscreen bg <image|color|gradient|slideshow|blur>"); return; }
            };
            loginscreen::set_background_mode(mode);
            shell_println!("Set background mode to {:?}.", mode);
        }
        "image" => {
            match parts.get(1) {
                Some(path) => {
                    loginscreen::set_background_image(path);
                    shell_println!("Set background image to {}.", path);
                }
                None => shell_println!("Usage: loginscreen image <path>"),
            }
        }
        "sync" => {
            loginscreen::sync_with_desktop();
            shell_println!("Synced login screen with desktop wallpaper.");
        }
        "fit" => {
            let mode = match parts.get(1).copied() {
                Some("fill") => loginscreen::FitMode::Fill,
                Some("fit") => loginscreen::FitMode::Fit,
                Some("stretch") => loginscreen::FitMode::Stretch,
                Some("center") => loginscreen::FitMode::Center,
                Some("tile") => loginscreen::FitMode::Tile,
                _ => { shell_println!("Usage: loginscreen fit <fill|fit|stretch|center|tile>"); return; }
            };
            loginscreen::set_fit_mode(mode);
            shell_println!("Set fit mode to {:?}.", mode);
        }
        "blur" => {
            let amt: u8 = match parts.get(1).and_then(|s| s.parse().ok()) {
                Some(v) => v,
                None => { shell_println!("Usage: loginscreen blur <0-100>"); return; }
            };
            loginscreen::set_blur(amt);
            shell_println!("Set blur amount to {}.", amt);
        }
        "clock" => {
            let pos = match parts.get(1).copied() {
                Some("tl") | Some("topleft") => loginscreen::ClockPosition::TopLeft,
                Some("tc") | Some("topcenter") => loginscreen::ClockPosition::TopCenter,
                Some("tr") | Some("topright") => loginscreen::ClockPosition::TopRight,
                Some("bl") | Some("bottomleft") => loginscreen::ClockPosition::BottomLeft,
                Some("bc") | Some("bottomcenter") => loginscreen::ClockPosition::BottomCenter,
                Some("br") | Some("bottomright") => loginscreen::ClockPosition::BottomRight,
                Some("hidden") | Some("off") => loginscreen::ClockPosition::Hidden,
                _ => { shell_println!("Usage: loginscreen clock <tl|tc|tr|bl|bc|br|hidden>"); return; }
            };
            loginscreen::set_clock_position(pos);
            shell_println!("Set clock position.");
        }
        "userlist" => {
            let mode = match parts.get(1).copied() {
                Some("all") => loginscreen::UserListMode::ShowAll,
                Some("recent") => loginscreen::UserListMode::RecentOnly,
                Some("text") => loginscreen::UserListMode::TextEntry,
                Some("hidden") | Some("off") => loginscreen::UserListMode::Hidden,
                _ => { shell_println!("Usage: loginscreen userlist <all|recent|text|hidden>"); return; }
            };
            loginscreen::set_user_list(mode);
            shell_println!("Set user list mode.");
        }
        "timeout" => {
            let secs: u32 = match parts.get(1).and_then(|s| s.parse().ok()) {
                Some(v) => v,
                None => { shell_println!("Usage: loginscreen timeout <seconds>"); return; }
            };
            loginscreen::set_lock_timeout(secs);
            shell_println!("Set lock timeout to {} s.", secs);
        }
        "message" | "msg" => {
            if parts.len() < 2 {
                shell_println!("Usage: loginscreen message <text...>");
                return;
            }
            let msg = parts[1..].join(" ");
            loginscreen::set_message(&msg);
            shell_println!("Set message.");
        }
        "logo" => {
            match parts.get(1) {
                Some(path) => {
                    loginscreen::set_logo(path);
                    shell_println!("Set logo to {}.", path);
                }
                None => shell_println!("Usage: loginscreen logo <path>"),
            }
        }
        "keyboard" | "vkb" => {
            let on = parts.get(1).copied() == Some("on") || parts.get(1).copied() == Some("true");
            loginscreen::set_virtual_keyboard(on);
            shell_println!("Virtual keyboard {}.", if on { "enabled" } else { "disabled" });
        }
        "stats" => {
            let (synced, changes, ops) = loginscreen::stats();
            shell_println!("Synced:      {}", synced);
            shell_println!("Changes:     {}", changes);
            shell_println!("Operations:  {}", ops);
        }
        "clear" => {
            loginscreen::clear_all();
            shell_println!("Reset login screen configuration.");
        }
        "test" => {
            match loginscreen::self_test() {
                Ok(()) => shell_println!("loginscreen: all tests passed."),
                Err(e) => shell_println!("loginscreen: test failed: {:?}", e),
            }
        }
        _ => {
            shell_println!("loginscreen — login screen configuration");
            shell_println!();
            shell_println!("Subcommands:");
            shell_println!("  init                          Load defaults");
            shell_println!("  show                          Show current settings");
            shell_println!("  bg <mode>                     Set background mode");
            shell_println!("  image <path>                  Set background image");
            shell_println!("  sync                          Sync with desktop wallpaper");
            shell_println!("  fit <mode>                    Set image fit mode");
            shell_println!("  blur <0-100>                  Set blur amount");
            shell_println!("  clock <position>              Set clock position");
            shell_println!("  userlist <mode>               Set user list mode");
            shell_println!("  timeout <seconds>             Set lock timeout");
            shell_println!("  message <text...>             Set custom message");
            shell_println!("  logo <path>                   Set logo image");
            shell_println!("  keyboard <on|off>             Toggle virtual keyboard");
            shell_println!("  stats / clear / test");
            shell_println!();
            shell_println!("Background: image, color, gradient, slideshow, blur");
            shell_println!("Fit: fill, fit, stretch, center, tile");
            shell_println!("Clock: tl, tc, tr, bl, bc, br, hidden");
            shell_println!("Userlist: all, recent, text, hidden");
            shell_println!("Alias: logscr");
        }
    }
}

/// `appnotify` / `anotify` — per-application notification settings.
fn cmd_appnotify(args: &str) {
    use crate::fs::appnotify;

    let parts: Vec<&str> = args.split_whitespace().collect();
    let sub = parts.first().copied().unwrap_or("");

    match sub {
        "list" | "ls" => {
            let apps = appnotify::list_apps();
            if apps.is_empty() {
                shell_println!("No apps registered");
            } else {
                shell_println!("{:<20} {:<16} {:<7} {:<6} Types", "App ID", "Display Name", "Enabled", "Sound");
                for app in &apps {
                    let snd = match &app.sound {
                        appnotify::SoundChoice::SystemDefault => "default",
                        appnotify::SoundChoice::Named(_) => "custom",
                        appnotify::SoundChoice::Silent => "silent",
                    };
                    shell_println!("{:<20} {:<16} {:<7} {:<6} {}",
                        app.app_id, app.display_name,
                        if app.enabled { "yes" } else { "no" },
                        snd, app.notification_types.len());
                }
            }
        }
        "show" => {
            if parts.len() < 2 {
                shell_println!("Usage: appnotify show <app-id>");
            } else {
                match appnotify::get_app(parts[1]) {
                    Ok(app) => {
                        shell_println!("App:        {} ({})", app.display_name, app.app_id);
                        shell_println!("Enabled:    {}", app.enabled);
                        let snd = match &app.sound {
                            appnotify::SoundChoice::SystemDefault => String::from("system default"),
                            appnotify::SoundChoice::Named(n) => alloc::format!("custom: {}", n),
                            appnotify::SoundChoice::Silent => String::from("silent"),
                        };
                        shell_println!("Sound:      {}", snd);
                        shell_println!("Display:    {:?}", app.display_mode);
                        shell_println!("Critical:   {}", app.allow_critical);
                        shell_println!("Rate limit: {}/min", app.rate_limit);
                        shell_println!("Group:      {}", app.group_notifications);
                        if !app.notification_types.is_empty() {
                            shell_println!("\nNotification types:");
                            for t in &app.notification_types {
                                let en = if t.enabled { "on" } else { "off" };
                                shell_println!("  {} [{}] - {}", t.type_key, en, t.description);
                            }
                        }
                    }
                    Err(e) => shell_println!("Error: {:?}", e),
                }
            }
        }
        "register" | "reg" => {
            if parts.len() < 3 {
                shell_println!("Usage: appnotify register <app-id> <display-name>");
            } else {
                let name = parts[2..].join(" ");
                match appnotify::register_app(parts[1], &name) {
                    Ok(()) => shell_println!("Registered: {} ({})", name, parts[1]),
                    Err(e) => shell_println!("Error: {:?}", e),
                }
            }
        }
        "unregister" | "unreg" => {
            if parts.len() < 2 {
                shell_println!("Usage: appnotify unregister <app-id>");
            } else {
                match appnotify::unregister_app(parts[1]) {
                    Ok(()) => shell_println!("Unregistered: {}", parts[1]),
                    Err(e) => shell_println!("Error: {:?}", e),
                }
            }
        }
        "enable" => {
            if parts.len() < 2 {
                shell_println!("Usage: appnotify enable <app-id>");
            } else {
                match appnotify::set_app_enabled(parts[1], true) {
                    Ok(()) => shell_println!("Enabled: {}", parts[1]),
                    Err(e) => shell_println!("Error: {:?}", e),
                }
            }
        }
        "disable" => {
            if parts.len() < 2 {
                shell_println!("Usage: appnotify disable <app-id>");
            } else {
                match appnotify::set_app_enabled(parts[1], false) {
                    Ok(()) => shell_println!("Disabled: {}", parts[1]),
                    Err(e) => shell_println!("Error: {:?}", e),
                }
            }
        }
        "sound" => {
            if parts.len() < 3 {
                shell_println!("Usage: appnotify sound <app-id> <default|silent|filename>");
            } else {
                let snd = match parts[2] {
                    "default" => appnotify::SoundChoice::SystemDefault,
                    "silent" | "none" => appnotify::SoundChoice::Silent,
                    name => appnotify::SoundChoice::Named(String::from(name)),
                };
                match appnotify::set_app_sound(parts[1], snd) {
                    Ok(()) => shell_println!("Sound set for {}", parts[1]),
                    Err(e) => shell_println!("Error: {:?}", e),
                }
            }
        }
        "display" => {
            if parts.len() < 3 {
                shell_println!("Usage: appnotify display <app-id> <banner-pane|pane|banner|suppress>");
            } else {
                let mode = match parts[2] {
                    "banner-pane" | "both" => appnotify::DisplayMode::BannerAndPane,
                    "pane" | "pane-only" => appnotify::DisplayMode::PaneOnly,
                    "banner" | "banner-only" => appnotify::DisplayMode::BannerOnly,
                    "suppress" | "off" => appnotify::DisplayMode::Suppressed,
                    _ => { shell_println!("Unknown mode: {}", parts[2]); return; }
                };
                match appnotify::set_app_display_mode(parts[1], mode) {
                    Ok(()) => shell_println!("Display mode set for {}", parts[1]),
                    Err(e) => shell_println!("Error: {:?}", e),
                }
            }
        }
        "critical" => {
            if parts.len() < 3 {
                shell_println!("Usage: appnotify critical <app-id> <on|off>");
            } else {
                let allow = matches!(parts[2], "on" | "yes" | "true");
                match appnotify::set_allow_critical(parts[1], allow) {
                    Ok(()) => shell_println!("Critical {} for {}", if allow { "allowed" } else { "denied" }, parts[1]),
                    Err(e) => shell_println!("Error: {:?}", e),
                }
            }
        }
        "ratelimit" | "rate" => {
            if parts.len() < 3 {
                shell_println!("Usage: appnotify ratelimit <app-id> <per-minute|0>");
            } else {
                match parts[2].parse::<u32>() {
                    Ok(v) => match appnotify::set_rate_limit(parts[1], v) {
                        Ok(()) => shell_println!("Rate limit set to {}/min for {}", v, parts[1]),
                        Err(e) => shell_println!("Error: {:?}", e),
                    },
                    Err(_) => shell_println!("Invalid number"),
                }
            }
        }
        "group" => {
            if parts.len() < 3 {
                shell_println!("Usage: appnotify group <app-id> <on|off>");
            } else {
                let g = matches!(parts[2], "on" | "yes" | "true");
                match appnotify::set_group(parts[1], g) {
                    Ok(()) => shell_println!("Grouping {} for {}", if g { "enabled" } else { "disabled" }, parts[1]),
                    Err(e) => shell_println!("Error: {:?}", e),
                }
            }
        }
        "addtype" => {
            if parts.len() < 4 {
                shell_println!("Usage: appnotify addtype <app-id> <type-key> <description...>");
            } else {
                let desc = parts[3..].join(" ");
                match appnotify::register_notification_type(
                    parts[1], parts[2], &desc, appnotify::SoundChoice::SystemDefault,
                ) {
                    Ok(()) => shell_println!("Added type '{}' to {}", parts[2], parts[1]),
                    Err(e) => shell_println!("Error: {:?}", e),
                }
            }
        }
        "rmtype" => {
            if parts.len() < 3 {
                shell_println!("Usage: appnotify rmtype <app-id> <type-key>");
            } else {
                match appnotify::unregister_notification_type(parts[1], parts[2]) {
                    Ok(()) => shell_println!("Removed type '{}' from {}", parts[2], parts[1]),
                    Err(e) => shell_println!("Error: {:?}", e),
                }
            }
        }
        "type-enable" | "ten" => {
            if parts.len() < 3 {
                shell_println!("Usage: appnotify type-enable <app-id> <type-key>");
            } else {
                match appnotify::set_type_enabled(parts[1], parts[2], true) {
                    Ok(()) => shell_println!("Enabled '{}' for {}", parts[2], parts[1]),
                    Err(e) => shell_println!("Error: {:?}", e),
                }
            }
        }
        "type-disable" | "tdis" => {
            if parts.len() < 3 {
                shell_println!("Usage: appnotify type-disable <app-id> <type-key>");
            } else {
                match appnotify::set_type_enabled(parts[1], parts[2], false) {
                    Ok(()) => shell_println!("Disabled '{}' for {}", parts[2], parts[1]),
                    Err(e) => shell_println!("Error: {:?}", e),
                }
            }
        }
        "type-sound" | "tsnd" => {
            if parts.len() < 4 {
                shell_println!("Usage: appnotify type-sound <app-id> <type-key> <default|silent|filename>");
            } else {
                let snd = match parts[3] {
                    "default" => Some(appnotify::SoundChoice::SystemDefault),
                    "silent" | "none" => Some(appnotify::SoundChoice::Silent),
                    "clear" | "reset" => None,
                    name => Some(appnotify::SoundChoice::Named(String::from(name))),
                };
                match appnotify::set_type_sound(parts[1], parts[2], snd) {
                    Ok(()) => shell_println!("Type sound set for {}:{}", parts[1], parts[2]),
                    Err(e) => shell_println!("Error: {:?}", e),
                }
            }
        }
        "effective" | "eff" => {
            if parts.len() < 3 {
                shell_println!("Usage: appnotify effective <app-id> <type-key>");
            } else {
                let eff = appnotify::effective_settings(parts[1], parts[2]);
                shell_println!("Show:     {}", eff.show);
                shell_println!("Sound:    {}", eff.sound.as_deref().unwrap_or("(system default)"));
                shell_println!("Display:  {:?}", eff.display_mode);
                shell_println!("Priority: {:?}", eff.priority);
            }
        }
        "sounds" => {
            let cat = parts.get(1).copied();
            let sounds = match cat {
                Some(c) => appnotify::sounds_by_category(c),
                None => appnotify::list_sounds(),
            };
            if sounds.is_empty() {
                shell_println!("No sounds registered");
            } else {
                shell_println!("{:<20} {:<16} {}", "Filename", "Label", "Category");
                for s in &sounds {
                    shell_println!("{:<20} {:<16} {}", s.filename, s.label, s.category);
                }
            }
        }
        "addsound" => {
            if parts.len() < 4 {
                shell_println!("Usage: appnotify addsound <filename> <label> <category>");
            } else {
                match appnotify::register_sound(parts[1], parts[2], parts[3]) {
                    Ok(()) => shell_println!("Added sound: {}", parts[1]),
                    Err(e) => shell_println!("Error: {:?}", e),
                }
            }
        }
        "init" => {
            appnotify::init_defaults();
            shell_println!("Initialised app notification defaults");
        }
        "stats" => {
            let (apps, sounds, types, ops) = appnotify::stats();
            shell_println!("Apps:     {}", apps);
            shell_println!("Sounds:   {}", sounds);
            shell_println!("Types:    {}", types);
            shell_println!("Ops:      {}", ops);
        }
        "test" => {
            match appnotify::self_test() {
                Ok(()) => shell_println!("appnotify: all tests passed"),
                Err(e) => shell_println!("appnotify: test FAILED: {:?}", e),
            }
        }
        _ => {
            shell_println!("appnotify — per-app notification settings");
            shell_println!("Usage: appnotify <subcommand>");
            shell_println!("  list              List registered apps");
            shell_println!("  show <app>        Show app details and types");
            shell_println!("  register <id> <name>  Register app");
            shell_println!("  unregister <id>   Remove app");
            shell_println!("  enable <id>       Enable app notifications");
            shell_println!("  disable <id>      Disable app notifications");
            shell_println!("  sound <id> <s>    Set app sound (default|silent|file)");
            shell_println!("  display <id> <m>  Set display mode");
            shell_println!("  critical <id> <v> Allow/deny critical notifications");
            shell_println!("  ratelimit <id> <n>  Set rate limit per minute");
            shell_println!("  group <id> <v>    Enable/disable grouping");
            shell_println!("  addtype <id> <key> <desc>  Register notification type");
            shell_println!("  rmtype <id> <key> Remove notification type");
            shell_println!("  type-enable <id> <key>   Enable type");
            shell_println!("  type-disable <id> <key>  Disable type");
            shell_println!("  type-sound <id> <key> <s>  Set type sound override");
            shell_println!("  effective <id> <key>  Show effective settings");
            shell_println!("  sounds [category]  List system sounds");
            shell_println!("  addsound <f> <l> <c>  Register system sound");
            shell_println!("  init              Load defaults");
            shell_println!("  stats             Show statistics");
            shell_println!("  test              Run self-tests");
        }
    }
}

/// `kernelbuild` / `kbuild` — kernel and OS component build configuration.
fn cmd_kernelbuild(args: &str) {
    use crate::fs::kernelbuild;

    let parts: Vec<&str> = args.split_whitespace().collect();
    let sub = parts.first().copied().unwrap_or("");

    match sub {
        "list" | "ls" => {
            let comps = kernelbuild::list_components();
            if comps.is_empty() {
                shell_println!("No components registered");
            } else {
                shell_println!("{:<16} {:<16} {:<14} {:<12} Params", "ID", "Name", "Type", "Status");
                for c in &comps {
                    shell_println!("{:<16} {:<16} {:<14} {:<12} {}",
                        c.id, c.name,
                        alloc::format!("{:?}", c.comp_type),
                        alloc::format!("{:?}", c.status),
                        c.params.len());
                }
            }
        }
        "info" | "show" => {
            if parts.len() < 2 {
                shell_println!("Usage: kernelbuild info <component-id>");
            } else {
                match kernelbuild::get_component(parts[1]) {
                    Ok(c) => {
                        shell_println!("ID:          {}", c.id);
                        shell_println!("Name:        {}", c.name);
                        shell_println!("Type:        {:?}", c.comp_type);
                        shell_println!("Source:      {}", c.source_dir);
                        shell_println!("Output:      {}", c.output_path);
                        shell_println!("Status:      {:?}", c.status);
                        shell_println!("Opt level:   {:?}", c.opt_level);
                        shell_println!("Builds:      {}", c.build_count);
                        shell_println!("Auto-build:  {}", c.auto_rebuild);
                        shell_println!("Critical:    {}", c.system_critical);
                        if !c.dependencies.is_empty() {
                            shell_println!("Deps:        {}", c.dependencies.join(", "));
                        }
                        if !c.params.is_empty() {
                            shell_println!("\nParameters:");
                            for p in &c.params {
                                let reqs = if p.requires_full_rebuild { " [full-rebuild]" } else { "" };
                                shell_println!("  {} = {} (default: {}){}", p.key, p.value, p.default_value, reqs);
                                if !p.allowed.is_empty() {
                                    shell_println!("    allowed: {}", p.allowed.join(", "));
                                }
                            }
                        }
                    }
                    Err(e) => shell_println!("Error: {:?}", e),
                }
            }
        }
        "register" | "reg" => {
            if parts.len() < 5 {
                shell_println!("Usage: kernelbuild register <id> <name> <type> <source-dir>");
                shell_println!("Types: kernel, module, service, utility, library, bootloader");
            } else {
                let ct = match parts[3] {
                    "kernel" => Some(kernelbuild::ComponentType::Kernel),
                    "module" => Some(kernelbuild::ComponentType::KernelModule),
                    "service" => Some(kernelbuild::ComponentType::SystemService),
                    "utility" => Some(kernelbuild::ComponentType::CoreUtility),
                    "library" | "lib" => Some(kernelbuild::ComponentType::SharedLibrary),
                    "bootloader" | "boot" => Some(kernelbuild::ComponentType::Bootloader),
                    _ => { shell_println!("Unknown type: {}", parts[3]); None }
                };
                if let Some(ct) = ct {
                    let output = if parts.len() > 5 { parts[5] } else { "/dev/null" };
                    match kernelbuild::register_component(parts[1], parts[2], ct, parts[4], output) {
                        Ok(()) => shell_println!("Registered: {}", parts[1]),
                        Err(e) => shell_println!("Error: {:?}", e),
                    }
                }
            }
        }
        "remove" | "rm" => {
            if parts.len() < 2 {
                shell_println!("Usage: kernelbuild remove <component-id>");
            } else {
                match kernelbuild::remove_component(parts[1]) {
                    Ok(()) => shell_println!("Removed: {}", parts[1]),
                    Err(e) => shell_println!("Error: {:?}", e),
                }
            }
        }
        "param" | "set" => {
            if parts.len() < 4 {
                shell_println!("Usage: kernelbuild param <component-id> <key> <value>");
            } else {
                match kernelbuild::set_param(parts[1], parts[2], parts[3]) {
                    Ok(()) => shell_println!("Set {}={} for {}", parts[2], parts[3], parts[1]),
                    Err(e) => shell_println!("Error: {:?}", e),
                }
            }
        }
        "addparam" => {
            if parts.len() < 5 {
                shell_println!("Usage: kernelbuild addparam <comp-id> <key> <default> <desc...>");
            } else {
                let desc = parts[4..].join(" ");
                match kernelbuild::add_param(parts[1], parts[2], &desc, parts[3], &[], false) {
                    Ok(()) => shell_println!("Added param {} to {}", parts[2], parts[1]),
                    Err(e) => shell_println!("Error: {:?}", e),
                }
            }
        }
        "resetparam" => {
            if parts.len() < 3 {
                shell_println!("Usage: kernelbuild resetparam <component-id> <key>");
            } else {
                match kernelbuild::reset_param(parts[1], parts[2]) {
                    Ok(()) => shell_println!("Reset {} for {}", parts[2], parts[1]),
                    Err(e) => shell_println!("Error: {:?}", e),
                }
            }
        }
        "resetall" => {
            if parts.len() < 2 {
                shell_println!("Usage: kernelbuild resetall <component-id>");
            } else {
                match kernelbuild::reset_all_params(parts[1]) {
                    Ok(()) => shell_println!("Reset all params for {}", parts[1]),
                    Err(e) => shell_println!("Error: {:?}", e),
                }
            }
        }
        "opt" => {
            if parts.len() < 3 {
                shell_println!("Usage: kernelbuild opt <component-id> <debug|o1|o2|release|size>");
            } else {
                let level = match parts[2] {
                    "debug" => Some(kernelbuild::OptLevel::Debug),
                    "o1" | "O1" => Some(kernelbuild::OptLevel::O1),
                    "o2" | "O2" => Some(kernelbuild::OptLevel::O2),
                    "release" => Some(kernelbuild::OptLevel::Release),
                    "size" | "os" | "Os" => Some(kernelbuild::OptLevel::Size),
                    _ => { shell_println!("Unknown level: {}", parts[2]); None }
                };
                if let Some(level) = level {
                    match kernelbuild::set_opt_level(parts[1], level) {
                        Ok(()) => shell_println!("Opt level set to {:?} for {}", level, parts[1]),
                        Err(e) => shell_println!("Error: {:?}", e),
                    }
                }
            }
        }
        "auto" => {
            if parts.len() < 3 {
                shell_println!("Usage: kernelbuild auto <component-id> <on|off>");
            } else {
                let on = matches!(parts[2], "on" | "yes" | "true");
                match kernelbuild::set_auto_rebuild(parts[1], on) {
                    Ok(()) => shell_println!("Auto-rebuild {} for {}", if on { "enabled" } else { "disabled" }, parts[1]),
                    Err(e) => shell_println!("Error: {:?}", e),
                }
            }
        }
        "dep" => {
            if parts.len() < 3 {
                shell_println!("Usage: kernelbuild dep <component-id> <dependency-id>");
            } else {
                match kernelbuild::add_dependency(parts[1], parts[2]) {
                    Ok(()) => shell_println!("Added dep {} → {}", parts[1], parts[2]),
                    Err(e) => shell_println!("Error: {:?}", e),
                }
            }
        }
        "build" => {
            if parts.len() < 2 {
                shell_println!("Usage: kernelbuild build <component-id>");
            } else {
                match kernelbuild::build(parts[1]) {
                    Ok(()) => shell_println!("Build successful: {}", parts[1]),
                    Err(e) => shell_println!("Build error: {:?}", e),
                }
            }
        }
        "changed" => {
            let changed = kernelbuild::scan_changed();
            if changed.is_empty() {
                shell_println!("All components up to date");
            } else {
                shell_println!("Components with source changes:");
                for id in &changed {
                    shell_println!("  {}", id);
                }
            }
        }
        "logs" => {
            let comp_id = parts.get(1).copied();
            let logs = match comp_id {
                Some(id) => kernelbuild::build_logs(id),
                None => kernelbuild::all_build_logs(),
            };
            if logs.is_empty() {
                shell_println!("No build logs");
            } else {
                for l in &logs {
                    let status = if l.success { "OK" } else { "FAIL" };
                    shell_println!("[{}] {} {}ms - {}", status, l.component_id, l.duration_ms, l.output);
                }
            }
        }
        "init" => {
            kernelbuild::init_defaults();
            shell_println!("Initialised kernel build defaults");
        }
        "stats" => {
            let (comps, built, changed, ops) = kernelbuild::stats();
            shell_println!("Components:     {}", comps);
            shell_println!("Up to date:     {}", built);
            shell_println!("Source changed: {}", changed);
            shell_println!("Operations:     {}", ops);
        }
        "test" => {
            match kernelbuild::self_test() {
                Ok(()) => shell_println!("kernelbuild: all tests passed"),
                Err(e) => shell_println!("kernelbuild: test FAILED: {:?}", e),
            }
        }
        _ => {
            shell_println!("kernelbuild — kernel/OS component build configuration");
            shell_println!("Usage: kernelbuild <subcommand>");
            shell_println!("  list              List components");
            shell_println!("  info <id>         Show component details");
            shell_println!("  register <id> <name> <type> <src>  Register component");
            shell_println!("  remove <id>       Remove component");
            shell_println!("  param <id> <k> <v>  Set build parameter");
            shell_println!("  addparam <id> <k> <def> <desc>  Add parameter");
            shell_println!("  resetparam <id> <k>  Reset parameter to default");
            shell_println!("  resetall <id>     Reset all params to defaults");
            shell_println!("  opt <id> <level>  Set optimisation level");
            shell_println!("  auto <id> <on|off>  Toggle auto-rebuild");
            shell_println!("  dep <id> <dep-id> Add dependency");
            shell_println!("  build <id>        Build component");
            shell_println!("  changed           List changed components");
            shell_println!("  logs [id]         Show build logs");
            shell_println!("  init              Load defaults");
            shell_println!("  stats             Show statistics");
            shell_println!("  test              Run self-tests");
        }
    }
}

/// `wakesensor` / `wsensor` — webcam/mic-based screen wake settings.
fn cmd_wakesensor(args: &str) {
    use crate::fs::wakesensor;

    let parts: Vec<&str> = args.split_whitespace().collect();
    let sub = parts.first().copied().unwrap_or("");

    match sub {
        "show" | "config" => {
            let cfg = wakesensor::config();
            shell_println!("Global enabled:  {}", cfg.globally_enabled);
            shell_println!("Battery policy:  {}", if cfg.disable_on_battery { "disable on battery" } else { "always" });
            shell_println!("Cooldown:        {} s", cfg.cooldown_secs);
            shell_println!("Log events:      {}", cfg.log_events);
            shell_println!("\nCamera:");
            shell_println!("  Enabled:       {}", cfg.camera.enabled);
            shell_println!("  Consent:       {:?}", cfg.camera.consent);
            shell_println!("  Sensitivity:   {:?} (threshold: {})", cfg.camera.sensitivity, cfg.camera.effective_threshold);
            shell_println!("  Power draw:    {} mW", cfg.camera.power_draw_mw);
            shell_println!("  LED indicator: {}", cfg.camera.show_indicator);
            shell_println!("  Wakes:         {} (false pos: {})", cfg.camera.wake_count, cfg.camera.false_positive_count);
            if let (Some(s), Some(e)) = (cfg.camera.active_hours_start, cfg.camera.active_hours_end) {
                shell_println!("  Active hours:  {}:00 - {}:00", s, e);
            }
            shell_println!("\nMicrophone:");
            shell_println!("  Enabled:       {}", cfg.mic.enabled);
            shell_println!("  Consent:       {:?}", cfg.mic.consent);
            shell_println!("  Sensitivity:   {:?} (threshold: {})", cfg.mic.sensitivity, cfg.mic.effective_threshold);
            shell_println!("  Power draw:    {} mW", cfg.mic.power_draw_mw);
            shell_println!("  LED indicator: {}", cfg.mic.show_indicator);
            shell_println!("  Wakes:         {} (false pos: {})", cfg.mic.wake_count, cfg.mic.false_positive_count);
        }
        "enable" => {
            match wakesensor::set_globally_enabled(true) {
                Ok(()) => shell_println!("Wake sensors globally enabled"),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "disable" => {
            match wakesensor::set_globally_enabled(false) {
                Ok(()) => shell_println!("Wake sensors globally disabled"),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "consent" => {
            if parts.len() < 3 {
                shell_println!("Usage: wakesensor consent <camera|mic> <grant|revoke>");
            } else {
                let sensor = match parts[1] {
                    "camera" | "cam" => Some(wakesensor::SensorType::Camera),
                    "mic" | "microphone" => Some(wakesensor::SensorType::Microphone),
                    _ => { shell_println!("Unknown sensor: {}", parts[1]); None }
                };
                if let Some(sensor) = sensor {
                    let result = match parts[2] {
                        "grant" | "yes" => {
                            shell_println!("WARNING: {}", wakesensor::config().privacy_warning);
                            wakesensor::grant_consent(sensor)
                        }
                        "revoke" | "deny" | "no" => wakesensor::revoke_consent(sensor),
                        _ => { shell_println!("Usage: grant or revoke"); return; }
                    };
                    match result {
                        Ok(()) => shell_println!("Consent updated for {:?}", sensor),
                        Err(e) => shell_println!("Error: {:?}", e),
                    }
                }
            }
        }
        "camera" | "cam" => {
            if parts.len() < 2 {
                shell_println!("Usage: wakesensor camera <on|off>");
            } else {
                let on = matches!(parts[1], "on" | "yes" | "true" | "enable");
                match wakesensor::set_sensor_enabled(wakesensor::SensorType::Camera, on) {
                    Ok(()) => shell_println!("Camera wake {}", if on { "enabled" } else { "disabled" }),
                    Err(e) => shell_println!("Error: {:?} (consent required?)", e),
                }
            }
        }
        "mic" | "microphone" => {
            if parts.len() < 2 {
                shell_println!("Usage: wakesensor mic <on|off>");
            } else {
                let on = matches!(parts[1], "on" | "yes" | "true" | "enable");
                match wakesensor::set_sensor_enabled(wakesensor::SensorType::Microphone, on) {
                    Ok(()) => shell_println!("Mic wake {}", if on { "enabled" } else { "disabled" }),
                    Err(e) => shell_println!("Error: {:?} (consent required?)", e),
                }
            }
        }
        "sensitivity" | "sens" => {
            if parts.len() < 3 {
                shell_println!("Usage: wakesensor sensitivity <camera|mic> <low|medium|high|custom>");
            } else {
                let sensor = match parts[1] {
                    "camera" | "cam" => Some(wakesensor::SensorType::Camera),
                    "mic" | "microphone" => Some(wakesensor::SensorType::Microphone),
                    _ => { shell_println!("Unknown sensor"); None }
                };
                let sens = match parts[2] {
                    "low" => Some(wakesensor::Sensitivity::Low),
                    "medium" | "med" => Some(wakesensor::Sensitivity::Medium),
                    "high" => Some(wakesensor::Sensitivity::High),
                    "custom" => Some(wakesensor::Sensitivity::Custom),
                    _ => { shell_println!("Unknown level"); None }
                };
                if let (Some(sensor), Some(sens)) = (sensor, sens) {
                    match wakesensor::set_sensitivity(sensor, sens) {
                        Ok(()) => shell_println!("Sensitivity set to {:?}", sens),
                        Err(e) => shell_println!("Error: {:?}", e),
                    }
                }
            }
        }
        "threshold" => {
            if parts.len() < 3 {
                shell_println!("Usage: wakesensor threshold <camera|mic> <0-100>");
            } else {
                let sensor = match parts[1] {
                    "camera" | "cam" => Some(wakesensor::SensorType::Camera),
                    "mic" | "microphone" => Some(wakesensor::SensorType::Microphone),
                    _ => { shell_println!("Unknown sensor"); None }
                };
                if let Some(sensor) = sensor {
                    match parts[2].parse::<u32>() {
                        Ok(v) => match wakesensor::set_custom_threshold(sensor, v) {
                            Ok(()) => shell_println!("Threshold set to {}", v.min(100)),
                            Err(e) => shell_println!("Error: {:?}", e),
                        },
                        Err(_) => shell_println!("Invalid number"),
                    }
                }
            }
        }
        "hours" => {
            if parts.len() < 4 {
                shell_println!("Usage: wakesensor hours <camera|mic> <start-hour> <end-hour>");
                shell_println!("  Use 'clear' for start to remove schedule");
            } else {
                let sensor = match parts[1] {
                    "camera" | "cam" => Some(wakesensor::SensorType::Camera),
                    "mic" | "microphone" => Some(wakesensor::SensorType::Microphone),
                    _ => { shell_println!("Unknown sensor"); None }
                };
                if let Some(sensor) = sensor {
                    if parts[2] == "clear" {
                        match wakesensor::set_active_hours(sensor, None, None) {
                            Ok(()) => shell_println!("Schedule cleared"),
                            Err(e) => shell_println!("Error: {:?}", e),
                        }
                    } else {
                        match (parts[2].parse::<u8>(), parts[3].parse::<u8>()) {
                            (Ok(s), Ok(e)) => match wakesensor::set_active_hours(sensor, Some(s), Some(e)) {
                                Ok(()) => shell_println!("Active hours: {}:00 - {}:00", s, e),
                                Err(e) => shell_println!("Error: {:?}", e),
                            },
                            _ => shell_println!("Invalid hours"),
                        }
                    }
                }
            }
        }
        "cooldown" => {
            if parts.len() < 2 {
                shell_println!("Usage: wakesensor cooldown <seconds>");
            } else {
                match parts[1].parse::<u32>() {
                    Ok(v) => match wakesensor::set_cooldown(v) {
                        Ok(()) => shell_println!("Cooldown set to {} s", v.clamp(1, 300)),
                        Err(e) => shell_println!("Error: {:?}", e),
                    },
                    Err(_) => shell_println!("Invalid number"),
                }
            }
        }
        "battery" => {
            if parts.len() < 2 {
                shell_println!("Usage: wakesensor battery <disable-on-battery|always>");
            } else {
                let dis = matches!(parts[1], "disable" | "off" | "disable-on-battery");
                match wakesensor::set_disable_on_battery(dis) {
                    Ok(()) => shell_println!("Battery policy: {}", if dis { "disable on battery" } else { "always active" }),
                    Err(e) => shell_println!("Error: {:?}", e),
                }
            }
        }
        "events" => {
            let events = wakesensor::wake_events();
            if events.is_empty() {
                shell_println!("No wake events");
            } else {
                shell_println!("{:<6} {:<10} {:<6} {:<6} {}", "ID", "Sensor", "Level", "Thr", "FP");
                for e in &events {
                    let sensor = match e.sensor {
                        wakesensor::SensorType::Camera => "Camera",
                        wakesensor::SensorType::Microphone => "Mic",
                    };
                    let fp = if e.false_positive { "yes" } else { "" };
                    shell_println!("{:<6} {:<10} {:<6} {:<6} {}", e.id, sensor, e.level, e.threshold, fp);
                }
            }
        }
        "clearevents" => {
            wakesensor::clear_events();
            shell_println!("Wake events cleared");
        }
        "warning" => {
            shell_println!("{}", wakesensor::config().privacy_warning);
        }
        "init" => {
            wakesensor::init_defaults();
            shell_println!("Initialised wake sensor defaults");
        }
        "stats" => {
            let (global, cam, mic, events, ops) = wakesensor::stats();
            shell_println!("Global:  {}", if global { "on" } else { "off" });
            shell_println!("Camera:  {}", if cam { "on" } else { "off" });
            shell_println!("Mic:     {}", if mic { "on" } else { "off" });
            shell_println!("Events:  {}", events);
            shell_println!("Ops:     {}", ops);
        }
        "test" => {
            match wakesensor::self_test() {
                Ok(()) => shell_println!("wakesensor: all tests passed"),
                Err(e) => shell_println!("wakesensor: test FAILED: {:?}", e),
            }
        }
        _ => {
            shell_println!("wakesensor — webcam/mic-based screen wake (opt-in)");
            shell_println!("Usage: wakesensor <subcommand>");
            shell_println!("  show              Show current configuration");
            shell_println!("  enable/disable    Global enable/disable");
            shell_println!("  consent <s> <v>   Grant/revoke privacy consent");
            shell_println!("  camera <on|off>   Enable/disable camera wake");
            shell_println!("  mic <on|off>      Enable/disable mic wake");
            shell_println!("  sensitivity <s> <l>  Set sensitivity level");
            shell_println!("  threshold <s> <n> Set custom threshold (0-100)");
            shell_println!("  hours <s> <start> <end>  Set active hours");
            shell_println!("  cooldown <secs>   Set cooldown between wakes");
            shell_println!("  battery <policy>  Set battery policy");
            shell_println!("  events            Show wake event log");
            shell_println!("  clearevents       Clear event log");
            shell_println!("  warning           Show privacy warning");
            shell_println!("  init              Load defaults");
            shell_println!("  stats             Show statistics");
            shell_println!("  test              Run self-tests");
        }
    }
}

/// `netsettings` / `netcfg` — comprehensive network settings.
fn cmd_netsettings(args: &str) {
    use crate::fs::netsettings;

    let parts: Vec<&str> = args.split_whitespace().collect();
    let sub = parts.first().copied().unwrap_or("");

    match sub {
        "list" | "ifaces" => {
            let ifaces = netsettings::list_interfaces();
            if ifaces.is_empty() {
                shell_println!("No interfaces");
            } else {
                shell_println!("{:<8} {:<12} {:<10} {:<8} {:<16} {}", "Name", "Type", "State", "Speed", "IPv4", "MAC");
                for i in &ifaces {
                    let speed = if i.speed_mbps > 0 { alloc::format!("{}M", i.speed_mbps) } else { String::from("-") };
                    shell_println!("{:<8} {:<12} {:<10} {:<8} {:<16} {}",
                        i.name, alloc::format!("{:?}", i.iface_type),
                        alloc::format!("{:?}", i.link_state),
                        speed, i.ipv4.address, i.mac_address);
                }
            }
        }
        "show" | "info" => {
            if parts.len() < 2 {
                shell_println!("Usage: netsettings show <interface>");
            } else {
                match netsettings::get_interface(parts[1]) {
                    Ok(i) => {
                        shell_println!("Interface: {} ({})", i.display_name, i.name);
                        shell_println!("Type:      {:?}", i.iface_type);
                        shell_println!("State:     {:?}", i.link_state);
                        shell_println!("MAC:       {}", i.mac_address);
                        shell_println!("MTU:       {}", i.mtu);
                        shell_println!("Speed:     {} Mbps", i.speed_mbps);
                        shell_println!("\nIPv4:");
                        shell_println!("  Method:  {:?}", i.ipv4.method);
                        shell_println!("  Address: {}", i.ipv4.address);
                        shell_println!("  Netmask: {}", i.ipv4.netmask);
                        shell_println!("  Gateway: {}", i.ipv4.gateway);
                        shell_println!("\nIPv6:");
                        shell_println!("  Method:  {:?}", i.ipv6.method);
                        shell_println!("  Address: {}", i.ipv6.address);
                        shell_println!("  Prefix:  /{}", i.ipv6.prefix_len);
                        shell_println!("  Privacy: {}", i.ipv6.privacy_extensions);
                        shell_println!("\nDNS:");
                        shell_println!("  Auto:    {}", i.dns.auto_dns);
                        if !i.dns.servers.is_empty() {
                            shell_println!("  Servers: {}", i.dns.servers.join(", "));
                        }
                        if !i.dns.doh_url.is_empty() {
                            shell_println!("  DoH:     {}", i.dns.doh_url);
                        }
                        if !i.connected_ssid.is_empty() {
                            shell_println!("\nWi-Fi:     {}", i.connected_ssid);
                        }
                    }
                    Err(e) => shell_println!("Error: {:?}", e),
                }
            }
        }
        "add" => {
            if parts.len() < 4 {
                shell_println!("Usage: netsettings add <name> <type> <mac>");
                shell_println!("Types: ethernet, wifi, loopback, virtual, vpn");
            } else {
                let it = match parts[2] {
                    "ethernet" | "eth" => Some(netsettings::InterfaceType::Ethernet),
                    "wifi" | "wlan" => Some(netsettings::InterfaceType::Wifi),
                    "loopback" | "lo" => Some(netsettings::InterfaceType::Loopback),
                    "virtual" | "virt" => Some(netsettings::InterfaceType::Virtual),
                    "vpn" => Some(netsettings::InterfaceType::Vpn),
                    _ => { shell_println!("Unknown type: {}", parts[2]); None }
                };
                if let Some(it) = it {
                    let mac = if parts.len() > 3 { parts[3] } else { "00:00:00:00:00:00" };
                    match netsettings::add_interface(parts[1], parts[1], it, mac) {
                        Ok(()) => shell_println!("Added: {}", parts[1]),
                        Err(e) => shell_println!("Error: {:?}", e),
                    }
                }
            }
        }
        "remove" | "rm" => {
            if parts.len() < 2 {
                shell_println!("Usage: netsettings remove <interface>");
            } else {
                match netsettings::remove_interface(parts[1]) {
                    Ok(()) => shell_println!("Removed: {}", parts[1]),
                    Err(e) => shell_println!("Error: {:?}", e),
                }
            }
        }
        "up" => {
            if parts.len() < 2 { shell_println!("Usage: netsettings up <interface>"); }
            else { match netsettings::set_link_state(parts[1], netsettings::LinkState::Up) {
                Ok(()) => shell_println!("{} up", parts[1]),
                Err(e) => shell_println!("Error: {:?}", e),
            }}
        }
        "down" => {
            if parts.len() < 2 { shell_println!("Usage: netsettings down <interface>"); }
            else { match netsettings::set_link_state(parts[1], netsettings::LinkState::Down) {
                Ok(()) => shell_println!("{} down", parts[1]),
                Err(e) => shell_println!("Error: {:?}", e),
            }}
        }
        "ipv4" => {
            if parts.len() < 5 {
                shell_println!("Usage: netsettings ipv4 <iface> <auto|manual> <addr> [mask] [gw]");
            } else {
                let method = match parts[2] {
                    "auto" | "dhcp" => netsettings::IpMethod::Auto,
                    "manual" | "static" => netsettings::IpMethod::Manual,
                    "off" | "disabled" => netsettings::IpMethod::Disabled,
                    _ => { shell_println!("Method: auto, manual, off"); return; }
                };
                let addr = parts.get(3).copied().unwrap_or("");
                let mask = parts.get(4).copied().unwrap_or("255.255.255.0");
                let gw = parts.get(5).copied().unwrap_or("");
                match netsettings::set_ipv4(parts[1], method, addr, mask, gw) {
                    Ok(()) => shell_println!("IPv4 set for {}", parts[1]),
                    Err(e) => shell_println!("Error: {:?}", e),
                }
            }
        }
        "ipv6" => {
            if parts.len() < 4 {
                shell_println!("Usage: netsettings ipv6 <iface> <auto|manual|off> [addr] [prefix] [gw]");
            } else {
                let method = match parts[2] {
                    "auto" | "slaac" => netsettings::IpMethod::Auto,
                    "manual" | "static" => netsettings::IpMethod::Manual,
                    "off" | "disabled" => netsettings::IpMethod::Disabled,
                    _ => { shell_println!("Method: auto, manual, off"); return; }
                };
                let addr = parts.get(3).copied().unwrap_or("");
                let prefix: u8 = parts.get(4).and_then(|s| s.parse().ok()).unwrap_or(64);
                let gw = parts.get(5).copied().unwrap_or("");
                match netsettings::set_ipv6(parts[1], method, addr, prefix, gw) {
                    Ok(()) => shell_println!("IPv6 set for {}", parts[1]),
                    Err(e) => shell_println!("Error: {:?}", e),
                }
            }
        }
        "dns" => {
            if parts.len() < 3 {
                shell_println!("Usage: netsettings dns <iface> <auto|server1,server2,...>");
            } else {
                if parts[2] == "auto" {
                    match netsettings::set_dns(parts[1], true, &[]) {
                        Ok(()) => shell_println!("DNS set to auto for {}", parts[1]),
                        Err(e) => shell_println!("Error: {:?}", e),
                    }
                } else {
                    let servers: Vec<&str> = parts[2].split(',').collect();
                    match netsettings::set_dns(parts[1], false, &servers) {
                        Ok(()) => shell_println!("DNS servers set for {}", parts[1]),
                        Err(e) => shell_println!("Error: {:?}", e),
                    }
                }
            }
        }
        "doh" => {
            if parts.len() < 3 {
                shell_println!("Usage: netsettings doh <iface> <url|off>");
            } else {
                let url = if parts[2] == "off" { "" } else { parts[2] };
                match netsettings::set_doh(parts[1], url) {
                    Ok(()) => shell_println!("DoH set for {}", parts[1]),
                    Err(e) => shell_println!("Error: {:?}", e),
                }
            }
        }
        "mtu" => {
            if parts.len() < 3 {
                shell_println!("Usage: netsettings mtu <iface> <value>");
            } else {
                match parts[2].parse::<u32>() {
                    Ok(v) => match netsettings::set_mtu(parts[1], v) {
                        Ok(()) => shell_println!("MTU set to {} for {}", v, parts[1]),
                        Err(e) => shell_println!("Error: {:?}", e),
                    },
                    Err(_) => shell_println!("Invalid MTU"),
                }
            }
        }
        "scan" | "wifi" => {
            let nets = netsettings::wifi_scan();
            if nets.is_empty() {
                shell_println!("No Wi-Fi networks found");
            } else {
                shell_println!("{:<24} {:<6} {:<14} {:<6} {:<4} {}", "SSID", "Signal", "Security", "Band", "Ch", "Saved");
                for n in &nets {
                    let band = match n.band {
                        netsettings::WifiBand::Band2g => "2.4G",
                        netsettings::WifiBand::Band5g => "5G",
                        netsettings::WifiBand::Band6g => "6G",
                    };
                    shell_println!("{:<24} {:<6} {:<14} {:<6} {:<4} {}",
                        n.ssid, n.signal, alloc::format!("{:?}", n.security),
                        band, n.channel, if n.saved { "yes" } else { "" });
                }
            }
        }
        "connect" => {
            if parts.len() < 4 {
                shell_println!("Usage: netsettings connect <iface> <ssid> [password]");
            } else {
                let pass = parts.get(3).copied().unwrap_or("");
                match netsettings::connect_wifi(parts[1], parts[2], pass) {
                    Ok(()) => shell_println!("Connected to {}", parts[2]),
                    Err(e) => shell_println!("Error: {:?}", e),
                }
            }
        }
        "disconnect" => {
            if parts.len() < 2 {
                shell_println!("Usage: netsettings disconnect <iface>");
            } else {
                match netsettings::disconnect_wifi(parts[1]) {
                    Ok(()) => shell_println!("Disconnected"),
                    Err(e) => shell_println!("Error: {:?}", e),
                }
            }
        }
        "saved" => {
            let nets = netsettings::saved_networks();
            if nets.is_empty() {
                shell_println!("No saved networks");
            } else {
                shell_println!("{:<24} {:<14} {:<10} {}", "SSID", "Security", "Auto", "Priority");
                for n in &nets {
                    shell_println!("{:<24} {:<14} {:<10} {}",
                        n.ssid, alloc::format!("{:?}", n.security),
                        if n.auto_connect { "yes" } else { "no" }, n.priority);
                }
            }
        }
        "forget" => {
            if parts.len() < 2 { shell_println!("Usage: netsettings forget <ssid>"); }
            else { match netsettings::forget_network(parts[1]) {
                Ok(()) => shell_println!("Forgot: {}", parts[1]),
                Err(e) => shell_println!("Error: {:?}", e),
            }}
        }
        "router" | "gateway" => {
            let ri = netsettings::router_info();
            shell_println!("Gateway:     {} {}", ri.gateway_ip, if ri.reachable { "(reachable)" } else { "(unreachable)" });
            if !ri.model.is_empty() { shell_println!("Model:       {}", ri.model); }
            if !ri.external_ipv4.is_empty() { shell_println!("External v4: {}", ri.external_ipv4); }
            if !ri.external_ipv6.is_empty() { shell_println!("External v6: {}", ri.external_ipv6); }
        }
        "hostname" => {
            if parts.len() < 2 {
                shell_println!("Hostname: {}", netsettings::hostname());
            } else {
                netsettings::set_hostname(parts[1]);
                shell_println!("Hostname set to {}", parts[1]);
            }
        }
        "init" => {
            netsettings::init_defaults();
            shell_println!("Initialised network settings defaults");
        }
        "stats" => {
            let (ifaces, connected, saved, ops) = netsettings::stats();
            shell_println!("Interfaces:  {} ({} connected)", ifaces, connected);
            shell_println!("Saved WiFi:  {}", saved);
            shell_println!("Operations:  {}", ops);
        }
        "test" => {
            match netsettings::self_test() {
                Ok(()) => shell_println!("netsettings: all tests passed"),
                Err(e) => shell_println!("netsettings: test FAILED: {:?}", e),
            }
        }
        _ => {
            shell_println!("netsettings — comprehensive network configuration");
            shell_println!("Usage: netsettings <subcommand>");
            shell_println!("  list              List interfaces");
            shell_println!("  show <iface>      Show interface details");
            shell_println!("  add <name> <type> <mac>  Add interface");
            shell_println!("  remove <name>     Remove interface");
            shell_println!("  up/down <iface>   Set link state");
            shell_println!("  ipv4 <iface> <method> <addr> [mask] [gw]");
            shell_println!("  ipv6 <iface> <method> [addr] [prefix] [gw]");
            shell_println!("  dns <iface> <auto|servers>  Set DNS");
            shell_println!("  doh <iface> <url|off>  Set DNS-over-HTTPS");
            shell_println!("  mtu <iface> <val> Set MTU");
            shell_println!("  scan              Scan Wi-Fi networks");
            shell_println!("  connect <iface> <ssid> [pass]  Connect WiFi");
            shell_println!("  disconnect <iface>  Disconnect WiFi");
            shell_println!("  saved             List saved networks");
            shell_println!("  forget <ssid>     Forget saved network");
            shell_println!("  router            Show gateway/router info");
            shell_println!("  hostname [name]   Get/set hostname");
            shell_println!("  init              Load defaults");
            shell_println!("  stats             Show statistics");
            shell_println!("  test              Run self-tests");
        }
    }
}

/// `sysinfo` / `hwinfo` — system information explorer.
fn cmd_sysinfo(args: &str) {
    use crate::fs::sysinfo;

    let parts: Vec<&str> = args.split_whitespace().collect();
    let sub = parts.first().copied().unwrap_or("");

    match sub {
        "" | "summary" => {
            let os = sysinfo::os_info();
            let cpu = sysinfo::cpu_info();
            let mem = sysinfo::memory_info();
            let kp = sysinfo::kernel_params();
            shell_println!("=== {} {} ({}) ===", os.name, os.version, os.codename);
            shell_println!("Arch:       {}", os.arch);
            shell_println!("Kernel:     {}", os.kernel_version);
            if !os.website.is_empty() { shell_println!("Website:    {}", os.website); }
            shell_println!("");
            shell_println!("CPU:        {}", cpu.model);
            shell_println!("  Cores:    {} / {} threads", cpu.cores, cpu.threads);
            shell_println!("  Freq:     {} - {} MHz", cpu.base_freq_mhz, cpu.max_freq_mhz);
            shell_println!("  Cache:    L1d={}K L1i={}K L2={}K L3={}K",
                cpu.l1d_cache_kib, cpu.l1i_cache_kib, cpu.l2_cache_kib, cpu.l3_cache_kib);
            shell_println!("");
            let total_gib = mem.total_bytes / (1024 * 1024 * 1024);
            let used_gib = mem.used_bytes / (1024 * 1024 * 1024);
            shell_println!("Memory:     {} GiB total, {} GiB used", total_gib, used_gib);
            shell_println!("  Type:     {} {} @ {} MT/s ({} DIMMs)",
                mem.mem_type, "", mem.speed_mts, mem.dimm_count);
            shell_println!("");
            shell_println!("Kernel params:");
            shell_println!("  Page size:   {} B", kp.page_size);
            shell_println!("  Scheduler:   {}", kp.sched_model);
            shell_println!("  Preempt:     {}", kp.preempt_model);
            shell_println!("  Allocator:   {}", kp.alloc_model);
            shell_println!("  Overcommit:  {}", kp.overcommit_mode);
            shell_println!("  Max CPUs:    {}", kp.max_cpus);
            shell_println!("  Root FS:     {}", kp.root_fs);
        }
        "os" => {
            let os = sysinfo::os_info();
            shell_println!("Name:       {}", os.name);
            shell_println!("Version:    {}", os.version);
            shell_println!("Build:      {} ({})", os.build_number, os.build_date);
            shell_println!("Codename:   {}", os.codename);
            shell_println!("Arch:       {}", os.arch);
            shell_println!("Kernel:     {}", os.kernel_version);
            shell_println!("Website:    {}", os.website);
            shell_println!("Uptime:     {} s", os.uptime_secs);
        }
        "cpu" => {
            let cpu = sysinfo::cpu_info();
            shell_println!("Model:      {}", cpu.model);
            shell_println!("Vendor:     {}", cpu.vendor);
            shell_println!("Family:     {} Model: {} Stepping: {}", cpu.family, cpu.model_num, cpu.stepping);
            shell_println!("Cores:      {} physical, {} logical", cpu.cores, cpu.threads);
            shell_println!("Freq:       {} MHz base, {} MHz boost", cpu.base_freq_mhz, cpu.max_freq_mhz);
            shell_println!("L1d cache:  {} KiB", cpu.l1d_cache_kib);
            shell_println!("L1i cache:  {} KiB", cpu.l1i_cache_kib);
            shell_println!("L2 cache:   {} KiB", cpu.l2_cache_kib);
            shell_println!("L3 cache:   {} KiB", cpu.l3_cache_kib);
            if !cpu.features.is_empty() {
                shell_println!("Features:   {}", cpu.features.join(", "));
            }
        }
        "memory" | "mem" => {
            let mem = sysinfo::memory_info();
            let total_gib = mem.total_bytes / (1024 * 1024 * 1024);
            let used_gib = mem.used_bytes / (1024 * 1024 * 1024);
            let avail_gib = mem.available_bytes / (1024 * 1024 * 1024);
            shell_println!("Total:      {} GiB ({} bytes)", total_gib, mem.total_bytes);
            shell_println!("Used:       {} GiB ({} bytes)", used_gib, mem.used_bytes);
            shell_println!("Available:  {} GiB ({} bytes)", avail_gib, mem.available_bytes);
            shell_println!("Swap:       {} / {} bytes", mem.swap_used, mem.swap_total);
            shell_println!("Type:       {}", mem.mem_type);
            shell_println!("Speed:      {} MT/s", mem.speed_mts);
            shell_println!("DIMMs:      {}", mem.dimm_count);
        }
        "storage" | "disk" | "disks" => {
            let devs = sysinfo::storage_info();
            if devs.is_empty() {
                shell_println!("No storage devices");
            } else {
                for d in &devs {
                    let cap_gib = d.capacity_bytes / (1024 * 1024 * 1024);
                    let free_gib = d.free_bytes / (1024 * 1024 * 1024);
                    let used_pct = if d.capacity_bytes > 0 {
                        ((d.capacity_bytes - d.free_bytes) * 100 / d.capacity_bytes) as u32
                    } else { 0 };
                    let flags = if d.network { " [network]" } else if d.removable { " [removable]" } else { "" };
                    shell_println!("{} on {} ({}) {} GiB / {} GiB ({}% used) [{}]{}",
                        d.device, d.mount_point, d.fs_type,
                        cap_gib - free_gib, cap_gib, used_pct,
                        d.interface, flags);
                }
            }
        }
        "gpu" | "gpus" => {
            let gpus = sysinfo::gpu_info();
            if gpus.is_empty() {
                shell_println!("No GPUs detected");
            } else {
                for (i, g) in gpus.iter().enumerate() {
                    shell_println!("GPU {}:  {} ({})", i, g.name, g.vendor);
                    shell_println!("  VRAM:    {} MiB", g.vram_mib);
                    shell_println!("  Driver:  {}", g.driver_version);
                    shell_println!("  Display: {} @ {} Hz", g.resolution, g.refresh_hz);
                    if !g.api_support.is_empty() {
                        shell_println!("  APIs:    {}", g.api_support.join(", "));
                    }
                }
            }
        }
        "net" | "network" => {
            let ifaces = sysinfo::network_info();
            if ifaces.is_empty() {
                shell_println!("No network interfaces");
            } else {
                shell_println!("{:<8} {:<10} {:<16} {:<18} {:<8} {}", "Name", "Type", "IP", "MAC", "Speed", "Status");
                for i in &ifaces {
                    let speed = if i.speed_mbps > 0 { alloc::format!("{}M", i.speed_mbps) } else { String::from("-") };
                    shell_println!("{:<8} {:<10} {:<16} {:<18} {:<8} {}",
                        i.name, i.iface_type, i.ip_address, i.mac_address,
                        speed, if i.connected { "up" } else { "down" });
                }
            }
        }
        "kernel" | "kparams" => {
            let kp = sysinfo::kernel_params();
            shell_println!("Page size:       {} bytes", kp.page_size);
            shell_println!("Scheduler:       {}", kp.sched_model);
            shell_println!("Preemption:      {}", kp.preempt_model);
            shell_println!("Allocator:       {}", kp.alloc_model);
            shell_println!("Overcommit:      {}", kp.overcommit_mode);
            shell_println!("Max CPUs:        {}", kp.max_cpus);
            shell_println!("Root FS:         {}", kp.root_fs);
            shell_println!("Debug asserts:   {}", kp.debug_assertions);
        }
        "init" => {
            sysinfo::init_defaults();
            shell_println!("Initialised system information defaults");
        }
        "stats" => {
            let (storage, gpus, nets, ops) = sysinfo::stats();
            shell_println!("Storage devs: {}", storage);
            shell_println!("GPUs:         {}", gpus);
            shell_println!("Net ifaces:   {}", nets);
            shell_println!("Operations:   {}", ops);
        }
        "test" => {
            match sysinfo::self_test() {
                Ok(()) => shell_println!("sysinfo: all tests passed"),
                Err(e) => shell_println!("sysinfo: test FAILED: {:?}", e),
            }
        }
        _ => {
            shell_println!("sysinfo — system information explorer");
            shell_println!("Usage: sysinfo <subcommand>");
            shell_println!("  (no args)         Full summary");
            shell_println!("  os                OS information");
            shell_println!("  cpu               CPU details");
            shell_println!("  memory            RAM details");
            shell_println!("  storage           Storage devices and partitions");
            shell_println!("  gpu               GPU information");
            shell_println!("  net               Network interfaces");
            shell_println!("  kernel            Kernel compile-time parameters");
            shell_println!("  init              Load defaults");
            shell_println!("  stats             Show statistics");
            shell_println!("  test              Run self-tests");
        }
    }
}

/// `perfmon` / `resmon` — performance monitor and resource tracking.
fn cmd_perfmon(args: &str) {
    use crate::fs::perfmon;

    let parts: Vec<&str> = args.split_whitespace().collect();
    let sub = parts.first().copied().unwrap_or("");

    match sub {
        "" | "show" | "latest" => {
            if let Some(cpu) = perfmon::cpu_latest() {
                shell_println!("CPU:  {}% (sys {}% user {}%) @ {} MHz",
                    cpu.usage_pct, cpu.system_pct, cpu.user_pct, cpu.freq_mhz);
                if cpu.temp_mc > 0 {
                    shell_println!("Temp: {}.{} °C", cpu.temp_mc / 1000, (cpu.temp_mc % 1000) / 100);
                }
                shell_println!("Procs: {} Threads: {}", cpu.process_count, cpu.thread_count);
            } else {
                shell_println!("No CPU samples yet");
            }
            if let Some(mem) = perfmon::mem_latest() {
                let used_mb = mem.used_bytes / (1024 * 1024);
                let avail_mb = mem.available_bytes / (1024 * 1024);
                shell_println!("RAM:  {} MiB used, {} MiB available", used_mb, avail_mb);
            }
            let alerts = perfmon::active_alerts();
            if !alerts.is_empty() {
                shell_println!("\n{} active alert(s):", alerts.len());
                for a in &alerts {
                    shell_println!("  [{}] {}", a.resource, a.message);
                }
            }
        }
        "cpu" => {
            let hist = perfmon::cpu_history();
            if hist.is_empty() {
                shell_println!("No CPU samples");
            } else {
                let n = hist.len().min(10);
                shell_println!("Last {} CPU samples:", n);
                for s in hist.iter().rev().take(n) {
                    shell_println!("  {}% (sys {}%, user {}%) @ {} MHz, {} procs",
                        s.usage_pct, s.system_pct, s.user_pct, s.freq_mhz, s.process_count);
                }
            }
        }
        "mem" | "memory" => {
            let hist = perfmon::mem_history();
            if hist.is_empty() {
                shell_println!("No memory samples");
            } else {
                let n = hist.len().min(10);
                shell_println!("Last {} memory samples:", n);
                for s in hist.iter().rev().take(n) {
                    let used_mb = s.used_bytes / (1024 * 1024);
                    let avail_mb = s.available_bytes / (1024 * 1024);
                    shell_println!("  {} MiB used, {} MiB avail, swap {} MiB, {} faults",
                        used_mb, avail_mb, s.swap_used_bytes / (1024 * 1024), s.page_faults);
                }
            }
        }
        "disk" => {
            let hist = perfmon::disk_history();
            if hist.is_empty() {
                shell_println!("No disk samples");
            } else {
                let n = hist.len().min(10);
                shell_println!("Last {} disk samples:", n);
                for s in hist.iter().rev().take(n) {
                    shell_println!("  {} R:{} W:{} IOPS r:{} w:{} busy:{}% q:{}",
                        s.device, s.read_bytes, s.write_bytes,
                        s.read_iops, s.write_iops, s.busy_pct, s.queue_depth);
                }
            }
        }
        "net" | "network" => {
            let hist = perfmon::net_history();
            if hist.is_empty() {
                shell_println!("No network samples");
            } else {
                let n = hist.len().min(10);
                shell_println!("Last {} network samples:", n);
                for s in hist.iter().rev().take(n) {
                    shell_println!("  {} rx:{} tx:{} pkts r:{} t:{} err:{}",
                        s.interface, s.rx_bytes, s.tx_bytes,
                        s.rx_packets, s.tx_packets, s.errors);
                }
            }
        }
        "alerts" => {
            let alerts = perfmon::all_alerts();
            if alerts.is_empty() {
                shell_println!("No alerts");
            } else {
                for a in &alerts {
                    let status = if a.dismissed { "dismissed" } else { "active" };
                    shell_println!("[{}] {} {} ({}% >= {}%) [{}]",
                        a.id, a.resource, a.message, a.value, a.threshold, status);
                }
            }
        }
        "dismiss" => {
            if parts.len() < 2 {
                shell_println!("Usage: perfmon dismiss <id|all>");
            } else if parts[1] == "all" {
                perfmon::dismiss_all_alerts();
                shell_println!("All alerts dismissed");
            } else {
                match parts[1].parse::<u64>() {
                    Ok(id) => match perfmon::dismiss_alert(id) {
                        Ok(()) => shell_println!("Alert {} dismissed", id),
                        Err(e) => shell_println!("Error: {:?}", e),
                    },
                    Err(_) => shell_println!("Invalid ID"),
                }
            }
        }
        "config" => {
            let cfg = perfmon::get_config();
            shell_println!("Interval:    {} ms", cfg.sample_interval_ms);
            shell_println!("Max samples: {}", cfg.max_samples);
            shell_println!("CPU:         {} (alert > {}%)", if cfg.cpu_enabled { "on" } else { "off" }, cfg.cpu_alert_pct);
            shell_println!("Memory:      {} (alert > {}%)", if cfg.mem_enabled { "on" } else { "off" }, cfg.mem_alert_pct);
            shell_println!("Disk:        {} (alert > {}%)", if cfg.disk_enabled { "on" } else { "off" }, cfg.disk_alert_pct);
            shell_println!("Network:     {}", if cfg.net_enabled { "on" } else { "off" });
        }
        "interval" => {
            if parts.len() < 2 { shell_println!("Usage: perfmon interval <ms>"); }
            else { match parts[1].parse::<u32>() {
                Ok(v) => { perfmon::set_interval(v); shell_println!("Interval set to {} ms", v.clamp(100, 60000)); }
                Err(_) => shell_println!("Invalid value"),
            }}
        }
        "init" => {
            perfmon::init_defaults();
            shell_println!("Initialised performance monitor defaults");
        }
        "stats" => {
            let (cpus, mems, disks, nets, alerts, ops) = perfmon::stats();
            shell_println!("CPU samples:  {}", cpus);
            shell_println!("Mem samples:  {}", mems);
            shell_println!("Disk samples: {}", disks);
            shell_println!("Net samples:  {}", nets);
            shell_println!("Alerts:       {}", alerts);
            shell_println!("Operations:   {}", ops);
        }
        "test" => {
            match perfmon::self_test() {
                Ok(()) => shell_println!("perfmon: all tests passed"),
                Err(e) => shell_println!("perfmon: test FAILED: {:?}", e),
            }
        }
        _ => {
            shell_println!("perfmon — performance monitor / resource tracker");
            shell_println!("Usage: perfmon <subcommand>");
            shell_println!("  (no args)         Show latest readings");
            shell_println!("  cpu               CPU history");
            shell_println!("  mem               Memory history");
            shell_println!("  disk              Disk I/O history");
            shell_println!("  net               Network history");
            shell_println!("  alerts            Show all alerts");
            shell_println!("  dismiss <id|all>  Dismiss alert(s)");
            shell_println!("  config            Show configuration");
            shell_println!("  interval <ms>     Set sample interval");
            shell_println!("  init              Load defaults");
            shell_println!("  stats             Show statistics");
            shell_println!("  test              Run self-tests");
        }
    }
}

/// `focusassist` / `dnd` — Focus Assist / Do Not Disturb mode.
fn cmd_focusassist(args: &str) {
    use crate::fs::focusassist;
    use alloc::format;
    let parts: Vec<&str> = args.split_whitespace().collect();
    let sub = parts.first().copied().unwrap_or("");
    match sub {
        "init" => {
            focusassist::init_defaults();
            shell_println!("Focus assist initialized with default profiles.");
        }
        "show" | "" => {
            let (profiles, schedules, active, missed, sessions, ops) = focusassist::stats();
            shell_println!("=== Focus Assist ===");
            shell_println!("Status:    {}", if active { "ACTIVE" } else { "off" });
            shell_println!("Profiles:  {}", profiles);
            shell_println!("Schedules: {}", schedules);
            shell_println!("Missed:    {}", missed);
            shell_println!("Sessions:  {}", sessions);
            shell_println!("Ops:       {}", ops);
            if let Some(profile) = focusassist::active_profile() {
                shell_println!("\nActive profile: {} (mode={:?})", profile.name, profile.mode);
                if !profile.priority_apps.is_empty() {
                    shell_println!("Priority apps: {}", profile.priority_apps.join(", "));
                }
                if let Some(ref reply) = profile.auto_reply {
                    shell_println!("Auto-reply: {}", reply);
                }
            }
        }
        "on" => {
            let profile_id = parts.get(1)
                .and_then(|s| s.parse::<u64>().ok())
                .unwrap_or(1);
            match focusassist::activate(profile_id) {
                Ok(()) => {
                    if let Some(p) = focusassist::active_profile() {
                        shell_println!("Focus assist ON: {} ({:?})", p.name, p.mode);
                    }
                }
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "off" => {
            match focusassist::deactivate() {
                Ok(missed) => {
                    shell_println!("Focus assist OFF.");
                    if !missed.is_empty() {
                        shell_println!("Missed {} notification(s):", missed.len());
                        for m in &missed {
                            shell_println!("  [{}] {}: {}", match m.priority {
                                focusassist::NotifPriority::Low => "low",
                                focusassist::NotifPriority::Normal => "normal",
                                focusassist::NotifPriority::High => "high",
                                focusassist::NotifPriority::Critical => "critical",
                                focusassist::NotifPriority::Alarm => "alarm",
                            }, m.app_id, m.title);
                        }
                    }
                }
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "profiles" => {
            let profiles = focusassist::list_profiles();
            if profiles.is_empty() {
                shell_println!("No profiles. Run 'focusassist init'.");
            } else {
                shell_println!("{:<4} {:<20} {:<15} {:<8} {}", "ID", "Name", "Mode", "Enabled", "Builtin");
                for p in &profiles {
                    shell_println!("{:<4} {:<20} {:<15} {:<8} {}", p.id, p.name,
                        format!("{:?}", p.mode), p.enabled, p.builtin);
                }
            }
        }
        "create" => {
            let name = parts.get(1).copied().unwrap_or("");
            let mode_str = parts.get(2).copied().unwrap_or("priority");
            if name.is_empty() {
                shell_println!("Usage: focusassist create <name> [priority|alarms|total]");
                return;
            }
            let mode = match mode_str {
                "priority" => focusassist::FocusMode::PriorityOnly,
                "alarms" => focusassist::FocusMode::AlarmsOnly,
                "total" => focusassist::FocusMode::Total,
                _ => {
                    shell_println!("Unknown mode '{}'. Use: priority, alarms, total", mode_str);
                    return;
                }
            };
            match focusassist::create_profile(name, mode) {
                Ok(id) => shell_println!("Created profile '{}' (id={})", name, id),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "remove" => {
            let id = parts.get(1).and_then(|s| s.parse::<u64>().ok()).unwrap_or(0);
            if id == 0 {
                shell_println!("Usage: focusassist remove <profile_id>");
                return;
            }
            match focusassist::remove_profile(id) {
                Ok(()) => shell_println!("Removed profile {}", id),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "mode" => {
            let id = parts.get(1).and_then(|s| s.parse::<u64>().ok()).unwrap_or(0);
            let mode_str = parts.get(2).copied().unwrap_or("");
            if id == 0 || mode_str.is_empty() {
                shell_println!("Usage: focusassist mode <profile_id> <priority|alarms|total>");
                return;
            }
            let mode = match mode_str {
                "priority" => focusassist::FocusMode::PriorityOnly,
                "alarms" => focusassist::FocusMode::AlarmsOnly,
                "total" => focusassist::FocusMode::Total,
                _ => {
                    shell_println!("Unknown mode '{}'", mode_str);
                    return;
                }
            };
            match focusassist::set_mode(id, mode) {
                Ok(()) => shell_println!("Set profile {} mode to {:?}", id, mode),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "addapp" => {
            let id = parts.get(1).and_then(|s| s.parse::<u64>().ok()).unwrap_or(0);
            let app_id = parts.get(2).copied().unwrap_or("");
            if id == 0 || app_id.is_empty() {
                shell_println!("Usage: focusassist addapp <profile_id> <app_id>");
                return;
            }
            match focusassist::add_priority_app(id, app_id) {
                Ok(()) => shell_println!("Added '{}' to profile {} priority apps", app_id, id),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "rmapp" => {
            let id = parts.get(1).and_then(|s| s.parse::<u64>().ok()).unwrap_or(0);
            let app_id = parts.get(2).copied().unwrap_or("");
            if id == 0 || app_id.is_empty() {
                shell_println!("Usage: focusassist rmapp <profile_id> <app_id>");
                return;
            }
            match focusassist::remove_priority_app(id, app_id) {
                Ok(()) => shell_println!("Removed '{}' from profile {} priority apps", app_id, id),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "apps" => {
            let id = parts.get(1).and_then(|s| s.parse::<u64>().ok()).unwrap_or(0);
            if id == 0 {
                shell_println!("Usage: focusassist apps <profile_id>");
                return;
            }
            match focusassist::priority_apps(id) {
                Ok(apps) => {
                    if apps.is_empty() {
                        shell_println!("No priority apps for profile {}", id);
                    } else {
                        shell_println!("Priority apps for profile {}:", id);
                        for a in &apps {
                            shell_println!("  {}", a);
                        }
                    }
                }
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "reply" => {
            let id = parts.get(1).and_then(|s| s.parse::<u64>().ok()).unwrap_or(0);
            if id == 0 {
                shell_println!("Usage: focusassist reply <profile_id> [message]");
                return;
            }
            let msg = if parts.len() > 2 {
                Some(parts[2..].join(" "))
            } else {
                None
            };
            match focusassist::set_auto_reply(id, msg.as_deref()) {
                Ok(()) => {
                    if let Some(ref m) = msg {
                        shell_println!("Set auto-reply for profile {}: {}", id, m);
                    } else {
                        shell_println!("Cleared auto-reply for profile {}", id);
                    }
                }
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "missed" => {
            let missed = focusassist::missed_notifications();
            if missed.is_empty() {
                shell_println!("No missed notifications.");
            } else {
                shell_println!("Missed {} notification(s):", missed.len());
                for m in &missed {
                    shell_println!("  [{}] {}: {}", match m.priority {
                        focusassist::NotifPriority::Low => "low",
                        focusassist::NotifPriority::Normal => "normal",
                        focusassist::NotifPriority::High => "high",
                        focusassist::NotifPriority::Critical => "critical",
                        focusassist::NotifPriority::Alarm => "alarm",
                    }, m.app_id, m.title);
                }
            }
        }
        "schedules" => {
            let scheds = focusassist::list_schedules();
            if scheds.is_empty() {
                shell_println!("No schedules.");
            } else {
                let day_names = ["Sun", "Mon", "Tue", "Wed", "Thu", "Fri", "Sat"];
                for s in &scheds {
                    let days: Vec<&str> = s.days.iter().enumerate()
                        .filter(|(_, d)| **d)
                        .map(|(i, _)| day_names[i])
                        .collect();
                    shell_println!("  id={} {:?} {:02}:{:02}-{:02}:{:02} days=[{}] profile={} enabled={}",
                        s.id, s.name, s.start_hour, s.start_minute,
                        s.end_hour, s.end_minute, days.join(","), s.profile_id, s.enabled);
                }
            }
        }
        "addsched" => {
            // focusassist addsched <name> <start_hh:mm> <end_hh:mm> <profile_id> [days]
            let name = parts.get(1).copied().unwrap_or("");
            let start = parts.get(2).copied().unwrap_or("");
            let end = parts.get(3).copied().unwrap_or("");
            let pid = parts.get(4).and_then(|s| s.parse::<u64>().ok()).unwrap_or(0);
            if name.is_empty() || start.is_empty() || end.is_empty() || pid == 0 {
                shell_println!("Usage: focusassist addsched <name> <HH:MM> <HH:MM> <profile_id> [days]");
                shell_println!("  days: comma-separated 0-6 (0=Sun). Default: all days.");
                return;
            }
            let parse_time = |t: &str| -> Option<(u8, u8)> {
                let p: Vec<&str> = t.split(':').collect();
                if p.len() != 2 { return None; }
                Some((p[0].parse().ok()?, p[1].parse().ok()?))
            };
            let (sh, sm) = match parse_time(start) {
                Some(t) => t,
                None => { shell_println!("Invalid start time"); return; }
            };
            let (eh, em) = match parse_time(end) {
                Some(t) => t,
                None => { shell_println!("Invalid end time"); return; }
            };
            let mut days = [true; 7];
            if let Some(d) = parts.get(5) {
                days = [false; 7];
                for part in d.split(',') {
                    if let Ok(n) = part.parse::<usize>() {
                        if n < 7 { days[n] = true; }
                    }
                }
            }
            match focusassist::add_schedule(name, days, sh, sm, eh, em, pid) {
                Ok(id) => shell_println!("Created schedule '{}' (id={})", name, id),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "rmsched" => {
            let id = parts.get(1).and_then(|s| s.parse::<u64>().ok()).unwrap_or(0);
            if id == 0 {
                shell_println!("Usage: focusassist rmsched <schedule_id>");
                return;
            }
            match focusassist::remove_schedule(id) {
                Ok(()) => shell_println!("Removed schedule {}", id),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "autofs" => {
            let val = parts.get(1).copied().unwrap_or("");
            match val {
                "on" => { let _ = focusassist::set_auto_fullscreen(true); shell_println!("Auto fullscreen: ON"); }
                "off" => { let _ = focusassist::set_auto_fullscreen(false); shell_println!("Auto fullscreen: OFF"); }
                _ => shell_println!("Usage: focusassist autofs <on|off>"),
            }
        }
        "autogame" => {
            let val = parts.get(1).copied().unwrap_or("");
            match val {
                "on" => { let _ = focusassist::set_auto_gaming(true); shell_println!("Auto gaming: ON"); }
                "off" => { let _ = focusassist::set_auto_gaming(false); shell_println!("Auto gaming: OFF"); }
                _ => shell_println!("Usage: focusassist autogame <on|off>"),
            }
        }
        "autopres" => {
            let val = parts.get(1).copied().unwrap_or("");
            match val {
                "on" => { let _ = focusassist::set_auto_presentation(true); shell_println!("Auto presentation: ON"); }
                "off" => { let _ = focusassist::set_auto_presentation(false); shell_println!("Auto presentation: OFF"); }
                _ => shell_println!("Usage: focusassist autopres <on|off>"),
            }
        }
        "stats" => {
            let (profiles, schedules, active, missed, sessions, ops) = focusassist::stats();
            shell_println!("profiles={} schedules={} active={} missed={} sessions={} ops={}",
                profiles, schedules, active, missed, sessions, ops);
        }
        "test" => {
            focusassist::self_test();
            shell_println!("Self-tests passed.");
        }
        _ => {
            shell_println!("focusassist / dnd — Focus Assist / Do Not Disturb");
            shell_println!("Subcommands:");
            shell_println!("  show          Show current focus status");
            shell_println!("  on [id]       Activate focus profile (default: 1=Priority Only)");
            shell_println!("  off           Deactivate focus, show missed summary");
            shell_println!("  profiles      List all focus profiles");
            shell_println!("  create <name> [priority|alarms|total]  Create custom profile");
            shell_println!("  remove <id>   Remove custom profile");
            shell_println!("  mode <id> <mode>  Set profile mode");
            shell_println!("  addapp <id> <app>  Add priority app to profile");
            shell_println!("  rmapp <id> <app>   Remove priority app from profile");
            shell_println!("  apps <id>     List priority apps for profile");
            shell_println!("  reply <id> [msg]  Set/clear auto-reply");
            shell_println!("  missed        Show missed notifications");
            shell_println!("  schedules     List focus schedules");
            shell_println!("  addsched <name> <HH:MM> <HH:MM> <profile_id> [days]  Add schedule");
            shell_println!("  rmsched <id>  Remove schedule");
            shell_println!("  autofs <on|off>    Auto-activate on fullscreen");
            shell_println!("  autogame <on|off>  Auto-activate on gaming");
            shell_println!("  autopres <on|off>  Auto-activate on presentation");
            shell_println!("  init          Initialize defaults");
            shell_println!("  stats         Show counters");
            shell_println!("  test          Run self-tests");
        }
    }
}

/// `storageclean` / `sclean` — storage cleanup and disk space analysis.
fn cmd_storageclean(args: &str) {
    use crate::fs::storageclean;
    let parts: Vec<&str> = args.split_whitespace().collect();
    let sub = parts.first().copied().unwrap_or("");
    match sub {
        "init" => {
            storageclean::init_defaults();
            shell_println!("Storage cleanup initialized.");
        }
        "show" | "" => {
            let (items, freed, scans, cleans, ops) = storageclean::stats();
            shell_println!("=== Storage Cleanup ===");
            shell_println!("Cached items:  {}", items);
            shell_println!("Total freed:   {}", storageclean::format_size(freed));
            shell_println!("Scans:         {}", scans);
            shell_println!("Cleanups:      {}", cleans);
            shell_println!("Ops:           {}", ops);
            if let Ok(cfg) = storageclean::config() {
                shell_println!("\nAuto-clean:    {}", if cfg.auto_enabled { "ON" } else { "off" });
                shell_println!("Threshold:     {}%", cfg.auto_clean_threshold_pct);
                shell_println!("Large file:    {}", storageclean::format_size(cfg.large_file_threshold));
                shell_println!("Old downloads: {} days", cfg.old_download_days);
                shell_println!("Log retention: {} days", cfg.log_retention_days);
            }
        }
        "scan" => {
            match storageclean::scan() {
                Ok(report) => {
                    shell_println!("Scan complete ({} us):", report.scan_duration_us);
                    shell_println!("  Total reclaimable: {}",
                        storageclean::format_size(report.total_reclaimable_bytes));
                    shell_println!("  Items: {}", report.total_items);
                    if !report.categories.is_empty() {
                        shell_println!("\nBreakdown:");
                        for cat in &report.categories {
                            shell_println!("  {:<20} {:>5} items  {}{}",
                                cat.category.label(), cat.item_count,
                                storageclean::format_size(cat.total_bytes),
                                if cat.recommended { " *" } else { "" });
                        }
                        shell_println!("\n* = recommended for cleanup");
                    }
                }
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "clean" => {
            let cat_name = parts.get(1).copied().unwrap_or("all");
            let cats = if cat_name == "all" {
                storageclean::CleanCategory::all().to_vec()
            } else if let Some(cat) = storageclean::parse_category(cat_name) {
                alloc::vec![cat]
            } else {
                shell_println!("Unknown category '{}'. Use: trash, temp, thumbs, logs, pkg, large, dl, dupes, all", cat_name);
                return;
            };
            match storageclean::clean(&cats) {
                Ok(result) => {
                    shell_println!("Cleaned {} items, freed {}",
                        result.items_cleaned, storageclean::format_size(result.freed_bytes));
                    if result.errors > 0 {
                        shell_println!("  {} errors", result.errors);
                    }
                    for (cat, freed) in &result.category_freed {
                        shell_println!("  {}: {}", cat.label(), storageclean::format_size(*freed));
                    }
                }
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "items" => {
            let cat_name = parts.get(1).copied().unwrap_or("");
            let items = if let Some(cat) = storageclean::parse_category(cat_name) {
                storageclean::items_for_category(cat)
            } else {
                storageclean::scan_items()
            };
            if items.is_empty() {
                shell_println!("No items. Run 'sclean scan' first.");
            } else {
                for item in items.iter().take(50) {
                    shell_println!("  [{:?}] {} ({})",
                        item.category, item.path,
                        storageclean::format_size(item.size_bytes));
                }
                if items.len() > 50 {
                    shell_println!("  ... and {} more", items.len() - 50);
                }
            }
        }
        "auto" => {
            let val = parts.get(1).copied().unwrap_or("");
            match val {
                "on" => {
                    let _ = storageclean::set_auto_enabled(true);
                    shell_println!("Auto-cleanup: ON");
                }
                "off" => {
                    let _ = storageclean::set_auto_enabled(false);
                    shell_println!("Auto-cleanup: OFF");
                }
                _ => shell_println!("Usage: sclean auto <on|off>"),
            }
        }
        "threshold" => {
            if let Some(pct) = parts.get(1).and_then(|s| s.parse::<u8>().ok()) {
                match storageclean::set_auto_threshold(pct) {
                    Ok(()) => shell_println!("Auto-clean threshold: {}%", pct),
                    Err(e) => shell_println!("Error: {:?}", e),
                }
            } else {
                shell_println!("Usage: sclean threshold <0-100>");
            }
        }
        "largefile" => {
            if let Some(size_str) = parts.get(1) {
                let bytes = parse_size_arg(size_str);
                if bytes > 0 {
                    let _ = storageclean::set_large_threshold(bytes);
                    shell_println!("Large file threshold: {}", storageclean::format_size(bytes));
                } else {
                    shell_println!("Invalid size. Use: 100M, 1G, etc.");
                }
            } else {
                shell_println!("Usage: sclean largefile <size>");
            }
        }
        "olddays" => {
            if let Some(days) = parts.get(1).and_then(|s| s.parse::<u32>().ok()) {
                let _ = storageclean::set_old_download_days(days);
                shell_println!("Old download threshold: {} days", days);
            } else {
                shell_println!("Usage: sclean olddays <days>");
            }
        }
        "logdays" => {
            if let Some(days) = parts.get(1).and_then(|s| s.parse::<u32>().ok()) {
                let _ = storageclean::set_log_retention(days);
                shell_println!("Log retention: {} days", days);
            } else {
                shell_println!("Usage: sclean logdays <days>");
            }
        }
        "exclude" => {
            let path = parts.get(1).copied().unwrap_or("");
            if path.is_empty() {
                let excl = storageclean::exclusions();
                if excl.is_empty() {
                    shell_println!("No exclusions.");
                } else {
                    for e in &excl {
                        shell_println!("  {}", e);
                    }
                }
            } else {
                let _ = storageclean::add_exclusion(path);
                shell_println!("Added exclusion: {}", path);
            }
        }
        "unexclude" => {
            let path = parts.get(1).copied().unwrap_or("");
            if path.is_empty() {
                shell_println!("Usage: sclean unexclude <path>");
            } else {
                match storageclean::remove_exclusion(path) {
                    Ok(()) => shell_println!("Removed exclusion: {}", path),
                    Err(e) => shell_println!("Error: {:?}", e),
                }
            }
        }
        "stats" => {
            let (items, freed, scans, cleans, ops) = storageclean::stats();
            shell_println!("items={} freed={} scans={} cleans={} ops={}",
                items, storageclean::format_size(freed), scans, cleans, ops);
        }
        "test" => {
            storageclean::self_test();
            shell_println!("Self-tests passed.");
        }
        _ => {
            shell_println!("storageclean / sclean — Storage cleanup & disk analysis");
            shell_println!("Subcommands:");
            shell_println!("  show           Show cleanup status and config");
            shell_println!("  scan           Scan for reclaimable space");
            shell_println!("  clean [cat]    Clean up (trash/temp/thumbs/logs/pkg/large/dl/all)");
            shell_println!("  items [cat]    Show scanned items");
            shell_println!("  auto <on|off>  Enable/disable automatic cleanup");
            shell_println!("  threshold <%%>  Set auto-clean disk usage threshold");
            shell_println!("  largefile <sz> Set large file threshold (e.g., 100M)");
            shell_println!("  olddays <n>    Set old download age threshold");
            shell_println!("  logdays <n>    Set log retention days");
            shell_println!("  exclude [path] Add exclusion / list exclusions");
            shell_println!("  unexclude <p>  Remove exclusion");
            shell_println!("  init           Initialize defaults");
            shell_println!("  stats          Show counters");
            shell_println!("  test           Run self-tests");
        }
    }
}

fn parse_size_arg(s: &str) -> u64 {
    let s = s.trim();
    if s.is_empty() {
        return 0;
    }
    let (num_part, suffix) = if s.ends_with('G') || s.ends_with('g') {
        (&s[..s.len()-1], 1024u64 * 1024 * 1024)
    } else if s.ends_with('M') || s.ends_with('m') {
        (&s[..s.len()-1], 1024u64 * 1024)
    } else if s.ends_with('K') || s.ends_with('k') {
        (&s[..s.len()-1], 1024u64)
    } else {
        (s, 1u64)
    };
    num_part.parse::<u64>().unwrap_or(0).saturating_mul(suffix)
}

/// `sysdiag` / `diag` — system diagnostics and troubleshooting.
fn cmd_sysdiag(args: &str) {
    use crate::fs::sysdiag;
    let parts: Vec<&str> = args.split_whitespace().collect();
    let sub = parts.first().copied().unwrap_or("");
    match sub {
        "show" | "" => {
            let issues = sysdiag::quick_check();
            if issues.is_empty() {
                shell_println!("System health: OK — no issues detected");
            } else {
                shell_println!("System health: {} issue(s)", issues.len());
                for issue in &issues {
                    let sev = issue.severity.label();
                    shell_println!("  [{}] {}: {}", sev, issue.category.label(), issue.title);
                    shell_println!("         {}", issue.detail);
                    shell_println!("    Fix: {}", issue.suggestion);
                }
            }
            let (_, total_runs, _, _, _) = sysdiag::stats();
            shell_println!("Total diagnostic runs: {}", total_runs);
        }
        "run" => {
            let cat_filter = parts.get(1).copied();
            if let Some(cname) = cat_filter {
                if let Some(cat) = parse_diag_category(cname) {
                    shell_println!("Running {} diagnostics...", cat.label());
                    match sysdiag::run_category(cat) {
                        Ok(report) => {
                            shell_println!("{}: {}/{} tests passed ({} us)",
                                report.category.label(),
                                report.tests_passed, report.tests_run,
                                report.duration_us);
                            for issue in &report.issues {
                                shell_println!("  [{}] {}", issue.severity.label(), issue.title);
                                shell_println!("         {}", issue.detail);
                                shell_println!("    Fix: {}", issue.suggestion);
                            }
                            if report.issues.is_empty() {
                                shell_println!("  All tests passed.");
                            }
                        }
                        Err(e) => shell_println!("Error: {:?}", e),
                    }
                } else {
                    shell_println!("Unknown category: {}", cname);
                    shell_println!("Categories: network, storage, memory, services, boot, security");
                }
            } else {
                shell_println!("Running full system diagnostics...");
                match sysdiag::run_all() {
                    Ok(report) => {
                        shell_println!("Results: {}/{} tests passed, {} issue(s) ({} us)",
                            report.total_passed, report.total_tests,
                            report.total_issues, report.duration_us);
                        shell_println!("Worst severity: {}", report.worst_severity.label());
                        shell_println!("");
                        for cat_report in &report.categories {
                            let status = if cat_report.issues.is_empty() { "OK" } else { "ISSUES" };
                            shell_println!("  {} [{}]: {}/{} passed",
                                cat_report.category.label(), status,
                                cat_report.tests_passed, cat_report.tests_run);
                            for issue in &cat_report.issues {
                                shell_println!("    [{}] {}", issue.severity.label(), issue.title);
                                shell_println!("           {}", issue.detail);
                                shell_println!("      Fix: {}", issue.suggestion);
                            }
                        }
                    }
                    Err(e) => shell_println!("Error: {:?}", e),
                }
            }
        }
        "issues" => {
            let filter_sev = parts.get(1).copied();
            let issues = if let Some(sev_str) = filter_sev {
                match sev_str {
                    "info" => sysdiag::issues_by_severity(sysdiag::Severity::Info),
                    "warning" | "warn" => sysdiag::issues_by_severity(sysdiag::Severity::Warning),
                    "error" | "err" => sysdiag::issues_by_severity(sysdiag::Severity::Error),
                    "critical" | "crit" => sysdiag::issues_by_severity(sysdiag::Severity::Critical),
                    _ => {
                        shell_println!("Unknown severity: {}", sev_str);
                        shell_println!("Severities: info, warning, error, critical");
                        return;
                    }
                }
            } else {
                sysdiag::current_issues()
            };
            if issues.is_empty() {
                shell_println!("No issues found. Run 'diag run' first.");
            } else {
                shell_println!("{} issue(s):", issues.len());
                for issue in &issues {
                    shell_println!("  #{} [{}] {}: {}",
                        issue.id, issue.severity.label(),
                        issue.category.label(), issue.title);
                    shell_println!("       {}", issue.detail);
                    shell_println!("  Fix: {}", issue.suggestion);
                }
            }
        }
        "category" | "cat" => {
            if let Some(cname) = parts.get(1).copied() {
                if let Some(cat) = parse_diag_category(cname) {
                    let issues = sysdiag::issues_for_category(cat);
                    if issues.is_empty() {
                        shell_println!("{}: no issues (run 'diag run {}' first)",
                            cat.label(), cname);
                    } else {
                        shell_println!("{}: {} issue(s)", cat.label(), issues.len());
                        for issue in &issues {
                            shell_println!("  [{}] {}", issue.severity.label(), issue.title);
                            shell_println!("       {}", issue.detail);
                            shell_println!("  Fix: {}", issue.suggestion);
                        }
                    }
                } else {
                    shell_println!("Unknown category: {}", cname);
                    shell_println!("Categories: network, storage, memory, services, boot, security");
                }
            } else {
                shell_println!("Usage: diag category <name>");
                shell_println!("Categories: network, storage, memory, services, boot, security");
            }
        }
        "history" | "hist" => {
            let hist = sysdiag::history();
            if hist.is_empty() {
                shell_println!("No diagnostic history. Run 'diag run' first.");
            } else {
                shell_println!("{} previous run(s):", hist.len());
                for (i, (ts, tests, passed, issues)) in hist.iter().enumerate() {
                    let status = if *issues == 0 { "OK" } else { "ISSUES" };
                    shell_println!("  #{}: ts={} tests={}/{} issues={} [{}]",
                        i + 1, ts, passed, tests, issues, status);
                }
            }
        }
        "stats" => {
            let (issue_count, total_runs, total_found, hist_count, ops) = sysdiag::stats();
            shell_println!("Current issues:      {}", issue_count);
            shell_println!("Total runs:          {}", total_runs);
            shell_println!("Total issues found:  {}", total_found);
            shell_println!("History entries:      {}", hist_count);
            shell_println!("Operations:          {}", ops);
        }
        "test" => {
            sysdiag::self_test();
            shell_println!("[sysdiag] All self-tests passed.");
        }
        "init" => {
            sysdiag::init_defaults();
            shell_println!("Diagnostics subsystem initialized.");
        }
        _ => {
            shell_println!("sysdiag — system diagnostics and troubleshooting");
            shell_println!("Usage: sysdiag|diag <subcommand>");
            shell_println!("");
            shell_println!("Subcommands:");
            shell_println!("  show               Show current health status (default)");
            shell_println!("  run [category]     Run full or category-specific diagnostics");
            shell_println!("  issues [severity]  List current issues, optionally filtered");
            shell_println!("  category <name>    Show issues for a specific category");
            shell_println!("  history            Show diagnostic run history");
            shell_println!("  stats              Show subsystem statistics");
            shell_println!("  init               Initialize diagnostics subsystem");
            shell_println!("  test               Run self-tests");
            shell_println!("");
            shell_println!("Categories: network, storage, memory, services, boot, security");
            shell_println!("Severities: info, warning, error, critical");
        }
    }
}

fn parse_diag_category(name: &str) -> Option<crate::fs::sysdiag::DiagCategory> {
    use crate::fs::sysdiag::DiagCategory;
    match name {
        "network" | "net" => Some(DiagCategory::Network),
        "storage" | "disk" => Some(DiagCategory::Storage),
        "memory" | "mem" => Some(DiagCategory::Memory),
        "services" | "svc" => Some(DiagCategory::Services),
        "boot" => Some(DiagCategory::Boot),
        "security" | "sec" => Some(DiagCategory::Security),
        _ => None,
    }
}

/// `nightlight` / `nlight` — blue light filter / night mode.
fn cmd_nightlight(args: &str) {
    use crate::fs::nightlight;
    let parts: Vec<&str> = args.split_whitespace().collect();
    let sub = parts.first().copied().unwrap_or("");
    match sub {
        "show" | "" => {
            let (enabled, temp, toggle_count, check_count, _) = nightlight::stats();
            let state = nightlight::current_state();
            shell_println!("Night Light: {} ({})", if enabled { "ON" } else { "OFF" }, state.label());
            shell_println!("  Temperature: {}", nightlight::format_temp(temp));
            if let Ok(cfg) = nightlight::config() {
                shell_println!("  Night temp:  {}K", cfg.night_temp);
                shell_println!("  Day temp:    {}K", cfg.day_temp);
                shell_println!("  Schedule:    {}", cfg.schedule_mode.label());
                shell_println!("  Start time:  {:02}:{:02}", cfg.start_time.hour, cfg.start_time.minute);
                shell_println!("  End time:    {:02}:{:02}", cfg.end_time.hour, cfg.end_time.minute);
                shell_println!("  Transition:  {} min", cfg.transition_minutes);
                if let Some(loc) = &cfg.location {
                    shell_println!("  Location:    lat={}, lon={}", loc.latitude, loc.longitude);
                }
                shell_println!("  On battery:  {}", if cfg.disable_on_battery { "disable" } else { "keep" });
                if cfg.manual_override {
                    shell_println!("  Override:    ACTIVE");
                }
            }
            shell_println!("  Toggles:     {}", toggle_count);
            shell_println!("  Checks:      {}", check_count);
        }
        "on" => match nightlight::set_enabled(true) {
            Ok(()) => shell_println!("Night light enabled."),
            Err(e) => shell_println!("Error: {:?}", e),
        },
        "off" => match nightlight::set_enabled(false) {
            Ok(()) => shell_println!("Night light disabled."),
            Err(e) => shell_println!("Error: {:?}", e),
        },
        "toggle" => match nightlight::toggle() {
            Ok(on) => shell_println!("Night light {}.", if on { "enabled" } else { "disabled" }),
            Err(e) => shell_println!("Error: {:?}", e),
        },
        "temp" => {
            if let Some(val) = parts.get(1) {
                if let Ok(t) = val.parse::<u32>() {
                    match nightlight::set_night_temp(t) {
                        Ok(()) => shell_println!("Night temperature set to {}", nightlight::format_temp(t)),
                        Err(e) => shell_println!("Error: {:?} (range: 1000-6500)", e),
                    }
                } else {
                    shell_println!("Invalid temperature: {}", val);
                }
            } else {
                shell_println!("Usage: nlight temp <kelvin>");
                shell_println!("Range: 1000 (very warm) to 6500 (neutral)");
                shell_println!("Common: 3000=warm  4000=soft  4500=default  5500=cool");
            }
        }
        "daytemp" => {
            if let Some(val) = parts.get(1) {
                if let Ok(t) = val.parse::<u32>() {
                    match nightlight::set_day_temp(t) {
                        Ok(()) => shell_println!("Day temperature set to {}K", t),
                        Err(e) => shell_println!("Error: {:?}", e),
                    }
                } else {
                    shell_println!("Invalid temperature: {}", val);
                }
            } else {
                shell_println!("Usage: nlight daytemp <kelvin>");
            }
        }
        "schedule" => {
            if let Some(mode) = parts.get(1) {
                match *mode {
                    "manual" => {
                        match nightlight::set_schedule_mode(nightlight::ScheduleMode::Manual) {
                            Ok(()) => shell_println!("Schedule mode: Manual"),
                            Err(e) => shell_println!("Error: {:?}", e),
                        }
                    }
                    "scheduled" | "fixed" => {
                        match nightlight::set_schedule_mode(nightlight::ScheduleMode::Scheduled) {
                            Ok(()) => shell_println!("Schedule mode: Scheduled"),
                            Err(e) => shell_println!("Error: {:?}", e),
                        }
                    }
                    "sunset" | "sun" | "auto" => {
                        match nightlight::set_schedule_mode(nightlight::ScheduleMode::SunsetSunrise) {
                            Ok(()) => shell_println!("Schedule mode: Sunset/Sunrise"),
                            Err(e) => shell_println!("Error: {:?}", e),
                        }
                    }
                    _ => {
                        shell_println!("Unknown mode: {}. Options: manual, scheduled, sunset", mode);
                    }
                }
            } else {
                shell_println!("Usage: nlight schedule <manual|scheduled|sunset>");
            }
        }
        "start" => {
            if let Some(time_str) = parts.get(1) {
                if let Some((h, m)) = parse_time_hhmm(time_str) {
                    match nightlight::set_start_time(h, m) {
                        Ok(()) => shell_println!("Start time set to {:02}:{:02}", h, m),
                        Err(e) => shell_println!("Error: {:?}", e),
                    }
                } else {
                    shell_println!("Invalid time. Use HH:MM format (e.g., 21:00)");
                }
            } else {
                shell_println!("Usage: nlight start <HH:MM>");
            }
        }
        "end" => {
            if let Some(time_str) = parts.get(1) {
                if let Some((h, m)) = parse_time_hhmm(time_str) {
                    match nightlight::set_end_time(h, m) {
                        Ok(()) => shell_println!("End time set to {:02}:{:02}", h, m),
                        Err(e) => shell_println!("Error: {:?}", e),
                    }
                } else {
                    shell_println!("Invalid time. Use HH:MM format (e.g., 07:00)");
                }
            } else {
                shell_println!("Usage: nlight end <HH:MM>");
            }
        }
        "location" | "loc" => {
            if let (Some(lat_str), Some(lon_str)) = (parts.get(1), parts.get(2)) {
                if let (Ok(lat), Ok(lon)) = (lat_str.parse::<i32>(), lon_str.parse::<i32>()) {
                    match nightlight::set_location(lat, lon) {
                        Ok(()) => shell_println!("Location set to lat={}, lon={}", lat, lon),
                        Err(e) => shell_println!("Error: {:?}", e),
                    }
                } else {
                    shell_println!("Invalid coordinates.");
                }
            } else {
                shell_println!("Usage: nlight location <latitude> <longitude>");
                shell_println!("Example: nlight location 40 -74  (New York)");
            }
        }
        "transition" => {
            if let Some(val) = parts.get(1) {
                if let Ok(mins) = val.parse::<u32>() {
                    match nightlight::set_transition_minutes(mins) {
                        Ok(()) => shell_println!("Transition duration set to {} minutes", mins),
                        Err(e) => shell_println!("Error: {:?} (max 120)", e),
                    }
                } else {
                    shell_println!("Invalid value: {}", val);
                }
            } else {
                shell_println!("Usage: nlight transition <minutes>");
            }
        }
        "battery" => {
            if let Some(val) = parts.get(1) {
                let disable = match *val {
                    "on" | "true" | "yes" | "disable" => true,
                    "off" | "false" | "no" | "keep" => false,
                    _ => {
                        shell_println!("Usage: nlight battery <on|off>");
                        return;
                    }
                };
                match nightlight::set_disable_on_battery(disable) {
                    Ok(()) => shell_println!("Disable on battery: {}", if disable { "yes" } else { "no" }),
                    Err(e) => shell_println!("Error: {:?}", e),
                }
            } else {
                shell_println!("Usage: nlight battery <on|off>");
            }
        }
        "override" => {
            let active = parts.get(1).copied().unwrap_or("on");
            let active = matches!(active, "on" | "true" | "yes");
            match nightlight::set_manual_override(active) {
                Ok(()) => shell_println!("Manual override: {}", if active { "ON" } else { "OFF" }),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "check" => {
            if let (Some(h_str), Some(m_str)) = (parts.get(1), parts.get(2)) {
                if let (Ok(h), Ok(m)) = (h_str.parse::<u8>(), m_str.parse::<u8>()) {
                    let temp = nightlight::check_schedule(h, m);
                    shell_println!("At {:02}:{:02}: {} ({})", h, m,
                        nightlight::format_temp(temp),
                        nightlight::current_state().label());
                } else {
                    shell_println!("Invalid time.");
                }
            } else {
                shell_println!("Usage: nlight check <hour> <minute>");
            }
        }
        "rgb" => {
            let temp = if let Some(val) = parts.get(1) {
                val.parse::<u32>().unwrap_or(6500)
            } else {
                nightlight::current_temperature()
            };
            shell_println!("{}", nightlight::format_temp(temp));
        }
        "stats" => {
            let (enabled, temp, toggles, checks, ops) = nightlight::stats();
            shell_println!("Enabled:      {}", enabled);
            shell_println!("Temperature:  {}K", temp);
            shell_println!("Toggles:      {}", toggles);
            shell_println!("Checks:       {}", checks);
            shell_println!("Operations:   {}", ops);
        }
        "test" => {
            nightlight::self_test();
            shell_println!("[nightlight] All self-tests passed.");
        }
        "init" => {
            nightlight::init_defaults();
            shell_println!("Night light subsystem initialized.");
        }
        _ => {
            shell_println!("nightlight — blue light filter / night mode");
            shell_println!("Usage: nightlight|nlight <subcommand>");
            shell_println!("");
            shell_println!("Subcommands:");
            shell_println!("  show               Show current status (default)");
            shell_println!("  on / off / toggle   Enable/disable/toggle");
            shell_println!("  temp <kelvin>      Set night temperature (1000-6500)");
            shell_println!("  daytemp <kelvin>   Set day temperature");
            shell_println!("  schedule <mode>    Set schedule: manual|scheduled|sunset");
            shell_println!("  start <HH:MM>      Set scheduled start time");
            shell_println!("  end <HH:MM>        Set scheduled end time");
            shell_println!("  location <lat> <lon> Set location for sunset/sunrise");
            shell_println!("  transition <min>   Set transition duration (0-120 min)");
            shell_println!("  battery <on|off>   Disable on battery power");
            shell_println!("  override [on|off]  Temporary schedule override");
            shell_println!("  check <H> <M>      Simulate schedule check at time");
            shell_println!("  rgb [kelvin]       Show RGB values for temperature");
            shell_println!("  stats              Show subsystem statistics");
            shell_println!("  init               Initialize subsystem");
            shell_println!("  test               Run self-tests");
        }
    }
}

/// Parse "HH:MM" time string into (hour, minute).
fn parse_time_hhmm(s: &str) -> Option<(u8, u8)> {
    let mut parts = s.split(':');
    let h_str = parts.next()?;
    let m_str = parts.next()?;
    let h = h_str.parse::<u8>().ok()?;
    let m = m_str.parse::<u8>().ok()?;
    if h > 23 || m > 59 {
        return None;
    }
    Some((h, m))
}

/// `tasksched` / `schtask` — scheduled task management.
fn cmd_tasksched(args: &str) {
    use crate::fs::tasksched;
    let parts: Vec<&str> = args.split_whitespace().collect();
    let sub = parts.first().copied().unwrap_or("");
    match sub {
        "show" | "" | "list" => {
            let tasks = tasksched::list_tasks();
            if tasks.is_empty() {
                shell_println!("No scheduled tasks.");
            } else {
                shell_println!("{} scheduled task(s):", tasks.len());
                for t in &tasks {
                    let sys = if t.system { " [system]" } else { "" };
                    shell_println!("  #{} {} [{}] {:02}:{:02} — {} {}{}",
                        t.id, t.name, t.schedule_type.label(),
                        t.hour, t.minute, t.status.label(),
                        t.command, sys);
                    if !t.arguments.is_empty() {
                        shell_println!("       args: {}", t.arguments);
                    }
                    if t.run_count > 0 {
                        shell_println!("       runs: {}, last: {}",
                            t.run_count,
                            if t.last_success { "OK" } else { "FAILED" });
                    }
                }
            }
        }
        "info" | "get" => {
            if let Some(id_str) = parts.get(1) {
                if let Ok(id) = id_str.parse::<u64>() {
                    match tasksched::get_task(id) {
                        Ok(t) => {
                            shell_println!("Task #{}: {}", t.id, t.name);
                            shell_println!("  Command:     {} {}", t.command, t.arguments);
                            shell_println!("  Schedule:    {}", t.schedule_type.label());
                            shell_println!("  Time:        {:02}:{:02}", t.hour, t.minute);
                            if t.schedule_type == tasksched::ScheduleType::Weekly {
                                let days: Vec<&str> = ["Sun","Mon","Tue","Wed","Thu","Fri","Sat"]
                                    .iter().enumerate()
                                    .filter(|(i, _)| t.weekdays[*i])
                                    .map(|(_, d)| *d)
                                    .collect();
                                shell_println!("  Days:        {}", days.join(", "));
                            }
                            if t.schedule_type == tasksched::ScheduleType::Interval {
                                shell_println!("  Interval:    {} min", t.interval_minutes);
                            }
                            shell_println!("  Priority:    {}", t.priority.label());
                            shell_println!("  Status:      {}", t.status.label());
                            shell_println!("  System:      {}", t.system);
                            shell_println!("  Runs:        {}", t.run_count);
                            if t.run_count > 0 {
                                shell_println!("  Last run:    {} ({})",
                                    if t.last_success { "OK" } else { "FAILED" },
                                    t.last_duration_us);
                            }
                            if !t.description.is_empty() {
                                shell_println!("  Description: {}", t.description);
                            }
                        }
                        Err(e) => shell_println!("Error: {:?}", e),
                    }
                } else {
                    shell_println!("Invalid task ID: {}", id_str);
                }
            } else {
                shell_println!("Usage: schtask info <id>");
            }
        }
        "create" | "add" => {
            // schtask create <name> <command> [daily|weekly|once|interval|boot|login]
            if let (Some(name), Some(cmd)) = (parts.get(1), parts.get(2)) {
                let sched_type = match parts.get(3).copied().unwrap_or("daily") {
                    "daily" => tasksched::ScheduleType::Daily,
                    "weekly" => tasksched::ScheduleType::Weekly,
                    "once" => tasksched::ScheduleType::Once,
                    "interval" => tasksched::ScheduleType::Interval,
                    "boot" => tasksched::ScheduleType::Boot,
                    "login" => tasksched::ScheduleType::Login,
                    other => {
                        shell_println!("Unknown schedule type: {}", other);
                        return;
                    }
                };
                match tasksched::create_task(name, cmd, sched_type) {
                    Ok(id) => shell_println!("Created task #{}", id),
                    Err(e) => shell_println!("Error: {:?}", e),
                }
            } else {
                shell_println!("Usage: schtask create <name> <command> [daily|weekly|once|interval|boot|login]");
            }
        }
        "remove" | "rm" => {
            if let Some(id_str) = parts.get(1) {
                if let Ok(id) = id_str.parse::<u64>() {
                    match tasksched::remove_task(id) {
                        Ok(()) => shell_println!("Task #{} removed.", id),
                        Err(e) => shell_println!("Error: {:?}", e),
                    }
                } else {
                    shell_println!("Invalid task ID.");
                }
            } else {
                shell_println!("Usage: schtask remove <id>");
            }
        }
        "time" => {
            if let (Some(id_str), Some(time_str)) = (parts.get(1), parts.get(2)) {
                if let Ok(id) = id_str.parse::<u64>() {
                    if let Some((h, m)) = parse_time_hhmm(time_str) {
                        match tasksched::set_time(id, h, m) {
                            Ok(()) => shell_println!("Task #{} time set to {:02}:{:02}", id, h, m),
                            Err(e) => shell_println!("Error: {:?}", e),
                        }
                    } else {
                        shell_println!("Invalid time format. Use HH:MM");
                    }
                } else {
                    shell_println!("Invalid task ID.");
                }
            } else {
                shell_println!("Usage: schtask time <id> <HH:MM>");
            }
        }
        "day" => {
            if let (Some(id_str), Some(day_str), Some(val)) =
                (parts.get(1), parts.get(2), parts.get(3))
            {
                if let Ok(id) = id_str.parse::<u64>() {
                    let day_num = match *day_str {
                        "sun" | "0" => Some(0usize),
                        "mon" | "1" => Some(1),
                        "tue" | "2" => Some(2),
                        "wed" | "3" => Some(3),
                        "thu" | "4" => Some(4),
                        "fri" | "5" => Some(5),
                        "sat" | "6" => Some(6),
                        _ => None,
                    };
                    if let Some(d) = day_num {
                        let enabled = matches!(*val, "on" | "true" | "yes" | "1");
                        match tasksched::set_weekday(id, d, enabled) {
                            Ok(()) => shell_println!("Task #{} weekday {} = {}", id, day_str, enabled),
                            Err(e) => shell_println!("Error: {:?}", e),
                        }
                    } else {
                        shell_println!("Unknown day: {}. Use sun/mon/tue/wed/thu/fri/sat", day_str);
                    }
                } else {
                    shell_println!("Invalid task ID.");
                }
            } else {
                shell_println!("Usage: schtask day <id> <sun|mon|tue|wed|thu|fri|sat> <on|off>");
            }
        }
        "interval" => {
            if let (Some(id_str), Some(min_str)) = (parts.get(1), parts.get(2)) {
                if let (Ok(id), Ok(mins)) = (id_str.parse::<u64>(), min_str.parse::<u32>()) {
                    match tasksched::set_interval(id, mins) {
                        Ok(()) => shell_println!("Task #{} interval set to {} min", id, mins),
                        Err(e) => shell_println!("Error: {:?}", e),
                    }
                } else {
                    shell_println!("Invalid arguments.");
                }
            } else {
                shell_println!("Usage: schtask interval <id> <minutes>");
            }
        }
        "args" => {
            if let Some(id_str) = parts.get(1) {
                if let Ok(id) = id_str.parse::<u64>() {
                    let task_args = parts.get(2..).map(|p| p.join(" ")).unwrap_or_default();
                    match tasksched::set_arguments(id, &task_args) {
                        Ok(()) => shell_println!("Task #{} arguments set.", id),
                        Err(e) => shell_println!("Error: {:?}", e),
                    }
                } else {
                    shell_println!("Invalid task ID.");
                }
            } else {
                shell_println!("Usage: schtask args <id> <arguments...>");
            }
        }
        "desc" => {
            if let Some(id_str) = parts.get(1) {
                if let Ok(id) = id_str.parse::<u64>() {
                    let desc = parts.get(2..).map(|p| p.join(" ")).unwrap_or_default();
                    match tasksched::set_description(id, &desc) {
                        Ok(()) => shell_println!("Task #{} description set.", id),
                        Err(e) => shell_println!("Error: {:?}", e),
                    }
                } else {
                    shell_println!("Invalid task ID.");
                }
            } else {
                shell_println!("Usage: schtask desc <id> <description...>");
            }
        }
        "enable" => {
            if let Some(id_str) = parts.get(1) {
                if let Ok(id) = id_str.parse::<u64>() {
                    match tasksched::enable_task(id) {
                        Ok(()) => shell_println!("Task #{} enabled.", id),
                        Err(e) => shell_println!("Error: {:?}", e),
                    }
                } else {
                    shell_println!("Invalid task ID.");
                }
            } else {
                shell_println!("Usage: schtask enable <id>");
            }
        }
        "disable" => {
            if let Some(id_str) = parts.get(1) {
                if let Ok(id) = id_str.parse::<u64>() {
                    match tasksched::disable_task(id) {
                        Ok(()) => shell_println!("Task #{} disabled.", id),
                        Err(e) => shell_println!("Error: {:?}", e),
                    }
                } else {
                    shell_println!("Invalid task ID.");
                }
            } else {
                shell_println!("Usage: schtask disable <id>");
            }
        }
        "due" => {
            if let (Some(h_str), Some(m_str)) = (parts.get(1), parts.get(2)) {
                if let (Ok(h), Ok(m)) = (h_str.parse::<u8>(), m_str.parse::<u8>()) {
                    let wd = parts.get(3).and_then(|d| d.parse::<u8>().ok()).unwrap_or(0);
                    let due = tasksched::check_due(h, m, wd);
                    if due.is_empty() {
                        shell_println!("No tasks due at {:02}:{:02}", h, m);
                    } else {
                        shell_println!("{} task(s) due:", due.len());
                        for id in &due {
                            if let Ok(t) = tasksched::get_task(*id) {
                                shell_println!("  #{} {}", id, t.name);
                            }
                        }
                    }
                } else {
                    shell_println!("Invalid time.");
                }
            } else {
                shell_println!("Usage: schtask due <hour> <minute> [weekday 0-6]");
            }
        }
        "run" => {
            if let Some(id_str) = parts.get(1) {
                if let Ok(id) = id_str.parse::<u64>() {
                    match tasksched::record_start(id) {
                        Ok(()) => {
                            shell_println!("Task #{} started.", id);
                            // Simulate immediate completion.
                            let _ = tasksched::record_complete(id, true, 0);
                            shell_println!("Task #{} completed.", id);
                        }
                        Err(e) => shell_println!("Error: {:?}", e),
                    }
                } else {
                    shell_println!("Invalid task ID.");
                }
            } else {
                shell_println!("Usage: schtask run <id>");
            }
        }
        "history" | "hist" => {
            let id_filter = parts.get(1).and_then(|s| s.parse::<u64>().ok());
            let history = if let Some(id) = id_filter {
                tasksched::task_history(id)
            } else {
                tasksched::all_history()
            };
            if history.is_empty() {
                shell_println!("No execution history.");
            } else {
                shell_println!("{} execution(s):", history.len());
                for h in history.iter().rev().take(20) {
                    let status = if h.success { "OK" } else { "FAIL" };
                    shell_println!("  #{} {} [{}] exit={} duration={}us",
                        h.task_id, h.task_name, status, h.exit_code, h.duration_us);
                }
            }
        }
        "next" => {
            if let Some((id, name, h, m)) = tasksched::next_due() {
                shell_println!("Next due: #{} {} at {:02}:{:02}", id, name, h, m);
            } else {
                shell_println!("No tasks scheduled.");
            }
        }
        "stats" => {
            let (count, runs, failures, hist, ops) = tasksched::stats();
            shell_println!("Tasks:       {}", count);
            shell_println!("Total runs:  {}", runs);
            shell_println!("Failures:    {}", failures);
            shell_println!("History:     {}", hist);
            shell_println!("Operations:  {}", ops);
        }
        "test" => {
            tasksched::self_test();
            shell_println!("[tasksched] All self-tests passed.");
        }
        "init" => {
            tasksched::init_defaults();
            shell_println!("Task scheduler initialized.");
        }
        _ => {
            shell_println!("tasksched — scheduled task management");
            shell_println!("Usage: tasksched|schtask <subcommand>");
            shell_println!("");
            shell_println!("Subcommands:");
            shell_println!("  list               List all tasks (default)");
            shell_println!("  info <id>          Show task details");
            shell_println!("  create <n> <cmd> [type]  Create task (daily/weekly/once/interval/boot/login)");
            shell_println!("  remove <id>        Remove a task");
            shell_println!("  time <id> <HH:MM>  Set task run time");
            shell_println!("  day <id> <d> <on|off>  Set weekday (sun-sat)");
            shell_println!("  interval <id> <min>  Set interval minutes");
            shell_println!("  args <id> <args>   Set task arguments");
            shell_println!("  desc <id> <text>   Set description");
            shell_println!("  enable/disable <id>  Enable/disable task");
            shell_println!("  due <H> <M> [wd]   Check due tasks at time");
            shell_println!("  run <id>           Run a task now");
            shell_println!("  history [id]       Show execution history");
            shell_println!("  next               Show next due task");
            shell_println!("  stats              Show statistics");
            shell_println!("  init               Initialize scheduler");
            shell_println!("  test               Run self-tests");
        }
    }
}

/// `envvars` / `envmgr` — environment variable management.
fn cmd_envvars(args: &str) {
    use crate::fs::envvars;
    use alloc::format;
    let parts: Vec<&str> = args.split_whitespace().collect();
    let sub = parts.first().copied().unwrap_or("");
    match sub {
        "show" | "" | "list" => {
            let sys = envvars::list_system();
            shell_println!("System variables ({}):", sys.len());
            for v in &sys {
                let ro = if v.read_only { " [ro]" } else { "" };
                let desc = if v.description.is_empty() {
                    String::new()
                } else {
                    format!("  # {}", v.description)
                };
                shell_println!("  {}={}{}{}", v.name, v.value, ro, desc);
            }
        }
        "get" => {
            if let Some(name) = parts.get(1) {
                match envvars::get_system(name) {
                    Ok(val) => shell_println!("{}={}", name, val),
                    Err(_) => shell_println!("{}: not set", name),
                }
            } else {
                shell_println!("Usage: envvars get <NAME>");
            }
        }
        "set" => {
            if let (Some(name), Some(_value)) = (parts.get(1), parts.get(2)) {
                let full_value = parts.get(2..).map(|p| p.join(" ")).unwrap_or_default();
                match envvars::set_system(name, &full_value) {
                    Ok(()) => shell_println!("{}={}", name, full_value),
                    Err(e) => shell_println!("Error: {:?}", e),
                }
            } else {
                shell_println!("Usage: envvars set <NAME> <value...>");
            }
        }
        "rm" | "unset" => {
            if let Some(name) = parts.get(1) {
                match envvars::remove_system(name) {
                    Ok(()) => shell_println!("{} removed.", name),
                    Err(e) => shell_println!("Error: {:?}", e),
                }
            } else {
                shell_println!("Usage: envvars rm <NAME>");
            }
        }
        "user" => {
            // envvars user <uid> [set <NAME> <val> | get <NAME> | list | rm <NAME>]
            if let Some(uid_str) = parts.get(1) {
                if let Ok(uid) = uid_str.parse::<u32>() {
                    let ucmd = parts.get(2).copied().unwrap_or("list");
                    match ucmd {
                        "list" | "" => {
                            let vars = envvars::list_user(uid);
                            if vars.is_empty() {
                                shell_println!("No user variables for uid {}.", uid);
                            } else {
                                shell_println!("User {} variables ({}):", uid, vars.len());
                                for v in &vars {
                                    shell_println!("  {}={}", v.name, v.value);
                                }
                            }
                        }
                        "set" => {
                            if let (Some(name), Some(_)) = (parts.get(3), parts.get(4)) {
                                let val = parts.get(4..).map(|p| p.join(" ")).unwrap_or_default();
                                match envvars::set_user(uid, name, &val) {
                                    Ok(()) => shell_println!("[uid {}] {}={}", uid, name, val),
                                    Err(e) => shell_println!("Error: {:?}", e),
                                }
                            } else {
                                shell_println!("Usage: envvars user <uid> set <NAME> <value>");
                            }
                        }
                        "get" => {
                            if let Some(name) = parts.get(3) {
                                match envvars::get_user(uid, name) {
                                    Ok(val) => shell_println!("[uid {}] {}={}", uid, name, val),
                                    Err(_) => shell_println!("{}: not set for uid {}", name, uid),
                                }
                            } else {
                                shell_println!("Usage: envvars user <uid> get <NAME>");
                            }
                        }
                        "rm" => {
                            if let Some(name) = parts.get(3) {
                                match envvars::remove_user(uid, name) {
                                    Ok(()) => shell_println!("[uid {}] {} removed.", uid, name),
                                    Err(e) => shell_println!("Error: {:?}", e),
                                }
                            } else {
                                shell_println!("Usage: envvars user <uid> rm <NAME>");
                            }
                        }
                        _ => {
                            shell_println!("Usage: envvars user <uid> <list|set|get|rm>");
                        }
                    }
                } else {
                    shell_println!("Invalid UID: {}", uid_str);
                }
            } else {
                shell_println!("Usage: envvars user <uid> <command>");
            }
        }
        "resolve" => {
            let uid = parts.get(1).and_then(|s| s.parse::<u32>().ok()).unwrap_or(0);
            let env = envvars::resolve_env(uid);
            shell_println!("Resolved environment for uid {} ({} vars):", uid, env.vars.len());
            for (name, val) in &env.vars {
                shell_println!("  {}={}", name, val);
            }
        }
        "expand" => {
            let uid = parts.get(1).and_then(|s| s.parse::<u32>().ok()).unwrap_or(0);
            let input = parts.get(2..).map(|p| p.join(" ")).unwrap_or_default();
            if input.is_empty() {
                shell_println!("Usage: envvars expand <uid> <string with $VAR>");
            } else {
                let result = envvars::expand(uid, &input);
                shell_println!("{}", result);
            }
        }
        "path" => {
            let pcmd = parts.get(1).copied().unwrap_or("list");
            match pcmd {
                "list" | "" => {
                    let dirs = envvars::path_list();
                    shell_println!("PATH ({} entries):", dirs.len());
                    for (i, d) in dirs.iter().enumerate() {
                        shell_println!("  {}: {}", i + 1, d);
                    }
                }
                "append" => {
                    if let Some(dir) = parts.get(2) {
                        match envvars::path_append(dir) {
                            Ok(()) => shell_println!("Appended {} to PATH", dir),
                            Err(e) => shell_println!("Error: {:?}", e),
                        }
                    } else {
                        shell_println!("Usage: envvars path append <dir>");
                    }
                }
                "prepend" => {
                    if let Some(dir) = parts.get(2) {
                        match envvars::path_prepend(dir) {
                            Ok(()) => shell_println!("Prepended {} to PATH", dir),
                            Err(e) => shell_println!("Error: {:?}", e),
                        }
                    } else {
                        shell_println!("Usage: envvars path prepend <dir>");
                    }
                }
                "rm" => {
                    if let Some(dir) = parts.get(2) {
                        match envvars::path_remove(dir) {
                            Ok(()) => shell_println!("Removed {} from PATH", dir),
                            Err(e) => shell_println!("Error: {:?}", e),
                        }
                    } else {
                        shell_println!("Usage: envvars path rm <dir>");
                    }
                }
                _ => {
                    shell_println!("Usage: envvars path <list|append|prepend|rm>");
                }
            }
        }
        "search" => {
            if let Some(query) = parts.get(1) {
                let results = envvars::search(query);
                if results.is_empty() {
                    shell_println!("No variables matching '{}'.", query);
                } else {
                    shell_println!("{} match(es):", results.len());
                    for v in &results {
                        shell_println!("  [{}] {}={}", v.scope.label(), v.name, v.value);
                    }
                }
            } else {
                shell_println!("Usage: envvars search <query>");
            }
        }
        "stats" => {
            let (sys, users, total_uv, ops) = envvars::stats();
            shell_println!("System vars:    {}", sys);
            shell_println!("Users:          {}", users);
            shell_println!("Total user vars: {}", total_uv);
            shell_println!("Operations:     {}", ops);
        }
        "test" => {
            envvars::self_test();
            shell_println!("[envvars] All self-tests passed.");
        }
        "init" => {
            envvars::init_defaults();
            shell_println!("Environment variables initialized.");
        }
        _ => {
            shell_println!("envvars — environment variable management");
            shell_println!("Usage: envvars|envmgr <subcommand>");
            shell_println!("");
            shell_println!("Subcommands:");
            shell_println!("  list               List system variables (default)");
            shell_println!("  get <NAME>         Get a system variable");
            shell_println!("  set <NAME> <val>   Set a system variable");
            shell_println!("  rm <NAME>          Remove a system variable");
            shell_println!("  user <uid> <cmd>   Manage per-user variables");
            shell_println!("    list/set/get/rm   User variable commands");
            shell_println!("  resolve [uid]      Show resolved env for user");
            shell_println!("  expand <uid> <str> Expand $VAR references");
            shell_println!("  path <cmd>         PATH management (list/append/prepend/rm)");
            shell_println!("  search <query>     Search variables");
            shell_println!("  stats              Show statistics");
            shell_println!("  init               Initialize subsystem");
            shell_println!("  test               Run self-tests");
        }
    }
}

/// `bluetooth` / `bt` — Bluetooth device management.
fn cmd_bluetooth(args: &str) {
    use crate::fs::bluetooth;
    use alloc::format;
    let parts: Vec<&str> = args.split_whitespace().collect();
    let sub = parts.first().copied().unwrap_or("");
    match sub {
        "show" | "" => {
            let enabled = bluetooth::is_enabled();
            shell_println!("Bluetooth: {}", if enabled { "ON" } else { "OFF" });
            if let Ok(cfg) = bluetooth::config() {
                shell_println!("  Adapter:       {} [{}]", cfg.adapter_name, cfg.adapter_state.label());
                shell_println!("  Version:       BT {}", cfg.bt_version);
                shell_println!("  Discoverable:  {}", cfg.discoverable);
                shell_println!("  Auto-connect:  {}", cfg.auto_connect);
            }
            let devices = bluetooth::list_devices();
            if devices.is_empty() {
                shell_println!("  No paired devices.");
            } else {
                shell_println!("  Paired devices ({}):", devices.len());
                for dev in &devices {
                    let conn = if dev.state == bluetooth::ConnectionState::Connected { " *" } else { "" };
                    let bat = dev.battery_pct.map_or(String::new(), |b| format!(" ({}%)", b));
                    shell_println!("    {} {} [{}]{}{}", dev.address, dev.name,
                        dev.device_type.label(), conn, bat);
                }
            }
        }
        "on" => match bluetooth::set_enabled(true) {
            Ok(()) => shell_println!("Bluetooth enabled."),
            Err(e) => shell_println!("Error: {:?}", e),
        },
        "off" => match bluetooth::set_enabled(false) {
            Ok(()) => shell_println!("Bluetooth disabled."),
            Err(e) => shell_println!("Error: {:?}", e),
        },
        "scan" => match bluetooth::scan() {
            Ok(results) => {
                if results.is_empty() {
                    shell_println!("No devices found.");
                } else {
                    shell_println!("{} device(s) found:", results.len());
                    for r in &results {
                        let paired = if r.paired { " [paired]" } else { "" };
                        shell_println!("  {} {} [{}] RSSI: {}dBm{}",
                            r.address, r.name, r.device_type.label(), r.rssi, paired);
                    }
                }
            }
            Err(e) => shell_println!("Error: {:?} (is Bluetooth enabled?)", e),
        },
        "pair" => {
            // bt pair <address> <name> [type]
            if let (Some(addr), Some(name)) = (parts.get(1), parts.get(2)) {
                let dt = match parts.get(3).copied().unwrap_or("other") {
                    "headphones" | "hp" => bluetooth::DeviceType::AudioHeadphones,
                    "speaker" | "spk" => bluetooth::DeviceType::AudioSpeaker,
                    "headset" | "hs" => bluetooth::DeviceType::AudioHeadset,
                    "keyboard" | "kb" => bluetooth::DeviceType::Keyboard,
                    "mouse" => bluetooth::DeviceType::Mouse,
                    "gamepad" | "gp" => bluetooth::DeviceType::Gamepad,
                    "phone" => bluetooth::DeviceType::Phone,
                    "computer" | "pc" => bluetooth::DeviceType::Computer,
                    "printer" => bluetooth::DeviceType::Printer,
                    _ => bluetooth::DeviceType::Other,
                };
                match bluetooth::pair(addr, name, dt) {
                    Ok(()) => shell_println!("Paired with {} ({})", name, addr),
                    Err(e) => shell_println!("Error: {:?}", e),
                }
            } else {
                shell_println!("Usage: bt pair <address> <name> [type]");
                shell_println!("Types: headphones, speaker, headset, keyboard, mouse, gamepad, phone, computer, printer, other");
            }
        }
        "unpair" | "remove" => {
            if let Some(addr) = parts.get(1) {
                match bluetooth::unpair(addr) {
                    Ok(()) => shell_println!("Unpaired {}.", addr),
                    Err(e) => shell_println!("Error: {:?}", e),
                }
            } else {
                shell_println!("Usage: bt unpair <address>");
            }
        }
        "connect" | "conn" => {
            if let Some(addr) = parts.get(1) {
                match bluetooth::connect(addr) {
                    Ok(()) => shell_println!("Connected to {}.", addr),
                    Err(e) => shell_println!("Error: {:?}", e),
                }
            } else {
                shell_println!("Usage: bt connect <address>");
            }
        }
        "disconnect" | "disc" => {
            if let Some(addr) = parts.get(1) {
                match bluetooth::disconnect(addr) {
                    Ok(()) => shell_println!("Disconnected {}.", addr),
                    Err(e) => shell_println!("Error: {:?}", e),
                }
            } else {
                shell_println!("Usage: bt disconnect <address>");
            }
        }
        "trust" => {
            if let Some(addr) = parts.get(1) {
                let on = parts.get(2).copied().unwrap_or("on") != "off";
                match bluetooth::set_trusted(addr, on) {
                    Ok(()) => shell_println!("Trust {}: {}", addr, on),
                    Err(e) => shell_println!("Error: {:?}", e),
                }
            } else {
                shell_println!("Usage: bt trust <address> [on|off]");
            }
        }
        "block" => {
            if let Some(addr) = parts.get(1) {
                let on = parts.get(2).copied().unwrap_or("on") != "off";
                match bluetooth::set_blocked(addr, on) {
                    Ok(()) => shell_println!("Block {}: {}", addr, on),
                    Err(e) => shell_println!("Error: {:?}", e),
                }
            } else {
                shell_println!("Usage: bt block <address> [on|off]");
            }
        }
        "info" => {
            if let Some(addr) = parts.get(1) {
                match bluetooth::get_device(addr) {
                    Ok(dev) => {
                        shell_println!("Device: {} ({})", dev.name, dev.address);
                        shell_println!("  Type:       {} {}", dev.device_type.icon(), dev.device_type.label());
                        shell_println!("  State:      {}", dev.state.label());
                        shell_println!("  Paired:     {}", dev.paired);
                        shell_println!("  Trusted:    {}", dev.trusted);
                        shell_println!("  Blocked:    {}", dev.blocked);
                        shell_println!("  RSSI:       {} dBm", dev.rssi);
                        if let Some(bat) = dev.battery_pct {
                            shell_println!("  Battery:    {}%", bat);
                        }
                        let profiles: Vec<&str> = dev.profiles.iter()
                            .map(|p| p.label())
                            .collect();
                        shell_println!("  Profiles:   {}", profiles.join(", "));
                        shell_println!("  Connects:   {}", dev.connect_count);
                    }
                    Err(e) => shell_println!("Error: {:?}", e),
                }
            } else {
                shell_println!("Usage: bt info <address>");
            }
        }
        "name" => {
            if let Some(_new_name) = parts.get(1) {
                let full = parts.get(1..).map(|p| p.join(" ")).unwrap_or_default();
                match bluetooth::set_adapter_name(&full) {
                    Ok(()) => shell_println!("Adapter name set to: {}", full),
                    Err(e) => shell_println!("Error: {:?}", e),
                }
            } else {
                shell_println!("Usage: bt name <adapter name>");
            }
        }
        "discoverable" | "disc-mode" => {
            let on = parts.get(1).copied().unwrap_or("on") != "off";
            match bluetooth::set_discoverable(on) {
                Ok(()) => shell_println!("Discoverable: {}", on),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "addscan" => {
            if let (Some(addr), Some(name)) = (parts.get(1), parts.get(2)) {
                let dt = match parts.get(3).copied().unwrap_or("other") {
                    "headphones" | "hp" => bluetooth::DeviceType::AudioHeadphones,
                    "speaker" => bluetooth::DeviceType::AudioSpeaker,
                    "keyboard" => bluetooth::DeviceType::Keyboard,
                    "mouse" => bluetooth::DeviceType::Mouse,
                    _ => bluetooth::DeviceType::Other,
                };
                let rssi = parts.get(4).and_then(|s| s.parse::<i8>().ok()).unwrap_or(-60);
                match bluetooth::add_scan_result(addr, name, dt, rssi) {
                    Ok(()) => shell_println!("Added scan result: {} {}", addr, name),
                    Err(e) => shell_println!("Error: {:?}", e),
                }
            } else {
                shell_println!("Usage: bt addscan <addr> <name> [type] [rssi]");
            }
        }
        "stats" => {
            let (total, connected, scans, pairs, ops) = bluetooth::stats();
            shell_println!("Paired devices:  {}", total);
            shell_println!("Connected:       {}", connected);
            shell_println!("Scan count:      {}", scans);
            shell_println!("Pair count:      {}", pairs);
            shell_println!("Operations:      {}", ops);
        }
        "test" => {
            bluetooth::self_test();
            shell_println!("[bluetooth] All self-tests passed.");
        }
        "init" => {
            bluetooth::init_defaults();
            shell_println!("Bluetooth subsystem initialized.");
        }
        _ => {
            shell_println!("bluetooth — Bluetooth device management");
            shell_println!("Usage: bluetooth|bt <subcommand>");
            shell_println!("");
            shell_println!("Subcommands:");
            shell_println!("  show               Show status and devices (default)");
            shell_println!("  on / off           Enable/disable Bluetooth");
            shell_println!("  scan               Scan for nearby devices");
            shell_println!("  pair <addr> <name> [type]  Pair with a device");
            shell_println!("  unpair <addr>      Remove pairing");
            shell_println!("  connect <addr>     Connect to paired device");
            shell_println!("  disconnect <addr>  Disconnect device");
            shell_println!("  trust <addr> [on|off]  Trust for auto-connect");
            shell_println!("  block <addr> [on|off]  Block device");
            shell_println!("  info <addr>        Show device details");
            shell_println!("  name <name>        Set adapter name");
            shell_println!("  discoverable [on|off]  Set discoverable mode");
            shell_println!("  addscan <addr> <name> [type] [rssi]  Add scan result");
            shell_println!("  stats              Show statistics");
            shell_println!("  init               Initialize subsystem");
            shell_println!("  test               Run self-tests");
        }
    }
}

/// `printmgr` / `lp` — print management.
fn cmd_printmgr(args: &str) {
    use crate::fs::printmgr;
    let parts: Vec<&str> = args.split_whitespace().collect();
    let sub = parts.first().copied().unwrap_or("");
    match sub {
        "show" | "" | "list" => {
            let printers = printmgr::list_printers();
            if printers.is_empty() {
                shell_println!("No printers configured.");
            } else {
                shell_println!("{} printer(s):", printers.len());
                for p in &printers {
                    let def = if p.is_default { " [default]" } else { "" };
                    shell_println!("  #{} {} ({}) [{}] {}{}", p.id, p.name, p.model,
                        p.printer_type.label(), p.status.label(), def);
                    shell_println!("       URI: {}  Jobs: {}  Pages: {}",
                        p.uri, p.total_jobs, p.total_pages);
                }
            }
        }
        "info" => {
            if let Some(id_str) = parts.get(1) {
                if let Ok(id) = id_str.parse::<u64>() {
                    match printmgr::get_printer(id) {
                        Ok(p) => {
                            shell_println!("Printer #{}: {}", p.id, p.name);
                            shell_println!("  Model:     {}", p.model);
                            shell_println!("  Type:      {}", p.printer_type.label());
                            shell_println!("  URI:       {}", p.uri);
                            shell_println!("  Status:    {}", p.status.label());
                            shell_println!("  Default:   {}", p.is_default);
                            shell_println!("  Location:  {}", p.location);
                            shell_println!("  Color:     {}", p.supports_color);
                            shell_println!("  Duplex:    {}", p.supports_duplex);
                            shell_println!("  Paper:     {}", p.default_paper.label());
                            shell_println!("  Quality:   {}", p.default_quality.label());
                            shell_println!("  Jobs:      {}", p.total_jobs);
                            shell_println!("  Pages:     {}", p.total_pages);
                        }
                        Err(e) => shell_println!("Error: {:?}", e),
                    }
                } else {
                    shell_println!("Invalid printer ID.");
                }
            } else {
                shell_println!("Usage: lp info <id>");
            }
        }
        "add" => {
            if let (Some(name), Some(uri)) = (parts.get(1), parts.get(2)) {
                let ptype = match parts.get(3).copied().unwrap_or("network") {
                    "local" | "usb" => printmgr::PrinterType::Local,
                    "network" | "net" | "ipp" => printmgr::PrinterType::Network,
                    "virtual" | "pdf" => printmgr::PrinterType::Virtual,
                    "bluetooth" | "bt" => printmgr::PrinterType::Bluetooth,
                    _ => printmgr::PrinterType::Network,
                };
                match printmgr::add_printer(name, name, ptype, uri) {
                    Ok(id) => shell_println!("Added printer #{}: {}", id, name),
                    Err(e) => shell_println!("Error: {:?}", e),
                }
            } else {
                shell_println!("Usage: lp add <name> <uri> [local|network|virtual|bluetooth]");
            }
        }
        "remove" | "rm" => {
            if let Some(id_str) = parts.get(1) {
                if let Ok(id) = id_str.parse::<u64>() {
                    match printmgr::remove_printer(id) {
                        Ok(()) => shell_println!("Printer #{} removed.", id),
                        Err(e) => shell_println!("Error: {:?}", e),
                    }
                } else {
                    shell_println!("Invalid printer ID.");
                }
            } else {
                shell_println!("Usage: lp remove <id>");
            }
        }
        "default" => {
            if let Some(id_str) = parts.get(1) {
                if let Ok(id) = id_str.parse::<u64>() {
                    match printmgr::set_default(id) {
                        Ok(()) => shell_println!("Default printer set to #{}.", id),
                        Err(e) => shell_println!("Error: {:?}", e),
                    }
                } else {
                    shell_println!("Invalid printer ID.");
                }
            } else if let Some(def) = printmgr::default_printer() {
                shell_println!("Default: #{} {}", def.id, def.name);
            } else {
                shell_println!("No default printer set.");
            }
        }
        "print" => {
            // lp print <document> [pages] [copies]
            if let Some(doc) = parts.get(1) {
                let pages = parts.get(2).and_then(|s| s.parse::<u32>().ok()).unwrap_or(1);
                let copies = parts.get(3).and_then(|s| s.parse::<u32>().ok()).unwrap_or(1);
                if let Some(def) = printmgr::default_printer() {
                    match printmgr::submit_job(def.id, doc, pages, copies, 0) {
                        Ok(job_id) => shell_println!("Job #{} submitted to {} ({} pages, {} copies)",
                            job_id, def.name, pages, copies),
                        Err(e) => shell_println!("Error: {:?}", e),
                    }
                } else {
                    shell_println!("No default printer. Use 'lp default <id>' first.");
                }
            } else {
                shell_println!("Usage: lp print <document> [pages] [copies]");
            }
        }
        "jobs" => {
            let jobs = printmgr::list_jobs();
            if jobs.is_empty() {
                shell_println!("No pending jobs.");
            } else {
                shell_println!("{} job(s):", jobs.len());
                for j in &jobs {
                    shell_println!("  #{} {} [{}] {} pages, {} copies → printer #{}",
                        j.id, j.document_name, j.status.label(),
                        j.pages, j.copies, j.printer_id);
                }
            }
        }
        "cancel" => {
            if let Some(id_str) = parts.get(1) {
                if let Ok(id) = id_str.parse::<u64>() {
                    match printmgr::cancel_job(id) {
                        Ok(()) => shell_println!("Job #{} cancelled.", id),
                        Err(e) => shell_println!("Error: {:?}", e),
                    }
                } else {
                    shell_println!("Invalid job ID.");
                }
            } else {
                shell_println!("Usage: lp cancel <job-id>");
            }
        }
        "complete" => {
            if let Some(id_str) = parts.get(1) {
                if let Ok(id) = id_str.parse::<u64>() {
                    let success = parts.get(2).copied().unwrap_or("ok") != "fail";
                    match printmgr::complete_job(id, success) {
                        Ok(()) => shell_println!("Job #{} completed (success={}).", id, success),
                        Err(e) => shell_println!("Error: {:?}", e),
                    }
                } else {
                    shell_println!("Invalid job ID.");
                }
            } else {
                shell_println!("Usage: lp complete <job-id> [ok|fail]");
            }
        }
        "history" => {
            let history = printmgr::job_history();
            if history.is_empty() {
                shell_println!("No print history.");
            } else {
                shell_println!("{} historical job(s):", history.len());
                for j in history.iter().rev().take(20) {
                    shell_println!("  #{} {} [{}] {} pages",
                        j.id, j.document_name, j.status.label(), j.pages_printed);
                }
            }
        }
        "clear" => match printmgr::clear_completed() {
            Ok(n) => shell_println!("Cleared {} completed/cancelled jobs.", n),
            Err(e) => shell_println!("Error: {:?}", e),
        },
        "stats" => {
            let (printers, pending, pages, hist, ops) = printmgr::stats();
            shell_println!("Printers:      {}", printers);
            shell_println!("Pending jobs:  {}", pending);
            shell_println!("Total pages:   {}", pages);
            shell_println!("History:       {}", hist);
            shell_println!("Operations:    {}", ops);
        }
        "test" => {
            printmgr::self_test();
            shell_println!("[printmgr] All self-tests passed.");
        }
        "init" => {
            printmgr::init_defaults();
            shell_println!("Print manager initialized.");
        }
        _ => {
            shell_println!("printmgr — print management");
            shell_println!("Usage: printmgr|lp <subcommand>");
            shell_println!("");
            shell_println!("Subcommands:");
            shell_println!("  list               List printers (default)");
            shell_println!("  info <id>          Show printer details");
            shell_println!("  add <name> <uri> [type]  Add printer");
            shell_println!("  remove <id>        Remove printer");
            shell_println!("  default [id]       Get/set default printer");
            shell_println!("  print <doc> [pages] [copies]  Submit print job");
            shell_println!("  jobs               List pending jobs");
            shell_println!("  cancel <job-id>    Cancel a job");
            shell_println!("  complete <job-id>  Mark job done");
            shell_println!("  history            Show print history");
            shell_println!("  clear              Clear completed jobs");
            shell_println!("  stats              Show statistics");
            shell_println!("  init               Initialize print manager");
            shell_println!("  test               Run self-tests");
        }
    }
}

/// `screenrec` / `srec` — screen recording management.
fn cmd_screenrec(args: &str) {
    use crate::fs::screenrec;
    let parts: Vec<&str> = args.split_whitespace().collect();
    let sub = parts.first().copied().unwrap_or("");
    match sub {
        "show" | "" => {
            let (count, active, total, total_sec, _total_bytes, _) = screenrec::stats();
            let recording = screenrec::is_recording();
            shell_println!("Screen Recording: {}", if recording { "RECORDING" } else { "idle" });
            if let Ok(cfg) = screenrec::get_config() {
                shell_println!("  Format:    {}", cfg.format.label());
                shell_println!("  Audio:     {}", cfg.audio.label());
                shell_println!("  Quality:   {}", cfg.quality.label());
                shell_println!("  FPS:       {}", cfg.fps);
                shell_println!("  Area:      {}", cfg.area.label());
                shell_println!("  Cursor:    {}", if cfg.show_cursor { "shown" } else { "hidden" });
                shell_println!("  Countdown: {}s", cfg.countdown_seconds);
                shell_println!("  Output:    {}", cfg.output_dir);
            }
            shell_println!("  Recordings: {} ({} active)", count, active);
            shell_println!("  Total:      {} recordings, {}",
                total, screenrec::format_duration(total_sec as u32));
        }
        "start" | "rec" => match screenrec::start_recording() {
            Ok(id) => {
                let rec = screenrec::get_recording(id).unwrap();
                shell_println!("Recording #{} started ({}).", id, rec.state.label());
                shell_println!("  File: {}", rec.file_path);
                if rec.state == screenrec::RecordingState::Countdown {
                    let _ = screenrec::begin_capture(id);
                    shell_println!("  Capture begun.");
                }
            }
            Err(e) => shell_println!("Error: {:?}", e),
        },
        "stop" => {
            if let Some(id_str) = parts.get(1) {
                if let Ok(id) = id_str.parse::<u64>() {
                    match screenrec::stop_recording(id) {
                        Ok(rec) => {
                            shell_println!("Recording #{} stopped.", id);
                            shell_println!("  Duration: {}", screenrec::format_duration(rec.duration_seconds));
                            shell_println!("  Frames:   {}", rec.frame_count);
                            shell_println!("  File:     {}", rec.file_path);
                        }
                        Err(e) => shell_println!("Error: {:?}", e),
                    }
                } else {
                    shell_println!("Invalid ID.");
                }
            } else {
                // Stop most recent active recording.
                let active = screenrec::active_recordings();
                if let Some(rec) = active.last() {
                    match screenrec::stop_recording(rec.id) {
                        Ok(r) => shell_println!("Recording #{} stopped ({}).",
                            r.id, screenrec::format_duration(r.duration_seconds)),
                        Err(e) => shell_println!("Error: {:?}", e),
                    }
                } else {
                    shell_println!("No active recording.");
                }
            }
        }
        "pause" => {
            let active = screenrec::active_recordings();
            if let Some(rec) = active.last() {
                match screenrec::pause_recording(rec.id) {
                    Ok(()) => shell_println!("Recording #{} paused.", rec.id),
                    Err(e) => shell_println!("Error: {:?}", e),
                }
            } else {
                shell_println!("No active recording.");
            }
        }
        "resume" => {
            let active = screenrec::active_recordings();
            if let Some(rec) = active.last() {
                match screenrec::resume_recording(rec.id) {
                    Ok(()) => shell_println!("Recording #{} resumed.", rec.id),
                    Err(e) => shell_println!("Error: {:?}", e),
                }
            } else {
                shell_println!("No paused recording.");
            }
        }
        "list" => {
            let recs = screenrec::list_recordings();
            if recs.is_empty() {
                shell_println!("No recordings.");
            } else {
                shell_println!("{} recording(s):", recs.len());
                for r in &recs {
                    shell_println!("  #{} [{}] {} — {} frames, {}",
                        r.id, r.state.label(), r.file_path,
                        r.frame_count, screenrec::format_duration(r.duration_seconds));
                }
            }
        }
        "format" => {
            if let Some(fmt) = parts.get(1) {
                let f = match *fmt {
                    "webm" => screenrec::OutputFormat::WebM,
                    "mp4" => screenrec::OutputFormat::Mp4,
                    "gif" => screenrec::OutputFormat::Gif,
                    _ => {
                        shell_println!("Unknown format. Options: webm, mp4, gif");
                        return;
                    }
                };
                match screenrec::set_format(f) {
                    Ok(()) => shell_println!("Format set to: {}", f.label()),
                    Err(e) => shell_println!("Error: {:?}", e),
                }
            } else {
                shell_println!("Usage: srec format <webm|mp4|gif>");
            }
        }
        "audio" => {
            if let Some(mode) = parts.get(1) {
                let m = match *mode {
                    "none" | "off" => screenrec::AudioMode::None,
                    "system" | "sys" => screenrec::AudioMode::System,
                    "mic" | "microphone" => screenrec::AudioMode::Microphone,
                    "both" | "all" => screenrec::AudioMode::Both,
                    _ => {
                        shell_println!("Unknown mode. Options: none, system, mic, both");
                        return;
                    }
                };
                match screenrec::set_audio(m) {
                    Ok(()) => shell_println!("Audio mode: {}", m.label()),
                    Err(e) => shell_println!("Error: {:?}", e),
                }
            } else {
                shell_println!("Usage: srec audio <none|system|mic|both>");
            }
        }
        "quality" => {
            if let Some(q) = parts.get(1) {
                let preset = match *q {
                    "low" => screenrec::QualityPreset::Low,
                    "medium" | "med" => screenrec::QualityPreset::Medium,
                    "high" => screenrec::QualityPreset::High,
                    "lossless" => screenrec::QualityPreset::Lossless,
                    _ => {
                        shell_println!("Unknown quality. Options: low, medium, high, lossless");
                        return;
                    }
                };
                match screenrec::set_quality(preset) {
                    Ok(()) => shell_println!("Quality: {}", preset.label()),
                    Err(e) => shell_println!("Error: {:?}", e),
                }
            } else {
                shell_println!("Usage: srec quality <low|medium|high|lossless>");
            }
        }
        "fps" => {
            if let Some(val) = parts.get(1) {
                if let Ok(fps) = val.parse::<u32>() {
                    match screenrec::set_fps(fps) {
                        Ok(()) => shell_println!("FPS set to {}", fps),
                        Err(e) => shell_println!("Error: {:?}", e),
                    }
                } else {
                    shell_println!("Invalid FPS.");
                }
            } else {
                shell_println!("Usage: srec fps <value>");
            }
        }
        "cursor" => {
            let on = parts.get(1).copied().unwrap_or("on") != "off";
            let _ = screenrec::set_show_cursor(on);
            shell_println!("Cursor: {}", if on { "shown" } else { "hidden" });
        }
        "countdown" => {
            if let Some(val) = parts.get(1) {
                if let Ok(s) = val.parse::<u8>() {
                    match screenrec::set_countdown(s) {
                        Ok(()) => shell_println!("Countdown: {}s", s),
                        Err(e) => shell_println!("Error: {:?}", e),
                    }
                } else {
                    shell_println!("Invalid value.");
                }
            } else {
                shell_println!("Usage: srec countdown <0-10>");
            }
        }
        "outdir" => {
            if let Some(dir) = parts.get(1) {
                match screenrec::set_output_dir(dir) {
                    Ok(()) => shell_println!("Output directory: {}", dir),
                    Err(e) => shell_println!("Error: {:?}", e),
                }
            } else {
                shell_println!("Usage: srec outdir <path>");
            }
        }
        "stats" => {
            let (count, active, total, total_sec, total_bytes, ops) = screenrec::stats();
            shell_println!("Recordings:  {}", count);
            shell_println!("Active:      {}", active);
            shell_println!("Total:       {}", total);
            shell_println!("Duration:    {}", screenrec::format_duration(total_sec as u32));
            shell_println!("Data:        {}", format_size_helper(total_bytes));
            shell_println!("Operations:  {}", ops);
        }
        "test" => {
            screenrec::self_test();
            shell_println!("[screenrec] All self-tests passed.");
        }
        "init" => {
            screenrec::init_defaults();
            shell_println!("Screen recording initialized.");
        }
        _ => {
            shell_println!("screenrec — screen recording");
            shell_println!("Usage: screenrec|srec <subcommand>");
            shell_println!("");
            shell_println!("Subcommands:");
            shell_println!("  show               Show status (default)");
            shell_println!("  start              Start recording");
            shell_println!("  stop [id]          Stop recording");
            shell_println!("  pause              Pause active recording");
            shell_println!("  resume             Resume paused recording");
            shell_println!("  list               List all recordings");
            shell_println!("  format <fmt>       Set format: webm, mp4, gif");
            shell_println!("  audio <mode>       Audio: none, system, mic, both");
            shell_println!("  quality <q>        Quality: low, medium, high, lossless");
            shell_println!("  fps <n>            Set frames per second");
            shell_println!("  cursor [on|off]    Show/hide cursor");
            shell_println!("  countdown <s>      Pre-record countdown (0-10s)");
            shell_println!("  outdir <path>      Set output directory");
            shell_println!("  stats              Show statistics");
            shell_println!("  init               Initialize subsystem");
            shell_println!("  test               Run self-tests");
        }
    }
}

fn format_size_helper(bytes: u64) -> alloc::string::String {
    use alloc::format;
    if bytes >= 1_073_741_824 {
        format!("{}.{} GB", bytes / 1_073_741_824, (bytes % 1_073_741_824) / 107_374_182)
    } else if bytes >= 1_048_576 {
        format!("{}.{} MB", bytes / 1_048_576, (bytes % 1_048_576) / 104_857)
    } else if bytes >= 1024 {
        format!("{}.{} KB", bytes / 1024, (bytes % 1024) / 102)
    } else {
        format!("{} B", bytes)
    }
}

/// `datausage` / `dusage` — network data usage monitoring.
fn cmd_datausage(args: &str) {
    use crate::fs::datausage;

    let parts: Vec<&str> = args.split_whitespace().collect();
    let sub = parts.first().copied().unwrap_or("");

    match sub {
        "show" | "" => {
            let (apps, daily, rx, tx, limits, ops) = datausage::stats();
            let metered = datausage::metered_status();
            shell_println!("=== Data Usage Monitor ===");
            shell_println!("  Apps tracked   : {}", apps);
            shell_println!("  Daily records  : {}", daily);
            shell_println!("  Total received : {}", datausage::format_bytes(rx));
            shell_println!("  Total sent     : {}", datausage::format_bytes(tx));
            shell_println!("  Total          : {}", datausage::format_bytes(rx.saturating_add(tx)));
            shell_println!("  Limits         : {}", limits);
            shell_println!("  Metered        : {}", metered.label());
            shell_println!("  Restrict bg    : {}", datausage::should_restrict_background());
            shell_println!("  Operations     : {}", ops);
        }
        "apps" => {
            let apps = datausage::app_usage();
            if apps.is_empty() {
                shell_println!("No app usage recorded.");
            } else {
                shell_println!("{:<20} {:>12} {:>12} {:>12} {:>6}",
                    "APP", "RECEIVED", "SENT", "TOTAL", "CONNS");
                for app in &apps {
                    shell_println!("{:<20} {:>12} {:>12} {:>12} {:>6}",
                        app.app_id,
                        datausage::format_bytes(app.rx_bytes),
                        datausage::format_bytes(app.tx_bytes),
                        datausage::format_bytes(app.total_bytes()),
                        app.connection_count);
                }
            }
        }
        "app" => {
            if let Some(name) = parts.get(1) {
                match datausage::usage_for_app(name) {
                    Ok(app) => {
                        shell_println!("App: {}", app.app_id);
                        shell_println!("  Received    : {}", datausage::format_bytes(app.rx_bytes));
                        shell_println!("  Sent        : {}", datausage::format_bytes(app.tx_bytes));
                        shell_println!("  Total       : {}", datausage::format_bytes(app.total_bytes()));
                        shell_println!("  Connections : {}", app.connection_count);
                    }
                    Err(e) => shell_println!("Error: {:?}", e),
                }
            } else {
                shell_println!("Usage: datausage app <app_id>");
            }
        }
        "record" => {
            // datausage record <app_id> <rx> <tx>
            if parts.len() >= 4 {
                let app_id = parts[1];
                let rx: u64 = parts[2].parse().unwrap_or(0);
                let tx: u64 = parts[3].parse().unwrap_or(0);
                match datausage::record_usage(app_id, rx, tx) {
                    Ok(()) => shell_println!("Recorded {} rx={} tx={}", app_id,
                        datausage::format_bytes(rx), datausage::format_bytes(tx)),
                    Err(e) => shell_println!("Error: {:?}", e),
                }
            } else {
                shell_println!("Usage: datausage record <app_id> <rx_bytes> <tx_bytes>");
            }
        }
        "summary" => {
            let period = match parts.get(1).copied().unwrap_or("all") {
                "today" => datausage::UsagePeriod::Today,
                "week" => datausage::UsagePeriod::ThisWeek,
                "month" => datausage::UsagePeriod::ThisMonth,
                "30d" | "30days" => datausage::UsagePeriod::Last30Days,
                _ => datausage::UsagePeriod::AllTime,
            };
            let s = datausage::usage_summary(period);
            shell_println!("=== {} Usage Summary ===", s.period.label());
            shell_println!("  Received : {}", datausage::format_bytes(s.rx_bytes));
            shell_println!("  Sent     : {}", datausage::format_bytes(s.tx_bytes));
            shell_println!("  Total    : {}", datausage::format_bytes(s.rx_bytes.saturating_add(s.tx_bytes)));
            shell_println!("  Apps     : {}", s.app_count);
            if !s.top_apps.is_empty() {
                shell_println!("  Top apps:");
                for (name, total) in &s.top_apps {
                    shell_println!("    {}: {}", name, datausage::format_bytes(*total));
                }
            }
        }
        "daily" => {
            let history = datausage::daily_history();
            if history.is_empty() {
                shell_println!("No daily records.");
            } else {
                shell_println!("{:>6} {:>12} {:>12} {:>12} {:>4}",
                    "DAY", "RECEIVED", "SENT", "TOTAL", "APPS");
                for d in &history {
                    shell_println!("{:>6} {:>12} {:>12} {:>12} {:>4}",
                        d.day,
                        datausage::format_bytes(d.rx_bytes),
                        datausage::format_bytes(d.tx_bytes),
                        datausage::format_bytes(d.rx_bytes.saturating_add(d.tx_bytes)),
                        d.apps.len());
                }
            }
        }
        "metered" => {
            match parts.get(1).copied() {
                Some("on") | Some("yes") => {
                    match datausage::set_metered(datausage::MeteredStatus::Metered) {
                        Ok(()) => shell_println!("Connection set to metered."),
                        Err(e) => shell_println!("Error: {:?}", e),
                    }
                }
                Some("off") | Some("no") => {
                    match datausage::set_metered(datausage::MeteredStatus::Unmetered) {
                        Ok(()) => shell_println!("Connection set to unmetered."),
                        Err(e) => shell_println!("Error: {:?}", e),
                    }
                }
                Some("roaming") => {
                    match datausage::set_metered(datausage::MeteredStatus::Roaming) {
                        Ok(()) => shell_println!("Connection set to roaming."),
                        Err(e) => shell_println!("Error: {:?}", e),
                    }
                }
                _ => {
                    shell_println!("Metered: {}", datausage::metered_status().label());
                    shell_println!("Usage: datausage metered <on|off|roaming>");
                }
            }
        }
        "limit" => {
            match parts.get(1).copied() {
                Some("add") => {
                    // datausage limit add <name> <bytes> [days]
                    if parts.len() >= 4 {
                        let name = parts[2];
                        let bytes: u64 = parts[3].parse().unwrap_or(0);
                        let days: u32 = parts.get(4).and_then(|s| s.parse().ok()).unwrap_or(30);
                        match datausage::add_limit(name, bytes, days) {
                            Ok(()) => shell_println!("Limit '{}' added: {} over {} days",
                                name, datausage::format_bytes(bytes), days),
                            Err(e) => shell_println!("Error: {:?}", e),
                        }
                    } else {
                        shell_println!("Usage: datausage limit add <name> <bytes> [days]");
                    }
                }
                Some("rm") | Some("remove") => {
                    if let Some(name) = parts.get(2) {
                        match datausage::remove_limit(name) {
                            Ok(()) => shell_println!("Limit '{}' removed.", name),
                            Err(e) => shell_println!("Error: {:?}", e),
                        }
                    } else {
                        shell_println!("Usage: datausage limit rm <name>");
                    }
                }
                Some("block") => {
                    // datausage limit block <name> <on|off>
                    if parts.len() >= 4 {
                        let name = parts[2];
                        let block = matches!(parts[3], "on" | "yes" | "true");
                        match datausage::set_block_on_exceed(name, block) {
                            Ok(()) => shell_println!("Block-on-exceed for '{}': {}", name, block),
                            Err(e) => shell_println!("Error: {:?}", e),
                        }
                    } else {
                        shell_println!("Usage: datausage limit block <name> <on|off>");
                    }
                }
                Some("alert") => {
                    // datausage limit alert <name> <pct>
                    if parts.len() >= 4 {
                        let name = parts[2];
                        let pct: u8 = parts[3].parse().unwrap_or(80);
                        match datausage::set_alert_threshold(name, pct) {
                            Ok(()) => shell_println!("Alert threshold for '{}': {}%", name, pct),
                            Err(e) => shell_println!("Error: {:?}", e),
                        }
                    } else {
                        shell_println!("Usage: datausage limit alert <name> <pct>");
                    }
                }
                _ => {
                    let limits = datausage::list_limits();
                    if limits.is_empty() {
                        shell_println!("No data limits configured.");
                    } else {
                        shell_println!("{:<20} {:>12} {:>6} {:>5} {:>7} {:>5}",
                            "NAME", "LIMIT", "DAYS", "ALERT", "EXCEED", "BLOCK");
                        for l in &limits {
                            shell_println!("{:<20} {:>12} {:>6} {:>4}% {:>7} {:>5}",
                                l.name,
                                datausage::format_bytes(l.limit_bytes),
                                l.period_days,
                                l.alert_pct,
                                if l.exceeded { "YES" } else { "no" },
                                if l.block_on_exceed { "YES" } else { "no" });
                        }
                    }
                }
            }
        }
        "reset" => {
            match datausage::reset_usage() {
                Ok(()) => shell_println!("Usage counters reset."),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "stats" => {
            let (apps, daily, rx, tx, limits, ops) = datausage::stats();
            shell_println!("Data usage stats:");
            shell_println!("  Apps tracked   : {}", apps);
            shell_println!("  Daily records  : {}", daily);
            shell_println!("  Total RX       : {} ({} bytes)", datausage::format_bytes(rx), rx);
            shell_println!("  Total TX       : {} ({} bytes)", datausage::format_bytes(tx), tx);
            shell_println!("  Limits         : {}", limits);
            shell_println!("  Operations     : {}", ops);
        }
        "test" => {
            datausage::self_test();
            shell_println!("datausage: self-tests completed (see serial).");
        }
        "init" => {
            datausage::init_defaults();
            shell_println!("Data usage monitoring initialized.");
        }
        "help" => {
            shell_println!("datausage (dusage) — network data usage monitoring");
            shell_println!("  show               Show current usage overview");
            shell_println!("  apps               List all app usage (sorted)");
            shell_println!("  app <id>           Show usage for specific app");
            shell_println!("  record <id> <rx> <tx>  Record usage for an app");
            shell_println!("  summary [period]   Usage summary (today/week/month/30d/all)");
            shell_println!("  daily              Show daily usage history");
            shell_println!("  metered <on|off|roaming>  Set metered status");
            shell_println!("  limit              List limits");
            shell_println!("  limit add <name> <bytes> [days]  Add limit");
            shell_println!("  limit rm <name>    Remove limit");
            shell_println!("  limit block <name> <on|off>  Block on exceed");
            shell_println!("  limit alert <name> <pct>     Set alert threshold");
            shell_println!("  reset              Reset all usage counters");
            shell_println!("  stats              Show raw stats");
            shell_println!("  test               Run self-tests");
            shell_println!("  init               Initialize subsystem");
        }
        _ => {
            shell_println!("Unknown subcommand '{}'. Try 'datausage help'.", sub);
        }
    }
}

/// `mousesettings` / `mouse` — mouse pointer and button settings.
fn cmd_mousesettings(args: &str) {
    use crate::fs::mousesettings;
    use alloc::format;

    let parts: Vec<&str> = args.split_whitespace().collect();
    let sub = parts.first().copied().unwrap_or("");

    match sub {
        "show" | "" => {
            let (devices, speed, accel, left, natural, ops) = mousesettings::stats();
            shell_println!("=== Mouse Settings ===");
            shell_println!("  Devices        : {}", devices);
            shell_println!("  Speed          : {}", speed);
            shell_println!("  Acceleration   : {}", accel);
            shell_println!("  Left-handed    : {}", left);
            shell_println!("  Natural scroll : {}", natural);
            shell_println!("  Operations     : {}", ops);
            if let Ok(cfg) = mousesettings::config() {
                shell_println!("  Scroll speed   : {}", cfg.scroll_speed);
                shell_println!("  Scroll method  : {}", cfg.scroll_method.label());
                shell_println!("  Double-click   : {} ms", cfg.double_click_ms);
                shell_println!("  Scroll lines   : {}", cfg.scroll_lines);
            }
        }
        "speed" => {
            if let Some(val) = parts.get(1).and_then(|s| s.parse::<u32>().ok()) {
                match mousesettings::set_speed(val) {
                    Ok(()) => shell_println!("Speed set to {}.", val),
                    Err(e) => shell_println!("Error: {:?}", e),
                }
            } else {
                shell_println!("Usage: mouse speed <1-20>");
            }
        }
        "accel" => {
            match parts.get(1).copied() {
                Some("flat") => { let _ = mousesettings::set_accel_profile(mousesettings::AccelProfile::Flat); shell_println!("Acceleration: Flat"); }
                Some("adaptive") => { let _ = mousesettings::set_accel_profile(mousesettings::AccelProfile::Adaptive); shell_println!("Acceleration: Adaptive"); }
                Some(v) => {
                    if let Ok(f) = v.parse::<u32>() {
                        match mousesettings::set_accel_factor(f) {
                            Ok(()) => shell_println!("Acceleration factor: {}", f),
                            Err(e) => shell_println!("Error: {:?}", e),
                        }
                    } else {
                        shell_println!("Usage: mouse accel <flat|adaptive|0-10>");
                    }
                }
                None => shell_println!("Usage: mouse accel <flat|adaptive|0-10>"),
            }
        }
        "lefthanded" => {
            let val = matches!(parts.get(1).copied(), Some("on") | Some("yes") | Some("true"));
            let _ = mousesettings::set_left_handed(val);
            shell_println!("Left-handed: {}", val);
        }
        "natural" => {
            let val = matches!(parts.get(1).copied(), Some("on") | Some("yes") | Some("true"));
            let _ = mousesettings::set_natural_scroll(val);
            shell_println!("Natural scroll: {}", val);
        }
        "scroll" => {
            match parts.get(1).copied() {
                Some("wheel") => { let _ = mousesettings::set_scroll_method(mousesettings::ScrollMethod::Wheel); shell_println!("Scroll: Wheel"); }
                Some("smooth") => { let _ = mousesettings::set_scroll_method(mousesettings::ScrollMethod::Smooth); shell_println!("Scroll: Smooth"); }
                Some("none") | Some("off") => { let _ = mousesettings::set_scroll_method(mousesettings::ScrollMethod::None); shell_println!("Scroll: Disabled"); }
                Some(v) => {
                    if let Ok(s) = v.parse::<u32>() {
                        match mousesettings::set_scroll_speed(s) {
                            Ok(()) => shell_println!("Scroll speed: {}", s),
                            Err(e) => shell_println!("Error: {:?}", e),
                        }
                    } else {
                        shell_println!("Usage: mouse scroll <wheel|smooth|none|1-20>");
                    }
                }
                None => shell_println!("Usage: mouse scroll <wheel|smooth|none|speed>"),
            }
        }
        "dblclick" => {
            if let Some(val) = parts.get(1).and_then(|s| s.parse::<u32>().ok()) {
                match mousesettings::set_double_click_ms(val) {
                    Ok(()) => shell_println!("Double-click interval: {} ms", val),
                    Err(e) => shell_println!("Error: {:?}", e),
                }
            } else {
                shell_println!("Usage: mouse dblclick <100-1000>");
            }
        }
        "devices" => {
            let devices = mousesettings::list_devices();
            if devices.is_empty() {
                shell_println!("No mouse devices registered.");
            } else {
                for d in &devices {
                    let status = if d.connected { "connected" } else { "disconnected" };
                    let wireless = if d.wireless { format!(" wireless batt={}%", d.battery_pct) } else { String::new() };
                    shell_println!("  [{}] {} — {} buttons, {} DPI, {}{}", d.id, d.name, d.buttons, d.dpi, status, wireless);
                }
            }
        }
        "stats" => {
            let (devices, speed, accel, left, natural, ops) = mousesettings::stats();
            shell_println!("Mouse stats: devices={} speed={} accel={} left={} natural={} ops={}", devices, speed, accel, left, natural, ops);
        }
        "test" => {
            mousesettings::self_test();
            shell_println!("mousesettings: self-tests completed (see serial).");
        }
        "init" => {
            mousesettings::init_defaults();
            shell_println!("Mouse settings initialized.");
        }
        _ => {
            shell_println!("mousesettings (mouse) — mouse settings");
            shell_println!("  show               Current settings");
            shell_println!("  speed <1-20>       Set pointer speed");
            shell_println!("  accel <flat|adaptive|0-10>  Acceleration");
            shell_println!("  lefthanded <on|off>  Swap buttons");
            shell_println!("  natural <on|off>   Natural scrolling");
            shell_println!("  scroll <wheel|smooth|none|speed>  Scroll");
            shell_println!("  dblclick <ms>      Double-click interval");
            shell_println!("  devices            List mouse devices");
            shell_println!("  stats / test / init");
        }
    }
}

/// `touchpad` / `tpad` — touchpad settings and gestures.
fn cmd_touchpad(args: &str) {
    use crate::fs::touchpad;

    let parts: Vec<&str> = args.split_whitespace().collect();
    let sub = parts.first().copied().unwrap_or("");

    match sub {
        "show" | "" => {
            let (devices, gestures, tap, natural, sens, ops) = touchpad::stats();
            shell_println!("=== Touchpad Settings ===");
            shell_println!("  Devices        : {}", devices);
            shell_println!("  Gestures       : {}", gestures);
            shell_println!("  Tap to click   : {}", tap);
            shell_println!("  Natural scroll : {}", natural);
            shell_println!("  Sensitivity    : {}", sens);
            shell_println!("  Operations     : {}", ops);
            if let Ok(cfg) = touchpad::config() {
                shell_println!("  Enabled        : {}", cfg.enabled);
                shell_println!("  Scroll method  : {}", cfg.scroll_method.label());
                shell_println!("  Click method   : {}", cfg.click_method.label());
                shell_println!("  Disable typing : {}", cfg.disable_while_typing);
                shell_println!("  Palm rejection : {}", cfg.palm_rejection);
                shell_println!("  Drag lock      : {}", cfg.drag_lock);
            }
        }
        "on" => {
            let _ = touchpad::set_enabled(true);
            shell_println!("Touchpad enabled.");
        }
        "off" => {
            let _ = touchpad::set_enabled(false);
            shell_println!("Touchpad disabled.");
        }
        "tap" => {
            let val = !matches!(parts.get(1).copied(), Some("off") | Some("no") | Some("false"));
            let _ = touchpad::set_tap_to_click(val);
            shell_println!("Tap to click: {}", val);
        }
        "natural" => {
            let val = !matches!(parts.get(1).copied(), Some("off") | Some("no") | Some("false"));
            let _ = touchpad::set_natural_scroll(val);
            shell_println!("Natural scroll: {}", val);
        }
        "sensitivity" | "sens" => {
            if let Some(val) = parts.get(1).and_then(|s| s.parse::<u32>().ok()) {
                match touchpad::set_sensitivity(val) {
                    Ok(()) => shell_println!("Sensitivity: {}", val),
                    Err(e) => shell_println!("Error: {:?}", e),
                }
            } else {
                shell_println!("Usage: touchpad sensitivity <1-20>");
            }
        }
        "scroll" => {
            match parts.get(1).copied() {
                Some("twofinger") | Some("2f") => { let _ = touchpad::set_scroll_method(touchpad::TouchScrollMethod::TwoFinger); shell_println!("Scroll: Two-finger"); }
                Some("edge") => { let _ = touchpad::set_scroll_method(touchpad::TouchScrollMethod::Edge); shell_println!("Scroll: Edge"); }
                Some("none") | Some("off") => { let _ = touchpad::set_scroll_method(touchpad::TouchScrollMethod::None); shell_println!("Scroll: Disabled"); }
                _ => shell_println!("Usage: touchpad scroll <twofinger|edge|none>"),
            }
        }
        "click" => {
            match parts.get(1).copied() {
                Some("areas") => { let _ = touchpad::set_click_method(touchpad::ClickMethod::ButtonAreas); shell_println!("Click: Button Areas"); }
                Some("finger") => { let _ = touchpad::set_click_method(touchpad::ClickMethod::ClickFinger); shell_println!("Click: Click Finger"); }
                Some("none") => { let _ = touchpad::set_click_method(touchpad::ClickMethod::None); shell_println!("Click: None"); }
                _ => shell_println!("Usage: touchpad click <areas|finger|none>"),
            }
        }
        "palm" => {
            match parts.get(1).copied() {
                Some("on") | Some("yes") => { let _ = touchpad::set_palm_rejection(true); shell_println!("Palm rejection: on"); }
                Some("off") | Some("no") => { let _ = touchpad::set_palm_rejection(false); shell_println!("Palm rejection: off"); }
                Some(v) => {
                    if let Ok(s) = v.parse::<u32>() {
                        match touchpad::set_palm_sensitivity(s) {
                            Ok(()) => shell_println!("Palm sensitivity: {}", s),
                            Err(e) => shell_println!("Error: {:?}", e),
                        }
                    } else {
                        shell_println!("Usage: touchpad palm <on|off|1-10>");
                    }
                }
                None => shell_println!("Usage: touchpad palm <on|off|1-10>"),
            }
        }
        "gestures" => {
            let gestures = touchpad::list_gestures();
            if gestures.is_empty() {
                shell_println!("No gestures configured.");
            } else {
                shell_println!("{:<25} {:<20} {:>7}", "GESTURE", "ACTION", "ENABLED");
                for g in &gestures {
                    shell_println!("{:<25} {:<20} {:>7}", g.gesture.label(), g.action.label(), g.enabled);
                }
            }
        }
        "typing" => {
            let val = !matches!(parts.get(1).copied(), Some("off") | Some("no") | Some("false"));
            let _ = touchpad::set_disable_while_typing(val);
            shell_println!("Disable while typing: {}", val);
        }
        "stats" => {
            let (devices, gestures, tap, natural, sens, ops) = touchpad::stats();
            shell_println!("Touchpad stats: devices={} gestures={} tap={} natural={} sens={} ops={}", devices, gestures, tap, natural, sens, ops);
        }
        "test" => {
            touchpad::self_test();
            shell_println!("touchpad: self-tests completed (see serial).");
        }
        "init" => {
            touchpad::init_defaults();
            shell_println!("Touchpad settings initialized.");
        }
        _ => {
            shell_println!("touchpad (tpad) — touchpad settings");
            shell_println!("  show                  Current settings");
            shell_println!("  on / off              Enable/disable");
            shell_println!("  tap <on|off>          Tap to click");
            shell_println!("  natural <on|off>      Natural scrolling");
            shell_println!("  sensitivity <1-20>    Sensitivity");
            shell_println!("  scroll <twofinger|edge|none>  Scroll method");
            shell_println!("  click <areas|finger|none>     Click method");
            shell_println!("  palm <on|off|1-10>    Palm rejection");
            shell_println!("  gestures              List gesture bindings");
            shell_println!("  typing <on|off>       Disable while typing");
            shell_println!("  stats / test / init");
        }
    }
}

/// `powerprofile` / `pprofile` — power profiles management.
fn cmd_powerprofile(args: &str) {
    use crate::fs::powerprofile;

    let parts: Vec<&str> = args.split_whitespace().collect();
    let sub = parts.first().copied().unwrap_or("");

    match sub {
        "show" | "" => {
            let (count, active, switches, batt_pct, batt_state, ops) = powerprofile::stats();
            shell_println!("=== Power Profiles ===");
            shell_println!("  Active         : {}", active);
            shell_println!("  Profiles       : {}", count);
            shell_println!("  Switches       : {}", switches);
            shell_println!("  Battery        : {}% ({})", batt_pct, batt_state);
            shell_println!("  CPU governor   : {}", powerprofile::active_cpu_governor().label());
            shell_println!("  Reduce bg      : {}", powerprofile::should_reduce_background());
            shell_println!("  No animations  : {}", powerprofile::should_disable_animations());
            shell_println!("  Operations     : {}", ops);
        }
        "list" => {
            let profiles = powerprofile::list_profiles();
            let active_name = powerprofile::active_profile_name();
            for p in &profiles {
                let active = if p.name == active_name { " *" } else { "" };
                shell_println!("  {} [{}] cpu={} max={}% boost={} bright={}%{}",
                    p.name, p.profile_type.label(), p.cpu_governor.label(),
                    p.cpu_max_pct, p.cpu_boost, p.brightness_pct, active);
            }
        }
        "balanced" => {
            match powerprofile::set_profile("Balanced") {
                Ok(()) => shell_println!("Switched to Balanced."),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "performance" | "perf" => {
            match powerprofile::set_profile("Performance") {
                Ok(()) => shell_println!("Switched to Performance."),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "powersaver" | "saver" => {
            match powerprofile::set_profile("Power Saver") {
                Ok(()) => shell_println!("Switched to Power Saver."),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "set" => {
            if let Some(name) = parts.get(1) {
                match powerprofile::set_profile(name) {
                    Ok(()) => shell_println!("Switched to {}.", name),
                    Err(e) => shell_println!("Error: {:?}", e),
                }
            } else {
                shell_println!("Usage: powerprofile set <name>");
            }
        }
        "create" => {
            if let Some(name) = parts.get(1) {
                match powerprofile::create_profile(name) {
                    Ok(()) => shell_println!("Created profile '{}'.", name),
                    Err(e) => shell_println!("Error: {:?}", e),
                }
            } else {
                shell_println!("Usage: powerprofile create <name>");
            }
        }
        "remove" | "rm" => {
            if let Some(name) = parts.get(1) {
                match powerprofile::remove_profile(name) {
                    Ok(()) => shell_println!("Removed profile '{}'.", name),
                    Err(e) => shell_println!("Error: {:?}", e),
                }
            } else {
                shell_println!("Usage: powerprofile remove <name>");
            }
        }
        "battery" | "batt" => {
            let bi = powerprofile::battery_info();
            shell_println!("Battery: {}% — {}", bi.charge_pct, bi.state.label());
            if bi.minutes_remaining > 0 {
                shell_println!("  Remaining: {} min", bi.minutes_remaining);
            }
            shell_println!("  Health: {}%  Cycles: {}", bi.health_pct, bi.cycle_count);
        }
        "brightness" | "bright" => {
            if let Some(val) = parts.get(1).and_then(|s| s.parse::<u32>().ok()) {
                match powerprofile::set_brightness(val) {
                    Ok(()) => shell_println!("Brightness: {}%", val),
                    Err(e) => shell_println!("Error: {:?}", e),
                }
            } else {
                shell_println!("Usage: powerprofile brightness <1-100>");
            }
        }
        "boost" => {
            let val = !matches!(parts.get(1).copied(), Some("off") | Some("no") | Some("false"));
            let _ = powerprofile::set_cpu_boost(val);
            shell_println!("CPU boost: {}", val);
        }
        "autoswitch" => {
            match parts.get(1).copied() {
                Some("on") | Some("yes") => { let _ = powerprofile::set_auto_switch(true); shell_println!("Auto-switch: on"); }
                Some("off") | Some("no") => { let _ = powerprofile::set_auto_switch(false); shell_println!("Auto-switch: off"); }
                Some(v) => {
                    if let Ok(pct) = v.parse::<u8>() {
                        let _ = powerprofile::set_auto_switch_threshold(pct);
                        shell_println!("Auto-switch threshold: {}%", pct);
                    } else {
                        shell_println!("Usage: powerprofile autoswitch <on|off|threshold%>");
                    }
                }
                None => shell_println!("Usage: powerprofile autoswitch <on|off|threshold%>"),
            }
        }
        "stats" => {
            let (count, active, switches, batt, bstate, ops) = powerprofile::stats();
            shell_println!("Power stats: profiles={} active={} switches={} battery={}% ({}) ops={}", count, active, switches, batt, bstate, ops);
        }
        "test" => {
            powerprofile::self_test();
            shell_println!("powerprofile: self-tests completed (see serial).");
        }
        "init" => {
            powerprofile::init_defaults();
            shell_println!("Power profiles initialized.");
        }
        _ => {
            shell_println!("powerprofile (pprofile) — power profiles");
            shell_println!("  show                  Current profile info");
            shell_println!("  list                  List all profiles");
            shell_println!("  balanced              Switch to Balanced");
            shell_println!("  performance           Switch to Performance");
            shell_println!("  powersaver            Switch to Power Saver");
            shell_println!("  set <name>            Switch to named profile");
            shell_println!("  create <name>         Create custom profile");
            shell_println!("  remove <name>         Remove custom profile");
            shell_println!("  battery               Battery info");
            shell_println!("  brightness <1-100>    Set brightness");
            shell_println!("  boost <on|off>        CPU boost");
            shell_println!("  autoswitch <on|off|%> Auto-switch settings");
            shell_println!("  stats / test / init");
        }
    }
}

/// `defaultapps` / `defapp` — default application management.
fn cmd_defaultapps(args: &str) {
    use crate::fs::defaultapps;
    use alloc::format;

    let parts: Vec<&str> = args.split_whitespace().collect();
    let sub = parts.first().copied().unwrap_or("");

    match sub {
        "show" | "" => {
            let (types, cats, overrides, ops) = defaultapps::stats();
            shell_println!("=== Default Applications ===");
            shell_println!("  Type mappings    : {}", types);
            shell_println!("  Category defaults: {}", cats);
            shell_println!("  User overrides   : {}", overrides);
            shell_println!("  Operations       : {}", ops);
        }
        "list" => {
            let cats = defaultapps::list_category_defaults(0);
            if cats.is_empty() {
                shell_println!("No category defaults configured.");
            } else {
                shell_println!("{:<20} {}", "CATEGORY", "APPLICATION");
                for cd in &cats {
                    shell_println!("{:<20} {}", cd.category.label(), cd.app_id);
                }
            }
        }
        "get" => {
            if let Some(mime) = parts.get(1) {
                let uid: u32 = parts.get(2).and_then(|s| s.parse().ok()).unwrap_or(0);
                match defaultapps::default_for_type(mime, uid) {
                    Some(app) => shell_println!("{} → {}", mime, app),
                    None => shell_println!("No default for '{}'", mime),
                }
            } else {
                shell_println!("Usage: defaultapps get <mime_type> [uid]");
            }
        }
        "set" => {
            // defapp set <mime> <app> [uid]
            if parts.len() >= 3 {
                let mime = parts[1];
                let app = parts[2];
                let uid: u32 = parts.get(3).and_then(|s| s.parse().ok()).unwrap_or(0);
                match defaultapps::set_default(mime, app, uid) {
                    Ok(()) => shell_println!("{} → {}", mime, app),
                    Err(e) => shell_println!("Error: {:?}", e),
                }
            } else {
                shell_println!("Usage: defaultapps set <mime> <app> [uid]");
            }
        }
        "rm" | "remove" => {
            if let Some(mime) = parts.get(1) {
                let uid: u32 = parts.get(2).and_then(|s| s.parse().ok()).unwrap_or(0);
                match defaultapps::remove_default(mime, uid) {
                    Ok(()) => shell_println!("Removed default for '{}'", mime),
                    Err(e) => shell_println!("Error: {:?}", e),
                }
            } else {
                shell_println!("Usage: defaultapps rm <mime> [uid]");
            }
        }
        "category" | "cat" => {
            // defapp category <cat> <app> [uid]
            if parts.len() >= 3 {
                let cat_name = parts[1];
                let app = parts[2];
                let uid: u32 = parts.get(3).and_then(|s| s.parse().ok()).unwrap_or(0);
                let cat = match cat_name {
                    "browser" | "web" => Some(defaultapps::AppCategory::WebBrowser),
                    "email" | "mail" => Some(defaultapps::AppCategory::EmailClient),
                    "files" | "filemgr" => Some(defaultapps::AppCategory::FileManager),
                    "editor" | "text" => Some(defaultapps::AppCategory::TextEditor),
                    "terminal" | "term" => Some(defaultapps::AppCategory::Terminal),
                    "image" | "viewer" => Some(defaultapps::AppCategory::ImageViewer),
                    "video" => Some(defaultapps::AppCategory::VideoPlayer),
                    "music" | "audio" => Some(defaultapps::AppCategory::MusicPlayer),
                    "pdf" => Some(defaultapps::AppCategory::PdfViewer),
                    "archive" | "zip" => Some(defaultapps::AppCategory::ArchiveManager),
                    _ => None,
                };
                match cat {
                    Some(c) => match defaultapps::set_category_default(c, app, uid) {
                        Ok(()) => shell_println!("{} → {}", c.label(), app),
                        Err(e) => shell_println!("Error: {:?}", e),
                    },
                    None => shell_println!("Unknown category '{}'. Try: browser email files editor terminal image video music pdf archive", cat_name),
                }
            } else {
                shell_println!("Usage: defaultapps category <type> <app> [uid]");
            }
        }
        "search" => {
            if let Some(query) = parts.get(1) {
                let results = defaultapps::search(query);
                if results.is_empty() {
                    shell_println!("No matches for '{}'.", query);
                } else {
                    for d in &results {
                        let user = if d.user_override { format!(" (user {})", d.uid) } else { String::new() };
                        shell_println!("  {} → {}{}", d.content_type, d.app_id, user);
                    }
                }
            } else {
                shell_println!("Usage: defaultapps search <query>");
            }
        }
        "stats" => {
            let (types, cats, overrides, ops) = defaultapps::stats();
            shell_println!("Default apps stats: types={} categories={} overrides={} ops={}", types, cats, overrides, ops);
        }
        "test" => {
            defaultapps::self_test();
            shell_println!("defaultapps: self-tests completed (see serial).");
        }
        "init" => {
            defaultapps::init_defaults();
            shell_println!("Default apps initialized.");
        }
        _ => {
            shell_println!("defaultapps (defapp) — default applications");
            shell_println!("  show                       Overview");
            shell_println!("  list                       Category defaults");
            shell_println!("  get <mime> [uid]           Get default for type");
            shell_println!("  set <mime> <app> [uid]     Set default for type");
            shell_println!("  rm <mime> [uid]            Remove default");
            shell_println!("  category <cat> <app> [uid] Set category default");
            shell_println!("  search <query>             Search mappings");
            shell_println!("  stats / test / init");
        }
    }
}

/// `monitors` / `monitor` — multi-monitor layout and configuration.
fn cmd_monitors(args: &str) {
    use crate::fs::monitors;
    use alloc::format;

    let parts: Vec<&str> = args.split_whitespace().collect();
    let sub = parts.first().copied().unwrap_or("");

    match sub {
        "show" | "" => {
            let (total, enabled, mode, primary_id, ops) = monitors::stats();
            let (bx, by, bw, bh) = monitors::desktop_bounds();
            shell_println!("=== Monitor Layout ===");
            shell_println!("  Monitors  : {} ({} enabled)", total, enabled);
            shell_println!("  Layout    : {}", mode);
            shell_println!("  Primary   : #{}", primary_id);
            shell_println!("  Desktop   : {}x{} at ({},{})", bw, bh, bx, by);
            shell_println!("  Operations: {}", ops);

            let mons = monitors::list_monitors();
            for m in &mons {
                let flags = format!("{}{}",
                    if m.primary { " [primary]" } else { "" },
                    if !m.enabled { " [disabled]" } else { "" });
                shell_println!("  #{} {} — {}x{}@{}Hz pos=({},{}) scale={}% {} rot={}{}",
                    m.id, m.name, m.width, m.height, m.refresh_hz,
                    m.x, m.y, m.scale_pct, m.connector.label(),
                    m.rotation.label(), flags);
            }
        }
        "list" => {
            let mons = monitors::list_monitors();
            for m in &mons {
                let p = if m.primary { "*" } else { " " };
                shell_println!("{} #{} {} — {}x{}@{}Hz {}", p, m.id, m.name, m.width, m.height, m.refresh_hz, m.connector.label());
            }
        }
        "primary" => {
            if let Some(id) = parts.get(1).and_then(|s| s.parse::<u32>().ok()) {
                match monitors::set_primary(id) {
                    Ok(()) => shell_println!("Primary display: #{}", id),
                    Err(e) => shell_println!("Error: {:?}", e),
                }
            } else {
                shell_println!("Usage: monitors primary <id>");
            }
        }
        "add" => {
            // monitors add <name> <connector> <output> <width> <height> <hz>
            if parts.len() >= 7 {
                let name = parts[1];
                let conn = match parts[2] {
                    "hdmi" => monitors::ConnectorType::Hdmi,
                    "dp" => monitors::ConnectorType::DisplayPort,
                    "vga" => monitors::ConnectorType::Vga,
                    "dvi" => monitors::ConnectorType::Dvi,
                    "usbc" => monitors::ConnectorType::UsbC,
                    _ => monitors::ConnectorType::Hdmi,
                };
                let output = parts[3];
                let w: u32 = parts[4].parse().unwrap_or(1920);
                let h: u32 = parts[5].parse().unwrap_or(1080);
                let hz: u32 = parts[6].parse().unwrap_or(60);
                match monitors::add_monitor(name, conn, output, w, h, hz) {
                    Ok(id) => shell_println!("Added monitor #{}: {} {}x{}@{}Hz", id, name, w, h, hz),
                    Err(e) => shell_println!("Error: {:?}", e),
                }
            } else {
                shell_println!("Usage: monitors add <name> <hdmi|dp|vga|dvi|usbc> <output> <w> <h> <hz>");
            }
        }
        "rm" | "remove" => {
            if let Some(id) = parts.get(1).and_then(|s| s.parse::<u32>().ok()) {
                match monitors::remove_monitor(id) {
                    Ok(()) => shell_println!("Removed monitor #{}", id),
                    Err(e) => shell_println!("Error: {:?}", e),
                }
            } else {
                shell_println!("Usage: monitors rm <id>");
            }
        }
        "mode" | "res" => {
            // monitors mode <id> <w> <h> [hz]
            if parts.len() >= 4 {
                let id: u32 = parts[1].parse().unwrap_or(0);
                let w: u32 = parts[2].parse().unwrap_or(0);
                let h: u32 = parts[3].parse().unwrap_or(0);
                let hz: u32 = parts.get(4).and_then(|s| s.parse().ok()).unwrap_or(60);
                match monitors::set_mode(id, w, h, hz) {
                    Ok(()) => shell_println!("Monitor #{}: {}x{}@{}Hz", id, w, h, hz),
                    Err(e) => shell_println!("Error: {:?}", e),
                }
            } else {
                shell_println!("Usage: monitors mode <id> <width> <height> [hz]");
            }
        }
        "pos" | "position" => {
            if parts.len() >= 4 {
                let id: u32 = parts[1].parse().unwrap_or(0);
                let x: i32 = parts[2].parse().unwrap_or(0);
                let y: i32 = parts[3].parse().unwrap_or(0);
                match monitors::set_position(id, x, y) {
                    Ok(()) => shell_println!("Monitor #{}: position ({},{})", id, x, y),
                    Err(e) => shell_println!("Error: {:?}", e),
                }
            } else {
                shell_println!("Usage: monitors pos <id> <x> <y>");
            }
        }
        "scale" => {
            if parts.len() >= 3 {
                let id: u32 = parts[1].parse().unwrap_or(0);
                let pct: u32 = parts[2].parse().unwrap_or(100);
                match monitors::set_scale(id, pct) {
                    Ok(()) => shell_println!("Monitor #{}: scale {}%", id, pct),
                    Err(e) => shell_println!("Error: {:?}", e),
                }
            } else {
                shell_println!("Usage: monitors scale <id> <pct>");
            }
        }
        "rotate" => {
            if parts.len() >= 3 {
                let id: u32 = parts[1].parse().unwrap_or(0);
                let rot = match parts[2] {
                    "normal" | "0" => monitors::Rotation::Normal,
                    "right" | "90" => monitors::Rotation::Right,
                    "inverted" | "180" => monitors::Rotation::Inverted,
                    "left" | "270" => monitors::Rotation::Left,
                    _ => monitors::Rotation::Normal,
                };
                match monitors::set_rotation(id, rot) {
                    Ok(()) => shell_println!("Monitor #{}: rotation {}", id, rot.label()),
                    Err(e) => shell_println!("Error: {:?}", e),
                }
            } else {
                shell_println!("Usage: monitors rotate <id> <normal|right|inverted|left>");
            }
        }
        "layout" => {
            match parts.get(1).copied() {
                Some("extend") => { let _ = monitors::set_layout_mode(monitors::LayoutMode::Extend); shell_println!("Layout: Extend"); }
                Some("mirror") => { let _ = monitors::set_layout_mode(monitors::LayoutMode::Mirror); shell_println!("Layout: Mirror"); }
                Some("single") => { let _ = monitors::set_layout_mode(monitors::LayoutMode::Single); shell_println!("Layout: Single"); }
                _ => shell_println!("Usage: monitors layout <extend|mirror|single>"),
            }
        }
        "arrange" => {
            match monitors::auto_arrange() {
                Ok(()) => shell_println!("Monitors auto-arranged."),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "enable" => {
            if let Some(id) = parts.get(1).and_then(|s| s.parse::<u32>().ok()) {
                let _ = monitors::set_enabled(id, true);
                shell_println!("Monitor #{} enabled.", id);
            } else {
                shell_println!("Usage: monitors enable <id>");
            }
        }
        "disable" => {
            if let Some(id) = parts.get(1).and_then(|s| s.parse::<u32>().ok()) {
                match monitors::set_enabled(id, false) {
                    Ok(()) => shell_println!("Monitor #{} disabled.", id),
                    Err(e) => shell_println!("Error: {:?}", e),
                }
            } else {
                shell_println!("Usage: monitors disable <id>");
            }
        }
        "stats" => {
            let (total, enabled, mode, primary, ops) = monitors::stats();
            shell_println!("Monitor stats: total={} enabled={} mode={} primary={} ops={}", total, enabled, mode, primary, ops);
        }
        "test" => {
            monitors::self_test();
            shell_println!("monitors: self-tests completed (see serial).");
        }
        "init" => {
            monitors::init_defaults();
            shell_println!("Monitor layout initialized.");
        }
        _ => {
            shell_println!("monitors (monitor) — multi-monitor layout");
            shell_println!("  show                        Layout overview");
            shell_println!("  list                        List monitors");
            shell_println!("  primary <id>                Set primary");
            shell_println!("  add <name> <conn> <out> <w> <h> <hz>  Add monitor");
            shell_println!("  rm <id>                     Remove monitor");
            shell_println!("  mode <id> <w> <h> [hz]      Set resolution");
            shell_println!("  pos <id> <x> <y>            Set position");
            shell_println!("  scale <id> <pct>            Set scale %");
            shell_println!("  rotate <id> <dir>           Rotate display");
            shell_println!("  layout <extend|mirror|single>  Layout mode");
            shell_println!("  arrange                     Auto-arrange");
            shell_println!("  enable/disable <id>");
            shell_println!("  stats / test / init");
        }
    }
}

/// `fwsettings` / `firewall` — firewall settings and rules.
fn cmd_fwsettings(args: &str) {
    use crate::fs::fwsettings;
    use alloc::format;

    let parts: Vec<&str> = args.split_whitespace().collect();
    let sub = parts.first().copied().unwrap_or("");

    match sub {
        "show" | "" => {
            let (rules, apps, blocked, allowed, enabled, ops) = fwsettings::stats();
            shell_println!("=== Firewall Settings ===");
            shell_println!("  Enabled        : {}", enabled);
            shell_println!("  Zone           : {}", fwsettings::active_zone().label());
            shell_println!("  Rules          : {}", rules);
            shell_println!("  App perms      : {}", apps);
            shell_println!("  Blocked        : {}", blocked);
            shell_println!("  Allowed        : {}", allowed);
            shell_println!("  Operations     : {}", ops);
        }
        "on" => {
            let _ = fwsettings::set_enabled(true);
            shell_println!("Firewall enabled.");
        }
        "off" => {
            let _ = fwsettings::set_enabled(false);
            shell_println!("Firewall disabled.");
        }
        "zone" => {
            match parts.get(1).copied() {
                Some("home") => { let _ = fwsettings::set_zone(fwsettings::NetworkZone::Home); shell_println!("Zone: Home"); }
                Some("work") => { let _ = fwsettings::set_zone(fwsettings::NetworkZone::Work); shell_println!("Zone: Work"); }
                Some("public") => { let _ = fwsettings::set_zone(fwsettings::NetworkZone::Public); shell_println!("Zone: Public"); }
                _ => shell_println!("Usage: firewall zone <home|work|public>"),
            }
        }
        "rules" => {
            let rules = fwsettings::list_rules();
            if rules.is_empty() {
                shell_println!("No firewall rules.");
            } else {
                shell_println!("{:>4} {:<20} {:>8} {:>5} {:>6} {:>6} {:>7} {:>5}",
                    "ID", "NAME", "DIR", "PROTO", "PORT", "ACTION", "ZONE", "HITS");
                for r in &rules {
                    let zone = r.zone.map_or("all".into(), |z| String::from(z.label()));
                    let port_str = if r.port == 0 { String::from("*") } else if r.port_end != 0 { format!("{}-{}", r.port, r.port_end) } else { format!("{}", r.port) };
                    let en = if r.enabled { "" } else { " [off]" };
                    shell_println!("{:>4} {:<20} {:>8} {:>5} {:>6} {:>6} {:>7} {:>5}{}",
                        r.id, r.name, r.direction.label(), r.protocol.label(),
                        port_str, r.action.label(), zone, r.hits, en);
                }
            }
        }
        "add" => {
            // firewall add <name> <in|out|both> <tcp|udp|icmp|any> <port> <allow|block>
            if parts.len() >= 6 {
                let name = parts[1];
                let dir = match parts[2] {
                    "in" => fwsettings::Direction::Inbound,
                    "out" => fwsettings::Direction::Outbound,
                    _ => fwsettings::Direction::Both,
                };
                let proto = match parts[3] {
                    "tcp" => fwsettings::Protocol::Tcp,
                    "udp" => fwsettings::Protocol::Udp,
                    "icmp" => fwsettings::Protocol::Icmp,
                    _ => fwsettings::Protocol::Any,
                };
                let port: u16 = parts[4].parse().unwrap_or(0);
                let action = match parts[5] {
                    "block" => fwsettings::RuleAction::Block,
                    "log" => fwsettings::RuleAction::Log,
                    _ => fwsettings::RuleAction::Allow,
                };
                match fwsettings::add_rule(name, dir, proto, port, action) {
                    Ok(id) => shell_println!("Rule #{} added: {} {} {} port {} {}",
                        id, name, dir.label(), proto.label(), port, action.label()),
                    Err(e) => shell_println!("Error: {:?}", e),
                }
            } else {
                shell_println!("Usage: firewall add <name> <in|out|both> <tcp|udp|icmp|any> <port> <allow|block>");
            }
        }
        "rm" | "remove" => {
            if let Some(id) = parts.get(1).and_then(|s| s.parse::<u64>().ok()) {
                match fwsettings::remove_rule(id) {
                    Ok(()) => shell_println!("Rule #{} removed.", id),
                    Err(e) => shell_println!("Error: {:?}", e),
                }
            } else {
                shell_println!("Usage: firewall rm <id>");
            }
        }
        "enable" => {
            if let Some(id) = parts.get(1).and_then(|s| s.parse::<u64>().ok()) {
                let _ = fwsettings::set_rule_enabled(id, true);
                shell_println!("Rule #{} enabled.", id);
            }
        }
        "disable" => {
            if let Some(id) = parts.get(1).and_then(|s| s.parse::<u64>().ok()) {
                let _ = fwsettings::set_rule_enabled(id, false);
                shell_println!("Rule #{} disabled.", id);
            }
        }
        "app" => {
            match parts.get(1).copied() {
                Some("list") => {
                    let perms = fwsettings::list_app_permissions();
                    if perms.is_empty() {
                        shell_println!("No app permissions.");
                    } else {
                        shell_println!("{:<20} {:>4} {:>4} {:>8} {:>8}", "APP", "OUT", "IN", "BLOCKED", "ALLOWED");
                        for p in &perms {
                            shell_println!("{:<20} {:>4} {:>4} {:>8} {:>8}",
                                p.app_id,
                                if p.allow_outbound { "yes" } else { "no" },
                                if p.allow_inbound { "yes" } else { "no" },
                                p.blocked_count, p.allowed_count);
                        }
                    }
                }
                Some("allow") if parts.len() >= 3 => {
                    let app = parts[2];
                    let _ = fwsettings::set_app_permission(app, true, true);
                    shell_println!("App '{}': allow all.", app);
                }
                Some("block") if parts.len() >= 3 => {
                    let app = parts[2];
                    let _ = fwsettings::set_app_permission(app, false, false);
                    shell_println!("App '{}': block all.", app);
                }
                Some("outonly") if parts.len() >= 3 => {
                    let app = parts[2];
                    let _ = fwsettings::set_app_permission(app, true, false);
                    shell_println!("App '{}': outbound only.", app);
                }
                Some("rm") if parts.len() >= 3 => {
                    let app = parts[2];
                    let _ = fwsettings::remove_app_permission(app);
                    shell_println!("App '{}' permission removed.", app);
                }
                _ => shell_println!("Usage: firewall app <list|allow|block|outonly|rm> [app_id]"),
            }
        }
        "stealth" => {
            let val = !matches!(parts.get(1).copied(), Some("off") | Some("no"));
            let _ = fwsettings::set_stealth_mode(val);
            shell_println!("Stealth mode: {}", val);
        }
        "stats" => {
            let (rules, apps, blocked, allowed, enabled, ops) = fwsettings::stats();
            shell_println!("Firewall stats: rules={} apps={} blocked={} allowed={} enabled={} ops={}", rules, apps, blocked, allowed, enabled, ops);
        }
        "test" => {
            fwsettings::self_test();
            shell_println!("fwsettings: self-tests completed (see serial).");
        }
        "init" => {
            fwsettings::init_defaults();
            shell_println!("Firewall initialized.");
        }
        _ => {
            shell_println!("fwsettings (firewall) — firewall settings");
            shell_println!("  show                       Overview");
            shell_println!("  on / off                   Enable/disable");
            shell_println!("  zone <home|work|public>    Set zone");
            shell_println!("  rules                      List rules");
            shell_println!("  add <name> <dir> <proto> <port> <action>");
            shell_println!("  rm <id>                    Remove rule");
            shell_println!("  enable/disable <id>        Rule on/off");
            shell_println!("  app list/allow/block/outonly/rm <app>");
            shell_println!("  stealth <on|off>           Stealth mode");
            shell_println!("  stats / test / init");
        }
    }
}

/// `updatemgr` / `updates` — system update management.
fn cmd_updatemgr(args: &str) {
    use crate::fs::updatemgr;

    let parts: Vec<&str> = args.split_whitespace().collect();
    let sub = parts.first().copied().unwrap_or("");

    match sub {
        "show" | "" => {
            let (pending, history, version, channel, auto, ops) = updatemgr::stats();
            let (crit, imp, rec, opt) = updatemgr::pending_count();
            shell_println!("=== System Updates ===");
            shell_println!("  OS Version     : {}", version);
            shell_println!("  Channel        : {}", channel);
            shell_println!("  Auto-check     : {}", auto);
            shell_println!("  Pending        : {} ({}C {}I {}R {}O)", pending, crit, imp, rec, opt);
            shell_println!("  Download size  : {}", updatemgr::format_update_size(updatemgr::pending_size()));
            shell_println!("  History        : {}", history);
            shell_println!("  Operations     : {}", ops);
        }
        "list" => {
            let updates = updatemgr::list_updates();
            if updates.is_empty() {
                shell_println!("No pending updates.");
            } else {
                shell_println!("{:>4} {:<20} {:>10} {:>10} {:>10} {:>12} {:>7}",
                    "ID", "PACKAGE", "FROM", "TO", "STATUS", "SIZE", "SEV");
                for u in &updates {
                    shell_println!("{:>4} {:<20} {:>10} {:>10} {:>10} {:>12} {:>7}",
                        u.id, u.package, u.from_version, u.to_version,
                        u.status.label(), updatemgr::format_update_size(u.size_bytes),
                        u.severity.label());
                }
            }
        }
        "check" => {
            match updatemgr::check_updates() {
                Ok(count) => shell_println!("{} updates pending.", count),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "install" => {
            if let Some(id) = parts.get(1).and_then(|s| s.parse::<u64>().ok()) {
                match updatemgr::install_update(id) {
                    Ok(()) => shell_println!("Update #{} installed.", id),
                    Err(e) => shell_println!("Error: {:?}", e),
                }
            } else {
                shell_println!("Usage: updates install <id>");
            }
        }
        "download" => {
            if let Some(id) = parts.get(1).and_then(|s| s.parse::<u64>().ok()) {
                match updatemgr::download_update(id) {
                    Ok(()) => shell_println!("Download started for update #{}.", id),
                    Err(e) => shell_println!("Error: {:?}", e),
                }
            } else {
                shell_println!("Usage: updates download <id>");
            }
        }
        "defer" => {
            if let Some(id) = parts.get(1).and_then(|s| s.parse::<u64>().ok()) {
                match updatemgr::defer_update(id) {
                    Ok(()) => shell_println!("Update #{} deferred.", id),
                    Err(e) => shell_println!("Error: {:?}", e),
                }
            } else {
                shell_println!("Usage: updates defer <id>");
            }
        }
        "info" => {
            if let Some(id) = parts.get(1).and_then(|s| s.parse::<u64>().ok()) {
                match updatemgr::get_update(id) {
                    Ok(u) => {
                        shell_println!("Update #{}: {} {} → {}", u.id, u.package, u.from_version, u.to_version);
                        shell_println!("  Type     : {}", u.update_type.label());
                        shell_println!("  Severity : {}", u.severity.label());
                        shell_println!("  Status   : {}", u.status.label());
                        shell_println!("  Size     : {}", updatemgr::format_update_size(u.size_bytes));
                        shell_println!("  Restart  : {}", u.requires_restart);
                        if !u.description.is_empty() {
                            shell_println!("  Desc     : {}", u.description);
                        }
                    }
                    Err(e) => shell_println!("Error: {:?}", e),
                }
            } else {
                shell_println!("Usage: updates info <id>");
            }
        }
        "history" => {
            let history = updatemgr::update_history();
            if history.is_empty() {
                shell_println!("No update history.");
            } else {
                for u in &history {
                    shell_println!("  {} {} → {} [{}]", u.package, u.from_version, u.to_version, u.status.label());
                }
            }
        }
        "channel" => {
            match parts.get(1).copied() {
                Some("stable") => { let _ = updatemgr::set_channel(updatemgr::UpdateChannel::Stable); shell_println!("Channel: Stable"); }
                Some("beta") => { let _ = updatemgr::set_channel(updatemgr::UpdateChannel::Beta); shell_println!("Channel: Beta"); }
                Some("nightly") => { let _ = updatemgr::set_channel(updatemgr::UpdateChannel::Nightly); shell_println!("Channel: Nightly"); }
                _ => shell_println!("Usage: updates channel <stable|beta|nightly>"),
            }
        }
        "auto" => {
            match parts.get(1).copied() {
                Some("on") | Some("yes") => { let _ = updatemgr::set_auto_check(true); shell_println!("Auto-check: on"); }
                Some("off") | Some("no") => { let _ = updatemgr::set_auto_check(false); shell_println!("Auto-check: off"); }
                _ => {
                    if let Ok(cfg) = updatemgr::get_config() {
                        shell_println!("Auto-check: {} (every {} hours)", cfg.auto_check, cfg.check_interval_hours);
                        shell_println!("Auto-download: {}", cfg.auto_download);
                        shell_println!("Auto-install: {}", cfg.auto_install);
                        shell_println!("Auto-install security: {}", cfg.auto_install_security);
                    }
                }
            }
        }
        "version" => {
            shell_println!("OS: {}", updatemgr::os_version());
        }
        "archive" => {
            match updatemgr::archive_completed() {
                Ok(n) => shell_println!("Archived {} completed updates.", n),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "stats" => {
            let (pending, history, version, channel, auto, ops) = updatemgr::stats();
            shell_println!("Update stats: pending={} history={} version={} channel={} auto={} ops={}", pending, history, version, channel, auto, ops);
        }
        "test" => {
            updatemgr::self_test();
            shell_println!("updatemgr: self-tests completed (see serial).");
        }
        "init" => {
            updatemgr::init_defaults();
            shell_println!("Update manager initialized.");
        }
        _ => {
            shell_println!("updatemgr (updates) — system update management");
            shell_println!("  show                Overview");
            shell_println!("  list                Pending updates");
            shell_println!("  check               Check for updates");
            shell_println!("  install <id>        Install update");
            shell_println!("  download <id>       Download update");
            shell_println!("  defer <id>          Defer update");
            shell_println!("  info <id>           Update details");
            shell_println!("  history             Update history");
            shell_println!("  channel <ch>        Set update channel");
            shell_println!("  auto [on|off]       Auto-check settings");
            shell_println!("  version             OS version");
            shell_println!("  archive             Archive completed");
            shell_println!("  stats / test / init");
        }
    }
}

/// `notifprefs` / `nprefs` — per-app notification preferences.
fn cmd_notifprefs(args: &str) {
    use crate::fs::notifprefs;

    let parts: Vec<&str> = args.split_whitespace().collect();
    let sub = parts.first().copied().unwrap_or("");

    match sub {
        "show" | "" => {
            let (apps, sounds, pos, timeout, ops) = notifprefs::stats();
            shell_println!("=== Notification Preferences ===");
            shell_println!("  App prefs      : {}", apps);
            shell_println!("  Sounds         : {}", sounds);
            shell_println!("  Position       : {}", pos);
            shell_println!("  Dismiss timeout: {} s", timeout);
            shell_println!("  Operations     : {}", ops);
            if let Ok(cfg) = notifprefs::global_config() {
                shell_println!("  Lock screen    : {}", cfg.show_on_lock_screen);
                shell_println!("  Show count     : {}", cfg.show_count);
                shell_println!("  Max visible    : {}", cfg.max_visible);
            }
        }
        "list" => {
            let prefs = notifprefs::list_app_prefs();
            if prefs.is_empty() {
                shell_println!("No per-app notification preferences.");
            } else {
                shell_println!("{:<20} {:>7} {:>6} {:>5} {:>8} {:>6} {:>8}",
                    "APP", "ENABLED", "BANNER", "SOUND", "PRIORITY", "DND-OV", "TOTAL");
                for p in &prefs {
                    shell_println!("{:<20} {:>7} {:>6} {:>5} {:>8} {:>6} {:>8}",
                        p.app_id, p.enabled, p.banner_style.label(),
                        p.sound, p.priority.label(),
                        p.dnd_override, p.total_count);
                }
            }
        }
        "app" => {
            if let Some(app_id) = parts.get(1) {
                let pref = notifprefs::get_app_pref(app_id).unwrap();
                shell_println!("App: {}", pref.app_id);
                shell_println!("  Enabled    : {}", pref.enabled);
                shell_println!("  Banner     : {}", pref.banner_style.label());
                shell_println!("  Sound      : {}", pref.sound);
                shell_println!("  Priority   : {}", pref.priority.label());
                shell_println!("  Lock screen: {}", pref.lock_screen.label());
                shell_println!("  DND override: {}", pref.dnd_override);
                shell_println!("  Group      : {}", pref.group);
                shell_println!("  Total      : {}", pref.total_count);
                shell_println!("  Suppressed : {}", pref.suppressed_count);
            } else {
                shell_println!("Usage: notifprefs app <app_id>");
            }
        }
        "enable" => {
            if let Some(app_id) = parts.get(1) {
                let _ = notifprefs::set_app_enabled(app_id, true);
                shell_println!("Notifications enabled for '{}'.", app_id);
            } else {
                shell_println!("Usage: notifprefs enable <app_id>");
            }
        }
        "disable" => {
            if let Some(app_id) = parts.get(1) {
                let _ = notifprefs::set_app_enabled(app_id, false);
                shell_println!("Notifications disabled for '{}'.", app_id);
            } else {
                shell_println!("Usage: notifprefs disable <app_id>");
            }
        }
        "banner" => {
            // notifprefs banner <app> <full|brief|none>
            if parts.len() >= 3 {
                let app = parts[1];
                let style = match parts[2] {
                    "brief" => notifprefs::BannerStyle::Brief,
                    "none" | "off" => notifprefs::BannerStyle::None,
                    _ => notifprefs::BannerStyle::Full,
                };
                let _ = notifprefs::set_banner_style(app, style);
                shell_println!("Banner for '{}': {}", app, style.label());
            } else {
                shell_println!("Usage: notifprefs banner <app> <full|brief|none>");
            }
        }
        "priority" => {
            if parts.len() >= 3 {
                let app = parts[1];
                let pri = match parts[2] {
                    "critical" => notifprefs::NotifPriority::Critical,
                    "high" => notifprefs::NotifPriority::High,
                    "low" => notifprefs::NotifPriority::Low,
                    "silent" => notifprefs::NotifPriority::Silent,
                    _ => notifprefs::NotifPriority::Normal,
                };
                let _ = notifprefs::set_app_priority(app, pri);
                shell_println!("Priority for '{}': {}", app, pri.label());
            } else {
                shell_println!("Usage: notifprefs priority <app> <critical|high|normal|low|silent>");
            }
        }
        "sound" => {
            match parts.get(1).copied() {
                Some("on") | Some("yes") => {
                    let _ = notifprefs::set_sounds_enabled(true);
                    shell_println!("Global notification sounds: on");
                }
                Some("off") | Some("no") => {
                    let _ = notifprefs::set_sounds_enabled(false);
                    shell_println!("Global notification sounds: off");
                }
                Some(app) if parts.len() >= 3 => {
                    let val = !matches!(parts[2], "off" | "no" | "false");
                    let _ = notifprefs::set_app_sound(app, val);
                    shell_println!("Sound for '{}': {}", app, val);
                }
                _ => shell_println!("Usage: notifprefs sound <on|off> OR notifprefs sound <app> <on|off>"),
            }
        }
        "position" | "pos" => {
            match parts.get(1).copied() {
                Some("tr") | Some("topright") => { let _ = notifprefs::set_position(notifprefs::NotifPosition::TopRight); shell_println!("Position: Top Right"); }
                Some("tl") | Some("topleft") => { let _ = notifprefs::set_position(notifprefs::NotifPosition::TopLeft); shell_println!("Position: Top Left"); }
                Some("br") | Some("bottomright") => { let _ = notifprefs::set_position(notifprefs::NotifPosition::BottomRight); shell_println!("Position: Bottom Right"); }
                Some("bl") | Some("bottomleft") => { let _ = notifprefs::set_position(notifprefs::NotifPosition::BottomLeft); shell_println!("Position: Bottom Left"); }
                _ => shell_println!("Usage: notifprefs position <tr|tl|br|bl>"),
            }
        }
        "timeout" => {
            if let Some(val) = parts.get(1).and_then(|s| s.parse::<u32>().ok()) {
                let _ = notifprefs::set_dismiss_timeout(val);
                shell_println!("Dismiss timeout: {} s", val);
            } else {
                shell_println!("Usage: notifprefs timeout <seconds>");
            }
        }
        "rm" | "remove" => {
            if let Some(app) = parts.get(1) {
                match notifprefs::remove_app_pref(app) {
                    Ok(()) => shell_println!("Preferences removed for '{}'.", app),
                    Err(e) => shell_println!("Error: {:?}", e),
                }
            } else {
                shell_println!("Usage: notifprefs rm <app_id>");
            }
        }
        "stats" => {
            let (apps, sounds, pos, timeout, ops) = notifprefs::stats();
            shell_println!("Notif prefs: apps={} sounds={} pos={} timeout={} ops={}", apps, sounds, pos, timeout, ops);
        }
        "test" => {
            notifprefs::self_test();
            shell_println!("notifprefs: self-tests completed (see serial).");
        }
        "init" => {
            notifprefs::init_defaults();
            shell_println!("Notification preferences initialized.");
        }
        _ => {
            shell_println!("notifprefs (nprefs) — notification preferences");
            shell_println!("  show                       Overview");
            shell_println!("  list                       All app prefs");
            shell_println!("  app <id>                   App details");
            shell_println!("  enable/disable <app>       Toggle app");
            shell_println!("  banner <app> <full|brief|none>");
            shell_println!("  priority <app> <level>     Set priority");
            shell_println!("  sound <on|off>             Global sounds");
            shell_println!("  sound <app> <on|off>       App sound");
            shell_println!("  position <tr|tl|br|bl>     Display position");
            shell_println!("  timeout <seconds>          Auto-dismiss");
            shell_println!("  rm <app>                   Remove app prefs");
            shell_println!("  stats / test / init");
        }
    }
}

/// `fileshare` / `share` — network file sharing.
fn cmd_fileshare(args: &str) {
    use crate::fs::fileshare;

    let parts: Vec<&str> = args.split_whitespace().collect();
    let sub = parts.first().copied().unwrap_or("");

    match sub {
        "show" | "" => {
            let (local, remote, enabled, connected, ops) = fileshare::stats();
            shell_println!("=== File Sharing ===");
            shell_println!("  Sharing enabled  : {}", enabled);
            shell_println!("  Hostname         : {}", fileshare::hostname());
            shell_println!("  Local shares     : {}", local);
            shell_println!("  Remote mounts    : {} ({} connected)", remote, connected);
            shell_println!("  Operations       : {}", ops);
        }
        "on" => {
            let _ = fileshare::set_sharing_enabled(true);
            shell_println!("File sharing enabled.");
        }
        "off" => {
            let _ = fileshare::set_sharing_enabled(false);
            shell_println!("File sharing disabled.");
        }
        "hostname" => {
            if let Some(name) = parts.get(1) {
                match fileshare::set_hostname(name) {
                    Ok(()) => shell_println!("Hostname: {}", name),
                    Err(e) => shell_println!("Error: {:?}", e),
                }
            } else {
                shell_println!("Hostname: {}", fileshare::hostname());
            }
        }
        "list" => {
            let shares = fileshare::list_shares();
            if shares.is_empty() {
                shell_println!("No local shares.");
            } else {
                shell_println!("{:>4} {:<16} {:<30} {:>5} {:>10} {:>7}",
                    "ID", "NAME", "PATH", "PROTO", "ACCESS", "ENABLED");
                for s in &shares {
                    shell_println!("{:>4} {:<16} {:<30} {:>5} {:>10} {:>7}",
                        s.id, s.name, s.path, s.protocol.label(),
                        s.access.label(), s.enabled);
                }
            }
        }
        "add" => {
            // share add <name> <path> [smb|nfs]
            if parts.len() >= 3 {
                let name = parts[1];
                let path = parts[2];
                let proto = match parts.get(3).copied() {
                    Some("nfs") => fileshare::ShareProtocol::Nfs,
                    Some("webdav") => fileshare::ShareProtocol::WebDav,
                    Some("sftp") => fileshare::ShareProtocol::Sftp,
                    _ => fileshare::ShareProtocol::Smb,
                };
                match fileshare::add_share(name, path, proto, fileshare::ShareAccess::ReadOnly) {
                    Ok(id) => shell_println!("Share #{} '{}' created ({}).", id, name, proto.label()),
                    Err(e) => shell_println!("Error: {:?}", e),
                }
            } else {
                shell_println!("Usage: share add <name> <path> [smb|nfs|webdav|sftp]");
            }
        }
        "rm" | "remove" => {
            if let Some(id) = parts.get(1).and_then(|s| s.parse::<u32>().ok()) {
                match fileshare::remove_share(id) {
                    Ok(()) => shell_println!("Share #{} removed.", id),
                    Err(e) => shell_println!("Error: {:?}", e),
                }
            } else {
                shell_println!("Usage: share rm <id>");
            }
        }
        "access" => {
            if parts.len() >= 3 {
                let id: u32 = parts[1].parse().unwrap_or(0);
                let access = match parts[2] {
                    "rw" | "readwrite" => fileshare::ShareAccess::ReadWrite,
                    "full" => fileshare::ShareAccess::FullControl,
                    _ => fileshare::ShareAccess::ReadOnly,
                };
                let _ = fileshare::set_share_access(id, access);
                shell_println!("Share #{}: {}", id, access.label());
            } else {
                shell_println!("Usage: share access <id> <ro|rw|full>");
            }
        }
        "guest" => {
            if parts.len() >= 3 {
                let id: u32 = parts[1].parse().unwrap_or(0);
                let allowed = matches!(parts[2], "on" | "yes" | "true");
                let _ = fileshare::set_guest_access(id, allowed);
                shell_println!("Share #{}: guest={}", id, allowed);
            } else {
                shell_println!("Usage: share guest <id> <on|off>");
            }
        }
        "connect" => {
            // share connect <host> <sharename> <mountpoint> [smb|nfs] [user]
            if parts.len() >= 4 {
                let host = parts[1];
                let share_name = parts[2];
                let mount = parts[3];
                let proto = match parts.get(4).copied() {
                    Some("nfs") => fileshare::ShareProtocol::Nfs,
                    Some("sftp") => fileshare::ShareProtocol::Sftp,
                    _ => fileshare::ShareProtocol::Smb,
                };
                let user = parts.get(5).copied().unwrap_or("");
                match fileshare::connect_remote(host, share_name, mount, proto, user) {
                    Ok(id) => shell_println!("Connected #{}: //{}:{}/{} → {}", id, host, proto.default_port(), share_name, mount),
                    Err(e) => shell_println!("Error: {:?}", e),
                }
            } else {
                shell_println!("Usage: share connect <host> <share> <mountpoint> [proto] [user]");
            }
        }
        "disconnect" => {
            if let Some(id) = parts.get(1).and_then(|s| s.parse::<u32>().ok()) {
                let _ = fileshare::disconnect_remote(id);
                shell_println!("Disconnected remote #{}.", id);
            } else {
                shell_println!("Usage: share disconnect <id>");
            }
        }
        "remotes" => {
            let remotes = fileshare::list_remotes();
            if remotes.is_empty() {
                shell_println!("No remote connections.");
            } else {
                for r in &remotes {
                    let auto = if r.auto_mount { " [auto]" } else { "" };
                    shell_println!("  #{} //{}/{} → {} [{}] {}{}",
                        r.id, r.host, r.share_name, r.mount_point,
                        r.protocol.label(), r.status.label(), auto);
                }
            }
        }
        "stats" => {
            let (local, remote, enabled, connected, ops) = fileshare::stats();
            shell_println!("Sharing stats: local={} remote={} enabled={} connected={} ops={}", local, remote, enabled, connected, ops);
        }
        "test" => {
            fileshare::self_test();
            shell_println!("fileshare: self-tests completed (see serial).");
        }
        "init" => {
            fileshare::init_defaults();
            shell_println!("File sharing initialized.");
        }
        _ => {
            shell_println!("fileshare (share) — network file sharing");
            shell_println!("  show                       Overview");
            shell_println!("  on / off                   Enable/disable");
            shell_println!("  hostname [name]            Get/set hostname");
            shell_println!("  list                       Local shares");
            shell_println!("  add <name> <path> [proto]  Add share");
            shell_println!("  rm <id>                    Remove share");
            shell_println!("  access <id> <ro|rw|full>   Set access");
            shell_println!("  guest <id> <on|off>        Guest access");
            shell_println!("  connect <host> <share> <mount> [proto] [user]");
            shell_println!("  disconnect <id>            Disconnect");
            shell_println!("  remotes                    Remote connections");
            shell_println!("  stats / test / init");
        }
    }
}

/// `parental` / `pctl` — parental controls for child accounts.
fn cmd_parental(args: &str) {
    use crate::fs::parental;
    let parts: Vec<&str> = args.split_whitespace().collect();
    let sub = parts.first().copied().unwrap_or("");
    match sub {
        "show" | "" => {
            let profiles = parental::list_profiles();
            if profiles.is_empty() {
                shell_println!("No child profiles configured.");
            } else {
                shell_println!("{:<6} {:<16} {:<8} {:<10} {:<12} limit  used  blocked", "UID", "Name", "Active", "Filter", "App Mode");
                for p in &profiles {
                    let en = if p.enabled { "yes" } else { "no" };
                    shell_println!("{:<6} {:<16} {:<8} {:<10} {:<12} {}m    {}m    {}",
                        p.uid, p.name, en, p.filter_level.label(),
                        p.app_mode.label(), p.daily_limit_minutes,
                        p.time_used_today, p.blocked_count);
                }
            }
        }
        "create" => {
            if parts.len() < 3 {
                shell_println!("Usage: parental create <uid> <name>");
                return;
            }
            let uid: u32 = match parts[1].parse() {
                Ok(v) => v,
                Err(_) => { shell_println!("Invalid UID"); return; }
            };
            let name = parts[2];
            match parental::create_profile(uid, name) {
                Ok(()) => shell_println!("Created child profile '{}' (uid={})", name, uid),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "remove" => {
            if parts.len() < 2 {
                shell_println!("Usage: parental remove <uid>");
                return;
            }
            let uid: u32 = match parts[1].parse() {
                Ok(v) => v,
                Err(_) => { shell_println!("Invalid UID"); return; }
            };
            match parental::remove_profile(uid) {
                Ok(()) => shell_println!("Removed profile for uid={}", uid),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "enable" | "disable" => {
            if parts.len() < 2 {
                shell_println!("Usage: parental {} <uid>", sub);
                return;
            }
            let uid: u32 = match parts[1].parse() {
                Ok(v) => v,
                Err(_) => { shell_println!("Invalid UID"); return; }
            };
            let on = sub == "enable";
            match parental::set_enabled(uid, on) {
                Ok(()) => shell_println!("{} controls for uid={}", if on { "Enabled" } else { "Disabled" }, uid),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "filter" => {
            if parts.len() < 3 {
                shell_println!("Usage: parental filter <uid> <none|light|moderate|strict>");
                return;
            }
            let uid: u32 = match parts[1].parse() {
                Ok(v) => v,
                Err(_) => { shell_println!("Invalid UID"); return; }
            };
            let level = match parts[2] {
                "none" => parental::FilterLevel::None,
                "light" => parental::FilterLevel::Light,
                "moderate" => parental::FilterLevel::Moderate,
                "strict" => parental::FilterLevel::Strict,
                _ => { shell_println!("Unknown filter: {}", parts[2]); return; }
            };
            match parental::set_filter_level(uid, level) {
                Ok(()) => shell_println!("Set filter to {} for uid={}", level.label(), uid),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "blocksite" => {
            if parts.len() < 3 {
                shell_println!("Usage: parental blocksite <uid> <pattern>");
                return;
            }
            let uid: u32 = match parts[1].parse() {
                Ok(v) => v,
                Err(_) => { shell_println!("Invalid UID"); return; }
            };
            let pattern = parts[2];
            match parental::add_blocked_site(uid, pattern) {
                Ok(()) => shell_println!("Blocked site '{}' for uid={}", pattern, uid),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "unblocksite" => {
            if parts.len() < 3 {
                shell_println!("Usage: parental unblocksite <uid> <pattern>");
                return;
            }
            let uid: u32 = match parts[1].parse() {
                Ok(v) => v,
                Err(_) => { shell_println!("Invalid UID"); return; }
            };
            match parental::remove_blocked_site(uid, parts[2]) {
                Ok(()) => shell_println!("Unblocked site for uid={}", uid),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "appmode" => {
            if parts.len() < 3 {
                shell_println!("Usage: parental appmode <uid> <allowall|allowlist|blockall>");
                return;
            }
            let uid: u32 = match parts[1].parse() {
                Ok(v) => v,
                Err(_) => { shell_println!("Invalid UID"); return; }
            };
            let mode = match parts[2] {
                "allowall" => parental::AppRestrictionMode::AllowAll,
                "allowlist" => parental::AppRestrictionMode::AllowList,
                "blockall" => parental::AppRestrictionMode::BlockAll,
                _ => { shell_println!("Unknown mode: {}", parts[2]); return; }
            };
            match parental::set_app_mode(uid, mode) {
                Ok(()) => shell_println!("Set app mode to {} for uid={}", mode.label(), uid),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "blockapp" => {
            if parts.len() < 3 {
                shell_println!("Usage: parental blockapp <uid> <app_id>");
                return;
            }
            let uid: u32 = match parts[1].parse() {
                Ok(v) => v,
                Err(_) => { shell_println!("Invalid UID"); return; }
            };
            match parental::add_blocked_app(uid, parts[2]) {
                Ok(()) => shell_println!("Blocked app '{}' for uid={}", parts[2], uid),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "allowapp" => {
            if parts.len() < 3 {
                shell_println!("Usage: parental allowapp <uid> <app_id>");
                return;
            }
            let uid: u32 = match parts[1].parse() {
                Ok(v) => v,
                Err(_) => { shell_println!("Invalid UID"); return; }
            };
            match parental::add_allowed_app(uid, parts[2]) {
                Ok(()) => shell_println!("Allowed app '{}' for uid={}", parts[2], uid),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "limit" => {
            if parts.len() < 3 {
                shell_println!("Usage: parental limit <uid> <minutes>");
                return;
            }
            let uid: u32 = match parts[1].parse() {
                Ok(v) => v,
                Err(_) => { shell_println!("Invalid UID"); return; }
            };
            let mins: u32 = match parts[2].parse() {
                Ok(v) => v,
                Err(_) => { shell_println!("Invalid minutes"); return; }
            };
            match parental::set_daily_limit(uid, mins) {
                Ok(()) => shell_println!("Daily limit set to {} minutes for uid={}", mins, uid),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "schedule" => {
            if parts.len() < 5 {
                shell_println!("Usage: parental schedule <uid> <day 0-6> <start_hour> <end_hour> [max_min]");
                return;
            }
            let uid: u32 = match parts[1].parse() {
                Ok(v) => v,
                Err(_) => { shell_println!("Invalid UID"); return; }
            };
            let day: usize = match parts[2].parse() {
                Ok(v) if v < 7 => v,
                _ => { shell_println!("Invalid day (0-6)"); return; }
            };
            let start: u8 = match parts[3].parse() {
                Ok(v) => v,
                Err(_) => { shell_println!("Invalid start hour"); return; }
            };
            let end: u8 = match parts[4].parse() {
                Ok(v) => v,
                Err(_) => { shell_println!("Invalid end hour"); return; }
            };
            let max_min: u32 = if parts.len() > 5 {
                match parts[5].parse() { Ok(v) => v, Err(_) => { shell_println!("Invalid max minutes"); return; } }
            } else {
                0
            };
            match parental::set_schedule(uid, day, start, end, max_min) {
                Ok(()) => shell_println!("Schedule day {} set: {}-{} (max {}m) for uid={}", day, start, end, max_min, uid),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "check" => {
            if parts.len() < 3 {
                shell_println!("Usage: parental check <app|web|time> <uid> <value>");
                return;
            }
            let check_type = parts[1];
            let uid: u32 = match parts[2].parse() {
                Ok(v) => v,
                Err(_) => { shell_println!("Invalid UID"); return; }
            };
            match check_type {
                "app" => {
                    if parts.len() < 4 { shell_println!("Usage: parental check app <uid> <app_id>"); return; }
                    let ok = parental::check_app_allowed(uid, parts[3]);
                    shell_println!("App '{}' for uid={}: {}", parts[3], uid, if ok { "ALLOWED" } else { "BLOCKED" });
                }
                "web" => {
                    if parts.len() < 4 { shell_println!("Usage: parental check web <uid> <url>"); return; }
                    let ok = parental::check_web_allowed(uid, parts[3]);
                    shell_println!("URL '{}' for uid={}: {}", parts[3], uid, if ok { "ALLOWED" } else { "BLOCKED" });
                }
                "time" => {
                    if parts.len() < 5 { shell_println!("Usage: parental check time <uid> <hour> <day>"); return; }
                    let hour: u8 = match parts[3].parse() { Ok(v) => v, Err(_) => { shell_println!("Invalid hour"); return; } };
                    let day: usize = match parts[4].parse() { Ok(v) => v, Err(_) => { shell_println!("Invalid day"); return; } };
                    let ok = parental::check_time_allowed(uid, hour, day);
                    shell_println!("Time check hour={} day={} for uid={}: {}", hour, day, uid, if ok { "ALLOWED" } else { "BLOCKED" });
                }
                _ => shell_println!("Unknown check type: {} (app|web|time)", check_type),
            }
        }
        "profile" => {
            if parts.len() < 2 {
                shell_println!("Usage: parental profile <uid>");
                return;
            }
            let uid: u32 = match parts[1].parse() {
                Ok(v) => v,
                Err(_) => { shell_println!("Invalid UID"); return; }
            };
            match parental::get_profile(uid) {
                Ok(p) => {
                    shell_println!("Child: {} (uid={})", p.name, p.uid);
                    shell_println!("  Enabled:      {}", p.enabled);
                    shell_println!("  Filter:       {}", p.filter_level.label());
                    shell_println!("  App mode:     {}", p.app_mode.label());
                    shell_println!("  Safe search:  {}", p.safe_search);
                    shell_println!("  Daily limit:  {} minutes", p.daily_limit_minutes);
                    shell_println!("  Used today:   {} minutes", p.time_used_today);
                    shell_println!("  Blocked:      {} total", p.blocked_count);
                    if !p.blocked_apps.is_empty() {
                        shell_println!("  Blocked apps: {}", p.blocked_apps.join(", "));
                    }
                    if !p.allowed_apps.is_empty() {
                        shell_println!("  Allowed apps: {}", p.allowed_apps.join(", "));
                    }
                    if !p.blocked_sites.is_empty() {
                        shell_println!("  Blocked sites: {}", p.blocked_sites.join(", "));
                    }
                }
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "stats" => {
            let (profiles, blocked, ops) = parental::stats();
            shell_println!("Profiles: {}  Total blocked: {}  Ops: {}", profiles, blocked, ops);
        }
        "test" => {
            parental::self_test();
            shell_println!("Parental self-test complete.");
        }
        "init" => {
            parental::init_defaults();
            shell_println!("Parental controls initialized.");
        }
        "help" => {
            shell_println!("parental (pctl) — parental controls");
            shell_println!("  show                         List profiles");
            shell_println!("  create <uid> <name>          Create child profile");
            shell_println!("  remove <uid>                 Remove profile");
            shell_println!("  profile <uid>                Show profile details");
            shell_println!("  enable/disable <uid>         Toggle controls");
            shell_println!("  filter <uid> <level>         Set filter (none|light|moderate|strict)");
            shell_println!("  appmode <uid> <mode>         Set app mode (allowall|allowlist|blockall)");
            shell_println!("  blockapp <uid> <app>         Block app");
            shell_println!("  allowapp <uid> <app>         Allow app");
            shell_println!("  blocksite <uid> <pattern>    Block website");
            shell_println!("  unblocksite <uid> <pattern>  Unblock website");
            shell_println!("  limit <uid> <minutes>        Set daily limit");
            shell_println!("  schedule <uid> <day> <start> <end> [max]");
            shell_println!("  check app|web|time <uid> <value>");
            shell_println!("  stats / test / init");
        }
        _ => {
            shell_println!("Unknown subcommand: {}", sub);
            shell_println!("Use 'parental help' for usage.");
        }
    }
}

/// `audiodevice` / `adev` — audio device management.
fn cmd_audiodevice(args: &str) {
    use crate::fs::audiodevice;
    let parts: Vec<&str> = args.split_whitespace().collect();
    let sub = parts.first().copied().unwrap_or("");
    match sub {
        "show" | "" => {
            let devices = audiodevice::list_devices();
            if devices.is_empty() {
                shell_println!("No audio devices.");
            } else {
                shell_println!("{:<4} {:<24} {:<10} {:<8} {:<6} {:<6} {}", "ID", "Name", "Type", "Dir", "Vol", "Muted", "");
                for d in &devices {
                    let def = if d.is_default { " *default" } else { "" };
                    shell_println!("{:<4} {:<24} {:<10} {:<8} {:<6} {:<6}{}",
                        d.id, d.name, d.device_type.label(), d.direction.label(),
                        d.volume, d.muted, def);
                }
            }
        }
        "outputs" => {
            let devices = audiodevice::output_devices();
            if devices.is_empty() {
                shell_println!("No output devices.");
            } else {
                for d in &devices {
                    let def = if d.is_default { " *" } else { "" };
                    shell_println!("{}: {} (vol={}, {}){}", d.id, d.name,
                        d.volume, d.sample_rate.label(), def);
                }
            }
        }
        "inputs" => {
            let devices = audiodevice::input_devices();
            if devices.is_empty() {
                shell_println!("No input devices.");
            } else {
                for d in &devices {
                    let def = if d.is_default { " *" } else { "" };
                    shell_println!("{}: {} (vol={}, {}){}", d.id, d.name,
                        d.volume, d.sample_rate.label(), def);
                }
            }
        }
        "add" => {
            if parts.len() < 4 {
                shell_println!("Usage: audiodevice add <name> <type> <dir> [driver]");
                shell_println!("  types: speakers|mic|headphones|usb|bluetooth|hdmi|virtual|dac");
                shell_println!("  dirs:  output|input|duplex");
                return;
            }
            let name = parts[1];
            let dev_type = match parts[2] {
                "speakers" => audiodevice::AudioDeviceType::Speakers,
                "mic" | "microphone" => audiodevice::AudioDeviceType::Microphone,
                "headphones" => audiodevice::AudioDeviceType::Headphones,
                "usb" => audiodevice::AudioDeviceType::Usb,
                "bluetooth" | "bt" => audiodevice::AudioDeviceType::Bluetooth,
                "hdmi" => audiodevice::AudioDeviceType::Hdmi,
                "virtual" => audiodevice::AudioDeviceType::Virtual,
                "dac" => audiodevice::AudioDeviceType::ExternalDac,
                _ => { shell_println!("Unknown type: {}", parts[2]); return; }
            };
            let direction = match parts[3] {
                "output" | "out" => audiodevice::DeviceDirection::Output,
                "input" | "in" => audiodevice::DeviceDirection::Input,
                "duplex" => audiodevice::DeviceDirection::Duplex,
                _ => { shell_println!("Unknown direction: {}", parts[3]); return; }
            };
            let driver = if parts.len() > 4 { parts[4] } else { "generic" };
            match audiodevice::add_device(name, dev_type, direction, driver) {
                Ok(id) => shell_println!("Added device '{}' (id={})", name, id),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "remove" => {
            if parts.len() < 2 {
                shell_println!("Usage: audiodevice remove <id>");
                return;
            }
            let id: u32 = match parts[1].parse() {
                Ok(v) => v,
                Err(_) => { shell_println!("Invalid ID"); return; }
            };
            match audiodevice::remove_device(id) {
                Ok(()) => shell_println!("Removed device {}", id),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "default" => {
            if parts.len() < 3 {
                shell_println!("Usage: audiodevice default <output|input> <id>");
                return;
            }
            let id: u32 = match parts[2].parse() {
                Ok(v) => v,
                Err(_) => { shell_println!("Invalid ID"); return; }
            };
            match parts[1] {
                "output" | "out" => match audiodevice::set_default_output(id) {
                    Ok(()) => shell_println!("Default output set to device {}", id),
                    Err(e) => shell_println!("Error: {:?}", e),
                },
                "input" | "in" => match audiodevice::set_default_input(id) {
                    Ok(()) => shell_println!("Default input set to device {}", id),
                    Err(e) => shell_println!("Error: {:?}", e),
                },
                _ => shell_println!("Specify 'output' or 'input'"),
            }
        }
        "volume" | "vol" => {
            if parts.len() < 3 {
                shell_println!("Usage: audiodevice volume <id> <0-100>");
                return;
            }
            let id: u32 = match parts[1].parse() {
                Ok(v) => v,
                Err(_) => { shell_println!("Invalid ID"); return; }
            };
            let vol: u32 = match parts[2].parse() {
                Ok(v) => v,
                Err(_) => { shell_println!("Invalid volume"); return; }
            };
            match audiodevice::set_device_volume(id, vol) {
                Ok(()) => shell_println!("Volume for device {} set to {}", id, vol),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "mute" | "unmute" => {
            if parts.len() < 2 {
                shell_println!("Usage: audiodevice {} <id>", sub);
                return;
            }
            let id: u32 = match parts[1].parse() {
                Ok(v) => v,
                Err(_) => { shell_println!("Invalid ID"); return; }
            };
            let m = sub == "mute";
            match audiodevice::set_device_mute(id, m) {
                Ok(()) => shell_println!("Device {} {}", id, if m { "muted" } else { "unmuted" }),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "rate" => {
            if parts.len() < 3 {
                shell_println!("Usage: audiodevice rate <id> <44100|48000|88200|96000|192000>");
                return;
            }
            let id: u32 = match parts[1].parse() {
                Ok(v) => v,
                Err(_) => { shell_println!("Invalid ID"); return; }
            };
            let rate = match parts[2] {
                "44100" => audiodevice::SampleRate::Rate44100,
                "48000" => audiodevice::SampleRate::Rate48000,
                "88200" => audiodevice::SampleRate::Rate88200,
                "96000" => audiodevice::SampleRate::Rate96000,
                "192000" => audiodevice::SampleRate::Rate192000,
                _ => { shell_println!("Unknown rate: {} (44100|48000|88200|96000|192000)", parts[2]); return; }
            };
            match audiodevice::set_sample_rate(id, rate) {
                Ok(()) => shell_println!("Sample rate for device {} set to {}", id, parts[2]),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "autoswitch" => {
            if parts.len() < 2 {
                shell_println!("Usage: audiodevice autoswitch <on|off>");
                return;
            }
            let on = match parts[1] {
                "on" | "true" | "yes" | "1" => true,
                "off" | "false" | "no" | "0" => false,
                _ => { shell_println!("Specify on or off"); return; }
            };
            match audiodevice::set_auto_switch(on) {
                Ok(()) => shell_println!("Auto-switch on connect: {}", if on { "enabled" } else { "disabled" }),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "info" => {
            if parts.len() < 2 {
                shell_println!("Usage: audiodevice info <id>");
                return;
            }
            let id: u32 = match parts[1].parse() {
                Ok(v) => v,
                Err(_) => { shell_println!("Invalid ID"); return; }
            };
            match audiodevice::get_device(id) {
                Ok(d) => {
                    shell_println!("Device {}: {}", d.id, d.name);
                    shell_println!("  Type:       {}", d.device_type.label());
                    shell_println!("  Direction:  {}", d.direction.label());
                    shell_println!("  State:      {}", d.state.label());
                    shell_println!("  Volume:     {}{}", d.volume, if d.muted { " (muted)" } else { "" });
                    shell_println!("  Default:    {}", d.is_default);
                    shell_println!("  Rate:       {}", d.sample_rate.label());
                    shell_println!("  Bit depth:  {}", d.bit_depth);
                    shell_println!("  Channels:   {}", d.channels);
                    shell_println!("  Latency:    {} ms", d.latency_ms);
                    shell_println!("  Driver:     {}", d.driver);
                }
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "stats" => {
            let (total, outputs, inputs, def_out, def_in, ops) = audiodevice::stats();
            shell_println!("Devices: {} (out={}, in={})  Default out={} in={}  Ops: {}",
                total, outputs, inputs, def_out, def_in, ops);
        }
        "test" => {
            audiodevice::self_test();
            shell_println!("Audio device self-test complete.");
        }
        "init" => {
            audiodevice::init_defaults();
            shell_println!("Audio devices initialized.");
        }
        "help" => {
            shell_println!("audiodevice (adev) — audio device management");
            shell_println!("  show                        List all devices");
            shell_println!("  outputs / inputs            List by direction");
            shell_println!("  info <id>                   Device details");
            shell_println!("  add <name> <type> <dir>     Add device");
            shell_println!("  remove <id>                 Remove device");
            shell_println!("  default output|input <id>   Set default");
            shell_println!("  volume <id> <0-100>         Set volume");
            shell_println!("  mute/unmute <id>            Toggle mute");
            shell_println!("  rate <id> <rate>            Set sample rate");
            shell_println!("  autoswitch on|off           Auto-switch on connect");
            shell_println!("  stats / test / init");
        }
        _ => {
            shell_println!("Unknown subcommand: {}", sub);
            shell_println!("Use 'audiodevice help' for usage.");
        }
    }
}

/// `sessionmgr` / `session` — user session management.
fn cmd_sessionmgr(args: &str) {
    use crate::fs::sessionmgr;
    let parts: Vec<&str> = args.split_whitespace().collect();
    let sub = parts.first().copied().unwrap_or("");
    match sub {
        "show" | "" => {
            let sessions = sessionmgr::list_sessions();
            if sessions.is_empty() {
                shell_println!("No active sessions.");
            } else {
                shell_println!("{:<4} {:<12} {:<6} {:<10} {:<10} {}", "ID", "User", "UID", "Type", "State", "");
                for s in &sessions {
                    let active = if s.is_active { " *" } else { "" };
                    shell_println!("{:<4} {:<12} {:<6} {:<10} {:<10}{}",
                        s.id, s.username, s.uid, s.session_type.label(),
                        s.state.label(), active);
                }
            }
        }
        "login" => {
            if parts.len() < 3 {
                shell_println!("Usage: session login <uid> <username> [type]");
                return;
            }
            let uid: u32 = match parts[1].parse() {
                Ok(v) => v,
                Err(_) => { shell_println!("Invalid UID"); return; }
            };
            let username = parts[2];
            let stype = if parts.len() > 3 {
                match parts[3] {
                    "console" => sessionmgr::SessionType::Console,
                    "remote" => sessionmgr::SessionType::Remote,
                    "greeter" => sessionmgr::SessionType::Greeter,
                    _ => sessionmgr::SessionType::Graphical,
                }
            } else {
                sessionmgr::SessionType::Graphical
            };
            match sessionmgr::create_session(uid, username, stype, ":0", "tty1") {
                Ok(id) => shell_println!("Session {} created for {} (uid={})", id, username, uid),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "logout" => {
            if parts.len() < 2 {
                shell_println!("Usage: session logout <id>");
                return;
            }
            let id: u32 = match parts[1].parse() {
                Ok(v) => v,
                Err(_) => { shell_println!("Invalid session ID"); return; }
            };
            match sessionmgr::destroy_session(id) {
                Ok(()) => shell_println!("Session {} terminated.", id),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "switch" => {
            if parts.len() < 2 {
                shell_println!("Usage: session switch <id>");
                return;
            }
            let id: u32 = match parts[1].parse() {
                Ok(v) => v,
                Err(_) => { shell_println!("Invalid session ID"); return; }
            };
            match sessionmgr::switch_session(id) {
                Ok(()) => shell_println!("Switched to session {}.", id),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "lock" => {
            match sessionmgr::lock_session() {
                Ok(()) => shell_println!("Session locked."),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "unlock" => {
            if parts.len() < 2 {
                shell_println!("Usage: session unlock <id>");
                return;
            }
            let id: u32 = match parts[1].parse() {
                Ok(v) => v,
                Err(_) => { shell_println!("Invalid session ID"); return; }
            };
            match sessionmgr::unlock_session(id) {
                Ok(()) => shell_println!("Session {} unlocked.", id),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "active" => {
            match sessionmgr::active_session() {
                Some(s) => shell_println!("Active: {} ({}) uid={} [{}]", s.username, s.session_type.label(), s.uid, s.state.label()),
                None => shell_println!("No active session."),
            }
        }
        "timeout" => {
            if parts.len() < 2 {
                shell_println!("Usage: session timeout <seconds>  (0 = disable)");
                return;
            }
            let secs: u32 = match parts[1].parse() {
                Ok(v) => v,
                Err(_) => { shell_println!("Invalid seconds"); return; }
            };
            match sessionmgr::set_lock_timeout(secs) {
                Ok(()) => shell_println!("Lock timeout set to {} seconds.", secs),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "info" => {
            if parts.len() < 2 {
                shell_println!("Usage: session info <id>");
                return;
            }
            let id: u32 = match parts[1].parse() {
                Ok(v) => v,
                Err(_) => { shell_println!("Invalid session ID"); return; }
            };
            match sessionmgr::get_session(id) {
                Ok(s) => {
                    shell_println!("Session {}: {} (uid={})", s.id, s.username, s.uid);
                    shell_println!("  Type:    {}", s.session_type.label());
                    shell_println!("  State:   {}", s.state.label());
                    shell_println!("  Display: {}", s.display);
                    shell_println!("  TTY:     {}", s.tty);
                    shell_println!("  Active:  {}", s.is_active);
                }
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "stats" => {
            let (count, logins, locks, active_uid, ops) = sessionmgr::stats();
            shell_println!("Sessions: {}  Logins: {}  Locks: {}  Active UID: {}  Ops: {}", count, logins, locks, active_uid, ops);
        }
        "test" => {
            sessionmgr::self_test();
            shell_println!("Session manager self-test complete.");
        }
        "init" => {
            sessionmgr::init_defaults();
            shell_println!("Session manager initialized.");
        }
        "help" => {
            shell_println!("sessionmgr (session) — user session management");
            shell_println!("  show               List sessions");
            shell_println!("  login <uid> <name>  Create session");
            shell_println!("  logout <id>         End session");
            shell_println!("  switch <id>         Switch to session");
            shell_println!("  lock / unlock <id>  Lock/unlock screen");
            shell_println!("  active              Show active session");
            shell_println!("  info <id>           Session details");
            shell_println!("  timeout <secs>      Set lock timeout");
            shell_println!("  stats / test / init");
        }
        _ => {
            shell_println!("Unknown subcommand: {}", sub);
            shell_println!("Use 'session help' for usage.");
        }
    }
}

/// `crashreport` / `crash` — crash report management.
fn cmd_crashreport(args: &str) {
    use crate::fs::crashreport;
    let parts: Vec<&str> = args.split_whitespace().collect();
    let sub = parts.first().copied().unwrap_or("");
    match sub {
        "show" | "" => {
            let reports = crashreport::list_reports();
            if reports.is_empty() {
                shell_println!("No crash reports.");
            } else {
                shell_println!("{:<4} {:<6} {:<16} {:<12} {:<10} {}", "ID", "PID", "Process", "Signal", "Severity", "Status");
                for r in reports.iter().take(20) {
                    shell_println!("{:<4} {:<6} {:<16} {:<12} {:<10} {}",
                        r.id, r.pid, r.process_name, r.signal.label(),
                        r.severity.label(), r.status.label());
                }
                if reports.len() > 20 {
                    shell_println!("... and {} more", reports.len() - 20);
                }
            }
        }
        "detail" => {
            if parts.len() < 2 {
                shell_println!("Usage: crash detail <id>");
                return;
            }
            let id: u32 = match parts[1].parse() {
                Ok(v) => v,
                Err(_) => { shell_println!("Invalid ID"); return; }
            };
            match crashreport::get_report(id) {
                Ok(r) => {
                    shell_println!("Crash Report #{}", r.id);
                    shell_println!("  Process:  {} (pid={})", r.process_name, r.pid);
                    shell_println!("  Signal:   {}", r.signal.label());
                    shell_println!("  Severity: {}", r.severity.label());
                    shell_println!("  Status:   {}", r.status.label());
                    if r.fault_address != 0 {
                        shell_println!("  Fault:    0x{:016x}", r.fault_address);
                    }
                    if r.instruction_pointer != 0 {
                        shell_println!("  IP:       0x{:016x}", r.instruction_pointer);
                    }
                    if !r.stack_trace.is_empty() {
                        shell_println!("  Stack trace ({} frames):", r.stack_trace.len());
                        for (i, addr) in r.stack_trace.iter().enumerate() {
                            shell_println!("    #{}: 0x{:016x}", i, addr);
                        }
                    }
                    if !r.modules.is_empty() {
                        shell_println!("  Modules: {}", r.modules.join(", "));
                    }
                    if !r.description.is_empty() {
                        shell_println!("  Note: {}", r.description);
                    }
                }
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "delete" => {
            if parts.len() < 2 {
                shell_println!("Usage: crash delete <id>");
                return;
            }
            let id: u32 = match parts[1].parse() {
                Ok(v) => v,
                Err(_) => { shell_println!("Invalid ID"); return; }
            };
            match crashreport::delete_report(id) {
                Ok(()) => shell_println!("Report {} deleted.", id),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "clear" => {
            match crashreport::clear_reports() {
                Ok(n) => shell_println!("Cleared {} reports.", n),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "describe" => {
            if parts.len() < 3 {
                shell_println!("Usage: crash describe <id> <text...>");
                return;
            }
            let id: u32 = match parts[1].parse() {
                Ok(v) => v,
                Err(_) => { shell_println!("Invalid ID"); return; }
            };
            let desc = parts[2..].join(" ");
            match crashreport::set_description(id, &desc) {
                Ok(()) => shell_println!("Description set for report {}.", id),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "enable" | "disable" => {
            let on = sub == "enable";
            match crashreport::set_enabled(on) {
                Ok(()) => shell_println!("Crash reporting {}.", if on { "enabled" } else { "disabled" }),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "autosubmit" => {
            if parts.len() < 2 {
                shell_println!("Usage: crash autosubmit <on|off>");
                return;
            }
            let on = matches!(parts[1], "on" | "true" | "yes" | "1");
            match crashreport::set_auto_submit(on) {
                Ok(()) => shell_println!("Auto-submit {}.", if on { "enabled" } else { "disabled" }),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "summary" => {
            let (fatal, non_fatal, hang, kernel) = crashreport::count_by_severity();
            shell_println!("Fatal: {}  Non-fatal: {}  Hang: {}  Kernel: {}", fatal, non_fatal, hang, kernel);
        }
        "stats" => {
            let (count, total, fatal, enabled, ops) = crashreport::stats();
            shell_println!("Reports: {}  Total crashes: {}  Fatal: {}  Enabled: {}  Ops: {}",
                count, total, fatal, enabled, ops);
        }
        "test" => {
            crashreport::self_test();
            shell_println!("Crash report self-test complete.");
        }
        "init" => {
            crashreport::init_defaults();
            shell_println!("Crash reporter initialized.");
        }
        "help" => {
            shell_println!("crashreport (crash) — crash report management");
            shell_println!("  show                  List reports");
            shell_println!("  detail <id>           Report details + stack trace");
            shell_println!("  delete <id>           Delete report");
            shell_println!("  describe <id> <text>  Add description");
            shell_println!("  clear                 Clear all reports");
            shell_println!("  summary               Count by severity");
            shell_println!("  enable/disable        Toggle reporting");
            shell_println!("  autosubmit on|off     Auto-submit toggle");
            shell_println!("  stats / test / init");
        }
        _ => {
            shell_println!("Unknown subcommand: {}", sub);
            shell_println!("Use 'crash help' for usage.");
        }
    }
}

/// `netproxy` / `proxy` — network proxy settings.
fn cmd_netproxy(args: &str) {
    use crate::fs::netproxy;
    use alloc::format;
    let parts: Vec<&str> = args.split_whitespace().collect();
    let sub = parts.first().copied().unwrap_or("");
    match sub {
        "show" | "" => {
            let mode = netproxy::get_mode().unwrap_or(netproxy::ProxyMode::None);
            shell_println!("Proxy mode: {}", mode.label());
            let proxies = netproxy::list_proxies();
            if proxies.is_empty() {
                shell_println!("No proxies configured.");
            } else {
                for p in &proxies {
                    let en = if p.enabled { "" } else { " [disabled]" };
                    let auth = if p.auth_required { format!(" (auth: {})", p.username) } else { String::new() };
                    shell_println!("  {}: {}:{}{}{}", p.protocol.label(), p.host, p.port, auth, en);
                }
            }
            let bypass = netproxy::list_bypass();
            if !bypass.is_empty() {
                shell_println!("Bypass rules:");
                for b in &bypass {
                    shell_println!("  {} — {}", b.pattern, b.description);
                }
            }
        }
        "mode" => {
            if parts.len() < 2 {
                shell_println!("Usage: proxy mode <none|manual|auto|detect>");
                return;
            }
            let mode = match parts[1] {
                "none" | "off" => netproxy::ProxyMode::None,
                "manual" => netproxy::ProxyMode::Manual,
                "auto" | "pac" => netproxy::ProxyMode::Auto,
                "detect" | "wpad" => netproxy::ProxyMode::SystemDetect,
                _ => { shell_println!("Unknown mode: {}", parts[1]); return; }
            };
            match netproxy::set_mode(mode) {
                Ok(()) => shell_println!("Proxy mode set to {}.", mode.label()),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "set" => {
            if parts.len() < 4 {
                shell_println!("Usage: proxy set <http|https|socks4|socks5|ftp> <host> <port>");
                return;
            }
            let proto = match parts[1] {
                "http" => netproxy::ProxyProtocol::Http,
                "https" => netproxy::ProxyProtocol::Https,
                "socks4" => netproxy::ProxyProtocol::Socks4,
                "socks5" | "socks" => netproxy::ProxyProtocol::Socks5,
                "ftp" => netproxy::ProxyProtocol::Ftp,
                _ => { shell_println!("Unknown protocol: {}", parts[1]); return; }
            };
            let host = parts[2];
            let port: u16 = match parts[3].parse() {
                Ok(v) => v,
                Err(_) => { shell_println!("Invalid port"); return; }
            };
            match netproxy::set_proxy(proto, host, port) {
                Ok(()) => shell_println!("Proxy set: {} → {}:{}", proto.label(), host, port),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "remove" => {
            if parts.len() < 2 {
                shell_println!("Usage: proxy remove <http|https|socks4|socks5|ftp>");
                return;
            }
            let proto = match parts[1] {
                "http" => netproxy::ProxyProtocol::Http,
                "https" => netproxy::ProxyProtocol::Https,
                "socks4" => netproxy::ProxyProtocol::Socks4,
                "socks5" | "socks" => netproxy::ProxyProtocol::Socks5,
                "ftp" => netproxy::ProxyProtocol::Ftp,
                _ => { shell_println!("Unknown protocol: {}", parts[1]); return; }
            };
            match netproxy::remove_proxy(proto) {
                Ok(()) => shell_println!("Proxy removed for {}.", proto.label()),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "pac" => {
            if parts.len() < 2 {
                let url = netproxy::get_pac_url().unwrap_or_default();
                if url.is_empty() {
                    shell_println!("No PAC URL configured.");
                } else {
                    shell_println!("PAC URL: {}", url);
                }
            } else {
                match netproxy::set_pac_url(parts[1]) {
                    Ok(()) => shell_println!("PAC URL set to {}", parts[1]),
                    Err(e) => shell_println!("Error: {:?}", e),
                }
            }
        }
        "bypass" => {
            if parts.len() < 2 {
                let rules = netproxy::list_bypass();
                for b in &rules {
                    shell_println!("  {} — {}", b.pattern, b.description);
                }
            } else if parts.len() >= 3 && parts[1] == "add" {
                let desc = if parts.len() > 3 { parts[3..].join(" ") } else { String::new() };
                match netproxy::add_bypass(parts[2], &desc) {
                    Ok(()) => shell_println!("Bypass added: {}", parts[2]),
                    Err(e) => shell_println!("Error: {:?}", e),
                }
            } else if parts.len() >= 3 && parts[1] == "remove" {
                match netproxy::remove_bypass(parts[2]) {
                    Ok(()) => shell_println!("Bypass removed: {}", parts[2]),
                    Err(e) => shell_println!("Error: {:?}", e),
                }
            } else {
                shell_println!("Usage: proxy bypass [add <pattern> [desc] | remove <pattern>]");
            }
        }
        "resolve" => {
            if parts.len() < 2 {
                shell_println!("Usage: proxy resolve <host> [http|https]");
                return;
            }
            let proto = if parts.len() > 2 {
                match parts[2] {
                    "https" => netproxy::ProxyProtocol::Https,
                    _ => netproxy::ProxyProtocol::Http,
                }
            } else {
                netproxy::ProxyProtocol::Http
            };
            match netproxy::resolve_proxy(parts[1], proto) {
                netproxy::ProxyResolution::Proxy { host, port, protocol } => {
                    shell_println!("→ Proxy: {} {}:{}", protocol.label(), host, port);
                }
                netproxy::ProxyResolution::Direct => {
                    shell_println!("→ Direct connection (no proxy)");
                }
            }
        }
        "stats" => {
            let (proxies, bypass, mode, overrides, ops) = netproxy::stats();
            shell_println!("Mode: {}  Proxies: {}  Bypass: {}  App overrides: {}  Ops: {}",
                mode, proxies, bypass, overrides, ops);
        }
        "test" => {
            netproxy::self_test();
            shell_println!("Proxy self-test complete.");
        }
        "init" => {
            netproxy::init_defaults();
            shell_println!("Proxy settings initialized.");
        }
        "help" => {
            shell_println!("netproxy (proxy) — network proxy settings");
            shell_println!("  show                             Current config");
            shell_println!("  mode <none|manual|auto|detect>   Set proxy mode");
            shell_println!("  set <proto> <host> <port>        Add/update proxy");
            shell_println!("  remove <proto>                   Remove proxy");
            shell_println!("  pac [url]                        Show/set PAC URL");
            shell_println!("  bypass [add|remove <pattern>]    Bypass rules");
            shell_println!("  resolve <host> [proto]           Test resolution");
            shell_println!("  stats / test / init");
        }
        _ => {
            shell_println!("Unknown subcommand: {}", sub);
            shell_println!("Use 'proxy help' for usage.");
        }
    }
}

/// `fileversion` / `fver` — file versioning and history.
fn cmd_fileversion(args: &str) {
    use crate::fs::fileversion;
    let parts: Vec<&str> = args.split_whitespace().collect();
    let sub = parts.first().copied().unwrap_or("");
    match sub {
        "show" | "" => {
            let (ver_count, file_count, captured, restored, watch_count, _ops) = fileversion::stats();
            shell_println!("File Versioning");
            shell_println!("  Versions stored:  {}", ver_count);
            shell_println!("  Files versioned:  {}", file_count);
            shell_println!("  Total captured:   {}", captured);
            shell_println!("  Total restored:   {}", restored);
            shell_println!("  Watched paths:    {}", watch_count);
            shell_println!("  Storage used:     {} bytes", fileversion::total_storage());
        }
        "list" => {
            if parts.len() < 2 {
                shell_println!("Usage: fver list <path>");
                return;
            }
            let versions = fileversion::list_versions(parts[1]);
            if versions.is_empty() {
                shell_println!("No versions for '{}'.", parts[1]);
            } else {
                shell_println!("{:<6} {:<4} {:<8} {}", "ID", "Ver", "Size", "Comment");
                for v in &versions {
                    shell_println!("{:<6} v{:<3} {:<8} {}", v.id, v.version, v.size, v.comment);
                }
            }
        }
        "detail" => {
            if parts.len() < 2 {
                shell_println!("Usage: fver detail <version_id>");
                return;
            }
            let id: u64 = match parts[1].parse() {
                Ok(v) => v,
                Err(_) => { shell_println!("Invalid version ID"); return; }
            };
            match fileversion::get_version(id) {
                Ok(v) => {
                    shell_println!("Version #{} of {}", v.id, v.path);
                    shell_println!("  Version:  v{}", v.version);
                    shell_println!("  Size:     {} bytes", v.size);
                    shell_println!("  Checksum: 0x{:016x}", v.checksum);
                    shell_println!("  User:     uid={}", v.uid);
                    if !v.comment.is_empty() {
                        shell_println!("  Comment:  {}", v.comment);
                    }
                }
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "comment" => {
            if parts.len() < 3 {
                shell_println!("Usage: fver comment <version_id> <text...>");
                return;
            }
            let id: u64 = match parts[1].parse() {
                Ok(v) => v,
                Err(_) => { shell_println!("Invalid version ID"); return; }
            };
            let text = parts[2..].join(" ");
            match fileversion::set_version_comment(id, &text) {
                Ok(()) => shell_println!("Comment set on version {}.", id),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "restore" => {
            if parts.len() < 2 {
                shell_println!("Usage: fver restore <version_id>");
                return;
            }
            let id: u64 = match parts[1].parse() {
                Ok(v) => v,
                Err(_) => { shell_println!("Invalid version ID"); return; }
            };
            match fileversion::restore_version(id) {
                Ok(v) => shell_println!("Restored version {} of {} ({} bytes)", v.version, v.path, v.size),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "delete" => {
            if parts.len() < 2 {
                shell_println!("Usage: fver delete <version_id>");
                return;
            }
            let id: u64 = match parts[1].parse() {
                Ok(v) => v,
                Err(_) => { shell_println!("Invalid version ID"); return; }
            };
            match fileversion::delete_version(id) {
                Ok(()) => shell_println!("Version {} deleted.", id),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "purge" => {
            if parts.len() < 2 {
                shell_println!("Usage: fver purge <path>");
                return;
            }
            match fileversion::purge_file_versions(parts[1]) {
                Ok(n) => shell_println!("Purged {} versions of {}.", n, parts[1]),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "watch" => {
            if parts.len() < 2 {
                let watches = fileversion::list_watches();
                if watches.is_empty() {
                    shell_println!("No watched paths.");
                } else {
                    for w in &watches {
                        shell_println!("  {} — {}", w.path, w.policy.label());
                    }
                }
            } else if parts.len() >= 3 && parts[1] == "add" {
                let policy = if parts.len() > 3 {
                    match parts[3] {
                        "all" => fileversion::VersionPolicy::KeepAll,
                        "disabled" | "off" => fileversion::VersionPolicy::Disabled,
                        n => match n.parse::<u32>() {
                            Ok(v) => fileversion::VersionPolicy::KeepLast(v),
                            Err(_) => fileversion::VersionPolicy::KeepLast(10),
                        },
                    }
                } else {
                    fileversion::VersionPolicy::KeepLast(10)
                };
                match fileversion::add_watch(parts[2], policy) {
                    Ok(()) => shell_println!("Watch added: {} ({})", parts[2], policy.label()),
                    Err(e) => shell_println!("Error: {:?}", e),
                }
            } else if parts.len() >= 3 && parts[1] == "remove" {
                match fileversion::remove_watch(parts[2]) {
                    Ok(()) => shell_println!("Watch removed: {}", parts[2]),
                    Err(e) => shell_println!("Error: {:?}", e),
                }
            } else {
                shell_println!("Usage: fver watch [add <path> [policy] | remove <path>]");
            }
        }
        "enable" | "disable" => {
            let on = sub == "enable";
            match fileversion::set_enabled(on) {
                Ok(()) => shell_println!("File versioning {}.", if on { "enabled" } else { "disabled" }),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "stats" => {
            let (ver_count, file_count, captured, restored, watch_count, ops) = fileversion::stats();
            shell_println!("Versions: {}  Files: {}  Captured: {}  Restored: {}  Watches: {}  Ops: {}",
                ver_count, file_count, captured, restored, watch_count, ops);
        }
        "test" => {
            fileversion::self_test();
            shell_println!("File versioning self-test complete.");
        }
        "init" => {
            fileversion::init_defaults();
            shell_println!("File versioning initialized.");
        }
        "help" => {
            shell_println!("fileversion (fver) — file version history");
            shell_println!("  show                    Overview");
            shell_println!("  list <path>             Versions of a file");
            shell_println!("  detail <id>             Version details");
            shell_println!("  comment <id> <text>     Add comment");
            shell_println!("  restore <id>            Restore version");
            shell_println!("  delete <id>             Delete version");
            shell_println!("  purge <path>            Delete all versions");
            shell_println!("  watch [add|remove]      Watch paths");
            shell_println!("  enable/disable          Toggle versioning");
            shell_println!("  stats / test / init");
        }
        _ => {
            shell_println!("Unknown subcommand: {}", sub);
            shell_println!("Use 'fver help' for usage.");
        }
    }
}

/// `devicemgr` / `devmgr` — hardware device management.
fn cmd_devicemgr(args: &str) {
    use crate::fs::devicemgr;
    let parts: Vec<&str> = args.split_whitespace().collect();
    let sub = parts.first().copied().unwrap_or("");
    match sub {
        "show" | "" => {
            let devices = devicemgr::list_devices();
            if devices.is_empty() {
                shell_println!("No devices.");
            } else {
                shell_println!("{:<4} {:<24} {:<10} {:<10} {:<10} {}", "ID", "Name", "Bus", "Class", "Status", "Driver");
                for d in &devices {
                    let drv = if d.driver.is_empty() { "-" } else { &d.driver };
                    shell_println!("{:<4} {:<24} {:<10} {:<10} {:<10} {}",
                        d.id, d.name, d.bus.label(), d.class.label(),
                        d.status.label(), drv);
                }
            }
        }
        "info" => {
            if parts.len() < 2 {
                shell_println!("Usage: devmgr info <id>");
                return;
            }
            let id: u32 = match parts[1].parse() {
                Ok(v) => v,
                Err(_) => { shell_println!("Invalid ID"); return; }
            };
            match devicemgr::get_device(id) {
                Ok(d) => {
                    shell_println!("Device {}: {}", d.id, d.name);
                    shell_println!("  Bus:      {} ({})", d.bus.label(), d.bus_address);
                    shell_println!("  Class:    {}", d.class.label());
                    shell_println!("  Vendor:   {} (0x{:04X})", d.vendor_name, d.vendor_id);
                    shell_println!("  Product:  0x{:04X}", d.product_id);
                    shell_println!("  Status:   {}", d.status.label());
                    shell_println!("  Driver:   {}", if d.driver.is_empty() { "none" } else { &d.driver });
                    shell_println!("  Enabled:  {}", d.enabled);
                    shell_println!("  Hotplug:  {}", d.hotplugged);
                }
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "add" => {
            if parts.len() < 4 {
                shell_println!("Usage: devmgr add <name> <bus> <class> [vendor] [address]");
                shell_println!("  bus:   pci|usb|acpi|platform|i2c|spi|bluetooth|virtual");
                shell_println!("  class: display|audio|network|storage|input|usb|bt|other");
                return;
            }
            let name = parts[1];
            let bus = match parts[2] {
                "pci" => devicemgr::BusType::Pci,
                "usb" => devicemgr::BusType::Usb,
                "acpi" => devicemgr::BusType::Acpi,
                "platform" => devicemgr::BusType::Platform,
                "i2c" => devicemgr::BusType::I2c,
                "spi" => devicemgr::BusType::Spi,
                "bluetooth" | "bt" => devicemgr::BusType::Bluetooth,
                "virtual" => devicemgr::BusType::Virtual,
                _ => { shell_println!("Unknown bus: {}", parts[2]); return; }
            };
            let class = match parts[3] {
                "display" => devicemgr::DeviceClass::Display,
                "audio" => devicemgr::DeviceClass::Audio,
                "network" | "net" => devicemgr::DeviceClass::Network,
                "storage" => devicemgr::DeviceClass::Storage,
                "input" => devicemgr::DeviceClass::Input,
                "usb" => devicemgr::DeviceClass::Usb,
                "bt" | "bluetooth" => devicemgr::DeviceClass::Bluetooth,
                "printer" => devicemgr::DeviceClass::Printer,
                _ => devicemgr::DeviceClass::Other,
            };
            let vendor = if parts.len() > 4 { parts[4] } else { "Generic" };
            let addr = if parts.len() > 5 { parts[5] } else { "auto" };
            match devicemgr::register_device(name, bus, class, 0, 0, vendor, addr, true) {
                Ok(id) => shell_println!("Registered device '{}' (id={})", name, id),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "remove" => {
            if parts.len() < 2 {
                shell_println!("Usage: devmgr remove <id>");
                return;
            }
            let id: u32 = match parts[1].parse() {
                Ok(v) => v,
                Err(_) => { shell_println!("Invalid ID"); return; }
            };
            match devicemgr::remove_device(id) {
                Ok(()) => shell_println!("Removed device {}.", id),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "bind" => {
            if parts.len() < 3 {
                shell_println!("Usage: devmgr bind <id> <driver> [version]");
                return;
            }
            let id: u32 = match parts[1].parse() {
                Ok(v) => v,
                Err(_) => { shell_println!("Invalid ID"); return; }
            };
            let version = if parts.len() > 3 { parts[3] } else { "1.0" };
            match devicemgr::bind_driver(id, parts[2], version) {
                Ok(()) => shell_println!("Bound driver '{}' to device {}.", parts[2], id),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "unbind" => {
            if parts.len() < 2 {
                shell_println!("Usage: devmgr unbind <id>");
                return;
            }
            let id: u32 = match parts[1].parse() {
                Ok(v) => v,
                Err(_) => { shell_println!("Invalid ID"); return; }
            };
            match devicemgr::unbind_driver(id) {
                Ok(()) => shell_println!("Driver unbound from device {}.", id),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "enable" | "disable" => {
            if parts.len() < 2 {
                shell_println!("Usage: devmgr {} <id>", sub);
                return;
            }
            let id: u32 = match parts[1].parse() {
                Ok(v) => v,
                Err(_) => { shell_println!("Invalid ID"); return; }
            };
            let on = sub == "enable";
            match devicemgr::set_enabled(id, on) {
                Ok(()) => shell_println!("Device {} {}.", id, if on { "enabled" } else { "disabled" }),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "nodriver" => {
            let count = devicemgr::devices_needing_driver();
            shell_println!("{} device(s) without a driver.", count);
        }
        "stats" => {
            let (total, ok, no_drv, hotplug, ops) = devicemgr::stats();
            shell_println!("Devices: {}  OK: {}  No driver: {}  Hotplug events: {}  Ops: {}",
                total, ok, no_drv, hotplug, ops);
        }
        "test" => {
            devicemgr::self_test();
            shell_println!("Device manager self-test complete.");
        }
        "init" => {
            devicemgr::init_defaults();
            shell_println!("Device manager initialized.");
        }
        "help" => {
            shell_println!("devicemgr (devmgr) — hardware device management");
            shell_println!("  show                       List devices");
            shell_println!("  info <id>                  Device details");
            shell_println!("  add <name> <bus> <class>   Register device");
            shell_println!("  remove <id>                Remove device");
            shell_println!("  bind <id> <driver>         Bind driver");
            shell_println!("  unbind <id>                Unbind driver");
            shell_println!("  enable/disable <id>        Toggle device");
            shell_println!("  nodriver                   Count undriven");
            shell_println!("  stats / test / init");
        }
        _ => {
            shell_println!("Unknown subcommand: {}", sub);
            shell_println!("Use 'devmgr help' for usage.");
        }
    }
}

/// `location` / `loc` — location services and permissions.
fn cmd_location(args: &str) {
    use crate::fs::location;
    let parts: Vec<&str> = args.split_whitespace().collect();
    let sub = parts.first().copied().unwrap_or("");
    match sub {
        "show" | "" => {
            let (enabled, perm_count, requests, denied, hist_len, _ops) = location::stats();
            shell_println!("Location Services");
            shell_println!("  Enabled:   {}", enabled);
            shell_println!("  Apps:      {} with permissions", perm_count);
            shell_println!("  Requests:  {} total ({} denied)", requests, denied);
            shell_println!("  History:   {} entries", hist_len);
            if let Some(fix) = location::current_location() {
                let lat_deg = fix.latitude_ud / 1_000_000;
                let lat_frac = (fix.latitude_ud % 1_000_000).unsigned_abs();
                let lon_deg = fix.longitude_ud / 1_000_000;
                let lon_frac = (fix.longitude_ud % 1_000_000).unsigned_abs();
                shell_println!("  Current:   {}.{:06}, {}.{:06} ±{}m ({})",
                    lat_deg, lat_frac, lon_deg, lon_frac, fix.accuracy_m, fix.source.label());
            } else {
                shell_println!("  Current:   unavailable");
            }
        }
        "enable" | "disable" => {
            let on = sub == "enable";
            match location::set_enabled(on) {
                Ok(()) => shell_println!("Location services {}.", if on { "enabled" } else { "disabled" }),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "update" => {
            if parts.len() < 4 {
                shell_println!("Usage: loc update <lat_ud> <lon_ud> <accuracy_m> [source]");
                shell_println!("  lat/lon in microdegrees (e.g., 47606209 for 47.606209°)");
                return;
            }
            let lat: i64 = match parts[1].parse() { Ok(v) => v, Err(_) => { shell_println!("Invalid latitude"); return; } };
            let lon: i64 = match parts[2].parse() { Ok(v) => v, Err(_) => { shell_println!("Invalid longitude"); return; } };
            let acc: u32 = match parts[3].parse() { Ok(v) => v, Err(_) => { shell_println!("Invalid accuracy"); return; } };
            let src = if parts.len() > 4 {
                match parts[4] {
                    "gps" => location::LocationSource::Gps,
                    "wifi" => location::LocationSource::Wifi,
                    "cell" => location::LocationSource::CellTower,
                    "ip" => location::LocationSource::IpBased,
                    "manual" => location::LocationSource::Manual,
                    _ => location::LocationSource::Manual,
                }
            } else {
                location::LocationSource::Manual
            };
            match location::update_location(lat, lon, 0, acc, src) {
                Ok(()) => shell_println!("Location updated."),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "perm" => {
            if parts.len() < 3 {
                let perms = location::list_app_permissions();
                if perms.is_empty() {
                    shell_println!("No app permissions set.");
                } else {
                    for p in &perms {
                        shell_println!("  {}: {} (requests: {})", p.app_id, p.permission.label(), p.request_count);
                    }
                }
                return;
            }
            let app_id = parts[1];
            let perm = match parts[2] {
                "allow" => location::LocationPermission::Allow,
                "while" | "inuse" => location::LocationPermission::WhileInUse,
                "deny" => location::LocationPermission::Deny,
                "ask" => location::LocationPermission::AskNextTime,
                _ => { shell_println!("Unknown permission: {} (allow|while|deny|ask)", parts[2]); return; }
            };
            match location::set_app_permission(app_id, perm) {
                Ok(()) => shell_println!("Permission for '{}' set to {}.", app_id, perm.label()),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "history" => {
            if parts.len() > 1 && parts[1] == "clear" {
                match location::clear_history() {
                    Ok(n) => shell_println!("Cleared {} history entries.", n),
                    Err(e) => shell_println!("Error: {:?}", e),
                }
            } else if parts.len() > 1 && (parts[1] == "on" || parts[1] == "off") {
                let on = parts[1] == "on";
                match location::set_record_history(on) {
                    Ok(()) => shell_println!("History recording {}.", if on { "enabled" } else { "disabled" }),
                    Err(e) => shell_println!("Error: {:?}", e),
                }
            } else {
                let hist = location::get_history();
                if hist.is_empty() {
                    shell_println!("No history recorded.");
                } else {
                    for h in hist.iter().rev().take(10) {
                        let lat_deg = h.latitude_ud / 1_000_000;
                        let lat_frac = (h.latitude_ud % 1_000_000).unsigned_abs();
                        let lon_deg = h.longitude_ud / 1_000_000;
                        let lon_frac = (h.longitude_ud % 1_000_000).unsigned_abs();
                        shell_println!("  {}.{:06}, {}.{:06} ±{}m ({})",
                            lat_deg, lat_frac, lon_deg, lon_frac, h.accuracy_m, h.source.label());
                    }
                }
            }
        }
        "stats" => {
            let (enabled, perms, requests, denied, hist, ops) = location::stats();
            shell_println!("Enabled: {}  Apps: {}  Requests: {}  Denied: {}  History: {}  Ops: {}",
                enabled, perms, requests, denied, hist, ops);
        }
        "test" => {
            location::self_test();
            shell_println!("Location self-test complete.");
        }
        "init" => {
            location::init_defaults();
            shell_println!("Location services initialized.");
        }
        "help" => {
            shell_println!("location (loc) — location services");
            shell_println!("  show                         Overview");
            shell_println!("  enable/disable               Toggle services");
            shell_println!("  update <lat> <lon> <acc>     Update location");
            shell_println!("  perm [app_id permission]     App permissions");
            shell_println!("  history [on|off|clear]       History management");
            shell_println!("  stats / test / init");
        }
        _ => {
            shell_println!("Unknown subcommand: {}", sub);
            shell_println!("Use 'loc help' for usage.");
        }
    }
}

/// `diskencrypt` / `dencrypt` — disk encryption management.
fn cmd_diskencrypt(args: &str) {
    use crate::fs::diskencrypt;
    let parts: Vec<&str> = args.split_whitespace().collect();
    let sub = parts.first().copied().unwrap_or("");
    match sub {
        "show" | "" => {
            let vols = diskencrypt::list_volumes();
            if vols.is_empty() {
                shell_println!("No volumes.");
            } else {
                shell_println!("{:<4} {:<12} {:<14} {:<16} {:<10} {}", "ID", "Label", "Device", "Algorithm", "Status", "Slots");
                for v in &vols {
                    shell_println!("{:<4} {:<12} {:<14} {:<16} {:<10} {}",
                        v.id, v.label, v.device, v.algorithm.label(),
                        v.status.label(), v.key_slots.len());
                }
            }
        }
        "info" => {
            if parts.len() < 2 {
                shell_println!("Usage: dencrypt info <id>");
                return;
            }
            let id: u32 = match parts[1].parse() { Ok(v) => v, Err(_) => { shell_println!("Invalid ID"); return; } };
            match diskencrypt::get_volume(id) {
                Ok(v) => {
                    shell_println!("Volume {}: {}", v.id, v.label);
                    shell_println!("  Device:    {}", v.device);
                    shell_println!("  Algorithm: {}", v.algorithm.label());
                    shell_println!("  Status:    {}", v.status.label());
                    shell_println!("  Size:      {} bytes", v.size_bytes);
                    shell_println!("  Mount:     {}", if v.mount_point.is_empty() { "-" } else { &v.mount_point });
                    shell_println!("  Recovery:  {}", v.has_recovery_key);
                    shell_println!("  TPM:       {}", v.tpm_sealed);
                    if !v.key_slots.is_empty() {
                        shell_println!("  Key slots:");
                        for s in &v.key_slots {
                            let act = if s.active { "active" } else { "inactive" };
                            shell_println!("    #{}: {} ({}) [{}]", s.slot, s.label, s.kdf.label(), act);
                        }
                    }
                }
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "unlock" => {
            if parts.len() < 3 {
                shell_println!("Usage: dencrypt unlock <id> <passphrase>");
                return;
            }
            let id: u32 = match parts[1].parse() { Ok(v) => v, Err(_) => { shell_println!("Invalid ID"); return; } };
            match diskencrypt::unlock_volume(id, parts[2]) {
                Ok(()) => shell_println!("Volume {} unlocked.", id),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "lock" => {
            if parts.len() < 2 {
                shell_println!("Usage: dencrypt lock <id>");
                return;
            }
            let id: u32 = match parts[1].parse() { Ok(v) => v, Err(_) => { shell_println!("Invalid ID"); return; } };
            match diskencrypt::lock_volume(id) {
                Ok(()) => shell_println!("Volume {} locked.", id),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "encrypt" => {
            if parts.len() < 2 {
                shell_println!("Usage: dencrypt encrypt <id> [algorithm]");
                shell_println!("  algorithms: aes256|aes128|serpent|twofish|chacha20");
                return;
            }
            let id: u32 = match parts[1].parse() { Ok(v) => v, Err(_) => { shell_println!("Invalid ID"); return; } };
            let alg = if parts.len() > 2 {
                match parts[2] {
                    "aes256" => diskencrypt::EncryptAlgorithm::Aes256Xts,
                    "aes128" => diskencrypt::EncryptAlgorithm::Aes128Xts,
                    "serpent" => diskencrypt::EncryptAlgorithm::Serpent256Xts,
                    "twofish" => diskencrypt::EncryptAlgorithm::Twofish256Xts,
                    "chacha20" => diskencrypt::EncryptAlgorithm::ChaCha20,
                    _ => { shell_println!("Unknown algorithm"); return; }
                }
            } else {
                diskencrypt::EncryptAlgorithm::Aes256Xts
            };
            match diskencrypt::start_encryption(id, alg) {
                Ok(()) => shell_println!("Started encryption of volume {} with {}.", id, alg.label()),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "recovery" => {
            if parts.len() < 2 {
                shell_println!("Usage: dencrypt recovery <id>");
                return;
            }
            let id: u32 = match parts[1].parse() { Ok(v) => v, Err(_) => { shell_println!("Invalid ID"); return; } };
            match diskencrypt::generate_recovery_key(id) {
                Ok(key) => {
                    shell_println!("Recovery key generated for volume {}:", id);
                    shell_println!("  {}", key);
                    shell_println!("  *** SAVE THIS KEY SECURELY ***");
                }
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "addslot" => {
            if parts.len() < 3 {
                shell_println!("Usage: dencrypt addslot <id> <label> [kdf]");
                return;
            }
            let id: u32 = match parts[1].parse() { Ok(v) => v, Err(_) => { shell_println!("Invalid ID"); return; } };
            let kdf = if parts.len() > 3 {
                match parts[3] {
                    "argon2id" | "argon2" => diskencrypt::Kdf::Argon2id,
                    "pbkdf2" => diskencrypt::Kdf::Pbkdf2,
                    "scrypt" => diskencrypt::Kdf::Scrypt,
                    _ => diskencrypt::Kdf::Argon2id,
                }
            } else {
                diskencrypt::Kdf::Argon2id
            };
            match diskencrypt::add_key_slot(id, kdf, parts[2]) {
                Ok(slot) => shell_println!("Added key slot #{} to volume {}.", slot, id),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "stats" => {
            let (total, encrypted, unlocked, failed, ops) = diskencrypt::stats();
            shell_println!("Volumes: {}  Encrypted: {}  Unlocked: {}  Failed unlocks: {}  Ops: {}",
                total, encrypted, unlocked, failed, ops);
        }
        "test" => {
            diskencrypt::self_test();
            shell_println!("Disk encryption self-test complete.");
        }
        "init" => {
            diskencrypt::init_defaults();
            shell_println!("Disk encryption initialized.");
        }
        "help" => {
            shell_println!("diskencrypt (dencrypt) — disk encryption management");
            shell_println!("  show                  List volumes");
            shell_println!("  info <id>             Volume details");
            shell_println!("  unlock <id> <pass>    Unlock volume");
            shell_println!("  lock <id>             Lock volume");
            shell_println!("  encrypt <id> [alg]    Start encryption");
            shell_println!("  recovery <id>         Generate recovery key");
            shell_println!("  addslot <id> <label>  Add key slot");
            shell_println!("  stats / test / init");
        }
        _ => {
            shell_println!("Unknown subcommand: {}", sub);
            shell_println!("Use 'dencrypt help' for usage.");
        }
    }
}

/// `pkgmgr` / `pkg` — package management.
fn cmd_pkgmgr(args: &str) {
    use crate::fs::pkgmgr;
    let parts: Vec<&str> = args.split_whitespace().collect();
    let sub = parts.first().copied().unwrap_or("");
    match sub {
        "show" | "" => {
            let (installed, available, upgradeable, repos, _) = pkgmgr::stats();
            shell_println!("Package Manager");
            shell_println!("  Installed:    {}", installed);
            shell_println!("  Available:    {}", available);
            shell_println!("  Upgradeable:  {}", upgradeable);
            shell_println!("  Repositories: {}", repos);
            shell_println!("  Total size:   {} bytes", pkgmgr::total_installed_size());
        }
        "list" => {
            let packages = pkgmgr::list_installed();
            if packages.is_empty() {
                shell_println!("No packages installed.");
            } else {
                shell_println!("{:<20} {:<10} {:<12} {}", "Name", "Version", "Section", "Status");
                for p in &packages {
                    shell_println!("{:<20} {:<10} {:<12} {}", p.name, p.version, p.section.label(), p.status.label());
                }
            }
        }
        "install" => {
            if parts.len() < 2 {
                shell_println!("Usage: pkg install <name> [version] [description]");
                return;
            }
            let name = parts[1];
            let version = if parts.len() > 2 { parts[2] } else { "1.0.0" };
            let desc = if parts.len() > 3 { parts[3..].join(" ") } else { String::from("User package") };
            match pkgmgr::install(name, version, &desc, pkgmgr::PkgSection::Other, 1024 * 1024) {
                Ok(()) => shell_println!("Installed '{}' v{}.", name, version),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "remove" => {
            if parts.len() < 2 {
                shell_println!("Usage: pkg remove <name>");
                return;
            }
            match pkgmgr::remove(parts[1]) {
                Ok(()) => shell_println!("Removed '{}'.", parts[1]),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "info" => {
            if parts.len() < 2 {
                shell_println!("Usage: pkg info <name>");
                return;
            }
            match pkgmgr::get_package(parts[1]) {
                Ok(p) => {
                    shell_println!("Package: {}", p.name);
                    shell_println!("  Version:   {}", p.version);
                    shell_println!("  Available: {}", p.available_version);
                    shell_println!("  Section:   {}", p.section.label());
                    shell_println!("  Status:    {}", p.status.label());
                    shell_println!("  Size:      {} bytes", p.installed_size);
                    shell_println!("  Repo:      {}", p.repo);
                    shell_println!("  Desc:      {}", p.description);
                }
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "search" => {
            if parts.len() < 2 {
                shell_println!("Usage: pkg search <query>");
                return;
            }
            let results = pkgmgr::search(parts[1]);
            if results.is_empty() {
                shell_println!("No matches for '{}'.", parts[1]);
            } else {
                for p in &results {
                    shell_println!("  {} {} — {} [{}]", p.name, p.version, p.description, p.status.label());
                }
            }
        }
        "upgrade" => {
            if parts.len() > 1 {
                match pkgmgr::upgrade(parts[1]) {
                    Ok(()) => shell_println!("Upgraded '{}'.", parts[1]),
                    Err(e) => shell_println!("Error: {:?}", e),
                }
            } else {
                match pkgmgr::upgrade_all() {
                    Ok(n) => shell_println!("Upgraded {} packages.", n),
                    Err(e) => shell_println!("Error: {:?}", e),
                }
            }
        }
        "upgradeable" => {
            let packages = pkgmgr::list_upgradeable();
            if packages.is_empty() {
                shell_println!("All packages up to date.");
            } else {
                for p in &packages {
                    shell_println!("  {} {} → {}", p.name, p.version, p.available_version);
                }
            }
        }
        "repos" => {
            let repos = pkgmgr::list_repos();
            if repos.is_empty() {
                shell_println!("No repositories.");
            } else {
                for r in &repos {
                    let en = if r.enabled { "" } else { " [disabled]" };
                    shell_println!("  {}: {}{}", r.name, r.url, en);
                }
            }
        }
        "addrepo" => {
            if parts.len() < 3 {
                shell_println!("Usage: pkg addrepo <name> <url>");
                return;
            }
            match pkgmgr::add_repo(parts[1], parts[2]) {
                Ok(()) => shell_println!("Added repository '{}'.", parts[1]),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "stats" => {
            let (installed, available, upgradeable, repos, ops) = pkgmgr::stats();
            shell_println!("Installed: {}  Available: {}  Upgradeable: {}  Repos: {}  Ops: {}",
                installed, available, upgradeable, repos, ops);
        }
        "test" => {
            pkgmgr::self_test();
            shell_println!("Package manager self-test complete.");
        }
        "init" => {
            pkgmgr::init_defaults();
            shell_println!("Package manager initialized.");
        }
        "help" => {
            shell_println!("pkgmgr (pkg) — package management");
            shell_println!("  show                  Overview");
            shell_println!("  list                  Installed packages");
            shell_println!("  install <name> [ver]  Install package");
            shell_println!("  remove <name>         Remove package");
            shell_println!("  info <name>           Package details");
            shell_println!("  search <query>        Search packages");
            shell_println!("  upgrade [name]        Upgrade one or all");
            shell_println!("  upgradeable           List available upgrades");
            shell_println!("  repos / addrepo       Repository management");
            shell_println!("  stats / test / init");
        }
        _ => {
            shell_println!("Unknown subcommand: {}", sub);
            shell_println!("Use 'pkg help' for usage.");
        }
    }
}

/// `remotedesktop` / `rdp` — remote desktop management.
fn cmd_remotedesktop(args: &str) {
    use crate::fs::remotedesktop;
    let parts: Vec<&str> = args.split_whitespace().collect();
    let sub = parts.first().copied().unwrap_or("");
    match sub {
        "show" | "" => {
            let (active, total, enabled, port, _) = remotedesktop::stats();
            shell_println!("Remote Desktop: {} (port {})", if enabled { "enabled" } else { "disabled" }, port);
            shell_println!("  Active sessions: {}  Total: {}", active, total);
            let sessions = remotedesktop::list_sessions();
            for s in &sessions {
                shell_println!("  {}: {} {} → {} [{}]", s.id, s.direction.label(),
                    s.protocol.label(), s.remote_host, s.state.label());
            }
        }
        "enable" | "disable" => {
            let on = sub == "enable";
            match remotedesktop::set_enabled(on) {
                Ok(()) => shell_println!("Remote desktop {}.", if on { "enabled" } else { "disabled" }),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "port" => {
            if parts.len() < 2 { shell_println!("Usage: rdp port <port>"); return; }
            let port: u16 = match parts[1].parse() { Ok(v) => v, Err(_) => { shell_println!("Invalid port"); return; } };
            match remotedesktop::set_port(port) {
                Ok(()) => shell_println!("Port set to {}.", port),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "connect" => {
            if parts.len() < 2 { shell_println!("Usage: rdp connect <host> [port] [rdp|vnc]"); return; }
            let host = parts[1];
            let port: u16 = if parts.len() > 2 { parts[2].parse().unwrap_or(3389) } else { 3389 };
            let proto = if parts.len() > 3 {
                match parts[3] { "vnc" => remotedesktop::RdProtocol::Vnc, _ => remotedesktop::RdProtocol::Rdp }
            } else { remotedesktop::RdProtocol::Rdp };
            match remotedesktop::connect(host, port, proto) {
                Ok(id) => shell_println!("Connecting to {} (session {})...", host, id),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "disconnect" => {
            if parts.len() < 2 { shell_println!("Usage: rdp disconnect <id>"); return; }
            let id: u32 = match parts[1].parse() { Ok(v) => v, Err(_) => { shell_println!("Invalid ID"); return; } };
            match remotedesktop::disconnect(id) {
                Ok(()) => shell_println!("Session {} disconnected.", id),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "quality" => {
            if parts.len() < 2 { shell_println!("Usage: rdp quality <low|medium|high|adaptive>"); return; }
            let q = match parts[1] {
                "low" => remotedesktop::QualityPreset::Low,
                "medium" => remotedesktop::QualityPreset::Medium,
                "high" => remotedesktop::QualityPreset::High,
                "adaptive" => remotedesktop::QualityPreset::Adaptive,
                _ => { shell_println!("Unknown quality preset"); return; }
            };
            match remotedesktop::set_quality(q) {
                Ok(()) => shell_println!("Quality set to {}.", q.label()),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "stats" => {
            let (active, total, enabled, port, ops) = remotedesktop::stats();
            shell_println!("Enabled: {}  Port: {}  Active: {}  Total: {}  Ops: {}", enabled, port, active, total, ops);
        }
        "test" => { remotedesktop::self_test(); shell_println!("Remote desktop self-test complete."); }
        "init" => { remotedesktop::init_defaults(); shell_println!("Remote desktop initialized."); }
        "help" => {
            shell_println!("remotedesktop (rdp) — remote desktop");
            shell_println!("  show                  Status and sessions");
            shell_println!("  enable/disable        Toggle server");
            shell_println!("  port <port>           Set listening port");
            shell_println!("  connect <host> [port] Connect to remote");
            shell_println!("  disconnect <id>       Disconnect session");
            shell_println!("  quality <preset>      Set quality");
            shell_println!("  stats / test / init");
        }
        _ => { shell_println!("Unknown subcommand: {}", sub); shell_println!("Use 'rdp help' for usage."); }
    }
}

/// `restorepoint` / `rpoint` — system restore points.
fn cmd_restorepoint(args: &str) {
    use crate::fs::restorepoint;
    let parts: Vec<&str> = args.split_whitespace().collect();
    let sub = parts.first().copied().unwrap_or("");
    match sub {
        "show" | "" => {
            let points = restorepoint::list_points();
            if points.is_empty() {
                shell_println!("No restore points.");
            } else {
                shell_println!("{:<4} {:<30} {:<16} {}", "ID", "Description", "Type", "Status");
                for p in &points {
                    shell_println!("{:<4} {:<30} {:<16} {}", p.id, p.description, p.restore_type.label(), p.status.label());
                }
            }
            let space = restorepoint::total_space_used();
            shell_println!("Total space: {} bytes", space);
        }
        "create" => {
            if parts.len() < 2 { shell_println!("Usage: rpoint create <description> [type]"); return; }
            let desc = parts[1..].join(" ");
            let rtype = restorepoint::RestoreType::Manual;
            match restorepoint::create(&desc, rtype) {
                Ok(id) => shell_println!("Restore point {} created.", id),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "delete" => {
            if parts.len() < 2 { shell_println!("Usage: rpoint delete <id>"); return; }
            let id: u32 = match parts[1].parse() { Ok(v) => v, Err(_) => { shell_println!("Invalid ID"); return; } };
            match restorepoint::delete(id) {
                Ok(()) => shell_println!("Restore point {} deleted.", id),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "restore" => {
            if parts.len() < 2 { shell_println!("Usage: rpoint restore <id>"); return; }
            let id: u32 = match parts[1].parse() { Ok(v) => v, Err(_) => { shell_println!("Invalid ID"); return; } };
            match restorepoint::restore(id) {
                Ok(p) => shell_println!("Restoring from '{}' (point {})...", p.description, p.id),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "info" => {
            if parts.len() < 2 { shell_println!("Usage: rpoint info <id>"); return; }
            let id: u32 = match parts[1].parse() { Ok(v) => v, Err(_) => { shell_println!("Invalid ID"); return; } };
            match restorepoint::get_point(id) {
                Ok(p) => {
                    shell_println!("Restore Point #{}", p.id);
                    shell_println!("  Description: {}", p.description);
                    shell_println!("  Type:        {}", p.restore_type.label());
                    shell_println!("  Status:      {}", p.status.label());
                    shell_println!("  Size:        {} bytes", p.size_bytes);
                    shell_println!("  OS version:  {}", p.os_version);
                    shell_println!("  FS snapshot: {}", p.has_fs_snapshot);
                    shell_println!("  Config snap: {}", p.has_config_snapshot);
                }
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "auto" => {
            if parts.len() < 2 { shell_println!("Usage: rpoint auto <on|off>"); return; }
            let on = matches!(parts[1], "on" | "true" | "yes");
            match restorepoint::set_auto_create(on) {
                Ok(()) => shell_println!("Auto-create {}.", if on { "enabled" } else { "disabled" }),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "stats" => {
            let (count, created, restored, space, ops) = restorepoint::stats();
            shell_println!("Points: {}  Created: {}  Restored: {}  Space: {} B  Ops: {}",
                count, created, restored, space, ops);
        }
        "test" => { restorepoint::self_test(); shell_println!("Restore point self-test complete."); }
        "init" => { restorepoint::init_defaults(); shell_println!("Restore points initialized."); }
        "help" => {
            shell_println!("restorepoint (rpoint) — system restore points");
            shell_println!("  show                List restore points");
            shell_println!("  create <desc>       Create restore point");
            shell_println!("  delete <id>         Delete point");
            shell_println!("  restore <id>        Restore from point");
            shell_println!("  info <id>           Point details");
            shell_println!("  auto on|off         Auto-create toggle");
            shell_println!("  stats / test / init");
        }
        _ => { shell_println!("Unknown subcommand: {}", sub); shell_println!("Use 'rpoint help' for usage."); }
    }
}

/// `battery` / `batt` — battery and UPS management.
fn cmd_battery(args: &str) {
    use crate::fs::battery;
    let parts: Vec<&str> = args.split_whitespace().collect();
    let sub = parts.first().copied().unwrap_or("");
    match sub {
        "show" | "" => {
            let sources = battery::list_sources();
            if sources.is_empty() {
                shell_println!("No power sources.");
            } else {
                for s in &sources {
                    shell_println!("{}: {} ({}) {}% [{}]", s.id, s.name,
                        s.source_type.label(), s.charge_pct, s.state.label());
                    if s.source_type == battery::PowerSourceType::Battery {
                        if s.time_remaining_min > 0 {
                            shell_println!("  Remaining: {} min", s.time_remaining_min);
                        }
                        shell_println!("  Health: {}  Cycles: {}  Temp: {}°C",
                            s.health.label(), s.cycle_count, s.temperature_mc / 1000);
                        shell_println!("  Capacity: {}/{} mWh (design: {} mWh)",
                            s.energy_remaining_mwh, s.full_charge_capacity_mwh, s.design_capacity_mwh);
                    }
                }
            }
        }
        "info" => {
            if parts.len() < 2 { shell_println!("Usage: batt info <id>"); return; }
            let id: u32 = match parts[1].parse() { Ok(v) => v, Err(_) => { shell_println!("Invalid ID"); return; } };
            match battery::get_source(id) {
                Ok(s) => {
                    shell_println!("Power Source {}: {}", s.id, s.name);
                    shell_println!("  Type:         {}", s.source_type.label());
                    shell_println!("  State:        {}", s.state.label());
                    shell_println!("  Charge:       {}%", s.charge_pct);
                    shell_println!("  Remaining:    {} min", s.time_remaining_min);
                    shell_println!("  Rate:         {} mW", s.power_rate_mw);
                    shell_println!("  Voltage:      {} mV", s.voltage_mv);
                    shell_println!("  Health:       {}", s.health.label());
                    shell_println!("  Cycles:       {}", s.cycle_count);
                    shell_println!("  Temperature:  {} m°C", s.temperature_mc);
                    shell_println!("  Manufacturer: {}", s.manufacturer);
                    shell_println!("  Model:        {}", s.model);
                    shell_println!("  Serial:       {}", s.serial);
                }
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "ac" => {
            if parts.len() < 2 { shell_println!("Usage: batt ac <on|off>"); return; }
            let on = matches!(parts[1], "on" | "true" | "connected");
            match battery::set_ac_connected(on) {
                Ok(()) => shell_println!("AC power: {}", if on { "connected" } else { "disconnected" }),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "alert" => {
            if parts.len() < 3 {
                match battery::get_alerts() {
                    Ok(a) => {
                        shell_println!("Alerts:");
                        shell_println!("  Low:      {}%", a.low_pct);
                        shell_println!("  Critical: {}%  Action: {}", a.critical_pct, a.critical_action);
                        shell_println!("  Charge limit: {} ({}%)",
                            if a.charge_limit_enabled { "on" } else { "off" }, a.charge_limit_pct);
                    }
                    Err(e) => shell_println!("Error: {:?}", e),
                }
                return;
            }
            match parts[1] {
                "low" => {
                    let pct: u8 = match parts[2].parse() { Ok(v) => v, Err(_) => { shell_println!("Invalid %"); return; } };
                    battery::set_low_threshold(pct).ok();
                    shell_println!("Low threshold set to {}%.", pct);
                }
                "critical" => {
                    let pct: u8 = match parts[2].parse() { Ok(v) => v, Err(_) => { shell_println!("Invalid %"); return; } };
                    battery::set_critical_threshold(pct).ok();
                    shell_println!("Critical threshold set to {}%.", pct);
                }
                "action" => {
                    battery::set_critical_action(parts[2]).ok();
                    shell_println!("Critical action set to '{}'.", parts[2]);
                }
                _ => shell_println!("Usage: batt alert low|critical|action <value>"),
            }
        }
        "limit" => {
            if parts.len() < 2 { shell_println!("Usage: batt limit <on|off> [pct]"); return; }
            let on = matches!(parts[1], "on" | "true" | "yes");
            let pct: u8 = if parts.len() > 2 { parts[2].parse().unwrap_or(80) } else { 80 };
            match battery::set_charge_limit(on, pct) {
                Ok(()) => shell_println!("Charge limit: {} ({}%)", if on { "on" } else { "off" }, pct),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "stats" => {
            let (count, pct, state, cycles, alerts, ops) = battery::stats();
            shell_println!("Sources: {}  Charge: {}%  State: {}  Cycles: {}  Alerts: {}  Ops: {}",
                count, pct, state, cycles, alerts, ops);
        }
        "test" => { battery::self_test(); shell_println!("Battery self-test complete."); }
        "init" => { battery::init_defaults(); shell_println!("Battery manager initialized."); }
        "help" => {
            shell_println!("battery (batt) — power source management");
            shell_println!("  show              All power sources");
            shell_println!("  info <id>         Source details");
            shell_println!("  ac on|off         Simulate AC state");
            shell_println!("  alert [low|critical|action <val>]");
            shell_println!("  limit on|off [%]  Charge limit");
            shell_println!("  stats / test / init");
        }
        _ => { shell_println!("Unknown subcommand: {}", sub); shell_println!("Use 'batt help' for usage."); }
    }
}

/// `dictation` / `dict` — speech-to-text dictation.
fn cmd_dictation(args: &str) {
    use crate::fs::dictation;
    let parts: Vec<&str> = args.split_whitespace().collect();
    let sub = parts.first().copied().unwrap_or("");
    match sub {
        "show" | "" => {
            let (state, lang, transcriptions, words, vocab, _) = dictation::stats();
            shell_println!("Dictation: {} ({})", state, if dictation::is_enabled() { "enabled" } else { "disabled" });
            shell_println!("  Language:       {}", lang);
            shell_println!("  Transcriptions: {}", transcriptions);
            shell_println!("  Total words:    {}", words);
            shell_println!("  Custom vocab:   {} entries", vocab);
        }
        "enable" | "disable" => {
            let on = sub == "enable";
            match dictation::set_enabled(on) {
                Ok(()) => shell_println!("Dictation {}.", if on { "enabled" } else { "disabled" }),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "start" => {
            match dictation::start_listening() {
                Ok(()) => shell_println!("Dictation started — listening..."),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "stop" => {
            match dictation::stop_listening() {
                Ok(()) => shell_println!("Dictation stopped."),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "pause" => { dictation::pause().ok(); shell_println!("Dictation paused."); }
        "resume" => { dictation::resume().ok(); shell_println!("Dictation resumed."); }
        "lang" => {
            if parts.len() < 2 {
                shell_println!("Usage: dict lang <en-us|en-gb|de|fr|es|ja|ko|zh|pt|it>");
                return;
            }
            let lang = match parts[1] {
                "en-us" | "en" => dictation::DictationLanguage::EnUs,
                "en-gb" => dictation::DictationLanguage::EnGb,
                "de" => dictation::DictationLanguage::DeDE,
                "fr" => dictation::DictationLanguage::FrFR,
                "es" => dictation::DictationLanguage::EsES,
                "ja" => dictation::DictationLanguage::JaJP,
                "ko" => dictation::DictationLanguage::KoKR,
                "zh" => dictation::DictationLanguage::ZhCN,
                "pt" => dictation::DictationLanguage::PtBR,
                "it" => dictation::DictationLanguage::ItIT,
                _ => { shell_println!("Unknown language: {}", parts[1]); return; }
            };
            match dictation::set_language(lang) {
                Ok(()) => shell_println!("Language set to {}.", lang.label()),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "vocab" => {
            if parts.len() < 2 {
                let vocab = dictation::list_vocab();
                if vocab.is_empty() {
                    shell_println!("No custom vocabulary.");
                } else {
                    for v in &vocab {
                        shell_println!("  {} ({})", v.phrase, v.phonetic);
                    }
                }
            } else if parts.len() >= 3 && parts[1] == "add" {
                let phonetic = if parts.len() > 3 { parts[3..].join(" ") } else { String::new() };
                match dictation::add_vocab(parts[2], &phonetic) {
                    Ok(()) => shell_println!("Added '{}' to vocabulary.", parts[2]),
                    Err(e) => shell_println!("Error: {:?}", e),
                }
            } else if parts.len() >= 3 && parts[1] == "remove" {
                match dictation::remove_vocab(parts[2]) {
                    Ok(()) => shell_println!("Removed '{}' from vocabulary.", parts[2]),
                    Err(e) => shell_println!("Error: {:?}", e),
                }
            } else {
                shell_println!("Usage: dict vocab [add <word> [phonetic] | remove <word>]");
            }
        }
        "recent" => {
            let count: usize = if parts.len() > 1 { parts[1].parse().unwrap_or(5) } else { 5 };
            let recent = dictation::recent_transcriptions(count);
            if recent.is_empty() {
                shell_println!("No recent transcriptions.");
            } else {
                for t in &recent {
                    shell_println!("  #{}: \"{}\" ({}% conf, {}ms)", t.id, t.text, t.confidence, t.duration_ms);
                }
            }
        }
        "history" => {
            if parts.len() > 1 && parts[1] == "clear" {
                match dictation::clear_history() {
                    Ok(n) => shell_println!("Cleared {} transcriptions.", n),
                    Err(e) => shell_println!("Error: {:?}", e),
                }
            } else {
                shell_println!("Usage: dict history clear");
            }
        }
        "stats" => {
            let (state, lang, transcriptions, words, vocab, ops) = dictation::stats();
            shell_println!("State: {}  Lang: {}  Transcriptions: {}  Words: {}  Vocab: {}  Ops: {}",
                state, lang, transcriptions, words, vocab, ops);
        }
        "test" => { dictation::self_test(); shell_println!("Dictation self-test complete."); }
        "init" => { dictation::init_defaults(); shell_println!("Dictation initialized."); }
        "help" => {
            shell_println!("dictation (dict) — speech-to-text input");
            shell_println!("  show                Overview");
            shell_println!("  enable/disable      Toggle dictation");
            shell_println!("  start/stop/pause    Control listening");
            shell_println!("  lang <code>         Set language");
            shell_println!("  vocab [add|remove]  Custom vocabulary");
            shell_println!("  recent [n]          Recent transcriptions");
            shell_println!("  history clear       Clear history");
            shell_println!("  stats / test / init");
        }
        _ => { shell_println!("Unknown subcommand: {}", sub); shell_println!("Use 'dict help' for usage."); }
    }
}

/// `screenreader` / `sr` — screen reader / UI narration.
fn cmd_screenreader(args: &str) {
    use crate::fs::screenreader;
    let parts: Vec<&str> = args.split_whitespace().collect();
    let sub = parts.first().copied().unwrap_or("");
    match sub {
        "show" | "" => {
            let (elems, announcements, queue, enabled, rate, _) = screenreader::stats();
            shell_println!("Screen Reader: {}", if enabled { "enabled" } else { "disabled" });
            shell_println!("  Speech rate:     {}", rate);
            shell_println!("  Elements:        {}", elems);
            shell_println!("  Announcements:   {}", announcements);
            shell_println!("  Speech queue:    {}", queue);
        }
        "enable" | "disable" => {
            let on = sub == "enable";
            match screenreader::set_enabled(on) {
                Ok(()) => shell_println!("Screen reader {}.", if on { "enabled" } else { "disabled" }),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "rate" => {
            if parts.len() < 2 {
                shell_println!("Usage: sr rate <very-slow|slow|normal|fast|very-fast>");
                return;
            }
            let rate = match parts[1] {
                "very-slow" | "veryslow" => screenreader::SpeechRate::VerySlow,
                "slow" => screenreader::SpeechRate::Slow,
                "normal" => screenreader::SpeechRate::Normal,
                "fast" => screenreader::SpeechRate::Fast,
                "very-fast" | "veryfast" => screenreader::SpeechRate::VeryFast,
                _ => { shell_println!("Unknown rate: {}", parts[1]); return; }
            };
            match screenreader::set_speech_rate(rate) {
                Ok(()) => shell_println!("Speech rate set to {}.", rate.label()),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "volume" | "vol" => {
            if parts.len() < 2 {
                let cfg = screenreader::get_config();
                match cfg {
                    Ok(c) => shell_println!("Volume: {}%", c.volume),
                    Err(e) => shell_println!("Error: {:?}", e),
                }
                return;
            }
            let vol: u32 = match parts[1].parse() {
                Ok(v) => v,
                Err(_) => { shell_println!("Invalid volume."); return; }
            };
            match screenreader::set_volume(vol) {
                Ok(()) => shell_println!("Volume set to {}%.", vol.min(100)),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "verbosity" | "verb" => {
            if parts.len() < 2 {
                shell_println!("Usage: sr verbosity <low|medium|high>");
                return;
            }
            let v = match parts[1] {
                "low" => screenreader::Verbosity::Low,
                "medium" | "med" => screenreader::Verbosity::Medium,
                "high" => screenreader::Verbosity::High,
                _ => { shell_println!("Unknown verbosity: {}", parts[1]); return; }
            };
            match screenreader::set_verbosity(v) {
                Ok(()) => shell_println!("Verbosity set to {}.", v.label()),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "announce" => {
            if parts.len() < 2 {
                shell_println!("Usage: sr announce <text>");
                return;
            }
            let text = parts[1..].join(" ");
            match screenreader::announce(&text) {
                Ok(()) => shell_println!("Announced: \"{}\"", text),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "elements" | "elems" => {
            let elems = screenreader::list_elements();
            if elems.is_empty() {
                shell_println!("No registered elements.");
            } else {
                shell_println!("{:<6} {:<16} {:<24} {}", "ID", "Role", "Name", "Focused");
                for e in &elems {
                    shell_println!("{:<6} {:<16} {:<24} {}",
                        e.id, e.role.label(), e.name, if e.focused { "*" } else { "" });
                }
            }
        }
        "queue" => {
            let len = screenreader::speech_queue_len();
            shell_println!("Speech queue: {} items", len);
            let mut count = 0;
            while count < 10 {
                if let Some(item) = screenreader::next_speech() {
                    shell_println!("  [{}] {}", count + 1, item);
                    count += 1;
                } else {
                    break;
                }
            }
            if count == 0 {
                shell_println!("  (empty)");
            }
        }
        "focus" => {
            match screenreader::focused_element() {
                Some(e) => shell_println!("Focused: #{} {} \"{}\"", e.id, e.role.label(), e.name),
                None => shell_println!("No focused element."),
            }
        }
        "stats" => {
            let (elems, announcements, queue, enabled, rate, ops) = screenreader::stats();
            shell_println!("Elements: {}  Announcements: {}  Queue: {}  Enabled: {}  Rate: {}  Ops: {}",
                elems, announcements, queue, enabled, rate, ops);
        }
        "test" => { screenreader::self_test(); shell_println!("Screen reader self-test complete."); }
        "init" => { screenreader::init_defaults(); shell_println!("Screen reader initialized."); }
        "help" => {
            shell_println!("screenreader (sr) — screen reader / UI narration");
            shell_println!("  show               Overview");
            shell_println!("  enable/disable      Toggle screen reader");
            shell_println!("  rate <speed>        Set speech rate");
            shell_println!("  volume [0-100]      Get/set volume");
            shell_println!("  verbosity <level>   Set verbosity (low/medium/high)");
            shell_println!("  announce <text>     Push text to TTS queue");
            shell_println!("  elements            List registered elements");
            shell_println!("  queue               Show/drain speech queue");
            shell_println!("  focus               Show focused element");
            shell_println!("  stats / test / init");
        }
        _ => { shell_println!("Unknown subcommand: {}", sub); shell_println!("Use 'sr help' for usage."); }
    }
}

/// `langpack` / `lpack` — language pack and translation management.
fn cmd_langpack(args: &str) {
    use crate::fs::langpack;
    let parts: Vec<&str> = args.split_whitespace().collect();
    let sub = parts.first().copied().unwrap_or("");
    match sub {
        "show" | "" => {
            let (total, installed, lang, lookups, misses, _) = langpack::stats();
            shell_println!("Language Packs");
            shell_println!("  System language: {}", lang);
            shell_println!("  Installed:       {}/{}", installed, total);
            shell_println!("  Lookups:         {} ({} misses)", lookups, misses);
            shell_println!("  RTL:             {}", if langpack::is_rtl() { "yes" } else { "no" });
        }
        "list" => {
            let packs = langpack::list_packs();
            if packs.is_empty() {
                shell_println!("No language packs.");
            } else {
                shell_println!("{:<10} {:<20} {:<20} {:<12} {}",
                    "Code", "Native", "English", "Status", "RTL");
                for p in &packs {
                    shell_println!("{:<10} {:<20} {:<20} {:<12} {}",
                        p.code, p.native_name, p.english_name, p.status.label(),
                        if p.rtl { "yes" } else { "no" });
                }
            }
        }
        "install" => {
            if parts.len() < 4 {
                shell_println!("Usage: lpack install <code> <native-name> <english-name> [rtl] [keyboard]");
                return;
            }
            let code = parts[1];
            let native = parts[2];
            let english = parts[3];
            let rtl = parts.get(4).copied() == Some("rtl");
            let kb = parts.get(if rtl { 5 } else { 4 }).copied().unwrap_or(code);
            match langpack::install(code, native, english, rtl, kb) {
                Ok(()) => shell_println!("Installed language pack: {} ({})", english, code),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "remove" | "uninstall" => {
            if parts.len() < 2 {
                shell_println!("Usage: lpack remove <code>");
                return;
            }
            match langpack::uninstall(parts[1]) {
                Ok(()) => shell_println!("Removed language pack: {}", parts[1]),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "set" | "use" => {
            if parts.len() < 2 {
                shell_println!("Usage: lpack set <code>");
                return;
            }
            match langpack::set_system_language(parts[1]) {
                Ok(()) => shell_println!("System language set to {}.", parts[1]),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "translate" | "tr" => {
            if parts.len() < 2 {
                shell_println!("Usage: lpack translate <key>");
                return;
            }
            let result = langpack::translate(parts[1]);
            shell_println!("{} → {}", parts[1], result);
        }
        "addstr" => {
            if parts.len() < 3 {
                shell_println!("Usage: lpack addstr <key> <value...>");
                return;
            }
            let value = parts[2..].join(" ");
            match langpack::add_translation(parts[1], &value) {
                Ok(()) => shell_println!("Added: {} = \"{}\"", parts[1], value),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "info" => {
            if parts.len() < 2 {
                shell_println!("Usage: lpack info <code>");
                return;
            }
            match langpack::get_pack(parts[1]) {
                Ok(p) => {
                    shell_println!("Language: {} ({})", p.english_name, p.code);
                    shell_println!("  Native name:  {}", p.native_name);
                    shell_println!("  Status:       {}", p.status.label());
                    shell_println!("  Strings:      {}", p.string_count);
                    shell_println!("  Completeness: {}%", p.completeness_pct);
                    shell_println!("  Size:         {} KiB", p.size_bytes / 1024);
                    shell_println!("  Keyboard:     {}", p.keyboard_layout);
                    shell_println!("  RTL:          {}", if p.rtl { "yes" } else { "no" });
                }
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "rtl" => {
            shell_println!("Current language RTL: {}", if langpack::is_rtl() { "yes" } else { "no" });
        }
        "stats" => {
            let (total, installed, lang, lookups, misses, ops) = langpack::stats();
            shell_println!("Packs: {}/{}  Lang: {}  Lookups: {}  Misses: {}  Ops: {}",
                installed, total, lang, lookups, misses, ops);
        }
        "test" => { langpack::self_test(); shell_println!("Language pack self-test complete."); }
        "init" => { langpack::init_defaults(); shell_println!("Language pack manager initialized."); }
        "help" => {
            shell_println!("langpack (lpack) — language and translation management");
            shell_println!("  show               Overview");
            shell_println!("  list               List installed packs");
            shell_println!("  install <args>      Install a language pack");
            shell_println!("  remove <code>       Remove a language pack");
            shell_println!("  set <code>          Set system language");
            shell_println!("  translate <key>     Translate a string key");
            shell_println!("  addstr <key> <val>  Add a translation string");
            shell_println!("  info <code>         Pack details");
            shell_println!("  rtl                 Check RTL status");
            shell_println!("  stats / test / init");
        }
        _ => { shell_println!("Unknown subcommand: {}", sub); shell_println!("Use 'lpack help' for usage."); }
    }
}

/// `spellcheck` / `spell` — system spell checker.
fn cmd_spellcheck(args: &str) {
    use crate::fs::spellcheck;
    let parts: Vec<&str> = args.split_whitespace().collect();
    let sub = parts.first().copied().unwrap_or("");
    match sub {
        "show" | "" => {
            let (dicts, personal, checks, misspellings, corrections, _) = spellcheck::stats();
            shell_println!("Spell Checker");
            shell_println!("  Dictionaries: {}", dicts);
            shell_println!("  Personal:     {} words", personal);
            shell_println!("  Checks:       {}", checks);
            shell_println!("  Misspellings: {}", misspellings);
            shell_println!("  Corrections:  {}", corrections);
        }
        "check" => {
            if parts.len() < 2 {
                shell_println!("Usage: spell check <word>");
                return;
            }
            let result = spellcheck::check_word(parts[1]);
            shell_println!("{}: {}", parts[1], result.label());
            if result == spellcheck::CheckResult::Misspelled {
                let suggestions = spellcheck::suggest(parts[1]);
                if !suggestions.is_empty() {
                    shell_println!("  Suggestions: {}", suggestions.join(", "));
                }
            }
        }
        "add" => {
            if parts.len() < 2 {
                shell_println!("Usage: spell add <word>");
                return;
            }
            match spellcheck::add_personal(parts[1]) {
                Ok(()) => shell_println!("Added '{}' to personal dictionary.", parts[1]),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "remove" => {
            if parts.len() < 2 {
                shell_println!("Usage: spell remove <word>");
                return;
            }
            match spellcheck::remove_personal(parts[1]) {
                Ok(()) => shell_println!("Removed '{}' from personal dictionary.", parts[1]),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "ignore" => {
            if parts.len() < 2 {
                shell_println!("Usage: spell ignore <word>");
                return;
            }
            match spellcheck::ignore_word(parts[1]) {
                Ok(()) => shell_println!("Ignoring '{}'.", parts[1]),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "personal" => {
            let words = spellcheck::list_personal();
            if words.is_empty() {
                shell_println!("Personal dictionary is empty.");
            } else {
                shell_println!("Personal dictionary ({} words):", words.len());
                for w in &words {
                    shell_println!("  {}", w);
                }
            }
        }
        "dicts" => {
            let dicts = spellcheck::list_dictionaries();
            shell_println!("{:<12} {:<8} {}", "Language", "Words", "Active");
            for d in &dicts {
                shell_println!("{:<12} {:<8} {}", d.language, d.word_count, if d.active { "*" } else { "" });
            }
        }
        "enable" | "disable" => {
            let on = sub == "enable";
            match spellcheck::set_enabled(on) {
                Ok(()) => shell_println!("Spell checker {}.", if on { "enabled" } else { "disabled" }),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "stats" => {
            let (dicts, personal, checks, misspellings, corrections, ops) = spellcheck::stats();
            shell_println!("Dicts: {}  Personal: {}  Checks: {}  Misspelled: {}  Corrections: {}  Ops: {}",
                dicts, personal, checks, misspellings, corrections, ops);
        }
        "test" => { spellcheck::self_test(); shell_println!("Spell check self-test complete."); }
        "init" => { spellcheck::init_defaults(); shell_println!("Spell checker initialized."); }
        "help" => {
            shell_println!("spellcheck (spell) — system spell checker");
            shell_println!("  show               Overview");
            shell_println!("  check <word>        Check a word");
            shell_println!("  add <word>          Add to personal dictionary");
            shell_println!("  remove <word>       Remove from personal dictionary");
            shell_println!("  ignore <word>       Ignore a word");
            shell_println!("  personal            List personal dictionary");
            shell_println!("  dicts               List dictionaries");
            shell_println!("  enable/disable      Toggle");
            shell_println!("  stats / test / init");
        }
        _ => { shell_println!("Unknown subcommand: {}", sub); shell_println!("Use 'spell help' for usage."); }
    }
}

/// `screentime` / `stime` — screen time and app usage tracking.
fn cmd_screentime(args: &str) {
    use crate::fs::screentime;
    let parts: Vec<&str> = args.split_whitespace().collect();
    let sub = parts.first().copied().unwrap_or("");
    match sub {
        "show" | "" => {
            let (apps, active, idle, switches, _, _) = screentime::stats();
            let active_mins = active / 60;
            let idle_mins = idle / 60;
            shell_println!("Screen Time (Today)");
            shell_println!("  Active:       {} min", active_mins);
            shell_println!("  Idle:         {} min", idle_mins);
            shell_println!("  App switches: {}", switches);
            shell_println!("  Tracked apps: {}", apps);
            shell_println!("  State:        {}", screentime::activity_state().label());
        }
        "apps" => {
            let apps = screentime::app_usage();
            if apps.is_empty() {
                shell_println!("No app usage data.");
            } else {
                shell_println!("{:<24} {:>10} {:>8}", "App", "Focus(s)", "Count");
                for a in &apps {
                    shell_println!("{:<24} {:>10} {:>8}", a.app_name, a.focus_secs, a.focus_count);
                }
            }
        }
        "today" => {
            let s = screentime::today_summary();
            shell_println!("Today: {} min active, {} min idle, {} switches",
                s.active_secs / 60, s.idle_secs / 60, s.app_switches);
            shell_println!("  Top app: {} ({} min)", s.top_app, s.top_app_secs / 60);
        }
        "limit" => {
            if parts.len() < 2 {
                let limits = screentime::get_limits();
                if limits.daily_limit_mins == 0 {
                    shell_println!("No daily limit set.");
                } else {
                    shell_println!("Daily limit: {} min", limits.daily_limit_mins);
                    shell_println!("Exceeded: {}", if screentime::limit_exceeded() { "yes" } else { "no" });
                }
                return;
            }
            let mins: u32 = match parts[1].parse() {
                Ok(m) => m,
                Err(_) => { shell_println!("Invalid minutes."); return; }
            };
            match screentime::set_daily_limit(mins) {
                Ok(()) => shell_println!("Daily limit set to {} min.", mins),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "enable" | "disable" => {
            let on = sub == "enable";
            match screentime::set_enabled(on) {
                Ok(()) => shell_println!("Screen time tracking {}.", if on { "enabled" } else { "disabled" }),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "reset" => {
            match screentime::reset_daily() {
                Ok(()) => shell_println!("Daily counters reset."),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "stats" => {
            let (apps, active, idle, switches, focus_events, ops) = screentime::stats();
            shell_println!("Apps: {}  Active: {}s  Idle: {}s  Switches: {}  Focus: {}  Ops: {}",
                apps, active, idle, switches, focus_events, ops);
        }
        "test" => { screentime::self_test(); shell_println!("Screen time self-test complete."); }
        "init" => { screentime::init_defaults(); shell_println!("Screen time initialized."); }
        "help" => {
            shell_println!("screentime (stime) — app usage and screen time tracking");
            shell_println!("  show               Today's overview");
            shell_println!("  apps               Per-app usage breakdown");
            shell_println!("  today              Daily summary");
            shell_println!("  limit [mins]       Get/set daily limit");
            shell_println!("  enable/disable     Toggle tracking");
            shell_println!("  reset              Reset daily counters");
            shell_println!("  stats / test / init");
        }
        _ => { shell_println!("Unknown subcommand: {}", sub); shell_println!("Use 'stime help' for usage."); }
    }
}

/// `disksmart` / `smart` — disk S.M.A.R.T. health monitoring.
fn cmd_disksmart(args: &str) {
    use crate::fs::disksmart;
    use alloc::format;
    let parts: Vec<&str> = args.split_whitespace().collect();
    let sub = parts.first().copied().unwrap_or("");
    match sub {
        "show" | "" => {
            let (drives, good, warn, checks, alerts, _) = disksmart::stats();
            shell_println!("Disk S.M.A.R.T. Health");
            shell_println!("  Drives:     {}", drives);
            shell_println!("  Healthy:    {}", good);
            shell_println!("  Warnings:   {}", warn);
            shell_println!("  Checks:     {}", checks);
            shell_println!("  Alerts:     {}", alerts);
        }
        "list" => {
            let drives = disksmart::list_drives();
            if drives.is_empty() {
                shell_println!("No drives monitored.");
            } else {
                shell_println!("{:<14} {:<28} {:<8} {:<8} {:<6} {}",
                    "Device", "Model", "Health", "Temp", "Wear%", "Hours");
                for d in &drives {
                    shell_println!("{:<14} {:<28} {:<8} {:<8} {:<6} {}",
                        d.device, d.model, d.health.label(),
                        format!("{}°C", d.temperature_c), d.wear_level_pct, d.power_on_hours);
                }
            }
        }
        "info" => {
            if parts.len() < 2 {
                shell_println!("Usage: smart info <device>");
                return;
            }
            match disksmart::get_drive(parts[1]) {
                Ok(d) => {
                    shell_println!("Drive: {} ({})", d.model, d.device);
                    shell_println!("  Serial:       {}", d.serial);
                    shell_println!("  Firmware:     {}", d.firmware);
                    shell_println!("  Interface:    {}", d.interface.label());
                    shell_println!("  Capacity:     {} GiB", d.capacity_bytes / (1024 * 1024 * 1024));
                    shell_println!("  Health:       {}", d.health.label());
                    shell_println!("  Temperature:  {}°C", d.temperature_c);
                    shell_println!("  Power-on:     {} hours", d.power_on_hours);
                    shell_println!("  Power cycles: {}", d.power_cycles);
                    shell_println!("  Reallocated:  {}", d.reallocated_sectors);
                    shell_println!("  Pending:      {}", d.pending_sectors);
                    shell_println!("  Wear level:   {}%", d.wear_level_pct);
                    if !d.last_test_result.is_empty() {
                        shell_println!("  Last test:    {}", d.last_test_result);
                    }
                    if !d.attributes.is_empty() {
                        shell_println!("  Attributes:");
                        for a in &d.attributes {
                            shell_println!("    [{:>3}] {:<30} val={:<4} worst={:<4} thresh={:<4} raw={}",
                                a.id, a.name, a.current, a.worst, a.threshold, a.raw_value);
                        }
                    }
                }
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "check" => {
            let alerts = disksmart::check_thresholds();
            if alerts == 0 {
                shell_println!("All drives healthy — no alerts.");
            } else {
                shell_println!("{} alert(s) detected!", alerts);
            }
        }
        "stats" => {
            let (drives, good, warn, checks, alerts, ops) = disksmart::stats();
            shell_println!("Drives: {}  Good: {}  Warn: {}  Checks: {}  Alerts: {}  Ops: {}",
                drives, good, warn, checks, alerts, ops);
        }
        "test" => { disksmart::self_test(); shell_println!("Disk S.M.A.R.T. self-test complete."); }
        "init" => { disksmart::init_defaults(); shell_println!("Disk S.M.A.R.T. initialized."); }
        "help" => {
            shell_println!("disksmart (smart) — disk health monitoring");
            shell_println!("  show               Overview");
            shell_println!("  list               List monitored drives");
            shell_println!("  info <device>       Detailed drive info");
            shell_println!("  check              Run threshold check");
            shell_println!("  stats / test / init");
        }
        _ => { shell_println!("Unknown subcommand: {}", sub); shell_println!("Use 'smart help' for usage."); }
    }
}

/// `magnifier` / `mag` — accessibility screen magnification.
fn cmd_magnifier(args: &str) {
    use crate::fs::magnifier;
    let parts: Vec<&str> = args.split_whitespace().collect();
    let sub = parts.first().copied().unwrap_or("");
    match sub {
        "show" | "" => {
            let (enabled, zoom, mode, filter, changes, _) = magnifier::stats();
            shell_println!("Magnifier: {}", if enabled { "enabled" } else { "disabled" });
            shell_println!("  Zoom:    {}%", zoom);
            shell_println!("  Mode:    {}", mode);
            shell_println!("  Filter:  {}", filter);
            shell_println!("  Changes: {}", changes);
            let vp = magnifier::get_viewport();
            shell_println!("  Viewport: {}x{} at ({},{})", vp.width, vp.height, vp.x, vp.y);
        }
        "enable" | "disable" => {
            let on = sub == "enable";
            match magnifier::set_enabled(on) {
                Ok(()) => shell_println!("Magnifier {}.", if on { "enabled" } else { "disabled" }),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "zoom" => {
            if parts.len() < 2 {
                shell_println!("Zoom: {}%", magnifier::zoom_level());
                return;
            }
            match parts[1] {
                "in" | "+" => {
                    match magnifier::zoom_in() {
                        Ok(level) => shell_println!("Zoomed in to {}%.", level),
                        Err(e) => shell_println!("Error: {:?}", e),
                    }
                }
                "out" | "-" => {
                    match magnifier::zoom_out() {
                        Ok(level) => shell_println!("Zoomed out to {}%.", level),
                        Err(e) => shell_println!("Error: {:?}", e),
                    }
                }
                _ => {
                    let pct: u32 = match parts[1].parse() {
                        Ok(v) => v,
                        Err(_) => { shell_println!("Invalid zoom level."); return; }
                    };
                    match magnifier::set_zoom(pct) {
                        Ok(()) => shell_println!("Zoom set to {}%.", magnifier::zoom_level()),
                        Err(e) => shell_println!("Error: {:?}", e),
                    }
                }
            }
        }
        "mode" => {
            if parts.len() < 2 {
                shell_println!("Usage: mag mode <fullscreen|lens|docked>");
                return;
            }
            let mode = match parts[1] {
                "fullscreen" | "full" => magnifier::MagMode::FullScreen,
                "lens" => magnifier::MagMode::Lens,
                "docked" | "dock" => magnifier::MagMode::Docked,
                _ => { shell_println!("Unknown mode: {}", parts[1]); return; }
            };
            match magnifier::set_mode(mode) {
                Ok(()) => shell_println!("Mode set to {}.", mode.label()),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "filter" => {
            if parts.len() < 2 {
                shell_println!("Usage: mag filter <none|inverted|grayscale|highcontrast|yellowblack|whiteblack>");
                return;
            }
            let f = match parts[1] {
                "none" => magnifier::ColorFilter::None,
                "inverted" | "invert" => magnifier::ColorFilter::Inverted,
                "grayscale" | "gray" => magnifier::ColorFilter::GrayScale,
                "highcontrast" | "hc" => magnifier::ColorFilter::HighContrast,
                "yellowblack" | "yb" => magnifier::ColorFilter::YellowOnBlack,
                "whiteblack" | "wb" => magnifier::ColorFilter::WhiteOnBlack,
                _ => { shell_println!("Unknown filter: {}", parts[1]); return; }
            };
            match magnifier::set_color_filter(f) {
                Ok(()) => shell_println!("Color filter set to {}.", f.label()),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "stats" => {
            let (enabled, zoom, mode, filter, changes, ops) = magnifier::stats();
            shell_println!("Enabled: {}  Zoom: {}%  Mode: {}  Filter: {}  Changes: {}  Ops: {}",
                enabled, zoom, mode, filter, changes, ops);
        }
        "test" => { magnifier::self_test(); shell_println!("Magnifier self-test complete."); }
        "init" => { magnifier::init_defaults(); shell_println!("Magnifier initialized."); }
        "help" => {
            shell_println!("magnifier (mag) — screen magnification");
            shell_println!("  show               Overview");
            shell_println!("  enable/disable     Toggle magnifier");
            shell_println!("  zoom [in|out|N]    Get/set zoom level");
            shell_println!("  mode <type>        Set view mode");
            shell_println!("  filter <type>      Set color filter");
            shell_println!("  stats / test / init");
        }
        _ => { shell_println!("Unknown subcommand: {}", sub); shell_println!("Use 'mag help' for usage."); }
    }
}

/// `cloudsync` / `csync` — cloud storage synchronization.
fn cmd_cloudsync(args: &str) {
    use crate::fs::cloudsync;
    let parts: Vec<&str> = args.split_whitespace().collect();
    let sub = parts.first().copied().unwrap_or("");
    match sub {
        "show" | "" => {
            let (accounts, syncs, conflicts, active, _) = cloudsync::stats();
            shell_println!("Cloud Sync");
            shell_println!("  Accounts: {} ({} active)", accounts, active);
            shell_println!("  Syncs:    {}", syncs);
            shell_println!("  Conflicts:{}", conflicts);
        }
        "list" => {
            let accts = cloudsync::list_accounts();
            if accts.is_empty() {
                shell_println!("No cloud sync accounts.");
            } else {
                shell_println!("{:<4} {:<12} {:<24} {:<20} {}",
                    "ID", "Provider", "Account", "Local Path", "Enabled");
                for a in &accts {
                    shell_println!("{:<4} {:<12} {:<24} {:<20} {}",
                        a.id, a.provider.label(), a.account_name, a.local_path,
                        if a.enabled { "yes" } else { "no" });
                }
            }
        }
        "add" => {
            if parts.len() < 5 {
                shell_println!("Usage: csync add <provider> <account> <local-path> <remote-path>");
                shell_println!("  Providers: webdav, nextcloud, dropbox, gdrive, onedrive, s3");
                return;
            }
            let provider = match parts[1] {
                "webdav" => cloudsync::CloudProvider::GenericWebDav,
                "nextcloud" | "nc" => cloudsync::CloudProvider::NextCloud,
                "dropbox" | "dbx" => cloudsync::CloudProvider::Dropbox,
                "gdrive" | "google" => cloudsync::CloudProvider::GoogleDrive,
                "onedrive" | "od" => cloudsync::CloudProvider::OneDrive,
                "s3" => cloudsync::CloudProvider::S3Compatible,
                _ => { shell_println!("Unknown provider: {}", parts[1]); return; }
            };
            match cloudsync::add_account(provider, parts[2], parts[3], parts[4]) {
                Ok(id) => shell_println!("Added account #{} ({}).", id, provider.label()),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "remove" => {
            if parts.len() < 2 {
                shell_println!("Usage: csync remove <id>");
                return;
            }
            let id: u32 = match parts[1].parse() {
                Ok(v) => v,
                Err(_) => { shell_println!("Invalid ID."); return; }
            };
            match cloudsync::remove_account(id) {
                Ok(()) => shell_println!("Removed account #{}.", id),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "conflicts" => {
            let conflicts = cloudsync::list_conflicts();
            if conflicts.is_empty() {
                shell_println!("No sync conflicts.");
            } else {
                for c in &conflicts {
                    shell_println!("  [acct #{}] {} (local: {} B, remote: {} B)",
                        c.account_id, c.path, c.local_size, c.remote_size);
                }
            }
        }
        "excludes" => {
            let excludes = cloudsync::list_excludes();
            shell_println!("Excluded patterns ({}):", excludes.len());
            for p in &excludes {
                shell_println!("  {}", p);
            }
        }
        "stats" => {
            let (accounts, syncs, conflicts, active, ops) = cloudsync::stats();
            shell_println!("Accounts: {}  Active: {}  Syncs: {}  Conflicts: {}  Ops: {}",
                accounts, active, syncs, conflicts, ops);
        }
        "test" => { cloudsync::self_test(); shell_println!("Cloud sync self-test complete."); }
        "init" => { cloudsync::init_defaults(); shell_println!("Cloud sync initialized."); }
        "help" => {
            shell_println!("cloudsync (csync) — cloud storage sync");
            shell_println!("  show               Overview");
            shell_println!("  list               List accounts");
            shell_println!("  add <args>          Add sync account");
            shell_println!("  remove <id>         Remove account");
            shell_println!("  conflicts           Show conflicts");
            shell_println!("  excludes            Show exclude patterns");
            shell_println!("  stats / test / init");
        }
        _ => { shell_println!("Unknown subcommand: {}", sub); shell_println!("Use 'csync help' for usage."); }
    }
}

/// `gestures` / `gesture` — touchpad/touchscreen gesture management.
fn cmd_gestures(args: &str) {
    use crate::fs::gestures;
    let parts: Vec<&str> = args.split_whitespace().collect();
    let sub = parts.first().copied().unwrap_or("");
    match sub {
        "show" | "" => {
            let (mappings, total, enabled, natural, _) = gestures::stats();
            shell_println!("Gestures: {}", if enabled { "enabled" } else { "disabled" });
            shell_println!("  Mappings:       {}", mappings);
            shell_println!("  Total gestures: {}", total);
            shell_println!("  Natural scroll: {}", if natural { "on" } else { "off" });
        }
        "list" => {
            let mappings = gestures::list_mappings();
            shell_println!("{:<28} {:<20} {}", "Gesture", "Action", "Enabled");
            for m in &mappings {
                shell_println!("{:<28} {:<20} {}",
                    m.gesture.label(), m.action.label(),
                    if m.enabled { "yes" } else { "no" });
            }
        }
        "enable" | "disable" => {
            let on = sub == "enable";
            match gestures::set_enabled(on) {
                Ok(()) => shell_println!("Gestures {}.", if on { "enabled" } else { "disabled" }),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "natural" => {
            if parts.len() < 2 {
                let cfg = gestures::get_config();
                match cfg {
                    Ok(c) => shell_println!("Natural scroll: {}", if c.natural_scroll { "on" } else { "off" }),
                    Err(e) => shell_println!("Error: {:?}", e),
                }
                return;
            }
            let on = parts[1] == "on" || parts[1] == "true" || parts[1] == "yes";
            match gestures::set_natural_scroll(on) {
                Ok(()) => shell_println!("Natural scroll {}.", if on { "enabled" } else { "disabled" }),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "stats" => {
            let (mappings, total, enabled, natural, ops) = gestures::stats();
            shell_println!("Mappings: {}  Total: {}  Enabled: {}  Natural: {}  Ops: {}",
                mappings, total, enabled, natural, ops);
        }
        "test" => { gestures::self_test(); shell_println!("Gestures self-test complete."); }
        "init" => { gestures::init_defaults(); shell_println!("Gestures initialized."); }
        "help" => {
            shell_println!("gestures (gesture) — touch gesture management");
            shell_println!("  show               Overview");
            shell_println!("  list               List gesture mappings");
            shell_println!("  enable/disable     Toggle gestures");
            shell_println!("  natural [on|off]   Natural scrolling");
            shell_println!("  stats / test / init");
        }
        _ => { shell_println!("Unknown subcommand: {}", sub); shell_println!("Use 'gesture help' for usage."); }
    }
}

/// `soundevents` / `sevents` — system notification sounds.
fn cmd_soundevents(args: &str) {
    use crate::fs::soundevents;
    use alloc::format;
    let parts: Vec<&str> = args.split_whitespace().collect();
    let sub = parts.first().copied().unwrap_or("");
    match sub {
        "show" | "" => {
            let (schemes, mappings, played, enabled, muted, _) = soundevents::stats();
            shell_println!("Sound Events: {}{}", if enabled { "enabled" } else { "disabled" },
                if muted { " (muted)" } else { "" });
            shell_println!("  Scheme:   {}", soundevents::active_scheme());
            shell_println!("  Schemes:  {}", schemes);
            shell_println!("  Mappings: {}", mappings);
            shell_println!("  Played:   {}", played);
        }
        "list" => {
            let mappings = soundevents::list_mappings();
            if mappings.is_empty() {
                shell_println!("No sound mappings in active scheme.");
            } else {
                shell_println!("{:<24} {:<6} {}", "Event", "Vol", "Sound");
                for m in &mappings {
                    shell_println!("{:<24} {:<6} {}",
                        m.event.label(),
                        if m.enabled { format!("{}%", m.volume) } else { String::from("off") },
                        m.sound_path);
                }
            }
        }
        "schemes" => {
            let schemes = soundevents::list_schemes();
            shell_println!("Available schemes:");
            for (name, desc) in &schemes {
                let active = if *name == soundevents::active_scheme() { " *" } else { "" };
                shell_println!("  {}{} — {}", name, active, desc);
            }
        }
        "scheme" => {
            if parts.len() < 2 {
                shell_println!("Active scheme: {}", soundevents::active_scheme());
                return;
            }
            match soundevents::set_scheme(parts[1]) {
                Ok(()) => shell_println!("Scheme set to {}.", parts[1]),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "enable" | "disable" => {
            let on = sub == "enable";
            match soundevents::set_enabled(on) {
                Ok(()) => shell_println!("Sound events {}.", if on { "enabled" } else { "disabled" }),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "mute" | "unmute" => {
            let m = sub == "mute";
            match soundevents::set_muted(m) {
                Ok(()) => shell_println!("Sound events {}.", if m { "muted" } else { "unmuted" }),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "volume" | "vol" => {
            if parts.len() < 2 {
                shell_println!("Usage: sevents volume <0-100>");
                return;
            }
            let vol: u32 = match parts[1].parse() {
                Ok(v) => v,
                Err(_) => { shell_println!("Invalid volume."); return; }
            };
            match soundevents::set_volume(vol) {
                Ok(()) => shell_println!("Volume set to {}%.", vol.min(100)),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "stats" => {
            let (schemes, mappings, played, enabled, muted, ops) = soundevents::stats();
            shell_println!("Schemes: {}  Mappings: {}  Played: {}  Enabled: {}  Muted: {}  Ops: {}",
                schemes, mappings, played, enabled, muted, ops);
        }
        "test" => { soundevents::self_test(); shell_println!("Sound events self-test complete."); }
        "init" => { soundevents::init_defaults(); shell_println!("Sound events initialized."); }
        "help" => {
            shell_println!("soundevents (sevents) — system notification sounds");
            shell_println!("  show               Overview");
            shell_println!("  list               List event→sound mappings");
            shell_println!("  schemes            List sound schemes");
            shell_println!("  scheme <name>       Set active scheme");
            shell_println!("  enable/disable     Toggle sounds");
            shell_println!("  mute/unmute        Mute/unmute");
            shell_println!("  volume <0-100>     Set volume");
            shell_println!("  stats / test / init");
        }
        _ => { shell_println!("Unknown subcommand: {}", sub); shell_println!("Use 'sevents help' for usage."); }
    }
}

/// `usbmgr` / `usb` — USB device management.
fn cmd_usbmgr(args: &str) {
    use crate::fs::usbmgr;
    use alloc::format;
    let parts: Vec<&str> = args.split_whitespace().collect();
    let sub = parts.first().copied().unwrap_or("");
    match sub {
        "show" | "" => {
            let (count, connects, disconnects, safe_removes, power, _) = usbmgr::stats();
            shell_println!("USB Devices");
            shell_println!("  Connected:    {}", count);
            shell_println!("  Connects:     {}", connects);
            shell_println!("  Disconnects:  {}", disconnects);
            shell_println!("  Safe removes: {}", safe_removes);
            shell_println!("  Power draw:   {} mA", power);
        }
        "list" => {
            let devs = usbmgr::list_devices();
            if devs.is_empty() {
                shell_println!("No USB devices connected.");
            } else {
                shell_println!("{:<6} {:<24} {:<14} {:<18} {}",
                    "Bus:P", "Product", "Class", "Speed", "mA");
                for d in &devs {
                    shell_println!("{:<6} {:<24} {:<14} {:<18} {}",
                        format!("{}:{}", d.bus, d.port), d.product, d.class.label(),
                        d.speed.label(), d.power_ma);
                }
            }
        }
        "info" => {
            if parts.len() < 3 {
                shell_println!("Usage: usb info <bus> <port>");
                return;
            }
            let bus: u8 = match parts[1].parse() { Ok(v) => v, Err(_) => { shell_println!("Invalid bus."); return; } };
            let port: u8 = match parts[2].parse() { Ok(v) => v, Err(_) => { shell_println!("Invalid port."); return; } };
            match usbmgr::get_device(bus, port) {
                Ok(d) => {
                    shell_println!("USB Device {}:{}", d.bus, d.port);
                    shell_println!("  Product:      {} ({})", d.product, d.manufacturer);
                    shell_println!("  Vendor/PID:   {:04x}:{:04x}", d.vendor_id, d.product_id);
                    if !d.serial.is_empty() { shell_println!("  Serial:       {}", d.serial); }
                    shell_println!("  Class:        {}", d.class.label());
                    shell_println!("  Speed:        {}", d.speed.label());
                    shell_println!("  Power:        {} mA", d.power_ma);
                    if !d.driver.is_empty() { shell_println!("  Driver:       {}", d.driver); }
                    shell_println!("  Removable:    {}", if d.removable { "yes" } else { "no" });
                }
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "eject" => {
            if parts.len() < 3 {
                shell_println!("Usage: usb eject <bus> <port>");
                return;
            }
            let bus: u8 = match parts[1].parse() { Ok(v) => v, Err(_) => { shell_println!("Invalid bus."); return; } };
            let port: u8 = match parts[2].parse() { Ok(v) => v, Err(_) => { shell_println!("Invalid port."); return; } };
            match usbmgr::safe_remove(bus, port) {
                Ok(()) => shell_println!("Device {}:{} safely removed.", bus, port),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "power" => {
            shell_println!("Total USB power draw: {} mA", usbmgr::total_power_draw());
        }
        "stats" => {
            let (count, connects, disconnects, safe_removes, power, ops) = usbmgr::stats();
            shell_println!("Devices: {}  Connects: {}  Disconnects: {}  SafeRemove: {}  Power: {} mA  Ops: {}",
                count, connects, disconnects, safe_removes, power, ops);
        }
        "test" => { usbmgr::self_test(); shell_println!("USB manager self-test complete."); }
        "init" => { usbmgr::init_defaults(); shell_println!("USB manager initialized."); }
        "help" => {
            shell_println!("usbmgr (usb) — USB device management");
            shell_println!("  show               Overview");
            shell_println!("  list               List connected devices");
            shell_println!("  info <bus> <port>   Device details");
            shell_println!("  eject <bus> <port>  Safely remove device");
            shell_println!("  power              Total power draw");
            shell_println!("  stats / test / init");
        }
        _ => { shell_println!("Unknown subcommand: {}", sub); shell_println!("Use 'usb help' for usage."); }
    }
}

/// `cliphistory` / `cliphist` — clipboard history.
fn cmd_cliphistory(args: &str) {
    use crate::fs::cliphistory;
    let parts: Vec<&str> = args.split_whitespace().collect();
    let sub = parts.first().copied().unwrap_or("");
    match sub {
        "show" | "" => {
            let (entries, pinned, copies, pastes, size, _) = cliphistory::stats();
            shell_println!("Clipboard History");
            shell_println!("  Entries: {} ({} pinned)", entries, pinned);
            shell_println!("  Copies:  {}", copies);
            shell_println!("  Pastes:  {}", pastes);
            shell_println!("  Size:    {} KiB", size / 1024);
        }
        "list" => {
            let count: usize = if parts.len() > 1 { parts[1].parse().unwrap_or(10) } else { 10 };
            let entries = cliphistory::list(count);
            if entries.is_empty() {
                shell_println!("Clipboard history is empty.");
            } else {
                for e in &entries {
                    let preview: String = e.content.chars().take(60).collect();
                    let pin = if e.pinned { " [pinned]" } else { "" };
                    shell_println!("  #{} [{}] {}{}", e.id, e.clip_type.label(), preview, pin);
                }
            }
        }
        "paste" => {
            if parts.len() < 2 {
                shell_println!("Usage: cliphist paste <id>");
                return;
            }
            let id: u64 = match parts[1].parse() { Ok(v) => v, Err(_) => { shell_println!("Invalid ID."); return; } };
            match cliphistory::paste(id) {
                Ok(content) => shell_println!("{}", content),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "pin" => {
            if parts.len() < 2 { shell_println!("Usage: cliphist pin <id>"); return; }
            let id: u64 = match parts[1].parse() { Ok(v) => v, Err(_) => { shell_println!("Invalid ID."); return; } };
            match cliphistory::pin(id) {
                Ok(()) => shell_println!("Entry #{} pinned.", id),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "unpin" => {
            if parts.len() < 2 { shell_println!("Usage: cliphist unpin <id>"); return; }
            let id: u64 = match parts[1].parse() { Ok(v) => v, Err(_) => { shell_println!("Invalid ID."); return; } };
            match cliphistory::unpin(id) {
                Ok(()) => shell_println!("Entry #{} unpinned.", id),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "delete" => {
            if parts.len() < 2 { shell_println!("Usage: cliphist delete <id>"); return; }
            let id: u64 = match parts[1].parse() { Ok(v) => v, Err(_) => { shell_println!("Invalid ID."); return; } };
            match cliphistory::delete(id) {
                Ok(()) => shell_println!("Entry #{} deleted.", id),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "search" => {
            if parts.len() < 2 { shell_println!("Usage: cliphist search <query>"); return; }
            let query = parts[1..].join(" ");
            let results = cliphistory::search(&query);
            if results.is_empty() {
                shell_println!("No matches for '{}'.", query);
            } else {
                for e in &results {
                    let preview: String = e.content.chars().take(60).collect();
                    shell_println!("  #{} [{}] {}", e.id, e.clip_type.label(), preview);
                }
            }
        }
        "clear" => {
            match cliphistory::clear() {
                Ok(n) => shell_println!("Cleared {} entries (pinned entries kept).", n),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "stats" => {
            let (entries, pinned, copies, pastes, size, ops) = cliphistory::stats();
            shell_println!("Entries: {}  Pinned: {}  Copies: {}  Pastes: {}  Size: {} B  Ops: {}",
                entries, pinned, copies, pastes, size, ops);
        }
        "test" => { cliphistory::self_test(); shell_println!("Clipboard history self-test complete."); }
        "init" => { cliphistory::init_defaults(); shell_println!("Clipboard history initialized."); }
        "help" => {
            shell_println!("cliphistory (cliphist) — clipboard history");
            shell_println!("  show               Overview");
            shell_println!("  list [n]           Recent entries");
            shell_println!("  paste <id>          Paste from history");
            shell_println!("  pin/unpin <id>      Pin/unpin entry");
            shell_println!("  delete <id>         Delete entry");
            shell_println!("  search <query>      Search history");
            shell_println!("  clear              Clear non-pinned entries");
            shell_println!("  stats / test / init");
        }
        _ => { shell_println!("Unknown subcommand: {}", sub); shell_println!("Use 'cliphist help' for usage."); }
    }
}

/// `displaycolor` / `dcolor` — ICC color profile management.
fn cmd_displaycolor(args: &str) {
    use crate::fs::displaycolor;
    let parts: Vec<&str> = args.split_whitespace().collect();
    let sub = parts.first().copied().unwrap_or("");
    match sub {
        "show" | "" => {
            let (profiles, displays, calibrated, cals, _) = displaycolor::stats();
            shell_println!("Display Color Management");
            shell_println!("  Profiles:      {}", profiles);
            shell_println!("  Displays:      {}", displays);
            shell_println!("  Calibrated:    {}", calibrated);
            shell_println!("  Calibrations:  {}", cals);
        }
        "profiles" => {
            let profiles = displaycolor::list_profiles();
            shell_println!("{:<4} {:<28} {:<12} {:<8} {}",
                "ID", "Name", "Space", "WP(K)", "Default");
            for p in &profiles {
                shell_println!("{:<4} {:<28} {:<12} {:<8} {}",
                    p.id, p.name, p.color_space.label(), p.white_point_k,
                    if p.is_default { "*" } else { "" });
            }
        }
        "displays" => {
            let assigns = displaycolor::list_assignments();
            shell_println!("{:<4} {:<20} {:<10} {}",
                "ID", "Display", "Profile", "Calibrated");
            for a in &assigns {
                shell_println!("{:<4} {:<20} {:<10} {}",
                    a.display_id, a.display_name, a.profile_id,
                    if a.calibrated { "yes" } else { "no" });
            }
        }
        "assign" => {
            if parts.len() < 3 {
                shell_println!("Usage: dcolor assign <display-id> <profile-id>");
                return;
            }
            let did: u32 = match parts[1].parse() { Ok(v) => v, Err(_) => { shell_println!("Invalid display ID."); return; } };
            let pid: u32 = match parts[2].parse() { Ok(v) => v, Err(_) => { shell_println!("Invalid profile ID."); return; } };
            match displaycolor::assign_profile(did, pid) {
                Ok(()) => shell_println!("Assigned profile #{} to display #{}.", pid, did),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "calibrate" => {
            if parts.len() < 2 {
                shell_println!("Usage: dcolor calibrate <display-id>");
                return;
            }
            let did: u32 = match parts[1].parse() { Ok(v) => v, Err(_) => { shell_println!("Invalid display ID."); return; } };
            match displaycolor::mark_calibrated(did) {
                Ok(()) => shell_println!("Display #{} marked as calibrated.", did),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "stats" => {
            let (profiles, displays, calibrated, cals, ops) = displaycolor::stats();
            shell_println!("Profiles: {}  Displays: {}  Calibrated: {}  Cals: {}  Ops: {}",
                profiles, displays, calibrated, cals, ops);
        }
        "test" => { displaycolor::self_test(); shell_println!("Display color self-test complete."); }
        "init" => { displaycolor::init_defaults(); shell_println!("Display color initialized."); }
        "help" => {
            shell_println!("displaycolor (dcolor) — color profile management");
            shell_println!("  show               Overview");
            shell_println!("  profiles           List color profiles");
            shell_println!("  displays           List display assignments");
            shell_println!("  assign <d> <p>      Assign profile to display");
            shell_println!("  calibrate <d>       Mark display calibrated");
            shell_println!("  stats / test / init");
        }
        _ => { shell_println!("Unknown subcommand: {}", sub); shell_println!("Use 'dcolor help' for usage."); }
    }
}

/// `syslog` / `slog` — system log viewer.
fn cmd_syslog(args: &str) {
    use crate::fs::syslog;
    let parts: Vec<&str> = args.split_whitespace().collect();
    let sub = parts.first().copied().unwrap_or("");
    match sub {
        "show" | "" => {
            let (entries, total, dropped, errors, crits, _) = syslog::stats();
            shell_println!("System Log");
            shell_println!("  Entries:  {}", entries);
            shell_println!("  Total:    {}", total);
            shell_println!("  Dropped:  {}", dropped);
            shell_println!("  Errors:   {}", errors);
            shell_println!("  Critical: {}", crits);
        }
        "tail" => {
            let count: usize = if parts.len() > 1 { parts[1].parse().unwrap_or(20) } else { 20 };
            let entries = syslog::tail(count);
            for e in &entries {
                let ts_secs = e.timestamp_ns / 1_000_000_000;
                shell_println!("[{:>8}s] {:<6} {}: {}",
                    ts_secs, e.severity.label(), e.source, e.message);
            }
        }
        "errors" => {
            let filter = syslog::LogFilter {
                min_severity: Some(syslog::Severity::Error),
                limit: Some(20),
                ..Default::default()
            };
            let entries = syslog::query(&filter);
            if entries.is_empty() {
                shell_println!("No errors in log.");
            } else {
                for e in &entries {
                    let ts_secs = e.timestamp_ns / 1_000_000_000;
                    shell_println!("[{:>8}s] {:<6} {}: {}",
                        ts_secs, e.severity.label(), e.source, e.message);
                }
            }
        }
        "grep" => {
            if parts.len() < 2 {
                shell_println!("Usage: slog grep <text>");
                return;
            }
            let query = parts[1..].join(" ");
            let filter = syslog::LogFilter {
                message: Some(String::from(&query)),
                limit: Some(20),
                ..Default::default()
            };
            let entries = syslog::query(&filter);
            if entries.is_empty() {
                shell_println!("No matches for '{}'.", query);
            } else {
                for e in &entries {
                    shell_println!("[{}] {:<6} {}: {}", e.id, e.severity.label(), e.source, e.message);
                }
            }
        }
        "log" => {
            if parts.len() < 3 {
                shell_println!("Usage: slog log <severity> <message...>");
                return;
            }
            let sev = match syslog::Severity::from_str(parts[1]) {
                Some(s) => s,
                None => { shell_println!("Unknown severity: {}", parts[1]); return; }
            };
            let msg = parts[2..].join(" ");
            match syslog::log(sev, "kshell", &msg) {
                Ok(id) => shell_println!("Logged #{}", id),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "clear" => {
            match syslog::clear() {
                Ok(n) => shell_println!("Cleared {} log entries.", n),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "counts" => {
            let counts = syslog::count_by_severity();
            for (sev, count) in &counts {
                shell_println!("  {:<8} {}", sev.label(), count);
            }
        }
        "stats" => {
            let (entries, total, dropped, errors, crits, ops) = syslog::stats();
            shell_println!("Entries: {}  Total: {}  Dropped: {}  Errors: {}  Critical: {}  Ops: {}",
                entries, total, dropped, errors, crits, ops);
        }
        "test" => { syslog::self_test(); shell_println!("System log self-test complete."); }
        "init" => { syslog::init_defaults(); shell_println!("System log initialized."); }
        "help" => {
            shell_println!("syslog (slog) — system log viewer");
            shell_println!("  show               Overview");
            shell_println!("  tail [n]           Recent entries");
            shell_println!("  errors             Show errors only");
            shell_println!("  grep <text>         Search messages");
            shell_println!("  log <sev> <msg>     Write a log entry");
            shell_println!("  clear              Clear all entries");
            shell_println!("  counts             Count by severity");
            shell_println!("  stats / test / init");
        }
        _ => { shell_println!("Unknown subcommand: {}", sub); shell_println!("Use 'slog help' for usage."); }
    }
}

/// `elog` — system event log (enhanced, hierarchical namespace, structured payload).
///
/// Provides query/filter access to the kernel event log service (eventlog.rs).
/// This is the system-wide event collection infrastructure per roadmap 2.6.
fn cmd_elog(args: &str) {
    use crate::eventlog::{self, EventBuilder, EventFilter, Severity};
    let parts: Vec<&str> = args.split_whitespace().collect();
    let sub = parts.first().copied().unwrap_or("");
    match sub {
        "show" | "" => {
            let st = eventlog::stats();
            shell_println!("System Event Log");
            shell_println!("  Total written: {}", st.total_written);
            shell_println!("  In buffer:     {} / {}", st.buffered, 4096);
            shell_println!("  Dropped:       {}", st.dropped);
            shell_println!("  Serial echo:   {} (and above)", st.serial_echo_level.as_str());
            shell_println!("\n  By severity:");
            for (sev, count) in &st.by_severity {
                if *count > 0 {
                    shell_println!("    {:>8} : {}", sev.as_str(), count);
                }
            }
            if !st.by_namespace.is_empty() {
                shell_println!("\n  By namespace:");
                for (ns, count) in &st.by_namespace {
                    shell_println!("    {:>12} : {}", ns, count);
                }
            }
        }
        "tail" => {
            let count: usize = parts.get(1).and_then(|s| s.parse().ok()).unwrap_or(20);
            let result = eventlog::query(&EventFilter::all(), count.wrapping_add(100));
            // Show the last `count` entries.
            let start = result.events.len().saturating_sub(count);
            for ev in result.events.get(start..).unwrap_or(&[]) {
                print_event(ev);
            }
            if result.events.is_empty() {
                shell_println!("(no events)");
            }
        }
        "ns" | "namespace" => {
            if parts.len() < 2 {
                shell_println!("Usage: elog ns <prefix> [count]");
                shell_println!("  Filter events by namespace prefix.");
                shell_println!("  Examples: elog ns security, elog ns system.boot 5");
                return;
            }
            let prefix = parts[1];
            let count: usize = parts.get(2).and_then(|s| s.parse().ok()).unwrap_or(20);
            let result = eventlog::query(
                &EventFilter::all().namespace(prefix),
                count,
            );
            shell_println!("Events matching namespace '{}': {} found", prefix, result.matched);
            for ev in &result.events {
                print_event(ev);
            }
        }
        "sev" | "severity" => {
            if parts.len() < 2 {
                shell_println!("Usage: elog sev <level> [count]");
                shell_println!("  Show events at or above severity level.");
                shell_println!("  Levels: debug, info, notice, warning, error, critical");
                return;
            }
            let sev = match Severity::from_str_loose(parts[1]) {
                Some(s) => s,
                None => { shell_println!("Unknown severity: {}", parts[1]); return; }
            };
            let count: usize = parts.get(2).and_then(|s| s.parse().ok()).unwrap_or(20);
            let result = eventlog::query(
                &EventFilter::all().min_severity(sev),
                count,
            );
            shell_println!("Events at {} or above: {} found", sev.as_str(), result.matched);
            for ev in &result.events {
                print_event(ev);
            }
        }
        "pid" => {
            if parts.len() < 2 {
                shell_println!("Usage: elog pid <pid> [count]");
                return;
            }
            let pid: u32 = match parts[1].parse() {
                Ok(p) => p,
                Err(_) => { shell_println!("Invalid PID: {}", parts[1]); return; }
            };
            let count: usize = parts.get(2).and_then(|s| s.parse().ok()).unwrap_or(20);
            let result = eventlog::query(
                &EventFilter::all().pid(pid),
                count,
            );
            shell_println!("Events from PID {}: {} found", pid, result.matched);
            for ev in &result.events {
                print_event(ev);
            }
        }
        "service" | "svc" => {
            if parts.len() < 2 {
                shell_println!("Usage: elog svc <name> [count]");
                return;
            }
            let name = parts[1];
            let count: usize = parts.get(2).and_then(|s| s.parse().ok()).unwrap_or(20);
            let result = eventlog::query(
                &EventFilter::all().service(name),
                count,
            );
            shell_println!("Events from service '{}': {} found", name, result.matched);
            for ev in &result.events {
                print_event(ev);
            }
        }
        "grep" | "search" => {
            if parts.len() < 2 {
                shell_println!("Usage: elog grep <text> [count]");
                shell_println!("  Case-insensitive search in event messages.");
                return;
            }
            // Join all remaining words as search text (except optional last number).
            let last = parts.last().and_then(|s| s.parse::<usize>().ok());
            let text = if last.is_some() && parts.len() > 2 {
                parts[1..parts.len().saturating_sub(1)].join(" ")
            } else {
                parts[1..].join(" ")
            };
            let count: usize = last.unwrap_or(20);
            let result = eventlog::query(
                &EventFilter::all().search(&text),
                count,
            );
            shell_println!("Events matching '{}': {} found", text, result.matched);
            for ev in &result.events {
                print_event(ev);
            }
        }
        "emit" | "log" => {
            if parts.len() < 4 {
                shell_println!("Usage: elog emit <namespace> <severity> <message...>");
                shell_println!("  Example: elog emit system.test info \"Test event message\"");
                return;
            }
            let ns = parts[1];
            let sev = match Severity::from_str_loose(parts[2]) {
                Some(s) => s,
                None => { shell_println!("Unknown severity: {}", parts[2]); return; }
            };
            let msg = parts[3..].join(" ");
            EventBuilder::new(ns, sev)
                .message(&msg)
                .service("kshell")
                .emit();
            shell_println!("Event emitted: [{}/{}] {}", sev.as_str(), ns, msg);
        }
        "clear" => {
            eventlog::clear();
            shell_println!("Event log cleared.");
        }
        "echo" => {
            if parts.len() < 2 {
                let level = eventlog::serial_echo_level();
                shell_println!("Serial echo level: {} (and above)", level.as_str());
                shell_println!("Usage: elog echo <level>  to change");
                return;
            }
            match Severity::from_str_loose(parts[1]) {
                Some(sev) => {
                    eventlog::set_serial_echo_level(sev);
                    shell_println!("Serial echo level set to: {}", sev.as_str());
                }
                None => shell_println!("Unknown severity: {}", parts[1]),
            }
        }
        "namespaces" => {
            shell_println!("Valid namespace roots:");
            for ns in eventlog::NAMESPACE_ROOTS {
                shell_println!("  {}.*", ns);
            }
        }
        "test" => {
            match eventlog::self_test() {
                Ok(()) => shell_println!("Event log self-test: PASSED"),
                Err(e) => shell_println!("Event log self-test: FAILED ({:?})", e),
            }
        }
        "stats" => {
            let st = eventlog::stats();
            shell_println!("total={} buffered={} dropped={} seq={}",
                st.total_written, st.buffered, st.dropped, eventlog::current_seq());
        }
        "help" => {
            shell_println!("elog — system event log (hierarchical, structured)");
            shell_println!("  show               Overview and statistics");
            shell_println!("  tail [n]           Recent n events (default 20)");
            shell_println!("  ns <prefix> [n]    Filter by namespace prefix");
            shell_println!("  sev <level> [n]    Filter by minimum severity");
            shell_println!("  pid <pid> [n]      Filter by source PID");
            shell_println!("  svc <name> [n]     Filter by service name");
            shell_println!("  grep <text> [n]    Search in messages");
            shell_println!("  emit <ns> <sev> <msg>  Emit a test event");
            shell_println!("  echo [level]       Serial echo threshold");
            shell_println!("  namespaces         List valid namespace roots");
            shell_println!("  clear              Clear all events");
            shell_println!("  stats / test");
            shell_println!();
            shell_println!("Severity levels: debug info notice warning error critical");
            shell_println!("Namespaces: system.* process.* security.* network.*");
            shell_println!("            storage.* filesystem.* service.* driver.* application.*");
        }
        _ => {
            shell_println!("Unknown subcommand: {}. Use 'elog help'.", sub);
        }
    }
}

/// Print a single event entry in human-readable format.
fn print_event(ev: &crate::eventlog::EventEntry) {
    let ts_secs = ev.timestamp_ns() / 1_000_000_000;
    let ts_ms = (ev.timestamp_ns() / 1_000_000) % 1000;
    let svc = ev.service_str();
    let svc_str = if svc.is_empty() { "-" } else { svc };
    shell_println!("[{:>5}.{:03}s] #{:<5} {:>8} {:24} pid={:<5} svc={}: {}",
        ts_secs, ts_ms, ev.seq(), ev.severity().as_str(),
        ev.namespace_str(), ev.source_pid(), svc_str, ev.message_str());
    // Show payload pairs if any.
    for (key, val) in ev.payload_iter() {
        shell_println!("           {}={}", key, val);
    }
}

/// `logpersist` / `lpersist` — event log persistence to disk.
///
/// Flushes the in-memory event log ring buffer to JSON-lines files
/// on disk, with configurable rotation and pruning.
fn cmd_logpersist(args: &str) {
    use crate::logpersist::{self, RotationMode};
    use crate::eventlog::Severity;
    let parts: Vec<&str> = args.split_whitespace().collect();
    let sub = parts.first().copied().unwrap_or("");
    match sub {
        "show" | "" => {
            let st = logpersist::stats();
            shell_println!("=== Event Log Persistence ===");
            shell_println!("  Enabled:        {}", st.enabled);
            shell_println!("  Mode:           {}", match st.mode {
                RotationMode::Combined => "combined",
                RotationMode::PerNamespace => "per-namespace",
            });
            shell_println!("  Compression:    {}", st.compression.label());
            shell_println!("  Log dir:        {}", st.log_dir);
            shell_println!("  Min severity:   {}", st.min_persist_severity.as_str());
            shell_println!("  Max file size:  {} MiB", st.max_file_size / (1024 * 1024));
            shell_println!("  Max rotated:    {}", st.max_rotated_files);
            shell_println!("  Max total:      {} MiB", st.max_total_storage / (1024 * 1024));
            shell_println!("  Total flushes:  {}", st.total_flushes);
            shell_println!("  Total written:  {} bytes", st.total_bytes_written);
            shell_println!("  Files compressed: {}", st.files_compressed);
            shell_println!("  Bytes saved:    {} bytes", st.bytes_saved_by_compression);
            shell_println!("  Total pruned:   {} files", st.total_pruned);
            shell_println!("  Last seq:       {}", st.global_last_flushed_seq);
            if !st.cursors.is_empty() {
                shell_println!();
                shell_println!("  {:12} {:>8} {:>12} {:>6} {:>10}",
                    "Namespace", "Events", "Bytes", "Rots", "CurSize");
                for (name, events, bytes, rots, cur_size) in &st.cursors {
                    shell_println!("  {:12} {:>8} {:>12} {:>6} {:>10}",
                        name, events, bytes, rots, cur_size);
                }
            }
        }
        "flush" => {
            match logpersist::flush() {
                Ok(n) => shell_println!("Flushed {} events to disk", n),
                Err(e) => shell_println!("Flush error: {:?}", e),
            }
        }
        "prune" => {
            let n = logpersist::prune();
            shell_println!("Pruned {} old log files", n);
        }
        "init" => {
            logpersist::init();
            shell_println!("Log persistence initialized with default config");
        }
        "enable" => {
            logpersist::set_enabled(true);
            shell_println!("Log persistence enabled");
        }
        "disable" => {
            logpersist::set_enabled(false);
            shell_println!("Log persistence disabled");
        }
        "mode" => {
            if let Some(m) = parts.get(1) {
                match *m {
                    "combined" => {
                        logpersist::set_mode(RotationMode::Combined);
                        shell_println!("Mode set to combined");
                    }
                    "per-namespace" | "perns" | "namespace" => {
                        logpersist::set_mode(RotationMode::PerNamespace);
                        shell_println!("Mode set to per-namespace");
                    }
                    _ => shell_println!("Unknown mode: {}. Use 'combined' or 'per-namespace'.", m),
                }
            } else {
                let cfg = logpersist::config();
                shell_println!("Current mode: {}", match cfg.mode {
                    RotationMode::Combined => "combined",
                    RotationMode::PerNamespace => "per-namespace",
                });
            }
        }
        "severity" | "sev" => {
            if let Some(s) = parts.get(1) {
                let sev = match *s {
                    "debug" => Severity::Debug,
                    "info" => Severity::Info,
                    "notice" => Severity::Notice,
                    "warning" | "warn" => Severity::Warning,
                    "error" | "err" => Severity::Error,
                    "critical" | "crit" => Severity::Critical,
                    _ => {
                        shell_println!("Unknown severity: {}", s);
                        return;
                    }
                };
                logpersist::set_min_severity(sev);
                shell_println!("Minimum persist severity set to {}", sev.as_str());
            } else {
                let cfg = logpersist::config();
                shell_println!("Minimum persist severity: {}", cfg.min_persist_severity.as_str());
            }
        }
        "compress" | "compression" => {
            use crate::logpersist::LogCompression;
            if let Some(algo) = parts.get(1) {
                let c = match *algo {
                    "none" | "off" => LogCompression::None,
                    "zstd" => LogCompression::Zstd,
                    "lz4" => LogCompression::Lz4,
                    "gzip" | "gz" => LogCompression::Gzip,
                    _ => {
                        shell_println!("Unknown algorithm: {}. Use: none, zstd, lz4, gzip", algo);
                        return;
                    }
                };
                logpersist::set_compression(c);
                shell_println!("Compression set to {}", c.label());
            } else {
                let c = logpersist::compression();
                shell_println!("Current compression: {}", c.label());
            }
        }
        "test" => {
            match logpersist::self_test() {
                Ok(()) => shell_println!("Log persistence self-test: PASSED"),
                Err(e) => shell_println!("Log persistence self-test: FAILED ({:?})", e),
            }
        }
        "help" => {
            shell_println!("logpersist — event log persistence to disk");
            shell_println!("  show               Status and statistics");
            shell_println!("  flush              Flush new events to disk now");
            shell_println!("  prune              Delete old rotated files exceeding cap");
            shell_println!("  init               Initialize with default config");
            shell_println!("  enable / disable   Toggle persistence");
            shell_println!("  mode [combined|per-namespace]  Set/show rotation mode");
            shell_println!("  severity [level]   Set/show min persist severity");
            shell_println!("  compress [none|zstd|lz4|gzip]  Set/show compression");
            shell_println!("  test               Run self-test");
        }
        _ => {
            shell_println!("Unknown subcommand: {}. Use 'logpersist help'.", sub);
        }
    }
}

/// `svcstart` / `svcs` — service startup orchestration.
///
/// Manages dependency-based parallel service startup, crash restart
/// with exponential backoff, and the startup app list.
fn cmd_svcstart(args: &str) {
    use crate::svcstart;
    let parts: Vec<&str> = args.split_whitespace().collect();
    let sub = parts.first().copied().unwrap_or("");
    match sub {
        "show" | "" => {
            let st = svcstart::stats();
            shell_println!("=== Service Startup Orchestrator ===");
            shell_println!("  Phase:          {}", st.phase.label());
            shell_println!("  Max dep level:  {}", st.max_level);
            shell_println!("  Graph size:     {} services", st.graph_size);
            shell_println!("  Svc started:    {}", st.services_started);
            shell_println!("  Apps launched:  {}", st.apps_launched);
            shell_println!("  Total restarts: {}", st.total_restarts);
            shell_println!("  Max retries:    {}", st.max_retries);
            shell_println!("  Backoff:        {} ms initial, {} ms max",
                st.initial_backoff_ms, st.max_backoff_ms);
            if st.boot_end_ns > st.boot_start_ns {
                let boot_ms = st.boot_end_ns.saturating_sub(st.boot_start_ns) / 1_000_000;
                shell_println!("  Boot time:      {} ms", boot_ms);
            }
        }
        "levels" => {
            let levels = svcstart::start_levels();
            if levels.is_empty() {
                shell_println!("No start levels resolved. Run 'svcstart resolve' first.");
            } else {
                for (i, level) in levels.iter().enumerate() {
                    let names: Vec<&str> = level.iter().map(|(_, n)| n.as_str()).collect();
                    shell_println!("Level {}: {}", i, names.join(", "));
                }
            }
        }
        "resolve" => {
            match svcstart::resolve_dependencies() {
                Ok(()) => {
                    let levels = svcstart::start_levels();
                    shell_println!("Dependency graph resolved: {} levels", levels.len());
                    for (i, level) in levels.iter().enumerate() {
                        let names: Vec<&str> = level.iter().map(|(_, n)| n.as_str()).collect();
                        shell_println!("  Level {}: {}", i, names.join(", "));
                    }
                }
                Err(e) => shell_println!("Resolve failed: {:?}", e),
            }
        }
        "boot" => {
            match svcstart::boot_services() {
                Ok(n) => shell_println!("Boot sequence complete: {} services started", n),
                Err(e) => shell_println!("Boot failed: {:?}", e),
            }
        }
        "crash" => {
            if let Some(id_str) = parts.get(1) {
                if let Ok(id) = id_str.parse::<u32>() {
                    match svcstart::report_crash(id) {
                        Ok(delay) => shell_println!("Crash recorded, restart scheduled (backoff: {} ms)",
                            delay / 1_000_000),
                        Err(e) => shell_println!("Crash report error: {:?}", e),
                    }
                } else {
                    shell_println!("Invalid service ID");
                }
            } else {
                shell_println!("Usage: svcstart crash <service-id>");
            }
        }
        "crashes" => {
            let records = svcstart::crash_records();
            if records.is_empty() {
                shell_println!("No crash records.");
            } else {
                shell_println!("{:16} {:>6} {:>8} {:>8} {:>8}",
                    "Service", "Consec", "Total", "Backoff", "Status");
                for (name, consec, total, backoff_ms, perm) in &records {
                    let status = if *perm { "FAILED" } else { "active" };
                    shell_println!("{:16} {:>6} {:>8} {:>5} ms {:>8}",
                        name, consec, total, backoff_ms, status);
                }
            }
        }
        "reset" => {
            if let Some(id_str) = parts.get(1) {
                if let Ok(id) = id_str.parse::<u32>() {
                    svcstart::reset_crash_count(id);
                    shell_println!("Crash count reset for service {}", id);
                } else {
                    shell_println!("Invalid service ID");
                }
            } else {
                shell_println!("Usage: svcstart reset <service-id>");
            }
        }
        "apps" => {
            let apps = svcstart::list_startup_apps();
            if apps.is_empty() {
                shell_println!("No startup apps configured.");
            } else {
                shell_println!("{:>3} {:>4} {:20} {:30} {:>5} {:>7}",
                    "ID", "Ord", "Name", "Path", "Wait", "On");
                for app in &apps {
                    shell_println!("{:>3} {:>4} {:20} {:30} {:>5} {:>7}",
                        app.id, app.order, app.display_name, app.path,
                        if app.wait_for_ready { "yes" } else { "no" },
                        if app.enabled { "yes" } else { "no" });
                }
            }
        }
        "addapp" => {
            if let (Some(path), Some(name)) = (parts.get(1), parts.get(2)) {
                let wait = parts.get(3).copied() == Some("wait");
                let id = svcstart::add_startup_app(path, "", name, wait);
                shell_println!("Startup app {} added: {} ({})", id, name, path);
            } else {
                shell_println!("Usage: svcstart addapp <path> <name> [wait]");
            }
        }
        "rmapp" => {
            if let Some(id_str) = parts.get(1) {
                if let Ok(id) = id_str.parse::<u32>() {
                    match svcstart::remove_startup_app(id) {
                        Ok(()) => shell_println!("Startup app {} removed", id),
                        Err(e) => shell_println!("Error: {:?}", e),
                    }
                } else {
                    shell_println!("Invalid app ID");
                }
            } else {
                shell_println!("Usage: svcstart rmapp <id>");
            }
        }
        "init" => {
            svcstart::init();
            shell_println!("Startup orchestrator initialized");
        }
        "sockets" | "sock" => {
            use crate::sockact;
            let entries = sockact::list();
            if entries.is_empty() {
                shell_println!("No socket activations configured.");
            } else {
                shell_println!("{:>3} {:>5} {:4} {:>6} {:16} {:12} {:>6} {:>4}",
                    "ID", "SvcID", "Type", "Port", "Service", "State", "Activ", "Pend");
                for e in &entries {
                    shell_println!("{:>3} {:>5} {:4} {:>6} {:16} {:12} {:>6} {:>4}",
                        e.id, e.service_id, e.socket_type.label(),
                        if e.port > 0 { alloc::format!("{}", e.port) } else { alloc::string::String::from("-") },
                        e.service_name, e.state.label(), e.activation_count, e.pending_connections);
                }
            }
        }
        "addsock" => {
            use crate::sockact::{self, SocketSpec, SocketType};
            if parts.len() >= 4 {
                let svc_id_str = parts.get(1).copied().unwrap_or("0");
                let sock_type_str = parts.get(2).copied().unwrap_or("tcp");
                let port_or_path = parts.get(3).copied().unwrap_or("0");
                if let Ok(svc_id) = svc_id_str.parse::<u32>() {
                    let (socket_type, port, path) = match sock_type_str {
                        "tcp" => (SocketType::Tcp, port_or_path.parse::<u16>().unwrap_or(0), String::new()),
                        "udp" => (SocketType::Udp, port_or_path.parse::<u16>().unwrap_or(0), String::new()),
                        "unix" => (SocketType::Unix, 0u16, String::from(port_or_path)),
                        "ipc" => (SocketType::IpcChannel, 0u16, String::from(port_or_path)),
                        _ => {
                            shell_println!("Unknown socket type: {}", sock_type_str);
                            return;
                        }
                    };
                    match sockact::register(svc_id, SocketSpec {
                        socket_type, port, path, bind_addr: String::new(), backlog: 128,
                    }) {
                        Ok(id) => shell_println!("Socket activation entry {} registered", id),
                        Err(e) => shell_println!("Error: {:?}", e),
                    }
                } else {
                    shell_println!("Invalid service ID");
                }
            } else {
                shell_println!("Usage: svcstart addsock <svc-id> <tcp|udp|unix|ipc> <port|path>");
            }
        }
        "rmsock" => {
            use crate::sockact;
            if let Some(id_str) = parts.get(1) {
                if let Ok(id) = id_str.parse::<u32>() {
                    match sockact::unregister(id) {
                        Ok(()) => shell_println!("Socket entry {} removed", id),
                        Err(e) => shell_println!("Error: {:?}", e),
                    }
                } else {
                    shell_println!("Invalid entry ID");
                }
            } else {
                shell_println!("Usage: svcstart rmsock <entry-id>");
            }
        }
        "test" => {
            match svcstart::self_test() {
                Ok(()) => shell_println!("Service startup self-test: PASSED"),
                Err(e) => shell_println!("Service startup self-test: FAILED ({:?})", e),
            }
        }
        "help" => {
            shell_println!("svcstart — service startup orchestration");
            shell_println!("  show               Status and statistics");
            shell_println!("  levels             Show resolved start levels");
            shell_println!("  resolve            Resolve dependency graph");
            shell_println!("  boot               Run full boot sequence");
            shell_println!("  crash <id>         Report a service crash");
            shell_println!("  crashes            Show crash records");
            shell_println!("  reset <id>         Reset crash counter for service");
            shell_println!("  apps               List startup apps");
            shell_println!("  addapp <path> <name> [wait]  Add a startup app");
            shell_println!("  rmapp <id>         Remove a startup app");
            shell_println!("  sockets            List socket activations");
            shell_println!("  addsock <svc-id> <type> <port|path>  Register socket");
            shell_println!("  rmsock <entry-id>  Remove socket activation");
            shell_println!("  init               Initialize orchestrator");
            shell_println!("  test               Run self-test");
        }
        _ => {
            shell_println!("Unknown subcommand: {}. Use 'svcstart help'.", sub);
        }
    }
}

/// `drvmon` — driver monitor: health, crash detection, auto-restart.
fn cmd_drvmon(args: &str) {
    use crate::drvmon;
    let parts: Vec<&str> = args.split_whitespace().collect();
    let sub = parts.first().copied().unwrap_or("");
    match sub {
        "show" | "" => {
            let st = drvmon::stats();
            shell_println!("=== Driver Monitor ===");
            shell_println!("  Monitored:      {}", st.total_drivers);
            shell_println!("  Healthy:        {}", st.healthy);
            shell_println!("  Degraded:       {}", st.degraded);
            shell_println!("  Unresponsive:   {}", st.unresponsive);
            shell_println!("  Restarting:     {}", st.restarting);
            shell_println!("  Failed:         {}", st.failed);
            shell_println!("  Stopped:        {}", st.stopped);
            shell_println!("  Ticks:          {}", st.tick_count);
            shell_println!("  Total crashes:  {}", st.total_crashes);
            shell_println!("  Total restarts: {}", st.total_restarts);
        }
        "list" | "ls" => {
            let drivers = drvmon::list();
            if drivers.is_empty() {
                shell_println!("No monitored drivers.");
            } else {
                shell_println!("{:>3} {:12} {:8} {:>6} {:12} {:>6} {:>6} {:>4}",
                    "ID", "Name", "Bus", "PID", "Health", "Crash", "Rstrt", "Mon");
                for d in &drivers {
                    shell_println!("{:>3} {:12} {:8} {:>6} {:12} {:>6} {:>6} {:>4}",
                        d.id, d.name, d.bus.label(), d.pid, d.health.label(),
                        d.total_crashes, d.total_restarts,
                        if d.monitoring { "yes" } else { "no" });
                }
            }
        }
        "register" | "reg" => {
            use crate::drvmon::{BusType, DriverPolicy};
            if parts.len() >= 3 {
                let name = parts.get(1).copied().unwrap_or("");
                let bus_str = parts.get(2).copied().unwrap_or("pci");
                let pid = parts.get(3).and_then(|s| s.parse::<u32>().ok()).unwrap_or(0);
                let bus = match bus_str {
                    "pci" => BusType::Pci,
                    "usb" => BusType::Usb,
                    "platform" | "plat" => BusType::Platform,
                    "virtual" | "virt" => BusType::Virtual,
                    _ => {
                        shell_println!("Unknown bus: {}. Use: pci, usb, platform, virtual", bus_str);
                        return;
                    }
                };
                match drvmon::register(name, name, bus, pid, DriverPolicy::default()) {
                    Ok(id) => shell_println!("Driver '{}' registered (id={})", name, id),
                    Err(e) => shell_println!("Error: {:?}", e),
                }
            } else {
                shell_println!("Usage: drvmon register <name> <bus> [pid]");
            }
        }
        "crash" => {
            if let Some(id_str) = parts.get(1) {
                if let Ok(id) = id_str.parse::<u32>() {
                    match drvmon::report_crash(id) {
                        Ok(()) => shell_println!("Crash reported for driver {}", id),
                        Err(e) => shell_println!("Error: {:?}", e),
                    }
                } else {
                    shell_println!("Invalid driver ID");
                }
            } else {
                shell_println!("Usage: drvmon crash <id>");
            }
        }
        "restart" => {
            if let Some(id_str) = parts.get(1) {
                if let Ok(id) = id_str.parse::<u32>() {
                    let new_pid = parts.get(2).and_then(|s| s.parse::<u32>().ok()).unwrap_or(0);
                    match drvmon::restart_driver(id, new_pid) {
                        Ok(()) => shell_println!("Driver {} restarted (pid={})", id, new_pid),
                        Err(e) => shell_println!("Error: {:?}", e),
                    }
                } else {
                    shell_println!("Invalid driver ID");
                }
            } else {
                shell_println!("Usage: drvmon restart <id> [new-pid]");
            }
        }
        "tick" => {
            let needs = drvmon::tick();
            if needs.is_empty() {
                shell_println!("All drivers healthy");
            } else {
                shell_println!("Drivers needing attention: {:?}", needs);
            }
        }
        "test" => {
            match drvmon::self_test() {
                Ok(()) => shell_println!("Driver monitor self-test: PASSED"),
                Err(e) => shell_println!("Driver monitor self-test: FAILED ({:?})", e),
            }
        }
        "help" => {
            shell_println!("drvmon — driver monitor (health, crash detection, auto-restart)");
            shell_println!("  show               Statistics overview");
            shell_println!("  list               List monitored drivers");
            shell_println!("  register <name> <bus> [pid]  Register a driver");
            shell_println!("  crash <id>         Report a driver crash");
            shell_println!("  restart <id> [pid] Restart a driver");
            shell_println!("  tick               Run health check cycle");
            shell_println!("  test               Run self-test");
        }
        _ => {
            shell_println!("Unknown subcommand: {}. Use 'drvmon help'.", sub);
        }
    }
}

/// `reslimit` / `rlimit` — per-service resource limits (cgroup-equivalent).
fn cmd_reslimit(args: &str) {
    use crate::reslimit;
    let parts: Vec<&str> = args.split_whitespace().collect();
    let sub = parts.first().copied().unwrap_or("");
    match sub {
        "" | "show" => {
            shell_println!("{}", reslimit::procfs_content());
        }
        "list" => {
            let groups = reslimit::list_groups();
            if groups.is_empty() {
                shell_println!("No resource groups (run 'reslimit init' first)");
            } else {
                shell_println!("{:<6} {:<20} {:<8} {:<8} {}",
                    "ID", "Name", "Parent", "Members", "Enforce");
                for (id, name, parent, members, enforce) in &groups {
                    shell_println!("{:<6} {:<20} {:<8} {:<8} {}",
                        id, name, parent, members,
                        if *enforce { "yes" } else { "no" });
                }
            }
        }
        "create" => {
            if let Some(name) = parts.get(1) {
                let parent: u32 = parts.get(2)
                    .and_then(|s| s.parse().ok())
                    .unwrap_or(0);
                match reslimit::create_group(name, parent) {
                    Ok(id) => shell_println!("Created group '{}' (id={})", name, id),
                    Err(e) => shell_println!("Error: {:?}", e),
                }
            } else {
                shell_println!("Usage: reslimit create <name> [parent-id]");
            }
        }
        "remove" => {
            if let Some(id_str) = parts.get(1) {
                if let Ok(id) = id_str.parse::<u32>() {
                    match reslimit::remove_group(id) {
                        Ok(()) => shell_println!("Removed group {}", id),
                        Err(e) => shell_println!("Error: {:?}", e),
                    }
                } else {
                    shell_println!("Invalid group ID");
                }
            } else {
                shell_println!("Usage: reslimit remove <group-id>");
            }
        }
        "assign" => {
            if let (Some(pid_str), Some(gid_str)) = (parts.get(1), parts.get(2)) {
                if let (Ok(pid), Ok(gid)) = (pid_str.parse::<u32>(), gid_str.parse::<u32>()) {
                    match reslimit::assign_process(pid, gid) {
                        Ok(()) => shell_println!("Assigned pid {} to group {}", pid, gid),
                        Err(e) => shell_println!("Error: {:?}", e),
                    }
                } else {
                    shell_println!("Invalid pid or group ID");
                }
            } else {
                shell_println!("Usage: reslimit assign <pid> <group-id>");
            }
        }
        "unassign" => {
            if let Some(pid_str) = parts.get(1) {
                if let Ok(pid) = pid_str.parse::<u32>() {
                    match reslimit::unassign_process(pid) {
                        Ok(()) => shell_println!("Unassigned pid {}", pid),
                        Err(e) => shell_println!("Error: {:?}", e),
                    }
                } else {
                    shell_println!("Invalid pid");
                }
            } else {
                shell_println!("Usage: reslimit unassign <pid>");
            }
        }
        "setmem" => {
            // reslimit setmem <group-id> <max-rss-mib> [soft-rss-mib]
            if let Some(gid_str) = parts.get(1) {
                if let Ok(gid) = gid_str.parse::<u32>() {
                    let max_mib: u64 = parts.get(2)
                        .and_then(|s| s.parse().ok())
                        .unwrap_or(0);
                    let soft_mib: u64 = parts.get(3)
                        .and_then(|s| s.parse().ok())
                        .unwrap_or(0);
                    let max_rss = if max_mib == 0 { reslimit::UNLIMITED }
                        else { max_mib.saturating_mul(1024 * 1024) };
                    let soft_rss = if soft_mib == 0 { reslimit::UNLIMITED }
                        else { soft_mib.saturating_mul(1024 * 1024) };
                    let limits = reslimit::MemoryLimits {
                        max_rss,
                        max_virtual: reslimit::UNLIMITED,
                        max_kernel_memory: reslimit::UNLIMITED,
                        soft_rss,
                        oom_kill: true,
                        oom_score_adj: 0,
                    };
                    match reslimit::set_memory_limits(gid, limits) {
                        Ok(()) => shell_println!("Memory limits set for group {}", gid),
                        Err(e) => shell_println!("Error: {:?}", e),
                    }
                } else {
                    shell_println!("Invalid group ID");
                }
            } else {
                shell_println!("Usage: reslimit setmem <group-id> <max-rss-mib> [soft-rss-mib]");
                shell_println!("  0 = unlimited");
            }
        }
        "setcpu" => {
            // reslimit setcpu <group-id> <max-percent> [weight]
            if let Some(gid_str) = parts.get(1) {
                if let Ok(gid) = gid_str.parse::<u32>() {
                    let max_pct: u64 = parts.get(2)
                        .and_then(|s| s.parse().ok())
                        .unwrap_or(0);
                    let weight: u32 = parts.get(3)
                        .and_then(|s| s.parse().ok())
                        .unwrap_or(100);
                    let limits = reslimit::CpuLimits {
                        max_cpu_percent: max_pct,
                        affinity_mask: 0,
                        weight,
                        soft: false,
                    };
                    match reslimit::set_cpu_limits(gid, limits) {
                        Ok(()) => shell_println!("CPU limits set for group {}", gid),
                        Err(e) => shell_println!("Error: {:?}", e),
                    }
                } else {
                    shell_println!("Invalid group ID");
                }
            } else {
                shell_println!("Usage: reslimit setcpu <group-id> <max-percent> [weight]");
                shell_println!("  0 = unlimited, weight default = 100");
            }
        }
        "setio" => {
            // reslimit setio <group-id> <read-mbps> <write-mbps> [low-priority]
            if let Some(gid_str) = parts.get(1) {
                if let Ok(gid) = gid_str.parse::<u32>() {
                    let read_mbps: u64 = parts.get(2)
                        .and_then(|s| s.parse().ok())
                        .unwrap_or(0);
                    let write_mbps: u64 = parts.get(3)
                        .and_then(|s| s.parse().ok())
                        .unwrap_or(0);
                    let low_pri = parts.get(4).is_some_and(|s| *s == "low");
                    let read_bps = if read_mbps == 0 { reslimit::UNLIMITED }
                        else { read_mbps.saturating_mul(1_000_000) };
                    let write_bps = if write_mbps == 0 { reslimit::UNLIMITED }
                        else { write_mbps.saturating_mul(1_000_000) };
                    let limits = reslimit::IoLimits {
                        max_read_bps: read_bps,
                        max_write_bps: write_bps,
                        max_read_iops: reslimit::UNLIMITED,
                        max_write_iops: reslimit::UNLIMITED,
                        weight: 100,
                        low_priority: low_pri,
                    };
                    match reslimit::set_io_limits(gid, limits) {
                        Ok(()) => shell_println!("I/O limits set for group {}", gid),
                        Err(e) => shell_println!("Error: {:?}", e),
                    }
                } else {
                    shell_println!("Invalid group ID");
                }
            } else {
                shell_println!("Usage: reslimit setio <group-id> <read-mbps> <write-mbps> [low]");
                shell_println!("  0 = unlimited");
            }
        }
        "setproc" => {
            // reslimit setproc <group-id> <max-procs> <max-threads> <max-files>
            if let Some(gid_str) = parts.get(1) {
                if let Ok(gid) = gid_str.parse::<u32>() {
                    let max_procs: u64 = parts.get(2)
                        .and_then(|s| s.parse().ok())
                        .unwrap_or(0);
                    let max_threads: u64 = parts.get(3)
                        .and_then(|s| s.parse().ok())
                        .unwrap_or(0);
                    let max_files: u64 = parts.get(4)
                        .and_then(|s| s.parse().ok())
                        .unwrap_or(0);
                    let limits = reslimit::ProcessLimits {
                        max_processes: if max_procs == 0 { reslimit::UNLIMITED } else { max_procs },
                        max_threads: if max_threads == 0 { reslimit::UNLIMITED } else { max_threads },
                        max_open_files: if max_files == 0 { reslimit::UNLIMITED } else { max_files },
                    };
                    match reslimit::set_process_limits(gid, limits) {
                        Ok(()) => shell_println!("Process limits set for group {}", gid),
                        Err(e) => shell_println!("Error: {:?}", e),
                    }
                } else {
                    shell_println!("Invalid group ID");
                }
            } else {
                shell_println!("Usage: reslimit setproc <group-id> <max-procs> <max-threads> <max-files>");
                shell_println!("  0 = unlimited");
            }
        }
        "enforce" => {
            if let (Some(gid_str), Some(val)) = (parts.get(1), parts.get(2)) {
                if let Ok(gid) = gid_str.parse::<u32>() {
                    let on = matches!(*val, "on" | "true" | "yes" | "1");
                    match reslimit::set_enforce(gid, on) {
                        Ok(()) => shell_println!("Enforcement {} for group {}",
                            if on { "enabled" } else { "disabled" }, gid),
                        Err(e) => shell_println!("Error: {:?}", e),
                    }
                } else {
                    shell_println!("Invalid group ID");
                }
            } else {
                shell_println!("Usage: reslimit enforce <group-id> <on|off>");
            }
        }
        "info" => {
            if let Some(gid_str) = parts.get(1) {
                if let Ok(gid) = gid_str.parse::<u32>() {
                    match reslimit::get_group(gid) {
                        Ok(g) => {
                            shell_println!("Group '{}' (id={}, parent={})", g.name, g.id, g.parent_id);
                            shell_println!("  Active: {}, Members: {}, Enforce: {}",
                                g.active, g.member_count, g.enforce);
                            shell_println!("  CPU: max {}%, weight={}", g.cpu.max_cpu_percent, g.cpu.weight);
                            shell_println!("  Memory: RSS used={} bytes", g.usage.rss_bytes);
                            shell_println!("  Processes: {}, Threads: {}, Files: {}",
                                g.usage.process_count, g.usage.thread_count, g.usage.open_files);
                        }
                        Err(e) => shell_println!("Error: {:?}", e),
                    }
                } else {
                    shell_println!("Invalid group ID");
                }
            } else {
                shell_println!("Usage: reslimit info <group-id>");
            }
        }
        "init" => {
            reslimit::init();
            shell_println!("Resource limits subsystem initialized");
        }
        "test" => {
            let ok = reslimit::self_test();
            if ok {
                shell_println!("Resource limits self-test: PASSED");
            } else {
                shell_println!("Resource limits self-test: FAILED");
            }
        }
        "help" => {
            shell_println!("reslimit — per-service resource limits (cgroup-equivalent)");
            shell_println!("  show                          Overview of all groups");
            shell_println!("  list                          List groups (compact)");
            shell_println!("  create <name> [parent-id]     Create a resource group");
            shell_println!("  remove <group-id>             Remove an empty group");
            shell_println!("  assign <pid> <group-id>       Assign process to group");
            shell_println!("  unassign <pid>                Remove process from group");
            shell_println!("  info <group-id>               Detailed group info");
            shell_println!("  setmem <gid> <max-mib> [soft] Set memory limits (MiB)");
            shell_println!("  setcpu <gid> <max-%> [weight] Set CPU limits");
            shell_println!("  setio <gid> <r-mbps> <w-mbps> Set I/O bandwidth limits");
            shell_println!("  setproc <gid> <procs> <thr> <files> Set process/thread/file limits");
            shell_println!("  enforce <gid> <on|off>        Toggle enforcement");
            shell_println!("  init                          Initialize subsystem");
            shell_println!("  test                          Run self-tests");
        }
        _ => {
            shell_println!("Unknown subcommand: {}. Use 'reslimit help'.", sub);
        }
    }
}

/// `initproc` / `init` — PID 1 init process management.
fn cmd_initproc(args: &str) {
    use crate::initproc;
    let parts: Vec<&str> = args.split_whitespace().collect();
    let sub = parts.first().copied().unwrap_or("");
    match sub {
        "" | "show" => {
            shell_println!("{}", initproc::procfs_content());
        }
        "state" => {
            shell_println!("System state: {}", initproc::system_state().label());
        }
        "boot" => {
            let stages = initproc::boot_stages();
            if stages.is_empty() {
                shell_println!("No boot stages recorded (run 'initproc start' first)");
            } else {
                shell_println!("{:<15} {:>10}  {}", "Stage", "Duration", "Status");
                for (name, duration_ns, success) in &stages {
                    let us = duration_ns / 1000;
                    let status = if *success { "OK" } else { "FAILED" };
                    shell_println!("{:<15} {:>8} µs  {}", name, us, status);
                }
                shell_println!("\nTotal boot time: {:.2} ms",
                    initproc::boot_time_ns() as f64 / 1_000_000.0);
            }
        }
        "orphans" => {
            shell_println!("Pending orphans: {}", initproc::orphan_count());
        }
        "critical" => {
            if let Some(action) = parts.get(1) {
                match *action {
                    "add" => {
                        if let Some(name) = parts.get(2) {
                            initproc::mark_critical(name);
                            shell_println!("Marked '{}' as critical", name);
                        } else {
                            shell_println!("Usage: initproc critical add <service-name>");
                        }
                    }
                    "remove" => {
                        if let Some(name) = parts.get(2) {
                            initproc::unmark_critical(name);
                            shell_println!("Unmarked '{}' as critical", name);
                        } else {
                            shell_println!("Usage: initproc critical remove <service-name>");
                        }
                    }
                    _ => shell_println!("Usage: initproc critical <add|remove> <name>"),
                }
            } else {
                shell_println!("Usage: initproc critical <add|remove> <name>");
            }
        }
        "start" => {
            match initproc::start() {
                Ok(()) => shell_println!("Init process started, system running"),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "shutdown" => {
            let reason = match parts.get(1).copied() {
                Some("reboot") => initproc::ShutdownReason::Reboot,
                Some("power") => initproc::ShutdownReason::PowerButton,
                _ => initproc::ShutdownReason::UserRequest,
            };
            match initproc::shutdown(reason) {
                Ok(()) => shell_println!("Shutdown complete"),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "tick" => {
            initproc::tick();
            shell_println!("Init tick executed");
        }
        "test" => {
            let ok = initproc::self_test();
            if ok {
                shell_println!("Init process self-test: PASSED");
            } else {
                shell_println!("Init process self-test: FAILED");
            }
        }
        "help" => {
            shell_println!("initproc — PID 1 init process (system orchestrator)");
            shell_println!("  show                  Full status overview");
            shell_println!("  state                 Current system state");
            shell_println!("  boot                  Boot stage timing");
            shell_println!("  orphans               Pending orphan count");
            shell_println!("  critical add <name>   Mark service as critical");
            shell_println!("  critical remove <name> Unmark critical service");
            shell_println!("  start                 Run boot sequence");
            shell_println!("  shutdown [reboot]     Initiate shutdown/reboot");
            shell_println!("  tick                  Run one main loop iteration");
            shell_println!("  test                  Run self-tests");
        }
        _ => {
            shell_println!("Unknown subcommand: {}. Use 'initproc help'.", sub);
        }
    }
}

/// `healthmon` / `hmon` — continuous system health monitoring.
fn cmd_healthmon(args: &str) {
    use crate::syshealth;
    let parts: Vec<&str> = args.split_whitespace().collect();
    let sub = parts.first().copied().unwrap_or("");
    match sub {
        "" | "show" => {
            shell_println!("{}", syshealth::procfs_content());
        }
        "check" => {
            let snap = syshealth::check();
            shell_println!("Overall: {}", snap.overall.label());
            for m in &snap.metrics {
                let indicator = match m.level {
                    syshealth::HealthLevel::Healthy => "[OK]",
                    syshealth::HealthLevel::Warning => "[!!]",
                    syshealth::HealthLevel::Critical => "[XX]",
                    syshealth::HealthLevel::Unknown => "[??]",
                };
                shell_println!("  {} {}: {}", indicator, m.name, m.message);
            }
        }
        "status" => {
            shell_println!("System health: {}", syshealth::overall_health().label());
        }
        "history" => {
            let hist = syshealth::history();
            if hist.is_empty() {
                shell_println!("No history available");
            } else {
                shell_println!("{:<12} {:<10} {}", "Time (s)", "Overall", "Metrics");
                for snap in &hist {
                    let ts_s = snap.timestamp_ns / 1_000_000_000;
                    let metric_summary: Vec<&str> = snap.metrics.iter()
                        .filter(|m| m.level != syshealth::HealthLevel::Healthy
                            && m.level != syshealth::HealthLevel::Unknown)
                        .map(|m| m.name.as_str())
                        .collect();
                    let issues = if metric_summary.is_empty() {
                        alloc::string::String::from("all normal")
                    } else {
                        metric_summary.join(", ")
                    };
                    shell_println!("{:<12} {:<10} {}", ts_s, snap.overall.label(), issues);
                }
            }
        }
        "init" => {
            syshealth::init();
            shell_println!("System health monitor initialized");
        }
        "enable" => {
            syshealth::set_enabled(true);
            shell_println!("Health monitoring enabled");
        }
        "disable" => {
            syshealth::set_enabled(false);
            shell_println!("Health monitoring disabled");
        }
        "test" => {
            let ok = syshealth::self_test();
            if ok {
                shell_println!("System health self-test: PASSED");
            } else {
                shell_println!("System health self-test: FAILED");
            }
        }
        "help" => {
            shell_println!("healthmon — continuous system health monitoring");
            shell_println!("  show            Full status overview");
            shell_println!("  check           Run health check now");
            shell_println!("  status          One-word health status");
            shell_println!("  history         Recent check history");
            shell_println!("  init            Initialize monitor");
            shell_println!("  enable/disable  Toggle monitoring");
            shell_println!("  test            Run self-tests");
        }
        _ => {
            shell_println!("Unknown subcommand: {}. Use 'syshealth help'.", sub);
        }
    }
}

/// `udriver` / `udrvfw` — userspace driver framework status and control.
fn cmd_udriver(args: &str) {
    use crate::udriver;
    let parts: Vec<&str> = args.split_whitespace().collect();
    let sub = parts.first().copied().unwrap_or("");
    match sub {
        "" | "show" => {
            shell_println!("{}", udriver::procfs_content());
        }
        "stats" => {
            let st = udriver::stats();
            shell_println!("Userspace Driver Framework");
            shell_println!("  IOMMU:             {}", if st.iommu_available { "yes" } else { "no" });
            shell_println!("  Total drivers:     {}", st.total_drivers);
            shell_println!("  Active drivers:    {}", st.active_drivers);
            shell_println!("  Unclaimed devices: {}", st.unclaimed_devices);
            shell_println!("  MMIO mapped:       {} KiB", st.total_mmio_bytes / 1024);
            shell_println!("  DMA allocated:     {} KiB", st.total_dma_bytes / 1024);
            shell_println!("  Registrations:     {}", st.total_registrations);
            shell_println!("  Crashes:           {}", st.total_crashes);
            shell_println!("  Cleanups:          {}", st.total_cleanups);
        }
        "unclaimed" | "devices" => {
            let devs = udriver::unclaimed_devices();
            if devs.is_empty() {
                shell_println!("No unclaimed devices");
            } else {
                shell_println!("{:<14} {:<12} {:<12} {}", "Address", "Vendor", "Device", "Class");
                for d in &devs {
                    shell_println!(
                        "{:02x}:{:02x}.{:<8} {:04x}         {:04x}         {:02x}:{:02x}",
                        d.addr.bus, d.addr.device, d.addr.function,
                        d.id.vendor_id, d.id.device_id,
                        d.id.class, d.id.subclass,
                    );
                }
            }
        }
        "drivers" | "list" => {
            let drivers = udriver::all_drivers();
            if drivers.is_empty() {
                shell_println!("No registered drivers");
            } else {
                shell_println!("{:<6} {:<20} {:<8} {:<14} {}", "ID", "Name", "PID", "Device", "State");
                for d in &drivers {
                    let state_str = match d.state {
                        udriver::DriverState::Registered => "registered",
                        udriver::DriverState::Binding => "binding",
                        udriver::DriverState::Active => "active",
                        udriver::DriverState::ShuttingDown => "shutting-down",
                        udriver::DriverState::Crashed => "crashed",
                        udriver::DriverState::Unregistered => "unregistered",
                    };
                    shell_println!(
                        "{:<6} {:<20} {:<8} {:02x}:{:02x}.{:<8} {}",
                        d.id, d.name, d.pid,
                        d.device_addr.bus, d.device_addr.device, d.device_addr.function,
                        state_str,
                    );
                }
            }
        }
        "info" => {
            let id_str = parts.get(1).copied().unwrap_or("");
            if let Ok(id) = id_str.parse::<u32>() {
                if let Some(d) = udriver::get_driver(id) {
                    shell_println!("Driver #{} '{}'", d.id, d.name);
                    shell_println!("  PID:    {}", d.pid);
                    shell_println!("  Device: {:02x}:{:02x}.{} (vendor={:04x} device={:04x})",
                        d.device_addr.bus, d.device_addr.device, d.device_addr.function,
                        d.device_id.vendor_id, d.device_id.device_id);
                    shell_println!("  State:  {:?}", d.state);
                    shell_println!("  MMIO mappings: {}", d.mmio_mappings.len());
                    for m in &d.mmio_mappings {
                        shell_println!("    BAR{}: phys={:#010x} virt={:#010x} size={:#x} {}",
                            m.bar_index, m.phys_base, m.virt_base, m.size,
                            if m.perms.write { "RW" } else { "RO" });
                    }
                    shell_println!("  DMA buffers: {} ({} KiB)", d.dma_buffers.len(), d.total_dma_bytes / 1024);
                    shell_println!("  IRQs: {:?}", d.irq_lines);
                    shell_println!("  IOMMU domain: {:?}", d.iommu_domain);
                    shell_println!("  I/O served: {}", d.io_requests_served);
                } else {
                    shell_println!("Driver #{} not found", id);
                }
            } else {
                shell_println!("Usage: udriver info <id>");
            }
        }
        "test" => {
            udriver::self_test();
            shell_println!("Userspace driver framework self-test: PASSED");
        }
        "help" => {
            shell_println!("udriver — userspace driver framework");
            shell_println!("  show               Full status overview");
            shell_println!("  stats              Summary statistics");
            shell_println!("  unclaimed/devices   List unclaimed devices");
            shell_println!("  drivers/list        List registered drivers");
            shell_println!("  info <id>           Detailed driver info");
            shell_println!("  test                Run self-tests");
        }
        _ => {
            shell_println!("Unknown subcommand: {}. Use 'udriver help'.", sub);
        }
    }
}

/// `devhotplug` / `devhp` — device hotplug event system.
fn cmd_devhotplug(args: &str) {
    use crate::devhotplug;
    let parts: Vec<&str> = args.split_whitespace().collect();
    let sub = parts.first().copied().unwrap_or("");
    match sub {
        "" | "show" => {
            shell_println!("{}", devhotplug::procfs_content());
        }
        "stats" => {
            let st = devhotplug::stats();
            shell_println!("Device Hotplug System");
            shell_println!("  Pending events:   {}", st.pending_events);
            shell_println!("  Total arrived:    {}", st.total_arrived);
            shell_println!("  Total removed:    {}", st.total_removed);
            shell_println!("  Total bindings:   {}", st.total_bindings);
            shell_println!("  Events dropped:   {}", st.events_dropped);
            shell_println!("  Driver DB:        {} entries", st.driver_db_entries);
            shell_println!("  History:          {} entries", st.history_entries);
        }
        "pending" => {
            let events = devhotplug::pending_events();
            if events.is_empty() {
                shell_println!("No pending events");
            } else {
                shell_println!("{} pending event(s):", events.len());
                for e in &events {
                    let addr_str = e.device_addr.map(|a| {
                        alloc::format!("{:02x}:{:02x}.{}", a.bus, a.device, a.function)
                    }).unwrap_or_default();
                    let drv_str = e.matched_driver.as_deref().unwrap_or("-");
                    shell_println!("  #{} {} {} {} → {}", e.id, e.bus.label(), e.kind.label(), addr_str, drv_str);
                }
            }
        }
        "history" => {
            let history = devhotplug::event_history();
            if history.is_empty() {
                shell_println!("No event history");
            } else {
                shell_println!("Event history ({} entries):", history.len());
                for e in &history {
                    let ts_s = e.timestamp_ns / 1_000_000_000;
                    let addr_str = e.device_addr.map(|a| {
                        alloc::format!("{:02x}:{:02x}.{}", a.bus, a.device, a.function)
                    }).unwrap_or_default();
                    let drv_str = e.matched_driver.as_deref().unwrap_or("-");
                    shell_println!("  [{}s] #{} {} {} {} → {}", ts_s, e.id, e.bus.label(), e.kind.label(), addr_str, drv_str);
                }
            }
        }
        "db" | "drivers" => {
            let db = devhotplug::driver_database();
            if db.is_empty() {
                shell_println!("Driver database is empty");
            } else {
                shell_println!("{} driver database entries:", db.len());
                shell_println!("{:<5} {:<10} {:<10} {:<10} {:<20} {}", "ID", "Vendor", "Device", "Class", "Driver", "Priority");
                for e in &db {
                    let v = if e.vendor_id == 0xFFFF { alloc::string::String::from("*") } else { alloc::format!("{:04x}", e.vendor_id) };
                    let d = if e.device_id == 0xFFFF { alloc::string::String::from("*") } else { alloc::format!("{:04x}", e.device_id) };
                    let c = if e.class == 0xFF { alloc::string::String::from("*:") } else { alloc::format!("{:02x}:", e.class) };
                    let s = if e.subclass == 0xFF { alloc::string::String::from("*") } else { alloc::format!("{:02x}", e.subclass) };
                    let enabled = if e.enabled { "" } else { " [off]" };
                    shell_println!("{:<5} {:<10} {:<10} {}{:<7} {:<20} {}{}", e.id, v, d, c, s, e.driver_name, e.priority, enabled);
                }
            }
        }
        "init" => {
            devhotplug::init();
            shell_println!("Hotplug system initialized with built-in driver database");
        }
        "test" => {
            devhotplug::self_test();
            shell_println!("Device hotplug self-test: PASSED");
        }
        "help" => {
            shell_println!("devhotplug — device hotplug event system");
            shell_println!("  show              Full status overview");
            shell_println!("  stats             Summary statistics");
            shell_println!("  pending           List pending events");
            shell_println!("  history           Event history");
            shell_println!("  db/drivers        Driver matching database");
            shell_println!("  init              Initialize with built-in entries");
            shell_println!("  test              Run self-tests");
        }
        _ => {
            shell_println!("Unknown subcommand: {}. Use 'devhotplug help'.", sub);
        }
    }
}

