/// `tftp` / `tftpd` — TFTP client and server.
fn cmd_tftp(args: &str) {
    use crate::net::tftp;
    let parts: Vec<&str> = args.split_whitespace().collect();
    let sub = parts.first().copied().unwrap_or("");
    match sub {
        "" | "show" => {
            shell_println!("{}", tftp::procfs_content());
        }
        "status" | "stats" => {
            let s = tftp::stats();
            shell_println!("TFTP Client/Server");
            shell_println!("  Client: {} gets, {} puts, {} errors, {} timeouts",
                s.client_gets, s.client_puts, s.client_errors, s.client_timeouts);
            shell_println!("  Server: {}",
                if s.server_enabled { "running" } else { "stopped" });
            if s.server_enabled {
                shell_println!("  Root:   {}", s.server_root);
                shell_println!("  Active: {}/4 transfers", s.active_transfers);
            }
            shell_println!("  Requests: {}, completed: {}, errors: {}",
                s.server_requests, s.server_completed, s.server_errors);
        }
        "get" => {
            // tftp get <ip> <filename>
            let ip_str = parts.get(1).copied().unwrap_or("");
            let filename = parts.get(2).copied().unwrap_or("");
            if ip_str.is_empty() || filename.is_empty() {
                shell_println!("Usage: tftp get <server-ip> <filename>");
                return;
            }
            let ip = match parse_ipv4(ip_str) {
                Some(ip) => ip,
                None => {
                    shell_println!("Invalid IP: {}", ip_str);
                    return;
                }
            };
            shell_println!("Downloading {} from {} ...", filename, ip);
            match tftp::get(ip, filename) {
                Ok(data) => {
                    shell_println!("Received {} bytes", data.len());
                    // Save to local filesystem.
                    let local_path = alloc::format!("/{}", filename);
                    match crate::fs::vfs::Vfs::write_file(&local_path, &data) {
                        Ok(()) => shell_println!("Saved to {}", local_path),
                        Err(e) => shell_println!("Save failed: {:?}", e),
                    }
                }
                Err(e) => shell_println!("Download failed: {:?}", e),
            }
        }
        "put" => {
            // tftp put <ip> <filename>
            let ip_str = parts.get(1).copied().unwrap_or("");
            let filename = parts.get(2).copied().unwrap_or("");
            if ip_str.is_empty() || filename.is_empty() {
                shell_println!("Usage: tftp put <server-ip> <filename>");
                return;
            }
            let ip = match parse_ipv4(ip_str) {
                Some(ip) => ip,
                None => {
                    shell_println!("Invalid IP: {}", ip_str);
                    return;
                }
            };
            // Read local file.
            let path = resolve_path(filename);
            match crate::fs::vfs::Vfs::read_file(&path) {
                Ok(data) => {
                    shell_println!("Uploading {} ({} bytes) to {} ...", filename, data.len(), ip);
                    match tftp::put(ip, filename, &data) {
                        Ok(()) => shell_println!("Upload complete"),
                        Err(e) => shell_println!("Upload failed: {:?}", e),
                    }
                }
                Err(e) => shell_println!("Cannot read {}: {:?}", filename, e),
            }
        }
        "get6" => {
            // tftp get6 <ipv6-addr> <filename>
            use crate::net::ipv6::Ipv6Addr;
            let ip_str = parts.get(1).copied().unwrap_or("");
            let filename = parts.get(2).copied().unwrap_or("");
            if ip_str.is_empty() || filename.is_empty() {
                shell_println!("Usage: tftp get6 <server-ipv6> <filename>");
                return;
            }
            let ip6 = match Ipv6Addr::parse(ip_str) {
                Some(addr) => addr,
                None => {
                    shell_println!("Invalid IPv6 address: {}", ip_str);
                    return;
                }
            };
            shell_println!("Downloading {} from {} (IPv6) ...", filename, ip6);
            match tftp::get_v6(ip6, filename) {
                Ok(data) => {
                    shell_println!("Received {} bytes", data.len());
                    let local_path = alloc::format!("/{}", filename);
                    match crate::fs::vfs::Vfs::write_file(&local_path, &data) {
                        Ok(()) => shell_println!("Saved to {}", local_path),
                        Err(e) => shell_println!("Save failed: {:?}", e),
                    }
                }
                Err(e) => shell_println!("Download failed: {:?}", e),
            }
        }
        "put6" => {
            // tftp put6 <ipv6-addr> <filename>
            use crate::net::ipv6::Ipv6Addr;
            let ip_str = parts.get(1).copied().unwrap_or("");
            let filename = parts.get(2).copied().unwrap_or("");
            if ip_str.is_empty() || filename.is_empty() {
                shell_println!("Usage: tftp put6 <server-ipv6> <filename>");
                return;
            }
            let ip6 = match Ipv6Addr::parse(ip_str) {
                Some(addr) => addr,
                None => {
                    shell_println!("Invalid IPv6 address: {}", ip_str);
                    return;
                }
            };
            let path = resolve_path(filename);
            match crate::fs::vfs::Vfs::read_file(&path) {
                Ok(data) => {
                    shell_println!("Uploading {} ({} bytes) to {} (IPv6) ...", filename, data.len(), ip6);
                    match tftp::put_v6(ip6, filename, &data) {
                        Ok(()) => shell_println!("Upload complete"),
                        Err(e) => shell_println!("Upload failed: {:?}", e),
                    }
                }
                Err(e) => shell_println!("Cannot read {}: {:?}", filename, e),
            }
        }
        "serve" | "start" => {
            let root = parts.get(1).copied().unwrap_or("/");
            match tftp::start_server(root) {
                Ok(()) => shell_println!("TFTP server started (root={})", root),
                Err(e) => shell_println!("Failed to start: {:?}", e),
            }
        }
        "stop" => {
            tftp::stop_server();
            shell_println!("TFTP server stopped");
        }
        "test" => {
            match tftp::self_test() {
                Ok(()) => shell_println!("TFTP self-test: PASSED"),
                Err(e) => shell_println!("TFTP self-test FAILED: {:?}", e),
            }
        }
        "help" => {
            shell_println!("tftp — Trivial File Transfer Protocol (IPv4 + IPv6)");
            shell_println!("  show                Full status overview");
            shell_println!("  status              Summary statistics");
            shell_println!("  get <ip> <file>     Download file from server (IPv4)");
            shell_println!("  put <ip> <file>     Upload file to server (IPv4)");
            shell_println!("  get6 <ip6> <file>   Download file from server (IPv6)");
            shell_println!("  put6 <ip6> <file>   Upload file to server (IPv6)");
            shell_println!("  serve [root]        Start TFTP server (default root: /)");
            shell_println!("  stop                Stop TFTP server");
            shell_println!("  test                Run self-tests");
        }
        _ => {
            shell_println!("Unknown subcommand: {}. Use 'tftp help'.", sub);
        }
    }
}

/// `netsyslog` / `rsyslog` — network syslog client/receiver.
fn cmd_netsyslog(args: &str) {
    use crate::net::syslog;
    let parts: Vec<&str> = args.split_whitespace().collect();
    let sub = parts.first().copied().unwrap_or("");
    match sub {
        "" | "show" => {
            shell_println!("{}", syslog::procfs_content());
        }
        "status" | "stats" => {
            let s = syslog::stats();
            shell_println!("Network Syslog");
            shell_println!("  Receiver:    {}",
                if s.receiver_enabled { "running" } else { "stopped" });
            shell_println!("  Forwarder:   {}",
                if s.forwarder_enabled {
                    if let Some((ip6, port)) = s.remote_server_v6 {
                        alloc::format!("→ [{}]:{}", ip6, port)
                    } else if let Some((ip, port)) = s.remote_server {
                        alloc::format!("→ {}:{}", ip, port)
                    } else {
                        String::from("enabled (no server)")
                    }
                } else { String::from("disabled") });
            shell_println!("  Received:    {}", s.messages_received);
            shell_println!("  Forwarded:   {}", s.messages_forwarded);
            shell_println!("  Parse errs:  {}", s.parse_errors);
            shell_println!("  Fwd errors:  {}", s.forward_errors);
            shell_println!("  Buffer:      {}/{}", s.ring_count, 64);
        }
        "listen" | "start" => {
            match syslog::start_receiver() {
                Ok(()) => shell_println!("Syslog receiver started"),
                Err(e) => shell_println!("Failed to start: {:?}", e),
            }
        }
        "stop" => {
            syslog::stop_receiver();
            shell_println!("Syslog receiver stopped");
        }
        "forward" => {
            // syslog forward <ip> [port]
            let ip_str = parts.get(1).copied().unwrap_or("");
            if ip_str.is_empty() {
                shell_println!("Usage: syslog forward <ip> [port]");
                return;
            }
            if ip_str == "off" || ip_str == "disable" {
                syslog::disable_forwarding();
                shell_println!("Log forwarding disabled");
                return;
            }
            let ip = match parse_ipv4(ip_str) {
                Some(ip) => ip,
                None => {
                    shell_println!("Invalid IP: {}", ip_str);
                    return;
                }
            };
            let port: u16 = parts.get(2).and_then(|s| s.parse().ok()).unwrap_or(514);
            syslog::set_remote_server(ip, port);
            shell_println!("Forwarding logs to {}:{}", ip, port);
        }
        "forward6" => {
            // syslog forward6 <ipv6-addr> [port]
            use crate::net::ipv6::Ipv6Addr;
            let ip_str = parts.get(1).copied().unwrap_or("");
            if ip_str.is_empty() {
                shell_println!("Usage: netsyslog forward6 <ipv6-addr> [port]");
                return;
            }
            if ip_str == "off" || ip_str == "disable" {
                syslog::disable_forwarding();
                shell_println!("Log forwarding disabled");
                return;
            }
            let ip = match Ipv6Addr::parse(ip_str) {
                Some(ip) => ip,
                None => {
                    shell_println!("Invalid IPv6 address: {}", ip_str);
                    return;
                }
            };
            let port: u16 = parts.get(2).and_then(|s| s.parse().ok()).unwrap_or(514);
            syslog::set_remote_server_v6(ip, port);
            shell_println!("Forwarding logs to [{}]:{}", ip, port);
        }
        "send" => {
            // syslog send <message>
            let message = parts.get(1..).map(|p| p.join(" ")).unwrap_or_default();
            if message.is_empty() {
                shell_println!("Usage: syslog send <message>");
                return;
            }
            syslog::forward_kern(syslog::Severity::Info, &message);
            shell_println!("Sent: {}", message);
        }
        "recent" | "messages" | "log" => {
            let count: usize = parts.get(1).and_then(|s| s.parse().ok()).unwrap_or(20);
            let messages = syslog::recent_messages(count);
            if messages.is_empty() {
                shell_println!("No messages in buffer");
            } else {
                for msg in &messages {
                    shell_println!("<{}.{}> {} [{}] {}: {}",
                        msg.facility.label(), msg.severity.label(),
                        msg.source_addr, msg.hostname, msg.app_name, msg.message);
                }
            }
        }
        "clear" => {
            syslog::clear_messages();
            shell_println!("Message buffer cleared");
        }
        "hostname" => {
            let name = parts.get(1).copied().unwrap_or("");
            if name.is_empty() {
                let s = syslog::stats();
                shell_println!("Hostname: {}", s.hostname);
            } else {
                syslog::set_hostname(name);
                shell_println!("Hostname set to {}", name);
            }
        }
        "port" => {
            let port_str = parts.get(1).copied().unwrap_or("");
            if port_str.is_empty() {
                shell_println!("Listen port: {}", syslog::stats().listen_port);
            } else {
                let port: u16 = port_str.parse().unwrap_or(0);
                if port == 0 {
                    shell_println!("Invalid port");
                } else {
                    syslog::set_port(port);
                    shell_println!("Port set to {} (restart to apply)", port);
                }
            }
        }
        "test" => {
            match syslog::self_test() {
                Ok(()) => shell_println!("Syslog self-test: PASSED"),
                Err(e) => shell_println!("Syslog self-test FAILED: {:?}", e),
            }
        }
        "help" => {
            shell_println!("syslog — network syslog client/receiver");
            shell_println!("  show                Full status overview");
            shell_println!("  status              Summary statistics");
            shell_println!("  listen              Start syslog receiver");
            shell_println!("  stop                Stop receiver");
            shell_println!("  forward <ip> [port] Forward logs to server");
            shell_println!("  forward off         Disable forwarding");
            shell_println!("  send <message>      Send a test message");
            shell_println!("  recent [N]          Show last N messages (default 20)");
            shell_println!("  clear               Clear message buffer");
            shell_println!("  hostname [name]     Get/set hostname");
            shell_println!("  port [num]          Get/set listen port");
            shell_println!("  test                Run self-tests");
        }
        _ => {
            shell_println!("Unknown subcommand: {}. Use 'syslog help'.", sub);
        }
    }
}

/// `wol` / `wakeonlan` — Wake-on-LAN magic packet sender.
fn cmd_wol(args: &str) {
    use crate::net::wol;
    let parts: Vec<&str> = args.split_whitespace().collect();
    let sub = parts.first().copied().unwrap_or("");
    match sub {
        "" | "help" => {
            shell_println!("wol — Wake-on-LAN magic packet sender");
            shell_println!("  wol <MAC>              Send wake packet (broadcast)");
            shell_println!("  wol <MAC> <broadcast>  Send to specific broadcast IP");
            shell_println!("  wol status             Show statistics");
            shell_println!("  wol test               Run self-tests");
            shell_println!("");
            shell_println!("MAC format: AA:BB:CC:DD:EE:FF or AA-BB-CC-DD-EE-FF");
        }
        "status" | "stats" => {
            let (sent, errors) = wol::stats();
            shell_println!("WoL packets sent: {}", sent);
            shell_println!("WoL send errors:  {}", errors);
        }
        "test" => {
            match wol::self_test() {
                Ok(()) => shell_println!("WoL self-test: PASSED"),
                Err(e) => shell_println!("WoL self-test FAILED: {:?}", e),
            }
        }
        _ => {
            // Treat first arg as MAC address.
            let mac = match wol::MacAddress::parse(sub) {
                Some(m) => m,
                None => {
                    shell_println!("Invalid MAC address: {}", sub);
                    shell_println!("Use format: AA:BB:CC:DD:EE:FF");
                    return;
                }
            };
            let broadcast = parts.get(1).and_then(|s| parse_ipv4(s));
            shell_println!("Sending WoL magic packet to {} ...", mac);
            match wol::wake(mac, broadcast) {
                Ok(()) => shell_println!("Magic packet sent"),
                Err(e) => shell_println!("Failed: {:?}", e),
            }
        }
    }
}

/// `pcap` / `tcpdump` — Network packet capture.
fn cmd_pcap(args: &str) {
    use crate::net::pcap;
    let parts: Vec<&str> = args.split_whitespace().collect();
    let sub = parts.first().copied().unwrap_or("");
    match sub {
        "" | "help" => {
            shell_println!("pcap — Network packet capture (libpcap format)");
            shell_println!("  pcap start           Start capturing all traffic");
            shell_println!("  pcap start tcp       Capture TCP only (IPv4+IPv6)");
            shell_println!("  pcap start udp       Capture UDP only (IPv4+IPv6)");
            shell_println!("  pcap start ipv6      Capture IPv6 only");
            shell_println!("  pcap start icmpv6    Capture ICMPv6 only");
            shell_println!("  pcap start port <N>  Capture traffic on port N");
            shell_println!("  pcap start rx        Capture RX only");
            shell_println!("  pcap start tx        Capture TX only");
            shell_println!("  pcap stop            Stop capture");
            shell_println!("  pcap status          Show capture statistics");
            shell_println!("  pcap export <file>   Export ring buffer to .pcap file");
            shell_println!("  pcap snaplen <N>     Set max bytes per packet");
            shell_println!("  pcap test            Run self-tests");
        }
        "start" => {
            if pcap::is_capturing() {
                shell_println!("Capture already running — stop first");
                return;
            }
            let filter_arg = parts.get(1).copied().unwrap_or("all");
            let filter = match filter_arg {
                "tcp" => pcap::CaptureFilter::tcp_only(),
                "udp" => pcap::CaptureFilter::udp_only(),
                "ipv6" | "ip6" => pcap::CaptureFilter::ipv6_only(),
                "icmpv6" | "icmp6" => pcap::CaptureFilter::icmpv6_only(),
                "rx" => {
                    let mut f = pcap::CaptureFilter::all();
                    f.capture_tx = false;
                    f
                }
                "tx" => {
                    let mut f = pcap::CaptureFilter::all();
                    f.capture_rx = false;
                    f
                }
                "port" => {
                    let port_num = parts.get(2).and_then(|s| s.parse::<u16>().ok());
                    match port_num {
                        Some(p) => {
                            let mut f = pcap::CaptureFilter::all();
                            f.port = p;
                            f
                        }
                        None => {
                            shell_println!("Usage: pcap start port <N>");
                            return;
                        }
                    }
                }
                // "all" or any unrecognised filter falls through to capture everything.
                _ => pcap::CaptureFilter::all(),
            };
            pcap::start(filter);
            shell_println!("Packet capture started");
        }
        "stop" => {
            if !pcap::is_capturing() {
                shell_println!("No capture is running");
                return;
            }
            pcap::stop();
            shell_println!("Packet capture stopped");
        }
        "status" | "stats" => {
            let s = pcap::stats();
            shell_println!("Packet Capture Status");
            shell_println!("  Active:    {}", if s.capturing { "CAPTURING" } else { "idle" });
            shell_println!("  Snaplen:   {} bytes", s.snaplen);
            shell_println!("  Ring:      {}/{} packets", s.ring_used, s.ring_capacity);
            shell_println!("  Captured:  {} ({} RX, {} TX)", s.total_captured, s.rx_captured, s.tx_captured);
            shell_println!("  Filtered:  {}", s.total_filtered);
            shell_println!("  Dropped:   {}", s.total_dropped);
        }
        "export" => {
            let filename = parts.get(1).copied().unwrap_or("capture.pcap");
            let data = pcap::export();
            if data.len() <= 24 {
                shell_println!("No packets captured — nothing to export");
                return;
            }
            // Write to VFS.
            let path = resolve_path(filename);
            match crate::fs::vfs::Vfs::write_file(&path, &data) {
                Ok(()) => {
                    shell_println!("Exported {} bytes to {}", data.len(), path);
                }
                Err(e) => {
                    shell_println!("Export failed: {:?}", e);
                }
            }
        }
        "snaplen" => {
            match parts.get(1).and_then(|s| s.parse::<u32>().ok()) {
                Some(n) => {
                    pcap::set_snaplen(n);
                    shell_println!("Snaplen set to {} bytes", n.min(1500));
                }
                None => {
                    shell_println!("Usage: pcap snaplen <bytes>");
                }
            }
        }
        "test" => {
            match pcap::self_test() {
                Ok(()) => shell_println!("pcap self-test: PASSED"),
                Err(e) => shell_println!("pcap self-test FAILED: {:?}", e),
            }
        }
        _ => {
            shell_println!("Unknown subcommand '{}'. Try 'pcap help'.", sub);
        }
    }
}

/// `traceroute` / `tracert` — Trace route to destination.
fn cmd_traceroute(args: &str) {
    use alloc::format;
    use crate::net::traceroute;
    let parts: Vec<&str> = args.split_whitespace().collect();
    let sub = parts.first().copied().unwrap_or("");
    match sub {
        "" | "help" => {
            shell_println!("traceroute — trace the path to a network destination");
            shell_println!("  traceroute <IP>              Trace route (default 30 hops, 3 probes)");
            shell_println!("  traceroute <IP> -m <N>       Max N hops");
            shell_println!("  traceroute <IP> -q <N>       N probes per hop");
            shell_println!("  traceroute status            Show statistics");
            shell_println!("  traceroute test              Run self-tests");
        }
        "status" | "stats" => {
            let s = traceroute::stats();
            shell_println!("Traceroute Statistics");
            shell_println!("  Active:          {}", if s.active { "yes" } else { "no" });
            shell_println!("  Total traces:    {}", s.total_traces);
            shell_println!("  Probes sent:     {}", s.total_probes_sent);
            shell_println!("  Probes timeout:  {}", s.total_probes_timeout);
            shell_println!("  Last hop count:  {}", s.last_hops);
        }
        "test" => {
            match traceroute::self_test() {
                Ok(()) => shell_println!("traceroute self-test: PASSED"),
                Err(e) => shell_println!("traceroute self-test FAILED: {:?}", e),
            }
        }
        _ => {
            // First arg is an IP address.
            let dst = match parse_ipv4(sub) {
                Some(ip) => ip,
                None => {
                    // Try DNS resolution.
                    match crate::net::dns::resolve(sub) {
                        Ok(ip) => {
                            shell_println!("traceroute to {} ({})", sub, ip);
                            ip
                        }
                        Err(_) => {
                            shell_println!("Cannot resolve '{}' — use IP address", sub);
                            return;
                        }
                    }
                }
            };

            // Parse optional flags.
            let mut max_hops: Option<u8> = None;
            let mut probes: Option<u8> = None;
            let mut i = 1;
            while i < parts.len() {
                match parts.get(i).copied() {
                    Some("-m") => {
                        max_hops = parts.get(i + 1).and_then(|s| s.parse::<u8>().ok());
                        i += 2;
                    }
                    Some("-q") => {
                        probes = parts.get(i + 1).and_then(|s| s.parse::<u8>().ok());
                        i += 2;
                    }
                    _ => { i += 1; }
                }
            }

            shell_println!("traceroute to {} (max {} hops, {} probes/hop)",
                dst,
                max_hops.unwrap_or(30),
                probes.unwrap_or(3),
            );

            match traceroute::trace(dst, max_hops, probes, None) {
                Ok(result) => {
                    // Print per-hop results.
                    for hop in &result.hops {
                        let mut line = format!("{:>2}  ", hop.hop);
                        let mut last_ip = crate::net::interface::Ipv4Addr::UNSPECIFIED;
                        for probe in &hop.probes {
                            if probe.received {
                                if probe.addr != last_ip {
                                    if !last_ip.is_unspecified() {
                                        line.push_str("  ");
                                    }
                                    line.push_str(&format!("{}", probe.addr));
                                    last_ip = probe.addr;
                                }
                                line.push_str(&format!("  {}", traceroute::format_rtt(probe.rtt_ns)));
                            } else {
                                line.push_str("  *");
                            }
                        }
                        shell_println!("{}", line);
                    }
                    if result.reached {
                        shell_println!("\nDestination reached in {} hops", result.hops.len());
                    } else {
                        shell_println!("\nDestination NOT reached after {} hops", result.hops.len());
                    }
                }
                Err(e) => {
                    shell_println!("traceroute failed: {:?}", e);
                }
            }
        }
    }
}

/// `traceroute6` — Trace route to an IPv6 destination.
fn cmd_traceroute6(args: &str) {
    use alloc::format;
    use crate::net::traceroute;
    use crate::net::ipv6::Ipv6Addr;
    let parts: Vec<&str> = args.split_whitespace().collect();
    let sub = parts.first().copied().unwrap_or("");
    match sub {
        "" | "help" => {
            shell_println!("traceroute6 — trace the path to an IPv6 destination");
            shell_println!("  traceroute6 <IPv6>           Trace route (default 30 hops, 3 probes)");
            shell_println!("  traceroute6 <IPv6> -m <N>    Max N hops");
            shell_println!("  traceroute6 <IPv6> -q <N>    N probes per hop");
            shell_println!("  traceroute6 status           Show statistics");
            shell_println!("  traceroute6 test             Run self-tests");
        }
        "status" | "stats" => {
            let s = traceroute::stats6();
            shell_println!("Traceroute6 Statistics");
            shell_println!("  Active:          {}", if s.active { "yes" } else { "no" });
            shell_println!("  Total traces:    {}", s.total_traces);
            shell_println!("  Probes sent:     {}", s.total_probes_sent);
            shell_println!("  Probes timeout:  {}", s.total_probes_timeout);
            shell_println!("  Last hop count:  {}", s.last_hops);
        }
        "test" => {
            match traceroute::self_test() {
                Ok(()) => shell_println!("traceroute self-test: PASSED"),
                Err(e) => shell_println!("traceroute self-test FAILED: {:?}", e),
            }
        }
        _ => {
            // First arg is an IPv6 address or hostname.
            let dst = match Ipv6Addr::parse(sub) {
                Some(ip) => ip,
                None => {
                    // Try AAAA DNS resolution.
                    match crate::net::dns::resolve6(sub) {
                        Ok(ip) => {
                            shell_println!("traceroute6 to {} ({})", sub, ip);
                            ip
                        }
                        Err(_) => {
                            shell_println!("Cannot resolve '{}' — use IPv6 address", sub);
                            return;
                        }
                    }
                }
            };

            // Parse optional flags.
            let mut max_hops: Option<u8> = None;
            let mut probes: Option<u8> = None;
            let mut i = 1;
            while i < parts.len() {
                match parts.get(i).copied() {
                    Some("-m") => {
                        max_hops = parts.get(i + 1).and_then(|s| s.parse::<u8>().ok());
                        i += 2;
                    }
                    Some("-q") => {
                        probes = parts.get(i + 1).and_then(|s| s.parse::<u8>().ok());
                        i += 2;
                    }
                    _ => { i += 1; }
                }
            }

            shell_println!("traceroute6 to {} (max {} hops, {} probes/hop)",
                dst,
                max_hops.unwrap_or(30),
                probes.unwrap_or(3),
            );

            match traceroute::trace6(dst, max_hops, probes, None) {
                Ok(result) => {
                    // Print per-hop results.
                    for hop in &result.hops {
                        let mut line = format!("{:>2}  ", hop.hop);
                        let mut last_ip = Ipv6Addr::UNSPECIFIED;
                        for probe in &hop.probes {
                            if probe.received {
                                if probe.addr != last_ip {
                                    if !last_ip.is_unspecified() {
                                        line.push_str("  ");
                                    }
                                    line.push_str(&format!("{}", probe.addr));
                                    last_ip = probe.addr;
                                }
                                line.push_str(&format!("  {}", traceroute::format_rtt(probe.rtt_ns)));
                            } else {
                                line.push_str("  *");
                            }
                        }
                        shell_println!("{}", line);
                    }
                    if result.reached {
                        shell_println!("\nDestination reached in {} hops", result.hops.len());
                    } else {
                        shell_println!("\nDestination NOT reached after {} hops", result.hops.len());
                    }
                }
                Err(e) => {
                    shell_println!("traceroute6 failed: {:?}", e);
                }
            }
        }
    }
}

/// `igmp` — IGMP multicast group management.
fn cmd_igmp(args: &str) {
    use crate::net::igmp;
    let parts: Vec<&str> = args.split_whitespace().collect();
    let sub = parts.first().copied().unwrap_or("");
    match sub {
        "" | "help" => {
            shell_println!("igmp — IGMP multicast group management");
            shell_println!("  igmp status         Show IGMP statistics");
            shell_println!("  igmp groups         List active group memberships");
            shell_println!("  igmp join <IP>      Join a multicast group");
            shell_println!("  igmp leave <IP>     Leave a multicast group");
            shell_println!("  igmp test           Run self-tests");
        }
        "status" | "stats" => {
            let s = igmp::stats();
            shell_println!("IGMP Statistics");
            shell_println!("  Active groups:    {}", s.active_groups);
            shell_println!("  Reports sent:     {}", s.reports_sent);
            shell_println!("  Leaves sent:      {}", s.leaves_sent);
            shell_println!("  Queries received: {}", s.queries_received);
            shell_println!("  Errors:           {}", s.errors);
        }
        "groups" | "list" => {
            let (groups, count) = igmp::list_groups();
            if count == 0 {
                shell_println!("No active IGMP group memberships");
            } else {
                shell_println!("Active IGMP groups ({}):", count);
                for info in &groups {
                    shell_println!("  {}  ({})", info.addr, info.state);
                }
            }
        }
        "join" => {
            let ip_str = parts.get(1).copied().unwrap_or("");
            match parse_ipv4(ip_str) {
                Some(ip) => {
                    if !ip.is_multicast() {
                        shell_println!("{} is not a multicast address (224.0.0.0/4)", ip);
                        return;
                    }
                    igmp::join(ip);
                    shell_println!("Joined multicast group {}", ip);
                }
                None => {
                    shell_println!("Usage: igmp join <multicast-IP>");
                    shell_println!("  e.g.: igmp join 239.1.1.1");
                }
            }
        }
        "leave" => {
            let ip_str = parts.get(1).copied().unwrap_or("");
            match parse_ipv4(ip_str) {
                Some(ip) => {
                    igmp::leave(ip);
                    shell_println!("Left multicast group {}", ip);
                }
                None => {
                    shell_println!("Usage: igmp leave <multicast-IP>");
                }
            }
        }
        "test" => {
            match igmp::self_test() {
                Ok(()) => shell_println!("IGMP self-test: PASSED"),
                Err(e) => shell_println!("IGMP self-test FAILED: {:?}", e),
            }
        }
        _ => {
            shell_println!("Unknown subcommand '{}'. Try 'igmp help'.", sub);
        }
    }
}

