/// `lldp` — Link Layer Discovery Protocol.
fn cmd_lldp(args: &str) {
    use crate::net::lldp;
    let parts: Vec<&str> = args.split_whitespace().collect();
    let sub = parts.first().copied().unwrap_or("");
    match sub {
        "" | "help" => {
            shell_println!("lldp — Link Layer Discovery Protocol");
            shell_println!("  lldp neighbors      Show discovered neighbors");
            shell_println!("  lldp status          Show LLDP statistics");
            shell_println!("  lldp enable          Enable LLDP advertisements");
            shell_println!("  lldp disable         Disable LLDP advertisements");
            shell_println!("  lldp clear           Clear neighbor table");
            shell_println!("  lldp test            Run self-tests");
        }
        "neighbors" | "show" | "list" => {
            let nbrs = lldp::neighbors();
            if nbrs.is_empty() {
                shell_println!("No LLDP neighbors discovered");
            } else {
                shell_println!("LLDP Neighbors ({}):", nbrs.len());
                for n in &nbrs {
                    shell_println!("  ─────────────────────────────────");
                    shell_println!("  MAC:       {}", n.mac);
                    if !n.system_name.is_empty() {
                        shell_println!("  Name:      {}", n.system_name);
                    }
                    if !n.chassis_id.is_empty() {
                        shell_println!("  Chassis:   {}", n.chassis_id);
                    }
                    if !n.port_id.is_empty() {
                        shell_println!("  Port:      {}", n.port_id);
                    }
                    if !n.port_desc.is_empty() {
                        shell_println!("  Port Desc: {}", n.port_desc);
                    }
                    if !n.system_desc.is_empty() {
                        shell_println!("  Sys Desc:  {}", n.system_desc);
                    }
                    if n.capabilities != 0 {
                        shell_println!("  Caps:      {} (enabled: {})",
                            lldp::format_capabilities(n.capabilities),
                            lldp::format_capabilities(n.enabled_caps),
                        );
                    }
                    if !n.mgmt_ip.is_unspecified() {
                        shell_println!("  Mgmt IP:   {}", n.mgmt_ip);
                    }
                    shell_println!("  TTL:       {}s", n.ttl);
                }
            }
        }
        "status" | "stats" => {
            let s = lldp::stats();
            shell_println!("LLDP Status");
            shell_println!("  TX enabled:       {}", if s.tx_enabled { "yes" } else { "no" });
            shell_println!("  Neighbors:        {}", s.neighbor_count);
            shell_println!("  Frames received:  {}", s.frames_received);
            shell_println!("  Frames sent:      {}", s.frames_sent);
            shell_println!("  Expired:          {}", s.neighbors_expired);
            shell_println!("  Parse errors:     {}", s.parse_errors);
        }
        "enable" | "on" => {
            lldp::enable();
            shell_println!("LLDP advertisements enabled");
        }
        "disable" | "off" => {
            lldp::disable();
            shell_println!("LLDP advertisements disabled");
        }
        "clear" | "flush" => {
            lldp::clear_neighbors();
            shell_println!("LLDP neighbor table cleared");
        }
        "test" => {
            match lldp::self_test() {
                Ok(()) => shell_println!("LLDP self-test: PASSED"),
                Err(e) => shell_println!("LLDP self-test FAILED: {:?}", e),
            }
        }
        _ => {
            shell_println!("Unknown subcommand '{}'. Try 'lldp help'.", sub);
        }
    }
}

/// `netstat` / `ss` — Network status and diagnostics.
fn cmd_netstat(args: &str) {
    use crate::net::netstat;
    let parts: Vec<&str> = args.split_whitespace().collect();
    let flag = parts.first().copied().unwrap_or("-a");
    match flag {
        "help" => {
            shell_println!("netstat — unified network status");
            shell_println!("  netstat              Show all connections and listeners");
            shell_println!("  netstat -a           Show all (same as default)");
            shell_println!("  netstat -t           TCP connections only");
            shell_println!("  netstat -u           UDP sockets only");
            shell_println!("  netstat -l           Listening sockets only");
            shell_println!("  netstat -s           Protocol statistics");
            shell_println!("  netstat -r           Routing table");
            shell_println!("  netstat -i           Interface statistics");
            shell_println!("  netstat -6           IPv6 information (SLAAC, NDP, routing)");
            shell_println!("  netstat test         Run self-tests");
        }
        "-t" | "--tcp" => {
            let conns = netstat::collect_tcp_connections();
            if conns.is_empty() {
                shell_println!("No active TCP connections");
            } else {
                shell_print!("{}", netstat::format_tcp_connections(&conns));
            }
        }
        "-u" | "--udp" => {
            let udp = netstat::collect_udp_sockets();
            if udp.is_empty() {
                shell_println!("No active UDP sockets");
            } else {
                shell_print!("{}", netstat::format_udp_sockets(&udp));
            }
        }
        "-l" | "--listen" => {
            let listeners = netstat::collect_tcp_listeners();
            let udp = netstat::collect_udp_sockets();
            if listeners.is_empty() && udp.is_empty() {
                shell_println!("No listening sockets");
            } else {
                if !listeners.is_empty() {
                    shell_print!("{}", netstat::format_tcp_listeners(&listeners));
                }
                if !udp.is_empty() {
                    shell_print!("{}", netstat::format_udp_sockets(&udp));
                }
            }
        }
        "-s" | "--stats" => {
            shell_print!("{}", netstat::format_protocol_stats());
        }
        "-r" | "--route" => {
            shell_print!("{}", netstat::format_routing());
        }
        "-i" | "--iface" | "--interface" => {
            shell_print!("{}", netstat::format_interface_stats());
        }
        "test" => {
            match netstat::self_test() {
                Ok(()) => shell_println!("netstat self-test: PASSED"),
                Err(e) => shell_println!("netstat self-test FAILED: {:?}", e),
            }
        }
        "-6" | "--ipv6" => {
            shell_print!("{}", netstat::format_ipv6_info());
        }
        // "-a" or any unrecognised flag falls through to the default
        // (show everything).
        _ => {
            let conns = netstat::collect_tcp_connections();
            let listeners = netstat::collect_tcp_listeners();
            let udp = netstat::collect_udp_sockets();

            if !conns.is_empty() {
                shell_print!("{}", netstat::format_tcp_connections(&conns));
                shell_println!("");
            }
            if !listeners.is_empty() {
                shell_print!("{}", netstat::format_tcp_listeners(&listeners));
                shell_println!("");
            }
            if !udp.is_empty() {
                shell_print!("{}", netstat::format_udp_sockets(&udp));
                shell_println!("");
            }
            if conns.is_empty() && listeners.is_empty() && udp.is_empty() {
                shell_println!("No active connections or sockets");
            }
        }
    }
}

/// `ndisc` / `arpscan` — Network discovery via ARP scanning.
fn cmd_ndisc(args: &str) {
    use crate::net::ndisc;
    let parts: Vec<&str> = args.split_whitespace().collect();
    let sub = parts.first().copied().unwrap_or("");
    match sub {
        "" | "help" => {
            shell_println!("ndisc — network discovery (ARP/NDP scan)");
            shell_println!("  ndisc scan          ARP scan local subnet (IPv4)");
            shell_println!("  ndisc scan6         IPv6 link-local neighbor discovery");
            shell_println!("  ndisc probe <IP>    Probe a specific host (IPv4)");
            shell_println!("  ndisc probe6 <IP6>  NDP probe an IPv6 address");
            shell_println!("  ndisc hosts         Show hosts from ARP cache (IPv4)");
            shell_println!("  ndisc hosts6        Show IPv6 neighbors (NDP cache)");
            shell_println!("  ndisc subnet        Show subnet information");
            shell_println!("  ndisc status        Show scan statistics");
            shell_println!("  ndisc test          Run self-tests");
        }
        "scan" => {
            shell_println!("Scanning local subnet...");
            match ndisc::scan_subnet() {
                Ok(result) => {
                    shell_println!("Probed {} hosts, {} responded:\n", result.probed, result.responding);
                    shell_println!("{:<16}  {:<18}  {}", "IP Address", "MAC Address", "Hostname");
                    shell_println!("{:<16}  {:<18}  {}", "──────────────", "─────────────────", "────────");
                    for host in &result.hosts {
                        let name = if host.hostname.is_empty() { "-" } else { &host.hostname };
                        shell_println!("{:<16}  {:<18}  {}", host.ip, host.mac, name);
                    }
                }
                Err(e) => shell_println!("Scan failed: {:?}", e),
            }
        }
        "scan6" => {
            shell_println!("Scanning IPv6 link-local neighbors...");
            match ndisc::scan_link_v6() {
                Ok(result) => {
                    if result.hosts.is_empty() {
                        shell_println!("No IPv6 neighbors discovered");
                    } else {
                        shell_println!("{} IPv6 neighbor(s) found:\n", result.responding);
                        shell_println!("{:<42}  {:<18}  {}", "IPv6 Address", "MAC Address", "Hostname");
                        shell_println!("{:<42}  {:<18}  {}", "────────────────────────────────────────", "─────────────────", "────────");
                        for host in &result.hosts {
                            let name = if host.hostname.is_empty() { "-" } else { &host.hostname };
                            shell_println!("{:<42}  {:<18}  {}", host.ip, host.mac, name);
                        }
                    }
                }
                Err(e) => shell_println!("Scan failed: {:?}", e),
            }
        }
        "probe" => {
            let ip_str = parts.get(1).copied().unwrap_or("");
            match parse_ipv4(ip_str) {
                Some(ip) => {
                    shell_println!("Probing {}...", ip);
                    match ndisc::probe_host(ip) {
                        Ok(Some(host)) => {
                            shell_println!("  IP:       {}", host.ip);
                            shell_println!("  MAC:      {}", host.mac);
                            if !host.hostname.is_empty() {
                                shell_println!("  Hostname: {}", host.hostname);
                            }
                        }
                        Ok(None) => shell_println!("  No response from {}", ip),
                        Err(e) => shell_println!("  Probe failed: {:?}", e),
                    }
                }
                None => shell_println!("Usage: ndisc probe <IP>"),
            }
        }
        "probe6" => {
            use crate::net::ipv6::Ipv6Addr;
            let ip_str = parts.get(1).copied().unwrap_or("");
            match Ipv6Addr::parse(ip_str) {
                Some(ip6) => {
                    shell_println!("Probing {} via NDP...", ip6);
                    match ndisc::probe_host_v6(ip6) {
                        Ok(Some(host)) => {
                            shell_println!("  IPv6:     {}", host.ip);
                            shell_println!("  MAC:      {}", host.mac);
                            if !host.hostname.is_empty() {
                                shell_println!("  Hostname: {}", host.hostname);
                            }
                        }
                        Ok(None) => shell_println!("  No response from {}", ip6),
                        Err(e) => shell_println!("  Probe failed: {:?}", e),
                    }
                }
                None => {
                    shell_println!("Usage: ndisc probe6 <IPv6>");
                    shell_println!("  e.g.: ndisc probe6 fe80::1");
                }
            }
        }
        "hosts" => {
            // Show ARP cache as host list.
            let (entries, count) = crate::net::arp::cache_entries();
            if count == 0 {
                shell_println!("No hosts in ARP cache");
            } else {
                shell_println!("Discovered hosts ({}):", count);
                shell_println!("{:<16}  {:<18}  {}", "IP Address", "MAC Address", "TTL(s)");
                shell_println!("{:<16}  {:<18}  {}", "──────────────", "─────────────────", "──────");
                for i in 0..count {
                    if let Some(e) = entries.get(i) {
                        shell_println!("{:<16}  {:<18}  {}", e.ip, e.mac, e.ttl_secs);
                    }
                }
            }
        }
        "hosts6" => {
            let hosts = ndisc::hosts_v6();
            if hosts.is_empty() {
                shell_println!("No IPv6 neighbors in NDP cache");
            } else {
                shell_println!("IPv6 Neighbors ({}):", hosts.len());
                shell_println!("{:<42}  {:<18}  {}", "IPv6 Address", "MAC Address", "Hostname");
                shell_println!("{:<42}  {:<18}  {}", "────────────────────────────────────────", "─────────────────", "────────");
                for host in &hosts {
                    let name = if host.hostname.is_empty() { "-" } else { &host.hostname };
                    shell_println!("{:<42}  {:<18}  {}", host.ip, host.mac, name);
                }
            }
        }
        "subnet" => {
            let info = crate::net::interface::info();
            if info.ip.is_unspecified() {
                shell_println!("No network interface configured");
                return;
            }
            let net = ndisc::network_addr(info.ip, info.subnet_mask);
            let bcast = ndisc::broadcast_addr(info.ip, info.subnet_mask);
            let hosts = ndisc::host_count(info.subnet_mask);
            shell_println!("Subnet Information");
            shell_println!("  Interface IP: {}", info.ip);
            shell_println!("  Subnet mask:  {}", info.subnet_mask);
            shell_println!("  Network:      {}", net);
            shell_println!("  Broadcast:    {}", bcast);
            shell_println!("  Host range:   {} addresses", hosts);
        }
        "status" | "stats" => {
            let s = ndisc::stats();
            shell_println!("Network Discovery Statistics");
            shell_println!("  Scanning:    {}", if s.scanning { "yes" } else { "no" });
            shell_println!("  Total scans: {}", s.total_scans);
            shell_println!("  Probes sent: {}", s.total_probes);
            shell_println!("  Discovered:  {}", s.total_discovered);
        }
        "test" => {
            match ndisc::self_test() {
                Ok(()) => shell_println!("ndisc self-test: PASSED"),
                Err(e) => shell_println!("ndisc self-test FAILED: {:?}", e),
            }
        }
        _ => {
            shell_println!("Unknown subcommand '{}'. Try 'ndisc help'.", sub);
        }
    }
}

/// `brctl` / `bridge` / `bond` — Ethernet bridging and link aggregation.
fn cmd_bridge(args: &str) {
    use alloc::vec::Vec;
    let parts: Vec<&str> = args.split_whitespace().collect();
    let sub = parts.first().copied().unwrap_or("help");

    match sub {
        "addbr" | "create" => {
            if parts.len() < 2 {
                shell_println!("Usage: brctl addbr <name>");
                return;
            }
            match crate::net::bridge::create_bridge(parts[1]) {
                Ok(idx) => shell_println!("Bridge '{}' created (index {})", parts[1], idx),
                Err(e) => shell_println!("brctl: create failed: {:?}", e),
            }
        }

        "delbr" | "delete" => {
            if parts.len() < 2 {
                shell_println!("Usage: brctl delbr <index>");
                return;
            }
            let idx: usize = match parts[1].parse() {
                Ok(i) => i,
                Err(_) => { shell_println!("brctl: invalid index"); return; }
            };
            match crate::net::bridge::delete_bridge(idx) {
                Ok(()) => shell_println!("Bridge {} deleted", idx),
                Err(e) => shell_println!("brctl: delete failed: {:?}", e),
            }
        }

        "addif" => {
            if parts.len() < 3 {
                shell_println!("Usage: brctl addif <bridge_idx> <port_id>");
                return;
            }
            let br_idx: usize = match parts[1].parse() {
                Ok(i) => i,
                Err(_) => { shell_println!("brctl: invalid bridge index"); return; }
            };
            let port_id: u8 = match parts[2].parse() {
                Ok(p) => p,
                Err(_) => { shell_println!("brctl: invalid port id"); return; }
            };
            match crate::net::bridge::add_port(br_idx, port_id) {
                Ok(()) => shell_println!("Port {} added to bridge {}", port_id, br_idx),
                Err(e) => shell_println!("brctl: add port failed: {:?}", e),
            }
        }

        "delif" => {
            if parts.len() < 3 {
                shell_println!("Usage: brctl delif <bridge_idx> <port_id>");
                return;
            }
            let br_idx: usize = match parts[1].parse() {
                Ok(i) => i,
                Err(_) => { shell_println!("brctl: invalid bridge index"); return; }
            };
            let port_id: u8 = match parts[2].parse() {
                Ok(p) => p,
                Err(_) => { shell_println!("brctl: invalid port id"); return; }
            };
            match crate::net::bridge::remove_port(br_idx, port_id) {
                Ok(()) => shell_println!("Port {} removed from bridge {}", port_id, br_idx),
                Err(e) => shell_println!("brctl: remove port failed: {:?}", e),
            }
        }

        "addbond" => {
            if parts.len() < 3 {
                shell_println!("Usage: brctl addbond <name> <mode>");
                shell_println!("  Modes: active-backup, round-robin, xor-hash");
                return;
            }
            let mode = match parts[2] {
                "active-backup" | "ab" => crate::net::bridge::BondMode::ActiveBackup,
                "round-robin" | "rr" => crate::net::bridge::BondMode::RoundRobin,
                "xor-hash" | "xor" => crate::net::bridge::BondMode::XorHash,
                _ => {
                    shell_println!("brctl: unknown mode '{}'", parts[2]);
                    return;
                }
            };
            match crate::net::bridge::create_bond(parts[1], mode) {
                Ok(idx) => shell_println!("Bond '{}' created (index {})", parts[1], idx),
                Err(e) => shell_println!("brctl: create bond failed: {:?}", e),
            }
        }

        "delbond" => {
            if parts.len() < 2 {
                shell_println!("Usage: brctl delbond <index>");
                return;
            }
            let idx: usize = match parts[1].parse() {
                Ok(i) => i,
                Err(_) => { shell_println!("brctl: invalid index"); return; }
            };
            match crate::net::bridge::delete_bond(idx) {
                Ok(()) => shell_println!("Bond {} deleted", idx),
                Err(e) => shell_println!("brctl: delete failed: {:?}", e),
            }
        }

        "show" | "list" | "ls" => {
            let bridges = crate::net::bridge::list_bridges();
            let bonds = crate::net::bridge::list_bonds();

            if bridges.is_empty() {
                shell_println!("No bridges configured");
            } else {
                shell_println!("Bridges:");
                for b in &bridges {
                    shell_println!("  [{}] {}: {} ports, {} FDB entries, bridged={}, flooded={}",
                        b.index, b.name, b.port_count, b.fdb_count,
                        b.frames_bridged, b.frames_flooded);
                }
            }

            if bonds.is_empty() {
                shell_println!("No bonds configured");
            } else {
                shell_println!("Bonds:");
                for b in &bonds {
                    shell_println!("  [{}] {}: mode={}, {} members, TX={}, RX={}",
                        b.index, b.name, b.mode, b.member_count, b.total_tx, b.total_rx);
                }
            }
        }

        "test" => {
            match crate::net::bridge::self_test() {
                Ok(()) => shell_println!("bridge: all self-tests passed"),
                Err(e) => shell_println!("bridge: self-test failed: {:?}", e),
            }
        }

        _ => {
            shell_println!("brctl — Ethernet bridging and link aggregation");
            shell_println!();
            shell_println!("Bridge commands:");
            shell_println!("  brctl addbr <name>                — create bridge");
            shell_println!("  brctl delbr <index>               — delete bridge");
            shell_println!("  brctl addif <bridge> <port>       — add port");
            shell_println!("  brctl delif <bridge> <port>       — remove port");
            shell_println!();
            shell_println!("Bond commands:");
            shell_println!("  brctl addbond <name> <mode>       — create bond");
            shell_println!("  brctl delbond <index>             — delete bond");
            shell_println!();
            shell_println!("  brctl show                        — list all");
            shell_println!("  brctl test                        — run self-tests");
        }
    }
}

/// `nat` — NAT/masquerade management for container networking.
fn cmd_nat(args: &str) {
    use alloc::vec::Vec;
    let parts: Vec<&str> = args.split_whitespace().collect();
    let sub = parts.first().copied().unwrap_or("status");

    match sub {
        "enable" | "on" => {
            crate::net::nat::enable();
            shell_println!("NAT enabled");
        }
        "disable" | "off" => {
            crate::net::nat::disable();
            shell_println!("NAT disabled");
        }
        "status" | "stats" => {
            let s = crate::net::nat::stats();
            shell_println!("NAT status:");
            shell_println!("  Enabled:          {}", if s.enabled { "yes" } else { "no" });
            shell_println!("  Active entries:   {}/{}", s.active_entries, s.max_entries);
            shell_println!("  Outgoing xlat:    {}", s.translations_out);
            shell_println!("  Incoming xlat:    {}", s.translations_in);
            shell_println!("  Entries created:  {}", s.entries_created);
            shell_println!("  Entries expired:  {}", s.entries_expired);
        }
        "list" | "ls" => {
            let entries = crate::net::nat::list_entries();
            if entries.is_empty() {
                shell_println!("No active NAT entries");
            } else {
                shell_println!("{:<5} {:<18} {:<18} {:<7} {:<4} {:<5}",
                    "PROTO", "ORIGINAL", "DESTINATION", "NATPORT", "NS", "TTL");
                for (proto, src_ip, src_port, dst_ip, dst_port, nat_port, ns_id, ttl) in &entries {
                    let proto_str = match proto {
                        crate::net::nat::NatProto::Tcp => "TCP",
                        crate::net::nat::NatProto::Udp => "UDP",
                    };
                    shell_println!("{:<5} {}:{:<10} {}:{:<10} {:<7} {:<4} {}s",
                        proto_str, src_ip, src_port, dst_ip, dst_port, nat_port, ns_id, ttl);
                }
                shell_println!("({} entries)", entries.len());
            }
        }
        "flush" => {
            if let Some(ns_str) = parts.get(1) {
                if let Ok(ns_id) = ns_str.parse::<u32>() {
                    crate::net::nat::flush_namespace(ns_id);
                    shell_println!("Flushed NAT entries for namespace {}", ns_id);
                } else {
                    shell_println!("Usage: nat flush <namespace_id>");
                }
            } else {
                shell_println!("Usage: nat flush <namespace_id>");
            }
        }
        "forward" | "fwd" => {
            // nat forward add tcp 8080 10.88.0.2 80 42
            // nat forward del tcp 8080
            // nat forward list
            let fwd_sub = parts.get(1).copied().unwrap_or("list");
            match fwd_sub {
                "add" => {
                    if parts.len() < 7 {
                        shell_println!("Usage: nat forward add <tcp|udp> <host_port> <container_ip> <container_port> <ns_id>");
                        return;
                    }
                    let proto = match parts.get(2).copied().unwrap_or("tcp") {
                        "udp" => crate::net::nat::NatProto::Udp,
                        _ => crate::net::nat::NatProto::Tcp,
                    };
                    let host_port = parts.get(3).and_then(|s| s.parse::<u16>().ok());
                    let container_ip = parts.get(4).and_then(|s| parse_ipv4(s));
                    let container_port = parts.get(5).and_then(|s| s.parse::<u16>().ok());
                    let ns_id = parts.get(6).and_then(|s| s.parse::<u32>().ok());

                    match (host_port, container_ip, container_port, ns_id) {
                        (Some(hp), Some(cip), Some(cp), Some(ns)) => {
                            match crate::net::nat::add_port_forward(proto, hp, cip, cp, ns) {
                                Ok(()) => shell_println!("Port forward added: :{} → {}:{} (ns={})", hp, cip, cp, ns),
                                Err(e) => shell_println!("Error: {:?}", e),
                            }
                        }
                        _ => shell_println!("Invalid arguments. Usage: nat forward add <tcp|udp> <host_port> <ip> <port> <ns_id>"),
                    }
                }
                "del" | "rm" => {
                    if parts.len() < 4 {
                        shell_println!("Usage: nat forward del <tcp|udp> <host_port>");
                        return;
                    }
                    let proto = match parts.get(2).copied().unwrap_or("tcp") {
                        "udp" => crate::net::nat::NatProto::Udp,
                        _ => crate::net::nat::NatProto::Tcp,
                    };
                    if let Some(hp) = parts.get(3).and_then(|s| s.parse::<u16>().ok()) {
                        match crate::net::nat::remove_port_forward(proto, hp) {
                            Ok(()) => shell_println!("Port forward removed: :{}", hp),
                            Err(e) => shell_println!("Error: {:?}", e),
                        }
                    } else {
                        shell_println!("Invalid port");
                    }
                }
                _ => {
                    let fwds = crate::net::nat::list_port_forwards();
                    if fwds.is_empty() {
                        shell_println!("No active port forwards");
                    } else {
                        shell_println!("{:<5} {:<10} {:<20} {:<4}", "PROTO", "HOST_PORT", "CONTAINER", "NS");
                        for (proto, hp, cip, cp, ns) in &fwds {
                            let proto_str = match proto {
                                crate::net::nat::NatProto::Tcp => "TCP",
                                crate::net::nat::NatProto::Udp => "UDP",
                            };
                            shell_println!("{:<5} {:<10} {}:{:<12} {}", proto_str, hp, cip, cp, ns);
                        }
                    }
                }
            }
        }
        // "help" or any unrecognised subcommand falls through to the help text.
        _ => {
            shell_println!("nat — NAT/masquerade management");
            shell_println!("Usage:");
            shell_println!("  nat                  — show status (default)");
            shell_println!("  nat enable|on        — enable NAT globally");
            shell_println!("  nat disable|off      — disable NAT globally");
            shell_println!("  nat status|stats     — show statistics");
            shell_println!("  nat list|ls          — list active NAT entries");
            shell_println!("  nat flush <ns_id>    — remove entries for a namespace");
            shell_println!("  nat forward list     — list port-forwarding rules");
            shell_println!("  nat forward add <tcp|udp> <host_port> <ip> <port> <ns_id>");
            shell_println!("  nat forward del <tcp|udp> <host_port>");
        }
    }
}

/// `socks` / `socks5` — SOCKS5 proxy client.
fn cmd_socks(args: &str) {
    use alloc::vec::Vec;
    let parts: Vec<&str> = args.split_whitespace().collect();
    let sub = parts.first().copied().unwrap_or("help");

    match sub {
        "connect" | "c" => {
            // socks connect <proxy> <proxy_port> <target> <target_port> [user] [pass]
            if parts.len() < 5 {
                shell_println!("Usage: socks connect <proxy> <proxy_port> <target> <target_port> [user] [pass]");
                return;
            }
            let proxy_str = parts[1];
            let proxy_port: u16 = match parts[2].parse() {
                Ok(p) => p,
                Err(_) => { shell_println!("socks: invalid proxy port"); return; }
            };
            let target_str = parts[3];
            let target_port: u16 = match parts[4].parse() {
                Ok(p) => p,
                Err(_) => { shell_println!("socks: invalid target port"); return; }
            };
            let user = parts.get(5).copied().unwrap_or("");
            let pass = parts.get(6).copied().unwrap_or("");

            let proxy_ip = if let Some(ip) = parse_ipv4(proxy_str) {
                ip
            } else {
                match crate::net::dns::resolve(proxy_str) {
                    Ok(ip) => ip,
                    Err(_) => {
                        shell_println!("socks: cannot resolve proxy '{}'", proxy_str);
                        return;
                    }
                }
            };

            // Try IP first, then domain name.
            if let Some(target_ip) = parse_ipv4(target_str) {
                shell_println!("Connecting via SOCKS5 proxy {}:{}...", proxy_ip, proxy_port);
                shell_println!("Target: {}:{}", target_ip, target_port);
                match crate::net::socks::connect(proxy_ip.into(), proxy_port, target_ip.into(), target_port, user, pass) {
                    Ok(result) => {
                        if result.success {
                            shell_println!("Connected! Handle: {}", result.handle);
                            shell_println!("Bound: {}:{}", result.bound_addr, result.bound_port);
                            crate::net::socks::close(result.handle);
                        } else {
                            shell_println!("Connection failed: {} ({})",
                                crate::net::socks::reply_description(result.reply_code),
                                result.reply_code);
                        }
                    }
                    Err(e) => shell_println!("socks: connect failed: {:?}", e),
                }
            } else {
                shell_println!("Connecting via SOCKS5 proxy {}:{}...", proxy_ip, proxy_port);
                shell_println!("Target: {}:{} (domain)", target_str, target_port);
                match crate::net::socks::connect_domain(proxy_ip.into(), proxy_port, target_str, target_port, user, pass) {
                    Ok(result) => {
                        if result.success {
                            shell_println!("Connected! Handle: {}", result.handle);
                            crate::net::socks::close(result.handle);
                        } else {
                            shell_println!("Connection failed: {} ({})",
                                crate::net::socks::reply_description(result.reply_code),
                                result.reply_code);
                        }
                    }
                    Err(e) => shell_println!("socks: connect failed: {:?}", e),
                }
            }
        }

        "codes" => {
            shell_println!("SOCKS5 reply codes:");
            for code in [0x00, 0x01, 0x02, 0x03, 0x04, 0x05, 0x06, 0x07, 0x08] {
                shell_println!("  0x{:02x}  {}", code, crate::net::socks::reply_description(code));
            }
        }

        "status" | "stats" => {
            let s = crate::net::socks::stats();
            shell_println!("SOCKS5 statistics:");
            shell_println!("  Connections:   {}", s.connections);
            shell_println!("  Successful:    {}", s.successful);
            shell_println!("  Auth attempts: {}", s.auth_attempts);
            shell_println!("  Errors:        {}", s.errors);
            shell_println!("  Bytes relayed: {}", s.bytes_relayed);
        }

        "test" => {
            match crate::net::socks::self_test() {
                Ok(()) => shell_println!("socks: all self-tests passed"),
                Err(e) => shell_println!("socks: self-test failed: {:?}", e),
            }
        }

        _ => {
            shell_println!("socks — SOCKS5 proxy client (RFC 1928)");
            shell_println!();
            shell_println!("Usage:");
            shell_println!("  socks connect <proxy> <pport> <target> <tport> [user] [pass]");
            shell_println!("  socks codes                — show SOCKS5 reply codes");
            shell_println!("  socks status               — show statistics");
            shell_println!("  socks test                 — run self-tests");
        }
    }
}

/// `qos` — Quality of Service traffic classification and rate limiting.
fn cmd_qos(args: &str) {
    use alloc::format;
    use alloc::vec::Vec;
    let parts: Vec<&str> = args.split_whitespace().collect();
    let sub = parts.first().copied().unwrap_or("help");

    match sub {
        "enable" | "on" => {
            crate::net::qos::set_enabled(true);
            shell_println!("QoS classification enabled");
        }

        "disable" | "off" => {
            crate::net::qos::set_enabled(false);
            shell_println!("QoS classification disabled");
        }

        "rule" | "add" => {
            // qos rule port <port> <priority>
            // qos rule proto <proto> <priority>
            // qos rule dscp <dscp> <priority>
            if parts.len() < 4 {
                shell_println!("Usage: qos rule <port|proto|dscp> <value> <priority>");
                return;
            }
            let kind = parts[1];
            let value: u16 = match parts[2].parse() {
                Ok(v) => v,
                Err(_) => {
                    shell_println!("qos: invalid value '{}'", parts[2]);
                    return;
                }
            };
            let priority: u8 = match parts[3].parse() {
                Ok(p) => p,
                Err(_) => {
                    shell_println!("qos: invalid priority '{}'", parts[3]);
                    return;
                }
            };

            let match_on = match kind {
                "port" | "dport" => crate::net::qos::ClassifyMatch::DstPort(value),
                "sport" => crate::net::qos::ClassifyMatch::SrcPort(value),
                "proto" | "protocol" => crate::net::qos::ClassifyMatch::Protocol(value as u8),
                "dscp" => crate::net::qos::ClassifyMatch::Dscp(value as u8),
                _ => {
                    shell_println!("qos: unknown match type '{}' (use port/proto/dscp)", kind);
                    return;
                }
            };

            match crate::net::qos::add_rule(match_on, priority) {
                Ok(()) => shell_println!("Rule added: {} {} → priority {}", kind, value, priority),
                Err(e) => shell_println!("qos: add rule failed: {:?}", e),
            }
        }

        "clear" => {
            crate::net::qos::clear_rules();
            shell_println!("All classification rules cleared");
        }

        "rules" => {
            let rules = crate::net::qos::list_rules();
            if rules.is_empty() {
                shell_println!("No classification rules configured");
            } else {
                shell_println!("Classification rules:");
                for (match_on, priority) in &rules {
                    let desc = match match_on {
                        crate::net::qos::ClassifyMatch::Protocol(p) => format!("protocol {}", p),
                        crate::net::qos::ClassifyMatch::DstPort(p) => format!("dst port {}", p),
                        crate::net::qos::ClassifyMatch::SrcPort(p) => format!("src port {}", p),
                        crate::net::qos::ClassifyMatch::Dscp(d) => format!("DSCP {}", d),
                        crate::net::qos::ClassifyMatch::All => "all traffic".to_string(),
                    };
                    shell_println!("  {} → priority {}", desc, priority);
                }
            }
        }

        "limit" => {
            // qos limit <priority> <rate_bps> <burst_bytes>
            if parts.len() < 4 {
                shell_println!("Usage: qos limit <priority> <rate_bps> <burst_bytes>");
                return;
            }
            let prio: u8 = match parts[1].parse() {
                Ok(p) => p,
                Err(_) => { shell_println!("qos: invalid priority"); return; }
            };
            let rate: u64 = match parts[2].parse() {
                Ok(r) => r,
                Err(_) => { shell_println!("qos: invalid rate"); return; }
            };
            let burst: u64 = match parts[3].parse() {
                Ok(b) => b,
                Err(_) => { shell_println!("qos: invalid burst"); return; }
            };

            match crate::net::qos::add_rate_limit(prio, rate, burst) {
                Ok(()) => shell_println!("Rate limit: priority {} = {} B/s (burst {})", prio, rate, burst),
                Err(e) => shell_println!("qos: rate limit failed: {:?}", e),
            }
        }

        "unlimit" => {
            if parts.len() < 2 {
                shell_println!("Usage: qos unlimit <priority>");
                return;
            }
            let prio: u8 = match parts[1].parse() {
                Ok(p) => p,
                Err(_) => { shell_println!("qos: invalid priority"); return; }
            };
            crate::net::qos::remove_rate_limit(prio);
            shell_println!("Rate limit removed for priority {}", prio);
        }

        "classes" => {
            let stats = crate::net::qos::class_stats();
            shell_println!("Traffic classes:");
            shell_println!("  {:>3}  {:20}  {:>10}  {:>12}  {:>8}", "Pri", "Name", "Packets", "Bytes", "Drops");
            for c in &stats {
                shell_println!("  {:>3}  {:20}  {:>10}  {:>12}  {:>8}", c.priority, c.name, c.packets, c.bytes, c.drops);
            }
        }

        "dscp" => {
            shell_println!("DSCP (DiffServ Code Point) values:");
            let vals = [
                (0, "BE"), (10, "AF11"), (12, "AF12"), (14, "AF13"),
                (18, "AF21"), (20, "AF22"), (22, "AF23"),
                (26, "AF31"), (28, "AF32"), (30, "AF33"),
                (34, "AF41"), (36, "AF42"), (38, "AF43"),
                (46, "EF"), (48, "CS6"), (56, "CS7"),
            ];
            for (val, name) in &vals {
                shell_println!("  {:>3}  {}", val, name);
            }
        }

        "status" | "stats" => {
            let enabled = crate::net::qos::is_enabled();
            shell_println!("QoS status: {}", if enabled { "enabled" } else { "disabled" });

            let limiters = crate::net::qos::rate_limit_info();
            if !limiters.is_empty() {
                shell_println!("Rate limiters:");
                for l in &limiters {
                    shell_println!("  Priority {}: {} B/s (burst {}), passed {}, dropped {}",
                        l.priority, l.rate_bps, l.burst_bytes, l.bytes_passed, l.bytes_dropped);
                }
            }
        }

        "test" => {
            match crate::net::qos::self_test() {
                Ok(()) => shell_println!("qos: all self-tests passed"),
                Err(e) => shell_println!("qos: self-test failed: {:?}", e),
            }
        }

        _ => {
            shell_println!("qos — Quality of Service traffic management");
            shell_println!();
            shell_println!("Usage:");
            shell_println!("  qos enable/disable                        — toggle QoS");
            shell_println!("  qos rule <port|proto|dscp> <val> <pri>    — add rule");
            shell_println!("  qos rules                                 — list rules");
            shell_println!("  qos clear                                 — clear all rules");
            shell_println!("  qos limit <priority> <rate> <burst>       — add rate limit");
            shell_println!("  qos unlimit <priority>                    — remove limit");
            shell_println!("  qos classes                               — show class stats");
            shell_println!("  qos dscp                                  — show DSCP values");
            shell_println!("  qos status                                — show status");
            shell_println!("  qos test                                  — run self-tests");
        }
    }
}

/// `vlan` — IEEE 802.1Q VLAN management.
fn cmd_vlan(args: &str) {
    use alloc::vec::Vec;
    let parts: Vec<&str> = args.split_whitespace().collect();
    let sub = parts.first().copied().unwrap_or("help");

    match sub {
        "add" | "create" => {
            // vlan add <vid> [name]
            if parts.len() < 2 {
                shell_println!("Usage: vlan add <vid> [name]");
                return;
            }
            let vid: u16 = match parts[1].parse() {
                Ok(v) => v,
                Err(_) => {
                    shell_println!("vlan: invalid VLAN ID '{}'", parts[1]);
                    return;
                }
            };
            let name = if parts.len() > 2 { parts[2] } else { "" };

            match crate::net::vlan::add_vlan(vid, name) {
                Ok(()) => shell_println!("VLAN {} added", vid),
                Err(e) => shell_println!("vlan: add failed: {:?}", e),
            }
        }

        "remove" | "del" | "delete" => {
            if parts.len() < 2 {
                shell_println!("Usage: vlan remove <vid>");
                return;
            }
            let vid: u16 = match parts[1].parse() {
                Ok(v) => v,
                Err(_) => {
                    shell_println!("vlan: invalid VLAN ID '{}'", parts[1]);
                    return;
                }
            };

            match crate::net::vlan::remove_vlan(vid) {
                Ok(()) => shell_println!("VLAN {} removed", vid),
                Err(e) => shell_println!("vlan: remove failed: {:?}", e),
            }
        }

        "list" | "ls" | "show" => {
            let vlans = crate::net::vlan::list_vlans();
            if vlans.is_empty() {
                shell_println!("No VLANs configured");
            } else {
                shell_println!("Configured VLANs:");
                shell_println!("  {:>5}  {:16}  {:>10} RX  {:>10} TX", "VID", "Name", "Frames", "Frames");
                for v in &vlans {
                    shell_println!("  {:>5}  {:16}  {:>10}     {:>10}", v.vid, v.name, v.rx_frames, v.tx_frames);
                }
            }
        }

        "pcp" => {
            shell_println!("802.1Q Priority Code Point (PCP) values:");
            for i in 0u8..8 {
                shell_println!("  {}: {}", i, crate::net::vlan::pcp_name(i));
            }
        }

        "status" | "stats" => {
            let s = crate::net::vlan::stats();
            shell_println!("VLAN statistics:");
            shell_println!("  Configured VLANs: {}", s.configured_vlans);
            shell_println!("  Tagged RX:        {}", s.tagged_rx);
            shell_println!("  Tagged TX:        {}", s.tagged_tx);
            shell_println!("  Untagged RX:      {}", s.untagged_rx);
            shell_println!("  Unknown drops:    {}", s.unknown_vlan_drops);
        }

        "test" => {
            match crate::net::vlan::self_test() {
                Ok(()) => shell_println!("vlan: all self-tests passed"),
                Err(e) => shell_println!("vlan: self-test failed: {:?}", e),
            }
        }

        _ => {
            shell_println!("vlan — IEEE 802.1Q VLAN management");
            shell_println!();
            shell_println!("Usage:");
            shell_println!("  vlan add <vid> [name]      — add VLAN interface");
            shell_println!("  vlan remove <vid>           — remove VLAN interface");
            shell_println!("  vlan list                   — list configured VLANs");
            shell_println!("  vlan pcp                    — show PCP priority values");
            shell_println!("  vlan status                 — show statistics");
            shell_println!("  vlan test                   — run self-tests");
        }
    }
}

/// `smtp` — SMTP client for sending email.
fn cmd_smtp(args: &str) {
    use alloc::vec::Vec;
    let parts: Vec<&str> = args.split_whitespace().collect();
    let sub = parts.first().copied().unwrap_or("help");

    match sub {
        "send" | "s" => {
            // smtp send <server> <from> <to> <subject> [body...]
            if parts.len() < 5 {
                shell_println!("Usage: smtp send <server> <from> <to> <subject> [body...]");
                return;
            }
            let server_str = parts[1];
            let from = parts[2];
            let to = parts[3];
            let subject = parts[4];
            let body = if parts.len() > 5 {
                parts[5..].join(" ")
            } else {
                alloc::string::String::from("(no body)")
            };

            let ip = if let Some(ip) = parse_ipv4(server_str) {
                ip
            } else {
                match crate::net::dns::resolve(server_str) {
                    Ok(ip) => ip,
                    Err(_) => {
                        shell_println!("smtp: cannot resolve server '{}'", server_str);
                        return;
                    }
                }
            };

            let msg = crate::net::smtp::EmailMessage::new(from, to, subject, &body);
            shell_println!("Sending to {} via {}...", to, ip);
            match crate::net::smtp::send_email(ip.into(), 0, &msg) {
                Ok(result) => {
                    shell_println!("Banner: {}", result.banner);
                    if result.accepted {
                        shell_println!("Message accepted: {}", result.server_reply);
                    } else {
                        shell_println!("Message rejected: {}", result.server_reply);
                    }
                }
                Err(e) => shell_println!("smtp: send failed: {:?}", e),
            }
        }

        "codes" => {
            shell_println!("Common SMTP reply codes:");
            shell_println!("  220  {}", crate::net::smtp::reply_description(220));
            shell_println!("  250  {}", crate::net::smtp::reply_description(250));
            shell_println!("  354  {}", crate::net::smtp::reply_description(354));
            shell_println!("  421  {}", crate::net::smtp::reply_description(421));
            shell_println!("  450  {}", crate::net::smtp::reply_description(450));
            shell_println!("  500  {}", crate::net::smtp::reply_description(500));
            shell_println!("  550  {}", crate::net::smtp::reply_description(550));
            shell_println!("  554  {}", crate::net::smtp::reply_description(554));
        }

        "status" | "stats" => {
            let s = crate::net::smtp::stats();
            shell_println!("SMTP statistics:");
            shell_println!("  Connections:     {}", s.connections);
            shell_println!("  Messages sent:   {}", s.messages_sent);
            shell_println!("  Messages failed: {}", s.messages_failed);
            shell_println!("  Bytes sent:      {}", s.bytes_sent);
        }

        "test" => {
            match crate::net::smtp::self_test() {
                Ok(()) => shell_println!("smtp: all self-tests passed"),
                Err(e) => shell_println!("smtp: self-test failed: {:?}", e),
            }
        }

        _ => {
            shell_println!("smtp — SMTP client for sending email");
            shell_println!();
            shell_println!("Usage:");
            shell_println!("  smtp send <server> <from> <to> <subject> [body...]");
            shell_println!("  smtp codes                 — show SMTP reply codes");
            shell_println!("  smtp status                — show statistics");
            shell_println!("  smtp test                  — run self-tests");
        }
    }
}

/// `ftp` — FTP client for file transfer.
fn cmd_ftp(args: &str) {
    use alloc::vec::Vec;
    let parts: Vec<&str> = args.split_whitespace().collect();
    let sub = parts.first().copied().unwrap_or("help");

    match sub {
        "connect" | "c" => {
            // ftp connect <host> [user] [pass]
            if parts.len() < 2 {
                shell_println!("Usage: ftp connect <host> [user] [pass]");
                return;
            }
            let host_str = parts[1];
            let user = parts.get(2).copied().unwrap_or("");
            let pass = parts.get(3).copied().unwrap_or("");

            let ip = if let Some(ip) = parse_ipv4(host_str) {
                ip
            } else {
                match crate::net::dns::resolve(host_str) {
                    Ok(ip) => ip,
                    Err(_) => {
                        shell_println!("ftp: cannot resolve host '{}'", host_str);
                        return;
                    }
                }
            };

            shell_println!("Connecting to {}...", ip);
            match crate::net::ftp::connect_and_login(ip.into(), user, pass) {
                Ok(result) => {
                    shell_println!("Banner: {}", result.banner);
                    if result.login_ok {
                        shell_println!("Login successful");
                    } else {
                        shell_println!("Login failed");
                    }
                }
                Err(e) => shell_println!("ftp: connect failed: {:?}", e),
            }
        }

        "ls" | "list" | "dir" => {
            // ftp ls <host> [path] [user] [pass]
            if parts.len() < 2 {
                shell_println!("Usage: ftp ls <host> [path] [user] [pass]");
                return;
            }
            let host_str = parts[1];
            let path = parts.get(2).copied().unwrap_or("");
            let user = parts.get(3).copied().unwrap_or("");
            let pass = parts.get(4).copied().unwrap_or("");

            let ip = if let Some(ip) = parse_ipv4(host_str) {
                ip
            } else {
                match crate::net::dns::resolve(host_str) {
                    Ok(ip) => ip,
                    Err(_) => {
                        shell_println!("ftp: cannot resolve host '{}'", host_str);
                        return;
                    }
                }
            };

            shell_println!("Listing {}:{}...", ip, if path.is_empty() { "/" } else { path });
            match crate::net::ftp::list_directory(ip.into(), path, user, pass) {
                Ok(listing) => {
                    for line in listing.lines() {
                        shell_println!("  {}", line);
                    }
                }
                Err(e) => shell_println!("ftp: list failed: {:?}", e),
            }
        }

        "get" | "download" => {
            // ftp get <host> <file> [user] [pass]
            if parts.len() < 3 {
                shell_println!("Usage: ftp get <host> <file> [user] [pass]");
                return;
            }
            let host_str = parts[1];
            let remote_path = parts[2];
            let user = parts.get(3).copied().unwrap_or("");
            let pass = parts.get(4).copied().unwrap_or("");

            let ip = if let Some(ip) = parse_ipv4(host_str) {
                ip
            } else {
                match crate::net::dns::resolve(host_str) {
                    Ok(ip) => ip,
                    Err(_) => {
                        shell_println!("ftp: cannot resolve host '{}'", host_str);
                        return;
                    }
                }
            };

            shell_println!("Downloading {}:{}...", ip, remote_path);
            match crate::net::ftp::download_file(ip.into(), remote_path, user, pass) {
                Ok(data) => {
                    shell_println!("Downloaded {} bytes", data.len());
                    // Try to show as text.
                    if let Ok(text) = core::str::from_utf8(&data) {
                        let lines: Vec<&str> = text.lines().collect();
                        let show = lines.len().min(20);
                        for line in &lines[..show] {
                            shell_println!("  {}", line);
                        }
                        if lines.len() > show {
                            shell_println!("  ... ({} more lines)", lines.len() - show);
                        }
                    } else {
                        shell_println!("  (binary data, {} bytes)", data.len());
                    }
                }
                Err(e) => shell_println!("ftp: download failed: {:?}", e),
            }
        }

        "codes" => {
            shell_println!("Common FTP reply codes:");
            shell_println!("  150  {}", crate::net::ftp::reply_description(150));
            shell_println!("  200  {}", crate::net::ftp::reply_description(200));
            shell_println!("  220  {}", crate::net::ftp::reply_description(220));
            shell_println!("  226  {}", crate::net::ftp::reply_description(226));
            shell_println!("  227  {}", crate::net::ftp::reply_description(227));
            shell_println!("  230  {}", crate::net::ftp::reply_description(230));
            shell_println!("  331  {}", crate::net::ftp::reply_description(331));
            shell_println!("  421  {}", crate::net::ftp::reply_description(421));
            shell_println!("  530  {}", crate::net::ftp::reply_description(530));
            shell_println!("  550  {}", crate::net::ftp::reply_description(550));
        }

        "status" | "stats" => {
            let s = crate::net::ftp::stats();
            shell_println!("FTP statistics:");
            shell_println!("  Connections:   {}", s.connections);
            shell_println!("  Logins:        {}", s.logins);
            shell_println!("  LIST commands: {}", s.list_commands);
            shell_println!("  RETR commands: {}", s.retr_commands);
            shell_println!("  Downloaded:    {} bytes", s.bytes_downloaded);
            shell_println!("  Uploaded:      {} bytes", s.bytes_uploaded);
            shell_println!("  Errors:        {}", s.errors);
        }

        "test" => {
            match crate::net::ftp::self_test() {
                Ok(()) => shell_println!("ftp: all self-tests passed"),
                Err(e) => shell_println!("ftp: self-test failed: {:?}", e),
            }
        }

        _ => {
            shell_println!("ftp — FTP client for file transfer");
            shell_println!();
            shell_println!("Usage:");
            shell_println!("  ftp connect <host> [user] [pass]       — connect and login");
            shell_println!("  ftp ls <host> [path] [user] [pass]     — list remote directory");
            shell_println!("  ftp get <host> <file> [user] [pass]    — download file");
            shell_println!("  ftp codes                              — show FTP reply codes");
            shell_println!("  ftp status                             — show statistics");
            shell_println!("  ftp test                               — run self-tests");
        }
    }
}

/// `snmp` — Simple Network Management Protocol client.
fn cmd_snmp(args: &str) {
    use alloc::vec::Vec;
    let parts: Vec<&str> = args.split_whitespace().collect();
    let sub = parts.first().copied().unwrap_or("help");

    match sub {
        "get" | "g" => {
            // snmp get <host> <oid> [community]
            if parts.len() < 3 {
                shell_println!("Usage: snmp get <host> <oid> [community]");
                return;
            }
            let host_str = parts[1];
            let oid_str = parts[2];
            let community = parts.get(3).copied().unwrap_or("public");

            let ip = if let Some(ip) = parse_ipv4(host_str) {
                ip
            } else {
                match crate::net::dns::resolve(host_str) {
                    Ok(ip) => ip,
                    Err(_) => {
                        shell_println!("snmp: cannot resolve host '{}'", host_str);
                        return;
                    }
                }
            };

            let oid = match crate::net::snmp::Oid::parse(oid_str) {
                Some(o) => o,
                None => {
                    shell_println!("snmp: invalid OID '{}'", oid_str);
                    return;
                }
            };

            let name = crate::net::snmp::oid_name(oid_str);
            if !name.is_empty() {
                shell_println!("Querying {} ({})...", oid_str, name);
            } else {
                shell_println!("Querying {}...", oid_str);
            }

            match crate::net::snmp::get(ip, &oid, community) {
                Ok(vb) => {
                    shell_println!("  {} = {}", vb.oid.to_string(), vb.value.display());
                }
                Err(e) => shell_println!("snmp: get failed: {:?}", e),
            }
        }

        "walk" | "w" => {
            // snmp walk <host> <oid> [community]
            if parts.len() < 3 {
                shell_println!("Usage: snmp walk <host> <oid> [community]");
                return;
            }
            let host_str = parts[1];
            let oid_str = parts[2];
            let community = parts.get(3).copied().unwrap_or("public");

            let ip = if let Some(ip) = parse_ipv4(host_str) {
                ip
            } else {
                match crate::net::dns::resolve(host_str) {
                    Ok(ip) => ip,
                    Err(_) => {
                        shell_println!("snmp: cannot resolve host '{}'", host_str);
                        return;
                    }
                }
            };

            let oid = match crate::net::snmp::Oid::parse(oid_str) {
                Some(o) => o,
                None => {
                    shell_println!("snmp: invalid OID '{}'", oid_str);
                    return;
                }
            };

            shell_println!("Walking subtree {}...", oid_str);
            let results = crate::net::snmp::walk(ip, &oid, community);
            if results.is_empty() {
                shell_println!("  (no results — walk requires UDP receive support)");
            } else {
                for vb in &results {
                    let name = crate::net::snmp::oid_name(&vb.oid.to_string());
                    if !name.is_empty() {
                        shell_println!("  {} ({}) = {}", vb.oid.to_string(), name, vb.value.display());
                    } else {
                        shell_println!("  {} = {}", vb.oid.to_string(), vb.value.display());
                    }
                }
                shell_println!("{} entries", results.len());
            }
        }

        "sysinfo" | "sys" => {
            // snmp sysinfo <host> [community]
            if parts.len() < 2 {
                shell_println!("Usage: snmp sysinfo <host> [community]");
                return;
            }
            let host_str = parts[1];
            let community = parts.get(2).copied().unwrap_or("public");

            let ip = if let Some(ip) = parse_ipv4(host_str) {
                ip
            } else {
                match crate::net::dns::resolve(host_str) {
                    Ok(ip) => ip,
                    Err(_) => {
                        shell_println!("snmp: cannot resolve host '{}'", host_str);
                        return;
                    }
                }
            };

            shell_println!("Querying system info from {}...", ip);
            let sys_oids = crate::net::snmp::system_oids();
            for (oid_str, name) in &sys_oids {
                if let Some(oid) = crate::net::snmp::Oid::parse(oid_str) {
                    match crate::net::snmp::get(ip, &oid, community) {
                        Ok(vb) => shell_println!("  {}: {}", name, vb.value.display()),
                        Err(_) => shell_println!("  {}: (timeout)", name),
                    }
                }
            }
        }

        "get6" | "g6" => {
            // snmp get6 <ipv6-host> <oid> [community]
            use crate::net::ipv6::Ipv6Addr;
            if parts.len() < 3 {
                shell_println!("Usage: snmp get6 <ipv6-host> <oid> [community]");
                return;
            }
            let host_str = parts[1];
            let oid_str = parts[2];
            let community = parts.get(3).copied().unwrap_or("public");

            let ip6 = match Ipv6Addr::parse(host_str) {
                Some(addr) => addr,
                None => {
                    // Try AAAA DNS resolution.
                    match crate::net::dns::resolve6(host_str) {
                        Ok(addr) => addr,
                        Err(_) => {
                            shell_println!("snmp: cannot resolve IPv6 host '{}'", host_str);
                            return;
                        }
                    }
                }
            };

            let oid = match crate::net::snmp::Oid::parse(oid_str) {
                Some(o) => o,
                None => {
                    shell_println!("snmp: invalid OID '{}'", oid_str);
                    return;
                }
            };

            let name = crate::net::snmp::oid_name(oid_str);
            if !name.is_empty() {
                shell_println!("Querying {} ({}) via IPv6...", oid_str, name);
            } else {
                shell_println!("Querying {} via IPv6...", oid_str);
            }

            match crate::net::snmp::get_v6(ip6, &oid, community) {
                Ok(vb) => {
                    shell_println!("  {} = {}", vb.oid.to_string(), vb.value.display());
                }
                Err(e) => shell_println!("snmp: get failed: {:?}", e),
            }
        }

        "walk6" | "w6" => {
            // snmp walk6 <ipv6-host> <oid> [community]
            use crate::net::ipv6::Ipv6Addr;
            if parts.len() < 3 {
                shell_println!("Usage: snmp walk6 <ipv6-host> <oid> [community]");
                return;
            }
            let host_str = parts[1];
            let oid_str = parts[2];
            let community = parts.get(3).copied().unwrap_or("public");

            let ip6 = match Ipv6Addr::parse(host_str) {
                Some(addr) => addr,
                None => {
                    match crate::net::dns::resolve6(host_str) {
                        Ok(addr) => addr,
                        Err(_) => {
                            shell_println!("snmp: cannot resolve IPv6 host '{}'", host_str);
                            return;
                        }
                    }
                }
            };

            let oid = match crate::net::snmp::Oid::parse(oid_str) {
                Some(o) => o,
                None => {
                    shell_println!("snmp: invalid OID '{}'", oid_str);
                    return;
                }
            };

            shell_println!("Walking subtree {} via IPv6...", oid_str);
            let results = crate::net::snmp::walk_v6(ip6, &oid, community);
            if results.is_empty() {
                shell_println!("  (no results — walk requires UDP receive support)");
            } else {
                for vb in &results {
                    let name = crate::net::snmp::oid_name(&vb.oid.to_string());
                    if !name.is_empty() {
                        shell_println!("  {} ({}) = {}", vb.oid.to_string(), name, vb.value.display());
                    } else {
                        shell_println!("  {} = {}", vb.oid.to_string(), vb.value.display());
                    }
                }
                shell_println!("{} entries", results.len());
            }
        }

        "sysinfo6" | "sys6" => {
            // snmp sysinfo6 <ipv6-host> [community]
            use crate::net::ipv6::Ipv6Addr;
            if parts.len() < 2 {
                shell_println!("Usage: snmp sysinfo6 <ipv6-host> [community]");
                return;
            }
            let host_str = parts[1];
            let community = parts.get(2).copied().unwrap_or("public");

            let ip6 = match Ipv6Addr::parse(host_str) {
                Some(addr) => addr,
                None => {
                    match crate::net::dns::resolve6(host_str) {
                        Ok(addr) => addr,
                        Err(_) => {
                            shell_println!("snmp: cannot resolve IPv6 host '{}'", host_str);
                            return;
                        }
                    }
                }
            };

            shell_println!("Querying system info from [{}] (IPv6)...", ip6);
            let sys_oids = crate::net::snmp::system_oids();
            for (oid_str, name) in &sys_oids {
                if let Some(oid) = crate::net::snmp::Oid::parse(oid_str) {
                    match crate::net::snmp::get_v6(ip6, &oid, community) {
                        Ok(vb) => shell_println!("  {}: {}", name, vb.value.display()),
                        Err(_) => shell_println!("  {}: (timeout)", name),
                    }
                }
            }
        }

        "oids" => {
            shell_println!("Well-known SNMP OIDs:");
            shell_println!("  System:");
            shell_println!("    1.3.6.1.2.1.1.1.0  sysDescr");
            shell_println!("    1.3.6.1.2.1.1.3.0  sysUpTime");
            shell_println!("    1.3.6.1.2.1.1.4.0  sysContact");
            shell_println!("    1.3.6.1.2.1.1.5.0  sysName");
            shell_println!("    1.3.6.1.2.1.1.6.0  sysLocation");
            shell_println!("  Interfaces:");
            shell_println!("    1.3.6.1.2.1.2.1.0  ifNumber");
            shell_println!("    1.3.6.1.2.1.2.2    ifTable");
            shell_println!("  TCP:");
            shell_println!("    1.3.6.1.2.1.6.9.0  tcpCurrEstab");
            shell_println!("    1.3.6.1.2.1.6.10.0 tcpInSegs");
            shell_println!("    1.3.6.1.2.1.6.11.0 tcpOutSegs");
            shell_println!("  UDP:");
            shell_println!("    1.3.6.1.2.1.7.1.0  udpInDatagrams");
            shell_println!("    1.3.6.1.2.1.7.4.0  udpOutDatagrams");
        }

        "status" | "stats" => {
            let s = crate::net::snmp::stats();
            shell_println!("SNMP statistics:");
            shell_println!("  GET sent:           {}", s.gets_sent);
            shell_println!("  GET-NEXT sent:      {}", s.get_nexts_sent);
            shell_println!("  Walks done:         {}", s.walks_done);
            shell_println!("  Responses received: {}", s.responses_received);
            shell_println!("  Errors:             {}", s.errors_received);
        }

        "test" => {
            match crate::net::snmp::self_test() {
                Ok(()) => shell_println!("snmp: all self-tests passed"),
                Err(e) => shell_println!("snmp: self-test failed: {:?}", e),
            }
        }

        _ => {
            shell_println!("snmp — Simple Network Management Protocol client");
            shell_println!();
            shell_println!("Usage:");
            shell_println!("  snmp get <host> <oid> [community]     — GET single OID");
            shell_println!("  snmp walk <host> <oid> [community]    — walk subtree");
            shell_println!("  snmp sysinfo <host> [community]       — query system info");
            shell_println!("  snmp get6 <host6> <oid> [community]   — GET via IPv6");
            shell_println!("  snmp walk6 <host6> <oid> [community]  — walk via IPv6");
            shell_println!("  snmp sysinfo6 <host6> [community]     — sysinfo via IPv6");
            shell_println!("  snmp oids                             — list well-known OIDs");
            shell_println!("  snmp status                           — show statistics");
            shell_println!("  snmp test                             — run self-tests");
        }
    }
}

/// `iperf` — network bandwidth measurement tool.
fn cmd_iperf(args: &str) {
    use alloc::vec::Vec;
    let parts: Vec<&str> = args.split_whitespace().collect();
    let sub = parts.first().copied().unwrap_or("help");

    match sub {
        "client" | "c" => {
            // iperf client <host> <port> [duration_polls]
            if parts.len() < 3 {
                shell_println!("Usage: iperf client <host> <port> [duration]");
                return;
            }
            let host_str = parts[1];
            let port_str = parts[2];
            let duration: u32 = parts.get(3)
                .and_then(|s| s.parse().ok())
                .unwrap_or(0);

            let ip = if let Some(ip) = parse_ipv4(host_str) {
                ip
            } else {
                match crate::net::dns::resolve(host_str) {
                    Ok(ip) => ip,
                    Err(_) => {
                        shell_println!("iperf: cannot resolve host '{}'", host_str);
                        return;
                    }
                }
            };

            let port: u16 = match port_str.parse() {
                Ok(p) => p,
                Err(_) => {
                    shell_println!("iperf: invalid port '{}'", port_str);
                    return;
                }
            };

            shell_println!("Connecting to {}:{}...", ip, port);
            shell_println!("Running TCP throughput test...");
            match crate::net::iperf::tcp_client_test(ip, port, duration) {
                Ok(result) => {
                    shell_println!("--- TCP Throughput Test ---");
                    shell_println!("  Transferred: {}", crate::net::iperf::format_bytes(result.bytes_transferred));
                    shell_println!("  Duration:    {}", crate::net::iperf::format_duration(result.duration_ns));
                    shell_println!("  Throughput:  {}", crate::net::iperf::format_bandwidth(result.throughput_bps));
                }
                Err(e) => shell_println!("iperf: test failed: {:?}", e),
            }
        }

        "server" | "s" => {
            // iperf server <port> [max_polls]
            if parts.len() < 2 {
                shell_println!("Usage: iperf server <port> [max_polls]");
                return;
            }
            let port: u16 = match parts[1].parse() {
                Ok(p) => p,
                Err(_) => {
                    shell_println!("iperf: invalid port '{}'", parts[1]);
                    return;
                }
            };
            let max_polls: u32 = parts.get(2)
                .and_then(|s| s.parse().ok())
                .unwrap_or(0);

            shell_println!("Listening on port {}...", port);
            match crate::net::iperf::tcp_server_test(port, max_polls) {
                Ok(result) => {
                    shell_println!("--- TCP Server Result ---");
                    shell_println!("  Received:    {}", crate::net::iperf::format_bytes(result.bytes_transferred));
                    shell_println!("  Duration:    {}", crate::net::iperf::format_duration(result.duration_ns));
                    shell_println!("  Throughput:  {}", crate::net::iperf::format_bandwidth(result.throughput_bps));
                }
                Err(e) => shell_println!("iperf: server failed: {:?}", e),
            }
        }

        "udp" | "u" => {
            // iperf udp <host> <port> [count] [size]
            if parts.len() < 3 {
                shell_println!("Usage: iperf udp <host> <port> [count] [size]");
                return;
            }
            let host_str = parts[1];
            let port_str = parts[2];
            let count: u32 = parts.get(3)
                .and_then(|s| s.parse().ok())
                .unwrap_or(100);
            let size: usize = parts.get(4)
                .and_then(|s| s.parse().ok())
                .unwrap_or(1400);

            let ip = if let Some(ip) = parse_ipv4(host_str) {
                ip
            } else {
                match crate::net::dns::resolve(host_str) {
                    Ok(ip) => ip,
                    Err(_) => {
                        shell_println!("iperf: cannot resolve host '{}'", host_str);
                        return;
                    }
                }
            };

            let port: u16 = match port_str.parse() {
                Ok(p) => p,
                Err(_) => {
                    shell_println!("iperf: invalid port '{}'", port_str);
                    return;
                }
            };

            shell_println!("Running UDP throughput test to {}:{}...", ip, port);
            shell_println!("  {} packets x {} bytes", count, size);
            match crate::net::iperf::udp_client_test(ip, port, count, size) {
                Ok(result) => {
                    shell_println!("--- UDP Throughput Test ---");
                    shell_println!("  Transferred: {}", crate::net::iperf::format_bytes(result.bytes_transferred));
                    shell_println!("  Duration:    {}", crate::net::iperf::format_duration(result.duration_ns));
                    shell_println!("  Throughput:  {}", crate::net::iperf::format_bandwidth(result.throughput_bps));
                    shell_println!("  Packets:     {}/{} sent", result.packets_received, result.packets_sent);
                    shell_println!("  Loss:        {:.1}%", result.loss_percent);
                    shell_println!("  Avg jitter:  {}", crate::net::iperf::format_duration(result.avg_jitter_ns));
                }
                Err(e) => shell_println!("iperf: test failed: {:?}", e),
            }
        }

        "udp6" | "u6" => {
            // iperf udp6 <ipv6-host> <port> [count] [size]
            use crate::net::ipv6::Ipv6Addr;
            if parts.len() < 3 {
                shell_println!("Usage: iperf udp6 <ipv6-host> <port> [count] [size]");
                return;
            }
            let host_str = parts[1];
            let port_str = parts[2];
            let count: u32 = parts.get(3)
                .and_then(|s| s.parse().ok())
                .unwrap_or(100);
            let size: usize = parts.get(4)
                .and_then(|s| s.parse().ok())
                .unwrap_or(1400);

            let ip6 = match Ipv6Addr::parse(host_str) {
                Some(addr) => addr,
                None => {
                    // Try AAAA DNS resolution.
                    match crate::net::dns::resolve6(host_str) {
                        Ok(addr) => addr,
                        Err(_) => {
                            shell_println!("iperf: cannot resolve IPv6 host '{}'", host_str);
                            return;
                        }
                    }
                }
            };

            let port: u16 = match port_str.parse() {
                Ok(p) => p,
                Err(_) => {
                    shell_println!("iperf: invalid port '{}'", port_str);
                    return;
                }
            };

            shell_println!("Running UDP6 throughput test to [{}]:{}...", ip6, port);
            shell_println!("  {} packets x {} bytes", count, size);
            match crate::net::iperf::udp_client_test_v6(ip6, port, count, size) {
                Ok(result) => {
                    shell_println!("--- UDP6 Throughput Test ---");
                    shell_println!("  Transferred: {}", crate::net::iperf::format_bytes(result.bytes_transferred));
                    shell_println!("  Duration:    {}", crate::net::iperf::format_duration(result.duration_ns));
                    shell_println!("  Throughput:  {}", crate::net::iperf::format_bandwidth(result.throughput_bps));
                    shell_println!("  Packets:     {}/{} sent", result.packets_received, result.packets_sent);
                    shell_println!("  Loss:        {:.1}%", result.loss_percent);
                    shell_println!("  Avg jitter:  {}", crate::net::iperf::format_duration(result.avg_jitter_ns));
                }
                Err(e) => shell_println!("iperf: test failed: {:?}", e),
            }
        }

        "status" | "stats" => {
            let s = crate::net::iperf::stats();
            shell_println!("iperf statistics:");
            shell_println!("  Tests run:       {}", s.tests_run);
            shell_println!("  TCP tests:       {}", s.tcp_tests);
            shell_println!("  UDP tests:       {}", s.udp_tests);
            shell_println!("  Server sessions: {}", s.server_sessions);
            shell_println!("  Total TX:        {}", crate::net::iperf::format_bytes(s.total_bytes_tx));
            shell_println!("  Total RX:        {}", crate::net::iperf::format_bytes(s.total_bytes_rx));
        }

        "test" => {
            match crate::net::iperf::self_test() {
                Ok(()) => shell_println!("iperf: all self-tests passed"),
                Err(e) => shell_println!("iperf: self-test failed: {:?}", e),
            }
        }

        _ => {
            shell_println!("iperf — network bandwidth measurement tool (IPv4 + IPv6)");
            shell_println!();
            shell_println!("Usage:");
            shell_println!("  iperf client <host> <port> [duration]   — TCP throughput test");
            shell_println!("  iperf server <port> [max_polls]         — TCP server mode");
            shell_println!("  iperf udp <host> <port> [count] [size]  — UDP throughput test");
            shell_println!("  iperf udp6 <host> <port> [count] [size] — UDP6 throughput test");
            shell_println!("  iperf status                            — show statistics");
            shell_println!("  iperf test                              — run self-tests");
        }
    }
}

/// `nc` / `netcat` — TCP/UDP networking swiss army knife.
fn cmd_nc(args: &str) {
    use alloc::vec::Vec;
    let parts: Vec<&str> = args.split_whitespace().collect();
    let sub = parts.first().copied().unwrap_or("help");

    match sub {
        "connect" | "c" => {
            // nc connect <host> <port>
            if parts.len() < 3 {
                shell_println!("Usage: nc connect <host> <port>");
                return;
            }
            let host_str = parts[1];
            let port_str = parts[2];

            let ip = if let Some(ip) = parse_ipv4(host_str) {
                ip
            } else {
                // Try DNS resolution.
                match crate::net::dns::resolve(host_str) {
                    Ok(ip) => ip,
                    Err(_) => {
                        shell_println!("nc: cannot resolve host '{}'", host_str);
                        return;
                    }
                }
            };

            let port: u16 = match port_str.parse() {
                Ok(p) => p,
                Err(_) => {
                    shell_println!("nc: invalid port '{}'", port_str);
                    return;
                }
            };

            shell_println!("Connecting to {}:{}...", ip, port);
            match crate::net::netcat::tcp_connect(ip, port) {
                Ok((handle, data)) => {
                    let svc = crate::net::netcat::service_name(port);
                    if svc.is_empty() {
                        shell_println!("Connected to {}:{} (handle {})", ip, port, handle);
                    } else {
                        shell_println!("Connected to {}:{} ({}) (handle {})", ip, port, svc, handle);
                    }
                    if !data.is_empty() {
                        shell_println!("Received {} bytes:", data.len());
                        // Print as text if valid UTF-8, otherwise hex.
                        if let Ok(text) = core::str::from_utf8(&data) {
                            for line in text.lines() {
                                shell_println!("  {}", line);
                            }
                        } else {
                            let preview_len = data.len().min(64);
                            let hex: Vec<u8> = data[..preview_len].iter()
                                .flat_map(|b| {
                                    let hi = b >> 4;
                                    let lo = b & 0xf;
                                    let to_hex = |n: u8| if n < 10 { b'0' + n } else { b'a' + n - 10 };
                                    [to_hex(hi), to_hex(lo), b' ']
                                })
                                .collect();
                            if let Ok(s) = core::str::from_utf8(&hex) {
                                shell_println!("  {}", s.trim());
                            }
                        }
                    }
                    // Close the connection.
                    crate::net::netcat::tcp_close(handle);
                }
                Err(e) => shell_println!("nc: connect failed: {:?}", e),
            }
        }

        "listen" | "l" => {
            // nc listen <port>
            if parts.len() < 2 {
                shell_println!("Usage: nc listen <port>");
                return;
            }
            let port: u16 = match parts[1].parse() {
                Ok(p) => p,
                Err(_) => {
                    shell_println!("nc: invalid port '{}'", parts[1]);
                    return;
                }
            };

            shell_println!("Listening on port {}...", port);
            match crate::net::netcat::tcp_listen(port) {
                Ok((handle, peer_ip, peer_port)) => {
                    shell_println!("Connection from {}:{} (handle {})", peer_ip, peer_port, handle);
                    // Try to receive some data.
                    match crate::net::netcat::tcp_recv(handle) {
                        Ok(data) if !data.is_empty() => {
                            shell_println!("Received {} bytes:", data.len());
                            if let Ok(text) = core::str::from_utf8(&data) {
                                for line in text.lines() {
                                    shell_println!("  {}", line);
                                }
                            }
                        }
                        _ => shell_println!("(no data received)"),
                    }
                    crate::net::netcat::tcp_close(handle);
                }
                Err(e) => shell_println!("nc: listen failed: {:?}", e),
            }
        }

        "send" | "s" => {
            // nc send <host> <port> <data...>
            if parts.len() < 4 {
                shell_println!("Usage: nc send <host> <port> <data...>");
                return;
            }
            let host_str = parts[1];
            let port_str = parts[2];
            let data_str: alloc::string::String = parts[3..].join(" ");

            let ip = if let Some(ip) = parse_ipv4(host_str) {
                ip
            } else {
                match crate::net::dns::resolve(host_str) {
                    Ok(ip) => ip,
                    Err(_) => {
                        shell_println!("nc: cannot resolve host '{}'", host_str);
                        return;
                    }
                }
            };

            let port: u16 = match port_str.parse() {
                Ok(p) => p,
                Err(_) => {
                    shell_println!("nc: invalid port '{}'", port_str);
                    return;
                }
            };

            // TCP send: connect, send, close.
            shell_println!("Connecting to {}:{}...", ip, port);
            match crate::net::netcat::tcp_connect(ip, port) {
                Ok((handle, _)) => {
                    match crate::net::netcat::tcp_send(handle, data_str.as_bytes()) {
                        Ok(sent) => shell_println!("Sent {} bytes to {}:{}", sent, ip, port),
                        Err(e) => shell_println!("nc: send failed: {:?}", e),
                    }
                    // Try to receive response.
                    match crate::net::netcat::tcp_recv(handle) {
                        Ok(data) if !data.is_empty() => {
                            shell_println!("Response ({} bytes):", data.len());
                            if let Ok(text) = core::str::from_utf8(&data) {
                                for line in text.lines() {
                                    shell_println!("  {}", line);
                                }
                            }
                        }
                        _ => {}
                    }
                    crate::net::netcat::tcp_close(handle);
                }
                Err(e) => shell_println!("nc: connect failed: {:?}", e),
            }
        }

        "udp" | "u" => {
            // nc udp <host> <port> <data...>
            if parts.len() < 4 {
                shell_println!("Usage: nc udp <host> <port> <data...>");
                return;
            }
            let host_str = parts[1];
            let port_str = parts[2];
            let data_str: alloc::string::String = parts[3..].join(" ");

            let ip = if let Some(ip) = parse_ipv4(host_str) {
                ip
            } else {
                match crate::net::dns::resolve(host_str) {
                    Ok(ip) => ip,
                    Err(_) => {
                        shell_println!("nc: cannot resolve host '{}'", host_str);
                        return;
                    }
                }
            };

            let port: u16 = match port_str.parse() {
                Ok(p) => p,
                Err(_) => {
                    shell_println!("nc: invalid port '{}'", port_str);
                    return;
                }
            };

            match crate::net::netcat::udp_send(ip, port, data_str.as_bytes()) {
                Ok(()) => shell_println!("Sent {} bytes (UDP) to {}:{}", data_str.len(), ip, port),
                Err(e) => shell_println!("nc: udp send failed: {:?}", e),
            }
        }

        "udp6" | "u6" => {
            // nc udp6 <ipv6-host> <port> <data...>
            use crate::net::ipv6::Ipv6Addr;
            if parts.len() < 4 {
                shell_println!("Usage: nc udp6 <ipv6-host> <port> <data...>");
                return;
            }
            let host_str = parts[1];
            let port_str = parts[2];
            let data_str: alloc::string::String = parts[3..].join(" ");

            let ip6 = match Ipv6Addr::parse(host_str) {
                Some(addr) => addr,
                None => {
                    match crate::net::dns::resolve6(host_str) {
                        Ok(addr) => addr,
                        Err(_) => {
                            shell_println!("nc: cannot resolve IPv6 host '{}'", host_str);
                            return;
                        }
                    }
                }
            };

            let port: u16 = match port_str.parse() {
                Ok(p) => p,
                Err(_) => {
                    shell_println!("nc: invalid port '{}'", port_str);
                    return;
                }
            };

            match crate::net::netcat::udp_send_v6(ip6, port, data_str.as_bytes()) {
                Ok(()) => shell_println!("Sent {} bytes (UDP6) to [{}]:{}", data_str.len(), ip6, port),
                Err(e) => shell_println!("nc: udp6 send failed: {:?}", e),
            }
        }

        "udplisten" | "ul" => {
            // nc udplisten <port> [timeout]
            if parts.len() < 2 {
                shell_println!("Usage: nc udplisten <port> [timeout]");
                return;
            }
            let port: u16 = match parts[1].parse() {
                Ok(p) => p,
                Err(_) => {
                    shell_println!("nc: invalid port '{}'", parts[1]);
                    return;
                }
            };
            let timeout: u32 = parts.get(2)
                .and_then(|s| s.parse().ok())
                .unwrap_or(0);

            shell_println!("Listening for UDP datagrams on port {} ...", port);
            match crate::net::netcat::udp_recv_any(port, timeout) {
                Ok((src_addr, src_port, data)) => {
                    shell_println!("Received {} bytes from [{}]:{}", data.len(), src_addr, src_port);
                    // Print as text if valid UTF-8, otherwise hex.
                    if let Ok(text) = core::str::from_utf8(&data) {
                        shell_println!("{}", text);
                    } else {
                        let hex: alloc::string::String = data.iter()
                            .take(128)
                            .map(|b| alloc::format!("{:02x}", b))
                            .collect::<alloc::vec::Vec<_>>()
                            .join(" ");
                        shell_println!("(hex) {}", hex);
                        if data.len() > 128 {
                            shell_println!("  ... ({} more bytes)", data.len() - 128);
                        }
                    }
                }
                Err(e) => shell_println!("nc: listen failed: {:?}", e),
            }
        }

        "scan" | "z" => {
            // nc scan <host> <start-port> [end-port]
            if parts.len() < 3 {
                shell_println!("Usage: nc scan <host> <start-port> [end-port]");
                return;
            }
            let host_str = parts[1];
            let start_str = parts[2];
            let end_str = parts.get(3).copied().unwrap_or(start_str);

            let ip = if let Some(ip) = parse_ipv4(host_str) {
                ip
            } else {
                match crate::net::dns::resolve(host_str) {
                    Ok(ip) => ip,
                    Err(_) => {
                        shell_println!("nc: cannot resolve host '{}'", host_str);
                        return;
                    }
                }
            };

            let start: u16 = match start_str.parse() {
                Ok(p) => p,
                Err(_) => {
                    shell_println!("nc: invalid port '{}'", start_str);
                    return;
                }
            };
            let end: u16 = match end_str.parse() {
                Ok(p) => p,
                Err(_) => {
                    shell_println!("nc: invalid port '{}'", end_str);
                    return;
                }
            };

            shell_println!("Scanning {}:{}-{}...", ip, start, end);
            let results = crate::net::netcat::scan_ports(ip, start, end);
            let mut open_count = 0u16;
            for r in &results {
                if r.open {
                    let svc = crate::net::netcat::service_name(r.port);
                    if svc.is_empty() {
                        shell_println!("  port {}: OPEN", r.port);
                    } else {
                        shell_println!("  port {}: OPEN ({})", r.port, svc);
                    }
                    open_count = open_count.saturating_add(1);
                }
            }
            shell_println!("Scan complete: {} ports scanned, {} open", results.len(), open_count);
        }

        "service" => {
            // nc service <port>
            if parts.len() < 2 {
                shell_println!("Usage: nc service <port>");
                return;
            }
            let port: u16 = match parts[1].parse() {
                Ok(p) => p,
                Err(_) => {
                    shell_println!("nc: invalid port '{}'", parts[1]);
                    return;
                }
            };
            let svc = crate::net::netcat::service_name(port);
            if svc.is_empty() {
                shell_println!("Port {}: (unknown service)", port);
            } else {
                shell_println!("Port {}: {}", port, svc);
            }
        }

        "status" | "stats" => {
            let s = crate::net::netcat::stats();
            shell_println!("Netcat statistics:");
            shell_println!("  TCP connects:   {}", s.tcp_connects);
            shell_println!("  TCP listens:    {}", s.tcp_listens);
            shell_println!("  UDP sends:      {}", s.udp_sends);
            shell_println!("  Port scans:     {}", s.port_scans);
            shell_println!("  Bytes sent:     {}", s.bytes_sent);
            shell_println!("  Bytes received: {}", s.bytes_received);
        }

        "test" => {
            match crate::net::netcat::self_test() {
                Ok(()) => shell_println!("nc: all self-tests passed"),
                Err(e) => shell_println!("nc: self-test failed: {:?}", e),
            }
        }

        _ => {
            shell_println!("nc — TCP/UDP networking swiss army knife");
            shell_println!();
            shell_println!("Usage:");
            shell_println!("  nc connect <host> <port>              — TCP connect (banner grab)");
            shell_println!("  nc listen <port>                      — TCP listen (accept one connection)");
            shell_println!("  nc send <host> <port> <data...>       — TCP send data");
            shell_println!("  nc udp <host> <port> <data...>        — UDP send datagram (IPv4)");
            shell_println!("  nc udp6 <host> <port> <data...>       — UDP send datagram (IPv6)");
            shell_println!("  nc udplisten <port> [timeout]         — listen for UDP (v4+v6)");
            shell_println!("  nc scan <host> <start> [end]          — port scan");
            shell_println!("  nc service <port>                     — look up well-known service");
            shell_println!("  nc status                             — show statistics");
            shell_println!("  nc test                               — run self-tests");
        }
    }
}

/// `inputa11y` / `ia11y` — input accessibility features.
fn cmd_inputa11y(args: &str) {
    use crate::fs::inputa11y;
    let parts: Vec<&str> = args.split_whitespace().collect();
    let sub = parts.first().copied().unwrap_or("");
    match sub {
        "show" | "" => {
            let (sticky, filter, toggle, mouse, keys, filtered, _) = inputa11y::stats();
            shell_println!("Input Accessibility");
            shell_println!("  Sticky keys:  {}", if sticky { "on" } else { "off" });
            shell_println!("  Filter keys:  {}", if filter { "on" } else { "off" });
            shell_println!("  Toggle keys:  {}", if toggle { "on" } else { "off" });
            shell_println!("  Mouse keys:   {}", if mouse { "on" } else { "off" });
            shell_println!("  Keys processed: {}", keys);
            shell_println!("  Keys filtered:  {}", filtered);

            if sticky {
                let states = inputa11y::get_sticky_states();
                for (m, s) in &states {
                    if *s != inputa11y::StickyState::Off {
                        shell_println!("  {} = {}", m.label(), s.label());
                    }
                }
            }
        }
        "sticky" => {
            if parts.len() < 2 {
                shell_println!("Usage: ia11y sticky <on|off>");
                return;
            }
            let on = parts[1] == "on" || parts[1] == "true";
            match inputa11y::set_sticky_keys(on) {
                Ok(()) => shell_println!("Sticky keys {}.", if on { "enabled" } else { "disabled" }),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "filter" => {
            if parts.len() < 2 {
                shell_println!("Usage: ia11y filter <on|off>");
                return;
            }
            let on = parts[1] == "on" || parts[1] == "true";
            match inputa11y::set_filter_keys(on) {
                Ok(()) => shell_println!("Filter keys {}.", if on { "enabled" } else { "disabled" }),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "toggle" => {
            if parts.len() < 2 {
                shell_println!("Usage: ia11y toggle <on|off>");
                return;
            }
            let on = parts[1] == "on" || parts[1] == "true";
            match inputa11y::set_toggle_keys(on) {
                Ok(()) => shell_println!("Toggle keys {}.", if on { "enabled" } else { "disabled" }),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "mouse" => {
            if parts.len() < 2 {
                shell_println!("Usage: ia11y mouse <on|off> [speed]");
                return;
            }
            let on = parts[1] == "on" || parts[1] == "true";
            match inputa11y::set_mouse_keys(on) {
                Ok(()) => {
                    shell_println!("Mouse keys {}.", if on { "enabled" } else { "disabled" });
                    if on && parts.len() > 2 {
                        if let Ok(speed) = parts[2].parse::<u32>() {
                            inputa11y::set_mouse_speed(speed).ok();
                            shell_println!("Mouse speed set to {}.", speed);
                        }
                    }
                }
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "bounce" => {
            if parts.len() < 2 {
                shell_println!("Usage: ia11y bounce <on|off>");
                return;
            }
            let on = parts[1] == "on" || parts[1] == "true";
            match inputa11y::set_bounce_keys(on) {
                Ok(()) => shell_println!("Bounce keys {}.", if on { "enabled" } else { "disabled" }),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "stats" => {
            let (sticky, filter, toggle, mouse, keys, filtered, ops) = inputa11y::stats();
            shell_println!("Sticky: {}  Filter: {}  Toggle: {}  Mouse: {}  Keys: {}  Filtered: {}  Ops: {}",
                sticky, filter, toggle, mouse, keys, filtered, ops);
        }
        "test" => { inputa11y::self_test(); shell_println!("Input a11y self-test complete."); }
        "init" => { inputa11y::init_defaults(); shell_println!("Input a11y initialized."); }
        "help" => {
            shell_println!("inputa11y (ia11y) — input accessibility");
            shell_println!("  show               Overview");
            shell_println!("  sticky <on|off>     Sticky keys");
            shell_println!("  filter <on|off>     Filter keys");
            shell_println!("  toggle <on|off>     Toggle keys");
            shell_println!("  mouse <on|off>      Mouse keys");
            shell_println!("  bounce <on|off>     Bounce keys");
            shell_println!("  stats / test / init");
        }
        _ => { shell_println!("Unknown subcommand: {}", sub); shell_println!("Use 'ia11y help' for usage."); }
    }
}

/// `driverupdate` / `dupdate` — driver version and update management.
fn cmd_driverupdate(args: &str) {
    use crate::fs::driverupdate;
    let parts: Vec<&str> = args.split_whitespace().collect();
    let sub = parts.first().copied().unwrap_or("");
    match sub {
        "" | "show" | "list" => {
            driverupdate::init_defaults();
            let drivers = driverupdate::list_drivers();
            if drivers.is_empty() {
                shell_println!("No drivers registered.");
            } else {
                shell_println!("{:<4} {:<30} {:<10} {:<10} {:<16}", "ID", "Name", "Version", "Category", "Status");
                for d in &drivers {
                    shell_println!("{:<4} {:<30} {:<10} {:<10} {:<16}",
                        d.id, d.name, d.version, d.category.label(), d.status.label());
                }
                let avail = driverupdate::updates_available();
                if avail > 0 {
                    shell_println!("\n{} update(s) available.", avail);
                }
            }
        }
        "register" | "add" => {
            let name = parts.get(1).copied().unwrap_or("");
            let ver = parts.get(2).copied().unwrap_or("1.0.0");
            if name.is_empty() {
                shell_println!("Usage: dupdate register <name> [version]");
            } else {
                match driverupdate::register_driver(name, driverupdate::DriverCategory::Other, ver, "User") {
                    Ok(id) => shell_println!("Registered driver '{}' v{} (id={})", name, ver, id),
                    Err(e) => shell_println!("Error: {:?}", e),
                }
            }
        }
        "update" | "install" => {
            if let Some(id_str) = parts.get(1) {
                if let Ok(id) = id_str.parse::<u32>() {
                    match driverupdate::install_update(id) {
                        Ok(()) => {
                            if let Ok(d) = driverupdate::get_driver(id) {
                                shell_println!("Updated '{}' to v{}", d.name, d.version);
                            }
                        }
                        Err(e) => shell_println!("Error: {:?}", e),
                    }
                } else { shell_println!("Invalid ID."); }
            } else { shell_println!("Usage: dupdate install <id>"); }
        }
        "rollback" | "revert" => {
            if let Some(id_str) = parts.get(1) {
                if let Ok(id) = id_str.parse::<u32>() {
                    match driverupdate::rollback(id) {
                        Ok(()) => {
                            if let Ok(d) = driverupdate::get_driver(id) {
                                shell_println!("Rolled back '{}' to v{}", d.name, d.version);
                            }
                        }
                        Err(e) => shell_println!("Error: {:?}", e),
                    }
                } else { shell_println!("Invalid ID."); }
            } else { shell_println!("Usage: dupdate rollback <id>"); }
        }
        "setupdate" => {
            let id_str = parts.get(1).copied().unwrap_or("");
            let ver = parts.get(2).copied().unwrap_or("");
            if id_str.is_empty() || ver.is_empty() {
                shell_println!("Usage: dupdate setupdate <id> <version>");
            } else if let Ok(id) = id_str.parse::<u32>() {
                match driverupdate::set_available_update(id, ver) {
                    Ok(()) => shell_println!("Update v{} staged for driver {}", ver, id),
                    Err(e) => shell_println!("Error: {:?}", e),
                }
            } else { shell_println!("Invalid ID."); }
        }
        "info" => {
            if let Some(id_str) = parts.get(1) {
                if let Ok(id) = id_str.parse::<u32>() {
                    match driverupdate::get_driver(id) {
                        Ok(d) => {
                            shell_println!("Driver #{}", d.id);
                            shell_println!("  Name:      {}", d.name);
                            shell_println!("  Category:  {}", d.category.label());
                            shell_println!("  Version:   {}", d.version);
                            shell_println!("  Previous:  {}", if d.previous_version.is_empty() { "none" } else { &d.previous_version });
                            shell_println!("  Available: {}", if d.available_version.is_empty() { "none" } else { &d.available_version });
                            shell_println!("  Status:    {}", d.status.label());
                            shell_println!("  Provider:  {}", d.provider);
                            shell_println!("  Auto-update: {}", d.auto_update);
                        }
                        Err(e) => shell_println!("Error: {:?}", e),
                    }
                } else { shell_println!("Invalid ID."); }
            } else { shell_println!("Usage: dupdate info <id>"); }
        }
        "stats" => {
            let (count, updates, total_updates, total_rollbacks, ops) = driverupdate::stats();
            shell_println!("Drivers: {}, Updates available: {}", count, updates);
            shell_println!("Total updates: {}, Total rollbacks: {}, Ops: {}", total_updates, total_rollbacks, ops);
        }
        "test" => { driverupdate::self_test(); shell_println!("Driver update self-test complete."); }
        "init" => { driverupdate::init_defaults(); shell_println!("Driver update initialized."); }
        _ => {
            shell_println!("driverupdate (dupdate) — driver update management");
            shell_println!("  show / list          List drivers");
            shell_println!("  info <id>            Driver details");
            shell_println!("  register <name> [v]  Register driver");
            shell_println!("  setupdate <id> <v>   Stage update");
            shell_println!("  install <id>         Install update");
            shell_println!("  rollback <id>        Rollback driver");
            shell_println!("  stats / test / init");
        }
    }
}

/// `netshare` / `nshare` — network share management.
fn cmd_netshare(args: &str) {
    use crate::fs::netshare;
    let parts: Vec<&str> = args.split_whitespace().collect();
    let sub = parts.first().copied().unwrap_or("");
    match sub {
        "" | "show" | "list" => {
            netshare::init_defaults();
            let shares = netshare::list_shares();
            if shares.is_empty() {
                shell_println!("No network shares mounted.");
            } else {
                shell_println!("{:<4} {:<8} {:<16} {:<20} {:<16} {:<12}", "ID", "Proto", "Host", "Remote", "Mount", "State");
                for s in &shares {
                    shell_println!("{:<4} {:<8} {:<16} {:<20} {:<16} {:<12}",
                        s.id, s.protocol.label(), s.host, s.remote_path, s.mount_point, s.state.label());
                }
            }
        }
        "mount" | "add" => {
            let host = parts.get(1).copied().unwrap_or("");
            let remote = parts.get(2).copied().unwrap_or("/");
            let mountpt = parts.get(3).copied().unwrap_or("");
            if host.is_empty() || mountpt.is_empty() {
                shell_println!("Usage: nshare mount <host> <remote_path> <mount_point> [user]");
            } else {
                let user = parts.get(4).copied().unwrap_or("guest");
                match netshare::mount(netshare::ShareProtocol::Smb3, host, remote, mountpt, user, false, false) {
                    Ok(id) => shell_println!("Mounted {}:{} at {} (id={})", host, remote, mountpt, id),
                    Err(e) => shell_println!("Error: {:?}", e),
                }
            }
        }
        "unmount" | "umount" | "remove" => {
            if let Some(id_str) = parts.get(1) {
                if let Ok(id) = id_str.parse::<u32>() {
                    match netshare::unmount(id) {
                        Ok(()) => shell_println!("Unmounted share {}", id),
                        Err(e) => shell_println!("Error: {:?}", e),
                    }
                } else { shell_println!("Invalid ID."); }
            } else { shell_println!("Usage: nshare unmount <id>"); }
        }
        "info" => {
            if let Some(id_str) = parts.get(1) {
                if let Ok(id) = id_str.parse::<u32>() {
                    match netshare::get_share(id) {
                        Ok(s) => {
                            shell_println!("Share #{}", s.id);
                            shell_println!("  Protocol:  {}", s.protocol.label());
                            shell_println!("  Host:      {}", s.host);
                            shell_println!("  Remote:    {}", s.remote_path);
                            shell_println!("  Mount:     {}", s.mount_point);
                            shell_println!("  User:      {}", s.username);
                            shell_println!("  State:     {}", s.state.label());
                            shell_println!("  Auto-mount: {}", s.auto_mount);
                            shell_println!("  Read-only: {}", s.read_only);
                            shell_println!("  Read: {} B, Written: {} B", s.bytes_read, s.bytes_written);
                        }
                        Err(e) => shell_println!("Error: {:?}", e),
                    }
                } else { shell_println!("Invalid ID."); }
            } else { shell_println!("Usage: nshare info <id>"); }
        }
        "auto" => {
            let shares = netshare::auto_mount_shares();
            if shares.is_empty() {
                shell_println!("No auto-mount shares.");
            } else {
                for s in &shares {
                    shell_println!("  [{}] {}:{} → {}", s.id, s.host, s.remote_path, s.mount_point);
                }
            }
        }
        "stats" => {
            let (count, connected, mounts, errors, ops) = netshare::stats();
            shell_println!("Shares: {}, Connected: {}", count, connected);
            shell_println!("Total mounts: {}, Errors: {}, Ops: {}", mounts, errors, ops);
        }
        "test" => { netshare::self_test(); shell_println!("Net share self-test complete."); }
        "init" => { netshare::init_defaults(); shell_println!("Net share initialized."); }
        _ => {
            shell_println!("netshare (nshare) — network share management");
            shell_println!("  show / list              List shares");
            shell_println!("  mount <host> <path> <mp> Mount share");
            shell_println!("  unmount <id>             Unmount share");
            shell_println!("  info <id>                Share details");
            shell_println!("  auto                     Auto-mount list");
            shell_println!("  stats / test / init");
        }
    }
}

/// `startuprepair` / `srepair` — boot diagnostics and repair.
fn cmd_startuprepair(args: &str) {
    use crate::fs::startuprepair;
    let parts: Vec<&str> = args.split_whitespace().collect();
    let sub = parts.first().copied().unwrap_or("");
    match sub {
        "" | "show" | "list" => {
            startuprepair::init_defaults();
            let sessions = startuprepair::list_sessions();
            if sessions.is_empty() {
                shell_println!("No repair sessions.");
            } else {
                shell_println!("{:<4} {:<6} {:<8} {:<10}", "ID", "Checks", "Auto", "Completed");
                for s in &sessions {
                    let completed = if s.completed_ns > 0 { "yes" } else { "no" };
                    shell_println!("{:<4} {:<6} {:<8} {:<10}",
                        s.session_id, s.checks.len(), s.auto_triggered, completed);
                }
            }
        }
        "run" | "scan" => {
            startuprepair::init_defaults();
            match startuprepair::run_all_checks() {
                Ok(sid) => {
                    shell_println!("Repair session {} completed.", sid);
                    if let Ok(session) = startuprepair::get_session(sid) {
                        for c in &session.checks {
                            shell_println!("  [{}] {} — {} — {}",
                                c.result.label(), c.category.label(), c.description, c.detail);
                        }
                        let passed = session.checks.iter().filter(|c| c.result == startuprepair::CheckResult::Pass).count();
                        let failed = session.checks.iter().filter(|c| c.result == startuprepair::CheckResult::Fail).count();
                        let repaired = session.checks.iter().filter(|c| c.result == startuprepair::CheckResult::Repaired).count();
                        shell_println!("\n{} passed, {} failed, {} repaired", passed, failed, repaired);
                    }
                }
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "session" | "info" => {
            if let Some(id_str) = parts.get(1) {
                if let Ok(id) = id_str.parse::<u32>() {
                    match startuprepair::get_session(id) {
                        Ok(session) => {
                            shell_println!("Session #{}", session.session_id);
                            shell_println!("  Auto-triggered: {}", session.auto_triggered);
                            shell_println!("  Completed: {}", session.completed_ns > 0);
                            shell_println!("  Checks:");
                            for c in &session.checks {
                                shell_println!("    [{}] {} — {}", c.result.label(), c.category.label(), c.description);
                                if !c.detail.is_empty() { shell_println!("          {}", c.detail); }
                            }
                        }
                        Err(e) => shell_println!("Error: {:?}", e),
                    }
                } else { shell_println!("Invalid ID."); }
            } else { shell_println!("Usage: srepair session <id>"); }
        }
        "failboot" => {
            match startuprepair::record_failed_boot() {
                Ok(needs_repair) => {
                    if needs_repair {
                        shell_println!("Auto-repair threshold reached! Run 'srepair run'.");
                    } else {
                        shell_println!("Failed boot recorded.");
                    }
                }
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "resetboots" => {
            match startuprepair::reset_failed_boots() {
                Ok(()) => shell_println!("Failed boot counter reset."),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "stats" => {
            let (sessions, checks, repairs, failed, ops) = startuprepair::stats();
            shell_println!("Sessions: {}, Checks: {}, Repairs: {}", sessions, checks, repairs);
            shell_println!("Failed boots: {}, Ops: {}", failed, ops);
        }
        "test" => { startuprepair::self_test(); shell_println!("Startup repair self-test complete."); }
        "init" => { startuprepair::init_defaults(); shell_println!("Startup repair initialized."); }
        _ => {
            shell_println!("startuprepair (srepair) — boot diagnostics");
            shell_println!("  show / list          List sessions");
            shell_println!("  run / scan           Run all checks");
            shell_println!("  session <id>         Session details");
            shell_println!("  failboot             Record failed boot");
            shell_println!("  resetboots           Reset fail counter");
            shell_println!("  stats / test / init");
        }
    }
}

/// `remoteassist` / `rassist` — remote assistance sessions.
fn cmd_remoteassist(args: &str) {
    use crate::fs::remoteassist;
    let parts: Vec<&str> = args.split_whitespace().collect();
    let sub = parts.first().copied().unwrap_or("");
    match sub {
        "" | "show" | "list" => {
            remoteassist::init_defaults();
            let sessions = remoteassist::list_sessions();
            if sessions.is_empty() {
                shell_println!("No remote assist sessions.");
            } else {
                shell_println!("{:<4} {:<8} {:<12} {:<14} {:<10} {:<10}", "ID", "Code", "State", "Mode", "Host", "Helper");
                for s in &sessions {
                    shell_println!("{:<4} {:<8} {:<12} {:<14} {:<10} {:<10}",
                        s.id, s.code, s.state.label(), s.mode.label(),
                        s.host_name, if s.helper_name.is_empty() { "-" } else { &s.helper_name });
                }
            }
        }
        "invite" | "create" => {
            remoteassist::init_defaults();
            let host = parts.get(1).copied().unwrap_or("User");
            let mode_str = parts.get(2).copied().unwrap_or("view");
            let mode = match mode_str {
                "full" => remoteassist::AssistMode::FullControl,
                "prompt" => remoteassist::AssistMode::PromptedControl,
                _ => remoteassist::AssistMode::ViewOnly,
            };
            match remoteassist::create_invitation(host, mode, 3600) {
                Ok((id, code)) => shell_println!("Invitation created: code={} (session {}, mode={})", code, id, mode.label()),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "connect" | "join" => {
            let code = parts.get(1).copied().unwrap_or("");
            let helper = parts.get(2).copied().unwrap_or("Helper");
            if code.is_empty() {
                shell_println!("Usage: rassist connect <code> [helper_name]");
            } else {
                match remoteassist::connect(code, helper) {
                    Ok(id) => shell_println!("Connected to session {} as '{}'", id, helper),
                    Err(e) => shell_println!("Error: {:?}", e),
                }
            }
        }
        "grant" => {
            if let Some(id_str) = parts.get(1) {
                if let Ok(id) = id_str.parse::<u32>() {
                    match remoteassist::grant_control(id) {
                        Ok(()) => shell_println!("Full control granted for session {}", id),
                        Err(e) => shell_println!("Error: {:?}", e),
                    }
                } else { shell_println!("Invalid ID."); }
            } else { shell_println!("Usage: rassist grant <id>"); }
        }
        "revoke" => {
            if let Some(id_str) = parts.get(1) {
                if let Ok(id) = id_str.parse::<u32>() {
                    match remoteassist::revoke_control(id) {
                        Ok(()) => shell_println!("Control revoked for session {}", id),
                        Err(e) => shell_println!("Error: {:?}", e),
                    }
                } else { shell_println!("Invalid ID."); }
            } else { shell_println!("Usage: rassist revoke <id>"); }
        }
        "pause" => {
            if let Some(id_str) = parts.get(1) {
                if let Ok(id) = id_str.parse::<u32>() {
                    match remoteassist::pause_session(id) {
                        Ok(()) => shell_println!("Session {} paused", id),
                        Err(e) => shell_println!("Error: {:?}", e),
                    }
                } else { shell_println!("Invalid ID."); }
            } else { shell_println!("Usage: rassist pause <id>"); }
        }
        "resume" => {
            if let Some(id_str) = parts.get(1) {
                if let Ok(id) = id_str.parse::<u32>() {
                    match remoteassist::resume_session(id) {
                        Ok(()) => shell_println!("Session {} resumed", id),
                        Err(e) => shell_println!("Error: {:?}", e),
                    }
                } else { shell_println!("Invalid ID."); }
            } else { shell_println!("Usage: rassist resume <id>"); }
        }
        "end" | "stop" => {
            if let Some(id_str) = parts.get(1) {
                if let Ok(id) = id_str.parse::<u32>() {
                    match remoteassist::end_session(id) {
                        Ok(()) => shell_println!("Session {} ended", id),
                        Err(e) => shell_println!("Error: {:?}", e),
                    }
                } else { shell_println!("Invalid ID."); }
            } else { shell_println!("Usage: rassist end <id>"); }
        }
        "clipboard" | "clip" => {
            let id_str = parts.get(1).copied().unwrap_or("");
            let on_off = parts.get(2).copied().unwrap_or("on");
            if let Ok(id) = id_str.parse::<u32>() {
                let shared = on_off != "off";
                match remoteassist::set_clipboard_sharing(id, shared) {
                    Ok(()) => shell_println!("Clipboard sharing {}", if shared { "enabled" } else { "disabled" }),
                    Err(e) => shell_println!("Error: {:?}", e),
                }
            } else { shell_println!("Usage: rassist clipboard <id> [on|off]"); }
        }
        "stats" => {
            let (active, total, files, ops) = remoteassist::stats();
            shell_println!("Active: {}, Total sessions: {}", active, total);
            shell_println!("Files transferred: {}, Ops: {}", files, ops);
        }
        "test" => { remoteassist::self_test(); shell_println!("Remote assist self-test complete."); }
        "init" => { remoteassist::init_defaults(); shell_println!("Remote assist initialized."); }
        _ => {
            shell_println!("remoteassist (rassist) — remote assistance");
            shell_println!("  show / list            List sessions");
            shell_println!("  invite [host] [mode]   Create invitation");
            shell_println!("  connect <code> [name]  Join session");
            shell_println!("  grant <id>             Grant control");
            shell_println!("  revoke <id>            Revoke control");
            shell_println!("  pause / resume <id>    Pause/resume");
            shell_println!("  end <id>               End session");
            shell_println!("  clipboard <id> [on|off] Clipboard sharing");
            shell_println!("  stats / test / init");
        }
    }
}

/// `taskmon` / `tmon` — process monitoring and task management.
fn cmd_taskmon(args: &str) {
    use crate::fs::taskmon;
    let parts: Vec<&str> = args.split_whitespace().collect();
    let sub = parts.first().copied().unwrap_or("");
    match sub {
        "" | "show" | "list" => {
            taskmon::init_defaults();
            let tasks = taskmon::list_tasks();
            if tasks.is_empty() {
                shell_println!("No tasks.");
            } else {
                shell_println!("{:<6} {:<16} {:<10} {:<12} {:<8} {:<10} {:<8}", "PID", "Name", "State", "Priority", "CPU%", "Mem(KB)", "Threads");
                for t in &tasks {
                    let cpu_int = t.cpu_percent / 100;
                    let cpu_frac = t.cpu_percent % 100;
                    shell_println!("{:<6} {:<16} {:<10} {:<12} {}.{:02}    {:<10} {:<8}",
                        t.pid, t.name, t.state.label(), t.priority.label(), cpu_int, cpu_frac, t.memory_kb, t.threads);
                }
            }
            let res = taskmon::get_resources();
            shell_println!("\nProcesses: {}, Threads: {}, Memory: {}/{} KB",
                res.process_count, res.thread_count, res.used_memory_kb, res.total_memory_kb);
        }
        "kill" => {
            if let Some(pid_str) = parts.get(1) {
                if let Ok(pid) = pid_str.parse::<u32>() {
                    match taskmon::kill_task(pid) {
                        Ok(()) => shell_println!("Killed task {}", pid),
                        Err(e) => shell_println!("Error: {:?}", e),
                    }
                } else { shell_println!("Invalid PID."); }
            } else { shell_println!("Usage: tmon kill <pid>"); }
        }
        "suspend" | "stop" => {
            if let Some(pid_str) = parts.get(1) {
                if let Ok(pid) = pid_str.parse::<u32>() {
                    match taskmon::suspend_task(pid) {
                        Ok(()) => shell_println!("Suspended task {}", pid),
                        Err(e) => shell_println!("Error: {:?}", e),
                    }
                } else { shell_println!("Invalid PID."); }
            } else { shell_println!("Usage: tmon suspend <pid>"); }
        }
        "resume" => {
            if let Some(pid_str) = parts.get(1) {
                if let Ok(pid) = pid_str.parse::<u32>() {
                    match taskmon::resume_task(pid) {
                        Ok(()) => shell_println!("Resumed task {}", pid),
                        Err(e) => shell_println!("Error: {:?}", e),
                    }
                } else { shell_println!("Invalid PID."); }
            } else { shell_println!("Usage: tmon resume <pid>"); }
        }
        "priority" | "prio" => {
            let pid_str = parts.get(1).copied().unwrap_or("");
            let prio_str = parts.get(2).copied().unwrap_or("");
            if pid_str.is_empty() || prio_str.is_empty() {
                shell_println!("Usage: tmon priority <pid> <realtime|high|normal|below|low|idle>");
            } else if let Ok(pid) = pid_str.parse::<u32>() {
                let prio = match prio_str {
                    "realtime" | "rt" => taskmon::TaskPriority::RealTime,
                    "high" | "h" => taskmon::TaskPriority::High,
                    "normal" | "n" => taskmon::TaskPriority::Normal,
                    "below" | "bn" => taskmon::TaskPriority::BelowNormal,
                    "low" | "l" => taskmon::TaskPriority::Low,
                    "idle" | "i" => taskmon::TaskPriority::Idle,
                    _ => { shell_println!("Unknown priority: {}", prio_str); return; }
                };
                match taskmon::set_priority(pid, prio) {
                    Ok(()) => shell_println!("Set PID {} priority to {}", pid, prio.label()),
                    Err(e) => shell_println!("Error: {:?}", e),
                }
            } else { shell_println!("Invalid PID."); }
        }
        "register" | "add" => {
            let name = parts.get(1).copied().unwrap_or("");
            if name.is_empty() {
                shell_println!("Usage: tmon register <name> [parent_pid]");
            } else {
                let ppid = parts.get(2).and_then(|s| s.parse::<u32>().ok()).unwrap_or(0);
                match taskmon::register_task(name, taskmon::TaskPriority::Normal, ppid, "user") {
                    Ok(pid) => shell_println!("Registered '{}' as PID {}", name, pid),
                    Err(e) => shell_println!("Error: {:?}", e),
                }
            }
        }
        "info" => {
            if let Some(pid_str) = parts.get(1) {
                if let Ok(pid) = pid_str.parse::<u32>() {
                    match taskmon::get_task(pid) {
                        Ok(t) => {
                            shell_println!("PID {}:", t.pid);
                            shell_println!("  Name:     {}", t.name);
                            shell_println!("  State:    {}", t.state.label());
                            shell_println!("  Priority: {}", t.priority.label());
                            shell_println!("  CPU:      {}.{:02}%", t.cpu_percent / 100, t.cpu_percent % 100);
                            shell_println!("  Memory:   {} KB", t.memory_kb);
                            shell_println!("  Threads:  {}", t.threads);
                            shell_println!("  Parent:   {}", t.parent_pid);
                            shell_println!("  User:     {}", t.user);
                        }
                        Err(e) => shell_println!("Error: {:?}", e),
                    }
                } else { shell_println!("Invalid PID."); }
            } else { shell_println!("Usage: tmon info <pid>"); }
        }
        "stats" => {
            let (count, created, killed, suspended, ops) = taskmon::stats();
            shell_println!("Tasks: {}, Created: {}, Killed: {}, Suspended: {}", count, created, killed, suspended);
            shell_println!("Ops: {}", ops);
        }
        "test" => { taskmon::self_test(); shell_println!("Task monitor self-test complete."); }
        "init" => { taskmon::init_defaults(); shell_println!("Task monitor initialized."); }
        _ => {
            shell_println!("taskmon (tmon) — process monitoring");
            shell_println!("  show / list           List processes");
            shell_println!("  info <pid>            Process details");
            shell_println!("  kill <pid>            Kill process");
            shell_println!("  suspend <pid>         Suspend process");
            shell_println!("  resume <pid>          Resume process");
            shell_println!("  priority <pid> <p>    Set priority");
            shell_println!("  register <name>       Register task");
            shell_println!("  stats / test / init");
        }
    }
}

/// `printqueue` / `pqueue` — print job queue management.
fn cmd_printqueue(args: &str) {
    use crate::fs::printqueue;
    let parts: Vec<&str> = args.split_whitespace().collect();
    let sub = parts.first().copied().unwrap_or("");
    match sub {
        "" | "show" | "printers" => {
            printqueue::init_defaults();
            let printers = printqueue::list_printers();
            if printers.is_empty() {
                shell_println!("No printers.");
            } else {
                shell_println!("{:<4} {:<30} {:<8} {:<6}", "ID", "Name", "Paused", "Jobs");
                for (id, name, paused, jobs) in &printers {
                    shell_println!("{:<4} {:<30} {:<8} {:<6}", id, name, paused, jobs);
                }
            }
        }
        "jobs" => {
            if let Some(id_str) = parts.get(1) {
                if let Ok(id) = id_str.parse::<u32>() {
                    match printqueue::get_jobs(id) {
                        Ok(jobs) => {
                            if jobs.is_empty() {
                                shell_println!("No jobs for printer {}.", id);
                            } else {
                                shell_println!("{:<4} {:<20} {:<10} {:<10} {:<6} {:<6}", "ID", "Document", "User", "Status", "Pages", "Copies");
                                for j in &jobs {
                                    shell_println!("{:<4} {:<20} {:<10} {:<10} {:<6} {:<6}",
                                        j.id, j.document_name, j.user, j.status.label(), j.pages, j.copies);
                                }
                            }
                        }
                        Err(e) => shell_println!("Error: {:?}", e),
                    }
                } else { shell_println!("Invalid printer ID."); }
            } else { shell_println!("Usage: pqueue jobs <printer_id>"); }
        }
        "add" | "addprinter" => {
            let name = parts.get(1).copied().unwrap_or("");
            if name.is_empty() {
                shell_println!("Usage: pqueue add <printer_name>");
            } else {
                match printqueue::add_printer(name) {
                    Ok(id) => shell_println!("Added printer '{}' (id={})", name, id),
                    Err(e) => shell_println!("Error: {:?}", e),
                }
            }
        }
        "submit" | "print" => {
            let printer_str = parts.get(1).copied().unwrap_or("");
            let doc = parts.get(2).copied().unwrap_or("document.pdf");
            let pages_str = parts.get(3).copied().unwrap_or("1");
            if printer_str.is_empty() {
                shell_println!("Usage: pqueue submit <printer_id> [document] [pages]");
            } else if let Ok(pid) = printer_str.parse::<u32>() {
                let pages = pages_str.parse::<u32>().unwrap_or(1);
                match printqueue::submit_job(pid, doc, "user", pages, 1, printqueue::PageSize::A4, false, false, 1024) {
                    Ok(jid) => shell_println!("Submitted job {} to printer {}", jid, pid),
                    Err(e) => shell_println!("Error: {:?}", e),
                }
            } else { shell_println!("Invalid printer ID."); }
        }
        "cancel" => {
            let printer_str = parts.get(1).copied().unwrap_or("");
            let job_str = parts.get(2).copied().unwrap_or("");
            if printer_str.is_empty() || job_str.is_empty() {
                shell_println!("Usage: pqueue cancel <printer_id> <job_id>");
            } else if let (Ok(pid), Ok(jid)) = (printer_str.parse::<u32>(), job_str.parse::<u32>()) {
                match printqueue::cancel_job(pid, jid) {
                    Ok(()) => shell_println!("Cancelled job {}", jid),
                    Err(e) => shell_println!("Error: {:?}", e),
                }
            } else { shell_println!("Invalid ID(s)."); }
        }
        "complete" => {
            let printer_str = parts.get(1).copied().unwrap_or("");
            let job_str = parts.get(2).copied().unwrap_or("");
            if printer_str.is_empty() || job_str.is_empty() {
                shell_println!("Usage: pqueue complete <printer_id> <job_id>");
            } else if let (Ok(pid), Ok(jid)) = (printer_str.parse::<u32>(), job_str.parse::<u32>()) {
                match printqueue::complete_job(pid, jid) {
                    Ok(()) => shell_println!("Completed job {}", jid),
                    Err(e) => shell_println!("Error: {:?}", e),
                }
            } else { shell_println!("Invalid ID(s)."); }
        }
        "pause" => {
            if let Some(id_str) = parts.get(1) {
                if let Ok(id) = id_str.parse::<u32>() {
                    match printqueue::pause_printer(id) {
                        Ok(()) => shell_println!("Paused printer {}", id),
                        Err(e) => shell_println!("Error: {:?}", e),
                    }
                } else { shell_println!("Invalid ID."); }
            } else { shell_println!("Usage: pqueue pause <printer_id>"); }
        }
        "resume" => {
            if let Some(id_str) = parts.get(1) {
                if let Ok(id) = id_str.parse::<u32>() {
                    match printqueue::resume_printer(id) {
                        Ok(()) => shell_println!("Resumed printer {}", id),
                        Err(e) => shell_println!("Error: {:?}", e),
                    }
                } else { shell_println!("Invalid ID."); }
            } else { shell_println!("Usage: pqueue resume <printer_id>"); }
        }
        "clear" => {
            if let Some(id_str) = parts.get(1) {
                if let Ok(id) = id_str.parse::<u32>() {
                    match printqueue::clear_completed(id) {
                        Ok(n) => shell_println!("Cleared {} completed jobs.", n),
                        Err(e) => shell_println!("Error: {:?}", e),
                    }
                } else { shell_println!("Invalid ID."); }
            } else { shell_println!("Usage: pqueue clear <printer_id>"); }
        }
        "stats" => {
            let (printers, jobs, pages, active, ops) = printqueue::stats();
            shell_println!("Printers: {}, Total jobs: {}, Total pages: {}", printers, jobs, pages);
            shell_println!("Active jobs: {}, Ops: {}", active, ops);
        }
        "test" => { printqueue::self_test(); shell_println!("Print queue self-test complete."); }
        "init" => { printqueue::init_defaults(); shell_println!("Print queue initialized."); }
        _ => {
            shell_println!("printqueue (pqueue) — print job queue");
            shell_println!("  show / printers              List printers");
            shell_println!("  jobs <printer_id>            List jobs");
            shell_println!("  add <name>                   Add printer");
            shell_println!("  submit <pid> [doc] [pages]   Submit job");
            shell_println!("  cancel <pid> <jid>           Cancel job");
            shell_println!("  complete <pid> <jid>         Complete job");
            shell_println!("  pause / resume <pid>         Pause/resume");
            shell_println!("  clear <pid>                  Clear done jobs");
            shell_println!("  stats / test / init");
        }
    }
}

/// `servicemgr` / `svcmgr` — system service management.
fn cmd_servicemgr(args: &str) {
    use crate::fs::servicemgr;
    let parts: Vec<&str> = args.split_whitespace().collect();
    let sub = parts.first().copied().unwrap_or("");
    match sub {
        "" | "show" | "list" => {
            servicemgr::init_defaults();
            let services = servicemgr::list_services();
            if services.is_empty() {
                shell_println!("No services registered.");
            } else {
                shell_println!("{:<4} {:<16} {:<20} {:<10} {:<16}", "ID", "Name", "Display Name", "State", "Startup");
                for s in &services {
                    shell_println!("{:<4} {:<16} {:<20} {:<10} {:<16}",
                        s.id, s.name, s.display_name, s.state.label(), s.startup_type.label());
                }
            }
        }
        "running" => {
            let running = servicemgr::list_running();
            if running.is_empty() {
                shell_println!("No running services.");
            } else {
                for s in &running {
                    shell_println!("  [{}] {} ({})", s.id, s.name, s.display_name);
                }
            }
        }
        "start" => {
            if let Some(id_str) = parts.get(1) {
                if let Ok(id) = id_str.parse::<u32>() {
                    match servicemgr::start_service(id) {
                        Ok(()) => shell_println!("Started service {}", id),
                        Err(e) => shell_println!("Error: {:?}", e),
                    }
                } else { shell_println!("Invalid ID."); }
            } else { shell_println!("Usage: svcmgr start <id>"); }
        }
        "stop" => {
            if let Some(id_str) = parts.get(1) {
                if let Ok(id) = id_str.parse::<u32>() {
                    match servicemgr::stop_service(id) {
                        Ok(()) => shell_println!("Stopped service {}", id),
                        Err(e) => shell_println!("Error: {:?}", e),
                    }
                } else { shell_println!("Invalid ID."); }
            } else { shell_println!("Usage: svcmgr stop <id>"); }
        }
        "restart" => {
            if let Some(id_str) = parts.get(1) {
                if let Ok(id) = id_str.parse::<u32>() {
                    match servicemgr::restart_service(id) {
                        Ok(()) => shell_println!("Restarted service {}", id),
                        Err(e) => shell_println!("Error: {:?}", e),
                    }
                } else { shell_println!("Invalid ID."); }
            } else { shell_println!("Usage: svcmgr restart <id>"); }
        }
        "startup" => {
            let id_str = parts.get(1).copied().unwrap_or("");
            let type_str = parts.get(2).copied().unwrap_or("");
            if id_str.is_empty() || type_str.is_empty() {
                shell_println!("Usage: svcmgr startup <id> <auto|manual|disabled|delayed>");
            } else if let Ok(id) = id_str.parse::<u32>() {
                let st = match type_str {
                    "auto" | "automatic" => servicemgr::StartupType::Automatic,
                    "manual" => servicemgr::StartupType::Manual,
                    "disabled" | "off" => servicemgr::StartupType::Disabled,
                    "delayed" => servicemgr::StartupType::DelayedAutomatic,
                    _ => { shell_println!("Unknown type: {}", type_str); return; }
                };
                match servicemgr::set_startup_type(id, st) {
                    Ok(()) => shell_println!("Set startup type to {}", st.label()),
                    Err(e) => shell_println!("Error: {:?}", e),
                }
            } else { shell_println!("Invalid ID."); }
        }
        "register" | "add" => {
            let name = parts.get(1).copied().unwrap_or("");
            let display = parts.get(2).copied().unwrap_or(name);
            if name.is_empty() {
                shell_println!("Usage: svcmgr register <name> [display_name]");
            } else {
                match servicemgr::register_service(name, display, "", servicemgr::StartupType::Manual) {
                    Ok(id) => shell_println!("Registered service '{}' (id={})", name, id),
                    Err(e) => shell_println!("Error: {:?}", e),
                }
            }
        }
        "info" => {
            if let Some(id_str) = parts.get(1) {
                if let Ok(id) = id_str.parse::<u32>() {
                    match servicemgr::get_service(id) {
                        Ok(s) => {
                            shell_println!("Service #{}", s.id);
                            shell_println!("  Name:        {}", s.name);
                            shell_println!("  Display:     {}", s.display_name);
                            shell_println!("  Description: {}", if s.description.is_empty() { "(none)" } else { &s.description });
                            shell_println!("  State:       {}", s.state.label());
                            shell_println!("  Startup:     {}", s.startup_type.label());
                            shell_println!("  PID:         {}", s.pid);
                            shell_println!("  Restarts:    {}", s.restart_count);
                            shell_println!("  Auto-restart: {}", s.auto_restart);
                            if !s.depends_on.is_empty() {
                                shell_println!("  Depends on: {:?}", s.depends_on);
                            }
                        }
                        Err(e) => shell_println!("Error: {:?}", e),
                    }
                } else { shell_println!("Invalid ID."); }
            } else { shell_println!("Usage: svcmgr info <id>"); }
        }
        "find" => {
            if let Some(name) = parts.get(1) {
                match servicemgr::find_by_name(name) {
                    Ok(s) => shell_println!("[{}] {} — {} ({})", s.id, s.name, s.state.label(), s.startup_type.label()),
                    Err(e) => shell_println!("Error: {:?}", e),
                }
            } else { shell_println!("Usage: svcmgr find <name>"); }
        }
        "stats" => {
            let (total, running, starts, stops, failures, ops) = servicemgr::stats();
            shell_println!("Services: {}, Running: {}", total, running);
            shell_println!("Starts: {}, Stops: {}, Failures: {}, Ops: {}", starts, stops, failures, ops);
        }
        "test" => {
            match servicemgr::self_test() {
                Ok(()) => shell_println!("Service manager self-test complete."),
                Err(e) => shell_println!("Service manager self-test FAILED: {:?}", e),
            }
        }
        "init" => { servicemgr::init_defaults(); shell_println!("Service manager initialized."); }
        _ => {
            shell_println!("servicemgr (svcmgr) — system service management");
            shell_println!("  show / list            List services");
            shell_println!("  running                Running services");
            shell_println!("  info <id>              Service details");
            shell_println!("  find <name>            Find by name");
            shell_println!("  start / stop <id>      Start/stop");
            shell_println!("  restart <id>           Restart service");
            shell_println!("  startup <id> <type>    Set startup type");
            shell_println!("  register <name>        Register service");
            shell_println!("  stats / test / init");
        }
    }
}

/// `hwmonitor` / `hwmon` — hardware monitoring.
fn cmd_hwmonitor(args: &str) {
    use crate::fs::hwmonitor;
    use alloc::format;
    let parts: Vec<&str> = args.split_whitespace().collect();
    let sub = parts.first().copied().unwrap_or("");
    match sub {
        "" | "show" | "sensors" => {
            hwmonitor::init_defaults();
            let sensors = hwmonitor::list_sensors();
            if sensors.is_empty() {
                shell_println!("No sensors.");
            } else {
                shell_println!("{:<4} {:<20} {:<12} {:<10} {:<8}", "ID", "Name", "Type", "Value", "Status");
                for s in &sensors {
                    let val_str = match s.sensor_type {
                        hwmonitor::SensorType::Temperature => format!("{}.{} °C", s.value / 1000, (s.value % 1000) / 100),
                        hwmonitor::SensorType::Voltage => format!("{}.{:03} V", s.value / 1000, s.value % 1000),
                        hwmonitor::SensorType::Power => format!("{}.{} W", s.value / 1000, (s.value % 1000) / 100),
                        _ => format!("{} {}", s.value, s.sensor_type.unit()),
                    };
                    shell_println!("{:<4} {:<20} {:<12} {:<10} {:<8}",
                        s.id, s.name, s.sensor_type.label(), val_str, s.status.label());
                }
            }
        }
        "components" | "comp" => {
            let comps = hwmonitor::list_components();
            if comps.is_empty() {
                shell_println!("No components.");
            } else {
                for c in &comps {
                    shell_println!("[{}] {} ({}) — {} sensor(s)", c.id, c.name, c.component_type, c.sensors.len());
                }
            }
        }
        "alerts" => {
            let limit = parts.get(1).and_then(|s| s.parse::<usize>().ok()).unwrap_or(20);
            let alerts = hwmonitor::get_alerts(limit);
            if alerts.is_empty() {
                shell_println!("No alerts.");
            } else {
                for a in &alerts {
                    let level = if a.is_critical { "CRITICAL" } else { "WARNING" };
                    shell_println!("  [{}] {} — value={}, threshold={}", level, a.sensor_name, a.value, a.threshold);
                }
            }
        }
        "clearalerts" => {
            let n = hwmonitor::clear_alerts();
            shell_println!("Cleared {} alert(s).", n);
        }
        "update" => {
            let id_str = parts.get(1).copied().unwrap_or("");
            let val_str = parts.get(2).copied().unwrap_or("");
            if id_str.is_empty() || val_str.is_empty() {
                shell_println!("Usage: hwmon update <sensor_id> <value>");
            } else if let (Ok(id), Ok(val)) = (id_str.parse::<u32>(), val_str.parse::<i64>()) {
                match hwmonitor::update_sensor(id, val) {
                    Ok(Some(true)) => shell_println!("CRITICAL: Sensor {} value {} exceeds critical threshold!", id, val),
                    Ok(Some(false)) => shell_println!("WARNING: Sensor {} value {} exceeds warning threshold.", id, val),
                    Ok(None) => shell_println!("Sensor {} updated to {}. Status: Normal.", id, val),
                    Err(e) => shell_println!("Error: {:?}", e),
                }
            } else { shell_println!("Invalid arguments."); }
        }
        "info" => {
            if let Some(id_str) = parts.get(1) {
                if let Ok(id) = id_str.parse::<u32>() {
                    match hwmonitor::get_sensor(id) {
                        Ok(s) => {
                            shell_println!("Sensor #{}", s.id);
                            shell_println!("  Name:     {}", s.name);
                            shell_println!("  Type:     {}", s.sensor_type.label());
                            shell_println!("  Value:    {} {}", s.value, s.sensor_type.unit());
                            shell_println!("  Min:      {} {}", s.min_value, s.sensor_type.unit());
                            shell_println!("  Max:      {} {}", s.max_value, s.sensor_type.unit());
                            shell_println!("  Warning:  {}", s.warning_threshold);
                            shell_println!("  Critical: {}", s.critical_threshold);
                            shell_println!("  Status:   {}", s.status.label());
                        }
                        Err(e) => shell_println!("Error: {:?}", e),
                    }
                } else { shell_println!("Invalid ID."); }
            } else { shell_println!("Usage: hwmon info <sensor_id>"); }
        }
        "stats" => {
            let (sensors, components, readings, alerts, ops) = hwmonitor::stats();
            shell_println!("Sensors: {}, Components: {}", sensors, components);
            shell_println!("Readings: {}, Alerts: {}, Ops: {}", readings, alerts, ops);
        }
        "test" => { hwmonitor::self_test(); shell_println!("Hardware monitor self-test complete."); }
        "init" => { hwmonitor::init_defaults(); shell_println!("Hardware monitor initialized."); }
        _ => {
            shell_println!("hwmonitor (hwmon) — hardware monitoring");
            shell_println!("  show / sensors         List sensors");
            shell_println!("  components             List components");
            shell_println!("  info <id>              Sensor details");
            shell_println!("  update <id> <value>    Update sensor");
            shell_println!("  alerts [limit]         Show alerts");
            shell_println!("  clearalerts            Clear alerts");
            shell_println!("  stats / test / init");
        }
    }
}

/// `appsandbox` / `sandbox` — application sandboxing.
fn cmd_appsandbox(args: &str) {
    use crate::fs::appsandbox;
    let parts: Vec<&str> = args.split_whitespace().collect();
    let sub = parts.first().copied().unwrap_or("");
    match sub {
        "" | "show" | "list" => {
            appsandbox::init_defaults();
            let sandboxes = appsandbox::list_sandboxes();
            if sandboxes.is_empty() {
                shell_println!("No sandboxes.");
            } else {
                shell_println!("{:<4} {:<20} {:<12} {:<8} {:<8} {:<8}", "ID", "App", "Trust", "Active", "Checks", "Denied");
                for s in &sandboxes {
                    shell_println!("{:<4} {:<20} {:<12} {:<8} {:<8} {:<8}",
                        s.id, s.app_name, s.trust_level.label(), s.active, s.access_attempts, s.access_denied);
                }
            }
        }
        "create" | "add" => {
            let name = parts.get(1).copied().unwrap_or("");
            let trust_str = parts.get(2).copied().unwrap_or("standard");
            if name.is_empty() {
                shell_println!("Usage: sandbox create <app_name> [untrusted|low|standard|elevated|system]");
            } else {
                let trust = match trust_str {
                    "untrusted" | "u" => appsandbox::TrustLevel::Untrusted,
                    "low" | "l" => appsandbox::TrustLevel::LowTrust,
                    "elevated" | "e" => appsandbox::TrustLevel::Elevated,
                    "system" | "s" => appsandbox::TrustLevel::System,
                    _ => appsandbox::TrustLevel::Standard,
                };
                match appsandbox::create_sandbox(name, trust) {
                    Ok(id) => shell_println!("Created sandbox '{}' (id={}, trust={})", name, id, trust.label()),
                    Err(e) => shell_println!("Error: {:?}", e),
                }
            }
        }
        "check" => {
            let id_str = parts.get(1).copied().unwrap_or("");
            let perm_str = parts.get(2).copied().unwrap_or("file_read");
            if let Ok(id) = id_str.parse::<u32>() {
                let perm = match perm_str {
                    "read" | "file_read" => appsandbox::Permission::FileRead,
                    "write" | "file_write" => appsandbox::Permission::FileWrite,
                    "network" | "net" => appsandbox::Permission::NetworkAccess,
                    "camera" => appsandbox::Permission::Camera,
                    "mic" | "microphone" => appsandbox::Permission::Microphone,
                    "location" | "loc" => appsandbox::Permission::Location,
                    "clipboard" | "clip" => appsandbox::Permission::Clipboard,
                    _ => appsandbox::Permission::FileRead,
                };
                match appsandbox::check_access(id, perm) {
                    Ok(d) => shell_println!("Access {}: {}", perm.label(), d.label()),
                    Err(e) => shell_println!("Error: {:?}", e),
                }
            } else { shell_println!("Usage: sandbox check <id> <permission>"); }
        }
        "grant" => {
            let id_str = parts.get(1).copied().unwrap_or("");
            let perm_str = parts.get(2).copied().unwrap_or("");
            if let Ok(id) = id_str.parse::<u32>() {
                let perm = match perm_str {
                    "read" | "file_read" => appsandbox::Permission::FileRead,
                    "write" | "file_write" => appsandbox::Permission::FileWrite,
                    "network" | "net" => appsandbox::Permission::NetworkAccess,
                    "camera" => appsandbox::Permission::Camera,
                    _ => { shell_println!("Unknown permission."); return; }
                };
                match appsandbox::grant_permission(id, perm, "") {
                    Ok(()) => shell_println!("Granted {} to sandbox {}", perm.label(), id),
                    Err(e) => shell_println!("Error: {:?}", e),
                }
            } else { shell_println!("Usage: sandbox grant <id> <permission>"); }
        }
        "revoke" => {
            let id_str = parts.get(1).copied().unwrap_or("");
            let perm_str = parts.get(2).copied().unwrap_or("");
            if let Ok(id) = id_str.parse::<u32>() {
                let perm = match perm_str {
                    "read" | "file_read" => appsandbox::Permission::FileRead,
                    "write" | "file_write" => appsandbox::Permission::FileWrite,
                    "network" | "net" => appsandbox::Permission::NetworkAccess,
                    _ => { shell_println!("Unknown permission."); return; }
                };
                match appsandbox::revoke_permission(id, perm) {
                    Ok(()) => shell_println!("Revoked {} from sandbox {}", perm.label(), id),
                    Err(e) => shell_println!("Error: {:?}", e),
                }
            } else { shell_println!("Usage: sandbox revoke <id> <permission>"); }
        }
        "remove" | "delete" => {
            if let Some(id_str) = parts.get(1) {
                if let Ok(id) = id_str.parse::<u32>() {
                    match appsandbox::remove_sandbox(id) {
                        Ok(()) => shell_println!("Removed sandbox {}", id),
                        Err(e) => shell_println!("Error: {:?}", e),
                    }
                } else { shell_println!("Invalid ID."); }
            } else { shell_println!("Usage: sandbox remove <id>"); }
        }
        "stats" => {
            let (count, created, checks, denied, ops) = appsandbox::stats();
            shell_println!("Sandboxes: {}, Created: {}", count, created);
            shell_println!("Checks: {}, Denied: {}, Ops: {}", checks, denied, ops);
        }
        "test" => { appsandbox::self_test(); shell_println!("App sandbox self-test complete."); }
        "init" => { appsandbox::init_defaults(); shell_println!("App sandbox initialized."); }
        _ => {
            shell_println!("appsandbox (sandbox) — app sandboxing");
            shell_println!("  show / list            List sandboxes");
            shell_println!("  create <app> [trust]   Create sandbox");
            shell_println!("  check <id> <perm>      Check access");
            shell_println!("  grant <id> <perm>      Grant permission");
            shell_println!("  revoke <id> <perm>     Revoke permission");
            shell_println!("  remove <id>            Remove sandbox");
            shell_println!("  stats / test / init");
        }
    }
}

/// `gamepadinput` / `gamepad` — game controller input.
fn cmd_gamepadinput(args: &str) {
    use crate::fs::gamepadinput;
    use alloc::format;
    let parts: Vec<&str> = args.split_whitespace().collect();
    let sub = parts.first().copied().unwrap_or("");
    match sub {
        "" | "show" | "list" => {
            gamepadinput::init_defaults();
            let pads = gamepadinput::list_gamepads();
            if pads.is_empty() {
                shell_println!("No gamepads connected.");
            } else {
                shell_println!("{:<4} {:<20} {:<12} {:<10} {:<6} {:<8}", "ID", "Name", "Type", "Conn", "Batt%", "Player");
                for g in &pads {
                    let batt = if g.battery_percent == 255 { "N/A".into() } else { format!("{}%", g.battery_percent) };
                    shell_println!("{:<4} {:<20} {:<12} {:<10} {:<6} {:<8}",
                        g.id, g.name, g.gamepad_type.label(), g.connection.label(),
                        batt, if g.player_number > 0 { format!("P{}", g.player_number) } else { "-".into() });
                }
            }
        }
        "add" | "register" => {
            let name = parts.get(1).copied().unwrap_or("");
            let type_str = parts.get(2).copied().unwrap_or("generic");
            if name.is_empty() {
                shell_println!("Usage: gamepad add <name> [xbox|ps|switch|generic|stick|wheel]");
            } else {
                let gtype = match type_str {
                    "xbox" | "xb" => gamepadinput::GamepadType::Xbox,
                    "ps" | "playstation" => gamepadinput::GamepadType::PlayStation,
                    "switch" | "ns" => gamepadinput::GamepadType::NintendoSwitch,
                    "stick" | "flight" => gamepadinput::GamepadType::FlightStick,
                    "wheel" | "racing" => gamepadinput::GamepadType::RacingWheel,
                    _ => gamepadinput::GamepadType::Generic,
                };
                match gamepadinput::register_gamepad(name, gtype, gamepadinput::ConnectionType::Usb, 255) {
                    Ok(id) => shell_println!("Registered '{}' as gamepad {} ({})", name, id, gtype.label()),
                    Err(e) => shell_println!("Error: {:?}", e),
                }
            }
        }
        "remove" => {
            if let Some(id_str) = parts.get(1) {
                if let Ok(id) = id_str.parse::<u32>() {
                    match gamepadinput::remove_gamepad(id) {
                        Ok(()) => shell_println!("Removed gamepad {}", id),
                        Err(e) => shell_println!("Error: {:?}", e),
                    }
                } else { shell_println!("Invalid ID."); }
            } else { shell_println!("Usage: gamepad remove <id>"); }
        }
        "deadzone" | "dz" => {
            let id_str = parts.get(1).copied().unwrap_or("");
            let val_str = parts.get(2).copied().unwrap_or("");
            if let (Ok(id), Ok(val)) = (id_str.parse::<u32>(), val_str.parse::<i32>()) {
                match gamepadinput::set_dead_zone(id, val) {
                    Ok(()) => shell_println!("Dead zone set to {} for gamepad {}", val, id),
                    Err(e) => shell_println!("Error: {:?}", e),
                }
            } else { shell_println!("Usage: gamepad deadzone <id> <value>"); }
        }
        "rumble" => {
            let id_str = parts.get(1).copied().unwrap_or("");
            let val_str = parts.get(2).copied().unwrap_or("5000");
            if let (Ok(id), Ok(val)) = (id_str.parse::<u32>(), val_str.parse::<u32>()) {
                match gamepadinput::set_rumble(id, val) {
                    Ok(()) => shell_println!("Rumble set to {} for gamepad {}", val, id),
                    Err(e) => shell_println!("Error: {:?}", e),
                }
            } else { shell_println!("Usage: gamepad rumble <id> [intensity]"); }
        }
        "info" => {
            if let Some(id_str) = parts.get(1) {
                if let Ok(id) = id_str.parse::<u32>() {
                    match gamepadinput::get_gamepad(id) {
                        Ok(g) => {
                            shell_println!("Gamepad #{}", g.id);
                            shell_println!("  Name:       {}", g.name);
                            shell_println!("  Type:       {}", g.gamepad_type.label());
                            shell_println!("  Connection: {}", g.connection.label());
                            shell_println!("  Battery:    {}", if g.battery_percent == 255 { "N/A".into() } else { format!("{}%", g.battery_percent) });
                            shell_println!("  Player:     {}", g.player_number);
                            shell_println!("  Dead zone:  {}", g.dead_zone);
                            shell_println!("  Rumble:     {}", g.rumble_intensity);
                            shell_println!("  Connected:  {}", g.connected);
                            shell_println!("  Presses:    {}", g.total_presses);
                        }
                        Err(e) => shell_println!("Error: {:?}", e),
                    }
                } else { shell_println!("Invalid ID."); }
            } else { shell_println!("Usage: gamepad info <id>"); }
        }
        "stats" => {
            let (count, connected, total_conn, total_inp, ops) = gamepadinput::stats();
            shell_println!("Gamepads: {}, Connected: {}", count, connected);
            shell_println!("Total connected: {}, Inputs: {}, Ops: {}", total_conn, total_inp, ops);
        }
        "test" => { gamepadinput::self_test(); shell_println!("Gamepad input self-test complete."); }
        "init" => { gamepadinput::init_defaults(); shell_println!("Gamepad input initialized."); }
        _ => {
            shell_println!("gamepadinput (gamepad) — controller input");
            shell_println!("  show / list          List gamepads");
            shell_println!("  info <id>            Gamepad details");
            shell_println!("  add <name> [type]    Register gamepad");
            shell_println!("  remove <id>          Remove gamepad");
            shell_println!("  deadzone <id> <val>  Set dead zone");
            shell_println!("  rumble <id> [val]    Set rumble");
            shell_println!("  stats / test / init");
        }
    }
}

/// `sysrestore` / `srestore` — system snapshot management.
fn cmd_sysrestore(args: &str) {
    use crate::fs::sysrestore;
    let parts: Vec<&str> = args.split_whitespace().collect();
    let sub = parts.first().copied().unwrap_or("");
    match sub {
        "" | "show" | "list" => {
            sysrestore::init_defaults();
            let snaps = sysrestore::list_snapshots();
            if snaps.is_empty() {
                shell_println!("No snapshots.");
            } else {
                shell_println!("{:<4} {:<20} {:<12} {:<10} {:<12} {:<6}", "ID", "Description", "Type", "State", "Size(MB)", "Pin");
                for s in &snaps {
                    let size_mb = s.size_bytes / (1024 * 1024);
                    shell_println!("{:<4} {:<20} {:<12} {:<10} {:<12} {:<6}",
                        s.id, s.description, s.snapshot_type.label(), s.state.label(), size_mb, if s.pinned { "yes" } else { "no" });
                }
                let total = sysrestore::total_size();
                shell_println!("\nTotal size: {} MB", total / (1024 * 1024));
            }
        }
        "create" | "snap" => {
            let desc = parts.get(1).copied().unwrap_or("Manual snapshot");
            let type_str = parts.get(2).copied().unwrap_or("manual");
            let stype = match type_str {
                "update" => sysrestore::SnapshotType::PreUpdate,
                "driver" => sysrestore::SnapshotType::PreDriverInstall,
                "config" => sysrestore::SnapshotType::PreConfigChange,
                "scheduled" => sysrestore::SnapshotType::Scheduled,
                "emergency" => sysrestore::SnapshotType::Emergency,
                _ => sysrestore::SnapshotType::Manual,
            };
            match sysrestore::create_snapshot(desc, stype, 100_000_000, 500) {
                Ok(id) => shell_println!("Created snapshot {} ({})", id, desc),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "restore" => {
            if let Some(id_str) = parts.get(1) {
                if let Ok(id) = id_str.parse::<u32>() {
                    match sysrestore::restore_snapshot(id) {
                        Ok(()) => shell_println!("Restored from snapshot {}", id),
                        Err(e) => shell_println!("Error: {:?}", e),
                    }
                } else { shell_println!("Invalid ID."); }
            } else { shell_println!("Usage: srestore restore <id>"); }
        }
        "pin" => {
            if let Some(id_str) = parts.get(1) {
                if let Ok(id) = id_str.parse::<u32>() {
                    match sysrestore::pin_snapshot(id) {
                        Ok(()) => shell_println!("Pinned snapshot {}", id),
                        Err(e) => shell_println!("Error: {:?}", e),
                    }
                } else { shell_println!("Invalid ID."); }
            } else { shell_println!("Usage: srestore pin <id>"); }
        }
        "unpin" => {
            if let Some(id_str) = parts.get(1) {
                if let Ok(id) = id_str.parse::<u32>() {
                    match sysrestore::unpin_snapshot(id) {
                        Ok(()) => shell_println!("Unpinned snapshot {}", id),
                        Err(e) => shell_println!("Error: {:?}", e),
                    }
                } else { shell_println!("Invalid ID."); }
            } else { shell_println!("Usage: srestore unpin <id>"); }
        }
        "delete" | "rm" => {
            if let Some(id_str) = parts.get(1) {
                if let Ok(id) = id_str.parse::<u32>() {
                    match sysrestore::delete_snapshot(id) {
                        Ok(()) => shell_println!("Deleted snapshot {}", id),
                        Err(e) => shell_println!("Error: {:?}", e),
                    }
                } else { shell_println!("Invalid ID."); }
            } else { shell_println!("Usage: srestore delete <id>"); }
        }
        "rotate" => {
            match sysrestore::run_rotation() {
                Ok(n) => shell_println!("Rotation removed {} snapshot(s).", n),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "policy" => {
            let policy = sysrestore::get_rotation_policy();
            shell_println!("Rotation policy:");
            shell_println!("  Max snapshots: {}", policy.max_snapshots);
            shell_println!("  Max size: {} MB", policy.max_total_bytes / (1024 * 1024));
            shell_println!("  Max age: {} days", policy.max_age_secs / 86400);
            shell_println!("  Keep minimum: {}", policy.keep_minimum);
        }
        "stats" => {
            let (count, created, restored, rotated, ops) = sysrestore::stats();
            shell_println!("Snapshots: {}, Created: {}, Restored: {}", count, created, restored);
            shell_println!("Rotated: {}, Ops: {}", rotated, ops);
        }
        "test" => { sysrestore::self_test(); shell_println!("System restore self-test complete."); }
        "init" => { sysrestore::init_defaults(); shell_println!("System restore initialized."); }
        _ => {
            shell_println!("sysrestore (srestore) — system snapshots");
            shell_println!("  show / list           List snapshots");
            shell_println!("  create [desc] [type]  Create snapshot");
            shell_println!("  restore <id>          Restore snapshot");
            shell_println!("  pin / unpin <id>      Pin/unpin");
            shell_println!("  delete <id>           Delete snapshot");
            shell_println!("  rotate                Run rotation");
            shell_println!("  policy                Show policy");
            shell_println!("  stats / test / init");
        }
    }
}

/// `audiomux` / `amux` — per-app audio routing.
fn cmd_audiomux(args: &str) {
    use crate::fs::audiomux;
    let parts: Vec<&str> = args.split_whitespace().collect();
    let sub = parts.first().copied().unwrap_or("");
    match sub {
        "" | "show" | "outputs" => {
            audiomux::init_defaults();
            let outputs = audiomux::list_outputs();
            if outputs.is_empty() {
                shell_println!("No audio outputs.");
            } else {
                shell_println!("{:<4} {:<24} {:<12} {:<6} {:<6} {:<8}", "ID", "Name", "Type", "Vol", "Mute", "Default");
                for o in &outputs {
                    shell_println!("{:<4} {:<24} {:<12} {:<6} {:<6} {:<8}",
                        o.id, o.name, o.endpoint.label(), o.volume, o.muted, if o.is_default { "*" } else { "" });
                }
            }
        }
        "streams" => {
            let streams = audiomux::list_streams();
            if streams.is_empty() {
                shell_println!("No active streams.");
            } else {
                shell_println!("{:<4} {:<20} {:<6} {:<8} {:<6} {:<6}", "ID", "App", "PID", "State", "Vol", "Out");
                for s in &streams {
                    shell_println!("{:<4} {:<20} {:<6} {:<8} {:<6} {:<6}",
                        s.id, s.app_name, s.app_pid, s.state.label(), s.volume, s.output_id);
                }
            }
        }
        "stream" | "play" => {
            let app = parts.get(1).copied().unwrap_or("");
            let pid_str = parts.get(2).copied().unwrap_or("0");
            if app.is_empty() {
                shell_println!("Usage: amux stream <app_name> [pid] [output_id]");
            } else {
                let pid = pid_str.parse::<u32>().unwrap_or(0);
                let out = parts.get(3).and_then(|s| s.parse::<u32>().ok());
                match audiomux::create_stream(app, pid, out) {
                    Ok(id) => shell_println!("Created stream {} for '{}'", id, app),
                    Err(e) => shell_println!("Error: {:?}", e),
                }
            }
        }
        "volume" | "vol" => {
            let id_str = parts.get(1).copied().unwrap_or("");
            let vol_str = parts.get(2).copied().unwrap_or("");
            if let (Ok(id), Ok(vol)) = (id_str.parse::<u32>(), vol_str.parse::<u32>()) {
                match audiomux::set_stream_volume(id, vol) {
                    Ok(()) => shell_println!("Stream {} volume set to {}", id, vol),
                    Err(e) => shell_println!("Error: {:?}", e),
                }
            } else { shell_println!("Usage: amux volume <stream_id> <0-100>"); }
        }
        "mute" => {
            if let Some(id_str) = parts.get(1) {
                if let Ok(id) = id_str.parse::<u32>() {
                    match audiomux::set_stream_muted(id, true) {
                        Ok(()) => shell_println!("Muted stream {}", id),
                        Err(e) => shell_println!("Error: {:?}", e),
                    }
                } else { shell_println!("Invalid ID."); }
            } else { shell_println!("Usage: amux mute <stream_id>"); }
        }
        "unmute" => {
            if let Some(id_str) = parts.get(1) {
                if let Ok(id) = id_str.parse::<u32>() {
                    match audiomux::set_stream_muted(id, false) {
                        Ok(()) => shell_println!("Unmuted stream {}", id),
                        Err(e) => shell_println!("Error: {:?}", e),
                    }
                } else { shell_println!("Invalid ID."); }
            } else { shell_println!("Usage: amux unmute <stream_id>"); }
        }
        "reroute" | "route" => {
            let stream_str = parts.get(1).copied().unwrap_or("");
            let out_str = parts.get(2).copied().unwrap_or("");
            if let (Ok(sid), Ok(oid)) = (stream_str.parse::<u32>(), out_str.parse::<u32>()) {
                match audiomux::reroute_stream(sid, oid) {
                    Ok(()) => shell_println!("Rerouted stream {} to output {}", sid, oid),
                    Err(e) => shell_println!("Error: {:?}", e),
                }
            } else { shell_println!("Usage: amux reroute <stream_id> <output_id>"); }
        }
        "default" => {
            if let Some(id_str) = parts.get(1) {
                if let Ok(id) = id_str.parse::<u32>() {
                    match audiomux::set_default_output(id) {
                        Ok(()) => shell_println!("Default output set to {}", id),
                        Err(e) => shell_println!("Error: {:?}", e),
                    }
                } else { shell_println!("Invalid ID."); }
            } else { shell_println!("Usage: amux default <output_id>"); }
        }
        "stats" => {
            let (outs, streams, created, reroutes, ops) = audiomux::stats();
            shell_println!("Outputs: {}, Streams: {}", outs, streams);
            shell_println!("Total created: {}, Reroutes: {}, Ops: {}", created, reroutes, ops);
        }
        "test" => { audiomux::self_test(); shell_println!("Audio mux self-test complete."); }
        "init" => { audiomux::init_defaults(); shell_println!("Audio mux initialized."); }
        _ => {
            shell_println!("audiomux (amux) — per-app audio routing");
            shell_println!("  show / outputs         List outputs");
            shell_println!("  streams                Active streams");
            shell_println!("  stream <app> [pid]     Create stream");
            shell_println!("  volume <id> <vol>      Set volume");
            shell_println!("  mute / unmute <id>     Mute/unmute");
            shell_println!("  reroute <sid> <oid>    Route to output");
            shell_println!("  default <oid>          Set default output");
            shell_println!("  stats / test / init");
        }
    }
}

/// `netthrottle` / `nthrottle` — network bandwidth throttling.
fn cmd_netthrottle(args: &str) {
    use crate::fs::netthrottle;
    let parts: Vec<&str> = args.split_whitespace().collect();
    let sub = parts.first().copied().unwrap_or("");
    match sub {
        "" | "show" | "list" => {
            netthrottle::init_defaults();
            let rules = netthrottle::list_rules();
            if rules.is_empty() {
                shell_println!("No bandwidth rules.");
            } else {
                shell_println!("{:<4} {:<16} {:<12} {:<12} {:<10} {:<8} {:<8}", "ID", "App", "Down(B/s)", "Up(B/s)", "Priority", "State", "On");
                for r in &rules {
                    shell_println!("{:<4} {:<16} {:<12} {:<12} {:<10} {:<8} {:<8}",
                        r.id, r.app_name, r.max_down_bps, r.max_up_bps,
                        r.priority.label(), r.state.label(), r.enabled);
                }
            }
        }
        "add" | "rule" => {
            let app = parts.get(1).copied().unwrap_or("");
            let down = parts.get(2).and_then(|s| s.parse::<u64>().ok()).unwrap_or(0);
            let up = parts.get(3).and_then(|s| s.parse::<u64>().ok()).unwrap_or(0);
            if app.is_empty() {
                shell_println!("Usage: nthrottle add <app> [max_down_bps] [max_up_bps]");
            } else {
                match netthrottle::add_rule(app, down, up, netthrottle::QosPriority::Normal) {
                    Ok(id) => shell_println!("Added rule {} for '{}'", id, app),
                    Err(e) => shell_println!("Error: {:?}", e),
                }
            }
        }
        "remove" | "rm" => {
            if let Some(id_str) = parts.get(1) {
                if let Ok(id) = id_str.parse::<u32>() {
                    match netthrottle::remove_rule(id) {
                        Ok(()) => shell_println!("Removed rule {}", id),
                        Err(e) => shell_println!("Error: {:?}", e),
                    }
                } else { shell_println!("Invalid ID."); }
            } else { shell_println!("Usage: nthrottle remove <id>"); }
        }
        "priority" | "prio" => {
            let id_str = parts.get(1).copied().unwrap_or("");
            let prio_str = parts.get(2).copied().unwrap_or("");
            if let Ok(id) = id_str.parse::<u32>() {
                let prio = match prio_str {
                    "critical" | "c" => netthrottle::QosPriority::Critical,
                    "high" | "h" => netthrottle::QosPriority::High,
                    "low" | "l" => netthrottle::QosPriority::Low,
                    "background" | "bg" => netthrottle::QosPriority::Background,
                    _ => netthrottle::QosPriority::Normal,
                };
                match netthrottle::set_priority(id, prio) {
                    Ok(()) => shell_println!("Priority set to {}", prio.label()),
                    Err(e) => shell_println!("Error: {:?}", e),
                }
            } else { shell_println!("Usage: nthrottle priority <id> <level>"); }
        }
        "enable" => {
            if let Some(s) = parts.get(1) {
                if let Ok(id) = s.parse::<u32>() {
                    netthrottle::set_enabled(id, true).ok();
                    shell_println!("Rule {} enabled.", id);
                } else { netthrottle::set_global_enabled(true).ok(); shell_println!("Global throttling enabled."); }
            } else { netthrottle::set_global_enabled(true).ok(); shell_println!("Global throttling enabled."); }
        }
        "disable" => {
            if let Some(s) = parts.get(1) {
                if let Ok(id) = s.parse::<u32>() {
                    netthrottle::set_enabled(id, false).ok();
                    shell_println!("Rule {} disabled.", id);
                } else { netthrottle::set_global_enabled(false).ok(); shell_println!("Global throttling disabled."); }
            } else { netthrottle::set_global_enabled(false).ok(); shell_println!("Global throttling disabled."); }
        }
        "stats" => {
            let (count, throttled, blocked, enabled, ops) = netthrottle::stats();
            shell_println!("Rules: {}, Global enabled: {}", count, enabled);
            shell_println!("Throttled: {}, Blocked: {}, Ops: {}", throttled, blocked, ops);
        }
        "test" => { netthrottle::self_test(); shell_println!("Net throttle self-test complete."); }
        "init" => { netthrottle::init_defaults(); shell_println!("Net throttle initialized."); }
        _ => {
            shell_println!("netthrottle (nthrottle) — bandwidth control");
            shell_println!("  show / list            List rules");
            shell_println!("  add <app> [down] [up]  Add rule");
            shell_println!("  remove <id>            Remove rule");
            shell_println!("  priority <id> <level>  Set QoS");
            shell_println!("  enable / disable [id]  Toggle");
            shell_println!("  stats / test / init");
        }
    }
}

/// `dumpanalyzer` / `dump` — crash dump analysis.
fn cmd_dumpanalyzer(args: &str) {
    use crate::fs::dumpanalyzer;
    let parts: Vec<&str> = args.split_whitespace().collect();
    let sub = parts.first().copied().unwrap_or("");
    match sub {
        "" | "show" | "list" => {
            dumpanalyzer::init_defaults();
            let analyses = dumpanalyzer::list_analyses();
            if analyses.is_empty() {
                shell_println!("No crash analyses.");
            } else {
                shell_println!("{:<4} {:<10} {:<16} {:<16} {:<6}", "ID", "Severity", "Fault", "Module", "PID");
                for a in &analyses {
                    shell_println!("{:<4} {:<10} {:<16} {:<16} {:<6}",
                        a.id, a.severity.label(), a.fault_type.label(), a.faulting_module, a.pid);
                }
            }
        }
        "info" | "detail" => {
            if let Some(id_str) = parts.get(1) {
                if let Ok(id) = id_str.parse::<u32>() {
                    match dumpanalyzer::get_analysis(id) {
                        Ok(a) => {
                            shell_println!("Analysis #{}", a.id);
                            shell_println!("  Dump:     {}", a.dump_path);
                            shell_println!("  Severity: {}", a.severity.label());
                            shell_println!("  Fault:    {}", a.fault_type.label());
                            shell_println!("  Module:   {}", a.faulting_module);
                            shell_println!("  Address:  0x{:x}", a.fault_address);
                            shell_println!("  PID:      {}", a.pid);
                            shell_println!("  Summary:  {}", a.summary);
                            if !a.stack_frames.is_empty() {
                                shell_println!("  Stack trace:");
                                for f in &a.stack_frames {
                                    shell_println!("    #{} 0x{:x} {}!{} +0x{:x}",
                                        f.index, f.address, f.module, f.function, f.offset);
                                }
                            }
                        }
                        Err(e) => shell_println!("Error: {:?}", e),
                    }
                } else { shell_println!("Invalid ID."); }
            } else { shell_println!("Usage: dump info <id>"); }
        }
        "delete" | "rm" => {
            if let Some(id_str) = parts.get(1) {
                if let Ok(id) = id_str.parse::<u32>() {
                    match dumpanalyzer::delete_analysis(id) {
                        Ok(()) => shell_println!("Deleted analysis {}", id),
                        Err(e) => shell_println!("Error: {:?}", e),
                    }
                } else { shell_println!("Invalid ID."); }
            } else { shell_println!("Usage: dump delete <id>"); }
        }
        "clear" => {
            let n = dumpanalyzer::clear_all();
            shell_println!("Cleared {} analysis(es).", n);
        }
        "stats" => {
            let (count, total, kernel, app, ops) = dumpanalyzer::stats();
            shell_println!("Analyses: {}, Total: {}", count, total);
            shell_println!("Kernel crashes: {}, App crashes: {}, Ops: {}", kernel, app, ops);
        }
        "test" => { dumpanalyzer::self_test(); shell_println!("Dump analyzer self-test complete."); }
        "init" => { dumpanalyzer::init_defaults(); shell_println!("Dump analyzer initialized."); }
        _ => {
            shell_println!("dumpanalyzer (dump) — crash dump analysis");
            shell_println!("  show / list         List analyses");
            shell_println!("  info <id>           Analysis details");
            shell_println!("  delete <id>         Delete analysis");
            shell_println!("  clear               Clear all");
            shell_println!("  stats / test / init");
        }
    }
}

/// `memdiag` / `mdiag` — memory diagnostics.
fn cmd_memdiag(args: &str) {
    use crate::fs::memdiag;
    let parts: Vec<&str> = args.split_whitespace().collect();
    let sub = parts.first().copied().unwrap_or("");
    match sub {
        "" | "show" | "health" => {
            memdiag::init_defaults();
            let h = memdiag::get_health();
            shell_println!("Memory Diagnostics:");
            shell_println!("  Total memory:     {} KB ({} MB)", h.total_memory_kb, h.total_memory_kb / 1024);
            shell_println!("  Tested:           {} KB", h.tested_memory_kb);
            shell_println!("  Last test:        {}", h.last_test_result.label());
            shell_println!("  ECC supported:    {}", h.ecc_supported);
            shell_println!("  Correctable:      {}", h.correctable_errors);
            shell_println!("  Uncorrectable:    {}", h.uncorrectable_errors);
        }
        "run" | "test" => {
            memdiag::init_defaults();
            let type_str = parts.get(1).copied().unwrap_or("quick");
            let test_type = match type_str {
                "standard" | "std" => memdiag::TestType::Standard,
                "extended" | "ext" => memdiag::TestType::Extended,
                "address" | "addr" => memdiag::TestType::AddressLine,
                "random" | "rand" => memdiag::TestType::Random,
                _ => memdiag::TestType::Quick,
            };
            let h = memdiag::get_health();
            match memdiag::run_test(test_type, 0, h.total_memory_kb) {
                Ok(id) => {
                    let tests = memdiag::list_tests();
                    if let Some(t) = tests.iter().find(|t| t.id == id) {
                        shell_println!("{} test #{}: {} ({} errors)", test_type.label(), id, t.result.label(), t.errors_found);
                    }
                }
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "tests" | "history" => {
            let tests = memdiag::list_tests();
            if tests.is_empty() {
                shell_println!("No test results.");
            } else {
                shell_println!("{:<4} {:<12} {:<8} {:<8} {:<12}", "ID", "Type", "Result", "Errors", "Range(KB)");
                for t in &tests {
                    shell_println!("{:<4} {:<12} {:<8} {:<8} {:<12}",
                        t.id, t.test_type.label(), t.result.label(), t.errors_found, t.range_size_kb);
                }
            }
        }
        "ecc" => {
            let limit = parts.get(1).and_then(|s| s.parse::<usize>().ok()).unwrap_or(20);
            let errors = memdiag::list_ecc_errors(limit);
            if errors.is_empty() {
                shell_println!("No ECC errors.");
            } else {
                for e in &errors {
                    shell_println!("  {} at 0x{:x} (DIMM {})", e.error_type.label(), e.address, e.dimm_slot);
                }
            }
        }
        "stats" => {
            let (count, total, correctable, uncorrectable, ops) = memdiag::stats();
            shell_println!("Tests: {}, Total runs: {}", count, total);
            shell_println!("Correctable: {}, Uncorrectable: {}, Ops: {}", correctable, uncorrectable, ops);
        }
        "selftest" => { memdiag::self_test(); shell_println!("Memory diagnostics self-test complete."); }
        "init" => { memdiag::init_defaults(); shell_println!("Memory diagnostics initialized."); }
        _ => {
            shell_println!("memdiag (mdiag) — memory diagnostics");
            shell_println!("  show / health        Health summary");
            shell_println!("  run [type]           Run test (quick/std/ext/addr/rand)");
            shell_println!("  tests / history      Test history");
            shell_println!("  ecc [limit]          ECC errors");
            shell_println!("  stats / selftest / init");
        }
    }
}

/// `parentaltime` / `ptime` — parental time limits.
fn cmd_parentaltime(args: &str) {
    use crate::fs::parentaltime;
    let parts: Vec<&str> = args.split_whitespace().collect();
    let sub = parts.first().copied().unwrap_or("");
    match sub {
        "" | "show" | "list" => {
            parentaltime::init_defaults();
            let configs = parentaltime::list_configs();
            if configs.is_empty() {
                shell_println!("No time configs.");
            } else {
                shell_println!("{:<4} {:<12} {:<10} {:<10} {:<10} {:<10} {:<6}",
                    "ID", "User", "Daily(m)", "Weekly(m)", "Used/D", "Used/W", "On");
                for c in &configs {
                    shell_println!("{:<4} {:<12} {:<10} {:<10} {:<10} {:<10} {:<6}",
                        c.id, c.username, c.daily_limit_minutes, c.weekly_limit_minutes,
                        c.used_today_minutes, c.used_week_minutes, c.active);
                }
            }
        }
        "create" | "add" => {
            let user = parts.get(1).copied().unwrap_or("");
            let daily = parts.get(2).and_then(|s| s.parse::<u32>().ok()).unwrap_or(120);
            let weekly = parts.get(3).and_then(|s| s.parse::<u32>().ok()).unwrap_or(0);
            if user.is_empty() {
                shell_println!("Usage: ptime create <user> [daily_min] [weekly_min]");
            } else {
                match parentaltime::create_config(user, daily, weekly) {
                    Ok(id) => shell_println!("Created time config for '{}' (id={}, daily={}m)", user, id, daily),
                    Err(e) => shell_println!("Error: {:?}", e),
                }
            }
        }
        "use" | "record" => {
            let id_str = parts.get(1).copied().unwrap_or("");
            let mins = parts.get(2).and_then(|s| s.parse::<u32>().ok()).unwrap_or(30);
            if let Ok(id) = id_str.parse::<u32>() {
                match parentaltime::record_usage(id, mins) {
                    Ok(status) => shell_println!("Recorded {} min. Status: {}", mins, status.label()),
                    Err(e) => shell_println!("Error: {:?}", e),
                }
            } else { shell_println!("Usage: ptime use <id> [minutes]"); }
        }
        "reset" => {
            if let Some(id_str) = parts.get(1) {
                if let Ok(id) = id_str.parse::<u32>() {
                    let weekly = parts.get(2).copied() == Some("weekly");
                    if weekly {
                        parentaltime::reset_weekly(id).ok();
                        shell_println!("Reset weekly usage for config {}", id);
                    } else {
                        parentaltime::reset_daily(id).ok();
                        shell_println!("Reset daily usage for config {}", id);
                    }
                } else { shell_println!("Invalid ID."); }
            } else { shell_println!("Usage: ptime reset <id> [weekly]"); }
        }
        "limit" => {
            let id_str = parts.get(1).copied().unwrap_or("");
            let mins = parts.get(2).and_then(|s| s.parse::<u32>().ok()).unwrap_or(0);
            if let Ok(id) = id_str.parse::<u32>() {
                match parentaltime::set_daily_limit(id, mins) {
                    Ok(()) => shell_println!("Daily limit set to {} min", mins),
                    Err(e) => shell_println!("Error: {:?}", e),
                }
            } else { shell_println!("Usage: ptime limit <id> <minutes>"); }
        }
        "enable" => {
            if let Some(id_str) = parts.get(1) {
                if let Ok(id) = id_str.parse::<u32>() {
                    parentaltime::set_active(id, true).ok();
                    shell_println!("Config {} enabled.", id);
                }
            }
        }
        "disable" => {
            if let Some(id_str) = parts.get(1) {
                if let Ok(id) = id_str.parse::<u32>() {
                    parentaltime::set_active(id, false).ok();
                    shell_println!("Config {} disabled.", id);
                }
            }
        }
        "remove" | "rm" => {
            if let Some(id_str) = parts.get(1) {
                if let Ok(id) = id_str.parse::<u32>() {
                    match parentaltime::remove_config(id) {
                        Ok(()) => shell_println!("Removed config {}", id),
                        Err(e) => shell_println!("Error: {:?}", e),
                    }
                } else { shell_println!("Invalid ID."); }
            } else { shell_println!("Usage: ptime remove <id>"); }
        }
        "stats" => {
            let (count, enforcements, warnings, ops) = parentaltime::stats();
            shell_println!("Configs: {}, Enforcements: {}, Warnings: {}", count, enforcements, warnings);
            shell_println!("Ops: {}", ops);
        }
        "test" => { parentaltime::self_test(); shell_println!("Parental time self-test complete."); }
        "init" => { parentaltime::init_defaults(); shell_println!("Parental time initialized."); }
        _ => {
            shell_println!("parentaltime (ptime) — time-based limits");
            shell_println!("  show / list             List configs");
            shell_println!("  create <user> [daily]   Create config");
            shell_println!("  use <id> [minutes]      Record usage");
            shell_println!("  limit <id> <minutes>    Set daily limit");
            shell_println!("  reset <id> [weekly]     Reset usage");
            shell_println!("  enable / disable <id>   Toggle");
            shell_println!("  remove <id>             Remove config");
            shell_println!("  stats / test / init");
        }
    }
}

/// `mediakeys` / `mkeys` — media playback session management.
fn cmd_mediakeys(args: &str) {
    use crate::fs::mediakeys;
    let parts: Vec<&str> = args.split_whitespace().collect();
    let sub = parts.first().copied().unwrap_or("");
    match sub {
        "" | "show" | "list" => {
            mediakeys::init_defaults();
            let sessions = mediakeys::list_sessions();
            if sessions.is_empty() {
                shell_println!("No media sessions.");
            } else {
                shell_println!("{:<4} {:<15} {:<20} {:<15} {:<10} {:<8}",
                    "ID", "App", "Title", "Artist", "State", "Active");
                for s in &sessions {
                    shell_println!("{:<4} {:<15} {:<20} {:<15} {:<10} {:<8}",
                        s.id, s.app_name, s.title, s.artist,
                        s.state.label(), if s.is_active { "Yes" } else { "No" });
                }
            }
        }
        "register" | "add" => {
            let app = parts.get(1).copied().unwrap_or("");
            let pid = parts.get(2).and_then(|s| s.parse::<u32>().ok()).unwrap_or(1);
            if app.is_empty() {
                shell_println!("Usage: mkeys register <app_name> [pid]");
            } else {
                match mediakeys::register_session(app, pid) {
                    Ok(id) => shell_println!("Registered session {} for '{}'", id, app),
                    Err(e) => shell_println!("Error: {:?}", e),
                }
            }
        }
        "unregister" | "rm" => {
            if let Some(id_str) = parts.get(1) {
                if let Ok(id) = id_str.parse::<u32>() {
                    match mediakeys::unregister_session(id) {
                        Ok(()) => shell_println!("Unregistered session {}", id),
                        Err(e) => shell_println!("Error: {:?}", e),
                    }
                } else { shell_println!("Invalid ID."); }
            } else { shell_println!("Usage: mkeys unregister <id>"); }
        }
        "update" | "np" => {
            let id_str = parts.get(1).copied().unwrap_or("");
            let title = parts.get(2).copied().unwrap_or("");
            let artist = parts.get(3).copied().unwrap_or("");
            let album = parts.get(4).copied().unwrap_or("");
            let dur = parts.get(5).and_then(|s| s.parse::<u64>().ok()).unwrap_or(0);
            if let Ok(id) = id_str.parse::<u32>() {
                match mediakeys::update_now_playing(id, title, artist, album, dur) {
                    Ok(()) => shell_println!("Updated now playing for session {}", id),
                    Err(e) => shell_println!("Error: {:?}", e),
                }
            } else { shell_println!("Usage: mkeys update <id> <title> [artist] [album] [duration_ms]"); }
        }
        "play" => {
            if let Some(id_str) = parts.get(1) {
                if let Ok(id) = id_str.parse::<u32>() {
                    mediakeys::set_playback_state(id, mediakeys::PlaybackState::Playing).ok();
                    shell_println!("Session {} → Playing", id);
                }
            } else {
                mediakeys::handle_key(mediakeys::MediaKey::Play).ok();
                shell_println!("Play (active session)");
            }
        }
        "pause" => {
            if let Some(id_str) = parts.get(1) {
                if let Ok(id) = id_str.parse::<u32>() {
                    mediakeys::set_playback_state(id, mediakeys::PlaybackState::Paused).ok();
                    shell_println!("Session {} → Paused", id);
                }
            } else {
                mediakeys::handle_key(mediakeys::MediaKey::Pause).ok();
                shell_println!("Pause (active session)");
            }
        }
        "toggle" | "pp" => {
            mediakeys::handle_key(mediakeys::MediaKey::PlayPause).ok();
            shell_println!("Play/Pause toggled.");
        }
        "stop" => {
            mediakeys::handle_key(mediakeys::MediaKey::Stop).ok();
            shell_println!("Stopped.");
        }
        "next" => {
            mediakeys::handle_key(mediakeys::MediaKey::Next).ok();
            shell_println!("Next track.");
        }
        "prev" => {
            mediakeys::handle_key(mediakeys::MediaKey::Previous).ok();
            shell_println!("Previous track.");
        }
        "active" => {
            if let Some(id_str) = parts.get(1) {
                if let Ok(id) = id_str.parse::<u32>() {
                    match mediakeys::set_active(id) {
                        Ok(()) => shell_println!("Session {} is now active.", id),
                        Err(e) => shell_println!("Error: {:?}", e),
                    }
                }
            } else {
                match mediakeys::get_active_session() {
                    Some(s) => shell_println!("Active: {} — {} by {} [{}]",
                        s.app_name, s.title, s.artist, s.state.label()),
                    None => shell_println!("No active session."),
                }
            }
        }
        "stats" => {
            let (count, total, keys, active_id, ops) = mediakeys::stats();
            shell_println!("Sessions: {}, Total: {}, Key events: {}", count, total, keys);
            shell_println!("Active ID: {}, Ops: {}", active_id, ops);
        }
        "test" => { mediakeys::self_test(); shell_println!("Media keys self-test complete."); }
        "init" => { mediakeys::init_defaults(); shell_println!("Media keys initialized."); }
        _ => {
            shell_println!("mediakeys (mkeys) — media playback sessions");
            shell_println!("  show / list                    List sessions");
            shell_println!("  register <app> [pid]           Register session");
            shell_println!("  unregister <id>                Remove session");
            shell_println!("  update <id> <title> [artist]   Now playing");
            shell_println!("  play / pause / toggle / stop   Transport");
            shell_println!("  next / prev                    Track control");
            shell_println!("  active [id]                    Show/set active");
            shell_println!("  stats / test / init");
        }
    }
}

/// `webcam` / `cam` — camera device management.
fn cmd_webcam(args: &str) {
    use crate::fs::webcam;
    let parts: Vec<&str> = args.split_whitespace().collect();
    let sub = parts.first().copied().unwrap_or("");
    match sub {
        "" | "show" | "list" => {
            webcam::init_defaults();
            let cams = webcam::list_cameras();
            if cams.is_empty() {
                shell_println!("No cameras.");
            } else {
                shell_println!("{:<4} {:<25} {:<10} {:<15} {:<7}",
                    "ID", "Name", "Type", "Privacy", "Default");
                for c in &cams {
                    shell_println!("{:<4} {:<25} {:<10} {:<15} {:<7}",
                        c.id, c.name, c.connection.label(), c.privacy.label(),
                        if c.is_default { "Yes" } else { "No" });
                }
            }
        }
        "streams" => {
            let streams = webcam::list_streams();
            if streams.is_empty() {
                shell_println!("No active streams.");
            } else {
                shell_println!("{:<4} {:<6} {:<15} {:<12} {:<6}",
                    "SID", "CamID", "App", "Resolution", "FPS");
                for s in &streams {
                    shell_println!("{:<4} {:<6} {:<15} {}x{:<8} {:<6}",
                        s.stream_id, s.camera_id, s.app_name, s.width, s.height, s.fps);
                }
            }
        }
        "register" | "add" => {
            let name = parts.get(1).copied().unwrap_or("");
            if name.is_empty() {
                shell_println!("Usage: cam register <name> [usb|builtin|network|virtual]");
            } else {
                let conn = match parts.get(2).copied().unwrap_or("usb") {
                    "builtin" => webcam::CameraConnection::Builtin,
                    "network" => webcam::CameraConnection::Network,
                    "virtual" => webcam::CameraConnection::Virtual,
                    _ => webcam::CameraConnection::Usb,
                };
                match webcam::register_camera(name, conn) {
                    Ok(id) => shell_println!("Registered camera {} '{}'", id, name),
                    Err(e) => shell_println!("Error: {:?}", e),
                }
            }
        }
        "unregister" | "rm" => {
            if let Some(id_str) = parts.get(1) {
                if let Ok(id) = id_str.parse::<u32>() {
                    match webcam::unregister_camera(id) {
                        Ok(()) => shell_println!("Unregistered camera {}", id),
                        Err(e) => shell_println!("Error: {:?}", e),
                    }
                } else { shell_println!("Invalid ID."); }
            } else { shell_println!("Usage: cam unregister <id>"); }
        }
        "open" => {
            let cam_id = parts.get(1).and_then(|s| s.parse::<u32>().ok()).unwrap_or(0);
            let app = parts.get(2).copied().unwrap_or("kshell");
            let w = parts.get(3).and_then(|s| s.parse::<u32>().ok()).unwrap_or(1280);
            let h = parts.get(4).and_then(|s| s.parse::<u32>().ok()).unwrap_or(720);
            let fps = parts.get(5).and_then(|s| s.parse::<u32>().ok()).unwrap_or(30);
            if cam_id == 0 {
                shell_println!("Usage: cam open <cam_id> [app] [width] [height] [fps]");
            } else {
                match webcam::open_stream(cam_id, app, 0, w, h, fps) {
                    Ok(sid) => shell_println!("Opened stream {} on camera {}", sid, cam_id),
                    Err(e) => shell_println!("Error: {:?}", e),
                }
            }
        }
        "close" => {
            if let Some(id_str) = parts.get(1) {
                if let Ok(sid) = id_str.parse::<u32>() {
                    match webcam::close_stream(sid) {
                        Ok(()) => shell_println!("Closed stream {}", sid),
                        Err(e) => shell_println!("Error: {:?}", e),
                    }
                } else { shell_println!("Invalid ID."); }
            } else { shell_println!("Usage: cam close <stream_id>"); }
        }
        "privacy" => {
            let id_str = parts.get(1).copied().unwrap_or("");
            let mode = parts.get(2).copied().unwrap_or("");
            if let Ok(id) = id_str.parse::<u32>() {
                let setting = match mode {
                    "open" => webcam::PrivacySetting::Open,
                    "prompt" => webcam::PrivacySetting::PromptRequired,
                    "disabled" | "off" => webcam::PrivacySetting::Disabled,
                    _ => { shell_println!("Modes: open, prompt, disabled"); return; }
                };
                match webcam::set_privacy(id, setting) {
                    Ok(()) => shell_println!("Camera {} privacy → {}", id, setting.label()),
                    Err(e) => shell_println!("Error: {:?}", e),
                }
            } else { shell_println!("Usage: cam privacy <cam_id> <open|prompt|disabled>"); }
        }
        "block" => {
            let app = parts.get(1).copied().unwrap_or("");
            if app.is_empty() {
                shell_println!("Usage: cam block <app_name>");
            } else {
                match webcam::block_app(app) {
                    Ok(()) => shell_println!("Blocked '{}'", app),
                    Err(e) => shell_println!("Error: {:?}", e),
                }
            }
        }
        "unblock" => {
            let app = parts.get(1).copied().unwrap_or("");
            if app.is_empty() {
                shell_println!("Usage: cam unblock <app_name>");
            } else {
                match webcam::unblock_app(app) {
                    Ok(()) => shell_println!("Unblocked '{}'", app),
                    Err(e) => shell_println!("Error: {:?}", e),
                }
            }
        }
        "blocked" => {
            let blocked = webcam::list_blocked();
            if blocked.is_empty() {
                shell_println!("No blocked apps.");
            } else {
                for b in &blocked { shell_println!("  {}", b.app_name); }
            }
        }
        "default" => {
            if let Some(id_str) = parts.get(1) {
                if let Ok(id) = id_str.parse::<u32>() {
                    match webcam::set_default(id) {
                        Ok(()) => shell_println!("Camera {} is now default.", id),
                        Err(e) => shell_println!("Error: {:?}", e),
                    }
                }
            } else { shell_println!("Usage: cam default <cam_id>"); }
        }
        "inuse" => {
            let ids = webcam::cameras_in_use();
            if ids.is_empty() {
                shell_println!("No cameras in use.");
            } else {
                shell_println!("Cameras in use: {:?}", ids);
            }
        }
        "stats" => {
            let (cams, streams, total, denied, ops) = webcam::stats();
            shell_println!("Cameras: {}, Active streams: {}, Total: {}", cams, streams, total);
            shell_println!("Denied: {}, Ops: {}", denied, ops);
        }
        "test" => { webcam::self_test(); shell_println!("Webcam self-test complete."); }
        "init" => { webcam::init_defaults(); shell_println!("Webcam initialized."); }
        _ => {
            shell_println!("webcam (cam) — camera management");
            shell_println!("  show / list                 List cameras");
            shell_println!("  streams                     Active streams");
            shell_println!("  register <name> [type]      Add camera");
            shell_println!("  unregister <id>             Remove camera");
            shell_println!("  open <cam_id> [app] [w] [h] Open stream");
            shell_println!("  close <stream_id>           Close stream");
            shell_println!("  privacy <id> <mode>         Set privacy");
            shell_println!("  block / unblock <app>       App access");
            shell_println!("  blocked                     List blocked");
            shell_println!("  default <id>                Set default");
            shell_println!("  inuse                       Show active");
            shell_println!("  stats / test / init");
        }
    }
}

/// `speechio` / `speech` — speech input/output services.
fn cmd_speechio(args: &str) {
    use crate::fs::speechio;
    let parts: Vec<&str> = args.split_whitespace().collect();
    let sub = parts.first().copied().unwrap_or("");
    match sub {
        "" | "show" | "voices" => {
            speechio::init_defaults();
            let voices = speechio::list_voices();
            if voices.is_empty() {
                shell_println!("No voices.");
            } else {
                shell_println!("{:<4} {:<15} {:<8} {:<10} {:<7}",
                    "ID", "Name", "Lang", "Gender", "Default");
                for v in &voices {
                    shell_println!("{:<4} {:<15} {:<8} {:<10} {:<7}",
                        v.id, v.name, v.language, v.gender.label(),
                        if v.is_default { "Yes" } else { "No" });
                }
            }
        }
        "speak" | "say" => {
            let text = if parts.len() > 1 {
                parts[1..].join(" ")
            } else {
                shell_println!("Usage: speech speak <text>");
                return;
            };
            match speechio::speak(&text, None, 100, 100, 80) {
                Ok(id) => shell_println!("Queued utterance {} — \"{}\"", id, text),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "stop" => {
            speechio::stop_speaking().ok();
            shell_println!("Stopped all speech.");
        }
        "queue" => {
            let utts = speechio::list_utterances();
            if utts.is_empty() {
                shell_println!("No utterances.");
            } else {
                shell_println!("{:<4} {:<10} {:<30} {:<5} {:<5}",
                    "ID", "State", "Text", "Rate", "Vol");
                for u in &utts {
                    let text_short: String = u.text.chars().take(28).collect();
                    shell_println!("{:<4} {:<10} {:<30} {:<5} {:<5}",
                        u.id, u.state.label(), text_short, u.rate_percent, u.volume_percent);
                }
            }
        }
        "cancel" => {
            if let Some(id_str) = parts.get(1) {
                if let Ok(id) = id_str.parse::<u32>() {
                    match speechio::cancel_utterance(id) {
                        Ok(()) => shell_println!("Cancelled utterance {}", id),
                        Err(e) => shell_println!("Error: {:?}", e),
                    }
                }
            } else { shell_println!("Usage: speech cancel <id>"); }
        }
        "addvoice" => {
            let name = parts.get(1).copied().unwrap_or("");
            let lang = parts.get(2).copied().unwrap_or("en-US");
            let gender = match parts.get(3).copied().unwrap_or("neutral") {
                "male" | "m" => speechio::VoiceGender::Male,
                "female" | "f" => speechio::VoiceGender::Female,
                _ => speechio::VoiceGender::Neutral,
            };
            if name.is_empty() {
                shell_println!("Usage: speech addvoice <name> [lang] [male|female|neutral]");
            } else {
                match speechio::add_voice(name, lang, gender) {
                    Ok(id) => shell_println!("Added voice {} '{}'", id, name),
                    Err(e) => shell_println!("Error: {:?}", e),
                }
            }
        }
        "rmvoice" => {
            if let Some(id_str) = parts.get(1) {
                if let Ok(id) = id_str.parse::<u32>() {
                    match speechio::remove_voice(id) {
                        Ok(()) => shell_println!("Removed voice {}", id),
                        Err(e) => shell_println!("Error: {:?}", e),
                    }
                }
            } else { shell_println!("Usage: speech rmvoice <id>"); }
        }
        "default" => {
            if let Some(id_str) = parts.get(1) {
                if let Ok(id) = id_str.parse::<u32>() {
                    match speechio::set_default_voice(id) {
                        Ok(()) => shell_println!("Voice {} is now default.", id),
                        Err(e) => shell_println!("Error: {:?}", e),
                    }
                }
            } else { shell_println!("Usage: speech default <voice_id>"); }
        }
        "tts" => {
            let mode = parts.get(1).copied().unwrap_or("");
            match mode {
                "on" | "enable" => {
                    speechio::set_tts_enabled(true).ok();
                    shell_println!("TTS enabled.");
                }
                "off" | "disable" => {
                    speechio::set_tts_enabled(false).ok();
                    shell_println!("TTS disabled.");
                }
                _ => shell_println!("Usage: speech tts <on|off>"),
            }
        }
        "listen" => {
            let mode = parts.get(1).copied().unwrap_or("start");
            match mode {
                "start" | "on" => {
                    speechio::set_recognition_enabled(true).ok();
                    match speechio::start_listening() {
                        Ok(()) => shell_println!("Listening..."),
                        Err(e) => shell_println!("Error: {:?}", e),
                    }
                }
                "stop" | "off" => {
                    speechio::stop_listening().ok();
                    shell_println!("Stopped listening.");
                }
                _ => shell_println!("Usage: speech listen <start|stop>"),
            }
        }
        "results" => {
            let results = speechio::list_results();
            if results.is_empty() {
                shell_println!("No recognition results.");
            } else {
                for r in &results {
                    shell_println!("[{}] \"{}\", confidence: {}.{}%",
                        r.id, r.text, r.confidence / 100, r.confidence % 100);
                }
            }
        }
        "stats" => {
            let (voices, spoken, recognized, tts_on, ops) = speechio::stats();
            shell_println!("Voices: {}, Spoken: {}, Recognized: {}", voices, spoken, recognized);
            shell_println!("TTS: {}, Ops: {}", if tts_on { "On" } else { "Off" }, ops);
        }
        "test" => { speechio::self_test(); shell_println!("Speech I/O self-test complete."); }
        "init" => { speechio::init_defaults(); shell_println!("Speech I/O initialized."); }
        _ => {
            shell_println!("speechio (speech) — speech services");
            shell_println!("  voices / show           List voices");
            shell_println!("  speak <text>            Queue TTS");
            shell_println!("  stop                    Stop speaking");
            shell_println!("  queue                   Show utterances");
            shell_println!("  cancel <id>             Cancel utterance");
            shell_println!("  addvoice <name> [lang]  Add voice");
            shell_println!("  rmvoice <id>            Remove voice");
            shell_println!("  default <id>            Set default voice");
            shell_println!("  tts <on|off>            Toggle TTS");
            shell_println!("  listen <start|stop>     Recognition");
            shell_println!("  results                 Show results");
            shell_println!("  stats / test / init");
        }
    }
}

/// `mobilelink` / `mlink` — phone/mobile device linking.
fn cmd_mobilelink(args: &str) {
    use crate::fs::mobilelink;
    let parts: Vec<&str> = args.split_whitespace().collect();
    let sub = parts.first().copied().unwrap_or("");
    match sub {
        "" | "show" | "list" => {
            mobilelink::init_defaults();
            let devs = mobilelink::list_devices();
            if devs.is_empty() {
                shell_println!("No linked devices.");
            } else {
                shell_println!("{:<4} {:<18} {:<10} {:<15} {:<12} {:<5}",
                    "ID", "Name", "Platform", "Model", "State", "Batt");
                for d in &devs {
                    shell_println!("{:<4} {:<18} {:<10} {:<15} {:<12} {}%",
                        d.id, d.name, d.platform.label(), d.model,
                        d.state.label(), d.battery_percent);
                }
            }
        }
        "pair" | "add" => {
            let name = parts.get(1).copied().unwrap_or("");
            let model = parts.get(2).copied().unwrap_or("Unknown");
            if name.is_empty() {
                shell_println!("Usage: mlink pair <name> [model] [android|ios|other]");
            } else {
                let platform = match parts.get(3).copied().unwrap_or("android") {
                    "ios" => mobilelink::MobilePlatform::Ios,
                    "other" => mobilelink::MobilePlatform::Other,
                    _ => mobilelink::MobilePlatform::Android,
                };
                match mobilelink::start_pairing(name, platform, model) {
                    Ok((id, code)) => shell_println!("Pairing device {}. Code: {}", id, code),
                    Err(e) => shell_println!("Error: {:?}", e),
                }
            }
        }
        "confirm" => {
            let id_str = parts.get(1).copied().unwrap_or("");
            let code_str = parts.get(2).copied().unwrap_or("");
            if let (Ok(id), Ok(code)) = (id_str.parse::<u32>(), code_str.parse::<u32>()) {
                match mobilelink::confirm_pairing(id, code) {
                    Ok(()) => shell_println!("Device {} paired successfully.", id),
                    Err(e) => shell_println!("Error: {:?}", e),
                }
            } else { shell_println!("Usage: mlink confirm <device_id> <code>"); }
        }
        "disconnect" | "dc" => {
            if let Some(id_str) = parts.get(1) {
                if let Ok(id) = id_str.parse::<u32>() {
                    match mobilelink::disconnect(id) {
                        Ok(()) => shell_println!("Disconnected device {}", id),
                        Err(e) => shell_println!("Error: {:?}", e),
                    }
                }
            } else { shell_println!("Usage: mlink disconnect <id>"); }
        }
        "reconnect" | "rc" => {
            if let Some(id_str) = parts.get(1) {
                if let Ok(id) = id_str.parse::<u32>() {
                    match mobilelink::reconnect(id) {
                        Ok(()) => shell_println!("Reconnected device {}", id),
                        Err(e) => shell_println!("Error: {:?}", e),
                    }
                }
            } else { shell_println!("Usage: mlink reconnect <id>"); }
        }
        "remove" | "rm" => {
            if let Some(id_str) = parts.get(1) {
                if let Ok(id) = id_str.parse::<u32>() {
                    match mobilelink::remove_device(id) {
                        Ok(()) => shell_println!("Removed device {}", id),
                        Err(e) => shell_println!("Error: {:?}", e),
                    }
                }
            } else { shell_println!("Usage: mlink remove <id>"); }
        }
        "notif" | "notifications" => {
            let dev_id = parts.get(1).and_then(|s| s.parse::<u32>().ok()).unwrap_or(0);
            let notifs = mobilelink::list_notifications(dev_id);
            if notifs.is_empty() {
                shell_println!("No notifications.");
            } else {
                for n in &notifs {
                    let status = if n.dismissed { " (dismissed)" } else { "" };
                    shell_println!("[{}] {} — {} / {}{}", n.id, n.app_name, n.title, n.body, status);
                }
            }
        }
        "sms" | "msg" => {
            let id_str = parts.get(1).copied().unwrap_or("");
            let to = parts.get(2).copied().unwrap_or("");
            let body = if parts.len() > 3 { parts[3..].join(" ") } else { String::new() };
            if let Ok(id) = id_str.parse::<u32>() {
                if to.is_empty() || body.is_empty() {
                    shell_println!("Usage: mlink sms <device_id> <recipient> <message>");
                } else {
                    match mobilelink::send_sms(id, to, &body) {
                        Ok(mid) => shell_println!("Sent SMS {} to {}", mid, to),
                        Err(e) => shell_println!("Error: {:?}", e),
                    }
                }
            } else { shell_println!("Usage: mlink sms <device_id> <recipient> <message>"); }
        }
        "feature" => {
            let id_str = parts.get(1).copied().unwrap_or("");
            let feat = parts.get(2).copied().unwrap_or("");
            let enable = parts.get(3).copied().unwrap_or("on") != "off";
            if let Ok(id) = id_str.parse::<u32>() {
                let feature = match feat {
                    "notif" => mobilelink::LinkFeature::NotificationMirror,
                    "sms" => mobilelink::LinkFeature::Sms,
                    "calls" => mobilelink::LinkFeature::PhoneCalls,
                    "files" => mobilelink::LinkFeature::FileTransfer,
                    "clipboard" => mobilelink::LinkFeature::ClipboardSync,
                    "photos" => mobilelink::LinkFeature::PhotoStream,
                    "battery" => mobilelink::LinkFeature::BatteryStatus,
                    _ => { shell_println!("Features: notif, sms, calls, files, clipboard, photos, battery"); return; }
                };
                match mobilelink::set_feature(id, feature, enable) {
                    Ok(()) => shell_println!("Feature '{}' {} for device {}",
                        feat, if enable { "enabled" } else { "disabled" }, id),
                    Err(e) => shell_println!("Error: {:?}", e),
                }
            } else { shell_println!("Usage: mlink feature <device_id> <feature> [on|off]"); }
        }
        "battery" => {
            if let Some(id_str) = parts.get(1) {
                if let Ok(id) = id_str.parse::<u32>() {
                    let pct = parts.get(2).and_then(|s| s.parse::<u8>().ok()).unwrap_or(0);
                    mobilelink::update_battery(id, pct).ok();
                    shell_println!("Device {} battery → {}%", id, pct);
                }
            } else { shell_println!("Usage: mlink battery <id> <percent>"); }
        }
        "stats" => {
            let (devs, paired, notifs, msgs, transfers, ops) = mobilelink::stats();
            shell_println!("Devices: {}, Total paired: {}, Notifications: {}", devs, paired, notifs);
            shell_println!("Messages: {}, Transfers: {}, Ops: {}", msgs, transfers, ops);
        }
        "test" => { mobilelink::self_test(); shell_println!("Mobile link self-test complete."); }
        "init" => { mobilelink::init_defaults(); shell_println!("Mobile link initialized."); }
        _ => {
            shell_println!("mobilelink (mlink) — phone/device linking");
            shell_println!("  show / list                 List devices");
            shell_println!("  pair <name> [model]         Start pairing");
            shell_println!("  confirm <id> <code>         Confirm pairing");
            shell_println!("  disconnect / reconnect <id> Connection");
            shell_println!("  remove <id>                 Unpair device");
            shell_println!("  notif [device_id]           Notifications");
            shell_println!("  sms <id> <to> <message>     Send SMS");
            shell_println!("  feature <id> <feat> [on|off] Toggle feature");
            shell_println!("  battery <id> <percent>      Update battery");
            shell_println!("  stats / test / init");
        }
    }
}

/// `screenlock` / `slock` — screen lock management.
fn cmd_screenlock(args: &str) {
    use crate::fs::screenlock;
    let parts: Vec<&str> = args.split_whitespace().collect();
    let sub = parts.first().copied().unwrap_or("");
    match sub {
        "" | "show" | "status" => {
            screenlock::init_defaults();
            let state = screenlock::get_state();
            shell_println!("Lock state: {}", state.label());
            if let Some(cfg) = screenlock::get_config() {
                shell_println!("Timeout: {}s, Method: {}, Max attempts: {}",
                    cfg.timeout_secs, cfg.primary_method.label(), cfg.max_attempts);
                shell_println!("Show: clock={}, media={}, notif={}",
                    cfg.show_clock, cfg.show_media, cfg.show_notifications);
            }
        }
        "lock" => {
            match screenlock::lock() {
                Ok(()) => shell_println!("Screen locked."),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "unlock" => {
            let credential = parts.get(1).copied().unwrap_or("");
            match screenlock::authenticate(screenlock::AuthMethod::Password, credential) {
                Ok(true) => shell_println!("Unlocked."),
                Ok(false) => shell_println!("Authentication failed."),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "force" => {
            screenlock::force_unlock().ok();
            shell_println!("Force unlocked.");
        }
        "timeout" => {
            if let Some(s) = parts.get(1) {
                if let Ok(secs) = s.parse::<u32>() {
                    screenlock::set_timeout(secs).ok();
                    shell_println!("Timeout set to {}s.", secs);
                }
            } else { shell_println!("Usage: slock timeout <seconds>"); }
        }
        "method" => {
            let m = parts.get(1).copied().unwrap_or("");
            let method = match m {
                "password" | "pw" => screenlock::AuthMethod::Password,
                "pin" => screenlock::AuthMethod::Pin,
                "fingerprint" | "fp" => screenlock::AuthMethod::Fingerprint,
                "face" => screenlock::AuthMethod::FaceRecognition,
                "smartcard" | "sc" => screenlock::AuthMethod::SmartCard,
                "none" => screenlock::AuthMethod::None,
                _ => { shell_println!("Methods: password, pin, fingerprint, face, smartcard, none"); return; }
            };
            screenlock::set_primary_method(method).ok();
            shell_println!("Auth method → {}", method.label());
        }
        "option" => {
            let opt = parts.get(1).copied().unwrap_or("");
            let val = parts.get(2).copied().unwrap_or("on") == "on";
            match screenlock::set_lock_screen_option(opt, val) {
                Ok(()) => shell_println!("{} → {}", opt, if val { "on" } else { "off" }),
                Err(e) => shell_println!("Error: {:?} (options: notifications, media, clock, require_on_wake)", e),
            }
        }
        "events" => {
            let events = screenlock::list_events();
            if events.is_empty() {
                shell_println!("No lock events.");
            } else {
                for e in events.iter().rev().take(20) {
                    shell_println!("[{}] {} via {} — {}", e.id, e.event_type.label(),
                        e.method.label(), if e.success { "success" } else { "failed" });
                }
            }
        }
        "stats" => {
            let (locks, unlocks, failed, lockouts, ops) = screenlock::stats();
            shell_println!("Locks: {}, Unlocks: {}, Failed: {}, Lockouts: {}",
                locks, unlocks, failed, lockouts);
            shell_println!("Ops: {}", ops);
        }
        "test" => { screenlock::self_test(); shell_println!("Screen lock self-test complete."); }
        "init" => { screenlock::init_defaults(); shell_println!("Screen lock initialized."); }
        _ => {
            shell_println!("screenlock (slock) — screen lock management");
            shell_println!("  status / show           Current state");
            shell_println!("  lock                    Lock screen");
            shell_println!("  unlock <credential>     Authenticate");
            shell_println!("  force                   Force unlock");
            shell_println!("  timeout <seconds>       Set auto-lock");
            shell_println!("  method <type>           Set auth method");
            shell_println!("  option <name> [on|off]  Lock screen options");
            shell_println!("  events                  Recent events");
            shell_println!("  stats / test / init");
        }
    }
}

/// `appstore` / `store` — application marketplace.
fn cmd_appstore(args: &str) {
    use crate::fs::appstore;
    let parts: Vec<&str> = args.split_whitespace().collect();
    let sub = parts.first().copied().unwrap_or("");
    match sub {
        "" | "show" | "list" => {
            appstore::init_defaults();
            let apps = appstore::list_apps();
            if apps.is_empty() {
                shell_println!("No apps in store.");
            } else {
                shell_println!("{:<4} {:<22} {:<14} {:<12} {:<10} {:<8}",
                    "ID", "Name", "Developer", "Category", "Version", "State");
                for a in &apps {
                    shell_println!("{:<4} {:<22} {:<14} {:<12} {:<10} {:<8}",
                        a.id, a.name, a.developer, a.category.label(),
                        a.version, a.state.label());
                }
            }
        }
        "search" => {
            let query = if parts.len() > 1 { parts[1..].join(" ") } else {
                shell_println!("Usage: store search <query>");
                return;
            };
            let results = appstore::search(&query);
            if results.is_empty() {
                shell_println!("No results for '{}'.", query);
            } else {
                for a in &results {
                    shell_println!("[{}] {} — {} ({})", a.id, a.name, a.description, a.state.label());
                }
            }
        }
        "install" => {
            if let Some(id_str) = parts.get(1) {
                if let Ok(id) = id_str.parse::<u32>() {
                    match appstore::install(id) {
                        Ok(()) => shell_println!("Installed app {}.", id),
                        Err(e) => shell_println!("Error: {:?}", e),
                    }
                }
            } else { shell_println!("Usage: store install <app_id>"); }
        }
        "uninstall" => {
            if let Some(id_str) = parts.get(1) {
                if let Ok(id) = id_str.parse::<u32>() {
                    match appstore::uninstall(id) {
                        Ok(()) => shell_println!("Uninstalled app {}.", id),
                        Err(e) => shell_println!("Error: {:?}", e),
                    }
                }
            } else { shell_println!("Usage: store uninstall <app_id>"); }
        }
        "update" => {
            if let Some(id_str) = parts.get(1) {
                if let Ok(id) = id_str.parse::<u32>() {
                    match appstore::update_app(id) {
                        Ok(()) => shell_println!("Updated app {}.", id),
                        Err(e) => shell_println!("Error: {:?}", e),
                    }
                }
            } else { shell_println!("Usage: store update <app_id>"); }
        }
        "check" => {
            match appstore::check_updates() {
                Ok(ids) => {
                    if ids.is_empty() { shell_println!("All apps up to date."); }
                    else { shell_println!("Updates available for: {:?}", ids); }
                }
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "installed" => {
            let installed = appstore::list_installed();
            if installed.is_empty() {
                shell_println!("No installed apps.");
            } else {
                for a in &installed {
                    shell_println!("[{}] {} v{} (store: v{})",
                        a.id, a.name, a.installed_version, a.version);
                }
            }
        }
        "review" => {
            let id_str = parts.get(1).copied().unwrap_or("");
            let rating = parts.get(2).and_then(|s| s.parse::<u8>().ok()).unwrap_or(0);
            let comment = if parts.len() > 3 { parts[3..].join(" ") } else { String::new() };
            if let Ok(id) = id_str.parse::<u32>() {
                if rating == 0 {
                    // Show reviews.
                    let reviews = appstore::list_reviews(id);
                    if reviews.is_empty() { shell_println!("No reviews."); }
                    else {
                        for r in &reviews {
                            shell_println!("{} — {}/5 — {}", r.user, r.rating, r.comment);
                        }
                    }
                } else {
                    match appstore::add_review(id, "kshell_user", rating, &comment) {
                        Ok(rid) => shell_println!("Review {} added ({}/5).", rid, rating),
                        Err(e) => shell_println!("Error: {:?}", e),
                    }
                }
            } else { shell_println!("Usage: store review <app_id> [rating] [comment]"); }
        }
        "add" => {
            let name = parts.get(1).copied().unwrap_or("");
            let dev = parts.get(2).copied().unwrap_or("Unknown");
            let cat_str = parts.get(3).copied().unwrap_or("other");
            let cat = match cat_str {
                "productivity" => appstore::AppCategory::Productivity,
                "dev" | "development" => appstore::AppCategory::Development,
                "graphics" => appstore::AppCategory::Graphics,
                "multimedia" | "media" => appstore::AppCategory::Multimedia,
                "games" => appstore::AppCategory::Games,
                "utilities" | "util" => appstore::AppCategory::Utilities,
                "system" => appstore::AppCategory::System,
                "comm" | "communication" => appstore::AppCategory::Communication,
                "education" | "edu" => appstore::AppCategory::Education,
                _ => appstore::AppCategory::Other,
            };
            if name.is_empty() {
                shell_println!("Usage: store add <name> [developer] [category]");
            } else {
                match appstore::add_app(name, dev, "", cat, "1.0.0", 1024) {
                    Ok(id) => shell_println!("Added app {} '{}'.", id, name),
                    Err(e) => shell_println!("Error: {:?}", e),
                }
            }
        }
        "rm" | "remove" => {
            if let Some(id_str) = parts.get(1) {
                if let Ok(id) = id_str.parse::<u32>() {
                    match appstore::remove_app(id) {
                        Ok(()) => shell_println!("Removed app {}.", id),
                        Err(e) => shell_println!("Error: {:?}", e),
                    }
                }
            } else { shell_println!("Usage: store remove <app_id>"); }
        }
        "stats" => {
            let (apps, installed, installs, updates, ops) = appstore::stats();
            shell_println!("Catalog: {}, Installed: {}, Total installs: {}", apps, installed, installs);
            shell_println!("Updates: {}, Ops: {}", updates, ops);
        }
        "test" => { appstore::self_test(); shell_println!("App store self-test complete."); }
        "init" => { appstore::init_defaults(); shell_println!("App store initialized."); }
        _ => {
            shell_println!("appstore (store) — application marketplace");
            shell_println!("  list / show              Browse catalog");
            shell_println!("  search <query>           Search apps");
            shell_println!("  install <id>             Install app");
            shell_println!("  uninstall <id>           Uninstall app");
            shell_println!("  update <id>              Update app");
            shell_println!("  check                    Check for updates");
            shell_println!("  installed                List installed");
            shell_println!("  review <id> [rating]     View/add review");
            shell_println!("  add <name> [dev] [cat]   Add to catalog");
            shell_println!("  remove <id>              Remove from catalog");
            shell_println!("  stats / test / init");
        }
    }
}

/// `wintiling` / `tile` — window tiling and workspace management.
fn cmd_wintiling(args: &str) {
    use crate::fs::wintiling;
    let parts: Vec<&str> = args.split_whitespace().collect();
    let sub = parts.first().copied().unwrap_or("");
    match sub {
        "" | "show" | "workspaces" => {
            wintiling::init_defaults();
            let wss = wintiling::list_workspaces();
            if wss.is_empty() {
                shell_println!("No workspaces.");
            } else {
                shell_println!("{:<4} {:<15} {:<18} {:<6} {:<6} {:<6}",
                    "ID", "Name", "Layout", "Gap", "Ratio", "Wins");
                for ws in &wss {
                    shell_println!("{:<4} {:<15} {:<18} {:<6} {:<6} {:<6}",
                        ws.id, ws.name, ws.layout.label(), ws.gap_px,
                        ws.master_ratio, ws.window_count);
                }
            }
        }
        "windows" | "wins" => {
            let ws_id = parts.get(1).and_then(|s| s.parse::<u32>().ok()).unwrap_or(0);
            let wins = wintiling::list_windows(ws_id);
            if wins.is_empty() {
                shell_println!("No windows.");
            } else {
                shell_println!("{:<6} {:<20} {:<4} {:<10} {:<10} {:<8}",
                    "WinID", "Title", "WS", "Position", "Size", "Float");
                for w in &wins {
                    shell_println!("{:<6} {:<20} {:<4} ({},{})     {}x{:<6} {:<8}",
                        w.window_id, w.title, w.workspace_id,
                        w.geometry.x, w.geometry.y,
                        w.geometry.width, w.geometry.height,
                        if w.is_floating { "Yes" } else { "No" });
                }
            }
        }
        "create" | "addws" => {
            let name = parts.get(1).copied().unwrap_or("New");
            let layout_str = parts.get(2).copied().unwrap_or("master");
            let layout = match layout_str {
                "float" | "floating" => wintiling::TilingLayout::Floating,
                "hsplit" | "horizontal" => wintiling::TilingLayout::HorizontalSplit,
                "vsplit" | "vertical" => wintiling::TilingLayout::VerticalSplit,
                "master" | "ms" => wintiling::TilingLayout::MasterStack,
                "grid" => wintiling::TilingLayout::Grid,
                "monocle" | "max" => wintiling::TilingLayout::Monocle,
                "3col" | "three" => wintiling::TilingLayout::ThreeColumn,
                _ => wintiling::TilingLayout::MasterStack,
            };
            match wintiling::create_workspace(name, layout) {
                Ok(id) => shell_println!("Created workspace {} '{}'.", id, name),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "rmws" => {
            if let Some(id_str) = parts.get(1) {
                if let Ok(id) = id_str.parse::<u32>() {
                    match wintiling::remove_workspace(id) {
                        Ok(()) => shell_println!("Removed workspace {}.", id),
                        Err(e) => shell_println!("Error: {:?}", e),
                    }
                }
            } else { shell_println!("Usage: tile rmws <workspace_id>"); }
        }
        "addwin" | "add" => {
            let wid = parts.get(1).and_then(|s| s.parse::<u32>().ok()).unwrap_or(0);
            let title = parts.get(2).copied().unwrap_or("Window");
            let ws = parts.get(3).and_then(|s| s.parse::<u32>().ok()).unwrap_or(1);
            if wid == 0 {
                shell_println!("Usage: tile add <window_id> [title] [workspace]");
            } else {
                match wintiling::add_window(wid, title, ws) {
                    Ok(()) => shell_println!("Added window {} to workspace {}.", wid, ws),
                    Err(e) => shell_println!("Error: {:?}", e),
                }
            }
        }
        "rmwin" | "rm" => {
            if let Some(id_str) = parts.get(1) {
                if let Ok(id) = id_str.parse::<u32>() {
                    match wintiling::remove_window(id) {
                        Ok(()) => shell_println!("Removed window {}.", id),
                        Err(e) => shell_println!("Error: {:?}", e),
                    }
                }
            } else { shell_println!("Usage: tile rm <window_id>"); }
        }
        "layout" => {
            let ws = parts.get(1).and_then(|s| s.parse::<u32>().ok()).unwrap_or(0);
            let layout_str = parts.get(2).copied().unwrap_or("");
            let layout = match layout_str {
                "float" | "floating" => wintiling::TilingLayout::Floating,
                "hsplit" | "horizontal" => wintiling::TilingLayout::HorizontalSplit,
                "vsplit" | "vertical" => wintiling::TilingLayout::VerticalSplit,
                "master" | "ms" => wintiling::TilingLayout::MasterStack,
                "grid" => wintiling::TilingLayout::Grid,
                "monocle" | "max" => wintiling::TilingLayout::Monocle,
                "3col" | "three" => wintiling::TilingLayout::ThreeColumn,
                _ => { shell_println!("Layouts: float, hsplit, vsplit, master, grid, monocle, 3col"); return; }
            };
            match wintiling::set_layout(ws, layout) {
                Ok(()) => shell_println!("Workspace {} → {}", ws, layout.label()),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "retile" => {
            let ws = parts.get(1).and_then(|s| s.parse::<u32>().ok()).unwrap_or(1);
            match wintiling::retile(ws) {
                Ok(()) => shell_println!("Retiled workspace {}.", ws),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "gap" => {
            let ws = parts.get(1).and_then(|s| s.parse::<u32>().ok()).unwrap_or(0);
            let gap = parts.get(2).and_then(|s| s.parse::<u32>().ok()).unwrap_or(0);
            if ws == 0 { shell_println!("Usage: tile gap <workspace> <pixels>"); }
            else {
                wintiling::set_gap(ws, gap).ok();
                shell_println!("Gap → {}px", gap);
            }
        }
        "ratio" => {
            let ws = parts.get(1).and_then(|s| s.parse::<u32>().ok()).unwrap_or(0);
            let ratio = parts.get(2).and_then(|s| s.parse::<u32>().ok()).unwrap_or(55);
            if ws == 0 { shell_println!("Usage: tile ratio <workspace> <percent>"); }
            else {
                wintiling::set_master_ratio(ws, ratio).ok();
                shell_println!("Master ratio → {}%", ratio);
            }
        }
        "float" => {
            if let Some(id_str) = parts.get(1) {
                if let Ok(id) = id_str.parse::<u32>() {
                    match wintiling::toggle_floating(id) {
                        Ok(f) => shell_println!("Window {} floating: {}", id, f),
                        Err(e) => shell_println!("Error: {:?}", e),
                    }
                }
            } else { shell_println!("Usage: tile float <window_id>"); }
        }
        "move" => {
            let wid = parts.get(1).and_then(|s| s.parse::<u32>().ok()).unwrap_or(0);
            let ws = parts.get(2).and_then(|s| s.parse::<u32>().ok()).unwrap_or(0);
            if wid == 0 || ws == 0 {
                shell_println!("Usage: tile move <window_id> <workspace>");
            } else {
                match wintiling::move_to_workspace(wid, ws) {
                    Ok(()) => shell_println!("Moved window {} to workspace {}.", wid, ws),
                    Err(e) => shell_println!("Error: {:?}", e),
                }
            }
        }
        "stats" => {
            let (ws, wins, tiles, retiles, ops) = wintiling::stats();
            shell_println!("Workspaces: {}, Windows: {}, Tiles: {}, Retiles: {}",
                ws, wins, tiles, retiles);
            shell_println!("Ops: {}", ops);
        }
        "test" => { wintiling::self_test(); shell_println!("Window tiling self-test complete."); }
        "init" => { wintiling::init_defaults(); shell_println!("Window tiling initialized."); }
        _ => {
            shell_println!("wintiling (tile) — window tiling");
            shell_println!("  workspaces              List workspaces");
            shell_println!("  windows [ws_id]         List windows");
            shell_println!("  create <name> [layout]  New workspace");
            shell_println!("  rmws <ws_id>            Remove workspace");
            shell_println!("  add <wid> [title] [ws]  Add window");
            shell_println!("  rm <wid>                Remove window");
            shell_println!("  layout <ws> <type>      Set layout");
            shell_println!("  retile [ws]             Recalculate");
            shell_println!("  gap <ws> <px>           Set gap");
            shell_println!("  ratio <ws> <pct>        Master ratio");
            shell_println!("  float <wid>             Toggle float");
            shell_println!("  move <wid> <ws>         Move window");
            shell_println!("  stats / test / init");
        }
    }
}

/// `peninput` / `pen` — stylus and pen input.
fn cmd_peninput(args: &str) {
    use crate::fs::peninput;
    let parts: Vec<&str> = args.split_whitespace().collect();
    let sub = parts.first().copied().unwrap_or("");
    match sub {
        "" | "show" | "list" => {
            peninput::init_defaults();
            let pens = peninput::list_pens();
            if pens.is_empty() {
                shell_println!("No pen devices.");
            } else {
                shell_println!("{:<4} {:<20} {:<10} {:<12} {:<10} {:<8}",
                    "ID", "Name", "Type", "State", "Pressure", "Tilt");
                for p in &pens {
                    shell_println!("{:<4} {:<20} {:<10} {:<12} {:<10} ({},{})",
                        p.id, p.name, p.pen_type.label(), p.state.label(),
                        p.pressure, p.tilt_x, p.tilt_y);
                }
            }
        }
        "register" | "add" => {
            let name = parts.get(1).copied().unwrap_or("");
            let type_str = parts.get(2).copied().unwrap_or("stylus");
            let pen_type = match type_str {
                "airbrush" => peninput::PenType::AirBrush,
                "artpen" => peninput::PenType::ArtPen,
                "eraser" => peninput::PenType::Eraser,
                "touch" => peninput::PenType::Touch,
                _ => peninput::PenType::Stylus,
            };
            if name.is_empty() {
                shell_println!("Usage: pen add <name> [stylus|airbrush|artpen|eraser|touch]");
            } else {
                let caps = peninput::PenCapabilities {
                    pressure: true, tilt: true, rotation: false,
                    eraser_tip: pen_type == peninput::PenType::Eraser, buttons: 2,
                };
                match peninput::register_pen(name, pen_type, caps) {
                    Ok(id) => shell_println!("Registered pen {} '{}'.", id, name),
                    Err(e) => shell_println!("Error: {:?}", e),
                }
            }
        }
        "rm" | "unregister" => {
            if let Some(id_str) = parts.get(1) {
                if let Ok(id) = id_str.parse::<u32>() {
                    match peninput::unregister_pen(id) {
                        Ok(()) => shell_println!("Unregistered pen {}.", id),
                        Err(e) => shell_println!("Error: {:?}", e),
                    }
                }
            } else { shell_println!("Usage: pen rm <id>"); }
        }
        "sim" | "simulate" => {
            let pen_id = parts.get(1).and_then(|s| s.parse::<u32>().ok()).unwrap_or(0);
            let action = parts.get(2).copied().unwrap_or("contact");
            if pen_id == 0 {
                shell_println!("Usage: pen sim <pen_id> <proxin|proxout|contact|release|move>");
            } else {
                match action {
                    "proxin" => { peninput::proximity_in(pen_id).ok(); shell_println!("Proximity in."); }
                    "proxout" => { peninput::proximity_out(pen_id).ok(); shell_println!("Proximity out."); }
                    "contact" => {
                        let x = parts.get(3).and_then(|s| s.parse::<u16>().ok()).unwrap_or(16000);
                        let y = parts.get(4).and_then(|s| s.parse::<u16>().ok()).unwrap_or(8000);
                        let p = parts.get(5).and_then(|s| s.parse::<u16>().ok()).unwrap_or(2048);
                        peninput::contact(pen_id, x, y, p).ok();
                        shell_println!("Contact at ({},{}) pressure {}.", x, y, p);
                    }
                    "release" => { peninput::release(pen_id).ok(); shell_println!("Released."); }
                    "move" => {
                        let x = parts.get(3).and_then(|s| s.parse::<u16>().ok()).unwrap_or(16000);
                        let y = parts.get(4).and_then(|s| s.parse::<u16>().ok()).unwrap_or(8000);
                        let p = parts.get(5).and_then(|s| s.parse::<u16>().ok()).unwrap_or(2048);
                        peninput::report_move(pen_id, x, y, p, 0, 0).ok();
                        shell_println!("Moved to ({},{}).", x, y);
                    }
                    _ => shell_println!("Actions: proxin, proxout, contact, release, move"),
                }
            }
        }
        "map" => {
            let pen_id = parts.get(1).and_then(|s| s.parse::<u32>().ok()).unwrap_or(0);
            let btn = parts.get(2).and_then(|s| s.parse::<u8>().ok()).unwrap_or(0);
            let action = parts.get(3).copied().unwrap_or("");
            if pen_id == 0 || action.is_empty() {
                shell_println!("Usage: pen map <pen_id> <button> <action>");
            } else {
                match peninput::set_button_mapping(pen_id, btn, action) {
                    Ok(()) => shell_println!("Button {} → '{}'.", btn, action),
                    Err(e) => shell_println!("Error: {:?}", e),
                }
            }
        }
        "events" => {
            let count = parts.get(1).and_then(|s| s.parse::<usize>().ok()).unwrap_or(20);
            let events = peninput::list_events(count);
            if events.is_empty() {
                shell_println!("No pen events.");
            } else {
                for e in &events {
                    shell_println!("[{}] pen {} {} at ({},{}) p={}",
                        e.id, e.pen_id, e.event_type.label(), e.x, e.y, e.pressure);
                }
            }
        }
        "stats" => {
            let (pens, events, strokes, ops) = peninput::stats();
            shell_println!("Pens: {}, Events: {}, Strokes: {}", pens, events, strokes);
            shell_println!("Ops: {}", ops);
        }
        "test" => { peninput::self_test(); shell_println!("Pen input self-test complete."); }
        "init" => { peninput::init_defaults(); shell_println!("Pen input initialized."); }
        _ => {
            shell_println!("peninput (pen) — stylus/pen input");
            shell_println!("  list / show                   List pens");
            shell_println!("  add <name> [type]             Register pen");
            shell_println!("  rm <id>                       Unregister");
            shell_println!("  sim <id> <action> [x] [y] [p] Simulate input");
            shell_println!("  map <id> <button> <action>    Map button");
            shell_println!("  events [count]                Show events");
            shell_println!("  stats / test / init");
        }
    }
}

/// `brightness` / `bright` — display brightness control.
fn cmd_brightness(args: &str) {
    use crate::fs::brightness;
    let parts: Vec<&str> = args.split_whitespace().collect();
    let sub = parts.first().copied().unwrap_or("");
    match sub {
        "" | "show" | "list" => {
            brightness::init_defaults();
            let displays = brightness::list_displays();
            if displays.is_empty() {
                shell_println!("No displays.");
            } else {
                shell_println!("{:<4} {:<20} {:<6} {:<10} {:<6} {:<6}",
                    "ID", "Name", "Level", "Mode", "Min", "Dim");
                for d in &displays {
                    shell_println!("{:<4} {:<20} {:<6} {:<10} {:<6} {:<6}",
                        d.id, d.name, d.brightness, d.mode.label(),
                        d.min_brightness, if d.dimmed { "Yes" } else { "No" });
                }
            }
        }
        "set" => {
            let id = parts.get(1).and_then(|s| s.parse::<u32>().ok()).unwrap_or(1);
            let level = parts.get(2).and_then(|s| s.parse::<u32>().ok()).unwrap_or(0);
            if level == 0 && parts.get(2).is_none() {
                shell_println!("Usage: bright set [display_id] <level>");
            } else {
                match brightness::set_brightness(id, level) {
                    Ok(()) => shell_println!("Brightness → {}%", level),
                    Err(e) => shell_println!("Error: {:?}", e),
                }
            }
        }
        "up" => {
            let id = parts.get(1).and_then(|s| s.parse::<u32>().ok()).unwrap_or(1);
            let step = parts.get(2).and_then(|s| s.parse::<u32>().ok()).unwrap_or(10);
            match brightness::brightness_up(id, step) {
                Ok(new) => shell_println!("Brightness → {}%", new),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "down" => {
            let id = parts.get(1).and_then(|s| s.parse::<u32>().ok()).unwrap_or(1);
            let step = parts.get(2).and_then(|s| s.parse::<u32>().ok()).unwrap_or(10);
            match brightness::brightness_down(id, step) {
                Ok(new) => shell_println!("Brightness → {}%", new),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "mode" => {
            let id = parts.get(1).and_then(|s| s.parse::<u32>().ok()).unwrap_or(1);
            let mode_str = parts.get(2).copied().unwrap_or("");
            let mode = match mode_str {
                "manual" | "man" => brightness::BrightnessMode::Manual,
                "auto" | "automatic" => brightness::BrightnessMode::Automatic,
                "battery" | "saver" => brightness::BrightnessMode::BatterySaver,
                _ => { shell_println!("Modes: manual, auto, battery"); return; }
            };
            brightness::set_mode(id, mode).ok();
            shell_println!("Mode → {}", mode.label());
        }
        "dim" => {
            let id = parts.get(1).and_then(|s| s.parse::<u32>().ok()).unwrap_or(1);
            brightness::dim(id).ok();
            shell_println!("Display {} dimmed.", id);
        }
        "undim" => {
            let id = parts.get(1).and_then(|s| s.parse::<u32>().ok()).unwrap_or(1);
            brightness::undim(id).ok();
            shell_println!("Display {} undimmed.", id);
        }
        "stats" => {
            let (count, adj, auto, ops) = brightness::stats();
            shell_println!("Displays: {}, Adjustments: {}, Auto: {}, Ops: {}", count, adj, auto, ops);
        }
        "test" => { brightness::self_test(); shell_println!("Brightness self-test complete."); }
        "init" => { brightness::init_defaults(); shell_println!("Brightness initialized."); }
        _ => {
            shell_println!("brightness (bright) — display brightness");
            shell_println!("  show / list         List displays");
            shell_println!("  set [id] <level>    Set brightness");
            shell_println!("  up [id] [step]      Increase");
            shell_println!("  down [id] [step]    Decrease");
            shell_println!("  mode [id] <type>    manual/auto/battery");
            shell_println!("  dim / undim [id]    Dim for idle");
            shell_println!("  stats / test / init");
        }
    }
}

/// `quicksettings` / `qs` — quick settings panel.
fn cmd_quicksettings(args: &str) {
    use crate::fs::quicksettings;
    use alloc::format;
    let parts: Vec<&str> = args.split_whitespace().collect();
    let sub = parts.first().copied().unwrap_or("");
    match sub {
        "" | "show" | "list" => {
            quicksettings::init_defaults();
            let tiles = quicksettings::get_tiles();
            if tiles.is_empty() {
                shell_println!("No tiles.");
            } else {
                shell_println!("{:<4} {:<18} {:<8} {:<6} {:<20}",
                    "ID", "Name", "Type", "Value", "Subtitle");
                for t in &tiles {
                    let val = match t.tile_type {
                        quicksettings::TileType::Toggle => {
                            if t.enabled { String::from("On") } else { String::from("Off") }
                        }
                        quicksettings::TileType::Slider => format!("{}%", t.value),
                        quicksettings::TileType::Action => String::from("—"),
                    };
                    shell_println!("{:<4} {:<18} {:<8} {:<6} {:<20}",
                        t.id, t.name, t.tile_type.label(), val, t.subtitle);
                }
            }
        }
        "toggle" => {
            if let Some(id_str) = parts.get(1) {
                if let Ok(id) = id_str.parse::<u32>() {
                    match quicksettings::toggle(id) {
                        Ok(on) => shell_println!("Toggled → {}", if on { "On" } else { "Off" }),
                        Err(e) => shell_println!("Error: {:?}", e),
                    }
                }
            } else { shell_println!("Usage: qs toggle <tile_id>"); }
        }
        "set" => {
            let id = parts.get(1).and_then(|s| s.parse::<u32>().ok()).unwrap_or(0);
            let val = parts.get(2).and_then(|s| s.parse::<u32>().ok()).unwrap_or(0);
            if id == 0 { shell_println!("Usage: qs set <tile_id> <value>"); }
            else {
                match quicksettings::set_value(id, val) {
                    Ok(()) => shell_println!("Set to {}%", val),
                    Err(e) => shell_println!("Error: {:?}", e),
                }
            }
        }
        "add" => {
            let name = parts.get(1).copied().unwrap_or("");
            let type_str = parts.get(2).copied().unwrap_or("toggle");
            let tile_type = match type_str {
                "slider" => quicksettings::TileType::Slider,
                "action" => quicksettings::TileType::Action,
                _ => quicksettings::TileType::Toggle,
            };
            if name.is_empty() {
                shell_println!("Usage: qs add <name> [toggle|slider|action]");
            } else {
                match quicksettings::add_tile(name, name, tile_type) {
                    Ok(id) => shell_println!("Added tile {} '{}'", id, name),
                    Err(e) => shell_println!("Error: {:?}", e),
                }
            }
        }
        "rm" | "remove" => {
            if let Some(id_str) = parts.get(1) {
                if let Ok(id) = id_str.parse::<u32>() {
                    quicksettings::remove_tile(id).ok();
                    shell_println!("Removed tile {}.", id);
                }
            } else { shell_println!("Usage: qs rm <id>"); }
        }
        "stats" => {
            let (tiles, toggles, adj, ops) = quicksettings::stats();
            shell_println!("Tiles: {}, Toggles: {}, Adjustments: {}, Ops: {}", tiles, toggles, adj, ops);
        }
        "test" => { quicksettings::self_test(); shell_println!("Quick settings self-test complete."); }
        "init" => { quicksettings::init_defaults(); shell_println!("Quick settings initialized."); }
        _ => {
            shell_println!("quicksettings (qs) — quick settings panel");
            shell_println!("  show / list         List tiles");
            shell_println!("  toggle <id>         Toggle on/off");
            shell_println!("  set <id> <value>    Set slider value");
            shell_println!("  add <name> [type]   Add tile");
            shell_println!("  rm <id>             Remove tile");
            shell_println!("  stats / test / init");
        }
    }
}

/// `volumeosd` / `vosd` — on-screen volume/brightness display.
fn cmd_volumeosd(args: &str) {
    use crate::fs::volumeosd;
    let parts: Vec<&str> = args.split_whitespace().collect();
    let sub = parts.first().copied().unwrap_or("");
    match sub {
        "" | "show" | "active" => {
            volumeosd::init_defaults();
            match volumeosd::get_active() {
                Some(osd) => shell_println!("Active: {} {} — {}% {}",
                    osd.osd_type.icon(), osd.osd_type.label(), osd.value, osd.label),
                None => shell_println!("No active OSD."),
            }
        }
        "volume" | "vol" => {
            let level = parts.get(1).and_then(|s| s.parse::<u32>().ok()).unwrap_or(50);
            let muted = parts.get(2).copied() == Some("mute");
            match volumeosd::show_volume(level, muted) {
                Ok(id) => shell_println!("OSD {} — Volume {}%{}", id, level, if muted { " (muted)" } else { "" }),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "bright" | "brightness" => {
            let level = parts.get(1).and_then(|s| s.parse::<u32>().ok()).unwrap_or(50);
            match volumeosd::show_brightness(level) {
                Ok(id) => shell_println!("OSD {} — Brightness {}%", id, level),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "custom" => {
            let label = parts.get(1).copied().unwrap_or("Info");
            let text = if parts.len() > 2 { parts[2..].join(" ") } else { String::new() };
            match volumeosd::show(volumeosd::OsdType::Custom, 0, label, &text) {
                Ok(id) => shell_println!("OSD {} — {}: {}", id, label, text),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "dismiss" => {
            volumeosd::dismiss().ok();
            shell_println!("OSD dismissed.");
        }
        "position" | "pos" => {
            let pos_str = parts.get(1).copied().unwrap_or("");
            let pos = match pos_str {
                "top" | "tc" => volumeosd::OsdPosition::TopCenter,
                "tr" => volumeosd::OsdPosition::TopRight,
                "center" | "c" => volumeosd::OsdPosition::Center,
                "bottom" | "bc" => volumeosd::OsdPosition::BottomCenter,
                "bl" => volumeosd::OsdPosition::BottomLeft,
                _ => { shell_println!("Positions: top, tr, center, bottom, bl"); return; }
            };
            volumeosd::set_position(pos).ok();
            shell_println!("Position → {}", pos.label());
        }
        "enable" => { volumeosd::set_enabled(true).ok(); shell_println!("OSD enabled."); }
        "disable" => { volumeosd::set_enabled(false).ok(); shell_println!("OSD disabled."); }
        "history" => {
            let history = volumeosd::list_history(10);
            if history.is_empty() { shell_println!("No OSD history."); }
            else {
                for h in &history {
                    shell_println!("[{}] {} {}% {}", h.id, h.osd_type.label(), h.value, h.label);
                }
            }
        }
        "stats" => {
            let (total, enabled, pos, ops) = volumeosd::stats();
            shell_println!("Shown: {}, Enabled: {}, Position: {}, Ops: {}", total, enabled, pos, ops);
        }
        "test" => { volumeosd::self_test(); shell_println!("Volume OSD self-test complete."); }
        "init" => { volumeosd::init_defaults(); shell_println!("Volume OSD initialized."); }
        _ => {
            shell_println!("volumeosd (vosd) — on-screen display");
            shell_println!("  show                Active OSD");
            shell_println!("  vol <level> [mute]  Show volume");
            shell_println!("  bright <level>      Show brightness");
            shell_println!("  custom <label> [text] Custom OSD");
            shell_println!("  dismiss             Hide OSD");
            shell_println!("  pos <position>      Set position");
            shell_println!("  enable / disable    Toggle OSD");
            shell_println!("  history             Recent OSDs");
            shell_println!("  stats / test / init");
        }
    }
}

/// `netdiag` / `ndiag` — network diagnostics.
fn cmd_netdiag(args: &str) {
    use crate::fs::netdiag;
    let parts: Vec<&str> = args.split_whitespace().collect();
    let sub = parts.first().copied().unwrap_or("");
    match sub {
        "" | "show" | "status" => {
            netdiag::init_defaults();
            let status = netdiag::connectivity_check().unwrap_or(netdiag::ConnectivityStatus::Disconnected);
            shell_println!("Connectivity: {}", status.label());
            let results = netdiag::list_results(5);
            if !results.is_empty() {
                shell_println!("\nRecent:");
                for r in &results {
                    shell_println!("  [{}] {} {} — {} ({}us)",
                        r.id, r.diag_type.label(), r.target, r.status.label(), r.latency_us);
                }
            }
        }
        "ping" => {
            let host = parts.get(1).copied().unwrap_or("127.0.0.1");
            let count = parts.get(2).and_then(|s| s.parse::<u32>().ok()).unwrap_or(4);
            match netdiag::ping(host, count) {
                Ok(r) => {
                    shell_println!("PING {} — {} ({})us", host, r.status.label(), r.latency_us);
                    shell_println!("{}", r.info);
                }
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "trace" | "traceroute" => {
            let host = parts.get(1).copied().unwrap_or("example.com");
            match netdiag::traceroute(host) {
                Ok(r) => {
                    shell_println!("Traceroute to {} ({} hops):", host, r.hops.len());
                    for h in &r.hops {
                        let status = if h.reached { "OK" } else { "***" };
                        shell_println!("  {:>2}  {:<20} {:<15} {}us {}",
                            h.hop_number, h.hostname, h.address, h.latency_us, status);
                    }
                }
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "dns" | "lookup" => {
            let name = parts.get(1).copied().unwrap_or("localhost");
            match netdiag::dns_lookup(name) {
                Ok(r) => shell_println!("{} → {} ({}us)", name, r.resolved, r.latency_us),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "results" => {
            let count = parts.get(1).and_then(|s| s.parse::<usize>().ok()).unwrap_or(20);
            let results = netdiag::list_results(count);
            if results.is_empty() { shell_println!("No results."); }
            else {
                for r in &results {
                    shell_println!("[{}] {} {} — {} {}",
                        r.id, r.diag_type.label(), r.target, r.status.label(), r.info);
                }
            }
        }
        "clear" => {
            netdiag::clear_results().ok();
            shell_println!("Results cleared.");
        }
        "stats" => {
            let (count, pings, traces, lookups, ops) = netdiag::stats();
            shell_println!("Results: {}, Pings: {}, Traces: {}, Lookups: {}", count, pings, traces, lookups);
            shell_println!("Ops: {}", ops);
        }
        "test" => { netdiag::self_test(); shell_println!("Network diagnostics self-test complete."); }
        "init" => { netdiag::init_defaults(); shell_println!("Network diagnostics initialized."); }
        _ => {
            shell_println!("netdiag (ndiag) — network diagnostics");
            shell_println!("  status              Connectivity check");
            shell_println!("  ping <host> [count] Ping host");
            shell_println!("  trace <host>        Traceroute");
            shell_println!("  dns <name>          DNS lookup");
            shell_println!("  results [count]     Recent results");
            shell_println!("  clear               Clear results");
            shell_println!("  stats / test / init");
        }
    }
}

/// `sharesheet` / `ssheet` — cross-app content sharing.
fn cmd_sharesheet(args: &str) {
    use crate::fs::sharesheet;
    let parts: Vec<&str> = args.split_whitespace().collect();
    let sub = parts.first().copied().unwrap_or("");
    match sub {
        "init" => {
            sharesheet::init_defaults();
            shell_println!("Share sheet initialized");
        }
        "list" => {
            let targets = sharesheet::list_targets();
            if targets.is_empty() {
                shell_println!("No share targets registered");
            } else {
                shell_println!("{:<4} {:<15} {:<20} {:<6} {}", "ID", "App", "Display Name", "Uses", "Types");
                for t in &targets {
                    let types: Vec<&str> = t.supported_types.iter().map(|ct| ct.label()).collect();
                    shell_println!("{:<4} {:<15} {:<20} {:<6} {}", t.id, t.app_name, t.display_name, t.use_count, types.join(", "));
                }
            }
        }
        "targets" => {
            let ct = match parts.get(1).copied().unwrap_or("text") {
                "url" => sharesheet::ContentType::Url,
                "image" | "img" => sharesheet::ContentType::Image,
                "file" => sharesheet::ContentType::File,
                "video" => sharesheet::ContentType::Video,
                "audio" => sharesheet::ContentType::Audio,
                "contact" => sharesheet::ContentType::Contact,
                "location" | "loc" => sharesheet::ContentType::Location,
                _ => sharesheet::ContentType::Text,
            };
            let targets = sharesheet::get_targets(ct);
            if targets.is_empty() {
                shell_println!("No targets for {}", ct.label());
            } else {
                shell_println!("Targets for {}:", ct.label());
                for t in &targets {
                    shell_println!("  #{}: {} (uses: {})", t.id, t.display_name, t.use_count);
                }
            }
        }
        "share" => {
            if parts.len() < 3 {
                shell_println!("Usage: sharesheet share <target_id> <data...>");
                return;
            }
            let tid: u32 = match parts.get(1).unwrap_or(&"0").parse() {
                Ok(v) => v,
                Err(_) => { shell_println!("Invalid target ID"); return; }
            };
            let data: String = parts[2..].join(" ");
            match sharesheet::share_to(tid, sharesheet::ContentType::Text, &data) {
                Ok(aid) => shell_println!("Shared action #{} to target #{}", aid, tid),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "register" => {
            let name = parts.get(1).copied().unwrap_or("custom");
            let display = parts.get(2).copied().unwrap_or(name);
            match sharesheet::register_target(name, display, alloc::vec![sharesheet::ContentType::Text, sharesheet::ContentType::Url]) {
                Ok(id) => shell_println!("Registered target #{}: {}", id, display),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "unregister" => {
            let id: u32 = match parts.get(1).unwrap_or(&"0").parse() {
                Ok(v) => v,
                Err(_) => { shell_println!("Invalid target ID"); return; }
            };
            match sharesheet::unregister_target(id) {
                Ok(()) => shell_println!("Unregistered target #{}", id),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "history" => {
            let count: usize = parts.get(1).unwrap_or(&"10").parse().unwrap_or(10);
            let history = sharesheet::list_history(count);
            if history.is_empty() {
                shell_println!("No share history");
            } else {
                for h in &history {
                    shell_println!("  #{}: {} → {} ({})", h.id, h.content_type.label(), h.target_name, h.data_preview);
                }
            }
        }
        "stats" => {
            let (targets, shares, ops) = sharesheet::stats();
            shell_println!("Targets: {}, Total shares: {}, Ops: {}", targets, shares, ops);
        }
        "test" => sharesheet::self_test(),
        _ => {
            shell_println!("Usage: sharesheet <command>");
            shell_println!("  list                List all targets");
            shell_println!("  targets [type]      Targets for content type");
            shell_println!("  share <id> <data>   Share text to target");
            shell_println!("  register <app> [name]  Register target");
            shell_println!("  unregister <id>     Remove target");
            shell_println!("  history [count]     Recent shares");
            shell_println!("  stats / test / init");
        }
    }
}

/// `oobe` / `setup` — out-of-box experience setup wizard.
fn cmd_oobe(args: &str) {
    use crate::fs::oobe;
    let parts: Vec<&str> = args.split_whitespace().collect();
    let sub = parts.first().copied().unwrap_or("");
    match sub {
        "init" => {
            oobe::init_defaults();
            shell_println!("OOBE initialized");
        }
        "status" => {
            let step = oobe::current_step();
            let completed = oobe::is_completed();
            shell_println!("Current step: {} ({})", step.label(), step.step_number());
            shell_println!("Completed: {}", completed);
            let skipped = oobe::skipped_steps();
            if !skipped.is_empty() {
                let names: Vec<&str> = skipped.iter().map(|s| s.label()).collect();
                shell_println!("Skipped: {}", names.join(", "));
            }
        }
        "next" | "advance" => {
            match oobe::advance() {
                Ok(step) => shell_println!("Advanced to: {} (step {})", step.label(), step.step_number()),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "back" => {
            match oobe::go_back() {
                Ok(step) => shell_println!("Went back to: {} (step {})", step.label(), step.step_number()),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "skip" => {
            match oobe::skip() {
                Ok(step) => shell_println!("Skipped to: {} (step {})", step.label(), step.step_number()),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "lang" => {
            let language = parts.get(1).copied().unwrap_or("en-US");
            let region = parts.get(2).copied().unwrap_or("US");
            match oobe::set_language(language, region) {
                Ok(()) => shell_println!("Language: {}, Region: {}", language, region),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "keyboard" | "kb" => {
            let layout = parts.get(1).copied().unwrap_or("us");
            match oobe::set_keyboard(layout) {
                Ok(()) => shell_println!("Keyboard layout: {}", layout),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "user" => {
            let username = parts.get(1).copied().unwrap_or("admin");
            let hostname = parts.get(2).copied().unwrap_or("");
            match oobe::set_user(username, hostname) {
                Ok(()) => shell_println!("User: {}, Host: {}", username, if hostname.is_empty() { "(default)" } else { hostname }),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "network" | "wifi" => {
            let ssid = parts.get(1).copied().unwrap_or("");
            match oobe::set_network(ssid) {
                Ok(()) => shell_println!("WiFi SSID: {}", if ssid.is_empty() { "(none)" } else { ssid }),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "privacy" => {
            let diag = parts.get(1).copied().unwrap_or("off") == "on";
            let loc = parts.get(2).copied().unwrap_or("off") == "on";
            let upd = parts.get(3).copied().unwrap_or("on") == "on";
            match oobe::set_privacy(diag, loc, upd) {
                Ok(()) => shell_println!("Diagnostics: {}, Location: {}, Auto-updates: {}", diag, loc, upd),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "theme" => {
            let t = parts.get(1).copied().unwrap_or("Default");
            match oobe::set_theme(t) {
                Ok(()) => shell_println!("Theme: {}", t),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "choices" => {
            match oobe::get_choices() {
                Some(c) => {
                    shell_println!("Language: {} ({})", c.language, c.region);
                    shell_println!("Keyboard: {}", c.keyboard_layout);
                    shell_println!("User: {} @ {}", c.username, c.hostname);
                    shell_println!("WiFi: {}", if c.wifi_ssid.is_empty() { "(none)" } else { &c.wifi_ssid });
                    shell_println!("Diagnostics: {}, Location: {}, Updates: {}", c.send_diagnostics, c.location_services, c.auto_updates);
                    shell_println!("Theme: {}", c.theme);
                }
                None => shell_println!("OOBE not initialized"),
            }
        }
        "complete" => {
            match oobe::force_complete() {
                Ok(()) => shell_println!("OOBE force-completed"),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "stats" => {
            let (step, completed, skipped, ops) = oobe::stats();
            shell_println!("Step: {}, Completed: {}, Skipped: {}, Ops: {}", step, completed, skipped, ops);
        }
        "test" => oobe::self_test(),
        _ => {
            shell_println!("Usage: oobe <command>");
            shell_println!("  status              Current state");
            shell_println!("  next / advance      Go to next step");
            shell_println!("  back                Go to previous step");
            shell_println!("  skip                Skip current step");
            shell_println!("  lang <lang> [region] Set language");
            shell_println!("  keyboard <layout>   Set keyboard");
            shell_println!("  user <name> [host]  Set user account");
            shell_println!("  network <ssid>      Set WiFi");
            shell_println!("  privacy <d> <l> <u> Set privacy (on/off)");
            shell_println!("  theme <name>        Set theme");
            shell_println!("  choices             Show all choices");
            shell_println!("  complete            Force complete");
            shell_println!("  stats / test / init");
        }
    }
}

/// `hdrdisplay` / `hdr` — HDR display management.
fn cmd_hdrdisplay(args: &str) {
    use crate::fs::hdrdisplay;
    let parts: Vec<&str> = args.split_whitespace().collect();
    let sub = parts.first().copied().unwrap_or("");
    match sub {
        "init" => {
            hdrdisplay::init_defaults();
            shell_println!("HDR display initialized");
        }
        "list" => {
            let displays = hdrdisplay::list_displays();
            if displays.is_empty() {
                shell_println!("No HDR displays");
            } else {
                for d in &displays {
                    let standards: Vec<&str> = d.supported_standards.iter().map(|s| s.label()).collect();
                    shell_println!("#{}: {} [{}]", d.id, d.name, if d.hdr_enabled { d.active_standard.label() } else { "SDR" });
                    shell_println!("    Peak: {} nits, Depth: {}-bit, Color: {}", d.peak_nits, d.bit_depth, d.color_space.label());
                    shell_println!("    Tone map: {}, SDR boost: {}%, Supported: {}", d.tone_mapping.label(), d.sdr_boost, standards.join(", "));
                }
            }
        }
        "enable" => {
            let id: u32 = match parts.get(1).unwrap_or(&"1").parse() {
                Ok(v) => v,
                Err(_) => { shell_println!("Invalid display ID"); return; }
            };
            let std = match parts.get(2).copied().unwrap_or("hdr10") {
                "hdr10plus" | "hdr10+" => hdrdisplay::HdrStandard::Hdr10Plus,
                "dolbyvision" | "dv" => hdrdisplay::HdrStandard::DolbyVision,
                "hlg" => hdrdisplay::HdrStandard::Hlg,
                _ => hdrdisplay::HdrStandard::Hdr10,
            };
            match hdrdisplay::enable_hdr(id, std) {
                Ok(()) => shell_println!("HDR enabled on display #{}: {}", id, std.label()),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "disable" => {
            let id: u32 = match parts.get(1).unwrap_or(&"1").parse() {
                Ok(v) => v,
                Err(_) => { shell_println!("Invalid display ID"); return; }
            };
            match hdrdisplay::disable_hdr(id) {
                Ok(()) => shell_println!("HDR disabled on display #{}", id),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "tonemap" | "tm" => {
            let id: u32 = match parts.get(1).unwrap_or(&"1").parse() {
                Ok(v) => v,
                Err(_) => { shell_println!("Invalid display ID"); return; }
            };
            let tm = match parts.get(2).copied().unwrap_or("auto") {
                "aces" | "filmic" => hdrdisplay::ToneMapping::AcesFilmic,
                "reinhard" => hdrdisplay::ToneMapping::Reinhard,
                "hable" => hdrdisplay::ToneMapping::Hable,
                "none" | "off" => hdrdisplay::ToneMapping::None,
                _ => hdrdisplay::ToneMapping::Auto,
            };
            match hdrdisplay::set_tone_mapping(id, tm) {
                Ok(()) => shell_println!("Tone mapping: {}", tm.label()),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "sdrboost" | "boost" => {
            let id: u32 = match parts.get(1).unwrap_or(&"1").parse() {
                Ok(v) => v,
                Err(_) => { shell_println!("Invalid display ID"); return; }
            };
            let boost: u32 = parts.get(2).unwrap_or(&"50").parse().unwrap_or(50);
            match hdrdisplay::set_sdr_boost(id, boost) {
                Ok(()) => shell_println!("SDR boost: {}%", boost.min(100)),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "colorspace" | "cs" => {
            let id: u32 = match parts.get(1).unwrap_or(&"1").parse() {
                Ok(v) => v,
                Err(_) => { shell_println!("Invalid display ID"); return; }
            };
            let cs = match parts.get(2).copied().unwrap_or("srgb") {
                "bt2020" | "2020" => hdrdisplay::ColorSpace::Bt2020,
                "dcip3" | "p3" => hdrdisplay::ColorSpace::DciP3,
                "adobergb" | "adobe" => hdrdisplay::ColorSpace::AdobeRgb,
                _ => hdrdisplay::ColorSpace::Srgb,
            };
            match hdrdisplay::set_color_space(id, cs) {
                Ok(()) => shell_println!("Color space: {}", cs.label()),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "register" => {
            let name = parts.get(1).copied().unwrap_or("Monitor");
            let nits: u32 = parts.get(2).unwrap_or(&"1000").parse().unwrap_or(1000);
            match hdrdisplay::register_display(name, nits, alloc::vec![hdrdisplay::HdrStandard::Hdr10, hdrdisplay::HdrStandard::Hlg]) {
                Ok(id) => shell_println!("Registered display #{}: {} ({} nits)", id, name, nits),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "stats" => {
            let (count, enabled, switches, ops) = hdrdisplay::stats();
            shell_println!("Displays: {}, HDR enabled: {}, Switches: {}, Ops: {}", count, enabled, switches, ops);
        }
        "test" => hdrdisplay::self_test(),
        _ => {
            shell_println!("Usage: hdrdisplay <command>");
            shell_println!("  list                   List displays");
            shell_println!("  enable <id> [standard] Enable HDR");
            shell_println!("  disable <id>           Disable HDR");
            shell_println!("  tonemap <id> <algo>    Set tone mapping");
            shell_println!("  sdrboost <id> <0-100>  SDR brightness boost");
            shell_println!("  colorspace <id> <cs>   Set color space");
            shell_println!("  register <name> [nits] Register display");
            shell_println!("  stats / test / init");
        }
    }
}

/// `surroundsound` / `ssound` — spatial audio and surround configuration.
fn cmd_surroundsound(args: &str) {
    use crate::fs::surroundsound;
    let parts: Vec<&str> = args.split_whitespace().collect();
    let sub = parts.first().copied().unwrap_or("");
    match sub {
        "init" => {
            surroundsound::init_defaults();
            shell_println!("Surround sound initialized");
        }
        "list" => {
            let configs = surroundsound::list_configs();
            if configs.is_empty() {
                shell_println!("No surround configs");
            } else {
                for c in &configs {
                    shell_println!("#{}: {} — {} ({} channels)", c.id, c.device_name, c.layout.label(), c.layout.channel_count());
                    shell_println!("    Virtual surround: {}, Crossover: {} Hz, LFE: {}", c.virtual_surround, c.crossover_hz, c.lfe_enabled);
                    let speakers: Vec<&str> = c.speakers.iter().map(|s| s.channel.label()).collect();
                    shell_println!("    Speakers: {}", speakers.join(", "));
                }
            }
        }
        "create" => {
            let name = parts.get(1).copied().unwrap_or("Speaker");
            let layout = match parts.get(2).copied().unwrap_or("stereo") {
                "mono" | "1.0" => surroundsound::SpeakerLayout::Mono,
                "2.1" => surroundsound::SpeakerLayout::Surround21,
                "5.1" => surroundsound::SpeakerLayout::Surround51,
                "7.1" => surroundsound::SpeakerLayout::Surround71,
                "atmos" | "7.1.4" => surroundsound::SpeakerLayout::Atmos714,
                _ => surroundsound::SpeakerLayout::Stereo,
            };
            match surroundsound::create_config(name, layout) {
                Ok(id) => shell_println!("Created config #{}: {} ({})", id, name, layout.label()),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "layout" => {
            let id: u32 = match parts.get(1).unwrap_or(&"1").parse() {
                Ok(v) => v,
                Err(_) => { shell_println!("Invalid config ID"); return; }
            };
            let layout = match parts.get(2).copied().unwrap_or("stereo") {
                "mono" | "1.0" => surroundsound::SpeakerLayout::Mono,
                "2.1" => surroundsound::SpeakerLayout::Surround21,
                "5.1" => surroundsound::SpeakerLayout::Surround51,
                "7.1" => surroundsound::SpeakerLayout::Surround71,
                "atmos" | "7.1.4" => surroundsound::SpeakerLayout::Atmos714,
                _ => surroundsound::SpeakerLayout::Stereo,
            };
            match surroundsound::set_layout(id, layout) {
                Ok(()) => shell_println!("Config #{} → {}", id, layout.label()),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "calibrate" | "cal" => {
            let id: u32 = match parts.get(1).unwrap_or(&"1").parse() {
                Ok(v) => v,
                Err(_) => { shell_println!("Invalid config ID"); return; }
            };
            let ch = match parts.get(2).copied().unwrap_or("center") {
                "fl" | "frontleft" => surroundsound::SpeakerChannel::FrontLeft,
                "fr" | "frontright" => surroundsound::SpeakerChannel::FrontRight,
                "sub" | "subwoofer" => surroundsound::SpeakerChannel::Subwoofer,
                "rl" | "rearleft" => surroundsound::SpeakerChannel::RearLeft,
                "rr" | "rearright" => surroundsound::SpeakerChannel::RearRight,
                "sl" | "sideleft" => surroundsound::SpeakerChannel::SideLeft,
                "sr" | "sideright" => surroundsound::SpeakerChannel::SideRight,
                _ => surroundsound::SpeakerChannel::Center,
            };
            let trim: i32 = parts.get(3).unwrap_or(&"0").parse().unwrap_or(0);
            let dist: u32 = parts.get(4).unwrap_or(&"200").parse().unwrap_or(200);
            match surroundsound::calibrate_speaker(id, ch, trim, dist) {
                Ok(()) => shell_println!("Calibrated {} on #{}: trim={} cb, dist={} cm", ch.label(), id, trim.clamp(-600, 600), dist),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "virtual" | "vs" => {
            let id: u32 = match parts.get(1).unwrap_or(&"1").parse() {
                Ok(v) => v,
                Err(_) => { shell_println!("Invalid config ID"); return; }
            };
            let enabled = parts.get(2).copied().unwrap_or("on") != "off";
            match surroundsound::set_virtual_surround(id, enabled) {
                Ok(()) => shell_println!("Virtual surround #{}: {}", id, if enabled { "on" } else { "off" }),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "crossover" | "xo" => {
            let id: u32 = match parts.get(1).unwrap_or(&"1").parse() {
                Ok(v) => v,
                Err(_) => { shell_println!("Invalid config ID"); return; }
            };
            let hz: u32 = parts.get(2).unwrap_or(&"80").parse().unwrap_or(80);
            match surroundsound::set_crossover(id, hz) {
                Ok(()) => shell_println!("Crossover #{}: {} Hz", id, hz.clamp(40, 200)),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "remove" => {
            let id: u32 = match parts.get(1).unwrap_or(&"0").parse() {
                Ok(v) => v,
                Err(_) => { shell_println!("Invalid config ID"); return; }
            };
            match surroundsound::remove_config(id) {
                Ok(()) => shell_println!("Removed config #{}", id),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "stats" => {
            let (configs, total, cals, ops) = surroundsound::stats();
            shell_println!("Configs: {}, Total: {}, Calibrations: {}, Ops: {}", configs, total, cals, ops);
        }
        "test" => surroundsound::self_test(),
        _ => {
            shell_println!("Usage: surroundsound <command>");
            shell_println!("  list                   List configs");
            shell_println!("  create <name> <layout> Create config");
            shell_println!("  layout <id> <layout>   Change layout");
            shell_println!("  calibrate <id> <ch> <trim> <dist>");
            shell_println!("  virtual <id> [on|off]  Virtual surround");
            shell_println!("  crossover <id> <hz>    Set crossover freq");
            shell_println!("  remove <id>            Remove config");
            shell_println!("  Layouts: mono, stereo, 2.1, 5.1, 7.1, atmos");
            shell_println!("  stats / test / init");
        }
    }
}

/// `audioeq` / `aeq` — audio equalizer management.
fn cmd_audioeq(args: &str) {
    use crate::fs::audioeq;
    use alloc::format;
    let parts: Vec<&str> = args.split_whitespace().collect();
    let sub = parts.first().copied().unwrap_or("");
    match sub {
        "init" => {
            audioeq::init_defaults();
            shell_println!("Audio EQ initialized");
        }
        "list" => {
            let configs = audioeq::list_configs();
            if configs.is_empty() {
                shell_println!("No EQ configs");
            } else {
                for c in &configs {
                    shell_println!("#{}: {} — {} [{}] preamp: {} cb",
                        c.id, c.device_name, c.preset.label(),
                        if c.enabled { "ON" } else { "OFF" }, c.preamp_cb);
                    let gains: Vec<alloc::string::String> = c.bands.iter()
                        .map(|b| format!("{}Hz:{}", b.freq_hz, b.gain_cb))
                        .collect();
                    shell_println!("    Bands: {}", gains.join(", "));
                }
            }
        }
        "preset" => {
            let id: u32 = match parts.get(1).unwrap_or(&"1").parse() {
                Ok(v) => v,
                Err(_) => { shell_println!("Invalid config ID"); return; }
            };
            let preset = match parts.get(2).copied().unwrap_or("flat") {
                "rock" => audioeq::EqPreset::Rock,
                "pop" => audioeq::EqPreset::Pop,
                "jazz" => audioeq::EqPreset::Jazz,
                "classical" => audioeq::EqPreset::Classical,
                "hiphop" | "hip-hop" => audioeq::EqPreset::HipHop,
                "electronic" | "edm" => audioeq::EqPreset::Electronic,
                "vocal" => audioeq::EqPreset::Vocal,
                "bass" => audioeq::EqPreset::Bass,
                "treble" => audioeq::EqPreset::Treble,
                _ => audioeq::EqPreset::Flat,
            };
            match audioeq::set_preset(id, preset) {
                Ok(()) => shell_println!("EQ #{} → {}", id, preset.label()),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "band" => {
            let id: u32 = match parts.get(1).unwrap_or(&"1").parse() {
                Ok(v) => v,
                Err(_) => { shell_println!("Invalid config ID"); return; }
            };
            let band: usize = parts.get(2).unwrap_or(&"0").parse().unwrap_or(0);
            let gain: i32 = parts.get(3).unwrap_or(&"0").parse().unwrap_or(0);
            match audioeq::set_band_gain(id, band, gain) {
                Ok(()) => shell_println!("Band {} gain: {} cb", band, gain.clamp(-1200, 1200)),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "preamp" => {
            let id: u32 = match parts.get(1).unwrap_or(&"1").parse() {
                Ok(v) => v,
                Err(_) => { shell_println!("Invalid config ID"); return; }
            };
            let gain: i32 = parts.get(2).unwrap_or(&"0").parse().unwrap_or(0);
            match audioeq::set_preamp(id, gain) {
                Ok(()) => shell_println!("Preamp: {} cb", gain.clamp(-1200, 1200)),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "enable" | "on" => {
            let id: u32 = match parts.get(1).unwrap_or(&"1").parse() {
                Ok(v) => v,
                Err(_) => { shell_println!("Invalid config ID"); return; }
            };
            match audioeq::set_enabled(id, true) {
                Ok(()) => shell_println!("EQ #{} enabled", id),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "disable" | "off" => {
            let id: u32 = match parts.get(1).unwrap_or(&"1").parse() {
                Ok(v) => v,
                Err(_) => { shell_println!("Invalid config ID"); return; }
            };
            match audioeq::set_enabled(id, false) {
                Ok(()) => shell_println!("EQ #{} disabled", id),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "create" => {
            let name = parts.get(1).copied().unwrap_or("Device");
            match audioeq::create_config(name) {
                Ok(id) => shell_println!("Created EQ #{}: {}", id, name),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "remove" => {
            let id: u32 = match parts.get(1).unwrap_or(&"0").parse() {
                Ok(v) => v,
                Err(_) => { shell_println!("Invalid config ID"); return; }
            };
            match audioeq::remove_config(id) {
                Ok(()) => shell_println!("Removed EQ #{}", id),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "stats" => {
            let (count, adj, presets, ops) = audioeq::stats();
            shell_println!("Configs: {}, Adjustments: {}, Preset changes: {}, Ops: {}", count, adj, presets, ops);
        }
        "test" => audioeq::self_test(),
        _ => {
            shell_println!("Usage: audioeq <command>");
            shell_println!("  list                List configs");
            shell_println!("  preset <id> <name>  Apply preset");
            shell_println!("  band <id> <n> <cb>  Set band gain");
            shell_println!("  preamp <id> <cb>    Set preamp gain");
            shell_println!("  enable/disable <id> Toggle EQ");
            shell_println!("  create <name>       New config");
            shell_println!("  remove <id>         Remove config");
            shell_println!("  Presets: flat rock pop jazz classical");
            shell_println!("           hiphop electronic vocal bass treble");
            shell_println!("  stats / test / init");
        }
    }
}

/// `screensaver` / `ssaver` — screen saver management.
fn cmd_screensaver(args: &str) {
    use crate::fs::screensaver;
    let parts: Vec<&str> = args.split_whitespace().collect();
    let sub = parts.first().copied().unwrap_or("");
    match sub {
        "init" => {
            screensaver::init_defaults();
            shell_println!("Screen saver initialized");
        }
        "list" => {
            let savers = screensaver::list_savers();
            if savers.is_empty() {
                shell_println!("No screen savers");
            } else {
                let active_id = screensaver::active_saver_id();
                for s in &savers {
                    let marker = if s.id == active_id { " *" } else { "" };
                    shell_println!("#{}: {} ({}) — {}s timeout, pw: {}, {}{}",
                        s.id, s.name, s.saver_type.label(),
                        s.timeout_secs, s.password_required,
                        if s.enabled { "enabled" } else { "disabled" },
                        marker);
                }
            }
        }
        "activate" => {
            match screensaver::activate() {
                Ok(()) => shell_println!("Screen saver activated"),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "deactivate" | "dismiss" => {
            match screensaver::deactivate() {
                Ok(()) => shell_println!("Screen saver deactivated"),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "preview" => {
            let id: u32 = match parts.get(1).unwrap_or(&"1").parse() {
                Ok(v) => v,
                Err(_) => { shell_println!("Invalid saver ID"); return; }
            };
            match screensaver::preview(id) {
                Ok(()) => shell_println!("Previewing saver #{}", id),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "set" => {
            let id: u32 = match parts.get(1).unwrap_or(&"1").parse() {
                Ok(v) => v,
                Err(_) => { shell_println!("Invalid saver ID"); return; }
            };
            match screensaver::set_active(id) {
                Ok(()) => shell_println!("Active saver set to #{}", id),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "timeout" => {
            let id: u32 = match parts.get(1).unwrap_or(&"1").parse() {
                Ok(v) => v,
                Err(_) => { shell_println!("Invalid saver ID"); return; }
            };
            let secs: u32 = parts.get(2).unwrap_or(&"300").parse().unwrap_or(300);
            match screensaver::set_timeout(id, secs) {
                Ok(()) => shell_println!("Timeout: {}s", secs.clamp(30, 7200)),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "password" | "pw" => {
            let id: u32 = match parts.get(1).unwrap_or(&"1").parse() {
                Ok(v) => v,
                Err(_) => { shell_println!("Invalid saver ID"); return; }
            };
            let required = parts.get(2).copied().unwrap_or("on") != "off";
            match screensaver::set_password_required(id, required) {
                Ok(()) => shell_println!("Password on wake: {}", required),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "register" => {
            let name = parts.get(1).copied().unwrap_or("Custom");
            let stype = match parts.get(2).copied().unwrap_or("blank") {
                "starfield" | "stars" => screensaver::SaverType::Starfield,
                "matrix" => screensaver::SaverType::Matrix,
                "bouncing" | "bounce" => screensaver::SaverType::Bouncing,
                "clock" => screensaver::SaverType::Clock,
                "slideshow" | "photos" => screensaver::SaverType::Slideshow,
                "bubbles" => screensaver::SaverType::Bubbles,
                _ => screensaver::SaverType::Blank,
            };
            match screensaver::register_saver(name, stype) {
                Ok(id) => shell_println!("Registered saver #{}: {} ({})", id, name, stype.label()),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "stats" => {
            let (count, acts, deacts, ops) = screensaver::stats();
            shell_println!("Savers: {}, Activations: {}, Deactivations: {}, Ops: {}", count, acts, deacts, ops);
        }
        "test" => screensaver::self_test(),
        _ => {
            shell_println!("Usage: screensaver <command>");
            shell_println!("  list                List savers");
            shell_println!("  activate            Start saver");
            shell_println!("  deactivate          Dismiss saver");
            shell_println!("  preview <id>        Preview saver");
            shell_println!("  set <id>            Set active saver");
            shell_println!("  timeout <id> <s>    Set idle timeout");
            shell_println!("  password <id> [on|off]  Password on wake");
            shell_println!("  register <name> <type>  Register saver");
            shell_println!("  Types: blank starfield matrix bouncing clock slideshow bubbles");
            shell_println!("  stats / test / init");
        }
    }
}

/// `colortemp` / `ctemp` — color temperature scheduling.
fn cmd_colortemp(args: &str) {
    use crate::fs::colortemp;
    let parts: Vec<&str> = args.split_whitespace().collect();
    let sub = parts.first().copied().unwrap_or("");
    match sub {
        "init" => {
            colortemp::init_defaults();
            shell_println!("Color temperature initialized");
        }
        "list" => {
            let profiles = colortemp::list_profiles();
            if profiles.is_empty() {
                shell_println!("No color temp profiles");
            } else {
                let active_id = colortemp::active_profile_id();
                for p in &profiles {
                    let marker = if p.id == active_id { " *" } else { "" };
                    shell_println!("#{}: {} — {} {}K [{}]{}",
                        p.id, p.name, p.mode.label(), p.current_kelvin,
                        if p.enabled { "ON" } else { "OFF" }, marker);
                    if p.mode == colortemp::TempMode::Scheduled || p.mode == colortemp::TempMode::SunSync {
                        shell_println!("    Day: {}K, Night: {}K, Sunset: {:02}:{:02}, Sunrise: {:02}:{:02}",
                            p.day_kelvin, p.night_kelvin,
                            p.sunset_min / 60, p.sunset_min % 60,
                            p.sunrise_min / 60, p.sunrise_min % 60);
                    }
                }
            }
        }
        "set" => {
            let id: u32 = match parts.get(1).unwrap_or(&"1").parse() {
                Ok(v) => v,
                Err(_) => { shell_println!("Invalid profile ID"); return; }
            };
            let kelvin: u32 = parts.get(2).unwrap_or(&"4000").parse().unwrap_or(4000);
            match colortemp::set_temperature(id, kelvin) {
                Ok(()) => shell_println!("Temperature: {}K", kelvin.clamp(1000, 10000)),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "mode" => {
            let id: u32 = match parts.get(1).unwrap_or(&"1").parse() {
                Ok(v) => v,
                Err(_) => { shell_println!("Invalid profile ID"); return; }
            };
            let mode = match parts.get(2).copied().unwrap_or("off") {
                "manual" => colortemp::TempMode::Manual,
                "scheduled" | "sched" => colortemp::TempMode::Scheduled,
                "sunsync" | "sun" => colortemp::TempMode::SunSync,
                _ => colortemp::TempMode::Off,
            };
            match colortemp::set_mode(id, mode) {
                Ok(()) => shell_println!("Mode: {}", mode.label()),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "daynight" | "dn" => {
            let id: u32 = match parts.get(1).unwrap_or(&"1").parse() {
                Ok(v) => v,
                Err(_) => { shell_println!("Invalid profile ID"); return; }
            };
            let day: u32 = parts.get(2).unwrap_or(&"6500").parse().unwrap_or(6500);
            let night: u32 = parts.get(3).unwrap_or(&"3400").parse().unwrap_or(3400);
            match colortemp::set_day_night(id, day, night) {
                Ok(()) => shell_println!("Day: {}K, Night: {}K", day.clamp(1000, 10000), night.clamp(1000, 10000)),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "schedule" => {
            let id: u32 = match parts.get(1).unwrap_or(&"1").parse() {
                Ok(v) => v,
                Err(_) => { shell_println!("Invalid profile ID"); return; }
            };
            let sunset: u16 = parts.get(2).unwrap_or(&"1200").parse().unwrap_or(1200);
            let sunrise: u16 = parts.get(3).unwrap_or(&"420").parse().unwrap_or(420);
            let trans: u16 = parts.get(4).unwrap_or(&"30").parse().unwrap_or(30);
            match colortemp::set_schedule_times(id, sunset, sunrise, trans) {
                Ok(()) => shell_println!("Sunset: {:02}:{:02}, Sunrise: {:02}:{:02}, Transition: {}m",
                    sunset / 60, sunset % 60, sunrise / 60, sunrise % 60, trans),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "update" => {
            let id: u32 = match parts.get(1).unwrap_or(&"1").parse() {
                Ok(v) => v,
                Err(_) => { shell_println!("Invalid profile ID"); return; }
            };
            let time: u16 = parts.get(2).unwrap_or(&"720").parse().unwrap_or(720);
            match colortemp::update_for_time(id, time) {
                Ok(k) => shell_println!("Temperature at {:02}:{:02}: {}K", time / 60, time % 60, k),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "create" => {
            let name = parts.get(1).copied().unwrap_or("Profile");
            match colortemp::create_profile(name) {
                Ok(id) => shell_println!("Created profile #{}: {}", id, name),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "active" => {
            let id: u32 = match parts.get(1).unwrap_or(&"1").parse() {
                Ok(v) => v,
                Err(_) => { shell_println!("Invalid profile ID"); return; }
            };
            match colortemp::set_active(id) {
                Ok(()) => shell_println!("Active profile: #{}", id),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "stats" => {
            let (count, active, adj, ops) = colortemp::stats();
            shell_println!("Profiles: {}, Active: #{}, Adjustments: {}, Ops: {}", count, active, adj, ops);
        }
        "test" => colortemp::self_test(),
        _ => {
            shell_println!("Usage: colortemp <command>");
            shell_println!("  list                   List profiles");
            shell_println!("  set <id> <kelvin>      Set temperature");
            shell_println!("  mode <id> <mode>       Set mode");
            shell_println!("  daynight <id> <d> <n>  Day/night Kelvin");
            shell_println!("  schedule <id> <sunset> <sunrise> <trans>");
            shell_println!("  update <id> <minutes>  Update for time");
            shell_println!("  create <name>          New profile");
            shell_println!("  active <id>            Set active profile");
            shell_println!("  Modes: off manual scheduled sunsync");
            shell_println!("  stats / test / init");
        }
    }
}

/// `gamemode` / `gmode` — gaming performance optimization.
fn cmd_gamemode(args: &str) {
    use crate::fs::gamemode;
    let parts: Vec<&str> = args.split_whitespace().collect();
    let sub = parts.first().copied().unwrap_or("");
    match sub {
        "init" => {
            gamemode::init_defaults();
            shell_println!("Game mode initialized");
        }
        "status" => {
            let state = gamemode::current_state();
            shell_println!("Game mode: {}", state.label());
            let games = gamemode::list_games();
            shell_println!("Registered games: {}", games.len());
        }
        "on" | "activate" => {
            let gid: u32 = parts.get(1).unwrap_or(&"0").parse().unwrap_or(0);
            match gamemode::activate(gid) {
                Ok(()) => shell_println!("Game mode activated"),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "off" | "deactivate" => {
            match gamemode::deactivate() {
                Ok(()) => shell_println!("Game mode deactivated"),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "register" => {
            let name = parts.get(1).copied().unwrap_or("Game");
            let proc_name = parts.get(2).copied().unwrap_or("game.exe");
            match gamemode::register_game(name, proc_name) {
                Ok(id) => shell_println!("Registered game #{}: {} ({})", id, name, proc_name),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "unregister" => {
            let id: u32 = match parts.get(1).unwrap_or(&"0").parse() {
                Ok(v) => v,
                Err(_) => { shell_println!("Invalid game ID"); return; }
            };
            match gamemode::unregister_game(id) {
                Ok(()) => shell_println!("Unregistered game #{}", id),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "games" | "list" => {
            let games = gamemode::list_games();
            if games.is_empty() {
                shell_println!("No registered games");
            } else {
                for g in &games {
                    shell_println!("#{}: {} ({}) — {} sessions, {} secs played",
                        g.id, g.name, g.process_name, g.total_sessions, g.total_play_secs);
                }
            }
        }
        "sessions" | "history" => {
            let count: usize = parts.get(1).unwrap_or(&"10").parse().unwrap_or(10);
            let sessions = gamemode::list_sessions(count);
            if sessions.is_empty() {
                shell_println!("No game sessions");
            } else {
                for s in &sessions {
                    shell_println!("  {} — {} secs", s.game_name, s.duration_secs);
                }
            }
        }
        "fps" => {
            let enabled = parts.get(1).copied().unwrap_or("on") != "off";
            match gamemode::set_fps_overlay(enabled) {
                Ok(()) => shell_println!("FPS overlay: {}", if enabled { "on" } else { "off" }),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "autodetect" | "auto" => {
            let enabled = parts.get(1).copied().unwrap_or("on") != "off";
            match gamemode::set_auto_detect(enabled) {
                Ok(()) => shell_println!("Auto-detect: {}", if enabled { "on" } else { "off" }),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "stats" => {
            let (games, acts, active, ops) = gamemode::stats();
            shell_println!("Games: {}, Activations: {}, Active: {}, Ops: {}", games, acts, active, ops);
        }
        "test" => gamemode::self_test(),
        _ => {
            shell_println!("Usage: gamemode <command>");
            shell_println!("  status              Current state");
            shell_println!("  on [game_id]        Activate game mode");
            shell_println!("  off                 Deactivate game mode");
            shell_println!("  register <name> <proc>  Register game");
            shell_println!("  unregister <id>     Remove game");
            shell_println!("  games               List registered games");
            shell_println!("  sessions [count]    Recent sessions");
            shell_println!("  fps [on|off]        FPS overlay");
            shell_println!("  auto [on|off]       Auto-detection");
            shell_println!("  stats / test / init");
        }
    }
}

/// `dpiscaling` / `dpi` — display scaling management.
fn cmd_dpiscaling(args: &str) {
    use crate::fs::dpiscaling;
    let parts: Vec<&str> = args.split_whitespace().collect();
    let sub = parts.first().copied().unwrap_or("");
    match sub {
        "init" => {
            dpiscaling::init_defaults();
            shell_println!("DPI scaling initialized");
        }
        "list" => {
            let displays = dpiscaling::list_displays();
            if displays.is_empty() {
                shell_println!("No displays");
            } else {
                for d in &displays {
                    shell_println!("#{}: {} — {}% (rec: {}%), {}dpi physical, {}dpi effective, {}",
                        d.id, d.display_name, d.scale_percent, d.recommended_percent,
                        d.physical_dpi, d.effective_dpi, d.method.label());
                }
            }
        }
        "set" => {
            let id: u32 = match parts.get(1).unwrap_or(&"1").parse() {
                Ok(v) => v,
                Err(_) => { shell_println!("Invalid display ID"); return; }
            };
            let pct: u32 = parts.get(2).unwrap_or(&"100").parse().unwrap_or(100);
            match dpiscaling::set_scale(id, pct) {
                Ok(()) => shell_println!("Scale: {}%", pct.clamp(50, 500)),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "method" => {
            let id: u32 = match parts.get(1).unwrap_or(&"1").parse() {
                Ok(v) => v,
                Err(_) => { shell_println!("Invalid display ID"); return; }
            };
            let m = match parts.get(2).copied().unwrap_or("fractional") {
                "integer" | "int" => dpiscaling::ScalingMethod::Integer,
                "resize" | "intresize" => dpiscaling::ScalingMethod::IntegerThenResize,
                _ => dpiscaling::ScalingMethod::Fractional,
            };
            match dpiscaling::set_method(id, m) {
                Ok(()) => shell_println!("Method: {}", m.label()),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "register" => {
            let name = parts.get(1).copied().unwrap_or("Monitor");
            let dpi: u32 = parts.get(2).unwrap_or(&"96").parse().unwrap_or(96);
            match dpiscaling::register_display(name, dpi) {
                Ok(id) => shell_println!("Registered display #{}: {} ({}dpi)", id, name, dpi),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "override" => {
            let app = parts.get(1).copied().unwrap_or("app");
            let awareness = match parts.get(2).copied().unwrap_or("system") {
                "unaware" => dpiscaling::DpiAwareness::Unaware,
                "permonitor" | "pm" => dpiscaling::DpiAwareness::PerMonitorAware,
                "permonitorv2" | "pmv2" => dpiscaling::DpiAwareness::PerMonitorAwareV2,
                _ => dpiscaling::DpiAwareness::SystemAware,
            };
            let pct: u32 = parts.get(3).unwrap_or(&"0").parse().unwrap_or(0);
            match dpiscaling::set_app_override(app, awareness, pct) {
                Ok(()) => shell_println!("Override for {}: {} {}%", app, awareness.label(), pct),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "overrides" => {
            let overrides = dpiscaling::list_overrides();
            if overrides.is_empty() {
                shell_println!("No app DPI overrides");
            } else {
                for o in &overrides {
                    shell_println!("  {}: {} ({}%)", o.app_name, o.awareness.label(), o.override_percent);
                }
            }
        }
        "stats" => {
            let (displays, overrides, changes, ops) = dpiscaling::stats();
            shell_println!("Displays: {}, Overrides: {}, Changes: {}, Ops: {}", displays, overrides, changes, ops);
        }
        "test" => dpiscaling::self_test(),
        _ => {
            shell_println!("Usage: dpiscaling <command>");
            shell_println!("  list                   List displays");
            shell_println!("  set <id> <percent>     Set scale (50-500%)");
            shell_println!("  method <id> <method>   Scaling method");
            shell_println!("  register <name> <dpi>  Register display");
            shell_println!("  override <app> <aware> [%]  App override");
            shell_println!("  overrides              List overrides");
            shell_println!("  Methods: integer fractional resize");
            shell_println!("  stats / test / init");
        }
    }
}

/// `netprofile` / `nprof` — network profile management.
fn cmd_netprofile(args: &str) {
    use crate::fs::netprofile;
    let parts: Vec<&str> = args.split_whitespace().collect();
    let sub = parts.first().copied().unwrap_or("");
    match sub {
        "init" => {
            netprofile::init_defaults();
            shell_println!("Network profiles initialized");
        }
        "list" => {
            let profiles = netprofile::list_profiles();
            if profiles.is_empty() {
                shell_println!("No network profiles");
            } else {
                let active = netprofile::active_id();
                for p in &profiles {
                    let marker = if p.id == active { " *" } else { "" };
                    shell_println!("#{}: {} ({}/{}) [{}] metered: {}{}",
                        p.id, p.name, p.network_type.label(), p.connection_type.label(),
                        if p.ssid.is_empty() { "(any)" } else { &p.ssid },
                        p.metered, marker);
                    if !p.auto_vpn.is_empty() {
                        shell_println!("    Auto VPN: {}", p.auto_vpn);
                    }
                    if !p.dns_servers.is_empty() {
                        shell_println!("    DNS: {}", p.dns_servers.join(", "));
                    }
                }
            }
        }
        "create" => {
            let name = parts.get(1).copied().unwrap_or("Network");
            let ssid = parts.get(2).copied().unwrap_or("");
            let ntype = match parts.get(3).copied().unwrap_or("private") {
                "public" => netprofile::NetworkType::Public,
                "domain" => netprofile::NetworkType::Domain,
                "trusted" => netprofile::NetworkType::Trusted,
                _ => netprofile::NetworkType::Private,
            };
            match netprofile::create_profile(name, ssid, ntype, netprofile::ConnectionType::WiFi) {
                Ok(id) => shell_println!("Created profile #{}: {}", id, name),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "apply" => {
            let id: u32 = match parts.get(1).unwrap_or(&"1").parse() {
                Ok(v) => v,
                Err(_) => { shell_println!("Invalid profile ID"); return; }
            };
            match netprofile::apply_profile(id) {
                Ok(()) => shell_println!("Applied profile #{}", id),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "type" => {
            let id: u32 = match parts.get(1).unwrap_or(&"1").parse() {
                Ok(v) => v,
                Err(_) => { shell_println!("Invalid profile ID"); return; }
            };
            let ntype = match parts.get(2).copied().unwrap_or("private") {
                "public" => netprofile::NetworkType::Public,
                "domain" => netprofile::NetworkType::Domain,
                "trusted" => netprofile::NetworkType::Trusted,
                "untrusted" => netprofile::NetworkType::Untrusted,
                _ => netprofile::NetworkType::Private,
            };
            match netprofile::set_network_type(id, ntype) {
                Ok(()) => shell_println!("Type: {}", ntype.label()),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "metered" => {
            let id: u32 = match parts.get(1).unwrap_or(&"1").parse() {
                Ok(v) => v,
                Err(_) => { shell_println!("Invalid profile ID"); return; }
            };
            let m = parts.get(2).copied().unwrap_or("on") != "off";
            match netprofile::set_metered(id, m) {
                Ok(()) => shell_println!("Metered: {}", m),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "vpn" => {
            let id: u32 = match parts.get(1).unwrap_or(&"1").parse() {
                Ok(v) => v,
                Err(_) => { shell_println!("Invalid profile ID"); return; }
            };
            let vpn = parts.get(2).copied().unwrap_or("");
            match netprofile::set_auto_vpn(id, vpn) {
                Ok(()) => shell_println!("Auto VPN: {}", if vpn.is_empty() { "(none)" } else { vpn }),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "remove" => {
            let id: u32 = match parts.get(1).unwrap_or(&"0").parse() {
                Ok(v) => v,
                Err(_) => { shell_println!("Invalid profile ID"); return; }
            };
            match netprofile::remove_profile(id) {
                Ok(()) => shell_println!("Removed profile #{}", id),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "find" => {
            let ssid = parts.get(1).copied().unwrap_or("");
            match netprofile::find_by_ssid(ssid) {
                Some(id) => shell_println!("Found profile #{} for SSID '{}'", id, ssid),
                None => shell_println!("No profile for SSID '{}'", ssid),
            }
        }
        "stats" => {
            let (count, active, switches, ops) = netprofile::stats();
            shell_println!("Profiles: {}, Active: #{}, Switches: {}, Ops: {}", count, active, switches, ops);
        }
        "test" => netprofile::self_test(),
        _ => {
            shell_println!("Usage: netprofile <command>");
            shell_println!("  list                   List profiles");
            shell_println!("  create <name> [ssid] [type]  Create profile");
            shell_println!("  apply <id>             Activate profile");
            shell_println!("  type <id> <type>       Set network type");
            shell_println!("  metered <id> [on|off]  Set metered");
            shell_println!("  vpn <id> <name>        Auto-connect VPN");
            shell_println!("  find <ssid>            Find by SSID");
            shell_println!("  remove <id>            Remove profile");
            shell_println!("  Types: private public domain trusted untrusted");
            shell_println!("  stats / test / init");
        }
    }
}

/// `apppermissions` / `apperm` — app permission management.
fn cmd_apppermissions(args: &str) {
    use crate::fs::apppermissions;
    let parts: Vec<&str> = args.split_whitespace().collect();
    let sub = parts.first().copied().unwrap_or("");

    let parse_perm = |s: &str| -> apppermissions::Permission {
        match s {
            "camera" | "cam" => apppermissions::Permission::Camera,
            "microphone" | "mic" => apppermissions::Permission::Microphone,
            "location" | "loc" => apppermissions::Permission::Location,
            "notifications" | "notif" => apppermissions::Permission::Notifications,
            "contacts" => apppermissions::Permission::Contacts,
            "calendar" | "cal" => apppermissions::Permission::Calendar,
            "storage" => apppermissions::Permission::Storage,
            "network" | "net" => apppermissions::Permission::Network,
            "bluetooth" | "bt" => apppermissions::Permission::Bluetooth,
            "background" | "bg" => apppermissions::Permission::BackgroundActivity,
            "settings" | "sys" => apppermissions::Permission::SystemSettings,
            "a11y" | "accessibility" => apppermissions::Permission::Accessibility,
            _ => apppermissions::Permission::Storage,
        }
    };

    match sub {
        "init" => {
            apppermissions::init_defaults();
            shell_println!("App permissions initialized");
        }
        "check" => {
            let app = parts.get(1).copied().unwrap_or("app");
            let perm = parse_perm(parts.get(2).copied().unwrap_or("storage"));
            let d = apppermissions::check(app, perm);
            shell_println!("{} → {}: {}", app, perm.label(), d.label());
        }
        "grant" => {
            let app = parts.get(1).copied().unwrap_or("app");
            let perm = parse_perm(parts.get(2).copied().unwrap_or("storage"));
            match apppermissions::grant(app, perm) {
                Ok(()) => shell_println!("Granted {} to {}", perm.label(), app),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "deny" => {
            let app = parts.get(1).copied().unwrap_or("app");
            let perm = parse_perm(parts.get(2).copied().unwrap_or("storage"));
            match apppermissions::deny(app, perm) {
                Ok(()) => shell_println!("Denied {} to {}", perm.label(), app),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "revoke" => {
            let app = parts.get(1).copied().unwrap_or("app");
            match apppermissions::revoke_all(app) {
                Ok(n) => shell_println!("Revoked {} permissions from {}", n, app),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "app" => {
            let app = parts.get(1).copied().unwrap_or("app");
            let perms = apppermissions::list_app_permissions(app);
            if perms.is_empty() {
                shell_println!("No permissions for {}", app);
            } else {
                for p in &perms {
                    shell_println!("  {}: {} (requests: {})", p.permission.label(), p.decision.label(), p.request_count);
                }
            }
        }
        "perm" => {
            let perm = parse_perm(parts.get(1).copied().unwrap_or("camera"));
            let apps = apppermissions::list_by_permission(perm);
            if apps.is_empty() {
                shell_println!("No apps with {} permission", perm.label());
            } else {
                for a in &apps {
                    shell_println!("  {}: {}", a.app_name, a.decision.label());
                }
            }
        }
        "log" => {
            let count: usize = parts.get(1).unwrap_or(&"10").parse().unwrap_or(10);
            let log = apppermissions::list_log(count);
            if log.is_empty() {
                shell_println!("No permission log entries");
            } else {
                for l in &log {
                    shell_println!("  {} → {}: {}", l.app_name, l.permission.label(),
                        if l.granted { "granted" } else { "denied" });
                }
            }
        }
        "stats" => {
            let (entries, checks, grants, denials, ops) = apppermissions::stats();
            shell_println!("Entries: {}, Checks: {}, Grants: {}, Denials: {}, Ops: {}", entries, checks, grants, denials, ops);
        }
        "test" => apppermissions::self_test(),
        _ => {
            shell_println!("Usage: apppermissions <command>");
            shell_println!("  check <app> <perm>  Check permission");
            shell_println!("  grant <app> <perm>  Grant permission");
            shell_println!("  deny <app> <perm>   Deny permission");
            shell_println!("  revoke <app>        Revoke all");
            shell_println!("  app <app>           List app's perms");
            shell_println!("  perm <perm>         List apps with perm");
            shell_println!("  log [count]         Permission log");
            shell_println!("  Perms: camera mic location notif contacts");
            shell_println!("         calendar storage net bt bg settings a11y");
            shell_println!("  stats / test / init");
        }
    }
}

/// `kbshortcuts` / `kbsc` — keyboard shortcut management.
fn cmd_kbshortcuts(args: &str) {
    use crate::fs::kbshortcuts;
    let parts: Vec<&str> = args.split_whitespace().collect();
    let sub = parts.first().copied().unwrap_or("");
    match sub {
        "init" => {
            kbshortcuts::init_defaults();
            shell_println!("Keyboard shortcuts initialized");
        }
        "list" => {
            let all = kbshortcuts::list_shortcuts();
            if all.is_empty() {
                shell_println!("No shortcuts");
            } else {
                for s in &all {
                    shell_println!("#{}: {}+{} → {} [{}] {} (used: {})",
                        s.id, s.modifiers.label(), s.key, s.action,
                        s.category.label(),
                        if s.enabled { "ON" } else { "OFF" },
                        s.use_count);
                }
            }
        }
        "bind" => {
            // bind <mods> <key> <action> [desc]
            let mods_str = parts.get(1).copied().unwrap_or("ctrl");
            let key = parts.get(2).copied().unwrap_or("A");
            let action = parts.get(3).copied().unwrap_or("action");
            let desc = parts.get(4).copied().unwrap_or(action);
            let mods = kbshortcuts::Modifiers {
                ctrl: mods_str.contains("ctrl"),
                alt: mods_str.contains("alt"),
                shift: mods_str.contains("shift"),
                super_key: mods_str.contains("super"),
            };
            match kbshortcuts::bind(mods, key, action, desc, kbshortcuts::ShortcutCategory::Custom) {
                Ok(id) => shell_println!("Bound #{}: {}+{} → {}", id, mods.label(), key, action),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "unbind" => {
            let id: u32 = match parts.get(1).unwrap_or(&"0").parse() {
                Ok(v) => v,
                Err(_) => { shell_println!("Invalid shortcut ID"); return; }
            };
            match kbshortcuts::unbind(id) {
                Ok(()) => shell_println!("Unbound #{}", id),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "trigger" => {
            let id: u32 = match parts.get(1).unwrap_or(&"0").parse() {
                Ok(v) => v,
                Err(_) => { shell_println!("Invalid shortcut ID"); return; }
            };
            match kbshortcuts::trigger(id) {
                Ok(action) => shell_println!("Triggered: {}", action),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "enable" | "disable" => {
            let id: u32 = match parts.get(1).unwrap_or(&"0").parse() {
                Ok(v) => v,
                Err(_) => { shell_println!("Invalid shortcut ID"); return; }
            };
            let enabled = sub == "enable";
            match kbshortcuts::set_enabled(id, enabled) {
                Ok(()) => shell_println!("Shortcut #{}: {}", id, if enabled { "enabled" } else { "disabled" }),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "category" | "cat" => {
            let cat = match parts.get(1).copied().unwrap_or("system") {
                "nav" | "navigation" => kbshortcuts::ShortcutCategory::Navigation,
                "window" | "wm" => kbshortcuts::ShortcutCategory::WindowManagement,
                "app" | "application" => kbshortcuts::ShortcutCategory::Application,
                "a11y" | "accessibility" => kbshortcuts::ShortcutCategory::Accessibility,
                "media" => kbshortcuts::ShortcutCategory::Media,
                "custom" => kbshortcuts::ShortcutCategory::Custom,
                _ => kbshortcuts::ShortcutCategory::System,
            };
            let shortcuts = kbshortcuts::list_by_category(cat);
            shell_println!("{} shortcuts:", cat.label());
            for s in &shortcuts {
                shell_println!("  #{}: {}+{} → {}", s.id, s.modifiers.label(), s.key, s.action);
            }
        }
        "stats" => {
            let (count, binds, triggers, ops) = kbshortcuts::stats();
            shell_println!("Shortcuts: {}, Binds: {}, Triggers: {}, Ops: {}", count, binds, triggers, ops);
        }
        "test" => kbshortcuts::self_test(),
        _ => {
            shell_println!("Usage: kbshortcuts <command>");
            shell_println!("  list                  List shortcuts");
            shell_println!("  bind <mods> <key> <action> [desc]");
            shell_println!("  unbind <id>           Remove shortcut");
            shell_println!("  trigger <id>          Trigger shortcut");
            shell_println!("  enable/disable <id>   Toggle shortcut");
            shell_println!("  category <cat>        Filter by category");
            shell_println!("  Mods: ctrl alt shift super (combine: ctrl+alt)");
            shell_println!("  Categories: system nav window app a11y media custom");
            shell_println!("  stats / test / init");
        }
    }
}

/// `displayarrange` / `darr` — multi-monitor arrangement.
fn cmd_displayarrange(args: &str) {
    use crate::fs::displayarrange;
    let parts: Vec<&str> = args.split_whitespace().collect();
    let sub = parts.first().copied().unwrap_or("");
    match sub {
        "init" => {
            displayarrange::init_defaults();
            shell_println!("Display arrangement initialized");
        }
        "list" => {
            let displays = displayarrange::list_displays();
            if displays.is_empty() {
                shell_println!("No displays");
            } else {
                shell_println!("Topology: {}", displayarrange::topology().label());
                for d in &displays {
                    shell_println!("#{}: {} — {}x{} at ({},{}) {} {}{}",
                        d.id, d.name, d.width, d.height, d.x, d.y,
                        d.orientation.label(),
                        if d.enabled { "ON" } else { "OFF" },
                        if d.is_primary { " [PRIMARY]" } else { "" });
                }
            }
        }
        "add" => {
            let name = parts.get(1).copied().unwrap_or("Monitor");
            let w: u32 = parts.get(2).unwrap_or(&"1920").parse().unwrap_or(1920);
            let h: u32 = parts.get(3).unwrap_or(&"1080").parse().unwrap_or(1080);
            match displayarrange::add_display(name, w, h) {
                Ok(id) => shell_println!("Added display #{}: {} ({}x{})", id, name, w, h),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "pos" | "position" => {
            let id: u32 = match parts.get(1).unwrap_or(&"1").parse() {
                Ok(v) => v,
                Err(_) => { shell_println!("Invalid display ID"); return; }
            };
            let x: i32 = parts.get(2).unwrap_or(&"0").parse().unwrap_or(0);
            let y: i32 = parts.get(3).unwrap_or(&"0").parse().unwrap_or(0);
            match displayarrange::set_position(id, x, y) {
                Ok(()) => shell_println!("Display #{} at ({}, {})", id, x, y),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "primary" => {
            let id: u32 = match parts.get(1).unwrap_or(&"1").parse() {
                Ok(v) => v,
                Err(_) => { shell_println!("Invalid display ID"); return; }
            };
            match displayarrange::set_primary(id) {
                Ok(()) => shell_println!("Primary: #{}", id),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "orient" => {
            let id: u32 = match parts.get(1).unwrap_or(&"1").parse() {
                Ok(v) => v,
                Err(_) => { shell_println!("Invalid display ID"); return; }
            };
            let o = match parts.get(2).copied().unwrap_or("landscape") {
                "portrait" | "vert" => displayarrange::Orientation::Portrait,
                "landscape-flip" | "lflip" => displayarrange::Orientation::LandscapeFlipped,
                "portrait-flip" | "pflip" => displayarrange::Orientation::PortraitFlipped,
                _ => displayarrange::Orientation::Landscape,
            };
            match displayarrange::set_orientation(id, o) {
                Ok(()) => shell_println!("Orientation: {}", o.label()),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "topology" | "topo" => {
            let t = match parts.get(1).copied().unwrap_or("extend") {
                "mirror" => displayarrange::Topology::Mirror,
                "single" => displayarrange::Topology::SingleDisplay,
                _ => displayarrange::Topology::Extend,
            };
            match displayarrange::set_topology(t) {
                Ok(()) => shell_println!("Topology: {}", t.label()),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "stats" => {
            let (count, topo, rearrangements, ops) = displayarrange::stats();
            shell_println!("Displays: {}, Topology: {}, Rearrangements: {}, Ops: {}", count, topo, rearrangements, ops);
        }
        "test" => displayarrange::self_test(),
        _ => {
            shell_println!("Usage: displayarrange <command>");
            shell_println!("  list                  List displays");
            shell_println!("  add <name> [w] [h]    Add display");
            shell_println!("  pos <id> <x> <y>      Set position");
            shell_println!("  primary <id>          Set primary");
            shell_println!("  orient <id> <orient>  Set orientation");
            shell_println!("  topology <mode>       extend/mirror/single");
            shell_println!("  stats / test / init");
        }
    }
}

/// `sysanimations` / `sanim` — system animation settings.
fn cmd_sysanimations(args: &str) {
    use crate::fs::sysanimations;
    let parts: Vec<&str> = args.split_whitespace().collect();
    let sub = parts.first().copied().unwrap_or("");
    match sub {
        "init" => {
            sysanimations::init_defaults();
            shell_println!("System animations initialized");
        }
        "list" => {
            let anims = sysanimations::list_animations();
            let (enabled, speed, reduce) = sysanimations::global_state();
            shell_println!("Global: {}, Speed: {}%, Reduce motion: {}", if enabled { "ON" } else { "OFF" }, speed, reduce);
            for a in &anims {
                let eff = sysanimations::effective_duration(a.animation_type);
                shell_println!("  {} — {}ms ({}) [{}] effective: {}ms",
                    a.animation_type.label(), a.duration_ms, a.easing.label(),
                    if a.enabled { "ON" } else { "OFF" }, eff);
            }
        }
        "enable" => {
            match sysanimations::set_global_enabled(true) {
                Ok(()) => shell_println!("Animations enabled"),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "disable" => {
            match sysanimations::set_global_enabled(false) {
                Ok(()) => shell_println!("Animations disabled"),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "speed" => {
            let pct: u32 = parts.get(1).unwrap_or(&"100").parse().unwrap_or(100);
            match sysanimations::set_speed(pct) {
                Ok(()) => shell_println!("Speed: {}%", pct.clamp(10, 400)),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "reduce" => {
            let on = parts.get(1).copied().unwrap_or("on") != "off";
            match sysanimations::set_reduce_motion(on) {
                Ok(()) => shell_println!("Reduce motion: {}", on),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "stats" => {
            let (count, enabled, changes, ops) = sysanimations::stats();
            shell_println!("Animations: {}, Enabled: {}, Changes: {}, Ops: {}", count, enabled, changes, ops);
        }
        "test" => sysanimations::self_test(),
        _ => {
            shell_println!("Usage: sysanimations <command>");
            shell_println!("  list                List animations");
            shell_println!("  enable / disable    Toggle all");
            shell_println!("  speed <percent>     Speed (10-400%)");
            shell_println!("  reduce [on|off]     Reduce motion");
            shell_println!("  stats / test / init");
        }
    }
}

/// `filevault` / `fvault` — encrypted folder management.
fn cmd_filevault(args: &str) {
    use crate::fs::filevault;
    let parts: Vec<&str> = args.split_whitespace().collect();
    let sub = parts.first().copied().unwrap_or("");
    match sub {
        "init" => {
            filevault::init_defaults();
            shell_println!("File vault initialized");
        }
        "list" => {
            let vaults = filevault::list_vaults();
            if vaults.is_empty() {
                shell_println!("No vaults");
            } else {
                for v in &vaults {
                    shell_println!("#{}: {} — {} [{}] at {} → {}",
                        v.id, v.name, v.state.label(), v.cipher.label(),
                        v.path, v.mount_point);
                    shell_println!("    Auto-lock: {}s", v.auto_lock_secs);
                }
            }
        }
        "create" => {
            let name = parts.get(1).copied().unwrap_or("Vault");
            let path = parts.get(2).copied().unwrap_or("/home/vault");
            let password = parts.get(3).copied().unwrap_or("password");
            let cipher = match parts.get(4).copied().unwrap_or("aes") {
                "chacha" | "chacha20" => filevault::VaultCipher::ChaCha20Poly1305,
                "cbc" => filevault::VaultCipher::Aes256Cbc,
                _ => filevault::VaultCipher::Aes256Gcm,
            };
            match filevault::create_vault(name, path, password, cipher) {
                Ok(id) => shell_println!("Created vault #{}: {} ({})", id, name, cipher.label()),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "unlock" => {
            let id: u32 = match parts.get(1).unwrap_or(&"0").parse() {
                Ok(v) => v,
                Err(_) => { shell_println!("Invalid vault ID"); return; }
            };
            let password = parts.get(2).copied().unwrap_or("");
            match filevault::unlock(id, password) {
                Ok(()) => shell_println!("Vault #{} unlocked", id),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "lock" => {
            let id: u32 = match parts.get(1).unwrap_or(&"0").parse() {
                Ok(v) => v,
                Err(_) => { shell_println!("Invalid vault ID"); return; }
            };
            match filevault::lock(id) {
                Ok(()) => shell_println!("Vault #{} locked", id),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "autolock" => {
            let id: u32 = match parts.get(1).unwrap_or(&"0").parse() {
                Ok(v) => v,
                Err(_) => { shell_println!("Invalid vault ID"); return; }
            };
            let secs: u32 = parts.get(2).unwrap_or(&"300").parse().unwrap_or(300);
            match filevault::set_auto_lock(id, secs) {
                Ok(()) => shell_println!("Auto-lock: {}s", secs),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "stats" => {
            let (count, unlocked, unlocks, failed, ops) = filevault::stats();
            shell_println!("Vaults: {}, Unlocked: {}, Unlocks: {}, Failed: {}, Ops: {}", count, unlocked, unlocks, failed, ops);
        }
        "test" => filevault::self_test(),
        _ => {
            shell_println!("Usage: filevault <command>");
            shell_println!("  list                     List vaults");
            shell_println!("  create <name> <path> <pw> [cipher]");
            shell_println!("  unlock <id> <password>   Unlock vault");
            shell_println!("  lock <id>                Lock vault");
            shell_println!("  autolock <id> <seconds>  Auto-lock timeout");
            shell_println!("  Ciphers: aes chacha cbc");
            shell_println!("  stats / test / init");
        }
    }
}

/// `mousegestures` / `mgest` — mouse gesture navigation.
fn cmd_mousegestures(args: &str) {
    use crate::fs::mousegestures;
    let parts: Vec<&str> = args.split_whitespace().collect();
    let sub = parts.first().copied().unwrap_or("");
    match sub {
        "init" => {
            mousegestures::init_defaults();
            shell_println!("Mouse gestures initialized");
        }
        "list" => {
            let bindings = mousegestures::list_bindings();
            if bindings.is_empty() {
                shell_println!("No gesture bindings");
            } else {
                for b in &bindings {
                    shell_println!("#{}: {} → {} ({}) [{}] used: {}",
                        b.id, b.pattern.label(), b.action, b.description,
                        if b.enabled { "ON" } else { "OFF" }, b.use_count);
                }
            }
        }
        "recognize" | "test-gesture" => {
            // Parse directions from args: e.g., "left up right"
            let dirs: Vec<mousegestures::Direction> = parts[1..].iter().filter_map(|s| {
                match *s {
                    "up" | "u" => Some(mousegestures::Direction::Up),
                    "down" | "d" => Some(mousegestures::Direction::Down),
                    "left" | "l" => Some(mousegestures::Direction::Left),
                    "right" | "r" => Some(mousegestures::Direction::Right),
                    _ => None,
                }
            }).collect();
            if dirs.is_empty() {
                shell_println!("Usage: mousegestures recognize <dir> [dir...]");
                return;
            }
            match mousegestures::recognize(&dirs) {
                Ok(Some(action)) => shell_println!("Recognized: {}", action),
                Ok(None) => shell_println!("No matching gesture"),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "bind" => {
            // bind <dirs> <action> [desc]
            // e.g., bind left+up new_tab "New Tab"
            let dir_str = parts.get(1).copied().unwrap_or("left");
            let action = parts.get(2).copied().unwrap_or("action");
            let desc = parts.get(3).copied().unwrap_or(action);
            let dirs: Vec<mousegestures::Direction> = dir_str.split('+').filter_map(|s| {
                match s {
                    "up" | "u" => Some(mousegestures::Direction::Up),
                    "down" | "d" => Some(mousegestures::Direction::Down),
                    "left" | "l" => Some(mousegestures::Direction::Left),
                    "right" | "r" => Some(mousegestures::Direction::Right),
                    _ => None,
                }
            }).collect();
            match mousegestures::bind(dirs, action, desc) {
                Ok(id) => shell_println!("Bound gesture #{}: {} → {}", id, dir_str, action),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "unbind" => {
            let id: u32 = match parts.get(1).unwrap_or(&"0").parse() {
                Ok(v) => v,
                Err(_) => { shell_println!("Invalid binding ID"); return; }
            };
            match mousegestures::unbind(id) {
                Ok(()) => shell_println!("Unbound gesture #{}", id),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "enable" => {
            match mousegestures::set_enabled(true) {
                Ok(()) => shell_println!("Gestures enabled"),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "disable" => {
            match mousegestures::set_enabled(false) {
                Ok(()) => shell_println!("Gestures disabled"),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "stats" => {
            let (count, gestures, recognized, ops) = mousegestures::stats();
            shell_println!("Bindings: {}, Gestures: {}, Recognized: {}, Ops: {}", count, gestures, recognized, ops);
        }
        "test" => mousegestures::self_test(),
        _ => {
            shell_println!("Usage: mousegestures <command>");
            shell_println!("  list                   List bindings");
            shell_println!("  recognize <dirs...>    Test gesture");
            shell_println!("  bind <dirs> <action>   Bind gesture");
            shell_println!("  unbind <id>            Remove binding");
            shell_println!("  enable / disable       Toggle gestures");
            shell_println!("  Directions: up down left right (combine with +)");
            shell_println!("  stats / test / init");
        }
    }
}

/// `fontsettings` / `fntset` — font rendering configuration.
fn cmd_fontsettings(args: &str) {
    use crate::fs::fontsettings;
    let parts: Vec<&str> = args.split_whitespace().collect();
    let sub = parts.first().copied().unwrap_or("");
    match sub {
        "init" => { fontsettings::init_defaults(); shell_println!("Font settings initialised."); }
        "show" | "" => {
            fontsettings::init_defaults();
            match fontsettings::get_config() {
                Some(cfg) => {
                    shell_println!("Font Settings:");
                    shell_println!("  Antialiasing:   {}", cfg.antialiasing.label());
                    shell_println!("  Hinting:        {}", cfg.hinting.label());
                    shell_println!("  Default font:   {} ({} dp)", cfg.default_family, cfg.default_size_dp);
                    shell_println!("  Monospace font: {} ({} dp)", cfg.monospace_family, cfg.monospace_size_dp);
                    shell_println!("  Document font:  {}", cfg.document_family);
                    shell_println!("  Min size:       {} dp", cfg.min_size_dp);
                    shell_println!("  Text scale:     {}%", cfg.text_scale_percent);
                    shell_println!("  Ligatures:      {}", if cfg.ligatures { "on" } else { "off" });
                }
                None => shell_println!("Font settings not initialised."),
            }
        }
        "aa" => {
            let method = parts.get(1).copied().unwrap_or("");
            let aa = match method {
                "none" => fontsettings::Antialiasing::None,
                "grayscale" | "gray" => fontsettings::Antialiasing::Grayscale,
                "subpixel" | "rgb" => fontsettings::Antialiasing::Subpixel,
                "bgr" => fontsettings::Antialiasing::SubpixelBgr,
                _ => { shell_println!("Usage: fontsettings aa <none|grayscale|subpixel|bgr>"); return; }
            };
            match fontsettings::set_antialiasing(aa) {
                Ok(()) => shell_println!("Antialiasing set to {}.", aa.label()),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "hinting" | "hint" => {
            let level = parts.get(1).copied().unwrap_or("");
            let h = match level {
                "none" => fontsettings::Hinting::None,
                "slight" => fontsettings::Hinting::Slight,
                "medium" => fontsettings::Hinting::Medium,
                "full" => fontsettings::Hinting::Full,
                _ => { shell_println!("Usage: fontsettings hinting <none|slight|medium|full>"); return; }
            };
            match fontsettings::set_hinting(h) {
                Ok(()) => shell_println!("Hinting set to {}.", h.label()),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "font" => {
            let family = parts.get(1..).map(|s| s.join(" ")).unwrap_or_default();
            if family.is_empty() { shell_println!("Usage: fontsettings font <family>"); return; }
            match fontsettings::set_default_font(&family) {
                Ok(()) => shell_println!("Default font set to '{}'.", family),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "mono" => {
            let family = parts.get(1..).map(|s| s.join(" ")).unwrap_or_default();
            if family.is_empty() { shell_println!("Usage: fontsettings mono <family>"); return; }
            match fontsettings::set_monospace_font(&family) {
                Ok(()) => shell_println!("Monospace font set to '{}'.", family),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "size" => {
            let val = parts.get(1).and_then(|s| s.parse::<u32>().ok());
            match val {
                Some(v) => match fontsettings::set_default_size(v) {
                    Ok(()) => shell_println!("Default size set to {} dp.", v),
                    Err(e) => shell_println!("Error: {:?}", e),
                },
                None => shell_println!("Usage: fontsettings size <decipoints>"),
            }
        }
        "scale" => {
            let val = parts.get(1).and_then(|s| s.parse::<u32>().ok());
            match val {
                Some(v) => match fontsettings::set_text_scale(v) {
                    Ok(()) => shell_println!("Text scale set to {}%.", v),
                    Err(e) => shell_println!("Error: {:?}", e),
                },
                None => shell_println!("Usage: fontsettings scale <percent>"),
            }
        }
        "ligatures" | "lig" => {
            let val = parts.get(1).copied().unwrap_or("");
            match val {
                "on" | "true" => match fontsettings::set_ligatures(true) {
                    Ok(()) => shell_println!("Ligatures enabled."),
                    Err(e) => shell_println!("Error: {:?}", e),
                },
                "off" | "false" => match fontsettings::set_ligatures(false) {
                    Ok(()) => shell_println!("Ligatures disabled."),
                    Err(e) => shell_println!("Error: {:?}", e),
                },
                _ => shell_println!("Usage: fontsettings ligatures <on|off>"),
            }
        }
        "stats" => {
            let (changes, ops) = fontsettings::stats();
            shell_println!("Font settings stats:");
            shell_println!("  Total changes: {}", changes);
            shell_println!("  Operations:    {}", ops);
        }
        "test" => fontsettings::self_test(),
        _ => {
            shell_println!("Usage: fontsettings <subcommand>");
            shell_println!("  show                  Current config");
            shell_println!("  aa <method>           Set antialiasing (none|grayscale|subpixel|bgr)");
            shell_println!("  hinting <level>       Set hinting (none|slight|medium|full)");
            shell_println!("  font <family>         Set default font family");
            shell_println!("  mono <family>         Set monospace font family");
            shell_println!("  size <decipoints>     Set default size (60-400)");
            shell_println!("  scale <percent>       Set text scale (50-300)");
            shell_println!("  ligatures <on|off>    Toggle ligatures");
            shell_println!("  stats / test / init");
        }
    }
}

/// `notifbadge` / `nbadge` — notification badge management.
fn cmd_notifbadge(args: &str) {
    use crate::fs::notifbadge;
    let parts: Vec<&str> = args.split_whitespace().collect();
    let sub = parts.first().copied().unwrap_or("");
    match sub {
        "init" => { notifbadge::init_defaults(); shell_println!("Notification badges initialised."); }
        "show" | "" => {
            notifbadge::init_defaults();
            let visible = notifbadge::list_visible();
            if visible.is_empty() {
                shell_println!("No visible badges.");
            } else {
                shell_println!("Visible badges:");
                for b in &visible {
                    match b.style {
                        notifbadge::BadgeStyle::Count => shell_println!("  {} — count: {}", b.app_name, b.count),
                        notifbadge::BadgeStyle::Dot => shell_println!("  {} — dot", b.app_name),
                        notifbadge::BadgeStyle::Attention => shell_println!("  {} — attention", b.app_name),
                        notifbadge::BadgeStyle::Progress => shell_println!("  {} — progress: {}%", b.app_name, b.progress),
                    }
                }
            }
        }
        "set" => {
            let app = parts.get(1).copied().unwrap_or("");
            let count = parts.get(2).and_then(|s| s.parse::<u32>().ok());
            if app.is_empty() || count.is_none() {
                shell_println!("Usage: notifbadge set <app> <count>");
                return;
            }
            match notifbadge::set_count(app, count.unwrap_or(0)) {
                Ok(()) => shell_println!("Badge for '{}' set to {}.", app, count.unwrap_or(0)),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "inc" | "increment" => {
            let app = parts.get(1).copied().unwrap_or("");
            if app.is_empty() { shell_println!("Usage: notifbadge inc <app>"); return; }
            match notifbadge::increment(app) {
                Ok(c) => shell_println!("Badge for '{}' incremented to {}.", app, c),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "dot" => {
            let app = parts.get(1).copied().unwrap_or("");
            let vis = parts.get(2).copied().unwrap_or("true");
            if app.is_empty() { shell_println!("Usage: notifbadge dot <app> [true|false]"); return; }
            let v = vis != "false";
            match notifbadge::set_dot(app, v) {
                Ok(()) => shell_println!("Dot badge for '{}' set to {}.", app, v),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "progress" | "prog" => {
            let app = parts.get(1).copied().unwrap_or("");
            let pct = parts.get(2).and_then(|s| s.parse::<u32>().ok());
            if app.is_empty() || pct.is_none() {
                shell_println!("Usage: notifbadge progress <app> <0-100>");
                return;
            }
            match notifbadge::set_progress(app, pct.unwrap_or(0)) {
                Ok(()) => shell_println!("Progress badge for '{}' set to {}%.", app, pct.unwrap_or(0)),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "clear" => {
            let app = parts.get(1).copied().unwrap_or("");
            if app.is_empty() {
                match notifbadge::clear_all() {
                    Ok(()) => shell_println!("All badges cleared."),
                    Err(e) => shell_println!("Error: {:?}", e),
                }
            } else {
                match notifbadge::clear(app) {
                    Ok(()) => shell_println!("Badge for '{}' cleared.", app),
                    Err(e) => shell_println!("Error: {:?}", e),
                }
            }
        }
        "get" => {
            let app = parts.get(1).copied().unwrap_or("");
            if app.is_empty() { shell_println!("Usage: notifbadge get <app>"); return; }
            match notifbadge::get_badge(app) {
                Some(b) => {
                    shell_println!("Badge for '{}':", app);
                    shell_println!("  Style:    {}", b.style.label());
                    shell_println!("  Count:    {}", b.count);
                    shell_println!("  Progress: {}%", b.progress);
                    shell_println!("  Visible:  {}", b.visible);
                }
                None => shell_println!("No badge for '{}'.", app),
            }
        }
        "enable" => match notifbadge::set_global_enabled(true) {
            Ok(()) => shell_println!("Badges enabled globally."),
            Err(e) => shell_println!("Error: {:?}", e),
        },
        "disable" => match notifbadge::set_global_enabled(false) {
            Ok(()) => shell_println!("Badges disabled globally."),
            Err(e) => shell_println!("Error: {:?}", e),
        },
        "stats" => {
            let (count, visible, updates, ops) = notifbadge::stats();
            shell_println!("Badge stats:");
            shell_println!("  Badge count:   {}", count);
            shell_println!("  Visible count: {}", visible);
            shell_println!("  Total updates: {}", updates);
            shell_println!("  Operations:    {}", ops);
        }
        "test" => notifbadge::self_test(),
        _ => {
            shell_println!("Usage: notifbadge <subcommand>");
            shell_println!("  show                  List visible badges");
            shell_println!("  set <app> <count>     Set count badge");
            shell_println!("  inc <app>             Increment count");
            shell_println!("  dot <app> [bool]      Set dot badge");
            shell_println!("  progress <app> <pct>  Set progress badge");
            shell_println!("  get <app>             Show badge details");
            shell_println!("  clear [app]           Clear badge(s)");
            shell_println!("  enable / disable      Toggle globally");
            shell_println!("  stats / test / init");
        }
    }
}

/// `lockwallpaper` / `lwp` — lock screen wallpaper management.
fn cmd_lockwallpaper(args: &str) {
    use crate::fs::lockwallpaper;
    let parts: Vec<&str> = args.split_whitespace().collect();
    let sub = parts.first().copied().unwrap_or("");
    match sub {
        "init" => { lockwallpaper::init_defaults(); shell_println!("Lock wallpaper initialised."); }
        "show" | "" => {
            lockwallpaper::init_defaults();
            match lockwallpaper::get_config() {
                Some(cfg) => {
                    shell_println!("Lock Wallpaper:");
                    shell_println!("  Mode:           {}", cfg.mode.label());
                    shell_println!("  Current image:  {}", cfg.current_image);
                    shell_println!("  Fit:            {}", cfg.fit_mode.label());
                    shell_println!("  Solid color:    {}", cfg.solid_color);
                    shell_println!("  Show clock:     {}", cfg.show_clock);
                    shell_println!("  Show notifs:    {}", cfg.show_notifications);
                    shell_println!("  Blur behind:    {}", cfg.blur_behind);
                    if cfg.mode == lockwallpaper::LockWallpaperMode::Slideshow {
                        shell_println!("  Slideshow dir:  {}", cfg.slideshow_dir);
                        shell_println!("  Interval:       {}s", cfg.slideshow_interval_secs);
                        shell_println!("  Images:         {}", cfg.slideshow_images.len());
                    }
                }
                None => shell_println!("Lock wallpaper not initialised."),
            }
        }
        "image" | "set" => {
            let path = parts.get(1..).map(|s| s.join(" ")).unwrap_or_default();
            if path.is_empty() { shell_println!("Usage: lockwallpaper image <path>"); return; }
            match lockwallpaper::set_image(&path) {
                Ok(()) => shell_println!("Lock wallpaper set to '{}'.", path),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "mode" => {
            let m = parts.get(1).copied().unwrap_or("");
            let mode = match m {
                "static" => lockwallpaper::LockWallpaperMode::Static,
                "slideshow" => lockwallpaper::LockWallpaperMode::Slideshow,
                "spotlight" => lockwallpaper::LockWallpaperMode::Spotlight,
                "color" | "solid" => lockwallpaper::LockWallpaperMode::SolidColor,
                "desktop" => lockwallpaper::LockWallpaperMode::SameAsDesktop,
                _ => { shell_println!("Usage: lockwallpaper mode <static|slideshow|spotlight|color|desktop>"); return; }
            };
            match lockwallpaper::set_mode(mode) {
                Ok(()) => shell_println!("Lock wallpaper mode set to {}.", mode.label()),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "slideshow" => {
            let dir = parts.get(1).copied().unwrap_or("");
            let interval = parts.get(2).and_then(|s| s.parse::<u32>().ok()).unwrap_or(60);
            if dir.is_empty() { shell_println!("Usage: lockwallpaper slideshow <dir> [interval_secs]"); return; }
            match lockwallpaper::set_slideshow_dir(dir, interval) {
                Ok(()) => shell_println!("Slideshow set: dir='{}', interval={}s.", dir, interval),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "addimage" | "add" => {
            let path = parts.get(1..).map(|s| s.join(" ")).unwrap_or_default();
            if path.is_empty() { shell_println!("Usage: lockwallpaper add <image_path>"); return; }
            match lockwallpaper::add_slideshow_image(&path) {
                Ok(()) => shell_println!("Added '{}' to slideshow.", path),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "rotate" | "next" => {
            match lockwallpaper::rotate() {
                Ok(img) => shell_println!("Rotated to: {}", img),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "fit" => {
            let f = parts.get(1).copied().unwrap_or("");
            let fit = match f {
                "fill" => lockwallpaper::FitMode::Fill,
                "fit" => lockwallpaper::FitMode::Fit,
                "stretch" => lockwallpaper::FitMode::Stretch,
                "tile" => lockwallpaper::FitMode::Tile,
                "center" => lockwallpaper::FitMode::Center,
                "span" => lockwallpaper::FitMode::Span,
                _ => { shell_println!("Usage: lockwallpaper fit <fill|fit|stretch|tile|center|span>"); return; }
            };
            match lockwallpaper::set_fit_mode(fit) {
                Ok(()) => shell_println!("Fit mode set to {}.", fit.label()),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "color" => {
            let c = parts.get(1).copied().unwrap_or("");
            if c.is_empty() { shell_println!("Usage: lockwallpaper color <#rrggbb>"); return; }
            match lockwallpaper::set_solid_color(c) {
                Ok(()) => shell_println!("Solid color set to '{}'.", c),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "clock" => {
            let val = parts.get(1).copied().unwrap_or("");
            let (clk, notif) = match val {
                "on" => (true, true),
                "off" => (false, false),
                _ => { shell_println!("Usage: lockwallpaper clock <on|off>"); return; }
            };
            match lockwallpaper::set_overlays(clk, notif) {
                Ok(()) => shell_println!("Overlays set: clock={}, notifications={}.", clk, notif),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "blur" => {
            let val = parts.get(1).copied().unwrap_or("");
            match val {
                "on" | "true" => match lockwallpaper::set_blur(true) {
                    Ok(()) => shell_println!("Blur enabled."),
                    Err(e) => shell_println!("Error: {:?}", e),
                },
                "off" | "false" => match lockwallpaper::set_blur(false) {
                    Ok(()) => shell_println!("Blur disabled."),
                    Err(e) => shell_println!("Error: {:?}", e),
                },
                _ => shell_println!("Usage: lockwallpaper blur <on|off>"),
            }
        }
        "stats" => {
            let (rotations, changes, ops) = lockwallpaper::stats();
            shell_println!("Lock wallpaper stats:");
            shell_println!("  Total rotations: {}", rotations);
            shell_println!("  Total changes:   {}", changes);
            shell_println!("  Operations:      {}", ops);
        }
        "test" => lockwallpaper::self_test(),
        _ => {
            shell_println!("Usage: lockwallpaper <subcommand>");
            shell_println!("  show                  Current config");
            shell_println!("  image <path>          Set static image");
            shell_println!("  mode <type>           Set mode (static|slideshow|spotlight|color|desktop)");
            shell_println!("  slideshow <dir> [s]   Set slideshow directory");
            shell_println!("  add <path>            Add slideshow image");
            shell_println!("  rotate                Next slideshow image");
            shell_println!("  fit <mode>            Set fit mode");
            shell_println!("  color <#hex>          Set solid color");
            shell_println!("  clock <on|off>        Toggle overlays");
            shell_println!("  blur <on|off>         Toggle blur behind");
            shell_println!("  stats / test / init");
        }
    }
}

/// `systemsounds` / `ssounds` — system sound scheme management.
fn cmd_systemsounds(args: &str) {
    use crate::fs::systemsounds;
    let parts: Vec<&str> = args.split_whitespace().collect();
    let sub = parts.first().copied().unwrap_or("");
    match sub {
        "init" => { systemsounds::init_defaults(); shell_println!("System sounds initialised."); }
        "show" | "" => {
            systemsounds::init_defaults();
            shell_println!("Active scheme: {}", systemsounds::active_scheme());
            shell_println!("Available schemes: {:?}", systemsounds::list_schemes());
            let assignments = systemsounds::list_assignments();
            if assignments.is_empty() {
                shell_println!("No assignments in active scheme.");
            } else {
                shell_println!("Assignments ({}):", assignments.len());
                for a in &assignments {
                    let status = if a.enabled { "on" } else { "off" };
                    shell_println!("  {:20} {} [{}] (plays: {})", a.event.label(), a.sound_path, status, a.play_count);
                }
            }
        }
        "play" => {
            let event_name = parts.get(1).copied().unwrap_or("");
            let event = match parse_sound_event(event_name) {
                Some(e) => e,
                None => { shell_println!("Unknown event '{}'. Use: startup, shutdown, login, logout, lock, unlock, notification, error, warning, info, device_connect, device_disconnect, recycle_bin, message_send, message_receive, screenshot, volume, low_battery", event_name); return; }
            };
            match systemsounds::play(event) {
                Ok(Some(path)) => shell_println!("Playing: {}", path),
                Ok(None) => shell_println!("Sound disabled or not assigned."),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "set" => {
            let event_name = parts.get(1).copied().unwrap_or("");
            let path = parts.get(2..).map(|s| s.join(" ")).unwrap_or_default();
            let event = match parse_sound_event(event_name) {
                Some(e) => e,
                None => { shell_println!("Unknown event. Use: startup, shutdown, notification, error, etc."); return; }
            };
            if path.is_empty() { shell_println!("Usage: systemsounds set <event> <path>"); return; }
            match systemsounds::set_sound(event, &path) {
                Ok(()) => shell_println!("Sound for {} set to '{}'.", event.label(), path),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "enable" => {
            let event_name = parts.get(1).copied().unwrap_or("");
            if event_name.is_empty() {
                match systemsounds::set_global_enabled(true) {
                    Ok(()) => shell_println!("System sounds enabled globally."),
                    Err(e) => shell_println!("Error: {:?}", e),
                }
            } else {
                let event = match parse_sound_event(event_name) {
                    Some(e) => e,
                    None => { shell_println!("Unknown event."); return; }
                };
                match systemsounds::set_event_enabled(event, true) {
                    Ok(()) => shell_println!("Sound for {} enabled.", event.label()),
                    Err(e) => shell_println!("Error: {:?}", e),
                }
            }
        }
        "disable" => {
            let event_name = parts.get(1).copied().unwrap_or("");
            if event_name.is_empty() {
                match systemsounds::set_global_enabled(false) {
                    Ok(()) => shell_println!("System sounds disabled globally."),
                    Err(e) => shell_println!("Error: {:?}", e),
                }
            } else {
                let event = match parse_sound_event(event_name) {
                    Some(e) => e,
                    None => { shell_println!("Unknown event."); return; }
                };
                match systemsounds::set_event_enabled(event, false) {
                    Ok(()) => shell_println!("Sound for {} disabled.", event.label()),
                    Err(e) => shell_println!("Error: {:?}", e),
                }
            }
        }
        "scheme" => {
            let name = parts.get(1).copied().unwrap_or("");
            if name.is_empty() {
                shell_println!("Active: {}", systemsounds::active_scheme());
                shell_println!("Available: {:?}", systemsounds::list_schemes());
            } else {
                match systemsounds::set_scheme(name) {
                    Ok(()) => shell_println!("Scheme set to '{}'.", name),
                    Err(e) => shell_println!("Error: {:?}", e),
                }
            }
        }
        "stats" => {
            let (schemes, events, plays, ops) = systemsounds::stats();
            shell_println!("System sounds stats:");
            shell_println!("  Scheme count: {}", schemes);
            shell_println!("  Event count:  {}", events);
            shell_println!("  Total plays:  {}", plays);
            shell_println!("  Operations:   {}", ops);
        }
        "test" => systemsounds::self_test(),
        _ => {
            shell_println!("Usage: systemsounds <subcommand>");
            shell_println!("  show                  Current assignments");
            shell_println!("  play <event>          Play event sound");
            shell_println!("  set <event> <path>    Set sound for event");
            shell_println!("  enable [event]        Enable sound/all");
            shell_println!("  disable [event]       Disable sound/all");
            shell_println!("  scheme [name]         Show/switch scheme");
            shell_println!("  stats / test / init");
            shell_println!("  Events: startup shutdown login logout lock unlock notification");
            shell_println!("          error warning info device_connect device_disconnect");
            shell_println!("          recycle_bin message_send message_receive screenshot");
            shell_println!("          volume low_battery");
        }
    }
}

/// Parse a sound event name string into a SoundEvent enum.
fn parse_sound_event(name: &str) -> Option<crate::fs::systemsounds::SoundEvent> {
    use crate::fs::systemsounds::SoundEvent;
    match name {
        "startup" => Some(SoundEvent::Startup),
        "shutdown" => Some(SoundEvent::Shutdown),
        "login" => Some(SoundEvent::Login),
        "logout" => Some(SoundEvent::Logout),
        "lock" => Some(SoundEvent::LockScreen),
        "unlock" => Some(SoundEvent::UnlockScreen),
        "notification" | "notif" => Some(SoundEvent::Notification),
        "error" => Some(SoundEvent::Error),
        "warning" | "warn" => Some(SoundEvent::Warning),
        "info" | "information" => Some(SoundEvent::Information),
        "device_connect" | "connect" => Some(SoundEvent::DeviceConnect),
        "device_disconnect" | "disconnect" => Some(SoundEvent::DeviceDisconnect),
        "recycle_bin" | "recycle" => Some(SoundEvent::EmptyRecycleBin),
        "message_send" | "send" => Some(SoundEvent::MessageSend),
        "message_receive" | "receive" => Some(SoundEvent::MessageReceive),
        "screenshot" => Some(SoundEvent::Screenshot),
        "volume" | "volume_change" => Some(SoundEvent::VolumeChange),
        "low_battery" | "battery" => Some(SoundEvent::LowBattery),
        _ => None,
    }
}

/// `hotcorners` / `hcorn` — hot corner screen actions.
fn cmd_hotcorners(args: &str) {
    use crate::fs::hotcorners;
    let parts: Vec<&str> = args.split_whitespace().collect();
    let sub = parts.first().copied().unwrap_or("");
    match sub {
        "init" => { hotcorners::init_defaults(); shell_println!("Hot corners initialised."); }
        "show" | "" => {
            hotcorners::init_defaults();
            let all = hotcorners::get_all();
            shell_println!("Hot Corners:");
            for c in &all {
                let status = if c.enabled { "on" } else { "off" };
                let modifier = if c.require_modifier { " (modifier required)" } else { "" };
                shell_println!("  {:12} → {:20} delay={}ms [{}]{}",
                    c.corner.label(), c.action.label(), c.delay_ms, status, modifier);
            }
        }
        "set" => {
            let corner_name = parts.get(1).copied().unwrap_or("");
            let action_name = parts.get(2).copied().unwrap_or("");
            let corner = match parse_corner(corner_name) {
                Some(c) => c,
                None => { shell_println!("Corner: tl, tr, bl, br"); return; }
            };
            let action = match parse_corner_action(action_name) {
                Some(a) => a,
                None => { shell_println!("Actions: none, windows, desktop, screensaver, lock, notifications, quicksettings, next, prev, launcher, disable"); return; }
            };
            match hotcorners::set_action(corner, action) {
                Ok(()) => shell_println!("{} set to {}.", corner.label(), action.label()),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "delay" => {
            let corner_name = parts.get(1).copied().unwrap_or("");
            let ms = parts.get(2).and_then(|s| s.parse::<u32>().ok());
            let corner = match parse_corner(corner_name) {
                Some(c) => c,
                None => { shell_println!("Usage: hotcorners delay <tl|tr|bl|br> <ms>"); return; }
            };
            match ms {
                Some(d) => match hotcorners::set_delay(corner, d) {
                    Ok(()) => shell_println!("{} delay set to {}ms.", corner.label(), d),
                    Err(e) => shell_println!("Error: {:?}", e),
                },
                None => shell_println!("Usage: hotcorners delay <corner> <ms>"),
            }
        }
        "trigger" => {
            let corner_name = parts.get(1).copied().unwrap_or("");
            let corner = match parse_corner(corner_name) {
                Some(c) => c,
                None => { shell_println!("Usage: hotcorners trigger <tl|tr|bl|br>"); return; }
            };
            match hotcorners::trigger(corner) {
                Ok(action) => shell_println!("Triggered: {}", action.label()),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "enable" => match hotcorners::set_global_enabled(true) {
            Ok(()) => shell_println!("Hot corners enabled."),
            Err(e) => shell_println!("Error: {:?}", e),
        },
        "disable" => match hotcorners::set_global_enabled(false) {
            Ok(()) => shell_println!("Hot corners disabled."),
            Err(e) => shell_println!("Error: {:?}", e),
        },
        "stats" => {
            let (enabled, triggers, ops) = hotcorners::stats();
            shell_println!("Hot corners stats:");
            shell_println!("  Enabled corners: {}", enabled);
            shell_println!("  Total triggers:  {}", triggers);
            shell_println!("  Operations:      {}", ops);
        }
        "test" => hotcorners::self_test(),
        _ => {
            shell_println!("Usage: hotcorners <subcommand>");
            shell_println!("  show                  Current config");
            shell_println!("  set <corner> <action>  Set action");
            shell_println!("  delay <corner> <ms>    Set delay");
            shell_println!("  trigger <corner>       Test trigger");
            shell_println!("  enable / disable       Toggle globally");
            shell_println!("  Corners: tl, tr, bl, br");
            shell_println!("  stats / test / init");
        }
    }
}

fn parse_corner(s: &str) -> Option<crate::fs::hotcorners::Corner> {
    use crate::fs::hotcorners::Corner;
    match s {
        "tl" | "top-left" | "topleft" => Some(Corner::TopLeft),
        "tr" | "top-right" | "topright" => Some(Corner::TopRight),
        "bl" | "bottom-left" | "bottomleft" => Some(Corner::BottomLeft),
        "br" | "bottom-right" | "bottomright" => Some(Corner::BottomRight),
        _ => None,
    }
}

fn parse_corner_action(s: &str) -> Option<crate::fs::hotcorners::CornerAction> {
    use crate::fs::hotcorners::CornerAction;
    match s {
        "none" => Some(CornerAction::None),
        "windows" | "all" => Some(CornerAction::ShowAllWindows),
        "desktop" | "show-desktop" => Some(CornerAction::ShowDesktop),
        "screensaver" | "saver" => Some(CornerAction::StartScreensaver),
        "lock" => Some(CornerAction::LockScreen),
        "notifications" | "notif" => Some(CornerAction::OpenNotifications),
        "quicksettings" | "qs" => Some(CornerAction::OpenQuickSettings),
        "next" | "next-desktop" => Some(CornerAction::NextDesktop),
        "prev" | "prev-desktop" => Some(CornerAction::PrevDesktop),
        "launcher" | "start" => Some(CornerAction::OpenLauncher),
        "disable" | "disable-screen" => Some(CornerAction::DisableScreen),
        _ => None,
    }
}

/// `dynlock` / `dlock` — dynamic proximity-based screen lock.
fn cmd_dynlock(args: &str) {
    use crate::fs::dynlock;
    let parts: Vec<&str> = args.split_whitespace().collect();
    let sub = parts.first().copied().unwrap_or("");
    match sub {
        "init" => { dynlock::init_defaults(); shell_println!("Dynamic lock initialised."); }
        "show" | "" => {
            dynlock::init_defaults();
            shell_println!("Dynamic Lock:");
            shell_println!("  State: {}", dynlock::lock_state().label());
            let devs = dynlock::list_devices();
            if devs.is_empty() {
                shell_println!("  No paired devices.");
            } else {
                shell_println!("  Devices ({}):", devs.len());
                for d in &devs {
                    let status = if d.enabled { d.status.label() } else { "Disabled" };
                    shell_println!("    {} [{}] — {} (locks: {})", d.name, d.address, status, d.lock_count);
                }
            }
        }
        "add" => {
            let name = parts.get(1).copied().unwrap_or("");
            let addr = parts.get(2).copied().unwrap_or("");
            if name.is_empty() || addr.is_empty() {
                shell_println!("Usage: dynlock add <name> <bt_address>");
                return;
            }
            match dynlock::add_device(name, addr) {
                Ok(()) => shell_println!("Device '{}' [{}] added.", name, addr),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "remove" | "rm" => {
            let addr = parts.get(1).copied().unwrap_or("");
            if addr.is_empty() { shell_println!("Usage: dynlock remove <bt_address>"); return; }
            match dynlock::remove_device(addr) {
                Ok(()) => shell_println!("Device removed."),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "enable" => match dynlock::set_enabled(true) {
            Ok(()) => shell_println!("Dynamic lock enabled."),
            Err(e) => shell_println!("Error: {:?}", e),
        },
        "disable" => match dynlock::set_enabled(false) {
            Ok(()) => shell_println!("Dynamic lock disabled."),
            Err(e) => shell_println!("Error: {:?}", e),
        },
        "grace" => {
            let secs = parts.get(1).and_then(|s| s.parse::<u32>().ok());
            match secs {
                Some(s) => match dynlock::set_grace(s) {
                    Ok(()) => shell_println!("Grace period set to {}s.", s),
                    Err(e) => shell_println!("Error: {:?}", e),
                },
                None => shell_println!("Usage: dynlock grace <seconds>"),
            }
        }
        "autounlock" => {
            let val = parts.get(1).copied().unwrap_or("");
            match val {
                "on" | "true" => match dynlock::set_auto_unlock(true) {
                    Ok(()) => shell_println!("Auto-unlock enabled."),
                    Err(e) => shell_println!("Error: {:?}", e),
                },
                "off" | "false" => match dynlock::set_auto_unlock(false) {
                    Ok(()) => shell_println!("Auto-unlock disabled."),
                    Err(e) => shell_println!("Error: {:?}", e),
                },
                _ => shell_println!("Usage: dynlock autounlock <on|off>"),
            }
        }
        "check" => {
            match dynlock::check_proximity() {
                Ok(true) => shell_println!("Lock triggered: no device in range."),
                Ok(false) => shell_println!("No lock needed."),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "unlock" => match dynlock::manual_unlock() {
            Ok(()) => shell_println!("Manually unlocked."),
            Err(e) => shell_println!("Error: {:?}", e),
        },
        "stats" => {
            let (devs, locks, unlocks, ops) = dynlock::stats();
            shell_println!("Dynamic lock stats:");
            shell_println!("  Devices:       {}", devs);
            shell_println!("  Total locks:   {}", locks);
            shell_println!("  Total unlocks: {}", unlocks);
            shell_println!("  Operations:    {}", ops);
        }
        "test" => dynlock::self_test(),
        _ => {
            shell_println!("Usage: dynlock <subcommand>");
            shell_println!("  show                  Current status");
            shell_println!("  add <name> <addr>     Add paired device");
            shell_println!("  remove <addr>         Remove device");
            shell_println!("  enable / disable      Toggle dynamic lock");
            shell_println!("  grace <seconds>       Set grace period");
            shell_println!("  autounlock <on|off>   Auto-unlock on return");
            shell_println!("  check                 Check proximity now");
            shell_println!("  unlock                Manual unlock");
            shell_println!("  stats / test / init");
        }
    }
}

/// `snaplayout` / `snlayout` — snap layout zones and templates.
fn cmd_snaplayout(args: &str) {
    use crate::fs::snaplayout;
    let parts: Vec<&str> = args.split_whitespace().collect();
    let sub = parts.first().copied().unwrap_or("");
    match sub {
        "init" => { snaplayout::init_defaults(); shell_println!("Snap layouts initialised."); }
        "show" | "" | "list" => {
            snaplayout::init_defaults();
            let layouts = snaplayout::list_layouts();
            let active = snaplayout::get_active();
            shell_println!("Snap Layouts ({}):", layouts.len());
            for l in &layouts {
                let marker = if active.as_ref().is_some_and(|a| a.id == l.id) { " *" } else { "" };
                shell_println!("  [{}] {} ({} zones, used {} times){}",
                    l.id, l.name, l.zones.len(), l.use_count, marker);
            }
        }
        "active" => {
            match snaplayout::get_active() {
                Some(layout) => {
                    shell_println!("Active: {} (id={})", layout.name, layout.id);
                    for z in &layout.zones {
                        shell_println!("  Zone {}: x={}% y={}% w={}% h={}%", z.id, z.x_pct, z.y_pct, z.w_pct, z.h_pct);
                    }
                }
                None => shell_println!("No active layout."),
            }
        }
        "use" | "switch" => {
            let id = parts.get(1).and_then(|s| s.parse::<u32>().ok());
            match id {
                Some(i) => match snaplayout::set_active(i) {
                    Ok(()) => shell_println!("Active layout set to id {}.", i),
                    Err(e) => shell_println!("Error: {:?}", e),
                },
                None => shell_println!("Usage: snaplayout use <id>"),
            }
        }
        "snap" => {
            let win_id = parts.get(1).and_then(|s| s.parse::<u32>().ok());
            let zone_id = parts.get(2).and_then(|s| s.parse::<u32>().ok());
            match (win_id, zone_id) {
                (Some(w), Some(z)) => match snaplayout::snap_to_zone(w, z) {
                    Ok(zone) => shell_println!("Window {} snapped to zone {} (x={}% y={}% w={}% h={}%).",
                        w, z, zone.x_pct, zone.y_pct, zone.w_pct, zone.h_pct),
                    Err(e) => shell_println!("Error: {:?}", e),
                },
                _ => shell_println!("Usage: snaplayout snap <window_id> <zone_id>"),
            }
        }
        "suggest" => {
            let count = parts.get(1).and_then(|s| s.parse::<usize>().ok()).unwrap_or(2);
            match snaplayout::suggest_layout(count) {
                Some(l) => shell_println!("Suggested: {} ({} zones) for {} windows.", l.name, l.zones.len(), count),
                None => shell_println!("No layouts available."),
            }
        }
        "remove" | "rm" => {
            let id = parts.get(1).and_then(|s| s.parse::<u32>().ok());
            match id {
                Some(i) => match snaplayout::remove_layout(i) {
                    Ok(()) => shell_println!("Layout {} removed.", i),
                    Err(e) => shell_println!("Error: {:?}", e),
                },
                None => shell_println!("Usage: snaplayout remove <id>"),
            }
        }
        "groups" => {
            let groups = snaplayout::list_groups();
            if groups.is_empty() {
                shell_println!("No snap groups.");
            } else {
                shell_println!("Snap groups ({}):", groups.len());
                for g in &groups {
                    shell_println!("  Group {} (layout {}): {} windows", g.group_id, g.layout_id, g.assignments.len());
                }
            }
        }
        "stats" => {
            let (layouts, groups, snaps, ops) = snaplayout::stats();
            shell_println!("Snap layout stats:");
            shell_println!("  Layouts:     {}", layouts);
            shell_println!("  Groups:      {}", groups);
            shell_println!("  Total snaps: {}", snaps);
            shell_println!("  Operations:  {}", ops);
        }
        "test" => snaplayout::self_test(),
        _ => {
            shell_println!("Usage: snaplayout <subcommand>");
            shell_println!("  show / list           List layouts");
            shell_println!("  active                Show active layout zones");
            shell_println!("  use <id>              Switch active layout");
            shell_println!("  snap <win> <zone>     Snap window to zone");
            shell_println!("  suggest <count>       Suggest layout for N windows");
            shell_println!("  remove <id>           Remove custom layout");
            shell_println!("  groups                List snap groups");
            shell_println!("  stats / test / init");
        }
    }
}

/// `haptfeedback` / `haptic` — haptic feedback settings.
fn cmd_haptfeedback(args: &str) {
    use crate::fs::haptfeedback;
    let parts: Vec<&str> = args.split_whitespace().collect();
    let sub = parts.first().copied().unwrap_or("");
    match sub {
        "init" => { haptfeedback::init_defaults(); shell_println!("Haptic feedback initialised."); }
        "show" | "" => {
            haptfeedback::init_defaults();
            let devs = haptfeedback::list_devices();
            let mappings = haptfeedback::list_mappings();
            if devs.is_empty() {
                shell_println!("No haptic devices.");
            } else {
                shell_println!("Haptic Devices ({}):", devs.len());
                for d in &devs {
                    let status = if d.enabled { "on" } else { "off" };
                    shell_println!("  [{}] {} ({}) intensity={} [{}] fires={}",
                        d.id, d.name, d.device_type.label(), d.intensity, status, d.fire_count);
                }
            }
            shell_println!("Event Mappings ({}):", mappings.len());
            for m in &mappings {
                let status = if m.enabled { "on" } else { "off" };
                shell_println!("  {:20} → {:12} [{}]", m.event.label(), m.pattern.label(), status);
            }
        }
        "add" => {
            let name = parts.get(1).copied().unwrap_or("");
            let dtype_str = parts.get(2).copied().unwrap_or("trackpad");
            if name.is_empty() { shell_println!("Usage: haptfeedback add <name> [trackpad|controller|touchscreen|stylus]"); return; }
            let dtype = match dtype_str {
                "trackpad" | "tp" => haptfeedback::DeviceType::Trackpad,
                "controller" | "gc" => haptfeedback::DeviceType::GameController,
                "touchscreen" | "ts" => haptfeedback::DeviceType::Touchscreen,
                "stylus" | "pen" => haptfeedback::DeviceType::Stylus,
                _ => { shell_println!("Types: trackpad, controller, touchscreen, stylus"); return; }
            };
            match haptfeedback::add_device(name, dtype) {
                Ok(id) => shell_println!("Device '{}' added with id {}.", name, id),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "remove" | "rm" => {
            let id = parts.get(1).and_then(|s| s.parse::<u32>().ok());
            match id {
                Some(i) => match haptfeedback::remove_device(i) {
                    Ok(()) => shell_println!("Device {} removed.", i),
                    Err(e) => shell_println!("Error: {:?}", e),
                },
                None => shell_println!("Usage: haptfeedback remove <id>"),
            }
        }
        "intensity" | "int" => {
            let id = parts.get(1).and_then(|s| s.parse::<u32>().ok());
            let val = parts.get(2).and_then(|s| s.parse::<u32>().ok());
            match (id, val) {
                (Some(i), Some(v)) => match haptfeedback::set_intensity(i, v) {
                    Ok(()) => shell_println!("Intensity for device {} set to {}.", i, v),
                    Err(e) => shell_println!("Error: {:?}", e),
                },
                _ => shell_println!("Usage: haptfeedback intensity <device_id> <0-100>"),
            }
        }
        "pattern" => {
            let event_name = parts.get(1).copied().unwrap_or("");
            let pattern_name = parts.get(2).copied().unwrap_or("");
            let event = match parse_haptic_event(event_name) {
                Some(e) => e,
                None => { shell_println!("Events: click, doubleclick, longpress, swipe, scroll, selection, dragstart, dragend, error, success, warning, keypress"); return; }
            };
            let pattern = match parse_haptic_pattern(pattern_name) {
                Some(p) => p,
                None => { shell_println!("Patterns: none, tap, doubletap, buzz, impact, rumble, rising, falling, heartbeat"); return; }
            };
            match haptfeedback::set_event_pattern(event, pattern) {
                Ok(()) => shell_println!("{} pattern set to {}.", event.label(), pattern.label()),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "fire" => {
            let event_name = parts.get(1).copied().unwrap_or("");
            let event = match parse_haptic_event(event_name) {
                Some(e) => e,
                None => { shell_println!("Usage: haptfeedback fire <event>"); return; }
            };
            match haptfeedback::fire(event) {
                Ok(p) => shell_println!("Fired: {}", p.label()),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "enable" => match haptfeedback::set_global_enabled(true) {
            Ok(()) => shell_println!("Haptic feedback enabled."),
            Err(e) => shell_println!("Error: {:?}", e),
        },
        "disable" => match haptfeedback::set_global_enabled(false) {
            Ok(()) => shell_println!("Haptic feedback disabled."),
            Err(e) => shell_println!("Error: {:?}", e),
        },
        "stats" => {
            let (devs, maps, fires, ops) = haptfeedback::stats();
            shell_println!("Haptic feedback stats:");
            shell_println!("  Devices:       {}", devs);
            shell_println!("  Mappings:      {}", maps);
            shell_println!("  Total fires:   {}", fires);
            shell_println!("  Operations:    {}", ops);
        }
        "test" => haptfeedback::self_test(),
        _ => {
            shell_println!("Usage: haptfeedback <subcommand>");
            shell_println!("  show                  Devices & mappings");
            shell_println!("  add <name> [type]     Add device");
            shell_println!("  remove <id>           Remove device");
            shell_println!("  intensity <id> <0-100> Set intensity");
            shell_println!("  pattern <event> <pat> Set event pattern");
            shell_println!("  fire <event>          Test fire event");
            shell_println!("  enable / disable      Toggle globally");
            shell_println!("  stats / test / init");
        }
    }
}

fn parse_haptic_event(s: &str) -> Option<crate::fs::haptfeedback::HapticEvent> {
    use crate::fs::haptfeedback::HapticEvent;
    match s {
        "click" => Some(HapticEvent::Click),
        "doubleclick" | "dblclick" => Some(HapticEvent::DoubleClick),
        "longpress" | "long" => Some(HapticEvent::LongPress),
        "swipe" => Some(HapticEvent::Swipe),
        "scroll" | "scrolltick" => Some(HapticEvent::ScrollTick),
        "selection" | "select" => Some(HapticEvent::SelectionChange),
        "dragstart" | "drag" => Some(HapticEvent::DragStart),
        "dragend" | "drop" => Some(HapticEvent::DragEnd),
        "error" => Some(HapticEvent::Error),
        "success" => Some(HapticEvent::Success),
        "warning" | "warn" => Some(HapticEvent::Warning),
        "keypress" | "key" => Some(HapticEvent::KeyPress),
        _ => None,
    }
}

fn parse_haptic_pattern(s: &str) -> Option<crate::fs::haptfeedback::HapticPattern> {
    use crate::fs::haptfeedback::HapticPattern;
    match s {
        "none" => Some(HapticPattern::None),
        "tap" => Some(HapticPattern::Tap),
        "doubletap" | "dtap" => Some(HapticPattern::DoubleTap),
        "buzz" => Some(HapticPattern::Buzz),
        "impact" => Some(HapticPattern::Impact),
        "rumble" => Some(HapticPattern::Rumble),
        "rising" => Some(HapticPattern::Rising),
        "falling" => Some(HapticPattern::Falling),
        "heartbeat" | "hb" => Some(HapticPattern::Heartbeat),
        _ => None,
    }
}

/// `eyeprotect` / `eye` — eye strain protection with break reminders.
fn cmd_eyeprotect(args: &str) {
    use crate::fs::eyeprotect;
    let parts: Vec<&str> = args.split_whitespace().collect();
    let sub = parts.first().copied().unwrap_or("");
    match sub {
        "init" => { eyeprotect::init_defaults(); shell_println!("Eye protection initialised."); }
        "show" | "" => {
            eyeprotect::init_defaults();
            shell_println!("Eye Protection: {}", eyeprotect::break_state().label());
            let profiles = eyeprotect::list_profiles();
            let active = eyeprotect::get_active();
            for p in &profiles {
                let marker = if active.as_ref().is_some_and(|a| a.id == p.id) { " *" } else { "" };
                let status = if p.enabled { "on" } else { "off" };
                shell_println!("  [{}] {} — every {}min, {}s break, {} [{}]{}",
                    p.id, p.name, p.interval_mins, p.break_duration_secs, p.reminder_mode.label(), status, marker);
            }
        }
        "start" => match eyeprotect::start_break() {
            Ok(()) => shell_println!("Break started."),
            Err(e) => shell_println!("Error: {:?}", e),
        },
        "end" => match eyeprotect::end_break() {
            Ok(()) => shell_println!("Break ended."),
            Err(e) => shell_println!("Error: {:?}", e),
        },
        "snooze" => match eyeprotect::snooze() {
            Ok(()) => shell_println!("Break snoozed."),
            Err(e) => shell_println!("Error: {:?}", e),
        },
        "skip" => match eyeprotect::skip() {
            Ok(()) => shell_println!("Break skipped."),
            Err(e) => shell_println!("Error: {:?}", e),
        },
        "check" => match eyeprotect::check_break() {
            Ok(state) => shell_println!("State: {}", state.label()),
            Err(e) => shell_println!("Error: {:?}", e),
        },
        "interval" => {
            let id = parts.get(1).and_then(|s| s.parse::<u32>().ok());
            let mins = parts.get(2).and_then(|s| s.parse::<u32>().ok());
            match (id, mins) {
                (Some(i), Some(m)) => match eyeprotect::set_interval(i, m) {
                    Ok(()) => shell_println!("Interval set to {} minutes.", m),
                    Err(e) => shell_println!("Error: {:?}", e),
                },
                _ => shell_println!("Usage: eyeprotect interval <profile_id> <minutes>"),
            }
        }
        "duration" => {
            let id = parts.get(1).and_then(|s| s.parse::<u32>().ok());
            let secs = parts.get(2).and_then(|s| s.parse::<u32>().ok());
            match (id, secs) {
                (Some(i), Some(s)) => match eyeprotect::set_break_duration(i, s) {
                    Ok(()) => shell_println!("Break duration set to {} seconds.", s),
                    Err(e) => shell_println!("Error: {:?}", e),
                },
                _ => shell_println!("Usage: eyeprotect duration <profile_id> <seconds>"),
            }
        }
        "profile" => {
            let id = parts.get(1).and_then(|s| s.parse::<u32>().ok());
            match id {
                Some(i) => match eyeprotect::set_active(i) {
                    Ok(()) => shell_println!("Active profile set to {}.", i),
                    Err(e) => shell_println!("Error: {:?}", e),
                },
                None => shell_println!("Usage: eyeprotect profile <id>"),
            }
        }
        "enable" => {
            let id = parts.get(1).and_then(|s| s.parse::<u32>().ok()).unwrap_or(0);
            if id > 0 {
                match eyeprotect::set_profile_enabled(id, true) {
                    Ok(()) => shell_println!("Profile {} enabled.", id),
                    Err(e) => shell_println!("Error: {:?}", e),
                }
            } else {
                shell_println!("Usage: eyeprotect enable <profile_id>");
            }
        }
        "disable" => {
            let id = parts.get(1).and_then(|s| s.parse::<u32>().ok()).unwrap_or(0);
            if id > 0 {
                match eyeprotect::set_profile_enabled(id, false) {
                    Ok(()) => shell_println!("Profile {} disabled.", id),
                    Err(e) => shell_println!("Error: {:?}", e),
                }
            } else {
                shell_println!("Usage: eyeprotect disable <profile_id>");
            }
        }
        "stats" => {
            let (profiles, breaks, snoozes, skips, ops) = eyeprotect::stats();
            shell_println!("Eye protection stats:");
            shell_println!("  Profiles:  {}", profiles);
            shell_println!("  Breaks:    {}", breaks);
            shell_println!("  Snoozes:   {}", snoozes);
            shell_println!("  Skips:     {}", skips);
            shell_println!("  Operations: {}", ops);
        }
        "test" => eyeprotect::self_test(),
        _ => {
            shell_println!("Usage: eyeprotect <subcommand>");
            shell_println!("  show                  Current status");
            shell_println!("  start / end           Manual break");
            shell_println!("  snooze / skip         Defer/skip break");
            shell_println!("  check                 Check if break due");
            shell_println!("  interval <id> <min>   Set break interval");
            shell_println!("  duration <id> <sec>   Set break duration");
            shell_println!("  profile <id>          Switch active profile");
            shell_println!("  enable/disable <id>   Toggle profile");
            shell_println!("  stats / test / init");
        }
    }
}

/// `pinnedapps` / `pinned` — taskbar/start menu pinned app management.
fn cmd_pinnedapps(args: &str) {
    use crate::fs::pinnedapps;
    use alloc::format;
    let parts: Vec<&str> = args.split_whitespace().collect();
    let sub = parts.first().copied().unwrap_or("");
    match sub {
        "init" => { pinnedapps::init_defaults(); shell_println!("Pinned apps initialised."); }
        "show" | "" => {
            pinnedapps::init_defaults();
            for loc in &[pinnedapps::PinLocation::Taskbar, pinnedapps::PinLocation::StartMenu, pinnedapps::PinLocation::Desktop] {
                let pins = pinnedapps::list_pins(*loc);
                if !pins.is_empty() {
                    shell_println!("{} ({}):", loc.label(), pins.len());
                    for p in &pins {
                        let group = if p.group.is_empty() { String::new() } else { format!(" [{}]", p.group) };
                        shell_println!("  #{} {} ({}){} launches={}", p.position, p.display_name, p.app_name, group, p.launch_count);
                    }
                }
            }
        }
        "pin" => {
            let loc_str = parts.get(1).copied().unwrap_or("");
            let app = parts.get(2).copied().unwrap_or("");
            let display = parts.get(3..).map(|s| s.join(" ")).unwrap_or_default();
            let loc = match loc_str {
                "taskbar" | "tb" => pinnedapps::PinLocation::Taskbar,
                "start" | "sm" => pinnedapps::PinLocation::StartMenu,
                "desktop" | "dt" => pinnedapps::PinLocation::Desktop,
                _ => { shell_println!("Usage: pinnedapps pin <taskbar|start|desktop> <app> [display_name]"); return; }
            };
            if app.is_empty() { shell_println!("Usage: pinnedapps pin <location> <app> [display_name]"); return; }
            let dname = if display.is_empty() { app } else { &display };
            match pinnedapps::pin(loc, app, dname, &format!("/usr/bin/{}", app)) {
                Ok(()) => shell_println!("'{}' pinned to {}.", app, loc.label()),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "unpin" => {
            let loc_str = parts.get(1).copied().unwrap_or("");
            let app = parts.get(2).copied().unwrap_or("");
            let loc = match loc_str {
                "taskbar" | "tb" => pinnedapps::PinLocation::Taskbar,
                "start" | "sm" => pinnedapps::PinLocation::StartMenu,
                "desktop" | "dt" => pinnedapps::PinLocation::Desktop,
                _ => { shell_println!("Usage: pinnedapps unpin <location> <app>"); return; }
            };
            if app.is_empty() { shell_println!("Usage: pinnedapps unpin <location> <app>"); return; }
            match pinnedapps::unpin(loc, app) {
                Ok(()) => shell_println!("'{}' unpinned from {}.", app, loc.label()),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "move" | "reorder" => {
            let loc_str = parts.get(1).copied().unwrap_or("");
            let app = parts.get(2).copied().unwrap_or("");
            let pos = parts.get(3).and_then(|s| s.parse::<u32>().ok());
            let loc = match loc_str {
                "taskbar" | "tb" => pinnedapps::PinLocation::Taskbar,
                "start" | "sm" => pinnedapps::PinLocation::StartMenu,
                "desktop" | "dt" => pinnedapps::PinLocation::Desktop,
                _ => { shell_println!("Usage: pinnedapps move <location> <app> <position>"); return; }
            };
            match pos {
                Some(p) => match pinnedapps::reorder(loc, app, p) {
                    Ok(()) => shell_println!("'{}' moved to position {}.", app, p),
                    Err(e) => shell_println!("Error: {:?}", e),
                },
                None => shell_println!("Usage: pinnedapps move <location> <app> <position>"),
            }
        }
        "launch" => {
            let app = parts.get(1).copied().unwrap_or("");
            if app.is_empty() { shell_println!("Usage: pinnedapps launch <app>"); return; }
            match pinnedapps::record_launch(app) {
                Ok(c) => shell_println!("Launch recorded for '{}' (count: {}).", app, c),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "stats" => {
            let (total, tb, sm, launches, ops) = pinnedapps::stats();
            shell_println!("Pinned apps stats:");
            shell_println!("  Total pinned:    {}", total);
            shell_println!("  Taskbar pins:    {}", tb);
            shell_println!("  Start menu pins: {}", sm);
            shell_println!("  Total launches:  {}", launches);
            shell_println!("  Operations:      {}", ops);
        }
        "test" => pinnedapps::self_test(),
        _ => {
            shell_println!("Usage: pinnedapps <subcommand>");
            shell_println!("  show                  List all pinned apps");
            shell_println!("  pin <loc> <app> [name] Pin app");
            shell_println!("  unpin <loc> <app>      Unpin app");
            shell_println!("  move <loc> <app> <pos>  Reorder");
            shell_println!("  launch <app>           Record launch");
            shell_println!("  Locations: taskbar(tb), start(sm), desktop(dt)");
            shell_println!("  stats / test / init");
        }
    }
}

/// `inputmethod` / `imf` — input method framework.
fn cmd_inputmethod(args: &str) {
    use crate::fs::inputmethod;
    let parts: Vec<&str> = args.split_whitespace().collect();
    let sub = parts.first().copied().unwrap_or("");
    match sub {
        "init" => { inputmethod::init_defaults(); shell_println!("Input method framework initialised."); }
        "show" | "" => {
            inputmethod::init_defaults();
            shell_println!("Active: {}", inputmethod::active_engine_name());
            let engines = inputmethod::list_engines();
            shell_println!("Engines ({}):", engines.len());
            for e in &engines {
                let status = if e.enabled { "on" } else { "off" };
                shell_println!("  [{}] {} ({}, {}) [{}] commits={}", e.id, e.name, e.engine_type.label(), e.language, status, e.commit_count);
            }
            if let Some(comp) = inputmethod::get_composition() {
                if comp.composing {
                    shell_println!("Composing: '{}' ({} candidates)", comp.preedit, comp.candidates.len());
                }
            }
        }
        "add" => {
            let name = parts.get(1).copied().unwrap_or("");
            let type_str = parts.get(2).copied().unwrap_or("direct");
            let lang = parts.get(3).copied().unwrap_or("en");
            if name.is_empty() { shell_println!("Usage: inputmethod add <name> [type] [lang]"); return; }
            let etype = match type_str {
                "direct" => inputmethod::EngineType::Direct,
                "pinyin" => inputmethod::EngineType::Pinyin,
                "wubi" => inputmethod::EngineType::Wubi,
                "japanese" | "jp" => inputmethod::EngineType::Japanese,
                "hangul" | "kr" => inputmethod::EngineType::Hangul,
                "translit" => inputmethod::EngineType::Transliteration,
                "handwriting" | "hw" => inputmethod::EngineType::Handwriting,
                _ => { shell_println!("Types: direct, pinyin, wubi, japanese, hangul, translit, handwriting"); return; }
            };
            match inputmethod::add_engine(name, etype, lang) {
                Ok(id) => shell_println!("Engine '{}' added (id={}).", name, id),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "remove" | "rm" => {
            let id = parts.get(1).and_then(|s| s.parse::<u32>().ok());
            match id {
                Some(i) => match inputmethod::remove_engine(i) {
                    Ok(()) => shell_println!("Engine {} removed.", i),
                    Err(e) => shell_println!("Error: {:?}", e),
                },
                None => shell_println!("Usage: inputmethod remove <id>"),
            }
        }
        "switch" => {
            let id = parts.get(1).and_then(|s| s.parse::<u32>().ok());
            match id {
                Some(i) => match inputmethod::switch_engine(i) {
                    Ok(()) => shell_println!("Switched to engine {}.", i),
                    Err(e) => shell_println!("Error: {:?}", e),
                },
                None => shell_println!("Usage: inputmethod switch <id>"),
            }
        }
        "cycle" => match inputmethod::cycle_engine() {
            Ok(name) => shell_println!("Cycled to: {}", name),
            Err(e) => shell_println!("Error: {:?}", e),
        },
        "compose" => {
            let text = parts.get(1..).map(|s| s.join(" ")).unwrap_or_default();
            if text.is_empty() { shell_println!("Usage: inputmethod compose <text>"); return; }
            match inputmethod::start_composition(&text) {
                Ok(()) => {
                    if let Some(comp) = inputmethod::get_composition() {
                        shell_println!("Composing: '{}'", comp.preedit);
                        for (i, c) in comp.candidates.iter().enumerate() {
                            let marker = if i == comp.selected { " ←" } else { "" };
                            shell_println!("  [{}] {}{}", i, c, marker);
                        }
                    }
                }
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "select" => {
            let idx = parts.get(1).and_then(|s| s.parse::<usize>().ok());
            match idx {
                Some(i) => match inputmethod::select_candidate(i) {
                    Ok(()) => shell_println!("Selected candidate {}.", i),
                    Err(e) => shell_println!("Error: {:?}", e),
                },
                None => shell_println!("Usage: inputmethod select <index>"),
            }
        }
        "commit" => match inputmethod::commit() {
            Ok(text) => shell_println!("Committed: '{}'", text),
            Err(e) => shell_println!("Error: {:?}", e),
        },
        "cancel" => match inputmethod::cancel_composition() {
            Ok(()) => shell_println!("Composition cancelled."),
            Err(e) => shell_println!("Error: {:?}", e),
        },
        "stats" => {
            let (engines, commits, switches, ops) = inputmethod::stats();
            shell_println!("Input method stats:");
            shell_println!("  Engines:    {}", engines);
            shell_println!("  Commits:    {}", commits);
            shell_println!("  Switches:   {}", switches);
            shell_println!("  Operations: {}", ops);
        }
        "test" => inputmethod::self_test(),
        _ => {
            shell_println!("Usage: inputmethod <subcommand>");
            shell_println!("  show                  Engines & composition");
            shell_println!("  add <name> [type] [lang]  Add engine");
            shell_println!("  remove <id>           Remove engine");
            shell_println!("  switch <id>           Switch engine");
            shell_println!("  cycle                 Cycle to next");
            shell_println!("  compose <text>        Start composition");
            shell_println!("  select <idx>          Select candidate");
            shell_println!("  commit / cancel       Finish composition");
            shell_println!("  stats / test / init");
        }
    }
}

/// `storagesense` / `ssense` — smart automated storage cleanup.
fn cmd_storagesense(args: &str) {
    use crate::fs::storagesense;
    let parts: Vec<&str> = args.split_whitespace().collect();
    let sub = parts.first().copied().unwrap_or("");
    match sub {
        "init" => { storagesense::init_defaults(); shell_println!("Storage Sense initialised."); }
        "show" | "" => {
            storagesense::init_defaults();
            shell_println!("Storage Sense — Schedule: {}", storagesense::get_schedule().label());
            let policies = storagesense::list_policies();
            for p in &policies {
                let status = if p.enabled { "on" } else { "off" };
                shell_println!("  {:20} [{}] max_age={}d est={} last={}",
                    p.category.label(), status, p.max_age_days,
                    storagesense::format_bytes(p.estimated_bytes),
                    storagesense::format_bytes(p.last_freed_bytes));
            }
            if let Ok(est) = storagesense::estimate_savings() { shell_println!("Estimated savings: {}", storagesense::format_bytes(est)) }
        }
        "run" => {
            let cat_name = parts.get(1).copied().unwrap_or("");
            if cat_name.is_empty() {
                match storagesense::run_cleanup() {
                    Ok(freed) => shell_println!("Cleanup complete: {} freed.", storagesense::format_bytes(freed)),
                    Err(e) => shell_println!("Error: {:?}", e),
                }
            } else {
                let cat = match parse_cleanup_category(cat_name) {
                    Some(c) => c,
                    None => { shell_println!("Categories: temp, recycle, downloads, thumbs, syscache, logs, browser, packages, updates"); return; }
                };
                match storagesense::run_category(cat) {
                    Ok(freed) => shell_println!("{} cleanup: {} freed.", cat.label(), storagesense::format_bytes(freed)),
                    Err(e) => shell_println!("Error: {:?}", e),
                }
            }
        }
        "schedule" | "sched" => {
            let s = parts.get(1).copied().unwrap_or("");
            let schedule = match s {
                "manual" => storagesense::Schedule::Manual,
                "daily" => storagesense::Schedule::Daily,
                "weekly" => storagesense::Schedule::Weekly,
                "monthly" => storagesense::Schedule::Monthly,
                "lowspace" | "auto" => storagesense::Schedule::OnLowSpace,
                _ => { shell_println!("Usage: storagesense schedule <manual|daily|weekly|monthly|lowspace>"); return; }
            };
            match storagesense::set_schedule(schedule) {
                Ok(()) => shell_println!("Schedule set to {}.", schedule.label()),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "enable" => {
            let cat_name = parts.get(1).copied().unwrap_or("");
            let cat = match parse_cleanup_category(cat_name) {
                Some(c) => c,
                None => { shell_println!("Usage: storagesense enable <category>"); return; }
            };
            match storagesense::set_category_enabled(cat, true) {
                Ok(()) => shell_println!("{} enabled.", cat.label()),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "disable" => {
            let cat_name = parts.get(1).copied().unwrap_or("");
            let cat = match parse_cleanup_category(cat_name) {
                Some(c) => c,
                None => { shell_println!("Usage: storagesense disable <category>"); return; }
            };
            match storagesense::set_category_enabled(cat, false) {
                Ok(()) => shell_println!("{} disabled.", cat.label()),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "age" => {
            let cat_name = parts.get(1).copied().unwrap_or("");
            let days = parts.get(2).and_then(|s| s.parse::<u32>().ok());
            let cat = match parse_cleanup_category(cat_name) {
                Some(c) => c,
                None => { shell_println!("Usage: storagesense age <category> <days>"); return; }
            };
            match days {
                Some(d) => match storagesense::set_max_age(cat, d) {
                    Ok(()) => shell_println!("{} max age set to {} days.", cat.label(), d),
                    Err(e) => shell_println!("Error: {:?}", e),
                },
                None => shell_println!("Usage: storagesense age <category> <days>"),
            }
        }
        "estimate" => match storagesense::estimate_savings() {
            Ok(est) => shell_println!("Estimated savings: {}", storagesense::format_bytes(est)),
            Err(e) => shell_println!("Error: {:?}", e),
        },
        "stats" => {
            let (policies, runs, freed, ops) = storagesense::stats();
            shell_println!("Storage Sense stats:");
            shell_println!("  Policies:     {}", policies);
            shell_println!("  Total runs:   {}", runs);
            shell_println!("  Total freed:  {}", storagesense::format_bytes(freed));
            shell_println!("  Operations:   {}", ops);
        }
        "test" => storagesense::self_test(),
        _ => {
            shell_println!("Usage: storagesense <subcommand>");
            shell_println!("  show                  Policies & estimates");
            shell_println!("  run [category]        Run cleanup");
            shell_println!("  schedule <type>       Set schedule");
            shell_println!("  enable/disable <cat>  Toggle category");
            shell_println!("  age <cat> <days>      Set max age");
            shell_println!("  estimate              Estimate savings");
            shell_println!("  stats / test / init");
        }
    }
}

fn parse_cleanup_category(s: &str) -> Option<crate::fs::storagesense::CleanupCategory> {
    use crate::fs::storagesense::CleanupCategory;
    match s {
        "temp" | "tmp" => Some(CleanupCategory::TempFiles),
        "recycle" | "trash" => Some(CleanupCategory::RecycleBin),
        "downloads" | "dl" => Some(CleanupCategory::Downloads),
        "thumbs" | "thumbnails" => Some(CleanupCategory::ThumbnailCache),
        "syscache" | "cache" => Some(CleanupCategory::SystemCache),
        "logs" | "log" => Some(CleanupCategory::LogFiles),
        "browser" => Some(CleanupCategory::BrowserCache),
        "packages" | "pkg" => Some(CleanupCategory::PackageCache),
        "updates" | "oldupd" => Some(CleanupCategory::OldUpdates),
        _ => None,
    }
}

/// `autofix` / `afix` — automated problem detection and repair.
fn cmd_autofix(args: &str) {
    use crate::fs::autofix;
    let parts: Vec<&str> = args.split_whitespace().collect();
    let sub = parts.first().copied().unwrap_or("");
    match sub {
        "init" => { autofix::init_defaults(); shell_println!("AutoFix initialised."); }
        "show" | "" | "list" => {
            autofix::init_defaults();
            let issues = autofix::list_issues(None);
            if issues.is_empty() {
                shell_println!("No issues detected. Run 'autofix scan' to check.");
            } else {
                shell_println!("Issues ({}):", issues.len());
                for i in &issues {
                    shell_println!("  [{}] [{}] {} — {} ({})", i.id, i.severity.label(), i.category.label(), i.description, i.status.label());
                }
            }
        }
        "scan" => match autofix::scan() {
            Ok(found) => shell_println!("Scan complete: {} issues found.", found),
            Err(e) => shell_println!("Error: {:?}", e),
        },
        "fix" => {
            let id = parts.get(1).and_then(|s| s.parse::<u32>().ok());
            match id {
                Some(i) => match autofix::fix(i) {
                    Ok(()) => shell_println!("Issue {} fixed.", i),
                    Err(e) => shell_println!("Error: {:?}", e),
                },
                None => shell_println!("Usage: autofix fix <issue_id>"),
            }
        }
        "fixall" => match autofix::fix_all() {
            Ok(count) => shell_println!("{} issues fixed.", count),
            Err(e) => shell_println!("Error: {:?}", e),
        },
        "ignore" => {
            let id = parts.get(1).and_then(|s| s.parse::<u32>().ok());
            match id {
                Some(i) => match autofix::ignore(i) {
                    Ok(()) => shell_println!("Issue {} ignored.", i),
                    Err(e) => shell_println!("Error: {:?}", e),
                },
                None => shell_println!("Usage: autofix ignore <issue_id>"),
            }
        }
        "clear" => match autofix::clear_resolved() {
            Ok(count) => shell_println!("{} resolved issues cleared.", count),
            Err(e) => shell_println!("Error: {:?}", e),
        },
        "stats" => {
            let (issues, scans, fixes, ignored, ops) = autofix::stats();
            shell_println!("AutoFix stats:");
            shell_println!("  Issues:   {}", issues);
            shell_println!("  Scans:    {}", scans);
            shell_println!("  Fixes:    {}", fixes);
            shell_println!("  Ignored:  {}", ignored);
            shell_println!("  Ops:      {}", ops);
        }
        "test" => autofix::self_test(),
        _ => {
            shell_println!("Usage: autofix <subcommand>");
            shell_println!("  show / list           List issues");
            shell_println!("  scan                  Run scan");
            shell_println!("  fix <id>              Fix issue");
            shell_println!("  fixall                Fix all issues");
            shell_println!("  ignore <id>           Ignore issue");
            shell_println!("  clear                 Clear resolved");
            shell_println!("  stats / test / init");
        }
    }
}

/// `recentsearch` / `rsearch` — search query history and suggestions.
fn cmd_recentsearch(args: &str) {
    use crate::fs::recentsearch;
    let parts: Vec<&str> = args.split_whitespace().collect();
    let sub = parts.first().copied().unwrap_or("");
    match sub {
        "init" => { recentsearch::init_defaults(); shell_println!("Recent search initialised."); }
        "show" | "" => {
            recentsearch::init_defaults();
            let recent = recentsearch::list_recent(20);
            if recent.is_empty() {
                shell_println!("No search history.");
            } else {
                shell_println!("Recent searches ({}):", recent.len());
                for e in &recent {
                    let pin_mark = if e.pinned { " [pinned]" } else { "" };
                    shell_println!("  '{}' ({}, {} results, used {}x){}",
                        e.query, e.source.label(), e.result_count, e.use_count, pin_mark);
                }
            }
        }
        "record" | "add" => {
            let source_str = parts.get(1).copied().unwrap_or("files");
            let query = parts.get(2..).map(|s| s.join(" ")).unwrap_or_default();
            if query.is_empty() { shell_println!("Usage: recentsearch record <source> <query>"); return; }
            let source = match source_str {
                "files" | "file" => recentsearch::SearchSource::FileSearch,
                "settings" | "set" => recentsearch::SearchSource::Settings,
                "apps" | "app" => recentsearch::SearchSource::AppLauncher,
                "run" => recentsearch::SearchSource::RunDialog,
                "web" => recentsearch::SearchSource::WebSearch,
                "help" => recentsearch::SearchSource::HelpSearch,
                _ => { shell_println!("Sources: files, settings, apps, run, web, help"); return; }
            };
            match recentsearch::record(&query, source, 0) {
                Ok(()) => shell_println!("Recorded: '{}'", query),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "suggest" => {
            let prefix = parts.get(1..).map(|s| s.join(" ")).unwrap_or_default();
            if prefix.is_empty() { shell_println!("Usage: recentsearch suggest <prefix>"); return; }
            let suggestions = recentsearch::suggest(&prefix, 10);
            if suggestions.is_empty() {
                shell_println!("No suggestions for '{}'.", prefix);
            } else {
                shell_println!("Suggestions for '{}':", prefix);
                for s in &suggestions {
                    shell_println!("  '{}' ({}, {}x)", s.query, s.source.label(), s.use_count);
                }
            }
        }
        "pin" => {
            let query = parts.get(1..).map(|s| s.join(" ")).unwrap_or_default();
            if query.is_empty() { shell_println!("Usage: recentsearch pin <query>"); return; }
            match recentsearch::pin(&query) {
                Ok(()) => shell_println!("Pinned: '{}'", query),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "unpin" => {
            let query = parts.get(1..).map(|s| s.join(" ")).unwrap_or_default();
            if query.is_empty() { shell_println!("Usage: recentsearch unpin <query>"); return; }
            match recentsearch::unpin(&query) {
                Ok(()) => shell_println!("Unpinned: '{}'", query),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "clear" => {
            let source = parts.get(1).copied().unwrap_or("");
            if source.is_empty() {
                match recentsearch::clear_history() {
                    Ok(c) => shell_println!("{} entries cleared.", c),
                    Err(e) => shell_println!("Error: {:?}", e),
                }
            } else {
                let src = match source {
                    "files" => recentsearch::SearchSource::FileSearch,
                    "settings" => recentsearch::SearchSource::Settings,
                    "apps" => recentsearch::SearchSource::AppLauncher,
                    "run" => recentsearch::SearchSource::RunDialog,
                    "web" => recentsearch::SearchSource::WebSearch,
                    "help" => recentsearch::SearchSource::HelpSearch,
                    _ => { shell_println!("Unknown source."); return; }
                };
                match recentsearch::clear_source(src) {
                    Ok(c) => shell_println!("{} {} entries cleared.", c, source),
                    Err(e) => shell_println!("Error: {:?}", e),
                }
            }
        }
        "enable" => match recentsearch::set_enabled(true) {
            Ok(()) => shell_println!("Search history enabled."),
            Err(e) => shell_println!("Error: {:?}", e),
        },
        "disable" => match recentsearch::set_enabled(false) {
            Ok(()) => shell_println!("Search history disabled."),
            Err(e) => shell_println!("Error: {:?}", e),
        },
        "stats" => {
            let (entries, pinned, searches, suggestions, ops) = recentsearch::stats();
            shell_println!("Recent search stats:");
            shell_println!("  Entries:          {}", entries);
            shell_println!("  Pinned:           {}", pinned);
            shell_println!("  Total searches:   {}", searches);
            shell_println!("  Suggestions used: {}", suggestions);
            shell_println!("  Operations:       {}", ops);
        }
        "test" => recentsearch::self_test(),
        _ => {
            shell_println!("Usage: recentsearch <subcommand>");
            shell_println!("  show                  Recent history");
            shell_println!("  record <src> <query>  Record search");
            shell_println!("  suggest <prefix>      Get suggestions");
            shell_println!("  pin/unpin <query>     Pin/unpin entry");
            shell_println!("  clear [source]        Clear history");
            shell_println!("  enable / disable      Toggle history");
            shell_println!("  stats / test / init");
        }
    }
}

/// `sysmaint` / `maint` — system maintenance scheduling.
fn cmd_sysmaint(args: &str) {
    use crate::fs::sysmaint;
    let parts: Vec<&str> = args.split_whitespace().collect();
    let sub = parts.first().copied().unwrap_or("");
    match sub {
        "init" => { sysmaint::init_defaults(); shell_println!("System maintenance initialised."); }
        "show" | "" | "list" => {
            sysmaint::init_defaults();
            let tasks = sysmaint::list_tasks();
            shell_println!("Maintenance Tasks ({}):", tasks.len());
            for t in &tasks {
                let status = if t.enabled { t.status.label() } else { "Disabled" };
                let idle = if t.idle_only { " (idle only)" } else { "" };
                shell_println!("  [{}] {:20} every {}h [{}] runs={}{}", t.id, t.task_type.label(), t.interval_hours, status, t.run_count, idle);
            }
        }
        "run" => {
            let id = parts.get(1).and_then(|s| s.parse::<u32>().ok());
            match id {
                Some(i) => match sysmaint::run_task(i) {
                    Ok(()) => shell_println!("Task {} completed.", i),
                    Err(e) => shell_println!("Error: {:?}", e),
                },
                None => match sysmaint::run_pending() {
                    Ok(count) => shell_println!("{} maintenance tasks completed.", count),
                    Err(e) => shell_println!("Error: {:?}", e),
                },
            }
        }
        "due" => match sysmaint::check_schedule() {
            Ok(due) => {
                if due.is_empty() {
                    shell_println!("No tasks due.");
                } else {
                    shell_println!("{} tasks due: {:?}", due.len(), due);
                }
            }
            Err(e) => shell_println!("Error: {:?}", e),
        },
        "enable" => {
            let id = parts.get(1).and_then(|s| s.parse::<u32>().ok());
            match id {
                Some(i) => match sysmaint::set_enabled(i, true) {
                    Ok(()) => shell_println!("Task {} enabled.", i),
                    Err(e) => shell_println!("Error: {:?}", e),
                },
                None => shell_println!("Usage: sysmaint enable <task_id>"),
            }
        }
        "disable" => {
            let id = parts.get(1).and_then(|s| s.parse::<u32>().ok());
            match id {
                Some(i) => match sysmaint::set_enabled(i, false) {
                    Ok(()) => shell_println!("Task {} disabled.", i),
                    Err(e) => shell_println!("Error: {:?}", e),
                },
                None => shell_println!("Usage: sysmaint disable <task_id>"),
            }
        }
        "interval" => {
            let id = parts.get(1).and_then(|s| s.parse::<u32>().ok());
            let hours = parts.get(2).and_then(|s| s.parse::<u32>().ok());
            match (id, hours) {
                (Some(i), Some(h)) => match sysmaint::set_interval(i, h) {
                    Ok(()) => shell_println!("Task {} interval set to {}h.", i, h),
                    Err(e) => shell_println!("Error: {:?}", e),
                },
                _ => shell_println!("Usage: sysmaint interval <task_id> <hours>"),
            }
        }
        "stats" => {
            let (tasks, runs, failures, ops) = sysmaint::stats();
            shell_println!("Maintenance stats:");
            shell_println!("  Tasks:     {}", tasks);
            shell_println!("  Runs:      {}", runs);
            shell_println!("  Failures:  {}", failures);
            shell_println!("  Ops:       {}", ops);
        }
        "test" => sysmaint::self_test(),
        _ => {
            shell_println!("Usage: sysmaint <subcommand>");
            shell_println!("  show / list           All tasks");
            shell_println!("  run [id]              Run task or all due");
            shell_println!("  due                   Check due tasks");
            shell_println!("  enable/disable <id>   Toggle task");
            shell_println!("  interval <id> <hours> Set interval");
            shell_println!("  stats / test / init");
        }
    }
}

/// `multiclip` / `mclip` — multi-clipboard with history and slots.
fn cmd_multiclip(args: &str) {
    use crate::fs::multiclip;
    use alloc::format;
    let parts: Vec<&str> = args.split_whitespace().collect();
    let sub = parts.first().copied().unwrap_or("");
    match sub {
        "init" => { multiclip::init_defaults(); shell_println!("Multi-clipboard initialised."); }
        "show" | "" | "list" => {
            multiclip::init_defaults();
            let history = multiclip::list_history(15);
            if history.is_empty() {
                shell_println!("Clipboard history empty.");
            } else {
                shell_println!("Clipboard History ({} entries):", history.len());
                for (i, e) in history.iter().enumerate() {
                    let pin = if e.pinned { " [pinned]" } else { "" };
                    let slot = if e.slot_name.is_empty() { String::new() } else { format!(" <{}>", e.slot_name) };
                    let preview = if e.content.len() > 40 {
                        format!("{}...", &e.content[..40])
                    } else {
                        e.content.clone()
                    };
                    shell_println!("  [{}] ({}) '{}'{}{} pastes={}", i, e.content_type.label(), preview, pin, slot, e.paste_count);
                }
            }
        }
        "copy" | "push" => {
            let text = parts.get(1..).map(|s| s.join(" ")).unwrap_or_default();
            if text.is_empty() { shell_println!("Usage: multiclip copy <text>"); return; }
            match multiclip::push(&text, multiclip::ContentType::PlainText) {
                Ok(id) => shell_println!("Copied (id={}): '{}'", id, text),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "paste" => {
            let idx = parts.get(1).and_then(|s| s.parse::<usize>().ok()).unwrap_or(0);
            match multiclip::paste(idx) {
                Ok(entry) => shell_println!("{}", entry.content),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "slot" => {
            let name = parts.get(1).copied().unwrap_or("");
            if name.is_empty() {
                let slots = multiclip::list_slots();
                if slots.is_empty() {
                    shell_println!("No named slots.");
                } else {
                    for s in &slots {
                        let preview = if s.content.len() > 40 { format!("{}...", &s.content[..40]) } else { s.content.clone() };
                        shell_println!("  <{}> '{}'", s.slot_name, preview);
                    }
                }
            } else {
                match multiclip::paste_slot(name) {
                    Ok(entry) => shell_println!("{}", entry.content),
                    Err(e) => shell_println!("Slot '{}': {:?}", name, e),
                }
            }
        }
        "setslot" => {
            let id = parts.get(1).and_then(|s| s.parse::<u32>().ok());
            let name = parts.get(2).copied().unwrap_or("");
            match id {
                Some(i) if !name.is_empty() => match multiclip::set_slot(i, name) {
                    Ok(()) => shell_println!("Slot '{}' assigned to entry {}.", name, i),
                    Err(e) => shell_println!("Error: {:?}", e),
                },
                _ => shell_println!("Usage: multiclip setslot <id> <name>"),
            }
        }
        "pin" => {
            let id = parts.get(1).and_then(|s| s.parse::<u32>().ok());
            match id {
                Some(i) => match multiclip::pin(i) {
                    Ok(()) => shell_println!("Entry {} pinned.", i),
                    Err(e) => shell_println!("Error: {:?}", e),
                },
                None => shell_println!("Usage: multiclip pin <id>"),
            }
        }
        "unpin" => {
            let id = parts.get(1).and_then(|s| s.parse::<u32>().ok());
            match id {
                Some(i) => match multiclip::unpin(i) {
                    Ok(()) => shell_println!("Entry {} unpinned.", i),
                    Err(e) => shell_println!("Error: {:?}", e),
                },
                None => shell_println!("Usage: multiclip unpin <id>"),
            }
        }
        "remove" | "rm" => {
            let id = parts.get(1).and_then(|s| s.parse::<u32>().ok());
            match id {
                Some(i) => match multiclip::remove(i) {
                    Ok(()) => shell_println!("Entry {} removed.", i),
                    Err(e) => shell_println!("Error: {:?}", e),
                },
                None => shell_println!("Usage: multiclip remove <id>"),
            }
        }
        "clear" => match multiclip::clear_history() {
            Ok(c) => shell_println!("{} entries cleared.", c),
            Err(e) => shell_println!("Error: {:?}", e),
        },
        "enable" => match multiclip::set_enabled(true) {
            Ok(()) => shell_println!("Multi-clipboard enabled."),
            Err(e) => shell_println!("Error: {:?}", e),
        },
        "disable" => match multiclip::set_enabled(false) {
            Ok(()) => shell_println!("Multi-clipboard disabled."),
            Err(e) => shell_println!("Error: {:?}", e),
        },
        "stats" => {
            let (entries, pinned, copies, pastes, ops) = multiclip::stats();
            shell_println!("Multi-clipboard stats:");
            shell_println!("  Entries:  {}", entries);
            shell_println!("  Pinned:   {}", pinned);
            shell_println!("  Copies:   {}", copies);
            shell_println!("  Pastes:   {}", pastes);
            shell_println!("  Ops:      {}", ops);
        }
        "test" => multiclip::self_test(),
        _ => {
            shell_println!("Usage: multiclip <subcommand>");
            shell_println!("  show / list           Clipboard history");
            shell_println!("  copy <text>           Copy text");
            shell_println!("  paste [index]         Paste (0=most recent)");
            shell_println!("  slot [name]           List/paste named slots");
            shell_println!("  setslot <id> <name>   Assign named slot");
            shell_println!("  pin/unpin <id>        Pin/unpin entry");
            shell_println!("  remove <id>           Remove entry");
            shell_println!("  clear                 Clear non-pinned");
            shell_println!("  enable / disable      Toggle history");
            shell_println!("  stats / test / init");
        }
    }
}

/// `focussession` / `fsess` — pomodoro-style focus session timer.
fn cmd_focussession(args: &str) {
    use crate::fs::focussession;
    let parts: Vec<&str> = args.split_whitespace().collect();
    let sub = parts.first().copied().unwrap_or("");
    match sub {
        "start" => {
            let task = if parts.len() > 1 {
                parts[1..].join(" ")
            } else {
                alloc::string::String::from("Focus")
            };
            match focussession::start(&task) {
                Ok(()) => shell_println!("Focus session started: {}", task),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "complete" | "done" => {
            match focussession::complete() {
                Ok(()) => shell_println!("Session completed! Break time."),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "abandon" | "stop" => {
            match focussession::abandon() {
                Ok(()) => shell_println!("Session abandoned."),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "break" => {
            match focussession::end_break() {
                Ok(()) => shell_println!("Break ended."),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "pause" => {
            match focussession::pause() {
                Ok(()) => shell_println!("Session paused."),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "resume" => {
            match focussession::resume() {
                Ok(()) => shell_println!("Session resumed."),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "status" | "show" => {
            let state = focussession::current_state();
            shell_println!("State: {}", state.label());
            if let Some(cfg) = focussession::get_config() {
                shell_println!("Focus: {} min, Short break: {} min, Long break: {} min",
                    cfg.focus_mins, cfg.short_break_mins, cfg.long_break_mins);
                shell_println!("Sessions before long break: {}", cfg.sessions_before_long);
                shell_println!("Block notifications: {}", cfg.block_notifications);
            }
        }
        "duration" | "setdur" => {
            if let Some(m) = parts.get(1).and_then(|s| s.parse::<u32>().ok()) {
                match focussession::set_focus_duration(m) {
                    Ok(()) => shell_println!("Focus duration set to {} min", m),
                    Err(e) => shell_println!("Error: {:?}", e),
                }
            } else {
                shell_println!("Usage: focussession duration <minutes>");
            }
        }
        "breaks" => {
            let short = parts.get(1).and_then(|s| s.parse::<u32>().ok());
            let long = parts.get(2).and_then(|s| s.parse::<u32>().ok());
            if let (Some(s), Some(l)) = (short, long) {
                match focussession::set_break_durations(s, l) {
                    Ok(()) => shell_println!("Breaks set: short={} min, long={} min", s, l),
                    Err(e) => shell_println!("Error: {:?}", e),
                }
            } else {
                shell_println!("Usage: focussession breaks <short_mins> <long_mins>");
            }
        }
        "history" => {
            let max = parts.get(1).and_then(|s| s.parse::<usize>().ok()).unwrap_or(10);
            let history = focussession::get_history(max);
            if history.is_empty() {
                shell_println!("No session history.");
            } else {
                for r in &history {
                    let status = if r.completed { "completed" } else { "abandoned" };
                    shell_println!("  [{}] {} — {} ({} min)", r.id, r.task_name, status, r.focus_mins);
                }
            }
        }
        "stats" => {
            let (sessions, abandoned, focus_mins, ops) = focussession::stats();
            shell_println!("Sessions: {}, Abandoned: {}, Focus mins: {}, Ops: {}",
                sessions, abandoned, focus_mins, ops);
        }
        "test" => focussession::self_test(),
        "init" => {
            focussession::init_defaults();
            shell_println!("Focus session subsystem initialised.");
        }
        _ => {
            shell_println!("Usage: focussession <subcommand>");
            shell_println!("  start [task]          Start focus session");
            shell_println!("  complete / done       Complete session");
            shell_println!("  abandon / stop        Abandon session");
            shell_println!("  pause / resume        Pause/resume");
            shell_println!("  break                 End break");
            shell_println!("  status / show         Current state");
            shell_println!("  duration <mins>       Set focus duration");
            shell_println!("  breaks <short> <long> Set break durations");
            shell_println!("  history [max]         Session history");
            shell_println!("  stats / test / init");
        }
    }
}

/// `quicknote` / `qnote` — quick notes and scratchpad.
fn cmd_quicknote(args: &str) {
    use crate::fs::quicknote;
    let parts: Vec<&str> = args.split_whitespace().collect();
    let sub = parts.first().copied().unwrap_or("");
    match sub {
        "new" | "create" => {
            let title = parts.get(1).copied().unwrap_or("Untitled");
            let content = if parts.len() > 2 {
                parts[2..].join(" ")
            } else {
                alloc::string::String::new()
            };
            match quicknote::create(title, &content) {
                Ok(id) => shell_println!("Note created: id={}", id),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "edit" => {
            let id = parts.get(1).and_then(|s| s.parse::<u32>().ok());
            if let Some(id) = id {
                let content = if parts.len() > 2 { parts[2..].join(" ") } else { alloc::string::String::new() };
                match quicknote::edit(id, &content) {
                    Ok(()) => shell_println!("Note {} updated.", id),
                    Err(e) => shell_println!("Error: {:?}", e),
                }
            } else {
                shell_println!("Usage: quicknote edit <id> <content>");
            }
        }
        "title" => {
            let id = parts.get(1).and_then(|s| s.parse::<u32>().ok());
            let title = parts.get(2).copied();
            if let (Some(id), Some(t)) = (id, title) {
                match quicknote::set_title(id, t) {
                    Ok(()) => shell_println!("Title updated for note {}.", id),
                    Err(e) => shell_println!("Error: {:?}", e),
                }
            } else {
                shell_println!("Usage: quicknote title <id> <title>");
            }
        }
        "color" => {
            let id = parts.get(1).and_then(|s| s.parse::<u32>().ok());
            let color = parts.get(2).and_then(|s| parse_note_color(s));
            if let (Some(id), Some(c)) = (id, color) {
                match quicknote::set_color(id, c) {
                    Ok(()) => shell_println!("Color set for note {}.", id),
                    Err(e) => shell_println!("Error: {:?}", e),
                }
            } else {
                shell_println!("Usage: quicknote color <id> <yellow|blue|green|pink|purple|orange|white>");
            }
        }
        "pin" => {
            if let Some(id) = parts.get(1).and_then(|s| s.parse::<u32>().ok()) {
                match quicknote::set_pinned(id, true) {
                    Ok(()) => shell_println!("Note {} pinned.", id),
                    Err(e) => shell_println!("Error: {:?}", e),
                }
            } else {
                shell_println!("Usage: quicknote pin <id>");
            }
        }
        "unpin" => {
            if let Some(id) = parts.get(1).and_then(|s| s.parse::<u32>().ok()) {
                match quicknote::set_pinned(id, false) {
                    Ok(()) => shell_println!("Note {} unpinned.", id),
                    Err(e) => shell_println!("Error: {:?}", e),
                }
            } else {
                shell_println!("Usage: quicknote unpin <id>");
            }
        }
        "tag" => {
            let id = parts.get(1).and_then(|s| s.parse::<u32>().ok());
            let tag = parts.get(2).copied();
            if let (Some(id), Some(t)) = (id, tag) {
                match quicknote::add_tag(id, t) {
                    Ok(()) => shell_println!("Tag '{}' added to note {}.", t, id),
                    Err(e) => shell_println!("Error: {:?}", e),
                }
            } else {
                shell_println!("Usage: quicknote tag <id> <tag>");
            }
        }
        "delete" | "rm" => {
            if let Some(id) = parts.get(1).and_then(|s| s.parse::<u32>().ok()) {
                match quicknote::delete(id) {
                    Ok(()) => shell_println!("Note {} deleted.", id),
                    Err(e) => shell_println!("Error: {:?}", e),
                }
            } else {
                shell_println!("Usage: quicknote delete <id>");
            }
        }
        "show" | "get" => {
            if let Some(id) = parts.get(1).and_then(|s| s.parse::<u32>().ok()) {
                if let Some(n) = quicknote::get(id) {
                    shell_println!("[{}] {} ({}{})", n.id, n.title, n.color.label(),
                        if n.pinned { ", pinned" } else { "" });
                    shell_println!("{}", n.content);
                    if !n.tags.is_empty() {
                        let tags: Vec<&str> = n.tags.iter().map(|t| t.as_str()).collect();
                        shell_println!("Tags: {}", tags.join(", "));
                    }
                } else {
                    shell_println!("Note not found.");
                }
            } else {
                shell_println!("Usage: quicknote show <id>");
            }
        }
        "list" => {
            let max = parts.get(1).and_then(|s| s.parse::<usize>().ok()).unwrap_or(20);
            let notes = quicknote::list(max);
            if notes.is_empty() {
                shell_println!("No notes.");
            } else {
                for n in &notes {
                    let trunc: alloc::string::String = n.content.chars().take(50).collect();
                    shell_println!("  [{}] {} — {} ({}{})", n.id, n.title, trunc,
                        n.color.label(), if n.pinned { ", pinned" } else { "" });
                }
            }
        }
        "pinned" => {
            let notes = quicknote::list_pinned();
            if notes.is_empty() {
                shell_println!("No pinned notes.");
            } else {
                for n in &notes {
                    shell_println!("  [{}] {} — {}", n.id, n.title, n.color.label());
                }
            }
        }
        "search" | "find" => {
            if parts.len() > 1 {
                let query = parts[1..].join(" ");
                let found = quicknote::search(&query, 20);
                if found.is_empty() {
                    shell_println!("No notes matching '{}'.", query);
                } else {
                    for n in &found {
                        shell_println!("  [{}] {} — {}", n.id, n.title, n.color.label());
                    }
                }
            } else {
                shell_println!("Usage: quicknote search <query>");
            }
        }
        "stats" => {
            let (notes, pinned, created, edits, ops) = quicknote::stats();
            shell_println!("Notes: {}, Pinned: {}, Created: {}, Edits: {}, Ops: {}",
                notes, pinned, created, edits, ops);
        }
        "test" => quicknote::self_test(),
        "init" => {
            quicknote::init_defaults();
            shell_println!("Quick notes subsystem initialised.");
        }
        _ => {
            shell_println!("Usage: quicknote <subcommand>");
            shell_println!("  new <title> [content] Create note");
            shell_println!("  edit <id> <content>   Edit content");
            shell_println!("  title <id> <title>    Set title");
            shell_println!("  color <id> <color>    Set color");
            shell_println!("  pin/unpin <id>        Pin/unpin");
            shell_println!("  tag <id> <tag>        Add tag");
            shell_println!("  delete <id>           Delete note");
            shell_println!("  show <id>             Show note");
            shell_println!("  list [max]            List notes");
            shell_println!("  pinned                List pinned");
            shell_println!("  search <query>        Search notes");
            shell_println!("  stats / test / init");
        }
    }
}

fn parse_note_color(s: &str) -> Option<crate::fs::quicknote::NoteColor> {
    use crate::fs::quicknote::NoteColor;
    match s.to_lowercase().as_str() {
        "yellow" => Some(NoteColor::Yellow),
        "blue" => Some(NoteColor::Blue),
        "green" => Some(NoteColor::Green),
        "pink" => Some(NoteColor::Pink),
        "purple" => Some(NoteColor::Purple),
        "orange" => Some(NoteColor::Orange),
        "white" => Some(NoteColor::White),
        _ => None,
    }
}

/// `cscheme` / `uischeme` — UI color scheme management.
fn cmd_uicolorscheme(args: &str) {
    use crate::fs::colorscheme;
    let parts: Vec<&str> = args.split_whitespace().collect();
    let sub = parts.first().copied().unwrap_or("");
    match sub {
        "show" | "active" => {
            if let Some(active) = colorscheme::get_active() {
                shell_println!("Active scheme: {} (id={})", active.name, active.id);
                shell_println!("Mode: {:?}, Accent: {}", active.mode, active.accent);
                for c in &active.colors {
                    shell_println!("  {:?}: {}", c.role, c.hex);
                }
            } else {
                shell_println!("No active scheme.");
            }
        }
        "list" => {
            let schemes = colorscheme::list_schemes();
            if schemes.is_empty() {
                shell_println!("No schemes.");
            } else {
                for s in &schemes {
                    shell_println!("  [{}] {} ({:?}) accent={}", s.id, s.name, s.mode, s.accent);
                }
            }
        }
        "set" => {
            if let Some(id) = parts.get(1).and_then(|s| s.parse::<u32>().ok()) {
                match colorscheme::set_scheme(id) {
                    Ok(()) => shell_println!("Scheme set to id={}.", id),
                    Err(e) => shell_println!("Error: {:?}", e),
                }
            } else {
                shell_println!("Usage: colorscheme set <id>");
            }
        }
        "light" => {
            match colorscheme::set_mode(colorscheme::ColorMode::Light) {
                Ok(()) => shell_println!("Switched to light mode."),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "dark" => {
            match colorscheme::set_mode(colorscheme::ColorMode::Dark) {
                Ok(()) => shell_println!("Switched to dark mode."),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "accent" => {
            if let Some(hex) = parts.get(1) {
                match colorscheme::set_accent(hex) {
                    Ok(()) => shell_println!("Accent set to {}.", hex),
                    Err(e) => shell_println!("Error: {:?}", e),
                }
            } else {
                shell_println!("Usage: colorscheme accent <#hex>");
            }
        }
        "color" => {
            let role = parts.get(1).and_then(|s| parse_color_role(s));
            let hex = parts.get(2);
            if let (Some(r), Some(h)) = (role, hex) {
                match colorscheme::set_color(r, h) {
                    Ok(()) => shell_println!("Color {:?} set to {}.", r, h),
                    Err(e) => shell_println!("Error: {:?}", e),
                }
            } else {
                shell_println!("Usage: colorscheme color <role> <#hex>");
                shell_println!("  Roles: background, surface, primary, secondary, accent,");
                shell_println!("         text, textsec, border, error, warning, success, link");
            }
        }
        "get" => {
            if let Some(role) = parts.get(1).and_then(|s| parse_color_role(s)) {
                if let Some(hex) = colorscheme::get_color(role) {
                    shell_println!("{:?}: {}", role, hex);
                } else {
                    shell_println!("Color not found.");
                }
            } else {
                shell_println!("Usage: colorscheme get <role>");
            }
        }
        "stats" => {
            let (schemes, changes, ops) = colorscheme::stats();
            shell_println!("Schemes: {}, Changes: {}, Ops: {}", schemes, changes, ops);
        }
        "test" => colorscheme::self_test(),
        "init" => {
            colorscheme::init_defaults();
            shell_println!("Color scheme subsystem initialised.");
        }
        _ => {
            shell_println!("Usage: colorscheme <subcommand>");
            shell_println!("  show / active         Show active scheme");
            shell_println!("  list                  List all schemes");
            shell_println!("  set <id>              Set active scheme");
            shell_println!("  light / dark          Switch mode");
            shell_println!("  accent <#hex>         Set accent color");
            shell_println!("  color <role> <#hex>   Set specific color");
            shell_println!("  get <role>            Get color value");
            shell_println!("  stats / test / init");
        }
    }
}

fn parse_color_role(s: &str) -> Option<crate::fs::colorscheme::ColorRole> {
    use crate::fs::colorscheme::ColorRole;
    match s.to_lowercase().as_str() {
        "background" | "bg" => Some(ColorRole::Background),
        "surface" => Some(ColorRole::Surface),
        "primary" => Some(ColorRole::Primary),
        "secondary" => Some(ColorRole::Secondary),
        "accent" => Some(ColorRole::Accent),
        "text" | "textprimary" => Some(ColorRole::TextPrimary),
        "textsec" | "textsecondary" => Some(ColorRole::TextSecondary),
        "border" => Some(ColorRole::Border),
        "error" => Some(ColorRole::Error),
        "warning" => Some(ColorRole::Warning),
        "success" => Some(ColorRole::Success),
        "link" => Some(ColorRole::Link),
        _ => None,
    }
}

/// `appcompat` / `acompat` — application compatibility layer.
fn cmd_appcompat(args: &str) {
    use crate::fs::appcompat;
    let parts: Vec<&str> = args.split_whitespace().collect();
    let sub = parts.first().copied().unwrap_or("");
    match sub {
        "set" => {
            let app = parts.get(1).copied();
            let level = parts.get(2).and_then(|s| parse_compat_level(s));
            if let (Some(app), Some(lvl)) = (app, level) {
                match appcompat::set_compat(app, lvl) {
                    Ok(()) => shell_println!("Compat level for '{}' set to {}.", app, lvl.label()),
                    Err(e) => shell_println!("Error: {:?}", e),
                }
            } else {
                shell_println!("Usage: appcompat set <app> <current|legacy1|legacy2|max>");
            }
        }
        "shim" => {
            let action = parts.get(1).copied().unwrap_or("");
            let app = parts.get(2).copied();
            let shim = parts.get(3).and_then(|s| parse_shim(s));
            match action {
                "add" => {
                    if let (Some(app), Some(sh)) = (app, shim) {
                        match appcompat::add_shim(app, sh) {
                            Ok(()) => shell_println!("Shim {} added to '{}'.", sh.label(), app),
                            Err(e) => shell_println!("Error: {:?}", e),
                        }
                    } else {
                        shell_println!("Usage: appcompat shim add <app> <shim_name>");
                    }
                }
                "remove" | "rm" => {
                    if let (Some(app), Some(sh)) = (app, shim) {
                        match appcompat::remove_shim(app, sh) {
                            Ok(()) => shell_println!("Shim {} removed from '{}'.", sh.label(), app),
                            Err(e) => shell_println!("Error: {:?}", e),
                        }
                    } else {
                        shell_println!("Usage: appcompat shim remove <app> <shim_name>");
                    }
                }
                _ => {
                    shell_println!("Usage: appcompat shim <add|remove> <app> <shim>");
                    shell_println!("  Shims: apiredirect, pathredirect, legacydpi, softrender,");
                    shell_println!("         singlethread, legacytimer, permissive, configredirect");
                }
            }
        }
        "profile" | "show" => {
            if let Some(app) = parts.get(1).copied() {
                if let Some(p) = appcompat::get_profile(app) {
                    shell_println!("Profile: {} ({})", p.app_name, p.compat_level.label());
                    shell_println!("Enabled: {}, Launches: {}", p.enabled, p.launch_count);
                    if p.shims.is_empty() {
                        shell_println!("Shims: none");
                    } else {
                        let labels: Vec<&str> = p.shims.iter().map(|s| s.label()).collect();
                        shell_println!("Shims: {}", labels.join(", "));
                    }
                } else {
                    shell_println!("No profile for '{}' (or profile disabled).", app);
                }
            } else {
                shell_println!("Usage: appcompat profile <app>");
            }
        }
        "list" => {
            let profiles = appcompat::list_profiles();
            if profiles.is_empty() {
                shell_println!("No compatibility profiles.");
            } else {
                for p in &profiles {
                    shell_println!("  {} — {} shims={} enabled={} launches={}",
                        p.app_name, p.compat_level.label(), p.shims.len(), p.enabled, p.launch_count);
                }
            }
        }
        "launch" => {
            if let Some(app) = parts.get(1).copied() {
                match appcompat::record_launch(app) {
                    Ok(shims) => shell_println!("Launch recorded for '{}': {} shims activated.", app, shims),
                    Err(e) => shell_println!("Error: {:?}", e),
                }
            } else {
                shell_println!("Usage: appcompat launch <app>");
            }
        }
        "enable" => {
            if let Some(app) = parts.get(1).copied() {
                match appcompat::set_profile_enabled(app, true) {
                    Ok(()) => shell_println!("Profile '{}' enabled.", app),
                    Err(e) => shell_println!("Error: {:?}", e),
                }
            } else {
                shell_println!("Usage: appcompat enable <app>");
            }
        }
        "disable" => {
            if let Some(app) = parts.get(1).copied() {
                match appcompat::set_profile_enabled(app, false) {
                    Ok(()) => shell_println!("Profile '{}' disabled.", app),
                    Err(e) => shell_println!("Error: {:?}", e),
                }
            } else {
                shell_println!("Usage: appcompat disable <app>");
            }
        }
        "remove" | "rm" => {
            if let Some(app) = parts.get(1).copied() {
                match appcompat::remove_profile(app) {
                    Ok(()) => shell_println!("Profile '{}' removed.", app),
                    Err(e) => shell_println!("Error: {:?}", e),
                }
            } else {
                shell_println!("Usage: appcompat remove <app>");
            }
        }
        "stats" => {
            let (profiles, launches, shim_acts, ops) = appcompat::stats();
            shell_println!("Profiles: {}, Launches: {}, Shim activations: {}, Ops: {}",
                profiles, launches, shim_acts, ops);
        }
        "test" => appcompat::self_test(),
        "init" => {
            appcompat::init_defaults();
            shell_println!("App compatibility subsystem initialised.");
        }
        _ => {
            shell_println!("Usage: appcompat <subcommand>");
            shell_println!("  set <app> <level>     Set compat level");
            shell_println!("  shim add/rm <app> <s> Add/remove shim");
            shell_println!("  profile <app>         Show profile");
            shell_println!("  list                  List all profiles");
            shell_println!("  launch <app>          Record launch");
            shell_println!("  enable/disable <app>  Toggle profile");
            shell_println!("  remove <app>          Remove profile");
            shell_println!("  stats / test / init");
        }
    }
}

fn parse_compat_level(s: &str) -> Option<crate::fs::appcompat::CompatLevel> {
    use crate::fs::appcompat::CompatLevel;
    match s.to_lowercase().as_str() {
        "current" => Some(CompatLevel::Current),
        "legacy1" | "l1" => Some(CompatLevel::Legacy1),
        "legacy2" | "l2" => Some(CompatLevel::Legacy2),
        "max" | "maxcompat" => Some(CompatLevel::MaxCompat),
        _ => None,
    }
}

fn parse_shim(s: &str) -> Option<crate::fs::appcompat::Shim> {
    use crate::fs::appcompat::Shim;
    match s.to_lowercase().as_str() {
        "apiredirect" | "api" => Some(Shim::ApiRedirect),
        "pathredirect" | "path" => Some(Shim::PathRedirect),
        "legacydpi" | "dpi" => Some(Shim::LegacyDpi),
        "softrender" | "software" => Some(Shim::SoftwareRendering),
        "singlethread" | "single" => Some(Shim::SingleThread),
        "legacytimer" | "timer" => Some(Shim::LegacyTimer),
        "permissive" | "perm" => Some(Shim::PermissiveMode),
        "configredirect" | "config" => Some(Shim::ConfigRedirect),
        _ => None,
    }
}

/// `windowrules` / `wrules` — per-window placement and behavior rules.
fn cmd_windowrules(args: &str) {
    use crate::fs::windowrules;
    let parts: Vec<&str> = args.split_whitespace().collect();
    let sub = parts.first().copied().unwrap_or("");
    match sub {
        "list" | "show" => {
            let rules = windowrules::list_rules();
            if rules.is_empty() {
                shell_println!("No window rules.");
            } else {
                for r in &rules {
                    shell_println!("  [{}] {} — {} '{}' ({} actions, {}, hits={})",
                        r.id, r.name, r.match_type.label(), r.match_value,
                        r.actions.len(), if r.enabled { "on" } else { "off" }, r.hit_count);
                }
            }
        }
        "add" => {
            let match_t = parts.get(1).and_then(|s| parse_match_type(s));
            let value = parts.get(2).copied();
            let name = if parts.len() > 3 { parts[3..].join(" ") } else { alloc::string::String::from("Rule") };
            if let (Some(mt), Some(v)) = (match_t, value) {
                match windowrules::add_rule(&name, mt, v) {
                    Ok(id) => shell_println!("Rule created: id={}", id),
                    Err(e) => shell_println!("Error: {:?}", e),
                }
            } else {
                shell_println!("Usage: windowrules add <match_type> <value> [name]");
                shell_println!("  Match types: app, appcontains, title, class, any");
            }
        }
        "action" => {
            let id = parts.get(1).and_then(|s| s.parse::<u32>().ok());
            let action = parts.get(2).and_then(|s| parse_rule_action(s));
            let p1 = parts.get(3).and_then(|s| s.parse::<i32>().ok()).unwrap_or(0);
            let p2 = parts.get(4).and_then(|s| s.parse::<i32>().ok()).unwrap_or(0);
            if let (Some(id), Some(act)) = (id, action) {
                match windowrules::add_action(id, act, p1, p2) {
                    Ok(()) => shell_println!("Action {} added to rule {}.", act.label(), id),
                    Err(e) => shell_println!("Error: {:?}", e),
                }
            } else {
                shell_println!("Usage: windowrules action <rule_id> <action> [p1] [p2]");
                shell_println!("  Actions: position, size, workspace, ontop, onbottom, opacity,");
                shell_println!("           nodecor, maximized, minimized, fullscreen, skiptask,");
                shell_println!("           skippager, pinall, center");
            }
        }
        "enable" => {
            if let Some(id) = parts.get(1).and_then(|s| s.parse::<u32>().ok()) {
                match windowrules::set_enabled(id, true) {
                    Ok(()) => shell_println!("Rule {} enabled.", id),
                    Err(e) => shell_println!("Error: {:?}", e),
                }
            } else {
                shell_println!("Usage: windowrules enable <id>");
            }
        }
        "disable" => {
            if let Some(id) = parts.get(1).and_then(|s| s.parse::<u32>().ok()) {
                match windowrules::set_enabled(id, false) {
                    Ok(()) => shell_println!("Rule {} disabled.", id),
                    Err(e) => shell_println!("Error: {:?}", e),
                }
            } else {
                shell_println!("Usage: windowrules disable <id>");
            }
        }
        "remove" | "rm" => {
            if let Some(id) = parts.get(1).and_then(|s| s.parse::<u32>().ok()) {
                match windowrules::remove_rule(id) {
                    Ok(()) => shell_println!("Rule {} removed.", id),
                    Err(e) => shell_println!("Error: {:?}", e),
                }
            } else {
                shell_println!("Usage: windowrules remove <id>");
            }
        }
        "match" => {
            let app = parts.get(1).copied().unwrap_or("");
            let title = parts.get(2).copied().unwrap_or("");
            let matches = windowrules::match_rules(app, title, "");
            if matches.is_empty() {
                shell_println!("No rules match app='{}' title='{}'.", app, title);
            } else {
                for (id, actions) in &matches {
                    let labels: Vec<&str> = actions.iter().map(|a| a.action.label()).collect();
                    shell_println!("  Rule {}: {}", id, labels.join(", "));
                }
            }
        }
        "stats" => {
            let (rules, enabled, matches, applied, ops) = windowrules::stats();
            shell_println!("Rules: {}, Enabled: {}, Matches: {}, Applied: {}, Ops: {}",
                rules, enabled, matches, applied, ops);
        }
        "test" => windowrules::self_test(),
        "init" => {
            windowrules::init_defaults();
            shell_println!("Window rules subsystem initialised.");
        }
        _ => {
            shell_println!("Usage: windowrules <subcommand>");
            shell_println!("  list / show           List all rules");
            shell_println!("  add <type> <val> [nm] Add rule");
            shell_println!("  action <id> <act> ... Add action to rule");
            shell_println!("  enable/disable <id>   Toggle rule");
            shell_println!("  remove <id>           Remove rule");
            shell_println!("  match <app> [title]   Test matching");
            shell_println!("  stats / test / init");
        }
    }
}

fn parse_match_type(s: &str) -> Option<crate::fs::windowrules::MatchType> {
    use crate::fs::windowrules::MatchType;
    match s.to_lowercase().as_str() {
        "app" | "appexact" => Some(MatchType::AppExact),
        "appcontains" | "appc" => Some(MatchType::AppContains),
        "title" | "titlecontains" => Some(MatchType::TitleContains),
        "class" | "classexact" => Some(MatchType::ClassExact),
        "any" | "all" => Some(MatchType::Any),
        _ => None,
    }
}

fn parse_rule_action(s: &str) -> Option<crate::fs::windowrules::RuleAction> {
    use crate::fs::windowrules::RuleAction;
    match s.to_lowercase().as_str() {
        "position" | "pos" => Some(RuleAction::SetPosition),
        "size" => Some(RuleAction::SetSize),
        "workspace" | "ws" => Some(RuleAction::MoveToWorkspace),
        "ontop" | "alwaysontop" => Some(RuleAction::AlwaysOnTop),
        "onbottom" => Some(RuleAction::AlwaysOnBottom),
        "opacity" => Some(RuleAction::SetOpacity),
        "nodecor" | "nodecorations" => Some(RuleAction::NoDecorations),
        "maximized" | "max" => Some(RuleAction::StartMaximized),
        "minimized" | "min" => Some(RuleAction::StartMinimized),
        "fullscreen" | "fs" => Some(RuleAction::StartFullscreen),
        "skiptask" | "skiptaskbar" => Some(RuleAction::SkipTaskbar),
        "skippager" => Some(RuleAction::SkipPager),
        "pinall" | "pinallws" => Some(RuleAction::PinAllWorkspaces),
        "center" => Some(RuleAction::CenterOnScreen),
        _ => None,
    }
}

/// `spatialaudio` / `spatial` — 3D audio positioning.
fn cmd_spatialaudio(args: &str) {
    use crate::fs::spatialaudio;
    let parts: Vec<&str> = args.split_whitespace().collect();
    let sub = parts.first().copied().unwrap_or("");
    match sub {
        "show" | "status" => {
            if let Some(cfg) = spatialaudio::get_config() {
                shell_println!("Spatial audio: {}", if cfg.global_enabled { "ON" } else { "OFF" });
                shell_println!("Layout: {} ({}ch)", cfg.layout.label(), cfg.layout.channel_count());
                shell_println!("Room: {}", cfg.room_size.label());
                shell_println!("Head tracking: {}", cfg.head_tracking);
                shell_println!("Reverb: {}%", cfg.reverb_level);
                shell_println!("Distance attenuation: {}", cfg.distance_attenuation);
                shell_println!("Doppler: {}", cfg.doppler_effect);
            } else {
                shell_println!("Not initialised.");
            }
        }
        "enable" => {
            match spatialaudio::set_enabled(true) {
                Ok(()) => shell_println!("Spatial audio enabled."),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "disable" => {
            match spatialaudio::set_enabled(false) {
                Ok(()) => shell_println!("Spatial audio disabled."),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "layout" => {
            if let Some(layout) = parts.get(1).and_then(|s| parse_speaker_layout(s)) {
                match spatialaudio::set_layout(layout) {
                    Ok(()) => shell_println!("Layout set to {}.", layout.label()),
                    Err(e) => shell_println!("Error: {:?}", e),
                }
            } else {
                shell_println!("Usage: spatialaudio layout <stereo|5.1|7.1|atmos|binaural>");
            }
        }
        "room" => {
            if let Some(room) = parts.get(1).and_then(|s| parse_room_size(s)) {
                match spatialaudio::set_room_size(room) {
                    Ok(()) => shell_println!("Room set to {}.", room.label()),
                    Err(e) => shell_println!("Error: {:?}", e),
                }
            } else {
                shell_println!("Usage: spatialaudio room <none|small|medium|large|hall|arena>");
            }
        }
        "reverb" => {
            if let Some(level) = parts.get(1).and_then(|s| s.parse::<u32>().ok()) {
                match spatialaudio::set_reverb(level) {
                    Ok(()) => shell_println!("Reverb set to {}%.", level.min(100)),
                    Err(e) => shell_println!("Error: {:?}", e),
                }
            } else {
                shell_println!("Usage: spatialaudio reverb <0-100>");
            }
        }
        "headtrack" => {
            let on = parts.get(1).copied().unwrap_or("on") == "on";
            match spatialaudio::set_head_tracking(on) {
                Ok(()) => shell_println!("Head tracking {}.", if on { "enabled" } else { "disabled" }),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "doppler" => {
            let on = parts.get(1).copied().unwrap_or("on") == "on";
            match spatialaudio::set_doppler(on) {
                Ok(()) => shell_println!("Doppler effect {}.", if on { "enabled" } else { "disabled" }),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "app" => {
            let app = parts.get(1).copied();
            let enabled = parts.get(2).map(|s| *s != "off" && *s != "false" && *s != "0").unwrap_or(true);
            if let Some(app) = app {
                match spatialaudio::set_app_enabled(app, enabled) {
                    Ok(()) => shell_println!("App '{}' spatial audio {}.", app, if enabled { "enabled" } else { "disabled" }),
                    Err(e) => shell_println!("Error: {:?}", e),
                }
            } else {
                shell_println!("Usage: spatialaudio app <name> [on|off]");
            }
        }
        "apps" => {
            let configs = spatialaudio::list_app_configs();
            if configs.is_empty() {
                shell_println!("No per-app configs.");
            } else {
                for c in &configs {
                    shell_println!("  {} — {}", c.app_name, if c.enabled { "on" } else { "off" });
                }
            }
        }
        "stats" => {
            let (apps, streams, changes, ops) = spatialaudio::stats();
            shell_println!("App configs: {}, Streams: {}, Changes: {}, Ops: {}",
                apps, streams, changes, ops);
        }
        "test" => spatialaudio::self_test(),
        "init" => {
            spatialaudio::init_defaults();
            shell_println!("Spatial audio subsystem initialised.");
        }
        _ => {
            shell_println!("Usage: spatialaudio <subcommand>");
            shell_println!("  show / status         Show config");
            shell_println!("  enable / disable      Toggle spatial audio");
            shell_println!("  layout <type>         Set speaker layout");
            shell_println!("  room <size>           Set room size");
            shell_println!("  reverb <0-100>        Set reverb level");
            shell_println!("  headtrack [on|off]    Toggle head tracking");
            shell_println!("  doppler [on|off]      Toggle Doppler effect");
            shell_println!("  app <name> [on|off]   Per-app toggle");
            shell_println!("  apps                  List app configs");
            shell_println!("  stats / test / init");
        }
    }
}

fn parse_speaker_layout(s: &str) -> Option<crate::fs::spatialaudio::SpeakerLayout> {
    use crate::fs::spatialaudio::SpeakerLayout;
    match s.to_lowercase().as_str() {
        "stereo" | "2.0" => Some(SpeakerLayout::Stereo),
        "5.1" | "surround51" => Some(SpeakerLayout::Surround51),
        "7.1" | "surround71" => Some(SpeakerLayout::Surround71),
        "atmos" | "dolby" => Some(SpeakerLayout::Atmos),
        "binaural" | "headphone" => Some(SpeakerLayout::Binaural),
        "custom" => Some(SpeakerLayout::Custom),
        _ => None,
    }
}

fn parse_room_size(s: &str) -> Option<crate::fs::spatialaudio::RoomSize> {
    use crate::fs::spatialaudio::RoomSize;
    match s.to_lowercase().as_str() {
        "none" | "off" => Some(RoomSize::None),
        "small" => Some(RoomSize::Small),
        "medium" | "med" => Some(RoomSize::Medium),
        "large" => Some(RoomSize::Large),
        "hall" | "concert" => Some(RoomSize::Hall),
        "arena" => Some(RoomSize::Arena),
        _ => None,
    }
}

/// `filetransfer` / `ftrans` — device-to-device file sharing.
fn cmd_filetransfer(args: &str) {
    use crate::fs::filetransfer;
    let parts: Vec<&str> = args.split_whitespace().collect();
    let sub = parts.first().copied().unwrap_or("");
    match sub {
        "show" | "status" => {
            let vis = filetransfer::get_visibility();
            shell_println!("Visibility: {}", vis.label());
            let devices = filetransfer::list_devices();
            shell_println!("Nearby devices: {}", devices.len());
            for d in &devices {
                shell_println!("  [{}] {} ({}, {}, signal={})",
                    d.id, d.name, d.device_type, d.transport.label(), d.signal_strength);
            }
        }
        "visibility" | "vis" => {
            if let Some(v) = parts.get(1).and_then(|s| parse_visibility(s)) {
                match filetransfer::set_visibility(v) {
                    Ok(()) => shell_println!("Visibility set to {}.", v.label()),
                    Err(e) => shell_println!("Error: {:?}", e),
                }
            } else {
                shell_println!("Usage: filetransfer visibility <hidden|contacts|everyone>");
            }
        }
        "savepath" => {
            if let Some(path) = parts.get(1) {
                match filetransfer::set_save_path(path) {
                    Ok(()) => shell_println!("Save path set to '{}'.", path),
                    Err(e) => shell_println!("Error: {:?}", e),
                }
            } else {
                shell_println!("Usage: filetransfer savepath <path>");
            }
        }
        "discover" => {
            let name = parts.get(1).copied().unwrap_or("Device");
            let dtype = parts.get(2).copied().unwrap_or("unknown");
            let transport = parts.get(3).and_then(|s| parse_transport(s)).unwrap_or(filetransfer::Transport::Auto);
            match filetransfer::discover_device(name, dtype, transport, -50) {
                Ok(id) => shell_println!("Device discovered: id={}", id),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "send" => {
            let device_id = parts.get(1).and_then(|s| s.parse::<u32>().ok());
            let file_name = parts.get(2).copied();
            let size = parts.get(3).and_then(|s| s.parse::<u64>().ok()).unwrap_or(0);
            if let (Some(did), Some(fname)) = (device_id, file_name) {
                match filetransfer::send_file(did, fname, size) {
                    Ok(tid) => shell_println!("Transfer initiated: id={}", tid),
                    Err(e) => shell_println!("Error: {:?}", e),
                }
            } else {
                shell_println!("Usage: filetransfer send <device_id> <filename> [size]");
            }
        }
        "accept" => {
            if let Some(id) = parts.get(1).and_then(|s| s.parse::<u32>().ok()) {
                match filetransfer::accept_transfer(id) {
                    Ok(()) => shell_println!("Transfer {} accepted.", id),
                    Err(e) => shell_println!("Error: {:?}", e),
                }
            } else {
                shell_println!("Usage: filetransfer accept <transfer_id>");
            }
        }
        "reject" => {
            if let Some(id) = parts.get(1).and_then(|s| s.parse::<u32>().ok()) {
                match filetransfer::reject_transfer(id) {
                    Ok(()) => shell_println!("Transfer {} rejected.", id),
                    Err(e) => shell_println!("Error: {:?}", e),
                }
            } else {
                shell_println!("Usage: filetransfer reject <transfer_id>");
            }
        }
        "cancel" => {
            if let Some(id) = parts.get(1).and_then(|s| s.parse::<u32>().ok()) {
                match filetransfer::cancel_transfer(id) {
                    Ok(()) => shell_println!("Transfer {} cancelled.", id),
                    Err(e) => shell_println!("Error: {:?}", e),
                }
            } else {
                shell_println!("Usage: filetransfer cancel <transfer_id>");
            }
        }
        "transfers" => {
            let max = parts.get(1).and_then(|s| s.parse::<usize>().ok()).unwrap_or(20);
            let transfers = filetransfer::list_transfers(max);
            if transfers.is_empty() {
                shell_println!("No transfers.");
            } else {
                for t in &transfers {
                    let dir = if t.outgoing { "OUT" } else { "IN " };
                    shell_println!("  [{}] {} {} → {} ({}, {}/{})",
                        t.id, dir, t.file_name, t.device_name, t.status.label(),
                        t.bytes_transferred, t.file_size);
                }
            }
        }
        "stats" => {
            let (devs, sent, recv, bytes_s, bytes_r, ops) = filetransfer::stats();
            shell_println!("Devices: {}, Sent: {}, Received: {}, Bytes sent: {}, Bytes recv: {}, Ops: {}",
                devs, sent, recv, bytes_s, bytes_r, ops);
        }
        "test" => filetransfer::self_test(),
        "init" => {
            filetransfer::init_defaults();
            shell_println!("File transfer subsystem initialised.");
        }
        _ => {
            shell_println!("Usage: filetransfer <subcommand>");
            shell_println!("  show / status         Show nearby devices");
            shell_println!("  visibility <mode>     Set visibility");
            shell_println!("  savepath <path>       Set receive path");
            shell_println!("  discover <n> <t> [tr] Simulate discovery");
            shell_println!("  send <dev> <file> [s] Send file");
            shell_println!("  accept/reject <id>    Accept/reject transfer");
            shell_println!("  cancel <id>           Cancel transfer");
            shell_println!("  transfers [max]       List transfers");
            shell_println!("  stats / test / init");
        }
    }
}

fn parse_visibility(s: &str) -> Option<crate::fs::filetransfer::Visibility> {
    use crate::fs::filetransfer::Visibility;
    match s.to_lowercase().as_str() {
        "hidden" | "off" => Some(Visibility::Hidden),
        "contacts" | "contactsonly" => Some(Visibility::ContactsOnly),
        "everyone" | "all" => Some(Visibility::Everyone),
        _ => None,
    }
}

fn parse_transport(s: &str) -> Option<crate::fs::filetransfer::Transport> {
    use crate::fs::filetransfer::Transport;
    match s.to_lowercase().as_str() {
        "bt" | "bluetooth" => Some(Transport::Bluetooth),
        "wifi" | "wifidirect" => Some(Transport::WifiDirect),
        "lan" | "local" | "network" => Some(Transport::LocalNetwork),
        "auto" => Some(Transport::Auto),
        _ => None,
    }
}

/// `startupopt` / `sopt` — boot profiling and optimization.
fn cmd_startupopt(args: &str) {
    use crate::fs::startupopt;
    let parts: Vec<&str> = args.split_whitespace().collect();
    let sub = parts.first().copied().unwrap_or("");
    match sub {
        "show" | "status" => {
            let (stages, boots, last_ms, fastest_ms, analyses, _ops) = startupopt::stats();
            shell_println!("Boot count: {}", boots);
            shell_println!("Last boot: {}ms", last_ms);
            shell_println!("Fastest boot: {}ms", fastest_ms);
            shell_println!("Stages recorded: {}", stages);
            shell_println!("Analyses run: {}", analyses);
        }
        "stages" => {
            let sorted = startupopt::get_stages_by_duration();
            if sorted.is_empty() {
                shell_println!("No stages recorded.");
            } else {
                shell_println!("Stages (slowest first):");
                for s in &sorted {
                    shell_println!("  {} ({}) — {}ms", s.name, s.category.label(), s.duration_ms);
                }
            }
        }
        "category" | "cat" => {
            if let Some(cat) = parts.get(1).and_then(|s| parse_stage_category(s)) {
                let stages = startupopt::get_stages_by_category(cat);
                if stages.is_empty() {
                    shell_println!("No stages for {}.", cat.label());
                } else {
                    for s in &stages {
                        shell_println!("  {} — {}ms", s.name, s.duration_ms);
                    }
                }
            } else {
                shell_println!("Usage: startupopt category <firmware|bootloader|kernel|drivers|services|session|desktop|autostart>");
            }
        }
        "begin" => {
            let name = parts.get(1).copied().unwrap_or("stage");
            let cat = parts.get(2).and_then(|s| parse_stage_category(s)).unwrap_or(startupopt::StageCategory::Services);
            match startupopt::begin_stage(name, cat) {
                Ok(()) => shell_println!("Stage '{}' started.", name),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "end" => {
            if let Some(name) = parts.get(1) {
                match startupopt::end_stage(name) {
                    Ok(ms) => shell_println!("Stage '{}' completed: {}ms.", name, ms),
                    Err(e) => shell_println!("Error: {:?}", e),
                }
            } else {
                shell_println!("Usage: startupopt end <stage_name>");
            }
        }
        "boot" => {
            match startupopt::record_boot() {
                Ok(total) => shell_println!("Boot recorded: total {}ms.", total),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "analyze" => {
            match startupopt::analyze() {
                Ok(count) => {
                    shell_println!("{} suggestions generated.", count);
                    let suggestions = startupopt::get_suggestions();
                    for s in &suggestions {
                        let applied = if s.applied { " [applied]" } else { "" };
                        shell_println!("  [{}] [{}] {} (save ~{}ms){}",
                            s.id, s.priority.label(), s.description, s.estimated_savings_ms, applied);
                    }
                }
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "apply" => {
            if let Some(id) = parts.get(1).and_then(|s| s.parse::<u32>().ok()) {
                match startupopt::apply_suggestion(id) {
                    Ok(()) => shell_println!("Suggestion {} marked as applied.", id),
                    Err(e) => shell_println!("Error: {:?}", e),
                }
            } else {
                shell_println!("Usage: startupopt apply <suggestion_id>");
            }
        }
        "clear" => {
            match startupopt::clear_stages() {
                Ok(()) => shell_println!("Stages cleared."),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "stats" => {
            let (stages, boots, last_ms, fastest_ms, analyses, ops) = startupopt::stats();
            shell_println!("Stages: {}, Boots: {}, Last: {}ms, Fastest: {}ms, Analyses: {}, Ops: {}",
                stages, boots, last_ms, fastest_ms, analyses, ops);
        }
        "test" => startupopt::self_test(),
        "init" => {
            startupopt::init_defaults();
            shell_println!("Startup optimization subsystem initialised.");
        }
        _ => {
            shell_println!("Usage: startupopt <subcommand>");
            shell_println!("  show / status         Boot timing summary");
            shell_println!("  stages                List stages (slowest first)");
            shell_println!("  category <cat>        Stages by category");
            shell_println!("  begin <name> [cat]    Begin recording stage");
            shell_println!("  end <name>            End recording stage");
            shell_println!("  boot                  Record boot completion");
            shell_println!("  analyze               Generate suggestions");
            shell_println!("  apply <id>            Mark suggestion applied");
            shell_println!("  clear                 Clear stage data");
            shell_println!("  stats / test / init");
        }
    }
}

fn parse_stage_category(s: &str) -> Option<crate::fs::startupopt::StageCategory> {
    use crate::fs::startupopt::StageCategory;
    match s.to_lowercase().as_str() {
        "firmware" | "fw" => Some(StageCategory::Firmware),
        "bootloader" | "boot" => Some(StageCategory::Bootloader),
        "kernel" | "kernearly" => Some(StageCategory::KernelEarly),
        "drivers" | "drv" => Some(StageCategory::Drivers),
        "services" | "svc" => Some(StageCategory::Services),
        "session" | "user" => Some(StageCategory::UserSession),
        "desktop" | "desk" => Some(StageCategory::Desktop),
        "autostart" | "auto" => Some(StageCategory::AutoStart),
        _ => None,
    }
}

/// `usagetime` / `utime` — per-app usage time tracking.
fn cmd_usagetime(args: &str) {
    use crate::fs::usagetime;
    use alloc::format;
    let parts: Vec<&str> = args.split_whitespace().collect();
    let sub = parts.first().copied().unwrap_or("");
    match sub {
        "top" | "show" => {
            let max = parts.get(1).and_then(|s| s.parse::<usize>().ok()).unwrap_or(10);
            let top = usagetime::top_apps(max);
            if top.is_empty() {
                shell_println!("No usage data.");
            } else {
                for a in &top {
                    let hrs = a.total_foreground_ms / 3_600_000;
                    let mins = (a.total_foreground_ms % 3_600_000) / 60_000;
                    let limit_str = a.daily_limit_ms.map_or(
                        alloc::string::String::from("no limit"),
                        |l| format!("limit {}m", l / 60_000)
                    );
                    shell_println!("  {} — {}h {}m ({} sessions, {})",
                        a.app_name, hrs, mins, a.session_count, limit_str);
                }
            }
        }
        "focus" => {
            if let Some(app) = parts.get(1) {
                match usagetime::app_focused(app) {
                    Ok(()) => shell_println!("Tracking '{}' focus.", app),
                    Err(e) => shell_println!("Error: {:?}", e),
                }
            } else {
                shell_println!("Usage: usagetime focus <app>");
            }
        }
        "blur" => {
            if let Some(app) = parts.get(1) {
                match usagetime::app_blurred(app) {
                    Ok(ms) => shell_println!("'{}' blurred after {}ms.", app, ms),
                    Err(e) => shell_println!("Error: {:?}", e),
                }
            } else {
                shell_println!("Usage: usagetime blur <app>");
            }
        }
        "limit" => {
            let app = parts.get(1).copied();
            let mins = parts.get(2).and_then(|s| s.parse::<u64>().ok());
            if let (Some(app), Some(m)) = (app, mins) {
                match usagetime::set_limit(app, m * 60_000) {
                    Ok(()) => shell_println!("Limit set for '{}': {} min.", app, m),
                    Err(e) => shell_println!("Error: {:?}", e),
                }
            } else {
                shell_println!("Usage: usagetime limit <app> <minutes>");
            }
        }
        "unlimit" => {
            if let Some(app) = parts.get(1) {
                match usagetime::remove_limit(app) {
                    Ok(()) => shell_println!("Limit removed for '{}'.", app),
                    Err(e) => shell_println!("Error: {:?}", e),
                }
            } else {
                shell_println!("Usage: usagetime unlimit <app>");
            }
        }
        "category" | "cat" => {
            let app = parts.get(1).copied();
            let cat = parts.get(2).and_then(|s| parse_usage_category(s));
            if let (Some(app), Some(c)) = (app, cat) {
                match usagetime::set_category(app, c) {
                    Ok(()) => shell_println!("Category set for '{}': {}.", app, c.label()),
                    Err(e) => shell_println!("Error: {:?}", e),
                }
            } else {
                shell_println!("Usage: usagetime category <app> <productivity|communication|entertainment|social|utility|dev|other>");
            }
        }
        "reset" => {
            match usagetime::reset_usage() {
                Ok(()) => shell_println!("Usage data reset."),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "enable" => {
            match usagetime::set_tracking(true) {
                Ok(()) => shell_println!("Tracking enabled."),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "disable" => {
            match usagetime::set_tracking(false) {
                Ok(()) => shell_println!("Tracking disabled."),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "stats" => {
            let (apps, sessions, tracked_ms, limited, ops) = usagetime::stats();
            shell_println!("Apps: {}, Sessions: {}, Tracked: {}ms, Limited: {}, Ops: {}",
                apps, sessions, tracked_ms, limited, ops);
        }
        "test" => usagetime::self_test(),
        "init" => {
            usagetime::init_defaults();
            shell_println!("Usage time subsystem initialised.");
        }
        _ => {
            shell_println!("Usage: usagetime <subcommand>");
            shell_println!("  top [max]             Top apps by usage");
            shell_println!("  focus/blur <app>      Track focus/blur");
            shell_println!("  limit <app> <mins>    Set daily limit");
            shell_println!("  unlimit <app>         Remove limit");
            shell_println!("  category <app> <cat>  Set category");
            shell_println!("  reset                 Reset all data");
            shell_println!("  enable / disable      Toggle tracking");
            shell_println!("  stats / test / init");
        }
    }
}

fn parse_usage_category(s: &str) -> Option<crate::fs::usagetime::UsageCategory> {
    use crate::fs::usagetime::UsageCategory;
    match s.to_lowercase().as_str() {
        "productivity" | "prod" => Some(UsageCategory::Productivity),
        "communication" | "comm" => Some(UsageCategory::Communication),
        "entertainment" | "ent" => Some(UsageCategory::Entertainment),
        "social" => Some(UsageCategory::Social),
        "utility" | "util" => Some(UsageCategory::Utility),
        "development" | "dev" => Some(UsageCategory::Development),
        "other" => Some(UsageCategory::Other),
        _ => None,
    }
}

/// `voicecontrol` / `vctl` — voice commands for OS actions.
fn cmd_voicecontrol(args: &str) {
    use crate::fs::voicecontrol;
    use alloc::format;
    let parts: Vec<&str> = args.split_whitespace().collect();
    let sub = parts.first().copied().unwrap_or("");
    match sub {
        "show" | "status" => {
            let listening = voicecontrol::is_listening();
            let wake = voicecontrol::get_wake_word();
            shell_println!("Listening: {}", listening);
            shell_println!("Wake word: '{}'", wake);
            let (cmds, recognitions, executed, rejected, _) = voicecontrol::stats();
            shell_println!("Commands: {}, Recognized: {}, Executed: {}, Rejected: {}",
                cmds, recognitions, executed, rejected);
        }
        "enable" => {
            match voicecontrol::set_enabled(true) {
                Ok(()) => shell_println!("Voice control enabled."),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "disable" => {
            match voicecontrol::set_enabled(false) {
                Ok(()) => shell_println!("Voice control disabled."),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "listen" => {
            match voicecontrol::set_listening(true) {
                Ok(()) => shell_println!("Now listening..."),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "stop" => {
            match voicecontrol::set_listening(false) {
                Ok(()) => shell_println!("Stopped listening."),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "wake" => {
            if let Some(_word) = parts.get(1) {
                let phrase = parts[1..].join(" ");
                match voicecontrol::set_wake_word(&phrase) {
                    Ok(()) => shell_println!("Wake word set to '{}'.", phrase),
                    Err(e) => shell_println!("Error: {:?}", e),
                }
            } else {
                shell_println!("Wake word: '{}'", voicecontrol::get_wake_word());
            }
        }
        "list" => {
            let cmds = voicecontrol::list_commands();
            if cmds.is_empty() {
                shell_println!("No commands.");
            } else {
                for c in &cmds {
                    shell_println!("  [{}] '{}' → {} ({}, {}, uses={})",
                        c.id, c.phrase, c.action, c.category.label(),
                        if c.enabled { "on" } else { "off" }, c.use_count);
                }
            }
        }
        "add" => {
            let phrase = parts.get(1).copied();
            let action = parts.get(2).copied();
            if let (Some(p), Some(a)) = (phrase, action) {
                let phrase_full = if parts.len() > 3 { parts[1..parts.len()-1].join(" ") } else { String::from(p) };
                match voicecontrol::add_command(&phrase_full, voicecontrol::CommandCategory::Custom, a) {
                    Ok(id) => shell_println!("Command added: id={}", id),
                    Err(e) => shell_println!("Error: {:?}", e),
                }
            } else {
                shell_println!("Usage: voicecontrol add <phrase> <action>");
            }
        }
        "remove" | "rm" => {
            if let Some(id) = parts.get(1).and_then(|s| s.parse::<u32>().ok()) {
                match voicecontrol::remove_command(id) {
                    Ok(()) => shell_println!("Command {} removed.", id),
                    Err(e) => shell_println!("Error: {:?}", e),
                }
            } else {
                shell_println!("Usage: voicecontrol remove <id>");
            }
        }
        "recognize" | "rec" => {
            if parts.len() > 1 {
                let phrase = parts[1..].join(" ");
                match voicecontrol::recognize(&phrase, voicecontrol::Confidence::High) {
                    Ok(Some(action)) => shell_println!("Recognized → {}", action),
                    Ok(None) => shell_println!("Not recognized: '{}'", phrase),
                    Err(e) => shell_println!("Error: {:?}", e),
                }
            } else {
                shell_println!("Usage: voicecontrol recognize <phrase>");
            }
        }
        "history" => {
            let max = parts.get(1).and_then(|s| s.parse::<usize>().ok()).unwrap_or(10);
            let history = voicecontrol::get_history(max);
            if history.is_empty() {
                shell_println!("No recognition history.");
            } else {
                for r in &history {
                    let cmd = r.matched_command_id.map_or(
                        alloc::string::String::from("no match"),
                        |id| format!("cmd={}", id)
                    );
                    shell_println!("  '{}' ({}) — {}", r.phrase, r.confidence.label(), cmd);
                }
            }
        }
        "stats" => {
            let (cmds, recognitions, executed, rejected, ops) = voicecontrol::stats();
            shell_println!("Commands: {}, Recognitions: {}, Executed: {}, Rejected: {}, Ops: {}",
                cmds, recognitions, executed, rejected, ops);
        }
        "test" => voicecontrol::self_test(),
        "init" => {
            voicecontrol::init_defaults();
            shell_println!("Voice control subsystem initialised.");
        }
        _ => {
            shell_println!("Usage: voicecontrol <subcommand>");
            shell_println!("  show / status         Show state");
            shell_println!("  enable / disable      Toggle voice control");
            shell_println!("  listen / stop         Start/stop listening");
            shell_println!("  wake [word]           Get/set wake word");
            shell_println!("  list                  List all commands");
            shell_println!("  add <phrase> <action> Add command");
            shell_println!("  remove <id>           Remove command");
            shell_println!("  recognize <phrase>    Test recognition");
            shell_println!("  history [max]         Recognition history");
            shell_println!("  stats / test / init");
        }
    }
}

/// `devpair` / `dpair` — device pairing workflow.
fn cmd_devpair(args: &str) {
    use crate::fs::devpair;
    let parts: Vec<&str> = args.split_whitespace().collect();
    let sub = parts.first().copied().unwrap_or("");
    match sub {
        "list" | "show" => {
            let devices = devpair::list_devices();
            if devices.is_empty() {
                shell_println!("No devices.");
            } else {
                for d in &devices {
                    shell_println!("  [{}] {} ({}) — {} addr={} signal={}{}",
                        d.id, d.name, d.device_type.label(), d.state.label(),
                        d.address, d.signal_strength,
                        if d.trusted { " [trusted]" } else { "" });
                }
            }
        }
        "scan" => {
            match devpair::start_scan() {
                Ok(()) => shell_println!("Scanning for devices..."),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "stopscan" => {
            match devpair::stop_scan() {
                Ok(()) => shell_println!("Scan stopped."),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "discover" => {
            let name = parts.get(1).copied().unwrap_or("Device");
            let addr = parts.get(2).copied().unwrap_or("00:00:00:00:00:00");
            let dtype = parts.get(3).and_then(|s| parse_pair_device_type(s)).unwrap_or(devpair::PairDeviceType::Other);
            match devpair::discover(name, addr, dtype, -50) {
                Ok(id) => shell_println!("Device discovered: id={}", id),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "pair" => {
            if let Some(id) = parts.get(1).and_then(|s| s.parse::<u32>().ok()) {
                match devpair::pair(id) {
                    Ok(()) => shell_println!("Pairing device {}...", id),
                    Err(e) => shell_println!("Error: {:?}", e),
                }
            } else {
                shell_println!("Usage: devpair pair <id>");
            }
        }
        "confirm" => {
            if let Some(id) = parts.get(1).and_then(|s| s.parse::<u32>().ok()) {
                match devpair::confirm_pair(id) {
                    Ok(()) => shell_println!("Device {} paired successfully.", id),
                    Err(e) => shell_println!("Error: {:?}", e),
                }
            } else {
                shell_println!("Usage: devpair confirm <id>");
            }
        }
        "trust" => {
            if let Some(id) = parts.get(1).and_then(|s| s.parse::<u32>().ok()) {
                match devpair::trust(id, true) {
                    Ok(()) => shell_println!("Device {} trusted.", id),
                    Err(e) => shell_println!("Error: {:?}", e),
                }
            } else {
                shell_println!("Usage: devpair trust <id>");
            }
        }
        "untrust" => {
            if let Some(id) = parts.get(1).and_then(|s| s.parse::<u32>().ok()) {
                match devpair::trust(id, false) {
                    Ok(()) => shell_println!("Device {} untrusted.", id),
                    Err(e) => shell_println!("Error: {:?}", e),
                }
            } else {
                shell_println!("Usage: devpair untrust <id>");
            }
        }
        "disconnect" => {
            if let Some(id) = parts.get(1).and_then(|s| s.parse::<u32>().ok()) {
                match devpair::disconnect(id) {
                    Ok(()) => shell_println!("Device {} disconnected.", id),
                    Err(e) => shell_println!("Error: {:?}", e),
                }
            } else {
                shell_println!("Usage: devpair disconnect <id>");
            }
        }
        "forget" => {
            if let Some(id) = parts.get(1).and_then(|s| s.parse::<u32>().ok()) {
                match devpair::forget(id) {
                    Ok(()) => shell_println!("Device {} forgotten.", id),
                    Err(e) => shell_println!("Error: {:?}", e),
                }
            } else {
                shell_println!("Usage: devpair forget <id>");
            }
        }
        "paired" => {
            let paired = devpair::list_paired();
            if paired.is_empty() {
                shell_println!("No paired devices.");
            } else {
                for d in &paired {
                    shell_println!("  [{}] {} ({}){}", d.id, d.name,
                        d.device_type.label(), if d.trusted { " [trusted]" } else { "" });
                }
            }
        }
        "stats" => {
            let (devices, paired, trusted, total_paired, total_failed, ops) = devpair::stats();
            shell_println!("Devices: {}, Paired: {}, Trusted: {}, Total paired: {}, Failed: {}, Ops: {}",
                devices, paired, trusted, total_paired, total_failed, ops);
        }
        "test" => devpair::self_test(),
        "init" => {
            devpair::init_defaults();
            shell_println!("Device pairing subsystem initialised.");
        }
        _ => {
            shell_println!("Usage: devpair <subcommand>");
            shell_println!("  list / show           List all devices");
            shell_println!("  scan / stopscan       Start/stop scanning");
            shell_println!("  discover <n> <a> [t]  Simulate discovery");
            shell_println!("  pair <id>             Initiate pairing");
            shell_println!("  confirm <id>          Confirm pairing");
            shell_println!("  trust/untrust <id>    Trust management");
            shell_println!("  disconnect <id>       Disconnect");
            shell_println!("  forget <id>           Remove device");
            shell_println!("  paired                List paired devices");
            shell_println!("  stats / test / init");
        }
    }
}

fn parse_pair_device_type(s: &str) -> Option<crate::fs::devpair::PairDeviceType> {
    use crate::fs::devpair::PairDeviceType;
    match s.to_lowercase().as_str() {
        "headphones" | "hp" => Some(PairDeviceType::Headphones),
        "speaker" | "spk" => Some(PairDeviceType::Speaker),
        "keyboard" | "kb" => Some(PairDeviceType::Keyboard),
        "mouse" => Some(PairDeviceType::Mouse),
        "gamepad" | "gp" => Some(PairDeviceType::Gamepad),
        "phone" => Some(PairDeviceType::Phone),
        "computer" | "pc" => Some(PairDeviceType::Computer),
        "printer" | "prn" => Some(PairDeviceType::Printer),
        "display" | "mon" => Some(PairDeviceType::Display),
        "other" => Some(PairDeviceType::Other),
        _ => None,
    }
}

/// `notifgroup` / `ngroup` — notification grouping and bundling.
fn cmd_notifgroup(args: &str) {
    use crate::fs::notifgroup;
    let parts: Vec<&str> = args.split_whitespace().collect();
    let sub = parts.first().copied().unwrap_or("");
    match sub {
        "show" | "list" => {
            let groups = notifgroup::get_groups();
            if groups.is_empty() {
                shell_println!("No notification groups.");
            } else {
                let unread = notifgroup::unread_count();
                shell_println!("{} groups, {} unread", groups.len(), unread);
                for g in &groups {
                    let unread_in_group = g.notifications.iter().filter(|n| !n.read).count();
                    shell_println!("  [{}] {} — {} notifs ({} unread){}{}",
                        g.group_id, g.app_name, g.notifications.len(), unread_in_group,
                        if g.expanded { " [expanded]" } else { "" },
                        if g.muted { " [muted]" } else { "" });
                    if g.expanded {
                        for n in &g.notifications {
                            let read_mark = if n.read { "✓" } else { "•" };
                            shell_println!("    {} [{}] {} — {}", read_mark, n.priority.label(), n.title, n.body);
                        }
                    }
                }
            }
        }
        "add" => {
            let app = parts.get(1).copied().unwrap_or("app");
            let title = parts.get(2).copied().unwrap_or("Notification");
            let body = if parts.len() > 3 { parts[3..].join(" ") } else { alloc::string::String::new() };
            match notifgroup::add_notification(app, title, &body, notifgroup::NotifPriority::Normal) {
                Ok((gid, nid)) => shell_println!("Added: group={}, notif={}", gid, nid),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "read" => {
            if let Some(id) = parts.get(1).and_then(|s| s.parse::<u32>().ok()) {
                match notifgroup::mark_read(id) {
                    Ok(()) => shell_println!("Notification {} marked read.", id),
                    Err(e) => shell_println!("Error: {:?}", e),
                }
            } else {
                shell_println!("Usage: notifgroup read <notif_id>");
            }
        }
        "readgroup" | "rg" => {
            if let Some(id) = parts.get(1).and_then(|s| s.parse::<u32>().ok()) {
                match notifgroup::mark_group_read(id) {
                    Ok(()) => shell_println!("Group {} marked read.", id),
                    Err(e) => shell_println!("Error: {:?}", e),
                }
            } else {
                shell_println!("Usage: notifgroup readgroup <group_id>");
            }
        }
        "expand" => {
            if let Some(id) = parts.get(1).and_then(|s| s.parse::<u32>().ok()) {
                match notifgroup::set_expanded(id, true) {
                    Ok(()) => shell_println!("Group {} expanded.", id),
                    Err(e) => shell_println!("Error: {:?}", e),
                }
            } else {
                shell_println!("Usage: notifgroup expand <group_id>");
            }
        }
        "collapse" => {
            if let Some(id) = parts.get(1).and_then(|s| s.parse::<u32>().ok()) {
                match notifgroup::set_expanded(id, false) {
                    Ok(()) => shell_println!("Group {} collapsed.", id),
                    Err(e) => shell_println!("Error: {:?}", e),
                }
            } else {
                shell_println!("Usage: notifgroup collapse <group_id>");
            }
        }
        "mute" => {
            if let Some(id) = parts.get(1).and_then(|s| s.parse::<u32>().ok()) {
                match notifgroup::set_muted(id, true) {
                    Ok(()) => shell_println!("Group {} muted.", id),
                    Err(e) => shell_println!("Error: {:?}", e),
                }
            } else {
                shell_println!("Usage: notifgroup mute <group_id>");
            }
        }
        "unmute" => {
            if let Some(id) = parts.get(1).and_then(|s| s.parse::<u32>().ok()) {
                match notifgroup::set_muted(id, false) {
                    Ok(()) => shell_println!("Group {} unmuted.", id),
                    Err(e) => shell_println!("Error: {:?}", e),
                }
            } else {
                shell_println!("Usage: notifgroup unmute <group_id>");
            }
        }
        "dismiss" => {
            if let Some(id) = parts.get(1).and_then(|s| s.parse::<u32>().ok()) {
                match notifgroup::dismiss_group(id) {
                    Ok(()) => shell_println!("Group {} dismissed.", id),
                    Err(e) => shell_println!("Error: {:?}", e),
                }
            } else {
                shell_println!("Usage: notifgroup dismiss <group_id>");
            }
        }
        "clear" => {
            match notifgroup::dismiss_all() {
                Ok(()) => shell_println!("All notifications dismissed."),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "mode" => {
            if let Some(m) = parts.get(1).and_then(|s| parse_grouping_mode(s)) {
                match notifgroup::set_mode(m) {
                    Ok(()) => shell_println!("Grouping mode set to {}.", m.label()),
                    Err(e) => shell_println!("Error: {:?}", e),
                }
            } else {
                let current = notifgroup::get_mode();
                shell_println!("Current mode: {}", current.label());
                shell_println!("Usage: notifgroup mode <app|category|conversation|none>");
            }
        }
        "stats" => {
            let (groups, total, unread, dismissed, ops) = notifgroup::stats();
            shell_println!("Groups: {}, Total: {}, Unread: {}, Dismissed: {}, Ops: {}",
                groups, total, unread, dismissed, ops);
        }
        "test" => notifgroup::self_test(),
        "init" => {
            notifgroup::init_defaults();
            shell_println!("Notification grouping subsystem initialised.");
        }
        _ => {
            shell_println!("Usage: notifgroup <subcommand>");
            shell_println!("  show / list           Show groups");
            shell_println!("  add <app> <title> ... Add notification");
            shell_println!("  read <notif_id>       Mark read");
            shell_println!("  readgroup <group_id>  Mark group read");
            shell_println!("  expand/collapse <id>  Expand/collapse");
            shell_println!("  mute/unmute <id>      Mute/unmute");
            shell_println!("  dismiss <id>          Dismiss group");
            shell_println!("  clear                 Dismiss all");
            shell_println!("  mode [type]           Get/set grouping");
            shell_println!("  stats / test / init");
        }
    }
}

fn parse_grouping_mode(s: &str) -> Option<crate::fs::notifgroup::GroupingMode> {
    use crate::fs::notifgroup::GroupingMode;
    match s.to_lowercase().as_str() {
        "app" | "byapp" => Some(GroupingMode::ByApp),
        "category" | "bycat" => Some(GroupingMode::ByCategory),
        "conversation" | "conv" => Some(GroupingMode::ByConversation),
        "none" | "off" => Some(GroupingMode::None),
        _ => None,
    }
}

/// `playmedia` / `pmedia` — system-wide media playback controls.
fn cmd_playmedia(args: &str) {
    use crate::fs::playmedia;
    let parts: Vec<&str> = args.split_whitespace().collect();
    let sub = parts.first().copied().unwrap_or("");
    match sub {
        "now" | "show" => {
            if let Some(np) = playmedia::get_now_playing() {
                shell_println!("{} — {} — {}", np.artist, np.title, np.album);
                shell_println!("State: {} | App: {} ({})", np.state.label(), np.app_name, np.media_type.label());
                shell_println!("Shuffle: {} | Repeat: {} | Volume: {}%", np.shuffle, np.repeat.label(), np.volume_percent);
            } else {
                shell_println!("Nothing playing.");
            }
        }
        "play" | "pause" | "pp" => {
            match playmedia::play_pause() {
                Ok(state) => shell_println!("Playback: {}", state.label()),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "next" => {
            match playmedia::next_track() {
                Ok(()) => shell_println!("Next track."),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "prev" => {
            match playmedia::prev_track() {
                Ok(()) => shell_println!("Previous track."),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "shuffle" => {
            let on = parts.get(1).copied().unwrap_or("on") != "off";
            match playmedia::set_shuffle(on) {
                Ok(()) => shell_println!("Shuffle {}.", if on { "on" } else { "off" }),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "repeat" => {
            let mode = parts.get(1).and_then(|s| match s.to_lowercase().as_str() {
                "off" => Some(playmedia::RepeatMode::Off),
                "one" | "1" => Some(playmedia::RepeatMode::One),
                "all" => Some(playmedia::RepeatMode::All),
                _ => None,
            }).unwrap_or(playmedia::RepeatMode::Off);
            match playmedia::set_repeat(mode) {
                Ok(()) => shell_println!("Repeat: {}.", mode.label()),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "register" => {
            let app = parts.get(1).copied().unwrap_or("app");
            let mtype = parts.get(2).map(|s| match s.to_lowercase().as_str() {
                "music" => playmedia::MediaType::Music,
                "video" => playmedia::MediaType::Video,
                "podcast" => playmedia::MediaType::Podcast,
                "audiobook" => playmedia::MediaType::Audiobook,
                "stream" => playmedia::MediaType::Stream,
                _ => playmedia::MediaType::Other,
            }).unwrap_or(playmedia::MediaType::Music);
            match playmedia::register_session(app, mtype) {
                Ok(id) => shell_println!("Session registered: id={}", id),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "track" => {
            let id = parts.get(1).and_then(|s| s.parse::<u32>().ok());
            let title = parts.get(2).copied().unwrap_or("Track");
            let artist = parts.get(3).copied().unwrap_or("Artist");
            if let Some(id) = id {
                match playmedia::set_track(id, title, artist, "", 300000) {
                    Ok(()) => shell_println!("Track set for session {}.", id),
                    Err(e) => shell_println!("Error: {:?}", e),
                }
            } else {
                shell_println!("Usage: playmedia track <session_id> <title> [artist]");
            }
        }
        "sessions" => {
            let sessions = playmedia::list_sessions();
            if sessions.is_empty() {
                shell_println!("No media sessions.");
            } else {
                for s in &sessions {
                    shell_println!("  [{}] {} ({}) — {} '{}'", s.id, s.app_name,
                        s.media_type.label(), s.state.label(), s.title);
                }
            }
        }
        "stats" => {
            let (sessions, plays, tracks, ops) = playmedia::stats();
            shell_println!("Sessions: {}, Play cmds: {}, Track changes: {}, Ops: {}",
                sessions, plays, tracks, ops);
        }
        "test" => playmedia::self_test(),
        "init" => {
            playmedia::init_defaults();
            shell_println!("Media playback subsystem initialised.");
        }
        _ => {
            shell_println!("Usage: playmedia <subcommand>");
            shell_println!("  now / show            Now playing info");
            shell_println!("  play / pause / pp     Toggle playback");
            shell_println!("  next / prev           Track control");
            shell_println!("  shuffle [on|off]      Toggle shuffle");
            shell_println!("  repeat <off|one|all>  Set repeat mode");
            shell_println!("  register <app> [type] Register session");
            shell_println!("  track <id> <t> [a]    Set track info");
            shell_println!("  sessions              List sessions");
            shell_println!("  stats / test / init");
        }
    }
}

/// `kbmacro` / `macro` — keyboard macro recording and playback.
fn cmd_kbmacro(args: &str) {
    use crate::fs::kbmacro;
    let parts: Vec<&str> = args.split_whitespace().collect();
    let sub = parts.first().copied().unwrap_or("");
    match sub {
        "list" | "show" => {
            let macros = kbmacro::list_macros();
            if macros.is_empty() {
                shell_println!("No macros.");
            } else {
                for m in &macros {
                    let hk = m.hotkey.as_deref().unwrap_or("none");
                    shell_println!("  [{}] {} — {} events, hotkey={}, repeat={}, plays={} ({})",
                        m.id, m.name, m.events.len(), hk, m.repeat_count, m.play_count,
                        if m.enabled { "on" } else { "off" });
                }
            }
        }
        "record" => {
            let name = if parts.len() > 1 { parts[1..].join(" ") } else { alloc::string::String::from("Macro") };
            match kbmacro::start_recording(&name) {
                Ok(()) => shell_println!("Recording '{}'. Use 'kbmacro stop' to finish.", name),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "event" => {
            let etype = parts.get(1).copied().unwrap_or("");
            match etype {
                "type" => {
                    let text = if parts.len() > 2 { parts[2..].join(" ") } else { alloc::string::String::new() };
                    match kbmacro::record_event(kbmacro::MacroEvent::TypeText(text)) {
                        Ok(()) => shell_println!("TypeText event recorded."),
                        Err(e) => shell_println!("Error: {:?}", e),
                    }
                }
                "delay" => {
                    let ms = parts.get(2).and_then(|s| s.parse::<u32>().ok()).unwrap_or(100);
                    match kbmacro::record_event(kbmacro::MacroEvent::Delay(ms)) {
                        Ok(()) => shell_println!("Delay {}ms recorded.", ms),
                        Err(e) => shell_println!("Error: {:?}", e),
                    }
                }
                "key" => {
                    let code = parts.get(2).and_then(|s| s.parse::<u32>().ok()).unwrap_or(0);
                    let _ = kbmacro::record_event(kbmacro::MacroEvent::KeyDown(code));
                    match kbmacro::record_event(kbmacro::MacroEvent::KeyUp(code)) {
                        Ok(()) => shell_println!("Key {} recorded.", code),
                        Err(e) => shell_println!("Error: {:?}", e),
                    }
                }
                _ => shell_println!("Usage: kbmacro event <type|delay|key> [args]"),
            }
        }
        "stop" => {
            match kbmacro::stop_recording() {
                Ok(id) => shell_println!("Macro saved: id={}", id),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "cancel" => {
            match kbmacro::cancel_recording() {
                Ok(()) => shell_println!("Recording cancelled."),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "play" | "run" => {
            if let Some(id) = parts.get(1).and_then(|s| s.parse::<u32>().ok()) {
                match kbmacro::play(id) {
                    Ok(count) => shell_println!("Played macro {}: {} events.", id, count),
                    Err(e) => shell_println!("Error: {:?}", e),
                }
            } else {
                shell_println!("Usage: kbmacro play <id>");
            }
        }
        "hotkey" => {
            let id = parts.get(1).and_then(|s| s.parse::<u32>().ok());
            let key = parts.get(2).copied();
            if let (Some(id), Some(k)) = (id, key) {
                match kbmacro::set_hotkey(id, k) {
                    Ok(()) => shell_println!("Hotkey set for macro {}: {}", id, k),
                    Err(e) => shell_println!("Error: {:?}", e),
                }
            } else {
                shell_println!("Usage: kbmacro hotkey <id> <key_combo>");
            }
        }
        "repeat" => {
            let id = parts.get(1).and_then(|s| s.parse::<u32>().ok());
            let count = parts.get(2).and_then(|s| s.parse::<u32>().ok());
            if let (Some(id), Some(c)) = (id, count) {
                match kbmacro::set_repeat(id, c) {
                    Ok(()) => shell_println!("Repeat count for macro {}: {}x", id, c),
                    Err(e) => shell_println!("Error: {:?}", e),
                }
            } else {
                shell_println!("Usage: kbmacro repeat <id> <count>");
            }
        }
        "enable" => {
            if let Some(id) = parts.get(1).and_then(|s| s.parse::<u32>().ok()) {
                match kbmacro::set_enabled(id, true) {
                    Ok(()) => shell_println!("Macro {} enabled.", id),
                    Err(e) => shell_println!("Error: {:?}", e),
                }
            }
        }
        "disable" => {
            if let Some(id) = parts.get(1).and_then(|s| s.parse::<u32>().ok()) {
                match kbmacro::set_enabled(id, false) {
                    Ok(()) => shell_println!("Macro {} disabled.", id),
                    Err(e) => shell_println!("Error: {:?}", e),
                }
            }
        }
        "delete" | "rm" => {
            if let Some(id) = parts.get(1).and_then(|s| s.parse::<u32>().ok()) {
                match kbmacro::delete_macro(id) {
                    Ok(()) => shell_println!("Macro {} deleted.", id),
                    Err(e) => shell_println!("Error: {:?}", e),
                }
            } else {
                shell_println!("Usage: kbmacro delete <id>");
            }
        }
        "stats" => {
            let (macros, plays, recorded, ops) = kbmacro::stats();
            shell_println!("Macros: {}, Plays: {}, Recorded: {}, Ops: {}",
                macros, plays, recorded, ops);
        }
        "test" => kbmacro::self_test(),
        "init" => {
            kbmacro::init_defaults();
            shell_println!("Keyboard macro subsystem initialised.");
        }
        _ => {
            shell_println!("Usage: kbmacro <subcommand>");
            shell_println!("  list / show           List macros");
            shell_println!("  record [name]         Start recording");
            shell_println!("  event <type|delay|key> Record event");
            shell_println!("  stop                  Stop and save");
            shell_println!("  cancel                Cancel recording");
            shell_println!("  play <id>             Play macro");
            shell_println!("  hotkey <id> <key>     Set hotkey");
            shell_println!("  repeat <id> <count>   Set repeat count");
            shell_println!("  enable/disable <id>   Toggle macro");
            shell_println!("  delete <id>           Delete macro");
            shell_println!("  stats / test / init");
        }
    }
}

/// `sysresource` / `sres` — system resource monitoring dashboard.
fn cmd_sysresource(args: &str) {
    use crate::fs::sysresource;
    let parts: Vec<&str> = args.split_whitespace().collect();
    let sub = parts.first().copied().unwrap_or("");
    match sub {
        "show" | "current" => {
            if let Some(snap) = sysresource::get_current() {
                shell_println!("CPU: {}%  |  GPU: {}%", snap.cpu_percent, snap.gpu_percent);
                shell_println!("Memory: {} / {} KB", snap.memory_used_kb, snap.memory_total_kb);
                shell_println!("Swap: {} / {} KB", snap.swap_used_kb, snap.swap_total_kb);
                shell_println!("Disk I/O: {} KB/s read, {} KB/s write", snap.disk_read_kb_s, snap.disk_write_kb_s);
                shell_println!("Net I/O: {} KB/s rx, {} KB/s tx", snap.net_rx_kb_s, snap.net_tx_kb_s);
                shell_println!("Processes: {}, Threads: {}", snap.process_count, snap.thread_count);
            } else {
                shell_println!("No samples yet. Run 'sysresource sample' first.");
            }
        }
        "sample" => {
            let cpu = parts.get(1).and_then(|s| s.parse::<u32>().ok()).unwrap_or(25);
            let mem_used = parts.get(2).and_then(|s| s.parse::<u64>().ok()).unwrap_or(4000000);
            let snap = sysresource::ResourceSnapshot {
                timestamp_ns: crate::hpet::elapsed_ns(),
                cpu_percent: cpu, memory_used_kb: mem_used, memory_total_kb: 8000000,
                swap_used_kb: 0, swap_total_kb: 2000000,
                disk_read_kb_s: 500, disk_write_kb_s: 200,
                net_rx_kb_s: 100, net_tx_kb_s: 50,
                gpu_percent: 15, gpu_memory_used_kb: 300000,
                process_count: 100, thread_count: 400,
            };
            match sysresource::sample(snap) {
                Ok(alerts) => {
                    shell_println!("Sample recorded (CPU={}%).", cpu);
                    for a in &alerts {
                        shell_println!("  ALERT: {} threshold exceeded!", a.label());
                    }
                }
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "alerts" => {
            let alerts = sysresource::get_alerts();
            for a in &alerts {
                shell_println!("  {} — threshold={}% enabled={} triggered={} count={}",
                    a.resource.label(), a.threshold_percent, a.alert_enabled,
                    a.triggered, a.trigger_count);
            }
        }
        "setalert" => {
            let res = parts.get(1).and_then(|s| match s.to_lowercase().as_str() {
                "cpu" => Some(sysresource::ResourceType::Cpu),
                "memory" | "mem" => Some(sysresource::ResourceType::Memory),
                "swap" => Some(sysresource::ResourceType::Swap),
                "disk" => Some(sysresource::ResourceType::Disk),
                "network" | "net" => Some(sysresource::ResourceType::Network),
                "gpu" => Some(sysresource::ResourceType::Gpu),
                _ => None,
            });
            let threshold = parts.get(2).and_then(|s| s.parse::<u32>().ok());
            if let (Some(r), Some(t)) = (res, threshold) {
                match sysresource::set_alert(r, t, true) {
                    Ok(()) => shell_println!("Alert set: {} at {}%.", r.label(), t),
                    Err(e) => shell_println!("Error: {:?}", e),
                }
            } else {
                shell_println!("Usage: sysresource setalert <cpu|memory|swap|disk|network|gpu> <threshold%>");
            }
        }
        "avg" => {
            let n = parts.get(1).and_then(|s| s.parse::<usize>().ok()).unwrap_or(10);
            let avg = sysresource::avg_cpu(n);
            shell_println!("Average CPU (last {} samples): {}%", n, avg);
        }
        "history" => {
            let max = parts.get(1).and_then(|s| s.parse::<usize>().ok()).unwrap_or(10);
            let hist = sysresource::get_history(max);
            if hist.is_empty() {
                shell_println!("No history.");
            } else {
                for s in &hist {
                    shell_println!("  CPU={}% MEM={}KB GPU={}%", s.cpu_percent, s.memory_used_kb, s.gpu_percent);
                }
            }
        }
        "clear" => {
            match sysresource::clear_history() {
                Ok(()) => shell_println!("History cleared."),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "stats" => {
            let (samples, hist_size, alerts, total_alerts, ops) = sysresource::stats();
            shell_println!("Samples: {}, History: {}, Alerts: {}, Triggered: {}, Ops: {}",
                samples, hist_size, alerts, total_alerts, ops);
        }
        "test" => sysresource::self_test(),
        "init" => {
            sysresource::init_defaults();
            shell_println!("System resource monitoring initialised.");
        }
        _ => {
            shell_println!("Usage: sysresource <subcommand>");
            shell_println!("  show / current        Show latest snapshot");
            shell_println!("  sample [cpu] [mem]    Record sample");
            shell_println!("  alerts                List alert thresholds");
            shell_println!("  setalert <res> <%>    Set alert threshold");
            shell_println!("  avg [n]               Average CPU");
            shell_println!("  history [max]         Show history");
            shell_println!("  clear                 Clear history");
            shell_println!("  stats / test / init");
        }
    }
}

/// `faceunlock` / `face` — facial recognition authentication.
fn cmd_faceunlock(args: &str) {
    use crate::fs::faceunlock;
    let parts: Vec<&str> = args.split_whitespace().collect();
    let sub = parts.first().copied().unwrap_or("");
    match sub {
        "show" | "status" => {
            let enabled = faceunlock::is_enabled();
            let security = faceunlock::get_security();
            shell_println!("Face unlock: {}", if enabled { "ON" } else { "OFF" });
            shell_println!("Security: {}", security.label());
            let enrollments = faceunlock::list_enrollments();
            shell_println!("Enrolled users: {}", enrollments.len());
            for e in &enrollments {
                shell_println!("  User {} ({}) — verified={}, failed={}, quality={}%",
                    e.user_id, e.user_name, e.verify_count, e.fail_count, e.model_quality);
            }
        }
        "enable" => {
            match faceunlock::set_enabled(true) {
                Ok(()) => shell_println!("Face unlock enabled."),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "disable" => {
            match faceunlock::set_enabled(false) {
                Ok(()) => shell_println!("Face unlock disabled."),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "enroll" => {
            let uid = parts.get(1).and_then(|s| s.parse::<u32>().ok());
            let name = parts.get(2).copied();
            if let (Some(id), Some(n)) = (uid, name) {
                match faceunlock::enroll(id, n) {
                    Ok(()) => shell_println!("User {} ({}) enrolled.", id, n),
                    Err(e) => shell_println!("Error: {:?}", e),
                }
            } else {
                shell_println!("Usage: faceunlock enroll <user_id> <name>");
            }
        }
        "unenroll" => {
            if let Some(id) = parts.get(1).and_then(|s| s.parse::<u32>().ok()) {
                match faceunlock::unenroll(id) {
                    Ok(()) => shell_println!("User {} unenrolled.", id),
                    Err(e) => shell_println!("Error: {:?}", e),
                }
            } else {
                shell_println!("Usage: faceunlock unenroll <user_id>");
            }
        }
        "verify" => {
            let uid = parts.get(1).and_then(|s| s.parse::<u32>().ok()).unwrap_or(1);
            let live = parts.get(2).copied().unwrap_or("true") != "false";
            match faceunlock::verify(uid, live) {
                Ok(result) => shell_println!("Verify result: {}", result.label()),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "security" => {
            if let Some(level) = parts.get(1).and_then(|s| match s.to_lowercase().as_str() {
                "low" => Some(faceunlock::SecurityLevel::Low),
                "standard" | "std" => Some(faceunlock::SecurityLevel::Standard),
                "high" => Some(faceunlock::SecurityLevel::High),
                "maximum" | "max" => Some(faceunlock::SecurityLevel::Maximum),
                _ => None,
            }) {
                match faceunlock::set_security(level) {
                    Ok(()) => shell_println!("Security set to {}.", level.label()),
                    Err(e) => shell_println!("Error: {:?}", e),
                }
            } else {
                shell_println!("Current: {}", faceunlock::get_security().label());
                shell_println!("Usage: faceunlock security <low|standard|high|maximum>");
            }
        }
        "liveness" => {
            let on = parts.get(1).copied().unwrap_or("on") != "off";
            match faceunlock::set_liveness(on) {
                Ok(()) => shell_println!("Liveness detection {}.", if on { "enabled" } else { "disabled" }),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "stats" => {
            let (enrollments, verifications, matches, rejections, ops) = faceunlock::stats();
            shell_println!("Enrolled: {}, Verifications: {}, Matches: {}, Rejections: {}, Ops: {}",
                enrollments, verifications, matches, rejections, ops);
        }
        "test" => faceunlock::self_test(),
        "init" => {
            faceunlock::init_defaults();
            shell_println!("Face unlock subsystem initialised.");
        }
        _ => {
            shell_println!("Usage: faceunlock <subcommand>");
            shell_println!("  show / status         Show status");
            shell_println!("  enable / disable      Toggle face unlock");
            shell_println!("  enroll <uid> <name>   Enroll face");
            shell_println!("  unenroll <uid>        Remove enrollment");
            shell_println!("  verify [uid] [live]   Test verification");
            shell_println!("  security <level>      Set security level");
            shell_println!("  liveness [on|off]     Toggle liveness check");
            shell_println!("  stats / test / init");
        }
    }
}

/// `usbpolicy` / `usbpol` — USB device access policies.
fn cmd_usbpolicy(args: &str) {
    use crate::fs::usbpolicy;
    use alloc::format;
    use alloc::string::String;
    let parts: Vec<&str> = args.split_whitespace().collect();
    let sub = parts.first().copied().unwrap_or("");
    match sub {
        "check" => {
            // check <vid> <pid> <class> <name>
            if parts.len() < 5 {
                shell_println!("Usage: usbpolicy check <vid_hex> <pid_hex> <class> <name>");
                return;
            }
            let vid = u16::from_str_radix(parts[1].trim_start_matches("0x"), 16).unwrap_or(0);
            let pid = u16::from_str_radix(parts[2].trim_start_matches("0x"), 16).unwrap_or(0);
            let class = parse_usb_class(parts[3]);
            let name = parts[4..].join(" ");
            match usbpolicy::check_device(vid, pid, class, &name) {
                Ok(d) => shell_println!("Decision for '{}' (VID={:#06X} PID={:#06X}): {}", name, vid, pid, d.label()),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "add" => {
            // add <name> <decision> [class=<class>] [vid=<hex>] [pid=<hex>]
            if parts.len() < 3 {
                shell_println!("Usage: usbpolicy add <name> <decision> [class=<class>] [vid=<hex>] [pid=<hex>]");
                return;
            }
            let name = parts[1];
            let decision = parse_usb_decision(parts[2]);
            let mut class = None;
            let mut vid = None;
            let mut pid = None;
            for p in &parts[3..] {
                if let Some(v) = p.strip_prefix("class=") { class = Some(parse_usb_class(v)); }
                if let Some(v) = p.strip_prefix("vid=") { vid = u16::from_str_radix(v.trim_start_matches("0x"), 16).ok(); }
                if let Some(v) = p.strip_prefix("pid=") { pid = u16::from_str_radix(v.trim_start_matches("0x"), 16).ok(); }
            }
            match usbpolicy::add_rule(name, vid, pid, class, decision) {
                Ok(id) => shell_println!("Added rule #{}: {} → {}", id, name, decision.label()),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "remove" => {
            if let Some(id_s) = parts.get(1) {
                if let Ok(id) = id_s.parse::<u32>() {
                    match usbpolicy::remove_rule(id) {
                        Ok(()) => shell_println!("Removed rule #{}", id),
                        Err(e) => shell_println!("Error: {:?}", e),
                    }
                } else {
                    shell_println!("Invalid rule ID");
                }
            } else {
                shell_println!("Usage: usbpolicy remove <rule_id>");
            }
        }
        "default" => {
            if let Some(d) = parts.get(1) {
                let decision = parse_usb_decision(d);
                match usbpolicy::set_default(decision) {
                    Ok(()) => shell_println!("Default decision: {}", decision.label()),
                    Err(e) => shell_println!("Error: {:?}", e),
                }
            } else {
                shell_println!("Usage: usbpolicy default <allow|deny|ask|readonly>");
            }
        }
        "block" => {
            if let Some(v) = parts.get(1) {
                let block = *v == "on" || *v == "true" || *v == "yes";
                match usbpolicy::set_block_unknown(block) {
                    Ok(()) => shell_println!("Block unknown: {}", if block { "ON" } else { "OFF" }),
                    Err(e) => shell_println!("Error: {:?}", e),
                }
            } else {
                shell_println!("Usage: usbpolicy block <on|off>");
            }
        }
        "list" => {
            let rules = usbpolicy::list_rules();
            if rules.is_empty() {
                shell_println!("No policy rules");
            } else {
                for r in &rules {
                    let en = if r.enabled { "ON" } else { "OFF" };
                    let class_s = r.class.map_or(String::from("any"), |c| String::from(c.label()));
                    let vid_s = r.vendor_id.map_or(String::from("any"), |v| format!("{:#06X}", v));
                    shell_println!("  #{}: {} [{}] → {} (VID={} class={} hits={})", r.id, r.name, en, r.decision.label(), vid_s, class_s, r.hit_count);
                }
            }
        }
        "log" => {
            let max = parts.get(1).and_then(|s| s.parse::<usize>().ok()).unwrap_or(10);
            let log = usbpolicy::get_log(max);
            if log.is_empty() {
                shell_println!("No events logged");
            } else {
                for e in &log {
                    shell_println!("  {} (VID={:#06X} PID={:#06X} {}) → {}{}", e.device_name, e.vendor_id, e.product_id, e.class.label(), e.decision.label(), e.rule_id.map_or(String::new(), |id| format!(" rule#{}", id)));
                }
            }
        }
        "stats" => {
            let (rules, log_size, allowed, denied, ops) = usbpolicy::stats();
            shell_println!("USB Policy: {} rules, {} log entries", rules, log_size);
            shell_println!("  Allowed: {} | Denied: {} | Ops: {}", allowed, denied, ops);
        }
        "test" => {
            usbpolicy::self_test();
            shell_println!("usbpolicy self-test complete");
        }
        "init" => {
            usbpolicy::init_defaults();
            shell_println!("usbpolicy initialised");
        }
        _ => {
            shell_println!("usbpolicy — USB device access policies");
            shell_println!("  check <vid> <pid> <class> <name>  Check device");
            shell_println!("  add <name> <decision> [opts]      Add rule");
            shell_println!("  remove <id>                       Remove rule");
            shell_println!("  default <decision>                Set default");
            shell_println!("  block <on|off>                    Block unknown");
            shell_println!("  list                              List rules");
            shell_println!("  log [n]                           Show event log");
            shell_println!("  stats / test / init");
        }
    }
}

fn parse_usb_class(s: &str) -> crate::fs::usbpolicy::UsbClass {
    use crate::fs::usbpolicy::UsbClass;
    match s.to_lowercase().as_str() {
        "storage" | "stor" => UsbClass::Storage,
        "hid" | "humaninterface" => UsbClass::HumanInterface,
        "audio" => UsbClass::Audio,
        "video" => UsbClass::Video,
        "printer" => UsbClass::Printer,
        "network" | "net" => UsbClass::Network,
        "wireless" => UsbClass::Wireless,
        "smartcard" => UsbClass::SmartCard,
        "hub" => UsbClass::Hub,
        _ => UsbClass::Other,
    }
}

fn parse_usb_decision(s: &str) -> crate::fs::usbpolicy::Decision {
    use crate::fs::usbpolicy::Decision;
    match s.to_lowercase().as_str() {
        "allow" => Decision::Allow,
        "deny" | "block" => Decision::Deny,
        "ask" | "askuser" => Decision::AskUser,
        "readonly" | "ro" => Decision::ReadOnly,
        _ => Decision::AskUser,
    }
}

/// `applaunch` / `alaunch` — search-based application launcher.
fn cmd_applaunch(args: &str) {
    use crate::fs::applaunch;
    let parts: Vec<&str> = args.split_whitespace().collect();
    let sub = parts.first().copied().unwrap_or("");
    match sub {
        "search" | "find" => {
            if parts.len() < 2 {
                shell_println!("Usage: applaunch search <query>");
                return;
            }
            let query = parts[1..].join(" ");
            let max = 10;
            let results = applaunch::search(&query, max);
            if results.is_empty() {
                shell_println!("No results for '{}'", query);
            } else {
                for r in &results {
                    shell_println!("  #{}: {} [{}] score={} launches={}", r.id, r.name, r.result_type.label(), r.score, r.launch_count);
                }
            }
        }
        "launch" => {
            if let Some(id_s) = parts.get(1) {
                if let Ok(id) = id_s.parse::<u32>() {
                    match applaunch::record_launch(id) {
                        Ok(action) => shell_println!("Launched #{}: {}", id, action),
                        Err(e) => shell_println!("Error: {:?}", e),
                    }
                } else {
                    shell_println!("Invalid item ID");
                }
            } else {
                shell_println!("Usage: applaunch launch <id>");
            }
        }
        "register" | "add" => {
            if parts.len() < 3 {
                shell_println!("Usage: applaunch register <name> <type> [action] [icon]");
                return;
            }
            let name = parts[1];
            let rtype = parse_result_type(parts[2]);
            let action = if parts.len() > 3 { parts[3] } else { "launch:default" };
            let icon = if parts.len() > 4 { parts[4] } else { "app" };
            match applaunch::register(name, alloc::vec![], rtype, action, icon) {
                Ok(id) => shell_println!("Registered '{}' as #{} [{}]", name, id, rtype.label()),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "unregister" | "remove" => {
            if let Some(id_s) = parts.get(1) {
                if let Ok(id) = id_s.parse::<u32>() {
                    match applaunch::unregister(id) {
                        Ok(()) => shell_println!("Unregistered #{}", id),
                        Err(e) => shell_println!("Error: {:?}", e),
                    }
                } else {
                    shell_println!("Invalid item ID");
                }
            } else {
                shell_println!("Usage: applaunch unregister <id>");
            }
        }
        "list" => {
            let items = applaunch::list_items();
            if items.is_empty() {
                shell_println!("No registered items");
            } else {
                for i in &items {
                    shell_println!("  #{}: {} [{}] → {} (launches={})", i.id, i.name, i.result_type.label(), i.action, i.launch_count);
                }
            }
        }
        "top" => {
            let max = parts.get(1).and_then(|s| s.parse::<usize>().ok()).unwrap_or(5);
            let top = applaunch::top_launched(max);
            if top.is_empty() {
                shell_println!("No launch history");
            } else {
                for (i, item) in top.iter().enumerate() {
                    shell_println!("  {}. {} — {} launches", i + 1, item.name, item.launch_count);
                }
            }
        }
        "stats" => {
            let (items, searches, launches, ops) = applaunch::stats();
            shell_println!("App Launcher: {} items, {} searches, {} launches, {} ops", items, searches, launches, ops);
        }
        "test" => {
            applaunch::self_test();
            shell_println!("applaunch self-test complete");
        }
        "init" => {
            applaunch::init_defaults();
            shell_println!("applaunch initialised");
        }
        _ => {
            shell_println!("applaunch — search-based application launcher");
            shell_println!("  search <query>           Search for items");
            shell_println!("  launch <id>              Launch and record");
            shell_println!("  register <name> <type>   Register item");
            shell_println!("  unregister <id>          Remove item");
            shell_println!("  list                     List all items");
            shell_println!("  top [n]                  Top launched items");
            shell_println!("  stats / test / init");
        }
    }
}

fn parse_result_type(s: &str) -> crate::fs::applaunch::ResultType {
    use crate::fs::applaunch::ResultType;
    match s.to_lowercase().as_str() {
        "app" | "application" => ResultType::Application,
        "file" => ResultType::File,
        "setting" | "settings" => ResultType::Setting,
        "command" | "cmd" => ResultType::Command,
        "calc" | "calculation" => ResultType::Calculation,
        "web" | "websearch" => ResultType::WebSearch,
        "bookmark" | "bm" => ResultType::Bookmark,
        _ => ResultType::Application,
    }
}

/// `sysprofiler` / `sprof` — detailed hardware/software inventory.
fn cmd_sysprofiler(args: &str) {
    use crate::fs::sysprofiler;
    let parts: Vec<&str> = args.split_whitespace().collect();
    let sub = parts.first().copied().unwrap_or("");
    match sub {
        "section" | "get" => {
            if let Some(name) = parts.get(1) {
                let section = parse_profiler_section(name);
                match sysprofiler::get_section(section) {
                    Some(data) => {
                        shell_println!("[{}]", data.section.label());
                        for e in &data.entries {
                            shell_println!("  {}: {}", e.key, e.value);
                        }
                    }
                    None => shell_println!("Section '{}' not found", name),
                }
            } else {
                shell_println!("Usage: sysprofiler section <cpu|memory|storage|...>");
            }
        }
        "all" => {
            let sections = sysprofiler::get_all();
            if sections.is_empty() {
                shell_println!("No profiler data");
            } else {
                for s in &sections {
                    shell_println!("[{}]", s.section.label());
                    for e in &s.entries {
                        shell_println!("  {}: {}", e.key, e.value);
                    }
                }
            }
        }
        "summary" => {
            let summary = sysprofiler::get_summary();
            shell_println!("{}", summary);
        }
        "set" => {
            // set <section> <key> <value>
            if parts.len() < 4 {
                shell_println!("Usage: sysprofiler set <section> <key> <value...>");
                return;
            }
            let section = parse_profiler_section(parts[1]);
            let key = parts[2];
            let value = parts[3..].join(" ");
            match sysprofiler::set_entry(section, key, &value) {
                Ok(()) => shell_println!("Set [{}] {} = {}", section.label(), key, value),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "refresh" => {
            if let Some(name) = parts.get(1) {
                let section = parse_profiler_section(name);
                match sysprofiler::refresh_section(section) {
                    Ok(()) => shell_println!("Refreshed {}", section.label()),
                    Err(e) => shell_println!("Error: {:?}", e),
                }
            } else {
                shell_println!("Usage: sysprofiler refresh <section>");
            }
        }
        "stats" => {
            let (sections, queries, refreshes, ops) = sysprofiler::stats();
            shell_println!("System Profiler: {} sections, {} queries, {} refreshes, {} ops", sections, queries, refreshes, ops);
        }
        "test" => {
            sysprofiler::self_test();
            shell_println!("sysprofiler self-test complete");
        }
        "init" => {
            sysprofiler::init_defaults();
            shell_println!("sysprofiler initialised");
        }
        _ => {
            shell_println!("sysprofiler — detailed hardware/software inventory");
            shell_println!("  section <name>               Show section");
            shell_println!("  all                          Show all sections");
            shell_println!("  summary                      Text summary");
            shell_println!("  set <section> <key> <value>  Set entry");
            shell_println!("  refresh <section>            Refresh section");
            shell_println!("  stats / test / init");
        }
    }
}

fn parse_profiler_section(s: &str) -> crate::fs::sysprofiler::Section {
    use crate::fs::sysprofiler::Section;
    match s.to_lowercase().as_str() {
        "cpu" | "processor" => Section::Cpu,
        "memory" | "mem" | "ram" => Section::Memory,
        "storage" | "disk" => Section::Storage,
        "graphics" | "gpu" => Section::Graphics,
        "network" | "net" => Section::Network,
        "audio" | "sound" => Section::Audio,
        "usb" => Section::Usb,
        "firmware" | "bios" | "uefi" => Section::Firmware,
        "software" | "sw" => Section::Software,
        "display" | "screen" => Section::Display,
        _ => Section::Cpu,
    }
}

/// `clipsync` / `clsync` — cross-device clipboard sync.
fn cmd_clipsync(args: &str) {
    use crate::fs::clipsync;
    let parts: Vec<&str> = args.split_whitespace().collect();
    let sub = parts.first().copied().unwrap_or("");
    match sub {
        "enable" | "on" => {
            match clipsync::set_enabled(true) {
                Ok(()) => shell_println!("Clipboard sync enabled"),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "disable" | "off" => {
            match clipsync::set_enabled(false) {
                Ok(()) => shell_println!("Clipboard sync disabled"),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "status" => {
            let enabled = clipsync::is_enabled();
            shell_println!("Clipboard sync: {}", if enabled { "ENABLED" } else { "DISABLED" });
        }
        "device" | "add" => {
            if parts.len() < 3 {
                shell_println!("Usage: clipsync device <name> <send|receive|bidirectional>");
                return;
            }
            let name = parts[1];
            let dir = parse_sync_direction(parts[2]);
            match clipsync::add_device(name, dir) {
                Ok(id) => shell_println!("Added device #{}: {} ({})", id, name, dir.label()),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "remove" => {
            if let Some(id_s) = parts.get(1) {
                if let Ok(id) = id_s.parse::<u32>() {
                    match clipsync::remove_device(id) {
                        Ok(()) => shell_println!("Removed device #{}", id),
                        Err(e) => shell_println!("Error: {:?}", e),
                    }
                } else {
                    shell_println!("Invalid device ID");
                }
            } else {
                shell_println!("Usage: clipsync remove <device_id>");
            }
        }
        "copy" => {
            // copy <type> <preview> <size>
            if parts.len() < 4 {
                shell_println!("Usage: clipsync copy <type> <size> <preview...>");
                return;
            }
            let ctype = parse_sync_content_type(parts[1]);
            let size = parts[2].parse::<u64>().unwrap_or(0);
            let preview = parts[3..].join(" ");
            match clipsync::on_copy(ctype, &preview, size) {
                Ok(id) => shell_println!("Queued entry #{} ({}, {} bytes)", id, ctype.label(), size),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "sync" => {
            if let Some(id_s) = parts.get(1) {
                if let Ok(id) = id_s.parse::<u32>() {
                    match clipsync::sync_to_device(id) {
                        Ok(count) => shell_println!("Synced {} entries to device #{}", count, id),
                        Err(e) => shell_println!("Error: {:?}", e),
                    }
                } else {
                    shell_println!("Invalid device ID");
                }
            } else {
                shell_println!("Usage: clipsync sync <device_id>");
            }
        }
        "devices" | "list" => {
            let devices = clipsync::list_devices();
            if devices.is_empty() {
                shell_println!("No sync devices");
            } else {
                for d in &devices {
                    let en = if d.enabled { "ON" } else { "OFF" };
                    shell_println!("  #{}: {} [{}] {} — sent={} recv={}", d.id, d.name, en, d.direction.label(), d.items_sent, d.items_received);
                }
            }
        }
        "queue" => {
            let max = parts.get(1).and_then(|s| s.parse::<usize>().ok()).unwrap_or(10);
            let queue = clipsync::get_queue(max);
            if queue.is_empty() {
                shell_println!("Sync queue empty");
            } else {
                for e in &queue {
                    let synced = if e.synced { "✓" } else { "…" };
                    shell_println!("  #{}: [{}] {} {} ({} bytes)", e.id, e.content_type.label(), synced, e.preview, e.size_bytes);
                }
            }
        }
        "maxsize" => {
            if let Some(s) = parts.get(1) {
                if let Ok(bytes) = s.parse::<u64>() {
                    match clipsync::set_max_size(bytes) {
                        Ok(()) => shell_println!("Max sync size: {} bytes", bytes),
                        Err(e) => shell_println!("Error: {:?}", e),
                    }
                } else {
                    shell_println!("Invalid size");
                }
            } else {
                shell_println!("Usage: clipsync maxsize <bytes>");
            }
        }
        "allow" | "deny" => {
            if let Some(t) = parts.get(1) {
                let ctype = parse_sync_content_type(t);
                let allowed = sub == "allow";
                match clipsync::set_type_allowed(ctype, allowed) {
                    Ok(()) => shell_println!("{} {} sync: {}", ctype.label(), if allowed { "allowed" } else { "denied" }, if allowed { "ON" } else { "OFF" }),
                    Err(e) => shell_println!("Error: {:?}", e),
                }
            } else {
                shell_println!("Usage: clipsync allow|deny <text|image|file|richtext|url>");
            }
        }
        "stats" => {
            let (devices, sent, received, bytes, ops) = clipsync::stats();
            shell_println!("Clipboard Sync: {} devices", devices);
            shell_println!("  Sent: {} | Received: {} | Bytes: {} | Ops: {}", sent, received, bytes, ops);
        }
        "test" => {
            clipsync::self_test();
            shell_println!("clipsync self-test complete");
        }
        "init" => {
            clipsync::init_defaults();
            shell_println!("clipsync initialised");
        }
        _ => {
            shell_println!("clipsync — cross-device clipboard sync");
            shell_println!("  enable / disable             Toggle sync");
            shell_println!("  status                       Show status");
            shell_println!("  device <name> <direction>    Add device");
            shell_println!("  remove <id>                  Remove device");
            shell_println!("  copy <type> <size> <text>    Queue for sync");
            shell_println!("  sync <device_id>             Sync to device");
            shell_println!("  devices                      List devices");
            shell_println!("  queue [n]                    Show queue");
            shell_println!("  maxsize <bytes>              Set max size");
            shell_println!("  allow|deny <type>            Filter types");
            shell_println!("  stats / test / init");
        }
    }
}

fn parse_sync_direction(s: &str) -> crate::fs::clipsync::SyncDirection {
    use crate::fs::clipsync::SyncDirection;
    match s.to_lowercase().as_str() {
        "send" | "sendonly" => SyncDirection::SendOnly,
        "receive" | "recv" | "receiveonly" => SyncDirection::ReceiveOnly,
        "both" | "bidirectional" | "bi" => SyncDirection::Bidirectional,
        _ => SyncDirection::Bidirectional,
    }
}

fn parse_sync_content_type(s: &str) -> crate::fs::clipsync::SyncContentType {
    use crate::fs::clipsync::SyncContentType;
    match s.to_lowercase().as_str() {
        "text" | "txt" => SyncContentType::Text,
        "image" | "img" => SyncContentType::Image,
        "file" => SyncContentType::File,
        "richtext" | "rich" => SyncContentType::RichText,
        "url" | "link" => SyncContentType::Url,
        _ => SyncContentType::Text,
    }
}

/// `netusage` / `nusage` — network usage monitor.
fn cmd_netusage(args: &str) {
    use crate::fs::netusage;
    let parts: Vec<&str> = args.split_whitespace().collect();
    let sub = parts.first().copied().unwrap_or("");
    match sub {
        "record" => {
            // record <app> <iface> <up|down> <bytes>
            if parts.len() < 5 {
                shell_println!("Usage: netusage record <app> <iface> <up|down> <bytes>");
                return;
            }
            let app = parts[1];
            let iface = parts[2];
            let dir = if parts[3] == "up" || parts[3] == "upload" {
                netusage::Direction::Upload
            } else {
                netusage::Direction::Download
            };
            let bytes = parts[4].parse::<u64>().unwrap_or(0);
            match netusage::record_traffic(app, iface, dir, bytes) {
                Ok(()) => shell_println!("Recorded {} bytes {} for '{}'", bytes, dir.label(), app),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "connect" => {
            if let Some(app) = parts.get(1) {
                match netusage::record_connection(app) {
                    Ok(()) => shell_println!("Connection recorded for '{}'", app),
                    Err(e) => shell_println!("Error: {:?}", e),
                }
            } else {
                shell_println!("Usage: netusage connect <app>");
            }
        }
        "cap" => {
            if parts.len() < 3 {
                shell_println!("Usage: netusage cap <app> <bytes|none>");
                return;
            }
            let app = parts[1];
            let cap = if parts[2] == "none" || parts[2] == "off" {
                None
            } else {
                Some(parts[2].parse::<u64>().unwrap_or(0))
            };
            match netusage::set_cap(app, cap) {
                Ok(()) => match cap {
                    Some(b) => shell_println!("Cap for '{}': {} bytes", app, b),
                    None => shell_println!("Cap removed for '{}'", app),
                },
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "app" | "get" => {
            if let Some(app) = parts.get(1) {
                match netusage::get_app_usage(app) {
                    Some(u) => {
                        shell_println!("  {} — sent={} recv={} conns={}", u.app_name, u.bytes_sent, u.bytes_received, u.connections);
                        if let Some(cap) = u.cap_bytes {
                            let total = u.bytes_sent + u.bytes_received;
                            let pct = if cap > 0 { total * 100 / cap } else { 0 };
                            shell_println!("  Cap: {} bytes ({}% used){}", cap, pct, if u.cap_warned { " ⚠ EXCEEDED" } else { "" });
                        }
                    }
                    None => shell_println!("No usage data for '{}'", app),
                }
            } else {
                shell_println!("Usage: netusage app <name>");
            }
        }
        "top" => {
            let max = parts.get(1).and_then(|s| s.parse::<usize>().ok()).unwrap_or(10);
            let top = netusage::top_apps(max);
            if top.is_empty() {
                shell_println!("No usage data");
            } else {
                for (i, a) in top.iter().enumerate() {
                    let total = a.bytes_sent + a.bytes_received;
                    shell_println!("  {}. {} — {} bytes (↑{} ↓{})", i + 1, a.app_name, total, a.bytes_sent, a.bytes_received);
                }
            }
        }
        "ifaces" | "interfaces" => {
            let ifaces = netusage::list_interfaces();
            for i in &ifaces {
                shell_println!("  {} [{}] — ↑{} bytes ({} pkts) ↓{} bytes ({} pkts)", i.name, i.iface_type.label(), i.bytes_sent, i.packets_sent, i.bytes_received, i.packets_received);
            }
        }
        "add" => {
            if parts.len() < 3 {
                shell_println!("Usage: netusage add <name> <type>");
                return;
            }
            let itype = parse_interface_type(parts[2]);
            match netusage::add_interface(parts[1], itype) {
                Ok(()) => shell_println!("Added interface '{}' [{}]", parts[1], itype.label()),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "reset" => {
            match netusage::reset_all() {
                Ok(()) => shell_println!("All usage stats reset"),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "stats" => {
            let (apps, ifaces, sent, recv, conns, warnings, ops) = netusage::stats();
            shell_println!("Network Usage: {} apps, {} interfaces", apps, ifaces);
            shell_println!("  Sent: {} | Received: {} | Connections: {}", sent, recv, conns);
            shell_println!("  Cap warnings: {} | Ops: {}", warnings, ops);
        }
        "test" => {
            netusage::self_test();
            shell_println!("netusage self-test complete");
        }
        "init" => {
            netusage::init_defaults();
            shell_println!("netusage initialised");
        }
        _ => {
            shell_println!("netusage — network usage monitor");
            shell_println!("  record <app> <iface> <up|down> <bytes>  Record traffic");
            shell_println!("  connect <app>                           Record connection");
            shell_println!("  cap <app> <bytes|none>                  Set data cap");
            shell_println!("  app <name>                              Show app usage");
            shell_println!("  top [n]                                 Top apps by usage");
            shell_println!("  ifaces                                  List interfaces");
            shell_println!("  add <name> <type>                       Add interface");
            shell_println!("  reset                                   Reset all stats");
            shell_println!("  stats / test / init");
        }
    }
}

fn parse_interface_type(s: &str) -> crate::fs::netusage::InterfaceType {
    use crate::fs::netusage::InterfaceType;
    match s.to_lowercase().as_str() {
        "ethernet" | "eth" => InterfaceType::Ethernet,
        "wifi" | "wlan" => InterfaceType::Wifi,
        "cellular" | "cell" => InterfaceType::Cellular,
        "vpn" => InterfaceType::Vpn,
        "loopback" | "lo" => InterfaceType::Loopback,
        _ => InterfaceType::Other,
    }
}

/// `touchscreen` / `tscreen` — touchscreen settings.
fn cmd_touchscreen(args: &str) {
    use crate::fs::touchscreen;
    let parts: Vec<&str> = args.split_whitespace().collect();
    let sub = parts.first().copied().unwrap_or("");
    match sub {
        "add" => {
            if parts.len() < 3 {
                shell_println!("Usage: touchscreen add <name> <max_touches>");
                return;
            }
            let name = parts[1];
            let touches = parts[2].parse::<u8>().unwrap_or(10);
            match touchscreen::add_device(name, touches) {
                Ok(id) => shell_println!("Added touchscreen #{}: {} ({} touches)", id, name, touches),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "remove" => {
            if let Some(id_s) = parts.get(1) {
                if let Ok(id) = id_s.parse::<u32>() {
                    match touchscreen::remove_device(id) {
                        Ok(()) => shell_println!("Removed device #{}", id),
                        Err(e) => shell_println!("Error: {:?}", e),
                    }
                } else {
                    shell_println!("Invalid device ID");
                }
            } else {
                shell_println!("Usage: touchscreen remove <id>");
            }
        }
        "calibrate" | "cal" => {
            if let Some(id_s) = parts.get(1) {
                if let Ok(id) = id_s.parse::<u32>() {
                    match touchscreen::calibrate(id) {
                        Ok(()) => shell_println!("Calibrated device #{}", id),
                        Err(e) => shell_println!("Error: {:?}", e),
                    }
                } else {
                    shell_println!("Invalid device ID");
                }
            } else {
                shell_println!("Usage: touchscreen calibrate <device_id>");
            }
        }
        "sensitivity" | "sens" => {
            if let Some(v) = parts.get(1) {
                if let Ok(val) = v.parse::<u32>() {
                    match touchscreen::set_sensitivity(val) {
                        Ok(()) => shell_println!("Sensitivity: {}", val),
                        Err(e) => shell_println!("Error: {:?}", e),
                    }
                } else {
                    shell_println!("Invalid value (1-100)");
                }
            } else {
                shell_println!("Sensitivity: {}", touchscreen::get_sensitivity());
            }
        }
        "palm" => {
            if let Some(v) = parts.get(1) {
                let on = *v == "on" || *v == "true" || *v == "yes";
                match touchscreen::set_palm_rejection(on) {
                    Ok(()) => shell_println!("Palm rejection: {}", if on { "ON" } else { "OFF" }),
                    Err(e) => shell_println!("Error: {:?}", e),
                }
            } else {
                shell_println!("Usage: touchscreen palm <on|off>");
            }
        }
        "sound" => {
            if let Some(v) = parts.get(1) {
                let on = *v == "on" || *v == "true";
                match touchscreen::set_touch_sound(on) {
                    Ok(()) => shell_println!("Touch sound: {}", if on { "ON" } else { "OFF" }),
                    Err(e) => shell_println!("Error: {:?}", e),
                }
            } else {
                shell_println!("Usage: touchscreen sound <on|off>");
            }
        }
        "vibration" | "haptic" => {
            if let Some(v) = parts.get(1) {
                let on = *v == "on" || *v == "true";
                match touchscreen::set_touch_vibration(on) {
                    Ok(()) => shell_println!("Touch vibration: {}", if on { "ON" } else { "OFF" }),
                    Err(e) => shell_println!("Error: {:?}", e),
                }
            } else {
                shell_println!("Usage: touchscreen vibration <on|off>");
            }
        }
        "gesture" => {
            if parts.len() < 3 {
                shell_println!("Usage: touchscreen gesture <type> <action>");
                return;
            }
            let gtype = parse_gesture_type(parts[1]);
            let action = parts[2..].join(" ");
            match touchscreen::set_gesture(gtype, &action) {
                Ok(id) => shell_println!("Gesture #{}: {} → {}", id, gtype.label(), action),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "gestures" => {
            let gestures = touchscreen::list_gestures();
            if gestures.is_empty() {
                shell_println!("No gesture bindings");
            } else {
                for g in &gestures {
                    let en = if g.enabled { "ON" } else { "OFF" };
                    shell_println!("  #{}: {} [{}] → {} (triggers={})", g.id, g.gesture.label(), en, g.action, g.trigger_count);
                }
            }
        }
        "devices" | "list" => {
            let devices = touchscreen::list_devices();
            if devices.is_empty() {
                shell_println!("No touchscreen devices");
            } else {
                for d in &devices {
                    let cal = if d.calibrated { "calibrated" } else { "uncalibrated" };
                    let en = if d.enabled { "ON" } else { "OFF" };
                    shell_println!("  #{}: {} [{}] {} max_touches={}", d.id, d.name, en, cal, d.max_touches);
                }
            }
        }
        "stats" => {
            let (devices, gestures, touches, gest_count, cals, ops) = touchscreen::stats();
            shell_println!("Touchscreen: {} devices, {} gestures", devices, gestures);
            shell_println!("  Touches: {} | Gestures: {} | Calibrations: {} | Ops: {}", touches, gest_count, cals, ops);
        }
        "test" => {
            touchscreen::self_test();
            shell_println!("touchscreen self-test complete");
        }
        "init" => {
            touchscreen::init_defaults();
            shell_println!("touchscreen initialised");
        }
        _ => {
            shell_println!("touchscreen — touchscreen input settings");
            shell_println!("  add <name> <touches>      Add device");
            shell_println!("  remove <id>               Remove device");
            shell_println!("  calibrate <id>            Calibrate device");
            shell_println!("  sensitivity [1-100]       Set/show sensitivity");
            shell_println!("  palm <on|off>             Palm rejection");
            shell_println!("  sound <on|off>            Touch sound");
            shell_println!("  vibration <on|off>        Touch vibration");
            shell_println!("  gesture <type> <action>   Set gesture binding");
            shell_println!("  gestures                  List gestures");
            shell_println!("  devices                   List devices");
            shell_println!("  stats / test / init");
        }
    }
}

fn parse_gesture_type(s: &str) -> crate::fs::touchscreen::GestureType {
    use crate::fs::touchscreen::GestureType;
    match s.to_lowercase().as_str() {
        "tap" => GestureType::Tap,
        "doubletap" | "dtap" => GestureType::DoubleTap,
        "longpress" | "lpress" => GestureType::LongPress,
        "swipe" => GestureType::Swipe,
        "pinch" => GestureType::Pinch,
        "rotate" => GestureType::Rotate,
        "3swipe" | "threefingerswipe" => GestureType::ThreeFingerSwipe,
        "4swipe" | "fourfingerswipe" => GestureType::FourFingerSwipe,
        "edge" | "edgeswipe" => GestureType::EdgeSwipe,
        _ => GestureType::Tap,
    }
}

/// `diskquota` / `dquota` — disk quota management.
fn cmd_diskquota(args: &str) {
    use crate::fs::diskquota;
    let parts: Vec<&str> = args.split_whitespace().collect();
    let sub = parts.first().copied().unwrap_or("");
    match sub {
        "set" => {
            // set <name> <user|group> <soft_bytes> <hard_bytes>
            if parts.len() < 5 {
                shell_println!("Usage: diskquota set <name> <user|group> <soft> <hard>");
                return;
            }
            let name = parts[1];
            let target = if parts[2] == "group" {
                diskquota::QuotaTarget::Group
            } else {
                diskquota::QuotaTarget::User
            };
            let soft = parts[3].parse::<u64>().unwrap_or(0);
            let hard = parts[4].parse::<u64>().unwrap_or(0);
            match diskquota::set_quota(name, target, soft, hard) {
                Ok(id) => shell_println!("Quota #{} for {} '{}': soft={} hard={}", id, target.label(), name, soft, hard),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "files" => {
            if parts.len() < 5 {
                shell_println!("Usage: diskquota files <name> <user|group> <soft> <hard>");
                return;
            }
            let name = parts[1];
            let target = if parts[2] == "group" {
                diskquota::QuotaTarget::Group
            } else {
                diskquota::QuotaTarget::User
            };
            let soft = parts[3].parse::<u64>().unwrap_or(0);
            let hard = parts[4].parse::<u64>().unwrap_or(0);
            match diskquota::set_file_limits(name, target, soft, hard) {
                Ok(()) => shell_println!("File limits for {} '{}': soft={} hard={}", target.label(), name, soft, hard),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "check" => {
            if parts.len() < 4 {
                shell_println!("Usage: diskquota check <name> <user|group> <bytes>");
                return;
            }
            let name = parts[1];
            let target = if parts[2] == "group" {
                diskquota::QuotaTarget::Group
            } else {
                diskquota::QuotaTarget::User
            };
            let bytes = parts[3].parse::<u64>().unwrap_or(0);
            match diskquota::check_quota(name, target, bytes) {
                Ok(allowed) => shell_println!("{} write of {} bytes: {}", name, bytes, if allowed { "ALLOWED" } else { "DENIED" }),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "update" => {
            if parts.len() < 4 {
                shell_println!("Usage: diskquota update <name> <user|group> <bytes_delta> [file_delta]");
                return;
            }
            let name = parts[1];
            let target = if parts[2] == "group" {
                diskquota::QuotaTarget::Group
            } else {
                diskquota::QuotaTarget::User
            };
            let bdelta = parts[3].parse::<i64>().unwrap_or(0);
            let fdelta = parts.get(4).and_then(|s| s.parse::<i64>().ok()).unwrap_or(0);
            match diskquota::update_usage(name, target, bdelta, fdelta) {
                Ok(()) => shell_println!("Updated {} '{}': bytes={:+} files={:+}", target.label(), name, bdelta, fdelta),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "remove" => {
            if parts.len() < 3 {
                shell_println!("Usage: diskquota remove <name> <user|group>");
                return;
            }
            let name = parts[1];
            let target = if parts[2] == "group" {
                diskquota::QuotaTarget::Group
            } else {
                diskquota::QuotaTarget::User
            };
            match diskquota::remove_quota(name, target) {
                Ok(()) => shell_println!("Removed quota for {} '{}'", target.label(), name),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "get" => {
            if parts.len() < 3 {
                shell_println!("Usage: diskquota get <name> <user|group>");
                return;
            }
            let name = parts[1];
            let target = if parts[2] == "group" {
                diskquota::QuotaTarget::Group
            } else {
                diskquota::QuotaTarget::User
            };
            match diskquota::get_quota(name, target) {
                Some(q) => {
                    shell_println!("  {} '{}' [{}]", q.target_type.label(), q.name, q.status().label());
                    shell_println!("  Bytes: {} / {} (soft) / {} (hard)", q.bytes_used, q.soft_limit_bytes, q.hard_limit_bytes);
                    shell_println!("  Files: {}", q.file_count);
                }
                None => shell_println!("No quota for {} '{}'", target.label(), name),
            }
        }
        "list" => {
            let quotas = diskquota::list_quotas();
            if quotas.is_empty() {
                shell_println!("No quotas configured");
            } else {
                for q in &quotas {
                    let pct = if q.hard_limit_bytes > 0 { q.bytes_used * 100 / q.hard_limit_bytes } else { 0 };
                    shell_println!("  #{}: {} '{}' [{}] — {} / {} ({}%)", q.id, q.target_type.label(), q.name, q.status().label(), q.bytes_used, q.hard_limit_bytes, pct);
                }
            }
        }
        "enable" | "on" => {
            match diskquota::set_enabled(true) {
                Ok(()) => shell_println!("Quota enforcement enabled"),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "disable" | "off" => {
            match diskquota::set_enabled(false) {
                Ok(()) => shell_println!("Quota enforcement disabled"),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "stats" => {
            let (entries, checks, denials, warnings, ops) = diskquota::stats();
            shell_println!("Disk Quota: {} entries, {} checks", entries, checks);
            shell_println!("  Denials: {} | Warnings: {} | Ops: {}", denials, warnings, ops);
        }
        "test" => {
            diskquota::self_test();
            shell_println!("diskquota self-test complete");
        }
        "init" => {
            diskquota::init_defaults();
            shell_println!("diskquota initialised");
        }
        _ => {
            shell_println!("diskquota — disk quota management");
            shell_println!("  set <name> <user|group> <soft> <hard>  Set quota");
            shell_println!("  files <name> <type> <soft> <hard>      Set file limits");
            shell_println!("  check <name> <type> <bytes>            Check write");
            shell_println!("  update <name> <type> <delta> [fdelta]  Update usage");
            shell_println!("  get <name> <type>                      Show quota");
            shell_println!("  remove <name> <type>                   Remove quota");
            shell_println!("  list                                   List all");
            shell_println!("  enable / disable                       Toggle enforcement");
            shell_println!("  stats / test / init");
        }
    }
}

/// `appdefaults` / `adef` — per-app default settings.
fn cmd_appdefaults(args: &str) {
    use crate::fs::appdefaults;
    let parts: Vec<&str> = args.split_whitespace().collect();
    let sub = parts.first().copied().unwrap_or("");
    match sub {
        "get" => {
            if parts.len() < 3 {
                shell_println!("Usage: appdefaults get <app> <key>");
                return;
            }
            match appdefaults::get(parts[1], parts[2]) {
                Ok(Some(v)) => shell_println!("  {}.{} = {} ({})", parts[1], parts[2], v.display_value(), v.type_label()),
                Ok(None) => shell_println!("  {}.{} not set", parts[1], parts[2]),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "set" => {
            if parts.len() < 4 {
                shell_println!("Usage: appdefaults set <app> <key> <value> [type]");
                return;
            }
            let app = parts[1];
            let key = parts[2];
            let raw = parts[3];
            let ptype = parts.get(4).copied().unwrap_or("auto");
            let value = match ptype {
                "int" | "i" => {
                    if let Ok(v) = raw.parse::<i64>() {
                        appdefaults::PrefValue::Int(v)
                    } else {
                        shell_println!("Invalid integer");
                        return;
                    }
                }
                "bool" | "b" => {
                    let v = raw == "true" || raw == "yes" || raw == "1" || raw == "on";
                    appdefaults::PrefValue::Bool(v)
                }
                "string" | "s" => appdefaults::PrefValue::Str(alloc::string::String::from(raw)),
                _ => {
                    // Auto-detect.
                    if raw == "true" || raw == "false" {
                        appdefaults::PrefValue::Bool(raw == "true")
                    } else if let Ok(v) = raw.parse::<i64>() {
                        appdefaults::PrefValue::Int(v)
                    } else {
                        appdefaults::PrefValue::Str(alloc::string::String::from(raw))
                    }
                }
            };
            match appdefaults::set(app, key, value) {
                Ok(()) => shell_println!("Set {}.{} = {}", app, key, raw),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "delete" | "del" => {
            if parts.len() < 3 {
                shell_println!("Usage: appdefaults delete <app> <key>");
                return;
            }
            match appdefaults::delete(parts[1], parts[2]) {
                Ok(()) => shell_println!("Deleted {}.{}", parts[1], parts[2]),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "reset" => {
            if let Some(app) = parts.get(1) {
                match appdefaults::reset(app) {
                    Ok(()) => shell_println!("Reset all prefs for '{}'", app),
                    Err(e) => shell_println!("Error: {:?}", e),
                }
            } else {
                shell_println!("Usage: appdefaults reset <app>");
            }
        }
        "remove" => {
            if let Some(app) = parts.get(1) {
                match appdefaults::remove_app(app) {
                    Ok(()) => shell_println!("Removed app '{}'", app),
                    Err(e) => shell_println!("Error: {:?}", e),
                }
            } else {
                shell_println!("Usage: appdefaults remove <app>");
            }
        }
        "show" => {
            if let Some(app) = parts.get(1) {
                match appdefaults::get_app_prefs(app) {
                    Some(prefs) => {
                        shell_println!("  {} ({} entries, r={} w={})", prefs.app_name, prefs.entries.len(), prefs.total_reads, prefs.total_writes);
                        for e in &prefs.entries {
                            shell_println!("    {} = {} ({})", e.key, e.value.display_value(), e.value.type_label());
                        }
                    }
                    None => shell_println!("No prefs for '{}'", app),
                }
            } else {
                shell_println!("Usage: appdefaults show <app>");
            }
        }
        "apps" | "list" => {
            let apps = appdefaults::list_apps();
            if apps.is_empty() {
                shell_println!("No apps with preferences");
            } else {
                for app in &apps {
                    let keys = appdefaults::list_keys(app);
                    shell_println!("  {} ({} keys)", app, keys.len());
                }
            }
        }
        "keys" => {
            if let Some(app) = parts.get(1) {
                let keys = appdefaults::list_keys(app);
                if keys.is_empty() {
                    shell_println!("No keys for '{}'", app);
                } else {
                    for k in &keys {
                        shell_println!("  {}", k);
                    }
                }
            } else {
                shell_println!("Usage: appdefaults keys <app>");
            }
        }
        "stats" => {
            let (apps, reads, writes, resets, ops) = appdefaults::stats();
            shell_println!("App Defaults: {} apps", apps);
            shell_println!("  Reads: {} | Writes: {} | Resets: {} | Ops: {}", reads, writes, resets, ops);
        }
        "test" => {
            appdefaults::self_test();
            shell_println!("appdefaults self-test complete");
        }
        "init" => {
            appdefaults::init_defaults();
            shell_println!("appdefaults initialised");
        }
        _ => {
            shell_println!("appdefaults — per-app default settings");
            shell_println!("  get <app> <key>                  Read preference");
            shell_println!("  set <app> <key> <value> [type]   Write preference");
            shell_println!("  delete <app> <key>               Delete preference");
            shell_println!("  show <app>                       Show all prefs");
            shell_println!("  reset <app>                      Clear app prefs");
            shell_println!("  remove <app>                     Remove app entry");
            shell_println!("  apps                             List apps");
            shell_println!("  keys <app>                       List keys");
            shell_println!("  stats / test / init");
        }
    }
}

/// `policyengine` / `pengine` — system-wide policy enforcement.
fn cmd_policyengine(args: &str) {
    use crate::fs::policyengine;
    use alloc::format;
    let parts: Vec<&str> = args.split_whitespace().collect();
    let sub = parts.first().copied().unwrap_or("");
    match sub {
        "eval" | "evaluate" => {
            if parts.len() < 4 {
                shell_println!("Usage: policyengine eval <subject> <action> <resource>");
                return;
            }
            match policyengine::evaluate(parts[1], parts[2], parts[3]) {
                Ok(effect) => shell_println!("Result: {} (subject={} action={} resource={})", effect.label(), parts[1], parts[2], parts[3]),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "add" => {
            if parts.len() < 7 {
                shell_println!("Usage: policyengine add <name> <category> <subject> <action> <resource> <effect> [priority]");
                return;
            }
            let cat = parse_policy_category(parts[2]);
            let effect = parse_policy_effect(parts[6]);
            let priority = parts.get(7).and_then(|s| s.parse::<u32>().ok()).unwrap_or(50);
            match policyengine::add_rule(parts[1], cat, parts[3], parts[4], parts[5], effect, priority) {
                Ok(id) => shell_println!("Added rule #{}: {} [{}] → {}", id, parts[1], cat.label(), effect.label()),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "remove" => {
            if let Some(id_s) = parts.get(1) {
                if let Ok(id) = id_s.parse::<u32>() {
                    match policyengine::remove_rule(id) {
                        Ok(()) => shell_println!("Removed rule #{}", id),
                        Err(e) => shell_println!("Error: {:?}", e),
                    }
                } else {
                    shell_println!("Invalid rule ID");
                }
            } else {
                shell_println!("Usage: policyengine remove <id>");
            }
        }
        "list" => {
            let rules = policyengine::list_rules();
            if rules.is_empty() {
                shell_println!("No policy rules");
            } else {
                for r in &rules {
                    let en = if r.enabled { "ON" } else { "OFF" };
                    shell_println!("  #{}: {} [{}] [{}] p={} hits={}", r.id, r.name, r.category.label(), en, r.priority, r.hit_count);
                    shell_println!("     {} {} {} → {}", r.subject, r.action, r.resource, r.effect.label());
                }
            }
        }
        "audit" => {
            let max = parts.get(1).and_then(|s| s.parse::<usize>().ok()).unwrap_or(10);
            let log = policyengine::get_audit_log(max);
            if log.is_empty() {
                shell_println!("No audit entries");
            } else {
                for e in &log {
                    let rule = e.rule_id.map_or(String::from("default"), |id| format!("rule#{}", id));
                    shell_println!("  {} {} {} → {} ({})", e.subject, e.action, e.resource, e.effect.label(), rule);
                }
            }
        }
        "enforce" => {
            if let Some(v) = parts.get(1) {
                let on = *v == "on" || *v == "true" || *v == "yes";
                match policyengine::set_enforcement(on) {
                    Ok(()) => shell_println!("Enforcement: {}", if on { "ON" } else { "OFF" }),
                    Err(e) => shell_println!("Error: {:?}", e),
                }
            } else {
                shell_println!("Usage: policyengine enforce <on|off>");
            }
        }
        "default" => {
            if let Some(v) = parts.get(1) {
                let effect = parse_policy_effect(v);
                match policyengine::set_default(effect) {
                    Ok(()) => shell_println!("Default effect: {}", effect.label()),
                    Err(e) => shell_println!("Error: {:?}", e),
                }
            } else {
                shell_println!("Usage: policyengine default <allow|deny|audit>");
            }
        }
        "stats" => {
            let (rules, audit, evals, denials, audits, ops) = policyengine::stats();
            shell_println!("Policy Engine: {} rules, {} audit entries", rules, audit);
            shell_println!("  Evaluations: {} | Denials: {} | Audits: {} | Ops: {}", evals, denials, audits, ops);
        }
        "test" => {
            policyengine::self_test();
            shell_println!("policyengine self-test complete");
        }
        "init" => {
            policyengine::init_defaults();
            shell_println!("policyengine initialised");
        }
        _ => {
            shell_println!("policyengine — system-wide policy enforcement");
            shell_println!("  eval <subject> <action> <resource>  Evaluate policy");
            shell_println!("  add <name> <cat> <subj> <act> <res> <effect> [pri]");
            shell_println!("  remove <id>              Remove rule");
            shell_println!("  list                     List rules");
            shell_println!("  audit [n]                Show audit log");
            shell_println!("  enforce <on|off>         Toggle enforcement");
            shell_println!("  default <effect>         Set default effect");
            shell_println!("  stats / test / init");
        }
    }
}

fn parse_policy_category(s: &str) -> crate::fs::policyengine::PolicyCategory {
    use crate::fs::policyengine::PolicyCategory;
    match s.to_lowercase().as_str() {
        "security" | "sec" => PolicyCategory::Security,
        "privacy" | "priv" => PolicyCategory::Privacy,
        "network" | "net" => PolicyCategory::Network,
        "application" | "app" => PolicyCategory::Application,
        "hardware" | "hw" => PolicyCategory::Hardware,
        "storage" | "stor" => PolicyCategory::Storage,
        "system" | "sys" => PolicyCategory::System,
        _ => PolicyCategory::System,
    }
}

fn parse_policy_effect(s: &str) -> crate::fs::policyengine::Effect {
    use crate::fs::policyengine::Effect;
    match s.to_lowercase().as_str() {
        "allow" => Effect::Allow,
        "deny" | "block" => Effect::Deny,
        "audit" | "log" => Effect::Audit,
        "allowaudit" | "allow+audit" => Effect::AllowWithAudit,
        _ => Effect::Allow,
    }
}

/// `fontpreview` / `fprev` — font preview and comparison.
fn cmd_fontpreview(args: &str) {
    use crate::fs::fontpreview;
    let parts: Vec<&str> = args.split_whitespace().collect();
    let sub = parts.first().copied().unwrap_or("");
    match sub {
        "preview" | "show" => {
            if let Some(id_s) = parts.get(1) {
                if let Ok(id) = id_s.parse::<u32>() {
                    let size = parts.get(2).and_then(|s| s.parse::<u32>().ok()).unwrap_or(16);
                    let sample = if parts.len() > 3 { Some(parts[3..].join(" ")) } else { None };
                    match fontpreview::preview(id, sample.as_deref(), size) {
                        Ok(p) => {
                            shell_println!("  {} {} @ {}pt", p.family, p.style.label(), p.size_pt);
                            shell_println!("  \"{}\"", p.sample_text);
                        }
                        Err(e) => shell_println!("Error: {:?}", e),
                    }
                } else {
                    shell_println!("Invalid font ID");
                }
            } else {
                shell_println!("Usage: fontpreview preview <id> [size] [sample_text]");
            }
        }
        "compare" => {
            if parts.len() < 2 {
                shell_println!("Usage: fontpreview compare <id1,id2,...> [size]");
                return;
            }
            let ids: Vec<u32> = parts[1].split(',').filter_map(|s| s.parse::<u32>().ok()).collect();
            let size = parts.get(2).and_then(|s| s.parse::<u32>().ok()).unwrap_or(14);
            match fontpreview::compare(&ids, None, size) {
                Ok(results) => {
                    for r in &results {
                        shell_println!("  #{}: {} {} @ {}pt", r.font_id, r.family, r.style.label(), r.size_pt);
                        shell_println!("     \"{}\"", r.sample_text);
                    }
                }
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "search" => {
            if let Some(q) = parts.get(1) {
                let results = fontpreview::search(q);
                if results.is_empty() {
                    shell_println!("No fonts matching '{}'", q);
                } else {
                    for f in &results {
                        shell_println!("  #{}: {} {} [{}] ({} glyphs)", f.id, f.family, f.style.label(), f.category.label(), f.glyph_count);
                    }
                }
            } else {
                shell_println!("Usage: fontpreview search <query>");
            }
        }
        "category" | "cat" => {
            if let Some(c) = parts.get(1) {
                let cat = parse_font_category(c);
                let fonts = fontpreview::by_category(cat);
                if fonts.is_empty() {
                    shell_println!("No {} fonts", cat.label());
                } else {
                    for f in &fonts {
                        shell_println!("  #{}: {} {}", f.id, f.family, f.style.label());
                    }
                }
            } else {
                shell_println!("Usage: fontpreview category <sans|serif|mono|display|hand|symbol>");
            }
        }
        "list" => {
            let fonts = fontpreview::list_fonts();
            if fonts.is_empty() {
                shell_println!("No fonts registered");
            } else {
                for f in &fonts {
                    shell_println!("  #{}: {} {} [{}] {} v{} ({} glyphs, {} previews)", f.id, f.family, f.style.label(), f.category.label(), f.file_path, f.version, f.glyph_count, f.preview_count);
                }
            }
        }
        "add" => {
            if parts.len() < 5 {
                shell_println!("Usage: fontpreview add <family> <style> <category> <path> [version] [glyphs]");
                return;
            }
            let style = parse_font_style(parts[2]);
            let cat = parse_font_category(parts[3]);
            let path = parts[4];
            let version = parts.get(5).copied().unwrap_or("1.0");
            let glyphs = parts.get(6).and_then(|s| s.parse::<u32>().ok()).unwrap_or(0);
            match fontpreview::add_font(parts[1], style, cat, path, version, glyphs) {
                Ok(id) => shell_println!("Added font #{}: {} {}", id, parts[1], style.label()),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "sample" => {
            if parts.len() < 2 {
                shell_println!("Usage: fontpreview sample <text...>");
                return;
            }
            let text = parts[1..].join(" ");
            match fontpreview::set_sample(&text) {
                Ok(()) => shell_println!("Default sample: \"{}\"", text),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "stats" => {
            let (fonts, previews, comparisons, ops) = fontpreview::stats();
            shell_println!("Font Preview: {} fonts, {} previews, {} comparisons, {} ops", fonts, previews, comparisons, ops);
        }
        "test" => {
            fontpreview::self_test();
            shell_println!("fontpreview self-test complete");
        }
        "init" => {
            fontpreview::init_defaults();
            shell_println!("fontpreview initialised");
        }
        _ => {
            shell_println!("fontpreview — font preview and comparison");
            shell_println!("  preview <id> [size] [text]   Preview a font");
            shell_println!("  compare <id1,id2> [size]     Compare fonts");
            shell_println!("  search <query>               Search fonts");
            shell_println!("  category <type>              Browse by category");
            shell_println!("  list                         List all fonts");
            shell_println!("  add <family> <style> <cat> <path>  Add font");
            shell_println!("  sample <text>                Set default sample");
            shell_println!("  stats / test / init");
        }
    }
}

fn parse_font_style(s: &str) -> crate::fs::fontpreview::FontStyle {
    use crate::fs::fontpreview::FontStyle;
    match s.to_lowercase().as_str() {
        "regular" | "r" => FontStyle::Regular,
        "bold" | "b" => FontStyle::Bold,
        "italic" | "i" => FontStyle::Italic,
        "bolditalic" | "bi" => FontStyle::BoldItalic,
        "light" | "l" => FontStyle::Light,
        "medium" | "m" => FontStyle::Medium,
        "semibold" | "sb" => FontStyle::SemiBold,
        "extrabold" | "eb" => FontStyle::ExtraBold,
        _ => FontStyle::Regular,
    }
}

fn parse_font_category(s: &str) -> crate::fs::fontpreview::FontCategory {
    use crate::fs::fontpreview::FontCategory;
    match s.to_lowercase().as_str() {
        "sans" | "sansserif" => FontCategory::SansSerif,
        "serif" => FontCategory::Serif,
        "mono" | "monospace" => FontCategory::Monospace,
        "display" => FontCategory::Display,
        "hand" | "handwriting" => FontCategory::Handwriting,
        "symbol" | "sym" => FontCategory::Symbol,
        _ => FontCategory::SansSerif,
    }
}

/// `wifiscan` / `wifi` — Wi-Fi network scanning and management.
fn cmd_wifiscan(args: &str) {
    use crate::fs::wifiscan;
    use alloc::string::String;
    let parts: Vec<&str> = args.split_whitespace().collect();
    let sub = parts.first().copied().unwrap_or("");
    match sub {
        "scan" => {
            match wifiscan::scan() {
                Ok(count) => shell_println!("Scan complete: {} networks visible", count),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "discover" => {
            if parts.len() < 6 {
                shell_println!("Usage: wifiscan discover <ssid> <bssid> <security> <band> <channel> [signal]");
                return;
            }
            let security = parse_wifi_security(parts[3]);
            let band = parse_wifi_band(parts[4]);
            let channel = parts[5].parse::<u8>().unwrap_or(1);
            let signal = parts.get(6).and_then(|s| s.parse::<i32>().ok()).unwrap_or(-60);
            match wifiscan::discover(parts[1], parts[2], security, band, channel, signal) {
                Ok(id) => shell_println!("Network #{}: {} ({} {} ch{} {}dBm)", id, parts[1], security.label(), band.label(), channel, signal),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "connect" => {
            if let Some(ssid) = parts.get(1) {
                match wifiscan::connect(ssid) {
                    Ok(()) => shell_println!("Connected to '{}'", ssid),
                    Err(e) => shell_println!("Error: {:?}", e),
                }
            } else {
                shell_println!("Usage: wifiscan connect <ssid>");
            }
        }
        "disconnect" => {
            match wifiscan::disconnect() {
                Ok(()) => shell_println!("Disconnected"),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "forget" => {
            if let Some(ssid) = parts.get(1) {
                match wifiscan::forget(ssid) {
                    Ok(()) => shell_println!("Forgot '{}'", ssid),
                    Err(e) => shell_println!("Error: {:?}", e),
                }
            } else {
                shell_println!("Usage: wifiscan forget <ssid>");
            }
        }
        "status" => {
            let state = wifiscan::get_state();
            let ssid = wifiscan::connected_ssid().unwrap_or_else(|| String::from("none"));
            shell_println!("Wi-Fi: {} ({})", state.label(), ssid);
        }
        "list" | "networks" => {
            let nets = wifiscan::list_networks();
            if nets.is_empty() {
                shell_println!("No networks discovered");
            } else {
                for n in &nets {
                    let known = if n.known { "★" } else { " " };
                    shell_println!("  {} #{}: {} [{}] {} ch{} {}dBm", known, n.id, n.ssid, n.security.label(), n.band.label(), n.channel, n.signal_dbm);
                }
            }
        }
        "saved" => {
            let saved = wifiscan::list_saved();
            if saved.is_empty() {
                shell_println!("No saved networks");
            } else {
                for s in &saved {
                    let auto = if s.auto_connect { "auto" } else { "manual" };
                    shell_println!("  {} [{}] {} (connected {} times)", s.ssid, s.security.label(), auto, s.connect_count);
                }
            }
        }
        "stats" => {
            let (nets, saved, scans, conns, fails, ops) = wifiscan::stats();
            shell_println!("Wi-Fi: {} networks, {} saved", nets, saved);
            shell_println!("  Scans: {} | Connections: {} | Failures: {} | Ops: {}", scans, conns, fails, ops);
        }
        "test" => {
            wifiscan::self_test();
            shell_println!("wifiscan self-test complete");
        }
        "init" => {
            wifiscan::init_defaults();
            shell_println!("wifiscan initialised");
        }
        _ => {
            shell_println!("wifiscan — Wi-Fi network management");
            shell_println!("  scan                                      Scan for networks");
            shell_println!("  discover <ssid> <bssid> <sec> <band> <ch> Add network");
            shell_println!("  connect <ssid>                            Connect");
            shell_println!("  disconnect                                Disconnect");
            shell_println!("  forget <ssid>                             Forget saved");
            shell_println!("  status                                    Show status");
            shell_println!("  list                                      List networks");
            shell_println!("  saved                                     Saved networks");
            shell_println!("  stats / test / init");
        }
    }
}

fn parse_wifi_security(s: &str) -> crate::fs::wifiscan::SecurityType {
    use crate::fs::wifiscan::SecurityType;
    match s.to_lowercase().as_str() {
        "open" | "none" => SecurityType::Open,
        "wep" => SecurityType::Wep,
        "wpa" | "wpapsk" => SecurityType::WpaPsk,
        "wpa2" | "wpa2psk" => SecurityType::Wpa2Psk,
        "wpa3" | "wpa3psk" | "sae" => SecurityType::Wpa3Psk,
        "wpa2e" | "wpa2enterprise" => SecurityType::Wpa2Enterprise,
        "wpa3e" | "wpa3enterprise" => SecurityType::Wpa3Enterprise,
        _ => SecurityType::Wpa2Psk,
    }
}

fn parse_wifi_band(s: &str) -> crate::fs::wifiscan::Band {
    use crate::fs::wifiscan::Band;
    match s.to_lowercase().as_str() {
        "2.4" | "2g" | "24" | "24ghz" => Band::Band24Ghz,
        "5" | "5g" | "5ghz" => Band::Band5Ghz,
        "6" | "6g" | "6ghz" | "6e" => Band::Band6Ghz,
        _ => Band::Band5Ghz,
    }
}

/// `splitview` / `split` — multi-pane window management.
fn cmd_splitview(args: &str) {
    use crate::fs::splitview;
    use alloc::format;
    let parts: Vec<&str> = args.split_whitespace().collect();
    let sub = parts.first().copied().unwrap_or("");
    match sub {
        "create" => {
            let orient = if parts.get(1).copied().unwrap_or("h") == "v" {
                splitview::Orientation::Vertical
            } else {
                splitview::Orientation::Horizontal
            };
            match splitview::create_split(orient) {
                Ok(id) => shell_println!("Created split #{} ({})", id, orient.label()),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "remove" => {
            if let Some(id_s) = parts.get(1) {
                if let Ok(id) = id_s.parse::<u32>() {
                    match splitview::remove_split(id) {
                        Ok(()) => shell_println!("Removed split #{}", id),
                        Err(e) => shell_println!("Error: {:?}", e),
                    }
                } else {
                    shell_println!("Invalid split ID");
                }
            } else {
                shell_println!("Usage: splitview remove <split_id>");
            }
        }
        "add" => {
            if parts.len() < 2 {
                shell_println!("Usage: splitview add <split_id> [window_id]");
                return;
            }
            let split_id = parts[1].parse::<u32>().unwrap_or(0);
            let win_id = parts.get(2).and_then(|s| s.parse::<u32>().ok());
            match splitview::add_pane(split_id, win_id) {
                Ok(pane_id) => shell_println!("Added pane #{} to split #{}", pane_id, split_id),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "rmpane" => {
            if parts.len() < 3 {
                shell_println!("Usage: splitview rmpane <split_id> <pane_id>");
                return;
            }
            let split_id = parts[1].parse::<u32>().unwrap_or(0);
            let pane_id = parts[2].parse::<u32>().unwrap_or(0);
            match splitview::remove_pane(split_id, pane_id) {
                Ok(()) => shell_println!("Removed pane #{} from split #{}", pane_id, split_id),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "resize" => {
            if parts.len() < 4 {
                shell_println!("Usage: splitview resize <split_id> <pane_id> <ratio>");
                return;
            }
            let split_id = parts[1].parse::<u32>().unwrap_or(0);
            let pane_id = parts[2].parse::<u32>().unwrap_or(0);
            let ratio = parts[3].parse::<u32>().unwrap_or(50);
            match splitview::resize_pane(split_id, pane_id, ratio) {
                Ok(()) => shell_println!("Resized pane #{} to {}%", pane_id, ratio),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "focus" => {
            if parts.len() < 3 {
                shell_println!("Usage: splitview focus <split_id> <pane_id>");
                return;
            }
            let split_id = parts[1].parse::<u32>().unwrap_or(0);
            let pane_id = parts[2].parse::<u32>().unwrap_or(0);
            match splitview::focus_pane(split_id, pane_id) {
                Ok(()) => shell_println!("Focused pane #{}", pane_id),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "orient" => {
            if parts.len() < 3 {
                shell_println!("Usage: splitview orient <split_id> <h|v>");
                return;
            }
            let split_id = parts[1].parse::<u32>().unwrap_or(0);
            let orient = if parts[2] == "v" {
                splitview::Orientation::Vertical
            } else {
                splitview::Orientation::Horizontal
            };
            match splitview::set_orientation(split_id, orient) {
                Ok(()) => shell_println!("Split #{}: {}", split_id, orient.label()),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "list" => {
            let splits = splitview::list_splits();
            if splits.is_empty() {
                shell_println!("No splits");
            } else {
                let active = splitview::active_split();
                for s in &splits {
                    let marker = if active == Some(s.id) { "→" } else { " " };
                    shell_println!("{} Split #{} ({}, {} panes)", marker, s.id, s.orientation.label(), s.panes.len());
                    for p in &s.panes {
                        let f = if p.focused { "★" } else { " " };
                        let win = p.window_id.map_or(String::from("empty"), |w| format!("win#{}", w));
                        shell_println!("    {} Pane #{}: {} ({}%)", f, p.id, win, p.ratio);
                    }
                }
            }
        }
        "stats" => {
            let (splits, created, panes, resizes, ops) = splitview::stats();
            shell_println!("Split View: {} splits, {} created total", splits, created);
            shell_println!("  Panes added: {} | Resizes: {} | Ops: {}", panes, resizes, ops);
        }
        "test" => {
            splitview::self_test();
            shell_println!("splitview self-test complete");
        }
        "init" => {
            splitview::init_defaults();
            shell_println!("splitview initialised");
        }
        _ => {
            shell_println!("splitview — multi-pane window management");
            shell_println!("  create <h|v>                     Create split");
            shell_println!("  remove <split_id>                Remove split");
            shell_println!("  add <split_id> [window_id]       Add pane");
            shell_println!("  rmpane <split_id> <pane_id>      Remove pane");
            shell_println!("  resize <split> <pane> <ratio>    Resize pane");
            shell_println!("  focus <split_id> <pane_id>       Focus pane");
            shell_println!("  orient <split_id> <h|v>          Set orientation");
            shell_println!("  list                             List splits");
            shell_println!("  stats / test / init");
        }
    }
}

/// `iotdevice` / `iot` — IoT/smart home device management.
fn cmd_iotdevice(args: &str) {
    use crate::fs::iotdevice;
    let parts: Vec<&str> = args.split_whitespace().collect();
    let sub = parts.first().copied().unwrap_or("");
    match sub {
        "discover" | "add" => {
            if parts.len() < 5 {
                shell_println!("Usage: iotdevice discover <name> <type> <protocol> <room>");
                return;
            }
            let dtype = parse_iot_device_type(parts[2]);
            let proto = parse_iot_protocol(parts[3]);
            let room = parts[4..].join(" ");
            match iotdevice::discover(parts[1], dtype, proto, &room) {
                Ok(id) => shell_println!("Device #{}: {} [{}] via {} in {}", id, parts[1], dtype.label(), proto.label(), room),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "remove" => {
            if let Some(id_s) = parts.get(1) {
                if let Ok(id) = id_s.parse::<u32>() {
                    match iotdevice::remove_device(id) {
                        Ok(()) => shell_println!("Removed device #{}", id),
                        Err(e) => shell_println!("Error: {:?}", e),
                    }
                } else { shell_println!("Invalid device ID"); }
            } else { shell_println!("Usage: iotdevice remove <id>"); }
        }
        "set" => {
            if parts.len() < 3 {
                shell_println!("Usage: iotdevice set <id> <state>");
                return;
            }
            let id = parts[1].parse::<u32>().unwrap_or(0);
            let value = parts[2..].join(" ");
            match iotdevice::set_state(id, &value) {
                Ok(()) => shell_println!("Device #{} → {}", id, value),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "online" | "offline" => {
            if let Some(id_s) = parts.get(1) {
                if let Ok(id) = id_s.parse::<u32>() {
                    let online = sub == "online";
                    match iotdevice::set_online(id, online) {
                        Ok(()) => shell_println!("Device #{}: {}", id, if online { "ONLINE" } else { "OFFLINE" }),
                        Err(e) => shell_println!("Error: {:?}", e),
                    }
                } else { shell_println!("Invalid device ID"); }
            } else { shell_println!("Usage: iotdevice online|offline <id>"); }
        }
        "group" => {
            if parts.len() < 3 {
                shell_println!("Usage: iotdevice group <name> <id1,id2,...>");
                return;
            }
            let ids: Vec<u32> = parts[2].split(',').filter_map(|s| s.parse::<u32>().ok()).collect();
            match iotdevice::create_group(parts[1], ids) {
                Ok(id) => shell_println!("Group #{}: {}", id, parts[1]),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "gcmd" => {
            if parts.len() < 3 {
                shell_println!("Usage: iotdevice gcmd <group_id> <state>");
                return;
            }
            let gid = parts[1].parse::<u32>().unwrap_or(0);
            let value = parts[2..].join(" ");
            match iotdevice::group_command(gid, &value) {
                Ok(count) => shell_println!("Set {} devices to '{}'", count, value),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "room" => {
            if let Some(room) = parts.get(1) {
                let devs = iotdevice::by_room(&parts[1..].join(" "));
                if devs.is_empty() {
                    shell_println!("No devices in '{}'", room);
                } else {
                    for d in &devs {
                        let status = if d.online { "●" } else { "○" };
                        shell_println!("  {} #{}: {} [{}] = {}", status, d.id, d.name, d.device_type.label(), d.state_value);
                    }
                }
            } else { shell_println!("Usage: iotdevice room <name>"); }
        }
        "list" => {
            let devs = iotdevice::list_devices();
            if devs.is_empty() {
                shell_println!("No IoT devices");
            } else {
                for d in &devs {
                    let status = if d.online { "●" } else { "○" };
                    shell_println!("  {} #{}: {} [{}] via {} in {} = {} (cmds={})", status, d.id, d.name, d.device_type.label(), d.protocol.label(), d.room, d.state_value, d.command_count);
                }
            }
        }
        "groups" => {
            let groups = iotdevice::list_groups();
            if groups.is_empty() {
                shell_println!("No groups");
            } else {
                for g in &groups {
                    shell_println!("  #{}: {} ({} devices: {:?})", g.id, g.name, g.device_ids.len(), g.device_ids);
                }
            }
        }
        "stats" => {
            let (devices, groups, online, commands, discoveries, ops) = iotdevice::stats();
            shell_println!("IoT: {} devices ({} online), {} groups", devices, online, groups);
            shell_println!("  Commands: {} | Discoveries: {} | Ops: {}", commands, discoveries, ops);
        }
        "test" => { iotdevice::self_test(); shell_println!("iotdevice self-test complete"); }
        "init" => { iotdevice::init_defaults(); shell_println!("iotdevice initialised"); }
        _ => {
            shell_println!("iotdevice — IoT/smart home device management");
            shell_println!("  discover <name> <type> <proto> <room>  Add device");
            shell_println!("  remove <id>                            Remove device");
            shell_println!("  set <id> <state>                       Set state");
            shell_println!("  online|offline <id>                    Set connectivity");
            shell_println!("  group <name> <id1,id2>                 Create group");
            shell_println!("  gcmd <group_id> <state>                Group command");
            shell_println!("  room <name>                            Devices by room");
            shell_println!("  list / groups                          List all");
            shell_println!("  stats / test / init");
        }
    }
}

fn parse_iot_device_type(s: &str) -> crate::fs::iotdevice::DeviceType {
    use crate::fs::iotdevice::DeviceType;
    match s.to_lowercase().as_str() {
        "light" | "lamp" | "bulb" => DeviceType::Light,
        "switch" => DeviceType::Switch,
        "thermostat" | "thermo" => DeviceType::Thermostat,
        "camera" | "cam" => DeviceType::Camera,
        "lock" => DeviceType::Lock,
        "speaker" | "spk" => DeviceType::Speaker,
        "sensor" => DeviceType::Sensor,
        "plug" | "outlet" => DeviceType::Plug,
        "fan" => DeviceType::Fan,
        _ => DeviceType::Other,
    }
}

fn parse_iot_protocol(s: &str) -> crate::fs::iotdevice::Protocol {
    use crate::fs::iotdevice::Protocol;
    match s.to_lowercase().as_str() {
        "wifi" | "wlan" => Protocol::Wifi,
        "bluetooth" | "bt" | "ble" => Protocol::Bluetooth,
        "zigbee" | "zb" => Protocol::Zigbee,
        "zwave" | "zw" => Protocol::Zwave,
        "thread" => Protocol::Thread,
        "matter" => Protocol::Matter,
        _ => Protocol::Wifi,
    }
}

/// `prochistory` / `phist` — process execution history.
fn cmd_prochistory(args: &str) {
    use crate::fs::prochistory;
    use alloc::format;
    let parts: Vec<&str> = args.split_whitespace().collect();
    let sub = parts.first().copied().unwrap_or("");
    match sub {
        "start" => {
            if parts.len() < 3 {
                shell_println!("Usage: prochistory start <name> <pid> [args]");
                return;
            }
            let name = parts[1];
            let pid = parts[2].parse::<u32>().unwrap_or(0);
            let pargs = if parts.len() > 3 { parts[3..].join(" ") } else { alloc::string::String::new() };
            match prochistory::record_start(name, pid, &pargs) {
                Ok(id) => shell_println!("Started #{}: {} (pid={})", id, name, pid),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "exit" => {
            if parts.len() < 3 {
                shell_println!("Usage: prochistory exit <pid> <exit_code> [reason] [mem_kb]");
                return;
            }
            let pid = parts[1].parse::<u32>().unwrap_or(0);
            let code = parts[2].parse::<i32>().unwrap_or(0);
            let reason = parts.get(3).map(|s| parse_exit_reason(s)).unwrap_or(prochistory::ExitReason::Normal);
            let mem = parts.get(4).and_then(|s| s.parse::<u64>().ok()).unwrap_or(0);
            match prochistory::record_exit(pid, code, reason, mem) {
                Ok(()) => shell_println!("Exited pid={} code={} ({})", pid, code, reason.label()),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "recent" => {
            let max = parts.get(1).and_then(|s| s.parse::<usize>().ok()).unwrap_or(10);
            let hist = prochistory::recent(max);
            if hist.is_empty() {
                shell_println!("No process history");
            } else {
                for e in &hist {
                    let status = if e.is_running() {
                        alloc::string::String::from("RUNNING")
                    } else {
                        let reason = e.exit_reason.map_or("?", |r| r.label());
                        let dur = e.duration_ms().unwrap_or(0);
                        format!("exit={} {} {}ms", e.exit_code.unwrap_or(0), reason, dur)
                    };
                    shell_println!("  #{}: {} (pid={}) — {}", e.entry_id, e.name, e.pid, status);
                }
            }
        }
        "running" => {
            let r = prochistory::running();
            if r.is_empty() {
                shell_println!("No running processes in history");
            } else {
                for e in &r {
                    shell_println!("  #{}: {} (pid={})", e.entry_id, e.name, e.pid);
                }
            }
        }
        "crashed" => {
            let max = parts.get(1).and_then(|s| s.parse::<usize>().ok()).unwrap_or(10);
            let crashes = prochistory::crashed(max);
            if crashes.is_empty() {
                shell_println!("No crashes recorded");
            } else {
                for e in &crashes {
                    let reason = e.exit_reason.map_or("?", |r| r.label());
                    shell_println!("  #{}: {} (pid={}) — {} (exit={} mem={}KB)", e.entry_id, e.name, e.pid, reason, e.exit_code.unwrap_or(-1), e.peak_memory_kb);
                }
            }
        }
        "search" => {
            if let Some(q) = parts.get(1) {
                let results = prochistory::search(q);
                if results.is_empty() {
                    shell_println!("No processes matching '{}'", q);
                } else {
                    for e in &results {
                        let status = if e.is_running() { "RUNNING" } else { "exited" };
                        shell_println!("  #{}: {} (pid={}) — {}", e.entry_id, e.name, e.pid, status);
                    }
                }
            } else { shell_println!("Usage: prochistory search <query>"); }
        }
        "stats" => {
            let (size, started, exited, crashed, ops) = prochistory::stats();
            shell_println!("Process History: {} entries", size);
            shell_println!("  Started: {} | Exited: {} | Crashed: {} | Ops: {}", started, exited, crashed, ops);
        }
        "test" => { prochistory::self_test(); shell_println!("prochistory self-test complete"); }
        "init" => { prochistory::init_defaults(); shell_println!("prochistory initialised"); }
        _ => {
            shell_println!("prochistory — process execution history");
            shell_println!("  start <name> <pid> [args]          Record start");
            shell_println!("  exit <pid> <code> [reason] [mem]   Record exit");
            shell_println!("  recent [n]                         Recent history");
            shell_println!("  running                            Running processes");
            shell_println!("  crashed [n]                        Crash history");
            shell_println!("  search <query>                     Search by name");
            shell_println!("  stats / test / init");
        }
    }
}

fn parse_exit_reason(s: &str) -> crate::fs::prochistory::ExitReason {
    use crate::fs::prochistory::ExitReason;
    match s.to_lowercase().as_str() {
        "normal" | "ok" => ExitReason::Normal,
        "crashed" | "crash" => ExitReason::Crashed,
        "killed" | "kill" => ExitReason::Killed,
        "timeout" => ExitReason::Timeout,
        "oom" | "outofmemory" => ExitReason::OutOfMemory,
        _ => ExitReason::Unknown,
    }
}

/// `notiffilter` / `nfilter` — notification filtering rules.
fn cmd_notiffilter(args: &str) {
    use crate::fs::notiffilter;
    use alloc::string::String;
    let parts: Vec<&str> = args.split_whitespace().collect();
    let sub = parts.first().copied().unwrap_or("");
    match sub {
        "add" => {
            if parts.len() < 4 {
                shell_println!("Usage: notiffilter add <name> <field> <pattern> <action>");
                return;
            }
            let field = parse_match_field(parts[2]);
            let pattern = parts[3];
            let action = parts.get(4).map(|s| parse_filter_action(s)).unwrap_or(notiffilter::FilterAction::Block);
            match notiffilter::add_rule(parts[1], field, pattern, action) {
                Ok(id) => shell_println!("Rule #{}: {} on {} matching '{}' → {}", id, parts[1], field.label(), pattern, action.label()),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "remove" => {
            if let Some(id_s) = parts.get(1) {
                if let Ok(id) = id_s.parse::<u32>() {
                    match notiffilter::remove_rule(id) {
                        Ok(()) => shell_println!("Removed rule #{}", id),
                        Err(e) => shell_println!("Error: {:?}", e),
                    }
                } else { shell_println!("Invalid rule ID"); }
            } else { shell_println!("Usage: notiffilter remove <id>"); }
        }
        "enable" | "disable" => {
            if let Some(id_s) = parts.get(1) {
                if let Ok(id) = id_s.parse::<u32>() {
                    let on = sub == "enable";
                    match notiffilter::set_enabled(id, on) {
                        Ok(()) => shell_println!("Rule #{}: {}", id, if on { "ENABLED" } else { "DISABLED" }),
                        Err(e) => shell_println!("Error: {:?}", e),
                    }
                } else { shell_println!("Invalid rule ID"); }
            } else { shell_println!("Usage: notiffilter enable|disable <id>"); }
        }
        "eval" | "test-eval" => {
            if parts.len() < 5 {
                shell_println!("Usage: notiffilter eval <app> <category> <title> <body>");
                return;
            }
            let notif = notiffilter::NotifData {
                app_name: String::from(parts[1]),
                category: String::from(parts[2]),
                title: String::from(parts[3]),
                body: if parts.len() > 4 { parts[4..].join(" ") } else { String::new() },
                priority: String::from("normal"),
            };
            match notiffilter::evaluate(&notif) {
                Ok(action) => shell_println!("Result: {}", action.label()),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "list" => {
            let rules = notiffilter::list_rules();
            if rules.is_empty() {
                shell_println!("No filter rules");
            } else {
                for r in &rules {
                    let en = if r.enabled { "ON" } else { "OFF" };
                    shell_println!("  #{}: {} [{}] {} contains '{}' → {} (hits={})", r.id, r.name, en, r.field.label(), r.pattern, r.action.label(), r.hit_count);
                }
            }
        }
        "stats" => {
            let (rules, evaluated, allowed, blocked, silenced, ops) = notiffilter::stats();
            shell_println!("Notification Filter: {} rules", rules);
            shell_println!("  Evaluated: {} | Allowed: {} | Blocked: {} | Silenced: {} | Ops: {}", evaluated, allowed, blocked, silenced, ops);
        }
        "test" => { notiffilter::self_test(); shell_println!("notiffilter self-test complete"); }
        "init" => { notiffilter::init_defaults(); shell_println!("notiffilter initialised"); }
        _ => {
            shell_println!("notiffilter — notification filtering rules");
            shell_println!("  add <name> <field> <pattern> <action>  Add rule");
            shell_println!("  remove <id>                            Remove rule");
            shell_println!("  enable|disable <id>                    Toggle rule");
            shell_println!("  eval <app> <cat> <title> <body>        Test evaluation");
            shell_println!("  list                                   List rules");
            shell_println!("  stats / test / init");
        }
    }
}

fn parse_match_field(s: &str) -> crate::fs::notiffilter::MatchField {
    use crate::fs::notiffilter::MatchField;
    match s.to_lowercase().as_str() {
        "app" | "appname" => MatchField::AppName,
        "category" | "cat" => MatchField::Category,
        "title" => MatchField::Title,
        "body" => MatchField::Body,
        "priority" | "pri" => MatchField::Priority,
        _ => MatchField::Title,
    }
}

fn parse_filter_action(s: &str) -> crate::fs::notiffilter::FilterAction {
    use crate::fs::notiffilter::FilterAction;
    match s.to_lowercase().as_str() {
        "allow" => FilterAction::Allow,
        "silence" | "mute" => FilterAction::Silence,
        "block" | "deny" => FilterAction::Block,
        "redirect" => FilterAction::Redirect,
        "defer" => FilterAction::Defer,
        _ => FilterAction::Block,
    }
}

/// `colorblind` / `cvd` — color blindness accessibility filters.
fn cmd_colorblind(args: &str) {
    use crate::fs::colorblind;
    let parts: Vec<&str> = args.split_whitespace().collect();
    let sub = parts.first().copied().unwrap_or("");
    match sub {
        "enable" | "on" => {
            match colorblind::set_enabled(true) {
                Ok(()) => shell_println!("Color blindness filter enabled"),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "disable" | "off" => {
            match colorblind::set_enabled(false) {
                Ok(()) => shell_println!("Color blindness filter disabled"),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "type" | "set" => {
            if let Some(t) = parts.get(1) {
                let cvd = parse_cvd_type(t);
                match colorblind::set_type(cvd) {
                    Ok(()) => shell_println!("Filter type: {}", cvd.label()),
                    Err(e) => shell_println!("Error: {:?}", e),
                }
            } else {
                shell_println!("Usage: colorblind type <protan|deutan|tritan|...>");
            }
        }
        "intensity" => {
            if let Some(v) = parts.get(1) {
                if let Ok(val) = v.parse::<u32>() {
                    match colorblind::set_intensity(val) {
                        Ok(()) => shell_println!("Intensity: {}%", val),
                        Err(e) => shell_println!("Error: {:?}", e),
                    }
                } else { shell_println!("Invalid value (0-100)"); }
            } else {
                let (_, _, intensity, _) = colorblind::current();
                shell_println!("Intensity: {}%", intensity);
            }
        }
        "simulate" => {
            if let Some(v) = parts.get(1) {
                let on = *v == "on" || *v == "true";
                match colorblind::set_simulate(on) {
                    Ok(()) => shell_println!("Simulation mode: {}", if on { "ON" } else { "OFF" }),
                    Err(e) => shell_println!("Error: {:?}", e),
                }
            } else { shell_println!("Usage: colorblind simulate <on|off>"); }
        }
        "preset" => {
            if let Some(id_s) = parts.get(1) {
                if let Ok(id) = id_s.parse::<u32>() {
                    match colorblind::apply_preset(id) {
                        Ok(()) => shell_println!("Applied preset #{}", id),
                        Err(e) => shell_println!("Error: {:?}", e),
                    }
                } else { shell_println!("Invalid preset ID"); }
            } else { shell_println!("Usage: colorblind preset <id>"); }
        }
        "presets" => {
            let presets = colorblind::list_presets();
            for p in &presets {
                shell_println!("  #{}: {} [{}] intensity={} — {}", p.id, p.name, p.cvd_type.short_label(), p.intensity, p.description);
            }
        }
        "status" => {
            let (en, cvd, intensity, sim) = colorblind::current();
            shell_println!("Color blindness filter: {}", if en { "ENABLED" } else { "DISABLED" });
            shell_println!("  Type: {} | Intensity: {}% | Simulate: {}", cvd.label(), intensity, if sim { "ON" } else { "OFF" });
        }
        "stats" => {
            let (presets, activations, changes, ops) = colorblind::stats();
            shell_println!("Color Blindness: {} presets", presets);
            shell_println!("  Activations: {} | Changes: {} | Ops: {}", activations, changes, ops);
        }
        "test" => { colorblind::self_test(); shell_println!("colorblind self-test complete"); }
        "init" => { colorblind::init_defaults(); shell_println!("colorblind initialised"); }
        _ => {
            shell_println!("colorblind — color blindness accessibility filters");
            shell_println!("  enable / disable             Toggle filter");
            shell_println!("  type <cvd_type>              Set filter type");
            shell_println!("  intensity [0-100]            Set/show intensity");
            shell_println!("  simulate <on|off>            Toggle simulation");
            shell_println!("  preset <id>                  Apply preset");
            shell_println!("  presets                      List presets");
            shell_println!("  status                       Show current state");
            shell_println!("  stats / test / init");
        }
    }
}

fn parse_cvd_type(s: &str) -> crate::fs::colorblind::CvdType {
    use crate::fs::colorblind::CvdType;
    match s.to_lowercase().as_str() {
        "none" | "off" => CvdType::None,
        "protan" | "protanopia" => CvdType::Protanopia,
        "deutan" | "deuteranopia" => CvdType::Deuteranopia,
        "tritan" | "tritanopia" => CvdType::Tritanopia,
        "protanomaly" => CvdType::Protanomaly,
        "deuteranomaly" => CvdType::Deuteranomaly,
        "tritanomaly" => CvdType::Tritanomaly,
        "achromat" | "achromatopsia" | "grayscale" => CvdType::Achromatopsia,
        "custom" => CvdType::Custom,
        _ => CvdType::None,
    }
}

/// `clipaction` / `caction` — clipboard quick actions.
fn cmd_clipaction(args: &str) {
    use crate::fs::clipaction;
    let parts: Vec<&str> = args.split_whitespace().collect();
    let sub = parts.first().copied().unwrap_or("");
    match sub {
        "detect" => {
            let text = if parts.len() > 1 { parts[1..].join(" ") } else { shell_println!("Usage: clipaction detect <text>"); return; };
            let ct = clipaction::detect_type(&text);
            shell_println!("Detected: {} → {}", text, ct.label());
        }
        "actions" => {
            let ct = if let Some(t) = parts.get(1) {
                parse_clip_content_type(t)
            } else { shell_println!("Usage: clipaction actions <type>"); return; };
            let actions = clipaction::get_actions(ct);
            if actions.is_empty() {
                shell_println!("No actions for type '{}'", ct.label());
            } else {
                shell_println!("Actions for {}:", ct.label());
                for a in &actions {
                    shell_println!("  [{}] {} → {}", a.id, a.name, a.command);
                }
            }
        }
        "exec" => {
            let id: u32 = match parts.get(1).and_then(|s| s.parse().ok()) {
                Some(v) => v,
                None => { shell_println!("Usage: clipaction exec <id>"); return; }
            };
            match clipaction::execute_action(id) {
                Ok(cmd) => shell_println!("Executed action {} → command: {}", id, cmd),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "add" => {
            if parts.len() < 4 {
                shell_println!("Usage: clipaction add <name> <type> <command>");
                return;
            }
            let name = parts[1];
            let ct = parse_clip_content_type(parts[2]);
            let command = parts[3..].join(" ");
            match clipaction::add_action(name, ct, &command) {
                Ok(id) => shell_println!("Added action {} (id={})", name, id),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "remove" => {
            let id: u32 = match parts.get(1).and_then(|s| s.parse().ok()) {
                Some(v) => v,
                None => { shell_println!("Usage: clipaction remove <id>"); return; }
            };
            match clipaction::remove_action(id) {
                Ok(()) => shell_println!("Removed action {}", id),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "list" => {
            let actions = clipaction::list_actions();
            if actions.is_empty() {
                shell_println!("No actions registered");
            } else {
                shell_println!("{} action(s):", actions.len());
                for a in &actions {
                    let status = if a.enabled { "on" } else { "off" };
                    shell_println!("  [{}] {} ({}) → {} [{}] uses={}", a.id, a.name, a.content_type.label(), a.command, status, a.use_count);
                }
            }
        }
        "stats" => {
            let (action_count, detections, executions, ops) = clipaction::stats();
            shell_println!("Clipboard Actions: actions={} detections={} executions={} ops={}", action_count, detections, executions, ops);
        }
        "init" => { clipaction::init_defaults(); shell_println!("Clipboard actions initialized"); }
        "test" => clipaction::self_test(),
        _ => {
            shell_println!("Usage: clipaction <detect|actions|exec|add|remove|list|stats|init|test>");
            shell_println!("Aliases: caction");
        }
    }
}

fn parse_clip_content_type(s: &str) -> crate::fs::clipaction::ContentType {
    use crate::fs::clipaction::ContentType;
    match s.to_lowercase().as_str() {
        "url" => ContentType::Url,
        "email" => ContentType::Email,
        "phone" => ContentType::PhoneNumber,
        "path" | "filepath" => ContentType::FilePath,
        "color" => ContentType::Color,
        "code" => ContentType::Code,
        "json" => ContentType::Json,
        "text" | "plain" => ContentType::PlainText,
        "number" | "num" => ContentType::Number,
        "date" => ContentType::Date,
        _ => ContentType::PlainText,
    }
}

/// `energysaver` / `esaver` — system power optimization.
fn cmd_energysaver(args: &str) {
    use crate::fs::energysaver;
    let parts: Vec<&str> = args.split_whitespace().collect();
    let sub = parts.first().copied().unwrap_or("");
    match sub {
        "mode" => {
            if let Some(m) = parts.get(1) {
                let mode = parse_energy_mode(m);
                match energysaver::set_mode(mode) {
                    Ok(()) => shell_println!("Energy mode set to {}", mode.label()),
                    Err(e) => shell_println!("Error: {:?}", e),
                }
            } else {
                let mode = energysaver::get_mode();
                shell_println!("Current mode: {}", mode.label());
            }
        }
        "profile" => {
            match energysaver::get_profile() {
                Some(p) => {
                    shell_println!("Energy Profile ({}):", p.mode.label());
                    shell_println!("  Brightness: {}%", p.display_brightness_pct);
                    shell_println!("  Display timeout: {}s", p.display_timeout_sec);
                    shell_println!("  CPU max freq: {}%", p.cpu_max_freq_pct);
                    shell_println!("  WiFi power save: {}", p.wifi_power_save);
                    shell_println!("  Bluetooth off: {}", p.bluetooth_off);
                    shell_println!("  Reduce animations: {}", p.reduce_animations);
                    shell_println!("  Background app limit: {}", p.background_app_limit);
                }
                None => shell_println!("Energy saver not initialized"),
            }
        }
        "brightness" => {
            let pct: u32 = match parts.get(1).and_then(|s| s.parse().ok()) {
                Some(v) => v,
                None => { shell_println!("Usage: energysaver brightness <0-100>"); return; }
            };
            match energysaver::set_brightness(pct) {
                Ok(()) => shell_println!("Brightness set to {}%", pct.min(100)),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "cpulimit" => {
            let pct: u32 = match parts.get(1).and_then(|s| s.parse().ok()) {
                Some(v) => v,
                None => { shell_println!("Usage: energysaver cpulimit <0-100>"); return; }
            };
            match energysaver::set_cpu_limit(pct) {
                Ok(()) => shell_println!("CPU limit set to {}%", pct.min(100)),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "throttle" => {
            if parts.len() < 3 {
                shell_println!("Usage: energysaver throttle <app> <cpu_limit_pct>");
                return;
            }
            let name = parts[1];
            let limit: u32 = match parts[2].parse() {
                Ok(v) => v,
                Err(_) => { shell_println!("Invalid CPU limit"); return; }
            };
            match energysaver::throttle_app(name, limit) {
                Ok(()) => shell_println!("Throttled '{}' to {}% CPU", name, limit),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "unthrottle" => {
            let name = match parts.get(1) {
                Some(n) => *n,
                None => { shell_println!("Usage: energysaver unthrottle <app>"); return; }
            };
            match energysaver::unthrottle_app(name) {
                Ok(()) => shell_println!("Unthrottled '{}'", name),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "throttled" => {
            let apps = energysaver::list_throttled();
            if apps.is_empty() {
                shell_println!("No throttled apps");
            } else {
                shell_println!("{} throttled app(s):", apps.len());
                for a in &apps {
                    shell_println!("  {} — CPU {}%, net={}, bg={}", a.name, a.cpu_limit_pct, a.network_allowed, a.background_allowed);
                }
            }
        }
        "estimate" => {
            if let Some(min) = parts.get(1).and_then(|s| s.parse::<u64>().ok()) {
                match energysaver::set_estimate(min) {
                    Ok(()) => shell_println!("Battery estimate set to {} min", min),
                    Err(e) => shell_println!("Error: {:?}", e),
                }
            } else {
                let (_, _, _, est, _) = energysaver::stats();
                shell_println!("Estimated battery: {} min", est);
            }
        }
        "autoswitch" => {
            if parts.len() < 3 {
                shell_println!("Usage: energysaver autoswitch <on|off> <threshold_%>");
                return;
            }
            let enabled = parts[1] == "on";
            let thresh: u32 = parts.get(2).and_then(|s| s.parse().ok()).unwrap_or(20);
            match energysaver::set_auto_switch(enabled, thresh) {
                Ok(()) => shell_println!("Auto-switch: {} at {}%", if enabled { "on" } else { "off" }, thresh),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "stats" => {
            let (throttled, mode_changes, total_throttles, est, ops) = energysaver::stats();
            shell_println!("Energy Saver: throttled={} mode_changes={} throttles={} est_min={} ops={}", throttled, mode_changes, total_throttles, est, ops);
        }
        "init" => { energysaver::init_defaults(); shell_println!("Energy saver initialized"); }
        "test" => energysaver::self_test(),
        _ => {
            shell_println!("Usage: energysaver <mode|profile|brightness|cpulimit|throttle|unthrottle|throttled|estimate|autoswitch|stats|init|test>");
            shell_println!("Aliases: esaver");
        }
    }
}

fn parse_energy_mode(s: &str) -> crate::fs::energysaver::EnergyMode {
    use crate::fs::energysaver::EnergyMode;
    match s.to_lowercase().as_str() {
        "performance" | "perf" => EnergyMode::Performance,
        "balanced" | "bal" => EnergyMode::Balanced,
        "powersaver" | "saver" => EnergyMode::PowerSaver,
        "ultrasaver" | "ultra" => EnergyMode::UltraSaver,
        "custom" => EnergyMode::Custom,
        _ => EnergyMode::Balanced,
    }
}

/// `filerules` / `frules` — automatic file organization rules.
fn cmd_filerules(args: &str) {
    use crate::fs::filerules;
    let parts: Vec<&str> = args.split_whitespace().collect();
    let sub = parts.first().copied().unwrap_or("");
    match sub {
        "list" => {
            let rules = filerules::list_rules();
            if rules.is_empty() {
                shell_println!("No file rules");
            } else {
                shell_println!("{} rule(s):", rules.len());
                for r in &rules {
                    let status = if r.enabled { "on" } else { "off" };
                    shell_println!("  [{}] {} — {} '{}' → {} '{}' [{}] hits={}", r.id, r.name, r.condition.label(), r.pattern, r.action.label(), r.action_param, status, r.hit_count);
                }
            }
        }
        "add" => {
            if parts.len() < 5 {
                shell_println!("Usage: filerules add <name> <condition> <pattern> <action> [param]");
                return;
            }
            let name = parts[1];
            let cond = parse_filerule_condition(parts[2]);
            let pattern = parts[3];
            let action = parse_filerule_action(parts[4]);
            let param = if parts.len() > 5 { parts[5..].join(" ") } else { alloc::string::String::new() };
            match filerules::add_rule(name, cond, pattern, action, &param) {
                Ok(id) => shell_println!("Added rule '{}' (id={})", name, id),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "remove" => {
            let id: u32 = match parts.get(1).and_then(|s| s.parse().ok()) {
                Some(v) => v,
                None => { shell_println!("Usage: filerules remove <id>"); return; }
            };
            match filerules::remove_rule(id) {
                Ok(()) => shell_println!("Removed rule {}", id),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "enable" | "disable" => {
            let id: u32 = match parts.get(1).and_then(|s| s.parse().ok()) {
                Some(v) => v,
                None => { shell_println!("Usage: filerules {} <id>", sub); return; }
            };
            let enabled = sub == "enable";
            match filerules::set_enabled(id, enabled) {
                Ok(()) => shell_println!("Rule {} {}", id, if enabled { "enabled" } else { "disabled" }),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "eval" => {
            if parts.len() < 5 {
                shell_println!("Usage: filerules eval <filename> <ext> <size> <dir>");
                return;
            }
            let filename = parts[1];
            let ext = parts[2];
            let size: u64 = parts.get(3).and_then(|s| s.parse().ok()).unwrap_or(0);
            let dir = parts.get(4).copied().unwrap_or("/");
            match filerules::evaluate(filename, ext, size, dir) {
                Ok(matches) => {
                    if matches.is_empty() {
                        shell_println!("No rules matched");
                    } else {
                        shell_println!("{} rule(s) matched:", matches.len());
                        for (id, action, param) in &matches {
                            shell_println!("  Rule {} → {} '{}'", id, action.label(), param);
                        }
                    }
                }
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "stats" => {
            let (rules, evals, matches, applied, ops) = filerules::stats();
            shell_println!("File Rules: rules={} evals={} matches={} applied={} ops={}", rules, evals, matches, applied, ops);
        }
        "init" => { filerules::init_defaults(); shell_println!("File rules initialized"); }
        "test" => filerules::self_test(),
        _ => {
            shell_println!("Usage: filerules <list|add|remove|enable|disable|eval|stats|init|test>");
            shell_println!("Aliases: frules");
        }
    }
}

fn parse_filerule_condition(s: &str) -> crate::fs::filerules::MatchCondition {
    use crate::fs::filerules::MatchCondition;
    match s.to_lowercase().as_str() {
        "ext" | "extension" => MatchCondition::ExtensionIs,
        "contains" | "namecontains" => MatchCondition::NameContains,
        "startswith" | "namestarts" => MatchCondition::NameStartsWith,
        "sizegt" | "sizegreater" => MatchCondition::SizeGreaterThan,
        "sizelt" | "sizeless" => MatchCondition::SizeLessThan,
        "indir" | "indirectory" => MatchCondition::InDirectory,
        "any" | "anyfile" => MatchCondition::AnyFile,
        _ => MatchCondition::AnyFile,
    }
}

fn parse_filerule_action(s: &str) -> crate::fs::filerules::RuleAction {
    use crate::fs::filerules::RuleAction;
    match s.to_lowercase().as_str() {
        "move" | "moveto" => RuleAction::MoveTo,
        "copy" | "copyto" => RuleAction::CopyTo,
        "rename" => RuleAction::Rename,
        "tag" | "addtag" => RuleAction::AddTag,
        "perm" | "permission" => RuleAction::SetPermission,
        "compress" | "zip" => RuleAction::Compress,
        "delete" | "del" => RuleAction::Delete,
        "notify" => RuleAction::Notify,
        _ => RuleAction::Notify,
    }
}

/// `secureboot` / `sboot` — secure boot verification and key management.
fn cmd_secureboot(args: &str) {
    use crate::fs::secureboot;
    use crate::fs::secureboot::BootState;
    let parts: Vec<&str> = args.split_whitespace().collect();
    let sub = parts.first().copied().unwrap_or("");
    match sub {
        "status" => {
            let state = secureboot::get_state();
            shell_println!("Secure Boot: {}", state.label());
            let keys = secureboot::list_keys();
            shell_println!("Enrolled keys: {}", keys.len());
            for k in &keys {
                shell_println!("  [{}] {} ({}) — {}", k.id, k.subject, k.key_type.label(), k.fingerprint);
            }
        }
        "set" => {
            let state = match parts.get(1).map(|s| s.to_lowercase()).as_deref() {
                Some("disabled" | "off") => BootState::Disabled,
                Some("setup") => BootState::SetupMode,
                Some("enabled" | "on") => BootState::Enabled,
                Some("strict") => BootState::EnforcingStrict,
                _ => { shell_println!("Usage: secureboot set <disabled|setup|enabled|strict>"); return; }
            };
            match secureboot::set_state(state) {
                Ok(()) => shell_println!("Secure boot state set to {}", state.label()),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "enroll" => {
            if parts.len() < 4 {
                shell_println!("Usage: secureboot enroll <type> <subject> <fingerprint>");
                return;
            }
            let kt = parse_sboot_key_type(parts[1]);
            let subject = parts[2];
            let fp = parts[3];
            match secureboot::enroll_key(kt, subject, fp) {
                Ok(id) => shell_println!("Enrolled key '{}' (id={})", subject, id),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "remove" => {
            let id: u32 = match parts.get(1).and_then(|s| s.parse().ok()) {
                Some(v) => v,
                None => { shell_println!("Usage: secureboot remove <id>"); return; }
            };
            match secureboot::remove_key(id) {
                Ok(()) => shell_println!("Removed key {}", id),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "verify" => {
            if parts.len() < 3 {
                shell_println!("Usage: secureboot verify <image_name> <hash>");
                return;
            }
            let image = parts[1];
            let hash = parts[2];
            match secureboot::verify_image(image, hash) {
                Ok(true) => shell_println!("Image '{}' verified OK", image),
                Ok(false) => shell_println!("Image '{}' REJECTED", image),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "keys" => {
            let keys = secureboot::list_keys();
            if keys.is_empty() {
                shell_println!("No enrolled keys");
            } else {
                shell_println!("{} key(s):", keys.len());
                for k in &keys {
                    shell_println!("  [{}] {} ({}) — {}", k.id, k.subject, k.key_type.label(), k.fingerprint);
                }
            }
        }
        "records" => {
            let max: usize = parts.get(1).and_then(|s| s.parse().ok()).unwrap_or(10);
            let records = secureboot::get_records(max);
            if records.is_empty() {
                shell_println!("No verification records");
            } else {
                shell_println!("{} record(s):", records.len());
                for r in &records {
                    let status = if r.verified { "OK" } else { "REJECTED" };
                    shell_println!("  {} [{}] hash={} key={:?}", r.image_name, status, r.hash, r.key_id);
                }
            }
        }
        "stats" => {
            let (keys, records, verified, rejected, ops) = secureboot::stats();
            shell_println!("Secure Boot: keys={} records={} verified={} rejected={} ops={}", keys, records, verified, rejected, ops);
        }
        "init" => { secureboot::init_defaults(); shell_println!("Secure boot initialized"); }
        "test" => secureboot::self_test(),
        _ => {
            shell_println!("Usage: secureboot <status|set|enroll|remove|verify|keys|records|stats|init|test>");
            shell_println!("Aliases: sboot");
        }
    }
}

fn parse_sboot_key_type(s: &str) -> crate::fs::secureboot::KeyType {
    use crate::fs::secureboot::KeyType;
    match s.to_lowercase().as_str() {
        "pk" | "platform" => KeyType::PlatformKey,
        "kek" | "exchange" => KeyType::KeyExchangeKey,
        "db" | "signature" => KeyType::SignatureDatabase,
        "dbx" | "forbidden" => KeyType::ForbiddenSignature,
        "mok" | "owner" => KeyType::MachineOwnerKey,
        _ => KeyType::MachineOwnerKey,
    }
}

/// `eventlog` / `elog` — centralized system event logging.
fn cmd_eventlog(args: &str) {
    use crate::fs::eventlog;
    let parts: Vec<&str> = args.split_whitespace().collect();
    let sub = parts.first().copied().unwrap_or("");
    match sub {
        "log" => {
            if parts.len() < 4 {
                shell_println!("Usage: eventlog log <severity> <category> <source> [message...]");
                return;
            }
            let sev = parse_event_severity(parts[1]);
            let cat = parse_event_category(parts[2]);
            let source = parts[3];
            let msg = if parts.len() > 4 { parts[4..].join(" ") } else { String::from("(no message)") };
            match eventlog::log_event(sev, cat, source, &msg) {
                Ok(id) => shell_println!("Logged event #{} [{}] {}: {}", id, sev.label(), source, msg),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "recent" => {
            let max: usize = parts.get(1).and_then(|s| s.parse().ok()).unwrap_or(10);
            let events = eventlog::recent(max);
            if events.is_empty() {
                shell_println!("No events");
            } else {
                for e in &events {
                    shell_println!("  #{} [{}] {} ({}): {}", e.id, e.severity.label(), e.source, e.category.label(), e.message);
                }
            }
        }
        "errors" => {
            let max: usize = parts.get(1).and_then(|s| s.parse().ok()).unwrap_or(20);
            let events = eventlog::query_by_severity(crate::fs::eventlog::Severity::Error, max);
            if events.is_empty() {
                shell_println!("No errors");
            } else {
                shell_println!("{} error(s):", events.len());
                for e in &events {
                    shell_println!("  #{} [{}] {}: {}", e.id, e.severity.label(), e.source, e.message);
                }
            }
        }
        "source" => {
            let src = match parts.get(1) {
                Some(s) => *s,
                None => { shell_println!("Usage: eventlog source <name>"); return; }
            };
            let max: usize = parts.get(2).and_then(|s| s.parse().ok()).unwrap_or(20);
            let events = eventlog::query_by_source(src, max);
            if events.is_empty() {
                shell_println!("No events from '{}'", src);
            } else {
                for e in &events {
                    shell_println!("  #{} [{}] {}: {}", e.id, e.severity.label(), e.source, e.message);
                }
            }
        }
        "category" => {
            let cat = match parts.get(1) {
                Some(c) => parse_event_category(c),
                None => { shell_println!("Usage: eventlog category <name>"); return; }
            };
            let max: usize = parts.get(2).and_then(|s| s.parse().ok()).unwrap_or(20);
            let events = eventlog::query_by_category(cat, max);
            if events.is_empty() {
                shell_println!("No events in category '{}'", cat.label());
            } else {
                for e in &events {
                    shell_println!("  #{} [{}] {}: {}", e.id, e.severity.label(), e.source, e.message);
                }
            }
        }
        "clear" => {
            if let Some(src) = parts.get(1) {
                match eventlog::clear_source(src) {
                    Ok(n) => shell_println!("Cleared {} events from '{}'", n, src),
                    Err(e) => shell_println!("Error: {:?}", e),
                }
            } else {
                match eventlog::clear_all() {
                    Ok(n) => shell_println!("Cleared {} events", n),
                    Err(e) => shell_println!("Error: {:?}", e),
                }
            }
        }
        "counts" => {
            let c = eventlog::severity_counts();
            shell_println!("Severity counts: DEBUG={} INFO={} WARN={} ERROR={} CRIT={}", c[0], c[1], c[2], c[3], c[4]);
        }
        "stats" => {
            let (count, logged, cleared, queries, ops) = eventlog::stats();
            shell_println!("Event Log: events={} logged={} cleared={} queries={} ops={}", count, logged, cleared, queries, ops);
        }
        "init" => { eventlog::init_defaults(); shell_println!("Event log initialized"); }
        "test" => eventlog::self_test(),
        _ => {
            shell_println!("Usage: eventlog <log|recent|errors|source|category|clear|counts|stats|init|test>");
            shell_println!("Aliases: elog");
        }
    }
}

fn parse_event_severity(s: &str) -> crate::fs::eventlog::Severity {
    use crate::fs::eventlog::Severity;
    match s.to_lowercase().as_str() {
        "debug" | "dbg" => Severity::Debug,
        "info" => Severity::Info,
        "warning" | "warn" => Severity::Warning,
        "error" | "err" => Severity::Error,
        "critical" | "crit" => Severity::Critical,
        _ => Severity::Info,
    }
}

fn parse_event_category(s: &str) -> crate::fs::eventlog::EventCategory {
    use crate::fs::eventlog::EventCategory;
    match s.to_lowercase().as_str() {
        "system" | "sys" => EventCategory::System,
        "security" | "sec" => EventCategory::Security,
        "application" | "app" => EventCategory::Application,
        "hardware" | "hw" => EventCategory::Hardware,
        "network" | "net" => EventCategory::Network,
        "storage" | "stor" => EventCategory::Storage,
        "driver" | "drv" => EventCategory::Driver,
        "service" | "svc" => EventCategory::Service,
        _ => EventCategory::System,
    }
}

/// `systemimage` / `simg` — system image snapshot management.
fn cmd_systemimage(args: &str) {
    use crate::fs::systemimage;
    use alloc::format;
    let parts: Vec<&str> = args.split_whitespace().collect();
    let sub = parts.first().copied().unwrap_or("");
    match sub {
        "list" => {
            let images = systemimage::list_images();
            if images.is_empty() {
                shell_println!("No system images");
            } else {
                shell_println!("{} image(s):", images.len());
                for img in &images {
                    let base = img.base_image_id.map_or(String::from("-"), |b| format!("{}", b));
                    shell_println!("  [{}] {} ({}) [{}] {}B base={}", img.id, img.name, img.image_type.label(), img.status.label(), img.size_bytes, base);
                }
            }
        }
        "create" => {
            if parts.len() < 3 {
                shell_println!("Usage: systemimage create <name> <type> [description] [size] [base_id]");
                return;
            }
            let name = parts[1];
            let itype = parse_image_type(parts[2]);
            let desc = if parts.len() > 3 { parts[3..].join(" ") } else { String::from("System image") };
            let size: u64 = parts.get(4).and_then(|s| s.parse().ok()).unwrap_or(1_000_000_000);
            let base: Option<u32> = parts.get(5).and_then(|s| s.parse().ok());
            match systemimage::create_image(name, itype, &desc, size, base) {
                Ok(id) => shell_println!("Created image '{}' (id={})", name, id),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "delete" => {
            let id: u32 = match parts.get(1).and_then(|s| s.parse().ok()) {
                Some(v) => v,
                None => { shell_println!("Usage: systemimage delete <id>"); return; }
            };
            match systemimage::delete_image(id) {
                Ok(()) => shell_println!("Deleted image {}", id),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "restore" => {
            let id: u32 = match parts.get(1).and_then(|s| s.parse().ok()) {
                Some(v) => v,
                None => { shell_println!("Usage: systemimage restore <id>"); return; }
            };
            match systemimage::restore_image(id) {
                Ok(()) => shell_println!("Restored from image {}", id),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "verify" => {
            let id: u32 = match parts.get(1).and_then(|s| s.parse().ok()) {
                Some(v) => v,
                None => { shell_println!("Usage: systemimage verify <id>"); return; }
            };
            match systemimage::verify_image(id) {
                Ok(true) => shell_println!("Image {} verified OK", id),
                Ok(false) => shell_println!("Image {} CORRUPTED", id),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "info" => {
            let id: u32 = match parts.get(1).and_then(|s| s.parse().ok()) {
                Some(v) => v,
                None => { shell_println!("Usage: systemimage info <id>"); return; }
            };
            match systemimage::get_image(id) {
                Some(img) => {
                    shell_println!("Image #{}: {}", img.id, img.name);
                    shell_println!("  Type: {}", img.image_type.label());
                    shell_println!("  Status: {}", img.status.label());
                    shell_println!("  Size: {} bytes", img.size_bytes);
                    shell_println!("  Description: {}", img.description);
                    shell_println!("  Checksum: {}", img.checksum);
                    if let Some(base) = img.base_image_id {
                        shell_println!("  Base image: {}", base);
                    }
                }
                None => shell_println!("Image {} not found", id),
            }
        }
        "stats" => {
            let (count, created, restored, verified, bytes, ops) = systemimage::stats();
            shell_println!("System Image: images={} created={} restored={} verified={} bytes={} ops={}", count, created, restored, verified, bytes, ops);
        }
        "init" => { systemimage::init_defaults(); shell_println!("System image initialized"); }
        "test" => systemimage::self_test(),
        _ => {
            shell_println!("Usage: systemimage <list|create|delete|restore|verify|info|stats|init|test>");
            shell_println!("Aliases: simg");
        }
    }
}

fn parse_image_type(s: &str) -> crate::fs::systemimage::ImageType {
    use crate::fs::systemimage::ImageType;
    match s.to_lowercase().as_str() {
        "full" => ImageType::Full,
        "incremental" | "inc" => ImageType::Incremental,
        "differential" | "diff" => ImageType::Differential,
        "boot" | "bootpart" => ImageType::BootPartition,
        "userdata" | "user" => ImageType::UserData,
        _ => ImageType::Full,
    }
}

/// `raidmgr` / `raid` — software RAID array management.
fn cmd_raidmgr(args: &str) {
    use crate::fs::raidmgr;
    let parts: Vec<&str> = args.split_whitespace().collect();
    let sub = parts.first().copied().unwrap_or("");
    match sub {
        "list" => {
            let arrays = raidmgr::list_arrays();
            if arrays.is_empty() {
                shell_println!("No RAID arrays");
            } else {
                shell_println!("{} array(s):", arrays.len());
                for a in &arrays {
                    shell_println!("  [{}] {} ({}) [{}] disks={} usable={}B stripe={}KB",
                        a.id, a.name, a.level.label(), a.status.label(),
                        a.disks.len(), a.usable_bytes, a.stripe_size_kb);
                }
            }
        }
        "create" => {
            if parts.len() < 4 {
                shell_println!("Usage: raidmgr create <name> <level> <disk1,disk2,...> [disk_size] [stripe_kb]");
                return;
            }
            let name = parts[1];
            let level = parse_raid_level(parts[2]);
            let disk_ids: Vec<&str> = parts[3].split(',').collect();
            let size: u64 = parts.get(4).and_then(|s| s.parse().ok()).unwrap_or(1_000_000_000);
            let stripe: u32 = parts.get(5).and_then(|s| s.parse().ok()).unwrap_or(64);
            match raidmgr::create_array(name, level, &disk_ids, size, stripe) {
                Ok(id) => shell_println!("Created {} array '{}' (id={})", level.label(), name, id),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "delete" => {
            let id: u32 = match parts.get(1).and_then(|s| s.parse().ok()) {
                Some(v) => v,
                None => { shell_println!("Usage: raidmgr delete <id>"); return; }
            };
            match raidmgr::delete_array(id) {
                Ok(()) => shell_println!("Deleted array {}", id),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "add" => {
            if parts.len() < 3 {
                shell_println!("Usage: raidmgr add <array_id> <disk_id> [size] [spare]");
                return;
            }
            let aid: u32 = match parts[1].parse() {
                Ok(v) => v,
                Err(_) => { shell_println!("Invalid array ID"); return; }
            };
            let disk = parts[2];
            let size: u64 = parts.get(3).and_then(|s| s.parse().ok()).unwrap_or(1_000_000_000);
            let spare = parts.get(4).is_some_and(|s| *s == "spare");
            match raidmgr::add_disk(aid, disk, size, spare) {
                Ok(()) => shell_println!("Added {} to array {} as {}", disk, aid, if spare { "spare" } else { "active" }),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "remove" => {
            if parts.len() < 3 {
                shell_println!("Usage: raidmgr remove <array_id> <disk_id>");
                return;
            }
            let aid: u32 = match parts[1].parse() {
                Ok(v) => v,
                Err(_) => { shell_println!("Invalid array ID"); return; }
            };
            match raidmgr::remove_disk(aid, parts[2]) {
                Ok(()) => shell_println!("Removed {} from array {}", parts[2], aid),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "fail" => {
            if parts.len() < 3 {
                shell_println!("Usage: raidmgr fail <array_id> <disk_id>");
                return;
            }
            let aid: u32 = match parts[1].parse() {
                Ok(v) => v,
                Err(_) => { shell_println!("Invalid array ID"); return; }
            };
            match raidmgr::fail_disk(aid, parts[2]) {
                Ok(()) => shell_println!("Marked {} as failed in array {}", parts[2], aid),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "rebuild" => {
            let aid: u32 = match parts.get(1).and_then(|s| s.parse().ok()) {
                Some(v) => v,
                None => { shell_println!("Usage: raidmgr rebuild <array_id>"); return; }
            };
            match raidmgr::start_rebuild(aid) {
                Ok(()) => shell_println!("Rebuild started on array {}", aid),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "info" => {
            let aid: u32 = match parts.get(1).and_then(|s| s.parse().ok()) {
                Some(v) => v,
                None => { shell_println!("Usage: raidmgr info <array_id>"); return; }
            };
            match raidmgr::get_array(aid) {
                Some(a) => {
                    shell_println!("Array #{}: {} ({})", a.id, a.name, a.level.label());
                    shell_println!("  Status: {}", a.status.label());
                    shell_println!("  Total: {}B, Usable: {}B", a.total_bytes, a.usable_bytes);
                    shell_println!("  Stripe: {}KB", a.stripe_size_kb);
                    shell_println!("  Disks:");
                    for d in &a.disks {
                        shell_println!("    {} [{}] {}B", d.disk_id, d.role.label(), d.size_bytes);
                    }
                }
                None => shell_println!("Array {} not found", aid),
            }
        }
        "stats" => {
            let (count, created, rebuilds, failures, ops) = raidmgr::stats();
            shell_println!("RAID: arrays={} created={} rebuilds={} failures={} ops={}", count, created, rebuilds, failures, ops);
        }
        "init" => { raidmgr::init_defaults(); shell_println!("RAID manager initialized"); }
        "test" => raidmgr::self_test(),
        _ => {
            shell_println!("Usage: raidmgr <list|create|delete|add|remove|fail|rebuild|info|stats|init|test>");
            shell_println!("Aliases: raid");
        }
    }
}

fn parse_raid_level(s: &str) -> crate::fs::raidmgr::RaidLevel {
    use crate::fs::raidmgr::RaidLevel;
    match s.to_lowercase().as_str() {
        "0" | "raid0" | "stripe" => RaidLevel::Raid0,
        "1" | "raid1" | "mirror" => RaidLevel::Raid1,
        "5" | "raid5" => RaidLevel::Raid5,
        "6" | "raid6" => RaidLevel::Raid6,
        "10" | "raid10" => RaidLevel::Raid10,
        "jbod" => RaidLevel::Jbod,
        _ => RaidLevel::Raid1,
    }
}

/// `networkbridge` / `nbridge` — network bridge management.
fn cmd_networkbridge(args: &str) {
    use crate::fs::networkbridge;
    let parts: Vec<&str> = args.split_whitespace().collect();
    let sub = parts.first().copied().unwrap_or("");
    match sub {
        "list" => {
            let bridges = networkbridge::list_bridges();
            if bridges.is_empty() {
                shell_println!("No bridges");
            } else {
                shell_println!("{} bridge(s):", bridges.len());
                for br in &bridges {
                    let ip = br.ip_address.as_deref().unwrap_or("-");
                    shell_println!("  [{}] {} ({}) [{}] ifaces={} ip={} mtu={}",
                        br.id, br.name, br.mode.label(), br.state.label(),
                        br.interfaces.len(), ip, br.mtu);
                }
            }
        }
        "create" => {
            if parts.len() < 2 {
                shell_println!("Usage: networkbridge create <name> [mode]");
                return;
            }
            let name = parts[1];
            let mode = parts.get(2).map_or(crate::fs::networkbridge::BridgeMode::Transparent, |m| parse_bridge_mode(m));
            match networkbridge::create_bridge(name, mode) {
                Ok(id) => shell_println!("Created bridge '{}' (id={}) mode={}", name, id, mode.label()),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "delete" => {
            let id: u32 = match parts.get(1).and_then(|s| s.parse().ok()) {
                Some(v) => v,
                None => { shell_println!("Usage: networkbridge delete <id>"); return; }
            };
            match networkbridge::delete_bridge(id) {
                Ok(()) => shell_println!("Deleted bridge {}", id),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "add" => {
            if parts.len() < 4 {
                shell_println!("Usage: networkbridge add <bridge_id> <iface> <type> [mac]");
                return;
            }
            let bid: u32 = match parts[1].parse() {
                Ok(v) => v,
                Err(_) => { shell_println!("Invalid bridge ID"); return; }
            };
            let iface = parts[2];
            let itype = parse_iface_type(parts[3]);
            let mac = parts.get(4).copied().unwrap_or("00:00:00:00:00:00");
            match networkbridge::add_interface(bid, iface, itype, mac) {
                Ok(()) => shell_println!("Added {} to bridge {}", iface, bid),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "remove" => {
            if parts.len() < 3 {
                shell_println!("Usage: networkbridge remove <bridge_id> <iface>");
                return;
            }
            let bid: u32 = match parts[1].parse() {
                Ok(v) => v,
                Err(_) => { shell_println!("Invalid bridge ID"); return; }
            };
            match networkbridge::remove_interface(bid, parts[2]) {
                Ok(()) => shell_println!("Removed {} from bridge {}", parts[2], bid),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "up" | "down" => {
            let bid: u32 = match parts.get(1).and_then(|s| s.parse().ok()) {
                Some(v) => v,
                None => { shell_println!("Usage: networkbridge {} <bridge_id>", sub); return; }
            };
            let st = if sub == "up" { crate::fs::networkbridge::BridgeState::Up } else { crate::fs::networkbridge::BridgeState::Down };
            match networkbridge::set_state(bid, st) {
                Ok(()) => shell_println!("Bridge {} set to {}", bid, st.label()),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "ip" => {
            if parts.len() < 4 {
                shell_println!("Usage: networkbridge ip <bridge_id> <ip> <mask>");
                return;
            }
            let bid: u32 = match parts[1].parse() {
                Ok(v) => v,
                Err(_) => { shell_println!("Invalid bridge ID"); return; }
            };
            match networkbridge::set_ip(bid, parts[2], parts[3]) {
                Ok(()) => shell_println!("Bridge {} IP set to {}/{}", bid, parts[2], parts[3]),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "mtu" => {
            if parts.len() < 3 {
                shell_println!("Usage: networkbridge mtu <bridge_id> <mtu>");
                return;
            }
            let bid: u32 = match parts[1].parse() {
                Ok(v) => v,
                Err(_) => { shell_println!("Invalid bridge ID"); return; }
            };
            let mtu: u32 = match parts[2].parse() {
                Ok(v) => v,
                Err(_) => { shell_println!("Invalid MTU"); return; }
            };
            match networkbridge::set_mtu(bid, mtu) {
                Ok(()) => shell_println!("Bridge {} MTU set to {}", bid, mtu),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "info" => {
            let bid: u32 = match parts.get(1).and_then(|s| s.parse().ok()) {
                Some(v) => v,
                None => { shell_println!("Usage: networkbridge info <bridge_id>"); return; }
            };
            match networkbridge::get_bridge(bid) {
                Some(br) => {
                    shell_println!("Bridge #{}: {} ({})", br.id, br.name, br.mode.label());
                    shell_println!("  State: {}", br.state.label());
                    let ip = br.ip_address.as_deref().unwrap_or("-");
                    let mask = br.subnet_mask.as_deref().unwrap_or("-");
                    shell_println!("  IP: {}/{}", ip, mask);
                    shell_println!("  MTU: {}, STP: {}", br.mtu, br.stp_enabled);
                    shell_println!("  Interfaces:");
                    for iface in &br.interfaces {
                        shell_println!("    {} ({}) mac={}", iface.name, iface.iface_type.label(), iface.mac_address);
                    }
                }
                None => shell_println!("Bridge {} not found", bid),
            }
        }
        "stats" => {
            let (count, created, ifaces, forwarded, ops) = networkbridge::stats();
            shell_println!("Network Bridge: bridges={} created={} ifaces_added={} forwarded={} ops={}", count, created, ifaces, forwarded, ops);
        }
        "init" => { networkbridge::init_defaults(); shell_println!("Network bridge initialized"); }
        "test" => networkbridge::self_test(),
        _ => {
            shell_println!("Usage: networkbridge <list|create|delete|add|remove|up|down|ip|mtu|info|stats|init|test>");
            shell_println!("Aliases: nbridge");
        }
    }
}

fn parse_bridge_mode(s: &str) -> crate::fs::networkbridge::BridgeMode {
    use crate::fs::networkbridge::BridgeMode;
    match s.to_lowercase().as_str() {
        "transparent" | "l2" => BridgeMode::Transparent,
        "nat" => BridgeMode::Nat,
        "routed" | "l3" => BridgeMode::Routed,
        "isolated" => BridgeMode::Isolated,
        _ => BridgeMode::Transparent,
    }
}

fn parse_iface_type(s: &str) -> crate::fs::networkbridge::IfaceType {
    use crate::fs::networkbridge::IfaceType;
    match s.to_lowercase().as_str() {
        "physical" | "phys" => IfaceType::Physical,
        "virtual" | "virt" => IfaceType::Virtual,
        "vlan" => IfaceType::VlanTag,
        "loopback" | "lo" => IfaceType::Loopback,
        "tap" => IfaceType::Tap,
        _ => IfaceType::Physical,
    }
}

/// `secureerase` / `serase` — secure data deletion.
fn cmd_secureerase(args: &str) {
    use crate::fs::secureerase;
    let parts: Vec<&str> = args.split_whitespace().collect();
    let sub = parts.first().copied().unwrap_or("");
    match sub {
        "start" => {
            if parts.len() < 3 {
                shell_println!("Usage: secureerase start <target> <method> [size] [passes]");
                return;
            }
            let target = parts[1];
            let method = parse_erase_method(parts[2]);
            let size: u64 = parts.get(3).and_then(|s| s.parse().ok()).unwrap_or(1_000_000);
            let passes: Option<u32> = parts.get(4).and_then(|s| s.parse().ok());
            match secureerase::start_erase(target, method, size, passes) {
                Ok(id) => shell_println!("Started erase job {} on '{}' ({})", id, target, method.label()),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "complete" => {
            let id: u32 = match parts.get(1).and_then(|s| s.parse().ok()) {
                Some(v) => v,
                None => { shell_println!("Usage: secureerase complete <id>"); return; }
            };
            match secureerase::complete_erase(id) {
                Ok(()) => shell_println!("Job {} completed", id),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "cancel" => {
            let id: u32 = match parts.get(1).and_then(|s| s.parse().ok()) {
                Some(v) => v,
                None => { shell_println!("Usage: secureerase cancel <id>"); return; }
            };
            match secureerase::cancel_erase(id) {
                Ok(()) => shell_println!("Job {} cancelled", id),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "status" => {
            let id: u32 = match parts.get(1).and_then(|s| s.parse().ok()) {
                Some(v) => v,
                None => { shell_println!("Usage: secureerase status <id>"); return; }
            };
            match secureerase::get_job(id) {
                Some(job) => {
                    shell_println!("Job #{}: {} ({})", job.id, job.target, job.method.label());
                    shell_println!("  Status: {} — {}%", job.status.label(), job.progress_pct());
                    shell_println!("  Pass: {}/{}", job.current_pass, job.total_passes);
                    shell_println!("  Erased: {}/{}B", job.erased_bytes, job.total_bytes);
                }
                None => shell_println!("Job {} not found", id),
            }
        }
        "list" => {
            let jobs = secureerase::list_jobs();
            if jobs.is_empty() {
                shell_println!("No erase jobs");
            } else {
                shell_println!("{} job(s):", jobs.len());
                for j in &jobs {
                    shell_println!("  [{}] {} ({}) [{}] {}%", j.id, j.target, j.method.label(), j.status.label(), j.progress_pct());
                }
            }
        }
        "stats" => {
            let (count, started, completed, bytes, ops) = secureerase::stats();
            shell_println!("Secure Erase: jobs={} started={} completed={} bytes_erased={} ops={}", count, started, completed, bytes, ops);
        }
        "init" => { secureerase::init_defaults(); shell_println!("Secure erase initialized"); }
        "test" => secureerase::self_test(),
        _ => {
            shell_println!("Usage: secureerase <start|complete|cancel|status|list|stats|init|test>");
            shell_println!("Aliases: serase");
        }
    }
}

fn parse_erase_method(s: &str) -> crate::fs::secureerase::EraseMethod {
    use crate::fs::secureerase::EraseMethod;
    match s.to_lowercase().as_str() {
        "zero" | "zerofill" => EraseMethod::ZeroFill,
        "random" | "randomfill" => EraseMethod::RandomFill,
        "dod3" | "dod" => EraseMethod::DoD3Pass,
        "dod7" => EraseMethod::DoD7Pass,
        "gutmann" => EraseMethod::Gutmann,
        "custom" => EraseMethod::CustomPasses,
        _ => EraseMethod::ZeroFill,
    }
}

/// `dnssettings` / `dns` — DNS resolver configuration.
fn cmd_dnssettings(args: &str) {
    use crate::fs::dnssettings;
    let parts: Vec<&str> = args.split_whitespace().collect();
    let sub = parts.first().copied().unwrap_or("");
    match sub {
        "servers" => {
            let servers = dnssettings::list_servers();
            if servers.is_empty() {
                shell_println!("No DNS servers");
            } else {
                shell_println!("{} server(s):", servers.len());
                for s in &servers {
                    let status = if s.is_active { "active" } else { "inactive" };
                    shell_println!("  {} ({}) pri={} [{}] queries={} fail={}", s.address, s.protocol.label(), s.priority, status, s.queries_sent, s.failures);
                }
            }
        }
        "add" => {
            if parts.len() < 2 {
                shell_println!("Usage: dnssettings add <address> [protocol] [priority]");
                return;
            }
            let addr = parts[1];
            let proto = parts.get(2).map_or(crate::fs::dnssettings::DnsProtocol::Plain, |p| parse_dns_protocol(p));
            let pri: u32 = parts.get(3).and_then(|s| s.parse().ok()).unwrap_or(10);
            match dnssettings::add_server(addr, proto, pri) {
                Ok(()) => shell_println!("Added DNS server {} ({})", addr, proto.label()),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "remove" => {
            let addr = match parts.get(1) {
                Some(a) => *a,
                None => { shell_println!("Usage: dnssettings remove <address>"); return; }
            };
            match dnssettings::remove_server(addr) {
                Ok(()) => shell_println!("Removed {}", addr),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "resolve" => {
            let name = match parts.get(1) {
                Some(n) => *n,
                None => { shell_println!("Usage: dnssettings resolve <hostname>"); return; }
            };
            match dnssettings::resolve(name) {
                Ok(ip) => shell_println!("{} → {}", name, ip),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "flush" => {
            match dnssettings::flush_cache() {
                Ok(n) => shell_println!("Flushed {} cached records", n),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "search" => {
            if let Some(domain) = parts.get(1) {
                match dnssettings::add_search_domain(domain) {
                    Ok(()) => shell_println!("Added search domain '{}'", domain),
                    Err(e) => shell_println!("Error: {:?}", e),
                }
            } else {
                let domains = dnssettings::list_search_domains();
                shell_println!("Search domains: {}", if domains.is_empty() { String::from("(none)") } else { domains.join(", ") });
            }
        }
        "stats" => {
            let (servers, cache, queries, hits, failures, ops) = dnssettings::stats();
            shell_println!("DNS: servers={} cache={} queries={} hits={} failures={} ops={}", servers, cache, queries, hits, failures, ops);
        }
        "init" => { dnssettings::init_defaults(); shell_println!("DNS settings initialized"); }
        "test" => dnssettings::self_test(),
        _ => {
            shell_println!("Usage: dnssettings <servers|add|remove|resolve|flush|search|stats|init|test>");
            shell_println!("Aliases: dns");
        }
    }
}

fn parse_dns_protocol(s: &str) -> crate::fs::dnssettings::DnsProtocol {
    use crate::fs::dnssettings::DnsProtocol;
    match s.to_lowercase().as_str() {
        "plain" | "udp" => DnsProtocol::Plain,
        "doh" | "https" => DnsProtocol::Doh,
        "dot" | "tls" => DnsProtocol::Dot,
        "dnscrypt" | "crypt" => DnsProtocol::Dnscrypt,
        _ => DnsProtocol::Plain,
    }
}

/// `backupsched` / `bsched` — automated backup scheduling.
fn cmd_backupsched(args: &str) {
    use crate::fs::backupsched;
    let parts: Vec<&str> = args.split_whitespace().collect();
    let sub = parts.first().copied().unwrap_or("");
    match sub {
        "list" => {
            let scheds = backupsched::list_schedules();
            if scheds.is_empty() {
                shell_println!("No backup schedules");
            } else {
                shell_println!("{} schedule(s):", scheds.len());
                for s in &scheds {
                    let status = if s.enabled { "on" } else { "off" };
                    shell_println!("  [{}] {} ({} {}) {} → {} [{}] runs={}", s.id, s.name, s.backup_type.label(), s.frequency.label(), s.source_path, s.destination, status, s.run_count);
                }
            }
        }
        "create" => {
            if parts.len() < 4 {
                shell_println!("Usage: backupsched create <name> <source> <dest> [type] [freq] [retention]");
                return;
            }
            let name = parts[1];
            let source = parts[2];
            let dest = parts[3];
            let btype = parts.get(4).map_or(crate::fs::backupsched::BackupType::Incremental, |t| parse_backup_type(t));
            let freq = parts.get(5).map_or(crate::fs::backupsched::BackupFrequency::Daily, |f| parse_backup_freq(f));
            let retention: u32 = parts.get(6).and_then(|s| s.parse().ok()).unwrap_or(30);
            match backupsched::create_schedule(name, source, dest, btype, freq, retention) {
                Ok(id) => shell_println!("Created schedule '{}' (id={})", name, id),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "delete" => {
            let id: u32 = match parts.get(1).and_then(|s| s.parse().ok()) {
                Some(v) => v,
                None => { shell_println!("Usage: backupsched delete <id>"); return; }
            };
            match backupsched::delete_schedule(id) {
                Ok(()) => shell_println!("Deleted schedule {}", id),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "enable" | "disable" => {
            let id: u32 = match parts.get(1).and_then(|s| s.parse().ok()) {
                Some(v) => v,
                None => { shell_println!("Usage: backupsched {} <id>", sub); return; }
            };
            let enabled = sub == "enable";
            match backupsched::set_enabled(id, enabled) {
                Ok(()) => shell_println!("Schedule {} {}", id, if enabled { "enabled" } else { "disabled" }),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "run" => {
            let id: u32 = match parts.get(1).and_then(|s| s.parse().ok()) {
                Some(v) => v,
                None => { shell_println!("Usage: backupsched run <id>"); return; }
            };
            match backupsched::run_now(id, crate::fs::backupsched::RunResult::Success, 100_000_000, 500) {
                Ok(()) => shell_println!("Backup run completed for schedule {}", id),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "history" => {
            let id: u32 = match parts.get(1).and_then(|s| s.parse().ok()) {
                Some(v) => v,
                None => { shell_println!("Usage: backupsched history <id>"); return; }
            };
            let max: usize = parts.get(2).and_then(|s| s.parse().ok()).unwrap_or(10);
            let hist = backupsched::get_history(id, max);
            if hist.is_empty() {
                shell_println!("No history for schedule {}", id);
            } else {
                shell_println!("{} run(s):", hist.len());
                for r in &hist {
                    shell_println!("  [{}] {}B, {} files, {}ms", r.result.label(), r.bytes_backed, r.files_count, r.duration_ms);
                }
            }
        }
        "stats" => {
            let (scheds, hist, runs, success, failed, bytes, ops) = backupsched::stats();
            shell_println!("Backup: schedules={} history={} runs={} success={} failed={} bytes={} ops={}", scheds, hist, runs, success, failed, bytes, ops);
        }
        "init" => { backupsched::init_defaults(); shell_println!("Backup scheduler initialized"); }
        "test" => backupsched::self_test(),
        _ => {
            shell_println!("Usage: backupsched <list|create|delete|enable|disable|run|history|stats|init|test>");
            shell_println!("Aliases: bsched");
        }
    }
}

fn parse_backup_type(s: &str) -> crate::fs::backupsched::BackupType {
    use crate::fs::backupsched::BackupType;
    match s.to_lowercase().as_str() {
        "full" => BackupType::Full,
        "incremental" | "inc" => BackupType::Incremental,
        "differential" | "diff" => BackupType::Differential,
        "mirror" => BackupType::Mirror,
        _ => BackupType::Incremental,
    }
}

fn parse_backup_freq(s: &str) -> crate::fs::backupsched::BackupFrequency {
    use crate::fs::backupsched::BackupFrequency;
    match s.to_lowercase().as_str() {
        "hourly" => BackupFrequency::Hourly,
        "daily" => BackupFrequency::Daily,
        "weekly" => BackupFrequency::Weekly,
        "monthly" => BackupFrequency::Monthly,
        "manual" => BackupFrequency::Manual,
        _ => BackupFrequency::Daily,
    }
}

/// `displaycal` / `dcal` — display color calibration.
fn cmd_displaycal(args: &str) {
    use crate::fs::displaycal;
    let parts: Vec<&str> = args.split_whitespace().collect();
    let sub = parts.first().copied().unwrap_or("");
    match sub {
        "list" => {
            let monitors = displaycal::list_monitors();
            if monitors.is_empty() {
                shell_println!("No monitors");
            } else {
                shell_println!("{} monitor(s):", monitors.len());
                for m in &monitors {
                    shell_println!("  [{}] {} ({}) [{}] gamma={}/{}/{} wp={}K bright={}cd/m²",
                        m.id, m.monitor_name, m.profile_type.label(), m.status.label(),
                        m.gamma_r, m.gamma_g, m.gamma_b, m.white_point_k, m.brightness_target);
                }
            }
        }
        "add" => {
            let name = match parts.get(1) {
                Some(n) => *n,
                None => { shell_println!("Usage: displaycal add <name>"); return; }
            };
            match displaycal::add_monitor(name) {
                Ok(id) => shell_println!("Added monitor '{}' (id={})", name, id),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "remove" => {
            let id: u32 = match parts.get(1).and_then(|s| s.parse().ok()) {
                Some(v) => v,
                None => { shell_println!("Usage: displaycal remove <id>"); return; }
            };
            match displaycal::remove_monitor(id) {
                Ok(()) => shell_println!("Removed monitor {}", id),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "profile" => {
            if parts.len() < 3 {
                shell_println!("Usage: displaycal profile <id> <type>");
                return;
            }
            let id: u32 = match parts[1].parse() {
                Ok(v) => v,
                Err(_) => { shell_println!("Invalid monitor ID"); return; }
            };
            let ptype = parse_profile_type(parts[2]);
            match displaycal::set_profile(id, ptype) {
                Ok(()) => shell_println!("Profile set to {} for monitor {}", ptype.label(), id),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "gamma" => {
            if parts.len() < 5 {
                shell_println!("Usage: displaycal gamma <id> <r> <g> <b> (values * 100, e.g., 220 = 2.20)");
                return;
            }
            let id: u32 = match parts[1].parse() {
                Ok(v) => v,
                Err(_) => { shell_println!("Invalid monitor ID"); return; }
            };
            let r: u32 = parts.get(2).and_then(|s| s.parse().ok()).unwrap_or(220);
            let g: u32 = parts.get(3).and_then(|s| s.parse().ok()).unwrap_or(220);
            let b: u32 = parts.get(4).and_then(|s| s.parse().ok()).unwrap_or(220);
            match displaycal::set_gamma(id, r, g, b) {
                Ok(()) => shell_println!("Gamma set to {}/{}/{} for monitor {}", r, g, b, id),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "whitepoint" | "wp" => {
            if parts.len() < 3 {
                shell_println!("Usage: displaycal whitepoint <id> <kelvin>");
                return;
            }
            let id: u32 = match parts[1].parse() {
                Ok(v) => v,
                Err(_) => { shell_println!("Invalid monitor ID"); return; }
            };
            let k: u32 = match parts[2].parse() {
                Ok(v) => v,
                Err(_) => { shell_println!("Invalid temperature"); return; }
            };
            match displaycal::set_white_point(id, k) {
                Ok(()) => shell_println!("White point set to {}K for monitor {}", k, id),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "calibrate" => {
            let id: u32 = match parts.get(1).and_then(|s| s.parse().ok()) {
                Some(v) => v,
                None => { shell_println!("Usage: displaycal calibrate <id>"); return; }
            };
            match displaycal::calibrate(id) {
                Ok(()) => shell_println!("Monitor {} calibrated", id),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "info" => {
            let id: u32 = match parts.get(1).and_then(|s| s.parse().ok()) {
                Some(v) => v,
                None => { shell_println!("Usage: displaycal info <id>"); return; }
            };
            match displaycal::get_monitor(id) {
                Some(m) => {
                    shell_println!("Monitor #{}: {}", m.id, m.monitor_name);
                    shell_println!("  Profile: {}", m.profile_type.label());
                    shell_println!("  Status: {}", m.status.label());
                    shell_println!("  Gamma: R={} G={} B={}", m.gamma_r, m.gamma_g, m.gamma_b);
                    shell_println!("  White point: {}K", m.white_point_k);
                    shell_println!("  Brightness target: {} cd/m²", m.brightness_target);
                }
                None => shell_println!("Monitor {} not found", id),
            }
        }
        "stats" => {
            let (count, calibrations, profile_changes, ops) = displaycal::stats();
            shell_println!("Display Cal: monitors={} calibrations={} profile_changes={} ops={}", count, calibrations, profile_changes, ops);
        }
        "init" => { displaycal::init_defaults(); shell_println!("Display calibration initialized"); }
        "test" => displaycal::self_test(),
        _ => {
            shell_println!("Usage: displaycal <list|add|remove|profile|gamma|whitepoint|calibrate|info|stats|init|test>");
            shell_println!("Aliases: dcal");
        }
    }
}

fn parse_profile_type(s: &str) -> crate::fs::displaycal::ProfileType {
    use crate::fs::displaycal::ProfileType;
    match s.to_lowercase().as_str() {
        "srgb" => ProfileType::Srgb,
        "adobergb" | "adobe" => ProfileType::AdobeRgb,
        "dcip3" | "p3" => ProfileType::DciP3,
        "rec2020" | "2020" => ProfileType::Rec2020,
        "custom" => ProfileType::Custom,
        _ => ProfileType::Srgb,
    }
}

/// `vpnprofile` / `vpnp` — VPN connection profile management.
fn cmd_vpnprofile(args: &str) {
    use crate::fs::vpnprofile;
    let parts: Vec<&str> = args.split_whitespace().collect();
    let sub = parts.first().copied().unwrap_or("");
    match sub {
        "list" => {
            let profiles = vpnprofile::list_profiles();
            if profiles.is_empty() {
                shell_println!("No VPN profiles");
            } else {
                shell_println!("{} profile(s):", profiles.len());
                for p in &profiles {
                    let ac = if p.auto_connect { "auto" } else { "-" };
                    let ks = if p.kill_switch { "KS" } else { "-" };
                    shell_println!("  [{}] {} ({}) {}:{} [{}] {} {} tx={}B rx={}B",
                        p.id, p.name, p.protocol.label(), p.server, p.port,
                        p.state.label(), ac, ks, p.bytes_sent, p.bytes_received);
                }
            }
        }
        "create" => {
            if parts.len() < 4 {
                shell_println!("Usage: vpnprofile create <name> <protocol> <server> [port]");
                return;
            }
            let name = parts[1];
            let proto = parse_vpn_protocol(parts[2]);
            let server = parts[3];
            let port: u16 = parts.get(4).and_then(|s| s.parse().ok()).unwrap_or(1194);
            match vpnprofile::create_profile(name, proto, server, port) {
                Ok(id) => shell_println!("Created VPN profile '{}' (id={})", name, id),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "delete" => {
            let id: u32 = match parts.get(1).and_then(|s| s.parse().ok()) {
                Some(v) => v,
                None => { shell_println!("Usage: vpnprofile delete <id>"); return; }
            };
            match vpnprofile::delete_profile(id) {
                Ok(()) => shell_println!("Deleted profile {}", id),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "connect" => {
            let id: u32 = match parts.get(1).and_then(|s| s.parse().ok()) {
                Some(v) => v,
                None => { shell_println!("Usage: vpnprofile connect <id>"); return; }
            };
            match vpnprofile::connect(id) {
                Ok(()) => shell_println!("Connected to VPN {}", id),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "disconnect" => {
            let id: u32 = match parts.get(1).and_then(|s| s.parse().ok()) {
                Some(v) => v,
                None => { shell_println!("Usage: vpnprofile disconnect <id>"); return; }
            };
            match vpnprofile::disconnect(id) {
                Ok(()) => shell_println!("Disconnected from VPN {}", id),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "killswitch" => {
            if parts.len() < 3 {
                shell_println!("Usage: vpnprofile killswitch <id> <on|off>");
                return;
            }
            let id: u32 = match parts[1].parse() {
                Ok(v) => v,
                Err(_) => { shell_println!("Invalid ID"); return; }
            };
            let enabled = parts[2] == "on";
            match vpnprofile::set_kill_switch(id, enabled) {
                Ok(()) => shell_println!("Kill switch {} for profile {}", if enabled { "enabled" } else { "disabled" }, id),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "info" => {
            let id: u32 = match parts.get(1).and_then(|s| s.parse().ok()) {
                Some(v) => v,
                None => { shell_println!("Usage: vpnprofile info <id>"); return; }
            };
            match vpnprofile::get_profile(id) {
                Some(p) => {
                    shell_println!("VPN #{}: {}", p.id, p.name);
                    shell_println!("  Protocol: {}", p.protocol.label());
                    shell_println!("  Server: {}:{}", p.server, p.port);
                    shell_println!("  State: {}", p.state.label());
                    shell_println!("  Auto-connect: {}, Kill switch: {}", p.auto_connect, p.kill_switch);
                    shell_println!("  Traffic: tx={}B rx={}B", p.bytes_sent, p.bytes_received);
                    shell_println!("  Connections: {}", p.total_connections);
                    if let Some(ref dns) = p.dns_override {
                        shell_println!("  DNS override: {}", dns);
                    }
                }
                None => shell_println!("Profile {} not found", id),
            }
        }
        "stats" => {
            let (count, connects, disconnects, errors, ops) = vpnprofile::stats();
            shell_println!("VPN: profiles={} connects={} disconnects={} errors={} ops={}", count, connects, disconnects, errors, ops);
        }
        "init" => { vpnprofile::init_defaults(); shell_println!("VPN profiles initialized"); }
        "test" => vpnprofile::self_test(),
        _ => {
            shell_println!("Usage: vpnprofile <list|create|delete|connect|disconnect|killswitch|info|stats|init|test>");
            shell_println!("Aliases: vpnp");
        }
    }
}

fn parse_vpn_protocol(s: &str) -> crate::fs::vpnprofile::VpnProtocol {
    use crate::fs::vpnprofile::VpnProtocol;
    match s.to_lowercase().as_str() {
        "openvpn" | "ovpn" => VpnProtocol::OpenVpn,
        "wireguard" | "wg" => VpnProtocol::WireGuard,
        "ipsec" => VpnProtocol::IpSec,
        "l2tp" => VpnProtocol::L2tp,
        "sstp" => VpnProtocol::Sstp,
        "pptp" => VpnProtocol::Pptp,
        _ => VpnProtocol::WireGuard,
    }
}

/// `diskhealth` / `dhealth` — disk health monitoring.
fn cmd_diskhealth(args: &str) {
    use crate::fs::diskhealth;
    let parts: Vec<&str> = args.split_whitespace().collect();
    let sub = parts.first().copied().unwrap_or("");
    match sub {
        "list" => {
            let disks = diskhealth::list_disks();
            if disks.is_empty() {
                shell_println!("No monitored disks");
            } else {
                shell_println!("{} disk(s):", disks.len());
                for d in &disks {
                    shell_println!("  [{}] {} ({}) {} [{}] temp={}°C life={}% realloc={}",
                        d.id, d.device_name, d.model, d.disk_type.label(),
                        d.health.label(), d.temperature_c, d.remaining_life_pct, d.reallocated_sectors);
                }
            }
        }
        "check" => {
            let id: u32 = match parts.get(1).and_then(|s| s.parse().ok()) {
                Some(v) => v,
                None => { shell_println!("Usage: diskhealth check <id>"); return; }
            };
            match diskhealth::check_health(id) {
                Ok(grade) => shell_println!("Disk {} health: {}", id, grade.label()),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "add" => {
            if parts.len() < 4 {
                shell_println!("Usage: diskhealth add <name> <model> <type> [serial] [capacity]");
                return;
            }
            let name = parts[1];
            let model = parts[2];
            let dtype = parse_disk_type(parts[3]);
            let serial = parts.get(4).copied().unwrap_or("UNKNOWN");
            let capacity: u64 = parts.get(5).and_then(|s| s.parse().ok()).unwrap_or(500_000_000_000);
            match diskhealth::add_disk(name, model, serial, dtype, capacity) {
                Ok(id) => shell_println!("Added disk '{}' (id={})", name, id),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "remove" => {
            let id: u32 = match parts.get(1).and_then(|s| s.parse().ok()) {
                Some(v) => v,
                None => { shell_println!("Usage: diskhealth remove <id>"); return; }
            };
            match diskhealth::remove_disk(id) {
                Ok(()) => shell_println!("Removed disk {}", id),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "info" => {
            let id: u32 = match parts.get(1).and_then(|s| s.parse().ok()) {
                Some(v) => v,
                None => { shell_println!("Usage: diskhealth info <id>"); return; }
            };
            match diskhealth::get_disk(id) {
                Some(d) => {
                    shell_println!("Disk #{}: {} ({})", d.id, d.device_name, d.model);
                    shell_println!("  Type: {}", d.disk_type.label());
                    shell_println!("  Serial: {}", d.serial);
                    shell_println!("  Capacity: {}B", d.capacity_bytes);
                    shell_println!("  Health: {}", d.health.label());
                    shell_println!("  Temperature: {}°C", d.temperature_c);
                    shell_println!("  Power-on hours: {}", d.power_on_hours);
                    shell_println!("  Remaining life: {}%", d.remaining_life_pct);
                    shell_println!("  Reallocated sectors: {}", d.reallocated_sectors);
                    shell_println!("  Read errors: {}, Write errors: {}", d.read_error_rate, d.write_error_rate);
                }
                None => shell_println!("Disk {} not found", id),
            }
        }
        "stats" => {
            let (count, checks, warnings, failures, ops) = diskhealth::stats();
            shell_println!("Disk Health: disks={} checks={} warnings={} failures={} ops={}", count, checks, warnings, failures, ops);
        }
        "init" => { diskhealth::init_defaults(); shell_println!("Disk health initialized"); }
        "test" => diskhealth::self_test(),
        _ => {
            shell_println!("Usage: diskhealth <list|check|add|remove|info|stats|init|test>");
            shell_println!("Aliases: dhealth");
        }
    }
}

fn parse_disk_type(s: &str) -> crate::fs::diskhealth::DiskType {
    use crate::fs::diskhealth::DiskType;
    match s.to_lowercase().as_str() {
        "hdd" | "hard" => DiskType::Hdd,
        "ssd" | "solid" => DiskType::Ssd,
        "nvme" => DiskType::Nvme,
        "usb" => DiskType::Usb,
        _ => DiskType::Unknown,
    }
}

/// `recoverypart` / `rpart` — recovery partition management.
fn cmd_recoverypart(args: &str) {
    use crate::fs::recoverypart;
    let parts: Vec<&str> = args.split_whitespace().collect();
    let sub = parts.first().copied().unwrap_or("");
    match sub {
        "status" => {
            let status = recoverypart::get_status();
            let (total, used, free) = recoverypart::space_usage();
            shell_println!("Recovery partition: {}", status.label());
            shell_println!("  Space: {}B total, {}B used, {}B free", total, used, free);
            let tools = recoverypart::list_tools();
            shell_println!("  Tools: {}", tools.len());
            for t in &tools {
                shell_println!("    [{}] {} ({}) v{} — {}B", t.id, t.name, t.tool_type.label(), t.version, t.size_bytes);
            }
        }
        "add" => {
            if parts.len() < 3 {
                shell_println!("Usage: recoverypart add <name> <type> [version] [size]");
                return;
            }
            let name = parts[1];
            let ttype = parse_recovery_tool_type(parts[2]);
            let version = parts.get(3).copied().unwrap_or("1.0");
            let size: u64 = parts.get(4).and_then(|s| s.parse().ok()).unwrap_or(10_000_000);
            match recoverypart::add_tool(name, ttype, version, size) {
                Ok(id) => shell_println!("Added tool '{}' (id={})", name, id),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "remove" => {
            let id: u32 = match parts.get(1).and_then(|s| s.parse().ok()) {
                Some(v) => v,
                None => { shell_println!("Usage: recoverypart remove <id>"); return; }
            };
            match recoverypart::remove_tool(id) {
                Ok(()) => shell_println!("Removed tool {}", id),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "verify" => {
            match recoverypart::verify_integrity() {
                Ok(true) => shell_println!("Recovery partition integrity OK"),
                Ok(false) => shell_println!("Recovery partition integrity FAILED"),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "repair" => {
            let id: u32 = match parts.get(1).and_then(|s| s.parse().ok()) {
                Some(v) => v,
                None => { shell_println!("Usage: recoverypart repair <tool_id>"); return; }
            };
            match recoverypart::run_repair(id) {
                Ok(()) => shell_println!("Repair completed with tool {}", id),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "boot" => {
            match recoverypart::boot_recovery() {
                Ok(()) => shell_println!("Booting into recovery environment..."),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "stats" => {
            let (tools, repairs, verifications, boots, ops) = recoverypart::stats();
            shell_println!("Recovery: tools={} repairs={} verifications={} boots={} ops={}", tools, repairs, verifications, boots, ops);
        }
        "init" => { recoverypart::init_defaults(); shell_println!("Recovery partition initialized"); }
        "test" => recoverypart::self_test(),
        _ => {
            shell_println!("Usage: recoverypart <status|add|remove|verify|repair|boot|stats|init|test>");
            shell_println!("Aliases: rpart");
        }
    }
}

fn parse_recovery_tool_type(s: &str) -> crate::fs::recoverypart::ToolType {
    use crate::fs::recoverypart::ToolType;
    match s.to_lowercase().as_str() {
        "repair" | "sysrepair" => ToolType::SystemRepair,
        "factory" | "reset" => ToolType::FactoryReset,
        "diskcheck" | "chkdsk" => ToolType::DiskCheck,
        "bootrepair" | "boot" => ToolType::BootRepair,
        "memtest" | "memory" => ToolType::MemoryTest,
        "shell" | "cmd" => ToolType::CommandShell,
        "netdiag" | "network" => ToolType::NetworkDiag,
        "filerecovery" | "recover" => ToolType::FileRecovery,
        _ => ToolType::SystemRepair,
    }
}

/// `userprofile` / `uprof` — user account profile management.
fn cmd_userprofile(args: &str) {
    use crate::fs::userprofile;
    let parts: Vec<&str> = args.split_whitespace().collect();
    let sub = parts.first().copied().unwrap_or("");
    match sub {
        "list" => {
            let profiles = userprofile::list_profiles();
            if profiles.is_empty() {
                shell_println!("No user profiles");
            } else {
                shell_println!("{} profile(s):", profiles.len());
                for p in &profiles {
                    let active = if p.is_active { "*" } else { " " };
                    let locked = if p.is_locked { " [locked]" } else { "" };
                    shell_println!("  {}[{}] {} ({}) {} logins={}{}", active, p.id, p.username, p.account_type.label(), p.display_name, p.login_count, locked);
                }
            }
        }
        "create" => {
            if parts.len() < 3 {
                shell_println!("Usage: userprofile create <username> <display_name> [type]");
                return;
            }
            let username = parts[1];
            let display = parts[2];
            let atype = parts.get(3).map_or(crate::fs::userprofile::AccountType::Standard, |t| parse_account_type(t));
            match userprofile::create_profile(username, display, atype) {
                Ok(id) => shell_println!("Created profile '{}' (id={})", username, id),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "delete" => {
            let id: u32 = match parts.get(1).and_then(|s| s.parse().ok()) {
                Some(v) => v,
                None => { shell_println!("Usage: userprofile delete <id>"); return; }
            };
            match userprofile::delete_profile(id) {
                Ok(()) => shell_println!("Deleted profile {}", id),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "switch" => {
            let id: u32 = match parts.get(1).and_then(|s| s.parse().ok()) {
                Some(v) => v,
                None => { shell_println!("Usage: userprofile switch <id>"); return; }
            };
            match userprofile::switch_user(id) {
                Ok(()) => shell_println!("Switched to user {}", id),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "lock" | "unlock" => {
            let id: u32 = match parts.get(1).and_then(|s| s.parse().ok()) {
                Some(v) => v,
                None => { shell_println!("Usage: userprofile {} <id>", sub); return; }
            };
            let locked = sub == "lock";
            match userprofile::set_locked(id, locked) {
                Ok(()) => shell_println!("Profile {} {}", id, if locked { "locked" } else { "unlocked" }),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "rename" => {
            if parts.len() < 3 {
                shell_println!("Usage: userprofile rename <id> <new_display_name>");
                return;
            }
            let id: u32 = match parts[1].parse() {
                Ok(v) => v,
                Err(_) => { shell_println!("Invalid ID"); return; }
            };
            let name = parts[2..].join(" ");
            match userprofile::set_display_name(id, &name) {
                Ok(()) => shell_println!("Renamed profile {} to '{}'", id, name),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "whoami" => {
            match userprofile::active_user() {
                Some(u) => shell_println!("{} ({}) — {}", u.username, u.account_type.label(), u.display_name),
                None => shell_println!("No active user"),
            }
        }
        "info" => {
            let id: u32 = match parts.get(1).and_then(|s| s.parse().ok()) {
                Some(v) => v,
                None => { shell_println!("Usage: userprofile info <id>"); return; }
            };
            match userprofile::get_profile(id) {
                Some(p) => {
                    shell_println!("User #{}: {}", p.id, p.username);
                    shell_println!("  Display: {}", p.display_name);
                    shell_println!("  Type: {}", p.account_type.label());
                    shell_println!("  Home: {}", p.home_dir);
                    shell_println!("  Shell: {}", p.shell);
                    shell_println!("  Logins: {}", p.login_count);
                    shell_println!("  Active: {}, Locked: {}", p.is_active, p.is_locked);
                }
                None => shell_println!("Profile {} not found", id),
            }
        }
        "stats" => {
            let (count, logins, switches, ops) = userprofile::stats();
            shell_println!("User Profiles: profiles={} logins={} switches={} ops={}", count, logins, switches, ops);
        }
        "init" => { userprofile::init_defaults(); shell_println!("User profiles initialized"); }
        "test" => userprofile::self_test(),
        _ => {
            shell_println!("Usage: userprofile <list|create|delete|switch|lock|unlock|rename|whoami|info|stats|init|test>");
            shell_println!("Aliases: uprof");
        }
    }
}

fn parse_account_type(s: &str) -> crate::fs::userprofile::AccountType {
    use crate::fs::userprofile::AccountType;
    match s.to_lowercase().as_str() {
        "admin" => AccountType::Admin,
        "standard" | "std" => AccountType::Standard,
        "guest" => AccountType::Guest,
        "system" | "sys" => AccountType::System,
        "managed" => AccountType::Managed,
        _ => AccountType::Standard,
    }
}

/// `diskclean` / `dclean` — automated disk cleanup.
fn cmd_diskclean(args: &str) {
    use crate::fs::diskclean;
    let parts: Vec<&str> = args.split_whitespace().collect();
    let sub = parts.first().copied().unwrap_or("");
    match sub {
        "scan" => {
            match diskclean::scan() {
                Ok(summaries) => {
                    if summaries.is_empty() {
                        shell_println!("No reclaimable items found");
                    } else {
                        let total: u64 = summaries.iter().map(|s| s.total_bytes).sum();
                        shell_println!("Found {} categories, {}B reclaimable:", summaries.len(), total);
                        for s in &summaries {
                            shell_println!("  {} — {} items, {}B", s.category.label(), s.item_count, s.total_bytes);
                        }
                    }
                }
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "clean" => {
            let cats: Vec<crate::fs::diskclean::CleanCategory> = if parts.len() > 1 {
                parts[1..].iter().map(|s| parse_clean_category(s)).collect()
            } else {
                alloc::vec![
                    crate::fs::diskclean::CleanCategory::TempFiles,
                    crate::fs::diskclean::CleanCategory::SystemCache,
                    crate::fs::diskclean::CleanCategory::OldLogs,
                    crate::fs::diskclean::CleanCategory::ThumbnailCache,
                    crate::fs::diskclean::CleanCategory::CrashDumps,
                ]
            };
            match diskclean::clean(&cats) {
                Ok((items, bytes)) => shell_println!("Cleaned {} items, {}B freed", items, bytes),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "estimate" => {
            let est = diskclean::estimate();
            shell_println!("Estimated reclaimable: {}B", est);
        }
        "items" => {
            let items = diskclean::list_items();
            if items.is_empty() {
                shell_println!("No items (run scan first)");
            } else {
                shell_println!("{} item(s):", items.len());
                for i in &items {
                    let safe = if i.safe_to_remove { "safe" } else { "KEEP" };
                    shell_println!("  [{}] {} — {}B [{}]", i.category.label(), i.path, i.size_bytes, safe);
                }
            }
        }
        "stats" => {
            let (count, scans, cleaned_bytes, cleaned_items, ops) = diskclean::stats();
            shell_println!("Disk Cleanup: items={} scans={} cleaned_bytes={} cleaned_items={} ops={}", count, scans, cleaned_bytes, cleaned_items, ops);
        }
        "init" => { diskclean::init_defaults(); shell_println!("Disk cleanup initialized"); }
        "test" => diskclean::self_test(),
        _ => {
            shell_println!("Usage: diskclean <scan|clean|estimate|items|stats|init|test>");
            shell_println!("Aliases: dclean");
        }
    }
}

fn parse_clean_category(s: &str) -> crate::fs::diskclean::CleanCategory {
    use crate::fs::diskclean::CleanCategory;
    match s.to_lowercase().as_str() {
        "temp" | "tmpfiles" => CleanCategory::TempFiles,
        "syscache" | "systemcache" => CleanCategory::SystemCache,
        "appcache" => CleanCategory::AppCache,
        "logs" | "oldlogs" => CleanCategory::OldLogs,
        "packages" | "pkgcache" => CleanCategory::PackageCache,
        "thumbs" | "thumbnails" => CleanCategory::ThumbnailCache,
        "trash" | "trashbin" => CleanCategory::TrashBin,
        "updates" => CleanCategory::DownloadedUpdates,
        "browser" => CleanCategory::BrowserData,
        "crashes" | "dumps" => CleanCategory::CrashDumps,
        _ => CleanCategory::TempFiles,
    }
}

/// `cas` — content-addressed store management.
fn cmd_cas(args: &str) {
    use crate::fs::cas;
    let parts: Vec<&str> = args.split_whitespace().collect();
    let sub = parts.first().copied().unwrap_or("");
    match sub {
        "stats" | "" => {
            let s = cas::stats();
            shell_println!("=== Content-Addressed Store ===");
            shell_println!("  Blobs:              {}", s.blob_count);
            shell_println!("  Total bytes:        {}", s.total_bytes);
            shell_println!("  Max bytes:          {}", s.max_bytes);
            shell_println!("  Total refs:         {}", s.total_refs);
            shell_println!("  Dedup hits:         {}", s.dedup_hits);
            shell_println!("  Integrity failures: {}", s.integrity_failures);
            shell_println!("  GC collected:       {}", s.gc_collected);
        }
        "put" => {
            let data = parts.get(1..).map(|p| p.join(" ")).unwrap_or_default();
            if data.is_empty() {
                shell_println!("Usage: cas put <data>");
                return;
            }
            match cas::put(data.as_bytes()) {
                Ok(hash) => {
                    let hex = cas::hash_to_hex(&hash);
                    shell_println!("Stored: {}", hex);
                }
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "get" => {
            if let Some(hex) = parts.get(1) {
                if let Some(hash) = cas::hex_to_hash(hex) {
                    match cas::get(&hash) {
                        Ok(data) => {
                            if let Ok(s) = core::str::from_utf8(&data) {
                                shell_println!("{}", s);
                            } else {
                                shell_println!("({} bytes, binary)", data.len());
                            }
                        }
                        Err(e) => shell_println!("Error: {:?}", e),
                    }
                } else {
                    shell_println!("Invalid hash hex");
                }
            } else {
                shell_println!("Usage: cas get <hash>");
            }
        }
        "has" => {
            if let Some(hex) = parts.get(1) {
                if let Some(hash) = cas::hex_to_hash(hex) {
                    shell_println!("{}", if cas::has(&hash) { "yes" } else { "no" });
                } else {
                    shell_println!("Invalid hash hex");
                }
            } else {
                shell_println!("Usage: cas has <hash>");
            }
        }
        "release" => {
            if let Some(hex) = parts.get(1) {
                if let Some(hash) = cas::hex_to_hash(hex) {
                    match cas::release(&hash) {
                        Ok(()) => shell_println!("Released"),
                        Err(e) => shell_println!("Error: {:?}", e),
                    }
                } else {
                    shell_println!("Invalid hash hex");
                }
            } else {
                shell_println!("Usage: cas release <hash>");
            }
        }
        "gc" => {
            let (collected, freed) = cas::gc();
            shell_println!("GC: {} blobs collected, {} bytes freed", collected, freed);
        }
        "limit" => {
            if let Some(val) = parts.get(1) {
                if let Ok(max) = val.parse::<u64>() {
                    cas::set_max_bytes(max);
                    shell_println!("Max bytes set to {}", max);
                } else {
                    shell_println!("Invalid number");
                }
            } else {
                let s = cas::stats();
                shell_println!("Current limit: {} bytes", s.max_bytes);
            }
        }
        _ => {
            shell_println!("Usage: cas [stats|put|get|has|release|gc|limit]");
            shell_println!("  stats           — show store statistics");
            shell_println!("  put <data>      — store data, print hash");
            shell_println!("  get <hash>      — retrieve data by hash");
            shell_println!("  has <hash>      — check if hash exists");
            shell_println!("  release <hash>  — decrement refcount");
            shell_println!("  gc              — garbage collect zero-ref blobs");
            shell_println!("  limit [bytes]   — show/set max byte limit");
        }
    }
}

/// `logrotate` / `lrot` — log rotation management.
fn cmd_logrotate(args: &str) {
    use crate::fs::logrotate;
    let parts: Vec<&str> = args.split_whitespace().collect();
    let sub = parts.first().copied().unwrap_or("");
    match sub {
        "stats" | "" => {
            let (rule_count, rotations, bytes_rotated, cleanups, ops) = logrotate::stats();
            shell_println!("=== Log Rotation ===");
            shell_println!("  Rules:          {}", rule_count);
            shell_println!("  Total rotations: {}", rotations);
            shell_println!("  Bytes rotated:  {}", bytes_rotated);
            shell_println!("  Cleanups:       {}", cleanups);
            shell_println!("  Ops:            {}", ops);
        }
        "list" => {
            logrotate::init_defaults();
            let rules = logrotate::list_rules();
            if rules.is_empty() {
                shell_println!("No rotation rules configured.");
            } else {
                shell_println!("{:<4} {:<30} {:<10} {:<8} {}", "ID", "Path", "Compress", "Max", "Enabled");
                for r in &rules {
                    shell_println!("{:<4} {:<30} {:<10} {:<8} {}",
                        r.id, r.log_path, r.compress.label(), r.max_archives,
                        if r.enabled { "yes" } else { "no" });
                }
            }
        }
        "add" => {
            if let Some(path) = parts.get(1) {
                logrotate::init_defaults();
                let compress = parse_logrotate_compress(parts.get(2).copied().unwrap_or("gzip"));
                let max = parts.get(3).and_then(|v| v.parse::<u32>().ok()).unwrap_or(7);
                match logrotate::add_rule(path, logrotate::RotateTrigger::Daily, compress, max) {
                    Ok(id) => shell_println!("Rule {} added for {}", id, path),
                    Err(e) => shell_println!("Error: {:?}", e),
                }
            } else {
                shell_println!("Usage: logrotate add <path> [compress] [max_archives]");
            }
        }
        "remove" => {
            if let Some(id_str) = parts.get(1) {
                if let Ok(id) = id_str.parse::<u32>() {
                    match logrotate::remove_rule(id) {
                        Ok(()) => shell_println!("Rule {} removed", id),
                        Err(e) => shell_println!("Error: {:?}", e),
                    }
                } else { shell_println!("Invalid ID"); }
            } else { shell_println!("Usage: logrotate remove <id>"); }
        }
        "rotate" => {
            if let Some(id_str) = parts.get(1) {
                if let Ok(id) = id_str.parse::<u32>() {
                    match logrotate::rotate(id) {
                        Ok(bytes) => shell_println!("Rotated: {} bytes", bytes),
                        Err(e) => shell_println!("Error: {:?}", e),
                    }
                } else { shell_println!("Invalid ID"); }
            } else {
                logrotate::init_defaults();
                match logrotate::check_all() {
                    Ok(n) => shell_println!("Rotated {} logs", n),
                    Err(e) => shell_println!("Error: {:?}", e),
                }
            }
        }
        "events" => {
            let events = logrotate::list_events();
            if events.is_empty() {
                shell_println!("No rotation events.");
            } else {
                for e in events.iter().rev().take(20) {
                    shell_println!("  Rule {}: {} ({} bytes)", e.rule_id, e.archive_name, e.original_size);
                }
            }
        }
        _ => {
            shell_println!("Usage: logrotate [stats|list|add|remove|rotate|events]");
        }
    }
}

fn parse_logrotate_compress(s: &str) -> crate::fs::logrotate::CompressMethod {
    use crate::fs::logrotate::CompressMethod;
    match s {
        "none" => CompressMethod::None,
        "gzip" | "gz" => CompressMethod::Gzip,
        "bzip2" | "bz2" => CompressMethod::Bzip2,
        "xz" => CompressMethod::Xz,
        "zstd" | "zst" => CompressMethod::Zstd,
        _ => CompressMethod::Gzip,
    }
}

/// `powerwake` / `pwake` — wake-on-LAN and scheduled wake management.
fn cmd_powerwake(args: &str) {
    use crate::fs::powerwake;
    let parts: Vec<&str> = args.split_whitespace().collect();
    let sub = parts.first().copied().unwrap_or("");
    match sub {
        "stats" | "" => {
            let (timers, wol_targets, total_wakes, wol_sent, ops) = powerwake::stats();
            shell_println!("=== Power Wake ===");
            shell_println!("  Active timers:  {}", timers);
            shell_println!("  WoL targets:    {}", wol_targets);
            shell_println!("  Total wakes:    {}", total_wakes);
            shell_println!("  WoL packets:    {}", wol_sent);
            shell_println!("  Ops:            {}", ops);
        }
        "timers" => {
            powerwake::init_defaults();
            let timers = powerwake::list_timers();
            if timers.is_empty() {
                shell_println!("No wake timers.");
            } else {
                shell_println!("{:<4} {:<20} {:<10} {}", "ID", "Reason", "Recurring", "Enabled");
                for t in &timers {
                    shell_println!("{:<4} {:<20} {:<10} {}",
                        t.id, t.reason,
                        if t.recurring { "yes" } else { "no" },
                        if t.enabled { "yes" } else { "no" });
                }
            }
        }
        "schedule" => {
            let reason = parts.get(1..).map(|p| p.join(" ")).unwrap_or_default();
            if reason.is_empty() {
                shell_println!("Usage: powerwake schedule <reason>");
                return;
            }
            powerwake::init_defaults();
            let future = crate::hpet::elapsed_ns() + 3_600_000_000_000; // 1 hour
            match powerwake::schedule_wake(future, &reason, false, 0) {
                Ok(id) => shell_println!("Timer {} scheduled", id),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "cancel" => {
            if let Some(id_str) = parts.get(1) {
                if let Ok(id) = id_str.parse::<u32>() {
                    match powerwake::cancel_timer(id) {
                        Ok(()) => shell_println!("Timer {} cancelled", id),
                        Err(e) => shell_println!("Error: {:?}", e),
                    }
                } else { shell_println!("Invalid ID"); }
            } else { shell_println!("Usage: powerwake cancel <id>"); }
        }
        "wol" => {
            match parts.get(1).copied() {
                Some("add") => {
                    if let (Some(name), Some(mac)) = (parts.get(2), parts.get(3)) {
                        powerwake::init_defaults();
                        match powerwake::add_wol_target(name, mac) {
                            Ok(id) => shell_println!("WoL target {} added: {} ({})", id, name, mac),
                            Err(e) => shell_println!("Error: {:?}", e),
                        }
                    } else { shell_println!("Usage: powerwake wol add <name> <mac>"); }
                }
                Some("send") => {
                    if let Some(id_str) = parts.get(2) {
                        if let Ok(id) = id_str.parse::<u32>() {
                            match powerwake::send_wol(id) {
                                Ok(()) => shell_println!("WoL packet sent"),
                                Err(e) => shell_println!("Error: {:?}", e),
                            }
                        } else { shell_println!("Invalid ID"); }
                    } else { shell_println!("Usage: powerwake wol send <id>"); }
                }
                Some("list") | None => {
                    powerwake::init_defaults();
                    let targets = powerwake::list_wol_targets();
                    if targets.is_empty() {
                        shell_println!("No WoL targets.");
                    } else {
                        shell_println!("{:<4} {:<15} {:<20} {}", "ID", "Name", "MAC", "Sent");
                        for w in &targets {
                            shell_println!("{:<4} {:<15} {:<20} {}", w.id, w.name, w.mac_address, w.send_count);
                        }
                    }
                }
                Some("remove") => {
                    if let Some(id_str) = parts.get(2) {
                        if let Ok(id) = id_str.parse::<u32>() {
                            match powerwake::remove_wol_target(id) {
                                Ok(()) => shell_println!("WoL target {} removed", id),
                                Err(e) => shell_println!("Error: {:?}", e),
                            }
                        } else { shell_println!("Invalid ID"); }
                    } else { shell_println!("Usage: powerwake wol remove <id>"); }
                }
                _ => { shell_println!("Usage: powerwake wol [list|add|send|remove]"); }
            }
        }
        "history" => {
            powerwake::init_defaults();
            let hist = powerwake::wake_history();
            if hist.is_empty() {
                shell_println!("No wake history.");
            } else {
                for e in hist.iter().rev().take(20) {
                    shell_println!("  {} — {}", e.source.label(), e.detail);
                }
            }
        }
        _ => {
            shell_println!("Usage: powerwake [stats|timers|schedule|cancel|wol|history]");
        }
    }
}

/// `diskio` / `dio` — disk I/O statistics.
fn cmd_diskio(args: &str) {
    use crate::fs::diskio;
    let parts: Vec<&str> = args.split_whitespace().collect();
    let sub = parts.first().copied().unwrap_or("");
    match sub {
        "stats" | "" => {
            let (dev_count, reads, writes, br, bw, ops) = diskio::stats();
            shell_println!("=== Disk I/O ===");
            shell_println!("  Devices:        {}", dev_count);
            shell_println!("  Global reads:   {}", reads);
            shell_println!("  Global writes:  {}", writes);
            shell_println!("  Bytes read:     {}", br);
            shell_println!("  Bytes written:  {}", bw);
            shell_println!("  Ops:            {}", ops);
        }
        "list" => {
            diskio::init_defaults();
            let devs = diskio::all_devices();
            if devs.is_empty() {
                shell_println!("No I/O recorded yet.");
            } else {
                shell_println!("{:<12} {:>8} {:>8} {:>12} {:>12} {:>10} {:>10}",
                    "Device", "Reads", "Writes", "BytesRead", "BytesWrite", "AvgRd(ns)", "AvgWr(ns)");
                for d in &devs {
                    shell_println!("{:<12} {:>8} {:>8} {:>12} {:>12} {:>10} {:>10}",
                        d.device_name, d.reads, d.writes, d.bytes_read, d.bytes_written,
                        d.avg_read_latency_ns(), d.avg_write_latency_ns());
                }
            }
        }
        "device" => {
            if let Some(name) = parts.get(1) {
                match diskio::device_stats(name) {
                    Some(d) => {
                        shell_println!("=== {} ===", d.device_name);
                        shell_println!("  Reads:          {} ({} bytes)", d.reads, d.bytes_read);
                        shell_println!("  Writes:         {} ({} bytes)", d.writes, d.bytes_written);
                        shell_println!("  Avg read lat:   {} ns", d.avg_read_latency_ns());
                        shell_println!("  Max read lat:   {} ns", d.read_latency_max_ns);
                        shell_println!("  Avg write lat:  {} ns", d.avg_write_latency_ns());
                        shell_println!("  Max write lat:  {} ns", d.write_latency_max_ns);
                        shell_println!("  Read errors:    {}", d.read_errors);
                        shell_println!("  Write errors:   {}", d.write_errors);
                    }
                    None => shell_println!("Device '{}' not found", name),
                }
            } else { shell_println!("Usage: diskio device <name>"); }
        }
        "reset" => {
            if let Some(name) = parts.get(1) {
                match diskio::reset_device(name) {
                    Ok(()) => shell_println!("Stats for '{}' reset", name),
                    Err(e) => shell_println!("Error: {:?}", e),
                }
            } else { shell_println!("Usage: diskio reset <device>"); }
        }
        _ => {
            shell_println!("Usage: diskio [stats|list|device|reset]");
        }
    }
}

/// `sysuptime` / `suptime` — system uptime tracking.
fn cmd_sysuptime(args: &str) {
    use crate::fs::sysuptime;
    let parts: Vec<&str> = args.split_whitespace().collect();
    let sub = parts.first().copied().unwrap_or("");
    match sub {
        "" | "show" => {
            sysuptime::init_defaults();
            let uptime = sysuptime::current_uptime_ns();
            let formatted = sysuptime::format_duration(uptime);
            let session = sysuptime::current_session_id();
            let longest = sysuptime::longest_uptime_ns();
            shell_println!("=== System Uptime ===");
            shell_println!("  Current uptime: {}", formatted);
            shell_println!("  Session ID:     {}", session);
            shell_println!("  Longest ever:   {}", sysuptime::format_duration(longest));
        }
        "history" => {
            sysuptime::init_defaults();
            let hist = sysuptime::history();
            if hist.is_empty() {
                shell_println!("No shutdown history.");
            } else {
                shell_println!("{:<6} {:<20} {}", "ID", "Duration", "Reason");
                for s in hist.iter().rev().take(20) {
                    shell_println!("{:<6} {:<20} {}",
                        s.session_id,
                        sysuptime::format_duration(s.duration_ns),
                        s.shutdown_reason.label());
                }
            }
        }
        "stats" => {
            let (hist_count, total_sessions, longest, total_uptime, ops) = sysuptime::stats();
            shell_println!("=== Uptime Statistics ===");
            shell_println!("  History entries: {}", hist_count);
            shell_println!("  Total sessions:  {}", total_sessions);
            shell_println!("  Longest uptime:  {}", sysuptime::format_duration(longest));
            shell_println!("  Total uptime:    {}", sysuptime::format_duration(total_uptime));
            shell_println!("  Ops:             {}", ops);
        }
        _ => {
            shell_println!("Usage: sysuptime [show|history|stats]");
        }
    }
}

/// `netspeed` / `nspeed` — network speed testing and bandwidth.
fn cmd_netspeed(args: &str) {
    use crate::fs::netspeed;
    let parts: Vec<&str> = args.split_whitespace().collect();
    let sub = parts.first().copied().unwrap_or("");
    match sub {
        "stats" | "" => {
            let (results, ifaces, total_tests, ops) = netspeed::stats();
            shell_println!("=== Network Speed ===");
            shell_println!("  Test results:   {}", results);
            shell_println!("  Interfaces:     {}", ifaces);
            shell_println!("  Total tests:    {}", total_tests);
            shell_println!("  Ops:            {}", ops);
        }
        "test" => {
            let iface = parts.get(1).copied().unwrap_or("eth0");
            netspeed::init_defaults();
            let _ = iface; // honest run_test no longer takes a measurement
            match netspeed::run_test(iface) {
                Ok(r) => {
                    shell_println!("=== Speed Test: {} ===", r.interface);
                    shell_println!("  Download: {}", netspeed::format_speed(r.download_bps));
                    shell_println!("  Upload:   {}", netspeed::format_speed(r.upload_bps));
                    shell_println!("  Latency:  {} ms", r.latency_ms);
                    shell_println!("  Jitter:   {} ms", r.jitter_ms);
                    shell_println!("  Server:   {}", r.server);
                }
                // run_test no longer fabricates results; speed testing needs a
                // real throughput-measurement backend (see fs::netspeed).
                Err(crate::error::KernelError::NotSupported) => {
                    shell_println!("Speed testing is not yet implemented.");
                    shell_println!("(It requires a network measurement backend to record real throughput.)");
                    shell_println!("Use `netspeed bandwidth` to view real per-interface byte counters.");
                }
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "bandwidth" => {
            netspeed::init_defaults();
            let snaps = netspeed::bandwidth_snapshots();
            if snaps.is_empty() {
                shell_println!("No bandwidth data.");
            } else {
                shell_println!("{:<12} {:>12} {:>12} {:>10} {:>10}",
                    "Interface", "RX Bytes", "TX Bytes", "RX Pkts", "TX Pkts");
                for s in &snaps {
                    shell_println!("{:<12} {:>12} {:>12} {:>10} {:>10}",
                        s.interface, s.rx_bytes, s.tx_bytes, s.rx_packets, s.tx_packets);
                }
            }
        }
        "history" => {
            let hist = netspeed::test_history();
            if hist.is_empty() {
                shell_println!("No test history.");
            } else {
                for r in hist.iter().rev().take(10) {
                    shell_println!("  #{}: {} — ↓{} ↑{} ({}ms)",
                        r.id, r.interface,
                        netspeed::format_speed(r.download_bps),
                        netspeed::format_speed(r.upload_bps),
                        r.latency_ms);
                }
            }
        }
        _ => {
            shell_println!("Usage: netspeed [stats|test|bandwidth|history]");
        }
    }
}

/// `cfreq` — CPU frequency scaling management (fs::cpufreq).
fn cmd_cfreq(args: &str) {
    use crate::fs::cpufreq;
    let parts: Vec<&str> = args.split_whitespace().collect();
    let sub = parts.first().copied().unwrap_or("");
    match sub {
        "" | "list" => {
            cpufreq::init_defaults();
            let cpus = cpufreq::list_cpus();
            if cpus.is_empty() {
                shell_println!("No CPUs found.");
            } else {
                shell_println!("{:<6} {:>12} {:>12} {:>12} {:<12}",
                    "CPU", "Current", "Min", "Max", "Governor");
                for c in &cpus {
                    shell_println!("{:<6} {:>12} {:>12} {:>12} {:<12}",
                        c.cpu_id,
                        cpufreq::format_freq(c.current_khz),
                        cpufreq::format_freq(c.scaling_min_khz),
                        cpufreq::format_freq(c.scaling_max_khz),
                        c.governor.label());
                }
                shell_println!("Boost: {}", if cpufreq::boost_enabled() { "enabled" } else { "disabled" });
            }
        }
        "governor" => {
            if let Some(gov_str) = parts.get(1) {
                cpufreq::init_defaults();
                let gov = parse_cpufreq_governor(gov_str);
                match cpufreq::set_governor(gov) {
                    Ok(()) => shell_println!("Governor set to {}", gov.label()),
                    Err(e) => shell_println!("Error: {:?}", e),
                }
            } else {
                if let Some(gov) = cpufreq::get_governor() {
                    shell_println!("Current governor: {}", gov.label());
                } else {
                    shell_println!("Not initialized");
                }
            }
        }
        "boost" => {
            match parts.get(1).copied() {
                Some("on") | Some("enable") => {
                    cpufreq::init_defaults();
                    cpufreq::set_boost(true).expect("boost");
                    shell_println!("Boost enabled");
                }
                Some("off") | Some("disable") => {
                    cpufreq::init_defaults();
                    cpufreq::set_boost(false).expect("boost");
                    shell_println!("Boost disabled");
                }
                _ => {
                    shell_println!("Boost: {}", if cpufreq::boost_enabled() { "enabled" } else { "disabled" });
                }
            }
        }
        "stats" => {
            let (cpu_count, transitions, gov_changes, boost, ops) = cpufreq::stats();
            shell_println!("=== CPU Frequency Stats ===");
            shell_println!("  CPUs:             {}", cpu_count);
            shell_println!("  Transitions:      {}", transitions);
            shell_println!("  Governor changes: {}", gov_changes);
            shell_println!("  Boost:            {}", boost);
            shell_println!("  Ops:              {}", ops);
        }
        _ => {
            shell_println!("Usage: cpufreq [list|governor|boost|stats]");
        }
    }
}

fn parse_cpufreq_governor(s: &str) -> crate::fs::cpufreq::Governor {
    use crate::fs::cpufreq::Governor;
    match s {
        "performance" | "perf" => Governor::Performance,
        "powersave" | "power" => Governor::Powersave,
        "ondemand" | "od" => Governor::OnDemand,
        "conservative" | "cons" => Governor::Conservative,
        "schedutil" | "su" => Governor::Schedutil,
        "userspace" | "user" => Governor::Userspace,
        _ => Governor::Schedutil,
    }
}

/// `therm` — system thermal monitoring (fs::thermal).
fn cmd_therm(args: &str) {
    use crate::fs::thermal;
    let parts: Vec<&str> = args.split_whitespace().collect();
    let sub = parts.first().copied().unwrap_or("");
    match sub {
        "" | "zones" => {
            thermal::init_defaults();
            let zones = thermal::list_zones();
            if zones.is_empty() {
                shell_println!("No thermal zones.");
            } else {
                shell_println!("{:<4} {:<20} {:<8} {:>10} {:>10} {:>10} {}",
                    "ID", "Name", "Type", "Current", "Passive", "Critical", "Throttled");
                for z in &zones {
                    shell_println!("{:<4} {:<20} {:<8} {:>10} {:>10} {:>10} {}",
                        z.id, z.name, z.zone_type.label(),
                        thermal::format_temp(z.temp_mc),
                        thermal::format_temp(z.passive_trip_mc),
                        thermal::format_temp(z.critical_trip_mc),
                        if z.throttled { "YES" } else { "no" });
                }
            }
        }
        "fans" => {
            thermal::init_defaults();
            let fans = thermal::list_fans();
            if fans.is_empty() {
                shell_println!("No fans detected.");
            } else {
                shell_println!("{:<4} {:<20} {:>8} {:>8} {:>6} {:<10}",
                    "ID", "Name", "RPM", "Max RPM", "Duty%", "Mode");
                for f in &fans {
                    shell_println!("{:<4} {:<20} {:>8} {:>8} {:>5}% {:<10}",
                        f.id, f.name, f.rpm, f.max_rpm, f.duty_pct, f.mode.label());
                }
            }
        }
        "fan" => {
            if let (Some(id_str), Some(duty_str)) = (parts.get(1), parts.get(2)) {
                if let (Ok(id), Ok(duty)) = (id_str.parse::<u32>(), duty_str.parse::<u8>()) {
                    thermal::init_defaults();
                    match thermal::set_fan_duty(id, duty) {
                        Ok(()) => shell_println!("Fan {} set to {}%", id, duty),
                        Err(e) => shell_println!("Error: {:?}", e),
                    }
                } else { shell_println!("Invalid arguments"); }
            } else { shell_println!("Usage: thermal fan <id> <duty%>"); }
        }
        "stats" => {
            let (zones, fans, readings, throttles, ops) = thermal::stats();
            shell_println!("=== Thermal Stats ===");
            shell_println!("  Zones:           {}", zones);
            shell_println!("  Fans:            {}", fans);
            shell_println!("  Total readings:  {}", readings);
            shell_println!("  Throttle events: {}", throttles);
            shell_println!("  Ops:             {}", ops);
        }
        _ => {
            shell_println!("Usage: thermal [zones|fans|fan|stats]");
        }
    }
}

/// `swapmon` / `smon` — swap usage monitoring.
fn cmd_swapmon(args: &str) {
    use crate::fs::swapmon;
    let parts: Vec<&str> = args.split_whitespace().collect();
    let sub = parts.first().copied().unwrap_or("");
    match sub {
        "" | "show" => {
            swapmon::init_defaults();
            let (total, used) = swapmon::total_usage();
            let pct = if total > 0 { used * 100 / total } else { 0 };
            shell_println!("=== Swap Usage ===");
            shell_println!("  Total: {} bytes", total);
            shell_println!("  Used:  {} bytes ({}%)", used, pct);
            shell_println!("  Free:  {} bytes", total.saturating_sub(used));
        }
        "devices" => {
            swapmon::init_defaults();
            let devs = swapmon::list_devices();
            if devs.is_empty() {
                shell_println!("No swap devices.");
            } else {
                shell_println!("{:<4} {:<20} {:<10} {:>12} {:>12} {:>5} {}",
                    "ID", "Path", "Type", "Total", "Used", "Use%", "Enabled");
                for d in &devs {
                    shell_println!("{:<4} {:<20} {:<10} {:>12} {:>12} {:>4}% {}",
                        d.id, d.path, d.swap_type.label(),
                        d.total_bytes, d.used_bytes, d.usage_pct(),
                        if d.enabled { "yes" } else { "no" });
                }
            }
        }
        "processes" => {
            swapmon::init_defaults();
            let procs = swapmon::list_processes();
            if procs.is_empty() {
                shell_println!("No processes using swap.");
            } else {
                shell_println!("{:<8} {:<20} {:>12}", "PID", "Name", "Swap Bytes");
                for p in procs.iter().take(20) {
                    shell_println!("{:<8} {:<20} {:>12}", p.pid, p.name, p.swap_bytes);
                }
            }
        }
        "stats" => {
            let (devs, procs, swap_in, swap_out, in_bytes, out_bytes, ops) = swapmon::stats();
            shell_println!("=== Swap Statistics ===");
            shell_println!("  Devices:        {}", devs);
            shell_println!("  Swapped procs:  {}", procs);
            shell_println!("  Total swap-in:  {} ({} bytes)", swap_in, in_bytes);
            shell_println!("  Total swap-out: {} ({} bytes)", swap_out, out_bytes);
            shell_println!("  Ops:            {}", ops);
        }
        _ => {
            shell_println!("Usage: swapmon [show|devices|processes|stats]");
        }
    }
}

/// `sysctlfs` / `sctlfs` — system parameter tuning.
fn cmd_sysctlfs(args: &str) {
    use crate::fs::sysctlfs;
    let parts: Vec<&str> = args.split_whitespace().collect();
    let sub = parts.first().copied().unwrap_or("");
    match sub {
        "" | "list" => {
            sysctlfs::init_defaults();
            let params = if let Some(prefix) = parts.get(1) {
                sysctlfs::list_prefix(prefix)
            } else {
                sysctlfs::list_all()
            };
            for p in &params {
                let modified = if p.modified { " [modified]" } else { "" };
                let ro = if p.read_only { " (ro)" } else { "" };
                shell_println!("{} = {}{}{}", p.key, p.value, ro, modified);
            }
            if params.is_empty() { shell_println!("No matching parameters."); }
        }
        "get" => {
            if let Some(key) = parts.get(1) {
                sysctlfs::init_defaults();
                match sysctlfs::get(key) {
                    Ok(val) => shell_println!("{} = {}", key, val),
                    Err(e) => shell_println!("Error: {:?}", e),
                }
            } else { shell_println!("Usage: sysctlfs get <key>"); }
        }
        "set" => {
            if let (Some(key), Some(val)) = (parts.get(1), parts.get(2)) {
                sysctlfs::init_defaults();
                match sysctlfs::set(key, val) {
                    Ok(()) => shell_println!("{} = {}", key, val),
                    Err(e) => shell_println!("Error: {:?}", e),
                }
            } else { shell_println!("Usage: sysctlfs set <key> <value>"); }
        }
        "modified" => {
            sysctlfs::init_defaults();
            let modified = sysctlfs::list_modified();
            if modified.is_empty() {
                shell_println!("No modified parameters.");
            } else {
                for p in &modified {
                    shell_println!("{} = {}", p.key, p.value);
                }
            }
        }
        "stats" => {
            let (count, reads, writes, modified, ops) = sysctlfs::stats();
            shell_println!("=== Sysctl Stats ===");
            shell_println!("  Parameters: {}", count);
            shell_println!("  Reads:      {}", reads);
            shell_println!("  Writes:     {}", writes);
            shell_println!("  Modified:   {}", modified);
            shell_println!("  Ops:        {}", ops);
        }
        _ => {
            shell_println!("Usage: sysctlfs [list|get|set|modified|stats]");
        }
    }
}

/// `cputopo` / `ctopo` — CPU topology information.
fn cmd_cputopo(args: &str) {
    use crate::fs::cputopo;
    let parts: Vec<&str> = args.split_whitespace().collect();
    let sub = parts.first().copied().unwrap_or("");
    match sub {
        "" | "show" => {
            cputopo::init_defaults();
            let pkgs = cputopo::packages();
            for pkg in &pkgs {
                shell_println!("Package {}: {}", pkg.id, pkg.model_name);
                shell_println!("  Cores: {}, Threads/core: {}, Total: {}",
                    pkg.cores, pkg.threads_per_core, pkg.total_threads);
            }
            shell_println!("SMT: {}", if cputopo::smt_enabled() { "enabled" } else { "disabled" });
            shell_println!("Online: {}/{}", cputopo::online_count(), cputopo::cpu_count());
        }
        "cpus" => {
            cputopo::init_defaults();
            let cpus = cputopo::list_cpus();
            shell_println!("{:<6} {:<8} {:<6} {:<8} {:<6} {}",
                "CPU", "Package", "Core", "Thread", "NUMA", "Online");
            for c in &cpus {
                shell_println!("{:<6} {:<8} {:<6} {:<8} {:<6} {}",
                    c.id, c.package_id, c.core_id, c.thread_id, c.numa_node,
                    if c.online { "yes" } else { "no" });
            }
        }
        "cache" => {
            cputopo::init_defaults();
            let caches = cputopo::cache_info();
            shell_println!("{:<6} {:>8} {:>8} {:>6} {:>8}",
                "Level", "Size", "Line", "Assoc", "Shared");
            for c in &caches {
                shell_println!("{:<6} {:>6}KB {:>6}B {:>6} {:>8}",
                    c.cache_type.label(), c.size_kb, c.line_size, c.associativity, c.shared_by_threads);
            }
        }
        "siblings" => {
            if let Some(id_str) = parts.get(1) {
                if let Ok(id) = id_str.parse::<u32>() {
                    let siblings = cputopo::thread_siblings(id);
                    if siblings.is_empty() {
                        shell_println!("CPU {} has no thread siblings", id);
                    } else {
                        shell_println!("CPU {} siblings: {:?}", id, siblings);
                    }
                } else { shell_println!("Invalid CPU ID"); }
            } else { shell_println!("Usage: cputopo siblings <cpu_id>"); }
        }
        "stats" => {
            let (cpus, pkgs, numa, smt, queries, ops) = cputopo::stats();
            shell_println!("=== CPU Topology Stats ===");
            shell_println!("  Logical CPUs: {}", cpus);
            shell_println!("  Packages:     {}", pkgs);
            shell_println!("  NUMA nodes:   {}", numa);
            shell_println!("  SMT:          {}", smt);
            shell_println!("  Queries:      {}", queries);
            shell_println!("  Ops:          {}", ops);
        }
        _ => {
            shell_println!("Usage: cputopo [show|cpus|cache|siblings|stats]");
        }
    }
}

/// `memlayout` / `mlayout` — memory layout information.
fn cmd_memlayout(args: &str) {
    use crate::fs::memlayout;
    let parts: Vec<&str> = args.split_whitespace().collect();
    let sub = parts.first().copied().unwrap_or("");
    match sub {
        "" | "show" => {
            memlayout::init_defaults();
            shell_println!("=== Memory Layout ===");
            shell_println!("  Total RAM:      {}", memlayout::format_size(memlayout::total_ram()));
            shell_println!("  Reserved:       {}", memlayout::format_size(memlayout::total_reserved()));
            shell_println!("  Kernel:         {}", memlayout::format_size(memlayout::total_kernel()));
        }
        "regions" => {
            memlayout::init_defaults();
            let regions = memlayout::list_regions();
            shell_println!("{:<18} {:>12} {:<18} {}", "Start", "Size", "Type", "Description");
            for r in &regions {
                shell_println!("0x{:016X} {:>12} {:<18} {}",
                    r.start, memlayout::format_size(r.size), r.region_type.label(), r.description);
            }
        }
        "stats" => {
            let (count, ram, reserved, kernel, queries, ops) = memlayout::stats();
            shell_println!("=== Memory Layout Stats ===");
            shell_println!("  Regions:    {}", count);
            shell_println!("  RAM:        {}", memlayout::format_size(ram));
            shell_println!("  Reserved:   {}", memlayout::format_size(reserved));
            shell_println!("  Kernel:     {}", memlayout::format_size(kernel));
            shell_println!("  Queries:    {}", queries);
            shell_println!("  Ops:        {}", ops);
        }
        _ => {
            shell_println!("Usage: memlayout [show|regions|stats]");
        }
    }
}

/// `lavg` — fs-zone load average tracking (EMA-based).
fn cmd_lavg(args: &str) {
    use crate::fs::loadavg;
    let parts: Vec<&str> = args.split_whitespace().collect();
    let sub = parts.first().copied().unwrap_or("");
    match sub {
        "status" | "" => {
            loadavg::init_defaults();
            let (avg1, avg5, avg15, running, total) = loadavg::get();
            shell_println!("Load averages (×1000 fixed-point):");
            shell_println!("  1min:  {}", loadavg::format_load(avg1));
            shell_println!("  5min:  {}", loadavg::format_load(avg5));
            shell_println!("  15min: {}", loadavg::format_load(avg15));
            shell_println!("  Running/Total: {}/{}", running, total);
        }
        "update" => {
            loadavg::init_defaults();
            let running = parts.get(1).and_then(|s| s.parse::<u32>().ok()).unwrap_or(1);
            let total = parts.get(2).and_then(|s| s.parse::<u32>().ok()).unwrap_or(10);
            if let Err(e) = loadavg::update(running, total) {
                shell_println!("Error: {:?}", e);
            } else {
                shell_println!("Load average updated with {}/{} running/total", running, total);
            }
        }
        "history" => {
            let snaps = loadavg::history();
            if snaps.is_empty() {
                shell_println!("No load history recorded.");
            } else {
                shell_println!("{} load snapshots:", snaps.len());
                let show = if snaps.len() > 10 { &snaps[snaps.len()-10..] } else { &snaps };
                for s in show {
                    shell_println!("  1m={} 5m={} 15m={} {}/{} @{}ns",
                        loadavg::format_load(s.avg_1m), loadavg::format_load(s.avg_5m),
                        loadavg::format_load(s.avg_15m), s.running, s.total, s.timestamp_ns);
                }
            }
        }
        "stats" => {
            loadavg::init_defaults();
            let (hist, updates, ops) = loadavg::stats();
            shell_println!("Load average stats:");
            shell_println!("  History entries: {}", hist);
            shell_println!("  Total updates:   {}", updates);
            shell_println!("  Operations:      {}", ops);
        }
        "test" => {
            loadavg::self_test();
            shell_println!("loadavg self-test passed.");
        }
        _ => {
            shell_println!("Usage: lavg [status|update <tasks>|history|stats|test]");
        }
    }
}

/// `kernlog` / `klog` — kernel log ring buffer.
fn cmd_kernlog(args: &str) {
    use crate::fs::kernlog;
    let parts: Vec<&str> = args.split_whitespace().collect();
    let sub = parts.first().copied().unwrap_or("");
    match sub {
        "dmesg" | "" => {
            kernlog::init_defaults();
            let msgs = kernlog::dmesg();
            if msgs.is_empty() {
                shell_println!("No kernel log messages.");
            } else {
                shell_println!("{} messages:", msgs.len());
                let show = if msgs.len() > 20 { &msgs[msgs.len()-20..] } else { &msgs };
                for e in show {
                    shell_println!("  [{}] <{}> {}: {}", e.seq, e.level.label(), e.source, e.message);
                }
            }
        }
        "log" => {
            kernlog::init_defaults();
            let level_str = parts.get(1).copied().unwrap_or("info");
            let source = parts.get(2).copied().unwrap_or("kshell");
            let msg: alloc::string::String = parts.get(3..).map_or(
                alloc::string::String::from("test message"),
                |p| p.join(" "),
            );
            let level = parse_kernlog_level(level_str);
            match kernlog::log(level, source, &msg) {
                Ok(seq) => shell_println!("Logged as seq {}", seq),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "tail" => {
            kernlog::init_defaults();
            let n = parts.get(1).and_then(|s| s.parse::<usize>().ok()).unwrap_or(10);
            let msgs = kernlog::tail(n);
            for e in &msgs {
                shell_println!("  [{}] <{}> {}: {}", e.seq, e.level.label(), e.source, e.message);
            }
        }
        "filter" => {
            kernlog::init_defaults();
            let kind = parts.get(1).copied().unwrap_or("");
            let val = parts.get(2).copied().unwrap_or("");
            match kind {
                "level" => {
                    let level = parse_kernlog_level(val);
                    let msgs = kernlog::filter_level(level);
                    shell_println!("{} messages at level {}:", msgs.len(), level.label());
                    for e in &msgs {
                        shell_println!("  [{}] {}: {}", e.seq, e.source, e.message);
                    }
                }
                "source" => {
                    let msgs = kernlog::filter_source(val);
                    shell_println!("{} messages from '{}':", msgs.len(), val);
                    for e in &msgs {
                        shell_println!("  [{}] <{}> {}", e.seq, e.level.label(), e.message);
                    }
                }
                _ => shell_println!("Usage: kernlog filter <level|source> <value>"),
            }
        }
        "clear" => {
            kernlog::init_defaults();
            if let Err(e) = kernlog::clear() {
                shell_println!("Error: {:?}", e);
            } else {
                shell_println!("Kernel log cleared.");
            }
        }
        "stats" => {
            kernlog::init_defaults();
            let (count, total, dropped, ops) = kernlog::stats();
            shell_println!("Kernel log stats:");
            shell_println!("  Current messages: {}", count);
            shell_println!("  Total logged:     {}", total);
            shell_println!("  Dropped:          {}", dropped);
            shell_println!("  Operations:       {}", ops);
        }
        "test" => {
            kernlog::self_test();
            shell_println!("kernlog self-test passed.");
        }
        _ => {
            shell_println!("Usage: kernlog [dmesg|log <level> <source> <msg>|tail [n]|filter <level|source> <val>|clear|stats|test]");
        }
    }
}

fn parse_kernlog_level(s: &str) -> crate::fs::kernlog::LogLevel {
    use crate::fs::kernlog::LogLevel;
    match s {
        "emerg" | "emergency" => LogLevel::Emergency,
        "alert" => LogLevel::Alert,
        "crit" | "critical" => LogLevel::Critical,
        "err" | "error" => LogLevel::Error,
        "warn" | "warning" => LogLevel::Warning,
        "notice" => LogLevel::Notice,
        "info" => LogLevel::Info,
        "debug" | "dbg" => LogLevel::Debug,
        _ => LogLevel::Info,
    }
}

/// `coredump` / `cdump` — crash dump management.
fn cmd_coredump(args: &str) {
    use crate::fs::coredump;
    let parts: Vec<&str> = args.split_whitespace().collect();
    let sub = parts.first().copied().unwrap_or("");
    match sub {
        "list" | "" => {
            coredump::init_defaults();
            let dumps = coredump::list_dumps();
            if dumps.is_empty() {
                shell_println!("No core dumps stored.");
            } else {
                shell_println!("{} core dump(s):", dumps.len());
                for d in &dumps {
                    shell_println!("  [{}] pid={} {} reason={} size={} path={}",
                        d.id, d.pid, d.process_name, d.reason.label(),
                        d.size_bytes, d.path);
                }
            }
        }
        "get" => {
            let id = parts.get(1).and_then(|s| s.parse::<u32>().ok()).unwrap_or(0);
            match coredump::get_dump(id) {
                Some(d) => {
                    shell_println!("Core dump #{}:", d.id);
                    shell_println!("  PID:      {}", d.pid);
                    shell_println!("  Process:  {}", d.process_name);
                    shell_println!("  Reason:   {}", d.reason.label());
                    shell_println!("  Signal:   {}", d.signal_code);
                    shell_println!("  Size:     {} bytes", d.size_bytes);
                    shell_println!("  Path:     {}", d.path);
                    shell_println!("  Time:     {}ns", d.timestamp_ns);
                }
                None => shell_println!("Dump {} not found.", id),
            }
        }
        "record" => {
            coredump::init_defaults();
            let pid = parts.get(1).and_then(|s| s.parse::<u32>().ok()).unwrap_or(1);
            let name = parts.get(2).copied().unwrap_or("test_process");
            let size = parts.get(3).and_then(|s| s.parse::<u64>().ok()).unwrap_or(4096);
            match coredump::record_dump(pid, name, coredump::DumpReason::Segfault, size, 11) {
                Ok(id) => shell_println!("Recorded core dump #{}", id),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "delete" | "rm" => {
            let id = parts.get(1).and_then(|s| s.parse::<u32>().ok()).unwrap_or(0);
            match coredump::delete_dump(id) {
                Ok(()) => shell_println!("Deleted dump {}.", id),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "cleanup" => {
            coredump::init_defaults();
            let keep = parts.get(1).and_then(|s| s.parse::<usize>().ok()).unwrap_or(10);
            match coredump::cleanup(keep) {
                Ok(n) => shell_println!("Cleaned up {} old dumps (keeping {}).", n, keep),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "enable" => {
            coredump::init_defaults();
            if let Err(e) = coredump::set_enabled(true) {
                shell_println!("Error: {:?}", e);
            } else {
                shell_println!("Core dumps enabled.");
            }
        }
        "disable" => {
            coredump::init_defaults();
            if let Err(e) = coredump::set_enabled(false) {
                shell_println!("Error: {:?}", e);
            } else {
                shell_println!("Core dumps disabled.");
            }
        }
        "stats" => {
            coredump::init_defaults();
            let (count, total, bytes, cleaned, ops) = coredump::stats();
            shell_println!("Core dump stats:");
            shell_println!("  Current dumps: {}", count);
            shell_println!("  Total dumps:   {}", total);
            shell_println!("  Total bytes:   {}", bytes);
            shell_println!("  Cleaned up:    {}", cleaned);
            shell_println!("  Operations:    {}", ops);
        }
        "test" => {
            coredump::self_test();
            shell_println!("coredump self-test passed.");
        }
        _ => {
            shell_println!("Usage: coredump [list|get <id>|record <pid> <name> <size>|delete <id>|cleanup [keep]|enable|disable|stats|test]");
        }
    }
}

/// `fwupdate` / `fwup` — firmware version management and update tracking.
fn cmd_fwupdate(args: &str) {
    use crate::fs::fwupdate;
    let parts: Vec<&str> = args.split_whitespace().collect();
    let sub = parts.first().copied().unwrap_or("");
    match sub {
        "list" | "" => {
            fwupdate::init_defaults();
            let devices = fwupdate::list_devices();
            if devices.is_empty() {
                shell_println!("No firmware devices.");
            } else {
                shell_println!("{} firmware device(s):", devices.len());
                for d in &devices {
                    let avail = d.available_version.as_deref().unwrap_or("-");
                    shell_println!("  [{}] {} ({}) v{} → {} [{}] vendor={}",
                        d.id, d.name, d.fw_type.label(), d.current_version,
                        avail, d.status.label(), d.vendor);
                }
            }
        }
        "get" => {
            let id = parts.get(1).and_then(|s| s.parse::<u32>().ok()).unwrap_or(0);
            match fwupdate::get_device(id) {
                Some(d) => {
                    let avail = d.available_version.as_deref().unwrap_or("none");
                    shell_println!("Firmware device #{}:", d.id);
                    shell_println!("  Name:      {}", d.name);
                    shell_println!("  Type:      {}", d.fw_type.label());
                    shell_println!("  Current:   {}", d.current_version);
                    shell_println!("  Available: {}", avail);
                    shell_println!("  Status:    {}", d.status.label());
                    shell_println!("  Vendor:    {}", d.vendor);
                }
                None => shell_println!("Device {} not found.", id),
            }
        }
        "check" => {
            fwupdate::init_defaults();
            match fwupdate::check_updates() {
                Ok(n) => shell_println!("{} firmware update(s) available.", n),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "apply" => {
            let id = parts.get(1).and_then(|s| s.parse::<u32>().ok()).unwrap_or(0);
            match fwupdate::apply_update(id) {
                Ok(()) => shell_println!("Firmware update applied for device {}. Reboot required.", id),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "history" => {
            let records = fwupdate::update_history();
            if records.is_empty() {
                shell_println!("No firmware update history.");
            } else {
                shell_println!("{} update record(s):", records.len());
                for r in &records {
                    let status = if r.success { "OK" } else { "FAILED" };
                    shell_println!("  dev={} ({}) {} → {} [{}] @{}ns",
                        r.device_id, r.device_name, r.from_version,
                        r.to_version, status, r.timestamp_ns);
                }
            }
        }
        "stats" => {
            fwupdate::init_defaults();
            let (devs, updates, failures, checks, ops) = fwupdate::stats();
            shell_println!("Firmware update stats:");
            shell_println!("  Devices:     {}", devs);
            shell_println!("  Updates:     {}", updates);
            shell_println!("  Failures:    {}", failures);
            shell_println!("  Checks:      {}", checks);
            shell_println!("  Operations:  {}", ops);
        }
        "test" => {
            fwupdate::self_test();
            shell_println!("fwupdate self-test passed.");
        }
        _ => {
            shell_println!("Usage: fwupdate [list|get <id>|check|apply <id>|history|stats|test]");
        }
    }
}

/// `timesync` / `tsync` — NTP time synchronization.
fn cmd_timesync(args: &str) {
    use crate::fs::timesync;
    let parts: Vec<&str> = args.split_whitespace().collect();
    let sub = parts.first().copied().unwrap_or("");
    match sub {
        "status" | "" => {
            timesync::init_defaults();
            let status = timesync::get_status();
            let (servers, syncs, errors, last, _) = timesync::stats();
            shell_println!("Time sync status: {}", status.label());
            shell_println!("  Servers:    {}", servers);
            shell_println!("  Syncs:      {}", syncs);
            shell_println!("  Errors:     {}", errors);
            if last > 0 {
                shell_println!("  Last sync:  {}ns", last);
            }
        }
        "list" => {
            timesync::init_defaults();
            let servers = timesync::list_servers();
            if servers.is_empty() {
                shell_println!("No NTP servers configured.");
            } else {
                shell_println!("{} server(s):", servers.len());
                for s in &servers {
                    let en = if s.enabled { "ON" } else { "OFF" };
                    shell_println!("  [{}] {} ({}) [{}] polls={} offset={}us delay={}us",
                        s.id, s.address, s.stratum.label(), en,
                        s.poll_count, s.offset_us, s.delay_us);
                }
            }
        }
        "add" => {
            timesync::init_defaults();
            let addr = parts.get(1).copied().unwrap_or("pool.ntp.org");
            let stratum = parse_timesync_stratum(parts.get(2).copied().unwrap_or("2"));
            match timesync::add_server(addr, stratum) {
                Ok(id) => shell_println!("Added server #{}: {}", id, addr),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "remove" | "rm" => {
            let id = parts.get(1).and_then(|s| s.parse::<u32>().ok()).unwrap_or(0);
            match timesync::remove_server(id) {
                Ok(()) => shell_println!("Removed server {}.", id),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "sync" => {
            timesync::init_defaults();
            match timesync::sync_now() {
                Ok(()) => shell_println!("Sync completed. Status: {}", timesync::get_status().label()),
                Err(e) => shell_println!("Sync error: {:?}", e),
            }
        }
        "history" => {
            let hist = timesync::sync_history();
            if hist.is_empty() {
                shell_println!("No sync history.");
            } else {
                shell_println!("{} sync record(s):", hist.len());
                let show = if hist.len() > 10 { &hist[hist.len()-10..] } else { &hist };
                for r in show {
                    let ok = if r.success { "OK" } else { "FAIL" };
                    shell_println!("  srv={} offset={}us delay={}us [{}] @{}ns",
                        r.server_id, r.offset_us, r.delay_us, ok, r.timestamp_ns);
                }
            }
        }
        "stats" => {
            timesync::init_defaults();
            let (servers, syncs, errors, last, ops) = timesync::stats();
            shell_println!("Time sync stats:");
            shell_println!("  Servers:    {}", servers);
            shell_println!("  Syncs:      {}", syncs);
            shell_println!("  Errors:     {}", errors);
            shell_println!("  Last sync:  {}ns", last);
            shell_println!("  Operations: {}", ops);
        }
        "test" => {
            timesync::self_test();
            shell_println!("timesync self-test passed.");
        }
        _ => {
            shell_println!("Usage: timesync [status|list|add <addr> [stratum]|remove <id>|sync|history|stats|test]");
        }
    }
}

fn parse_timesync_stratum(s: &str) -> crate::fs::timesync::Stratum {
    use crate::fs::timesync::Stratum;
    match s {
        "1" | "primary" => Stratum::Primary,
        "2" | "secondary" => Stratum::Secondary,
        "3" | "tertiary" => Stratum::Tertiary,
        _ => Stratum::Unknown,
    }
}

/// `kmod` — kernel module management.
fn cmd_kmod(args: &str) {
    use crate::fs::kmod;
    let parts: Vec<&str> = args.split_whitespace().collect();
    let sub = parts.first().copied().unwrap_or("");
    match sub {
        "list" | "" => {
            kmod::init_defaults();
            let modules = kmod::list_modules();
            let live: Vec<_> = modules.iter().filter(|m| m.state == kmod::ModuleState::Live).collect();
            if live.is_empty() {
                shell_println!("No modules loaded.");
            } else {
                shell_println!("{} module(s) loaded:", live.len());
                for m in &live {
                    let deps = if m.depends_on.is_empty() {
                        alloc::string::String::from("-")
                    } else {
                        m.depends_on.join(",")
                    };
                    shell_println!("  {} v{} [{}] {}B refs={} deps={}",
                        m.name, m.version, m.mod_type.label(),
                        m.size_bytes, m.ref_count, deps);
                }
            }
        }
        "info" => {
            let name = parts.get(1).copied().unwrap_or("");
            match kmod::get_module(name) {
                Some(m) => {
                    shell_println!("Module: {}", m.name);
                    shell_println!("  Version:     {}", m.version);
                    shell_println!("  Type:        {}", m.mod_type.label());
                    shell_println!("  State:       {}", m.state.label());
                    shell_println!("  Size:        {} bytes", m.size_bytes);
                    shell_println!("  Ref count:   {}", m.ref_count);
                    shell_println!("  Description: {}", m.description);
                    if !m.depends_on.is_empty() {
                        shell_println!("  Depends on:  {}", m.depends_on.join(", "));
                    }
                    let params = kmod::get_params(name);
                    if !params.is_empty() {
                        shell_println!("  Parameters:");
                        for p in &params {
                            shell_println!("    {}={} ({})", p.param_name, p.value, p.description);
                        }
                    }
                }
                None => shell_println!("Module '{}' not found.", name),
            }
        }
        "load" => {
            kmod::init_defaults();
            let name = parts.get(1).copied().unwrap_or("unnamed");
            let mod_type = parse_kmod_type(parts.get(2).copied().unwrap_or("other"));
            let size = parts.get(3).and_then(|s| s.parse::<u64>().ok()).unwrap_or(4096);
            match kmod::load_module(name, mod_type, size, "user-loaded module") {
                Ok(()) => shell_println!("Module '{}' loaded.", name),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "unload" | "rmmod" => {
            let name = parts.get(1).copied().unwrap_or("");
            match kmod::unload_module(name) {
                Ok(()) => shell_println!("Module '{}' unloaded.", name),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "param" => {
            let modname = parts.get(1).copied().unwrap_or("");
            let param = parts.get(2).copied().unwrap_or("");
            let value = parts.get(3).copied().unwrap_or("");
            if modname.is_empty() || param.is_empty() {
                shell_println!("Usage: kmod param <module> <param> <value>");
            } else {
                match kmod::set_param(modname, param, value, "user-set parameter") {
                    Ok(()) => shell_println!("Set {}.{} = {}", modname, param, value),
                    Err(e) => shell_println!("Error: {:?}", e),
                }
            }
        }
        "stats" => {
            kmod::init_defaults();
            let (live, loads, unloads, errors, ops) = kmod::stats();
            shell_println!("Kernel module stats:");
            shell_println!("  Live modules:   {}", live);
            shell_println!("  Total loads:    {}", loads);
            shell_println!("  Total unloads:  {}", unloads);
            shell_println!("  Total errors:   {}", errors);
            shell_println!("  Operations:     {}", ops);
        }
        "test" => {
            kmod::self_test();
            shell_println!("kmod self-test passed.");
        }
        _ => {
            shell_println!("Usage: kmod [list|info <name>|load <name> [type] [size]|unload <name>|param <mod> <key> <val>|stats|test]");
        }
    }
}

fn parse_kmod_type(s: &str) -> crate::fs::kmod::ModuleType {
    use crate::fs::kmod::ModuleType;
    match s {
        "driver" | "drv" => ModuleType::Driver,
        "fs" | "filesystem" => ModuleType::Filesystem,
        "net" | "network" => ModuleType::Network,
        "sec" | "security" => ModuleType::Security,
        "crypto" => ModuleType::Crypto,
        _ => ModuleType::Other,
    }
}

/// `entropy` / `epool` — system entropy pool management.
fn cmd_entropy(args: &str) {
    use crate::fs::entropy;
    let parts: Vec<&str> = args.split_whitespace().collect();
    let sub = parts.first().copied().unwrap_or("");
    match sub {
        "status" | "" => {
            entropy::init_defaults();
            let avail = entropy::available();
            let qual = entropy::quality();
            shell_println!("Entropy pool:");
            shell_println!("  Available: {} bits", avail);
            shell_println!("  Quality:   {}", qual.label());
        }
        "sources" => {
            entropy::init_defaults();
            let sources = entropy::list_sources();
            shell_println!("{} entropy sources:", sources.len());
            for s in &sources {
                let en = if s.enabled { "ON" } else { "OFF" };
                shell_println!("  {} [{}] bits={} events={}",
                    s.source.label(), en, s.bits_contributed, s.events);
            }
        }
        "add" => {
            entropy::init_defaults();
            let bits = parts.get(1).and_then(|s| s.parse::<u64>().ok()).unwrap_or(64);
            let source_str = parts.get(2).copied().unwrap_or("jitter");
            let source = parse_entropy_source(source_str);
            match entropy::add_entropy(source, bits) {
                Ok(()) => shell_println!("Added {} bits from {}", bits, source.label()),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "drain" => {
            let bits = parts.get(1).and_then(|s| s.parse::<u64>().ok()).unwrap_or(32);
            match entropy::drain_entropy(bits) {
                Ok(got) => shell_println!("Drained {} bits (requested {})", got, bits),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "reseed" => {
            entropy::init_defaults();
            match entropy::reseed() {
                Ok(()) => shell_println!("Reseeded from hardware RNG. Available: {} bits", entropy::available()),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "stats" => {
            entropy::init_defaults();
            let (avail, added, drained, events, reseeds, ops) = entropy::stats();
            shell_println!("Entropy stats:");
            shell_println!("  Available:     {} bits", avail);
            shell_println!("  Total added:   {} bits", added);
            shell_println!("  Total drained: {} bits", drained);
            shell_println!("  Total events:  {}", events);
            shell_println!("  Reseeds:       {}", reseeds);
            shell_println!("  Operations:    {}", ops);
        }
        "test" => {
            entropy::self_test();
            shell_println!("entropy self-test passed.");
        }
        _ => {
            shell_println!("Usage: entropy [status|sources|add <bits> [source]|drain <bits>|reseed|stats|test]");
        }
    }
}

fn parse_entropy_source(s: &str) -> crate::fs::entropy::EntropySource {
    use crate::fs::entropy::EntropySource;
    match s {
        "hw" | "hardware" => EntropySource::Hardware,
        "irq" | "interrupt" => EntropySource::Interrupt,
        "disk" => EntropySource::Disk,
        "kb" | "keyboard" => EntropySource::Keyboard,
        "mouse" => EntropySource::Mouse,
        "net" | "network" => EntropySource::Network,
        "jitter" | "cpu" => EntropySource::Jitter,
        "seed" => EntropySource::Seed,
        _ => EntropySource::Jitter,
    }
}

/// `iosched` / `ioq` — block I/O scheduler configuration.
fn cmd_iosched(args: &str) {
    use crate::fs::iosched;
    let parts: Vec<&str> = args.split_whitespace().collect();
    let sub = parts.first().copied().unwrap_or("");
    match sub {
        "list" | "" => {
            iosched::init_defaults();
            let devices = iosched::list_devices();
            if devices.is_empty() {
                shell_println!("No I/O scheduler devices.");
            } else {
                shell_println!("{} device(s):", devices.len());
                for d in &devices {
                    shell_println!("  {} algo={} depth={} merge={} read_exp={}ms write_exp={}ms",
                        d.device_name, d.algorithm.label(), d.queue_depth,
                        d.merge_enabled, d.read_expire_ms, d.write_expire_ms);
                }
            }
        }
        "get" => {
            let name = parts.get(1).copied().unwrap_or("");
            match iosched::get_device(name) {
                Some(d) => {
                    shell_println!("Device: {}", d.device_name);
                    shell_println!("  Algorithm:    {}", d.algorithm.label());
                    shell_println!("  Queue depth:  {}", d.queue_depth);
                    shell_println!("  Read expire:  {}ms", d.read_expire_ms);
                    shell_println!("  Write expire: {}ms", d.write_expire_ms);
                    shell_println!("  Merge:        {}", d.merge_enabled);
                    shell_println!("  Front merge:  {}", d.front_merge);
                    shell_println!("  Nr requests:  {}", d.nr_requests);
                    shell_println!("  Dispatched:   {}", d.total_dispatched);
                    shell_println!("  Merged:       {}", d.total_merged);
                }
                None => shell_println!("Device '{}' not found.", name),
            }
        }
        "set" => {
            let dev = parts.get(1).copied().unwrap_or("");
            let algo_str = parts.get(2).copied().unwrap_or("bfq");
            let algo = parse_iosched_algo(algo_str);
            match iosched::set_scheduler(dev, algo) {
                Ok(()) => shell_println!("Set {} scheduler to {}", dev, algo.label()),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "depth" => {
            let dev = parts.get(1).copied().unwrap_or("");
            let depth = parts.get(2).and_then(|s| s.parse::<u32>().ok()).unwrap_or(128);
            match iosched::set_queue_depth(dev, depth) {
                Ok(()) => shell_println!("Set {} queue depth to {}", dev, depth),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "add" => {
            iosched::init_defaults();
            let name = parts.get(1).copied().unwrap_or("vdc");
            let algo = parse_iosched_algo(parts.get(2).copied().unwrap_or("bfq"));
            match iosched::add_device(name, algo) {
                Ok(()) => shell_println!("Added device {} with {}", name, algo.label()),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "default" => {
            iosched::init_defaults();
            let algo = parse_iosched_algo(parts.get(1).copied().unwrap_or("bfq"));
            match iosched::set_default(algo) {
                Ok(()) => shell_println!("Default algorithm set to {}", algo.label()),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "stats" => {
            iosched::init_defaults();
            let (devs, dispatched, merged, requeued, ops) = iosched::stats();
            shell_println!("I/O scheduler stats:");
            shell_println!("  Devices:    {}", devs);
            shell_println!("  Dispatched: {}", dispatched);
            shell_println!("  Merged:     {}", merged);
            shell_println!("  Requeued:   {}", requeued);
            shell_println!("  Operations: {}", ops);
        }
        "test" => {
            iosched::self_test();
            shell_println!("iosched self-test passed.");
        }
        _ => {
            shell_println!("Usage: iosched [list|get <dev>|set <dev> <algo>|depth <dev> <n>|add <dev> [algo]|default <algo>|stats|test]");
        }
    }
}

fn parse_iosched_algo(s: &str) -> crate::fs::iosched::IoAlgorithm {
    use crate::fs::iosched::IoAlgorithm;
    match s {
        "none" | "noop" => IoAlgorithm::None,
        "fifo" => IoAlgorithm::Fifo,
        "deadline" | "dl" => IoAlgorithm::Deadline,
        "bfq" => IoAlgorithm::Bfq,
        "kyber" => IoAlgorithm::Kyber,
        "mq" | "mq-deadline" => IoAlgorithm::Mq,
        _ => IoAlgorithm::Bfq,
    }
}

/// `netmon` / `nmon` — active network connection tracking.
fn cmd_netmon(args: &str) {
    use crate::fs::netmon;
    let parts: Vec<&str> = args.split_whitespace().collect();
    let sub = parts.first().copied().unwrap_or("");
    match sub {
        "list" | "" => {
            netmon::init_defaults();
            let conns = netmon::list_connections();
            if conns.is_empty() {
                shell_println!("No active connections.");
            } else {
                shell_println!("{} connection(s):", conns.len());
                for c in &conns {
                    shell_println!("  [{}] {} {}:{} → {}:{} [{}] pid={} ({})",
                        c.id, c.protocol.label(), c.local_addr, c.local_port,
                        c.remote_addr, c.remote_port, c.state.label(),
                        c.pid, c.process_name);
                }
            }
        }
        "get" => {
            let id = parts.get(1).and_then(|s| s.parse::<u32>().ok()).unwrap_or(0);
            match netmon::get_connection(id) {
                Some(c) => {
                    shell_println!("Connection #{}:", c.id);
                    shell_println!("  Protocol: {}", c.protocol.label());
                    shell_println!("  State:    {}", c.state.label());
                    shell_println!("  Local:    {}:{}", c.local_addr, c.local_port);
                    shell_println!("  Remote:   {}:{}", c.remote_addr, c.remote_port);
                    shell_println!("  PID:      {} ({})", c.pid, c.process_name);
                    shell_println!("  Sent:     {} bytes", c.bytes_sent);
                    shell_println!("  Recv:     {} bytes", c.bytes_recv);
                }
                None => shell_println!("Connection {} not found.", id),
            }
        }
        "pid" => {
            netmon::init_defaults();
            let pid = parts.get(1).and_then(|s| s.parse::<u32>().ok()).unwrap_or(0);
            let conns = netmon::per_process(pid);
            shell_println!("{} connection(s) for PID {}:", conns.len(), pid);
            for c in &conns {
                shell_println!("  [{}] {} {}:{} → {}:{} [{}]",
                    c.id, c.protocol.label(), c.local_addr, c.local_port,
                    c.remote_addr, c.remote_port, c.state.label());
            }
        }
        "close" => {
            let id = parts.get(1).and_then(|s| s.parse::<u32>().ok()).unwrap_or(0);
            match netmon::close_connection(id) {
                Ok(()) => shell_println!("Connection {} closed.", id),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "stats" => {
            netmon::init_defaults();
            let (active, created, closed, sent, recv, ops) = netmon::stats();
            shell_println!("Network monitor stats:");
            shell_println!("  Active:      {}", active);
            shell_println!("  Created:     {}", created);
            shell_println!("  Closed:      {}", closed);
            shell_println!("  Bytes sent:  {}", sent);
            shell_println!("  Bytes recv:  {}", recv);
            shell_println!("  Operations:  {}", ops);
        }
        "test" => {
            netmon::self_test();
            shell_println!("netmon self-test passed.");
        }
        _ => {
            shell_println!("Usage: netmon [list|get <id>|pid <pid>|close <id>|stats|test]");
        }
    }
}

/// `groupmgr` / `grp` — user group management.
fn cmd_groupmgr(args: &str) {
    use crate::fs::groupmgr;
    use alloc::format;
    let parts: Vec<&str> = args.split_whitespace().collect();
    let sub = parts.first().copied().unwrap_or("");
    match sub {
        "list" | "" => {
            groupmgr::init_defaults();
            let groups = groupmgr::list_groups();
            shell_println!("{} group(s):", groups.len());
            for g in &groups {
                let members: Vec<_> = g.members.iter().map(|m| format!("{}", m)).collect();
                shell_println!("  {}({}) [{}] members=[{}] — {}",
                    g.name, g.gid, g.group_type.label(),
                    members.join(","), g.description);
            }
        }
        "get" => {
            let gid = parts.get(1).and_then(|s| s.parse::<u32>().ok());
            let name = parts.get(1).copied().unwrap_or("");
            let group = if let Some(gid) = gid {
                groupmgr::get_group(gid)
            } else {
                groupmgr::get_by_name(name)
            };
            match group {
                Some(g) => {
                    let members: Vec<_> = g.members.iter().map(|m| format!("{}", m)).collect();
                    shell_println!("Group: {} (GID {})", g.name, g.gid);
                    shell_println!("  Type:        {}", g.group_type.label());
                    shell_println!("  Members:     [{}]", members.join(", "));
                    shell_println!("  Description: {}", g.description);
                }
                None => shell_println!("Group not found."),
            }
        }
        "create" => {
            groupmgr::init_defaults();
            let gid = parts.get(1).and_then(|s| s.parse::<u32>().ok()).unwrap_or(2000);
            let name = parts.get(2).copied().unwrap_or("newgroup");
            let gtype = parse_groupmgr_type(parts.get(3).copied().unwrap_or("user"));
            match groupmgr::create_group(gid, name, gtype, "User-created group") {
                Ok(()) => shell_println!("Created group '{}' (GID {})", name, gid),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "delete" | "rm" => {
            let gid = parts.get(1).and_then(|s| s.parse::<u32>().ok()).unwrap_or(0);
            match groupmgr::delete_group(gid) {
                Ok(()) => shell_println!("Deleted group {}.", gid),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "adduser" => {
            let gid = parts.get(1).and_then(|s| s.parse::<u32>().ok()).unwrap_or(0);
            let uid = parts.get(2).and_then(|s| s.parse::<u32>().ok()).unwrap_or(0);
            match groupmgr::add_member(gid, uid) {
                Ok(()) => shell_println!("Added UID {} to GID {}.", uid, gid),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "rmuser" => {
            let gid = parts.get(1).and_then(|s| s.parse::<u32>().ok()).unwrap_or(0);
            let uid = parts.get(2).and_then(|s| s.parse::<u32>().ok()).unwrap_or(0);
            match groupmgr::remove_member(gid, uid) {
                Ok(()) => shell_println!("Removed UID {} from GID {}.", uid, gid),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "user" => {
            groupmgr::init_defaults();
            let uid = parts.get(1).and_then(|s| s.parse::<u32>().ok()).unwrap_or(0);
            let groups = groupmgr::groups_for_user(uid);
            shell_println!("UID {} belongs to {} group(s):", uid, groups.len());
            for g in &groups {
                shell_println!("  {}({})", g.name, g.gid);
            }
        }
        "stats" => {
            groupmgr::init_defaults();
            let (count, created, deleted, member_ops, ops) = groupmgr::stats();
            shell_println!("Group manager stats:");
            shell_println!("  Groups:      {}", count);
            shell_println!("  Created:     {}", created);
            shell_println!("  Deleted:     {}", deleted);
            shell_println!("  Member ops:  {}", member_ops);
            shell_println!("  Operations:  {}", ops);
        }
        "test" => {
            groupmgr::self_test();
            shell_println!("groupmgr self-test passed.");
        }
        _ => {
            shell_println!("Usage: groupmgr [list|get <gid|name>|create <gid> <name> [type]|delete <gid>|adduser <gid> <uid>|rmuser <gid> <uid>|user <uid>|stats|test]");
        }
    }
}

fn parse_groupmgr_type(s: &str) -> crate::fs::groupmgr::GroupType {
    use crate::fs::groupmgr::GroupType;
    match s {
        "system" | "sys" => GroupType::System,
        "user" => GroupType::User,
        "service" | "svc" => GroupType::Service,
        _ => GroupType::User,
    }
}

/// `sysrq` — magic SysRq key handler management.
fn cmd_sysrq(args: &str) {
    use crate::fs::sysrq;
    let parts: Vec<&str> = args.split_whitespace().collect();
    let sub = parts.first().copied().unwrap_or("");
    match sub {
        "list" | "" => {
            sysrq::init_defaults();
            let handlers = sysrq::list_handlers();
            shell_println!("{} SysRq handler(s):", handlers.len());
            for h in &handlers {
                let en = if h.enabled { "ON" } else { "OFF" };
                shell_println!("  '{}' [{}] [{}] {} (triggers: {})",
                    h.key, en, h.category.label(), h.description, h.trigger_count);
            }
        }
        "trigger" => {
            sysrq::init_defaults();
            let key = parts.get(1).and_then(|s| s.chars().next()).unwrap_or('h');
            match sysrq::trigger(key) {
                Ok(()) => shell_println!("SysRq '{}' triggered.", key),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "register" => {
            sysrq::init_defaults();
            let key = parts.get(1).and_then(|s| s.chars().next()).unwrap_or('z');
            let desc: alloc::string::String = parts.get(2..).map_or(
                alloc::string::String::from("custom handler"),
                |p| p.join(" "),
            );
            match sysrq::register(key, sysrq::SysRqCategory::Custom, &desc) {
                Ok(()) => shell_println!("Registered SysRq '{}': {}", key, desc),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "unregister" | "rm" => {
            let key = parts.get(1).and_then(|s| s.chars().next()).unwrap_or('z');
            match sysrq::unregister(key) {
                Ok(()) => shell_println!("Unregistered SysRq '{}'.", key),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "enable" => {
            let key = parts.get(1).and_then(|s| s.chars().next()).unwrap_or('h');
            match sysrq::set_handler_enabled(key, true) {
                Ok(()) => shell_println!("SysRq '{}' enabled.", key),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "disable" => {
            let key = parts.get(1).and_then(|s| s.chars().next()).unwrap_or('h');
            match sysrq::set_handler_enabled(key, false) {
                Ok(()) => shell_println!("SysRq '{}' disabled.", key),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "mask" => {
            sysrq::init_defaults();
            if let Some(val) = parts.get(1) {
                let mask = u32::from_str_radix(val.trim_start_matches("0x"), 16).unwrap_or(0x7F);
                match sysrq::set_enabled_mask(mask) {
                    Ok(()) => shell_println!("SysRq mask set to 0x{:x}", mask),
                    Err(e) => shell_println!("Error: {:?}", e),
                }
            } else {
                shell_println!("SysRq mask: 0x{:x}", sysrq::get_enabled_mask());
            }
        }
        "stats" => {
            sysrq::init_defaults();
            let (count, triggers, blocked, mask, ops) = sysrq::stats();
            shell_println!("SysRq stats:");
            shell_println!("  Handlers:  {}", count);
            shell_println!("  Triggers:  {}", triggers);
            shell_println!("  Blocked:   {}", blocked);
            shell_println!("  Mask:      0x{:x}", mask);
            shell_println!("  Operations: {}", ops);
        }
        "test" => {
            sysrq::self_test();
            shell_println!("sysrq self-test passed.");
        }
        _ => {
            shell_println!("Usage: sysrq [list|trigger <key>|register <key> <desc>|unregister <key>|enable <key>|disable <key>|mask [val]|stats|test]");
        }
    }
}

/// `telemetry` / `telem` — system telemetry collection.
fn cmd_telemetry(args: &str) {
    use crate::fs::telemetry;
    let parts: Vec<&str> = args.split_whitespace().collect();
    let sub = parts.first().copied().unwrap_or("");
    match sub {
        "list" | "" => {
            telemetry::init_defaults();
            let metrics = telemetry::list_metrics();
            if metrics.is_empty() {
                shell_println!("No metrics registered.");
            } else {
                shell_println!("{} metric(s):", metrics.len());
                for m in &metrics {
                    let en = if m.enabled { "ON" } else { "OFF" };
                    let avg = if m.sample_count > 0 { m.total_sum / m.sample_count } else { 0 };
                    shell_println!("  {} [{}] [{}] = {} {} (avg={}, n={})",
                        m.name, m.metric_type.label(), en, m.value,
                        m.unit, avg, m.sample_count);
                }
            }
        }
        "query" | "get" => {
            let name = parts.get(1).copied().unwrap_or("");
            match telemetry::query(name) {
                Some(m) => {
                    let avg = if m.sample_count > 0 { m.total_sum / m.sample_count } else { 0 };
                    shell_println!("Metric: {}", m.name);
                    shell_println!("  Type:    {}", m.metric_type.label());
                    shell_println!("  Category: {}", m.category.label());
                    shell_println!("  Value:   {} {}", m.value, m.unit);
                    shell_println!("  Min:     {}", m.min_value);
                    shell_println!("  Max:     {}", m.max_value);
                    shell_println!("  Avg:     {}", avg);
                    shell_println!("  Samples: {}", m.sample_count);
                }
                None => shell_println!("Metric '{}' not found.", name),
            }
        }
        "record" => {
            telemetry::init_defaults();
            let name = parts.get(1).copied().unwrap_or("");
            let value = parts.get(2).and_then(|s| s.parse::<u64>().ok()).unwrap_or(0);
            match telemetry::record(name, value) {
                Ok(()) => shell_println!("Recorded {}={}", name, value),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "register" => {
            telemetry::init_defaults();
            let name = parts.get(1).copied().unwrap_or("custom.metric");
            let mtype = parse_telemetry_type(parts.get(2).copied().unwrap_or("gauge"));
            let unit = parts.get(3).copied().unwrap_or("");
            match telemetry::register_metric(name, mtype, telemetry::MetricCategory::Custom, unit) {
                Ok(()) => shell_println!("Registered metric '{}'", name),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "remove" | "rm" => {
            let name = parts.get(1).copied().unwrap_or("");
            match telemetry::remove_metric(name) {
                Ok(()) => shell_println!("Removed metric '{}'.", name),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "export" => {
            telemetry::init_defaults();
            match telemetry::export() {
                Ok(metrics) => {
                    shell_println!("Exported {} metrics:", metrics.len());
                    for m in &metrics {
                        shell_println!("  {}={} {}", m.name, m.value, m.unit);
                    }
                }
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "stats" => {
            telemetry::init_defaults();
            let (count, samples, exports, enabled, ops) = telemetry::stats();
            shell_println!("Telemetry stats:");
            shell_println!("  Metrics:    {}", count);
            shell_println!("  Samples:    {}", samples);
            shell_println!("  Exports:    {}", exports);
            shell_println!("  Collection: {}", if enabled { "enabled" } else { "disabled" });
            shell_println!("  Operations: {}", ops);
        }
        "test" => {
            telemetry::self_test();
            shell_println!("telemetry self-test passed.");
        }
        _ => {
            shell_println!("Usage: telemetry [list|query <name>|record <name> <value>|register <name> [type] [unit]|remove <name>|export|stats|test]");
        }
    }
}

fn parse_telemetry_type(s: &str) -> crate::fs::telemetry::MetricType {
    use crate::fs::telemetry::MetricType;
    match s {
        "counter" | "cnt" => MetricType::Counter,
        "gauge" | "g" => MetricType::Gauge,
        "histogram" | "hist" => MetricType::Histogram,
        "rate" | "r" => MetricType::Rate,
        _ => MetricType::Gauge,
    }
}

/// `fscache` / `fcache` — filesystem cache policy management.
fn cmd_fscache(args: &str) {
    use crate::fs::fscache;
    let parts: Vec<&str> = args.split_whitespace().collect();
    let sub = parts.first().copied().unwrap_or("");
    match sub {
        "list" | "" => {
            fscache::init_defaults();
            let devs = fscache::list_devices();
            if devs.is_empty() {
                shell_println!("No cache devices.");
            } else {
                shell_println!("{} device(s):", devs.len());
                for d in &devs {
                    shell_println!("  {} policy={} ra={} dirty={}/{} cached={}",
                        d.device_name, d.policy.label(), d.readahead_pages,
                        d.dirty_pages, d.dirty_ratio_pct, d.cached_pages);
                }
            }
        }
        "policy" => {
            let dev = parts.get(1).copied().unwrap_or("");
            let pol = parse_fscache_policy(parts.get(2).copied().unwrap_or("wb"));
            match fscache::set_policy(dev, pol) {
                Ok(()) => shell_println!("Set {} policy to {}", dev, pol.label()),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "readahead" | "ra" => {
            let dev = parts.get(1).copied().unwrap_or("");
            let pages = parts.get(2).and_then(|s| s.parse::<u32>().ok()).unwrap_or(128);
            match fscache::set_readahead(dev, pages) {
                Ok(()) => shell_println!("Set {} read-ahead to {} pages", dev, pages),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "flush" => {
            let dev = parts.get(1).copied().unwrap_or("");
            match fscache::flush(dev) {
                Ok(n) => shell_println!("Flushed {} dirty pages on {}", n, dev),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "stats" => {
            fscache::init_defaults();
            let (devs, flushes, ras, evictions, ops) = fscache::stats();
            shell_println!("FS cache stats:");
            shell_println!("  Devices:     {}", devs);
            shell_println!("  Flushes:     {}", flushes);
            shell_println!("  Read-aheads: {}", ras);
            shell_println!("  Evictions:   {}", evictions);
            shell_println!("  Operations:  {}", ops);
        }
        "test" => {
            fscache::self_test();
            shell_println!("fscache self-test passed.");
        }
        _ => {
            shell_println!("Usage: fscache [list|policy <dev> <wb|wt|wa|none>|readahead <dev> <pages>|flush <dev>|stats|test]");
        }
    }
}

fn parse_fscache_policy(s: &str) -> crate::fs::fscache::CachePolicy {
    use crate::fs::fscache::CachePolicy;
    match s {
        "wb" | "writeback" | "write-back" => CachePolicy::WriteBack,
        "wt" | "writethrough" | "write-through" => CachePolicy::WriteThrough,
        "wa" | "writearound" | "write-around" => CachePolicy::WriteAround,
        "none" | "off" => CachePolicy::None,
        _ => CachePolicy::WriteBack,
    }
}

/// `nameservice` / `nsvc` — hostname/DNS name resolution.
fn cmd_nameservice(args: &str) {
    use crate::fs::nameservice;
    use alloc::format;
    let parts: Vec<&str> = args.split_whitespace().collect();
    let sub = parts.first().copied().unwrap_or("");
    match sub {
        "status" | "" => {
            nameservice::init_defaults();
            shell_println!("Hostname: {}", nameservice::get_hostname());
            shell_println!("Domain:   {}", nameservice::get_domain());
            let order = nameservice::get_order();
            let order_str: Vec<_> = order.iter().map(|o| o.label()).collect();
            shell_println!("Order:    {}", order_str.join(" → "));
            let (hosts, lookups, hits, misses, _) = nameservice::stats();
            shell_println!("Hosts:    {}", hosts);
            shell_println!("Lookups:  {} (hits={}, misses={})", lookups, hits, misses);
        }
        "hostname" => {
            nameservice::init_defaults();
            if let Some(name) = parts.get(1) {
                match nameservice::set_hostname(name) {
                    Ok(()) => shell_println!("Hostname set to '{}'", name),
                    Err(e) => shell_println!("Error: {:?}", e),
                }
            } else {
                shell_println!("{}", nameservice::get_hostname());
            }
        }
        "resolve" => {
            nameservice::init_defaults();
            let name = parts.get(1).copied().unwrap_or("localhost");
            match nameservice::resolve(name) {
                Ok(r) => shell_println!("{} → {} (via {})", r.hostname, r.address, r.source.label()),
                Err(_) => shell_println!("Could not resolve '{}'.", name),
            }
        }
        "hosts" => {
            nameservice::init_defaults();
            let hosts = nameservice::list_hosts();
            shell_println!("{} host entry(ies):", hosts.len());
            for h in &hosts {
                let aliases = if h.aliases.is_empty() { String::from("") }
                    else { format!(" ({})", h.aliases.join(", ")) };
                shell_println!("  {} → {}{}", h.address, h.hostname, aliases);
            }
        }
        "add" => {
            nameservice::init_defaults();
            let addr = parts.get(1).copied().unwrap_or("127.0.0.1");
            let name = parts.get(2).copied().unwrap_or("host");
            match nameservice::add_host(addr, name) {
                Ok(()) => shell_println!("Added {} → {}", addr, name),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "remove" | "rm" => {
            let name = parts.get(1).copied().unwrap_or("");
            match nameservice::remove_host(name) {
                Ok(()) => shell_println!("Removed '{}'.", name),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "flush" => {
            nameservice::init_defaults();
            match nameservice::flush_cache() {
                Ok(n) => shell_println!("Flushed {} cache entries.", n),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "test" => {
            nameservice::self_test();
            shell_println!("nameservice self-test passed.");
        }
        _ => {
            shell_println!("Usage: nameservice [status|hostname [name]|resolve <host>|hosts|add <addr> <name>|remove <name>|flush|test]");
        }
    }
}

/// `oomkiller` / `oom` — OOM killer policy and scoring.
fn cmd_oomkiller(args: &str) {
    use crate::fs::oomkiller;
    let parts: Vec<&str> = args.split_whitespace().collect();
    let sub = parts.first().copied().unwrap_or("");
    match sub {
        "list" | "" => {
            oomkiller::init_defaults();
            let scores = oomkiller::list_scores();
            shell_println!("Policy: {}", oomkiller::get_policy().label());
            shell_println!("{} process(es):", scores.len());
            for s in &scores {
                let eff = (s.score + s.adj).max(0);
                let ex = if s.exempt { " [EXEMPT]" } else { "" };
                shell_println!("  pid={} {} score={} adj={} eff={} mem={}B{}",
                    s.pid, s.process_name, s.score, s.adj, eff, s.memory_bytes, ex);
            }
        }
        "score" => {
            let pid = parts.get(1).and_then(|s| s.parse::<u32>().ok()).unwrap_or(0);
            match oomkiller::get_score(pid) {
                Some(s) => {
                    let eff = (s.score + s.adj).max(0);
                    shell_println!("PID {} ({}): score={} adj={} eff={} exempt={}",
                        s.pid, s.process_name, s.score, s.adj, eff, s.exempt);
                }
                None => shell_println!("PID {} not found.", pid),
            }
        }
        "adjust" => {
            let pid = parts.get(1).and_then(|s| s.parse::<u32>().ok()).unwrap_or(0);
            let adj = parts.get(2).and_then(|s| s.parse::<i32>().ok()).unwrap_or(0);
            match oomkiller::adjust_score(pid, adj) {
                Ok(()) => shell_println!("Set PID {} adj to {}", pid, adj),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "exempt" => {
            let pid = parts.get(1).and_then(|s| s.parse::<u32>().ok()).unwrap_or(0);
            let exempt = parts.get(2).copied().unwrap_or("true") != "false";
            match oomkiller::set_exempt(pid, exempt) {
                Ok(()) => shell_println!("PID {} exempt={}", pid, exempt),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "victim" => {
            oomkiller::init_defaults();
            match oomkiller::select_victim() {
                Ok(v) => {
                    let eff = (v.score + v.adj).max(0);
                    shell_println!("Would kill: PID {} ({}) score={}", v.pid, v.process_name, eff);
                }
                Err(e) => shell_println!("No victim: {:?}", e),
            }
        }
        "kill" => {
            let pid = parts.get(1).and_then(|s| s.parse::<u32>().ok()).unwrap_or(0);
            match oomkiller::kill(pid) {
                Ok(freed) => shell_println!("Killed PID {}, freed {} bytes.", pid, freed),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "policy" => {
            oomkiller::init_defaults();
            let pol = parse_oom_policy(parts.get(1).copied().unwrap_or("kill"));
            match oomkiller::set_policy(pol) {
                Ok(()) => shell_println!("OOM policy set to {}", pol.label()),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "history" => {
            let hist = oomkiller::kill_history();
            if hist.is_empty() {
                shell_println!("No OOM kill history.");
            } else {
                shell_println!("{} kill(s):", hist.len());
                for r in &hist {
                    shell_println!("  pid={} {} score={} freed={} @{}ns",
                        r.pid, r.process_name, r.score, r.memory_freed, r.timestamp_ns);
                }
            }
        }
        "stats" => {
            oomkiller::init_defaults();
            let (count, kills, freed, invocations, ops) = oomkiller::stats();
            shell_println!("OOM killer stats:");
            shell_println!("  Processes:    {}", count);
            shell_println!("  Kills:        {}", kills);
            shell_println!("  Memory freed: {}", freed);
            shell_println!("  Invocations:  {}", invocations);
            shell_println!("  Operations:   {}", ops);
        }
        "test" => {
            oomkiller::self_test();
            shell_println!("oomkiller self-test passed.");
        }
        _ => {
            shell_println!("Usage: oomkiller [list|score <pid>|adjust <pid> <adj>|exempt <pid> [true|false]|victim|kill <pid>|policy <kill|panic|reap|disabled>|history|stats|test]");
        }
    }
}

fn parse_oom_policy(s: &str) -> crate::fs::oomkiller::OomPolicy {
    use crate::fs::oomkiller::OomPolicy;
    match s {
        "kill" => OomPolicy::Kill,
        "panic" => OomPolicy::Panic,
        "reap" => OomPolicy::Reap,
        "disabled" | "off" => OomPolicy::Disabled,
        _ => OomPolicy::Kill,
    }
}

/// `blktrace` / `btrace` — block I/O tracing.
fn cmd_blktrace(args: &str) {
    use crate::fs::blktrace;
    let parts: Vec<&str> = args.split_whitespace().collect();
    let sub = parts.first().copied().unwrap_or("");
    match sub {
        "list" | "" => {
            blktrace::init_defaults();
            let devs = blktrace::list_devices();
            if devs.is_empty() {
                shell_println!("No block traces active.");
            } else {
                shell_println!("{} device(s):", devs.len());
                for d in &devs {
                    let st = if d.active { "ACTIVE" } else { "STOPPED" };
                    shell_println!("  {} [{}] events={} bytes={}",
                        d.device, st, d.total_events, d.total_bytes);
                }
            }
        }
        "start" => {
            blktrace::init_defaults();
            let dev = parts.get(1).copied().unwrap_or("sda");
            match blktrace::start(dev) {
                Ok(()) => shell_println!("Tracing started for {}", dev),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "stop" => {
            let dev = parts.get(1).copied().unwrap_or("sda");
            match blktrace::stop(dev) {
                Ok(()) => shell_println!("Tracing stopped for {}", dev),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "dump" => {
            let dev = parts.get(1).copied().unwrap_or("sda");
            let events = blktrace::dump(dev);
            if events.is_empty() {
                shell_println!("No events for {}.", dev);
            } else {
                shell_println!("{} events for {}:", events.len(), dev);
                let show = if events.len() > 20 { &events[events.len()-20..] } else { &events };
                for e in show {
                    shell_println!("  [{}] {} sector={} size={} lat={}us pid={} ({})",
                        e.seq, e.op.label(), e.sector, e.size_bytes,
                        e.latency_us, e.pid, e.process_name);
                }
            }
        }
        "clear" => {
            let dev = parts.get(1).copied().unwrap_or("sda");
            match blktrace::clear(dev) {
                Ok(n) => shell_println!("Cleared {} events from {}", n, dev),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "stats" => {
            blktrace::init_defaults();
            let (devs, events, bytes, active, ops) = blktrace::stats();
            shell_println!("Block trace stats:");
            shell_println!("  Devices:    {}", devs);
            shell_println!("  Active:     {}", active);
            shell_println!("  Events:     {}", events);
            shell_println!("  Bytes:      {}", bytes);
            shell_println!("  Operations: {}", ops);
        }
        "test" => {
            blktrace::self_test();
            shell_println!("blktrace self-test passed.");
        }
        _ => {
            shell_println!("Usage: blktrace [list|start <dev>|stop <dev>|dump <dev>|clear <dev>|stats|test]");
        }
    }
}

/// `cgroupfs` / `cgrp` — cgroup v2 resource management.
fn cmd_cgroupfs(args: &str) {
    use crate::fs::cgroupfs;
    let parts: Vec<&str> = args.split_whitespace().collect();
    let sub = parts.first().copied().unwrap_or("");
    match sub {
        "list" => {
            cgroupfs::init_defaults();
            let groups = cgroupfs::list_groups();
            shell_println!("Cgroups ({}):", groups.len());
            for g in &groups {
                shell_println!("  {} cpu_w={} mem_max={} pids={}/{} procs={}",
                    g.path, g.cpu_weight, g.memory_max, g.pids_current, g.pids_max, g.processes.len());
            }
        }
        "create" => {
            let path = parts.get(1).copied().unwrap_or("");
            if path.is_empty() {
                shell_println!("Usage: cgroupfs create <path>");
                return;
            }
            cgroupfs::init_defaults();
            match cgroupfs::create_group(path) {
                Ok(()) => shell_println!("Created cgroup: {}", path),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "delete" => {
            let path = parts.get(1).copied().unwrap_or("");
            if path.is_empty() {
                shell_println!("Usage: cgroupfs delete <path>");
                return;
            }
            cgroupfs::init_defaults();
            match cgroupfs::delete_group(path) {
                Ok(()) => shell_println!("Deleted cgroup: {}", path),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "cpu" => {
            let path = parts.get(1).copied().unwrap_or("");
            let weight_str = parts.get(2).copied().unwrap_or("0");
            let weight = weight_str.parse::<u32>().unwrap_or(0);
            if path.is_empty() || weight == 0 {
                shell_println!("Usage: cgroupfs cpu <path> <weight 1-10000>");
                return;
            }
            cgroupfs::init_defaults();
            match cgroupfs::set_cpu_weight(path, weight) {
                Ok(()) => shell_println!("CPU weight set to {} for {}", weight, path),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "mem" => {
            let path = parts.get(1).copied().unwrap_or("");
            let bytes_str = parts.get(2).copied().unwrap_or("0");
            let bytes = bytes_str.parse::<u64>().unwrap_or(0);
            if path.is_empty() {
                shell_println!("Usage: cgroupfs mem <path> <bytes>");
                return;
            }
            cgroupfs::init_defaults();
            match cgroupfs::set_memory_max(path, bytes) {
                Ok(()) => shell_println!("Memory max set to {} for {}", bytes, path),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "addpid" => {
            let path = parts.get(1).copied().unwrap_or("");
            let pid_str = parts.get(2).copied().unwrap_or("0");
            let pid = pid_str.parse::<u32>().unwrap_or(0);
            if path.is_empty() || pid == 0 {
                shell_println!("Usage: cgroupfs addpid <path> <pid>");
                return;
            }
            cgroupfs::init_defaults();
            match cgroupfs::add_pid(path, pid) {
                Ok(()) => shell_println!("Added PID {} to {}", pid, path),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "stats" => {
            cgroupfs::init_defaults();
            let (count, created, deleted, changes, ops) = cgroupfs::stats();
            shell_println!("Cgroup stats:");
            shell_println!("  Groups: {}", count);
            shell_println!("  Created: {}", created);
            shell_println!("  Deleted: {}", deleted);
            shell_println!("  Limit changes: {}", changes);
            shell_println!("  Operations: {}", ops);
        }
        "test" => {
            cgroupfs::self_test();
            shell_println!("cgroupfs self-test passed.");
        }
        _ => {
            shell_println!("Usage: cgroupfs [list|create <path>|delete <path>|cpu <path> <weight>|mem <path> <bytes>|addpid <path> <pid>|stats|test]");
        }
    }
}

/// `secpolicy` / `spol` — mandatory access control policy.
fn cmd_secpolicy(args: &str) {
    use crate::fs::secpolicy;
    let parts: Vec<&str> = args.split_whitespace().collect();
    let sub = parts.first().copied().unwrap_or("");
    match sub {
        "list" => {
            secpolicy::init_defaults();
            let rules = secpolicy::list_rules();
            shell_println!("Policy rules ({}):", rules.len());
            for r in &rules {
                shell_println!("  #{} {}->{} {} {} prio={}",
                    r.id, r.subject_label, r.object_label, r.action.label(), r.decision.label(), r.priority);
            }
        }
        "mode" => {
            secpolicy::init_defaults();
            if let Some(m) = parts.get(1) {
                let mode = match *m {
                    "disabled" | "off" => Some(secpolicy::EnforceMode::Disabled),
                    "permissive" | "perm" => Some(secpolicy::EnforceMode::Permissive),
                    "enforcing" | "on" => Some(secpolicy::EnforceMode::Enforcing),
                    _ => None,
                };
                match mode {
                    Some(m) => match secpolicy::set_mode(m) {
                        Ok(()) => shell_println!("Mode set to: {}", m.label()),
                        Err(e) => shell_println!("Error: {:?}", e),
                    },
                    None => shell_println!("Invalid mode. Use: disabled|permissive|enforcing"),
                }
            } else {
                shell_println!("Mode: {}", secpolicy::get_mode().label());
            }
        }
        "check" => {
            let subj = parts.get(1).copied().unwrap_or("");
            let obj = parts.get(2).copied().unwrap_or("");
            let act_str = parts.get(3).copied().unwrap_or("");
            if subj.is_empty() || obj.is_empty() || act_str.is_empty() {
                shell_println!("Usage: secpolicy check <subject> <object> <action>");
                shell_println!("  Actions: read|write|execute|create|delete|network");
                return;
            }
            let action = match act_str {
                "read" => Some(secpolicy::Action::Read),
                "write" => Some(secpolicy::Action::Write),
                "execute" | "exec" => Some(secpolicy::Action::Execute),
                "create" => Some(secpolicy::Action::Create),
                "delete" => Some(secpolicy::Action::Delete),
                "network" | "net" => Some(secpolicy::Action::Network),
                _ => None,
            };
            match action {
                Some(a) => {
                    secpolicy::init_defaults();
                    match secpolicy::check_access(subj, obj, a) {
                        Ok(d) => shell_println!("Decision: {}", d.label()),
                        Err(e) => shell_println!("Error: {:?}", e),
                    }
                }
                None => shell_println!("Unknown action: {}", act_str),
            }
        }
        "label" => {
            let id_str = parts.get(1).copied().unwrap_or("0");
            let etype = parts.get(2).copied().unwrap_or("");
            let label = parts.get(3).copied().unwrap_or("");
            if etype.is_empty() {
                shell_println!("Usage: secpolicy label <entity_id> <type> [label]");
                return;
            }
            secpolicy::init_defaults();
            let id = id_str.parse::<u32>().unwrap_or(0);
            if label.is_empty() {
                match secpolicy::get_label(id, etype) {
                    Some(l) => shell_println!("Label for {}:{}: {}", etype, id, l),
                    None => shell_println!("No label for {}:{}", etype, id),
                }
            } else {
                match secpolicy::set_label(id, etype, label) {
                    Ok(()) => shell_println!("Label set for {}:{} = {}", etype, id, label),
                    Err(e) => shell_println!("Error: {:?}", e),
                }
            }
        }
        "stats" => {
            secpolicy::init_defaults();
            let (rules, checks, allowed, denied, ops) = secpolicy::stats();
            shell_println!("Security policy stats:");
            shell_println!("  Mode: {}", secpolicy::get_mode().label());
            shell_println!("  Rules: {}", rules);
            shell_println!("  Checks: {}", checks);
            shell_println!("  Allowed: {}", allowed);
            shell_println!("  Denied: {}", denied);
            shell_println!("  Operations: {}", ops);
        }
        "test" => {
            secpolicy::self_test();
            shell_println!("secpolicy self-test passed.");
        }
        _ => {
            shell_println!("Usage: secpolicy [list|mode [disabled|permissive|enforcing]|check <subj> <obj> <action>|label <id> <type> [label]|stats|test]");
        }
    }
}

/// `procstat` / `pstat` — per-process resource statistics.
fn cmd_procstat(args: &str) {
    use crate::fs::procstat;
    let parts: Vec<&str> = args.split_whitespace().collect();
    let sub = parts.first().copied().unwrap_or("");
    match sub {
        "list" => {
            procstat::init_defaults();
            let procs = procstat::list_processes();
            shell_println!("Processes ({}):", procs.len());
            for p in &procs {
                shell_println!("  pid={} {} [{}] cpu={}us mem={} io_r={} io_w={} threads={}",
                    p.pid, p.name, p.state.label(), p.cpu_time_us, p.memory_bytes,
                    p.io_read_bytes, p.io_write_bytes, p.threads);
            }
        }
        "get" => {
            let pid_str = parts.get(1).copied().unwrap_or("0");
            let pid = pid_str.parse::<u32>().unwrap_or(0);
            if pid == 0 {
                shell_println!("Usage: procstat get <pid>");
                return;
            }
            procstat::init_defaults();
            match procstat::get_process(pid) {
                Some(p) => {
                    shell_println!("Process {}:", pid);
                    shell_println!("  Name: {}", p.name);
                    shell_println!("  State: {}", p.state.label());
                    shell_println!("  CPU: {}us (user={}us sys={}us)", p.cpu_time_us, p.user_time_us, p.sys_time_us);
                    shell_println!("  Memory: {} bytes ({} pages)", p.memory_bytes, p.rss_pages);
                    shell_println!("  I/O: read={} write={}", p.io_read_bytes, p.io_write_bytes);
                    shell_println!("  Page faults: {}", p.page_faults);
                    shell_println!("  Ctx switches: {}", p.ctx_switches);
                    shell_println!("  Threads: {}", p.threads);
                }
                None => shell_println!("Process {} not found", pid),
            }
        }
        "topcpu" => {
            let n_str = parts.get(1).copied().unwrap_or("5");
            let n = n_str.parse::<usize>().unwrap_or(0);
            let n = if n == 0 { 5 } else { n };
            procstat::init_defaults();
            let top = procstat::top_cpu(n);
            shell_println!("Top {} by CPU:", top.len());
            for p in &top {
                shell_println!("  pid={} {} cpu={}us", p.pid, p.name, p.cpu_time_us);
            }
        }
        "topmem" => {
            let n_str = parts.get(1).copied().unwrap_or("5");
            let n = n_str.parse::<usize>().unwrap_or(0);
            let n = if n == 0 { 5 } else { n };
            procstat::init_defaults();
            let top = procstat::top_mem(n);
            shell_println!("Top {} by memory:", top.len());
            for p in &top {
                shell_println!("  pid={} {} mem={}", p.pid, p.name, p.memory_bytes);
            }
        }
        "register" => {
            let pid_str = parts.get(1).copied().unwrap_or("0");
            let name = parts.get(2).copied().unwrap_or("unnamed");
            let pid = pid_str.parse::<u32>().unwrap_or(0);
            if pid == 0 {
                shell_println!("Usage: procstat register <pid> <name>");
                return;
            }
            procstat::init_defaults();
            match procstat::register(pid, name) {
                Ok(()) => shell_println!("Registered process {} ({})", pid, name),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "stats" => {
            procstat::init_defaults();
            let (count, updates, ops) = procstat::stats();
            shell_println!("Process stats:");
            shell_println!("  Tracked: {}", count);
            shell_println!("  Updates: {}", updates);
            shell_println!("  Operations: {}", ops);
        }
        "test" => {
            procstat::self_test();
            shell_println!("procstat self-test passed.");
        }
        _ => {
            shell_println!("Usage: procstat [list|get <pid>|topcpu [n]|topmem [n]|register <pid> <name>|stats|test]");
        }
    }
}

/// `kernparam` / `kparam` — kernel boot parameters.
fn cmd_kernparam(args: &str) {
    use crate::fs::kernparam;
    let parts: Vec<&str> = args.split_whitespace().collect();
    let sub = parts.first().copied().unwrap_or("");
    match sub {
        "list" => {
            kernparam::init_defaults();
            let params = kernparam::list_params();
            shell_println!("Kernel parameters ({}):", params.len());
            for p in &params {
                let consumer = p.consumed_by.as_deref().unwrap_or("-");
                shell_println!("  {}={} [{}] consumer={} — {}",
                    p.key, p.value, p.origin.label(), consumer, p.description);
            }
        }
        "get" => {
            let key = parts.get(1).copied().unwrap_or("");
            if key.is_empty() {
                shell_println!("Usage: kernparam get <key>");
                return;
            }
            kernparam::init_defaults();
            match kernparam::get(key) {
                Some(v) => shell_println!("{}={}", key, v),
                None => shell_println!("Parameter '{}' not found", key),
            }
        }
        "set" => {
            let key = parts.get(1).copied().unwrap_or("");
            let val = parts.get(2).copied().unwrap_or("");
            if key.is_empty() {
                shell_println!("Usage: kernparam set <key> <value>");
                return;
            }
            kernparam::init_defaults();
            match kernparam::set(key, val) {
                Ok(()) => shell_println!("Set {}={}", key, val),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "remove" => {
            let key = parts.get(1).copied().unwrap_or("");
            if key.is_empty() {
                shell_println!("Usage: kernparam remove <key>");
                return;
            }
            kernparam::init_defaults();
            match kernparam::remove(key) {
                Ok(()) => shell_println!("Removed: {}", key),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "cmdline" => {
            kernparam::init_defaults();
            shell_println!("Cmdline: {}", kernparam::cmdline());
        }
        "unconsumed" => {
            kernparam::init_defaults();
            let uncon = kernparam::unconsumed();
            shell_println!("Unconsumed parameters ({}):", uncon.len());
            for p in &uncon {
                shell_println!("  {}={} [{}]", p.key, p.value, p.origin.label());
            }
        }
        "stats" => {
            kernparam::init_defaults();
            let (count, lookups, sets, unconsumed, ops) = kernparam::stats();
            shell_println!("Kernel parameter stats:");
            shell_println!("  Parameters: {}", count);
            shell_println!("  Lookups: {}", lookups);
            shell_println!("  Sets: {}", sets);
            shell_println!("  Unconsumed: {}", unconsumed);
            shell_println!("  Operations: {}", ops);
        }
        "test" => {
            kernparam::self_test();
            shell_println!("kernparam self-test passed.");
        }
        _ => {
            shell_println!("Usage: kernparam [list|get <key>|set <key> <val>|remove <key>|cmdline|unconsumed|stats|test]");
        }
    }
}

/// `tracemon` / `trcmon` — kernel tracing and profiling.
fn cmd_tracemon(args: &str) {
    use crate::fs::tracemon;
    let parts: Vec<&str> = args.split_whitespace().collect();
    let sub = parts.first().copied().unwrap_or("");
    match sub {
        "list" => {
            tracemon::init_defaults();
            let tps = tracemon::list_tracepoints();
            shell_println!("Tracepoints ({}):", tps.len());
            for tp in &tps {
                let st = if tp.enabled { "ON" } else { "off" };
                shell_println!("  {} [{}] {} hits={} — {}", tp.name, tp.category.label(), st, tp.hit_count, tp.description);
            }
        }
        "enable" => {
            let name = parts.get(1).copied().unwrap_or("");
            if name.is_empty() {
                shell_println!("Usage: tracemon enable <tracepoint>");
                return;
            }
            tracemon::init_defaults();
            match tracemon::enable(name) {
                Ok(()) => shell_println!("Enabled: {}", name),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "disable" => {
            let name = parts.get(1).copied().unwrap_or("");
            if name.is_empty() {
                shell_println!("Usage: tracemon disable <tracepoint>");
                return;
            }
            tracemon::init_defaults();
            match tracemon::disable(name) {
                Ok(()) => shell_println!("Disabled: {}", name),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "on" => {
            tracemon::init_defaults();
            match tracemon::set_global(true) {
                Ok(()) => shell_println!("Tracing enabled globally"),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "off" => {
            tracemon::init_defaults();
            match tracemon::set_global(false) {
                Ok(()) => shell_println!("Tracing disabled globally"),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "read" => {
            let n_str = parts.get(1).copied().unwrap_or("20");
            let n = n_str.parse::<usize>().unwrap_or(20);
            tracemon::init_defaults();
            let events = tracemon::read_buffer(n);
            shell_println!("Trace events ({}):", events.len());
            for ev in &events {
                shell_println!("  [{}] tp={} cpu={} pid={} {}", ev.timestamp_ns, ev.tracepoint_id, ev.cpu, ev.pid, ev.data);
            }
        }
        "clear" => {
            tracemon::init_defaults();
            match tracemon::clear_buffer() {
                Ok(()) => shell_println!("Trace buffer cleared"),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "filter" => {
            let pid_str = parts.get(1).copied().unwrap_or("");
            tracemon::init_defaults();
            if pid_str.is_empty() || pid_str == "none" {
                match tracemon::set_filter_pid(None) {
                    Ok(()) => shell_println!("PID filter cleared"),
                    Err(e) => shell_println!("Error: {:?}", e),
                }
            } else {
                let pid = pid_str.parse::<u32>().unwrap_or(0);
                match tracemon::set_filter_pid(Some(pid)) {
                    Ok(()) => shell_println!("Filtering to PID {}", pid),
                    Err(e) => shell_println!("Error: {:?}", e),
                }
            }
        }
        "stats" => {
            tracemon::init_defaults();
            let (tp, ev, total, dropped, enabled, ops) = tracemon::stats();
            shell_println!("Trace monitor stats:");
            shell_println!("  Tracepoints: {}", tp);
            shell_println!("  Buffered events: {}", ev);
            shell_println!("  Total events: {}", total);
            shell_println!("  Dropped: {}", dropped);
            shell_println!("  Global enabled: {}", enabled);
            shell_println!("  Operations: {}", ops);
        }
        "test" => {
            tracemon::self_test();
            shell_println!("tracemon self-test passed.");
        }
        _ => {
            shell_println!("Usage: tracemon [list|enable <name>|disable <name>|on|off|read [n]|clear|filter <pid|none>|stats|test]");
        }
    }
}

/// `authbroker` / `abroker` — authentication and credential management.
fn cmd_authbroker(args: &str) {
    use crate::fs::authbroker;
    let parts: Vec<&str> = args.split_whitespace().collect();
    let sub = parts.first().copied().unwrap_or("");
    match sub {
        "list" => {
            authbroker::init_defaults();
            let creds = authbroker::list_credentials(None);
            shell_println!("Credentials ({}):", creds.len());
            for c in &creds {
                let locked = if c.locked { " LOCKED" } else { "" };
                shell_println!("  #{} {} [{}] fails={}{}", c.id, c.principal, c.method.label(), c.failed_attempts, locked);
            }
        }
        "auth" => {
            let principal = parts.get(1).copied().unwrap_or("");
            let method_str = parts.get(2).copied().unwrap_or("password");
            if principal.is_empty() {
                shell_println!("Usage: authbroker auth <principal> [method]");
                shell_println!("  Methods: password|token|certificate|biometric|kerberos|pubkey");
                return;
            }
            let method = match method_str {
                "password" | "pass" => authbroker::AuthMethod::Password,
                "token" => authbroker::AuthMethod::Token,
                "certificate" | "cert" => authbroker::AuthMethod::Certificate,
                "biometric" | "bio" => authbroker::AuthMethod::Biometric,
                "kerberos" | "krb" => authbroker::AuthMethod::Kerberos,
                "pubkey" | "pk" => authbroker::AuthMethod::PublicKey,
                _ => { shell_println!("Unknown method: {}", method_str); return; }
            };
            authbroker::init_defaults();
            match authbroker::authenticate(principal, method) {
                Ok(r) => shell_println!("Result: {}", r.label()),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "unlock" => {
            let principal = parts.get(1).copied().unwrap_or("");
            if principal.is_empty() {
                shell_println!("Usage: authbroker unlock <principal>");
                return;
            }
            authbroker::init_defaults();
            match authbroker::unlock(principal) {
                Ok(()) => shell_println!("Unlocked: {}", principal),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "grant" => {
            let principal = parts.get(1).copied().unwrap_or("");
            let resource = parts.get(2).copied().unwrap_or("");
            if principal.is_empty() || resource.is_empty() {
                shell_println!("Usage: authbroker grant <principal> <resource>");
                return;
            }
            authbroker::init_defaults();
            match authbroker::grant_capability(principal, resource, 0) {
                Ok(id) => shell_println!("Granted cap #{} to {} for {}", id, principal, resource),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "grants" => {
            let principal = parts.get(1).copied();
            authbroker::init_defaults();
            let grants = authbroker::list_grants(principal);
            shell_println!("Active grants ({}):", grants.len());
            for g in &grants {
                shell_println!("  #{} {} -> {}", g.id, g.principal, g.resource);
            }
        }
        "revoke" => {
            let id_str = parts.get(1).copied().unwrap_or("0");
            let id = id_str.parse::<u32>().unwrap_or(0);
            if id == 0 {
                shell_println!("Usage: authbroker revoke <grant_id>");
                return;
            }
            authbroker::init_defaults();
            match authbroker::revoke_grant(id) {
                Ok(()) => shell_println!("Revoked grant #{}", id),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "stats" => {
            authbroker::init_defaults();
            let (creds, grants, attempts, granted, denied, revoked, ops) = authbroker::stats();
            shell_println!("Auth broker stats:");
            shell_println!("  Credentials: {}", creds);
            shell_println!("  Active grants: {}", grants);
            shell_println!("  Auth attempts: {}", attempts);
            shell_println!("  Granted: {}", granted);
            shell_println!("  Denied: {}", denied);
            shell_println!("  Revoked: {}", revoked);
            shell_println!("  Operations: {}", ops);
        }
        "test" => {
            authbroker::self_test();
            shell_println!("authbroker self-test passed.");
        }
        _ => {
            shell_println!("Usage: authbroker [list|auth <principal> [method]|unlock <principal>|grant <principal> <resource>|grants [principal]|revoke <id>|stats|test]");
        }
    }
}

/// `prociso` / `piso` — process isolation and namespaces.
fn cmd_prociso(args: &str) {
    use crate::fs::prociso;
    use alloc::format;
    let parts: Vec<&str> = args.split_whitespace().collect();
    let sub = parts.first().copied().unwrap_or("");
    match sub {
        "list" => {
            prociso::init_defaults();
            let nss = prociso::list_namespaces();
            shell_println!("Namespaces ({}):", nss.len());
            for ns in &nss {
                let parent = ns.parent_id.map_or(String::from("-"), |p| format!("{}", p));
                shell_println!("  #{} {} [{}] iso={} parent={} procs={}",
                    ns.id, ns.name, ns.ns_type.label(), ns.isolation.label(), parent, ns.processes.len());
            }
        }
        "create" => {
            let ns_type_str = parts.get(1).copied().unwrap_or("");
            let name = parts.get(2).copied().unwrap_or("");
            if ns_type_str.is_empty() || name.is_empty() {
                shell_println!("Usage: prociso create <type> <name>");
                shell_println!("  Types: mnt|pid|net|user|ipc|uts|cgroup");
                return;
            }
            let ns_type = match ns_type_str {
                "mnt" | "mount" => prociso::NsType::Mount,
                "pid" => prociso::NsType::Pid,
                "net" => prociso::NsType::Net,
                "user" => prociso::NsType::User,
                "ipc" => prociso::NsType::Ipc,
                "uts" => prociso::NsType::Uts,
                "cgroup" => prociso::NsType::Cgroup,
                _ => { shell_println!("Unknown type: {}", ns_type_str); return; }
            };
            prociso::init_defaults();
            match prociso::create_namespace(ns_type, name, prociso::IsolationLevel::Full, None) {
                Ok(id) => shell_println!("Created namespace #{}: {}", id, name),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "delete" => {
            let id_str = parts.get(1).copied().unwrap_or("0");
            let id = id_str.parse::<u32>().unwrap_or(0);
            if id == 0 {
                shell_println!("Usage: prociso delete <ns_id>");
                return;
            }
            prociso::init_defaults();
            match prociso::delete_namespace(id) {
                Ok(()) => shell_println!("Deleted namespace #{}", id),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "attach" => {
            let pid_str = parts.get(1).copied().unwrap_or("0");
            let ns_str = parts.get(2).copied().unwrap_or("0");
            let pid = pid_str.parse::<u32>().unwrap_or(0);
            let ns_id = ns_str.parse::<u32>().unwrap_or(0);
            if pid == 0 || ns_id == 0 {
                shell_println!("Usage: prociso attach <pid> <ns_id>");
                return;
            }
            prociso::init_defaults();
            match prociso::attach(pid, ns_id) {
                Ok(()) => shell_println!("Attached PID {} to namespace #{}", pid, ns_id),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "detach" => {
            let pid_str = parts.get(1).copied().unwrap_or("0");
            let ns_str = parts.get(2).copied().unwrap_or("0");
            let pid = pid_str.parse::<u32>().unwrap_or(0);
            let ns_id = ns_str.parse::<u32>().unwrap_or(0);
            if pid == 0 || ns_id == 0 {
                shell_println!("Usage: prociso detach <pid> <ns_id>");
                return;
            }
            prociso::init_defaults();
            match prociso::detach(pid, ns_id) {
                Ok(()) => shell_println!("Detached PID {} from namespace #{}", pid, ns_id),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "container" => {
            let action = parts.get(1).copied().unwrap_or("");
            match action {
                "create" => {
                    let name = parts.get(2).copied().unwrap_or("");
                    if name.is_empty() {
                        shell_println!("Usage: prociso container create <name>");
                        return;
                    }
                    prociso::init_defaults();
                    match prociso::create_container(name, &[prociso::NsType::Mount, prociso::NsType::Pid, prociso::NsType::Net]) {
                        Ok(id) => shell_println!("Created container #{}: {}", id, name),
                        Err(e) => shell_println!("Error: {:?}", e),
                    }
                }
                "list" => {
                    prociso::init_defaults();
                    let containers = prociso::list_containers();
                    shell_println!("Containers ({}):", containers.len());
                    for c in &containers {
                        let st = if c.running { "running" } else { "stopped" };
                        shell_println!("  #{} {} [{}] ns={}", c.id, c.name, st, c.namespaces.len());
                    }
                }
                "delete" => {
                    let id_str = parts.get(2).copied().unwrap_or("0");
                    let id = id_str.parse::<u32>().unwrap_or(0);
                    if id == 0 {
                        shell_println!("Usage: prociso container delete <id>");
                        return;
                    }
                    prociso::init_defaults();
                    match prociso::delete_container(id) {
                        Ok(()) => shell_println!("Deleted container #{}", id),
                        Err(e) => shell_println!("Error: {:?}", e),
                    }
                }
                _ => shell_println!("Usage: prociso container [create <name>|list|delete <id>]"),
            }
        }
        "stats" => {
            prociso::init_defaults();
            let (ns, cont, att, det, ops) = prociso::stats();
            shell_println!("Process isolation stats:");
            shell_println!("  Namespaces: {}", ns);
            shell_println!("  Containers: {}", cont);
            shell_println!("  Attaches: {}", att);
            shell_println!("  Detaches: {}", det);
            shell_println!("  Operations: {}", ops);
        }
        "test" => {
            prociso::self_test();
            shell_println!("prociso self-test passed.");
        }
        _ => {
            shell_println!("Usage: prociso [list|create <type> <name>|delete <id>|attach <pid> <ns>|detach <pid> <ns>|container ...|stats|test]");
        }
    }
}

/// `dmevent` / `dmev` — device hotplug and event monitoring.
fn cmd_dmevent(args: &str) {
    use crate::fs::dmevent;
    let parts: Vec<&str> = args.split_whitespace().collect();
    let sub = parts.first().copied().unwrap_or("");
    match sub {
        "devices" => {
            dmevent::init_defaults();
            let devs = dmevent::list_devices();
            shell_println!("Known devices ({}):", devs.len());
            for d in &devs {
                let st = if d.online { "online" } else { "offline" };
                shell_println!("  {} [{}] {} {}", d.devname, d.subsystem.label(), st, d.devpath);
            }
        }
        "events" => {
            let n_str = parts.get(1).copied().unwrap_or("20");
            let n = n_str.parse::<usize>().unwrap_or(20);
            dmevent::init_defaults();
            let events = dmevent::poll(n);
            shell_println!("Recent events ({}):", events.len());
            for ev in &events {
                shell_println!("  seq={} {} [{}] {} {}", ev.seq, ev.event_type.label(), ev.subsystem.label(), ev.devname, ev.devpath);
            }
        }
        "notify" => {
            let ev_str = parts.get(1).copied().unwrap_or("");
            let sub_str = parts.get(2).copied().unwrap_or("");
            let devpath = parts.get(3).copied().unwrap_or("");
            let devname = parts.get(4).copied().unwrap_or("");
            if ev_str.is_empty() || sub_str.is_empty() || devpath.is_empty() {
                shell_println!("Usage: dmevent notify <add|remove|change> <block|net|usb|...> <devpath> <devname>");
                return;
            }
            let event_type = match ev_str {
                "add" => dmevent::EventType::Add,
                "remove" => dmevent::EventType::Remove,
                "change" => dmevent::EventType::Change,
                "online" => dmevent::EventType::Online,
                "offline" => dmevent::EventType::Offline,
                _ => { shell_println!("Unknown event: {}", ev_str); return; }
            };
            let subsystem = match sub_str {
                "block" => dmevent::Subsystem::Block,
                "net" => dmevent::Subsystem::Net,
                "usb" => dmevent::Subsystem::Usb,
                "pci" => dmevent::Subsystem::Pci,
                "input" => dmevent::Subsystem::Input,
                "tty" => dmevent::Subsystem::Tty,
                "sound" => dmevent::Subsystem::Sound,
                "gpu" => dmevent::Subsystem::Gpu,
                _ => { shell_println!("Unknown subsystem: {}", sub_str); return; }
            };
            dmevent::init_defaults();
            match dmevent::notify(event_type, subsystem, devpath, devname, &[]) {
                Ok(seq) => shell_println!("Event #{}: {} {} {}", seq, ev_str, devname, devpath),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "rules" => {
            dmevent::init_defaults();
            let rules = dmevent::list_rules();
            shell_println!("Event rules ({}):", rules.len());
            for r in &rules {
                let st = if r.enabled { "ON" } else { "off" };
                shell_println!("  #{} {} [{}] pattern={} action={} {}",
                    r.id, r.event_type.label(), r.subsystem.label(), r.devname_pattern, r.action, st);
            }
        }
        "clear" => {
            dmevent::init_defaults();
            match dmevent::clear_events() {
                Ok(()) => shell_println!("Event log cleared"),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "stats" => {
            dmevent::init_defaults();
            let (devs, evs, rules, total, matched, ops) = dmevent::stats();
            shell_println!("Device event stats:");
            shell_println!("  Devices: {}", devs);
            shell_println!("  Buffered events: {}", evs);
            shell_println!("  Rules: {}", rules);
            shell_println!("  Total events: {}", total);
            shell_println!("  Rule matches: {}", matched);
            shell_println!("  Operations: {}", ops);
        }
        "test" => {
            dmevent::self_test();
            shell_println!("dmevent self-test passed.");
        }
        _ => {
            shell_println!("Usage: dmevent [devices|events [n]|notify <type> <subsys> <path> <name>|rules|clear|stats|test]");
        }
    }
}

/// `pftrack` / `pft` — page fault tracking and analysis.
fn cmd_pftrack(args: &str) {
    use crate::fs::pftrack;
    let parts: Vec<&str> = args.split_whitespace().collect();
    let sub = parts.first().copied().unwrap_or("");
    match sub {
        "list" => {
            pftrack::init_defaults();
            let procs = pftrack::list_processes();
            shell_println!("Process fault stats ({}):", procs.len());
            for p in &procs {
                shell_println!("  pid={} {} total={} minor={} major={} cow={} inv={} prot={}",
                    p.pid, p.name, p.total, p.minor, p.major, p.cow, p.invalid, p.protection);
            }
        }
        "top" => {
            let n_str = parts.get(1).copied().unwrap_or("5");
            let n = n_str.parse::<usize>().unwrap_or(5);
            let n = if n == 0 { 5 } else { n };
            pftrack::init_defaults();
            let top = pftrack::top_faulters(n);
            shell_println!("Top {} faulters:", top.len());
            for p in &top {
                shell_println!("  pid={} {} total={} major={}", p.pid, p.name, p.total, p.major);
            }
        }
        "hotspots" => {
            let n_str = parts.get(1).copied().unwrap_or("10");
            let n = n_str.parse::<usize>().unwrap_or(10);
            pftrack::init_defaults();
            let hs = pftrack::hotspots(n);
            shell_println!("Top {} hotspot addresses:", hs.len());
            for h in &hs {
                shell_println!("  {:#x} count={} last_pid={} [{}]", h.address, h.count, h.last_pid, h.last_kind.label());
            }
        }
        "recent" => {
            let n_str = parts.get(1).copied().unwrap_or("20");
            let n = n_str.parse::<usize>().unwrap_or(20);
            pftrack::init_defaults();
            let events = pftrack::recent_events(n);
            shell_println!("Recent faults ({}):", events.len());
            for ev in &events {
                shell_println!("  pid={} addr={:#x} [{}] ip={:#x}", ev.pid, ev.address, ev.kind.label(), ev.instruction_ptr);
            }
        }
        "clear" => {
            pftrack::init_defaults();
            match pftrack::clear() {
                Ok(()) => shell_println!("Fault tracking data cleared"),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "stats" => {
            pftrack::init_defaults();
            let (procs, evs, total, minor, major, ops) = pftrack::stats();
            shell_println!("Page fault stats:");
            shell_println!("  Tracked processes: {}", procs);
            shell_println!("  Buffered events: {}", evs);
            shell_println!("  Total faults: {}", total);
            shell_println!("  Minor: {}", minor);
            shell_println!("  Major: {}", major);
            shell_println!("  Operations: {}", ops);
        }
        "test" => {
            pftrack::self_test();
            shell_println!("pftrack self-test passed.");
        }
        _ => {
            shell_println!("Usage: pftrack [list|top [n]|hotspots [n]|recent [n]|clear|stats|test]");
        }
    }
}

/// `ipclog` / `ipcl` — IPC message logging.
fn cmd_ipclog(args: &str) {
    use crate::fs::ipclog;
    let parts: Vec<&str> = args.split_whitespace().collect();
    let sub = parts.first().copied().unwrap_or("");
    match sub {
        "channels" => {
            ipclog::init_defaults();
            let chs = ipclog::list_channels();
            shell_println!("IPC channels ({}):", chs.len());
            for ch in &chs {
                shell_println!("  ch#{} {} sent={} recv={} bytes_s={} bytes_r={} lat={}us err={}",
                    ch.channel_id, ch.name, ch.messages_sent, ch.messages_received,
                    ch.bytes_sent, ch.bytes_received, ch.avg_latency_us, ch.errors);
            }
        }
        "recent" => {
            let n_str = parts.get(1).copied().unwrap_or("20");
            let n = n_str.parse::<usize>().unwrap_or(20);
            ipclog::init_defaults();
            let msgs = ipclog::recent(n);
            shell_println!("Recent IPC messages ({}):", msgs.len());
            for m in &msgs {
                shell_println!("  #{} {} {}→{} ch={} {}B lat={}us {}",
                    m.seq, m.msg_type.label(), m.src_pid, m.dst_pid, m.channel_id,
                    m.size_bytes, m.latency_us, m.label);
            }
        }
        "pid" => {
            let pid_str = parts.get(1).copied().unwrap_or("0");
            let pid = pid_str.parse::<u32>().unwrap_or(0);
            if pid == 0 {
                shell_println!("Usage: ipclog pid <pid>");
                return;
            }
            ipclog::init_defaults();
            let msgs = ipclog::query_pid(pid, 20);
            shell_println!("Messages for PID {} ({}):", pid, msgs.len());
            for m in &msgs {
                shell_println!("  #{} {} {}→{} ch={} {}B", m.seq, m.msg_type.label(), m.src_pid, m.dst_pid, m.channel_id, m.size_bytes);
            }
        }
        "channel" => {
            let ch_str = parts.get(1).copied().unwrap_or("0");
            let ch = ch_str.parse::<u32>().unwrap_or(0);
            if ch == 0 {
                shell_println!("Usage: ipclog channel <channel_id>");
                return;
            }
            ipclog::init_defaults();
            let msgs = ipclog::query_channel(ch, 20);
            shell_println!("Messages on channel {} ({}):", ch, msgs.len());
            for m in &msgs {
                shell_println!("  #{} {} {}→{} {}B", m.seq, m.msg_type.label(), m.src_pid, m.dst_pid, m.size_bytes);
            }
        }
        "on" => {
            ipclog::init_defaults();
            match ipclog::set_enabled(true) {
                Ok(()) => shell_println!("IPC logging enabled"),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "off" => {
            ipclog::init_defaults();
            match ipclog::set_enabled(false) {
                Ok(()) => shell_println!("IPC logging disabled"),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "clear" => {
            ipclog::init_defaults();
            match ipclog::clear() {
                Ok(()) => shell_println!("IPC log cleared"),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "stats" => {
            ipclog::init_defaults();
            let (channels, msgs, total, bytes, errors, enabled, ops) = ipclog::stats();
            shell_println!("IPC log stats:");
            shell_println!("  Channels: {}", channels);
            shell_println!("  Buffered messages: {}", msgs);
            shell_println!("  Total messages: {}", total);
            shell_println!("  Total bytes: {}", bytes);
            shell_println!("  Errors: {}", errors);
            shell_println!("  Enabled: {}", enabled);
            shell_println!("  Operations: {}", ops);
        }
        "test" => {
            ipclog::self_test();
            shell_println!("ipclog self-test passed.");
        }
        _ => {
            shell_println!("Usage: ipclog [channels|recent [n]|pid <pid>|channel <id>|on|off|clear|stats|test]");
        }
    }
}

/// `numastat` / `nstat` — NUMA node statistics.
fn cmd_numastat(args: &str) {
    use crate::fs::numastat;
    let parts: Vec<&str> = args.split_whitespace().collect();
    let sub = parts.first().copied().unwrap_or("");
    match sub {
        "list" => {
            numastat::init_defaults();
            let nodes = numastat::list_nodes();
            shell_println!("NUMA nodes ({}):", nodes.len());
            for n in &nodes {
                shell_println!("  node{} [{}] mem={}/{} free={} cpus={:?}",
                    n.id, n.state.label(), n.used_memory, n.total_memory, n.free_memory, n.cpus);
                shell_println!("    local_alloc={} remote_alloc={} lat={}ns mig_in={} mig_out={}",
                    n.local_allocs, n.remote_allocs, n.avg_latency_ns, n.migrations_in, n.migrations_out);
            }
        }
        "dist" => {
            numastat::init_defaults();
            let dists = numastat::list_distances();
            shell_println!("Node distances:");
            for d in &dists {
                shell_println!("  node{} -> node{}: {}", d.from_node, d.to_node, d.distance);
            }
        }
        "balance" => {
            numastat::init_defaults();
            let pct = numastat::remote_alloc_pct();
            shell_println!("Remote allocation: {}%", pct);
            if pct > 20 {
                shell_println!("  WARNING: High remote allocation ratio. Consider NUMA-aware placement.");
            } else {
                shell_println!("  OK: Remote allocation within acceptable range.");
            }
        }
        "stats" => {
            numastat::init_defaults();
            let (nodes, allocs, remote, migrations, pct, ops) = numastat::stats();
            shell_println!("NUMA stats:");
            shell_println!("  Nodes: {}", nodes);
            shell_println!("  Total allocs: {}", allocs);
            shell_println!("  Remote allocs: {} ({}%)", remote, pct);
            shell_println!("  Migrations: {}", migrations);
            shell_println!("  Operations: {}", ops);
        }
        "test" => {
            numastat::self_test();
            shell_println!("numastat self-test passed.");
        }
        _ => {
            shell_println!("Usage: numastat [list|dist|balance|stats|test]");
        }
    }
}

/// `shmem` / `shm` — shared memory regions.
fn cmd_shmem(args: &str) {
    use crate::fs::shmem;
    let parts: Vec<&str> = args.split_whitespace().collect();
    let sub = parts.first().copied().unwrap_or("");
    match sub {
        "list" => {
            shmem::init_defaults();
            let regions = shmem::list_regions();
            shell_println!("Shared memory regions ({}):", regions.len());
            for r in &regions {
                let pers = if r.persistent { " PERSIST" } else { "" };
                shell_println!("  #{} {} size={} [{}] owner={} attached={}{}", r.id, r.name, r.size, r.permission.label(), r.owner_pid, r.attached_pids.len(), pers);
            }
        }
        "create" => {
            let name = parts.get(1).copied().unwrap_or("");
            let size_str = parts.get(2).copied().unwrap_or("0");
            let size = size_str.parse::<u64>().unwrap_or(0);
            if name.is_empty() || size == 0 {
                shell_println!("Usage: shmem create <name> <size>");
                return;
            }
            shmem::init_defaults();
            match shmem::create(name, size, shmem::ShmPermission::ReadWrite, 1, false) {
                Ok(id) => shell_println!("Created shared region #{}: {} ({}B)", id, name, size),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "delete" => {
            let id_str = parts.get(1).copied().unwrap_or("0");
            let id = id_str.parse::<u32>().unwrap_or(0);
            if id == 0 {
                shell_println!("Usage: shmem delete <id>");
                return;
            }
            shmem::init_defaults();
            match shmem::delete(id) {
                Ok(()) => shell_println!("Deleted region #{}", id),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "attach" => {
            let id_str = parts.get(1).copied().unwrap_or("0");
            let pid_str = parts.get(2).copied().unwrap_or("0");
            let id = id_str.parse::<u32>().unwrap_or(0);
            let pid = pid_str.parse::<u32>().unwrap_or(0);
            if id == 0 || pid == 0 {
                shell_println!("Usage: shmem attach <id> <pid>");
                return;
            }
            shmem::init_defaults();
            match shmem::attach(id, pid) {
                Ok(()) => shell_println!("Attached PID {} to region #{}", pid, id),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "detach" => {
            let id_str = parts.get(1).copied().unwrap_or("0");
            let pid_str = parts.get(2).copied().unwrap_or("0");
            let id = id_str.parse::<u32>().unwrap_or(0);
            let pid = pid_str.parse::<u32>().unwrap_or(0);
            if id == 0 || pid == 0 {
                shell_println!("Usage: shmem detach <id> <pid>");
                return;
            }
            shmem::init_defaults();
            match shmem::detach(id, pid) {
                Ok(()) => shell_println!("Detached PID {} from region #{}", pid, id),
                Err(e) => shell_println!("Error: {:?}", e),
            }
        }
        "pid" => {
            let pid_str = parts.get(1).copied().unwrap_or("0");
            let pid = pid_str.parse::<u32>().unwrap_or(0);
            if pid == 0 {
                shell_println!("Usage: shmem pid <pid>");
                return;
            }
            shmem::init_defaults();
            let regs = shmem::regions_for_pid(pid);
            shell_println!("Regions for PID {} ({}):", pid, regs.len());
            for r in &regs {
                shell_println!("  #{} {} size={} [{}]", r.id, r.name, r.size, r.permission.label());
            }
        }
        "stats" => {
            shmem::init_defaults();
            let (regions, created, deleted, attaches, detaches, bytes, ops) = shmem::stats();
            shell_println!("Shared memory stats:");
            shell_println!("  Regions: {}", regions);
            shell_println!("  Created: {}", created);
            shell_println!("  Deleted: {}", deleted);
            shell_println!("  Attaches: {}", attaches);
            shell_println!("  Detaches: {}", detaches);
            shell_println!("  Total bytes: {}", bytes);
            shell_println!("  Operations: {}", ops);
        }
        "test" => {
            shmem::self_test();
            shell_println!("shmem self-test passed.");
        }
        _ => {
            shell_println!("Usage: shmem [list|create <name> <size>|delete <id>|attach <id> <pid>|detach <id> <pid>|pid <pid>|stats|test]");
        }
    }
}

/// `wqstat` / `wqs` — workqueue statistics.
fn cmd_wqstat(args: &str) {
    use crate::fs::wqstat;
    let parts: Vec<&str> = args.split_whitespace().collect();
    let sub = parts.first().copied().unwrap_or("");
    match sub {
        "list" => {
            wqstat::init_defaults();
            let wqs = wqstat::list();
            shell_println!("Workqueues ({}):", wqs.len());
            for q in &wqs {
                shell_println!("  {} [{}] pend={} active={} done={} cancel={} lat={}us max_lat={}us workers={}",
                    q.name, q.wq_type.label(), q.pending, q.active, q.completed, q.cancelled,
                    q.avg_latency_us, q.max_latency_us, q.workers);
            }
        }
        "get" => {
            let name = parts.get(1).copied().unwrap_or("");
            if name.is_empty() { shell_println!("Usage: wqstat get <name>"); return; }
            wqstat::init_defaults();
            match wqstat::get(name) {
                Some(q) => {
                    shell_println!("Workqueue: {}", q.name);
                    shell_println!("  Type: {}", q.wq_type.label());
                    shell_println!("  Pending: {} (max: {})", q.pending, q.max_pending);
                    shell_println!("  Active: {}", q.active);
                    shell_println!("  Completed: {}", q.completed);
                    shell_println!("  Cancelled: {}", q.cancelled);
                    shell_println!("  Avg latency: {}us", q.avg_latency_us);
                    shell_println!("  Max latency: {}us", q.max_latency_us);
                    shell_println!("  Workers: {}", q.workers);
                }
                None => shell_println!("Workqueue '{}' not found", name),
            }
        }
        "stats" => {
            wqstat::init_defaults();
            let (count, enqueued, completed, cancelled, ops) = wqstat::stats();
            shell_println!("Workqueue stats:");
            shell_println!("  Queues: {}", count);
            shell_println!("  Total enqueued: {}", enqueued);
            shell_println!("  Total completed: {}", completed);
            shell_println!("  Total cancelled: {}", cancelled);
            shell_println!("  Operations: {}", ops);
        }
        "test" => {
            wqstat::self_test();
            shell_println!("wqstat self-test passed.");
        }
        _ => {
            shell_println!("Usage: wqstat [list|get <name>|stats|test]");
        }
    }
}

/// `slabstat` / `slab` — slab allocator statistics.
fn cmd_slabstat(args: &str) {
    use crate::fs::slabstat;
    let parts: Vec<&str> = args.split_whitespace().collect();
    let sub = parts.first().copied().unwrap_or("");
    match sub {
        "list" => {
            slabstat::init_defaults();
            let caches = slabstat::list();
            shell_println!("Slab caches ({}):", caches.len());
            for c in &caches {
                shell_println!("  {} size={} active={}/{} util={}% hwm={} allocs={} frees={}",
                    c.name, c.object_size, c.active_objects, c.total_objects,
                    c.utilization_pct(), c.high_watermark, c.total_allocs, c.total_frees);
            }
        }
        "top" => {
            let n_str = parts.get(1).copied().unwrap_or("5");
            let n = n_str.parse::<usize>().unwrap_or(5);
            let n = if n == 0 { 5 } else { n };
            slabstat::init_defaults();
            let top = slabstat::top_active(n);
            shell_println!("Top {} by active objects:", top.len());
            for c in &top {
                shell_println!("  {} active={} util={}%", c.name, c.active_objects, c.utilization_pct());
            }
        }
        "get" => {
            let name = parts.get(1).copied().unwrap_or("");
            if name.is_empty() { shell_println!("Usage: slabstat get <cache_name>"); return; }
            slabstat::init_defaults();
            match slabstat::get(name) {
                Some(c) => {
                    shell_println!("Cache: {}", c.name);
                    shell_println!("  Object size: {}B (align={})", c.object_size, c.align);
                    shell_println!("  Objects: {}/{} ({}%)", c.active_objects, c.total_objects, c.utilization_pct());
                    shell_println!("  Slabs: {}/{}", c.active_slabs, c.total_slabs);
                    shell_println!("  Allocs: {} Frees: {}", c.total_allocs, c.total_frees);
                    shell_println!("  High watermark: {}", c.high_watermark);
                    shell_println!("  Reclaims: {}", c.reclaim_count);
                }
                None => shell_println!("Cache '{}' not found", name),
            }
        }
        "stats" => {
            slabstat::init_defaults();
            let (count, allocs, frees, reclaims, ops) = slabstat::stats();
            shell_println!("Slab stats:");
            shell_println!("  Caches: {}", count);
            shell_println!("  Total allocs: {}", allocs);
            shell_println!("  Total frees: {}", frees);
            shell_println!("  Reclaims: {}", reclaims);
            shell_println!("  Operations: {}", ops);
        }
        "test" => {
            slabstat::self_test();
            shell_println!("slabstat self-test passed.");
        }
        _ => {
            shell_println!("Usage: slabstat [list|top [n]|get <name>|stats|test]");
        }
    }
}

