/// `netdev` / `ndev` — network device statistics.
fn cmd_netdev(args: &str) {
    use crate::fs::netdev;
    let parts: Vec<&str> = args.split_whitespace().collect();
    let sub = parts.first().copied().unwrap_or("");
    match sub {
        "list" | "ls" => {
            for i in netdev::list() {
                shell_println!("{} ({}) {} {}Mbps mtu={}",
                    i.name, i.nic_type.label(),
                    if i.link_up { "UP" } else { "DOWN" },
                    i.speed_mbps, i.mtu);
                shell_println!("  RX: {} bytes {} pkts {} err {} drop",
                    i.rx_bytes, i.rx_packets, i.rx_errors, i.rx_drops);
                shell_println!("  TX: {} bytes {} pkts {} err {} drop",
                    i.tx_bytes, i.tx_packets, i.tx_errors, i.tx_drops);
            }
        }
        "get" => {
            let name = parts.get(1).copied().unwrap_or("eth0");
            match netdev::get(name) {
                Some(i) => {
                    shell_println!("{} ({}) {}", i.name, i.nic_type.label(), if i.link_up { "UP" } else { "DOWN" });
                    shell_println!("  Speed: {}Mbps  MTU: {}", i.speed_mbps, i.mtu);
                    shell_println!("  RX: {} bytes {} pkts", i.rx_bytes, i.rx_packets);
                    shell_println!("  TX: {} bytes {} pkts", i.tx_bytes, i.tx_packets);
                    shell_println!("  Errors: rx={} tx={}  Drops: rx={} tx={}", i.rx_errors, i.tx_errors, i.rx_drops, i.tx_drops);
                }
                None => shell_println!("Interface {} not found", name),
            }
        }
        "stats" => {
            let (ifaces, rx, tx, errors, drops, ops) = netdev::stats();
            shell_println!("Interfaces: {}", ifaces);
            shell_println!("Total RX: {} bytes", rx);
            shell_println!("Total TX: {} bytes", tx);
            shell_println!("Total errors: {}", errors);
            shell_println!("Total drops: {}", drops);
            shell_println!("Operations: {}", ops);
        }
        "test" => netdev::self_test(),
        _ => {
            shell_println!("Usage: netdev [list|get <iface>|stats|test]");
        }
    }
}

/// `cpustat` / `cpust` — per-CPU utilization breakdown.
fn cmd_cpustat(args: &str) {
    use crate::fs::cpustat;
    use alloc::format;
    let parts: Vec<&str> = args.split_whitespace().collect();
    let sub = parts.first().copied().unwrap_or("");
    match sub {
        "percpu" | "cpus" => {
            let modes = ["user", "nice", "sys", "idle", "iowait", "irq", "softirq", "steal"];
            for c in cpustat::per_cpu() {
                let mut line = format!("cpu{}:", c.cpu_id);
                for (i, m) in modes.iter().enumerate() {
                    line.push_str(&format!(" {}={}ns", m, c.times_ns[i]));
                }
                shell_println!("{}", line);
            }
        }
        "util" => {
            let overall = cpustat::utilization();
            shell_println!("Overall: {}.{}%", overall / 100, overall % 100);
            for (id, u) in cpustat::per_cpu_util() {
                shell_println!("  cpu{}: {}.{}%", id, u / 100, u % 100);
            }
        }
        "stats" => {
            let (cpus, ctxsw, irqs, ops) = cpustat::stats();
            let util = cpustat::utilization();
            shell_println!("CPUs: {}", cpus);
            shell_println!("Utilization: {}.{}%", util / 100, util % 100);
            shell_println!("Context switches: {}", ctxsw);
            shell_println!("Interrupts: {}", irqs);
            shell_println!("Operations: {}", ops);
        }
        "test" => cpustat::self_test(),
        _ => {
            shell_println!("Usage: cpustat [percpu|util|stats|test]");
        }
    }
}

/// `filelock` / `flkstat` — file lock statistics.
fn cmd_filelock(args: &str) {
    use crate::fs::filelock;
    use alloc::format;
    let parts: Vec<&str> = args.split_whitespace().collect();
    let sub = parts.first().copied().unwrap_or("");
    match sub {
        "list" | "ls" => {
            for l in filelock::active_locks() {
                shell_println!("[{}] id={} pid={} {} {}-{} {} cont={}",
                    l.lock_type.label(), l.id, l.pid, l.path, l.start,
                    if l.end == u64::MAX { "EOF".into() } else { format!("{}", l.end) },
                    if l.blocking { "BLOCK" } else { "NONBLOCK" }, l.contentions);
            }
        }
        "pid" => {
            let pid = parts.get(1).copied().unwrap_or("0").parse::<u32>().unwrap_or(0);
            for l in filelock::by_pid(pid) {
                shell_println!("[{}] id={} {} cont={}", l.lock_type.label(), l.id, l.path, l.contentions);
            }
        }
        "stats" => {
            let (active, acquired, released, contentions, deadlocks, ops) = filelock::stats();
            shell_println!("Active locks: {}", active);
            shell_println!("Total acquired: {}", acquired);
            shell_println!("Total released: {}", released);
            shell_println!("Total contentions: {}", contentions);
            shell_println!("Total deadlocks: {}", deadlocks);
            shell_println!("Operations: {}", ops);
        }
        "test" => filelock::self_test(),
        _ => {
            shell_println!("Usage: filelock [list|pid <pid>|stats|test]");
        }
    }
}

/// `pidstat` / `pidst` — PID allocation/namespace stats.
fn cmd_pidstat(args: &str) {
    use crate::fs::pidstat;
    use alloc::format;
    let parts: Vec<&str> = args.split_whitespace().collect();
    let sub = parts.first().copied().unwrap_or("");
    match sub {
        "list" | "ns" => {
            for ns in pidstat::ns_list() {
                shell_println!("ns{}: parent={} active={} max={} alloc={} free={} hwm={}",
                    ns.ns_id, ns.parent_id.map_or("root".into(), |p| format!("{}", p)),
                    ns.active_pids, ns.max_pid, ns.allocated, ns.freed, ns.high_watermark);
            }
        }
        "info" => {
            let id = parts.get(1).copied().unwrap_or("0").parse::<u32>().unwrap_or(0);
            match pidstat::ns_info(id) {
                Some(ns) => {
                    shell_println!("Namespace {}", ns.ns_id);
                    shell_println!("  Parent: {}", ns.parent_id.map_or("root".into(), |p| format!("{}", p)));
                    shell_println!("  Active PIDs: {}", ns.active_pids);
                    shell_println!("  Max PID: {}", ns.max_pid);
                    shell_println!("  High watermark: {}", ns.high_watermark);
                    shell_println!("  Allocated: {}", ns.allocated);
                    shell_println!("  Freed: {}", ns.freed);
                }
                None => shell_println!("Namespace {} not found", id),
            }
        }
        "stats" => {
            let (nss, alloc, freed, reuses, ops) = pidstat::stats();
            shell_println!("Namespaces: {}", nss);
            shell_println!("Total allocated: {}", alloc);
            shell_println!("Total freed: {}", freed);
            shell_println!("Total reuses: {}", reuses);
            shell_println!("Operations: {}", ops);
        }
        "test" => pidstat::self_test(),
        _ => {
            shell_println!("Usage: pidstat [list|info <ns_id>|stats|test]");
        }
    }
}

