fn cmd_dhcpv6(args: &str) {
    let parts: Vec<&str> = args.split_whitespace().collect();
    let sub = parts.first().copied().unwrap_or("help");

    match sub {
        "discover" | "d" => {
            shell_println!("Running DHCPv6 stateful discovery...");
            match crate::net::dhcpv6::discover() {
                Ok(addr) => {
                    shell_println!("DHCPv6 successful: {}", addr);
                    let s = crate::net::dhcpv6::stats();
                    if let Some(dns) = s.dns_server {
                        shell_println!("  DNS server: {}", dns);
                    }
                }
                Err(e) => shell_println!("DHCPv6 discovery failed: {:?}", e),
            }
        }
        "info" | "i" => {
            shell_println!("Sending DHCPv6 Information-Request (stateless)...");
            match crate::net::dhcpv6::info_request() {
                Ok(()) => {
                    let s = crate::net::dhcpv6::stats();
                    shell_println!("DHCPv6 info-request successful");
                    if let Some(dns) = s.dns_server {
                        shell_println!("  DNS server: {}", dns);
                    }
                }
                Err(e) => shell_println!("DHCPv6 info-request failed: {:?}", e),
            }
        }
        "status" | "stats" => {
            let s = crate::net::dhcpv6::stats();
            shell_println!("DHCPv6 Client Status");
            shell_println!("  State:              {}", s.state);
            if let Some(addr) = s.address {
                shell_println!("  Address:            {}", addr);
            }
            if let Some(dns) = s.dns_server {
                shell_println!("  DNS server:         {}", dns);
            }
            shell_println!("  Solicits sent:      {}", s.solicits_sent);
            shell_println!("  Requests sent:      {}", s.requests_sent);
            shell_println!("  Info-Requests sent: {}", s.info_requests_sent);
            shell_println!("  Replies received:   {}", s.replies_received);
            shell_println!("  Errors:             {}", s.errors);
        }
        "test" => {
            match crate::net::dhcpv6::self_test() {
                Ok(()) => shell_println!("DHCPv6 self-test: PASSED"),
                Err(e) => shell_println!("DHCPv6 self-test FAILED: {:?}", e),
            }
        }
        _ => {
            shell_println!("dhcpv6 — DHCPv6 client (IPv6 address/config)");
            shell_println!();
            shell_println!("Usage:");
            shell_println!("  dhcpv6 discover    — full stateful address acquisition");
            shell_println!("  dhcpv6 info        — stateless (DNS/domain only)");
            shell_println!("  dhcpv6 status      — show client state and stats");
            shell_println!("  dhcpv6 test        — run self-tests");
        }
    }
}

fn cmd_ping(args: &str) {
    if args.is_empty() {
        crate::console_println!("Usage: ping <ip-address>");
        crate::console_println!("  e.g., ping 10.0.2.2");
        return;
    }

    // Parse IP address or resolve hostname.
    let ip = if let Some(ip) = parse_ipv4(args) {
        ip
    } else {
        // Try DNS resolution.
        match crate::net::dns::resolve(args) {
            Ok(ip) => {
                crate::console_println!("PING {} ({})", args, ip);
                ip
            }
            Err(e) => {
                crate::console_println!("Cannot resolve {}: {:?}", args, e);
                return;
            }
        }
    };

    // Send 4 ICMP echo requests.
    let mut sent = 0u32;
    let mut received = 0u32;
    for i in 0..4u32 {
        match crate::net::icmp::ping(ip) {
            Ok(seq) => {
                sent = sent.saturating_add(1);
                if crate::net::icmp::wait_reply(seq, 2000) {
                    received = received.saturating_add(1);
                    crate::console_println!(
                        "Reply from {}: seq={}", ip, seq
                    );
                } else {
                    crate::console_println!("Request timed out: seq={}", seq);
                }
            }
            Err(e) => {
                crate::console_println!("ping: send failed: {:?}", e);
            }
        }

        // Brief delay between pings (if not the last one).
        if i < 3 {
            for _ in 0..500_000 {
                core::hint::spin_loop();
            }
        }
    }

    crate::console_println!(
        "--- {} ping statistics: {} sent, {} received ---",
        ip, sent, received
    );
}

/// `ping6` — send ICMPv6 Echo Requests to an IPv6 address.
/// `rs` / `rsolicit` — send an IPv6 Router Solicitation to discover routers.
///
/// Triggers SLAAC: if a router responds with a Router Advertisement
/// containing a prefix, the system auto-configures a global IPv6 address.
fn cmd_router_solicitation() {
    crate::console_println!("Sending Router Solicitation (ff02::2)...");
    match crate::net::icmpv6::send_router_solicitation() {
        Ok(()) => {
            // Poll for a bit to collect the RA response.
            for _ in 0..2000 {
                crate::net::poll();
                for _ in 0..10_000 {
                    core::hint::spin_loop();
                }
            }

            if crate::net::icmpv6::ra_received() {
                crate::console_println!("Router Advertisement received.");
                // Show configured addresses.
                let (addrs, count) = crate::net::icmpv6::slaac_addresses();
                if count > 0 {
                    for i in 0..count {
                        if let Some((addr, plen)) = addrs.get(i) {
                            crate::console_println!("  Global: {}/{}", addr, plen);
                        }
                    }
                } else {
                    crate::console_println!("  No prefixes with SLAAC flag.");
                }
                if let Some(rdnss) = crate::net::icmpv6::slaac_rdnss() {
                    crate::console_println!("  DNS:    {}", rdnss);
                }
            } else {
                crate::console_println!("No Router Advertisement received (timeout).");
            }
        }
        Err(e) => {
            crate::console_println!("Failed to send RS: {:?}", e);
        }
    }
}

fn cmd_ping6(args: &str) {
    if args.is_empty() {
        crate::console_println!("Usage: ping6 <ipv6-address>");
        crate::console_println!("  e.g., ping6 fe80::1");
        crate::console_println!("  e.g., ping6 ff02::1  (all nodes link-local)");
        return;
    }

    let dst = match crate::net::ipv6::Ipv6Addr::parse(args) {
        Some(addr) => addr,
        None => {
            crate::console_println!("Invalid IPv6 address: {}", args);
            return;
        }
    };

    crate::console_println!("PING6 {} ...", dst);

    let mut sent = 0u32;
    let mut received = 0u32;
    for i in 0..4u32 {
        match crate::net::icmpv6::ping6(dst) {
            Ok(seq) => {
                sent = sent.saturating_add(1);
                match crate::net::icmpv6::wait_reply_rtt(seq, 2000) {
                    Some(rtt_ns) => {
                        received = received.saturating_add(1);
                        #[allow(clippy::arithmetic_side_effects)]
                        let rtt_us = rtt_ns / 1000;
                        if rtt_us >= 1000 {
                            #[allow(clippy::arithmetic_side_effects)]
                            let rtt_ms = rtt_us / 1000;
                            crate::console_println!(
                                "Reply from {}: seq={} rtt={} ms",
                                dst, seq, rtt_ms
                            );
                        } else {
                            crate::console_println!(
                                "Reply from {}: seq={} rtt={} us",
                                dst, seq, rtt_us
                            );
                        }
                    }
                    None => {
                        crate::console_println!("Request timed out: seq={}", seq);
                    }
                }
            }
            Err(e) => {
                crate::console_println!("ping6: send failed: {:?}", e);
            }
        }

        // Brief delay between pings (if not the last one).
        if i < 3 {
            for _ in 0..500_000 {
                core::hint::spin_loop();
            }
        }
    }

    crate::console_println!(
        "--- {} ping6 statistics: {} sent, {} received ---",
        dst, sent, received
    );
}

/// `udp6` — send and receive UDP datagrams over IPv6.
///
/// Usage:
///   udp6 send <ipv6-addr> <port> <message>   — send a UDP datagram
///   udp6 listen <port> [timeout_ms]           — listen for datagrams
fn cmd_udp6(args: &str) {
    let parts: alloc::vec::Vec<&str> = args.split_whitespace().collect();
    let sub = parts.first().copied().unwrap_or("");

    match sub {
        "send" | "s" => {
            if parts.len() < 4 {
                crate::console_println!("Usage: udp6 send <ipv6-addr> <port> <message...>");
                return;
            }
            let dst = match crate::net::ipv6::Ipv6Addr::parse(parts[1]) {
                Some(addr) => addr,
                None => {
                    crate::console_println!("Invalid IPv6 address: {}", parts[1]);
                    return;
                }
            };
            let port: u16 = match parts[2].parse() {
                Ok(p) => p,
                Err(_) => {
                    crate::console_println!("Invalid port: {}", parts[2]);
                    return;
                }
            };
            // Reconstruct message from remaining parts.
            let msg: alloc::string::String = parts[3..].join(" ");
            let src_port: u16 = 49200; // Use a fixed ephemeral port for simplicity.

            crate::console_println!("Sending {} bytes to [{}]:{} ...", msg.len(), dst, port);
            match crate::net::udp::send_v6(src_port, dst, port, msg.as_bytes()) {
                Ok(()) => crate::console_println!("Sent."),
                Err(e) => crate::console_println!("Send failed: {:?}", e),
            }
        }
        "listen" | "l" => {
            let port: u16 = match parts.get(1).unwrap_or(&"0").parse() {
                Ok(p) if p > 0 => p,
                _ => {
                    crate::console_println!("Usage: udp6 listen <port> [timeout_ms]");
                    return;
                }
            };
            let timeout_ms: u64 = parts.get(2)
                .unwrap_or(&"5000")
                .parse()
                .unwrap_or(5000);

            let handle = match crate::net::udp::bind(crate::netns::ROOT_NS, port) {
                Ok(h) => h,
                Err(e) => {
                    crate::console_println!("Bind port {} failed: {:?}", port, e);
                    return;
                }
            };

            crate::console_println!(
                "Listening on UDP6 port {} for {}ms ...",
                port, timeout_ms
            );

            let start = crate::hrtimer::now_ns();
            #[allow(clippy::arithmetic_side_effects)]
            let deadline = start + timeout_ms * 1_000_000;
            let mut count: u32 = 0;

            loop {
                crate::net::poll();

                // Check for IPv6 datagrams.
                while let Some(dgram) = crate::net::udp::recv_v6(handle) {
                    count = count.saturating_add(1);
                    crate::console_println!(
                        "[{}]:{} → {} bytes",
                        dgram.src_ip, dgram.src_port, dgram.data.len()
                    );
                    // Try to display as text if it looks like UTF-8.
                    if let Ok(text) = core::str::from_utf8(&dgram.data) {
                        crate::console_println!("  \"{}\"", text);
                    } else {
                        // Show first 32 bytes as hex.
                        let show = dgram.data.len().min(32);
                        let hex: alloc::string::String = dgram.data[..show]
                            .iter()
                            .map(|b| alloc::format!("{:02x}", b))
                            .collect::<alloc::vec::Vec<_>>()
                            .join(" ");
                        crate::console_println!("  [{}]", hex);
                    }
                }

                // Also drain IPv4 datagrams so we don't fill that queue.
                while crate::net::udp::recv(handle).is_some() {}

                if crate::hrtimer::now_ns() >= deadline {
                    break;
                }

                for _ in 0..10_000 {
                    core::hint::spin_loop();
                }
            }

            crate::net::udp::close(handle);
            crate::console_println!("Received {} IPv6 datagrams.", count);
        }
        _ => {
            crate::console_println!("Usage:");
            crate::console_println!("  udp6 send <ipv6-addr> <port> <message>");
            crate::console_println!("  udp6 listen <port> [timeout_ms]");
            crate::console_println!();
            crate::console_println!("Examples:");
            crate::console_println!("  udp6 send fe80::1 5000 Hello world");
            crate::console_println!("  udp6 listen 5000 10000");
        }
    }
}

/// `firewall` — manage packet filtering rules.
///
/// Usage:
///   firewall                — show status and rules
///   firewall on|off         — enable/disable firewall
///   firewall policy accept|drop — set default policy
///   firewall allow|deny in|out tcp|udp|icmp|any [port N] [ip A.B.C.D[/N]] [prio N]
///   firewall remove N       — remove rule by index
///   firewall clear          — remove all rules
///   firewall stats          — show packet counters
///   firewall conntrack      — show connection tracking info
#[allow(clippy::too_many_lines)]
fn cmd_firewall(args: &str) {
    use crate::net::firewall;

    let parts: alloc::vec::Vec<&str> = args.split_whitespace().collect();
    let cmd = parts.first().copied().unwrap_or("");

    match cmd {
        "" | "status" => {
            let enabled = firewall::is_enabled();
            let policy = firewall::default_policy();
            let nrules = firewall::rule_count();
            let (allowed, denied) = firewall::stats();
            let ct = firewall::conntrack_count();

            crate::console_println!("=== Firewall (IPv4) ===");
            crate::console_println!("  Status:   {}", if enabled { "ENABLED" } else { "disabled" });
            crate::console_println!("  Policy:   {:?}", policy);
            crate::console_println!("  Rules:    {}", nrules);
            crate::console_println!("  Conntrack: {} entries", ct);
            crate::console_println!("  Allowed:  {}", allowed);
            crate::console_println!("  Denied:   {}", denied);

            let enabled6 = firewall::is_enabled6();
            let policy6 = firewall::default_policy6();
            let nrules6 = firewall::rule6_count();
            let (allowed6, denied6) = firewall::stats6();
            let ct6 = firewall::conntrack6_count();

            crate::console_println!("=== Firewall (IPv6) ===");
            crate::console_println!("  Status:   {}", if enabled6 { "ENABLED" } else { "disabled" });
            crate::console_println!("  Policy:   {:?}", policy6);
            crate::console_println!("  Rules:    {}", nrules6);
            crate::console_println!("  Conntrack: {} entries", ct6);
            crate::console_println!("  Allowed:  {}", allowed6);
            crate::console_println!("  Denied:   {}", denied6);
        }
        "on" | "enable" => firewall::enable(),
        "off" | "disable" => firewall::disable(),
        "on6" | "enable6" => firewall::enable6(),
        "off6" | "disable6" => firewall::disable6(),
        "policy" => {
            match parts.get(1).copied() {
                Some("accept") => firewall::set_default_policy(firewall::DefaultPolicy::Accept),
                Some("drop") => firewall::set_default_policy(firewall::DefaultPolicy::Drop),
                _ => crate::console_println!("Usage: firewall policy accept|drop"),
            }
        }
        "policy6" => {
            match parts.get(1).copied() {
                Some("accept") => firewall::set_default_policy6(firewall::DefaultPolicy::Accept),
                Some("drop") => firewall::set_default_policy6(firewall::DefaultPolicy::Drop),
                _ => crate::console_println!("Usage: firewall policy6 accept|drop"),
            }
        }
        "allow" | "deny" => {
            // Parse: allow|deny in|out|both tcp|udp|icmp|any [port N] [ip A.B.C.D[/N]] [prio N]
            let action = if cmd == "allow" {
                firewall::Action::Allow
            } else {
                firewall::Action::Deny
            };

            let direction = match parts.get(1).copied() {
                Some("in") => firewall::Direction::In,
                Some("out") => firewall::Direction::Out,
                Some("both") => firewall::Direction::Both,
                _ => {
                    crate::console_println!("Usage: firewall {} in|out|both tcp|udp|icmp|any [port N] [ip A.B.C.D[/N]] [prio N]", cmd);
                    return;
                }
            };

            let protocol = match parts.get(2).copied() {
                Some("tcp") => firewall::Protocol::Tcp,
                Some("udp") => firewall::Protocol::Udp,
                Some("icmp") => firewall::Protocol::Icmp,
                Some("any") | Some("all") => firewall::Protocol::Any,
                _ => {
                    crate::console_println!("Usage: firewall {} in|out|both tcp|udp|icmp|any [port N] [ip A.B.C.D[/N]] [prio N]", cmd);
                    return;
                }
            };

            // Parse optional modifiers.
            let mut dst_port: u16 = 0;
            let mut src_ip = crate::net::interface::Ipv4Addr::UNSPECIFIED;
            let mut src_prefix: u8 = 0;
            let mut priority: u16 = 100;

            let mut i = 3;
            while i < parts.len() {
                match parts[i] {
                    "port" => {
                        if let Some(p) = parts.get(i + 1) {
                            if let Ok(port) = p.parse::<u16>() {
                                dst_port = port;
                            }
                        }
                        i += 2;
                    }
                    "ip" => {
                        if let Some(ip_str) = parts.get(i + 1) {
                            // Parse IP[/prefix].
                            if let Some((ip_part, prefix_part)) = ip_str.split_once('/') {
                                if let Some(ip) = parse_ipv4(ip_part) {
                                    src_ip = ip;
                                    src_prefix = prefix_part.parse::<u8>().unwrap_or(32);
                                }
                            } else if let Some(ip) = parse_ipv4(ip_str) {
                                src_ip = ip;
                                src_prefix = 32;
                            }
                        }
                        i += 2;
                    }
                    "prio" | "priority" => {
                        if let Some(p) = parts.get(i + 1) {
                            priority = p.parse::<u16>().unwrap_or(100);
                        }
                        i += 2;
                    }
                    _ => { i += 1; }
                }
            }

            let rule = firewall::Rule {
                active: true,
                direction,
                action,
                protocol,
                src_ip,
                src_prefix,
                dst_port,
                priority,
                match_count: 0,
            };

            match firewall::add_rule(rule) {
                Ok(idx) => crate::console_println!("Rule {} added", idx),
                Err(e) => crate::console_println!("Error: {:?}", e),
            }
        }
        "allow6" | "deny6" => {
            // Parse: allow6|deny6 in|out|both tcp|udp|icmp|any [port N] [ip ADDR[/N]] [prio N]
            use crate::net::ipv6::Ipv6Addr;

            let action = if cmd == "allow6" {
                firewall::Action::Allow
            } else {
                firewall::Action::Deny
            };

            let direction = match parts.get(1).copied() {
                Some("in") => firewall::Direction::In,
                Some("out") => firewall::Direction::Out,
                Some("both") => firewall::Direction::Both,
                _ => {
                    crate::console_println!("Usage: fw {} in|out|both tcp|udp|icmp|any [port N] [ip ADDR[/N]] [prio N]", cmd);
                    return;
                }
            };

            let protocol = match parts.get(2).copied() {
                Some("tcp") => firewall::Protocol::Tcp,
                Some("udp") => firewall::Protocol::Udp,
                Some("icmp") | Some("icmpv6") => firewall::Protocol::Icmp,
                Some("any") | Some("all") => firewall::Protocol::Any,
                _ => {
                    crate::console_println!("Usage: fw {} in|out|both tcp|udp|icmp|any [port N] [ip ADDR[/N]] [prio N]", cmd);
                    return;
                }
            };

            let mut dst_port: u16 = 0;
            let mut src_ip = Ipv6Addr::UNSPECIFIED;
            let mut src_prefix: u8 = 0;
            let mut priority: u16 = 100;

            let mut i = 3;
            while i < parts.len() {
                match parts[i] {
                    "port" => {
                        if let Some(p) = parts.get(i + 1) {
                            if let Ok(port) = p.parse::<u16>() {
                                dst_port = port;
                            }
                        }
                        i += 2;
                    }
                    "ip" => {
                        if let Some(ip_str) = parts.get(i + 1) {
                            if let Some((ip_part, prefix_part)) = ip_str.split_once('/') {
                                if let Some(ip) = Ipv6Addr::parse(ip_part) {
                                    src_ip = ip;
                                    src_prefix = prefix_part.parse::<u8>().unwrap_or(128);
                                }
                            } else if let Some(ip) = Ipv6Addr::parse(ip_str) {
                                src_ip = ip;
                                src_prefix = 128;
                            }
                        }
                        i += 2;
                    }
                    "prio" | "priority" => {
                        if let Some(p) = parts.get(i + 1) {
                            priority = p.parse::<u16>().unwrap_or(100);
                        }
                        i += 2;
                    }
                    _ => { i += 1; }
                }
            }

            let rule = firewall::Rule6 {
                active: true,
                direction,
                action,
                protocol,
                src_ip,
                src_prefix,
                dst_port,
                priority,
                match_count: 0,
            };

            match firewall::add_rule6(rule) {
                Ok(idx) => crate::console_println!("IPv6 rule {} added", idx),
                Err(e) => crate::console_println!("Error: {:?}", e),
            }
        }
        "remove" | "rm" | "del" => {
            if let Some(idx_str) = parts.get(1) {
                if let Ok(idx) = idx_str.parse::<usize>() {
                    match firewall::remove_rule(idx) {
                        Ok(()) => crate::console_println!("Rule {} removed", idx),
                        Err(e) => crate::console_println!("Error: {:?}", e),
                    }
                } else {
                    crate::console_println!("Usage: firewall remove <index>");
                }
            } else {
                crate::console_println!("Usage: firewall remove <index>");
            }
        }
        "remove6" | "rm6" | "del6" => {
            if let Some(idx_str) = parts.get(1) {
                if let Ok(idx) = idx_str.parse::<usize>() {
                    match firewall::remove_rule6(idx) {
                        Ok(()) => crate::console_println!("IPv6 rule {} removed", idx),
                        Err(e) => crate::console_println!("Error: {:?}", e),
                    }
                } else {
                    crate::console_println!("Usage: firewall remove6 <index>");
                }
            } else {
                crate::console_println!("Usage: firewall remove6 <index>");
            }
        }
        "clear" | "flush" => {
            firewall::clear_rules();
            crate::console_println!("All IPv4 rules cleared");
        }
        "clear6" | "flush6" => {
            firewall::clear_rules6();
            crate::console_println!("All IPv6 rules cleared");
        }
        "stats" => {
            let (allowed, denied) = firewall::stats();
            crate::console_println!("IPv4 — Allowed: {}  Denied: {}", allowed, denied);
            let (allowed6, denied6) = firewall::stats6();
            crate::console_println!("IPv6 — Allowed: {}  Denied: {}", allowed6, denied6);
        }
        "rules" | "list" | "ls" => {
            let (rule_stats, count) = firewall::rule_stats();
            if count == 0 {
                crate::console_println!("No IPv4 rules configured");
            } else {
                crate::console_println!("=== IPv4 Firewall Rules ({}) ===", count);
                crate::console_println!("{:<4} {:<6} {:<5} {:<6} {:<20} {:<6} {:<6} {}",
                    "Idx", "Action", "Dir", "Proto", "Source", "Port", "Prio", "Matches");
                for rs in rule_stats.iter().take(count) {
                    let src = core::str::from_utf8(&rs.source[..rs.source_len as usize])
                        .unwrap_or("?");
                    let port_str = if rs.dst_port == 0 {
                        alloc::string::String::from("any")
                    } else {
                        alloc::format!("{}", rs.dst_port)
                    };
                    crate::console_println!("{:<4} {:<6} {:<5} {:<6} {:<20} {:<6} {:<6} {}",
                        rs.index, rs.action, rs.direction, rs.protocol,
                        src, port_str, rs.priority, rs.matches);
                }
            }
        }
        "rules6" | "list6" | "ls6" => {
            let (rule_stats, count) = firewall::rule6_stats();
            if count == 0 {
                crate::console_println!("No IPv6 rules configured");
            } else {
                crate::console_println!("=== IPv6 Firewall Rules ({}) ===", count);
                crate::console_println!("{:<4} {:<6} {:<5} {:<8} {:<42} {:<6} {:<6} {}",
                    "Idx", "Action", "Dir", "Proto", "Source", "Port", "Prio", "Matches");
                for rs in rule_stats.iter().take(count) {
                    let src = core::str::from_utf8(&rs.source[..rs.source_len as usize])
                        .unwrap_or("?");
                    let port_str = if rs.dst_port == 0 {
                        alloc::string::String::from("any")
                    } else {
                        alloc::format!("{}", rs.dst_port)
                    };
                    // For IPv6 rules, "icmp" actually means "icmpv6".
                    let proto = if rs.protocol == firewall::Protocol::Icmp {
                        "icmpv6"
                    } else {
                        match rs.protocol {
                            firewall::Protocol::Any => "any",
                            firewall::Protocol::Tcp => "tcp",
                            firewall::Protocol::Udp => "udp",
                            firewall::Protocol::Icmp => "icmpv6",
                        }
                    };
                    crate::console_println!("{:<4} {:<6} {:<5} {:<8} {:<42} {:<6} {:<6} {}",
                        rs.index, rs.action, rs.direction, proto,
                        src, port_str, rs.priority, rs.matches);
                }
            }
        }
        "conntrack" | "ct" => {
            let count = firewall::conntrack_count();
            let count6 = firewall::conntrack6_count();
            crate::console_println!("Connection tracking: {} IPv4, {} IPv6 active entries", count, count6);
        }
        "reset" => {
            firewall::reset_stats();
            firewall::clear_conntrack();
            firewall::reset_stats6();
            firewall::clear_conntrack6();
            crate::console_println!("Stats and conntrack reset (IPv4 + IPv6)");
        }
        _ => {
            crate::console_println!("Usage: fw [on|off|on6|off6|policy|policy6|allow|deny|allow6|deny6|");
            crate::console_println!("          remove|remove6|clear|clear6|rules|rules6|stats|conntrack|reset]");
        }
    }
}

/// `capgroups` — manage named capability groups.
///
/// Usage:
///   capgroups             — list all groups
///   capgroups info NAME   — show details for a group
///   capgroups create NAME — create a new group
///   capgroups remove NAME — remove a group (not built-ins)
fn cmd_cap_groups(args: &str) {
    use crate::cap::groups;

    let parts: alloc::vec::Vec<&str> = args.split_whitespace().collect();
    let cmd = parts.first().copied().unwrap_or("");

    match cmd {
        "" | "list" | "ls" => {
            let all = groups::list();
            crate::console_println!("=== Capability Groups ({}) ===", all.len());
            crate::console_println!("{:<5} {:<15} {:<6} {:<8} {}",
                "ID", "Name", "Caps", "Members", "Type");
            for (id, name, caps, members, builtin) in &all {
                let kind = if *builtin { "built-in" } else { "custom" };
                crate::console_println!("{:<5} {:<15} {:<6} {:<8} {}",
                    id, name, caps, members, kind);
            }
        }
        "create" | "add" => {
            if let Some(name) = parts.get(1) {
                match groups::create(name) {
                    Ok(id) => crate::console_println!("Group '{}' created (id={})", name, id),
                    Err(e) => crate::console_println!("Error: {:?}", e),
                }
            } else {
                crate::console_println!("Usage: capgroups create <name>");
            }
        }
        "remove" | "rm" | "del" => {
            if let Some(name) = parts.get(1) {
                if let Some(id) = groups::find_by_name(name) {
                    match groups::remove(id) {
                        Ok(()) => crate::console_println!("Group '{}' removed", name),
                        Err(e) => crate::console_println!("Error: {:?}", e),
                    }
                } else {
                    crate::console_println!("Group '{}' not found", name);
                }
            } else {
                crate::console_println!("Usage: capgroups remove <name>");
            }
        }
        _ => {
            crate::console_println!("Usage: capgroups [list|create|remove]");
        }
    }
}

/// `captags` — manage file/directory capability tags.
///
/// Usage:
///   captags                    — list all tagged paths
///   captags show PATH          — show tags on a path (including inherited)
///   captags add PATH GROUP     — tag a path with a capability group
///   captags remove PATH GROUP  — remove a tag from a path
///   captags clear PATH         — remove all tags from a path
///   captags check PATH UID GID — test access for a uid/gid combo
fn cmd_cap_tags(args: &str) {
    use crate::cap::file_tags;
    use crate::cap::groups;

    let parts: alloc::vec::Vec<&str> = args.split_whitespace().collect();
    let cmd = parts.first().copied().unwrap_or("");

    match cmd {
        "" | "list" | "ls" => {
            let all = file_tags::list_all();
            if all.is_empty() {
                crate::console_println!("No file capability tags set.");
                return;
            }
            crate::console_println!("=== File Capability Tags ({}) ===", all.len());
            for (path, group_ids) in &all {
                let names: alloc::vec::Vec<alloc::string::String> = group_ids.iter().map(|&id| {
                    // Try to get group name.
                    let all_groups = groups::list();
                    all_groups.iter()
                        .find(|(gid, _, _, _, _)| *gid == id)
                        .map(|(_, name, _, _, _)| name.clone())
                        .unwrap_or_else(|| alloc::format!("id={}", id))
                }).collect();
                crate::console_println!("  {} → [{}]", path, names.join(", "));
            }
        }
        "show" => {
            if let Some(path) = parts.get(1) {
                let direct = file_tags::get_tags(path);
                let effective = file_tags::effective_tags(path);
                let all_groups = groups::list();

                let name_for = |id: u32| -> alloc::string::String {
                    all_groups.iter()
                        .find(|(gid, _, _, _, _)| *gid == id)
                        .map(|(_, name, _, _, _)| name.clone())
                        .unwrap_or_else(|| alloc::format!("id={}", id))
                };

                crate::console_println!("Path: {}", path);
                if direct.is_empty() {
                    crate::console_println!("  Direct tags: (none)");
                } else {
                    let names: alloc::vec::Vec<_> = direct.iter().map(|&id| name_for(id)).collect();
                    crate::console_println!("  Direct tags: [{}]", names.join(", "));
                }
                if effective.is_empty() {
                    crate::console_println!("  Effective tags (incl. inherited): (none)");
                } else {
                    let names: alloc::vec::Vec<_> = effective.iter().map(|&id| name_for(id)).collect();
                    crate::console_println!("  Effective tags (incl. inherited): [{}]", names.join(", "));
                }
            } else {
                crate::console_println!("Usage: captags show <path>");
            }
        }
        "add" | "tag" => {
            if parts.len() >= 3 {
                let path = parts[1];
                let group_name = parts[2];
                if let Some(group_id) = groups::find_by_name(group_name) {
                    match file_tags::tag_path(path, group_id) {
                        Ok(()) => crate::console_println!("Tagged '{}' with group '{}'", path, group_name),
                        Err(e) => crate::console_println!("Error: {:?}", e),
                    }
                } else {
                    crate::console_println!("Group '{}' not found", group_name);
                }
            } else {
                crate::console_println!("Usage: captags add <path> <group_name>");
            }
        }
        "remove" | "rm" | "untag" => {
            if parts.len() >= 3 {
                let path = parts[1];
                let group_name = parts[2];
                if let Some(group_id) = groups::find_by_name(group_name) {
                    match file_tags::untag_path(path, group_id) {
                        Ok(()) => crate::console_println!("Removed '{}' tag from '{}'", group_name, path),
                        Err(e) => crate::console_println!("Error: {:?}", e),
                    }
                } else {
                    crate::console_println!("Group '{}' not found", group_name);
                }
            } else {
                crate::console_println!("Usage: captags remove <path> <group_name>");
            }
        }
        "clear" => {
            if let Some(path) = parts.get(1) {
                match file_tags::clear_tags(path) {
                    Ok(()) => crate::console_println!("All tags cleared from '{}'", path),
                    Err(e) => crate::console_println!("Error: {:?}", e),
                }
            } else {
                crate::console_println!("Usage: captags clear <path>");
            }
        }
        "check" => {
            // captags check <path> <uid> <gid>
            if parts.len() >= 4 {
                let path = parts[1];
                let uid: u32 = parts[2].parse().unwrap_or(u32::MAX);
                let gid: u32 = parts[3].parse().unwrap_or(u32::MAX);
                if uid == u32::MAX || gid == u32::MAX {
                    crate::console_println!("Usage: captags check <path> <uid> <gid>");
                    return;
                }
                match file_tags::check_access(uid, gid, &[], path) {
                    Ok(()) => crate::console_println!("ACCESS ALLOWED for uid={} gid={} on '{}'", uid, gid, path),
                    Err(_) => crate::console_println!("ACCESS DENIED for uid={} gid={} on '{}'", uid, gid, path),
                }
            } else {
                crate::console_println!("Usage: captags check <path> <uid> <gid>");
            }
        }
        _ => {
            crate::console_println!("Usage: captags [list|show|add|remove|clear|check]");
        }
    }
}

/// `sockact` — manage socket activation entries.
///
/// Usage:
///   sockact                     — list all socket activations
///   sockact add NAME PATH       — register socket activation
///   sockact remove NAME         — remove socket activation
///   sockact reset NAME          — reset failed service to idle
fn cmd_socket_activation(args: &str) {
    use crate::ipc::service;

    let parts: alloc::vec::Vec<&str> = args.split_whitespace().collect();
    let cmd = parts.first().copied().unwrap_or("");

    match cmd {
        "" | "list" | "ls" => {
            let all = service::list_socket_activations();
            if all.is_empty() {
                crate::console_println!("No socket activations configured.");
                return;
            }
            crate::console_println!("=== Socket Activations ({}) ===", all.len());
            crate::console_println!("{:<25} {:<25} {:<10} {:<6} {}",
                "Service", "Spawn Path", "Status", "Starts", "Queued");
            for (name, path, status, starts, queued) in &all {
                let status_str = match status {
                    service::ActivationStatus::Idle => "idle",
                    service::ActivationStatus::Starting => "starting",
                    service::ActivationStatus::Running => "running",
                    service::ActivationStatus::Failed => "FAILED",
                };
                crate::console_println!("{:<25} {:<25} {:<10} {:<6} {}",
                    name, path, status_str, starts, queued);
            }
        }
        "add" | "register" => {
            if parts.len() >= 3 {
                let name = parts[1];
                let path = parts[2];
                match service::register_socket_activation(name.as_bytes(), path) {
                    Ok(()) => crate::console_println!("Socket activation registered: {} → {}", name, path),
                    Err(e) => crate::console_println!("Error: {:?}", e),
                }
            } else {
                crate::console_println!("Usage: sockact add <service_name> <spawn_path>");
            }
        }
        "remove" | "rm" | "del" => {
            if let Some(name) = parts.get(1) {
                match service::unregister_socket_activation(name.as_bytes()) {
                    Ok(()) => crate::console_println!("Socket activation removed: {}", name),
                    Err(e) => crate::console_println!("Error: {:?}", e),
                }
            } else {
                crate::console_println!("Usage: sockact remove <service_name>");
            }
        }
        "reset" => {
            if let Some(name) = parts.get(1) {
                match service::reset_activation(name.as_bytes()) {
                    Ok(()) => crate::console_println!("Activation reset: {}", name),
                    Err(e) => crate::console_println!("Error: {:?}", e),
                }
            } else {
                crate::console_println!("Usage: sockact reset <service_name>");
            }
        }
        _ => {
            crate::console_println!("Usage: sockact [list|add|remove|reset]");
        }
    }
}

/// `slimit` — manage per-service resource limits.
///
/// Usage:
///   slimit                                  — list all service limits
///   slimit show NAME                        — show limits for a service
///   slimit set NAME rss=N cpu=N thr=N hdl=N — set custom limits
///   slimit profile NAME daemon|network|system|sandbox — apply preset
///   slimit remove NAME                      — remove limits for a service
fn cmd_service_limits(args: &str) {
    use crate::ipc::service_limits;

    let parts: alloc::vec::Vec<&str> = args.split_whitespace().collect();
    let cmd = parts.first().copied().unwrap_or("");

    match cmd {
        "" | "list" | "ls" => {
            let all = service_limits::list_all();
            if all.is_empty() {
                crate::console_println!("No service limits configured.");
                return;
            }
            crate::console_println!("=== Service Resource Limits ({}) ===", all.len());
            crate::console_println!("{:<25} {:<12} {:<8} {:<10} {}",
                "Service", "RSS", "CPU", "Threads", "Handles");
            for (name, limits) in &all {
                let rss = if limits.max_rss_frames == 0 {
                    alloc::string::String::from("unlimited")
                } else {
                    alloc::format!("{} fr", limits.max_rss_frames)
                };
                let cpu = if limits.cpu_quota_pct == 0 {
                    alloc::string::String::from("unlimited")
                } else {
                    alloc::format!("{}%", limits.cpu_quota_pct)
                };
                let thr = if limits.max_threads == 0 {
                    alloc::string::String::from("unlimited")
                } else {
                    alloc::format!("{}", limits.max_threads)
                };
                let hdl = if limits.max_handles == 0 {
                    alloc::string::String::from("unlimited")
                } else {
                    alloc::format!("{}", limits.max_handles)
                };
                crate::console_println!("{:<25} {:<12} {:<8} {:<10} {}",
                    name, rss, cpu, thr, hdl);
            }
        }
        "show" => {
            if let Some(name) = parts.get(1) {
                match service_limits::get_service_limits(name) {
                    Some(limits) => {
                        crate::console_println!("Service: {}", name);
                        crate::console_println!("  {}", limits);
                    }
                    None => crate::console_println!("No limits configured for '{}'", name),
                }
            } else {
                crate::console_println!("Usage: slimit show <service_name>");
            }
        }
        "set" => {
            // slimit set NAME rss=N cpu=N thr=N hdl=N
            if parts.len() < 3 {
                crate::console_println!("Usage: slimit set <name> rss=N cpu=N thr=N hdl=N");
                return;
            }
            let name = parts[1];
            let mut limits = service_limits::get_service_limits(name)
                .unwrap_or_default();

            for &param in &parts[2..] {
                if let Some(val) = param.strip_prefix("rss=") {
                    limits.max_rss_frames = val.parse().unwrap_or(0);
                } else if let Some(val) = param.strip_prefix("cpu=") {
                    limits.cpu_quota_pct = val.parse().unwrap_or(0);
                } else if let Some(val) = param.strip_prefix("thr=") {
                    limits.max_threads = val.parse().unwrap_or(0);
                } else if let Some(val) = param.strip_prefix("hdl=") {
                    limits.max_handles = val.parse().unwrap_or(0);
                } else {
                    crate::console_println!("Unknown parameter: {} (use rss=, cpu=, thr=, hdl=)", param);
                    return;
                }
            }

            match service_limits::set_service_limits(name, limits) {
                Ok(()) => crate::console_println!("Limits set for '{}': {}", name, limits),
                Err(e) => crate::console_println!("Error: {:?}", e),
            }
        }
        "profile" => {
            if parts.len() >= 3 {
                let name = parts[1];
                let profile = match parts[2] {
                    "daemon" | "d" => service_limits::ServiceProfile::Daemon,
                    "network" | "net" | "n" => service_limits::ServiceProfile::NetworkService,
                    "system" | "sys" | "s" => service_limits::ServiceProfile::SystemService,
                    "sandbox" | "sand" | "x" => service_limits::ServiceProfile::Sandboxed,
                    _ => {
                        crate::console_println!("Unknown profile: {} (daemon|network|system|sandbox)", parts[2]);
                        return;
                    }
                };
                match service_limits::apply_profile(name, profile) {
                    Ok(()) => crate::console_println!("Profile {:?} applied to '{}'", profile, name),
                    Err(e) => crate::console_println!("Error: {:?}", e),
                }
            } else {
                crate::console_println!("Usage: slimit profile <name> <daemon|network|system|sandbox>");
            }
        }
        "remove" | "rm" | "del" => {
            if let Some(name) = parts.get(1) {
                match service_limits::remove_service_limits(name) {
                    Ok(()) => crate::console_println!("Limits removed for '{}'", name),
                    Err(e) => crate::console_println!("Error: {:?}", e),
                }
            } else {
                crate::console_println!("Usage: slimit remove <service_name>");
            }
        }
        _ => {
            crate::console_println!("Usage: slimit [list|show|set|profile|remove]");
        }
    }
}

/// Parse a simple URL: "http://host/path" or just "host/path" or "host".
/// Returns (host, port, path).
fn parse_url(url: &str) -> Option<(&str, u16, &str)> {
    let url = url.strip_prefix("http://").unwrap_or(url);

    // Split host and path.
    let (host_port, path) = match url.find('/') {
        Some(i) => (&url[..i], &url[i..]),
        None => (url, "/"),
    };

    // Split host and port.
    let (host, port) = match host_port.rfind(':') {
        Some(i) => {
            let port_str = &host_port[i + 1..];
            match port_str.parse::<u16>() {
                Ok(p) => (&host_port[..i], p),
                Err(_) => (host_port, 80),
            }
        }
        None => (host_port, 80),
    };

    if host.is_empty() {
        return None;
    }
    Some((host, port, path))
}

// String formatting uses small bounded values.
#[allow(clippy::arithmetic_side_effects)]
fn cmd_wget(args: &str) {
    if args.is_empty() {
        crate::console_println!("Usage: wget <url>");
        crate::console_println!("  e.g., wget http://example.com/");
        crate::console_println!("  e.g., wget https://secure.example.com/");
        return;
    }

    // HTTPS URLs: use the HTTP module (has TLS 1.3 support).
    if args.starts_with("https://") {
        crate::console_println!("Fetching (HTTPS) {}...", args);
        match crate::net::http::get(args) {
            Ok(resp) => {
                crate::console_println!("--- Response (HTTP {}) ---", resp.status_code);
                let text = resp.body_text();
                if text.is_empty() {
                    crate::console_println!("(empty body, {} bytes raw)", resp.body.len());
                } else {
                    crate::console_print!("{}", text);
                }
                crate::console_println!("\n--- End ({} bytes) ---", resp.body.len());
            }
            Err(e) => crate::console_println!("HTTPS request failed: {:?}", e),
        }
        return;
    }

    let Some((host, port, path)) = parse_url(args) else {
        crate::console_println!("Invalid URL: {}", args);
        return;
    };

    crate::console_println!("Resolving {}...", host);

    // Resolve hostname to IP.
    let ip = if let Some(ip) = parse_ipv4(host) {
        ip
    } else {
        match crate::net::dns::resolve(host) {
            Ok(ip) => ip,
            Err(e) => {
                crate::console_println!("DNS resolution failed: {:?}", e);
                return;
            }
        }
    };

    crate::console_println!("Connecting to {}:{}...", ip, port);

    // Open TCP connection.
    let conn = match crate::net::tcp::connect(crate::netns::ROOT_NS, ip.into(), port) {
        Ok(c) => c,
        Err(e) => {
            crate::console_println!("Connection failed: {:?}", e);
            return;
        }
    };

    // Build HTTP request.
    let request = alloc::format!(
        "GET {} HTTP/1.0\r\nHost: {}\r\nConnection: close\r\n\r\n",
        path, host
    );

    crate::console_println!("Sending HTTP request...");

    if let Err(e) = crate::net::tcp::send(conn, request.as_bytes()) {
        crate::console_println!("Send failed: {:?}", e);
        let _ = crate::net::tcp::close(conn);
        return;
    }

    // Read response.
    crate::console_println!("--- Response ---");

    let mut total = 0usize;
    while let Ok(data) = crate::net::tcp::read_blocking(conn, 3000, 4096) {
        if data.is_empty() {
            // Check if connection closed.
            if crate::net::tcp::is_remote_closed(conn) {
                break;
            }
            // No data yet — try again briefly.
            continue;
        }
        total = total.saturating_add(data.len());
        // Print as text.
        match core::str::from_utf8(&data) {
            Ok(text) => crate::console_print!("{}", text),
            Err(_) => crate::console_print!("(binary: {} bytes)", data.len()),
        }
    }

    crate::console_println!("\n--- End ({} bytes received) ---", total);
    let _ = crate::net::tcp::close(conn);
}

fn cmd_dns(args: &str) {
    if args.is_empty() {
        crate::console_println!("Usage: dns <domain-name>");
        crate::console_println!("       dns -6 <domain-name>   (AAAA / IPv6)");
        crate::console_println!("  e.g., dns example.com");
        return;
    }

    // Check for -6 flag for AAAA query.
    let (query_ipv6, name) = if args.starts_with("-6 ") || args.starts_with("-6\t") {
        (true, args[3..].trim())
    } else if args == "-6" {
        crate::console_println!("Usage: dns -6 <domain-name>");
        return;
    } else {
        (false, args.trim())
    };

    if name.is_empty() {
        crate::console_println!("Usage: dns <domain-name>");
        return;
    }

    if query_ipv6 {
        crate::console_println!("Resolving {} (AAAA)...", name);
        match crate::net::dns::resolve6(name) {
            Ok(ip) => {
                crate::console_println!("{} -> {}", name, ip);
            }
            Err(e) => {
                crate::console_println!("AAAA resolution failed: {:?}", e);
            }
        }
    } else {
        crate::console_println!("Resolving {}...", name);
        match crate::net::dns::resolve(name) {
            Ok(ip) => {
                crate::console_println!("{} -> {}", name, ip);
            }
            Err(e) => {
                crate::console_println!("DNS resolution failed: {:?}", e);
            }
        }
    }
}

/// Parse an IPv4 address from a dotted-quad string.
fn parse_ipv4(s: &str) -> Option<crate::net::interface::Ipv4Addr> {
    let mut parts = s.split('.');
    let a = parts.next()?.parse::<u8>().ok()?;
    let b = parts.next()?.parse::<u8>().ok()?;
    let c = parts.next()?.parse::<u8>().ok()?;
    let d = parts.next()?.parse::<u8>().ok()?;
    // Reject trailing parts.
    if parts.next().is_some() {
        return None;
    }
    Some(crate::net::interface::Ipv4Addr::new(a, b, c, d))
}

/// Parse an IPv4 address from a dotted-quad string into raw octets.
/// Returns `[a, b, c, d]` on success, suitable for container config fields.
fn parse_ipv4_octets(s: &str) -> Option<[u8; 4]> {
    let ip = parse_ipv4(s)?;
    Some(ip.0)
}

fn cmd_irq() {
    crate::console_println!("IRQ interrupt counts:");
    let mut any = false;
    for i in 0..24u32 {
        let count = crate::ioapic::irq_consume(i);
        if count > 0 {
            crate::console_println!("  IRQ {:2}: {} interrupts", i, count);
            any = true;
        }
    }
    // Also show the total pending (peek without consume) for reference.
    if !any {
        crate::console_println!("  (no IRQ activity recorded)");
    }
}

fn cmd_reboot() {
    let caps = crate::power::capabilities();
    crate::console_println!("Rebooting...");
    if caps.acpi_reboot {
        crate::console_println!("  Using ACPI reset register.");
    }
    crate::power::reboot();
}

/// `iommu` — display IOMMU detection and DMA remapping status.
fn cmd_iommu() {
    use crate::iommu;

    crate::console_println!("=== IOMMU Status ===");
    crate::console_println!("{}", iommu::status_summary());

    if !iommu::is_available() {
        crate::console_println!();
        crate::console_println!("TIP: Enable Intel VT-d or AMD-Vi in BIOS/UEFI");
        return;
    }

    let units = iommu::unit_count();
    crate::console_println!();
    crate::console_println!("Hardware units:");
    for i in 0..units as usize {
        if let Some(unit) = iommu::get_unit(i) {
            crate::console_println!(
                "  Unit {}: base={:#x} seg={} include_all={}",
                i, unit.register_base, unit.segment, unit.include_all
            );
        }
    }

    // DMA remapping status.
    crate::console_println!();
    let remap = crate::iommu_remap::stats();
    crate::console_println!("DMA Remapping:");
    crate::console_println!("  status:          {}",
        if remap.active { "enabled" } else { "disabled" });
    crate::console_println!("  active domains:  {}", remap.active_domains);
    crate::console_println!("  mapped pages:    {}", remap.total_mapped_pages);
    crate::console_println!("  DMA faults:      {}", remap.total_faults);
}

/// `cgroup` — manage resource control groups.
///
/// Usage:
///   cgroup              — list all active cgroups
///   cgroup create [P]   — create child of parent P (default: 0/root)
///   cgroup delete ID    — delete an empty cgroup
///   cgroup cpu ID PCT   — set CPU limit (percent, 0=unlimited)
///   cgroup mem ID N     — set memory limit (frames, 0=unlimited)
///   cgroup stats ID     — show detailed stats
///   cgroup test         — run self-test
fn cmd_cgroup(args: &str) {
    use crate::cgroup;

    let parts: alloc::vec::Vec<&str> = args.split_whitespace().collect();
    let cmd = parts.first().copied().unwrap_or("");

    match cmd {
        "" | "list" | "ls" => {
            let count = cgroup::active_count();
            crate::console_println!("=== Resource Control Groups ({} active) ===", count);
            crate::console_println!(
                "{:<5} {:<7} {:<7} {:<8} {:<12} {:<12} {:<12}",
                "ID", "Parent", "Tasks", "Children", "CPU quota", "CPU used", "Mem(frames)"
            );
            for id in 0..cgroup::MAX_CGROUPS as u32 {
                if let Some(s) = cgroup::stats(id) {
                    let cpu_q = if s.cpu_quota == 0 {
                        "unlimited".to_string()
                    } else {
                        alloc::format!("{}/{}", s.cpu_quota, s.cpu_period)
                    };
                    let mem = if s.mem_limit == 0 {
                        "unlimited".to_string()
                    } else {
                        alloc::format!("{}/{}", s.mem_usage, s.mem_limit)
                    };
                    let parent = if s.parent == u32::MAX {
                        "-".to_string()
                    } else {
                        alloc::format!("{}", s.parent)
                    };
                    crate::console_println!(
                        "{:<5} {:<7} {:<7} {:<8} {:<12} {:<12} {:<12}",
                        id, parent, s.nr_tasks, s.nr_children,
                        cpu_q, s.cpu_used, mem
                    );
                }
            }
        }
        "create" => {
            let parent: u32 = parts.get(1)
                .and_then(|s| s.parse().ok())
                .unwrap_or(0);
            match cgroup::create(parent) {
                Ok(id) => crate::console_println!("Created cgroup {} (parent: {})", id, parent),
                Err(e) => crate::console_println!("Error: {:?}", e),
            }
        }
        "delete" | "del" | "rm" => {
            let Some(id_str) = parts.get(1) else {
                crate::console_println!("Usage: cgroup delete <id>");
                return;
            };
            let Ok(id) = id_str.parse::<u32>() else {
                crate::console_println!("Invalid cgroup ID");
                return;
            };
            match cgroup::delete(id) {
                Ok(()) => crate::console_println!("Deleted cgroup {}", id),
                Err(e) => crate::console_println!("Error: {:?}", e),
            }
        }
        "cpu" => {
            let Some(id_str) = parts.get(1) else {
                crate::console_println!("Usage: cgroup cpu <id> <percent>");
                return;
            };
            let Some(pct_str) = parts.get(2) else {
                crate::console_println!("Usage: cgroup cpu <id> <percent>");
                return;
            };
            let Ok(id) = id_str.parse::<u32>() else {
                crate::console_println!("Invalid cgroup ID");
                return;
            };
            let Ok(pct) = pct_str.parse::<u64>() else {
                crate::console_println!("Invalid percentage");
                return;
            };
            let limit = cgroup::CpuLimit::from_percent(pct);
            match cgroup::set_cpu_limit(id, limit) {
                Ok(()) => {
                    if pct == 0 {
                        crate::console_println!("Cgroup {}: CPU limit removed (unlimited)", id);
                    } else {
                        crate::console_println!("Cgroup {}: CPU limit set to {}%", id, pct);
                    }
                }
                Err(e) => crate::console_println!("Error: {:?}", e),
            }
        }
        "mem" | "memory" => {
            let Some(id_str) = parts.get(1) else {
                crate::console_println!("Usage: cgroup mem <id> <frames>");
                return;
            };
            let Some(frames_str) = parts.get(2) else {
                crate::console_println!("Usage: cgroup mem <id> <frames>");
                return;
            };
            let Ok(id) = id_str.parse::<u32>() else {
                crate::console_println!("Invalid cgroup ID");
                return;
            };
            let Ok(frames) = frames_str.parse::<u64>() else {
                crate::console_println!("Invalid frame count");
                return;
            };
            let limit = cgroup::MemLimit::frames(frames);
            match cgroup::set_mem_limit(id, limit) {
                Ok(()) => {
                    if frames == 0 {
                        crate::console_println!("Cgroup {}: memory limit removed (unlimited)", id);
                    } else {
                        crate::console_println!("Cgroup {}: memory limit set to {} frames", id, frames);
                    }
                }
                Err(e) => crate::console_println!("Error: {:?}", e),
            }
        }
        "stats" | "info" => {
            let Some(id_str) = parts.get(1) else {
                crate::console_println!("Usage: cgroup stats <id>");
                return;
            };
            let Ok(id) = id_str.parse::<u32>() else {
                crate::console_println!("Invalid cgroup ID");
                return;
            };
            let Some(s) = cgroup::stats(id) else {
                crate::console_println!("Cgroup {} not found", id);
                return;
            };
            crate::console_println!("=== Cgroup {} ===", id);
            let parent = if s.parent == u32::MAX { "none (root)".to_string() }
                         else { alloc::format!("{}", s.parent) };
            crate::console_println!("  Parent:           {}", parent);
            crate::console_println!("  Tasks:            {}", s.nr_tasks);
            crate::console_println!("  Children:         {}", s.nr_children);
            crate::console_println!("  CPU quota:        {}", if s.cpu_quota == 0 {
                "unlimited".to_string()
            } else {
                alloc::format!("{} ticks / {} period", s.cpu_quota, s.cpu_period)
            });
            crate::console_println!("  CPU used:         {} ticks (this period)", s.cpu_used);
            crate::console_println!("  CPU throttles:    {}", s.cpu_throttle_count);
            crate::console_println!("  Memory limit:     {}", if s.mem_limit == 0 {
                "unlimited".to_string()
            } else {
                alloc::format!("{} frames", s.mem_limit)
            });
            crate::console_println!("  Memory usage:     {} frames", s.mem_usage);
            crate::console_println!("  Memory peak:      {} frames", s.mem_peak);
            crate::console_println!("  I/O ops limit:    {}", if s.io_ops_limit == 0 {
                "unlimited".to_string()
            } else {
                alloc::format!("{} ops/period", s.io_ops_limit)
            });
            crate::console_println!("  I/O bytes limit:  {}", if s.io_bytes_limit == 0 {
                "unlimited".to_string()
            } else {
                alloc::format!("{} frames/period", s.io_bytes_limit)
            });
            crate::console_println!("  I/O ops used:     {} (this period)", s.io_ops_used);
            crate::console_println!("  I/O bytes used:   {} frames (this period)", s.io_bytes_used);
            crate::console_println!("  I/O throttles:    {}", s.io_throttle_count);
            crate::console_println!("  Eff. CPU quota:   {}", {
                let eff = cgroup::effective_cpu_quota(id);
                if eff == 0 { "unlimited".to_string() }
                else { alloc::format!("{} ticks", eff) }
            });
            crate::console_println!("  Eff. mem limit:   {}", {
                let eff = cgroup::effective_mem_limit(id);
                if eff == 0 { "unlimited".to_string() }
                else { alloc::format!("{} frames", eff) }
            });
            crate::console_println!("  Eff. I/O ops:     {}", {
                let eff = cgroup::effective_io_ops_limit(id);
                if eff == 0 { "unlimited".to_string() }
                else { alloc::format!("{} ops", eff) }
            });
            crate::console_println!("  Eff. I/O bytes:   {}", {
                let eff = cgroup::effective_io_bytes_limit(id);
                if eff == 0 { "unlimited".to_string() }
                else { alloc::format!("{} frames", eff) }
            });
        }
        "io" => {
            let Some(id_str) = parts.get(1) else {
                crate::console_println!("Usage: cgroup io <id> <ops_max> [bytes_max]");
                return;
            };
            let Some(ops_str) = parts.get(2) else {
                crate::console_println!("Usage: cgroup io <id> <ops_max> [bytes_max]");
                return;
            };
            let Ok(id) = id_str.parse::<u32>() else {
                crate::console_println!("Invalid cgroup ID");
                return;
            };
            let Ok(ops) = ops_str.parse::<u64>() else {
                crate::console_println!("Invalid ops count");
                return;
            };
            let bytes = parts.get(3)
                .and_then(|s| s.parse::<u64>().ok())
                .unwrap_or(0);
            let limit = cgroup::IoLimit::new(ops, bytes);
            match cgroup::set_io_limit(id, limit) {
                Ok(()) => {
                    let ops_str = if ops == 0 { "unlimited".to_string() }
                                  else { alloc::format!("{} ops/period", ops) };
                    let bytes_str = if bytes == 0 { "unlimited".to_string() }
                                    else { alloc::format!("{} frames/period", bytes) };
                    crate::console_println!(
                        "Cgroup {}: I/O limit set — ops: {}, bytes: {}",
                        id, ops_str, bytes_str
                    );
                }
                Err(e) => crate::console_println!("Error: {:?}", e),
            }
        }
        "test" => {
            cgroup::self_test();
        }
        _ => {
            crate::console_println!("Usage: cgroup [list|create|delete|cpu|mem|io|stats|test]");
            crate::console_println!("  cgroup              — list active cgroups");
            crate::console_println!("  cgroup create [P]   — create under parent P (default: root)");
            crate::console_println!("  cgroup delete ID    — delete empty cgroup");
            crate::console_println!("  cgroup cpu ID PCT   — set CPU limit (0=unlimited)");
            crate::console_println!("  cgroup mem ID N     — set memory limit in frames (0=unlimited)");
            crate::console_println!("  cgroup io ID OPS [BYTES] — set I/O limit (0=unlimited)");
            crate::console_println!("  cgroup stats ID     — detailed stats");
            crate::console_println!("  cgroup test         — run self-test");
        }
    }
}

/// `capreq` — manage capability requests.
///
/// Usage:
///   capreq                — list pending requests
///   capreq all            — list all requests (including resolved)
/// `pidns` — PID namespace management.
///
/// Usage:
///   pidns              — list active PID namespaces
///   pidns create [P]   — create under parent P (default: root)
///   pidns delete ID    — delete empty namespace
///   pidns stats ID     — detailed stats
///   pidns test         — run self-test
fn cmd_pidns(args: &str) {
    use crate::pidns;

    let parts: alloc::vec::Vec<&str> = args.split_whitespace().collect();
    let cmd = parts.first().copied().unwrap_or("");

    match cmd {
        "" | "list" | "ls" => {
            let count = pidns::active_count();
            crate::console_println!("=== PID Namespaces ({} active) ===", count);
            crate::console_println!(
                "{:<5} {:<7} {:<7} {:<10} {:<5}",
                "ID", "Parent", "Procs", "Children", "Init"
            );
            for id in 0..pidns::MAX_NAMESPACES as u32 {
                if let Some(s) = pidns::stats(id) {
                    let parent = if s.parent == u32::MAX {
                        "-".to_string()
                    } else {
                        alloc::format!("{}", s.parent)
                    };
                    let init = if s.has_init { "yes" } else { "no" };
                    crate::console_println!(
                        "{:<5} {:<7} {:<7} {:<10} {:<5}",
                        id, parent, s.nr_procs, s.nr_children, init
                    );
                }
            }
        }
        "create" => {
            let parent: u32 = parts.get(1)
                .and_then(|s| s.parse().ok())
                .unwrap_or(0);
            match pidns::create(parent) {
                Ok(id) => crate::console_println!("Created PID namespace {} (parent: {})", id, parent),
                Err(e) => crate::console_println!("Error: {:?}", e),
            }
        }
        "delete" | "del" | "rm" => {
            let Some(id_str) = parts.get(1) else {
                crate::console_println!("Usage: pidns delete <id>");
                return;
            };
            let Ok(id) = id_str.parse::<u32>() else {
                crate::console_println!("Invalid namespace ID");
                return;
            };
            match pidns::delete(id) {
                Ok(()) => crate::console_println!("Deleted PID namespace {}", id),
                Err(e) => crate::console_println!("Error: {:?}", e),
            }
        }
        "stats" | "info" => {
            let Some(id_str) = parts.get(1) else {
                crate::console_println!("Usage: pidns stats <id>");
                return;
            };
            let Ok(id) = id_str.parse::<u32>() else {
                crate::console_println!("Invalid namespace ID");
                return;
            };
            let Some(s) = pidns::stats(id) else {
                crate::console_println!("PID namespace {} not found", id);
                return;
            };
            crate::console_println!("=== PID Namespace {} ===", id);
            let parent = if s.parent == u32::MAX { "none (root)".to_string() }
                         else { alloc::format!("{}", s.parent) };
            crate::console_println!("  Parent:     {}", parent);
            crate::console_println!("  Processes:  {}", s.nr_procs);
            crate::console_println!("  Children:   {}", s.nr_children);
            crate::console_println!("  Has init:   {}", if s.has_init { "yes" } else { "no" });
            if let Some(init) = pidns::init_pid(id) {
                crate::console_println!("  Init PID:   {} (global)", init);
            }
            // Show PID mappings.
            let pids = pidns::list_pids(id);
            if !pids.is_empty() {
                crate::console_println!("  PID mappings:");
                for (local, global) in &pids {
                    crate::console_println!("    local {} → global {}", local, global);
                }
            }
        }
        "test" => {
            pidns::self_test();
        }
        _ => {
            crate::console_println!("Usage: pidns [list|create|delete|stats|test]");
            crate::console_println!("  pidns              — list active PID namespaces");
            crate::console_println!("  pidns create [P]   — create under parent P (default: root)");
            crate::console_println!("  pidns delete ID    — delete empty namespace");
            crate::console_println!("  pidns stats ID     — detailed stats with PID mappings");
            crate::console_println!("  pidns test         — run self-test");
        }
    }
}

fn cmd_userns(args: &str) {
    use crate::userns;

    let parts: alloc::vec::Vec<&str> = args.split_whitespace().collect();
    let cmd = parts.first().copied().unwrap_or("");

    match cmd {
        "" | "list" | "ls" => {
            let count = userns::active_count();
            crate::console_println!("=== User Namespaces ({} active) ===", count);
            crate::console_println!(
                "{:<5} {:<7} {:<8} {:<5} {:<5} {:<5} {:<5}",
                "ID", "Parent", "Owner", "UIDs", "GIDs", "Procs", "Kids"
            );
            for id in 0..userns::MAX_NAMESPACES as u32 {
                if let Some(s) = userns::stats(id) {
                    let parent = if s.parent == u32::MAX {
                        "-".to_string()
                    } else {
                        alloc::format!("{}", s.parent)
                    };
                    crate::console_println!(
                        "{:<5} {:<7} {:<8} {:<5} {:<5} {:<5} {:<5}",
                        id, parent, s.owner_uid, s.uid_map_count,
                        s.gid_map_count, s.nr_procs, s.nr_children
                    );
                }
            }
        }
        "create" => {
            let parent: u32 = parts.get(1)
                .and_then(|s| s.parse().ok())
                .unwrap_or(0);
            let owner: u32 = parts.get(2)
                .and_then(|s| s.parse().ok())
                .unwrap_or(0);
            match userns::create(parent, owner) {
                Ok(id) => crate::console_println!(
                    "Created user namespace {} (parent: {}, owner UID: {})", id, parent, owner
                ),
                Err(e) => crate::console_println!("Error: {:?}", e),
            }
        }
        "delete" | "del" | "rm" => {
            let Some(id_str) = parts.get(1) else {
                crate::console_println!("Usage: userns delete <id>");
                return;
            };
            let Ok(id) = id_str.parse::<u32>() else {
                crate::console_println!("Invalid namespace ID");
                return;
            };
            match userns::delete(id) {
                Ok(()) => crate::console_println!("Deleted user namespace {}", id),
                Err(e) => crate::console_println!("Error: {:?}", e),
            }
        }
        "uidmap" => {
            // userns uidmap <ns> <inner_start> <outer_start> <count>
            if parts.len() < 5 {
                crate::console_println!("Usage: userns uidmap <ns> <inner> <outer> <count>");
                return;
            }
            let ns = parts[1].parse::<u32>().unwrap_or(u32::MAX);
            let inner = parts[2].parse::<u32>().unwrap_or(0);
            let outer = parts[3].parse::<u32>().unwrap_or(0);
            let count = parts[4].parse::<u32>().unwrap_or(0);
            match userns::add_uid_mapping(ns, inner, outer, count) {
                Ok(()) => crate::console_println!(
                    "Added UID mapping: ns {} inner {}..{} → outer {}..{}",
                    ns, inner, inner.saturating_add(count).saturating_sub(1),
                    outer, outer.saturating_add(count).saturating_sub(1)
                ),
                Err(e) => crate::console_println!("Error: {:?}", e),
            }
        }
        "gidmap" => {
            // userns gidmap <ns> <inner_start> <outer_start> <count>
            if parts.len() < 5 {
                crate::console_println!("Usage: userns gidmap <ns> <inner> <outer> <count>");
                return;
            }
            let ns = parts[1].parse::<u32>().unwrap_or(u32::MAX);
            let inner = parts[2].parse::<u32>().unwrap_or(0);
            let outer = parts[3].parse::<u32>().unwrap_or(0);
            let count = parts[4].parse::<u32>().unwrap_or(0);
            match userns::add_gid_mapping(ns, inner, outer, count) {
                Ok(()) => crate::console_println!(
                    "Added GID mapping: ns {} inner {}..{} → outer {}..{}",
                    ns, inner, inner.saturating_add(count).saturating_sub(1),
                    outer, outer.saturating_add(count).saturating_sub(1)
                ),
                Err(e) => crate::console_println!("Error: {:?}", e),
            }
        }
        "stats" | "info" => {
            let Some(id_str) = parts.get(1) else {
                crate::console_println!("Usage: userns stats <id>");
                return;
            };
            let Ok(id) = id_str.parse::<u32>() else {
                crate::console_println!("Invalid namespace ID");
                return;
            };
            let Some(s) = userns::stats(id) else {
                crate::console_println!("User namespace {} not found", id);
                return;
            };
            crate::console_println!("=== User Namespace {} ===", id);
            let parent = if s.parent == u32::MAX {
                "none (root)".to_string()
            } else {
                alloc::format!("{}", s.parent)
            };
            crate::console_println!("  Parent:      {}", parent);
            crate::console_println!("  Owner UID:   {}", s.owner_uid);
            crate::console_println!("  Processes:   {}", s.nr_procs);
            crate::console_println!("  Children:    {}", s.nr_children);
            crate::console_println!("  UID ranges:  {}", s.uid_map_count);
            crate::console_println!("  GID ranges:  {}", s.gid_map_count);
            // Show UID mappings.
            let uid_maps = userns::uid_mappings(id);
            if !uid_maps.is_empty() {
                crate::console_println!("  UID mappings:");
                for m in &uid_maps {
                    crate::console_println!(
                        "    inner {}..{} → outer {}..{}",
                        m.inner_start, m.inner_start.saturating_add(m.count).saturating_sub(1),
                        m.outer_start, m.outer_start.saturating_add(m.count).saturating_sub(1)
                    );
                }
            }
            // Show GID mappings.
            let gid_maps = userns::gid_mappings(id);
            if !gid_maps.is_empty() {
                crate::console_println!("  GID mappings:");
                for m in &gid_maps {
                    crate::console_println!(
                        "    inner {}..{} → outer {}..{}",
                        m.inner_start, m.inner_start.saturating_add(m.count).saturating_sub(1),
                        m.outer_start, m.outer_start.saturating_add(m.count).saturating_sub(1)
                    );
                }
            }
            // Show UID translation example.
            crate::console_println!("  Translation example (inner 0 → host): {}", userns::uid_to_host(id, 0));
        }
        "test" => {
            userns::self_test();
        }
        _ => {
            crate::console_println!("Usage: userns [list|create|delete|uidmap|gidmap|stats|test]");
            crate::console_println!("  userns                         — list active user namespaces");
            crate::console_println!("  userns create [P] [owner]      — create under parent P with owner UID");
            crate::console_println!("  userns delete ID               — delete empty namespace");
            crate::console_println!("  userns uidmap NS I O C         — map inner I..I+C to outer O..O+C");
            crate::console_println!("  userns gidmap NS I O C         — same for GID");
            crate::console_println!("  userns stats ID                — detailed stats with mappings");
            crate::console_println!("  userns test                    — run self-test");
        }
    }
}

fn cmd_netns(args: &str) {
    use crate::netns;

    let parts: alloc::vec::Vec<&str> = args.split_whitespace().collect();
    let cmd = parts.first().copied().unwrap_or("");

    match cmd {
        "" | "list" | "ls" => {
            let count = netns::active_count();
            crate::console_println!("=== Network Namespaces ({} active) ===", count);
            crate::console_println!(
                "{:<5} {:<5} {:<16} {:<16} {:<16} {:<6} {:<5}",
                "ID", "Up", "IP", "Gateway", "DNS", "Routes", "Procs"
            );
            for id in 0..netns::MAX_NAMESPACES as u32 {
                if let Some(s) = netns::stats(id) {
                    let up = if s.iface_up { "yes" } else { "no" };
                    crate::console_println!(
                        "{:<5} {:<5} {:<16} {:<16} {:<16} {:<6} {:<5}",
                        id, up, alloc::format!("{}", s.ip),
                        alloc::format!("{}", s.gateway),
                        alloc::format!("{}", s.dns),
                        s.route_count, s.nr_procs
                    );
                }
            }
        }
        "create" => {
            match netns::create() {
                Ok(id) => crate::console_println!("Created network namespace {}", id),
                Err(e) => crate::console_println!("Error: {:?}", e),
            }
        }
        "delete" | "del" | "rm" => {
            let Some(id_str) = parts.get(1) else {
                crate::console_println!("Usage: netns delete <id>");
                return;
            };
            let Ok(id) = id_str.parse::<u32>() else {
                crate::console_println!("Invalid namespace ID");
                return;
            };
            match netns::delete(id) {
                Ok(()) => crate::console_println!("Deleted network namespace {}", id),
                Err(e) => crate::console_println!("Error: {:?}", e),
            }
        }
        "ifconfig" | "config" => {
            // netns ifconfig <ns> <ip> <mask> <gw> <dns>
            if parts.len() < 6 {
                crate::console_println!("Usage: netns ifconfig <ns> <ip> <mask> <gw> <dns>");
                crate::console_println!("  Example: netns ifconfig 1 10.0.0.2 255.255.255.0 10.0.0.1 8.8.8.8");
                return;
            }
            let ns = parts[1].parse::<u32>().unwrap_or(u32::MAX);
            let parse_ip = |s: &str| -> Option<netns::Ipv4Addr> {
                let octets: alloc::vec::Vec<&str> = s.split('.').collect();
                if octets.len() != 4 { return None; }
                Some(netns::Ipv4Addr::new(
                    octets[0].parse().ok()?,
                    octets[1].parse().ok()?,
                    octets[2].parse().ok()?,
                    octets[3].parse().ok()?,
                ))
            };
            let Some(ip) = parse_ip(parts[2]) else {
                crate::console_println!("Invalid IP address: {}", parts[2]);
                return;
            };
            let Some(mask) = parse_ip(parts[3]) else {
                crate::console_println!("Invalid subnet mask: {}", parts[3]);
                return;
            };
            let Some(gw) = parse_ip(parts[4]) else {
                crate::console_println!("Invalid gateway: {}", parts[4]);
                return;
            };
            let Some(dns) = parse_ip(parts[5]) else {
                crate::console_println!("Invalid DNS: {}", parts[5]);
                return;
            };
            match netns::configure_interface(ns, ip, mask, gw, dns) {
                Ok(()) => crate::console_println!(
                    "Configured ns {}: IP {} mask {} gw {} dns {}", ns, ip, mask, gw, dns
                ),
                Err(e) => crate::console_println!("Error: {:?}", e),
            }
        }
        "route" => {
            // netns route <ns> — show routes
            // netns route <ns> add <dest> <mask> <gw> [metric]
            // netns route <ns> del <dest> <mask>
            let Some(ns_str) = parts.get(1) else {
                crate::console_println!("Usage: netns route <ns> [add|del ...]");
                return;
            };
            let Ok(ns) = ns_str.parse::<u32>() else {
                crate::console_println!("Invalid namespace ID");
                return;
            };
            let sub = parts.get(2).copied().unwrap_or("");
            let parse_ip = |s: &str| -> Option<netns::Ipv4Addr> {
                let octets: alloc::vec::Vec<&str> = s.split('.').collect();
                if octets.len() != 4 { return None; }
                Some(netns::Ipv4Addr::new(
                    octets[0].parse().ok()?,
                    octets[1].parse().ok()?,
                    octets[2].parse().ok()?,
                    octets[3].parse().ok()?,
                ))
            };
            match sub {
                "" | "show" => {
                    let rt = netns::routes(ns);
                    if rt.is_empty() {
                        crate::console_println!("No routes in namespace {}", ns);
                    } else {
                        crate::console_println!("=== Routes (ns {}) ===", ns);
                        crate::console_println!("{:<18} {:<18} {:<18} {:<7}", "Destination", "Mask", "Gateway", "Metric");
                        for r in &rt {
                            crate::console_println!(
                                "{:<18} {:<18} {:<18} {:<7}",
                                alloc::format!("{}", r.destination),
                                alloc::format!("{}", r.mask),
                                alloc::format!("{}", r.gateway),
                                r.metric
                            );
                        }
                    }
                }
                "add" => {
                    if parts.len() < 6 {
                        crate::console_println!("Usage: netns route <ns> add <dest> <mask> <gw> [metric]");
                        return;
                    }
                    let Some(dest) = parse_ip(parts[3]) else {
                        crate::console_println!("Invalid destination");
                        return;
                    };
                    let Some(mask) = parse_ip(parts[4]) else {
                        crate::console_println!("Invalid mask");
                        return;
                    };
                    let Some(gw) = parse_ip(parts[5]) else {
                        crate::console_println!("Invalid gateway");
                        return;
                    };
                    let metric = parts.get(6).and_then(|s| s.parse().ok()).unwrap_or(100);
                    match netns::add_route(ns, dest, mask, gw, metric) {
                        Ok(()) => crate::console_println!(
                            "Added route: {} mask {} via {} metric {}", dest, mask, gw, metric
                        ),
                        Err(e) => crate::console_println!("Error: {:?}", e),
                    }
                }
                "del" | "delete" => {
                    if parts.len() < 5 {
                        crate::console_println!("Usage: netns route <ns> del <dest> <mask>");
                        return;
                    }
                    let Some(dest) = parse_ip(parts[3]) else {
                        crate::console_println!("Invalid destination");
                        return;
                    };
                    let Some(mask) = parse_ip(parts[4]) else {
                        crate::console_println!("Invalid mask");
                        return;
                    };
                    match netns::remove_route(ns, dest, mask) {
                        Ok(()) => crate::console_println!("Removed route: {} mask {}", dest, mask),
                        Err(e) => crate::console_println!("Error: {:?}", e),
                    }
                }
                _ => {
                    crate::console_println!("Usage: netns route <ns> [show|add|del]");
                }
            }
        }
        "stats" | "info" => {
            let Some(id_str) = parts.get(1) else {
                crate::console_println!("Usage: netns stats <id>");
                return;
            };
            let Ok(id) = id_str.parse::<u32>() else {
                crate::console_println!("Invalid namespace ID");
                return;
            };
            let Some(s) = netns::stats(id) else {
                crate::console_println!("Network namespace {} not found", id);
                return;
            };
            crate::console_println!("=== Network Namespace {} ===", id);
            crate::console_println!("  Interface:  {}", if s.iface_up { "up" } else { "down" });
            crate::console_println!("  IP:         {}", s.ip);
            crate::console_println!("  Subnet:     {}", s.subnet_mask);
            crate::console_println!("  Gateway:    {}", s.gateway);
            crate::console_println!("  DNS:        {}", s.dns);
            crate::console_println!("  Routes:     {}", s.route_count);
            crate::console_println!("  Processes:  {}", s.nr_procs);
            // Show routing table.
            let rt = netns::routes(id);
            if !rt.is_empty() {
                crate::console_println!("  Routing table:");
                for r in &rt {
                    crate::console_println!(
                        "    {} mask {} via {} metric {}",
                        r.destination, r.mask, r.gateway, r.metric
                    );
                }
            }
        }
        "up" | "down" => {
            let Some(id_str) = parts.get(1) else {
                crate::console_println!("Usage: netns up|down <id>");
                return;
            };
            let Ok(id) = id_str.parse::<u32>() else {
                crate::console_println!("Invalid namespace ID");
                return;
            };
            let up = cmd == "up";
            match netns::set_interface_up(id, up) {
                Ok(()) => crate::console_println!(
                    "Namespace {} interface {}", id, if up { "up" } else { "down" }
                ),
                Err(e) => crate::console_println!("Error: {:?}", e),
            }
        }
        "test" => {
            netns::self_test();
        }
        _ => {
            crate::console_println!("Usage: netns [list|create|delete|ifconfig|route|stats|up|down|test]");
            crate::console_println!("  netns                              — list active network namespaces");
            crate::console_println!("  netns create                       — create a new namespace");
            crate::console_println!("  netns delete ID                    — delete empty namespace");
            crate::console_println!("  netns ifconfig NS IP MASK GW DNS   — configure interface");
            crate::console_println!("  netns route NS                     — show routing table");
            crate::console_println!("  netns route NS add D M GW [metric] — add route");
            crate::console_println!("  netns route NS del D M             — remove route");
            crate::console_println!("  netns stats ID                     — detailed stats");
            crate::console_println!("  netns up|down ID                   — set interface up/down");
            crate::console_println!("  netns test                         — run self-test");
        }
    }
}

/// Real in-container process launch (the kernel side of Docker `docker exec`):
/// read the ELF from the container's rootfs and spawn it bound into the
/// container's cgroup + PID/user/network namespaces + rootfs jail, then (unless
/// detached) join on its exit code. Shared by `container run-in`, the
/// `container exec --rootfs` alias, and the `docker exec` delegate (Q17/§58,
/// option B).
///
/// `rest` is the token slice *after* the verb: `[-d] [-w DIR] <id> <path>
/// [args...]`. `-d` detaches (print the pid and return); otherwise block on the
/// spawned pid, print its exit status, and unregister it from container
/// bookkeeping. `-w`/`--workdir DIR` sets the exec'd process's initial working
/// directory (an absolute guest path); when omitted the exec inherits the
/// container's stored WorkingDir (Docker `exec` semantics).
fn container_exec_rootfs(rest: &[&str]) {
    use crate::container;

    // Parse leading options: `-d` (detached) and `-w/--workdir DIR` (initial
    // working directory for the exec'd command). Both may precede the id, in
    // any order. `-w` must be an absolute guest path (Docker requires this);
    // when omitted the exec inherits the container's stored WorkingDir.
    let mut idx = 0usize;
    let mut detached = false;
    let mut workdir: Option<&str> = None;
    loop {
        match rest.get(idx).copied() {
            Some("-d") => {
                detached = true;
                idx = idx.saturating_add(1);
            }
            Some("-w" | "--workdir") => {
                match rest.get(idx.saturating_add(1)).copied() {
                    Some(dir) if dir.starts_with('/') => {
                        workdir = Some(dir);
                        idx = idx.saturating_add(2);
                    }
                    Some(dir) => {
                        crate::console_println!(
                            "[run-in] Ignoring workdir '{}': must be an absolute path", dir
                        );
                        idx = idx.saturating_add(2);
                    }
                    None => {
                        crate::console_println!("[run-in] -w requires a directory argument");
                        return;
                    }
                }
            }
            _ => break,
        }
    }
    let Some(id_str) = rest.get(idx) else {
        crate::console_println!("Usage: container run-in [-d] [-w DIR] <id> <command> [args...]");
        return;
    };
    let Ok(id) = id_str.parse::<u32>() else {
        crate::console_println!("Invalid container ID");
        return;
    };

    // Everything after the id is argv (argv[0] = the guest executable path
    // resolved under the container's rootfs).
    let cmd_tokens = rest.get(idx.saturating_add(1)..).unwrap_or(&[]);
    let argv: alloc::vec::Vec<&[u8]> = cmd_tokens.iter().map(|s| s.as_bytes()).collect();
    let Some(&guest_cmd) = argv.first() else {
        crate::console_println!("Usage: container run-in [-d] [-w DIR] <id> <command> [args...]");
        return;
    };

    let cwd: Option<&[u8]> = workdir.map(str::as_bytes);
    match container::exec_path_env(id, guest_cmd, &argv, &[], cwd) {
        Ok(spawned) => {
            if detached {
                crate::console_println!(
                    "[run-in] container {} pid {} (detached)", id, spawned.pid
                );
            } else {
                match container::wait_process(spawned.pid) {
                    Ok(code) => crate::console_println!(
                        "[run-in] container {} pid {} exited with status {}",
                        id, spawned.pid, code
                    ),
                    Err(e) => crate::console_println!(
                        "[run-in] wait failed for pid {}: {:?}", spawned.pid, e
                    ),
                }
                // Unregister the finished process from container bookkeeping
                // (drops the pid entry + decrements namespace refcounts; the
                // cgroup task count is released when the dead task is reaped).
                let _ = container::remove_process_task(id, spawned.pid, spawned.task_id);
            }
        }
        Err(e) => crate::console_println!("[run-in] failed: {:?}", e),
    }
}

fn cmd_container(args: &str) {
    use crate::container;

    let parts: alloc::vec::Vec<&str> = args.split_whitespace().collect();
    let cmd = parts.first().copied().unwrap_or("");

    match cmd {
        "" | "list" | "ls" => {
            // Optional Docker-style `--filter`/`-f`, repeatable, with three
            // supported keys:
            //   label=KEY            label present (any value)
            //   label=KEY=VALUE      label equals value
            //   name=SUBSTRING       container name contains the substring
            //   status=STATE         state is created|running|stopped|failed
            // A container must satisfy ALL given filters (AND semantics). Note
            // this is slightly stricter than Docker for repeated same-key
            // filters (Docker ORs those), but it is simple and predictable.
            let mut label_filters: alloc::vec::Vec<(&str, Option<&str>)> =
                alloc::vec::Vec::new();
            let mut name_filters: alloc::vec::Vec<&str> = alloc::vec::Vec::new();
            let mut status_filters: alloc::vec::Vec<container::ContainerState> =
                alloc::vec::Vec::new();
            // `-q`/`--quiet` (Docker `ps -q`): print only container IDs, one per
            // line, with no header — for scripting (`rm $(ls -q)`).
            let mut quiet = false;
            // `-a`/`--all` (Docker `ps -a`): include non-running containers.
            // Without it, `ps` shows only Running containers, matching Docker
            // (a `status=` filter, if given, overrides this running-only
            // default so `ls --filter status=stopped` still works).
            let mut all_states = false;
            // `-n N` (Docker `ps -n`): show the N most-recently-created
            // containers of any state; `-l`/`--latest` == `-n 1`. Setting a
            // limit implies `-a` (last-N spans all states).
            let mut limit: Option<usize> = None;
            let mut fi = 1;
            while fi < parts.len() {
                match parts.get(fi) {
                    Some(&"-q") | Some(&"--quiet") => {
                        quiet = true;
                        fi = fi.saturating_add(1);
                    }
                    Some(&"-a") | Some(&"--all") => {
                        all_states = true;
                        fi = fi.saturating_add(1);
                    }
                    Some(&"-l") | Some(&"--latest") => {
                        limit = Some(1);
                        all_states = true;
                        fi = fi.saturating_add(1);
                    }
                    Some(&"-n") | Some(&"--last") => {
                        match parts.get(fi.saturating_add(1)).and_then(|s| s.parse::<usize>().ok()) {
                            Some(n) => {
                                limit = Some(n);
                                all_states = true;
                            }
                            None => crate::console_println!(
                                "[container] Ignoring -n: expected a count (e.g. -n 5)"
                            ),
                        }
                        fi = fi.saturating_add(2);
                    }
                    Some(&"--filter") | Some(&"-f") => {
                        if let Some(&spec) = parts.get(fi.saturating_add(1)) {
                            if let Some(lbl) = spec.strip_prefix("label=") {
                                match lbl.split_once('=') {
                                    Some((k, v)) if !k.is_empty() => {
                                        label_filters.push((k, Some(v)));
                                    }
                                    None if !lbl.is_empty() => {
                                        label_filters.push((lbl, None));
                                    }
                                    _ => crate::console_println!(
                                        "[container] Ignoring filter '{}': expected label=KEY[=VALUE]",
                                        spec
                                    ),
                                }
                            } else if let Some(nm) = spec.strip_prefix("name=") {
                                if nm.is_empty() {
                                    crate::console_println!(
                                        "[container] Ignoring filter '{}': empty name", spec
                                    );
                                } else {
                                    name_filters.push(nm);
                                }
                            } else if let Some(st) = spec.strip_prefix("status=") {
                                match container::parse_state(st) {
                                    Some(state) => status_filters.push(state),
                                    None => crate::console_println!(
                                        "[container] Ignoring filter '{}': status must be created|running|stopped|failed",
                                        spec
                                    ),
                                }
                            } else {
                                crate::console_println!(
                                    "[container] Unsupported filter '{}' (supported: label=, name=, status=)",
                                    spec
                                );
                            }
                            fi = fi.saturating_add(2);
                        } else {
                            fi = fi.saturating_add(1);
                        }
                    }
                    _ => fi = fi.saturating_add(1),
                }
            }

            let all = container::list();
            if all.is_empty() {
                // Quiet mode stays silent so `rm $(ls -q)` degrades to a no-op.
                if !quiet {
                    crate::console_println!("No containers.");
                }
                return;
            }
            // A container matches only if every filter is satisfied. Name and
            // status are checked against the listing tuple directly; labels
            // require an info() lookup (only performed when label filters exist).
            let matches = |id: container::ContainerId,
                           name: &str,
                           state: container::ContainerState|
             -> bool {
                if !name_filters.iter().all(|sub| name.contains(sub)) {
                    return false;
                }
                if status_filters.is_empty() {
                    // No explicit status filter: Docker `ps` shows only Running
                    // unless `-a`/`--all` was given.
                    if !all_states && state != container::ContainerState::Running {
                        return false;
                    }
                } else if !status_filters.contains(&state) {
                    return false;
                }
                if label_filters.is_empty() {
                    return true;
                }
                let Some(ci) = container::info(id) else { return false };
                container::labels_match(&ci.labels, &label_filters)
            };

            let mut shown: alloc::vec::Vec<&(container::ContainerId, alloc::string::String, _)> =
                all.iter().filter(|(id, name, state)| matches(*id, name, *state)).collect();
            // Order newest-first by creation sequence (Docker `ps` lists the
            // most recently created container at the top). `-n N`/`-l` then
            // keeps only the first N of that order.
            shown.sort_by(|a, b| {
                let sa = container::info(a.0).map_or(0, |ci| ci.created_seq);
                let sb = container::info(b.0).map_or(0, |ci| ci.created_seq);
                sb.cmp(&sa)
            });
            if let Some(n) = limit {
                shown.truncate(n);
            }
            if shown.is_empty() {
                if !quiet {
                    // Distinguish "filtered everything out" from "only stopped
                    // containers exist and -a wasn't given".
                    if !all_states
                        && status_filters.is_empty()
                        && label_filters.is_empty()
                        && name_filters.is_empty()
                    {
                        crate::console_println!("No running containers (use -a to show all).");
                    } else {
                        crate::console_println!("No containers match the filter.");
                    }
                }
                return;
            }
            // Quiet mode: just the IDs, one per line (Docker `ps -q`).
            if quiet {
                for (id, _name, _state) in &shown {
                    crate::console_println!("{}", id);
                }
                return;
            }
            crate::console_println!("=== Containers ({}) ===", shown.len());
            crate::console_println!(
                "{:<5} {:<20} {:<26}",
                "ID", "Name", "Status"
            );
            for (id, name, state) in &shown {
                // Docker `ps -a` style status: a stopped container shows its
                // recorded init exit code ("exited (N)"); other states show the
                // bare state word. The exit code requires an info() lookup, so
                // we only pay for it for stopped containers.
                let status = if *state == container::ContainerState::Stopped {
                    match container::info(*id).and_then(|ci| ci.exit_code) {
                        Some(code) => alloc::format!("exited ({})", code),
                        None => alloc::format!("{}", state),
                    }
                } else if *state == container::ContainerState::Running
                    && container::is_frozen(*id) == Some(true)
                {
                    // A frozen running container shows "paused" (Docker `ps`).
                    alloc::format!("{} (paused)", state)
                } else if *state == container::ContainerState::Running {
                    // Running: append the health sub-state when a healthcheck is
                    // configured (Docker's "Up (healthy)" / "(health: starting)").
                    match container::health_status(*id) {
                        Some(container::HealthStatus::Healthy) => {
                            alloc::format!("{} (healthy)", state)
                        }
                        Some(container::HealthStatus::Unhealthy) => {
                            alloc::format!("{} (unhealthy)", state)
                        }
                        Some(container::HealthStatus::Starting) => {
                            alloc::format!("{} (health: starting)", state)
                        }
                        _ => alloc::format!("{}", state),
                    }
                } else {
                    alloc::format!("{}", state)
                };
                crate::console_println!("{:<5} {:<20} {:<26}", id, name, status);
            }
        }
        "create" => {
            // container create <name> [options...]
            // Options: cpu=<N> mem=<N> uid=<inner:outer:count> net=<ip>[/<mask>][,gw=<ip>][,dns=<ip>]
            let name = parts.get(1).unwrap_or(&"unnamed");
            let mut cfg = container::ContainerConfig::new(name);

            // Parse key=value options from remaining args.
            for &arg in parts.iter().skip(2) {
                if let Some(val) = arg.strip_prefix("cpu=") {
                    if let Ok(cpu) = val.parse::<u64>() {
                        cfg.cpu_quota = cpu;
                    }
                } else if let Some(val) = arg.strip_prefix("mem=") {
                    if let Ok(mem) = val.parse::<u64>() {
                        cfg.mem_limit = mem;
                    }
                } else if let Some(val) = arg.strip_prefix("uid=") {
                    let uid_parts: alloc::vec::Vec<&str> = val.split(':').collect();
                    if uid_parts.len() == 3 {
                        if let (Ok(inner), Ok(outer), Ok(count)) = (
                            uid_parts[0].parse::<u32>(),
                            uid_parts[1].parse::<u32>(),
                            uid_parts[2].parse::<u32>(),
                        ) {
                            cfg = cfg.uid_map(inner, outer, count);
                        }
                    }
                } else if let Some(val) = arg.strip_prefix("net=") {
                    // net=10.88.0.2 or net=10.88.0.2,gw=10.88.0.1,dns=8.8.8.8
                    let net_parts: alloc::vec::Vec<&str> = val.split(',').collect();
                    if let Some(ip) = parse_ipv4_octets(net_parts.first().copied().unwrap_or("")) {
                        cfg.net_ip = Some(ip);
                        cfg.net_mask = Some([255, 255, 255, 0]); // default /24
                        for &part in net_parts.iter().skip(1) {
                            if let Some(gw) = part.strip_prefix("gw=") {
                                cfg.net_gateway = parse_ipv4_octets(gw);
                            } else if let Some(dns) = part.strip_prefix("dns=") {
                                cfg.net_dns = parse_ipv4_octets(dns);
                            }
                        }
                    }
                } else if let Some(val) = arg.strip_prefix("restart=") {
                    // restart=no|always|unless-stopped|on-failure[:N] (Docker
                    // `--restart`).
                    match container::parse_restart_policy(val) {
                        Some(policy) => cfg.restart_policy = policy,
                        None => crate::console_println!(
                            "[container] Ignoring restart='{}' (want no|always|unless-stopped|on-failure[:N])",
                            val
                        ),
                    }
                } else if arg == "rm" || arg == "--rm" || arg == "rm=true" {
                    // Docker `--rm`: auto-delete the container when its init
                    // exits (unless a restart policy takes precedence).
                    cfg.auto_remove = true;
                } else if arg == "rm=false" {
                    cfg.auto_remove = false;
                } else {
                    // Legacy positional: arg2=cpu, arg3=mem, arg4=uid
                    if parts.get(2) == Some(&arg) {
                        if let Ok(cpu) = arg.parse::<u64>() {
                            cfg.cpu_quota = cpu;
                        }
                    } else if parts.get(3) == Some(&arg) {
                        if let Ok(mem) = arg.parse::<u64>() {
                            cfg.mem_limit = mem;
                        }
                    }
                }
            }

            match container::create(&cfg) {
                Ok(id) => crate::console_println!(
                    "Created container '{}' (id={})", name, id
                ),
                Err(e) => crate::console_println!("Error: {:?}", e),
            }
        }
        "delete" | "del" | "rm" => {
            // `--force`/`-f` removes a running container (Docker `rm -f`); the
            // flag may appear before or after the ids.  Every non-flag token
            // after the subcommand is treated as a container id (Docker `rm`
            // accepts multiple targets and processes each independently).
            let force = parts.iter().skip(1).any(|&t| t == "-f" || t == "--force");
            let ids: alloc::vec::Vec<&str> = parts
                .iter()
                .skip(1)
                .copied()
                .filter(|&t| t != "-f" && t != "--force")
                .collect();
            if ids.is_empty() {
                crate::console_println!("Usage: container delete [-f|--force] <id> [id...]");
                return;
            }
            for id_str in ids {
                let Ok(id) = id_str.parse::<u32>() else {
                    crate::console_println!("Invalid container ID '{}'", id_str);
                    continue;
                };
                let result = if force {
                    container::force_delete(id)
                } else {
                    container::delete(id)
                };
                match result {
                    Ok(()) => crate::console_println!("Deleted container {}", id),
                    Err(e) => crate::console_println!("Container {}: Error: {:?}", id, e),
                }
            }
        }
        "start" => {
            // Docker `start` accepts multiple targets: each is processed
            // independently and failures don't abort the rest.
            if parts.len() < 2 {
                crate::console_println!("Usage: container start <id> [id...]");
                return;
            }
            for &id_str in parts.iter().skip(1) {
                let Ok(id) = id_str.parse::<u32>() else {
                    crate::console_println!("Invalid container ID '{}'", id_str);
                    continue;
                };
                match container::start(id) {
                    Ok(()) => crate::console_println!("Container {} started", id),
                    Err(e) => crate::console_println!("Container {}: Error: {:?}", id, e),
                }
            }
        }
        "stop" => {
            if parts.len() < 2 {
                crate::console_println!("Usage: container stop <id> [id...]");
                return;
            }
            for &id_str in parts.iter().skip(1) {
                let Ok(id) = id_str.parse::<u32>() else {
                    crate::console_println!("Invalid container ID '{}'", id_str);
                    continue;
                };
                match container::stop(id) {
                    Ok(()) => crate::console_println!("Container {} stopped", id),
                    Err(e) => crate::console_println!("Container {}: Error: {:?}", id, e),
                }
            }
        }
        "info" | "inspect" => {
            // Optional `--json`/`-j` (Docker `inspect` emits JSON): the first
            // non-flag token is the container id.
            let mut want_json = false;
            let mut id_str: Option<&str> = None;
            for &tok in parts.iter().skip(1) {
                if tok == "--json" || tok == "-j" {
                    want_json = true;
                } else if id_str.is_none() {
                    id_str = Some(tok);
                }
            }
            let Some(id_str) = id_str else {
                crate::console_println!("Usage: container info [--json] <id>");
                return;
            };
            let Ok(id) = id_str.parse::<u32>() else {
                crate::console_println!("Invalid container ID");
                return;
            };
            let Some(ci) = container::info(id) else {
                crate::console_println!("Container {} not found", id);
                return;
            };
            if want_json {
                // JSON string escaper: names/labels are OS-boundary data that
                // may contain quotes, backslashes, or control bytes.
                let esc = |s: &str| -> alloc::string::String {
                    let mut out = alloc::string::String::with_capacity(s.len());
                    for c in s.chars() {
                        match c {
                            '"' => out.push_str("\\\""),
                            '\\' => out.push_str("\\\\"),
                            '\n' => out.push_str("\\n"),
                            '\r' => out.push_str("\\r"),
                            '\t' => out.push_str("\\t"),
                            c if (c as u32) < 0x20 => {
                                out.push_str(&alloc::format!("\\u{:04x}", c as u32));
                            }
                            _ => out.push(c),
                        }
                    }
                    out
                };
                let mut labels_json = alloc::string::String::from("{");
                for (i, (k, v)) in ci.labels.iter().enumerate() {
                    if i > 0 {
                        labels_json.push(',');
                    }
                    labels_json.push_str(&alloc::format!("\"{}\":\"{}\"", esc(k), esc(v)));
                }
                labels_json.push('}');
                let init_pid_json = match ci.init_pid {
                    Some(pid) => alloc::format!("{}", pid),
                    None => alloc::string::String::from("null"),
                };
                let exit_json = match ci.exit_code {
                    Some(code) => alloc::format!("{}", code),
                    None => alloc::string::String::from("null"),
                };
                // Health surfaces as a JSON string only when a healthcheck is
                // configured; otherwise `null` (Docker omits the Health object
                // for containers without a healthcheck).
                let health_json = if ci.has_healthcheck {
                    alloc::format!("\"{}\"", ci.health_status)
                } else {
                    alloc::string::String::from("null")
                };
                // User-defined-network memberships (Docker multi-network, §60).
                let mut networks_json = alloc::string::String::from("[");
                for (i, m) in ci.memberships.iter().enumerate() {
                    if i > 0 {
                        networks_json.push(',');
                    }
                    networks_json.push_str(&alloc::format!(
                        "{{\"name\":\"{}\",\"ip\":\"{}\",\"veth\":{}}}",
                        esc(&m.network_name), fmt_ipv4(m.ip), m.veth_pair
                    ));
                }
                networks_json.push(']');
                crate::console_println!(
                    "{{\"id\":{},\"name\":\"{}\",\"state\":\"{}\",\"paused\":{},\"health\":{},\"exit_code\":{},\"restart_policy\":\"{}\",\"restart_count\":{},\"auto_remove\":{},\"init_pid\":{},\"processes\":{},\"rootfs\":\"{}\",\"hostname\":\"{}\",\"pid_ns\":{},\"user_ns\":{},\"net_ns\":{},\"cgroup\":{},\"created_seq\":{},\"networks\":{},\"labels\":{}}}",
                    id,
                    esc(&ci.name),
                    ci.state,
                    ci.frozen,
                    health_json,
                    exit_json,
                    ci.restart_policy,
                    ci.restart_count,
                    ci.auto_remove,
                    init_pid_json,
                    ci.nr_procs,
                    esc(&ci.root_path),
                    esc(&ci.hostname),
                    ci.pid_ns,
                    ci.user_ns,
                    ci.net_ns,
                    ci.cgroup_id,
                    ci.created_seq,
                    networks_json,
                    labels_json,
                );
                return;
            }
            crate::console_println!("=== Container {} ===", id);
            crate::console_println!("  Name:       {}", ci.name);
            // A frozen running container shows "running (paused)" (Docker
            // reports paused as a sub-state of running).
            if ci.frozen {
                crate::console_println!("  State:      {} (paused)", ci.state);
            } else {
                crate::console_println!("  State:      {}", ci.state);
            }
            // Health (Docker `HEALTHCHECK`): shown only when a healthcheck is
            // configured; the failure streak is appended while unhealthy.
            if ci.has_healthcheck {
                if ci.health_status == container::HealthStatus::Unhealthy {
                    crate::console_println!(
                        "  Health:     {} (failing streak: {})",
                        ci.health_status, ci.health_fail_streak
                    );
                } else {
                    crate::console_println!("  Health:     {}", ci.health_status);
                }
            }
            // Docker's "Exited (N)": show the init process's recorded exit
            // code once the container has stopped.
            if let Some(code) = ci.exit_code {
                crate::console_println!("  Exit code:  {}", code);
            }
            // Restart policy (Docker `--restart`); show the auto-restart count
            // only when a policy other than `no` is in effect.
            if ci.restart_policy == container::RestartPolicy::No {
                crate::console_println!("  Restart:    {}", ci.restart_policy);
            } else {
                crate::console_println!(
                    "  Restart:    {} (restarts: {})",
                    ci.restart_policy, ci.restart_count
                );
            }
            if ci.auto_remove {
                crate::console_println!("  AutoRemove: yes (--rm)");
            }
            crate::console_println!("  Processes:  {}", ci.nr_procs);
            match ci.init_pid {
                Some(pid) => crate::console_println!("  Init PID:   {}", pid),
                None => crate::console_println!("  Init PID:   (not run)"),
            }
            if ci.root_path.is_empty() {
                crate::console_println!("  Rootfs:     (host root)");
            } else {
                crate::console_println!("  Rootfs:     {}", ci.root_path);
            }
            crate::console_println!("  PID NS:     {}", ci.pid_ns);
            crate::console_println!("  User NS:    {}", ci.user_ns);
            crate::console_println!("  Net NS:     {}", ci.net_ns);
            crate::console_println!("  Cgroup:     {}", ci.cgroup_id);
            // Show sub-resource details.
            if let Some(s) = crate::userns::stats(ci.user_ns) {
                crate::console_println!("  UID maps:   {}", s.uid_map_count);
                crate::console_println!("  GID maps:   {}", s.gid_map_count);
            }
            if let Some(pair_id) = ci.veth_pair {
                crate::console_println!("  Veth pair:  {} (host A <-> container B)", pair_id);
            }
            // User-defined-network memberships (Docker multi-network, §60).
            if !ci.memberships.is_empty() {
                crate::console_println!("  Networks:");
                for m in &ci.memberships {
                    crate::console_println!(
                        "    {} -> ip {} (veth {})",
                        m.network_name, fmt_ipv4(m.ip), m.veth_pair
                    );
                }
            }
            if let Some(s) = crate::netns::stats(ci.net_ns) {
                if s.iface_up {
                    crate::console_println!("  Net IP:     {}", s.ip);
                } else {
                    crate::console_println!("  Net IP:     (not configured)");
                }
                crate::console_println!("  Routes:     {}", s.route_count);
            }
            if let Some(s) = crate::cgroup::stats(ci.cgroup_id) {
                if s.cpu_quota > 0 {
                    crate::console_println!("  CPU quota:  {} ticks/period", s.cpu_quota);
                }
                if s.mem_limit > 0 {
                    crate::console_println!("  Mem limit:  {} frames", s.mem_limit);
                }
            }
            if !ci.hostname.is_empty() {
                crate::console_println!("  Hostname:   {}", ci.hostname);
            }
            for (k, v) in &ci.labels {
                crate::console_println!("  Label:      {}={}", k, v);
            }
        }
        "top" | "ps-in" => {
            // container top <id>  —  list the processes running inside a
            // container (Docker `top`), with each process's live state and
            // name resolved from the process table.
            let Some(id_str) = parts.get(1) else {
                crate::console_println!("Usage: container top <id>");
                return;
            };
            let Ok(id) = id_str.parse::<u32>() else {
                crate::console_println!("Invalid container ID");
                return;
            };
            let Some(pids) = container::pids(id) else {
                crate::console_println!("Container {} not found", id);
                return;
            };
            if pids.is_empty() {
                crate::console_println!("Container {} has no running processes.", id);
                return;
            }
            crate::console_println!("=== Container {} processes ({}) ===", id, pids.len());
            crate::console_println!("{:<8} {:<10} {}", "PID", "State", "Name");
            for pid in pids {
                // The process may exit between the snapshot and the lookup;
                // show "(gone)" rather than dropping the row so the count
                // still matches the header.
                let state = match crate::proc::pcb::state(pid) {
                    Some(s) => alloc::format!("{:?}", s),
                    None => alloc::string::String::from("(gone)"),
                };
                let name = crate::proc::pcb::name(pid)
                    .unwrap_or_else(|| alloc::string::String::from("(gone)"));
                crate::console_println!("{:<8} {:<10} {}", pid, state, name);
            }
        }
        "stats" => {
            // container stats <id>  —  live resource usage from the
            // container's cgroup (Docker `stats`): CPU ticks, memory, I/O,
            // PIDs, and throttle counts.  Memory/I/O byte figures are stored
            // as 16 KiB frame counts; we surface both frames and MiB.
            let Some(id_str) = parts.get(1) else {
                // No id: one-shot table of every running container's cgroup
                // usage (Docker `docker stats --no-stream`).  We do not stream
                // (the shell has no interactive interrupt), so this is a single
                // snapshot rather than a live refresh.
                let running: alloc::vec::Vec<_> = container::list()
                    .into_iter()
                    .filter(|(_, _, st)| *st == container::ContainerState::Running)
                    .collect();
                if running.is_empty() {
                    crate::console_println!("(no running containers)");
                    return;
                }
                crate::console_println!(
                    "{:>4}  {:<20} {:>8} {:>10} {:>6}", "ID", "NAME", "CPU", "MEM(MiB)", "TASKS"
                );
                for (rid, rname, _) in running {
                    let Some(rci) = container::info(rid) else { continue };
                    match crate::cgroup::stats(rci.cgroup_id) {
                        Some(cg) => {
                            // 16 KiB per frame: MiB = frames / 64.
                            let mem_mib = cg.mem_usage / 64;
                            let name_disp = if rname.len() > 20 {
                                rname.get(..20).unwrap_or(&rname)
                            } else {
                                &rname
                            };
                            crate::console_println!(
                                "{:>4}  {:<20} {:>8} {:>10} {:>6}",
                                rid, name_disp, cg.cpu_used, mem_mib, cg.nr_tasks
                            );
                        }
                        None => crate::console_println!(
                            "{:>4}  {:<20} {:>8} {:>10} {:>6}", rid, rname, "-", "-", "-"
                        ),
                    }
                }
                return;
            };
            let Ok(id) = id_str.parse::<u32>() else {
                crate::console_println!("Invalid container ID");
                return;
            };
            let Some(ci) = container::info(id) else {
                crate::console_println!("Container {} not found", id);
                return;
            };
            let Some(cg) = crate::cgroup::stats(ci.cgroup_id) else {
                crate::console_println!(
                    "Container {} has no cgroup stats (cgroup {} inactive)",
                    id, ci.cgroup_id
                );
                return;
            };
            // 16 KiB per frame: MiB = frames / 64 (1024 KiB / 16 KiB).
            let frames_to_mib = |frames: u64| frames / 64;
            crate::console_println!("=== Container {} stats ({}) ===", id, ci.name);
            crate::console_println!("  Tasks:      {}", cg.nr_tasks);
            // CPU.
            if cg.cpu_quota > 0 {
                crate::console_println!(
                    "  CPU:        {} / {} ticks this period (throttled {}x)",
                    cg.cpu_used, cg.cpu_quota, cg.cpu_throttle_count
                );
            } else {
                crate::console_println!(
                    "  CPU:        {} ticks this period (unlimited)",
                    cg.cpu_used
                );
            }
            // Memory.
            if cg.mem_limit > 0 {
                crate::console_println!(
                    "  Memory:     {} / {} frames ({} / {} MiB), peak {} frames",
                    cg.mem_usage, cg.mem_limit,
                    frames_to_mib(cg.mem_usage), frames_to_mib(cg.mem_limit),
                    cg.mem_peak
                );
            } else {
                crate::console_println!(
                    "  Memory:     {} frames ({} MiB) of unlimited, peak {} frames",
                    cg.mem_usage, frames_to_mib(cg.mem_usage), cg.mem_peak
                );
            }
            // I/O (bytes stored as frame counts).
            let io_limited = cg.io_ops_limit > 0 || cg.io_bytes_limit > 0;
            if io_limited {
                crate::console_println!(
                    "  I/O:        {} ops, {} frames ({} MiB) this period (throttled {}x)",
                    cg.io_ops_used, cg.io_bytes_used,
                    frames_to_mib(cg.io_bytes_used), cg.io_throttle_count
                );
            } else {
                crate::console_println!(
                    "  I/O:        {} ops, {} frames ({} MiB) this period (unlimited)",
                    cg.io_ops_used, cg.io_bytes_used, frames_to_mib(cg.io_bytes_used)
                );
            }
        }
        "update" => {
            // container update <id> [--cpus N[.M]] [--memory SIZE] [--restart POLICY]
            //
            // Docker `update`: change a running container's CPU and/or memory
            // limits in place (applied to its cgroup, affecting live
            // processes), and/or its restart policy. A value of 0 (`--cpus 0` /
            // `--memory 0`) sets the corresponding limit to unlimited. At least
            // one field is required.
            let Some(id_str) = parts.get(1) else {
                crate::console_println!(
                    "Usage: container update <id> [--cpus N] [--memory SIZE] [--restart POLICY]"
                );
                return;
            };
            let Ok(id) = id_str.parse::<u32>() else {
                crate::console_println!("Invalid container ID");
                return;
            };
            let mut cpu_percent: Option<u64> = None;
            let mut mem_frames: Option<u64> = None;
            let mut restart: Option<container::RestartPolicy> = None;
            let mut i = 2;
            while let Some(&arg) = parts.get(i) {
                // Accept both `--restart POLICY` (separate token) and
                // `--restart=POLICY` (Docker's `=` form).
                if let Some(val) = arg
                    .strip_prefix("--restart=")
                    .or_else(|| arg.strip_prefix("restart="))
                {
                    match container::parse_restart_policy(val) {
                        Some(p) => restart = Some(p),
                        None => {
                            crate::console_println!(
                                "Invalid restart policy '{}' (want no|always|unless-stopped|on-failure[:N])",
                                val
                            );
                            return;
                        }
                    }
                    i += 1;
                    continue;
                }
                if arg == "--restart" {
                    let Some(&val) = parts.get(i + 1) else {
                        crate::console_println!("--restart requires a value");
                        return;
                    };
                    match container::parse_restart_policy(val) {
                        Some(p) => restart = Some(p),
                        None => {
                            crate::console_println!(
                                "Invalid restart policy '{}' (want no|always|unless-stopped|on-failure[:N])",
                                val
                            );
                            return;
                        }
                    }
                    i += 2;
                    continue;
                }
                match arg {
                    "--cpus" => {
                        let Some(&val) = parts.get(i + 1) else {
                            crate::console_println!("--cpus requires a value");
                            return;
                        };
                        // "0" explicitly means unlimited; parse_cpus_to_percent
                        // returns None for 0, so treat it specially.
                        if val == "0" {
                            cpu_percent = Some(0);
                        } else {
                            match parse_cpus_to_percent(val) {
                                Some(p) => cpu_percent = Some(p),
                                None => {
                                    crate::console_println!("Invalid --cpus value: {}", val);
                                    return;
                                }
                            }
                        }
                        i += 2;
                    }
                    "--memory" | "-m" => {
                        let Some(&val) = parts.get(i + 1) else {
                            crate::console_println!("--memory requires a value");
                            return;
                        };
                        if val == "0" {
                            mem_frames = Some(0);
                        } else {
                            match parse_mem_size_to_frames(val) {
                                Some(f) => mem_frames = Some(f),
                                None => {
                                    crate::console_println!("Invalid --memory value: {}", val);
                                    return;
                                }
                            }
                        }
                        i += 2;
                    }
                    other => {
                        crate::console_println!("Unknown option: {}", other);
                        return;
                    }
                }
            }
            if cpu_percent.is_none() && mem_frames.is_none() && restart.is_none() {
                crate::console_println!(
                    "Usage: container update <id> [--cpus N] [--memory SIZE] [--restart POLICY] (at least one)"
                );
                return;
            }
            // Apply the restart-policy change first (it can't fail on a valid
            // id and doesn't touch the cgroup), then the resource limits.
            if let Some(policy) = restart {
                match container::set_restart_policy(id, policy) {
                    Ok(()) => crate::console_println!(
                        "Container {} restart policy: {}", id, policy
                    ),
                    Err(e) => {
                        crate::console_println!("Error: {:?}", e);
                        return;
                    }
                }
            }
            if cpu_percent.is_some() || mem_frames.is_some() {
                match container::update_resources(id, cpu_percent, mem_frames) {
                    Ok(()) => {
                        if let Some(p) = cpu_percent {
                            if p == 0 {
                                crate::console_println!("Container {} CPU: unlimited", id);
                            } else {
                                crate::console_println!("Container {} CPU: {}%", id, p);
                            }
                        }
                        if let Some(f) = mem_frames {
                            if f == 0 {
                                crate::console_println!("Container {} memory: unlimited", id);
                            } else {
                                crate::console_println!(
                                    "Container {} memory: {} frames ({} MiB)",
                                    id, f, f / 64
                                );
                            }
                        }
                    }
                    Err(e) => crate::console_println!("Error: {:?}", e),
                }
            }
        }
        "rename" => {
            // container rename <id> <new-name>  (Docker `rename`)
            let Some(id_str) = parts.get(1) else {
                crate::console_println!("Usage: container rename <id> <new-name>");
                return;
            };
            let Ok(id) = id_str.parse::<u32>() else {
                crate::console_println!("Invalid container ID");
                return;
            };
            let Some(&new_name) = parts.get(2) else {
                crate::console_println!("Usage: container rename <id> <new-name>");
                return;
            };
            match container::rename(id, new_name) {
                Ok(()) => crate::console_println!("Container {} renamed to '{}'", id, new_name),
                Err(e) => crate::console_println!("Error: {:?}", e),
            }
        }
        "kill" => {
            // container kill <id> [id...]  (Docker `kill`): force-terminate the
            // container by killing all its processes; the init's exit
            // auto-stops the container with exit code 137.
            if parts.len() < 2 {
                crate::console_println!("Usage: container kill <id> [id...]");
                return;
            }
            for &id_str in parts.iter().skip(1) {
                let Ok(id) = id_str.parse::<u32>() else {
                    crate::console_println!("Invalid container ID '{}'", id_str);
                    continue;
                };
                match container::kill(id) {
                    Ok(0) => crate::console_println!("Container {}: no running processes to kill", id),
                    Ok(n) => crate::console_println!("Container {}: killed {} process(es)", id, n),
                    Err(e) => crate::console_println!("Container {}: Error: {:?}", id, e),
                }
            }
        }
        "port" => {
            // container port <id>  (Docker `port`): list the container's
            // published port mappings (`-p host:container[/proto]`) in the
            // form `CONTAINER/PROTO -> HOST`, matching Docker's output.
            let Some(id_str) = parts.get(1) else {
                crate::console_println!("Usage: container port <id>");
                return;
            };
            let Ok(id) = id_str.parse::<u32>() else {
                crate::console_println!("Invalid container ID");
                return;
            };
            let Some(ports) = container::published_ports(id) else {
                crate::console_println!("Container {} not found", id);
                return;
            };
            if ports.is_empty() {
                crate::console_println!("Container {} publishes no ports.", id);
                return;
            }
            for (proto, host_port, container_port) in ports {
                let p = match proto {
                    crate::net::nat::NatProto::Tcp => "tcp",
                    crate::net::nat::NatProto::Udp => "udp",
                };
                // Docker renders forwards as `80/tcp -> 0.0.0.0:8080`.
                crate::console_println!("{}/{} -> 0.0.0.0:{}", container_port, p, host_port);
            }
        }
        "wait" => {
            // container wait <id>  (Docker `wait`): block until the container
            // reaches a terminal state (stopped/failed), then print its init
            // exit code.  Uses the event-driven `container::wait`, which parks
            // the shell task on the container's init process and is woken by the
            // scheduler when it exits — no CPU-burning poll loop.
            let Some(id_str) = parts.get(1) else {
                crate::console_println!("Usage: container wait <id>");
                return;
            };
            let Ok(id) = id_str.parse::<u32>() else {
                crate::console_println!("Invalid container ID");
                return;
            };
            match container::wait(id) {
                Ok(container::WaitOutcome::Exited(code)) => {
                    crate::console_println!("{}", code);
                }
                Ok(container::WaitOutcome::Removed) => {
                    crate::console_println!("Container {} removed while waiting", id);
                }
                Err(_) => {
                    crate::console_println!("Container {} not found", id);
                }
            }
        }
        "diff" => {
            // container diff <id>  (Docker `diff`): list filesystem changes in
            // the container relative to its image — A (added), C (changed),
            // D (deleted) — by inspecting the overlay's writable upper layer.
            let Some(id_str) = parts.get(1) else {
                crate::console_println!("Usage: container diff <id>");
                return;
            };
            let Ok(id) = id_str.parse::<u32>() else {
                crate::console_println!("Invalid container ID");
                return;
            };
            match container::diff(id) {
                Ok(changes) => {
                    if changes.is_empty() {
                        crate::console_println!("(no changes)");
                    } else {
                        for c in &changes {
                            crate::console_println!("{} {}", c.kind.prefix(), c.path);
                        }
                    }
                }
                Err(crate::error::KernelError::InvalidArgument) => {
                    crate::console_println!(
                        "Container {} has no overlay rootfs (nothing to diff)", id
                    );
                }
                Err(e) => crate::console_println!("Container {}: Error: {:?}", id, e),
            }
        }
        "pause" => {
            // container pause <id> [id...]  (Docker `pause`): freeze the
            // container, suspending all of its threads until `unpause`.
            if parts.len() < 2 {
                crate::console_println!("Usage: container pause <id> [id...]");
                return;
            }
            for &id_str in parts.iter().skip(1) {
                let Ok(id) = id_str.parse::<u32>() else {
                    crate::console_println!("Invalid container ID '{}'", id_str);
                    continue;
                };
                match container::pause(id) {
                    Ok(n) => crate::console_println!("Container {} paused ({} thread(s) suspended)", id, n),
                    Err(e) => crate::console_println!("Container {}: Error: {:?}", id, e),
                }
            }
        }
        "unpause" | "resume" => {
            // container unpause <id> [id...]  (Docker `unpause`): thaw a frozen
            // container, resuming all of its threads.
            if parts.len() < 2 {
                crate::console_println!("Usage: container unpause <id> [id...]");
                return;
            }
            for &id_str in parts.iter().skip(1) {
                let Ok(id) = id_str.parse::<u32>() else {
                    crate::console_println!("Invalid container ID '{}'", id_str);
                    continue;
                };
                match container::unpause(id) {
                    Ok(n) => crate::console_println!("Container {} unpaused ({} thread(s) resumed)", id, n),
                    Err(e) => crate::console_println!("Container {}: Error: {:?}", id, e),
                }
            }
        }
        "rootfs" => {
            // container rootfs <id> <host-path>
            //
            // Configures the container's filesystem root (chroot) before it
            // is run.  Every process launched by `container run` is jailed
            // to this host subtree: it resolves `/bin/sh`, `/lib/...`, etc.
            // against the rootfs, and `..` cannot escape it.  Must be set
            // while the container is still in the Created state.
            let Some(id_str) = parts.get(1) else {
                crate::console_println!("Usage: container rootfs <id> <host-path>");
                return;
            };
            let Ok(id) = id_str.parse::<u32>() else {
                crate::console_println!("Invalid container ID");
                return;
            };
            let Some(&path) = parts.get(2) else {
                crate::console_println!("Usage: container rootfs <id> <host-path>");
                return;
            };
            match container::set_root_path(id, path) {
                Ok(()) => crate::console_println!(
                    "Container {} rootfs set to '{}'", id, path
                ),
                Err(e) => crate::console_println!("Error: {:?}", e),
            }
        }
        "run" => {
            // container run <id> <elf-path> [args...]
            //
            // Launches a real init process inside an existing (Created)
            // container: loads the ELF from the host VFS, binds the process
            // to the container's cgroup (Q14 billing) + PID/user/network
            // namespaces, jails it to the container's rootfs (if one was set
            // via `container rootfs`), and transitions Created → Running.
            //
            // NOTE: the ELF path passed here is resolved against the *host*
            // filesystem (the kernel reads the image before the jail takes
            // effect).  Once the process is running, its own syscalls
            // resolve against the container rootfs.  Give an absolute host
            // path to the binary you want as the container's init process.
            let Some(id_str) = parts.get(1) else {
                crate::console_println!("Usage: container run <id> <elf-path> [args...]");
                return;
            };
            let Ok(id) = id_str.parse::<u32>() else {
                crate::console_println!("Invalid container ID");
                return;
            };
            let Some(&path) = parts.get(2) else {
                crate::console_println!("Usage: container run <id> <elf-path> [args...]");
                return;
            };

            // Delegate to run_path: it reads the ELF from the host VFS, builds
            // argv (argv[0] = path, then extra args), launches the init
            // process, and records the launch spec so the container can later
            // be restarted (`container restart`).
            let extra_args: alloc::vec::Vec<&str> = parts.iter().skip(3).copied().collect();
            match container::run_path(id, path, &extra_args) {
                Ok(pid) => {
                    crate::console_println!(
                        "Container {} running: init pid={} (ELF: {})",
                        id, pid, path
                    );
                }
                Err(e) => crate::console_println!("Error: {:?}", e),
            }
        }
        "restart" => {
            // container restart <id> [id...]  (Docker `restart`): re-launch each
            // container's recorded init command (from the last `run`).
            if parts.len() < 2 {
                crate::console_println!("Usage: container restart <id> [id...]");
                return;
            }
            for &id_str in parts.iter().skip(1) {
                let Ok(id) = id_str.parse::<u32>() else {
                    crate::console_println!("Invalid container ID '{}'", id_str);
                    continue;
                };
                match container::restart(id) {
                    Ok(pid) => crate::console_println!(
                        "Container {} restarted: init pid={}", id, pid
                    ),
                    Err(e) => crate::console_println!("Container {}: Error: {:?}", id, e),
                }
            }
        }
        "cp" => {
            // container cp <src> <dest>  (Docker `cp`): copy a file between the
            // host VFS and a container's rootfs.  Exactly one of <src>/<dest>
            // is a container reference of the form `ID:/path`; the other is a
            // plain host VFS path.
            let (Some(&src), Some(&dst)) = (parts.get(1), parts.get(2)) else {
                crate::console_println!("Usage: container cp <src> <dest>  (one side is ID:/path)");
                return;
            };
            // Parse "ID:/path" into (id, path); a plain host path yields None.
            let parse_ref = |s: &str| -> Option<(u32, alloc::string::String)> {
                let (left, right) = s.split_once(':')?;
                let id = left.parse::<u32>().ok()?;
                Some((id, alloc::string::String::from(right)))
            };
            use crate::fs::vfs::{EntryType, Vfs};
            match (parse_ref(src), parse_ref(dst)) {
                (Some((id, cpath)), None) => {
                    // container -> host.  Directories are copied recursively via
                    // a tar transfer; regular files copy their bytes directly.
                    match container::entry_kind_in_container(id, &cpath) {
                        Ok(EntryType::Directory) => {
                            match container::copy_dir_from_container(id, &cpath) {
                                Ok(archive) => match container::untar_tree(dst, &archive) {
                                    Ok(()) => crate::console_println!(
                                        "Copied directory {}:{} -> {} ({} bytes archived)",
                                        id, cpath, dst, archive.len()
                                    ),
                                    Err(e) => crate::console_println!(
                                        "Failed to extract into '{}': {:?}", dst, e
                                    ),
                                },
                                Err(e) => crate::console_println!("Error: {:?}", e),
                            }
                        }
                        Ok(_) => match container::copy_from_container(id, &cpath) {
                            Ok(data) => match Vfs::write_file(dst, &data) {
                                Ok(()) => crate::console_println!(
                                    "Copied {} bytes from container {}:{} to {}",
                                    data.len(), id, cpath, dst
                                ),
                                Err(e) => crate::console_println!("Failed to write '{}': {:?}", dst, e),
                            },
                            Err(e) => crate::console_println!("Error: {:?}", e),
                        },
                        Err(e) => crate::console_println!("Error: {:?}", e),
                    }
                }
                (None, Some((id, cpath))) => {
                    // host -> container.  A host directory is copied recursively
                    // via a tar transfer; a regular file copies its bytes.
                    match Vfs::stat(src) {
                        Ok(meta) if meta.entry_type == EntryType::Directory => {
                            match container::tar_tree(src) {
                                Ok(archive) => match container::copy_dir_to_container(id, &cpath, &archive) {
                                    Ok(()) => crate::console_println!(
                                        "Copied directory {} -> {}:{} ({} bytes archived)",
                                        src, id, cpath, archive.len()
                                    ),
                                    Err(e) => crate::console_println!("Error: {:?}", e),
                                },
                                Err(e) => crate::console_println!(
                                    "Failed to archive '{}': {:?}", src, e
                                ),
                            }
                        }
                        Ok(_) => match Vfs::read_file(src) {
                            Ok(data) => match container::copy_to_container(id, &cpath, &data) {
                                Ok(()) => crate::console_println!(
                                    "Copied {} bytes from {} to container {}:{}",
                                    data.len(), src, id, cpath
                                ),
                                Err(e) => crate::console_println!("Error: {:?}", e),
                            },
                            Err(e) => crate::console_println!("Failed to read '{}': {:?}", src, e),
                        },
                        Err(e) => crate::console_println!("Failed to stat '{}': {:?}", src, e),
                    }
                }
                (Some(_), Some(_)) => {
                    crate::console_println!("cp between two containers is not supported");
                }
                (None, None) => {
                    crate::console_println!("One of <src>/<dest> must be a container ref (ID:/path)");
                }
            }
        }
        "exec" => {
            // container exec <id> <kshell-command...>   (Q17/§58, option B)
            //
            // The *netns-debug facade*: temporarily enter the container's
            // network namespace, run a **kshell builtin** there (so DNS/TCP/UDP
            // operations resolve inside the container's netns), then restore the
            // caller's namespace. This is deliberately NOT Docker `docker exec`
            // semantics — it runs a shell builtin, not a process from the
            // container rootfs. For a *real* in-container process launch use
            // `container run-in` (or the `container exec --rootfs` alias below,
            // which is what `docker exec` maps to).
            //
            // `container exec --rootfs [-d] <id> <path> [args...]` is an alias
            // for `run-in`: launch a genuine process from the container rootfs.
            if parts.get(1).copied() == Some("--rootfs") {
                container_exec_rootfs(parts.get(2..).unwrap_or(&[]));
                return;
            }

            let Some(id_str) = parts.get(1) else {
                crate::console_println!("Usage: container exec <id> <kshell-command...>");
                crate::console_println!("       container exec --rootfs [-d] [-w DIR] <id> <path> [args...]  (real rootfs exec)");
                return;
            };
            let Ok(id) = id_str.parse::<u32>() else {
                crate::console_println!("Invalid container ID");
                return;
            };
            // The command tail is everything in the raw arg string after the id
            // token (preserves the builtin's own argument spacing for `execute`).
            let cmd_offset = args.find(id_str).unwrap_or(0);
            let after_id = args.get(cmd_offset..).unwrap_or("").trim_start();
            let after_id = after_id.strip_prefix(id_str).unwrap_or("").trim_start();
            if after_id.is_empty() {
                crate::console_println!("Usage: container exec <id> <kshell-command...>");
                return;
            }

            // Look up the container's network namespace and verify it is running.
            let Some((_, _, net_ns)) = container::namespace_ids(id) else {
                crate::console_println!("Container {} not found", id);
                return;
            };
            let Some(ci) = container::info(id) else {
                crate::console_println!("Container {} not found", id);
                return;
            };
            if !matches!(ci.state, container::ContainerState::Running) {
                crate::console_println!(
                    "Container {} is not running (state: {:?})", id, ci.state
                );
                return;
            }

            // Save the caller's namespace, switch to the container's netns, run
            // the builtin, then restore — so DNS/TCP/UDP use the container's
            // network stack for the duration of this one command.
            let task_id = crate::sched::current_task_id();
            let orig_ns = crate::sched::current_task_net_ns();
            if let Err(e) = crate::sched::set_task_net_ns(task_id, net_ns) {
                crate::console_println!("Failed to enter namespace: {:?}", e);
                return;
            }
            crate::console_println!("[exec] Entering container {} (net_ns={})", id, net_ns);
            execute(after_id);
            let _ = crate::sched::set_task_net_ns(task_id, orig_ns);
            crate::console_println!("[exec] Exited container {} namespace", id);
        }
        "run-in" => {
            // container run-in [-d] <id> <path> [args...]   (Q17/§58, option B)
            //
            // Real in-container process launch (Docker `docker exec` semantics):
            // read <path> from the container's rootfs and spawn it as a genuine
            // process bound into the container's cgroup + PID/user/network
            // namespaces + rootfs jail. Foreground (default) blocks until it
            // exits and prints the status; `-d` detaches and prints the pid.
            container_exec_rootfs(parts.get(1..).unwrap_or(&[]));
        }
        "prune" => {
            // container prune  (Docker `container prune`): remove all stopped
            // containers (Stopped/Failed).  Created and running containers are
            // preserved.
            let removed = container::prune();
            crate::console_println!("Removed {} stopped container(s)", removed);
        }
        "system" => {
            // container system <df|prune>  (Docker `docker system df` /
            // `docker system prune`): aggregate disk usage across the three
            // runtime registries, and a combined reclaim sweep.
            match parts.get(1).copied() {
                Some("df") => {
                    // Docker `system df`: a per-type usage summary. Counts come
                    // straight from the registries; volume "size" is the summed
                    // byte total of each volume's backing tree (walked on the
                    // host VFS). Images are directory-referenced (no name-keyed
                    // store), so there is no image row to total.
                    let cts = container::list();
                    let total_ct = cts.len();
                    let running_ct = cts
                        .iter()
                        .filter(|(_, _, st)| *st == container::ContainerState::Running)
                        .count();
                    let vols = crate::volume::list();
                    let mut vol_bytes: u64 = 0;
                    for v in &vols {
                        vol_bytes = vol_bytes.saturating_add(crate::volume::backing_size(v));
                    }
                    let nets = crate::cnetwork::count();
                    let active_nets = crate::cnetwork::list()
                        .iter()
                        .filter(|n| !n.allocations.is_empty())
                        .count();
                    crate::console_println!("TYPE            TOTAL     ACTIVE    SIZE");
                    crate::console_println!(
                        "Containers      {:<9} {:<9} -", total_ct, running_ct
                    );
                    crate::console_println!(
                        "Volumes         {:<9} {:<9} {}",
                        vols.len(), "-", format_size_human(vol_bytes)
                    );
                    crate::console_println!(
                        "Networks        {:<9} {:<9} -", nets, active_nets
                    );
                }
                Some("prune") => {
                    // Docker `system prune`: reclaim stopped containers and
                    // unused (zero-allocation) networks. Volumes are NOT pruned:
                    // our runtime does not track per-volume usage, so "unused"
                    // is undeterminable — sweeping them could delete live data.
                    // (Docker likewise leaves volumes alone without --volumes.)
                    let ct_removed = container::prune();
                    let net_removed = crate::cnetwork::prune();
                    crate::console_println!(
                        "Removed {} stopped container(s), {} unused network(s)",
                        ct_removed, net_removed
                    );
                    crate::console_println!(
                        "Volumes left intact (usage is untracked; remove explicitly with `container volume remove`)"
                    );
                }
                _ => {
                    crate::console_println!("Usage: container system <df|prune>");
                    crate::console_println!("  container system df     — disk usage by containers/volumes/networks");
                    crate::console_println!("  container system prune  — remove stopped containers + unused networks");
                }
            }
        }
        "export" => {
            // container export <id> <host-tar-path>  (Docker `export`): pack the
            // container's rootfs into a tar archive written to the host VFS.
            let (Some(id_str), Some(&out_path)) = (parts.get(1), parts.get(2)) else {
                crate::console_println!("Usage: container export <id> <host-tar-path>");
                return;
            };
            let Ok(id) = id_str.parse::<u32>() else {
                crate::console_println!("Invalid container ID");
                return;
            };
            match container::export_rootfs(id) {
                Ok(archive) => match crate::fs::vfs::Vfs::write_file(out_path, &archive) {
                    Ok(()) => crate::console_println!(
                        "Exported container {} rootfs: {} bytes -> {}",
                        id, archive.len(), out_path
                    ),
                    Err(e) => crate::console_println!("Failed to write '{}': {:?}", out_path, e),
                },
                Err(e) => crate::console_println!("Error: {:?}", e),
            }
        }
        "import" => {
            // container import <host-tar-path> <name> <rootfs-dir>  (Docker
            // `import`): create a container named <name> whose rootfs is the
            // tar archive at <host-tar-path>, extracted into <rootfs-dir>.
            let (Some(&tar_path), Some(&name), Some(&dest_dir)) =
                (parts.get(1), parts.get(2), parts.get(3))
            else {
                crate::console_println!(
                    "Usage: container import <host-tar-path> <name> <rootfs-dir>"
                );
                return;
            };
            match crate::fs::vfs::Vfs::read_file(tar_path) {
                Ok(archive) => match container::import_rootfs(name, &archive, dest_dir) {
                    Ok(id) => crate::console_println!(
                        "Imported {} ({} bytes) -> container {} (rootfs {})",
                        tar_path, archive.len(), id, dest_dir
                    ),
                    Err(e) => crate::console_println!("Error: {:?}", e),
                },
                Err(e) => crate::console_println!("Failed to read '{}': {:?}", tar_path, e),
            }
        }
        "commit" => {
            // container commit <src-id> <new-name> <rootfs-dir>  (Docker
            // `commit`): snapshot a container's rootfs into a new, independent
            // container with its own rootfs at <rootfs-dir>.
            let (Some(id_str), Some(&new_name), Some(&dest_dir)) =
                (parts.get(1), parts.get(2), parts.get(3))
            else {
                crate::console_println!(
                    "Usage: container commit <src-id> <new-name> <rootfs-dir>"
                );
                return;
            };
            let Ok(src) = id_str.parse::<u32>() else {
                crate::console_println!("Invalid container ID");
                return;
            };
            match container::commit(src, new_name, dest_dir) {
                Ok(id) => crate::console_println!(
                    "Committed container {} -> container {} (rootfs {})",
                    src, id, dest_dir
                ),
                Err(e) => crate::console_println!("Error: {:?}", e),
            }
        }
        "logs" => {
            // container logs [--tail N] <id>  (Docker `logs`): print the
            // container init process's captured stdout+stderr.  `--tail N`
            // limits output to the last N lines (Docker `logs --tail`).
            let mut tail: Option<usize> = None;
            let mut id_str: Option<&str> = None;
            let mut li = 1;
            while li < parts.len() {
                match parts.get(li) {
                    Some(&"--tail") | Some(&"-n") => {
                        match parts.get(li.saturating_add(1)) {
                            Some(&"all") => {
                                tail = None;
                                li = li.saturating_add(2);
                            }
                            Some(n) => match n.parse::<usize>() {
                                Ok(v) => {
                                    tail = Some(v);
                                    li = li.saturating_add(2);
                                }
                                Err(_) => {
                                    crate::console_println!(
                                        "container logs: invalid --tail value '{}'", n
                                    );
                                    return;
                                }
                            },
                            None => {
                                crate::console_println!("container logs: --tail needs a value");
                                return;
                            }
                        }
                    }
                    Some(tok) => {
                        id_str = Some(tok);
                        li = li.saturating_add(1);
                    }
                    None => li = li.saturating_add(1),
                }
            }
            let Some(id_str) = id_str else {
                crate::console_println!("Usage: container logs [--tail N] ID");
                return;
            };
            let Ok(id) = id_str.parse::<u32>() else {
                crate::console_println!("Invalid container ID");
                return;
            };
            match container::logs(id) {
                Ok(data) => match core::str::from_utf8(&data) {
                    // Captured output is text: print it verbatim (or the last
                    // N lines under --tail).
                    Ok(text) => {
                        let out = match tail {
                            Some(n) => {
                                // Trailing newline shouldn't count as an empty
                                // final line; trim it before splitting, then
                                // keep the last N lines.
                                let trimmed = text.strip_suffix('\n').unwrap_or(text);
                                let lines: alloc::vec::Vec<&str> = trimmed.split('\n').collect();
                                let start = lines.len().saturating_sub(n);
                                lines.get(start..).unwrap_or(&[]).join("\n")
                            }
                            None => alloc::string::String::from(text.strip_suffix('\n').unwrap_or(text)),
                        };
                        if !out.is_empty() {
                            crate::console::write_str(&out);
                            crate::console_println!();
                        }
                    }
                    // Non-UTF-8 capture: don't force bytes through the text
                    // console — report the size (matches `cat`'s convention).
                    Err(_) => crate::console_println!(
                        "(binary log, {} bytes)", data.len()
                    ),
                },
                Err(e) => crate::console_println!("Error: {:?}", e),
            }
        }
        "events" => {
            // container events [-n N] [--id ID]  (Docker `events`): print the
            // recent container lifecycle event log (create/start/die/stop/kill/
            // pause/unpause/restart/destroy), oldest first.  We record a bounded
            // ring, so this is the recent window rather than the full history.
            let mut limit: usize = 0; // 0 = all retained events
            let mut filter_id: Option<u32> = None;
            let mut ei = 1;
            while ei < parts.len() {
                match parts.get(ei) {
                    Some(&"-n") | Some(&"--tail") => {
                        match parts.get(ei.saturating_add(1)).and_then(|n| n.parse::<usize>().ok()) {
                            Some(v) => {
                                limit = v;
                                ei = ei.saturating_add(2);
                            }
                            None => {
                                crate::console_println!("container events: -n needs a numeric value");
                                return;
                            }
                        }
                    }
                    Some(&"--id") | Some(&"-c") | Some(&"--container") => {
                        match parts.get(ei.saturating_add(1)).and_then(|n| n.parse::<u32>().ok()) {
                            Some(v) => {
                                filter_id = Some(v);
                                ei = ei.saturating_add(2);
                            }
                            None => {
                                crate::console_println!("container events: --id needs a container ID");
                                return;
                            }
                        }
                    }
                    Some(tok) => {
                        // Bare token: treat as a container ID filter (Docker allows
                        // `events --filter container=ID`; we accept the id directly).
                        match tok.parse::<u32>() {
                            Ok(v) => filter_id = Some(v),
                            Err(_) => {
                                crate::console_println!("container events: unknown argument '{}'", tok);
                                return;
                            }
                        }
                        ei = ei.saturating_add(1);
                    }
                    None => ei = ei.saturating_add(1),
                }
            }
            let events = container::events_snapshot(0, limit, filter_id);
            if events.is_empty() {
                crate::console_println!("(no container events recorded)");
            } else {
                for e in &events {
                    // Monotonic timestamp shown as seconds.milliseconds since boot
                    // (we have no wall clock in this context; relative time is the
                    // honest representation).
                    let secs = e.time_ns / 1_000_000_000;
                    let ms = (e.time_ns % 1_000_000_000) / 1_000_000;
                    let action = e.kind.action();
                    match e.exit_code {
                        Some(code) => crate::console_println!(
                            "{:>6}.{:03}s  container {:<8} id={} name={} (exit {})",
                            secs, ms, action, e.id, e.name, code
                        ),
                        None => crate::console_println!(
                            "{:>6}.{:03}s  container {:<8} id={} name={}",
                            secs, ms, action, e.id, e.name
                        ),
                    }
                }
            }
        }
        "volume" | "vol" => {
            // container volume <create|ls|rm|inspect|prune> ... (Docker
            // `docker volume`): manage named volumes — runtime-owned backing
            // directories mounted into containers via `-v NAME:/path`.
            let action = parts.get(1).copied().unwrap_or("ls");
            match action {
                "ls" | "list" => {
                    let names = crate::volume::list();
                    if names.is_empty() {
                        crate::console_println!("(no volumes)");
                    } else {
                        crate::console_println!("{:<24} {}", "NAME", "MOUNTPOINT");
                        for name in &names {
                            let mount = crate::volume::path_of(name).unwrap_or_default();
                            crate::console_println!("{:<24} {}", name, mount);
                        }
                    }
                }
                "create" => {
                    let Some(name) = parts.get(2) else {
                        crate::console_println!("Usage: container volume create NAME");
                        return;
                    };
                    match crate::volume::create(name) {
                        Ok(path) => crate::console_println!("{} ({})", name, path),
                        Err(e) => crate::console_println!("Error: {:?}", e),
                    }
                }
                "rm" | "remove" | "delete" => {
                    if parts.len() < 3 {
                        crate::console_println!("Usage: container volume rm NAME [NAME...]");
                        return;
                    }
                    for name in parts.iter().skip(2) {
                        match crate::volume::remove(name) {
                            Ok(()) => crate::console_println!("{}", name),
                            Err(e) => crate::console_println!("{}: {:?}", name, e),
                        }
                    }
                }
                "inspect" => {
                    let Some(name) = parts.get(2) else {
                        crate::console_println!("Usage: container volume inspect NAME");
                        return;
                    };
                    match crate::volume::path_of(name) {
                        Some(path) => {
                            crate::console_println!("Name:       {}", name);
                            crate::console_println!("Driver:     local");
                            crate::console_println!("Mountpoint: {}", path);
                        }
                        None => crate::console_println!("Volume '{}' not found", name),
                    }
                }
                "prune" => {
                    let n = crate::volume::prune();
                    crate::console_println!("Removed {} volume(s)", n);
                }
                other => {
                    crate::console_println!("Unknown volume action '{}'", other);
                    crate::console_println!("Usage: container volume <create|ls|rm|inspect|prune> ...");
                }
            }
        }
        "network" | "net" => {
            cmd_container_network(&parts);
        }
        "test" => {
            container::self_test();
        }
        _ => {
            crate::console_println!("Usage: container [list|create|delete|rootfs|run|restart|start|stop|kill|pause|unpause|prune|system|exec|cp|export|import|commit|logs|events|volume|network|info|top|stats|update|rename|port|wait|test]");
            crate::console_println!("  container [list] [-a] [-q] [-n N|-l] [--filter label=K[=V]|name=SUB|status=STATE] — list containers (-a: all, -q: IDs, -n/-l: last N/latest)");
            crate::console_println!("  container create NAME [cpu=%] [mem=] [uid=] [net=] [restart=POLICY] [rm] — create container");
            crate::console_println!("  container delete [-f] ID [ID...]         — delete container(s) (-f force-removes a running one)");
            crate::console_println!("  container rootfs ID <host-path>          — set filesystem root (chroot)");
            crate::console_println!("  container run ID <elf-path> [args...]    — launch init process in container");
            crate::console_println!("  container restart ID [ID...]             — re-launch the recorded init command");
            crate::console_println!("  container start ID [ID...]               — mark as running");
            crate::console_println!("  container stop ID [ID...]                — mark as stopped");
            crate::console_println!("  container kill ID [ID...]                — force-kill all container processes");
            crate::console_println!("  container pause ID [ID...]               — freeze (suspend all threads)");
            crate::console_println!("  container unpause ID [ID...]             — thaw (resume all threads)");
            crate::console_println!("  container prune                          — remove all stopped containers");
            crate::console_println!("  container system <df|prune>              — disk usage summary / reclaim stopped containers+unused networks");
            crate::console_println!("  container exec ID <kshell-command>       — netns-debug facade: run a kshell builtin in the container's network namespace");
            crate::console_println!("  container run-in [-d] ID <path> [args]   — run a real process from the container rootfs (docker exec; foreground waits + prints exit status; -d detaches)");
            crate::console_println!("  container exec --rootfs [-d] ID <path> [args]  — alias for run-in");
            crate::console_println!("  container cp <src> <dest>                — copy file/dir host<->rootfs (one side ID:/path)");
            crate::console_println!("  container export ID <host-tar-path>      — pack rootfs into a tar archive");
            crate::console_println!("  container import <tar> <name> <rootfs-dir> — create container from a tar archive");
            crate::console_println!("  container commit ID <name> <rootfs-dir>  — snapshot rootfs into a new container");
            crate::console_println!("  container logs [--tail N] ID             — print captured init stdout/stderr (--tail: last N lines)");
            crate::console_println!("  container events [-n N] [--id ID]        — recent lifecycle events (create/start/die/stop/kill/pause/restart/destroy)");
            crate::console_println!("  container volume <create|ls|rm|inspect|prune> NAME — manage named volumes (mount with -v NAME:/path)");
            crate::console_println!("  container network <create|ls|rm|inspect|prune> NAME [--subnet CIDR] [--gateway IP] — manage user-defined networks (IPAM)");
            crate::console_println!("  container info [--json] ID               — detailed inspection (--json: machine-readable)");
            crate::console_println!("  container top ID                         — list processes running in container");
            crate::console_println!("  container stats [ID]                     — cgroup resource usage (no ID: table of all running)");
            crate::console_println!("  container update ID [--cpus N] [--memory SIZE] [--restart POLICY] — change live limits/restart policy");
            crate::console_println!("  container rename ID <new-name>           — rename a container");
            crate::console_println!("  container port ID                        — list published port mappings");
            crate::console_println!("  container wait ID                        — block until container stops, print exit code");
            crate::console_println!("  container diff ID                        — list rootfs changes vs image (A/C/D)");
            crate::console_println!("  container test                           — run self-test");
            crate::console_println!();
            crate::console_println!("Aliases: ct");
        }
    }
}

/// Format a four-octet IPv4 address as a dotted-quad string.
fn fmt_ipv4(ip: [u8; 4]) -> alloc::string::String {
    let [a, b, c, d] = ip;
    alloc::format!("{a}.{b}.{c}.{d}")
}

/// Resolve a container name or numeric id to a [`crate::container::ContainerId`]
/// (Docker accepts either). A numeric reference is preferred when it names a
/// live container; otherwise the reference is matched against container names.
fn resolve_container_ref(reference: &str) -> Option<crate::container::ContainerId> {
    if let Ok(id) = reference.parse::<crate::container::ContainerId>() {
        if crate::container::info(id).is_some() {
            return Some(id);
        }
    }
    crate::container::list()
        .into_iter()
        .find(|(_, name, _)| name == reference)
        .map(|(id, _, _)| id)
}

/// `container network <create|ls|rm|inspect|prune>` — manage user-defined
/// container networks with IPAM (Docker `docker network`). `parts` is the
/// whitespace-split `container network ...` argv (so `parts[0]` == "network").
fn cmd_container_network(parts: &[&str]) {
    let action = parts.get(1).copied().unwrap_or("ls");
    match action {
        "ls" | "list" => {
            let nets = crate::cnetwork::list();
            if nets.is_empty() {
                crate::console_println!("(no networks)");
            } else {
                crate::console_println!(
                    "{:<20} {:<20} {:<16} {}", "NAME", "SUBNET", "GATEWAY", "IN-USE"
                );
                for n in &nets {
                    let subnet = alloc::format!(
                        "{}/{}", fmt_ipv4(n.network_addr), n.prefix_len
                    );
                    crate::console_println!(
                        "{:<20} {:<20} {:<16} {}",
                        n.name, subnet, fmt_ipv4(n.gateway), n.allocations.len()
                    );
                }
            }
        }
        "create" => {
            let Some(&name) = parts.get(2) else {
                crate::console_println!(
                    "Usage: container network create NAME [--subnet CIDR] [--gateway IP]"
                );
                return;
            };
            // Optional --subnet CIDR and --gateway IP flags.
            let mut subnet: Option<([u8; 4], u8)> = None;
            let mut gateway: Option<[u8; 4]> = None;
            let mut j = 3usize;
            while j < parts.len() {
                match parts.get(j).copied() {
                    Some("--subnet") => {
                        match parts.get(j.saturating_add(1)).copied() {
                            Some(cidr) => match crate::cnetwork::parse_cidr(cidr) {
                                Ok(v) => subnet = Some(v),
                                Err(_) => {
                                    crate::console_println!(
                                        "Invalid --subnet '{}' (want A.B.C.D/N)", cidr
                                    );
                                    return;
                                }
                            },
                            None => {
                                crate::console_println!("--subnet requires a CIDR argument");
                                return;
                            }
                        }
                        j = j.saturating_add(2);
                    }
                    Some("--gateway") => {
                        match parts.get(j.saturating_add(1)).copied() {
                            Some(ip) => match crate::cnetwork::parse_ipv4(ip) {
                                Ok(v) => gateway = Some(v),
                                Err(_) => {
                                    crate::console_println!(
                                        "Invalid --gateway '{}' (want A.B.C.D)", ip
                                    );
                                    return;
                                }
                            },
                            None => {
                                crate::console_println!("--gateway requires an IP argument");
                                return;
                            }
                        }
                        j = j.saturating_add(2);
                    }
                    Some(other) => {
                        crate::console_println!("Unknown network create flag '{}'", other);
                        return;
                    }
                    None => break,
                }
            }
            let result = match subnet {
                Some((net, pfx)) => {
                    crate::cnetwork::create_with_subnet(name, net, pfx, gateway)
                }
                None if gateway.is_some() => {
                    crate::console_println!("--gateway requires --subnet");
                    return;
                }
                None => crate::cnetwork::create(name),
            };
            match result {
                Ok(()) => match crate::cnetwork::inspect(name) {
                    Some(n) => crate::console_println!(
                        "{} ({}/{})", name, fmt_ipv4(n.network_addr), n.prefix_len
                    ),
                    None => crate::console_println!("{}", name),
                },
                Err(e) => crate::console_println!("Error: {:?}", e),
            }
        }
        "rm" | "remove" | "delete" => {
            if parts.len() < 3 {
                crate::console_println!("Usage: container network rm NAME [NAME...]");
                return;
            }
            for name in parts.iter().skip(2) {
                match crate::cnetwork::remove(name) {
                    Ok(()) => crate::console_println!("{}", name),
                    Err(e) => crate::console_println!("{}: {:?}", name, e),
                }
            }
        }
        "inspect" => {
            let Some(&name) = parts.get(2) else {
                crate::console_println!("Usage: container network inspect NAME");
                return;
            };
            match crate::cnetwork::inspect(name) {
                Some(n) => {
                    crate::console_println!("Name:       {}", name);
                    crate::console_println!("Driver:     local");
                    crate::console_println!(
                        "Subnet:     {}/{}", fmt_ipv4(n.network_addr), n.prefix_len
                    );
                    crate::console_println!("Gateway:    {}", fmt_ipv4(n.gateway));
                    if n.allocations.is_empty() {
                        crate::console_println!("Containers: (none)");
                    } else {
                        crate::console_println!("Containers:");
                        for (ip, owner) in &n.allocations {
                            match owner {
                                Some(id) => crate::console_println!(
                                    "  {} -> container {}", fmt_ipv4(*ip), id
                                ),
                                None => crate::console_println!(
                                    "  {} -> (reserved)", fmt_ipv4(*ip)
                                ),
                            }
                        }
                    }
                    if !n.dns_names.is_empty() {
                        crate::console_println!("DNS names:");
                        for (nm, ip) in &n.dns_names {
                            crate::console_println!("  {} -> {}", nm, fmt_ipv4(*ip));
                        }
                    }
                }
                None => crate::console_println!("Network '{}' not found", name),
            }
        }
        "prune" => {
            let n = crate::cnetwork::prune();
            crate::console_println!("Removed {} network(s)", n);
        }
        "resolve" | "lookup" => {
            // container network resolve NET NAME — Docker embedded-DNS query.
            let (Some(&net), Some(&query)) = (parts.get(2), parts.get(3)) else {
                crate::console_println!("Usage: container network resolve NET NAME");
                return;
            };
            match crate::cnetwork::resolve(net, query) {
                Some(ip) => crate::console_println!("{} -> {}", query, fmt_ipv4(ip)),
                None => crate::console_println!(
                    "{}: name does not resolve on network '{}'", query, net
                ),
            }
        }
        "connect" => {
            // container network connect NET CONTAINER — join a running/created
            // container to an additional user-defined network (Docker parity, §60).
            let (Some(&net), Some(&ctref)) = (parts.get(2), parts.get(3)) else {
                crate::console_println!("Usage: container network connect NET CONTAINER");
                return;
            };
            let Some(ct_id) = resolve_container_ref(ctref) else {
                crate::console_println!("Container '{}' not found", ctref);
                return;
            };
            // Embedded-DNS names for the new network: the container's name plus
            // its hostname (when set and distinct), matching the create-time flow.
            let cinfo = crate::container::info(ct_id);
            let mut names: alloc::vec::Vec<&str> = alloc::vec::Vec::new();
            if let Some(ci) = cinfo.as_ref() {
                if !ci.name.is_empty() {
                    names.push(ci.name.as_str());
                }
                if !ci.hostname.is_empty() && !ci.hostname.eq_ignore_ascii_case(&ci.name) {
                    names.push(ci.hostname.as_str());
                }
            }
            match crate::cnetwork::connect_container(net, ct_id, &names) {
                Ok(lease) => {
                    let peers = crate::cnetwork::inspect(net)
                        .map_or(0, |i| i.allocations.len());
                    crate::console_println!(
                        "{} connected to '{}' (ip {}, {} member{})",
                        ctref, net, fmt_ipv4(lease.ip), peers,
                        if peers == 1 { "" } else { "s" }
                    );
                }
                Err(e) => crate::console_println!("Error: {:?}", e),
            }
        }
        "disconnect" => {
            // container network disconnect NET CONTAINER — leave a network (§60).
            let (Some(&net), Some(&ctref)) = (parts.get(2), parts.get(3)) else {
                crate::console_println!("Usage: container network disconnect NET CONTAINER");
                return;
            };
            let Some(ct_id) = resolve_container_ref(ctref) else {
                crate::console_println!("Container '{}' not found", ctref);
                return;
            };
            match crate::cnetwork::disconnect_container(net, ct_id) {
                Ok(()) => crate::console_println!("{} disconnected from '{}'", ctref, net),
                Err(crate::error::KernelError::InvalidArgument) => crate::console_println!(
                    "Cannot disconnect '{}' from its primary network '{}' (created with --network); \
                     delete the container to release it",
                    ctref, net
                ),
                Err(e) => crate::console_println!("Error: {:?}", e),
            }
        }
        other => {
            crate::console_println!("Unknown network action '{}'", other);
            crate::console_println!(
                "Usage: container network <create|ls|rm|inspect|prune|resolve|connect|disconnect> NAME [--subnet CIDR] [--gateway IP]"
            );
        }
    }
}

/// Parse a Docker-style memory size string into a count of 16 KiB frames.
///
/// Accepts a non-negative integer optionally followed by a binary unit
/// suffix (`b`, `k`, `m`, `g`, case-insensitive, with an optional trailing
/// `b` — e.g. `512m`, `512mb`, `1g`). A bare number is bytes. The byte total
/// is rounded **up** to a whole frame so the limit never under-counts. Returns
/// `None` for an empty/zero/unparseable value or an unknown unit.
fn parse_mem_size_to_frames(s: &str) -> Option<u64> {
    let s = s.trim();
    if s.is_empty() {
        return None;
    }
    // Split the leading digit run from the optional unit suffix.
    let bytes = s.as_bytes();
    let mut num_end = 0usize;
    while num_end < bytes.len()
        && bytes.get(num_end).copied().is_some_and(|c| c.is_ascii_digit())
    {
        num_end = num_end.saturating_add(1);
    }
    if num_end == 0 {
        return None;
    }
    let num: u64 = s.get(..num_end)?.parse().ok()?;
    let unit = s.get(num_end..)?.trim();
    let mult: u64 = match unit {
        "" | "b" | "B" => 1,
        "k" | "K" | "kb" | "Kb" | "kB" | "KB" => 1_024,
        "m" | "M" | "mb" | "Mb" | "mB" | "MB" => 1_048_576,
        "g" | "G" | "gb" | "Gb" | "gB" | "GB" => 1_073_741_824,
        _ => return None,
    };
    let total_bytes = num.checked_mul(mult)?;
    if total_bytes == 0 {
        return None;
    }
    let frame = crate::mm::frame::FRAME_SIZE as u64;
    // Ceiling division: (bytes + frame - 1) / frame.
    let frames = total_bytes.checked_add(frame.saturating_sub(1))?.checked_div(frame)?;
    if frames == 0 { None } else { Some(frames) }
}

/// Parse a Docker-style `--cpus` value (fractional cores) into a percentage
/// of one core, where one full core is 100.
///
/// Examples: `1` → 100, `1.5` → 150, `0.25` → 25, `2` → 200. Only the first
/// two fractional digits are significant (percent granularity); a single
/// fractional digit is treated as tenths (`0.5` → 50). Float arithmetic is
/// avoided entirely (no kernel FPU state). Returns `None` for an
/// empty/zero/non-numeric value.
fn parse_cpus_to_percent(s: &str) -> Option<u64> {
    let s = s.trim();
    if s.is_empty() {
        return None;
    }
    let (int_part, frac_part) = match s.split_once('.') {
        Some((a, b)) => (a, b),
        None => (s, ""),
    };
    let int_val: u64 = if int_part.is_empty() {
        0
    } else {
        int_part.parse().ok()?
    };
    // Accumulate up to two fractional digits as hundredths; all remaining
    // fractional characters must still be digits (reject garbage like "1.5x").
    let mut frac2: u64 = 0;
    let mut taken: u32 = 0;
    for &c in frac_part.as_bytes() {
        if !c.is_ascii_digit() {
            return None;
        }
        if taken < 2 {
            let digit = u64::from(c.saturating_sub(b'0'));
            frac2 = frac2.saturating_mul(10).saturating_add(digit);
            taken = taken.saturating_add(1);
        }
    }
    // A single fractional digit means tenths → scale to hundredths.
    if taken == 1 {
        frac2 = frac2.saturating_mul(10);
    }
    let percent = int_val.checked_mul(100)?.checked_add(frac2)?;
    if percent == 0 { None } else { Some(percent) }
}

/// Boot-time self-test for the container CLI resource-limit parsers.
///
/// Kernel tests are QEMU boot self-tests (the target is `no_std` on a custom
/// triple, so host `cargo test` cannot run them). This exercises the pure
/// `parse_mem_size_to_frames` / `parse_cpus_to_percent` helpers added for
/// `oci run --memory`/`--cpus`, covering the happy paths and the rejection
/// cases. Called from `main.rs` alongside the other subsystem self-tests.
pub fn cli_resource_parser_self_test() {
    let frame = crate::mm::frame::FRAME_SIZE as u64; // 16384

    // Memory: bare bytes round up to whole frames.
    assert_eq!(parse_mem_size_to_frames("16384"), Some(1));
    assert_eq!(parse_mem_size_to_frames("16385"), Some(2));
    assert_eq!(parse_mem_size_to_frames("1"), Some(1)); // <1 frame rounds up
    // Unit suffixes (binary), with and without a trailing 'b'.
    assert_eq!(parse_mem_size_to_frames("1k"), Some(1)); // 1024 → 1 frame
    assert_eq!(parse_mem_size_to_frames("1m"), Some(1_048_576 / frame));
    assert_eq!(parse_mem_size_to_frames("512m"), Some(512 * 1_048_576 / frame));
    assert_eq!(parse_mem_size_to_frames("512mb"), Some(512 * 1_048_576 / frame));
    assert_eq!(parse_mem_size_to_frames("1g"), Some(1_073_741_824 / frame));
    // Rejections.
    assert_eq!(parse_mem_size_to_frames(""), None);
    assert_eq!(parse_mem_size_to_frames("0"), None);
    assert_eq!(parse_mem_size_to_frames("abc"), None);
    assert_eq!(parse_mem_size_to_frames("10x"), None);

    // CPUs → percent of one core.
    assert_eq!(parse_cpus_to_percent("1"), Some(100));
    assert_eq!(parse_cpus_to_percent("2"), Some(200));
    assert_eq!(parse_cpus_to_percent("1.5"), Some(150));
    assert_eq!(parse_cpus_to_percent("0.5"), Some(50)); // single frac digit = tenths
    assert_eq!(parse_cpus_to_percent("0.25"), Some(25));
    assert_eq!(parse_cpus_to_percent("0.05"), Some(5));
    // Rejections.
    assert_eq!(parse_cpus_to_percent(""), None);
    assert_eq!(parse_cpus_to_percent("0"), None);
    assert_eq!(parse_cpus_to_percent("0.0"), None);
    assert_eq!(parse_cpus_to_percent("1.5x"), None);
    assert_eq!(parse_cpus_to_percent("abc"), None);

    crate::serial_println!("[kshell] CLI resource-limit parser self-test PASSED");
}

/// `docker` (alias `dk`) — Docker-CLI-compatible front-end.
///
/// This is a thin translation layer over the native `oci` (image) and
/// `container` (lifecycle) commands so that operators with Docker muscle
/// memory can drive SlateOS containers with familiar verbs. Each Docker
/// subcommand is rewritten to the equivalent native command and dispatched:
///
///   docker run <image-dir> [flags...]   → oci run <image-dir> [flags...]
///   docker create <image-dir> [flags..] → oci create <image-dir> [flags...]
///   docker ps [-a]                       → container list (all states)
///   docker start <id>                    → container start <id>
///   docker stop <id>                     → container stop <id>
///   docker rm <id>                       → container delete <id>
///   docker inspect <id>                  → container info <id>
///   docker exec <id> <command...>        → container exec <id> <command...>
///   docker images                        → oci images (list the named store)
///   docker tag <dir|ref> <ref>           → oci tag (import a dir or re-tag)
///   docker rmi <ref>                      → oci rmi (remove a store tag)
///   docker commit <id> <name:tag>        → author a new image from a
///                                          container's changes, tag it in the store
///
/// `docker ps` lists every container regardless of state (SlateOS has no
/// separate "running-only" index; `-a`/`--all` is accepted and ignored
/// because the listing already shows all states).
fn cmd_docker(args: &str) {
    let trimmed = args.trim_start();
    // Split off the first whitespace-delimited token (the Docker subcommand)
    // and keep the remainder verbatim so quoting/spacing in arguments to the
    // delegated command is preserved.
    let (sub, rest) = match trimmed.split_once(char::is_whitespace) {
        Some((s, r)) => (s, r.trim_start()),
        None => (trimmed, ""),
    };

    // Delegate a Docker subcommand to the native `container` handler, forwarding
    // the argument tail verbatim.  `target` is the `container` subcommand name
    // (often identical to the Docker one, occasionally renamed — e.g. `rm` ->
    // `delete`, `inspect` -> `info`, `ps` -> `list`).
    let delegate = |target: &str| {
        let mut delegated = alloc::string::String::from(target);
        if !rest.is_empty() {
            delegated.push(' ');
            delegated.push_str(rest);
        }
        cmd_container(&delegated);
    };

    match sub {
        // Image-backed lifecycle: delegate straight to the OCI runner, which
        // already understands -v/-p/-e/--name/--net/--restart/--rm.
        "run" | "create" => {
            let mut delegated = alloc::string::String::from(sub);
            if !rest.is_empty() {
                delegated.push(' ');
                delegated.push_str(rest);
            }
            cmd_oci(&delegated);
        }
        // `docker ps` shows running containers; `docker ps -a` shows all — the
        // native `container list` has identical semantics, so forward the flags
        // (previously they were silently dropped).
        "ps" => delegate("list"),
        // Renamed subcommands (Docker name differs from the native one).
        "rm" => delegate("delete"),
        "inspect" => delegate("info"),
        // `docker exec` is a *real* in-container process launch from the
        // rootfs, so it maps to the native `container run-in` verb — NOT
        // `container exec`, which is the netns-debug facade (Q17/§58, option B).
        "exec" => delegate("run-in"),
        // 1:1 passthroughs — the Docker and native subcommand names match.
        "start" | "stop" | "kill" | "restart" | "pause" | "unpause"
        | "events" | "logs" | "stats" | "top" | "port" | "wait"
        | "diff" | "rename" | "update" | "prune" | "cp" | "export"
        | "import" | "volume" | "network" | "system" => delegate(sub),
        // `docker commit <container> <name:tag>` authors a *new image* from the
        // container's filesystem changes and tags it into the store — image
        // production, distinct from the native `container commit` (which clones
        // a container). We stage a standalone OCI layout in a temp dir, import
        // it into the store under the given ref, then discard the temp dir
        // (Docker's commit has no dest-dir artifact).
        "commit" => {
            let mut it = rest.split_whitespace();
            let (Some(id_str), Some(reference)) = (it.next(), it.next()) else {
                crate::console_println!("Usage: docker commit <container-id> <name:tag>");
                return;
            };
            let Ok(id) = id_str.parse::<u32>() else {
                crate::console_println!("Invalid container ID");
                return;
            };
            let tmp = "/tmp/oci-commit-tmp";
            // Best-effort clean of a stale temp layout from a prior commit.
            let _ = crate::fs::vfs::Vfs::remove_recursive(tmp);
            match crate::container::commit_image(id, tmp) {
                Ok(digest) => {
                    match crate::oci::store_tag_from_dir(tmp, reference) {
                        Ok(_) => crate::console_println!(
                            "Committed container {} as {} ({})", id, reference, digest
                        ),
                        Err(e) => crate::console_println!("commit tag failed: {:?}", e),
                    }
                    // Blobs are now copied into the store; drop the staging dir.
                    let _ = crate::fs::vfs::Vfs::remove_recursive(tmp);
                }
                Err(e) => crate::console_println!("commit failed: {:?}", e),
            }
        }
        // Named image store (`/var/lib/images`): `docker images` lists tagged
        // images, `docker tag` adds/imports a reference, `docker rmi` removes
        // one — all backed by the store in `oci.rs`.
        "images" | "image" => {
            let mut delegated = alloc::string::String::from("images");
            if !rest.is_empty() {
                delegated.push(' ');
                delegated.push_str(rest);
            }
            cmd_oci(&delegated);
        }
        "tag" | "rmi" => {
            let mut delegated = alloc::string::String::from(sub);
            if !rest.is_empty() {
                delegated.push(' ');
                delegated.push_str(rest);
            }
            cmd_oci(&delegated);
        }
        // Image save/load operate on OCI *images* (directory trees), so they
        // route to the `oci` handler, not the container handler. `docker save`
        // bundles an image dir into a tar; `docker load` restores it into a dir
        // (we take an explicit dest dir since there is no name-keyed store).
        "save" | "load" => {
            let mut delegated = alloc::string::String::from(sub);
            if !rest.is_empty() {
                delegated.push(' ');
                delegated.push_str(rest);
            }
            cmd_oci(&delegated);
        }
        // `docker build` authors an OCI image from a Dockerfile — an image
        // operation, so it routes to the `oci` handler (`oci build`).
        "build" => {
            let mut delegated = alloc::string::String::from("build");
            if !rest.is_empty() {
                delegated.push(' ');
                delegated.push_str(rest);
            }
            cmd_oci(&delegated);
        }
        // `docker history <image-dir>` shows an image's build history — an
        // image operation, so it routes to `oci history`.
        "history" => {
            let mut delegated = alloc::string::String::from("history");
            if !rest.is_empty() {
                delegated.push(' ');
                delegated.push_str(rest);
            }
            cmd_oci(&delegated);
        }
        "version" => {
            crate::console_println!("SlateOS docker-compat shim — front-end for `oci` and `container`");
        }
        _ => {
            crate::console_println!("Usage: docker <build|history|run|create|ps|start|stop|restart|kill|pause|unpause|rm|inspect|exec|logs|events|stats|top|port|wait|diff|rename|update|prune|cp|commit|export|import|save|load|system|images|tag|rmi|version> ...");
            crate::console_println!("  docker build <dockerfile> <context-dir> <dest-dir> [--build-arg K=V ...] [--target STAGE]   — build an OCI image from a Dockerfile (RUN deferred, see Q17)");
            crate::console_println!("  docker run <image-dir> [--name N] [--net IP] [-v h:g] [-p h:c[/proto]] [-e K=V] [--env-file F] [-m SIZE] [--cpus N] [--read-only] [-w DIR] [-u UID[:GID]] [--entrypoint EXE] [--hostname NAME] [--restart POLICY] [--rm] [--label K=V ...] [--label-file FILE] [COMMAND [ARG...]]");
            crate::console_println!("  docker create <image-dir> [flags...]   — create without starting");
            crate::console_println!("  docker ps [-a] [-q] [-n N|-l]          — list containers (running; -a: all)");
            crate::console_println!("  docker start|stop|restart|kill <id>    — lifecycle control");
            crate::console_println!("  docker pause|unpause <id>              — freeze / thaw all threads");
            crate::console_println!("  docker rm [-f] <id>                    — remove container(s)");
            crate::console_println!("  docker inspect [--json] <id>           — detailed container info (--json)");
            crate::console_println!("  docker exec <id> <command...>          — run a command in the container NS");
            crate::console_println!("  docker logs [--tail N] <id>            — captured init stdout/stderr");
            crate::console_println!("  docker events [-n N] [--id <id>]       — recent lifecycle events");
            crate::console_println!("  docker stats|top <id>                  — live resource usage / process list");
            crate::console_println!("  docker port|wait <id>                  — published ports / block until exit");
            crate::console_println!("  docker diff <id>                       — rootfs changes vs image (A/C/D)");
            crate::console_println!("  docker rename <id> <name>              — rename a container");
            crate::console_println!("  docker update <id> [--cpus N] [--memory SIZE] [--restart POLICY]");
            crate::console_println!("  docker prune                           — remove all stopped containers");
            crate::console_println!("  docker cp <src> <dest>                 — copy between host and rootfs");
            crate::console_println!("  docker commit|export|import ...        — snapshot / pack / load a rootfs");
            crate::console_println!("  docker save <image-dir|name:tag> <out-tar>  — bundle an OCI image into a tar");
            crate::console_println!("  docker load <in-tar> [dest-dir]        — restore a saved image tar (imports into the store by ref.name)");
            crate::console_println!("  docker system df|prune                 — disk usage / reclaim stopped containers+networks");
            crate::console_println!("  docker images                          — list tagged images in the named store");
            crate::console_println!("  docker tag <dir|ref> <ref>             — import an image dir or re-tag an existing ref");
            crate::console_println!("  docker rmi <ref>                       — remove a tag from the named store (GCs blobs)");
            crate::console_println!("  docker history <image-dir>             — show image build history (created-by + size)");
            crate::console_println!();
            crate::console_println!("Native equivalents: `oci` (images) and `container`/`ct` (lifecycle).");
            crate::console_println!("Alias: dk");
        }
    }
}

/// `oci` — OCI container image management.
///
/// Subcommands:
///   oci inspect <dir>   — parse and display OCI image metadata
///   oci layers <dir>    — list image layers with digests
///   oci verify <dir>    — verify all blob digests
///   oci test            — run self-tests
fn cmd_oci(args: &str) {
    use crate::oci;

    let parts: alloc::vec::Vec<&str> = args.split_whitespace().collect();
    let cmd = parts.first().copied().unwrap_or("");

    match cmd {
        "inspect" => {
            let Some(dir) = parts.get(1) else {
                crate::console_println!("Usage: oci inspect <image-dir>");
                return;
            };
            match oci::resolve_image_source(dir) {
                Ok((_, image)) => {
                    crate::console_println!("=== OCI Image: {} ===", dir);
                    crate::console_println!("  Architecture: {}", image.config.architecture);
                    crate::console_println!("  OS:           {}", image.config.os);
                    crate::console_println!("  Layers:       {}", image.manifest.layers.len());

                    if !image.config.entrypoint.is_empty() {
                        let ep: alloc::string::String = image.config.entrypoint.join(" ");
                        crate::console_println!("  Entrypoint:   {}", ep);
                    }
                    if !image.config.cmd.is_empty() {
                        let cmd_str: alloc::string::String = image.config.cmd.join(" ");
                        crate::console_println!("  Cmd:          {}", cmd_str);
                    }
                    if !image.config.working_dir.is_empty() {
                        crate::console_println!("  WorkingDir:   {}", image.config.working_dir);
                    }
                    if !image.config.user.is_empty() {
                        crate::console_println!("  User:         {}", image.config.user);
                    }
                    if !image.config.env.is_empty() {
                        crate::console_println!("  Environment:");
                        for e in &image.config.env {
                            crate::console_println!("    {}", e);
                        }
                    }
                    if !image.config.exposed_ports.is_empty() {
                        let ports: alloc::string::String =
                            image.config.exposed_ports.join(", ");
                        crate::console_println!("  Ports:        {}", ports);
                    }
                    if !image.config.volumes.is_empty() {
                        let vols: alloc::string::String = image.config.volumes.join(", ");
                        crate::console_println!("  Volumes:      {}", vols);
                    }
                    if !image.config.stop_signal.is_empty() {
                        crate::console_println!("  StopSignal:   {}", image.config.stop_signal);
                    }
                    if !image.config.shell.is_empty() {
                        let sh: alloc::string::String = image.config.shell.join(" ");
                        crate::console_println!("  Shell:        {}", sh);
                    }
                    if !image.config.onbuild.is_empty() {
                        crate::console_println!("  OnBuild:");
                        for t in &image.config.onbuild {
                            crate::console_println!("    {}", t);
                        }
                    }
                    if !image.config.labels.is_empty() {
                        crate::console_println!("  Labels:");
                        for (k, v) in &image.config.labels {
                            crate::console_println!("    {}={}", k, v);
                        }
                    }
                }
                Err(e) => crate::console_println!("Error loading image: {:?}", e),
            }
        }
        "layers" => {
            let Some(dir) = parts.get(1) else {
                crate::console_println!("Usage: oci layers <image-dir>");
                return;
            };
            match oci::resolve_image_source(dir) {
                Ok((_, image)) => {
                    crate::console_println!("=== Layers ({}) ===", image.manifest.layers.len());
                    for (i, layer) in image.manifest.layers.iter().enumerate() {
                        crate::console_println!(
                            "  [{}] {} ({} bytes, {})",
                            i, layer.digest, layer.size, layer.media_type
                        );
                    }
                    crate::console_println!("Config: {} ({} bytes)",
                        image.manifest.config.digest,
                        image.manifest.config.size
                    );
                }
                Err(e) => crate::console_println!("Error: {:?}", e),
            }
        }
        "history" | "hist" => {
            let Some(dir) = parts.get(1) else {
                crate::console_println!("Usage: oci history <image-dir>");
                return;
            };
            match oci::resolve_image_source(dir) {
                Ok((_, image)) => {
                    if image.config.history.is_empty() {
                        crate::console_println!(
                            "No build history recorded in image config ({} layers)",
                            image.manifest.layers.len()
                        );
                        return;
                    }
                    crate::console_println!("=== History ({} steps) ===",
                        image.config.history.len());
                    crate::console_println!("  {:>12}  CREATED BY", "SIZE");
                    // Non-empty steps consume layers in order; empty steps are
                    // metadata-only (0 bytes), matching `docker history`.
                    let mut layer_idx = 0usize;
                    for h in &image.config.history {
                        let size = if h.empty_layer {
                            0
                        } else {
                            let s = image
                                .manifest
                                .layers
                                .get(layer_idx)
                                .map_or(0, |l| l.size);
                            layer_idx = layer_idx.saturating_add(1);
                            s
                        };
                        crate::console_println!("  {:>12}  {}", size, h.created_by);
                    }
                }
                Err(e) => crate::console_println!("Error: {:?}", e),
            }
        }
        "run" | "create" => {
            // oci run <image-dir> [--name NAME] [--net IP[,gw=..,dns=..]] [--network NAME]
            //                      [-v src:/guest[:ro|:rw] ...] [-p host:container[/proto] ...]
            //   where src is an absolute host path (bind mount) or a bare name
            //   (named volume, created on demand under VOLUMES_ROOT)
            //                      [-e KEY=value ...] [--env-file FILE ...] [-m SIZE] [--cpus N] [--read-only] [-w DIR] [-u UID[:GID]] [--entrypoint EXE] [--hostname NAME] [--label K=V ...] [--label-file FILE] [COMMAND [ARG...]]
            //
            // Loads an OCI image, extracts all layers into a merged rootfs
            // directory, creates a container with the image's configuration,
            // and reports the container ID for subsequent exec/stop/delete.
            let Some(dir) = parts.get(1) else {
                crate::console_println!("Usage: oci run <image-dir> [--name NAME] [--net IP[,gw=..,dns=..]] [--network NAME] [--network-alias NAME ...] [-v src:/guest[:ro|:rw] ...] [--tmpfs /guest ...] [-p host:container[/proto] ...] [-e KEY=value ...] [--env-file FILE ...] [-m SIZE] [--cpus N] [--read-only] [--restart POLICY] [--rm] [-w DIR] [-u UID[:GID]] [--entrypoint EXE] [--hostname NAME] [--label K=V ...] [--label-file FILE] [COMMAND [ARG...]]");
                return;
            };

            // Parse optional flags.
            let mut name: Option<&str> = None;
            let mut net_ip: Option<[u8; 4]> = None;
            let mut net_gw: Option<[u8; 4]> = None;
            let mut net_dns: Option<[u8; 4]> = None;
            let mut net_mask: Option<[u8; 4]> = None;
            // `--network NAME`: attach to a user-defined network, drawing a
            // conflict-free IP from its IPAM (Docker `docker run --network`).
            let mut net_name: Option<&str> = None;
            // `--network-alias NAME` (repeatable): extra embedded-DNS names the
            // container answers to on its network, alongside its name/hostname.
            let mut net_aliases: alloc::vec::Vec<&str> = alloc::vec::Vec::new();
            // Volume mounts as (host_target, guest_prefix, read_only) triples
            // from `-v host:guest` (Docker order). The host target is either an
            // absolute host path (bind mount) or a named volume's backing path
            // (resolved at parse time), so the tuple owns its strings rather
            // than borrowing the raw argv. Installed after the container is
            // created (while still in Created state).
            let mut volumes: alloc::vec::Vec<(alloc::string::String, alloc::string::String, bool)> =
                alloc::vec::Vec::new();
            // Published ports as (proto, host_port, container_port) from
            // `-p host:container[/tcp|/udp]` (Docker order, default tcp).
            // Installed after the container is created (Created state).
            let mut ports: alloc::vec::Vec<(crate::net::nat::NatProto, u16, u16)> =
                alloc::vec::Vec::new();
            // Tmpfs (in-memory) mounts as absolute guest paths from
            // `--tmpfs /guest`. Installed after the container is created
            // (Created state); each backs an ephemeral writable memfs.
            let mut tmpfs: alloc::vec::Vec<alloc::string::String> =
                alloc::vec::Vec::new();
            // Extra `KEY=value` environment entries from `-e`/`--env`. These
            // override the image's declared ENV (Docker semantics) and are
            // merged at launch (see the env construction below).
            let mut extra_env: alloc::vec::Vec<&str> = alloc::vec::Vec::new();
            // `KEY=value` entries read from `--env-file FILE`. Stored as raw
            // bytes (env values may contain non-UTF-8 data, which we must not
            // corrupt) and owned because they come from file contents, not
            // from `parts`. Precedence: image ENV < env-file < CLI `-e`.
            let mut env_file_entries: alloc::vec::Vec<alloc::vec::Vec<u8>> =
                alloc::vec::Vec::new();
            // Resource limits from `--memory`/`-m <size>` (bytes, with optional
            // k/m/g suffix → 16 KiB frames) and `--cpus <N[.M]>` (fractional
            // cores → percent of one core, e.g. 1.5 → 150%). Applied to the
            // container cgroup at create time (Step 4 below).
            let mut mem_frames: Option<u64> = None;
            let mut cpu_percent: Option<u64> = None;
            // Docker `--read-only`: mount the container rootfs read-only so
            // writes that don't land in a writable (`:rw`) volume are denied
            // with EROFS. Applied to the container at create time (Step 4).
            let mut read_only_root = false;
            // Docker `--restart POLICY`: auto-restart policy for the init
            // process (no|always|unless-stopped|on-failure[:N]). Applied to the
            // container config at create time.
            let mut restart_policy: Option<crate::container::RestartPolicy> = None;
            // Docker `--rm`: auto-delete the container when its init exits.
            let mut auto_remove = false;
            // Docker `--workdir`/`-w`: initial working directory of the init
            // process (a guest path resolved under the container jail). When
            // unset, the image's `WorkingDir` config is used, else `/`.
            let mut workdir: Option<&str> = None;
            // Docker `--user`/`-u uid[:gid]`: numeric user/group the init
            // process runs as. When unset, the image's `User` config is used,
            // else root (0:0). Only numeric ids are supported (a name has no
            // /etc/passwd to resolve against in this minimal runtime).
            let mut user: Option<&str> = None;
            // Docker `--entrypoint EXE`: override the image's ENTRYPOINT. An
            // empty value (`--entrypoint ""`) clears it (CMD then becomes the
            // whole command line), matching Docker.
            let mut entrypoint_override: Option<&str> = None;
            // Docker `--hostname`/`-h NAME`: the UTS hostname the container's
            // init process sees via uname(2), independent of any rootfs jail.
            // Truncated to 64 bytes by the container layer.
            let mut hostname: Option<&str> = None;
            // Docker `--label`/`-l KEY=VALUE`: arbitrary metadata `(key, value)`
            // pairs stored on the container (no runtime behavior). A bare KEY
            // (no `=`) gets an empty value, matching Docker.
            let mut labels: alloc::vec::Vec<(&str, &str)> = alloc::vec::Vec::new();
            // Docker `--label-file FILE`: KEY=VALUE lines (same format as
            // --env-file). Owned because they come from file contents.
            // Precedence: --label-file < CLI --label (CLI wins).
            let mut label_file_entries:
                alloc::vec::Vec<(alloc::string::String, alloc::string::String)> =
                alloc::vec::Vec::new();
            // Docker trailing `IMAGE [COMMAND] [ARG...]`: positional tokens
            // after the image dir override the image's CMD (the ENTRYPOINT is
            // kept unless --entrypoint is also given). The first non-option
            // token starts the command; everything after it is taken literally
            // (no further option parsing), matching Docker's argument model.
            let mut cmd_override: alloc::vec::Vec<&str> = alloc::vec::Vec::new();
            let mut i = 2;
            while i < parts.len() {
                match parts[i] {
                    "--memory" | "-m" => {
                        if let Some(&spec) = parts.get(i.saturating_add(1)) {
                            match parse_mem_size_to_frames(spec) {
                                Some(frames) => mem_frames = Some(frames),
                                None => crate::console_println!(
                                    "[oci] Ignoring memory '{}': expected SIZE[k|m|g] (e.g. 512m)",
                                    spec
                                ),
                            }
                            i = i.saturating_add(2);
                        } else {
                            i = i.saturating_add(1);
                        }
                    }
                    "--cpus" => {
                        if let Some(&spec) = parts.get(i.saturating_add(1)) {
                            match parse_cpus_to_percent(spec) {
                                Some(pct) => cpu_percent = Some(pct),
                                None => crate::console_println!(
                                    "[oci] Ignoring cpus '{}': expected a positive number (e.g. 1.5)",
                                    spec
                                ),
                            }
                            i = i.saturating_add(2);
                        } else {
                            i = i.saturating_add(1);
                        }
                    }
                    "--env" | "-e" => {
                        if let Some(&spec) = parts.get(i.saturating_add(1)) {
                            // Require KEY=value: a bare `-e KEY` would mean
                            // "inherit the host's KEY" in Docker, but a
                            // container has no host environment to inherit, so
                            // reject it rather than silently pass an empty var.
                            if let Some((key, _)) = spec.split_once('=') {
                                if key.is_empty() {
                                    crate::console_println!(
                                        "[oci] Ignoring env '{}': empty key", spec
                                    );
                                } else {
                                    extra_env.push(spec);
                                }
                            } else {
                                crate::console_println!(
                                    "[oci] Ignoring env '{}': expected KEY=value", spec
                                );
                            }
                            i = i.saturating_add(2);
                        } else {
                            i = i.saturating_add(1);
                        }
                    }
                    "--env-file" => {
                        if let Some(&path) = parts.get(i.saturating_add(1)) {
                            match crate::fs::vfs::Vfs::read_file(path) {
                                Ok(bytes) => {
                                    // Parse KEY=value lines as raw bytes (see
                                    // `oci::parse_env_file`). Report rejected
                                    // lines but keep the valid entries.
                                    let parsed = oci::parse_env_file(&bytes);
                                    for n in &parsed.rejected_lines {
                                        crate::console_println!(
                                            "[oci] Ignoring env-file '{}' line {}: expected KEY=value",
                                            path, n
                                        );
                                    }
                                    env_file_entries.extend(parsed.entries);
                                }
                                Err(e) => crate::console_println!(
                                    "[oci] Could not read env-file '{}': {:?}", path, e
                                ),
                            }
                            i = i.saturating_add(2);
                        } else {
                            i = i.saturating_add(1);
                        }
                    }
                    "--publish" | "-p" => {
                        if let Some(&spec) = parts.get(i.saturating_add(1)) {
                            // Format: host:container[/proto]. Split the proto
                            // suffix first, then the host:container pair.
                            let (pair, proto) = match spec.split_once('/') {
                                Some((p, "tcp")) => (p, crate::net::nat::NatProto::Tcp),
                                Some((p, "udp")) => (p, crate::net::nat::NatProto::Udp),
                                Some((_, other)) => {
                                    crate::console_println!(
                                        "[oci] Ignoring port '{}': unknown protocol '{}' (use tcp/udp)",
                                        spec, other
                                    );
                                    i = i.saturating_add(2);
                                    continue;
                                }
                                None => (spec, crate::net::nat::NatProto::Tcp),
                            };
                            match pair.split_once(':') {
                                Some((h, c)) => {
                                    match (h.parse::<u16>(), c.parse::<u16>()) {
                                        (Ok(hp), Ok(cp)) if hp != 0 && cp != 0 => {
                                            ports.push((proto, hp, cp));
                                        }
                                        _ => crate::console_println!(
                                            "[oci] Ignoring port '{}': expected host:container with nonzero ports",
                                            spec
                                        ),
                                    }
                                }
                                None => crate::console_println!(
                                    "[oci] Ignoring port '{}': expected host:container", spec
                                ),
                            }
                            i = i.saturating_add(2);
                        } else {
                            i = i.saturating_add(1);
                        }
                    }
                    "--volume" | "-v" => {
                        if let Some(&spec) = parts.get(i.saturating_add(1)) {
                            // Docker `-v source:guest[:mode]`.  The guest is an
                            // absolute Unix path; an optional third field is the
                            // access mode (`ro` = read-only, `rw` = read-write,
                            // the default).  The source is one of two forms,
                            // distinguished exactly as Docker does — by whether
                            // it starts with `/`:
                            //   * absolute path (`/host/path`)  -> bind mount
                            //   * bare name    (`myvol`)        -> named volume,
                            //     created on demand under VOLUMES_ROOT and its
                            //     backing directory bind-mounted in.
                            // Split into at most three colon-separated segments.
                            let mut segs = spec.splitn(3, ':');
                            let source = segs.next().unwrap_or("");
                            let guest = segs.next().unwrap_or("");
                            let mode = segs.next();
                            let read_only = match mode {
                                None | Some("rw") => Some(false),
                                Some("ro") => Some(true),
                                Some(other) => {
                                    crate::console_println!(
                                        "[oci] Ignoring volume '{}': unknown mode '{}' (expected ro or rw)",
                                        spec, other
                                    );
                                    None
                                }
                            };
                            if let Some(ro) = read_only {
                                if !guest.starts_with('/') {
                                    crate::console_println!(
                                        "[oci] Ignoring volume '{}': guest path must be absolute (source:/guest[:ro|:rw])",
                                        spec
                                    );
                                } else if source.starts_with('/') {
                                    // Host bind mount: use the absolute host path.
                                    volumes.push((
                                        alloc::string::String::from(source),
                                        alloc::string::String::from(guest),
                                        ro,
                                    ));
                                } else if source.is_empty() {
                                    crate::console_println!(
                                        "[oci] Ignoring volume '{}': empty source (want /host:/guest or name:/guest)",
                                        spec
                                    );
                                } else {
                                    // Named volume: create-on-demand and mount
                                    // its backing directory.
                                    match crate::volume::ensure(source) {
                                        Ok(backing) => {
                                            volumes.push((
                                                backing,
                                                alloc::string::String::from(guest),
                                                ro,
                                            ));
                                        }
                                        Err(e) => {
                                            crate::console_println!(
                                                "[oci] Ignoring volume '{}': cannot create named volume '{}': {:?}",
                                                spec, source, e
                                            );
                                        }
                                    }
                                }
                            }
                            i = i.saturating_add(2);
                        } else {
                            i = i.saturating_add(1);
                        }
                    }
                    "--tmpfs" => {
                        if let Some(&spec) = parts.get(i.saturating_add(1)) {
                            // Docker `--tmpfs /guest[:options]`. The guest is an
                            // absolute Unix path; Docker also accepts mount
                            // options after a `:` (size=, mode=, …). Our memfs
                            // does not yet enforce size/mode quotas, so rather
                            // than silently ignore them (an unbounded tmpfs is a
                            // containment/DoS gap), reject a spec that carries
                            // options — the honest failure mode until quota
                            // enforcement lands.
                            if let Some((path, opts)) = spec.split_once(':') {
                                crate::console_println!(
                                    "[oci] Ignoring tmpfs '{}': mount options ('{}') not yet supported (want --tmpfs /guest)",
                                    spec, opts
                                );
                                let _ = path;
                            } else if !spec.starts_with('/') || spec == "/" {
                                crate::console_println!(
                                    "[oci] Ignoring tmpfs '{}': guest path must be absolute and not '/'",
                                    spec
                                );
                            } else {
                                tmpfs.push(alloc::string::String::from(spec));
                            }
                            i = i.saturating_add(2);
                        } else {
                            i = i.saturating_add(1);
                        }
                    }
                    "--read-only" => {
                        // Flag (no argument): make the container rootfs RO.
                        read_only_root = true;
                        i = i.saturating_add(1);
                    }
                    "--rm" => {
                        // Flag (no argument): auto-remove on init exit.
                        auto_remove = true;
                        i = i.saturating_add(1);
                    }
                    "--restart" => {
                        if let Some(&spec) = parts.get(i.saturating_add(1)) {
                            match crate::container::parse_restart_policy(spec) {
                                Some(p) => restart_policy = Some(p),
                                None => crate::console_println!(
                                    "[oci] Ignoring restart '{}': want no|always|unless-stopped|on-failure[:N]",
                                    spec
                                ),
                            }
                            i = i.saturating_add(2);
                        } else {
                            i = i.saturating_add(1);
                        }
                    }
                    "--workdir" | "-w" => {
                        if let Some(&spec) = parts.get(i.saturating_add(1)) {
                            // Must be an absolute guest path; a relative
                            // workdir is rejected (Docker requires absolute).
                            if spec.starts_with('/') {
                                workdir = Some(spec);
                            } else {
                                crate::console_println!(
                                    "[oci] Ignoring workdir '{}': must be an absolute path",
                                    spec
                                );
                            }
                            i = i.saturating_add(2);
                        } else {
                            i = i.saturating_add(1);
                        }
                    }
                    "--user" | "-u" => {
                        if let Some(&spec) = parts.get(i.saturating_add(1)) {
                            user = Some(spec);
                            i = i.saturating_add(2);
                        } else {
                            i = i.saturating_add(1);
                        }
                    }
                    "--name" | "-n" => {
                        if let Some(&n) = parts.get(i.saturating_add(1)) {
                            name = Some(n);
                            i = i.saturating_add(2);
                        } else {
                            i = i.saturating_add(1);
                        }
                    }
                    "--net" => {
                        if let Some(&net_str) = parts.get(i.saturating_add(1)) {
                            let net_parts: alloc::vec::Vec<&str> = net_str.split(',').collect();
                            if let Some(ip) = parse_ipv4_octets(net_parts.first().copied().unwrap_or("")) {
                                net_ip = Some(ip);
                                for &part in net_parts.iter().skip(1) {
                                    if let Some(gw) = part.strip_prefix("gw=") {
                                        net_gw = parse_ipv4_octets(gw);
                                    } else if let Some(dns) = part.strip_prefix("dns=") {
                                        net_dns = parse_ipv4_octets(dns);
                                    }
                                }
                            }
                            i = i.saturating_add(2);
                        } else {
                            i = i.saturating_add(1);
                        }
                    }
                    "--network" => {
                        if let Some(&nn) = parts.get(i.saturating_add(1)) {
                            net_name = Some(nn);
                            i = i.saturating_add(2);
                        } else {
                            i = i.saturating_add(1);
                        }
                    }
                    "--network-alias" => {
                        if let Some(&al) = parts.get(i.saturating_add(1)) {
                            if !al.is_empty() {
                                net_aliases.push(al);
                            }
                            i = i.saturating_add(2);
                        } else {
                            i = i.saturating_add(1);
                        }
                    }
                    "--entrypoint" => {
                        if let Some(&spec) = parts.get(i.saturating_add(1)) {
                            entrypoint_override = Some(spec);
                            i = i.saturating_add(2);
                        } else {
                            i = i.saturating_add(1);
                        }
                    }
                    "--hostname" | "-h" => {
                        if let Some(&spec) = parts.get(i.saturating_add(1)) {
                            hostname = Some(spec);
                            i = i.saturating_add(2);
                        } else {
                            i = i.saturating_add(1);
                        }
                    }
                    "--label" | "-l" => {
                        if let Some(&spec) = parts.get(i.saturating_add(1)) {
                            // KEY=VALUE; a bare KEY gets an empty value.
                            let (key, value) = match spec.split_once('=') {
                                Some((k, v)) => (k, v),
                                None => (spec, ""),
                            };
                            if key.is_empty() {
                                crate::console_println!(
                                    "[oci] Ignoring label '{}': empty key", spec
                                );
                            } else {
                                labels.push((key, value));
                            }
                            i = i.saturating_add(2);
                        } else {
                            i = i.saturating_add(1);
                        }
                    }
                    "--label-file" => {
                        if let Some(&path) = parts.get(i.saturating_add(1)) {
                            match crate::fs::vfs::Vfs::read_file(path) {
                                Ok(bytes) => {
                                    // Reuse the env-file line parser (same
                                    // KEY=VALUE format). Labels must be UTF-8
                                    // (they are stored as strings), so reject
                                    // (rather than corrupt) any non-UTF-8 line.
                                    let parsed = oci::parse_env_file(&bytes);
                                    for n in &parsed.rejected_lines {
                                        crate::console_println!(
                                            "[oci] Ignoring label-file '{}' line {}: expected KEY=VALUE",
                                            path, n
                                        );
                                    }
                                    for entry in &parsed.entries {
                                        let key_bytes = oci::env_entry_key(entry);
                                        let val_bytes = entry
                                            .get(key_bytes.len().saturating_add(1)..)
                                            .unwrap_or(&[]);
                                        match (
                                            core::str::from_utf8(key_bytes),
                                            core::str::from_utf8(val_bytes),
                                        ) {
                                            (Ok(k), Ok(v)) => label_file_entries.push((
                                                alloc::string::String::from(k),
                                                alloc::string::String::from(v),
                                            )),
                                            _ => crate::console_println!(
                                                "[oci] Ignoring label-file '{}': non-UTF-8 label entry",
                                                path
                                            ),
                                        }
                                    }
                                }
                                Err(e) => crate::console_println!(
                                    "[oci] Could not read label-file '{}': {:?}", path, e
                                ),
                            }
                            i = i.saturating_add(2);
                        } else {
                            i = i.saturating_add(1);
                        }
                    }
                    tok if tok.starts_with('-') => {
                        // Unknown option: skip it (and don't consume a value,
                        // since we don't know its arity).
                        i = i.saturating_add(1);
                    }
                    _ => {
                        // First positional token after the image dir: this and
                        // every remaining token form the CMD override. Stop
                        // option parsing (Docker treats the rest literally).
                        if let Some(rest) = parts.get(i..) {
                            cmd_override.extend_from_slice(rest);
                        }
                        break;
                    }
                }
            }

            // Step 1: Load OCI image metadata. `dir` may be an on-disk OCI
            // layout directory or a named-store reference (`name:tag`);
            // `blob_dir` is where the layer blobs actually live.
            crate::console_println!("[oci] Loading image from {}...", dir);
            let (blob_dir, image) = match oci::resolve_image_source(dir) {
                Ok(pair) => pair,
                Err(e) => {
                    crate::console_println!("[oci] Failed to load image: {:?}", e);
                    return;
                }
            };

            let image_name = name.unwrap_or_else(|| {
                // Try to derive name from directory path.
                dir.rsplit('/').next().unwrap_or("oci-container")
            });

            crate::console_println!(
                "[oci] Image: {} ({}), {} layers",
                image.config.architecture,
                image.config.os,
                image.manifest.layers.len()
            );

            // Step 2: Create rootfs directory and extract layers.
            let rootfs_base = alloc::format!("/tmp/oci-{}", image_name);
            let rootfs_lower = alloc::format!("{}/lower", rootfs_base);
            let rootfs_upper = alloc::format!("{}/upper", rootfs_base);

            // Create directory structure.
            if let Err(e) = crate::fs::vfs::Vfs::mkdir(&rootfs_base) {
                // May already exist — ignore AlreadyExists.
                if !matches!(e, crate::error::KernelError::AlreadyExists) {
                    crate::console_println!("[oci] Failed to create {}: {:?}", rootfs_base, e);
                    return;
                }
            }
            if let Err(e) = crate::fs::vfs::Vfs::mkdir(&rootfs_lower) {
                if !matches!(e, crate::error::KernelError::AlreadyExists) {
                    crate::console_println!("[oci] Failed to create {}: {:?}", rootfs_lower, e);
                    return;
                }
            }
            if let Err(e) = crate::fs::vfs::Vfs::mkdir(&rootfs_upper) {
                if !matches!(e, crate::error::KernelError::AlreadyExists) {
                    crate::console_println!("[oci] Failed to create {}: {:?}", rootfs_upper, e);
                    return;
                }
            }

            // Extract each layer into the lower directory (merged — last layer wins).
            let mut total_files: u64 = 0;
            for (idx, layer) in image.manifest.layers.iter().enumerate() {
                crate::console_println!(
                    "[oci] Extracting layer {}/{} ({} bytes)...",
                    idx.saturating_add(1),
                    image.manifest.layers.len(),
                    layer.size
                );
                match oci::extract_layer(&blob_dir, layer, &rootfs_lower) {
                    Ok(count) => {
                        total_files = total_files.saturating_add(count);
                        crate::console_println!(
                            "[oci]   Layer {}: {} files extracted",
                            idx.saturating_add(1),
                            count
                        );
                    }
                    Err(e) => {
                        crate::console_println!(
                            "[oci] Failed to extract layer {}: {:?}",
                            idx.saturating_add(1),
                            e
                        );
                        return;
                    }
                }
            }
            crate::console_println!("[oci] Rootfs: {} total files in {}", total_files, rootfs_lower);

            // Step 3: Create overlay filesystem (lower = extracted image
            // layers, upper = writable scratch).  On success we mount it into
            // the VFS so the container's writes are copy-on-write isolated
            // from the read-only image.  If overlay creation fails we fall
            // back to jailing the container directly at the read-only lower
            // dir (no write isolation, but still runnable).
            let overlay_name = alloc::format!("oci-{}", image_name);
            let overlay_id = match crate::fs::overlay::create(&overlay_name, &rootfs_lower, &rootfs_upper) {
                Ok(ov_id) => {
                    crate::console_println!("[oci] Overlay created (id={}): lower={}, upper={}", ov_id, rootfs_lower, rootfs_upper);
                    Some(ov_id)
                }
                Err(e) => {
                    crate::console_println!("[oci] Overlay creation failed: {:?} (continuing without overlay)", e);
                    None
                }
            };

            // Step 3.5: if `--network NAME` was given (and no explicit `--net`
            // IP), draw a conflict-free address from that network's IPAM. The
            // reservation is unowned until the container id exists (below); we
            // stash `(name, ip)` so ownership can be bound after create and so a
            // failed create can release the reservation rather than leak it.
            let mut network_lease: Option<(&str, [u8; 4])> = None;
            if let Some(nn) = net_name {
                if net_ip.is_some() {
                    crate::console_println!(
                        "[oci] --network {} ignored: explicit --net IP already given", nn
                    );
                } else {
                    match crate::cnetwork::allocate(nn, None) {
                        Ok(lease) => {
                            net_ip = Some(lease.ip);
                            net_gw = Some(lease.gateway);
                            net_mask = Some(lease.netmask);
                            network_lease = Some((nn, lease.ip));
                        }
                        Err(e) => {
                            crate::console_println!(
                                "[oci] Cannot allocate IP from network '{}': {:?}", nn, e
                            );
                            return;
                        }
                    }
                }
            }

            // Step 4: Create container.
            let mut cfg = crate::container::ContainerConfig::new(image_name);
            // Record the image the container came from (dir path or store
            // `name:tag` ref) so `oci commit` / `docker commit` can later
            // author a new image layered on this base.
            cfg.image_source = String::from(*dir);
            cfg.net_ip = net_ip;
            cfg.net_gateway = net_gw;
            cfg.net_dns = net_dns;
            if net_ip.is_some() {
                // Prefer the network's mask (from IPAM); fall back to /24 for a
                // bare `--net IP`.
                cfg.net_mask = net_mask.or(Some([255, 255, 255, 0]));
            }
            // Apply optional resource limits (--memory / --cpus). 0 = unlimited
            // is the cgroup default, so we only override when a flag was given.
            if let Some(frames) = mem_frames {
                cfg.mem_limit = frames;
            }
            if let Some(pct) = cpu_percent {
                cfg.cpu_quota = pct;
            }
            // Apply optional UTS hostname (--hostname/-h). The builder
            // truncates names longer than 64 bytes.
            if let Some(hn) = hostname {
                cfg = cfg.hostname(hn);
            }
            // Apply metadata labels. --label-file first, then CLI --label, so
            // the builder's last-write-wins dedup makes CLI labels override
            // file labels (Docker precedence).
            for (k, v) in &label_file_entries {
                cfg = cfg.label(k, v);
            }
            for (k, v) in &labels {
                cfg = cfg.label(k, v);
            }
            // Apply optional lifecycle automation (--restart / --rm). Note
            // --read-only is applied post-create via set_read_only_root below,
            // not here.
            if let Some(policy) = restart_policy {
                cfg.restart_policy = policy;
            }
            cfg.auto_remove = auto_remove;

            match crate::container::create(&cfg) {
                Ok(ct_id) => {
                    crate::console_println!();
                    crate::console_println!("=== Container Created ===");
                    crate::console_println!("  Container ID: {}", ct_id);
                    crate::console_println!("  Name:         {}", image_name);
                    if !cfg.hostname.is_empty() {
                        crate::console_println!("  Hostname:     {}", cfg.hostname);
                    }
                    if cfg.restart_policy != crate::container::RestartPolicy::No {
                        crate::console_println!("  Restart:      {}", cfg.restart_policy);
                    }
                    if cfg.auto_remove {
                        crate::console_println!("  AutoRemove:   yes (--rm)");
                    }
                    for (k, v) in &cfg.labels {
                        crate::console_println!("  Label:        {}={}", k, v);
                    }
                    // Bind the reserved network address to this container so its
                    // lease is reclaimed when the container is deleted. The
                    // reservation was made unowned above (before the id existed).
                    if let Some((nn, ip)) = network_lease {
                        match crate::cnetwork::set_allocation_owner(nn, ip, ct_id) {
                            Ok(()) => crate::console_println!(
                                "  Network:      {} (ip {})", nn, fmt_ipv4(ip)
                            ),
                            Err(e) => crate::console_println!(
                                "[oci] Warning: could not bind network '{}' owner: {:?}", nn, e
                            ),
                        }
                        // Register the container's DNS names on the network so
                        // same-network peers can resolve it by name (Docker
                        // embedded DNS): the container name plus its hostname
                        // (when set and distinct). Non-fatal on failure.
                        if let Some(cinfo) = crate::container::info(ct_id) {
                            let mut names: alloc::vec::Vec<&str> = alloc::vec::Vec::new();
                            if !cinfo.name.is_empty() {
                                names.push(cinfo.name.as_str());
                            }
                            if !cinfo.hostname.is_empty()
                                && !cinfo.hostname.eq_ignore_ascii_case(&cinfo.name)
                            {
                                names.push(cinfo.hostname.as_str());
                            }
                            // Explicit --network-alias names (register_dns_names
                            // de-duplicates case-insensitively).
                            for &al in &net_aliases {
                                names.push(al);
                            }
                            if !names.is_empty() {
                                if let Err(e) =
                                    crate::cnetwork::register_dns_names(nn, ct_id, &names)
                                {
                                    crate::console_println!(
                                        "[oci] Warning: could not register DNS names on '{}': {:?}",
                                        nn, e
                                    );
                                }
                            }
                        }
                        // Attach the container's host-side veth to the network's
                        // shared L2 bridge so same-network peers can reach it
                        // directly (Docker user-defined bridge semantics). The
                        // bridge is created lazily on the first attach; a
                        // single-member network never allocates one. Non-fatal:
                        // without the bridge the container still has host/NAT
                        // connectivity, just no direct peer L2 path.
                        match crate::container::info(ct_id).and_then(|i| i.veth_pair) {
                            Some(vp) => {
                                match crate::cnetwork::attach_container_veth(nn, ct_id, vp) {
                                    Ok(()) => {
                                        let peers = crate::cnetwork::inspect(nn)
                                            .map_or(0, |i| i.allocations.len());
                                        crate::console_println!(
                                            "  L2 bridge:    {} ({} member{})",
                                            nn, peers, if peers == 1 { "" } else { "s" }
                                        );
                                        // Record the create-time primary network as a
                                        // membership (§60) so `inspect`/`ps` list it
                                        // alongside any runtime `network connect`s. It
                                        // reuses the primary veth just attached above.
                                        if let Some(ni) = crate::cnetwork::inspect(nn) {
                                            let _ = crate::container::record_primary_membership(
                                                ct_id, nn, ip, ni.network_addr, ni.prefix_len,
                                            );
                                        }
                                    }
                                    Err(e) => crate::console_println!(
                                        "[oci] Warning: could not attach to network '{}' bridge: {:?}",
                                        nn, e
                                    ),
                                }
                            }
                            None => crate::console_println!(
                                "[oci] Warning: network '{}' has no veth to bridge (no host link)",
                                nn
                            ),
                        }
                    }

                    // Determine the container's jail root.  Prefer the merged
                    // overlay mount (copy-on-write isolation): mount the
                    // per-container `OverlayFs` adapter at
                    // `/containers/<name>/rootfs` so reads see the merged view
                    // and writes land in the upper layer.  If the overlay was
                    // not created or the mount fails, fall back to jailing the
                    // container directly at the read-only lower dir.
                    let merged_mount = alloc::format!("/containers/{}/rootfs", image_name);
                    let mut jail_root = rootfs_lower.clone();
                    let mut mounted_overlay = false;
                    if let Some(ov_id) = overlay_id {
                        match crate::fs::overlay::OverlayFs::new(ov_id) {
                            Ok(ovfs) => {
                                match crate::fs::vfs::Vfs::mount(
                                    &merged_mount,
                                    alloc::boxed::Box::new(ovfs),
                                ) {
                                    Ok(()) => {
                                        jail_root = merged_mount.clone();
                                        mounted_overlay = true;
                                        crate::console_println!(
                                            "[oci] Overlay mounted at {} (copy-on-write)",
                                            merged_mount
                                        );
                                    }
                                    Err(e) => {
                                        crate::console_println!(
                                            "[oci] Could not mount overlay at {}: {:?} (using read-only lower)",
                                            merged_mount, e
                                        );
                                    }
                                }
                            }
                            Err(e) => {
                                crate::console_println!(
                                    "[oci] Could not open overlay adapter: {:?} (using read-only lower)",
                                    e
                                );
                            }
                        }
                    }
                    crate::console_println!("  Rootfs:       {}", jail_root);

                    // Compute the effective command (what the init process
                    // actually runs), applying Docker's ENTRYPOINT/CMD override
                    // rules: `--entrypoint` replaces (or, with "", clears) the
                    // image ENTRYPOINT and drops its default CMD; trailing
                    // `IMAGE CMD...` tokens replace the image CMD. See
                    // `ImageConfig::effective_command`.
                    let command: alloc::vec::Vec<alloc::string::String> =
                        image.config.effective_command(entrypoint_override, &cmd_override);

                    // Show the effective runtime config.
                    if !command.is_empty() {
                        let cmd_str: alloc::string::String = command.join(" ");
                        crate::console_println!("  Command:      {}", cmd_str);
                    }
                    if !image.config.working_dir.is_empty() {
                        crate::console_println!("  WorkingDir:   {}", image.config.working_dir);
                    }
                    if !image.config.env.is_empty() {
                        crate::console_println!("  Environment:");
                        for e in &image.config.env {
                            crate::console_println!("    {}", e);
                        }
                    }

                    if let Some(ns) = crate::container::namespace_ids(ct_id) {
                        crate::console_println!("  PID NS:       {}", ns.0);
                        crate::console_println!("  User NS:      {}", ns.1);
                        crate::console_println!("  Net NS:       {}", ns.2);
                    }

                    // Jail the container to its rootfs (must happen while
                    // still in Created state, before `run`).  The init process
                    // then resolves `/bin/sh`, `/lib/...`, etc. against the
                    // container's filesystem instead of the host.
                    if let Err(e) = crate::container::set_root_path(ct_id, &jail_root) {
                        crate::console_println!(
                            "[oci] Warning: could not set rootfs jail: {:?}", e
                        );
                    }
                    // Apply Docker `--read-only`: mark the container rootfs
                    // read-only (Created state). Writable `:rw` volumes below
                    // still punch writable holes through it.
                    if read_only_root {
                        match crate::container::set_read_only_root(ct_id, true) {
                            Ok(()) => crate::console_println!("  Root FS:      read-only"),
                            Err(e) => crate::console_println!(
                                "[oci] Warning: could not set read-only root: {:?}", e
                            ),
                        }
                    }
                    // If we mounted an overlay, record it on the container so
                    // `container delete` unmounts the adapter on teardown.
                    if mounted_overlay {
                        if let Err(e) = crate::container::set_rootfs_mount(ct_id, &merged_mount) {
                            crate::console_println!(
                                "[oci] Warning: could not record rootfs mount: {:?}", e
                            );
                        }
                    }
                    // Record the overlay id (independent of whether the adapter
                    // was mounted) so `container diff` can locate the writable
                    // scratch layer even when the merged mount fell back to the
                    // read-only lower dir.
                    if let Some(ov_id) = overlay_id {
                        if let Err(e) = crate::container::set_overlay_id(ct_id, Some(ov_id)) {
                            crate::console_println!(
                                "[oci] Warning: could not record overlay id: {:?}", e
                            );
                        }
                    }

                    // Install any `-v host:guest` volume (bind) mounts (also
                    // while still in Created state).  A volume lets the
                    // container see a host directory at a guest path, escaping
                    // the rootfs (e.g. `-v /srv/data:/data`).
                    for (host, guest, read_only) in &volumes {
                        match crate::container::add_volume_mount(ct_id, host, guest, *read_only) {
                            Ok(()) => crate::console_println!(
                                "  Volume:       {} -> {}{}",
                                host, guest,
                                if *read_only { " (ro)" } else { "" }
                            ),
                            Err(e) => crate::console_println!(
                                "[oci] Warning: could not add volume {}:{}: {:?}",
                                host, guest, e
                            ),
                        }
                    }

                    // Install any `--tmpfs /guest` in-memory mounts (Created
                    // state).  Each gives the container an ephemeral writable
                    // filesystem at the guest path, backed by a fresh memfs —
                    // common for scratch space in a `--read-only` container.
                    for guest in &tmpfs {
                        match crate::container::add_tmpfs_mount(ct_id, guest) {
                            Ok(()) => crate::console_println!(
                                "  Tmpfs:        {} (in-memory)", guest
                            ),
                            Err(e) => crate::console_println!(
                                "[oci] Warning: could not add tmpfs {}: {:?}",
                                guest, e
                            ),
                        }
                    }

                    // Install any `-p host:container` published ports (Created
                    // state).  The NAT rules forwarding host traffic to the
                    // container are installed at run() time; this records the
                    // intent.  Requires the container to have a network IP
                    // (set via `--net`), which add_port_publish enforces.
                    for &(proto, hp, cp) in &ports {
                        match crate::container::add_port_publish(ct_id, proto, hp, cp) {
                            Ok(()) => crate::console_println!(
                                "  Publish:      {:?} :{} -> :{}", proto, hp, cp
                            ),
                            Err(e) => crate::console_println!(
                                "[oci] Warning: could not publish {:?} :{} -> :{}: {:?} (need --net IP)",
                                proto, hp, cp, e
                            ),
                        }
                    }

                    // Launch the image's entrypoint/cmd as the container's
                    // init process, jailed to the rootfs.  `command[0]` is the
                    // executable; it is read from the host *inside* the rootfs
                    // (the kernel loads the image before the jail takes effect),
                    // then the running process resolves its own syscalls against
                    // the jail.
                    let launched = if command.is_empty() {
                        crate::console_println!(
                            "[oci] Image declares no entrypoint/cmd; not launching an init process."
                        );
                        false
                    } else {
                        // Guest-visible exe path (absolute within the rootfs).
                        let exe_rel = command.first().map(alloc::string::String::as_str)
                            .unwrap_or("");
                        let exe_guest = if exe_rel.starts_with('/') {
                            alloc::string::String::from(exe_rel)
                        } else {
                            alloc::format!("/{}", exe_rel)
                        };
                        // Host path to read the ELF from (jail root + guest
                        // path).  When an overlay is mounted this reads through
                        // the merged view; otherwise it reads the lower dir.
                        let exe_host = alloc::format!("{}{}", jail_root, exe_guest);

                        match crate::fs::vfs::Vfs::read_file(&exe_host) {
                            Ok(elf) => {
                                let argv_owned: alloc::vec::Vec<alloc::vec::Vec<u8>> =
                                    command.iter().map(|s| s.as_bytes().to_vec()).collect();
                                let argv_refs: alloc::vec::Vec<&[u8]> =
                                    argv_owned.iter().map(alloc::vec::Vec::as_slice).collect();
                                // Merge environment entries using Docker
                                // precedence: CLI `-e` > `--env-file` > image
                                // ENV, with no duplicate keys. Keys are the
                                // bytes before the first `=` (whole entry if
                                // none). We add CLI `-e` first, then env-file
                                // entries whose key isn't already set, then
                                // image ENV entries whose key isn't already set.
                                let mut envp_owned: alloc::vec::Vec<alloc::vec::Vec<u8>> =
                                    alloc::vec::Vec::new();
                                for spec in &extra_env {
                                    envp_owned.push(spec.as_bytes().to_vec());
                                }
                                for entry in &env_file_entries {
                                    let key = oci::env_entry_key(entry);
                                    let already = envp_owned
                                        .iter()
                                        .any(|e| oci::env_entry_key(e) == key);
                                    if !already {
                                        envp_owned.push(entry.clone());
                                    }
                                }
                                for entry in &image.config.env {
                                    let key = oci::env_entry_key(entry.as_bytes());
                                    let already = envp_owned
                                        .iter()
                                        .any(|e| oci::env_entry_key(e) == key);
                                    if !already {
                                        envp_owned.push(entry.as_bytes().to_vec());
                                    }
                                }
                                let envp_refs: alloc::vec::Vec<&[u8]> =
                                    envp_owned.iter().map(alloc::vec::Vec::as_slice).collect();
                                // Effective working directory: CLI `--workdir`/`-w`
                                // wins, else the image's `WorkingDir`, else none
                                // (init starts at `/`). Owned so the bytes outlive
                                // `opts`, which borrows them via `.cwd()`.
                                let effective_workdir: Option<alloc::string::String> =
                                    workdir.map(alloc::string::String::from).or_else(|| {
                                        let wd = &image.config.working_dir;
                                        if wd.is_empty() {
                                            None
                                        } else {
                                            Some(wd.clone())
                                        }
                                    });
                                // Effective user identity: CLI `--user`/`-u`
                                // wins, else the image's `User` config, else
                                // none (init stays root). Only numeric
                                // `uid[:gid]` is accepted — a username has no
                                // /etc/passwd to resolve against here, so it is
                                // warned and ignored. When `:gid` is omitted the
                                // gid defaults to 0 (matching Docker's behavior
                                // for a uid with no passwd entry).
                                let user_spec: Option<alloc::string::String> =
                                    user.map(alloc::string::String::from).or_else(|| {
                                        let u = &image.config.user;
                                        if u.is_empty() { None } else { Some(u.clone()) }
                                    });
                                let effective_uid_gid: Option<(u32, u32)> =
                                    user_spec.as_deref().and_then(|s| {
                                        let mut segs = s.splitn(2, ':');
                                        let uid_s = segs.next().unwrap_or("");
                                        let gid_s = segs.next();
                                        match (uid_s.parse::<u32>(), gid_s.map(str::parse::<u32>)) {
                                            (Ok(uid), None) => Some((uid, 0)),
                                            (Ok(uid), Some(Ok(gid))) => Some((uid, gid)),
                                            _ => {
                                                crate::console_println!(
                                                    "[oci] Ignoring user '{}': expected numeric uid[:gid]",
                                                    s
                                                );
                                                None
                                            }
                                        }
                                    });
                                let mut opts = crate::proc::spawn::SpawnOptions::new(&exe_guest)
                                    .argv(&argv_refs)
                                    .envp(&envp_refs)
                                    .exe_path(exe_guest.as_bytes());
                                if let Some(wd) = effective_workdir.as_deref() {
                                    opts = opts.cwd(wd.as_bytes());
                                    crate::console_println!("  WorkDir:      {}", wd);
                                }
                                if let Some((uid, gid)) = effective_uid_gid {
                                    opts = opts.uid_gid(uid, gid);
                                    crate::console_println!("  User:         {}:{}", uid, gid);
                                }
                                match crate::container::run(ct_id, &elf, &opts) {
                                    Ok(pid) => {
                                        crate::console_println!(
                                            "  Init PID:     {} ({})", pid, exe_guest
                                        );
                                        true
                                    }
                                    Err(e) => {
                                        crate::console_println!(
                                            "[oci] Failed to launch init process: {:?}", e
                                        );
                                        false
                                    }
                                }
                            }
                            Err(e) => {
                                crate::console_println!(
                                    "[oci] Could not read entrypoint '{}' (host {}): {:?}",
                                    exe_guest, exe_host, e
                                );
                                false
                            }
                        }
                    };

                    crate::console_println!();
                    if launched {
                        crate::console_println!(
                            "Container {} is running. Use 'container info {}' to inspect.",
                            ct_id, ct_id
                        );
                    } else {
                        // No init process launched — fall back to the manual
                        // model so the user can still exec into the container.
                        let _ = crate::container::start(ct_id);
                        crate::console_println!(
                            "Use 'container exec {}' to run commands in this container.", ct_id
                        );
                    }
                    crate::console_println!(
                        "Use 'container stop {}' then 'container delete {}' to clean up.",
                        ct_id, ct_id
                    );
                }
                Err(e) => {
                    // Release the network reservation made before create so a
                    // failed run does not leak an IP.
                    if let Some((nn, ip)) = network_lease {
                        let _ = crate::cnetwork::release(nn, ip);
                    }
                    crate::console_println!("[oci] Container creation failed: {:?}", e);
                }
            }
        }
        "save" => {
            // oci save <image-dir|name:tag> <out-tar>  (Docker `save`): bundle a
            // complete OCI image *directory tree* (index, manifest, config blob,
            // layer blobs) into a single ustar archive on the host VFS, so the
            // image can be moved to another host and restored with `oci load`.
            // A `name:tag` argument is first exported from the named store into a
            // temporary single-manifest layout (only that image's blobs), which
            // is then tarred and removed.  Unlike `container export` (which packs
            // a *container's* flattened rootfs), `save` preserves the image's
            // layered on-disk layout verbatim.
            let (Some(&src), Some(&out_path)) = (parts.get(1), parts.get(2)) else {
                crate::console_println!("Usage: oci save <image-dir|name:tag> <out-tar>");
                return;
            };
            let is_layout = crate::fs::vfs::Vfs::metadata(
                &alloc::format!("{}/oci-layout", src.trim_end_matches('/')),
            )
            .is_ok();
            let (pack_dir, temp) = if is_layout {
                (alloc::string::String::from(src.trim_end_matches('/')), false)
            } else {
                let tmp = alloc::string::String::from("/tmp/oci-save-tmp");
                let _ = crate::fs::vfs::Vfs::remove_recursive(&tmp);
                match oci::store_export_ref(src, &tmp) {
                    Ok(()) => (tmp, true),
                    Err(e) => {
                        crate::console_println!(
                            "Not an image dir or store reference '{}': {:?}", src, e
                        );
                        return;
                    }
                }
            };
            // Validate that a real OCI image landed before packing, so `save`
            // fails cleanly instead of producing a tar of arbitrary junk.
            match oci::load_image(&pack_dir) {
                Ok(image) => {
                    let layers = image.manifest.layers.len();
                    match crate::container::tar_tree(&pack_dir) {
                        Ok(archive) => {
                            match crate::fs::vfs::Vfs::write_file(out_path, &archive) {
                                Ok(()) => crate::console_println!(
                                    "Saved image {} ({} layers): {} bytes -> {}",
                                    src, layers, archive.len(), out_path
                                ),
                                Err(e) => crate::console_println!(
                                    "Failed to write '{}': {:?}", out_path, e
                                ),
                            }
                        }
                        Err(e) => crate::console_println!(
                            "Failed to pack image '{}': {:?}", src, e
                        ),
                    }
                }
                Err(e) => crate::console_println!(
                    "Not a valid OCI image at '{}': {:?}", pack_dir, e
                ),
            }
            if temp {
                let _ = crate::fs::vfs::Vfs::remove_recursive(&pack_dir);
            }
        }
        "load" => {
            // oci load <in-tar> [dest-dir]  (Docker `load`): restore an image
            // archive produced by `oci save`.  The tar is extracted via the
            // shared `untar_tree` primitive (which rejects `..`-escaping member
            // names before writing) into `dest-dir` if given, else into a temp
            // dir.  Any `ref.name`-annotated manifests are then imported into the
            // named store so the image is usable by `name:tag` — matching Docker,
            // where `load` repopulates the local image store.
            let Some(&tar_path) = parts.get(1) else {
                crate::console_println!("Usage: oci load <in-tar> [dest-dir]");
                return;
            };
            let archive = match crate::fs::vfs::Vfs::read_file(tar_path) {
                Ok(a) => a,
                Err(e) => {
                    crate::console_println!("Failed to read '{}': {:?}", tar_path, e);
                    return;
                }
            };
            let (extract_dir, temp) = match parts.get(2) {
                Some(&d) => (alloc::string::String::from(d), false),
                None => {
                    let tmp = alloc::string::String::from("/tmp/oci-load-tmp");
                    let _ = crate::fs::vfs::Vfs::remove_recursive(&tmp);
                    (tmp, true)
                }
            };
            match crate::container::untar_tree(&extract_dir, &archive) {
                Ok(()) => match oci::load_image(&extract_dir) {
                    Ok(image) => {
                        let layers = image.manifest.layers.len();
                        // Import ref.name-annotated tags into the store.
                        match oci::store_import_dir(&extract_dir) {
                            Ok(tags) if !tags.is_empty() => crate::console_println!(
                                "Loaded {} ({} bytes, {} layers) -> store tags: {}",
                                tar_path, archive.len(), layers, tags.join(", ")
                            ),
                            Ok(_) => crate::console_println!(
                                "Loaded {} ({} bytes, {} layers){}",
                                tar_path, archive.len(), layers,
                                if temp {
                                    " but no ref.name annotation; nothing tagged in store"
                                } else {
                                    ""
                                }
                            ),
                            Err(e) => crate::console_println!(
                                "Loaded {} but store import failed: {:?}", tar_path, e
                            ),
                        }
                    }
                    Err(e) => crate::console_println!(
                        "Extracted {} but it is not a valid OCI image: {:?}", tar_path, e
                    ),
                },
                Err(e) => crate::console_println!(
                    "Failed to extract '{}': {:?}", tar_path, e
                ),
            }
            if temp {
                let _ = crate::fs::vfs::Vfs::remove_recursive(&extract_dir);
            }
        }
        "build" => {
            // oci build <dockerfile> <context-dir> <dest-image-dir>
            //           [--build-arg KEY=VALUE ...]   (Docker `build`)
            // Parse a Dockerfile and author an OCI image directory. Every
            // instruction except RUN is supported (RUN needs the operator-gated
            // in-container exec — see open-questions.md Q17); build_image
            // reports a precise diagnostic in that case.
            let mut positional: alloc::vec::Vec<&str> = alloc::vec::Vec::new();
            let mut build_args: alloc::vec::Vec<(alloc::string::String, alloc::string::String)> =
                alloc::vec::Vec::new();
            let mut target: Option<&str> = None;
            let mut tag: Option<&str> = None;
            let mut i = 1usize;
            while let Some(&tok) = parts.get(i) {
                if tok == "-t" || tok == "--tag" {
                    if let Some(&t) = parts.get(i.saturating_add(1)) {
                        tag = Some(t);
                        i = i.saturating_add(2);
                    } else {
                        crate::console_println!("[oci] -t/--tag needs a name:tag");
                        i = i.saturating_add(1);
                    }
                } else if let Some(t) = tok.strip_prefix("--tag=") {
                    tag = Some(t);
                    i = i.saturating_add(1);
                } else if tok == "--build-arg" {
                    if let Some(&kv) = parts.get(i.saturating_add(1)) {
                        // KEY=VALUE; a bare KEY takes the ambient value "" here
                        // (the builder only applies it to a declared ARG).
                        let (k, v) = match kv.split_once('=') {
                            Some((k, v)) => (k, v),
                            None => (kv, ""),
                        };
                        if k.is_empty() {
                            crate::console_println!("[oci] Ignoring --build-arg '{}': empty key", kv);
                        } else {
                            build_args.push((
                                alloc::string::String::from(k),
                                alloc::string::String::from(v),
                            ));
                        }
                        i = i.saturating_add(2);
                    } else {
                        crate::console_println!("[oci] --build-arg needs KEY=VALUE");
                        i = i.saturating_add(1);
                    }
                } else if tok == "--target" {
                    if let Some(&t) = parts.get(i.saturating_add(1)) {
                        target = Some(t);
                        i = i.saturating_add(2);
                    } else {
                        crate::console_println!("[oci] --target needs a stage name or index");
                        i = i.saturating_add(1);
                    }
                } else if let Some(t) = tok.strip_prefix("--target=") {
                    target = Some(t);
                    i = i.saturating_add(1);
                } else {
                    positional.push(tok);
                    i = i.saturating_add(1);
                }
            }
            let (Some(&dockerfile), Some(&ctx), Some(&dest)) =
                (positional.first(), positional.get(1), positional.get(2))
            else {
                crate::console_println!(
                    "Usage: oci build <dockerfile> <context-dir> <dest-image-dir> [-t name:tag] [--build-arg KEY=VALUE ...] [--target STAGE]"
                );
                return;
            };
            match crate::fs::vfs::Vfs::read_file(dockerfile) {
                Ok(df) => match oci::build_image_targeted(&df, ctx, dest, &build_args, target) {
                    Ok(desc) => {
                        crate::console_println!(
                            "Built image -> {} (manifest {}, {} bytes)",
                            dest, desc.digest, desc.size
                        );
                        // `-t name:tag` imports the freshly-built image into the
                        // named store so it can be referenced by name.
                        if let Some(reference) = tag {
                            match oci::store_tag_from_dir(dest, reference) {
                                Ok(_) => crate::console_println!("Tagged -> {}", reference),
                                Err(e) => crate::console_println!(
                                    "build succeeded but tag '{}' failed: {:?}", reference, e
                                ),
                            }
                        }
                    }
                    Err(e) => crate::console_println!("build failed: {}", e.describe()),
                },
                Err(e) => {
                    crate::console_println!("Failed to read Dockerfile '{}': {:?}", dockerfile, e);
                }
            }
        }
        // Named image store — `docker tag`/`images`/`rmi` by name:tag.
        "tag" => {
            // Two forms:
            //   oci tag <image-dir> <name:tag>   — import a built dir + tag it
            //   oci tag <src-ref>   <name:tag>    — add a second tag (both in store)
            let (Some(&a), Some(&b)) = (parts.get(1), parts.get(2)) else {
                crate::console_println!("Usage: oci tag <image-dir|src-ref> <name:tag>");
                return;
            };
            // A source that looks like a path (has a `/` or exists as a dir) is
            // imported; otherwise it is treated as an existing store reference.
            let is_dir = crate::fs::vfs::Vfs::metadata(a)
                .map(|m| m.entry_type == crate::fs::vfs::EntryType::Directory)
                .unwrap_or(false);
            if is_dir {
                match oci::store_tag_from_dir(a, b) {
                    Ok(digest) => crate::console_println!("Tagged {} -> {} ({})", a, b, digest),
                    Err(e) => crate::console_println!("tag failed: {:?}", e),
                }
            } else {
                match oci::store_add_tag(a, b) {
                    Ok(()) => crate::console_println!("Tagged {} -> {}", a, b),
                    Err(e) => crate::console_println!("tag failed: {:?}", e),
                }
            }
        }
        "images" | "image" | "ls" => {
            match oci::store_list() {
                Ok(imgs) if imgs.is_empty() => {
                    crate::console_println!("No images in store ({}).", oci::STORE_DIR);
                }
                Ok(imgs) => {
                    crate::console_println!("{:<28} {:<20} {:>10}", "REPOSITORY:TAG", "DIGEST", "SIZE");
                    for im in imgs {
                        // Show the short (12-hex) digest, Docker-style.
                        let short = im
                            .digest
                            .split_once(':')
                            .map(|(_, hex)| hex.get(..12).unwrap_or(hex))
                            .unwrap_or(&im.digest);
                        crate::console_println!("{:<28} {:<20} {:>10}", im.reference, short, im.size);
                    }
                }
                Err(e) => crate::console_println!("images failed: {:?}", e),
            }
        }
        "rmi" => {
            let Some(&reference) = parts.get(1) else {
                crate::console_println!("Usage: oci rmi <name:tag>");
                return;
            };
            match oci::store_remove(reference) {
                Ok(()) => crate::console_println!("Untagged: {}", reference),
                Err(e) => crate::console_println!("rmi failed: {:?}", e),
            }
        }
        "commit" => {
            // oci commit <container-id> <dest-dir> [name:tag]  (Docker
            // `commit`): author a new OCI image from a container's filesystem
            // changes (its overlay upper layer + whiteouts), layered on the
            // base image the container was created from. The image is written
            // as a standalone OCI layout at <dest-dir>; an optional trailing
            // `name:tag` also tags it into the image store.
            let (Some(id_str), Some(&dest_dir)) = (parts.get(1), parts.get(2)) else {
                crate::console_println!("Usage: oci commit <container-id> <dest-dir> [name:tag]");
                return;
            };
            let Ok(id) = id_str.parse::<u32>() else {
                crate::console_println!("Invalid container ID");
                return;
            };
            match crate::container::commit_image(id, dest_dir) {
                Ok(digest) => {
                    crate::console_println!("Committed container {} -> image {} ({})", id, dest_dir, digest);
                    if let Some(&reference) = parts.get(3) {
                        match oci::store_tag_from_dir(dest_dir, reference) {
                            Ok(d) => crate::console_println!("Tagged {} -> {} ({})", dest_dir, reference, d),
                            Err(e) => crate::console_println!("commit tag failed: {:?}", e),
                        }
                    }
                }
                Err(e) => crate::console_println!("commit failed: {:?}", e),
            }
        }
        "test" => {
            match oci::self_test() {
                Ok(()) => crate::console_println!("OCI self-test passed."),
                Err(e) => crate::console_println!("OCI self-test failed: {:?}", e),
            }
        }
        _ => {
            crate::console_println!("Usage: oci [inspect|layers|history|run|build|commit|tag|images|rmi|save|load|test]");
            crate::console_println!("  oci inspect <dir>  — show image metadata and config");
            crate::console_println!("  oci layers <dir>   — list layer digests and sizes");
            crate::console_println!("  oci history <dir>  — show build history (per-step created-by + size)");
            crate::console_println!("  oci build <dockerfile> <context-dir> <dest-dir> [--build-arg K=V ...] [--target STAGE] — build an OCI image from a Dockerfile (Docker build; RUN deferred, see Q17)");
            crate::console_println!("  oci save <dir> <out-tar>   — bundle an image directory into a tar (Docker save)");
            crate::console_println!("  oci load <in-tar> <dest-dir> — restore a saved image tar into a directory (Docker load)");
            crate::console_println!("  oci commit <container-id> <dest-dir> [name:tag] — author a new image from a container's changes (Docker commit)");
            crate::console_println!("  oci run <dir> [--name NAME] [--net IP[,gw=..,dns=..]] [--network NAME] [--network-alias NAME ...] [-v src:/guest[:ro|:rw] ...] [--tmpfs /guest ...] [-p host:container[/proto] ...] [-e KEY=value ...] [--env-file FILE ...] [-m SIZE] [--cpus N] [--read-only] [-w DIR] [-u UID[:GID]] [--entrypoint EXE] [--hostname NAME] [--label K=V ...] [--label-file FILE] [COMMAND [ARG...]]");
            crate::console_println!("                     — create container from OCI image (-v shares a host dir, -p publishes a port, -e sets env, -m/--cpus limit resources, --read-only locks the rootfs, -w sets the workdir, -u sets the numeric user, --entrypoint/trailing COMMAND override the image entrypoint/cmd)");
            crate::console_println!("  oci test           — run parser self-tests");
        }
    }
}

fn cmd_scfilter(args: &str) {
    use crate::scfilter;

    let parts: alloc::vec::Vec<&str> = args.split_whitespace().collect();
    let cmd = parts.first().copied().unwrap_or("");

    match cmd {
        "" | "list" | "ls" => {
            let count = scfilter::active_count();
            crate::console_println!("Active syscall filters: {}", count);
        }
        "install" => {
            let Some(pid_str) = parts.get(1) else {
                crate::console_println!("Usage: scfilter install <pid> [deny-all]");
                return;
            };
            let Ok(pid) = pid_str.parse::<u64>() else {
                crate::console_println!("Invalid PID");
                return;
            };
            let mode = parts.get(2).copied().unwrap_or("allow-all");
            let result = if mode == "deny-all" {
                scfilter::install_deny_all(pid)
            } else {
                scfilter::install(pid)
            };
            match result {
                Ok(()) => crate::console_println!(
                    "Installed {} filter for PID {}", mode, pid
                ),
                Err(e) => crate::console_println!("Error: {:?}", e),
            }
        }
        "remove" | "rm" => {
            let Some(pid_str) = parts.get(1) else {
                crate::console_println!("Usage: scfilter remove <pid>");
                return;
            };
            let Ok(pid) = pid_str.parse::<u64>() else {
                crate::console_println!("Invalid PID");
                return;
            };
            scfilter::remove(pid);
            crate::console_println!("Removed filter for PID {}", pid);
        }
        "deny" => {
            // scfilter deny <pid> <syscall_nr>
            if parts.len() < 3 {
                crate::console_println!("Usage: scfilter deny <pid> <syscall_nr>");
                return;
            }
            let Ok(pid) = parts[1].parse::<u64>() else {
                crate::console_println!("Invalid PID");
                return;
            };
            let Ok(nr) = parts[2].parse::<u64>() else {
                crate::console_println!("Invalid syscall number");
                return;
            };
            match scfilter::deny(pid, nr) {
                Ok(()) => crate::console_println!("Denied syscall {} for PID {}", nr, pid),
                Err(e) => crate::console_println!("Error: {:?}", e),
            }
        }
        "allow" => {
            if parts.len() < 3 {
                crate::console_println!("Usage: scfilter allow <pid> <syscall_nr>");
                return;
            }
            let Ok(pid) = parts[1].parse::<u64>() else {
                crate::console_println!("Invalid PID");
                return;
            };
            let Ok(nr) = parts[2].parse::<u64>() else {
                crate::console_println!("Invalid syscall number");
                return;
            };
            match scfilter::allow(pid, nr) {
                Ok(()) => crate::console_println!("Allowed syscall {} for PID {}", nr, pid),
                Err(e) => crate::console_println!("Error: {:?}", e),
            }
        }
        "check" => {
            if parts.len() < 3 {
                crate::console_println!("Usage: scfilter check <pid> <syscall_nr>");
                return;
            }
            let Ok(pid) = parts[1].parse::<u64>() else {
                crate::console_println!("Invalid PID");
                return;
            };
            let Ok(nr) = parts[2].parse::<u64>() else {
                crate::console_println!("Invalid syscall number");
                return;
            };
            let allowed = scfilter::check(pid, nr);
            crate::console_println!(
                "Syscall {} for PID {}: {}", nr, pid,
                if allowed { "ALLOWED" } else { "DENIED" }
            );
        }
        "info" => {
            let Some(pid_str) = parts.get(1) else {
                crate::console_println!("Usage: scfilter info <pid>");
                return;
            };
            let Ok(pid) = pid_str.parse::<u64>() else {
                crate::console_println!("Invalid PID");
                return;
            };
            if !scfilter::has_filter(pid) {
                crate::console_println!("No filter installed for PID {}", pid);
                return;
            }
            let allowed = scfilter::allowed_count(pid).unwrap_or(0);
            let denied = scfilter::deny_count(pid);
            crate::console_println!("=== Syscall Filter for PID {} ===", pid);
            crate::console_println!("  Allowed syscalls: {}/{}", allowed, scfilter::MAX_SYSCALL_NR);
            crate::console_println!("  Denied attempts:  {}", denied);
        }
        "test" => {
            scfilter::self_test();
        }
        _ => {
            crate::console_println!("Usage: scfilter [list|install|remove|deny|allow|check|info|test]");
            crate::console_println!("  scfilter                           — show active filter count");
            crate::console_println!("  scfilter install PID [deny-all]    — install filter");
            crate::console_println!("  scfilter remove PID                — remove filter");
            crate::console_println!("  scfilter deny PID NR               — deny syscall NR");
            crate::console_println!("  scfilter allow PID NR              — allow syscall NR");
            crate::console_println!("  scfilter check PID NR              — test if allowed");
            crate::console_println!("  scfilter info PID                  — show filter stats");
            crate::console_println!("  scfilter test                      — run self-test");
            crate::console_println!();
            crate::console_println!("Aliases: seccomp");
        }
    }
}

///   capreq approve ID     — approve a pending request
///   capreq deny ID        — deny a pending request
///   capreq test           — submit a test request
///   capreq handler on/off — register/unregister policy handler
fn cmd_cap_request(args: &str) {
    use crate::cap::request;

    let parts: alloc::vec::Vec<&str> = args.split_whitespace().collect();
    let cmd = parts.first().copied().unwrap_or("");

    match cmd {
        "" | "list" | "pending" => {
            let pending = request::list_pending();
            if pending.is_empty() {
                crate::console_println!("No pending capability requests.");
                crate::console_println!("Handler active: {}", request::handler_active());
                return;
            }
            crate::console_println!("=== Pending Capability Requests ({}) ===", pending.len());
            for req in &pending {
                crate::console_println!(
                    "  #{}: pid={} ({}) wants {:?}/{:?}",
                    req.id, req.pid, req.process_name,
                    req.resource_type, req.rights
                );
                crate::console_println!("       Reason: {}", req.reason);
            }
        }
        "all" => {
            let all = request::list_all();
            if all.is_empty() {
                crate::console_println!("No capability requests on record.");
                return;
            }
            crate::console_println!("=== All Capability Requests ({}) ===", all.len());
            for req in &all {
                let status_str = match req.status {
                    request::RequestStatus::Pending => "PENDING",
                    request::RequestStatus::Approved => "APPROVED",
                    request::RequestStatus::Denied => "DENIED",
                    request::RequestStatus::TimedOut => "TIMEOUT",
                    request::RequestStatus::Cancelled => "CANCEL",
                };
                crate::console_println!(
                    "  #{}: [{}] pid={} ({}) {:?}/{:?} -- {}",
                    req.id, status_str, req.pid, req.process_name,
                    req.resource_type, req.rights, req.reason
                );
            }
        }
        "approve" | "allow" | "grant" => {
            let id_str = parts.get(1).unwrap_or(&"");
            let id: u64 = match id_str.parse() {
                Ok(v) => v,
                Err(_) => {
                    crate::console_println!("Usage: capreq approve <request-id>");
                    return;
                }
            };
            match request::approve(id) {
                Ok(req) => {
                    crate::console_println!(
                        "Approved #{}: pid={} gets {:?}/{:?}",
                        id, req.pid, req.resource_type, req.rights
                    );
                }
                Err(e) => {
                    crate::console_println!("Failed to approve #{}: {:?}", id, e);
                }
            }
        }
        "deny" | "reject" => {
            let id_str = parts.get(1).unwrap_or(&"");
            let id: u64 = match id_str.parse() {
                Ok(v) => v,
                Err(_) => {
                    crate::console_println!("Usage: capreq deny <request-id>");
                    return;
                }
            };
            match request::deny(id) {
                Ok(()) => {
                    crate::console_println!("Denied #{}", id);
                }
                Err(e) => {
                    crate::console_println!("Failed to deny #{}: {:?}", id, e);
                }
            }
        }
        "handler" => {
            let action = parts.get(1).copied().unwrap_or("");
            match action {
                "on" | "register" => {
                    request::register_handler();
                    crate::console_println!("Policy handler registered (requests will pend)");
                }
                "off" | "unregister" => {
                    request::unregister_handler();
                    crate::console_println!("Policy handler unregistered (auto-deny mode)");
                }
                _ => {
                    crate::console_println!(
                        "Handler: {} ({})",
                        if request::handler_active() { "active" } else { "inactive" },
                        if request::handler_active() { "requests pend" } else { "auto-deny" }
                    );
                }
            }
        }
        "test" => {
            // Submit a test request for demonstration.
            if !request::handler_active() {
                request::register_handler();
                crate::console_println!("(registered handler for test)");
            }
            match request::request_capability(
                1,
                "kshell",
                crate::cap::ResourceType::File,
                crate::cap::Rights::WRITE,
                "Test request from kshell",
            ) {
                Ok(id) => {
                    crate::console_println!("Submitted test request #{}", id);
                    crate::console_println!("Use 'capreq approve {}' or 'capreq deny {}'", id, id);
                }
                Err(e) => {
                    crate::console_println!("Failed to submit test request: {:?}", e);
                }
            }
        }
        _ => {
            crate::console_println!("Usage: capreq [list|all|approve ID|deny ID|handler on/off|test]");
        }
    }
}

fn cmd_version() {
    shell_println!("Kernel v0.1.0 (x86_64, microkernel)");
    shell_println!("Built with Rust, AI-developed");
}

/// `uname [-asnrvmo]` — print system information.
///
/// Flags:
/// - `-s`: kernel name ("MintOS")
/// - `-n`: network hostname
/// - `-r`: kernel release ("0.1.0")
/// - `-v`: kernel version string (includes build date from RTC)
/// - `-m`: machine hardware name ("x86_64")
/// - `-o`: operating system ("MintOS")
/// - `-a`: all of the above
/// - No flags: same as `-s`
fn cmd_uname(args: &str) {
    let trimmed = args.trim();

    // Parse which fields to show.
    let mut show_s = false;
    let mut show_n = false;
    let mut show_r = false;
    let mut show_v = false;
    let mut show_m = false;
    let mut show_o = false;

    if trimmed.is_empty() {
        // No flags → default to -s.
        show_s = true;
    } else {
        for token in trimmed.split_whitespace() {
            if let Some(flags) = token.strip_prefix('-') {
                for ch in flags.chars() {
                    match ch {
                        'a' => {
                            show_s = true;
                            show_n = true;
                            show_r = true;
                            show_v = true;
                            show_m = true;
                            show_o = true;
                        }
                        's' => show_s = true,
                        'n' => show_n = true,
                        'r' => show_r = true,
                        'v' => show_v = true,
                        'm' => show_m = true,
                        'o' => show_o = true,
                        _ => {
                            crate::console_println!(
                                "uname: invalid option -- '{}'", ch
                            );
                            set_exit(1);
                            return;
                        }
                    }
                }
            } else {
                crate::console_println!(
                    "uname: extra operand '{}'", token
                );
                set_exit(1);
                return;
            }
        }
    }

    // Collect fields in POSIX order: s n r v m o.
    let mut parts: alloc::vec::Vec<alloc::string::String> = alloc::vec::Vec::new();

    if show_s {
        parts.push(alloc::string::String::from("MintOS"));
    }
    if show_n {
        parts.push(crate::fs::sysfs::get_hostname());
    }
    if show_r {
        parts.push(alloc::string::String::from("0.1.0"));
    }
    if show_v {
        let dt = crate::rtc::read_datetime();
        parts.push(alloc::format!(
            "#1 SMP {:04}-{:02}-{:02}",
            dt.year, dt.month, dt.day
        ));
    }
    if show_m {
        parts.push(alloc::string::String::from("x86_64"));
    }
    if show_o {
        parts.push(alloc::string::String::from("MintOS"));
    }

    let line: alloc::string::String = parts.join(" ");
    shell_println!("{}", line);
}

// ---------------------------------------------------------------------------
// Text processing utilities
// ---------------------------------------------------------------------------

/// `sort FILE` — sort lines of a file alphabetically.
///
/// Options: `sort -r FILE` for reverse order.
fn cmd_sort(args: &str) {
    let (reverse, path) = if args.starts_with("-r ") {
        (true, args.get(3..).unwrap_or("").trim())
    } else {
        (false, args.trim())
    };

    if path.is_empty() {
        crate::console_println!("Usage: sort [-r] <file>");
        return;
    }

    let data = match crate::fs::Vfs::read_file(path) {
        Ok(d) => d,
        Err(e) => {
            crate::console_println!("sort: cannot read '{}': {:?}", path, e);
            return;
        }
    };

    let text = match core::str::from_utf8(&data) {
        Ok(t) => t,
        Err(_) => {
            crate::console_println!("sort: file is not valid UTF-8");
            return;
        }
    };

    let mut lines: Vec<&str> = text.lines().collect();
    lines.sort_unstable();
    if reverse {
        lines.reverse();
    }

    for line in &lines {
        shell_println!("{}", line);
    }
}

/// `uniq FILE` — remove adjacent duplicate lines.
///
/// Options: `uniq -c FILE` to prefix lines with occurrence count.
fn cmd_uniq(args: &str) {
    let (count_mode, path) = if args.starts_with("-c ") {
        (true, args.get(3..).unwrap_or("").trim())
    } else {
        (false, args.trim())
    };

    if path.is_empty() {
        crate::console_println!("Usage: uniq [-c] <file>");
        return;
    }

    let data = match crate::fs::Vfs::read_file(path) {
        Ok(d) => d,
        Err(e) => {
            crate::console_println!("uniq: cannot read '{}': {:?}", path, e);
            return;
        }
    };

    let text = match core::str::from_utf8(&data) {
        Ok(t) => t,
        Err(_) => {
            crate::console_println!("uniq: file is not valid UTF-8");
            return;
        }
    };

    let lines: Vec<&str> = text.lines().collect();
    if lines.is_empty() {
        return;
    }

    let mut prev = lines[0];
    let mut count = 1u64;

    for &line in lines.iter().skip(1) {
        if line == prev {
            count = count.wrapping_add(1);
        } else {
            if count_mode {
                shell_println!("{:7} {}", count, prev);
            } else {
                shell_println!("{}", prev);
            }
            prev = line;
            count = 1;
        }
    }
    // Print the last run.
    if count_mode {
        shell_println!("{:7} {}", count, prev);
    } else {
        shell_println!("{}", prev);
    }
}

// ---------------------------------------------------------------------------
// Pipe-input variants
//
// These accept piped text as a second argument.  When `args` is non-empty
// (e.g. a filename), the piped input is ignored and the file-based command
// runs instead.  When `args` is empty, the piped text is processed directly.
// ---------------------------------------------------------------------------

/// Sort piped input lines.  If `args` is non-empty it is treated as a
/// filename (delegates to `cmd_sort`).
fn cmd_sort_input(args: &str, input: &str) {
    if !args.is_empty() {
        cmd_sort(args);
        return;
    }
    let mut lines: Vec<&str> = input.lines().collect();
    lines.sort_unstable();
    for line in &lines {
        shell_println!("{}", line);
    }
}

/// Remove adjacent duplicate lines from piped input.  If `args` is
/// non-empty it is treated as a filename (delegates to `cmd_uniq`).
fn cmd_uniq_input(args: &str, input: &str) {
    if !args.is_empty() {
        cmd_uniq(args);
        return;
    }
    let lines: Vec<&str> = input.lines().collect();
    if lines.is_empty() {
        return;
    }

    let mut prev = lines[0];
    shell_println!("{}", prev);
    for &line in lines.iter().skip(1) {
        if line != prev {
            shell_println!("{}", line);
            prev = line;
        }
    }
}

/// Grep piped input for a pattern.  `args` is the search pattern (no file
/// argument).  If `args` contains a space it is interpreted as
/// `<pattern> <file>` and delegates to `cmd_grep`.
fn cmd_grep_input(args: &str, input: &str) {
    // Parse flags and find the pattern.
    let mut flags = GrepFlags::new();
    let mut positional: alloc::vec::Vec<&str> = Vec::new();

    for word in args.split_whitespace() {
        if word.starts_with('-') && word.len() > 1 && !word.starts_with("--") {
            for ch in word[1..].chars() {
                match ch {
                    'i' => flags.case_insensitive = true,
                    'I' => flags.case_insensitive = false,
                    'v' => flags.invert = true,
                    'c' => flags.count_only = true,
                    'n' => flags.show_line_numbers = true,
                    'w' => flags.whole_word = true,
                    _ => {}
                }
            }
        } else {
            positional.push(word);
        }
    }

    // If there are 2+ positional args, it looks like "pattern file" — delegate.
    if positional.len() >= 2 {
        cmd_grep(args);
        return;
    }

    let pattern = match positional.first() {
        Some(p) => *p,
        None => {
            crate::console_println!("grep: no pattern specified");
            return;
        }
    };

    let pattern_cmp = if flags.case_insensitive {
        to_lower(pattern)
    } else {
        String::from(pattern)
    };

    let mut match_count = 0usize;
    for (line_num, line) in input.lines().enumerate() {
        let line_cmp = if flags.case_insensitive {
            to_lower(line)
        } else {
            String::from(line)
        };

        let matched = grep_matches(&line_cmp, &pattern_cmp, flags.whole_word);
        let show = if flags.invert { !matched } else { matched };

        if show {
            match_count = match_count.saturating_add(1);

            if !flags.count_only {
                if flags.show_line_numbers {
                    shell_println!("{}: {}", line_num.saturating_add(1), line);
                } else {
                    shell_println!("{}", line);
                }
            }

            if match_count >= flags.max_matches {
                shell_println!("... (showing first {} matches)", flags.max_matches);
                break;
            }
        }
    }

    if flags.count_only {
        shell_println!("{}", match_count);
    } else if match_count == 0 {
        crate::console_println!("grep: no matches for '{}'", pattern);
    }
}

/// Show the first N lines of piped input.  `args` is an optional line
/// count (default 10).  If `args` looks like a filename (non-numeric),
/// delegates to `cmd_head`.
fn cmd_head_input(args: &str, input: &str) {
    let trimmed = args.trim();

    // If args is non-empty and not purely numeric, treat as "N file" or
    // just "file" — delegate to the file-based command.
    if !trimmed.is_empty() {
        if trimmed.parse::<usize>().is_err() {
            cmd_head(args);
            return;
        }
    }

    let count: usize = if trimmed.is_empty() {
        10
    } else {
        trimmed.parse::<usize>().unwrap_or(10)
    };

    for (printed, line) in input.lines().enumerate() {
        if printed >= count {
            break;
        }
        shell_println!("{}", line);
    }
}

/// Show the last N lines of piped input.  `args` is an optional line
/// count (default 10).  If `args` looks like a filename (non-numeric),
/// delegates to `cmd_tail`.
fn cmd_tail_input(args: &str, input: &str) {
    let trimmed = args.trim();

    if !trimmed.is_empty() {
        if trimmed.parse::<usize>().is_err() {
            cmd_tail(args);
            return;
        }
    }

    let count: usize = if trimmed.is_empty() {
        10
    } else {
        trimmed.parse::<usize>().unwrap_or(10)
    };

    let lines: Vec<&str> = input.lines().collect();
    let start = if lines.len() > count { lines.len() - count } else { 0 };
    for line in &lines[start..] {
        shell_println!("{}", line);
    }
}

/// Count lines, words, and bytes of piped input.  `args` is ignored
/// (if non-empty, delegates to `cmd_wc` with a filename).
#[allow(clippy::arithmetic_side_effects)]
fn cmd_wc_input(args: &str, input: &str) {
    if !args.is_empty() {
        cmd_wc(args);
        return;
    }

    let bytes = input.len();
    let mut lines: usize = 0;
    let mut words: usize = 0;
    let mut in_word = false;

    for b in input.bytes() {
        if b == b'\n' {
            lines += 1;
        }
        let is_ws = b == b' ' || b == b'\t' || b == b'\n' || b == b'\r';
        if is_ws {
            in_word = false;
        } else if !in_word {
            in_word = true;
            words += 1;
        }
    }

    shell_println!("  {} lines  {} words  {} bytes", lines, words, bytes);
}

// ---------------------------------------------------------------------------
// Script execution, text utilities, and misc commands
// ---------------------------------------------------------------------------

/// Execute kshell commands from a file (like bash `source` or `.`).
///
/// Each non-empty, non-comment line in the file is executed as a
/// separate command.  Lines starting with `#` are comments.
/// Maximum nesting depth is 8 to prevent infinite recursion.
fn cmd_source(args: &str) {
    /// Track recursion depth to prevent infinite `source` loops.
    static SOURCE_DEPTH: Mutex<u8> = Mutex::new(0);

    const MAX_DEPTH: u8 = 8;

    if args.is_empty() {
        crate::console_println!("Usage: source <script-file>");
        return;
    }

    let path = resolve_path(args);

    let data = match crate::fs::Vfs::read_file(&path) {
        Ok(d) => d,
        Err(e) => {
            crate::console_println!("source: {}: {:?}", path, e);
            return;
        }
    };

    let text = match core::str::from_utf8(&data) {
        Ok(s) => s,
        Err(_) => {
            crate::console_println!("source: {}: not a text file", path);
            return;
        }
    };

    // Check recursion depth.
    {
        let mut depth = SOURCE_DEPTH.lock();
        if *depth >= MAX_DEPTH {
            crate::console_println!("source: maximum nesting depth ({}) exceeded", MAX_DEPTH);
            return;
        }
        *depth = depth.saturating_add(1);
    }

    // Execute each line.
    for (line_num, line) in text.lines().enumerate() {
        let trimmed = line.trim();
        // Skip empty lines and comments — but NOT while we're collecting
        // a here-document body (where #-lines are literal content).
        let in_heredoc = HEREDOC_COLLECTOR.lock().is_some();
        if !in_heredoc && (trimmed.is_empty() || trimmed.starts_with('#')) {
            continue;
        }
        crate::serial_println!("[source] {}:{}: {}", path, line_num.saturating_add(1), trimmed);
        execute(trimmed);

        // `set -e` (errexit): abort script on non-zero exit status.
        if OPT_ERREXIT.load(core::sync::atomic::Ordering::Relaxed) && last_exit() != 0 {
            crate::console_println!(
                "{}:{}: command failed (exit {}), aborting (set -e)",
                path,
                line_num.saturating_add(1),
                last_exit(),
            );
            break;
        }
    }

    // Decrement depth.
    {
        let mut depth = SOURCE_DEPTH.lock();
        *depth = depth.saturating_sub(1);
    }
}

/// Print a sequence of numbers (like Unix `seq`).
///
/// `seq N` prints 1..N.  `seq N M` prints N..M.
fn cmd_seq(args: &str) {
    let parts: Vec<&str> = args.split_whitespace().collect();

    let (start, end) = match parts.len() {
        1 => {
            let n = match parts[0].parse::<i64>() {
                Ok(v) => v,
                Err(_) => {
                    crate::console_println!("Usage: seq N [M]");
                    return;
                }
            };
            (1i64, n)
        }
        2 => {
            let a = parts[0].parse::<i64>().unwrap_or(1);
            let b = parts[1].parse::<i64>().unwrap_or(1);
            (a, b)
        }
        _ => {
            crate::console_println!("Usage: seq N [M]");
            return;
        }
    };

    if start <= end {
        let mut i = start;
        while i <= end {
            shell_println!("{}", i);
            i = i.saturating_add(1);
        }
    } else {
        let mut i = start;
        while i >= end {
            shell_println!("{}", i);
            i = i.saturating_sub(1);
        }
    }
}

/// Number lines of a file (like Unix `nl`).
fn cmd_nl(args: &str) {
    if args.is_empty() {
        crate::console_println!("Usage: nl <file>");
        return;
    }

    let path = resolve_path(args);

    let data = match crate::fs::Vfs::read_file(&path) {
        Ok(d) => d,
        Err(e) => {
            crate::console_println!("nl: {}: {:?}", path, e);
            return;
        }
    };

    let text = core::str::from_utf8(&data).unwrap_or("<binary>");
    for (i, line) in text.lines().enumerate() {
        shell_println!("{:>6}\t{}", i.saturating_add(1), line);
    }
}

/// Number lines of piped input.
fn cmd_nl_input(args: &str, input: &str) {
    if !args.is_empty() {
        cmd_nl(args);
        return;
    }
    for (i, line) in input.lines().enumerate() {
        shell_println!("{:>6}\t{}", i.saturating_add(1), line);
    }
}

/// Reverse the order of lines in a file (like Unix `tac`).
fn cmd_rev(args: &str) {
    if args.is_empty() {
        crate::console_println!("Usage: rev <file>");
        return;
    }

    let path = resolve_path(args);

    let data = match crate::fs::Vfs::read_file(&path) {
        Ok(d) => d,
        Err(e) => {
            crate::console_println!("rev: {}: {:?}", path, e);
            return;
        }
    };

    let text = core::str::from_utf8(&data).unwrap_or("<binary>");
    let lines: Vec<&str> = text.lines().collect();
    for line in lines.iter().rev() {
        shell_println!("{}", line);
    }
}

/// Reverse lines of piped input.
fn cmd_rev_input(args: &str, input: &str) {
    if !args.is_empty() {
        cmd_rev(args);
        return;
    }
    let lines: Vec<&str> = input.lines().collect();
    for line in lines.iter().rev() {
        shell_println!("{}", line);
    }
}

/// `cut -d DELIM -f N [FILE]` — extract fields from each line.
///
/// Supports:
/// - `-d C`: delimiter character (default tab)
/// - `-f N` or `-f N,M,...`: field numbers (1-based)
/// - `-c N-M`: character ranges
#[allow(clippy::arithmetic_side_effects)]
fn cmd_cut(args: &str) {
    let (delim, fields, chars_range, file_path) = parse_cut_args(args);

    if let Some(path) = file_path {
        let resolved = resolve_path(&path);
        match crate::fs::Vfs::read_file(&resolved) {
            Ok(data) => {
                let text = core::str::from_utf8(&data).unwrap_or("");
                cut_process(text, delim, &fields, chars_range);
            }
            Err(e) => {
                crate::console_println!("cut: {}: {:?}", path, e);
                set_exit(1);
            }
        }
    } else {
        crate::console_println!("Usage: cut -d DELIM -f FIELDS [file]  or  cut -c RANGE [file]");
        set_exit(1);
    }
}

fn cmd_cut_input(args: &str, input: &str) {
    let (delim, fields, chars_range, _) = parse_cut_args(args);
    cut_process(input, delim, &fields, chars_range);
}

/// Parsed `cut` arguments: (delimiter, field numbers, char range, file path).
type CutArgs = (char, Vec<usize>, Option<(usize, usize)>, Option<String>);

/// Parse cut command arguments.
fn parse_cut_args(args: &str) -> CutArgs {
    let mut delim = '\t';
    let mut fields: Vec<usize> = Vec::new();
    let mut chars_range: Option<(usize, usize)> = None;
    let mut file_path: Option<String> = None;
    let mut rest = args;

    loop {
        rest = rest.trim_start();
        if rest.starts_with("-d") {
            rest = rest.get(2..).unwrap_or("").trim_start();
            if let Some(c) = rest.chars().next() {
                delim = c;
                rest = rest.get(c.len_utf8()..).unwrap_or("");
            }
        } else if rest.starts_with("-f") {
            rest = rest.get(2..).unwrap_or("").trim_start();
            // Parse field list: N or N,M,...
            let end = rest.find([' ', '\t']).unwrap_or(rest.len());
            let spec = rest.get(..end).unwrap_or("");
            for part in spec.split(',') {
                if let Ok(n) = part.trim().parse::<usize>() {
                    if n > 0 { fields.push(n); }
                }
            }
            rest = rest.get(end..).unwrap_or("");
        } else if rest.starts_with("-c") {
            rest = rest.get(2..).unwrap_or("").trim_start();
            let end = rest.find([' ', '\t']).unwrap_or(rest.len());
            let spec = rest.get(..end).unwrap_or("");
            if let Some(dash) = spec.find('-') {
                let start = spec.get(..dash).and_then(|s| s.parse::<usize>().ok()).unwrap_or(1);
                let end_val = spec.get(dash + 1..).and_then(|s| s.parse::<usize>().ok()).unwrap_or(usize::MAX);
                chars_range = Some((start.max(1), end_val));
            } else if let Ok(n) = spec.parse::<usize>() {
                chars_range = Some((n.max(1), n.max(1)));
            }
            rest = rest.get(end..).unwrap_or("");
        } else if !rest.is_empty() {
            file_path = Some(String::from(rest.split_whitespace().next().unwrap_or("")));
            break;
        } else {
            break;
        }
    }

    (delim, fields, chars_range, file_path)
}

/// Process text with cut (field or character extraction).
#[allow(clippy::arithmetic_side_effects)]
fn cut_process(text: &str, delim: char, fields: &[usize], chars_range: Option<(usize, usize)>) {
    for line in text.lines() {
        if let Some((start, end)) = chars_range {
            // Character range mode.
            let chars: Vec<char> = line.chars().collect();
            let s = start.saturating_sub(1); // 1-based to 0-based
            let e = end.min(chars.len());
            let slice: String = chars.get(s..e).unwrap_or(&[]).iter().collect();
            shell_println!("{}", slice);
        } else if !fields.is_empty() {
            // Field mode.
            let parts: Vec<&str> = line.split(delim).collect();
            let mut first = true;
            for &f in fields {
                if !first { shell_print!("{}", delim); }
                first = false;
                if let Some(part) = parts.get(f.saturating_sub(1)) {
                    shell_print!("{}", part);
                }
            }
            shell_println!();
        } else {
            shell_println!("{}", line);
        }
    }
}

/// `tr SET1 SET2` — translate characters.
///
/// Replaces each character in SET1 with the corresponding character in SET2.
/// `tr -d SET1` deletes characters in SET1.
fn cmd_tr(args: &str) {
    // tr needs piped input; standalone usage reads a file.
    let mut parts = args.splitn(3, ' ');
    let set1_or_flag = parts.next().unwrap_or("");
    let set2_or_file = parts.next().unwrap_or("");
    let file = parts.next().unwrap_or("").trim();

    if set1_or_flag == "-d" {
        // Delete mode: tr -d SET1 FILE
        if set2_or_file.is_empty() {
            crate::console_println!("Usage: tr -d CHARS [file]  or pipe: cmd | tr -d CHARS");
            set_exit(1);
            return;
        }
        if !file.is_empty() {
            let resolved = resolve_path(file);
            match crate::fs::Vfs::read_file(&resolved) {
                Ok(data) => {
                    let text = core::str::from_utf8(&data).unwrap_or("");
                    tr_delete(text, set2_or_file);
                }
                Err(e) => {
                    crate::console_println!("tr: {}: {:?}", file, e);
                    set_exit(1);
                }
            }
        } else {
            crate::console_println!("Usage: tr -d CHARS [file]");
            set_exit(1);
        }
    } else if set1_or_flag.is_empty() || set2_or_file.is_empty() {
        crate::console_println!("Usage: tr SET1 SET2 [file]  or  tr -d CHARS [file]");
        set_exit(1);
    } else if !file.is_empty() {
        let resolved = resolve_path(file);
        match crate::fs::Vfs::read_file(&resolved) {
            Ok(data) => {
                let text = core::str::from_utf8(&data).unwrap_or("");
                tr_translate(text, set1_or_flag, set2_or_file);
            }
            Err(e) => {
                crate::console_println!("tr: {}: {:?}", file, e);
                set_exit(1);
            }
        }
    } else {
        crate::console_println!("Usage: tr SET1 SET2 [file]  or pipe: cmd | tr SET1 SET2");
        set_exit(1);
    }
}

fn cmd_tr_input(args: &str, input: &str) {
    let mut parts = args.splitn(2, ' ');
    let set1_or_flag = parts.next().unwrap_or("");
    let set2 = parts.next().unwrap_or("");

    if set1_or_flag == "-d" {
        tr_delete(input, set2);
    } else if !set2.is_empty() {
        tr_translate(input, set1_or_flag, set2);
    } else {
        crate::console_println!("Usage: cmd | tr SET1 SET2  or  cmd | tr -d CHARS");
    }
}

fn tr_translate(text: &str, set1: &str, set2: &str) {
    let s1: Vec<char> = expand_tr_set(set1);
    let s2: Vec<char> = expand_tr_set(set2);

    let mut result = String::with_capacity(text.len());
    for ch in text.chars() {
        if let Some(pos) = s1.iter().position(|&c| c == ch) {
            // Replace with corresponding char from set2 (or last char if shorter).
            let replacement = s2.get(pos).or_else(|| s2.last()).copied().unwrap_or(ch);
            result.push(replacement);
        } else {
            result.push(ch);
        }
    }
    shell_print!("{}", result);
}

fn tr_delete(text: &str, set1: &str) {
    let s1: Vec<char> = expand_tr_set(set1);
    let mut result = String::with_capacity(text.len());
    for ch in text.chars() {
        if !s1.contains(&ch) {
            result.push(ch);
        }
    }
    shell_print!("{}", result);
}

/// Expand a tr character set.  Handles ranges like `a-z` and escapes like `\n`.
fn expand_tr_set(set: &str) -> Vec<char> {
    let set = strip_quotes(set);
    let mut chars = Vec::new();
    let bytes = set.as_bytes();
    let len = bytes.len();
    let mut i = 0;

    while i < len {
        if bytes[i] == b'\\' && i.saturating_add(1) < len {
            let next = bytes[i.saturating_add(1)];
            match next {
                b'n' => chars.push('\n'),
                b't' => chars.push('\t'),
                b'r' => chars.push('\r'),
                b'\\' => chars.push('\\'),
                _ => chars.push(next as char),
            }
            i = i.saturating_add(2);
        } else if i.saturating_add(2) < len && bytes[i.saturating_add(1)] == b'-' {
            // Range: a-z
            let start = bytes[i];
            let end = bytes[i.saturating_add(2)];
            if start <= end {
                for c in start..=end {
                    chars.push(c as char);
                }
            }
            i = i.saturating_add(3);
        } else {
            chars.push(bytes[i] as char);
            i = i.saturating_add(1);
        }
    }
    chars
}

/// `yes [STRING]` — repeatedly output STRING (default "y").
///
/// Limited to 100 lines to prevent infinite loops in the kernel shell.
fn cmd_yes(args: &str) {
    let text = if args.is_empty() { "y" } else { args };
    for _ in 0..100_u32 {
        shell_println!("{}", text);
    }
}

/// `tac [FILE]` — print lines in reverse order (opposite of cat).
fn cmd_tac(args: &str) {
    if args.is_empty() {
        crate::console_println!("Usage: tac <file>");
        return;
    }

    let path = resolve_path(args);
    match crate::fs::Vfs::read_file(&path) {
        Ok(data) => {
            let text = core::str::from_utf8(&data).unwrap_or("");
            tac_process(text);
        }
        Err(e) => {
            crate::console_println!("tac: {}: {:?}", args, e);
            set_exit(1);
        }
    }
}

fn cmd_tac_input(args: &str, input: &str) {
    if !args.is_empty() {
        cmd_tac(args);
        return;
    }
    tac_process(input);
}

fn tac_process(text: &str) {
    let lines: Vec<&str> = text.lines().collect();
    for line in lines.iter().rev() {
        shell_println!("{}", line);
    }
}

/// `fold [-w WIDTH] [FILE]` — wrap lines to specified width (default 80).
#[allow(clippy::arithmetic_side_effects)]
fn cmd_fold(args: &str) {
    let (width, file) = parse_fold_args(args);

    if let Some(path) = file {
        let resolved = resolve_path(&path);
        match crate::fs::Vfs::read_file(&resolved) {
            Ok(data) => {
                let text = core::str::from_utf8(&data).unwrap_or("");
                fold_process(text, width);
            }
            Err(e) => {
                crate::console_println!("fold: {}: {:?}", path, e);
                set_exit(1);
            }
        }
    } else {
        crate::console_println!("Usage: fold [-w WIDTH] <file>");
        set_exit(1);
    }
}

fn cmd_fold_input(args: &str, input: &str) {
    let (width, _) = parse_fold_args(args);
    fold_process(input, width);
}

fn parse_fold_args(args: &str) -> (usize, Option<String>) {
    let mut width: usize = 80;
    let mut rest = args.trim();

    if rest.starts_with("-w") {
        rest = rest.get(2..).unwrap_or("").trim_start();
        let end = rest.find([' ', '\t']).unwrap_or(rest.len());
        if let Ok(w) = rest.get(..end).unwrap_or("80").parse::<usize>() {
            width = w.max(1);
        }
        rest = rest.get(end..).unwrap_or("").trim_start();
    }

    let file = if rest.is_empty() { None } else { Some(String::from(rest)) };
    (width, file)
}

#[allow(clippy::arithmetic_side_effects)]
fn fold_process(text: &str, width: usize) {
    for line in text.lines() {
        if line.len() <= width {
            shell_println!("{}", line);
        } else {
            let mut pos = 0;
            while pos < line.len() {
                let end = (pos + width).min(line.len());
                if let Some(chunk) = line.get(pos..end) {
                    shell_println!("{}", chunk);
                }
                pos = end;
            }
        }
    }
}

/// `paste FILE1 FILE2 ...` — merge lines of files side by side.
///
/// With piped input and a file arg, merges piped input with file.
fn cmd_paste(args: &str) {
    let files: Vec<&str> = args.split_whitespace().collect();
    if files.is_empty() {
        crate::console_println!("Usage: paste FILE1 [FILE2 ...]");
        set_exit(1);
        return;
    }

    // Read all files.
    let mut columns: Vec<Vec<String>> = Vec::new();
    for file in &files {
        let path = resolve_path(file);
        match crate::fs::Vfs::read_file(&path) {
            Ok(data) => {
                let text = core::str::from_utf8(&data).unwrap_or("");
                columns.push(text.lines().map(String::from).collect());
            }
            Err(e) => {
                crate::console_println!("paste: {}: {:?}", file, e);
                set_exit(1);
                return;
            }
        }
    }

    paste_output(&columns);
}

fn cmd_paste_input(args: &str, input: &str) {
    let mut columns: Vec<Vec<String>> = Vec::new();
    // Input becomes the first column.
    columns.push(input.lines().map(String::from).collect());

    // If there's a file argument, add it as additional columns.
    for file in args.split_whitespace() {
        let path = resolve_path(file);
        match crate::fs::Vfs::read_file(&path) {
            Ok(data) => {
                let text = core::str::from_utf8(&data).unwrap_or("");
                columns.push(text.lines().map(String::from).collect());
            }
            Err(e) => {
                crate::console_println!("paste: {}: {:?}", file, e);
                set_exit(1);
                return;
            }
        }
    }

    paste_output(&columns);
}

fn paste_output(columns: &[Vec<String>]) {
    let max_lines = columns.iter().map(|c| c.len()).max().unwrap_or(0);
    for i in 0..max_lines {
        for (ci, col) in columns.iter().enumerate() {
            if ci > 0 { shell_print!("\t"); }
            if let Some(line) = col.get(i) {
                shell_print!("{}", line);
            }
        }
        shell_println!();
    }
}

/// `xargs COMMAND [INITIAL-ARGS]` — build and execute commands from input.
///
/// Reads words from stdin (piped input) and appends them as arguments to
/// COMMAND.  By default, all input words are appended to a single invocation.
/// With `-n N`, limits to N arguments per invocation.
fn cmd_xargs(_args: &str) {
    crate::console_println!("Usage: cmd | xargs COMMAND [args]");
    crate::console_println!("xargs requires piped input.");
    set_exit(1);
}

fn cmd_xargs_input(args: &str, input: &str) {
    let mut max_args: Option<usize> = None;
    let mut rest = args.trim();

    // Parse -n N flag.
    if rest.starts_with("-n") {
        rest = rest.get(2..).unwrap_or("").trim_start();
        let end = rest.find([' ', '\t']).unwrap_or(rest.len());
        max_args = rest.get(..end).and_then(|s| s.parse::<usize>().ok());
        rest = rest.get(end..).unwrap_or("").trim_start();
    }

    let command = if rest.is_empty() { "echo" } else { rest };

    // Collect input words.
    let words: Vec<&str> = input.split_whitespace().collect();
    if words.is_empty() {
        return;
    }

    match max_args {
        Some(n) if n > 0 => {
            // Execute in batches of N words.
            for chunk in words.chunks(n) {
                let full_cmd = alloc::format!("{} {}", command, chunk.join(" "));
                execute(&full_cmd);
            }
        }
        _ => {
            // All words in one invocation.
            let full_cmd = alloc::format!("{} {}", command, words.join(" "));
            execute(&full_cmd);
        }
    }
}

/// Pause for N milliseconds (busy-wait using APIC tick counter).
fn cmd_sleep(args: &str) {
    let ms = match args.parse::<u64>() {
        Ok(n) if n > 0 => n,
        _ => {
            crate::console_println!("Usage: sleep <milliseconds>");
            return;
        }
    };

    // Cap at 10 seconds to prevent accidental infinite waits.
    let capped = ms.min(10_000);
    if capped != ms {
        crate::console_println!("(capped to {} ms)", capped);
    }

    // Busy-wait using the APIC tick counter.
    // Each tick is ~1 ms (PIT-driven APIC timer at ~1000 Hz).
    let start = crate::apic::tick_count();
    let target = start.saturating_add(capped);
    while crate::apic::tick_count() < target {
        // HLT until next interrupt to save power.
        crate::cpu::hlt();
    }
}

/// Conditional expression evaluation (like POSIX `test` / `[`).
///
/// Supports:
///   File tests:    -e FILE, -f FILE, -d FILE, -s FILE (exists, file, dir, non-empty)
///   String tests:  -z STR (empty), -n STR (non-empty), STR = STR, STR != STR
///   Integer tests: N -eq N, N -ne N, N -lt N, N -le N, N -gt N, N -ge N
///   Logical:       ! EXPR (negation)
///
/// Sets exit status: 0 (true) or 1 (false).
fn cmd_test(args: &str) {
    // Strip trailing `]` if invoked as `[`.
    let args = if args.ends_with(']') {
        args.get(..args.len().saturating_sub(1)).unwrap_or("").trim()
    } else {
        args
    };

    if args.is_empty() {
        // Empty test is false (POSIX behavior).
        set_exit(1);
        return;
    }

    let result = eval_test(args);
    set_exit(if result { 0 } else { 1 });
}

/// Evaluate a test expression, returning true or false.
fn eval_test(args: &str) -> bool {
    let parts: Vec<&str> = args.split_whitespace().collect();

    if parts.is_empty() {
        return false;
    }

    // Negation: `! EXPR`
    if parts[0] == "!" {
        let rest = parts.get(1..).unwrap_or(&[]).join(" ");
        return !eval_test(&rest);
    }

    // Unary file/string tests.
    if parts.len() == 2 {
        let op = parts[0];
        let operand = parts[1];

        match op {
            "-e" => {
                // File exists.
                let path = resolve_path(operand);
                return crate::fs::Vfs::stat(&path).is_ok();
            }
            "-f" => {
                // Is regular file.
                let path = resolve_path(operand);
                return crate::fs::Vfs::stat(&path)
                    .map(|m| m.entry_type == crate::fs::EntryType::File)
                    .unwrap_or(false);
            }
            "-d" => {
                // Is directory.
                let path = resolve_path(operand);
                return crate::fs::Vfs::stat(&path)
                    .map(|m| m.entry_type == crate::fs::EntryType::Directory)
                    .unwrap_or(false);
            }
            "-s" => {
                // File exists and is non-empty.
                let path = resolve_path(operand);
                return crate::fs::Vfs::stat(&path)
                    .map(|m| m.size > 0)
                    .unwrap_or(false);
            }
            "-L" | "-h" => {
                // Is symbolic link.
                let path = resolve_path(operand);
                return crate::fs::Vfs::lstat(&path)
                    .map(|m| m.entry_type == crate::fs::EntryType::Symlink)
                    .unwrap_or(false);
            }
            "-r" => {
                // File is readable (exists with read permission).
                let path = resolve_path(operand);
                return crate::fs::Vfs::metadata(&path)
                    .map(|m| m.permissions & 0o400 != 0)
                    .unwrap_or(false);
            }
            "-w" => {
                // File is writable (exists with write permission).
                let path = resolve_path(operand);
                return crate::fs::Vfs::metadata(&path)
                    .map(|m| m.permissions & 0o200 != 0)
                    .unwrap_or(false);
            }
            "-x" => {
                // File is executable (exists with execute permission).
                let path = resolve_path(operand);
                return crate::fs::Vfs::metadata(&path)
                    .map(|m| m.permissions & 0o100 != 0)
                    .unwrap_or(false);
            }
            "-v" => {
                // Variable is set (non-empty).
                return env_get(operand).is_some_and(|v| !v.is_empty())
                    || is_array(operand);
            }
            "-z" => {
                // String is empty.
                return operand.is_empty();
            }
            "-n" => {
                // String is non-empty.
                return !operand.is_empty();
            }
            _ => {}
        }
    }

    // Binary operators: STR = STR, STR != STR, N -eq N, etc.
    if parts.len() == 3 {
        let left = parts[0];
        let op = parts[1];
        let right = parts[2];

        match op {
            "=" | "==" => return left == right,
            "!=" => return left != right,
            "<" => return left < right,  // Lexicographic string comparison.
            ">" => return left > right,
            "-eq" | "-ne" | "-lt" | "-le" | "-gt" | "-ge" => {
                let l = left.parse::<i64>().unwrap_or(0);
                let r = right.parse::<i64>().unwrap_or(0);
                return match op {
                    "-eq" => l == r,
                    "-ne" => l != r,
                    "-lt" => l < r,
                    "-le" => l <= r,
                    "-gt" => l > r,
                    "-ge" => l >= r,
                    _ => false,
                };
            }
            _ => {}
        }
    }

    // Single argument: true if non-empty string.
    if parts.len() == 1 {
        return !parts[0].is_empty();
    }

    // Unrecognized expression — treat as false.
    false
}

/// Evaluate and print an arithmetic expression.
///
/// Usage: `expr 1 + 2 * 3` → `7`
fn cmd_expr(args: &str) {
    if args.is_empty() {
        crate::console_println!("Usage: expr <expression>");
        crate::console_println!("  Operators: + - * / % ()");
        crate::console_println!("  Example: expr 2 + 3 * 4");
        set_exit(1);
        return;
    }
    let result = eval_arithmetic(args);
    shell_println!("{}", result);
}

// ---------------------------------------------------------------------------
// Arithmetic evaluation for $((...))
// ---------------------------------------------------------------------------

/// Evaluate a simple arithmetic expression.
///
/// Supports: integer literals, `+`, `-`, `*`, `/`, `%`, unary `-`,
/// parentheses `(...)`, and whitespace.
///
/// All arithmetic is done in i64.  Division by zero returns 0.
fn eval_arithmetic(expr: &str) -> i64 {
    let tokens = tokenize_arith(expr);
    let mut pos = 0;
    parse_expr(&tokens, &mut pos)
}

/// Arithmetic token.
#[derive(Clone, Copy)]
enum ArithToken {
    Num(i64),
    Plus,
    Minus,
    Star,
    Slash,
    Percent,
    LParen,
    RParen,
    /// Comparison: <
    Lt,
    /// Comparison: <=
    Le,
    /// Comparison: >
    Gt,
    /// Comparison: >=
    Ge,
    /// Comparison: ==
    Eq,
    /// Comparison: !=
    Ne,
    /// Logical AND: &&
    And,
    /// Logical OR: ||
    Or,
    /// Logical NOT: !
    Not,
}

/// Tokenize an arithmetic expression string.
///
/// Supports: numbers, +, -, *, /, %, (, ), <, <=, >, >=, ==, !=, &&, ||, !
/// Also recognizes bare variable names (resolved to their integer value).
fn tokenize_arith(s: &str) -> Vec<ArithToken> {
    let bytes = s.as_bytes();
    let len = bytes.len();
    let mut tokens = Vec::new();
    let mut i = 0;

    while i < len {
        let b = bytes[i];
        match b {
            b' ' | b'\t' => { i = i.saturating_add(1); }
            b'+' => { tokens.push(ArithToken::Plus); i = i.saturating_add(1); }
            b'-' => { tokens.push(ArithToken::Minus); i = i.saturating_add(1); }
            b'*' => { tokens.push(ArithToken::Star); i = i.saturating_add(1); }
            b'/' => { tokens.push(ArithToken::Slash); i = i.saturating_add(1); }
            b'%' => { tokens.push(ArithToken::Percent); i = i.saturating_add(1); }
            b'(' => { tokens.push(ArithToken::LParen); i = i.saturating_add(1); }
            b')' => { tokens.push(ArithToken::RParen); i = i.saturating_add(1); }
            b'<' => {
                if bytes.get(i.saturating_add(1)) == Some(&b'=') {
                    tokens.push(ArithToken::Le);
                    i = i.saturating_add(2);
                } else {
                    tokens.push(ArithToken::Lt);
                    i = i.saturating_add(1);
                }
            }
            b'>' => {
                if bytes.get(i.saturating_add(1)) == Some(&b'=') {
                    tokens.push(ArithToken::Ge);
                    i = i.saturating_add(2);
                } else {
                    tokens.push(ArithToken::Gt);
                    i = i.saturating_add(1);
                }
            }
            b'=' => {
                if bytes.get(i.saturating_add(1)) == Some(&b'=') {
                    tokens.push(ArithToken::Eq);
                    i = i.saturating_add(2);
                } else {
                    // Lone `=` in arithmetic context — skip (assignment handled
                    // separately in eval_cfor_expr).
                    i = i.saturating_add(1);
                }
            }
            b'!' => {
                if bytes.get(i.saturating_add(1)) == Some(&b'=') {
                    tokens.push(ArithToken::Ne);
                    i = i.saturating_add(2);
                } else {
                    tokens.push(ArithToken::Not);
                    i = i.saturating_add(1);
                }
            }
            b'&' => {
                if bytes.get(i.saturating_add(1)) == Some(&b'&') {
                    tokens.push(ArithToken::And);
                    i = i.saturating_add(2);
                } else {
                    i = i.saturating_add(1); // Skip lone &.
                }
            }
            b'|' => {
                if bytes.get(i.saturating_add(1)) == Some(&b'|') {
                    tokens.push(ArithToken::Or);
                    i = i.saturating_add(2);
                } else {
                    i = i.saturating_add(1); // Skip lone |.
                }
            }
            b'0'..=b'9' => {
                let start = i;
                while i < len && bytes[i].is_ascii_digit() {
                    i = i.saturating_add(1);
                }
                if let Some(num_bytes) = bytes.get(start..i) {
                    if let Ok(num_str) = core::str::from_utf8(num_bytes) {
                        let val = num_str.parse::<i64>().unwrap_or(0);
                        tokens.push(ArithToken::Num(val));
                    }
                }
            }
            c if c.is_ascii_alphabetic() || c == b'_' => {
                // Variable name — resolve to integer value.
                let start = i;
                while i < len && (bytes[i].is_ascii_alphanumeric() || bytes[i] == b'_') {
                    i = i.saturating_add(1);
                }
                if let Some(name_bytes) = bytes.get(start..i) {
                    if let Ok(name) = core::str::from_utf8(name_bytes) {
                        let val = env_get(name)
                            .and_then(|v| v.parse::<i64>().ok())
                            .unwrap_or(0);
                        tokens.push(ArithToken::Num(val));
                    }
                }
            }
            _ => {
                // Unknown character — skip.
                i = i.saturating_add(1);
            }
        }
    }

    tokens
}

/// Parse a logical OR expression: and_expr ('||' and_expr)*
fn parse_expr(tokens: &[ArithToken], pos: &mut usize) -> i64 {
    let mut val = parse_and_expr(tokens, pos);
    while let Some(ArithToken::Or) = tokens.get(*pos) {
        *pos = pos.saturating_add(1);
        let rhs = parse_and_expr(tokens, pos);
        val = if val != 0 || rhs != 0 { 1 } else { 0 };
    }
    val
}

/// Parse a logical AND expression: cmp_expr ('&&' cmp_expr)*
fn parse_and_expr(tokens: &[ArithToken], pos: &mut usize) -> i64 {
    let mut val = parse_cmp_expr(tokens, pos);
    while let Some(ArithToken::And) = tokens.get(*pos) {
        *pos = pos.saturating_add(1);
        let rhs = parse_cmp_expr(tokens, pos);
        val = if val != 0 && rhs != 0 { 1 } else { 0 };
    }
    val
}

/// Parse a comparison expression: add_expr (('<' | '<=' | '>' | '>=' | '==' | '!=') add_expr)*
fn parse_cmp_expr(tokens: &[ArithToken], pos: &mut usize) -> i64 {
    let mut val = parse_add_expr(tokens, pos);
    loop {
        match tokens.get(*pos) {
            Some(ArithToken::Lt) => {
                *pos = pos.saturating_add(1);
                let rhs = parse_add_expr(tokens, pos);
                val = if val < rhs { 1 } else { 0 };
            }
            Some(ArithToken::Le) => {
                *pos = pos.saturating_add(1);
                let rhs = parse_add_expr(tokens, pos);
                val = if val <= rhs { 1 } else { 0 };
            }
            Some(ArithToken::Gt) => {
                *pos = pos.saturating_add(1);
                let rhs = parse_add_expr(tokens, pos);
                val = if val > rhs { 1 } else { 0 };
            }
            Some(ArithToken::Ge) => {
                *pos = pos.saturating_add(1);
                let rhs = parse_add_expr(tokens, pos);
                val = if val >= rhs { 1 } else { 0 };
            }
            Some(ArithToken::Eq) => {
                *pos = pos.saturating_add(1);
                let rhs = parse_add_expr(tokens, pos);
                val = if val == rhs { 1 } else { 0 };
            }
            Some(ArithToken::Ne) => {
                *pos = pos.saturating_add(1);
                let rhs = parse_add_expr(tokens, pos);
                val = if val != rhs { 1 } else { 0 };
            }
            _ => break,
        }
    }
    val
}

/// Parse an additive expression: term (('+' | '-') term)*
fn parse_add_expr(tokens: &[ArithToken], pos: &mut usize) -> i64 {
    let mut val = parse_term(tokens, pos);
    loop {
        match tokens.get(*pos) {
            Some(ArithToken::Plus) => {
                *pos = pos.saturating_add(1);
                val = val.wrapping_add(parse_term(tokens, pos));
            }
            Some(ArithToken::Minus) => {
                *pos = pos.saturating_add(1);
                val = val.wrapping_sub(parse_term(tokens, pos));
            }
            _ => break,
        }
    }
    val
}

/// Parse a multiplicative expression: unary (('*' | '/' | '%') unary)*
fn parse_term(tokens: &[ArithToken], pos: &mut usize) -> i64 {
    let mut val = parse_unary(tokens, pos);
    loop {
        match tokens.get(*pos) {
            Some(ArithToken::Star) => {
                *pos = pos.saturating_add(1);
                val = val.wrapping_mul(parse_unary(tokens, pos));
            }
            Some(ArithToken::Slash) => {
                *pos = pos.saturating_add(1);
                let rhs = parse_unary(tokens, pos);
                val = if rhs == 0 { 0 } else { val.wrapping_div(rhs) };
            }
            Some(ArithToken::Percent) => {
                *pos = pos.saturating_add(1);
                let rhs = parse_unary(tokens, pos);
                val = if rhs == 0 { 0 } else { val.wrapping_rem(rhs) };
            }
            _ => break,
        }
    }
    val
}

/// Parse a unary expression: '-' unary | '!' unary | atom
fn parse_unary(tokens: &[ArithToken], pos: &mut usize) -> i64 {
    if let Some(ArithToken::Minus) = tokens.get(*pos) {
        *pos = pos.saturating_add(1);
        return parse_unary(tokens, pos).wrapping_neg();
    }
    if let Some(ArithToken::Not) = tokens.get(*pos) {
        *pos = pos.saturating_add(1);
        let val = parse_unary(tokens, pos);
        return if val == 0 { 1 } else { 0 };
    }
    parse_atom(tokens, pos)
}

/// Parse an atom: number | '(' expr ')'
fn parse_atom(tokens: &[ArithToken], pos: &mut usize) -> i64 {
    match tokens.get(*pos) {
        Some(ArithToken::Num(n)) => {
            let val = *n;
            *pos = pos.saturating_add(1);
            val
        }
        Some(ArithToken::LParen) => {
            *pos = pos.saturating_add(1);
            let val = parse_expr(tokens, pos);
            // Consume matching ')'.
            if let Some(ArithToken::RParen) = tokens.get(*pos) {
                *pos = pos.saturating_add(1);
            }
            val
        }
        _ => {
            // Unexpected token — return 0.
            0
        }
    }
}

/// Show environment variables.
fn cmd_printenv() {
    let vars = ENV_VARS.lock();
    if vars.is_empty() {
        shell_println!("(no environment variables set)");
    } else {
        for (k, v) in vars.iter() {
            shell_println!("{}={}", k, v);
        }
    }
}

/// Set an environment variable.
///
/// Usage: `export NAME=VALUE` or `export NAME VALUE`.
/// With no arguments, lists all variables (same as `printenv`).
/// Read a line from the keyboard and store it in a variable.
///
/// Usage:
///   `read VAR`         — read a line into VAR
///   `read -p "msg" VAR` — print prompt, then read
///   `read`             — read into $REPLY
fn cmd_read(args: &str) {
    let mut prompt: Option<&str> = None;
    let mut var_name = "REPLY";
    let mut into_array = false;
    let mut rest = args;

    // Parse flags: -p "prompt", -a (array mode).
    loop {
        if rest.starts_with("-a ") || rest.starts_with("-a\t") {
            into_array = true;
            rest = rest.get(3..).unwrap_or("").trim_start();
            continue;
        }
        break;
    }

    // Parse -p "prompt" flag.
    if rest.starts_with("-p ") || rest.starts_with("-p\t") {
        rest = rest.get(3..).unwrap_or("").trim_start();
        // Extract the prompt string (may be quoted).
        if rest.starts_with('"') {
            if let Some(end) = rest.get(1..).and_then(|s| s.find('"')) {
                prompt = rest.get(1..end.saturating_add(1));
                rest = rest.get(end.saturating_add(2)..).unwrap_or("").trim_start();
            }
        } else if rest.starts_with('\'') {
            if let Some(end) = rest.get(1..).and_then(|s| s.find('\'')) {
                prompt = rest.get(1..end.saturating_add(1));
                rest = rest.get(end.saturating_add(2)..).unwrap_or("").trim_start();
            }
        } else {
            // Unquoted: first word is the prompt.
            let end = rest.find(' ').unwrap_or(rest.len());
            prompt = rest.get(..end);
            rest = rest.get(end..).unwrap_or("").trim_start();
        }
    }

    if !rest.is_empty() {
        var_name = rest.split_whitespace().next().unwrap_or("REPLY");
    }

    // Print prompt if specified.
    if let Some(p) = prompt {
        shell_print!("{}", p);
    }

    // Read a line from keyboard input.
    let mut buf = [0u8; MAX_LINE];
    let mut len = 0;

    loop {
        let byte = crate::keyboard::read_char();
        match byte {
            b'\r' | b'\n' => {
                shell_println!();
                break;
            }
            0x7F | 0x08 => {
                // Backspace.
                if len > 0 {
                    len -= 1;
                    shell_print!("\x08 \x08");
                }
            }
            3 => {
                // Ctrl+C — cancel.
                shell_println!();
                set_exit(1);
                return;
            }
            _ => {
                if len < MAX_LINE {
                    buf[len] = byte;
                    len += 1;
                    shell_print!("{}", byte as char);
                }
            }
        }
    }

    let value = core::str::from_utf8(buf.get(..len).unwrap_or(&[]))
        .unwrap_or("");

    if into_array {
        // Split input into words and store as array.
        let words: Vec<String> = value.split_whitespace()
            .map(String::from)
            .collect();
        array_set(var_name, words);
    } else {
        env_set(var_name, value);
    }
}

/// `mapfile [-t] ARRAY [FILE]` — read lines from file into an array.
///
/// Reads all lines from FILE (or stdin if invoked via pipe) and stores
/// each line as an element of ARRAY.  With `-t`, trailing newlines are
/// stripped from each element.  Also available as `readarray`.
fn cmd_mapfile(args: &str) {
    let mut strip_newlines = false;
    let mut rest = args;

    // Parse flags.
    while rest.starts_with('-') {
        if rest.starts_with("-t ") || rest.starts_with("-t\t") || rest == "-t" {
            strip_newlines = true;
            rest = rest.get(3..).unwrap_or("").trim_start();
        } else {
            break;
        }
    }

    // Parse array name.
    let (var_name, file_path) = if let Some(sp) = rest.find(' ') {
        (rest.get(..sp).unwrap_or("MAPFILE"), rest.get(sp.saturating_add(1)..).unwrap_or("").trim())
    } else if !rest.is_empty() {
        (rest, "")
    } else {
        ("MAPFILE", "")
    };

    if file_path.is_empty() {
        crate::console_println!("mapfile: no file specified (pipe input or provide a file path)");
        set_exit(1);
        return;
    }

    let path = resolve_path(file_path);
    match crate::fs::Vfs::read_file(&path) {
        Ok(data) => {
            let text = core::str::from_utf8(&data).unwrap_or("");
            mapfile_store(var_name, text, strip_newlines);
            set_exit(0);
        }
        Err(e) => {
            crate::console_println!("mapfile: {}: {:?}", file_path, e);
            set_exit(1);
        }
    }
}

/// `mapfile` with piped input: `cmd | mapfile [-t] ARRAY`
fn cmd_mapfile_input(args: &str, input: &str) {
    let mut strip_newlines = false;
    let mut rest = args;

    while rest.starts_with('-') {
        if rest.starts_with("-t ") || rest.starts_with("-t\t") || rest == "-t" {
            strip_newlines = true;
            rest = rest.get(3..).unwrap_or("").trim_start();
        } else {
            break;
        }
    }

    let var_name = if rest.is_empty() { "MAPFILE" } else { rest.split_whitespace().next().unwrap_or("MAPFILE") };
    mapfile_store(var_name, input, strip_newlines);
    set_exit(0);
}

/// Common helper: split text into lines and store as an array variable.
fn mapfile_store(var_name: &str, text: &str, strip_newlines: bool) {
    let lines: Vec<String> = text.split('\n')
        .map(|line| {
            if strip_newlines {
                String::from(line.trim_end_matches('\n').trim_end_matches('\r'))
            } else {
                alloc::format!("{}\n", line)
            }
        })
        .collect();

    // Remove the trailing empty element that split('\n') produces for
    // text ending in a newline.
    let lines = if lines.last().is_some_and(|l| l.is_empty() || l == "\n") {
        lines.get(..lines.len().saturating_sub(1)).unwrap_or(&[]).to_vec()
    } else {
        lines
    };

    array_set(var_name, lines);
}

/// `tee FILE` with piped input: writes input to file AND passes through.
fn cmd_tee_input(args: &str, input: &str) {
    let path = args.trim();
    if path.is_empty() {
        // No file — just pass through.
        shell_print!("{}", input);
        return;
    }

    let resolved = resolve_path(path);
    // Pass through to output.
    shell_print!("{}", input);
    // Also write to file.
    if let Err(e) = crate::fs::Vfs::write_file(&resolved, input.as_bytes()) {
        crate::console_println!("tee: write error: {:?}", e);
    }
}

/// `readonly [VAR=VALUE ...]` — mark variables as read-only.
///
/// With no arguments, lists all readonly variables.
/// `readonly VAR=VALUE` sets the value and marks it readonly.
/// `readonly VAR` marks an existing variable readonly without changing its value.
fn cmd_readonly(args: &str) {
    if args.is_empty() {
        // List all readonly variables.
        let ro = READONLY_VARS.lock();
        for name in ro.iter() {
            if let Some(val) = env_get(name) {
                crate::console_println!("declare -r {}=\"{}\"", name, val);
            } else {
                crate::console_println!("declare -r {}", name);
            }
        }
        return;
    }

    // Process each word as a separate readonly declaration.
    for word in args.split_whitespace() {
        if let Some(eq_pos) = word.find('=') {
            let name = word.get(..eq_pos).unwrap_or("");
            let value = word.get(eq_pos.saturating_add(1)..).unwrap_or("");
            if name.is_empty() {
                crate::console_println!("readonly: invalid variable name");
                continue;
            }
            // Set the value (bypass readonly check since we're about to mark it).
            ENV_VARS.lock().insert(String::from(name), String::from(value));
            READONLY_VARS.lock().insert(String::from(name));
        } else {
            // Just mark as readonly (no value change).
            READONLY_VARS.lock().insert(String::from(word));
        }
    }
}

/// `let EXPR [EXPR ...]` — evaluate arithmetic expressions.
///
/// Each argument is evaluated as an arithmetic expression.  The exit
/// status is 1 if the last expression evaluates to 0, and 0 otherwise
/// (like bash).  Supports assignment: `let "x = 5 + 3"`.
fn cmd_let(args: &str) {
    if args.is_empty() {
        crate::console_println!("Usage: let EXPRESSION ...");
        set_exit(1);
        return;
    }

    // Each whitespace-separated word is a separate expression, unless
    // quoted.  For simplicity in our kshell, treat the entire arg as
    // one expression (users can quote as needed).
    let expr = strip_quotes(args);

    // Check for assignment: `VAR = EXPR` or `VAR=EXPR`.
    if let Some(eq_pos) = expr.find('=') {
        let left = expr.get(..eq_pos).unwrap_or("").trim();
        let right = expr.get(eq_pos.saturating_add(1)..).unwrap_or("").trim();
        // Left side must be a valid variable name.
        if !left.is_empty() && left.chars().all(|c| c.is_ascii_alphanumeric() || c == '_')
            && !left.starts_with(|c: char| c.is_ascii_digit())
        {
            let val = eval_arithmetic(right);
            env_set(left, &alloc::format!("{}", val));
            set_exit(if val == 0 { 1 } else { 0 });
            return;
        }
    }

    // No assignment — just evaluate.
    let val = eval_arithmetic(expr);
    set_exit(if val == 0 { 1 } else { 0 });
}

/// `trap 'COMMAND' SIGNAL` — set a handler for a shell event.
///
/// Supported signals: EXIT, ERR, INT.
/// `trap - SIGNAL` clears the handler.
/// `trap` with no arguments lists current handlers.
fn cmd_trap(args: &str) {
    if args.is_empty() {
        // List all trap handlers.
        let handlers = TRAP_HANDLERS.lock();
        if handlers.is_empty() {
            crate::console_println!("No trap handlers set.");
        } else {
            for (sig, cmd) in handlers.iter() {
                crate::console_println!("trap -- '{}' {}", cmd, sig);
            }
        }
        return;
    }

    // Split: trap 'COMMAND' SIGNAL [SIGNAL...]
    // or:    trap - SIGNAL
    let trimmed = args.trim();

    if trimmed == "-" || trimmed.starts_with("- ") {
        // Clear handler(s).
        let signals = trimmed.get(1..).unwrap_or("").trim();
        for sig in signals.split_whitespace() {
            let sig_upper = sig.to_uppercase();
            TRAP_HANDLERS.lock().remove(&sig_upper);
        }
        return;
    }

    // Parse: first argument is the command (possibly quoted), rest are signals.
    let (command, rest) = if trimmed.starts_with('\'') || trimmed.starts_with('"') {
        // Quoted command.
        let quote = trimmed.as_bytes()[0] as char;
        if let Some(end) = trimmed.get(1..).and_then(|s| s.find(quote)) {
            let cmd = trimmed.get(1..end.saturating_add(1)).unwrap_or("");
            let rest = trimmed.get(end.saturating_add(2)..).unwrap_or("").trim();
            (cmd, rest)
        } else {
            (trimmed, "")
        }
    } else {
        // Unquoted: first word is command.
        let mut parts = trimmed.splitn(2, ' ');
        let cmd = parts.next().unwrap_or("");
        let rest = parts.next().unwrap_or("").trim();
        (cmd, rest)
    };

    if rest.is_empty() {
        crate::console_println!("Usage: trap 'COMMAND' SIGNAL [SIGNAL...]");
        set_exit(1);
        return;
    }

    // Set the handler for each signal.
    for sig in rest.split_whitespace() {
        let sig_upper = sig.to_uppercase();
        match sig_upper.as_str() {
            "EXIT" | "ERR" | "INT" => {
                TRAP_HANDLERS.lock().insert(sig_upper, String::from(command));
            }
            _ => {
                crate::console_println!("trap: unsupported signal '{}'", sig);
                set_exit(1);
            }
        }
    }
}

/// Execute any trap handler registered for the given signal.
fn fire_trap(signal: &str) {
    let cmd = TRAP_HANDLERS.lock().get(signal).cloned();
    if let Some(cmd) = cmd {
        execute(&cmd);
    }
}

/// `command CMD [ARGS...]` — run CMD bypassing aliases and functions.
///
/// Executes only built-in shell commands, ignoring any alias or function
/// with the same name.
fn cmd_command(args: &str) {
    if args.is_empty() {
        crate::console_println!("Usage: command CMD [args...]");
        set_exit(1);
        return;
    }
    // Dispatch directly without alias expansion.
    dispatch(args);
}

fn cmd_export(args: &str) {
    if args.is_empty() {
        // List all variables.
        cmd_printenv();
        return;
    }

    // Try `NAME=VALUE` form first.
    if let Some(eq_pos) = args.find('=') {
        let name = args.get(..eq_pos).unwrap_or("").trim();
        let value = args.get(eq_pos.saturating_add(1)..).unwrap_or("").trim();
        if name.is_empty() {
            crate::console_println!("export: invalid variable name");
            return;
        }
        env_set(name, value);
    } else {
        // Try `NAME VALUE` form.
        let mut parts = args.splitn(2, ' ');
        let name = parts.next().unwrap_or("").trim();
        let value = parts.next().unwrap_or("").trim();
        if name.is_empty() {
            crate::console_println!("export: invalid variable name");
            return;
        }
        env_set(name, value);
    }

    // Keep PWD in sync.
    sync_env_pwd();
}

/// Set shell options or variables.
///
/// Flags:
///   `set -e` — exit on error (errexit)
///   `set +e` — disable exit on error
///   `set -x` — trace commands before execution
///   `set +x` — disable tracing
///   `set NAME=VALUE` or `set NAME VALUE` — set variable (like export)
fn cmd_set(args: &str) {
    if args.is_empty() {
        // Show current options and variables.
        let errexit = OPT_ERREXIT.load(core::sync::atomic::Ordering::Relaxed);
        let xtrace = OPT_XTRACE.load(core::sync::atomic::Ordering::Relaxed);
        crate::console_println!("Shell options:");
        crate::console_println!("  errexit (-e): {}", if errexit { "on" } else { "off" });
        crate::console_println!("  xtrace  (-x): {}", if xtrace { "on" } else { "off" });
        return;
    }

    match args {
        "-e" => {
            OPT_ERREXIT.store(true, core::sync::atomic::Ordering::Relaxed);
            return;
        }
        "+e" => {
            OPT_ERREXIT.store(false, core::sync::atomic::Ordering::Relaxed);
            return;
        }
        "-x" => {
            OPT_XTRACE.store(true, core::sync::atomic::Ordering::Relaxed);
            return;
        }
        "+x" => {
            OPT_XTRACE.store(false, core::sync::atomic::Ordering::Relaxed);
            return;
        }
        "-ex" | "-xe" => {
            OPT_ERREXIT.store(true, core::sync::atomic::Ordering::Relaxed);
            OPT_XTRACE.store(true, core::sync::atomic::Ordering::Relaxed);
            return;
        }
        "+ex" | "+xe" => {
            OPT_ERREXIT.store(false, core::sync::atomic::Ordering::Relaxed);
            OPT_XTRACE.store(false, core::sync::atomic::Ordering::Relaxed);
            return;
        }
        _ => {}
    }

    // Fall back to variable-setting behavior.
    cmd_export(args);
}

/// Declare a local variable inside a function.
///
/// Usage: `local VAR=VALUE` or `local VAR VALUE` or `local VAR`
///
/// Saves the variable's current value (or notes it was unset) so it
/// can be restored when the function returns.  Outside a function,
/// behaves identically to `export`.
fn cmd_local(args: &str) {
    if args.is_empty() {
        crate::console_println!("Usage: local VAR[=VALUE]");
        return;
    }

    // Parse NAME=VALUE or NAME VALUE.
    let (name, value) = if let Some(eq_pos) = args.find('=') {
        let n = args.get(..eq_pos).unwrap_or("").trim();
        let v = args.get(eq_pos.saturating_add(1)..).unwrap_or("").trim();
        (n, v)
    } else {
        let mut parts = args.splitn(2, ' ');
        let n = parts.next().unwrap_or("").trim();
        let v = parts.next().unwrap_or("").trim();
        (n, v)
    };

    if name.is_empty() {
        crate::console_println!("local: invalid variable name");
        return;
    }

    // Save the current value on the local variable stack (if inside a function).
    {
        let mut stack = LOCAL_VARS.lock();
        if let Some(frame) = stack.last_mut() {
            // Only save if we haven't already saved this name in this frame.
            let already_saved = frame.iter().any(|(n, _)| n == name);
            if !already_saved {
                let prev = env_get(name);
                frame.push((String::from(name), prev));
            }
        }
        // If not inside a function (stack is empty), `local` still works
        // like `export` — sets the variable without scope protection.
    }

    // Set the variable.
    env_set(name, value);
}

/// Remove an environment variable.
///
/// Usage: `unset NAME [NAME ...]`
fn cmd_unset(args: &str) {
    if args.is_empty() {
        crate::console_println!("Usage: unset [-f] NAME [NAME ...]");
        return;
    }

    // `unset -f NAME` removes a function definition.
    if args.starts_with("-f ") || args.starts_with("-f\t") {
        let names = args.get(3..).unwrap_or("").trim();
        for name in names.split_whitespace() {
            if FUNCTIONS.lock().remove(name).is_none() {
                crate::console_println!("unset: function '{}': not defined", name);
            }
        }
        return;
    }

    for name in args.split_whitespace() {
        // Check for `unset arr[N]` — remove a single array element.
        if let Some(bracket) = name.find('[') {
            if name.ends_with(']') {
                let arr_name = name.get(..bracket).unwrap_or("");
                let idx_str = name.get(bracket.saturating_add(1)..name.len().saturating_sub(1)).unwrap_or("");
                if let Ok(index) = idx_str.parse::<usize>() {
                    array_unset_element(arr_name, index);
                    continue;
                }
            }
        }
        // Try removing as array first, then as scalar.
        if !array_remove(name) && !env_remove(name) {
            crate::console_println!("unset: '{}': not set", name);
        }
    }
}

/// List or inspect shell functions.
///
/// Usage:
///   `declare -f`       — list all function names and bodies
///   `declare -f NAME`  — show a specific function's body
///   `declare`          — list all function names
/// Show what kind of command a name is (builtin, function, alias).
///
/// Usage: `type name [name ...]`
fn cmd_type(args: &str) {
    if args.is_empty() {
        crate::console_println!("Usage: type <name> [<name> ...]");
        return;
    }

    for name in args.split_whitespace() {
        // Check aliases first.
        if let Some(val) = alias_get(name) {
            crate::console_println!("{} is aliased to '{}'", name, val);
            continue;
        }

        // Check user-defined functions.
        if FUNCTIONS.lock().contains_key(name) {
            crate::console_println!("{} is a function", name);
            continue;
        }

        // Check array variables.
        if is_array(name) {
            let len = array_len(name).unwrap_or(0);
            crate::console_println!("{} is an array ({} elements)", name, len);
            continue;
        }

        // Check builtins (simplified — we check the dispatch table names).
        if is_builtin(name) {
            crate::console_println!("{} is a shell builtin", name);
            continue;
        }

        // Check keywords.
        if matches!(name, "if" | "then" | "elif" | "else" | "fi" | "while" | "until" | "for"
            | "do" | "done" | "case" | "esac" | "function" | "in" | "select")
        {
            crate::console_println!("{} is a shell keyword", name);
            continue;
        }

        crate::console_println!("{}: not found", name);
        set_exit(1);
    }
}

