// ---------------------------------------------------------------------------
// unxz — XZ/LZMA2 decompression
// ---------------------------------------------------------------------------

fn cmd_unxz(args: &str) {
    let parts: alloc::vec::Vec<&str> = args.split_whitespace().collect();
    if parts.is_empty() {
        crate::console_println!(
            "Usage: unxz [-t] FILE.xz [-o OUTPUT]   Decompress XZ/LZMA2 file\n\
             \x20      xzcat FILE.xz                   Decompress to stdout\n\
             \x20 -t   Test integrity only (no output written)\n\
             \x20 -o F Write output to F instead of auto-naming"
        );
        return;
    }

    let mut test_only = false;
    let mut input_path: Option<&str> = None;
    let mut output_path: Option<&str> = None;
    let mut skip_next = false;

    for (i, &p) in parts.iter().enumerate() {
        if skip_next {
            skip_next = false;
            continue;
        }
        match p {
            "-t" | "--test" => test_only = true,
            "-o" => {
                if let Some(&out) = parts.get(i.wrapping_add(1)) {
                    output_path = Some(out);
                    skip_next = true;
                } else {
                    crate::console_println!("unxz: -o requires an argument");
                    return;
                }
            }
            _ => {
                if input_path.is_none() {
                    input_path = Some(p);
                }
            }
        }
    }

    let input = match input_path {
        Some(p) => resolve_path(p),
        None => {
            crate::console_println!("unxz: no input file specified");
            return;
        }
    };

    // Read the input data.
    let file_data = match crate::fs::Vfs::read_file(&input) {
        Ok(d) => d,
        Err(e) => {
            crate::console_println!("unxz: '{}': {:?}", input, e);
            return;
        }
    };

    // Verify XZ magic (FD 37 7A 58 5A 00).
    if file_data.len() < 12
        || file_data.get(..6) != Some(&[0xFD, 0x37, 0x7A, 0x58, 0x5A, 0x00])
    {
        crate::console_println!("unxz: '{}': not an XZ file", input);
        return;
    }

    // Decompress.
    let decompressed = match crate::fs::xz::unxz(&file_data) {
        Ok(d) => d,
        Err(e) => {
            crate::console_println!("unxz: '{}': decompression failed: {:?}", input, e);
            return;
        }
    };

    if test_only {
        crate::console_println!(
            "unxz: '{}': OK ({} -> {} bytes)",
            input, file_data.len(), decompressed.len()
        );
        return;
    }

    // Determine output path.
    let out = if let Some(explicit) = output_path {
        resolve_path(explicit)
    } else {
        // Strip .xz extension, or .txz → .tar
        if input.ends_with(".xz") {
            alloc::string::String::from(&input[..input.len().saturating_sub(3)])
        } else if input.ends_with(".txz") {
            let base = &input[..input.len().saturating_sub(4)];
            alloc::format!("{}.tar", base)
        } else if input.ends_with(".lzma") {
            alloc::string::String::from(&input[..input.len().saturating_sub(5)])
        } else {
            alloc::format!("{}.out", input)
        }
    };

    match crate::fs::Vfs::write_file(&out, &decompressed) {
        Ok(()) => {
            crate::console_println!(
                "unxz: '{}' -> '{}' ({} -> {} bytes)",
                input, out, file_data.len(), decompressed.len()
            );
        }
        Err(e) => {
            crate::console_println!("unxz: write '{}': {:?}", out, e);
        }
    }
}

// ---------------------------------------------------------------------------
// unzstd / zstdcat — Zstandard decompression
// ---------------------------------------------------------------------------

/// `unzstd` / `zstdcat` command — decompress Zstandard (.zst) files.
fn cmd_unzstd(args: &str) {
    let parts: alloc::vec::Vec<&str> = args.split_whitespace().collect();
    if parts.is_empty() {
        crate::console_println!(
            "Usage: unzstd [-t] FILE.zst [-o OUTPUT]   Decompress Zstandard file\n\
             \x20      zstdcat FILE.zst                    Decompress to stdout\n\
             \x20 -t   Test integrity only (no output written)\n\
             \x20 -o F Write output to F instead of auto-naming"
        );
        return;
    }

    let mut test_only = false;
    let mut input_path: Option<&str> = None;
    let mut output_path: Option<&str> = None;
    let mut skip_next = false;

    for (i, &p) in parts.iter().enumerate() {
        if skip_next {
            skip_next = false;
            continue;
        }
        match p {
            "-t" | "--test" => test_only = true,
            "-o" => {
                if let Some(&out) = parts.get(i.wrapping_add(1)) {
                    output_path = Some(out);
                    skip_next = true;
                } else {
                    crate::console_println!("unzstd: -o requires an argument");
                    return;
                }
            }
            _ => {
                if input_path.is_none() {
                    input_path = Some(p);
                }
            }
        }
    }

    let input = match input_path {
        Some(p) => resolve_path(p),
        None => {
            crate::console_println!("unzstd: no input file specified");
            return;
        }
    };

    // Read the input data.
    let file_data = match crate::fs::Vfs::read_file(&input) {
        Ok(d) => d,
        Err(e) => {
            crate::console_println!("unzstd: '{}': {:?}", input, e);
            return;
        }
    };

    // Verify Zstandard magic (FD 2F B5 28).
    if file_data.len() < 8 {
        crate::console_println!("unzstd: '{}': file too small", input);
        return;
    }
    let magic = u32::from(file_data[0])
        | (u32::from(file_data[1]) << 8)
        | (u32::from(file_data[2]) << 16)
        | (u32::from(file_data[3]) << 24);
    if magic != 0xFD2F_B528 {
        crate::console_println!("unzstd: '{}': not a Zstandard file", input);
        return;
    }

    // Decompress.
    let decompressed = match crate::fs::zstd::unzstd(&file_data) {
        Ok(d) => d,
        Err(e) => {
            crate::console_println!("unzstd: '{}': decompression failed: {:?}", input, e);
            return;
        }
    };

    if test_only {
        crate::console_println!(
            "unzstd: '{}': OK ({} -> {} bytes)",
            input, file_data.len(), decompressed.len()
        );
        return;
    }

    // Determine output path.
    let out = if let Some(explicit) = output_path {
        resolve_path(explicit)
    } else {
        // Strip .zst extension, or .tzst → .tar
        if input.ends_with(".zst") {
            alloc::string::String::from(&input[..input.len().saturating_sub(4)])
        } else if input.ends_with(".tzst") {
            let base = &input[..input.len().saturating_sub(5)];
            alloc::format!("{}.tar", base)
        } else if input.ends_with(".zstd") {
            alloc::string::String::from(&input[..input.len().saturating_sub(5)])
        } else {
            alloc::format!("{}.out", input)
        }
    };

    match crate::fs::Vfs::write_file(&out, &decompressed) {
        Ok(()) => {
            crate::console_println!(
                "unzstd: '{}' -> '{}' ({} -> {} bytes)",
                input, out, file_data.len(), decompressed.len()
            );
        }
        Err(e) => {
            crate::console_println!("unzstd: write '{}': {:?}", out, e);
        }
    }
}

// ---------------------------------------------------------------------------
// zstd — Zstandard compression
// ---------------------------------------------------------------------------

/// `zstd` command — compress files using Zstandard.
///
/// Modes:
/// - Default: LZ77 compression with predefined FSE tables
/// - `-s` / `--store`: Store mode (no LZ77, fast but larger output)
fn cmd_zstd(args: &str) {
    let parts: alloc::vec::Vec<&str> = args.split_whitespace().collect();
    if parts.is_empty() {
        crate::console_println!(
            "Usage: zstd [-s] FILE [-o OUTPUT]   Compress file with Zstandard\n\
             \x20 -s   Store mode (no LZ77, raw/RLE blocks only)\n\
             \x20 -o F Write output to F instead of FILE.zst"
        );
        return;
    }

    let mut store_mode = false;
    let mut input_path: Option<&str> = None;
    let mut output_path: Option<&str> = None;
    let mut skip_next = false;

    for (i, &p) in parts.iter().enumerate() {
        if skip_next {
            skip_next = false;
            continue;
        }
        match p {
            "-s" | "--store" => store_mode = true,
            "-o" => {
                if let Some(&out) = parts.get(i.wrapping_add(1)) {
                    output_path = Some(out);
                    skip_next = true;
                } else {
                    crate::console_println!("zstd: -o requires an argument");
                    return;
                }
            }
            _ => {
                if input_path.is_none() {
                    input_path = Some(p);
                }
            }
        }
    }

    let input = match input_path {
        Some(p) => resolve_path(p),
        None => {
            crate::console_println!("zstd: no input file specified");
            return;
        }
    };

    // Read the input data.
    let file_data = match crate::fs::Vfs::read_file(&input) {
        Ok(d) => d,
        Err(e) => {
            crate::console_println!("zstd: '{}': {:?}", input, e);
            return;
        }
    };

    // Compress.
    let compressed = if store_mode {
        crate::fs::zstd::zstd_store(&file_data)
    } else {
        crate::fs::zstd::compress_zstd(&file_data)
    };

    // Determine output path.
    let out = if let Some(explicit) = output_path {
        resolve_path(explicit)
    } else {
        alloc::format!("{}.zst", input)
    };

    match crate::fs::Vfs::write_file(&out, &compressed) {
        Ok(()) => {
            let ratio = if file_data.is_empty() {
                0
            } else {
                compressed.len() * 100 / file_data.len()
            };
            crate::console_println!(
                "zstd: '{}' -> '{}' ({} -> {} bytes, {}%)",
                input, out, file_data.len(), compressed.len(), ratio
            );
        }
        Err(e) => {
            crate::console_println!("zstd: write '{}': {:?}", out, e);
        }
    }
}

// ---------------------------------------------------------------------------
// unlz4 / lz4cat — LZ4 decompression
// ---------------------------------------------------------------------------

/// `unlz4` command — decompress LZ4 frame files.
///
/// Usage:
///   `unlz4 [-t] FILE.lz4 [-o OUTPUT]`
///   `lz4cat FILE.lz4`  — decompress to stdout
fn cmd_unlz4(args: &str) {
    let parts: alloc::vec::Vec<&str> = args.split_whitespace().collect();
    if parts.is_empty() {
        crate::console_println!(
            "Usage: unlz4 [-t] FILE.lz4 [-o OUTPUT]   Decompress LZ4 file\n\
             \x20      lz4cat FILE.lz4                    Decompress to stdout\n\
             \x20 -t   Test integrity only (no output written)\n\
             \x20 -o F Write output to F instead of auto-naming"
        );
        return;
    }

    let mut test_only = false;
    let mut input_path: Option<&str> = None;
    let mut output_path: Option<&str> = None;
    let mut skip_next = false;

    for (i, &p) in parts.iter().enumerate() {
        if skip_next {
            skip_next = false;
            continue;
        }
        match p {
            "-t" | "--test" => test_only = true,
            "-o" => {
                if let Some(&out) = parts.get(i.wrapping_add(1)) {
                    output_path = Some(out);
                    skip_next = true;
                } else {
                    crate::console_println!("unlz4: -o requires an argument");
                    return;
                }
            }
            _ => {
                if input_path.is_none() {
                    input_path = Some(p);
                }
            }
        }
    }

    let input = match input_path {
        Some(p) => resolve_path(p),
        None => {
            crate::console_println!("unlz4: no input file specified");
            return;
        }
    };

    // Read the input data.
    let file_data = match crate::fs::Vfs::read_file(&input) {
        Ok(d) => d,
        Err(e) => {
            crate::console_println!("unlz4: '{}': {:?}", input, e);
            return;
        }
    };

    // Verify LZ4 frame magic (04 22 4D 18).
    if file_data.len() < 7 {
        crate::console_println!("unlz4: '{}': file too small", input);
        return;
    }
    let magic = u32::from(file_data[0])
        | (u32::from(file_data[1]) << 8)
        | (u32::from(file_data[2]) << 16)
        | (u32::from(file_data[3]) << 24);
    if magic != 0x04224D18 {
        crate::console_println!("unlz4: '{}': not an LZ4 file (magic: {:#010X})", input, magic);
        return;
    }

    // Decompress.
    let decompressed = match crate::fs::lz4::decompress(&file_data) {
        Ok(d) => d,
        Err(e) => {
            crate::console_println!("unlz4: '{}': decompression failed: {:?}", input, e);
            return;
        }
    };

    if test_only {
        crate::console_println!(
            "unlz4: '{}': OK ({} -> {} bytes)",
            input, file_data.len(), decompressed.len()
        );
        return;
    }

    // Determine output path.
    let out = if let Some(explicit) = output_path {
        resolve_path(explicit)
    } else {
        // Strip .lz4 extension, or .tlz4 → .tar
        if input.ends_with(".lz4") {
            alloc::string::String::from(&input[..input.len().saturating_sub(4)])
        } else {
            alloc::format!("{}.out", input)
        }
    };

    match crate::fs::Vfs::write_file(&out, &decompressed) {
        Ok(()) => {
            crate::console_println!(
                "unlz4: '{}' -> '{}' ({} -> {} bytes)",
                input, out, file_data.len(), decompressed.len()
            );
        }
        Err(e) => {
            crate::console_println!("unlz4: write '{}': {:?}", out, e);
        }
    }
}

